INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (4, 'ay-j247', 'sekans-diyaloglari-1-paramparca-fatih-akin', 'Sekans Diyalogları 1 – Paramparça / Fatih Akın', 'SEKANS DİYALOGLARI 1 – PARAMPARÇA / FATİH AKIN', '<p><strong>SEKANS DİYALOGLARI 1 – PARAMPARÇA / FATİH AKIN </strong></p>\r\n<p><strong>Cem <span style="text-decoration: underline;">Kay</span>alıgil, Seda <span style="text-decoration: underline;">Usu</span>bütün, Semra <span style="text-decoration: underline;">Gün</span>düz</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p>6 Mayıs 2018</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p>&nbsp;</p>\r\n<p><em>Ara Yazılar için </em><strong>Fatih Akın</strong><em>’ın 2017 filmi <strong>Paramparça</strong>’yı </em>(In the Fade)<em> Başka Sinema’da izledik ve çıkışta hararetle masaya yatırdık. Düzenlenmiş haliyle konuşma kaydı karşınızda...</em></p>\r\n<p><em>&nbsp;</em></p>\r\n<p><strong>!!! SÜRPRİZBOZAN İÇERİR, ÖNCE FİLMİ İZLEMENİZ ÖNERİLİR !!!</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Foto%201_1060x441.jpg" alt="Foto 1 1060x441" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>YÖNETMEN: FATİH AKIN</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> <strong><em>Duvara Karşı</em></strong>’yı izleyip, hayran olanlardanım. Peşinden de <strong><em>Sound of İstanbul</em></strong> falan, özellikle müzik seçimleri konusu ve aynı şekilde keskinliği... Yani <strong>Fatih Akın</strong>’ı <strong>Fatih Akın</strong> yapan dilindeki keskinlik bence. Almanya’da yaşıyor işte, Türk yönetmen olması bile tartışılır zaman zaman.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Benim izlediğim üçüncü filmi bu. <strong><em>Duvara Karşı</em></strong> ve <strong><em>Solino</em></strong>’yu izlemiştim. İkisinde de sonun nasıl geldiğini, sondaki dönüşümün nasıl gerçekleştiğini ben anlayamadım.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> <strong><em>Duvara Karşı</em></strong>’daki keskinlik aslında belki de o sonlarla ilgili eleştiriyi hak ediyor. Oradaki kadın karakteri dinsel mitolojide Adem’in Havva’dan önceki eşi Lillith’e benzetiyorlar, &nbsp;yaşama dönük, ayartıcı, baştan çıkaran, yaşam dolu bir kadın. Ama sonuçta o ortamdan uzaklaştırılıyor ve O’nun yerine Havva gibi son derece mülayim, aile değerlerine uygun, erkeğini tamamlayan, çocuklarına özen gösteren tarzda bir kadın tiplemesi geliyor. <strong><em>Duvara Karşı</em></strong> filminde de en çok eleştirilen şeylerden biri, <strong>Sibel Kekilli</strong>’nin oynadığı karakter aslında Lillith’i temsil ediyorken bir yerden sonra evleniyor... duvara vurduktan sonra belki. Hemen sonrasında bir geri adım atıyor ve topluma uyma şeklinde bir gidişatı var. Filmi öyle bitirmiş olmasının, “Lillith’i niye Havva’ya çevirdi ki <strong>Fatih Akın</strong>?” dedirten bir yanı var.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>FİLM: PARAMPARÇA</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Şimdi bu filme gelelim isterseniz. Bu filmde de beklenmedik olan sondu. Ama çok iyi çizildi mi yani olaylar oraya getirdi mi? Eleştirilerim var.</p>\r\n<p style="text-align: justify;"><strong>Kay</strong>: Seninle aynı kanıdayım. Üç bölümden oluşuyor bu film. Aile, Adalet ve Deniz. Kötü isimlendirme bence bunlar</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Deniz’i ben merak ettim izlerken, nereye varacak acaba diye. Orası sürpriz bir bölümdü bence ve iyi bir yere vardı, “Deniz” adını hak etti. Başka nasıl olacaktı. Yalnızca onları havaya uçursa deniz olmayacaktı büyük olasılıkla. Kendini de öldürmesi bence bir şekilde o sonsuzluğa kavuşmak isteğini karşılıyor ki sondaki çekim çok güzeldi, ufku aşağıda gösteren deniz çekimi. Kamera hani önce ufku aşağıda gösteriyor sonra denizi gösteriyor sonra zaten yazılar geliyor... yani öyle gökyüzüne yükselen birinin bakışı gibi</p>\r\n<p style="text-align: justify;"><strong>Kay</strong>: Gökyüzüne yükselen biri öyle mi görür?!</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Sanki yerden bir bakışın tersi olarak havada yükselmiş birinin baş aşağı bakışı idi.</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 45%; float: left;"><img src="/images/arayazilar/Foto%202_472x233.jpg" alt="Foto 2" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 53.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%203_560x233.jpg" alt="Foto 3" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>BÖLÜM 1: AİLE</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bir ve ikinci bölümlerde memnundum ben, akışları çok iyiydi. Orada, girişte beni rahatsız eden bir şey kamera oldu. Aktüel kamerada “Ben aktüel kamera kullanıyorum!” diye fazla sallandırma alışkanlığı var, amatörce. Ayrıca bir süre için aklıma takıldı, “Biz en başta o hapishaneyi niye gördük, bu adam niye hapisteydi?” diye. Bu daha sonra açımlandı; o geçmişin aslında filmin şimdiki hikayesiyle güzel bir bağı var. Adamın uyuşturucu geçmişinin olmasının kadına etkisi ve kadının uyuşturucu kullanımı ve sonrasında da bunun mahkemede bir önem arz etmesi güzel bir zincir oluşturuyor. Bence bunlar yönetmenlik ve senaryo başarıları. Bir de, yas tutan bir kadının halini nasıl gösterirsin sen? Mesela çocuğunun yatağında yatmak, çok iyi bir fikir bence.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bana fazla dramatik geldi o sahne çünkü zaten kadının çok etkilendiği belli. En baştan itibaren başına dünyanın en kötü şeyinin gelmiş olma endişesini bize yansıttı, öğrendikten sonraki acısını da yansıttı. Bu yüzden biraz gereksiz ekstra dramatik geldi. Yani çocuğunun yatağında yatsın tabii ama o ağlamalar ve uyandığında burnunda bir sümük olması... güzel bir ayrıntı denebilir, tamam, ama yeterince vermişti bize acı çektiğini, ne kadar canının yandığını….</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 49.5%; float: left;"><img src="/images/arayazilar/Foto%204_520x214.jpg" alt="Foto 4" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 49%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%205_512x214.jpg" alt="Foto 5" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> O, yeni bilgi vermek için değildi bence. Onun hayatından gösterilen kesitte çocuğa verilen yeri göstermek için orijinal bir fikir. Kalkıp da sevdiği oyuncağa sarılmıyor mesela, o bana daha klişe geliyor. Ama evet anneler çocuklarının yatağına yatar, anneler için çocuklarının yatağının sembolik bir önemi olduğunu hatırladım, kendi annemin laflarından hatırladım.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Aslında o karakterle ilgili fikir de veriyor, başka bir karakter çizebilirdi çocuğunun odasına girmeye çekinen, yaklaşmak istemeyen, oyuncağına dokunmak istemeyen... ona karşın bu kadın, üzerine giden, yatağın kokusunu duymak isteyen, kaybı olmasına karşın onu hala yaşamak isteyen özellikte. İyi bir şey bu karakter özelliklerini bize göstermesi.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Yani filmde, ilk bölümde yası izliyoruz. İkinci bölümde adaletin yerine gelmesi temennisini izliyoruz. Üçüncü bölümde de adaletin yerini bulması için çabalayan birini izliyoruz.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Her bölüm geçişinde bir video gösterdi.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Bir videoda arabayı tamir etmesi ve sonrasında bombayı yapacak bilgisi olması bağlantısı gibi.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> O çok yerindeydi.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Çok inandırıcı oldu, onu göstermesi ve sonra bomba yapması…</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> O benden de bir yıldız aldı.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Güzel bir detay, akıllıca. Bir de ilk bölümden de koparmıyor, anne-çocuk ilişkisi ve aile konusunda güzel bir video, olabilecek bir video. Sonrasında bomba bağlantısı olmasa da orada duran bir konu.</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 42.5%; float: left;"><img src="/images/arayazilar/Foto%206_447x254.jpg" alt="Foto 6" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 56%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%207_585x254.jpg" alt="Foto 7" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Güncel bir kullanım bu telefon videosu çekimi. Hele ki anneler küçük çocuklarını çekerler. Herkes çekiyor, her şeyi çekiyoruz. Bu her şeyi çekiyor olmanın kullanımını da görüyoruz filmde. Öykünün ilerleyişine yarayacak şekilde kullanımı da hoşuma gitti. Biz aslında geçmişini bunlar yoluyla öğreniyoruz. Bu filmin bu sene yapılıyor olmasının da altını çiziyor, 10 sene önce olsaydı böyle bir şey olmayacaktı.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Çocuk seçimi de bence çok iyiydi. Çünkü öyle hoş bir çocuk seçmişler ki sevgiyle büyüdüğü vesaire çok belli. O ailenin aile işlevlerini yerine getirdiğini, bir dezonans olmadığını görüyoruz. Buna karşın yerinde olmayan şeyler de var filmde. Ben mesela aile bölümünde yas kısmını biraz uzun buldum, ilk bölümün ritmini yavaş buldum.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Temel bir derdi var ya hani, geçmişinde böyle yaşamış insanların işlevlerini yerine getirebilen bir aile kuramayacağı yargısı çıkıyor, geçmişini de didikliyorlar.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Uyuşturucu ile ilgili özellikle değil mi? Sanki iyi bir anne olamayacakmış izlenimi uyandırıyor ki onu kayınvalidesi de söyledi ona.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Ne var o kayınvalidenin söyleminin gerisinde? Çünkü çocuğu da çok masum değil, hapse girmiş çıkmış bir oğlu var, bir de gelinini eleştiriyor. Gelinin anneliğini eleştiriyor. O hikayeyi derinleştirebilirdi.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> İlginç yani, bir Alman kadın olarak eğitimini bırakmış. Gelinin anneliğinde hiçbir sıkıntı yok. tamamen işini annelik olarak almış bir kadın yani. Kayınvalideyi neden memnun edememiş? Büyük olasılıkla içkiden, uyuşturucudan. Ya da “niye oğlum bir Türk kızı bulmadı da gitti Almanla evlendi?” Böyle de olabilir, geçmişten ön yargısal bir şey de olabilir.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> İki tartışma çok kısa sürdü, biri kendi annesiyle olan tartışması, diğeri de eşinin anne ve babasıyla olan</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bence şöyle bir tercih var, kamera da o tercihin altını çiziyor. Çoğunlukla kadın dolduruyor kamerayı, çevresi pek yok. Bu da bize en son bölümde verilen bir durumu açıklıyor: kadının kimseye danışmadan kendi kafasına göre karar verebilmesi. Avukatı, sırdaşı ve arkadaşı olan kişiyle hiçbir şey konuşmadan, ona haber de vermeden alacağı kararı alıyor. Dünyadan yalıtılmış bir kadın portresi.</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 49%; float: left;"><img src="/images/arayazilar/Foto%208_514x214.jpg" alt="Foto 8" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 49.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%209_516x214.jpg" alt="Foto 9" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> O biraz aileye adanmışlık, kendini ailesiyle tanımlamış olmakla ilgili büyük olasılıkla. Çünkü Nazilerin öldürdüğü gerçeği ortaya çıkmadan önce de bir intihar denemesi oldu. Yani bir miktar suisidal bir tip belki o gerçekten. Hemen sonrasında uyuşturucu istemesi, kendini uyuşturmak istemesi anlamında söylüyorum.... En sondaki kararına bana göre en çok katkı yapan, arada da bir intihar girişimi olması. Ve çevresinde de işte kendi anne babası, adamın anne babası, ve bir arkadaşı dışında başka bir bağlantı görmüyoruz. Yaşamında başka nerede ne tür bir bağlantısı olduğunu görmüyoruz.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Çünkü yokmuş!</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bu filmlerde bilemiyorsun işte, yok muymuş yoksa yönetmen senaryo nedeniyle mi bize bu kadarını sunmuş?</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> İşte bu kadın nasıl bütün kamerayı dolduruyorsa, filmde de bize gösterilenden başka bir şey yok. Senin söylediğinde bağlayarak, kocası ve çocuğu ölünce bir şey kalmıyor kadında da.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Onlar o kadar değerli ki hayatında onlarsız bir yaşam düşünemiyor, ama çevresinde yine bir sürü insan olabilir, bir sürü insan olmasına karşın bu kararı verebilir bir kişi. Öyle çizmemiş, yani çevresine hiç kimse yerleştirmemiş filmde. Senaryo gereği demeyi tercih ediyorum ben o yüzden, olmaması bence çok mümkün değil çünkü. Yani bunu sorgulamak lazım, bu kadın kendini neden öldürdü? Tamam, eşini çocuğunu kaybetti, öncelikle kendi yaşantısından çok büyük bir kayıp var. İkincisi, adaleti bulamadı. Ayrıca, filmin ikinci bölümünde, “adalet” bölümünde mahkeme salonunda diğer tarafın aleyhine bulgular biriktikçe kadının sevincini, içinin rahatlamasını, onların gerçekten cezalandırılmasını istiyor olmasını da çok güzel verdi. Yani bu kaybın bir dönüşü olmalıydı, cezalarını bulmalılardı. Onun için adaletin yerini bulması önemliydi, ama işte olmayınca.... O da ilginç: bir Alman mahkemesinden böyle bir karar çıkar mı? Bence filmin konuşulabilecek ayrı bir yönü.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Ben inanmıyorum.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bana da hiç inandırıcı gelmedi</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>BÖLÜM 2: ADALET</strong></p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 47%; float: left;"><img src="/images/arayazilar/Foto%2010_496x223.jpg" alt="Foto 10" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 51.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%2011_536x223.jpg" alt="Foto 11" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bu benim birinci eleştirim zaten filme, orada sadece film olsun diye verilmiş bir karar var. Ortada bir film olsun diye yalancı bir şey yapıyorlar.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bir de filmin sonunda “Naziler, sırf Alman değiller diye dokuz kişi öldürdü,” diye bir kayıt vermesi... Böyle <em>fiction</em> bir filmin sonunda bir belgesel izlemişiz gibi bir bilgi konması beni her zaman rahatsız eder. Almanya’yı biliyoruz, Neonaziler var biliyoruz… Böyle bir olay sadece kurmaca olsa, hatta hayal ürünü bile olsa bu öykü bir şey anlatır, anlatıyor. Öyle “gerçek olaylara dayanmaktadır” demesinin hiçbir anlamı olmadığını düşünüyorum.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Çok güzel bir nokta. Benim bir eleştirim de bununla bağlantılı olacak: Biz ne filmi izledik öncelikle? Yas ve intikam filmi izledim de ne yani, böyle çok film var. Farklı olarak ne izledim burada?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Arada Almanya var, Alman adalet sistemi var. Alman adalet sistemine ne kadar gerçekçi yaklaşıyor acaba, bence ciddi bir soru işareti.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Ama Alman adalet sisteminin eleştirisi yok filmde, öyle bir amaç da yok, değil mi?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Ama yoksa... orada gerçekten çok ters bir şey var, bizim kabul edemeyeceğimiz bir sonuç var yani mahkemede.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> İşte o noktada benim kafamda bir soru işareti canlanıyor. O mahkemelerde ne kararlar verilmiş, bunu bilmiyoruz. Eğer ki Alman mahkemesi daha önce gerçekten bu tür bir karar vermiş ise, bu filmdeki mahkeme de bu yüzden böyle bir karar veriyorsa, film başka bir şeyin filmine dönüşmüş oluyor.</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> O bilgiyi ekleseydi keşke sonuna değil mi, “dokuz kişiden şu kadarı şu cezayı aldı” gibi...</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Ama muhtemelen öyle bir şey yok, ortada öyle bir gerçeklik yok.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Gerçekten Almanya’da böyle bir mahkeme izler miyiz? Yani bu, <strong>Akın</strong>’ın eleştirisinin bir parçası mıydı? Bir Alman mahkemesinde bu deliller varken, böyle bir savunma ve böyle bir suçlama varken, böyle bir karar çıkar mı çıkmaz mı konusunda ne diyor? Böyle bir şey olmuş olsun olmasın, öyle bir olasılığı gördüğü için mi bize yansıtıyor? Almanya’da acaba nasıl karşılandı bu film, Almanya’da yaşayıp da oradaki adalet sistemini bilen kişiler acaba nasıl değerlendiriyor filmin o yönünü? Çünkü haksız bir sonuç var. Çocukların babası geldi ifade verdi, en önemli görgü tanığı yani!</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Sen bence iyi ifade ettin. Bence filme dair en önemli eleştiri de bu.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Kadının aklına Naziler niye geldi mesela? Nazi konusunu kadın açıyor, avukatı kim yapmış olabilir diye sorduğunda söylüyor. Dolayısıyla ona ilişkin bir şeyler verebilirdi, aile yaşamları sırasında onları sıkıştıran, onlar olmasa da benzer durumdaki komşularını veya diğer insanları sıkıştıran birtakım örnekler belki olabilirdi. Yani Naziler aklına hemen geldiğine göre onların yaşadığı ortamda böyle bir tehdit var. Adamın ofisi Türk mahallesindeydi, belki o nedenle var. Sonra “niye Yunanistan?” diye düşündüm.. Almanya’daki Nazileri destekleyen adamın Yunanlı olması da ilginç... Ona bakmak lazım.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> O tarihsel bir şey galiba.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Muhtemelen orada var bir şeyler, araştırmadan koymamıştır onları, amblem var, parti adı var, görüntüler falan var... <em>Altını çizmek</em>, hani derdinin ne olduğunun ve ne vermek istediğinin <em>altını çizmek</em>: bu filmde bence o çok yok. <strong><em>Duvara Karşı</em></strong> çok daha net bir filmdi buna göre.</p>\r\n<p style="text-align: justify;"><strong>BÖLÜM 3: DENİZ</strong></p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Üçüncü bölüm bence zorlama bir bölüm. Bir de ikinci bölüm bitince, “Peki bundan sonra ne olacak?” sorusu gündeme geliyor. Birinci bölüm bitince de olmuştu gerçi: “Yas hali uzadı, peki şimdi nereye gidiyoruz?” Bu hissi veriyor. Çocuğun ve eşin denize girme videosundan Yunanistan’a geçiyoruz. Bir sürpriz yapıyor burada, onlarla birlikte gittiği deniz kenarına gittiği hissini veriyor, meğer Yunanistan’daymış, orada bir sürpriz yapıyor bize. Bu bana inandırıcı gelmiyor: Sen kalk Yunanistan’a kadar git, adamın otelini bas, onları bul! Bir kere bundan nasıl haberi oldu ben anlamadım.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Oteli internetten falan biliyor.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Hayır, bombacıların orada olduğuna dair bir fotoğraf var ya, o fotoğraf nereden geldi? “Bizim burada olduğumuzu kimse bilmiyor,” diyorlar, e kadın nasıl biliyor? Filmde gösterilmesi gereken bir bilgi bence, olmaması beni rahatsız etti.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Adalet bölümünde, mahkemede, avukatla konuşurken kadının bir cümlesi vardı ya “Bunların hepsi birbiriyle bağlantılı, bu insanların hepsi birbiriyle ilişkili,” cümlesi. Dolayısıyla o Yunan adamın gelip orada yalancı tanıklık ediyor olması kadın için daha fazla şey ifade etti. Bunların hepsi işte Neonazi, hepsinin derdi aynı...</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Yok, tekrar söyleyeyim, telefonunda bir haber vardı ya, “Şu anda bunlar devlet parasıyla Yunanistan’da tatil yapıyorlar” diye, fotoğraf vardı telefonunda, o fotoğraf nereden geldi?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Dolaşıyor demek ki internette bir yerlerde. Çünkü bunlar da niye Yunanistan’a gelmişlerdi, çünkü gelmeselerdi Almanya’da bütün kameralar üzerlerindeydi…</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Zaten <em>geldikleri için</em> haber oluyor. Ben en başta onu gazete haberi sandım ama gazete haberi olsa çocuklar “Burada olduğumuzu kimse bilemez,” gibi laflar etmezler. Peki kadına o fotoğraf nasıl nasıl ulaştı? Bu konuda cahiliz, filmde bunun cevabı yok. Onların orada olduğu bilgisiyle oraya gidiyor ve bu onun için çok büyük bir hamle. Ama o geçişi görmüyoruz.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Evet evet, o bölümün zaten şaşırtmacalı bir bölüm olması biraz bunlarla da ilişkili. “Niye burada, ne yapmaya çalışıyor, neyine güveniyor da o adamın oteline gidiyor?” Bunlar geçiyor aklımdan izlerken. Bu nasıl bir cesaret? Ne gerek var?</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Ben de böyle dedim. Kaçtı sonra adamdan, sigarası bitmişti, bir büfeye gitti ya… Hah, tamam yani, cesaret edemedi… Bu bana anlaşılır geliyor. Ama sonra git, bir daha adamı takip et, çocukların peşine düş...</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 50%; float: left;"><img src="/images/arayazilar/Foto%2012_524x217.jpg" alt="Foto 12" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 48.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%2013_508x217.jpg" alt="Foto 13" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Aç parantez: o takip çok ilginçti, oradaki kamera güzeldi. Bir arabanın bir arabayı takip etmesini böyle vermek… Yürüyen insanların takibinde vardır da, araba çekiminde ben ilk kez bu kadar… Kenara çekiliyor, bakıyor, biraz burnunu uzatıyor, öbür arabayı görüyor, onun arkasından gidiyor falan, o sahnenin çekimini beğendim ben... Kapa parantez. Ama ne cesareti yani, ablacım nereye gidiyorsun?!</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> İntihara meyilli bir kadın ya…</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Gözükara…</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Bileklerini kestikten sonra vazgeçti, orada adalet yerini bulsaydı da ben yaşama çok tutunacağını zannetmiyorum...</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bak mesela öyle olsaydı ne yapardı acaba, güzel bir soru…</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> ... o gözü karalığı da ondan geliyor sanki… Adalet duygusu için olsa ilk bombayı yerleştirdiğinde orada bırakır giderdi, öyle yapmadı.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Orada niye geri aldı bombayı?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bir tane kuş gördü!</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bir tane kuş gördük evet, gıcık etti beni, neydi o?! İşte bunlar <strong>Fatih Akın</strong>’da var, <strong><em>Duvara Karşı</em></strong>’da da vardı. Bir dönüşüm yaşıyor ve biz görmüyoruz onun nasıl olduğunu.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Tamam görmeyebiliriz. Ruhsal bir dönüşüm çünkü bu. Tam gerçek olmaya başladığında olay, yani oraya yerleştirmiş, onları bekliyor ve düğmeye basacak, tek bir hamle kalmış artık. Orada bir takım şeyleri sorgulamak ve “Yapmayayım,” demek, “Yaa doğru mu yapıyorum?...” demek... Ben o kadar sorgulamazdım. Ama tamam, kuş çok saçma, kuş olmasa daha iyiydi!</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Mesela kadın biraz ketum ya, filmin de o kadar ketum olması gerekmiyordu! <em>(Gülüşme)</em> Ketum bir kadın profili çizebilir, ama <em>hikayede</em> boşluklar vardı.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Şunu anlıyoruz: Avukata “Her şey için teşekkür ederim,” diyor ya, en son lafı o, orada kararı vermiş, onun üzerine regl oluyor, oradaki sebep-sonuç ilişkisi öyle, değil mi?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Hayır bak şöyle oluyor, bombadan vaz geçiyor, oteline dönüyor, otelinde otururken ve düşünürken regl olduğunu anlıyor, sonra arabaya binip telefonu açıyor, biz oralarda rezolüsyon mu oldu acaba diye düşünüyoruz, yani artık vazgeçti öldürmekten, kendince bunu bir şekilde halledecek mi diyoruz. Artık öyle bir noktadayız. Yalnız en son avukatla konuşurken “Ben artık temyiz falan istemiyorum,” diyor ama sesi tedirgin. “Her şey için teşekkür ederim,” demesi sonradan intihar ile birleşince anlam kazanıyor.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Ben sırayı yanlış kurdum ama dediğim şey hâlâ geçerli orada. Regl sırasında kendi kafasında kurmuş, regl olması ile kendini öldürme fikri birbiriyle bağlantılı. Avukatın telefonunu açması da o rahatlama üzerine oluyor.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bombayı geri alırken onun farkında değil. Önce yapamadığını görüyor. Sonra niye yapamadı, neyi yapamadı, neyi yapacak... onu yapsa da bir anlamı yok, diye düşündü bence… Düşüneceği bir zaman aralığı lazım, o da işte tam bir güne denk geliyor</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 42%; float: left;"><img src="/images/arayazilar/Foto%2014_438x245.jpg" alt="Foto 14" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 56.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%2015_593x245.jpg" alt="Foto 15" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> O videonun öyle bir kullanımı da var, orada tekrar görüyoruz videoyu, onlar denize giriyor bu kumsalda kalıyor ya hani…</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Son bölümün adının “Deniz” olması da bununla ilgili. Onlarla birlikte denize gidiyor yani.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Çok büyük ihtimalle öyle. Kafada kurmasını o videoyla göstermiş oluyor, şöyle kuruyor: yani bu hayatta kendisi arkada kalınca, hayatın bir anlamı yok. O video bunu gösteren bir video değil yalnız. O niyetle bize gösteriliyor ama o video onu gösterebilen bir video değil.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Ama bak bir şey daha vardı, o gece kendi otelinin önündeki kumsalda yürüyordu ve çok dalgalı, fırtınalı bir deniz vardı. Orada da kendini öldürmek aklından geçiyor. Yani evet, avukatla konuştuğunda az çok karar vermişti, ama sonrasında kendini bu kararı uygulamaya hazırlaması, veda etmesi... Yani bir sürü sahne var aslında orada, birinci bomba ile ikinci bomba arasında bir günde kadının zihninin nereden nereye geldiğini gösteren bir sürü sahne var...</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bence yok!</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> ... ama ne kadar düzgün, tartışılır.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Filme dair en önemli eleştiri bu olmalı. Zaten iki eleştiri olacak, bir tanesi mahkeme kararı: Böyle karar mı olur?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Bir de <em>kadının</em> kararı: Böyle karar mı olur?</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> O video onu göstermeye çalışıyor ama zayıf gösteriyor, eleştirim o. Başka bir video çekilebilirmiş orada.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Belki şöyle olabilirdi, baba ve çocuk denize gidiyorlar ve düşüyorlar, bir tehlike oluyor, gitmediği için yanlarına kötü hissedeceği bir şey oluyor.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Sen kendin yazdın şimdi bunu değil mi?</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Aynen, ben yazdım! Yani hissettirsin bize kadının geride kalmasının kötü bir şey olduğunu, ve onlarsız kalmak istemediğini, sonuna kadar sorumluluklarını taşıdığını…</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Çünkü sinemanın edebiyata karşı zayıflığı burada. İnsanların kafasından geçenleri anlatma araçları sınırlı. Dış ses var, daha doğrusu iç ses diyelim, çok kötü bir yöntemdir, bu filme hiç yakışmazdı, iyi ki kullanmamış.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Uygun şekilde kullanırsan tabii ki klişe kullanmanın hiçbir zararı yok. Klişeler zaten kullanılmak için varlar.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Araba tamiri çok iyi bir kullanımdı. Tâ baştan beri bomba yapmayı düşünüyor.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> O zaman bence çok daha anlamlı oluyor. Biz görmedik bu kararın ne zaman verildiğini... Bomba yapabileceği bir ortam da var, mahkemede ona çok güzel bombayı nasıl yapacağını anlattılar...orada ayrıntılar falan güzeldi, değil mi?</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> Çocuğun anısı olarak da götürmüş olabilir arabayı.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Evet ama biraz fazla yer kaplar, sırt çantasıyla giden bir insan için... Uzaktan kumandasını falan niye alsın? Bu kesinlikle bomba yapmak için...</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Bir de ilk seferinde hiç denemeden yapabiliyor musun bu bombayı? Bir şey bana yanlış geliyor burada... O kadar yapabileceğini düşünerek planlı olarak gidiyorsun, sonra bu kadar planlamış biri de orada o kadar tedirgin olmamalı…</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Evet, evet… Öyle bir plan varsa o zaman vazgeçme anı biraz tehlikeye giriyor değil mi?</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Evet.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Kuş!! <em>(Gülüşme)</em></p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Kuş!! Bir tane kuş ayna üzerinde...</p>\r\n<p style="text-align: justify;"><strong>Gün:</strong> “Bunu yaparsam onlar gibi olacağım, onlara benzeyeceğim,” gibi bir düşünce mi uyandı kuş sayesinde?</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Onlara benzemekle ilgili bir dert olduğunu ben zannetmiyorum.</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Ben de zannetmiyorum. Mesela öyle bir vurgu şeyde vardı, çocukların babasında. <strong><em>Daha</em></strong> filmi için şöyle demiştik ya: “Bu babadan ancak böyle bir oğul olur.” Bu filmde de tam tersi var, bu çocuğun nasıl böyle bir babası olur? Neonazi nasıl olunuyor, Hitler hayranı nasıl olunuyor, öyle babanın ailesinden Hitler hayranı nasıl çıkar dedirten bir yanı bence var.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Almanya’da bunu demiyorsun galiba...</p>\r\n<p>&nbsp;</p>\r\n<div style="width: 100%;">\r\n<div style="width: 48%; float: left;"><img src="/images/arayazilar/Foto%2016_506x220.jpg" alt="Foto 16" /></div>\r\n<div style="width: 1.5%; float: left;">&nbsp;</div>\r\n<div style="width: 50.5%; text-align: right; float: left;"><img src="/images/arayazilar/Foto%2017_527x220.jpg" alt="Foto 17" /></div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Usu:</strong> Müzik kullanımını beğendik.</p>\r\n<p style="text-align: justify;"><strong>Kay:</strong> Doğru yerde doğru şekilde girdi bence, telefondaki müziğin seçimi de bence güzel, kadının telefonundaki.</p>\r\n<p style="text-align: justify;"><strong><strong>Usu:</strong> </strong>Kadının bombanın patladığı ofise geldiğinde, içeri girdiğinde, duvardaki kanı görmesi ve ona yaklaştığında bizim kalp sesi duymamız... Çocuğun ölümünü, çarpmakta olan bir kalbin yavaşlaması ve durması ses efekti ile vermesi... Çok güzeldi.<strong><br /></strong></p>', 179, 62, 'Ara Yazı', '/images/arayazilar/Foto%201_1060x441.jpg', '2018-05-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (5, 'ay-j248', 'sekans-diyaloglari-1-paramparca-fatih-akin-baslik', 'Sekans Diyalogları 1 – Paramparça / Fatih Akın_başlık', 'Sekans Diyalogları 1 - Paramparça / Fatih Akın', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=247:sekans-diyaloglari-1&amp;catid=42:ara-yazilar&amp;lang=tr-TR" target="_self" style="color: #1fa8d1;">Sekans Diyalogları 1 - <strong><em>Paramparça</em></strong> / <strong>Fatih Akın</strong></a></p>\r\n<p style="font-size: 10pt;"><strong>Cem Kayalıgil,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Seda Usubütün,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Semra Gündüz</strong></p>', 179, 62, 'Ara Yazı', NULL, '2018-05-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (6, 'ay-j250', 'vincere-baslik', 'Vincere_başlık', 'Vincere', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=251:vincere&amp;catid=42:ara-yazilar&amp;lang=tr-TR" style="color: #1fa8d1;"><em><strong>Vincere</strong></em><strong><br /></strong></a></p>\r\n<p style="font-size: 10pt;"><strong>Mine Tezgiden</strong></p>', 26, 62, 'Ara Yazı', NULL, '2018-06-24');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (7, 'ay-j251', 'vincere', 'Vincere', 'VINCERE', '<p><em><strong>VINCERE</strong></em></p>\r\n<p><strong>Marco Bellocchio</strong>, 2009</p>\r\n<p>Biyografi, Dram</p>\r\n<p style="text-align: right;"><strong>Mine Tezgiden</strong></p>\r\n<p style="text-align: right;">Haziran 2018<strong>&nbsp;</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">1939 doğumlu İtalyan yönetmen <strong>Marco Bellocchio</strong>, 2009 yapımı filminde, Mussolini’yi bize hayatına 1910’larda giren sevgilisi, ilk karısı Ida üzerinden yeniden izletip okutuyor. İnce çalışılmış dönem detayları, güçlü mizansenleri, dönüp baktıran ışık tasarımıyla <strong>Bellocchio</strong>, tutkunun ve aşkın ışığının etkisini bizim de gözlerimize ve aklımıza uzun süre kalacak şekilde sirayet ettiriyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sosyalist Parti ile henüz yollarını ayırmamış Bernito’nun güçlü, sınır tanımaz duruşu çarpıcı, sersemleticidir. İtalya’da esen sert fütürizm rüzgarları arasında Bernito’nun sahip olduğu değişim, yükselme ve sıra dışılık arzusunun aslında ne olduğu ve neye dönüşeceğini kestirmek, kendini ele verişlere karşın gözleri kamaşmış Ida için çok daha zordur. O da bu tutkunun peşine takılır, elde ne varsa göz kırpmadan harcanır, engeller aşıldıkça yenileri kaçınılmaz ve vazgeçilmez olur. Gerçeklik kıyılarından uzaklaştıkça, yenileri yaratılır ve orada asılı kalınır. Peşine düşülen ardındakileri&nbsp; harcamaktan çekinmese de acı geçicidir, umut sadece o yönde. Başka bir dünya, başka bir hayat ise hem çok yakın hem yıllarca uzak… Ve bu ateşle yanan sadece Ida olmayacaktır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ida Dalser karakterini özellikle <strong><em>Karşı Pencere</em></strong>’den (<strong>Ferzan Özpetek</strong>, 2003) tanıdığımız <strong>Giovanna Mezzogiorno</strong>;<strong>&nbsp;</strong>Benito Mussolini ve oğlu Benito Albino Mussolini karakterlerini <strong>Filippo Timi</strong> oynuyor, görüntü yönetmeni ise <strong>Daniele Ciprì</strong>. <strong><em>Vincere</em></strong>, 2009 Cannes Film Festivali’nin Altın Palmiye adayı, aldığı pek çok ödülün ilk sıralarında Chicago International Film Festivali En İyi Yönetmen, Görüntü Yönetmeni, Kadın Oyuncu ve Erkek Oyuncu ödülleri yer alıyor…</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Cepteki Yumruklar</em></strong>&nbsp;(<strong><em>I Pugni in Tasca</em></strong>, 1965) ve&nbsp;&nbsp;<strong><em>Günaydın Gece</em></strong>’nin (<strong><em>Buongiorno Notte</em></strong>, 2003) <strong>Bellocchio</strong>’nun atlanmaması gereken filmleri arasında olduğunu da bu noktada hatırlatmakta fayda var.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Son olarak <strong><em>Vincere</em></strong>’yi minik arkadaşlarımızla birlikte izlememenizi öneriyorum, iyi seyirler…</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/vincere.png" alt="vincere" style="color: #000000; display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong><em>Vincere</em></strong> fragman:</p>\r\n<p><a href="http://www.imdb.com/title/tt1156173/?ref_=ttfc_fc_tt" target="_blank" rel="noopener">http://www.imdb.com/title/tt1156173/?ref_=ttfc_fc_tt</a></p>', 1, 62, 'Ara Yazı', '/images/arayazilar/vincere.png', '2018-06-24');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (8, 'ay-j252', 'sekans-diyaloglari-2-kelebekler-tolga-karacelik-baslik', 'Sekans Diyalogları 2 – Kelebekler / Tolga Karaçelik_başlık', 'Sekans Diyalogları 2 - Kelebekler / Tolga Karaçelik', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=253:sekans-diyaloglari-2&amp;catid=42:ara-yazilar&amp;lang=tr-TR" target="_self" style="color: #1fa8d1;">Sekans Diyalogları 2 - <strong><em>Kelebekler</em></strong>&nbsp;/ <strong>Tolga Karaçelik</strong></a></p>\r\n<p style="font-size: 10pt;"><strong>Nurten Bayraktar,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Özgür Erdi Akbaba,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Gülşah Altuğ</strong></p>', 180, 62, 'Ara Yazı', NULL, '2018-07-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (9, 'ay-j253', 'sekans-diyaloglari-2-kelebekler-tolga-karacelik', 'Sekans Diyalogları 2 – Kelebekler / Tolga Karaçelik', 'SEKANS DİYALOGLARI 2 - KELEBEKLER / TOLGA KARAÇELİK', '<p style="text-align: center;"><strong>SEKANS DİYALOGLARI 2 - <em>KELEBEKLER</em> </strong>/ <strong>TOLGA KARAÇELİK</strong></p>\r\n<p style="text-align: center;"><strong>N</strong><strong>urten Bayraktar, Özgür Erdi Akbaba, Gülşah Altuğ</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">20 Temmuz 2018</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><em>2018’in en ilgi çeken filmi belki de <strong>Kelebekler</strong> oldu. Sundance Film Festivali’nde büyük ödülü almasından belki de daha çok</em> <strong>Karaçelik</strong><em>’in önceki filmlerinden bu derece farklılaşmasına şaşırıldı. Film demlendi, eleştiriler yapıldı, </em><strong>Karaçelik </strong><em>ile çok sayıda söyleşi yapıldı. Filmi ve filme gelen eleştirileri serbest çağrışım usulünde konuştuk ve Ara Yazılar için derledik.</em></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p style="text-align: justify;"><strong>!!! SÜRPRİZBOZAN İÇERİR, ÖNCE FİLMİ İZLEMENİZ ÖNERİLİR !!!</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/kelebekler/kelebekler1.jpg" alt="kelebekler1" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Filmdeki erkek dırdırına ne demeli?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Film birçok meseleyle dalga geçerken aslında alışılmışın tersini gösteriyor. Erkek dırdırı da bunlardan birisi. Dırdırı yapanlar hep erkek. Karakterlerin yaşamlarıyla tanıştığımız açılış sekansında Suzan’ın anaokulu öğretmeni olduğunu görüyoruz ve nefessiz dırdır eden bir çocuk karşısındaki pes etmişliğinden kocasının çenesi düşüklüğünden isyan etmesine gidiyor olay. Tabii en can alıcı yer de gazinodaki öfke patlaması. Sebebi ise yine erkek dırdırı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA: </strong>Kötü bir tablo varsa bunun öylesi böylesi yoktur demek istemiş <strong>Tolga Karaçelik</strong>. Dırdır eden başlangıçta küçücük bir çocuk, sonra orta yaşta bir adam ve daha sonra ileri yaşlarda bir adam, yediden yetmişe diyebileceğimiz erkek slaytı diye gözler önüne serilmiş.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Kadınlık ve erkeklik rolleri ne tür bir bakış açısıyla yansıtılmış?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA: </strong>Filmde barda geçen konuşmalar kadın ve erkeğin alışılmış cinsiyet rolleri arasında da güzel bir zıtlık yaratıyor, çünkü kadın, Kenan’a asılırken futbol maçından ve oyunculardan bahsediyor. Bir kadın kendi isteğiyle bir erkeğin yanına gelip bar sohbetini başlatıp aynı şekilde sonlandırabiliyor. Filmdeki kadın karakterler olay ve durumlarla başa çıkma yöntemleri açısından da ilgi çekici görünüyorlar. Güçlü kadınlar (Suzan ve muhtarın karısı gibi) ya da sesi ve sözü olan kadınlar, filmde erkeklerin karşında daha da sesli ve sözlü olabiliyor. Aynı şekilde ana karakter Suzan başta olmak üzere filmde kadınların çizimi daha maskülen.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Bu kadınlık-erkeklik meselesiyle bar sahnesinde tersyüz edilme durumu var. Futbol muhabbeti açarak karşı cinsi tavlamaya çalışan bir kadın, futboldan bir şey anlamayan ise erkek. Hatta kadının özgüvenli duruşu, espri anlayışı, kontrol eden konumunda bulunmasına karşın Kenan, pasif ve biraz aptalca davranıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Senaryonun bir yere varmadığı eleştirisine ne demeli?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Hayır, buna katılmıyorum. Film, ciddi ile komiğin, ölüm ile yaşamın, gerçek ile abartının birbiriyle ilişkisi üzerine kurulmuş. Eee, senaryo da kurgu da böyle gidiyor doğal olarak.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> İşte hayat bu değil mi? Ne zaman ne yaşayacağımızı bilmiyoruz. Gülecek miyiz, ağlayacak mıyız bilmiyoruz. <strong>Karaçelik</strong> ilk defa bu filminde sürprizlerle dolu hayatı senaryoyla eşleştirmiş.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Bence bu eleştiri filmin çok yönlü anlatım diline yönelik yapılan bir eleştiri. Öncelikle salt ve kolay anlaşılır katmanlardan oluşmuyor film, bunu kabul etmek lazım; fakat hikâye özgün ve naif dokunuşlarla zenginleştirilmiş. Film bir noktada aile öyküsü: parçalanmış ya da baştan hiç var olmamış bir alenin trajikomik öyküsünü anlatıyor. Filmin aile kurumuna ve aile tanımlarına yönelik bir eleştirisi olduğunu da düşünüyorum; ancak metnin dine, felsefeye, feminizme, toplumsal cinsiyete, ahlâka, kültüre, popüler kültüre yaptığı ironik dokunuşlar da çok şey söylüyor gibi.</p>\r\n<p>&nbsp;<img src="/images/arayazilar/kelebekler/kelebekler2.jpg" alt="kelebekler2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- </strong><strong>Filmin sonunun hayal kırıklığı olduğu yönünde bazı eleştiriler var…</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Filmin sonu da aynen bahsettiğim gibi. Kör çoban, çatıyı tamir etmiş. Kör ve çoban! Ne alaka? Baba, miras diye borç bırakmış. Çoban da ölmüş adamın arkasından para istiyor… Hepsi saçma, zaten işin cilvesi de bu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> Bu eleştirileri pek anlamıyorum, çünkü filmin havasından suyundan o kadar iyi yararlanılmış ki final çat kapı gelen misafir tadı bırakıyor. Cemal karakterinin kör çobanın anlattıklarına verdiği tepki ile Kenan’ın gülen Cemal’e olan çıkışı filmi mutlu son havasına bürüyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Komik, gerçekten güldük yani, öyle bir son beklendik değildi; ama ben bu sonun filmin öyküsel gidişatına ‘cuk’ diye oturduğunu pek söyleyemeyeceğim. Bu son <strong>Karaçelik</strong>’in işi bence; inek nerde, dağa kaçtı, dağ nerde yandı bitti kül oldu misali.</p>\r\n<p><strong style="text-align: justify;">&nbsp;</strong></p>\r\n<p style="text-align: justify;"><strong>- Kurgu kötü diyenler de olmuş…</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:&nbsp;</strong>Hem biçimsel hem içeriksel bakımdan aynı tonda olmasıyla organik bir bütünlük sağlamış bence. Karakterler ağlarken pat diye kahkaha; gülerken pat diye ağlama; hızlı ritimden pat diye yavaşa… Tüm bu kesmeler de hayata müdahale eden olaylar gibi; ani, tesadüfi (tabii bu insanın inancına göre de değişir), alakasız ve saçma- saçma ama önemli. Böyle bir senaryoya böyle bir kurgu uyum sağlar.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:&nbsp;</strong>Böyle bir filme daha farklı nasıl bir kurgu yapılabilir bilmiyorum, ama bu filmle ilgili bildiğim tek bir şey var: Böyle sade bir filme böyle kurgu lazımdı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Filmin ritmine uyan bir kurgu, baştan sona…Filmde en çok beğendim nokta kurgu oldu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/arayazilar/kelebekler/kelebekler3.jpg" alt="kelebekler3" />&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Toplumsal meselelere ve dini konulara yer verme biçimlerine gelirsek…</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> Din üzerine esprili bir dille bu kadar derin yaklaşılması ve rencide etmeden sorgulamaya yöneltmesi, astronot Cemal’in mesleki hayatının tebessümle anlatılması ve bir astronotun mesleği ile olan bağlılığını çok samimiyetle görebilmemiz gibi sebeplerle yönetmen, bu filmin altından kalkabildiğini gösteriyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Din ve inanç kavramlarının sorgulanabilir tarafını köyün hocasından dinlemek çok hoş bir ironi olmuş. Daha da ötesi böyle bir köyde işlevselliğini yitirmiş inanç sistemlerinin varlığı artık gelenekten öte değildir. Yani böyle bir köyde aslında dinin cenaze namazı çoktan kılınmış.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Kelebekler nedir? Mezarla olan bağlantısı yeterince açık mı?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Filmin en kapalı yönü kelebekler bence. İşlevi ne? Renkli, cıvıl cıvıl, baharı getiren masum varlıkların aslında ölümü getirmesi diyeceğim. Tabii bu yorumu filmin mozaik yapısına dayanarak çıkarmaya çalışıyorum. Daha da ötesini anlamadım!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Kelebekler&nbsp; filme mistik bir ruh katmış. Tarihte mezarların üzerine konan kelebek türleri var, fakat hatırladığım kadarıyla onlar mezarların üzerinde oluşan bir bitki ile beslendikleri için bunu yapıyorlardı. Ölümü getiren yahut hatırlatan başka bir durum söz konusu mu bilemeyeceğim; ama kelebeklerin hikayesini sevdim.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Şarkılar göze sokulmuş mu?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Vallahi, hangi türden eser olursa olsun eski şarkılar kullanılınca alıcı kitle bunu göze sokmak gibi hissetmiyor, aksine romantik ve nostaljik bir duyguya kapılıyor bence. Seçilen şarkıların sözleri, filmin meselelerini kabak gibi ortaya çıkarıyor, o kesin, ama 90’ların pek de bilinmeyen şarkılarını bulup kullanmışlar. O yüzden rahatsız etmiyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:&nbsp;</strong>“Barış Manço’yu anmamız; Erkut Taçkın, Nazan Öncel ve Grup Gündoğarken’i tekrar hatırlamamız iyi oldu.” desem her şey anlaşılır zaten.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Hatıralar, beklentiler ve gerçekler… Anne ve baba hayal kırıklığı mı?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Aynen öyle… Tıpkı kadın ve erkeğin kendi türlerine uymaması gibi anne ve baba figürleri yapıcı değil yıkıcı, gelecek vaat eden değil hayal kırıklığı. Çocuklarından birini ölürken yanında götürmek isteyen bir anne, küçük yaşta çocuklarını reddeden bir baba.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> Yine bir baba travması diyoruz, ama izledikçe önce yüzeysel sonra yarayı dağlamayan bir anne travması izliyoruz. Sancılı bir anne anıları olmasına rağmen yine filmi baba bitiriyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Film ailevi bağları eleştiriyor fakat filmde bir bağ göremiyoruz, olması da mümkün değil zaten. Hani bir de olmayan bağı nasıl açıklayacaksın, hatıra desen silinesi hatıralar bilinmezliklerle, eksiklerle dolu. Yani ortada ne aile var ne bağ var ne de doğru düzgün anı var. Olanı da izleyiciye veriyor zaten <strong>Karaçelik</strong>.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Ana öykü klişe mi?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Klişeyi farklı anlatmak olmuş bu… Birçok filmin, romanın, şiirin, resmin… yaptığı gibi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Yani parçalanmış aile hikayelerini çok gördük evet, fakat böylesi pek de klişe sayılmaz. Film, hadi sıkı sıkı sarılalım, bir aile olalım demiyor bence. Verdiği mesajlar farklı…</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Suzan sarhoşken ve mezarın başında dökülüyor. Bu anların önemi nedir?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> İnsanın doruk noktaları, duygusal boşalma anları… Aslına bakarsan en klişe iç dökme biçimlerini Suzan’da görüyoruz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> Kadın: Ne yazık ki yolun sonundaki güvenilir limanlara demir atıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Suzan’ın mezar başında dökülmesinin klişe olduğuna kesinlikle katılıyorum. Hatta bence biraz bayağı kalıyor. Bunu sona yaklaştıran ince bir çıkış olarak da görebiliriz. Öyküye dönük yapılmış bir duygusal boşalım sahnesi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Aile içindeki bilinmezlikler, baba ile birlikte gömülüyor mu?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:</strong> Tekrarlıyorum, bu film bilmek, hikâyeyi çözmek, bağları kurmak üzerine bir film zaten değil. Böyle bir kaygısı yok.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Toplumsal meselelere mizahi bakış açısıyla yaklaşım sadece popüler filmlere özgü olmamalı.</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:&nbsp;</strong>Herkes ekmeğini mizahtan çıkarabilsin işte daha ne. Çıkarabilene her yer sinema.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Tavukların patlaması öyküye katkı sağlıyor mu?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Yapımcılardan Diloy Hanım da dedi: “Komik işte.” Muhtemelen <strong>Karaçelik </strong>bu tür bir olayı bir yerlerde okudu, duydu ya da öylesine uydurdu ve kendisi çok eğlendiği için filme de koydu. İlla bir yorum katacaksak da diyorum ki tavukların o köyde patlaması, karakterlerin maneviyatlarının patlamasını simgeliyor. Her şey Hasanlar’da oluyor çünkü.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/arayazilar/kelebekler/kelebekler4.jpg" alt="kelebekler4" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- Astronotun filme katkısı nedir?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:&nbsp;</strong>Ne beklenirdi ki bence Cemal’ın onaylanma ve kendini kanıtlama kaygısı var. Kendini yakmaya kalkışması, kitap yazması ve kendi bildiği hayatı tırnak içine sığdırmaya çalışması bundan. Bir de tabii kimlik arayışı var.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/arayazilar/kelebekler/kelebekler5.1.jpg" alt="kelebekler5.1" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>- “Bazen çok üzülüyorum.”</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>NB:</strong> Aha! “Vallahi olay budur.” dedim! Filmin tüm mesajı bu: Bazen çok üzülüyorum, her zaman değil, bazen! İşte yine o mozaiğe geleceğim: Hayat bazen saçma, bazen ciddi, bazen üzücü, bazen komik. Bazen, her zaman değil.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>ÖEA:</strong> Söylenecek çok şey var ama sadece şunu diyebilirim: Bazen çok şey söylemek istiyorum…</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; padding-left: 30px;"><strong>GA:&nbsp;</strong>Hayat bu, kelebekler de uçar gider, sen uçuşu hatırla… Bazen de mutlu ol ama.</p>\r\n<p>&nbsp;</p>', 179, 62, 'Ara Yazı', '/images/arayazilar/kelebekler/kelebekler1.jpg', '2018-08-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (10, 'ay-j256', 'guvercin-yonetmen-banu-sivaci-ve-film-ekibi-i-le-soylesi', 'Güvercin – Yönetmen Banu Sıvacı Ve Film Ekibi İle Söyleşi', 'GÜVERCİN', '<p style="text-align: center;"><strong>GÜVERCİN</strong></p>\r\n<p style="text-align: center;"><strong>YÖNETMEN BANU SIVACI VE FİLM EKİBİ İLE SÖYLEŞİ<br /> Söyleşi: Özgür Erdi Akbaba, Cem Kayalıgil, Nurten Bayraktar</strong></p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p>&nbsp;<img src="/images/arayazilar/guvercin/foto1_1060x795.jpg" alt="foto1 1060x795" /></p>\r\n<p style="text-align: center;"><span style="font-size: 10pt;"><strong>Yönetmen Banu Sıvacı, Görüntü Yönetmeni Arda Yıldıran&nbsp;</strong><strong>ve Başrol Kemal Burak Alper</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>ÖEA: Filmi izledikten hemen sonra ilk izlenimlerimi paylaşayım. Çok şaşırdım; iyi anlamda şaşırdım. Film, beklediğimden de iyi, özellikle görsel açıdan çok tatmin ediciydi.Arda Bey, sizin için film nasıl geçti?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>AY:</strong> Bizim için film keyifli ve yorucu geçti, çok çalıştık. Özellikle güvercinler bizi uğraştırdı, kameraları çatı sahnelerine kurup aşağıya iniyorduk. Güvercinler alışınca tekrar çekim alanına çıkıyorduk. En sonunda da kameralara alıştılar.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto2.jpg" alt="foto2" /></p>\r\n<p style="text-align: center;"><span style="font-size: 10pt;"><strong>Arda Yıldıran (sağda)</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Filmin görsel gücü çok yüksekti, sizi tebrik etmek lazım.</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>AY:&nbsp;</strong>Çok teşekkür ederim. Ben grafik tasarımı eğitimi aldım. Banu’nun resim eğitimi de renklere olan hâkimiyetimizi arttırdı.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Başrol oyunculuğu da bir o kadar etkiliydi. İlk film miydi?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>KBA:</strong> Hayır, dördüncüydü; ama başrol olarak ilk filmdi. Dolayısıyla benim için de önemli ve heyecan vericiydi.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Tebrik ederim. Zaten katıldığınız festivallerden de hep güzel dönüşler aldınız.<em>Güvercin</em>’e geçmeden önce biraz yönetmen Banu Sıvacı’yı tanıyalım. Banu Sıvacı sinemasını nasıl tanımlarız?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto3_1060x708.jpg" alt="foto3 1060x708" /></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>BS:</strong> Onu daha ben de bilmiyorum. Bu alanda daha yeniyim, sürekli kendimi geliştirmeye çalışıyorum. İlerleyen yıllarda daha net ortaya çıkacaktır.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Neden sinema yapıyorsunuz?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:</strong> Ben resim mezunuyum, sinemaya ilgim hep vardı. Resmin yanında sinema yapmak istediğim için bu yola girdim.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Gelecek projeleriniz hakkında bilgi verir misiniz?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp;</strong>Tabii ki. Şu anda filmimizin festival katılımları ve gösterimleri oluyor, ama şu an üzerinde çalıştığım başka bir projem var.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Bir yıl öncesinde belki filmin hayallerini kurarken belki de projeleştirirken şimdi ise ilk filmini yapmış bir yönetmen olarak hayatınızda ne gibi bir fark var?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp;</strong>Aslında sadece uzun metrajlı bir filmim var. Pek bir değişim olduğunu söyleyemem.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>CK:&nbsp;<em>Güvercin’e</em> gelelim. Bu film, bir kadın yönetmen filmi diyebilir miyiz?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp;</strong>Bu konuya hiç katılmıyorum, çünkü ben filmlerin bir yönetmen tarafından çekildiğine inanıyorum. Bir film varsa ortada, o film kadın veya erkek yönetmen tarafından değil, bir yönetmen tarafından çekilmiştir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ÖEA: Senaryoyu yazarken hayal ettikleriniz ortaya çıktı mı? Siz filminizden tatmin oldunuz mu?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp;</strong>Senaryoyu yazmaya uzun süre önce başladım. Çok daha karmaşık ve karakterliydi. Zamanla bunun sadece Yusuf’un hikayesi olacağına karar verdim. Ama filmi çekerken bile kendinizi kaptırıyorsunuz, ister istemez kurguda o fazlalıklar gidiyor. Filmin sonunda ortaya çıkmasını istediğim fikir filmde vardı. Film kendi özünü yakalamıştı, bu benim için yeterliydi.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto4.jpg" alt="foto4" /></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>ÖEA: Filminizin konusunu düşününce ilk uzun metraj için zor bir çekim aşaması değil mi? Hiç vazgeçmeyi ya da değiştirmeyi düşündünüz mü? Özellikle kuşlarla ilgili sahneler zor olmuş olmalı.</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp;</strong>Zor bir süreç oldu. Özellikle kuşların bize alışma süreci uzun zaman aldı. Sonunda oldu ama. Kuşlara olan ilgim bize kolaylık sağladı ancak tabii zorluklar oldu.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto5.jpg" alt="foto5" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>CK: Adana’nın arka sokaklarında geçen bir film ama <em>01</em> dizisindeki gibi bir kültür değil.</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:</strong> Aslında filmin Adana’da olduğunu vurgulamak istemedim zaten bunu belli eden bir imge de yok.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>CK: Yurt dışında nasıl tepkiler aldınız? Güvercinlerle bu tür bir ilişki yerel bir kültürün parçası aslında. Sizce film evrensel mi yerel mi?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:</strong> Yurt dışında iyi tepkiler aldık. Güvercinlerle nasıl çekim yaptığımız en çok sorulan sorulardan biriydi. Bence filmin vermek istediği evrenseldi ve seyircilerden aldığımız tepkiler de güzeldi.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto6_1060x790.jpg" alt="foto6 1060x790" /></p>\r\n<p style="text-align: center;"><span style="font-size: 10pt;"><strong>Ankara Film Festivali, En İyi İlk Film Ödülü</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>ÖEA: Son olarak Banu Sıvacı için en önemli 10 film nedir?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>BS:&nbsp; &nbsp;&nbsp;</strong>1- Dom zaVasenja (Çingeneler Zamanı)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2- TheSong of Sparrows (Serçelerin Şarkısı)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 3- Eternity and a Day (Sonsuzluk ve Bir Gün)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 4- The Cook, TheThief, His Wife and Her Lover (Aşçı, Hırsız, Karısı ve Aşığı)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 5- Vengo</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 6- Taste of Cherry (Kirazın Tadı)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 7- Ikiru (Yaşamak)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 8- Skammen (Utanç)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 9- Les Nuits de Cabiria (Cabiria’nın Geceleri)</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 10- Anayurt Oteli</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/guvercin/foto7.jpg" alt="foto7" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong><em>GÜVERCİN</em>&nbsp;21 EYLÜL’DE GÖSTERİMDE</strong></p>', 1, 62, 'Ara Yazı', '/images/arayazilar/guvercin/foto1_1060x795.jpg', '2018-09-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (11, 'ay-j257', 'guvercin-yonetmen-banu-sivaci-ve-film-ekibi-i-le-soylesi-baslik', 'Güvercin – Yönetmen Banu Sıvacı Ve Film Ekibi İle Söyleşi_başlık', 'Güvercin – Yönetmen Banu Sıvacı Ve Film Ekibi İle Söyleşi', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=256:guvercin-banu-sivaci&amp;catid=42:ara-yazilar&amp;lang=tr-TR" target="_self" style="color: #1fa8d1;"><em><strong>Güvercin</strong></em> – Yönetmen <strong>Banu Sıvacı</strong> Ve Film Ekibi İle Söyleşi</a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;">Özgür Erdi Akbaba,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Cem Kayalıgil,</strong></p>\r\n<p style="font-size: 10pt;"><strong>Nurten Bayraktar</strong></p>', 181, 62, 'Ara Yazı', NULL, '2018-09-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (12, 'ay-j265', 'i-stanbul-film-festivali-nden-notlar-1-baslik', 'İstanbul Film Festivali\'nden Notlar - 1_başlık', 'İstanbul Film Festivali\'nden Notlar - 1', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=266:iff-notlar-1&amp;catid=42:ara-yazilar&amp;lang=tr-TR"><span style="color: #1fa8d1;">İstanbul Film&nbsp;Festivali\'nden Notlar - 1</span></a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;">İlker Mutlu</strong></p>', 20, 62, 'Ara Yazı', NULL, '2019-04-12');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (13, 'ay-j266', 'i-stanbul-film-festivali-nden-notlar-1', 'İstanbul Film Festivali\'nden Notlar - 1', 'FESTİVAL NASIL GEÇİYOR?', '<p style="text-align: center;"><strong>FESTİVAL NASIL GEÇİYOR?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>İlker Mutlu</strong></p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p style="text-align: justify;">Bu yıl 38\'incisi yapılmakta olan İstanbul Film Festivali\'ne (İFF) İzmir Kitap Fuarı’nda kitabım olduğu için birkaç gün geç katılabildim. Şimdiye kadar ancak altı filmi takip edebildim. Doğrusu bahar başlangıcı için biraz yağmurlu ve serin giden havalara iyi bir seçenek sunuyor festivalin salonları. Bu salonların dağınık olmaları, festivalin en başta gelen dezavantajı. Zira Fransız Kültür’den Nişantaşı’ndaki Cinemaximum City’s’e atlayan ve yolu hesaba katmayan bir program yapmışsanız, arada kaçırdığınız seanslar olabiliyor. İlk gün <em><strong>Paterloo</strong></em>’yu kaçırmam gibi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bunun dışında, etkinlikler geçtiğimiz yıllarda daha yoğundu sanki, eğer bu da dezavantajlardan sayılabilirse. Ama İFF, İFF’dir yine de ve gördüğüm kadarıyla seanslardaki doluluk oranı hiçde azımsanacak gibi değil.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Şimdiye kadar görebildiğim filmleri kısaca bir geçersek:</p>\r\n<p>&nbsp;</p>\r\n<p><strong><em>Lanetli Kumaş</em></strong> (In Fabric):</p>\r\n<p style="text-align: justify;">Daha önce <em><strong>Berberian Soubd Studio</strong></em> ve <em><strong>Burgundy Dükü</strong></em> filmlerini gördüğüm ve klasik bazı film türlerine saygı duruşu niteliğindeki kendine özgü anlatım tarzı ile beni kendine çeken yetenekli yönetmen <strong>Peter Strickland</strong>, bu defa İtalyan giallo ve korku filmlerini baz alarak, <strong>Argento</strong>’nun kırmızı dehşeti ile <strong>Bava</strong>’nın grotesk açılarından da yoğun bir şekilde faydalanıp, ortaya nevi şahsına münhasır bir film koymuş. Bunu yaparken de günümüz tüketim toplumunu alabildiğine eleştirmekten de geri durmamış. Lanetli, katil elbisenin cinayetleri sizi zaman zaman gülümsetse de o gerilime kapılıp gitmekten kendinizi alamıyorsunuz. Filmin her anı simgesel öğelerle dolu. En belirgini, bir Yunan lokantasındaki ilk randevu sahnesi mesela. Adamın adı Adonis; Yunan mitolojisinde erkek güzelliğinin simgesi olan bir tanrı bu Adonis. Neticede ustaca yazılıp detaylandırılmış, seyri çılgın bir deneyim olan, iyi bir seyirlik <em><strong>Lanetli Kumaş</strong></em>.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Okul Çıkışı</strong></em> (L’Heure de la Sortie):</p>\r\n<p style="text-align: justify;">Film, <strong>Christophe Duffosé</strong>’nin aynı adlı romanından perdeye uyarlanmış. Gerilimi her daim ayakta tutan yapısıyla merak uyandırsa da, bu kıyamet senaryosu, film bittiğinde pek çok karşılıksız soru bırakıyor kafada. Dünyanın sonuna takılı kalmış ortaokul çağında çocuklar, en son gerçekleştirmeyi planladıkları intihar boyutunda eylemi haklı kılmak için derledikleri görüntüler, birbirlerine yaptıkları ölümcül işkenceler ve onları takip ederken insanlıktan çıkıp deliren, hatta intihar eden öğretmenler. Neden? Neden? Bir sürü nedeni yanıtsız, havada bırakarak bitiyor film ve sizi de çaresiz, öylece ortada bırakıveriyor.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Dünyanın Sınırında</strong></em> (To the Ends of the World):</p>\r\n<p style="text-align: justify;"><strong>Guillaume Nicloux</strong>’nun yönettiği film, Çinhindi’ndeki savaş ortamında geçen bir tür imkansız aşk, bir Romeo ve Jülyet çeşitlemesi gibi. Uzun zamandır perdede izlemediğimiz <strong>Gerard Depardieu</strong>’yü tekrar izlemek hoş olsa da, <strong>Coppola</strong>’nın <em><strong>Kıyamet</strong></em>’ini anımsatan yapısına rağmen oldukça ağır ilerliyor ve insanı zorluyor film. Yine de yönetmenin ve ekibinin sergilediği teknik ustalık saygıyı hak ediyor.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Canavarlar</strong></em> (Monsters):</p>\r\n<p style="text-align: justify;">Yepyeni bir Romanya filmi izlemek açısından ilginçti film. Filmin yönetmeni ve senaristi olan <strong>Marius Olteanu</strong> hoşgörüsüzlüğü, iletişimsizliği bir çiftin 24 saati içinde vermeye çalışıyor ve bunu büyük oranda da başarıyor. Lakin film fazlasıyla konuşkan ve bu durum zaman zaman sarkmalara yol açıyor. Bazı sahnelerin gereksiz olduğu hissine kapılıyorsunuz.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Gözü Kara</strong></em> (Jumpman):</p>\r\n<p style="text-align: justify;"><strong>Ivan I. Tverdovsky</strong>’nin hem yazıp hem de yönettiği yapım, bir nevi süper kahraman ya da üstün özellikli insan filmi. Filmde annesi tarafından bir yetimhaneye terk edilen Denis’in hikayesi anlatılıyor. Denis, kolay kolay yara bere almamaktadır, neredeyse ölümsüzdür. Yıllar sonra pişman olup onu yetimhaneden kaçıran annesi, onun bu özelliğini paraya çevirmenin yolunu bulur. Zengin arabalarının önüne atlayıp kendisine çarpmalarını sağlayacak ve adamları soyacaklardır! Yönetmen bu tür konuları seviyor. Daha önceki <em><strong>Zoology</strong> </em>adlı filminde de kuyruklu bir kadın vardı. Çocuğun çevresindeki her katmandan insanın çocuğun bu özelliğinden faydalanması, gelir elde etmesi üzerinden günümüz toplumuna da açık bir eleştiri getirildiği söylenebilir. Filmdeki tüm oyuncular, ama özellikle Denis’i oynayan genç oyuncu, harika.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Bu Her Şeyi Değiştirir</strong> </em>(This Changes Everything):</p>\r\n<p style="text-align: justify;"><strong>Tom Donahue</strong>’nin yönettiği bu hem eğlenceli hem de düşündürücü belgesel, <em><strong>In Fabric</strong> </em>ve <em><strong>Jumpman</strong></em>’le birlikte en sevdiğim üç yapımın başına yerleşti. Hollywood özelinde tüm dünyada kadın yönetmen ve oyunculara uygulanan ayrımcılığı belgeleriyle gözler önüne seren belgesel, sinemanın emekleme yıllarında büyük ağırlığa sahip kadın sinema çalışanlarının sayılarının, bu sanat sektör haline gelip para kazandırdıkça nasıl azalıp günümüzdeki seviyeye geldiğini vurucu bir dille anlatıyor. <strong>Geena Davis</strong>’ten <strong>Meryl Streep</strong>’e, <strong>Reese Witherspoon</strong>’dan <strong>Natalie Portman</strong>’a kadar onlarca kadın yönetmen, yapımcı ve aktris, hem kendilerine uygulanan tacizleri, hem de sinemada nasıl ikinci derecede kalmaya zorlandıklarını büyük bir açık yüreklilikle anlatıyorlar.</p>\r\n<p>&nbsp;</p>\r\n<p>Evet, şimdilik benden haberler bu kadar. Sizlere üç günde bir festivalden haberler vermeye çalışacağım. Sanatla dolu günler…</p>\r\n<p>&nbsp;</p>', 1, 62, 'Ara Yazı', NULL, '2019-04-12');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (14, 'ay-j267', 'i-stanbul-film-festivali-nden-notlar-2', 'İstanbul Film Festivali\'nden Notlar - 2', '38. İSTANBUL FİLM FESTİVALİ', '<p style="text-align: center;"><strong><strong>38. İSTANBUL FİLM FESTİVALİ</strong></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>İlker Mutlu</strong></p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p style="text-align: justify;">Bu yıl 38\'incisi yapılmakta olan İstanbul Film Festivali’nde bu ikinci üç günde, her biri çeşitli özellikleriyle diğerlerine üstün gelen dokuz film gördüm. İlk üç gündeki çoğu vasatta, bazıları vasatın az üstünde ilerleyen filmlerin ardından bu ikinci üç gün ilaç gibi geldi. Tam festivalin kalanının da böyle geçeceği kanaatine varıyordum ki, dördüncü günden itibaren üç gün boyunca gördüğüm dokuz film beni hakikaten çok şaşırttı. Bu yapımlar şunlardı:&nbsp;<strong><em>God Exists, Her Name is Petrunia</em></strong> (Teona Strugar Mitevska, 2018), <strong><em>Murder Me, Monster</em></strong> (Alejandro Fadel, 2018), <strong><em>Talking About Trees</em></strong> (Suhaib Gasmelbari, 2018), <strong><em>The Waiter</em></strong> (Steve Krikris, 2018), <strong><em>Shadow</em></strong> (Zhang Yimou, 2018), <strong><em>The Man Who Surprises Everyone</em></strong> (Natasha Merkulova &amp; Aleksey Chupov, 2018), &nbsp;<strong><em>Görülmüştür</em></strong> (Serhat Karaaslan, 2018), <strong><em>Kız Kardeşler</em></strong> (Emin Alper, 2018) ve <strong><em>Decembers</em></strong> (Enrique Castro Rios, 2018) &nbsp;filmlerini görebildim.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bunlardan <strong><em>God Exists, Her Name is Petrunia</em></strong>, Kuzey Makedonya, Belçika, Slovenya, Fransa, Sırbistan ortak yapımı olup, Berlin’de yarıştığından bu yana kendinden bahsettiriyordu. Otuzlu yaşlarda, “evde kalmış”, kendinden adeta nefret eden kilolu bir kız olan Petrunia, hayattan iyice yıldığı bir anda, çok da bilinçli olmaksızın denk geldiği bir Teofanya bayramı ayininde denize atılan haçı bulmak için suya dalan onlarca gençle birlikte denize atlar ve haçı bulur. Haçın iyi şans getireceğine inanılır ve gelenekte bu işi yalnızca erkekler yapar. Bu durum tüm kasabayı kızdırır. Bir kadının gelenekleri yıkıp erkeklerin önüne geçmesi olacak şey midir? Petrunia tüm zorlamalara rağmen haçı vermemeye kararlıdır. <strong>Zorica Nusheva</strong>, Petrunia rolünde harikalar yaratırken, altıncı uzun metrajını çeken kadın yönetmen <strong>Teona Strugar Mitevska</strong> da hikayeye hakkını veren bir yönetmenlik sergilemiş.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Murder Me, Monster</em></strong>, 2018’de Cannes’da dikkat çekmiş, ilginç bir Güney Amerika korkusu olarak hayli etkileyici. Deneyimli yönetmen <strong>Alejandro Fadel</strong>, esas canavar içimizde misali bir yaklaşımla seyircinin kendi korkularıyla yüzleşmesine yardımcı oluyor. Canavarı tümden görmek seyircinin ona acımaya başlamasına neden oluyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Talking About Trees</em></strong>, Berlin’den ödüllü, sıcak bir belgesel. Yönetmen <strong>Suhaib Gasmelbari</strong>, bazıları zamanında ülkenin önemli yönetmenleri olan yaklaşık elli yıllık dost dört adamın kurdukları Sudan Sinema Kulübü bünyesindeki mücadelelerini anlatıyor. İdealist ve o derece insancıllar ki yaptıkları tüm faaliyetleri ücretsiz gerçekleştiriyorlar. Eski filmleri toplayarak bir arşiv kurmak, artık kapalı durumdaki metruk sinema salonlarını yeniden diriltmek hayalindeler. Bu dört ihtiyarın kimi zaman komik, kimi zaman hüzünlü mücadeleleri seyirciyi kolayca avucunun içine alıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>The Waiter</em></strong>, oyunculuk ve reklamdan gelen <strong>Steve Krikris</strong>’in üzerinde yedi yıl uğraştığı ilk uzun metrajı. Bu Yunan filmi, takıntılı, yalnız yaşayan bir garsonun yaşadığı tuhaf macerayı ele alıyor. Kırklı yaşlarda, kendi dünyasında yaşayan garson Renos’un rutini, komşusunun ortadan kaybolmasıyla bozuluyor. Sürprizli hikayesiyle insanı sarsan güzel bir kara film örneği olmuş.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Shadow</em></strong>, <strong>Zhang Yimou</strong>’nun bu başta yeni bir <em><strong>Kaplan ve Ejderha</strong></em> vakası mı dedirten, yine aynı kılıç dövüşü türüne girmekle beraber, aslında hayli farklı yapıda bir film. Muhtelif festivallerden şimdilik 11 ödül toplamış olan Çin, Hong Kong yapımında bir kumandan, Kralın tahtını kurtarmak için kendisine benzeyen bir “gölge kumandan” yetiştiriyor. Ancak hedefine sadık kalması için de onu hep ailesiyle ödüllendireceğini söylüyor. Tablo gibi görüntüleri ve bale benzeri enfes dövüş kareografilerinin dışında usta işi bir kurguyla ilerleyen hikaye, usta yönetmenin hayranlarını yanıltmıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>The Man Who Surprises Everyone</em></strong>, Rusya, Fransa, Estonya ortak yapımı. <strong>Natasha Merkulova</strong> ve <strong>Aleksey Chupov</strong>’un birlikte yönettikleri film, katıldığı festivallerden on üç ödülle dönmüş. Artık son evresine girdiği kanser hastalığından dolayı iki aylık ömrü kaldığını öğrenen Igor, gerçeği kabullenip kendini salar önce, ama karısının ısrarıyla tedavi yolları aramaya başlar. Son çare olarak gittikleri şifacı ona Azraili aldatmak için kılık değiştiren ördekten bahseder. Bundan etkilenir ve Azraili aldatmak için büyük bedeller pahasına kadın kılığına girer Igor. Filmin neredeyse hiç müzik kullanmaksızın dramı aktarışına hayran kaldım doğrusu. Her bir oyuncu görevini başarıyla yerine getiriyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Görülmüştür</em></strong>, <strong>Serhat Karaaslan</strong>’ın üç kısa filmden sonra çektiği ilk uzun metrajı. Bir cezaevinde mahkum mektuplarını okuyup sansürleyen Zakir, bir yandan da yazarlık kursuna gider. Kurstaki bir ödev gereği sansürlediği mektuplardan birinden çıkan, mahkumlardan Recep ve karısı Selma’ya ait bir resmi alır. Bu resim onda takıntıya dönüşecektir. Başrol oyuncusu <strong>Berkay Ateş</strong>’in televizyon yıldızı oluşu beni başta uzak tuttu filmden, ama oyuncu rolün altından başarıyla kalkmış, hem de dizideki tiklerinden sıyrılarak! Ama en güzeli, uzun zamandır seyrine hasret kaldığımız <strong>Füsun Demirel</strong>’i görmekti. İyi, sürprizli bir yapımdı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Kızkardeşler</em></strong>, <strong>Emin Alper</strong>’in <em><strong>Tepenin Ardı</strong></em>’ndan bu yana merakla beklediğimiz filmiydi. Almanya, Hollanda ve Yunanistan’ın da ortak yapımcı olduğu film, farklı yaşlardaki üç kız kardeşin kasabaya besleme olarak gönderilip, orada tutunamayarak geri gelmelerini, yine de tekrar kasabaya dönmek için taşıdıkları hırsı yansıtışlarını yetkin bir dille anlatıyor. Güçlü oyunculuklar ve başarılı mizansenle destekli filmin <strong>Emin Alper</strong>’i de aktör olarak göstermesi güzel bir sürprizdi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Decembers</em></strong> ile <strong>Enrique Castro Rios</strong>’un kişiliğinde alçakgönüllü bir yönetmenle tanışmış olmak büyük bir keyifti. Aslen belgeselci olan ve filmi destekleyen belgesel görüntülerle de bunu bize sık sık hatırlatan yönetmen, bize ABD’nin 1989’daki Panama işgalini ve o işgalde ölen bir gazetecini ruhunun on yıl sonra geri dönerek aile arasındaki huzursuzlukları çözmeye çalışmasını öykülüyor. Bunu yaparken öyle incelikli bir sinema kullanıyor ki yönetmen, sizi alıp o diyarlara götürüyor. Özellikle tüm bir olayı özetleyen yatak odası sekansı beni adeta vurdu. Kadın kilise için hazırlanırken kendi gençliği, oğlunun küçüklüğü ve oğlunun büyük hali aynı odadadır. Anlatılmaz, yaşanır denebilecek bir sahne doğrusu.</p>\r\n<p>&nbsp;</p>\r\n<p>Arkası var. Festival daha bitmedi…</p>\r\n<p>&nbsp;</p>', 1, 62, 'Ara Yazı', NULL, '2019-04-15');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (15, 'ay-j268', 'i-stanbul-film-festivali-nden-notlar-2-baslik', 'İstanbul Film Festivali\'nden Notlar - 2_başlık', 'İstanbul Film Festivali\'nden Notlar - 2', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=267:iff-notlar-2&amp;catid=42:ara-yazilar&amp;lang=tr-TR"><span style="color: #1fa8d1;">İstanbul Film&nbsp;Festivali\'nden Notlar - 2</span></a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;">İlker Mutlu</strong></p>', 20, 62, 'Ara Yazı', NULL, '2019-04-15');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (16, 'ay-j269', 'i-stanbul-film-festivali-nden-notlar-3', 'İstanbul Film Festivali\'nden Notlar - 3', '38. İSTANBUL FİLM FESTİVALİ', '<p style="text-align: center;"><strong><strong>38. İSTANBUL FİLM FESTİVALİ</strong></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>İlker Mutlu</strong></p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p style="text-align: justify;">Bu yıl 38\'incisi yapılmakta olan İstanbul Film Festivali’ni gördüğüm son filmlerle ve ödül töreniyle bitiriyorum artık. Son üç günde, daha çok yerli yapım görmeye çalıştım. Yerli yapımların tümünü görmeyi özellikle planlamıştım oysa. Ama sinemaların arasındaki mesafe, ulaşım zorluğu buna müsaade etmedi.&nbsp;Neticede festivali şunlarla kapattım:&nbsp;<strong><em>Suç Unsuru</em></strong> (Süleyman Arda Eminçe), <strong><em>Aden</em></strong> (Barış Atay), <strong><em>Son Çıkış </em></strong>(Ramiz Matin), <strong><em>Border</em></strong> (Ali Abbasi), <strong><em>Dragged Across Cocrete</em></strong> (S. Craig Zahler), <strong><em>Nebula</em></strong> (Tarık Aktaş).</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Suç Unsuru</em></strong>, <strong>Süleyman Arda Eminçe</strong>’nin ilk filmiydi. Başından geçen trajikomik bir olayı temel alan film, tek mekanda geçmesine rağmen burayı iyi, ekonomik kullanabilen, alçak gönüllü bir yapım. Küfür kullanmaksızın da güldürmenin mümkün olduğunu kanıtlıyor yapım. Aynı evi paylaşan iki arkadaş, bir sabah evleri polis tarafından basılınca ne olduğuna şaşırır. Komiser Baran ve ekibi, aldıkları emir doğrultusunda, evlerinde suç unsuru arayacaklardır. Fakat bu unsurun ne olduğunu iki taraf da bilmez. Genç oyuncular üzerlerine düşeni yaparken, Komiser Baran rolündeki, dizilerdeki şaşkın komik rollerine alıştığımız Bülent Çolak, dram da içeren oyunuyla şaşırtıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Aden</em></strong>, oyunculuktan gelip ve 2015 yapımı olan <em><strong>Eksik</strong></em> ile yönetmenliğe başlayan <strong>Barış Atay</strong>’ın, <strong>Onur Orhan</strong>’ın senaryosundan çektiği bir kıyamet sonrası filmi. Bizde hiç örneği olmayan bir türü denemiş yönetmen. Dişi olanı hamile olan bir çift, yıkıma uğramış bir dünyada yaşanabilir bir yerleşke, “cennet” aramaktadır. Yolları sırlarla dolu, bir nevi iktidar mücadelesi veren iki kardeşin kaldığı bir eve düşer. Dini referanslarla ilerleyen hayli ilginç yapısıyla, oyunculuklardaki çok da göze batmayan zayıflıklar ve kıyafetlerin yıpranmamış, tertemiz görüntüsüne rağmen kendini izlettiriyor film. Belli bir gerilim duygusu içerdiğini de kabul etmeliyim.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Son Çıkış</em></strong>, <strong>Ramin Matin</strong>’in yarışma dışı gösterilen kara komedisi. Bezgin bir mimar büyük şehrin debdebesinden bunalıp İstanbul’dan daha müthiş bir ortam olacağını düşündüğü, güneyde organik tarım yapan bir komüne gitmek üzere havaalanına doğru yola çıkar. Plansız kentsel dönüşümle betona boğulan bir İstanbul semtinde meteliksiz ve telefonsuz kalarak kapana kısılır. Nihayet komüne ulaştığında da karşılaştığı hayal kırıklığıdır. Çıkışsızlık temalı, yine küfre dayanmamasıyla sempati toplayan komedi, Türkiye’deki plansız inşaat endüstrisine de ince eleştiriler getiriyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Sınır&nbsp;</em></strong>(Border):&nbsp;<strong><em>Let the Right One In</em></strong> (Tomas Alfredson, 2018) filminin uyarlandığı tuhaf vampir romanının yazarı <strong>John Ajvide Lindqvist</strong>’in bu defa iki trolün ilginç aşkını anlattığı romanıyla bu filme konu oluyor. Şüphelendiği, kendi cinsinden olduğu için de ayrıca ilgi duyduğu adamı kafaya takan sınır polisi trol Tina, öğrendiği sırların ardından aşkıyla görevinin arasında kalır. Yapım “Nordik kara film” olarak tanımlanıyor. <strong><em>Shelley</em></strong> (2016) ile dikkat çeken yönetmen <strong>Ali Abbasi</strong>, bu filmle En İyi Makyaj ve Saç Tasarımı Oscarı’na aday olmuş, Cannes’da da Belirli Bir Bakış Ödülü almıştı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Adaletsiz </em></strong>(Dragged Across Concrete):&nbsp;<strong><em>Bone Tomahawk</em></strong> (2015) adlı ilk filmiyle festivallerde ilgi gören, övgü alan western roman ve senaryoları yazmış yönetmen <strong>S. Craig Zahler</strong>’in ikinci filmi. Yönetmen, senaryosunu da yazdığı bu bir nevi modern westernde, görevden uzaklaştırılan çaresiz iki polisin bir vurgun yapma çabalarını anlatıyor. Kadroda <strong>Mel Gibson</strong>, <strong>Vince Vaughin</strong>, <strong>Don Johnson</strong>, <strong>Udo Kier</strong> gibi usta, yıldız isimler var. Zaman geçirtiyor ve kimi anları ilginç. Bir <strong><em>Heat</em></strong> (Michael Mann, 1995) değil elbette.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Nebula </em></strong>(Dead Horse Nebula), <strong>Tarık Aktaş</strong>’ın ilk uzun metrajı. Senaryoyu da kendi yazmış. Deneysel bir yapısı olduğu söylenebilecek film herkese hitap etmemekle birlikte, 2018’de Locarno’da Gelecek Vaat Eden En İyi Yönetmen Ödülü almıştı. Küçükken açık arazide bir at ölüsü bulan Hay, o günkü deneyiminden çok etkilenir ve yıllar sonra yaşadığı bir kurban olayı geçmişte yaşadığı bu çocukluk anısının tekrar canlanmasına neden olur.</p>\r\n<p>&nbsp;</p>\r\n<p>Festival boyunca izlediğim filmlerin dökümü burada sona eriyor. Festival sonunda 16 Nisan Salı gecesi Rahmi Koç Müzesi’nde gerçekleşen ödül töreni hayli kalabalık ve eğlenceliydi. Yaşanan kimi aksaklıklar, İFF törenlerinin değişmez konuğu kara kedinin sunuculardan rol çalması, gecenin nazarlığı oldu. 52 filmin yarıştığı festivalin galipleri şöyleydi:</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Uluslararası Yarışma:</strong></p>\r\n<p>Başkanlığını usta yönetmen <strong>Lynne Ramsay</strong>’in üstlendiği jürinin takdiriyle:</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Altın Lale:</strong> <strong><em>Sinekkuşu</em></strong> (Bolsae<em> </em><strong><em>/ </em></strong>House of Hummingbird,<strong><em>&nbsp;</em></strong>Bora Kim), “inceliği, güzelliği, duygusal etkisi ve yetkinliğiyle genç bir kızın dünyadaki yerini ve yaşamında bir pırıltı bulma çabasını çok güzel çizdiği için” aldı. Kore yapımı filmin kadın yönetmeni <strong>Kim</strong>, oldukça heyecanlıydı. Ülkesinde kadın yönetmenlerin film çekmesinin önündeki engellerden bahsetti ve aldığı ödülün belki bu engelleri yıkmada bir adım olacağını söyledi.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Jüri Özel Ödülü:</strong>&nbsp;<strong><em>Ağaçlardan Bahsetmek</em></strong>&nbsp;(Talking About Trees<em>,</em><strong><em>&nbsp;</em></strong>Suhaib Gasmelbari), “başarısızlıklar bazen öyle büyük olur ki umut yeşermek zorundadır; ‘dehşete dair suskunluğu ima ettiği için ağaçlardan bahsetmenin neredeyse suç sayıldığı bir dönem’” gerekçesiyle aldı. Bu filmden önceki yazımda övgüyle bahsetmiştim. Yönetmeninin ve birbirinden heyecanlı oyuncularının törende olmalarını çok isterdim, ama gelememişlerdi.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Ulusal Yarışma:</strong></p>\r\n<p>Başkanlığını <strong>Ümit Ünal</strong>’ın üstlendiği jüri, yarışan 9 filmi değerlendirdi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Altın Lale:</strong>&nbsp;<strong><em>Kız Kardeşler </em></strong>(A Tale of Three Sisters,&nbsp;Emin Alper) hakkıyla aldı. Bu filmden de daha önce bahsetmiştim. Film yurt dışında da ilgi görüyor. Emin Alper’in destek sağlamak için çektiği zorluklar biliniyor. Bu filmle ilk filmini kat kat aştığı da bir gerçek. En İyi Yönetmen, En İyi Özgün Müzik (Giorgos ve Nikos Papaioannou) ve En İyi Kadın Oyuncu Ödülleri de <strong><em>Kız Kardeşler</em></strong>’e gitti. Hatta kadın oyuncu ödülünü kız kardeşlerin üçü (Cemre Ebüzziya, Ece Yüksel ve Helin Kandemir) paylaştılar.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Jüri Özel Ödülü:</strong>&nbsp;<strong><em>Yuva</em></strong> (Emre Yeksan) aldı. Adana Film Festivali üzerine olan yazımda bu filmden detaylıca bahsetmiştim. Hakikaten zor şartlar altında çekilmiş, farklı hikayesiyle de insanı yakalayan bir yapım. <strong><em>Yuva</em></strong>, En İyi Erkek Oyuncu (Kutay Sandıkçı) ve En İyi Görüntü Yönetmeni (Jakub Giza) ödüllerini de aldı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>En İyi Senaryo:</strong>&nbsp;<strong><em>Görülmüştür</em></strong> (Serhat Karaslan) filmi aldı. Daha önce ele aldığım film, aslında basit bir konuyu ele alma şekliyle evrensele taşımayı başarıyordu ve sinemamızda pek girilmeyen, hapishanelerin mektup sansüründe çalışan memurlarına değiniyordu. Film, En İyi Kurgu ödülünü de (Ali Aga) aldı.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Mansiyon:</strong> <strong><em>Aden</em></strong> (Barış Atay)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Ulusal Kısa Film Yarışması:</strong></p>\r\n<p><strong>En İyi Kısa Film: </strong><strong><em>Avarya</em></strong> (Gökalp Gönen) filmi, “kuvvetli atmosferi ve yarattığı özgün karakterler sebebiyle” aldı.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Ulusal Belgesel Yarışması:</strong></p>\r\n<p style="text-align: justify;"><strong>En İyi Belgesel:</strong> <strong><em>Tanrı Göçmen Çocukları Sever mi Anne?</em></strong> (Lusin Bitmez), “yerinden olan bireylerin karşılaştığı zorlukları göze batmayan bir bakış açısı ve beceriyle işlediği; saygıyı eksik etmeyen sıcak bir yaklaşımla, geleceğe umutla uzanarak çocuklar ve ailelerine odaklanıp geniş toplumun ufak bir evrenini çizdiği için” bu ödülü aldı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Sinemada İnsan Hakları Ödülü:</strong></p>\r\n<p style="text-align: justify;"><strong>Ödül:</strong> “Şiirsel olmakla birlikte aynı zamanda insanı düşünmeye sevk edebildiği için” <strong>Enrique Castro Ríos</strong>’ın yönettiği <strong><em>Aralık’ta </em></strong>(Diciembres / Decembers)&nbsp;filmine verildi. Bu filmi önceki yazımda ele almış ve çok etkilendiğimi belirtmiştim.</p>\r\n<p><strong>Mansiyon:</strong> <strong><em>#Dişil Haz </em></strong>(#Female Pleasure, Barbara Miller)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seyfi Teoman En İyi İlk Film Ödülü:</strong><strong>&nbsp;<em>Nebula</em></strong> (Tarık Aktaş)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>FIPRESCI Ödülleri:</strong></p>\r\n<p><strong>Uluslararası Yarışma: <strong><em>Ağaçlardan Bahsetmek </em></strong></strong>(Talking About Trees,<strong><em>&nbsp;</em></strong>Suhaib Gasmelbari)</p>\r\n<p><strong>Ulusal Yarışma: <em>Kız Kardeşler</em></strong> (Emin Alper)</p>\r\n<p style="text-align: justify;"><strong>Ulusal Kısa Film Yarışması: <em>Gümüş</em></strong> (Deniz Telek)</p>\r\n<p>&nbsp;</p>', 1, 62, 'Ara Yazı', NULL, '2019-04-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (17, 'ay-j270', 'i-stanbul-film-festivali-nden-notlar-3-baslik', 'İstanbul Film Festivali\'nden Notlar - 3_başlık', 'İstanbul Film Festivali\'nden Notlar - 3', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=269:iff-notlar-3&amp;catid=42:ara-yazilar&amp;lang=tr-TR"><span style="color: #1fa8d1;">İstanbul Film&nbsp;Festivali\'nden Notlar - 3</span></a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;">İlker Mutlu</strong></p>', 20, 62, 'Ara Yazı', NULL, '2019-04-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (18, 'ay-j285', 'teneke-trampet-baslik', 'Teneke Trampet_başlık', 'Teneke Trampet', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=286:teneke-trampet&amp;catid=42:ara-yazilar&amp;lang=tr-TR"><span style="color: #1fa8d1;">Teneke Trampet</span></a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;">Gülbin Paytar</strong></p>', 1, 62, 'Ara Yazı', NULL, '2020-08-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (19, 'ay-j286', 'teneke-trampet', 'Teneke Trampet', 'TENEKE TRAMPET', '<p style="text-align: center;"><strong>TENEKE TRAMPET</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Gülbin Paytar</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Yönetmen:&nbsp;</strong>Volker Schlöndorff</p>\r\n<p style="text-align: center;"><strong>Senaryo:&nbsp;</strong>Günter Grass (roman), Volker Schlöndorff, Jean-Claude Carriere, Franz Seitz</p>\r\n<p style="text-align: center;"><strong>Görüntü Yönetmeni:&nbsp;</strong>Igor Luther</p>\r\n<p style="text-align: center;"><strong>Sanat Yönetmeni:&nbsp;</strong>Nicos Perakis</p>\r\n<p style="text-align: center;"><strong>Müzik:&nbsp;</strong>Maurice Jarre</p>\r\n<p style="text-align: center;"><strong>Kurgu:&nbsp;</strong>Suzanne Baron</p>\r\n<p style="text-align: center;"><strong>Oyuncular:&nbsp;</strong>Mario Adorf, Angela Winkler, David Bennent</p>\r\n<p style="text-align: center;"><strong>1979 / 142’, B. Almanya, Fransa, Polonya, Yugoslavya</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p style="text-align: justify;">Haziran ayı içinde sosyal medyada durmaksızın akan binlerce ileti arasında bir an için görünüp kaybolan bir haber sinema meraklılarının dikkatini çekmiş olmalı. Haber şöyleydi: “<em>Alman yönetmen </em><strong>Volker Schlöndorff</strong><em>’</em><em>un</em><em></em><em>&nbsp;yabancı dilde film Oscar’ını kazanan <strong>Teneke Trampet</strong> filminde birlikte çalıştığı Slovak görüntü yönetmeni </em><strong>Igor Luther</strong><em> 7 Haziran 2020 tarihinde, 77 yaşında hayata gözlerini yumdu.</em>”</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Teneke Trampet</em></strong> (Die Blechtrommel, Volker Schlöndorff, 1979) önemli bir edebiyat yapıtının başarılı sinema uyarlaması olarak kabul edilen, içerdiği hayli rahatsız edici bazı ögeler nedeniyle zamanında birçok ülkede yasaklanmış ve bazı yerlerde ancak mahkeme kararları sonrası serbest bırakılmış, ortak yapımcı ülkelerden ikisinin (Batı Almanya ve Yugoslavya)&nbsp;bugün artık sahnede bile olmadığı bir film. Ülkemizde ise 1980’den kısa süre sonra olmasına karşın şaşırtıcı biçimde gösterime girerek izlenme olanağı bulmuş, şanslı bir sinemasever kuşak üzerinde önemli etkiler bırakmış bir yapım. Böylesi bir filmin görüntü yönetmenliğini yapmış bir ismin kaybı da sinema sektörü için önemli elbette. Bununla birlikte, dünyadaki otoriter yönetim örneklerinin kaygıyla izlendiği günümüzde, aradan geçen yıllarla sinema tarihinin sayfaları arasına sıkışan bu filmin tekrar hatırlanmasına vesile olması önemli sayılabilir düşüncesindeyiz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Teneke Trampet</em></strong>&nbsp;bize bir yandan 1920’lerin sonlarında Danzig’de ‘iki baba ile bir anneden oluşan’ bir aileye doğan ve ilk gençliğini Nazilerin iktidar yolunda yükselişe geçtiği 1930’lu yıllardan, düşüşün başladığı 1940’ların ortalarına kadar olan dönemde geçiren küçük Oskar’ın hikayesini anlatırken, diğer yandan da o günün toplumuna kuvvetli bir eleştiri getiriyor. Hikayenin başlarında, içine doğduğu toplumun dürüstlük, aile ve bireysel çıkarlar gibi konulardaki çöküntüsünü erken yaşta gören küçük Oskar’ın, köklerinin dayandığı sağlam yapılı köylü sınıfını temsil eden büyükannesine duyduğu bağlılığı kaybetmemekle birlikte, yaşadığı zamanın kendisine dayattığı yaşam biçimini reddederek ‘büyümemeye karar vermesine’ tanık oluyoruz. Bu süreçte, masum görünüşünün ardında gizlenen kötücül ve hayli ürkütücü yanını da bize göstermekten çekinmeyen Oskar’ın elinde, etrafında olan bitene karşı kullandığı sadece iki enstrüman vardır artık: Camın, çerçevenin aşağı inmesine sebep olan yüksek perdeden tiz sesi ve kimse ilgilenmese de boynuna asıp durmaksızın çaldığı teneke trampeti.</p>\r\n<p>&nbsp;<img src="/images/arayazilar/teneke_trampet/TT3.jpg" alt="TT3" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Nazi politikalarının Alman halkı tarafından kabul edilmesinde, Nazi partisinin yükselişinde ve iktidarının tüm dünyayı etkiler hale gelişinde, olacakları sezmelerine karşın sessiz kalan ya da etkisiz teneke trampetlerine sıkı sıkıya sarılmaktan başka bir şey yapmayan Alman entelektüellerinin de sorumluluğu vardır kuşkusuz. Dolayısıyla film hakkında yazılanların pek çoğunda Alman orta sınıfının eleştirildiği görüşü yer alsa da filmin asıl eleştirisinin orta sınıfın yanı sıra ve hatta ondan fazla, bir kısım sanatçı ve aydına yöneldiği görüşündeyiz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kahramanımızın, örneğin, bir itirazı vardır var olmasına da olanları değiştirmek için çabalamaya gücü ve daha önemlisi niyeti var mıdır, işte orası hayli şüphelidir. Çevresinde itiraz etmek istediği her olaya çığlık atarak ve trampet çalarak tepki gösteren Oskar’ın başlangıçta yarattığı ufak karışıklıkların zamanla kanıksanması ve gördüğü haşarı çocuk muamelesiyle olaylar üzerinde etkili olamaması filmin temel açmazlarından biri olarak öne çıkmaktadır. Oysa ki bu duruma zamanla Oskar da alışır, neredeyse işine gelir: itiraz yöntemi etkisizdir belki ama en azından kimse onu ‘hiçbir şey yapmamakla’ suçlayamaz. Hatta bir süre sonra tiz çığlığını bile sadece kendisi gibi büyümeyen sanatçı sevgilisine güzellemeler yapmak için kullanır artık.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çocuk görünümünün yarattığı korunaklı duvarların ardında kendi bencilliğini yaşamayı tercih eden Oskar, büyümeyi reddederken etrafında gördüklerine karşı etkili bir tutum takınmayı reddeder aslında. Cinsellik de dahil, bir yetişkinin her türlü deneyimine hayatında yer vermesine karşın, bunların sorumluluğunu bir yetişkinden beklenecek şekilde üstlenmeyi düşünmez. Çok sevdiği Musevi oyuncakçıyı ölüme sürükleyen politik rüzgarlar onu sarsmaz mesela. O, yırtılan teneke trampetinin yerine, yağmalanmış dükkanın rafında kalan son yeni trampeti uzanıp almaktan memnundur. Yahut gerçek babası olmasından ‘amcasının’ kendisi yüzünden diğer Nazi karşıtı direnişçilerle birlikte ölüme gitmesinde bir vicdan muhasebesi yaşamaz, onun derdi trampetini tamir ettirebilmektir. Kamera bir bağ kurma arayışıyla sık sık Oskar’ın yüzüne döner, filmin neredeyse her anında onu takip eder, ancak bu tekinsiz yüzde bir duygu ya da düşünce okumamız pek mümkün olmaz.</p>\r\n<p>&nbsp;<img src="/images/arayazilar/teneke_trampet/TT1.jpg" alt="TT1" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">O dönem Danzig toplumunun tipik bir mensubu olan annesi, tiksindirici yöntemlerle yakalandığını gördüğü ve aslında ne olduğunu gayet iyi bildiği yılan balıklarını yemeyi -iktidarın politikalarını ve nimetlerini kabullenmeyi- başlangıçta reddetse de aynı balıklar Nazi Partisi üyesi eşi tarafından pişirilip şık bir sofrada, porselen tabakla sunulduğunda afiyetle yemeyi pekala kabul eder. Hatta bu kabulü öylesine ileri götürür ki bir kez yemeye başlayınca kendini durduramaz ve yılan balığı konservelerini doyumsuz bir iştahla şuursuzca tüketerek, tıpkı Alman toplumu gibi kendi kendinin mahvına sebep olur.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Oskar annesinin ölümüne üzülür elbette ama üzüntüsü eve gelen genç güzel yardımcıyla ilk kez yaşadığı cinsellik girişimlerine veya bu konuda rakip saydığı babasını kıskanmasına engel olacak kadar derin değildir. (Aynı film bugün çekilse böylesi bir rolün küçük yaşta bir oyuncuya verilmesine itiraz edenler de olur mutlaka diye düşünmeden edemez insan.)</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bir ara, yine kendisi gibi büyümeyi reddeden bir grup sanatçıyla birlikte, artık bir sirk gösterisinin parodisi olmaktan öte anlam taşımayan ve sadece Nazilerin eğlencesine hizmet eden gösteri dünyasına katılmayı da pek sorgulamadan kabul eder.</p>\r\n<p>&nbsp;<img src="/images/arayazilar/teneke_trampet/TT2.jpg" alt="TT2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Oskar, belki de ilk gerçek dehşeti sevgilisini savaşa aniden kurban verdiğinde yaşayacak, sonrasında döndüğü aile ocağında da Almanya’nın yenilgisini, eve giren Rus askerleri kendi hatası sebebiyle babasını öldürdüğünde kesin olarak anlayacaktır. Nihayet her şeyin sona yaklaştığı, kendisini çocuk bırakan baskı rejiminin düşüşe sürüklendiği bu anda teneke trampetini de babasıyla birlikte mezara koyarak terk edecek, büyümeye karar verecektir. Ancak bunca reddetme, kaçış ve yıkımın ardından başlayan yeni büyüme dönemi için acaba biraz fazla geç kalınmamış mıdır? Yaralı Oskar, filmin başladığı yerde, Avrupa kırsalının patates tarlaları içinde arabayla taşınırken izleyicinin zihnine de bu soruları bırakarak uzaklaşır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmin başarısında yönetmen <strong>Volker Schlöndorff</strong>’un, film çekildiği sırada henüz 11 yaşında olan ve baş kahraman Oskar’ın tüm yükünü şaşırtıcı bir başarıyla omuzlayan oyuncu <strong>David Bennent</strong>’le uyumlu birlikteliğinin rolü büyük olsa gerek. Aradan geçen 41 uzun yıl sonra hala diri kalmasının ve söyleyecek sözü olmasının ise dayandığı edebi eserin gücünden olduğu kadar filmin oluşturduğu görsel dilin etkisinden de kaynaklandığı şüphesizdir. Sinemaya aktarılması çok zor olan bu yapıtı, bir daha bir araya gelmesi olanaksız oyuncu kadrosu ve teknik ekibi ustalıkla yöneterek sinemaya aktarma cesaretini gösterenlere saygı duymamak elde değil.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><strong><strong>Igor Luther</strong></strong></strong>’in ölümü nedeniyle de olsa on yıllar öncesinden gelen bu benzersiz filmi bir kez daha hatırlarken, tüm ‘itirazı olanlara’ gönüllerince gelişip cesaretle büyüyecekleri özgür zamanlar dileriz.</p>\r\n<p>&nbsp;</p>', 98, 62, 'Ara Yazı', '/images/arayazilar/teneke_trampet/TT3.jpg', '2020-08-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (20, 'ay-j292', 'golgeler-i-cinde', 'Gölgeler İçinde', 'GÖLGELERİN İÇİNDEN GERÇEĞE YOLCULUK', '<p style="text-align: left;"><strong>GÖLGELERİN İÇİNDEN GERÇEĞE YOLCULUK</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><strong>Zehra Yiğit - Perihan Taş Öz</strong></p>\r\n<p style="text-align: right;"><strong>Ekim 2020</strong></p>\r\n<p>&nbsp;<strong>&nbsp;</strong></p>\r\n<p style="text-align: justify;"><strong>Erdem Tepegöz</strong>’ün kendine has bir biçimde gerçekçi atmosferi ile öne çıkan filmi <strong><em>Zerre</em></strong> (2012), hem Türkiye’de hem de yurtdışında kendisinden övgülerle söz ettirmişti. <strong><em>Zerre</em></strong>, ana karakteri Zeynep özelinde maduniyet kavramını tartışmaya açarak, madunların gündelik yaşamlarına, onların içinde bulundukları toplumsal tahakküm ve tabiiyet ilişkilerine bakarken; aynı zamanda kapitalizm eleştirisini de elden bırakmıyordu. Üstelik bu eleştiriyi yaparken, bir yandan kapitalizmin insan emeği üzerindeki sömürüsünü sınıf, direniş biçimleri, ötekilerin dayanışması gibi bağlamlarda ele alırken; &nbsp;diğer yandan doğa üzerindeki sömürüsünü de kentsel dönüşüm üzerinden aktarıyordu. Ve tüm bu yönleri ile <strong><em>Zerre</em></strong>, çok yönlü bir sistem eleştirisi niteliği taşıyordu.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto1.jpg" alt="Foto1" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Tepegöz</strong> ikinci filminde yine bir sistem eleştirisine soyunurken bu kez sinemasal söylem anlamında daha farklı bir dünya kuruyor. Distopik filmlerde sıklıkla yer alan pek çok türsel kodu içinde barındıran <strong><em>Gölgeler İçinde </em></strong>(2020); gözetleme, disiplin toplumu, panoptikon, disipliner iktidar, pasifleştirilmiş beden, biyo-iktidar gibi Fukolidyen kavramları Türkiye sinemasının gündemine taşıyor. <strong>Michel Foucault</strong>, modern toplumda değişen iktidar anlayışını <strong><em>Hapishanenin Doğuşu</em></strong> adlı eserinde <strong><em>Görülmeden Gözetim Altında Tutan Hapishane Sistemi</em></strong> (1992, 245-289) adlı bölümde analiz etmiş ve bu yeni iktidarın metaforu olarak panoptikon kavramını kullanmıştır. 1785 yılında mimar <strong>Jeremy Bentham</strong> tarafından inşa edilen panoptikon (bütünü gözetlemek anlamına gelir) bu düzenlemenin mimari biçimidir. “Görülmeden gözetim altında tutmaya olanak veren düzenleme, sürekli görmeye ve hemen tanımaya olanak veren mekansal birimler oluşturmaktadır” (Foucault, 1992, 251). Eğer gözetleyenler kendilerini gizliyor ve görünmüyor, gözetlenenler ise kendilerini gözetleyeni göremiyorlarsa bu durumda sürekli gözetlendiklerini hesaplamak zorunda kalır ve kendi kendilerine oto kontrol uygularlar. Foucault’ya göre (1992, 251) “görünürlük bir tuzaktır.” Böylece görünmeden gözetleyen iktidar, kendi statükosunu sağlamlaştırarak, otoritesini sürekli kılabilir. <strong>Foucault</strong>, bu sistemi bir distopya olarak görür ve bunu, gözün iktidarı olarak tanımlar.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Gözün İktidarı-İktidarın Gözü: <em>Gölgeler İçinde</em></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Klasik modernleşme kuramcılarının öne sürdüğü; daha iyiye, daha güzele, bütüncül, doyurucu ve uyumlu bir toplumsal düzene modernleşme ile ulaşılacağı tezinin II. Dünya Savaşıyla beraber Auschwitz’den Hiroşima’ya kadar yaşanan kitlesel acılarla çökmesi ile ütopya distopyaya dönüşür. Aydınlanma ile yaşanan araçsal aklın yükselişi ile kapitalizm, akıldışı yeni baskı mekanizmaları yaratır. Toplumsal yaşamın bütün alanlarında hissedilen tahakküm, bireysel özgürlükleri yok eder. <strong><em>Tek Boyutlu İnsan</em></strong> adlı kitabında, modern kapitalist toplumdaki üretkenliğin bireyin özgürlüğünü yok ettiğini, barışın, bir gözdağı olarak savaş ile sağlandığını ve baskı ile sürdürüldüğünü söyleyen <strong>Herbert Marcuse</strong> (1964, Giriş: 9-10), çağdaş toplumların yeteneklerinin büyük olmasının, bu toplumların bireyi denetleme mekanizmalarının gündelik alanı dahi kapsayan, geniş bir alanda yapılandırılmasından kaynaklandığını belirtir. Pek çok distopik bilimkurgu romanı ya da filmi bu noktadan hareketle geleceğin nasıl olacağına dair endişe ve korkuları olumsuz senaryolar eşliğinde anlatır; bugünün toplumsal, ekonomik, kültürel, ideolojik ve bilimsel pek çok çıkmazına çözüm olabilecek başka dünyalar yaratarak yanıt vermeye çalışırlar. Bilimkurgu distopyaları, bu yönü ile özünde ciddi sistem eleştirileri barındıran bir tür olarak ayrı bir önem arz ederler.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto2.jpg" alt="Foto2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bağımsız bilimkurgu distopyalarından biri olarak sayılabilecek <strong><em>Gölgeler İçinde</em></strong>, sistemin kontrol ve tahakküm altına aldığı edilgenleşmiş, gözetimi kabul etmiş insanlara; bu otoriter iktidar ağından kurtulmanın, yani özgürleşmenin olanaklı olduğunu hatırlatır ve seyircisine bu olanağı bir direniş biçimi olarak sorgulatmak ister. Başrollerinde <strong>Numan Acar, Vedat Erincin, Ahmet Melih Yılmaz, Emrullah Çakay</strong> gibi oyuncuların yer aldığı film, ilkel bir teknolojinin hakim olduğu bir maden ocağında çalışan işçilere odaklanıyor. Filmde kameraların 7/24 takip ettiği köle gibi çalıştırılan işçilerden biri, bu kontrol ve denetim mekanizmasını makinistin de desteği ile sorgulayarak, sisteme karşı çıkar. Böylece kendisinin ve arkadaşlarının özgürleşme sürecini başlatır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Gürcistan’ın bir maden kasabasında beş haftada çekilen <strong><em>Gölgeler İçinde</em></strong>, bağımsız bir bilimkurgu-distopya örneği olarak dikkat çekerken, filmsel anlatının belki en etkileyici kısmı mekan kullanımı… <strong>Tepegöz</strong>’ün titiz bir arayış sonucunda tercih etmiş olduğu bu mekan, endüstri devriminin karanlık atmosferini hatırlatıyor. Malzeme olarak demirin ağır bastığı, renk olarak soğuk yeşil ya da kırmızıların hakim olduğu bir görsel atmosfer üzerine yapılandırılan mekan tasarımı, griliklerin ağır bastığı kapalı ya da sürekli yağışlı olan karanlık bir hava ile destekleniyor. Bu mekanik ortam, ses kullanımı ile de betimlenmeye devam ediyor. Böylece hikayede her kapı açıldığında duyulan keskin gıcırdama sesinden, fabrikadaki makinelerin sesine kadar her unsur, bu metalik atmosferi tamamlayan sinemasal söylem öğelerine dönüşüyor. Mekan, içerisinde çalışan işçilerin de makineleştiklerine dair çağrışıma kolayca izin veriyor. İşçilerin üzerine konumlanmış olan, onları gözetleyen kameralar ile iktidarın, işçilerin üzerinde konumlanışı gösterilirken, bu sistem içerisinde onların kıstırılmışlıklarıyla beraber hapsolmuşluk imgesi de filmin tamamına yayılan bir metafora dönüşüyor.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto3.jpg" alt="Foto3" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto4.jpg" alt="Foto4" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Mekan içerisinde anlatının karakterlerinin konumlanışı da bu klostrofobik ortamı desteklemeye devam ediyor. Filmin ana karakteri gibi tüm karakterler bu mekan içerisinde yalnız konumlandırılarak, onların güçsüzlüklerine, yalnızlıklarına, çaresizlerine gönderme yapılıyor. Bu sistemde, işçilerin ailelerine, çocuklarına, arkadaşlık ilişkilerine ya da gündelik yaşamlarındaki herhangi bir eğlenceye yer verilmezken, kendilerine ait özel bir yaşam alanlarının olmadığı, yatak odasından yemekhaneye kadar her yerde gözetlendikleri görülüyor. Sürekli yalnız olarak hareket eden karakterler, bu gri soğuk mekanda sadece “yaşamak için yaşayan”, tek boyutlu ve itaatkar insanlar olarak çiziliyorlar. Diğer yandan bu durum modern iktidarın egemen olması anlamına da geliyor. İktidarın insanları bireyselleştirmesi, onların gözetim altında tutulmasını ve cezalandırılmasını da mümkün kılıyor. Bu yönleri ile yazının başında belirttiğimiz gibi, <strong><em>Gölgeler İçinde</em></strong>’nin distopik film türünün ortak anlatısal kodları ile uyumlu olduğu ve yönetmenin bu atmosferi başarılı bir biçimde yaratmış olduğu söylenebilir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Gelelim filmin hikayesine. Makine sesleri ile açılan filmin ilk görüntülerine, karanlık, klostrofobik bir maden ocağında hareket halinde olan bir aracın içinde bulunan yorgun maden işçilerinin yüzü yansır. İşçiler çalışırlarken, maden ocağında bir patlama olur ve orada bulunanlar bu patlama ile savrulurlar. Seyircinin kulakları ve ruhunu acıtan bir uğultu eşliğinde işçilerin kaçışmalarıyla ekran kararır. İşçilerin yaşam ve ölüm arasında hapsolmuş olduğu bu daracık alandaki var olma mücadeleleri, belirgin bir biçimde kendini hissettirir.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto5.jpg" alt="Foto5" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Hemen ardından bir göze yakın çekim ile açılan sahnede ana karakterin sağlık durumu bir makine tarafından kontrol edilir. Biyo-iktidarın insan bedenine bir makine gibi bakışı ve onun beden üzerindeki disipliner yapısı bu sahne aracılığı ile vurgulanır. Bu kontrol sahnesinde, muayene olmayı bekleyen “sessiz yığını” oluşturan işçilerin korkak ve endişeli hali, tepelerindeki kameralar aracılığıyla sistemin bedenler üzerindeki tahakkümünü açık bir biçimde gözler önüne serer. Yaklaşık ilk yedi dakikada, yönetmenin nasıl bir atmosfer kurduğu ve film söyleminin genel çerçevesi böylece çizilmiş olur. Film anlatısı, bundan sonrasında bu distopik evrenin sınırlarını çizen sistem karşısında bir direnişin mümkün olup olmadığı ya da nasıl olacağı sorularının izini sürer.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ancak tam da bu kısımda –elbette yönetmenin bilinçli bir tercihi ile– bu iz sürmenin üstü kapalı yollarla sürdürüldüğü görülür. Bu üstü kapalılığın seyirci açısından kimi kez bazı boşluklara karşılık gelebileceği söylenebilir. Örneğin: Filmdeki iktidar-göz kim? Ne üretiyor? İnsanları nasıl bir cezalandırma-ödül sistemi ile normalleştiriyor? Cevapları net verilmeyen bunun gibi sorulara filmin devamında yeni sorular da ekleniyor. Örneğin sürekli izlenen fabrika işçilerine verilen cezalar listesi şöyle; yemek vermemek, suyu kesmek ve sarsıntı vermek. Buna ek olarak gözle görülür tehditlerden biri de ne anlama geldiği tam anlaşılamayan sağlık kontrolü sırasında hissedilen sistemin dışına itilme korkusu. &nbsp;Haklı olarak ortaya çıkan: Peki bu işçiler, bu sistemden neden kaçamıyorlar? Onları burada kalmaya zorunlu kılan şey nedir? Bunun gibi sorular karşılıksız kalıyor. Dahası işçilerin ne ürettikleri, ürettikleri ürünü kimin kullandığı, yeni dedikleri işçilerin nereden geldikleri gibi soruların yanıtı da filmde bulunmuyor. Filmde karakterlerin bir kimlikleri olmadığı için -pek çok distopik filmde olduğu gibi- isimleri de yok. Karakterlerin “yeniler”, “benim çocuk”, “tamirci” gibi -kendini işaret etmeyen- isimlere sahip olmaları aynı zamanda, filmin köle gibi çalışan işçi sınıfı alegorisi yapmasına da izin veriyor. Filmsel anlatının karakterleri her ne kadar “gölgeler içinde” olsalar da kendileri de birer gölge durumunda. Filmde gölge ironik bir şekilde varlığın kanıtı olsa da, bu insanların varlıklarını bulmaları, bir anlamda gerçeğe ulaşmaları, bilinçlenmeleri ve sistemi yıkmaları ile mümkün görünüyor. Filmin finalinde ana karakterlerin özgürlüklerine ulaşmaları sonrası yaşadıkları sevinç ve bir tehdidin ortadan kalkması olarak okunabilecek yanan fabrika ekrana tüm gösterişi ile yansıyor ve yönetmen izleyiciyi bu anın keyfini çıkarmaya davet ediyor. Bunu bir kez başaran insanların, kendileri dışında ezilen insanların varlıklarını fark ettikleri anda, bu direnişin kolektif bir eyleme dönüşüp dönüşemeyeceği ya da herkes için kurtarıcı olup olamayacağı sorusu beliriyor. Ancak görüyoruz ki bu başarının ardından distopya evreni tekrar kuruluyor, makineleşen sesi izleyici tekrar duyuyor.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/arayazilar/GOLGELER_ICINDE/Foto6.jpg" alt="Foto6" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sonuç niyetine…</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Türkiye’de 2000 sonrası bağımsız sinema tartışmaları kapsamında gerek akademisyenler, gerekse yönetmenlerin kendileri tarafından dile getirilen en önemli kavramlardan biri “kişisel sinema”dır. Bağımsız sinema kavramının toplumsal niteliğine dair yapılan değerlendirmelerden farklı olarak, kişisel sinema kavramı yönetmenlerin film yapma biçimlerindeki “kendine has” öğelere odaklanmaktadır. Bu kendine haslık, her yönetmende farklı bir söylemle şekillenmektedir: <strong>Nuri Bilge Ceylan, Zeki Demirkubuz, Semih Kaplanoğlu, Reha Erdem, Yeşim Ustaoğlu, Pelin Esmer, Derviş Zaim</strong> ve beraberinde birçok yönetmen bu kişisel sinemanın farklı ve nitelikli örneklerini vermeye devam etmektedirler. Bu yönetmenlerin filmlerinde belirli tema ve kavramları, kendine has bir tutarlılık ve titizlikle ele aldıkları ve kişisel sinema yolculuklarıyla bu tema ve kavramları yeniden anlamlandırdıkları görülmektedir. <strong>Erdem Tepegöz</strong>, ilk filmi <strong><em>Zerre</em></strong> ile hem sınıfsal hem de toplumsal cinsiyet bağlamında sınırları oldukça katı çizilmiş daracık bir alana sıkışan Zeynep’in hikayesini kendine özgü bir üslupla, etkileyici bir biçimde aktarmıştı. Üstelik bunu yaparken yalın bir söylemle ana karakteri Zeynep özelinde hem onun gündelik yaşamının sıradanlığını, hem de bu sıradanlığın acımasızlığını içinden çıkılamaz bir kısır döngü olarak anlatmayı da başarmıştı. <strong>Tepegöz</strong>, <strong><em>Gölgeler İçinde</em></strong>’de ise benzer bir çıkışsızlığı bu kez çok daha ideolojik bir çerçeveden sunuyor. <strong><em>Zerre</em></strong> filminde izleyiciyi bildiği ancak çoğu kez görmezden geldiği bir dünyaya misafir ederken, bu filminde ise bir anlamda aslında herkesin kendisinden bir parça bulabileceği ve bir şekilde içinde konumlandırıldığı bir sistem hikayesi ile seyircisinin bir yüzleşme yaşamasını ve sorgulama içine girmesini istiyor. <strong>Tepegöz</strong>’ün sinemasına has tanımlanabilecek, her iki filmde de tutarlılık gösteren en önemli öğe atmosfer yaratmaktaki başarısı. <strong><em>Zerre</em></strong>’ de kentin gölgesinde yaşayan ve kendisine yer bulamayan Zeynep’in dünyası ne kadar gerçekçi bir atmosfer içinde sunulmuş ise, <strong><em>Gölgeler İçinde</em></strong>’ de sistemin gölgesinde yaşayan insanların sıkışmışlığı yine başarılı bir distopik atmosfer içerisinde, bilimkurgu öğeleri de eklenerek aktarılıyor. <strong>Tepegöz</strong>, aynı zamanda Türkiye sinemasında örneklerine çok az rastlanan farklı bir türsel anlatıyı da bu ülkenin sinema tarihine kazandırmış oluyor. Her iki filmin atmosferi de önce huzursuzluk yaratıyor, ardından direnmenin ipuçlarını naif bir biçimde izleyicisine fısıldıyor. Kentte Zeynep’in üzerine düşen gölge, bu kez bilmediğimiz bir mekanda çeşitli toplumsal-ideolojik kodlarla örülmüş bir sistemin içinde sıkışmış kalmış, adını dahi bilmediğimiz insanların üzerine düşüyor. Bu karanlık gölgeyi dağıtmanın yolu, önce onu tanımak, sonra sorgulamak, daha sonra da değiştirmeye hazır olmaktan geçiyor. <strong>Tepegöz</strong>, ikinci filminde de aynı tavrını koruyup, bir yandan umutsuzluğun resmini çizerken, bir yandan da umudun nereden, nasıl doğacağı üzerine düşünmemiz gerektiğini bir sorumluluk olarak hatırlatıyor.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kaynakça</strong></p>\r\n<p>Foucault, M., (1992). Hapishanenin Doğuşu, Çev.: M. A. Kılışbay, İstanbul: İmge Yayınevi.</p>\r\n<p style="text-align: justify;">Marcuse, H., (1964). One-Dimensional Man. U.S.A: Beacon Pres.</p>', 1, 62, 'Ara Yazı', '/images/arayazilar/GOLGELER_ICINDE/Foto1.jpg', '2020-10-26');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (21, 'ay-j293', 'golgeler-i-cinden-gercege-yolculuk', 'Gölgeler İçinden Gerçeğe Yolculuk', 'Gölgeler İçinden Gerçeğe Yolculuk', '<p style="font-size: 10pt;"><a href="index.php?option=com_content&amp;view=article&amp;id=292:golgeler-icinde&amp;catid=42:ara-yazilar&amp;lang=tr-TR"><span style="color: #1fa8d1;">Gölgeler İçinden Gerçeğe Yolculuk</span></a></p>\r\n<p style="font-size: 10pt;"><strong style="font-size: 10pt;"><strong>Zehra Yiğit - Perihan Taş Öz</strong><br /></strong></p>', 1, 62, 'Ara Yazı', NULL, '2020-10-26');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (22, 'ay-j298', 'soylesi-umut-demirci-ile-yardimci-yonetmenlik-uzerine', 'Söyleşi: Umut Demirci ile Yardımcı Yönetmenlik Üzerine', 'SÖYLEŞİ: UMUT ÖZDEMİRCİ İLE YARDIMCI YÖNETMENLİK ÜZERİNE', '<p><strong>SÖYLEŞİ: UMUT ÖZDEMİRCİ İLE YARDIMCI YÖNETMENLİK ÜZERİNE</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><strong>Özgür Erdi Akbaba</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Umut Özdemirci</strong>’yi kamera arkasındaki yardımcı beyin, sinemanın gerçek emekçilerinden diye adlandırırsak yanlış olmaz diye düşünüyoruz. <strong>Russell Crowe</strong>’un başrolünü oynadığı ve yönettiği <strong><em>Son Umut </em></strong>(Russell Crowe, 2014) filminde büyük bir deneyim yaşadı. Uluslararası bir iş olan <strong><em>One Night in İstanbul</em></strong> (James Marquand, 2014), <strong><em>Annemin Şarkısı </em></strong>(Erol Mintaş, 2014), <strong><em>Çekmeceler</em></strong> (Caner Alper, Mehmet Binay, 2015) ve ses getiren yerli yapımlardan <strong><em>Organize İşler: Sazan Sarmalı </em></strong>(Yılmaz Erdoğan, 2019) filmlerinde yine kamera arkasındaydı. Ayrıca son dönemlerde dijital platformlarda dikkat çeken <strong><em>Bir Başkadır</em>, <em>Atiye</em>, <em>Yeşilçam</em>, <em>10 Bin Adım</em></strong> gibi çok beğenilen projelerde de görev aldı. Kısa bir zaman diliminde güçlü projelerde yer almanın doğru zamanda doğru işleri başarıyla yürütmek sayesinde gerçekleştiğini düşünerek <strong>Umut Özdemirci</strong>’yi tanımak istedik. Söyleşimizi kabul edip bizi kırmadığı için teşekkür ederiz.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Söyleşi_Umut_Özdemirci_ile/Resim1.jpg" alt="Resim1" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Sinema ile yolunuzun kesişmesi nasıl gerçekleşti?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> <strong><em>Dawson’s Creek</em></strong> dizisi ile başladı diyebilirim, dizideki ana karakterimiz sinema-televizyon okuyup sektöre atıldıktan sonra 2 yıl içinde ünlü bir yönetmen ve esas kızların vazgeçilmez, kötümser ama karizmatik sevgilisi olup çıkıyordu. Ben de o zamanlar yeteri kadar <em>grunge</em> dinlediğim ve <strong><em>Trainspotting </em></strong>(Danny Boyle, 1996) filminden ezbere replikler bildiğim için bana uygun olduğunu düşündüm. Hem kızları hem de entelektüel çevreyi etkilerim, diye bir düşünceye sahip 17 yaşında bir çocuk başka ne isterdi ki?</p>\r\n<p style="text-align: justify; text-indent: 30px;">Sinemada çalışmanın benim için vazgeçilmez tarafı her işin farklı olması: ekip, mekânlar… Her işte yeni bir şey öğrenmeye, yeni bir hikâye duymaya en açık alan olması diye söyleyebilirim.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Yardımcı yönetmen ne yapar? Ders kitaplarındaki tanımın dışında bize neler söyleyebilirsiniz? Yardımcı yönetmenlik görevi ne kadar önemlidir? Genç yönetmen adaylarına kariyerlerinin başlangıcında yardımcı yönetmenlik önerir misiniz?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Yardımcı yönetmeni, yönetmenden sonra görüntü yönetmeni ile seti paylaşan biri olarak düşünüyorum. Görüntü yönetmeni teknik ekibin başıysa, yardımcı yönetmen de setteki diğer tüm ekiplerin başındaki kişi olarak görülebilir. Setin düzgün ilerlemesini, çekim programına uyulmasını, oyuncuların hazırlığını, sanat, set vb. tüm ekiplerin koordine bir şekilde hareket etmesini sağlayan reji ekibinin başı olarak görev alıyor.</p>\r\n<p style="text-align: justify; text-indent: 30px;">Sette ekip yönetmenin yanı sıra iyi bir iletişim becerisi de olması elzem elbette. Setin kaotik ortamında -illa ki kaotik bir yere doğru evriliyor- uzun saatler çalışmanın sonucunda yorulmanın da etkisiyle set insanları tartışmayı hiyerarşik baskı unsuru haline getirebiliyor. Böyle anlarda iyi bir yardımcı yönetmenin “5 dakika ara” demesi bile setin o anki durumunu pozitife döndürebiliyor. Kanımca, bir çekim programı yapmanın yanında, iletişimi güçlü bir yardımcı yönetmen her setin altından kalkabilir.</p>\r\n<p style="text-align: justify; text-indent: 30px;">Yönetmen olmak isteyenler için; evet, yardımcı yönetmenlikten yönetmenliğe geçiş Türkiye’de çoğunlukla uygulanan bir sistem. Fakat bunun yönetmenlik isteyen bireyin tercihleriyle ilgisi olduğunu düşünüyorum. Işıktan, kameradan, setten, kostüm gruplarından da yönetmenlik mesleğine geçiş yapanlar var. Yegâne önerim hiç sete çıkmadan yönetmen olmamak üzerine olabilir. Kâğıtta yazılan her şey kamera önünde gerçeğe dönüşmeyebiliyor ya da farklı şekilde gözükebiliyor. Bunun önüne geçmek için set tecrübesi çok önemli.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Türk sinemasının son yıllarda uluslararası film festivallerinde görünürlüğünün artmasıyla yükselişe geçtiği konuşuluyor. Siz bu görüşe katılıyor musunuz?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Ben çalıştığım alanda festival filmleriyle haşır neşir değilim, yabancı platformların Türkiye’ye girmesiyle, kaliteli iş gücü ve yabancılar için ucuz yapım masrafları sayesinde Türkiye’deki film sektörünün büyüyeceğini söyleyebilirim, en azından 5 yıldır benim gözlemlerim bu yönde. Festivale gitmeyeli çok oldu, bu yüzden buna fason bir cevap vermek istemem. Türk sineması hakkında yorum yapamayacağım.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> <strong>S<em>on Umut</em></strong> filmiyle uluslararası bir projede yer aldınız. Uluslararası büyük bir prodüksiyonda yer almak hangi farklı deneyimleri kazandırdı?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Profesyonellik. Yabancı ekiplerin gerek sendika kuralları gerekse güvenlik önlemleri bize nazaran daha nitelikli. Daha doğrusu, bizim film setlerimizde de yeteri kadar önlem var ancak olay uygulamaya geldiğinde çoğunlukla hiyerarşi nedeniyle kontrol edilmediğini düşünüyorum. Setlerdeki kuralları uygulayacak kişiler yapım grubunun içinde yer alıyor, bu durumda sözlerini yapımın aleyhinde kullanmaları her zaman mümkün olmuyor. Yabancı setlerde -benim çalıştıklarım- teknik takip yapan ekip bağımsız ve bu sayede elbette daha iyi bir kontrol sağlanıyor.</p>\r\n<p style="text-align: justify; text-indent: 30px;">Bireysel olarak çok daha rahat olabileceğimi bana fark ettiren yabancı setler oldu. Türk yapım şirketleriyle çalışırken çok daha panik ve hızlı davranmayı koşullu olarak kabul ediyorum. Oysa güneş, ne olursa olsun belli bir saatte batacak, neyi ne kadar hızlandırabileceğimiz ancak eldeki imkânlara bağlı. <em>Son Umut</em>’taki yabancı şefim Scott LoveLock’un dediği gibi: “Endişelenme, nasılsa bu nihai kurgu değil.”</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Söyleşi_Umut_Özdemirci_ile/Resim2.jpg" alt="Resim2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> İlerleyen zamanlarda <strong>Umut Özdemirci</strong>’yi sinema sanatının ve üretiminin hangi cephelerinde göreceğiz?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Profesyonel anlamda reji koordinasyon olarak görev yapıyorum, bu görevden emekli olurum diye düşünüyorum. Yazdığım ama çizilmesi için bir ortak aradığım çizgi romanlar yaratıyorum, en azından deniyorum. İstanbul dışında ikamet etmek en iyi seçimim oldu. Yaklaşık 3 yıldır, çalışmadığım zamanlarda büyük şehirden uzaktayım. Benim için toprakla ilgilenmek yönetmen ve oyuncularla ilgilenmekten çoğu zaman daha keyifli.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Bir sinema emekçisi olarak, sizin için film çekimlerinin en zorlu kısmı hangi aşamadır ve neden zordur?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Bir set günü için:</p>\r\n<p style="text-align: justify; text-indent: 60px;"><em>Dış/Gece - 2 Sayfa - Kış: Karların içinde iki araba hızla ilerler, biri kavşağı dönerken diğeri hızını alamaz ve şarampole yuvarlanır. Araba tam patlayacakken erkek kahramanımız arabadan sürünerek çıkar, üstü başı yara içindedir.</em></p>\r\n<p style="text-align: justify; text-indent: 30px;">Bu, yazdığım sahneyi çekmek; hava şartları, güvenlik, fazla tekrar almanın zor olması, dublör kullanımı ve ekstra ekipman sebebiyle benim için ve çoğu set ekibi için sanırım oldukça zorlu olurdu.</p>\r\n<p style="text-align: justify; text-indent: 30px;">Tüm yapım süreci içerisinde en zorunun senaryoda son anda yapılan revizeler olduğunu söyleyebilirim. Her şeyi ayarladıktan sonra bir anda zeki senaristin aklına gelen ve tüm dekupajı değiştirecek aksiyon ve diyalog değişiklikleri olabiliyor. Emin olunuz ki her zaman revizyon olur.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Yer aldığınız herhangi bir projede sizi zorlayan bir sahne/sekans yönetimi anınızı paylaşır mısınız?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> <strong><em>Taken 2 </em></strong>(Olivier Megaton, 2021) filminde reji-2 olarak çalışıyordum ve Eminönü’nde bir iş gününde yaklaşık 300 yardımcı oyuncu, 8 tane <em>prop</em> araba ile yağmurlu bir havada setimiz vardı. Kalabalık kontrolü, telsizden gelen anlamadığımız anonslar, yolları kapattığımız için Eminönü esnafının ve halkın haklı sabırsızlığı… O güne bir daha dönmek istemem. Yönetim konusunda çok başarılı olduğumuzu söyleyemeyeceğim, ama sahne çekildi ve bence iyi oldu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Sanatsal bakış açısıyla, Türk sinemasını nasıl tanımlarsınız?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>UÖ:</strong> Gerçekten tanımlayamam. Yapmak istemediğim için değil, yapamayacağım için. Türk sineması beni işe aldığı müddetçe içinde olacağım için mutluyum.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ÖEA:</strong> Klasik <strong><em>Sekans</em></strong> sorusu olarak, sevdiğiniz filmleri ve yönetmenleri merak ediyoruz.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><strong>UÖ:</strong> </strong>Defalarca izlediğim<strong> <strong><em>Star Wars </em></strong></strong>(eskiler, en eskiler) ve<strong> <strong><em>The Godfather</em></strong> </strong>serileri benim için farklıdır.</p>\r\n<p>&nbsp;</p>', 1, 62, 'Ara Yazı', '/images/arayazilar/Söyleşi_Umut_Özdemirci_ile/Resim1.jpg', '2021-09-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (23, 'ay-j301', 'yonetmenin-dilinden-bir-kisa-film-yolculugu-av', 'Yönetmenin Dilinden Bir Kısa Film Yolculuğu: Av', 'ANKARA GALASI BEKLENİYOR!', '<p style="text-align: center;"><strong>ANKARA GALASI BEKLENİYOR!</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>YÖNETMENİNİN DİLİNDEN BİR KISA FİLM YOLCULUĞU:</strong></p>\r\n<p style="text-align: center;"><strong>“AV” </strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p style="text-align: center;"><strong>İlker MUTLU</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/arayazilar/av/AV_afis.jpg" alt="AV afis" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">İkinci kısam <strong><em>Gölgeler</em></strong>’in üzerinden hayli zaman geçmişti ve aslında bir uzun metraj çekmenin olanaklarını arayıp duruyordum. Şair, tiyatrocu ve yönetmen <strong>Salih Temiz</strong>’le gayrı resmi bir ortaklığımız çoktan oluşmuştu. İntermet üzerinde birlikte programlar yapıyor, projeler üretip duruyorduk. Onun kısası <strong><em>Görsem Seni</em></strong> ve Rize’de çektiğimiz arıcılık belgeseli üzerine hayli uğraşmıştık. Ortaklığı resmileştirmek her zaman aklımızdaydı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">O arada geçtiğimiz yaklaşık iki yıl boyunca Samsun Atakum Belediyesine ait ATATV’ye çektiğim <strong><em>Fenerin Büyüsü</em></strong> adlı programa, pandemi nedeniyle ara vermiştik. Bu programa Samsun’da sinema ile ilgilenen her yaştan insanı çıkarıyordum. Bir bölümde de daha önce <strong>Fuat Yılmaz</strong>’ın <strong><em>Ayakta Kal</em></strong> adlı internet dizisinde birlikte çalıştığım, oyunculuğu seven ve bu yolda bir yerlere gelmeye çabalayan üç arkadaşımı konuk etmiştim: <strong>Cemalettin Solar, Şahin Saydereli ve Mustafa Uyar</strong>. Samsun’dan çalışmanın zorlukları üzerine bir saati aşan bir program olmuştu. Çıkışta, her birini ayrı ayrı başrolüne taşıyacağım üç proje sözü verdim onlara.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto1.jpg" alt="Foto1" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;">&nbsp;<span style="font-size: 9pt;"><strong><em>Fenerin Büyüsü</em></strong> program dekoru önünde, ilk dönem çekimlerindeki oyuncu kadrosu ile.<br />Soldan sağa <strong>Cemalettin Solar, Mustafa Uyar, Şahin Saydereli </strong>ve ben,<strong> İlker Mutlu.</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Buna çok sevindiler ve dağıldık. Şakayla başlayan iş ciddiye döndü ve harıl harıl üç ayrı hikaye arayışına girdim. Kafamda bir sürü öykü vardı elbette, ama hiçbiri bu üçlüye uygun değildi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Derken üç yıl kadar önce çıkardığım hacimli romanım <strong><em>Gölgeni Ardına Al</em></strong>’a bakmak geldi aklıma. Roman, her birinin ayrı ayrı hikayesi olan onlarca kahramanı bir araya getiriyordu. Bunlardan bazılarının bu üç dostumun tip ve karakterlerine uyduğunu fark ettim ve üç hikayeyi tekrar ele alarak romandaki bütünlüklerinden kopardım. Yıllardır kurduğum <strong><em>Gölgeni Ardına Al</em></strong> uzun metraj hayalini parça parça gerçekleştirebilirdim belki böylece.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Mustafa Uyar</strong>’ı başrole taşıyacağım yan öykü <strong><em>Ufuk ile Perşembe</em></strong> idi. Nisan başında yazmaya başladığım senaryo son şeklini ancak Mayıs başında almaya başladı. Bu şekliyle yedi karakter içermekteydi öykü: Mustafa‘nın oynayacağı Kadir’den başka Hıdır, Mustafa, Ufuk, Kadir’in beş ve on beş yaşındaki halleri ve bir babaanne. Hıdır ve Mustafa vardı elimizde: <strong>Şahin Saydereli</strong> ve <strong>Cemalettin Solar</strong>. <strong>Salih Temiz</strong>, daha önce <strong><em>Görsem Seni</em></strong>’de oynattığı teyzesini babaanne rolüne düşündü. O da reddetmedi. Kadın başrol Ufuk için en başından beri aklımda daha önce sahnede seyrettiğim tiyatrocu <strong>Ebru Müjde</strong> vardı. Hiçbiri oyunculuktan gelme olmayan diğer oyunculara oyun verme açısından da bana yardımı olabileceğini düşünüyordum. Ama o esnada İstanbul’daydı ve bacağıyla ilgili bir rahatsızlığı vardı!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Yaz aylarında rahat rahat çekmeyi düşünüyordum filmi. Bir an önce başlamamız gerekiyordu. Bir arkadaşım, daha önce <strong><em>Fenerin Büyüsü</em></strong>’ne de çıkardığımız, tiyatro deneyimi de olan, Ebru’nun da kefil olduğu İngilizce öğretmeni <strong>Nazlı Namlı</strong>’yı önerdi Ufuk için. Nazlı’ya senaryoyu gönderdik. Bizi bekletmedi ve iki gün içinde geri döndü. Ufuk’u da bulmuştuk.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto2.jpg" alt="Foto2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Başroldeki <strong>Nazlı Namlı</strong> beni vurmaya kadar götürdü işi!<br />(Bu arada dikkatli bakanlar kafamın yarık olduğunu görürler)</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çocuk oyuncuları yeri geldiğinde nasılsa ayarlarız diyerek okuma provalarına başladık. Diğer arkadaşlar bir şekilde ezber ve rolü yorumlama konusunda iyiydiler, ama başrolümüz <strong>Mustafa Uyar’</strong>da zaman zaman sıkıntı yaşıyorduk. Mustafa diyalogsuz sahnelerde çok iyiydi, ama ezberi kötüydü. Tutuktu. Neticede rol onun için yazılmıştı ve tipine de birebir oturuyordu. Onda direnmeye kararlıydım.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto3.jpg" alt="Foto3" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">İlk ekip okuma provasında.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Yönetmen yardımcısı olarak daha önce Samsun Sinema Topluluğu’nda tanıştığım ve bir kısasını gösterdiğimiz, <strong><em>Fenerin Büyüsü</em></strong>’nün de ilk bölümüne konuk ettiğim, daha henüz on beş-on altı yaşlarında olmasına rağmen kendi kendine filmler çeken, kurgulayan, geleceği parlak kızımızı seçtik. Deniz, çekimlerin ilk dönemi boyunca bizimle birlikteydi. Sonra Fransa’dan kazandığı bir bursla Paris’e, sinema okumaya gitti.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto4.jpg" alt="Foto4" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">İlk iskele çekiminden.<br />Kameraya gülümseyen, <strong>Deniz Mıdık</strong>’ı Paris\'e sinema okumaya yolladık.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çekimleri niye ilk dönem, ikinci dönem diye ayırdığımı birazdan anlayacaksınız. Okuma provaları, rollerin oturtulması ve ezber (bence!) tamamlanır tamamlanmaz, Haziran başında çekimlere giriştik. Kadir’in dayak yediği sahneyi, Hıdır’ın Kadir’i ikna konuşmasını ve orman sahnelerini bir gün içinde toparladık. Müthiş mutluydum. Bu kısımların tamamlanması, filmin üçte birinin bitmesi anlamına geliyordu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">İskele sahnesine gelmiştik. Bunun için pırıl pırıl bir hava istiyordum. Bunun için biraz beklememiz gerekti. Birkaç gün sonra o havayı yakaladık. Bir taraftan da filmin ikinci yarısını kapsayacak olan psikolog sahnesi için bir muayenehane arayışındaydık ve o gün de uygun bir yazıhane bulunduğu haberi geldi. Müthiş keyifliydik.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">İskele sahnesi, Hıdır’ın Kadir’in ağzından laf almaya çalıştığı, diyaloglu bir sahneydi. O ana kadar Mustafa’nın diyaloglu sahnesi yoktu pek, kısa cümleleri vardı, o kadar. Ama orada uzun uzun, Hıdır’ı atlatmaya yönelik cevaplar vermesi gerekiyordu senaryoya göre. Bir süre Mustafa’yı arkadan alıp metni görüş açısının dışında tutarak okuttuk ona, çekimlerin bir kısmını böyle gerçekleştirdik. Ama tam karşıdan yakın plan almamız gereken, Kadir’in açılmaya başladığı sahneye gelince olan oldu: Mustafa takılmaya başladı. Üst üste yapılan çekimlerin yirmi beşincisinde Mustafa titremeye başladı ve “Abi, ben iyi değilim,” dedi. Başımdan aşağı kaynar sular dökülmekteydi sanki. Ama hemen toparlanmayı başardık ve Mustafa’yı hastaneye yetiştirdik. Uzun süre filme devam edemeyeceği bilgisini aldık o gün; yıkıldık adeta.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ama hani “Show must go on!” düsturu gereği hemen ertesi gün başka arayışlara giriştik <strong>Salih Temiz</strong>’le. Bir sürü yatırım yapmış, kamera, ışık, ses cihazları almıştık bu ve sonra yapacağımız filmler için. Duramazdık. Mustafa’ya verdiğim söz için elimde yığınla hikaye vardı zaten. Biz de bu defa işi şansa bırakmamaya karar verip deneyimli tiyatrocu arkadaşımız <strong>Eray Özdal</strong>’a gittik Kadir’i oynaması için. Kabul etti Eray. <strong>Salih Temiz</strong>’le ağzımız kulaklarımızda gezdik o gece.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto5.jpg" alt="Foto5" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">İkinci dönemde ekipten değişen sadece <strong>Mustafa Uyar</strong>\'dı. Yerine sağdan beşinci sıradaki <strong>Eray Özdal </strong>geldi.<br />Onun yanındaki beyazlı da hem yapım ortağım, hem de kurgucum ve görüntü yönetmenim <strong>Salih Temiz.</strong><br />Beytepe\'deki ilk çekim günümüz. (İkinci dönem, Eylül başları.)</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ertesi gün eldeki görüntüleri izlemeye giriştik içlerinde kullanabileceklerimiz var mı diye. Vardı ama çok azdı. Biz de filmi baştan çekmeye karar verdik.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Salih Temiz</strong>, Samsun merkezdeki Beytepe Kafe-Restoran’ın internet yayıncılığı yapılan üst katında <strong><em>Sinema Bileti</em></strong> adında bir program yapıyordu. Beni oraya götürdü ve üst kattaki idari odayı dayak sahnesi için kullanabileceğimizi söyledi. Mekanı görür görmez aşık olmuştum. Hemen senaryoda ayarlamalar yaptım ve sadece dayağı değil, Hıdır’ın Kadir’i ikna sahnesini de orada çekmek üzere düzenledim. İki gün sonra iki sekansı da orada çektik ve aslında baştan beri gündüz çekilmesini planladığımız iskele sahnesini bir sonraki gün, gece çekmeye karar verdik.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">İskele sahnesini de tamamladıktan sonra geriye rüya ve psikoterapi sekansları kalıyordu. O esnada bulduğumuz ilk psikolog muayenehanesinin kapanmakta olduğunu öğrendik ve canımız çok sıkıldı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ben babaanne rüyası için en başından beri dedemlerin Cedit Mahallesindeki eski evini kullanmayı planlıyordum, ama Ankara yolunda yaşayan babaannemizi, yani <strong>Salih Temiz</strong>’in teyzesini oraya getirmek zordu. Biz de seti Ankara yolundaki eve taşımayı planladık.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto6.jpg" alt="Foto6" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Babaannemizi canlandıran <strong>Nebahat Çelik</strong>,&nbsp;ekiple birlikte.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">İş Kadir’in küçüklüğünü ve gençliğini oynayacak çocukları bulmaya kalmıştı. <strong>Şahin Saydereli</strong> bu meseleyi çözmeye gönüllü oldu ve oturduğu mahalleden çocuk resimleri göndermeye başladı. Küçük çocuk için seçtiğimiz ilk delikanlı nedense mızıkçılık edip sete gelmeyince, yine onun kadar tatlı <strong>Anıl Berk Atıcı</strong>’yı buldu Şahin. Anıl çekimleri burnumuzdan getirecekti, ama değdi doğrusu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Hep tavsiye edilir, sakın çocuk ve hayvan kullanma filminde diye. <strong><em>Gölgeler</em></strong>’de dersimi almış olmalıydım, ama çocuk rolleri yazmadan duramıyordum işte!</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto7.jpg" alt="Foto7" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Kadir\'in küçüklüğü <strong>Anıl Berk Atıcı</strong>. Döner ekmekle kandırıyoruz kendisini.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Daha büyük olan <strong>Ali Kemal Öztürk</strong>, rolünü hakkıyla yerine getirip gitti. Ama Anıl’la hala işimiz vardı ve çocuk hiperaktifti, yerinde tutamıyordunuz. Sonuçta işi şansa bırakarak aynı sahneleri defalarca çekmeye karar verdik. Böylece içlerinden kullanılabilir olanları seçebilecektik. Filmin kronolojik olarak son sahnelerinden biri olan kuymak yeme anı için teyze bir kazan kuymak yapmıştı resmen. Sahne biter bitmez kuymağı sıcağıyla bahçeye taşıdık ve ekipçe yemeye giriştik. Neden sonra Anıl’ın yokluğunu fark ettik ki o sırada evin köşesinden sesi gelmeye başlamıştı bile. Bir anda dehşet içinde donakaldık: Anıl yukarıda bıraktığımız Sony 4K kamerayı eline almış koşturuyordu. “Dur!” demeye kalmadan düştü ve kamera da yere savruldu. E, çocuğun babası da orada. Kamerayı mı kaldıracaksın, çocuğu mu? Neyse ki kamerada bir şey yoktu köşesindeki ufak bir ezilmeden başka…</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto8.jpg" alt="Foto8" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Aramızdaki genç, Kadir\'in gençliğini canlandıran <strong>Ali Kemal Öztürk</strong>.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Psikolog sahneleri için son anada <strong>Saime Çağlı</strong> adındaki uzman psikolog arkadaşımız yetişti yardıma ve Terapihane adını verdiği yazıhanesini emrimize sundu. Orada yaptığımız çekimlerde hiç zorlanmadık. Kamera hareketlerini ve çekim açılarını ince ince belirttiğim bir nevi storyboard hazırlamıştım. Eray da Nazlı da oyunculuğa yabancı değillerdi ve bu da işimizi çok kolaylaştırdı. Setlerde hayli tecrübe kazanmış olan Şahin, bize çekimlerdeki teknik bazı sorunların çözümünde müthiş yardımcı oldu.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çekimler tamamlanmış, sıra son kurgu, efekt ve müziklere gelmişti. İlk ikisi bizdeydi ama müziğe verecek paramız yoktu. Biz de internet üzerinden ücretsiz kullanabileceğimiz müzik parçalarını taramaya başladık. Seçtiğimiz üç parçanın internet sitelerini de ne olur ne olmaz diyerek jenerikte paylaştık.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kurgu esnasında aklımızda hiç olmayan bir sorunla karşılaştık. Mikrofonları ses alma cihazına değil, doğrudan kameraya bağlamıştık ve dış sesler fazlaca karışmıştı akışa. Dublaj yapmak zorundaydık!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bunun için sessiz bir mekan bulmalıydık ve biz de Pazar günleri kapalı olan bir iş hanının en üstündeki bir yazıhaneyi seçtik bu işi yapmak için. Bu canımı çok sıkmıştı. Çünkü çekimlerde doğru tonlamaları yakalamak için çok uğraşmıştım. Yine de hızlıca tamamladık dublajı ve bir daha kurgunun üzerinden geçtik. Film artık günahlarıyla, sevaplarıyla bitmişti.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto9.jpg" alt="Foto9" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Ekip dublajda.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Son kurgu yaklaşık 27 dakika tutmuştu. Türkiye’deki festivallerin 20 dakikayı aşan filmleri almadıkları bilgisi gelmişti ve bu canımızı bir kere daha sıktı. Filmi kurguda zaten kısaltabileceğimiz kadar kısaltmıştık, artık kesecek yer de kalmamıştı. Gözü dış festivallere dikip gala hazırlıklarına başladık. Altı ay kadar süren çabamızı en azından bir seyirci kitlesiyle paylaşmalıydık.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Samsun Büyükşehir Belediyesine ait Atakum Kültür Merkezi’ndeki iki yüz kişilik salonu tuttuk ve 25 Aralık 2021 gecesi galayı gerçekleştirdik. İki yüz kişilik salonun beşte dördünü doldurmayı başarmıştık! Gelemeyenleri anlıyorduk; hava soğuktu ve aynı saatte Trabzon maçı vardı televizyonda…</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto10.jpg" alt="Foto10" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Atakum Kültür Merkezi’ndeki Gala Gösterimi</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sözlerimi bitirirken Samsun’la ilgili birkaç fikrimi de siz okuyucularla paylaşmak isterim. Samsun Sinema Topluluğu deneyimi ve <strong><em>Fenerin Büyüsü</em></strong> programına çektiğim bölümler boyunca Samsun’da çalışan pek çok kısa filmci tanıdım. Bugün gençler daha da ileri giderek uzun metraj yapımına soyunmaktalar. Bu sene içinde Samsun’da genç yönetmenlerce çekilen uzun metraj yapım sayısı beşi buldu. Şehrimizin sinema yapmak için her türlü altyapısı var; tarihi ve turistik yerlerimiz bol, kent hareketli bir yapıda ve her türlü ulaşım olanaklarına sahip. Üretim alanlarının hayli sınırlı olduğu ilimizde sinema yeni bir sektör haline gelebilir ve arayıştaki pek çok gencin yoluna ışık olabilir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Av</em></strong>, severek çalıştığımız, yoğun efor harcadığımız bir iş oldu. Ekip olarak filmimizi seviyoruz. Film, şimdi bir yıl kadar sürecek olan festival yolculuğuna çıkıyor. Dilerim bir festivalde, bir özel gösterimde ya da yapacağımız bir galada sizin de şehrinize uğrar <strong><em>Av</em></strong> ve hayallerimizi sizlerle buluşturur…</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/av/Foto11.jpg" alt="Foto11" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;">Filmin kilit objesi, el kuklası Niyazi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><a href="mailto:ilkermutlu@yahoo.com" target="_blank">ilkermutlu@yahoo.com</a></p>', 182, 62, 'Ara Yazı', '/images/arayazilar/av/AV_afis.jpg', '2022-01-08');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (24, 'ay-j304', 'ahmet-necdet-cupur-ile-yaramaz-cocuklar-uzerine-soylesi', 'Ahmet Necdet Çupur ile Yaramaz Çocuklar Üzerine Söyleşi', 'YARAMAZ ÇOCUKLAR (LES ENFANTS TERRIBLES)', '<p style="text-align: center;"><strong><em>YARAMAZ ÇOCUKLAR</em> (<em>LES ENFANTS TERRIBLES</em>)<em></em></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><strong>Handan Erdil</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Yönetmen <strong>Ahmet Necdet Çupur</strong> ilk belgesel filmi <strong><em>Yaramaz Çocuklar</em></strong>’da kamerasını kendi ailesine çeviriyor. Hatay’ın Keskincik köyünde yaşayan ailede, bir tarafta kendi yollarını kendileri çizmek için direnen çocuklar, diğer tarafta ise bu direnişe karşı çıkan baskıcı ve otoriter ebeveynler yer alıyor. Bir fabrikada işçi olarak çalışan Zeynep, açık liseye devam ederek köyünden ayrılmak ve üniversitede okuyabilmek için çabalıyor. Mahmut ise görücü usulü gerçekleştirdiği evliliğini sonlandırıp kendi tercih ettiği hayatı yaşamak istiyor. Bu süreçte ebeveynlerin ısrarlı karşı çıkışları çocukları engelleyemezken, yaramaz çocukların ısrarı ebeveynlerinin otoritesini sarsıyor. Kendisi de geçmişte kardeşleriyle benzer deneyimleri paylaşan <strong>Çupur</strong>, 20 yıl önce eğitimine devam etmek için ayrıldığı köyüne dönerek kamerasıyla bu mücadeleye tanıklık ediyor. Yönetmenin yazdığı senaryoları güçlendirmek adına geçmişinden görseller alma niyetiyle başladığı çekimler, çektiği görsellerin barındırdığı güçlü hikâyeyi fark etmesiyle belgesele dönüşmüş. Dünya prömiyeri 2021 yılında <em>Visions du Réel</em>’de gerçekleştirilen belgesel, festivalden “Jüri Özel Ödülü” ile ayrılmıştı. Türkiye prömiyerinin yapıldığı Adana Altın Koza Film Festivali’nde ise “En İyi Film, En İyi Kurgu ve Özel Mansiyon” ödüllerini kazandı. Katıldığı ulusal ve uluslararası önemli birçok festivalden ödülle dönen <strong><em>Yaramaz Çocuklar</em></strong> 2022 Mart ayından itibaren gösterime girdi.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_1.jpg" alt="FOTO 1" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: <em>Yaramaz Çocuklar</em></strong> ilk belgesel filminiz, aynı zamanda ilk uzun metrajınız. Öncesinde de 2017 yapımı <strong><em>Latin </em><em>Babylon</em></strong> adlı bir kısa filminiz var. Kurmacadan belgesele geçiş nasıl oldu, diye sorarak başlamak istiyorum.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ: </strong>Daha önceden inşaat mühendisiydim. <strong><em>Latin </em></strong><strong><em>Babylon</em></strong> da Basra’da bir Amerikan üssünde çalışmak için kuzey Irak’tan güney Irak’a gittiğim yolda karşılaştığım şeyleri anlatan bir kısa filmdi. Daha önceden olduğu gibi şimdi de halen kurmaca içerisindeyim. 2017’de kısa filmimi bitirdikten sonra da ona yakın, başka bir tane senaryo yazdım. Birçok kurmaca projesi yazsam da kurmaca projelerimin çoğunda aynı şekilde evi, geçmişimi ve o köyü anlatıyordum. Bu senaryoların hepsi çok zaman alıyordu ve burada, Paris’te bir yapımcı vb. diğer şeyleri bulmak bayağı zordu. Bunların değerini göstermek için, kız kardeşim beni aradığı zaman en azından hem köye dönerim hem de kurmaca olarak yazdığım senaryoları bir şekilde&nbsp;güçlendirmek adına geçmişimden görseller alıp kullanırım, diye düşündüm. Oraya gittiğimde ise <strong>Zeynep</strong>’le tanışıp onu daha fazla tanımam, Zeynep’ten sonra <strong>Nezahat </strong>ile olan görüşmem, ardından da <strong>Mahmut</strong>’un gelmesi benim köyde daha fazla kalmama neden oldu. Aklımda bir belgesel çekme, orayla ilgili bir şeyler yapma düşüncesi yoktu. Bu şekilde başladı belgesel.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Evet, bunu ayrıca soracaktım. Belgesel, anlatı boyunca öykünün merkezinde olan Zeynep\'le yaptığınız telefon konuşmasıyla başlıyor. Zeynep&nbsp;içinde bulunduğu ruh halini telefon kaydında&nbsp;anlatarak bir nevi çağrıda bulunuyor size. Bu kaydın öncesine gidersek, iletişiminizin hangi aşamasında karar verdiniz çektiklerinizi belgesele dönüştürmeye?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ: </strong>Zeynep nişanlıydı, kuzenimizle nişanlıydı. Daha o zamanlar 14-15 yaşlarındaydı ve bu nişanı bitiremiyordu. Bir şekilde beni aradığı zaman bununla ilgili konuşmaya başladık. Dedim ki: “Tabii ki gelip bununla ilgili bir çözüm arayışı içerisine girebiliriz”. Ama Zeynep kendi düşüncelerinden ve duygularından bahsetmeye başlayınca, o zamanlar merak etmeye başladım: Karakter olarak, insani olarak nasıl bu dereceye geldiğini merak etmeye başladım. Sonrasında ona sorular sormaya başladım ve karşımda hiç beklemediğim ve ‘’her zaman orada o değişikliğin olabileceği’’ umudunda olan bir karakter ortaya çıktı. Gerçek bir insan değilmiş de her zaman beklediğim bir karaktermiş gibi geldi. Oraya gidip olayların içerisine girdikçe, Zeynep’in düşüncelerini ve enerjisini hissedip daha fazla kalmaya başladım. Bir hafta iki haftaya dönüştü, bir aya dönüştü ve iki buçuk ay kadar kaldım orada. O zaman içerisinde 40 saate yakın çekim yapmıştım. Ama hala belgesel olacağını düşünmüyordum. Buraya Fransa’ya dönüp çektiklerimi izlediğimde o imajlar ve görseller bana bir hikâyenin olduğunu anlattı. O zaman karar verdim. Bütün her şeyi izleyip yavaş yavaş hikâyenin görsellerde olduğunu fark edince belgesel olduğunu anladım. O zaman da yazdığım bütün senaryolardan çok daha güçlü bir görsele sahip olduğumu fark ettim.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Sonra tekrar mı gittiniz çekimlere devam etmek için?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Sonra yazmaya başladım. Elimde baz olarak Zeynep, Nezahat, Mahmut ve ebeveynlerimiz vardı ama benim de hikâyem vardı. Hiç belgesel çekmemiştim ve belgesellere kolay erişemem nedeniyle izleme olanağım da çok azdı. 2018’de belgesel hayatına girdiğim zaman garip bir şekilde farklı bir dünyanın var olduğunu anladım. Kurmacalar dışında başka bir sinema dünyası vardı. Çok daha ayrıntılı ve çok daha farklı şeylerin yapılabileceği bir dünyayı keşfettim. Yazmaya başladıktan sonra bir şekilde burada CNC’den (Fransız Ulusal Sinema Merkezi) yardım aldım. Çünkü ilk gittiğim zaman elimde hiçbir şey yoktu, sadece arkadaşımın kamerasını aldım, başka bir arkadaşımın ses cihazını aldım, o şekilde devam etmiştim. Kısa filmin <strong><em>Latin </em></strong><strong><em>Babylon</em></strong> o zaman festivallerde gösterilmeye devam ediyordu ve festivalde <strong>Sonia</strong> <strong>Kronlund</strong> ile tanıştım. Onun Cannes’da bir filmi vardı, bir Afganistan film yönetmeninin üzerine yaptığı, <strong><em>Nothingwood</em></strong> (2017) adında. Onunla tanıştım, o da beni yapımcı bir arkadaşıyla tanıştırdı. 2018’in yazında da bir yapımcıyla görüşmeye başladım. 2018’in Eylül’ünde yeni bir olay olduğunda da arkadaşlarımın kamerası ve ses sistemi ile tekrar döndüm köye. Ondan sonra değişmeye başladı çünkü ilk gittiğim zaman kafamda belgesel yapma fikri ya da bir hikâye olmadığı için çok daha özgürdüm, herhangi bir arayış içerisinde değildim. Sadece Zeynep’in iç hikâyesini anlatmaya çalışıyordum, Nezahat’in iç dünyasını, Mahmut’un kendi istediklerini keşfetmeye çalışıyordum. Sonraki dönüşlerimde yavaş yavaş durumun farkındalığı bende ve diğerlerinde oluşmaya başladığı zaman, bir şekilde belgesel ya da hikâyenin artık o kadar doğal görünmeye başladığını fark ettim.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Bir öyküye dönüştüğünü mü fark ettiniz?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Doğrudur ama öykü her zaman vardır. Sadece öyküye yön vermek doğrultusunda karar verdiğimiz zaman, o zaman arayışımız çok netleşiyor. İzlediğiniz belgeselin muhtemelen yüzde altmışı hiç öykü arayışı olmadan olan durumlardan oluşuyor. İnsanlarda belli bir farkındalık olduğu zaman ekranın içerisinde bir şekilde bana daha az ilginç geliyor. İnsanların kendi hayatlarında hiç farkındalık olmadığı şeylerin yaşandığı zaman, o bana daha çok anlam veriyor. Nedenini bilmiyorum.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Doğallıkla ilgili bir şey olabilir mi?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Her şey doğaldır. Şu anda her ne kadar bilgisayar karşısına geçsek de doğal olduğumuzu düşünüyorum. Doğallığımızı bozabilecek şeylerin tanımı farklı olabilir. Doğallıktan öte sanırım ‘’farkındalıklarımızı ne kadar başkalarının farkındalıklarıyla yaşayabiliyoruz’’ ile alakalı. Etrafımızdaki objelerin her birinin bir şekli var ve o şekil yapılabilecek şekillere bağlı olarak değişiyor. Mesela şu anda bilgisayarımız dikdörtgen, benim defterim kitabım, masam her şey dikdörtgen. Sanırım farkındalık olmadan, bende, Zeynep’te, Nezahat’ta veya Mahmut’ta belgesel olabileceği ya da film olabileceği farkındalığı olmadığı zaman her birimiz farklı objelerdeydik. Ve dikdörtgen değildik, kare değildik ya da şeklimiz tam değildi. Her birimiz ayrı ayrı Zeynep, Nezahat, Mahmut, Ahmet’tik. Ama belgesel olduğunu anlayıp ondan sonra Mahmut’a, Nezahat’e, Zeynep’e veya aileme ‘’bir film olabilir bundan’’ dediğim zaman, yavaş yavaş onlarda ve de bende böyle bir beklenti olduğunu fark ettim. O da filmin ikinci yarısında bence hissediliyor, ben hissedebiliyorum en azından. Sanki doğallığımızı kaybetmek değil de her şey çok netleşiyor, hayat o kadar net değil ama çok netleşiyor bir anda.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Anladım, buradan artık ‘’biz birlikte bir öykü anlatacağız’’a geçmiş oluyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Kesinlikle.</p>\r\n<p style="text-align: justify;">&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_2.jpg" alt="FOTO 2" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Peki siz ilk kayıtlardan yola çıkarak bir belgesel yapmaya ve çekimlere devam etmeye karar verdiğinizde ailenin tepkisi nasıl oldu? Hem kardeşleri hem de anne-babayı soruyorum. Daha belgeselin ilk başlarında babayı görüyoruz, otoriter bir baba. Onun otoritesinden kaynaklı evde süregiden bir çatışma ve kavgalar yaşanıyor ilk sahnelerden itibaren. Kardeşlerin yanı sıra otoriter ve muhafazakâr biri olarak baba hem filme çekiliyor olmayı hem de bunu herkesin izleyecek olmasını nasıl karşıladı?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Dediğim gibi, ilk gittiğim zamanlarda yalnızca ailemi değil her şeyi çekiyordum. Mesela komşuları da çekiyordum. Sokaktaki her şeyi çekiyordum. Birçok şeyi çektiğim zaman tam olarak herkesin kafasında ‘’işte bizimle ilgili bir şeyler çekiyor’’ ya da ‘’belgesel olacak, ona göre bir adım atayım’’ gibi bir anlayış yoktu. Gün içerisinde evde akşamları sürekli bu tür kavgalar oluşuyordu. Ama hiç kimse muhafazakâr ve otoriter babamı sorgulayabilecek durumda değildi. Benim oraya dönmemle, kardeşlerimin benden güç alarak yavaş yavaş seslerini yükseltmesi ve babamın karşısına geçebilecek, onunla eşit güce sahip biri olan kendi oğlu bir anda babamda artık elinde bütün her şeyi tutamayacağını, her şeye yön veremeyeceği duygusunu uyandırdı. Her ne kadar kendi otoritesini veya film olayını kafasının bir yerinde tutsa da birçok zaman ‘’hayır kamerayı şimdi kapatıyorsun’’ diyen tek kişi babamdı mesela. Çoğu zaman onun gösterişi içerisindeydi, gücünü benim önümde de göstermeye kalktı. Filmin başında dışarıdan geliyor ve pencereden bizi gözlemliyordu. Bu tür şeyler çok sık oluyordu. Dışarıdan gözlemleyen ve içeriye girerek odanın tam ortasında oturup kumandayı ele alarak ‘’her şeyi kontrol altına almaya çalışan baba’’ figürünü hepimiz biliyoruz. Benim için sürpriz olan garip bir şekilde açık olması, kendi gücünü benim karşımda, kendi arenası içerisinde gösterme ihtiyacı duymasıydı. ‘’Siz değişiyorsunuz ama bu değişiminiz o kadar da iyi değil, bunun önüne geçmek için ben her şeyi yapmaya hazırım’’ diyordu. Sanırım kendi kendini ifade etme isteği de sürekli vardı ve bu istekle birçok şeye izin vermişti onu filme alırken. Ama ailem eskiden bu kadar muhafazakâr ve otoriter değildi, zamanla maalesef çok daha ileriye gitmişler, onu fark ettim. Yalnızca benim ailem değil birçok ailede bunu fark ettim. Benim zamanında kız kardeşim istediği zaman dışarı çıkabiliyordu, tişört giyebiliyordu. Şu an Zeynep saçları biraz olsa göründüğünde ya da dışarıda tek başına yürüdüğü zaman büyük olaylar kopuyor. Son yirmi yıl içerisinde bu kadar muhafazakâr hale gelmemizin maalesef hepimiz nedenlerini biliyoruz.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Evet, oy kullanma sahnesinde de görüyoruz onu. Israrla aynı partiye oy kullanılıyor ve Zeynep orada da durmak, karşı çıkmak istiyor ama olmuyor. Onun pişmanlığını da yaşıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> O benim için çok önemliydi mesela. 18 yaşına giriyor, ilk defa oy kullanıyor ve maalesef her ne kadar bilinçli olsa da oyunu istemediği birine vermesini anlatmak benim için çok önemliydi. Onun için anne ve kızın atışma sahnesi çıkıyor ortaya. Çünkü değişimi o kadar çok istiyor ki Zeynep, değişimin parçası olabilmek için oy hakkını kullanması gereken yerde kullanamıyor. Kendi kendine kızıyor önce, ondan sonra kendi kızgınlığını annesine yöneltiyor. Bu tür tartışmaları maalesef babası ile yapamayacağı için anneye yöneliyor. Babamın çıkışını fark ettiğim zaman direkt onun yerine oturdum, tam olarak anne ve kızın eşit olduğunu anlatabilmek için ortalarında kaldım. Bir şekilde ona baktım, anneme baktım, onların içerisindeki o iletişimin bu şekilde olabileceğini hiç düşünmüyordum. Her ne kadar annem kötü sözler söylese de onun Zeynep\'i dinlemesi benim için çok önemliydi, bunu görmek benim için iyi bir şeydi. Annem maalesef muhafazakâr ve gerici bir tutuma çok daha fazla tutunmuş şu anda ama hâlâ dinleme kapasitesi var, birazcık olsun dinleyebiliyor yine de.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>O anne-kız tartışması belgeselin bütününde en güçlü ve etkileyici sahne olarak duruyor. Zeynep’le bu konuları konuşmuş muydunuz kendi aranızda? Siz Zeynep’in kendini böyle ifade edebilecek kadar bilinçlenmiş olduğunun farkında mıydınız? &nbsp;Ya da feminist okumalar yapıyor muydu?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Kesinlikle bilmiyordum, farkında da değildim. O sahne mesela üç saat sürüyor, onların aralarındaki tartışmanın öncesi de var, namaz kıldıktan sonra da devam ediyor. Gün içerisinde bu tür tartışmalar o kadar sık bir şekilde oluyordu ki. İlk yaptığım kurguda 45 dakika sürüyordu ikisinin çatışması, o zaman farkına varabildim Zeynep’in bu kadar feminist ve çok daha ilerici düşüncelere sahip olduğunu. Çünkü kameradayken ve durumu yaşarken sadece duygusal olarak bazı şeylere yaklaşabiliyoruz. Anlayamıyordum, yani onun söylediği şeylerin ne kadar önemli olduğunun farkında değildim. Ekranın karşısına geçtiğim zaman bu tür şeyleri anlamaya başladım. Oradayken, çekimlerdeyken, Zeynep’in feminist düşüncelerinin olup olmadığının çok farkında değildim çünkü sürekli çalışıyordu. Haftanın altı günü çalışıyordu. Sabah beşte çıkıyor, akşam saat dokuzda geri geliyordu. Bir tek akşamları biraz sohbet ediyorduk. Benim hayata bakış açımla Zeynep’inki arasında biraz fark var ve bu düşünceleri nereden getirdiğini anlayamıyordum. Yani ben de okuyorum ama okuduklarımı tekrarladığım zaman onların kopyalama ve yapıştırma olduğunun farkındaydım. Mesela o sahnede şöyle bir diyalog geçiyor aralarında; annesi diyor ki ‘’Allah bizi burada yarattı, ben burada büyüdüm’’. Zeynep de ‘’Allah bizi senin karnına koydu, orada mı kalsaydık’’ diyor. Bu örneği verdiği ve bunu ekranda izlediğim zaman bunları bir yerden okuduğunu düşünmedim. Bu tür düşünceler ve duygular o kadar bastırıldıktan sonra doğal hale geliyor ki. Zeynep’in bu karakteri kitaplardan dolayı değildi, yaşadığı ve kendi duyarlılığından kaynaklanan bir sonuç olarak görüyorum ben bunu.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_3.jpg" alt="FOTO 3" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Buradan anneye geçmek istiyorum. Anneyi de babanın otoritesini sürdüren bir karakter olarak görüyoruz ancak bir kadın olarak anneyi bu patriarkal düzenin bir parçası olarak değil de bu düzen içerisinde bir anlamda öğütülmüş ve ona ayak uydurmak zorunda kalmış biri olarak görüyorum ben. Belki anne de Zeynep’le benzer süreçlerden geçti ama Zeynep gibi bilinçli davranamadı, müdahale edebilecek gücü kendisinde bulamadı. Sizin anneyle bunları konuşma imkânınız oldu mu? Anne kamera karşısında kendini açma ihtiyacı hissetti mi?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> 20 yaşını geçmiş hiçbir kişide kendini açma gibi bir durum olmuyordu orada. Birçok kişiyi takip ettim, genel olarak 20 yaşını geçtikten sonra bir şekilde kapanıyoruz, neden bilmiyorum. Mahmut da bana çok açık gelmiyor. Sadece kendi doğrultusunda bir şeylere karar verdiği zaman kendini açabiliyor, onun haricinde yine de kapalı olarak görüyorum onu. Annem veya babam sürekli kapalıydı. Annemin Zeynep’e karşı gelmesinin en büyük nedeni; şimdi şöyle bir şey var, o da öyle bir örnek veriyor ki ona da hak vermek gerekiyor. Diyor ki ’’televizyonda görüyoruz giden kızlara neler yapıldığını’’. Kızların evden ayrıldıktan sonraki yollarını bulabilmeleri, maalesef yalnızca benim annemde değil bütün annelerde olan bir imaj. Hani “evden gitmek istiyorsan, okula gitmek istiyorsan tamam ama dışardaki dünya o kadar acımasız ki senin burada kalmanı ben gerekiyorsa her şeyi yaparak sağlayacağım’’ diyor. Her ne kadar bunu çok daha farklı kelimelerle yapsa da. Annemin muhafazakâr olduğunu bilmiyordum. Daha önceden maalesef babamdan çok acı çekmiş bir kadın olarak bizim yanımızda olabileceğini düşünüyorduk. Ama bir şekilde kendi kızlarını sevmiyor, nedenini bilmiyorum. Mahmut’a karşı çıkmıyor gördüğünüz gibi. Halam geliyor mesela, Mahmut’a ‘’yok bunu yapamayacaksın’’ demiyorlar. Onunla şöyle konuşmalar yapıyorlar; ‘’bak bunu yaparsan daha iyi olur”.&nbsp; Ama Zeynep’e karşı konuşmalarında çok daha net tavırları var. Bu da maalesef, bu tür analizlere girmek istemesem de onlara uygulanan davranış biçiminin kopyası oluyor. Filmden sonra, bir şekilde ben, Mahmut ve Cemal annemle Zeynep’in kendi yoluna izin vermesi için anlaşmaya çalıştık, konuşmaya çalıştık. Annemin kendi gençliğini hatırlatmaya ve ondan yola çıkarak belki kızının daha iyi bir geleceğe sahip olabilmesi için bir şeyler yapabileceğini anlatmaya çalıştık. Aynı dili konuşamıyoruz maalesef. Zeynep de annesi de aynı dilleri konuşamadıkları için bu tür sahneler hâlâ çıkıyor. Mesela en son gittiğim zaman aynı sahne tekrar oluştu ve dedim ki bir yerde bir kamera mı var artık? Analizinize katılıyorum tabii ki ama erkek biri olarak bunu söylersem annem, halam ve diğer kadınlar üzerine, o zaman kadınların kendi bilinçlerinin olmadığını ve bilinçlerini belli bir süreç içerisinde erkekler tarafından kaybettiklerini kabullenmiş olurum.  Ve bunu kabul etmek istemiyorum. Yani 30 yıl sonra Zeynep anne olup kendi kızıyla olan konuşmasında eğer Zeynep’in eril dünyanın parçası olduğunu görürsem çok üzülürüm. Ne demek istediğinizi de anlıyorum ama annemin de halamın da diğer kadınların da bilinç sahibi olduğuna inanıyorum her ne kadar bunu çok iyi kullanmak istemeseler de. Doğrudur, babamın söylediği söylemleri Zeynep üzerine aynı şekilde kopyala yapıştırıyor ama kendisinin de belli bir sorumluluk sahibi olduğunu anlaması gerekiyor bence. Ve bunu anlatmaya çalıştık filmden sonra. En azından film bitti ama konuşmalarınızda bunu anlatmaya çalışıyoruz. Çok pozitif bir değişim yok şu ana kadar ama dedik ki en azından daha genç olan insanlara, daha bükülmemiş olan kızlara yönelebiliriz diye düşündük. Zeynep’ten sonra birkaç tane komşu kızı var, onların en azından okul, eğitim masraflarını karşılanabilecek. Eğitimin çok değerli olmadığını biliyorsunuz o bölgede ya da bazı yerlerde. Üniversiteye dört buçuk milyon giriyor şu anda sanırım. Dört buçuk milyonun sadece beş yüz bini girebiliyor üniversiteye. Üniversiteye girdikten sonra iş olmaması tabii orada eğitimin değerini düşürüyor. Ama eğitimin sadece para kazanabilecek bir taraf olmadığını bir türlü ebeveynlere anlatamıyoruz. Zeynep gibi birçok diğer kıza yardımcı olmaya çalıştığımız zaman maalesef o yola bir türlü girmiyorlar.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Buradan şuna gelmek istiyorum. Evet, belgesel mikro ölçekte bir aileye odaklanıyor ama bir taraftan da toplumsal bir yapıya karşılık geliyor. Bu bağlamda benim aklıma feminist hareketin ünlü sözü ‘’özel/kişisel olan politiktir’’ geliyor. Bu sözü doğrulayan bir belgesel aynı zamanda <strong><em>Yaramaz</em> <em>Çocuklar</em></strong>. Ben burada ‘’mahremiyet’’ kavramına değinmek istiyorum. ‘’Ailenin özelini kamuya açma’’ bağlamında -bu belgesele dair okuduğum eleştirilerden birinde geçen bir cümleydi- bu mahremiyetin sınırları nerede başlıyor ve nerede bitiyor sizce?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> O tür eleştirileri duydum, maalesef çok fazla takip edemedim belki de daha fazla takip etmem gerekiyordu. Bir tek <strong>Necati Sönmez</strong>’in yazısını göndermişti bana <strong>Nadir</strong>, yapımcım. Diğer taraftaki yazıları okumam gerekti belki de, o eleştiriler bana birçok şey kazandırabilirdi. Mahremiyet tam olarak nedir? Kendi açımdan onu bilemiyorum. Ben belgeselimde şunu fark ettim. Tamamdır; Zeynep, Mahmut, Nezahat, annem, babam onları tartışıyoruz ama “anne nedir, baba nedir, ev nedir, çocukluğumuz nedir, kendi haklarımız nedir, kardeşler arasındaki bağ nedir?”, onlara inmeye çalıştım. Yani birçok olay vardı, babamı kötü gösterebilecek ya da Türkiye’yi. Çünkü ben yalnızca evde çekim yapmadım, dışarda da çekim yaptım. Zeynep’in fabrikasının içerisinde, dört yüz tane kızın bu fabrikalarda çalıştırılması ya da Mahmut’un dini açıdan nasıl manipüle edildiği. Bunların hepsi sosyal olarak hepimizin farkında olduğu şeylerdi, biliyorduk. Ben sorgulamam gereken, kendi adıma sorgulamam gereken bazı bağları sormaya çalıştım. Benim için mahremiyet ne bilmiyorum ama o bağlar içerisinde “babalık nedir, babam kim, annem kim, evim nedir, doğduğum ev benim için ne anlama geliyor, konuştuğum dil, benim Arap kökenli veya Türk kökenli olmam”, bu tür şeylerin derinine ulaşmaya çalıştım. Mahremiyeti sosyolojik olarak sorguladığımız zaman, eğer bu soru benim filmimle sorgulanırsa ona çok çok sevinirim. Eleştiri olarak veya pozitif olarak benim için bu mahremiyeti sorgulamak yeterli olur. Sosyolojik olarak artık, Arap-Müslüman kültürüne bağlı insanlar olarak ailenin kutsal olmadığını ve ailenin ne olduğunu sorgulamaya başlamamız gerektiğine inanıyorum. Ve umarım benim belgeselim birazcık olsun bu soruyu sorgulamış olur. Sadece iyi olmadıklarından dolayı mahremiyet sorusu geliyor. Eğer babam ve annem iyi olsaydı, çocuklar iyi olsaydı ama karşımıza okul yaptırmayan bir Türk devletini veya fabrikalarda fabrika sahibinin kötü davrandığını gösterseydik hiç kimse mahremiyeti sorgulamayacaktı. Ama bir kişi evden çıkıp, hayatı boyunca dışarda tüm yaşamını geçirip tekrar eve döndüğü zaman bir anda iki tane görsel oluyor. Dışardaki hayatın içerdeki hayatla olan çatışmasını fark ettiğim zaman aslında içerdeki hayatımı hiç tanımadığımı fark ettim. Ailenin benim için ne anlama geldiğini hiç bilmiyormuşum. Tabii ki bütün ebeveynler bu şekilde değiller, bazı aileler sevgiye, dayanışmaya, o tür şeylere bağlılar ama yine de iyi veya kötü ailemizin bizim üzerimizde olan etkilerini sorgulamaya başlamamız gerekiyor diye düşünüyorum.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_4.jpg" alt="FOTO 4" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Yönetmen olarak kamerayı siz kullanıyorsunuz ilk zamanlarda, çekimleri siz yapıyorsunuz. Dışarıdan gelip çeken bir yabancıya göre bu işinizi kolaylaştıran bir şey olmalı. Merak ettiğim şey hangi aşamada kameranın varlığı unutuldu? Ya da unutuldu mu gerçekten, bir zamandan sonra ‘’duvardaki sinek’’ oldu mu kamera? Aynı zamanda jenerikte ek görüntü yönetmeni olarak <strong>Lucie Baudinaud </strong>adını görüyoruz, daha sonraları dahil oldu sanırım çekimlere. Onun, ikinci bir kameraman olarak dışardan gelen birinin varlığı nasıl karşılandı evde?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Şimdi, benim çocukluğumla ilgili herhangi bir fotoğraf yok. Dedemim veya başkalarının fotoğraf olarak, imaj veya video olarak görsel hiçbir şeyimiz yok. Kameranın varlığı bir şekilde hiç anlam kazanmadığından dolayı kamera sadece bir objeydi. Şu anda telefonların hayatlarına girmesiyle videolar anlam kazanmaya başladı. Ama düşünsenize, şimdi bir kişi geliyor, evinize daha hiç icat edilmemiş bir şeyle geliyor ve bir şekilde şunu çekiyorum, dışardaki hayatı çekiyorum. Kamera hiçbir zaman onların hayatında bir anlam kazanmadığı için kameraya göre hareket etme gibi bir durum yoktu. Benim de aklımda bir film, hikâye ya da belgesel düşüncesi olmadığı için ve çektiğim herhangi bir görseli daha sonradan başka bir yerde kullanacağımı düşündüğüm için, hiçbir zaman kameranın varlığı bazı şeyleri değiştirmedi. İlk başlarda, ilk iki gittiğim zaman. Toplam olarak altı defa gittim.  2017’de başladım, 2018’de tekrar orada iki buçuk ay kalmıştım, daha sonra Ağustos’un sonu Eylül’ün başında on gün gittim. Bunlarda tek başınaydım. Bu süreçte hiç farkındalık olmadan, kameranın evin içerisinde dolaştığını fark ettim. Kamera şunu yapıyordu; Zeynep, Nezahat ve Mahmut’a şunu yapıyordu. Hiçbiri kendi arasında konuşmuyor, bunu da fark ettiniz mi bilmiyorum ama iletişimsizlik öyle bir yere gelmiş ki hiç kimsenin -Cemal ve Zeynep haricinde- aralarında direkt, eşit olarak herhangi bir iletişim yok. Her ne kadar şu anda çok fazla konuşsam da genelde daha az konuşuyorum. Kamerayla beraber yavaş yavaş Nezahat, Zeynep, Cemal ve diğerlerini, köydeki birçok kişiyi dinlemeye başladım. Kamera bir şekilde dinleyici görevi görmeye başladı. Kameranın dinleyici görevi olduğunu anladıkları zaman, kendilerini ifade etme ihtiyacına -babam da dahil buna, annem hariç- herkes buna girmeye başladı. Kendi doğrularının aslında gerçek doğrular olduğunu anlatmaya çalıştılar. Benim onlardan istediğim ‘’kameraya bakma, şunu yapma’’ gibi şeyler de yoktu. Sadece oturuyordum bir köşede, bütün gün boyunca. Genelde akşamları geliyorlar ve dolu geliyorlar. Çünkü bütün gün çalışmışlar, bütün gün yalnızlık çekmişler ve akşamları da bir şekilde küçük küçük iletişimler oluyordu. İki buçuk ay boyunca kamera bir köşede oturup dinleyici görevini gördükten sonra ben bile kameranın ne zaman çalışıp çalışmadığını unutmaya başlamıştım. Kamerayla ilgili bu durum 2019’un Nisan-Mayıs’ına kadar sürdü. 2019’un Nisan-Mayıs’ında filmin kısa kliplerini <em>Vision</em> <em>du</em> <em>Réel</em>’de göstermeye başladık. “Work in Progress”e seçilmiştik ve orda görsellerin çok karanlık olduğunu, yeterli olmadığını ve kalitenin düşük olduğunu söylediler. Her ne kadar görselleri hiç çalışmamış olduğumuzu fark etsek de&nbsp;hiç çalışmamıştık, maalesef çalışıp oraya göndermemiz gerekiyordu ama çok ham bir şekilde oraya göndermiştik. O zaman bir on günlük Lucie ile çalışma olanağı doğdu, ‘’en azından bir deneyelim, dışarıdan biri geldiği zaman nasıl olur’’ dedik. Lucie geldiği zaman kameranın karşısına geçtim, karakter olarak benim de ailenin bir parçası olduğumu göstermek istedim. Herkes de bunu görmek istiyordu zaten. O zaman doğal olan bütün her şeyin değişmeye başladığını –doğalın her ne kadar tanımını yapmasak da- ailenin çok daha nazik olduğunu, Zeynep’in çok daha fazla kendini Lucie ile eşit bir kadınmış gibi göstermeye çalıştığını fark ettim. On gün çalıştıktan sonra Lucie’ye dedim ki devam etmememiz gerekiyor. Lucie geri döndü Fransa’ya, ben de beş hafta boyunca tekrar çekimlere devam ettim. Lucie’nin varlığı maalesef çok doğal olmayan bir durum yarattı.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Gittikten sonra nasıl oldu peki?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> O zaman Mahmut ve Nezahat’in konusu vardı, Zeynep konusu yoktu ama Zeynep’in sorunu sürekli devam ediyordu, aynı şeyler devam ediyordu. Kamerayı ben aldıktan sonra kameranın çok daha kişiselleştiğini fark ettim. Artık kamera bir yerde oturup dinleyici görevi görmüyordu. Konuşuyordu, ben konuşuyordum, her ne kadar onu kullanmasam da. Konuşmaya başladım, müdahale etmeye başladım. Daha fazla içeriye girdiğini fark ettim kameranın, daha az mesafe olmaya başladı. Artık onların içerisinden onların şeylerini çekmeye çalışmıştım, çıkarmaya çalışmıştım. Onun için çok az kullandım bu tür çekimleri. Artık ebeveynlerimin haksızlığı o kadar fazla işlemeye başlamıştı ki, ben de ebeveynlerime karşı haksız olduğumu fark etmeye başladım kameranın karşısında. Kamera çok daha kişisel olunca da işte o, benim için filmimin asıl koptuğu yer buydu, hani filmin tam olarak sonlarına doğru Nezahat’in eşyalarını gönderdiğimiz zaman, dayım çıkıyor ve orada diyor ki “artık senin çekim yapmanı istemiyorlar’’. Ben de tabii ki deyip kamerayı etrafa, başka bir yöne çevirip kapatıyorum. Sanırım kamera öyle bir hale geldi ki artık olayların bütün her şeyine girmeye çalışmaya başlamıştı <strong>Lucie</strong> gittikten sonra. O iyi bir şey değildi, benim açımdan daha sonra bunu fark ettim. Paparazzi demeyeyim de böyle...</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Röntgencilik olabilir mi?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Aynen öyle, ona girmeye başladığını fark ettim. Oysa ilk başlarda, Lucie’den önce, sadece filme aldığım kişilerden yola çıkarak onların duygularını almaya başlamıştım, çekmeye çalışmıştım. Lucie’den sonra, Lucie ile benim de kamera karşısına geçtiğim artık benim de karakterimin kamera önünde veya arkasında aynı rolü üstlendiğini fark ettim. O zaman da kameranın aslında insanların hayatlarına çok fazla etki etmemesi gerektiğin anladım. Bu bana kurguda nerede durmam gerektiğini fark ettirdi. İçerisinde miyim, dışarısında mıyım? Eğer her ikisinin arasındaysam onu bulmam çok önemliydi ve onu kurgulamaya çalıştım.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_5.jpg" alt="FOTO 5" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Evet, kurgu sürecini soracağım tam bu noktada. Kurguda iki isim görüyoruz:&nbsp;<strong>Nicholas Sublarti</strong>&nbsp;ve <strong>Elif Uluengin</strong>. Bu süreç nasıl işledi, kaba kurgu size ait sanırım.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Evet, elimde 300 saatlik çekim vardı ve kullanılan dil, konuşulan dil ne Arapça ne Türkçe oluyordu tam olarak, bazen aynı cümlenin içerisinde çevriliyordu. Kimse tam olarak ne söylendiğini anlayamıyordu. İlk ve ikinci çekimlerimin birçoğunun kurgusunu ben yaptım. Kurgusunu yaptıktan sonra Nicholas ile 18 dakikalık küçük bir tanıtım videosu yapmaya çalıştık, beş dakikalık ve 18 dakikalık. O gittikten sonra Elif Uluengin adında, Belçikalı ama Türk asıllı bir kurgucuyla çalıştım, o da olayların tamamen dışında kalıyordu. Herkes olayların dışında kaldığı için bir şekilde kurguyu çok daha netleştirmek bana düştü. Bir şekilde kurguyu yaparken şuna karar vermem gerekiyordu, bakış açıları. Kimin bakış açısından bu filmi anlatıyorum? Eğer kendi bakış açımdan filmi anlatıyorsam hep aynı düzeyin içerisinde kaldığını fark ettim. Yani benim için Zeynep’in Cemal’le olan konuşmasında Zeynep ne istiyor? Benim açımdan Zeynep ne istiyor? Bu tür soruları o kadar fazla sorguladım ki bir anda şunu fark ettim, eğer Zeynep istediği şeyleri almak için kendisi karar veriyorsa, onun aktif olduğu ve karar kılıcı olduğu bütün sekansları bir yere koydum Ondan sonra Mahmut’un aynı şekilde aktif olduğu ve karar kıldığı bütün sekansları bir yere koydum. İstediklerini anlayıp ondan sonra izledikleri yolları bulabilmek için etraflarında olan, onları durdurmaya çalışan ebeveynlerimi koydum. Ondan sonra halamı ve imamı da koyduğum zaman bir anda hikâye kendi kendini ortaya çıkardı zaten. Üç saatlik kurguyu yaptıktan sonra da Elif’in ardından <strong>Mathilde</strong><strong> Van de </strong><strong>Mortel</strong>&nbsp; ile devam ettim ve o da belgeseli çok daha sinemasal bir hale getirdi. Ben yaptığım zaman çok daha “raw”dı, önemli olan iç yolculuktu. Mathilde yaptığı zaman çok daha sinemasal bir akış içerisine getirdi. Kurgu baya bir zaman almıştı, toplamda 22 hafta kurgu yaptım.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>“Kurguda durmam gerektiği yeri fark ettirdi” demiştiniz. Bunu nasıl anladınız?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> İlk önce zordu gerçekten. Çok daha kötü şeyler gelişiyordu normalde, onların hiçbirini koymadım. Çünkü bu kadar şiddetin bu kadar etkili, bu kadar kötü olabileceğinin yaşarken farkında olmuyordum, daha sonradan izlediğimiz zaman farkına vardım. Bir anda görsellerin arkasında yatan anlamlar oluşmaya başladı. Bir anda aslında hiçbir zaman o ailenin bir parçası değilmişim gibi bir görsel oluşmaya başladı. Ve de ‘’her zaman oranın bir parçasıyım’’ı anlatan bir görsel. Bunu anlatan çok iyi bir durum var, filmin başına koydum onu. Hani böyle penceredeyim, pencerenin içine aileme bakıyorum, onlar da elektrik kesilmiş, onun içerisinde konuşuyorlar. Sanırım pencerenin tam dışında kalmam benim yerimin o olduğunu fark ettirdi. Görsel olarak onu fark ettim. Ama tabii bunu 300 saati binlerce dakika izledikten sonra fark ettim. Bunu anladığım zaman, işte yalnızca abi değil film yönetmeni, yalnızca film yönetmeni değil de insan olarak seçimlerimi sorguladım ve onlar bana hangi sekansı bırakıp hangi sekansı koymamam gerektiğini anlattı. Bana çok şey anlattı. Bu belgesel bana kim olduğumu çok daha farklı gösterdi ve buna çok saygı duyuyorum; filmin anlamını önce değil de daha sonradan anlamaya.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Yaramaz_Çocuklar/FOTO_6.jpg" alt="FOTO 6" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Tam bununla alakalı bir sorum vardı, en sona saklamıştım ama yeri gelmişken sorayım. Bakan ve bakılan bağlamında, mesafelense de ailenin parçası, kardeşleriyle aynı deneyim yaşayan bir yönetmen var; bir tarafta aileye bakan yönetmen, bir tarafta da ailenin parçası olarak bakılan yönetmen. Bir yönetmen olarak bu süreç sizin için ne ifade etti? Hem içeride hem de dışarıda bir yönetmen olarak sizin için nasıl bir deneyimdi belgesel?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Sanırım ilk başında oraya gittiğim zaman benim açımdan böyle geçmişle olan nostaljik bir bakış açısı vardı. 13 yaşımda evimi bıraktım, okula gitmek için evimi bıraktım ama okula giderken de maalesef annem ve babamla çok iyi ilişkilerimiz olmadı. Demek istediğim Antakya’ya tek başıma gittim, bir oda kiraladım, bir restoranda çalıştım. Maalesef korkudan geceleri mesela kendi odamın içerisinde ışıklarda sabaha kadar uyuyamadığım anlar oldu. 13 yaşında olmama rağmen annem 45 dakikalık o yolculuğu yapıp benim yanıma aç mıyım, hasta mıyım diyerek iki, üç, dört yıl boyunca hiç gelmedi. Liseye başladığım zaman da cemaat yurtlarında kalmaya başladım. Cemaat yurtlarında iki yıl kaldıktan sonra da değiştiğimi fark ettim ve değiştiğimde hep geçmiş bana birçok acıyla dolu, acılarla dolu, çok iyi bir çocukluk değilmiş gibi geliyordu. Filmi yapmaya gittiğim ve evi, etrafındaki şeyleri çekmeye başladığım zaman -Mahmut’un da dediği gibi- o sahne benim için çok önemli, çocukluğumuzu öldürdüler sahnesi; “biz burada basket oynamadık mı, orda uyumadık mı” diyor Mahmut, Zeynep de diyor ki “benim çocukluğumu yaşatmadılar”, onu fark ettim. Her ne kadar acılarla ve sıkıntılarla dolu bir geçmiş olduğu imajı olsa da bana, 32 yaşıma kadar, oraya dönüp filme almaya başladığım zaman, bir şekilde geçmişle bağlantı kurmaya başladım. Gerçek duygusal bağlar kurmaya başladım. Daha önceden bir itilmişlik vardı, başka bir yere doğru gitme arzusu vardı. Bu belgeselle orada gerçek duygusal bağlar kurmaya başladım. Şu an çok daha mutlu bir insan olduğumu düşünüyorum bu filmi yaptıktan sonra. Belgeselin bakan- bakılan ilişkisinin tam olarak analizini yapmayı hiç istemem, çünkü benim için analizler bazı şeyleri öldürüyor, bana düşmüyor o. O analizi ben kişisel olarak yapmak istemiyorum ama sinema dilinin aslında gerçek insan, gerçek yaşam dilinden birazcık daha üstün olduğunu fark ettim bu belgeselle. Sanırım gerçekle gerçeklik arasındaki farkın ne olduğunu gördüm. Bakış açısının hiçbir zaman objektif olamayacağını ve her ne kadar bu şekilde baksak da yanımızda başka şeylerin sürekli olabileceğini fark ettim. Hiçbir zaman objektif bir bakış açısının olabileceğini düşünmüyorum. Onun için daha fazla duygularıma ya da düşüncelerime güvenip baktığım yerin ne anlama geldiğini, baktığım yerde anlamı kurmaya çalıştım. Yanda olaylar oluyordu ama o olaylara eğer ben bakmıyorsam, buraya bakıyorsam bunun gerçek bir anlamı vardır diye düşündüm. Belgesel bana bunu fark ettirdi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>HE: </strong>Peki, kimler izledi belgeseli ailede? Konuşma imkânı bulmuşsunuzdur sanırım. Nasıl temsil edildiklerini düşünüyorlar? Kendilerine ve hikâyeye nasıl baktılar?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Ebeveynlerim hariç herkes izledi. Adana Film Festivali’ne Zeynep<strong>&nbsp;</strong>ve&nbsp;Mahmut<strong>&nbsp;</strong>gelmişti, Nezahat’a da özel gösterim yaptık, kendi evinde izlettik. Nezahat ilk gördüğü zaman çok duygulanmıştı, kendisini, kendi hikâyesini görüp bir şekilde ağlamaya başlamıştı. Annesine izlettirmedim. Vision du Réel’de film ödül aldıktan sonra Türkiye’de bazı Türk kanallarında fragmanı yayınlanmıştı ve fragmanı izleyen ebeveynler bir şekilde Zeynep’e, Nezahat’e, hepsine karşı çıkmaya başlamışlardı, beni de tehdit etmişlerdi. Onun için şimdilik en azından biraz sakinlesinler. Zeynep ve Nezahat dışarı çıkar çıkmaz ebeveynlere de izletmek istiyorum. Zeynep ve Mahmut, Adana Film Festivali’ne gelip izledikleri zaman tabii ki duygulanmışlardı ama Mahmut şunu söyledi: Ben bu tür şeyleri hayatım boyunca o kadar yaşadım ki, bu tür şeylerin normal olduğunu zannediyordum. Bir de “o kadar uzun süre yaşayınca bastırıyoruz” dedi. Hep bastırdığını söyledi. Şu anda ekranda görüp, babasının ve annesinin bu şekilde olduğunu ilk defa fark etti. Dedi ki “bunların içerisinde yaşadım ama düşünsel olarak bu farkındalığı yaşamadım”. “Böyle pasif bir kişiliğe sahip olduğumu da bilmiyordum” dedi. Zeynep bir şekilde kendinin çok daha cesur olduğunu fark etti, dedi ki “bazen bunları yaşarken ben hep korkuyordum ama bu korkuyu bir türlü göremedim filmin içerisinde, hep cesur bir kızmışım gibi gösteriyorsun” dedi. “Ben kendimi bu şekilde görüyorum ve bu cesareti yaşayıp bu şekilde devam etmek istiyorum ama birçok zaman ben korkuyorum” dedi. Dedim ki Mahmut’a “tamam, sen kendini pasif olarak görüyorsun, sen de öyle görüyorsun Zeynep ama yalnızca sizin hikâyeniz yok, başka hikâyeler de var”. Bir türlü onu fark edemiyorlar. Garip bir şekilde filmi izledikleri zaman sadece kendilerini izliyorlar. Mahmut’un hikâyesi Zeynep’te hiçbir şey uyandırmıyor, bu bana çok garip geliyor. Çünkü ben filmi izlediğim zaman, bir belgesel izliyorum, bir hikâye izliyorum, bir aile izliyorum. Sizin izlediğiniz gibi, herkesin izlediği gibi izliyorum. Onlar sadece kendi hikayelerini görüyorlar, o bana çok garip geliyor.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>HE: </strong>Belki içinde yer aldıkları için ilk anda dikkatleri kendileri üzerinde olabilir, biraz demlendikten sonra zamanla bütüne de bakacaklardır, ne dersiniz?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>ANÇ:</strong> Aynı soruyu bir yıl geçtikten sonra da sordum. Hâlâ değişmedi. Hani Zeynep’i bir kız ve feminist olarak görüp onu hayatımın dışında göremiyorum. Ben Zeynep’in hikâyesini gördüğüm zaman kendimi de aynı değerler için savaşmaya hazır buluyorum. Zeynep, Mahmut’un veya Nezahat’in durumunu anlamıyor. Diyor ki “Nezahat neden böyle”. Evet neden öyle ama nedenlerinin çok büyük bir önemi yok, sonuçlar burada ve sonuçlarda Nezahat iyi bir yere gitmiyor. Neden o empatiyi kuramıyoruz? Neden Zeynep o empatiyi kuramıyor, bilemiyorum. O bana biraz üzüntü verdi, yaşadığımız şeylerde sadece kendi kavgamızı görmemiz. Başkalarının kavgasını görememek bana bizim kültürümüzün bir parçasıymış gibi geldi. Festivallerde onu da fark ettim. Sanki hiçbir aile öyle değilmiş gibi görüyorlardı. Festivallerde benim ailem uzaydan gelmiş bir aile olarak görülüyordu. Aileyi izledikleri zaman ‘’çocuklar, anne, baba, kardeş, kız kardeş, aile, yeni haklar’’ olarak görmüyorlardı. “Mahremiyet, Arap asıllı aile, Hatay’dan gelme aile, ya da yönetmenin başka bir yerden gelmesi”. Hep böyle etiket gibi durumlar oluşuyordu insanlarda. Bir türlü bunların ötesine geçip filmin içine dalamıyorduk, festivallerde bunu fark ettim. Oysa orada sadece bir aile var, bazı aile bireyleri birbirini sevmeyebilirler ama bir aile var. Zeynep’in, Mahmut’un ve Nezahat’in de kendi hikâyelerinden çok tüm hikâyeyi almamaları bana garip gelmişti. Hâlâ da garip geliyor.</p>', 1, 62, 'Ara Yazı', '/images/arayazilar/Yaramaz_Çocuklar/FOTO_1.jpg', '2022-03-19');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (25, 'ay-j307', 'paris-te-sinema-okumak', 'Paris\'te Sinema Okumak', 'PARİS’TE SİNEMA OKUMAK', '<p style="text-align: center;"><strong>PARİS’TE SİNEMA OKUMAK</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><strong>Deniz Mıdık</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM00_x529.jpg" alt="DM0 hfl" width="529" height="375" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Liseye gittiğim yıllar boyunca Avrupa’da sinema okumayı hayal edip sürekli araştırmıştım. Belki İsveç’te, İtalya’da, Almanya’da… Film okuluna gitmek istiyordum. Film okulları üniversitelerin sinema bölümlerinden biraz daha farklı. Teori yerine teknik eğitim ve sayamayacağın kadar çok film çekimi. İngilizce konuştuğum için uluslararası İngilizce eğitim veren film okullarına bakmaya karar verdim ve tahmin ettiğimden çok daha fazla uluslararası film okulu olduğunu fark ettim. Bu okullar genellikle 1 ila 3 yıl arasında değişiyor. Öğrenciler arasında dünyanın her yerinden insanlar oluyor hatta o ülkenin bireylerinden bile tek tük katılım var. Bu okullar arasında benim en çok ilgimi çeken Paris’teki oldu. Başvuru formunu doldurdum, filmlerimi gönderdim ve daha gitmeme 1,5 yıl varken kabul aldım.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Paris’te ev ya da yurt bulmak çok zor bir iş. Ben bir tanıdığım aracılığıyla buldum, diğer arkadaşlarım emlak sitelerinden benim gibi aylarca araştırmış. Hiçbirimiz yurt bulamadık. Ama evler belki de yüzyıllar öncesinden kalma, Paris’e sanatçı mekanı havasını veren çok güzel küçük daireler. Ayrıca devlet herkese ayırt etmeden kira yardımı veriyor ve kiranızın büyük bir miktarını bu para ile karşılıyorsunuz. Tabi Fransa’nın evrak işlerini tamamlayabilirseniz.</p>\r\n<p>&nbsp;</p>\r\n<table style="margin-left: auto; margin-right: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-right: 10px;"><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM1_rsz.jpg" alt="DM1 rsz" /></td>\r\n<td><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM2.jpeg" alt="DM2" /></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sınıfta 10 kişiyiz ve film yapımı öğrencileriyiz. Bir de oyunculuk sınıfı var, film çekeceğimiz zaman bize yardım ediyorlar. Sene boyunca birisi belgesel, birisi karakterizasyon, diğerleri serbest olmak üzere 6 büyük proje yapıyoruz. Herkesin kendi yönettiği bir ve asistanlık yaptığı en az bir film oluyor bu projelerde. Senaryoları yazdıktan sonra öğretmenlerimize gönderiyoruz, tekrar yazılıyor ve çekime hazır hale geliyor. Filmleri çekerken yalnızız, bu kısma öğretmenler müdahale etmiyor. Kurgu günleri gece yarısına kadar stüdyoda kalma hakkımız var ve ilk taslağı, son taslağı öğretmenlerimize gösterip bir kez daha düzenliyoruz. Çekim 2, kurgu 1 haftamızı alıyor ve sonunda koltuklara oturup yiyip içerek film gösterimlerimizi yapıyoruz. Tekrar geribildirimler alınıyor. Filmlerimizi sene sonunda bir demo-reel ve portfolio internet sitesi oluşturmak için saklıyoruz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Proje yapmadığımız zamanlar sinematografi, prodüksiyon, senaryo yazımı, sinema tarihi, kurgu, ışık ve ses dersleri alıyoruz. Buraya gelmeden önce sinemada bilmediğim bu kadar çok şey olduğunu&nbsp; fark etmemiştim. Sadece ilk 3 haftada öğrendiğimiz bilgilerle ilk filmimizi çekince bile daha önceki kısa filmlerime kıyasla çok büyük bir ilerleme kaydettiğimi gördüm. Ders aldığımız hocalar farklı ülkelerden geliyor bizim gibi. Bazen aynı dersin farklı konuları için farklı hocalar geliyor. Mesela Afrika tarihi dersi için farklı bir hocanın, ya da prodüksiyon dersi ikinci dönem için bir prodüktörün gelmesi gibi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bazı günler daha küçük projelerimiz oluyor; stop-motion yapmak, yeşil ekran kullanmak, Paris anıtlarını açık havada timelapse çekmek, deneysel lensler denemek gibi. Dönemleri geldiğinde Paris’teki fotoğraf ya da film-tv ekipman fuarlarını geziyoruz, milyon avroluk kameraları deniyoruz, bedava şapkalarımızı alıp bir sonraki fuarı bekliyoruz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-align: justify;">Senaryolarımızı yazarken istediğimizi yapmakta özgürüz, tek şart çekilebilir olması. Konu açısından hiçbir sınırlamamız yok, gerekirse yeşil ekran tarzı efektler ekleyebiliyoruz. Filmlerimizi çekerken Canon 90D kullanıyoruz; lens, mikrofon, ışık, tripod, gimball seçeneklerimiz neredeyse sınırsız. Stüdyoları istediğimiz zamanlarda kullanabiliyoruz, film çekimlerini ya bizim ayarladığımız mekanlarda ya da zamanımızın çoğunluğunu geçirdiğimiz stüdyoda yapıyoruz. Montaj yaparken okulun Mac’leri kuruluyor. İstediğimiz zaman ekipman ya da bilgisayar ödünç alabiliyoruz. Oyuncularımızı seçerken oyunculuk sınıfı yeterli olmadığında ilan verip seçmeler düzenliyoruz, genelde seçilen oyuncular başka oyunculuk okullarının öğrencileri oluyor.</span></p>\r\n<p>&nbsp;</p>\r\n<table style="margin-left: auto; margin-right: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-right: 10px;"><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM4_rsz.jpg" alt="DM4 rsz" /></td>\r\n<td><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM3.jpeg" alt="DM3" /></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Fransa’da sinemaya yaklaşım, Türkiye’dekinden çok farklı. Yeni dalgadan kalan sinematek geleneğinin hala bir etkisi var; hangi yıldan olursa olsun, bir filmi sinemada izlemek istersek mutlaka buluyoruz. Sinemalara çok yoğun talep var. Her sokakta mutlaka bir sinema olmasına rağmen <strong><em>French Dispatch</em></strong>’in çıktığı gün en az 5 sinemanın önünde sıra bekleyip bilet bulamamıştık. Sinemaların yanında aynı zamanda çok fazla sinema kütüphanesi ve sergisi var. Geçen ay Orsay müzesine sinema sergisi kurulmuştu, halihazırda <strong>Sinematek</strong> de kocaman bir sergi ve kütüphane. Bir de <strong>François Traffaut</strong> <strong>Sinema Kütüphanesi</strong>’ni görünce gözlerime inanamamıştım.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Paris’te yaşamak başlı başına çok farklı bir deneyim. Aradığın her etkinlik, her yemek, her insan etrafta bir yerlerde. Tüm sokaklar resim gibi. Her yer film seti potansiyelinde, tüm şehir film seti olmuş denebilir. Ben de buraya geldiğimde ilk iş olarak ünlü filmlerin çekildiği yerleri ziyaret ettim. Fransızların İngilizce konuşmadığı da yalan. Hatta Fransızca aksanını beğenmezlerse sana İngilizce cevap veriyorlar!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Tabii ki diğer Avrupa şehirlerine kıyasla daha pahalı bir şehir. Ama araştırmanı yeterince yaparsan, yıllık metro kartıyla, kira yardımıyla, öğrenci olmanın getirdiği indirimlerle (örneğin müzeler ücretsiz) biraz daha ucuza getirebiliyorsunuz.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">En güzeli ise aynı amacı, tutkuyu paylaşan insanlarla beraber olmak. Günlük hayatınla filmlerin birbirine karışması, sınıf arkadaşlarınla sinemaya gidip üzerine konuşmak, senaryolarınızı tartışmak, belki bir sonraki seneni öngöremediğin bir yolda yalnız olmadığını hissetmek çok güzel. Farklı ülkelerden gelen insanlarla “zeytin kahvaltıda yenmez”, “makarnaya yoğurt konmaz” tartışmalarına girmek, onların yemeklerini yemek, geleneklerini uygulamak (bardaklar çarpıştırılırken göz göze bakılır, yılbaşı hediyeleri elden verilmez) ayrı bir deneyim. &nbsp;Bizden daha heyecanlı öğretmenlerden ders almak, onlarla sohbet etmek, ilk defa filmini acımadan eleştiren birini görmek, ki çok işe yaradı, ve hayatımın en verimli eğitimlerinden birini almak tüm bu çabaya değer.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Pariste_Sinema_Okumak/DM5_rsz.jpg" alt="DM5 rsz" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>', 183, 62, 'Ara Yazı', '/images/arayazilar/Pariste_Sinema_Okumak/DM00_x529.jpg', '2022-03-26');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (26, 'ay-j308', 'sabirsizlik-zamani-cocuklari', 'Sabırsızlık Zamanı Çocukları', 'SABIRSIZLIK ZAMANI ÇOCUKLARI', '<p style="text-align: center;"><strong><em>SABIRSIZLIK ZAMANI</em> ÇOCUKLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><strong>Zehra Yiğit</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Yönetmen</strong>: Aydın Orak<strong><br /> Senaryo</strong>: Aydın Orak<strong><br /> Görüntü</strong> <strong>Yönetmeni</strong>: Vedat Oyan<strong><br /> Sanat Yönetmeni: </strong>Salih Süleymani<strong><br /> </strong><strong>Kurgu</strong>: Murat Hasarı<br /> <strong>Müzik: </strong>O.A.G<br /> <strong>Oyuncular</strong>: Mirza Zarg, Mirhat Zarg, İştar Gökseven, Pelin Batu, Feride Çetin, Ali Seçkiner Alıcı ve Rıza Sönmez</p>\r\n<p><strong>Yapım Yılı/Süre:</strong>2021/93 ’</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Sabırsızlık_Zamanı/sabz.3_x960.jpg" alt="sabz.3 x960" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çocukluk, hem Türkiye hem de dünya sinemasında sıklıkla yetişkinlerin dünyasındaki sorunların çocuk bakış açısı ile görünür kılınmasını sağlayan bir metafor olarak karşımıza çıkarken, aynı zamanda iktidar ilişkilerinin, toplumsal adaletsizliklerin ve eşitsizliklerin tartışılmasına da bir zemin hazırlar. Prömiyerini 37. Varşova Film Festivali’nin yarışma bölümünde yapan, <strong>Aydın Orak</strong>’ın yönettiği <strong><em>Sabırsızlık Zamanı</em></strong><em>,</em> anlatının merkezine iki çocuk karakteri (Mirza ve Mirhat) alarak, onların yaşam koşullarını ve bu şartlarda can bulan gündelik hayatlarını metaforik dille anlatıyor. Diyarbakır’ın yaz sıcağında, yoksul bir mahallede yaşayan, tek hayalleri mahallede yapılan lüks site içerisindeki havuza girmek ve serinlemek olan iki kardeşin hikayesini izleyicisine ulaştıran film, izleyicisini, bir yandan kendi çocukluğuna doğru bir yolculuğa çıkarırken diğer yandan filmin ana karakterleri Mirza ve Mirhat’ın soru ve sorunları ile düşünmeye sevk ediyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Sabırsızlık Zamanı</em></strong>, bir güvenlik görevlisi ile iki çocuğun karşı karşıya gelen görüntüleri ile açılıyor. Bir metafor olarak güvenlik görevlisi sistemi temsil ederken, çocukların onun karşısında durma hali, sistem ile karşı karşıya gelme anlamlarında kullanılırken film boyunca onun kurallarını eleştirme, sorgulama ve hatta ona isyan etme anlamlarına da dönüşüyor. Görevli ile çocukların karşı karşıya geldikleri sahnede çocukların attıkları çığlıklar, onların baskılanmış, bastırılmış ve yok sayılmış, dolayısıyla işitilmeyen sesleri olarak okunabilirken, aynı zamanda onların anlayamadıkları eşitsiz dünyaya karşı bir tür isyan, öfke boşaltımları ve eşitlik arayışları olarak da okunabilir. Toplumsal cinsiyet vurgusu yapmadan, çocuksu masumiyeti kara mizahla hikayesine dahil eden <strong>Orak</strong>, masumken mağdur olan, toplumsal ve ekonomik eşitsizlik ve adaletsizliğe kurban verilen, kendilerinin yaratmadıkları düzende, hak etmedikleri eşitsizliklerle savaşmak zorunda kalan bu iki çocuğun hikayesi ile, sabırsız çocuklar tarafından sınırların ihlal edilmesinin mümkün olup olmadığını tartışıyor. Kullandığı minimal dil ile de izleyicisinin yüreğine dokunmayı ve buruk bir tat bırakmayı başarıyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmin isminin görülmesi sonrası şehre yukarıdan bakarak toplumsal ve ekonomik şartlar hakkında izleyicisine genel bir bilgi veren <strong>Orak</strong>’ın kamerası, bu evlerden herhangi birine sakince sokuluyor. Böylece bu evde yaşayan iki çocuğun yaşamları ve bu yaşamlara dair detaylar, Diyarbakır’ın bu semtindeki yaşamların birer alegorisi durumuna da dönüşüyor. Bu evdeki iki çocuk olan Mirza ve Mirhat, babaları, anneleri ve ablaları ile mutlu bir aile tablosu oluşturuyorlar. Örneğin babaları, onlara her gün bir kelimenin anlamını öğrenmelerini salık veriyor ve onların bir gün profesör olacaklarını hayal ediyor. Aile fertlerinden daha gerçekçi olan anneleri, zaman zaman onların kurdukları hayalleri tatlı dille eleştirse de yine de birlikte çaldıkları sazın, söyledikleri türkünün ve samimi sohbetlerinin ortasında mutlu görünüyorlar. Şube öğretmenlerinin yetersizliğinden dolayı okulda derslerinin çoğu boş geçse de Mirza ve Mirhat, bu yoksulluğu ve yoksunluğu esprili bir dille aktarmayı başarıyorlar. İdealist öğretmenlerinin onlara verdiği felsefi ve sosyolojik eğitim ile yaşamı keşfetmeye devam eden çocuklar, öğretmenleri sayesinde <strong>Cervantes</strong>’in <em>Don Kişot</em>’u ile tanışıyorlar. Okulun kapısı önünde <em>“Ben Don Kişot’um”</em> diye bağıran çocukların havuza ulaşma hayalleri ve sisteme karşı savaşları, Don Kişot’un yel değirmenine karşı savaşı ile paralellik taşıyor.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Sabırsızlık_Zamanı/sabz.1_x960.jpg" alt="sabz.1 x960" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmin anlatısında Mirza ve Mirhat’ın girmeyi hayal ettikleri sitenin çevresindeki demir teller bir sınır alegorisi olarak, aynı mahalledeki iki sınıfın gelir düzeyindeki farklılığın, bir yaşam tarzı ayrımını da beraberinde getirdiğinin altını çiziyor. Mirhat’ın sitede yaşayan küçük kızla demir teller ardından kurduğu diyalog, yetişkinlerin dünyasının birer tezahürü ve tekerrürü olarak dikkat çekerken, bu dilin çocuk dünyasına ait olmayışı ve ayrıksılığı fark ediliyor, tıpkı yetişkinlerin kurdukları düzenin sonuçlarının onların dünyalarına ait olmayışı gibi. Televizyonda bir yandan kentsel dönüşüm mağdurlarına yapılacak kira desteği haberleri işitiliyorken, çocukların dünyasında, sitenin havuzuna girme problemleri ile matematik dersinde işledikleri havuz problemleri örtüşüyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çocukların bu güvenlikli sitedeki havuza girme denemeleri, önce bekçi sonra sitedeki çocuklar tarafından engellenirken, çocukların dünyalarında, zihinsel güçleri ile taşı hareket ettirerek cam çerçeve kırma ya da havuzda dondurma yiyen çocuğun dondurmasını düşürme gibi masum intikamların hayali kuruluyor. Çocuklar, adalet arayışlarının öfkesiyle güvenlik görevlisinin evinin camını kırarken, meselenin sadece güvenlik görevlisi ile ilgili olduğunu sanacak kadar naif düşünüyorlar. Çözüm olarak hurda satıp, para kazanmayı tercih eden çocuklar, bu işten hayal ettikleri parayı kazanamayınca, havuz yaptırmak yerine plastik havuz alarak, bu plastik havuzda da eğlenmenin yolunu bulmayı ihmal etmiyorlar. Dünyayı değiştirme hayali kuran bu çocukların karşı karşıya kaldıkları yetişkinler ile aralarındaki diyaloglar, sitede yaşayan çocuklarla olan atışmalar çocuk dünyasının hem saflığını hem de zekiliğini ve sınırları esnetme potansiyelini ortaya koyuyor.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sitede yaşayan, özel araçla okula giden ve sitenin içerisindeki havuzda serinleyen çocukların aksine yoksul bir mahallede yaşayan, okullarında pek çok dersi boş geçen Mirza ve Mirhat, ellerindeki bir lira ile dondurma almak yerine bunu ihtiyacı olan biriyle paylaşacak kadar da yüce gönüllü olarak çizilirlerken, bu çocuklar, idealist öğretmenlerinin dediği gibi eğitimin yalnızca okulda olmadığının göstergesi durumuna da geçiyorlar. Filmde yetişkinlerin çizdikleri sınırlar içerisinde hareket eden bu çocuklar, bütün bu yoksunlukların ortasında, hayallerini bırakmayıp her gün bu hayalleri biraz daha genişleterek, sistem içerisinde kendilerine delikler açıp, buralardan sızabilecekleri alanları yaratıyorlar. <strong>Orak</strong>, çocukların nedeni olmadıkları ancak sonucunu yaşadıkları, sosyolojik, ekonomik, politik, demografik pek çok unsurun birleşimi olan çok boyutlu bir sorunu, yoksulluğu, sınıfsal eşitsizlik ve adaletsizliği mercek altına alırken, havuz problemi metaforu ile yoksulluğun getirdiği eğitim, konut, yaşam şartları gibi olanakların yoksunluğunu da anlatısına dahil ediyor. Yönetmen, çocukların yaşamlarını, çocuksu dünyanın naifliğini, yaratıcılığını ve sorunlarla baş etme yöntemini de izleyicisine ajitasyon yapmadan aktarırken başka türlü bir yaşamın varlığını da fısıldıyor. Kentsel dönüşüm ve bu dönüşümün yarattığı adaletsizliklere dair çocukların sordukları <em>“Neden beyazlar gerçek, biz naylon havuza giriyoruz?”</em> sorusu ise izleyicisinin yüzüne tokat gibi iniyor. Mirza ve Mirhat, bu yoksulluk ve yoksunluk sınırları içerisinde hapseden sisteme dair sordukları safça soruları ve çocuksu başkaldırışları ile birer kahramana dönüşürken, izleyici onların “kahraman” olmak zorunda kalmadıkları bir dünyanın adaletinin nasıl kurulacağı sorusu ile baş başa kalıyor.</p>\r\n<p>&nbsp;</p>', 184, 62, 'Ara Yazı', '/images/arayazilar/Sabırsızlık_Zamanı/sabz.3_x960.jpg', '2022-04-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (27, 'ay-j311', 'i-sci-fi-lmleri-festi-vali-si-nema-topluluklari-calistayi', 'İŞÇİ FİLMLERİ FESTİVALİ SİNEMA TOPLULUKLARI ÇALIŞTAYI', 'İŞÇİ FİLMLERİ FESTİVALİ SİNEMA TOPLULUKLARI ÇALIŞTAYI', '<p style="text-align: center;"><strong>İŞÇİ FİLMLERİ FESTİVALİ SİNEMA TOPLULUKLARI ÇALIŞTAYI</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Standart - ticari dağıtım ağına alternatif bir sinema kültürünü geliştirmeye odaklanan çeşitli film toplulukları, 17. Uluslararası İşçi Filmleri Festivali çerçevesinde ve FilmKoop’un (*) ev sahipliğinde, 7 Mayıs Cumartesi günü “Sinema Toplulukları Çalıştayı”nda bir araya geldi. Çalıştay, FilmKoop’un her pazar günü bağımsız Türkiye sinemasından örnekleri gösterdiği Kadıköy Sinematek/Sinemaevi’nde düzenlendi; hem bizzat toplantı salonuna gelenlerle yüz yüze hem de Zoom aracılığıyla başka şehirlerdeki topluluk temsilcilerinin de katılımının sağlanmasıyla, hibrit düzende yapıldı. Sinematek/Sinemaevi’ne gelebilenlerle birlikte 21 sinema topluluğu (**) etkinliklerini anlattılar ve karşılaştıkları sorunları paylaştılar. Neredeyse bütün topluluklar, film gösterimi yaptıklarını veya pandemi yüzünden kesintiye uğrayan gösterim düzenlerini yeniden kurmaya çalıştıklarını dile getirdiler. Bazı topluluklar bu gösterimleri Başka Sinema ile ortaklaşarak yaptıklarını ifade ettiler. <em>Yönetmen katılımlı özel gösterimler</em> yapmak, <em>film günleri veya festivalleri </em>organize etmek (ör. Sinetopya - Ankara, Akhisar Sinema Derneği, Mersinefil, Ortadoğu Sinema Akademisi Derneği - Diyarbakır), <em>çevrimiçi film çözümlemesi buluşmaları</em> düzenlemek (ör. ODTÜ Mezunlar Derneği İstanbul Şb.), <em>film kuramı dersleri</em> sunmak (ör. Atölye Gölge - Bandırma) ve <em>meslek profesyonellerine yönelerek üretim odaklı çalışmalar</em> yapmak (Ayvalık Sinema İnisiyatifi) da, toplulukların çalıştayda andıkları diğer etkinlik çeşitleriydi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Çalıştayın ikinci bölümünde; FilmKoop Yönetim Kurulundan Önder Özdemir, çalıştay öncesinde topluluklara dağıtılan formlara yapılan geri bildirimleri değerlendiren (Özdemir, 40’ın üzerinde geri bildirim aldıklarını ifade etti), ayrıca bunlarda öne çıkan sorun başlıkları için FilmKoop’un sunabileceği çözümleri tanıtan bir sunum yaptı. Toplulukların form geri bildirimlerinde olduğu kadar çalıştayın ilk bölümünde de sıklıkla yakındıkları üç sorun, bu sunumda, “gösterim yeri ve teknik altyapı”, “film seçimi ve temini” ve “telif ve bilet satışı” olarak başlıklandırıldı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Özdemir, “AVM’lerin içine sıkışmış sinema”lar yerine alternatif izleme mekanları ve deneyimleri ihtiyacından bahsetti. Bu ihtiyaca yönelik olarak FilmKoop’un, sinema topluluklarının karşılaştıkları sorunların çözümünde oynayabileceği etkin ve kolaylaştırıcı rolü şu şekilde anlattı:</p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style="text-align: justify;">\r\n<p>Gösterim yeri seçenekleri, il ve ilçelerdeki belediye salonları ve kültür merkezleri olabilir. Bunlardaki teknik olanakların sinema için kabul edilebilir seviyede iyileştirilmesine dönük olarak FilmKoop, salon ve teçhizat için ön inceleme ve değerlendirme, ses testi ve projeksiyon kalibrasyonunu içeren teknik danışmanlık hizmetleri sunabilecek. Mevcut projeksiyon cihazının kullanılması maliyeti düşürecektir. Gösterim teçhizatı için asgari standart, bir BluRay oynatıcısının alınması ve 2.1 ses sisteminin kurulması yoluyla sağlanabilir. Ancak olanak olan yerler için uygun fiyatlı DCP çözümleri üretilebilir. Her koşulda, kullanılacak projeksiyon cihazının film gösterimine uygun şekilde kalibre edilmesi, göz ardı edilmemesi gereken bir zorunluluk.</p>\r\n</li>\r\n<li style="text-align: justify;">\r\n<p>Film seçimi ve temini, topluluk temsilcileri ile FilmKoop’un birlikte oluşturacağı bir komitenin birlikte çalışmasıyla sağlanabilir. Böyle bir komite tematik paketler oluşturabilir, farklı ülke sinemalarına eğilebilir. Daha çok önemsenen bir hedef olarak, bağımsız Türkiye sinemasından örneklerin seyirciyle buluşabilmesi için çoklu gösterim seçenekleri değerlendirilecek. Farklı yerlerdeki eşzamanlı gösterimler sonrasında, gösterilen filmin yönetmeniyle çevrimiçi söyleşi yapma olanağı yaratılabilir. Örneğin İstanbul’daki bir stüdyoda bir moderatör filmin yönetmeniyle özel söyleşi yaparken, farklı illerdeki salonlar ile bu stüdyo arasında çevrimiçin bağlantı kurulabilir; seyirciler söyleşiyi canlı izledikleri gibi, sesli veya yazılı sorular yoluyla söyleşiye doğrudan da katılabilir.</p>\r\n</li>\r\n<li style="text-align: justify;">\r\n<p>Birçok topluluk, film gösterimlerini ücretsiz yapmayı istiyor; ancak filmleri ücretsiz göstermek, aslında yasal zemini olmayan bir pratik. Hem bundan ötürü hem de bağımsız sinemacılara sonraki filmleri için gelir sağlayabilme hedefinin gözetilmesiyle, film gösterimlerinin ücretli bilet satışıyla yapılması gerekiyor. Bu noktada FilmKoop, bilet satışını sağlamak üzere çözümler üretebilir FilmKoop fatura kesme yetkisi sayesinde, kooperatif bileşenlerinin önünde hukuki olanakları açan bir organ işlevi görebilecek.</p>\r\n</li>\r\n</ul>\r\n<p style="text-align: justify;">Çalıştay sonunda bir koordinasyon komitesi seçimi yapıldı. Bunun devamında, FilmKoop çatısı altında oluşturulacak bir çalışma grubu, kooperatif ve sinema topluluklarının ortak ve sürdürülebilir bir gösterim-etkinlik planında buluşması için çalışacak.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">* FilmKoop (Sınırlı Sorumlu Sinema Filmi Sanatını Geliştirme, Yaygınlaştırma, Tanıtma, Sosyal Kalkınma ve İşletme Kooperatifi), aralarında Özcan Alper, Meriç Demiray, Pelin Esmer, Vuslat Saraçoğlu, Kıvanç Sezer gibi isimlerin de bulunduğu bağımsız yönetmen / senarist / yapımcılarla birlikte, Ekim 2020’de kuruldu. Kooperatif, bağımsız sinemanın üretim, dolaşım ve yaygınlaşma koşullarının iyileştirilmesine odaklanıyor. FilmKoop’un internet sitesi: <a href="http://www.filmkoop.org"></a><a href="http://www.filmkoop.org">http://www.filmkoop.org</a></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bu yazının yazılmasındaki desteği için FilmKoop’tan Önder Özdemir’e teşekkür ederiz.</p>\r\n<p>&nbsp;</p>\r\n<p>** Çalıştaya katılan sinema toplulukları:</p>\r\n<p>Akhisar Sinema Topluluğu (Manisa),</p>\r\n<p>Sinetopya (Ankara),</p>\r\n<p>Baküs - Bahçeli Kültür Sanat (Antalya),</p>\r\n<p>Sine Ardahan Sinema Topluluğu,</p>\r\n<p>Artvin Sinema Topluluğu,</p>\r\n<p>Atölye Gölge (Balıkesir Bandırma), &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n<p>Ayvalık Sinema İnisiyatifi (Balıkesir),</p>\r\n<p>Aykırı Sinema Derneği (Bursa),</p>\r\n<p>Ortadoğu Sinema Akademisi Derneği (Diyarbakır),</p>\r\n<p>Trakya Üniversitesi Öğrenci Topluluğu (Edirne),</p>\r\n<p>Edirne Osman İnci Müzesi,</p>\r\n<p>Kars Sinema Topluluğu,</p>\r\n<p>Lüleburgaz Sinema Topluluğu,</p>\r\n<p>Eğitim-Sen Marmaris Şubesi,</p>\r\n<p>Mersinefil Mersin Sinema Derneği,</p>\r\n<p>ODTÜ Mezunlar Derneği Sinema Kulübü,</p>\r\n<p>ODTÜ Mezunlar Derneği&nbsp;İstanbul Şubesi Sinema Kulübü,</p>\r\n<p>Samsun Sinema Topluluğu,</p>\r\n<p>Moz Art Kültür (Şanlıurfa),</p>\r\n<p>Yalova Üniversitesi Sinema Kulübü,</p>\r\n<p>Sinema Kulüpleri Birliği</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/altyazilar/filmkoop_calistay_foto.jpeg" alt="filmkoop1" width="1024" height="576" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 62, 'Ara Yazı', '/images/altyazilar/filmkoop_calistay_foto.jpeg', '2022-05-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (28, 'ay-j326', 'turki-ye-si-nema-yazininda-sekans-dergi-si', 'TÜRKİYE SİNEMA YAZININDA SEKANS DERGİSİ', 'TÜRKİYE SİNEMA YAZININDA SEKANS DERGİSİ', '<p style="text-align: center;"><strong>TÜRKİYE SİNEMA YAZININDA <em>SEKANS</em> DERGİSİ</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Cem Kayalıgil</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><em>HECE Dergisi’nin Haziran-Temmuz-Ağustos 2024 tarihli “Türk Sineması Özel Sayısı”nda (Cilt 1) yayımlanmış olan bu yazıyı, tarihimizin kısa bir özetini sunduğu için kendi internet sitemizde de paylaşmak istedik. Paylaşmamıza izin veren HECE Dergisi’ne ve özel sayının editörlerinden Sn. Hatice Bildirici’ye teşekkür ederiz. (Bağlantı ve görseller yazının bu versiyonunda eklendi.)</em></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><em>Sekans Sinema Kültürü Dergisi</em>, sinema sanatını tarihsel ve kültürel bağlamıyla kucaklamayı önemseyen sinemaseverlerden oluşan Sekans Sinema Grubu’nun kolektif emeğinin en önemli ürünü. 2005’ten beri yayımlanıyor; bugüne bügün, 20’si basılı ve 24’ü <em>sekans.org</em> internet sitesine yüklenmiş e-dergi formatında olmak üzere 44 defa <em>okurunu</em> buldu. Burada “okurunu”yu vurguluyorum: Kanımca, katkısıyla <em>Sekans</em>’ı ilerletmiş ve kendisini <em>Sekans</em>’ın kurgu odasında gören herkesin kıvanç duyabileceği birinci şey, derginin özgünlüğünün kabul görmüş, karşılık bulmuş olmasıdır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bugünkü Sekans Sinema Grubu’nun kökleri, 2002 yılında Ankara’da kurulan Sinema Dostları Derneği’ne uzanıyor. Dernek, ana uğraşısını sinema kuramı, film eleştirisi, film çözümlemesi, senaryo vb. alanlarda eğitim seminerleri düzenlemek olarak belirlemişti. Bu derslerin neredeyse tamamını Gökhan Erkılıç veriyordu, derneğin vizyonunun arkasındaki isim de oydu. Bu nokta, yani Gökhan Erkılıç’ta temsilini bulan şey, saptanmayı ve açımlanmayı -ve bence takdir edilmeyi- özellikle hak ediyor. Zira kanımca, ilk sayısından bugüne <em>Sekans</em>’ta yazı yoluyla cisim kazandırmaya çalıştığımız bakışı da aynı hatlarla tarif edebiliriz. Açıktan açığa öznel bir yorumla diyebilirim ki Gökhan Erkılıç’ın sinema sanatıyla ve sinemanın tarih ve coğrafyaya içkin görünümleriyle kurduğu bağ ayrıksıdır. Körlemesine veya uçarı bir sinefili değildir; çok büyük oranda öz öğrenimli ve ciddi bir sinema okurluğuna yaslanır. Erkılıç buradan, kuşatıcı ve bütünlüklü bir bilgi devşirmiş (hayran kalmamak elde değil), bu bilgiyle de şu ya da bu kuramı (hatta büyük harfle Kuram’ı) baş tacı etmeksizin duyarlı bir eleştirel bakışın geliştirilmesini esas almış. Sinema Dostları Derneği’nin eğitim odaklı yapısının arka planında, böylesi sahih bir birikimi -Erkılıç’ın muazzam bir oylum ve düzenliliğe sahip film ve yazı arşiviyle destekleyerek- başka sinemaseverlerle paylaşma motivasyonu vardı.<a href="#_ftn1" id="_ftnref1"><sup>[1]</sup></a> Ve sözünü ettiğim vizyonun doğal tamamlayıcı parçası, filmler ve sinema kültürü hakkında yazılı üretimde bulunulması yoluyla pasif sinema seyirciliğinin bırakılmasıydı. Bunun ilk (kamusal) çıktısı, fotokopi yoluyla çoğaltılan <em>Kinorama</em> fanzini oldu. Erkılıç’ın dernekteki ilk öğrencileri olarak, onun yanında, bu fanzinde “acemiliğimizi” tamamladık. Ekip 2004 sonu itibarıyla hem özgün hem de Türkçe’ye daha önce çevrilmemiş yazıların yer alacağı, matbaada basılıp Ankara ve İstanbul’daki anlaşmalı kitapçılara elden bırakılacak, referans niteliği taşıyan, ideal senaryoya göre iki ayda bir yayımlanacak bir sinema kültürü dergisini -tasarımını/mizanpajını da üstlenerek- çıkarmaya hazırdı. İşte <em>Sekans</em>’ın sekansı da böyle başladı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/arayazilar/Turkiye_Sinema_Yazininda_Sekans/Sekans-1.jpg" alt="Sekans 1" width="306" height="272" /></p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;"><a href="tr/arsiv/basili-sayilar/142-dergi-1">Sekans Sinema Kültürü Dergisi 1 (Şubat – Mart 2005)</a></span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Şubat-Mart 2005 tarihli ilk <em>Sekans Sinema Kültürü Dergisi</em>’nin<a href="#_ftn2" id="_ftnref2"><sup>[2]</sup></a> “Filmin Koptuğu An” başlıklı önsözü, şaşırtıcı olmayan bir şekilde, bir manifesto niteliğindedir. “Şimdi, sinema ve yayıncılığımız için yeni sekanslar kurma zamanıdır.” sözleriyle son bulan yazıdan yapacağım iki alıntıda ben, Sekans için 19. yılda da hâlâ geçerli olan doğrultunun tarifini buluyorum:</p>\r\n<p>&nbsp;</p>\r\n<p style="padding-left: 60px; padding-right: 60px; text-align: justify; font-size: 9pt; line-height: 1.4;">Sinema Dostları Derneği olarak yaptığımız anketlerden, sinemayla ilgilenenlerin beşte dördünün ara sıra bile olsa bir sinema dergisi okumadığını öğrendik. Popülerin dışında kalana lütfederek yer verenlerin, sinemayı ideolojik bir araç olarak kullananların ya da salt akademik açlıklarının giderilmesi için havanlarında su dövenlerin bizlere izlettirdikleri filmin bundan başka bir sonu da olamazdı. Öyleyse sinemanın gerçek bir sinema dergisine gereksinimi vardı. Sekans işte bu boşluğu doldurmak için çıkıyor.</p>\r\n<p style="padding-left: 60px; padding-right: 60px; font-size: 9pt;">(…)</p>\r\n<p style="padding-left: 60px; padding-right: 60px; text-align: justify; font-size: 9pt; line-height: 1.4;">Sekans’ı düzeyli araştırmacılığı dolayısıyla akademik; gündemle, güncel olanla ve görsel tüketicilerle olan ilişkileri bağlamında popüler ve açıldığı alanın özgül ruhuna eğilmesi bakımından sinematografik bir dergi olarak tanımlamak olası.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/Turkiye_Sinema_Yazininda_Sekans/Sekans-2.jpg" alt="Sekans 2" width="600" height="532" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bu doğrultunun hangi yolla tutturulduğunu bir çırpıda belirginleştirmek için <em>Sekans</em>’ın bölüm başlıklarındaki çeşitliliğe kamera arkasından bakalım derim. Öncelikle iki sabit bölüm olan “Eleştiri” ve “Çözümleme”nin <em>Sekans</em> okurları ve yazarları için olabildiğince net şekilde ayrıştırılması editöryel düzeyde önemsenir. Yaygın anlayışın tersine <em>Sekans</em>’ta film eleştirisi, film çözümlemesinden (hele ki film hikayesinin baştan sona anlatımından) başka bir şey, hatta onun <em>ilerisinde</em> bir aşama olarak görülerek, beğeninin/yerginin somutlaştırılmış ve gerekçelendirilmiş sunumunu ifade eder. “Deneme” bölümü daha “izlenimci” sayılabilecek yazılar içindir; film seyriyle veya sinema yazını okumalarıyla gelen öznel duygu, fikir ve sorgulamaları daha <em>az</em> soğukkanlılıkla paylaşan yazıları da değerli bulduğumuza işaret eder. “Görüntü”, “Senaryo”, “Kısa Film”, “Teknoloji”, “Film Müziği”, “Belgesel” gibi bölümlerde, nokta atışıyla, ilgili alanın detaylarına bakılır (bu bölümlerde söyleşilerden de özellikle yararlanılır). “50 Yaşında” ve “100 Yaşında”nın okurla “başka bir sinema <em>da</em> var” duygudaşlığının en açık şekilde kurulduğu başlıklar olduğuna inanıyorum. Bunlarda, belirli bir yılın filmleri tekil olarak yakın plana alınır, film seçiminde uygulanan baskın ölçüt de <em>gölgede kalmışlık</em>tır (“eksik veya yanlış bilinme”yi de içerecek şekilde). “Sinema Kitaplığı” bölümünü, alandaki kitapları (ağırlıklı olarak yeni yayımlanmış olanları) <em>bizim</em> nasıl okuduğumuzu ortaya koyan değerlendirmelerle oluşturmayı amaçlarız. Bazen bu yazılarla sadece okura değil, yayıncıya, yazara ve çevirmene de hitap ettiğimiz olur. Okur dışındaki bu taraflardan aldığımız takdir mesajları bizleri çok gönendirmiş, birkaç küskün/mutsuz/sinirli geri bildirim de camiaya dair bilgimizi artırmıştır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">“Sinema Arkeolojisi”nde <em>arşivcilik</em> heyecanımızı paylaşırız; sinema yazınının (ve daha geniş düşünürsek, sinema-yazınsal kültürün <em>maddi</em> görünümlerinin) tarihinden detaylar sunarız. &nbsp;“Kuram/Yorum”, “Biyografi”, “Akım”, “Tarih”, “Bir Film Bir Yönetmen”, “Tema” ve elbette “Dosya” gibi başlıklar altındaki yazılar (ve eski, basılı sayılarımızda daha sıklıkla yer verdiğimiz çeviriler) ise, pek de iyi gözle bakmadığımız “akademik söylem”e kapılma tuzağına düşmemeyi çoğunlukla başarabilmiş, yine de derinliğinden şüphe edilmeyecek araştırmaların güzel örneklerini barındırır.<a href="#_ftn3" id="_ftnref3"><sup>[3]</sup></a> <em>Sekans</em> ilk sayısından beri böyle bir renklilikle ve -bence daha da önemlisi- bununla gelen özgün standartların gözetilmesiyle hazırlanıyor.<a href="#_ftn4" id="_ftnref4"><sup>[4]</sup></a></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/arayazilar/Turkiye_Sinema_Yazininda_Sekans/Secki-1.jpg" alt="Secki 1" width="450" height="650" />&nbsp;</p>\r\n<p style="text-align: center;"><span style="font-size: 9pt;"><a href="tr/arsiv/basili-sayilar/128-secki-1">Sekans Sinema Yazıları Seçkisi 1 (Kasım 2009)</a></span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><em>Sekans</em>’ın düzenli yazar kadrosu da dönemden döneme genişliyor; birçok anlamıyla “temas” kurabildiğimiz kişilerle çoğalıyoruz. Bu noktada, 2012’den beri aralıksız olarak düzenlediğimiz Film Eleştirisi ve Film Çözümlemesi Yarışması’nı da ayrıca anmalı (<a href="tr/grup/yarisma">bağlantı</a>). Türkiye sinemasından filmler üzerine çalışmaların değerlendirildiği, kazanan yazıları <em>Sekans</em> sayfalarında yayımladığımız yarışma sayesinde biz de, yeni yazarlara olanak tanıma amacımızın karşılık bulduğunu sevinçle gözlemliyoruz. Sinema yazınını <em>kişilikli bir topluluk olarak</em> zenginleştirmek, bizim için, yola ilk çıktığımız zamandan beri öncelikli hedefti; dolayısıyla diyebiliriz ki biz aslında bu hareketlilikle varlık kazanıyoruz.</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p style="text-align: justify;"><span style="font-size: 9pt;"><a href="#_ftnref1" id="_ftn1"><sup>[1]</sup></a> Bunu geçmiş zaman kipinde yazmamın nedeni derneği 2009’da feshetmiş olmamız. Yoksa Gökhan Erkılıç’ın dersleri bugün de, Sekans Sinema Grubu dediğimiz oluşumun çatısı altında, canlı ve etkin olarak yürütülmeye devam ediyor. Bunun yanına dergi yayımcılığı dışındaki etkinliklerimizle ilgili iki not daha düşeyim (ilkinde Nagihan Konukcu’nun başka bir bağlamda yazdığı cümleleri alıntılıyorum): (1) Sekans Sinema Grubu, Mart 2013’te düzenlenen 24. Ankara Uluslararası Film Festivali’nin festival koordinasyonunu ve program yönetmenliğini üstlendi. Teması “Doğu İmgeleri” olan festivalde az bilinen ülke sinemalarına (Pakistan, Irak, Kazakistan, Birleşik Arap Emirlikleri, vb.) yer verildi. (2) Grubun geçmişinde kısa film yapımı da var. Bugünlerdeyse orta-uzun metraj bir görsel yapımın hazırlığı içerisindeyiz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 9pt;"><a href="#_ftnref2" id="_ftn2"><sup>[2]</sup></a>17x15 cm ölçülerinde 136 sayfadan oluşan birinci sayıda ön kapağın sağ altındaki fiyat ibaresi, o yılbaşıyla birlikte ülke parasında yapılan değişimi de belgeler nitelikte: “4 YTL • 4 MiLYON TL”. “Dergi”nin (Sonrasında çıkarttığımız “Seçki”den ayırmak için böyle yazıyorum.) Ekim – Aralık 2007 tarihli 10. ve son sayısı ise “5 YTL” satış fiyatına sahipti.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 9pt;"><a href="#_ftnref3" id="_ftn3"><sup>[3]</sup></a> Basılı dergilerimizin (“[D]ergi” [2005 – 2007 arası, 10 sayı] ve “[S]eçki” [2009-2014 arası, 10 sayı]) içinde yer almış yazı başlıkları için, internet sitemiz <em>sekans.org</em>’daki “Arşiv” sekmesini kullanabilirsiniz (Aynı sekmeden e-dergi formatındaki sayılarımıza da doğrudan erişebilirsiniz. [Bağlantılar: <a href="tr/arsiv/basili-sayilar/">Basılı sayılar</a> ve <a href="tr/arsiv/e-sayilar">e-sayılar</a>]) Bu dipnotta tadımlık kabilinden, kısmen rastgele seçtiğim bazı eski işlerimizi de anayım.</span></p>\r\n<p style="text-align: justify;"><span style="font-size: 9pt;"><em>Ana Söyleşi:</em> Kim Ki-Duk (D7), József Pacskovszky (D9), Jean-Pierre Limosin (D10), James Monaco (S1), Pascal Bonitzer (S2). // <em>Dosya</em>: Sinema ve Sansür (D2), Pasolini (D5), Rossellini (D7), Fassbinder (D9), Rocha (S8), Sinema ve Edebiyat (S5). // <em>Biyografi</em>: Alice Guy Blaché (D3), Grigori Vasiliyeviç Alexandrov (D8). // <em>Akım</em>: Cinéma Vérité (D10), Çekoslovakya Yeni Dalgası (S8).</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 9pt;"><a href="#_ftnref4" id="_ftn4"><sup>[4]</sup></a> Bu bağlamda tutarlılık ve sürekliliğin sağlanması için kurgu masasında ciddi emek harcamış kişiler olarak Ece Özdemir, Nagihan Konukcu ve Tansu Timuçin’i vefayla anıyorum. Bugünkü e-dergiyi hazırlayan yayın ekibiyse, iyice bir süredir, şu isimlerden oluşuyor (soyadı sırasına göre): Gökhan Erkılıç, Süheyla Tolunay İşlek, Cem Kayalıgil, Derya (Akman) Şele, Seda Usubütün, Ayhan Yılmaz.</span></p>', 64, 62, 'Ara Yazı', '/images/arayazilar/Turkiye_Sinema_Yazininda_Sekans/Sekans-1.jpg', '2024-07-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (29, 'ay-j332', 'truman-show-fi-lmi-uzeri-ne', 'TRUMAN SHOW FİLMİ ÜZERİNE', '', '<h6 style="text-align: center;"><span style="font-size: 12pt;">&nbsp;TRUMAN SHOW FİLMİ ÜZERİNE</span></h6>\r\n<h4 style="text-align: center;"><span style="font-size: 12pt;">Arzu Beyza Yanar</span></h4>\r\n<p><span style="font-size: 12pt;"></span></p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;"><strong>Peter Weir</strong>’in yönettiği 1998 yapımı&nbsp;<strong><em>The Truman Show</em></strong>&nbsp;filmi, kültür endüstrisi ve postmodern tüketim toplumuna dair önemli bir eleştiri sunar. Reality şovunun yönetmeni, büyük sanatçılardan sıkıldığını, senaryoların özgün otantiklikten koptuğunu ilan eder. Filmin geçtiği tüm alan,&nbsp;<strong>Adorno</strong>&nbsp;ve&nbsp;<strong>Horkheimer</strong>’ın kültür endüstrisi kavramıyla okunabilir; burada, genişlemeci kapitalist üretim, kitlesel üretimin standartlaşma mantığı ve “işaretlerin manipülasyonu ya da aşırı üretimi”, üretimin değerini kaybettiği ve tekrar üretimin önem kazandığı “meta işareti” öne çıkar. Filmde, yüksek kültürün saygın nihai hedefleri Las Vegas pop kültürü tarafından derinden yerinden edilir.&nbsp;<strong>Featherstone</strong>, postmodern kültürü, İkinci Dünya Savaşı sonrası geç kapitalizmin derinliksiz tüketimci toplum kültürü olarak görür (Featherstone, 1996). Truman’ın yaşadığı kasabada, temsil ile gerçek arasındaki sınırları bulanıklaştıran işaretlerin yinelenmesi, sözde sosyal bir alan olan gündelik hayata ve gündelik yaşam pratiklerine nüfuz eder; yaşamının her anı kitleleri çeken bir reklam haline gelir. Truman, dışlandığı topluluklarda sosyal ilişkileri inşa etmek için bir merkez ve odak noktası olarak kullanılır. Nesneleştirilmiş, gösteri tarafından hapsedilmiş Truman’ın hayatı yaşanmış bir boyuttan yoksundur; statükonun bir göstergesi haline gelir. Truman’ın hikâyesi, doğar doğmaz televizyon için seçilmek üzere planlandığında başlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p><img src="newui/assets/img/truman1.png" alt="" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">İnsanı toplumun ötesine taşıyan şey “kültürel düzensizlik”tir; televizyonun dünyayı küresel ölçekte kapitalist pazar gücüne dönüştürdüğü imgeler, yan yana getirilenlerdir. Truman’ın vücut biçimi, ses tonu, duruş ve yürüyüş şekli onun bastırılmış kimliğini açığa çıkarır. Truman’ın hayatında hiçbir şey, sembolik metalar ve imgelerin sürekli dolaşımda olması nedeniyle, boş zaman olarak algılanan yaşamında stabil kalmaz.&nbsp;<strong>Adorno&nbsp;</strong>ve&nbsp;<strong>Horkheimer</strong>, kültür endüstrisinin üretim birliğinin eğlenceyi tüketicileri kontrol etmek için işin bir uzantısı olarak araçsallaştırdığını; eğlencenin ise metaları sıkıcılıktan kurtardığını, aynı anda her şeyin ilerleme sürecinde olmasını ve aslında hiçbir şeyin değişmemesini sağlamak için mükemmellik dayattığını ileri sürer.</span></p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">Truman’ın Sylvia ile dans sekansında görüldüğü gibi, kültür endüstrisinin eğlence sahneleri entelektüel aktivitelerle tamamlanır.&nbsp;<strong>Featherstone</strong>’un belirttiği gibi, kültür endüstrisi ve tüketim kültürü kendini “düzenli”, “saygın”, “koruyucu” olarak sunar; endüstri, tüketici taleplerini karşıladıkça kıtlığı aşar (Featherstone, 1996). Bu durumda üretim ilahi kutsal karakterini kaybeder ve yalnızca tüketimi hedefler; tüketim ise boş zamanı hedefler.&nbsp;<strong>Featherstone</strong>, 19. yüzyılın rasyonalizasyon ve modernleşmesinden esinlenen teorileri ile “ihlal, protesto, sınırda aşırılıklar”la karakterize popüler kültür arasında ikili bir karşıtlık kurar. Fuarlar ve festivallerin popüler kültürü, “kültürel düzensizlik alanları” olarak grotesk, fantastik, sınırda mekânlar sunar; meta değişimi, egzotik malların sergilenmesi, günlük yaşamın parçalanması gibi.&nbsp;<strong>Benjamin</strong>&nbsp;de gündelik nesnelerin kitlesel üretiminde ütopik olanı fark ederek Paris’in pasajlarında estetikleştirilmiş metaların sergilendiğini görmüş, onları rüya imajlarına dönüştürmüştür.</span></p>\r\n<p>&nbsp;</p>\r\n<p><img src="newui/assets/img/truman2.png" alt="" width="593" height="332" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">Truman, postmodern dekorlar ve ince yapılar, ürünler arasında dolaşan, merkezsizleşmiş bir özne olarak karşımıza çıkar; sanat, eğlence ve turizme karşı kayıtsız bakışıyla dolaşır. Filmin biçimi, içerikle postmodern anlamda uyumlu olarak metaları estetikleştirir. Seahaven kasabasının pastel renkli evleri, tertemiz sokakları, sürekli gülümseyen komşular aslında bir turizm broşürü ya da bir reklam seti gibi düzenlenmiştir. Burada yaşamın kendisi, bir tatil köyü estetiğine indirgenir. Gerçeklik değil, bir tüketim imgesi inşa edilir. Filmde hava durumundan mimariye, kıyafetlerden diyaloglara kadar her şey bir reklam estetiğiyle parlatılmıştır. Truman bu dekorlar arasında amaçsızca gezinir, çevresindeki sahneleri sorgulamadan gözlemler. Bu, postmodern teoride bahsedilen “merkezsiz özne<strong>”</strong>&nbsp;ile uyumludur: kendi bütünlüklü hikâyesini kurmak yerine, hazır imgeler ve sahneler içinde akıp gider.&nbsp;<strong>Benjamin</strong>’in mekanik çoğaltmasına karşı,&nbsp;<strong>Adorno&nbsp;</strong>ve&nbsp;<strong>Horkheimer</strong>’in kitle kültürü üzerine eleştirel teorisi, çağdaş bilimsel bilinç, pozitivizm ve empirizmin, toplumsal koşulları doğru şekilde teorileştirmek yerine teknokrasinin hüküm sürdüğü mevcut sosyal düzeni onaylamaya adandığı varsayımından doğar; özneler empirik nesneler olarak muamele görür. Onlar, tüm kitle kültürünün aynı olduğunu, yaşamın her bölümünün rasyonel olduğunu ancak sistemin manipüle edilmiş kapalı bir zincir olduğunu ve her tüketicinin kategorize edildiğini ileri sürer.</span></p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">Filmde Truman’ın sorgulama yöntemlerinden habersiz popülizme bağımlı bir mağdur olarak iki seçenekle tuzağa düşürüldüğü görülür: Eğer gösterideki kahraman toplumsal normlara uyarsa “akıl hastası” olarak etiketlenir; uymazsa günlük yaşam nesnesine dönüştürülür. Sonuçta, Truman Show postmodern kültürün bireyi nasıl nesneleştirdiğini ve kültür endüstrisinin özgürlük yanılsamasıyla özneyi nasıl kuşattığını açığa çıkarır. Bu tekrarın zinciri, her defasında başa sararak değişim imkânını ortadan kaldırır.</span></p>\r\n<h5 style="text-align: center;"><span style="font-size: 12pt;"><strong>Kaynakça</strong></span></h5>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">Featherstone, Mike. (1996)&nbsp;<em>Postmodernizm ve Tüketim Kültürü</em>&nbsp;(çev. Mehmet Küçük), Ayrıntı Yayınları.</span></p>\r\n<p style="text-align: justify;"><span style="font-size: 12pt;">Horkheimer, Max ve Adorno, Theodor. (1991) “Chapter 3: The Culture Industry: Enlightenment as Mass Deception”, 94-136.&nbsp;<em>Dialectic of Enlightenment&nbsp;</em>içinde, Routledge.</span></p>', 185, 62, 'Ara Yazı', '/newui/assets/img/truman1.png', '2025-10-11');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (30, 'ay-j334', 'kavak-agacinin-golgesinde', 'Kavak Ağacının Gölgesinde', 'KAVAK AĞACININ GÖLGESİNDE (Kenan Diler, 2025)', '<p style="text-align: center;"><strong>KAVAK AĞACININ GÖLGESİNDE (Kenan Diler, 2025)</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;">Emrah&nbsp;Günok&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/kavak-agacinin-golgesinde-images/poster.jpg" alt="poster" width="500" height="717" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">2025 yılında tamamlanan ve gösterime hazır hale gelen Kavak Ağacının Gölgesinde prömiyerini 16-17 Nisan tarihlerinde İstanbul Film Festivali’nde yapar. Film daha sonra Safranbolu’da “En İyi Belgesel Film” ödülünü alacak, yoluna daha sonra Altın Koza ve Documentarist’le devam edecektir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmin baş karakteri Mikail Haskanlı hayalleri ve yaşamı arasındaki çelişkilere verdiği orijinal tepkiler üzerinden önümüze gelen belgesel, filmin konusunu da teşkil eder. Film Mikail’in sürekli zorluklar içinde yaşamak durumunda kalmış olan annesini en azından hayatının son döneminde rahat ettirmek için açmak istediği butik otel hayalini gündeme taşır. Bu ilginç karakter bir yandan 10 sene önce işletmeye başladığı Eskici Kafe’yi çekip çevirirken, diğer yandan da ev içindeki iktidarını bütünüyle kaybetmiş olan alzheimer hastası babasının yol açtığı sorunlarla boğuşur. Babasının gençlik, kendisininse çocukluk dönemine dair hatırladıkları üzerinden geçmişe açılan film; eve adamın ikinci eşi olarak gelmiş, bu nedenle de olmadık sıkıntılara katlanmak zorunda kalmış olan annenin rahat etmesini sağlayacak butik otelin hayali üzerinden önümüze bir gelecek perspektifi koyar.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Anlatısallık Barındıran Bir Belgesel</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Normal şartlar altında belgesel sıfatını hak eden bir çalışma, kurmaca eserlere baştan başa sinmiş olan anlatısallık etkisinden bütünüyle arınmış olmalıdır. Sözgelimi Afrika’nın Serengeti düzlüklerinde çekilmiş bir aslan belgeseli o ekosistemde yaşayan hayvanlardan birine odaklansa bile, seçmiş olduğu tekili ait olduğu türün herhangi bir bireyi olarak sunmaya devam eder. O bölgede yaşayan dişi aslanlardan sadece birini takibe alan çekim ekibinin derdi kuşku yok ki o aslanı aynı bölgede yaşayan diğer bireylerden ayırt eden özelliklere odaklanmak değil, onu o bölgede yaşamakta olan türün prototipi olarak gündeme taşımaktır. Bu ise, belgesele özgü görme biçiminin ve bu görmenin gündeme getireceği varlıkları taşıyacak olan sinema dilinin asli bir özelliği olarak telakki edilir. Türü göstermek üzere bireye odaklanmak ise belgesel diline özgü bir metafor olarak yerleşiklik kazanır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bu anlamıyla, Mikail’le ilgili olarak ortaya konmuş olan bu çalışmanın da nasıl bir denge üzerinde durmakta olduğunu sorgulamak kaçınılmaz hale gelir. “Kenan Diler’in kurmaca didaktiğiyle kurgulanmış belgeseli, bu bağlamda docu-drama tarzında sağlam bir yapı sunuyor” derken <a href="https://filmhafizasi.com/44-istanbul-film-festivali-gunlukleri-5/">İrem Yavuzer</a>’in tam da böyle bir gerilimi ima ettiğini düşünmek, en azından benim için, kaçınılmazdır. Gerçekten de, nedir docu-drama?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Docu-drama, genele ilişkin bir izlenimi nakletmek üzere metafor öğesi olarak tekili gündeme getirmekten kaçınmayan sinematografik sunum tarzını betimlemek üzere kullanılabilir rahatlıkla. Dolayısıyla bu film dahilinde yönetmenin Mikail’i Van insanının bir benzeri ya da örneği olarak ele aldığını, onu o kişi olarak diğerlerinden ayıran özellikleri ise verilecek mesajı taşıyacak süslü bir zarf haline getirdiğini düşünmek gerekir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">“Mikail’i ilk gördüğümde, çevresine o kadar farklı bir enerji yayıyordu ki. Sanki o coğrafyada doğmuş ama oraya ait değilmiş gibiydi. Bu beni çok etkiledi.”</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmin yönetmeni Kenan Diler’in Safranbolu’da katıldığı ödül törenini müteakiben verdiği <a href="https://www.cinedergi.com/2025/06/13/bir-butik-otelin-pesinde/">bir röportajda</a> dile getirdiği bu cümle yukarıda sorduğumuz soruyu yanıtlamak için önemli bir ipucu barındırıyor olabilir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kendi biricik yaşamı ile karşımıza gelen Mikail ne kadar tekil bir varlıksa, onunla muhtemelen uzun süre arkadaşlık etmiş, dolayısıyla ondan edindiği izlenimi sinematografik bir ürüne dönüştürmeye karar vermiş olan Kenan Diler de biricik bir varlıktır. Ne var ki, biricik, tekrarlanamaz ve tür sınıflamasına dahil edilmesi imkansız görünen bu iki kişinin karşılaşmasından doğan sinerjinin yanı sıra bu enerjinin sonucu olarak ortaya çıkan ürünün de anlatısal bir karaktere sahip olması gerekir. Genelde anlatısal eserler tüm benzemezliğiyle ana karaktere dönüşmüş olan anlatı karakterinin, yine başka hiç kimseyle özdeş olmayan müellifin hayal gücü içinde bir yer bulması sayesinde vücuda gelirler.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bu gerilime rağmen Kavak Ağacının Gölgesinde adlı çalışmayı bir belgesel olarak tanımlamaya devam ediyor oluşumuzun altında yatan temel gerekçe nedir?</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/kavak-agacinin-golgesinde-images/gors02.jpg" alt="gors02" width="1090" height="486" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Genellik İntibaı Yaratan Belgesel Çekimler</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Filmi belgesel gramerine uyan çekimlerle anlatısal bir semantik üzerine kurulu olan sahnelerin kesişip durduğu bir bütün olarak algılamak gerekir. Kameranın Mikail’in evine girdiği, babanın da çekim ekibine katıldığı sahneler gerek Van’daki ortalama bir ev ve bir aileyi tanıtması gerekse de bu insanların yaşamlarından gündelik kesitler sunması anlamında belgesel çekimlere karşılık gelirler. Geçmişiyle hesaplaşan, babanın onları bırakıp Ankara’ya gitmesinden yakınan ve “Bizi hasta olanlar hasta etti” diyecek kadar seyirciyi kendi özel alanına davet eden kız kardeş o an yapılmakta olan çekime öznel bir hava katmak şöyle dursun, nesnel ve belgesel görüntüyü besleyecek bir performans sergilemiş olur.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Burada kamera belgesele içkin olan bir gazetecilik çalışması yürütmekte, ilgili kişilerin tanıklıklarına başvurmak gibi gayet soğukkanlı bir görevi ifa etmektedir. Hatta öyle denebilir ki, kız kardeşin annenin geçmişinden bahsettiği bir sahnede Mikail’in verdiği tepki üzerine “Mikail annesine çok düşkün!” diyerek araya giren yönetmen söz konusu çekimlerin yeteri kadar nesnel olduğundan o derece emin olmuş olmalıdır ki, yaptığı kişisel hamlenin, aile fertlerinin öznelliklerini fazlasıyla uyarıp onların belgesel etkiyi kıracak bir şey yapmayacaklarından neredeyse emin görünür.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Babayla oğulun ayna başına geldikleri sahne veya Mikail’in evden çıkıp caddeye yönelen babayı alıp tekrar eve getirmesi ve onun daha sonra evden çıkmasını önlemek üzere kapıya telden bir kilit yapması gibi sahneler bir sonuca yol açacak olaylar gibi sunulsalar da, aslında babanın içine düştüğü talihsiz hali önemli bir bileşen olarak öne çıkaran bir durum tasviri olmaktan öteye gitmezler. Zaten gitmemeleri de gerekir, zira olay intibaı yaratılmaya başlandığı andan itibaren dramatik etki güçlenmiş, belgesel etki baskılanmış olur. Dolayısıyla Diler’i psikolojik ağırlığı oldukça yüksek olan ev içi gibi bir ortamda dahi kamerayı nesnel bir tavırla kullanabilmiş olmasından dolayı tebrik etmek gerekir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Aynı şey Eskici Kafe’nin sıradan bir gününü tasvir etmekle yetinen sahneler için de söylenebilir. Bu noktada belirtmeden geçmenin imkansız olduğunu hissettiğim temel bir husus vardır ki, o da bu filmin ana karakteri ve yönetmen arasındaki dilsel bir çekişmenin ürünü olduğu intibaını üzerimden hiçbir anda atamamış olduğumdur. Gerçekten de, yönetmen filmi bir belgesel kıvamına getirmeye çalışırken Mikail işin başından itibaren kurmaca/anlatısal etkiyi besleyecek bir oyunculuk performansı sergiler.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Eskici’nin herhangi bir günü, gelen müşteriyi her an kışkırtma ve olay çıkarma potansiyeli taşıyan anons ve olaylarla doludur. Müşterinin her zaman haklı olmadığını, sigaranın tek tek içilmesi gerektiğini ve kendini orada zamanın efendisi ilan eden işletmecinin insanlara aceleci olmamaları yollu hatırlatmaları bunlara bağlı olarak kopabilecek başka olaylara davetiye çıkartmaya gebe görünseler de aslında mekanın duygusal atmosferine ilişkin fikir veren betimsel sekanslar olmakla kalırlar. “Burası da böyle bir yermiş, gerçekten ilginç!” dedirtmekle kalır, tasvir işlevine bağlı kalmaya devam ederler.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kafeye gelip de içeride yer olmadığı için dışarıda beklemek konusunda sıkıntı çıkaran müşteri sahnesi, Mikail’in onları beklemeyi bilmemekle suçlaması ve onların da başka bir yere gitmek üzere mekanı terk etmeye kalkmaları pek tabii ki olay gibi görünmeye en yakın sahnedir. Filmin bu sahneden feragat etmeyip de onu belgesel diline ustalıkla yedirmesi gerçekten büyük bir başarıdır. Yönetmenin belgesel dilinin yaratabileceği sıkıcılığı kıracak, ama filmin nesnel tavrına da halel getirmeyecek bir denge içinde bu gerilimli sahneyi elden çıkarmamakla çok iyi ettiğini düşünmemek olanaksızdır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Mikail’in arsa bakmak için Gevaş’ta bir emlakçıyı ziyaret ettiği sahnede kullanılan gizli kamera çekimi, yapılan işin bir de gazetecilik boyutu olduğu hissiyatını besleyerek belgesel dile bir katkı sunmuş olur. Söz konusu sahne boyunca emlakçının sergilediği duyarsız tavır Mikail’in tadını öyle bir kaçırır ki, ana karakterin en doğal anlarında bile değme oyuncuya taş çıkartacak bir auraya sahip olduğunu görmezden gelmek hepten imkansızlaşır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ailesinin yanında büründüğü sessizlik emlakçının karşısında maruz kaldığı kilitlenmeyle yan yana gelerek ana karakterin içindeki kırılganlığı dışa vurur.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Psikolojik Derinlik Sunan Anlatısal Çekimler</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Mikail’in Eskici’yi terk edip şehir sokakları boyunca yürüdüğü sahneler boyunca kameranın ona neredeyse yapışık gidiyor oluşu gözlerden kaçmamış olmalıdır. Kenan Diler’in film boyunca bağlı kaldığı bu tercih daha sonra bahsedeceğim bir başka çekim tekniğiyle dengelenecek, bu sayede de karakterin psikolojik derinliğine yer açarak esere dramatik bir ton kazandıracaktır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kameranın ana karakterin şehirdeki dolaşmaları esnasında ona yakından eşlik etmesinin iki işlevi var gibi görünmektedir: seyircinin bakış açısını daraltarak Mikail’in aslında ait olmadığı, içinde sıkıştığı ve kendini çok da özgür hissetmediği bir ortamda yaşıyor olduğunu ihsas ettirmek; ikinci olarak da onu yalnız bırakmayıp sürekli kollamak suretiyle karakterin kendi gölgesi haline gelmiş kameradan başkaca bir yoldaşı olmadığı duygusunu canlı tutmak. Belgesel dili devam ettirecek olsa oyuncuyu daha nesnel bir plandan görmeyi tercih etmesi gerekecek olan kameranın bu yakınlığı, mesafeyi neredeyse kameranın kendisini ikinci bir oyuncu olarak plana dahil etmiş, bunu da kadim dostunu yalnız bırakmamak adına yapmış olduğu duygusunu uyandırır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bu yorumu besleyecek olan sahne ise kameranın Mikail’i bir başına bıraktığı, bu sayede de onu beceriksiz ve ürkek bir tavırla şehir müzisyenlerine eşlik etmeye çalışırken kayda aldığı sahnedir. Kameranın onun can yoldaşı olduğu, onun onu yalnız bırakıp da görev mesafesine çekilmesi durumunda karakterin ne kadar biçare kaldığını ortaya koyan bu sahne, duygusal derinliği yakalamak için kamerayı da oyuncuya dönüştürmek gibi bir buluş üzerinden tasarlanmışsa gerçekten de amacına ulaşmış gibi görünmektedir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Şimdi gelelim yukarıda verdiğimiz sözün gereğini yerine getirmeye. Kameranın bahsi geçen sahnede ana karakterden ayrılması o ana kadar ona yapışık gitmesinin birinci anlamını verir. Kameranın ayrılmasıyla ortaya çıkan ikinci anlam ise ana karakteri artık kendi haline bırakma zamanının geldiği, çünkü onun şehrin onu ezen ağır havasını üzerinden atmış olduğunu dışa vuran çok daha iyimser bir anlamdır. Filmin girişinde yer alan ve Mikail’i gölün kenarında uzak plan üzerinden ekrana taşıyan çekimin anlamı şimdi belirginleşmiştir. Çünkü gölü arka fona almış ve Mikail’i kendi başına bırakmış olan kamera seyircinin görüş alanını genişletip karakterin ferahlayarak kendine döndüğünün müjdesini verir. Yakın takip ve geriye çekilmelerin meydana getirdiği ikililer serisi elimizdeki eserin gerçek bir sinema diline kavuşabilmiş olduğunu mükemmelen örnekler gibidir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Mikail’i otelin maketini yapmak için Eskici’de gece işe koyulmuşken gösteren çekimler, eşlik eden müzik ve yakın-uzak çekim trafiğinin ona göre ayarlanmış olması film boyunca anlatısal etkinin kendini en güçlü biçimde dışa vurduğu sahne olarak öne çıkar. Çalışan elleri, çatılmış kaşları ve kullanılan malzemeyi ayrı ayrı konu alan çekimler ve bu çekimleri dinamik bir şekilde art arda sıralayan montaj, bir de ona eşlik eden müzikle bir araya gelince ana karakterin ruhunda kopan fırtınanın yarattığı dramatik etkiyi dışa vurmuş olur. Bu noktada filmin genel ritmi yanı sıra özellikle bu sahnenin akışına çok uygun tarzda bestelenmiş olan, bu anlamıyla da eldeki yapıtın nabzı haline gelmeyi başaran besteler için Eriş Dervişoğlu ve Sabır Erdinç’i ayrıca tebrik etmek gerekir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ortalama belgesel dilinin butik otelin maketinin yapım sürecini orta planda kaydedip montajı da işin gelişimini sakince yansıtacak bir ritme mecbur etmesi beklenebilecekken, çekilen malzemenin el, yüz, kıl testere gibi çok küçük parçalarını oldukça yüksek bir ritimde ve dinamik bir müzik eşliğinde sunmak aksiyon filmlerinden alışkın olduğumuz anlatısal bir etkiyi tahrik eder. Burada karşımıza gelen Mikail’in bir durumu değil, onu nihai sona taşıyacak olan nedenin olay karakteri arz eden bir sunumudur.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/kavak-agacinin-golgesinde-images/gors01.jpg" alt="gors01" width="1090" height="488" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Çekilmeye Direnen Bir Oyuncu: Mikail Haskanlı</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bende kalan intiba odur ki, Van’ın sosyokültürel dokusunu, burada yaşanan hayatların bir ortalamasını aktarabilmek için çekilecek bir belgesel başka bir oyuncudan yola çıkılarak yapılmış olsa muhtemelen yalnızca bir belgesel olmakla kalırdı. Elimizdeki bu eseri belgesel olmaktan docu-dramaya evriltmekte en büyük paya sahip olanın ana karakter olduğu bana olduğu kadar diğer seyircilere de aşikar gelmiş olmalıdır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bunun en önemli sebebi, tuhaf bir biçimde, Mikail’in hiçbir surette rol yapmıyor gibi görünmesidir. Öyle bir oyuncu profili ortaya koymaktadır ki, kendin ol desen oynayacak, şunu oyna desen de bu sefer kendini bir oyun olarak ortaya koyacakmış intibaı yaratır. Eskici’nin patron bölmesinde Mikail’in sorulan soruları yanıtlamaktansa uzun bir tirat atması gözden kaçmamış olmalıdır. Bunun nedeni büyük ihtimalle, onun bir insan olarak sizin sorduğunuz sorunun yarattığı talebi daha geniş bir anlam zemini üzerine yayarak diyalog talebini boşa çıkaracak olmasıdır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Şurası açıktır ki, Mikail kamera önüne geldiği her durumda içinden zaten ve halihazırda başlatmış olduğu bir konuşmayı devam ettirmektedir. Filmi izlerken benim ona taktığım lakap, sırf bu yüzden, “anneannemin radyosu”dur. Açılma, kapanma ve kanal değiştirme anlarına hiç denk gelemediğimiz, bize sadece kendi istediklerini kendi istediği biçimde anlatmayı tercih eden, bütünüyle özerk bir varlıktır bu radyo. Bir yerde “gitmeyi bilemeyen kalmayı da bilemez”, bir başka yerde “kendime yabancıyım, dünyaya da yabancıyım” ve en önemlisi, gölün kenarında “kendimize bizi kimsenin bulamayacağı, ama herkesin bulabileceği bir yer yapacağız” diyen; içindeki sesi neredeyse kendisi de kontrol edemeyen bir filozof vardır karşımızda.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/arayazilar/kavak-agacinin-golgesinde-images/gors03.jpg" alt="gors03" width="1089" height="486" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Evet, böyle bir oyuncuyu yönetmek büyük bir odaklanma ve derin bir sezgi gerektirir. Mikail Haskanlı’nın oyunculuğu, destek sunan ve işin tamamlanmasına katkı veren bir oyunculuk olmaktan çok baş edilmesi, ehlileştirilmesi gereken bir performans hüviyetine sahipmiş izlenimi yaratır. Yoldaşlık/yüzüstü bırakma, sıkışma/ferahlama ve kararsızlık (şüphe)/dirayet(le işe koyulma) ikililerinden meydana gelen semantik birimleri uzak ve yakın çekimler sayesinde ustalıkla düzenleyerek bir sinema diline dönüştürmeyi başaran Kenan Diler’i bu noktada gerçekten tebrik etmek lazım gelir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Evet, prestijli bir film festivalinde kimseye bedavadan birincilik verilmez. Dramatik tonu yükseltme konusunda bu denli etkili olan bir oyuncuyu bu denli ustalıkla kıvama getirmek bir meseledir. Mikail Haskanlı’nın yaratıcı ama cıva misali performansını tutarlılık arz eden böyle sağlam bir sinema dili içinde ehlileştirmeyi başaran yönetmenin de kazandığı başarıya şaşırmamak gerekir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sinema diline hakimiyeti konusunda kendini bu denli kanıtlamış olan genç yönetmenin eğer kurmacaya yönelse nasıl işler çıkartacağını merak etmemek mümkün değildir. Ama şu an için biz seyirciye düşen onu büyük bir içtenlikle tebrik etmektir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">28 Ekim 2025, Van</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Kavak Ağacının Gölgesinde filmi resmi fragmanı için <a href="https://www.youtube.com/watch?v=NBW7dbNVSRs">tıklayın [YouTube]</a></p>', 157, 62, 'Ara Yazı', '/images/arayazilar/kavak-agacinin-golgesinde-images/poster.jpg', '2025-11-11');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (31, 'ay-j152', 'hayata-calim-at-uzerine-futboldan-sonra-hayat-var-mi', 'Hayata Çalım At Üzerine: Futboldan Sonra Hayat Var mı?', 'Serhan Mersin', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Hayata &Ccedil;alım At (Looking for Eric, 2009) &Uuml;zerine:</h2>\r\n<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><b>Futboldan Sonra Hayat Var mı?</b></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Serhan Mersin</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span><a href="mailto:webtasarim@sekans.org" style="color: #895f37;">webtasarim@sekans.org</a></span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px;"><span style="font-size: 10pt;"><b><span>Hayata &Ccedil;alım At (Looking For Eric)</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Y&ouml;netmen:&nbsp;</span></b><span>Ken Loach</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Senaryo:&nbsp;</span></b><span>Paul Laverty</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni:&nbsp;</span></b><span>Barry Ackroyd</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>M&uuml;zik</span></b><span>:&nbsp;</span><span>Isobel Griffiths</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Kurgu</span></b><span>:&nbsp;</span><span>Mark Wright</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Oyuncular:&nbsp;</span></b><span>Steve Evets, Eric Cantona, Stephanie Bishop, Gerard Kearns, Stefan Gumbs, Lucy-Jo Hudson, John Henshaw</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Yapımcı:&nbsp;</span></b><span>Rebecca O\'Brien</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>2009/116&rsquo;/Birleşik Krallık-Fransa-İtalya-Bel&ccedil;ika-İspanya</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/looking_for_eric2.jpg" alt="looking for eric2" width="499" height="401" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-family: Verdana;"><span style="font-size: medium;">K</span><span style="font-size: x-small;">e</span></span></b><b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">n Loach</span></b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&rsquo;ın&nbsp;<b><i>Kerkenez</i></b>&nbsp;(<i>Kes</i>, 1969) filmi, İngiltere&rsquo;nin Barnsley şehrinde iş&ccedil;i sınıfı k&ouml;kenli bir ailenin k&uuml;&ccedil;&uuml;k oğlu Billy Casper&rsquo;ın okulda ve evde yaşadığı horg&ouml;r&uuml;y&uuml; alt ederek hayata tutunmasını sağlayan bir kerkenez ile olan ilişkisini anlatır. Britanya Film Enstit&uuml;s&uuml; tarafından Britanya tarihinin en iyi yedinci filmi se&ccedil;ilen&nbsp;<b><i>Kerkenez</i></b>&rsquo;in unutulmaz sahnelerinden bir tanesi &ouml;ğrencilere beden eğitimi dersinde karşılıklı ma&ccedil; yaptıran &ouml;ğretmenin oynadığı sahnedir. &Ccedil;ocukken topun sahibi olduğu i&ccedil;in oynatılmak zorunda olan şişman ve zengin &ccedil;ocuklar gibi hodbince tavırlar sergileyen orta yaşlardaki &ouml;ğretmen, d&ouml;nemin klasik Manchester United formasıyla ma&ccedil;a hem oyuncu hem de hakem olarak dahil olur. Ma&ccedil;ta kuralları kendisi koyar, pek &ccedil;oğu ma&ccedil;ta metazori oynayan &ouml;ğrencilere kaba davranır; onları tokatlar, &uuml;zerlerine top atar. &Ccedil;oğu zaman kendi takımını kayıracak kararlar alır, kendisine yapılan bir hareket i&ccedil;in penaltı verir mesela. Kalecinin penaltıyı kurtarması &uuml;zerine atışı tekrarlattırır. Nihayetinde gol&uuml; attıktan sonra ise orta noktaya koşarken kendisinin Manchester United&rsquo;ın efsanevi oyuncusu&nbsp;<b>Bobby Charlton</b>&nbsp;olduğunu s&ouml;yler. Zaten &uuml;zerindeki forma da&nbsp;<b>Bobby Charlton</b>&rsquo;ın dokuz numaralı formasıdır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Ken Loach</span></b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&nbsp;bu filmden 30 yıl sonra bir başka filminde,<i>&nbsp;<b>Hayata &Ccedil;alım At</b></i>&rsquo;ta (<i>Looking For Eric</i>, 2009) başka bir efsane Manchester United&rsquo;lıyı,&nbsp;<b>Eric Cantona</b>&rsquo;yı filmine dahil ediyor. Ama bu sefer kanlı ve canlı olarak, filminde &ouml;nemli bir rol da vererek.&nbsp;<b>Cantona</b>&nbsp;belki futbol i&ccedil;in erken sayılacak bir yaşta, 30 yaşında futbola veda ettiğinde, arkasında adına besteler yapılan muhteşem bir d&ouml;nem bırakmıştı. Sadece portakal soyar gibi oynadığı futboluyla değil, felsefi kişiliğiyle de takdir toplamış, yeşil sahalarda ender rastlanan bir fenomen halini almıştı. Attığı veya attırdığı zek&acirc; dolu gollerin yanısıra hır&ccedil;ın tavırlarıyla ve dikbaşlılığıyla tanınmıştı. Bu tavrını pekiştiren ve onu futboldan dokuz ay uzaklaştıracak bir ceza almasına neden olan ise 1995 yılında bir Crystal Palace ma&ccedil;ında g&ouml;rd&uuml;ğ&uuml; kırmız kart sonrası soyunma odasına giderken kendisine k&uuml;freden ırk&ccedil;ı bir taraftara u&ccedil;an tekmeyle saldırması ve bununla da yetinmeyip taraftarı yumruklaması olmuştu.&nbsp;<b>Ken Loach</b>&rsquo;ın bu zapt&uuml;rapt altına alınması g&uuml;&ccedil; futbolcuda g&ouml;rd&uuml;ğ&uuml; muhtemelen işte bu sıradışı kişilikti: Zirvedeyken futbolu bırakmakta beis g&ouml;rmeyen, nevi şahsına m&uuml;nhasır bir kişilikle s&ouml;ylenmesi ve yapılması gerekenleri &ccedil;ekinmeden ifşa eden ve her zaman kendi bildiği doğru yoldan giden birisi olmasıydı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;"><img src="/images/yazilar/eric-cantona-in-the-air.jpg" alt="eric-cantona-in-the-air" width="550" height="331" style="display: block; margin-left: auto; margin-right: auto;" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Dokuz aylık cezadan d&ouml;n&uuml;ş&uuml;n&uuml; Sunderland ma&ccedil;ında attığı iki golle kutlamıştı&nbsp;<b>Cantona</b>. O ma&ccedil;ta attığı gol futbolculuk kariyerinin en &uuml;st noktalarından birisi haline gelecektir. Orta sahadan aldığı topu s&uuml;r&uuml;p, takım arkadaşı&nbsp;<b>McClair</b>&nbsp;ile paslaştıktan sonra kalecinin &uuml;zerinden aşırttığı ve direğe &ccedil;arparak i&ccedil;eri giren gol. Alamet-i farikası yakası kalkık formasıyla gol sonrası bir an i&ccedil;in duruşu, etrafında d&ouml;n&uuml;p seyirciye vakur bir şekilde bakışı, g&ouml;ğs&uuml;n&uuml; kabartışı, kollarını yukarı doğru kaldırışı ve sonrasında takım arkadaşlarıyla gol&uuml; kutlayışı. Bir gol i&ccedil;in sevinmedeki asalet bile onu anlatmak i&ccedil;in yetecektir. Gelgelelim, bu gol değildir futbol sahalarındaki en &ouml;nem verdiği an. Filmde, &ldquo;<b>King Eric</b>&rdquo;&nbsp;<b>Cantona</b>&nbsp;hayatının en g&uuml;zel anının bir gol değil, bir pas olduğunu s&ouml;yler. Tottenham Hotspur ma&ccedil;ında takım arkadaşı&nbsp;<b>Irwin</b>&rsquo;e sağ ayağının dışıyla verdiği pas onun deyişiyle &ldquo;b&uuml;y&uuml;k futbol tanrısına bir hizmet gibi&rdquo;dir. &nbsp;<b><i>Hayata &Ccedil;alım At</i></b>&nbsp;bu minvalde işleyen; gol atmanın değil, gol pası vermenin, dayanışmanın, birlikten doğan g&uuml;c&uuml;n filmi.&nbsp;<b>Tanıl Bora</b>&rsquo;nın futbolun sol tarzı olarak nitelendirdiği, &ldquo;paslaşarak, paylaşarak, takım ruhuyla, oyundan zevk alarak, neşeyi &ccedil;oğaltmak i&ccedil;in&rdquo; oynanan bir oyunun filmsel temsili. Neredeyse her&nbsp;<b>Ken Loach</b>&nbsp;filmine konu olan sosyal hiyerarşinin dibinde yer alanların, &ccedil;alışan sınıfların, kaybedenlerin, yoksulların, şiddete maruz kalanların sadece ve sadece birlik olabilirlerse kazanabileceğinin bir temaşası. &nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Sosyal ger&ccedil;ek&ccedil;ilik temalı filmlerini yer yer melodram, yer yer de mizahla harmanlayarak her zaman politik sinemanın başarılı bir temsilcisi olan&nbsp;<b>Ken Loach</b>, belgesele yakın duru anlatımıyla sıradan insanın ve ezilenlerin sesi haline gelereks&ouml;m&uuml;r&uuml;lenlere bakan bir film ortaya &ccedil;ıkartıyor. Daha &ouml;nce&nbsp;<b><i>Carla&rsquo;nın Şarkısı&nbsp;</i></b>(<i>Carla&rsquo;s Song</i>, 1996),&nbsp;<b><i>Benim Adım Joe</i></b>&nbsp;(<i>My Name is Joe</i>, 1998),&nbsp;<b><i>Ekmek ve G&uuml;ller</i></b>&nbsp;(<i>Bread and Roses</i>, 2000),&nbsp;<b><i>Afili Delikanlı</i></b>&nbsp;(<i>Sweet Sixteen</i>, 2002),&nbsp;<b><i>Ae Fond Kiss</i></b>&nbsp;(2004), Cannes Film Festivali&rsquo;nde Altın Palmiye kazanan&nbsp;<b><i>&Ouml;zg&uuml;rl&uuml;k R&uuml;zgarı</i></b>(<i>The Wind That Shakes the Barley</i>, 2006),<i>&nbsp;<b>İşte &Ouml;zg&uuml;r D&uuml;nya</b></i>&nbsp;(<i>It&rsquo;s a Free World</i>, 2007) gibi son d&ouml;nem &ccedil;ektiği filmlerinin senaryosunu yazan&nbsp;<b>Paul Laverty</b>&nbsp;ile<i><b>Hayata &Ccedil;alım At</b>&rsquo;</i>ta da beraber &ccedil;alışıyor. Kontrgerilladan, İrlanda&rsquo;nın &ouml;zg&uuml;rl&uuml;k kavgasına; g&ouml;&ccedil;men iş&ccedil;ilerin &ccedil;alışma koşullarından, İngiliz hukuk sistemine muhtelif konulara değinen&nbsp;<b>Loach</b>, bu filmiyle futbol d&uuml;nyasına el atarak, o &ccedil;ok bilindik ve artık biraz da bayatlamış bir metafor &uuml;zerinden, hayat ve futbol ilişkisi &uuml;zerinden anlatısını kurmaya &ccedil;alışıyor. &ldquo;Ben herhangi biri değilim, ben&nbsp;<b>Cantona</b>&rsquo;yım&rdquo; diyen bir futbol ilahının, en son kendisini seyrettiği yıllar &ouml;nceki bir ma&ccedil;ta&nbsp; mutlu olan bir postacının hayatına girerek onu değiştirmesini anlatıyor. Aslında her şey, filmin jeneriğinde de karşımıza &ccedil;ıktığı &uuml;zere&nbsp;<b>Cantona</b>&rsquo;nın g&uuml;zel bir pasıyla başlıyor.&nbsp;<b>Eric Cantona</b>&rsquo;nın bu pası y&ouml;netmen&nbsp;<b>Ken Loach</b>&nbsp;tarafından başarıyla değerlendiriliyor. İki ayrı anlatıyla ilerleyen film, dengeli melodramatik yapısıyla bir nevi romantik komediye evriliyor ve yer yer klişeye ka&ccedil;sa da vermek istediği mesajı seyirciye ulaştırıyor.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&ldquo;En asil intikam affetmektir&rdquo;</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Filmin ilk b&ouml;l&uuml;m&uuml;nde postacı Eric Bishop&rsquo;un hayatının i&ccedil;ine giriyoruz. Postacı Eric, ikinci evliliğinden kalma, onu pek de &ouml;nemsemeyen &uuml;vey oğullarıyla aynı evde yaşayan, işte yapması gereken dağıtımları aksatan, hayatını bir t&uuml;rl&uuml; rayına oturtamayan bir panik atak hastası. Makus talihi, ilk eşi Lily&rsquo;den olan kızının okulu bitirebilmek i&ccedil;in yazması gereken tez ile ilgili &ccedil;alışmalarını yapabilmesi i&ccedil;in bebeğine daha uzun s&uuml;re bakmasını istemesiyle değişir. Zira Eric, bebeği kızının annesinden, bebek doğduğu sıralarda terkettiği Lily&rsquo;den alacaktır. Bu da ka&ccedil;ınılmaz olarak uzun bir s&uuml;re sonra Lily ile tekrar karşılaşmasını getirecektir. Eric, bebeği almaya gittiğinde, Lily&rsquo;yi uzaktan g&ouml;rd&uuml;ğ&uuml;nde kaybettiklerinin farkına varır. Mutsuzluğunun &ccedil;aresini oğlunun odasından &ccedil;aldığı otla gidermeye &ccedil;abalarken, duvarında resmini astığı &ldquo;d&uuml;nyanın g&ouml;r&uuml;p g&ouml;rebileceği en harika santrfor&rdquo;&nbsp;<b>Eric Cantona</b>, postacı Eric&rsquo;in alter egosu olarak g&ouml;rd&uuml;ğ&uuml; halusinasyonlarda ortaya &ccedil;ıkar. Futbolcu Eric, bir filozof&ccedil;asına postacı Eric&rsquo;e hayatla ilgili &ouml;ğ&uuml;tler vermeye başlar. Bu &ouml;ğ&uuml;tler sayesinde postacı Eric, Lily&rsquo;yle y&uuml;zleşebilecek g&uuml;c&uuml; bulur. Neden onu terkettiğini, onu asla unutmadığını anlatır. Tekrar g&ouml;r&uuml;şmeye başlarlar.&nbsp;<b>Cantona</b>&rsquo;nın &ouml;ğ&uuml;tleri işe yaramıştır: Eric, Lily&rsquo;nin g&uuml;venini tekrar kazanır. Lily&rsquo;nin yaptığı ise onu affetmektir, b&ouml;ylelikle intikamını alacaktır&nbsp;<b>Cantona</b>&rsquo;nın &ouml;ng&ouml;rd&uuml;ğ&uuml; şekilde.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&ldquo;Her zaman d&uuml;ş&uuml;nd&uuml;ğ&uuml;nden daha fazla se&ccedil;eneğin vardır&rdquo;</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Filmin paralel devam eden ikinci hikayesi ise Eric&rsquo;in beraber yaşadığı &uuml;vey oğullarının başlarını derde sokmasıyla ortaya &ccedil;ıkıyor. Televizyondan, beton karma makinasına kadar &ccedil;aldıkları pek &ccedil;ok eşyayı eve getiren, evde arkadaşlarıyla kafalarına g&ouml;re takılan &ccedil;ocuklara karşı Eric evin d&uuml;zenini korumayı kendine g&ouml;rev bilir. Ne var ki, b&uuml;y&uuml;k kardeş Ryan&rsquo;ın mahallenin &ldquo;ağır abi&rdquo;lerinden birisinin silahını evde saklamaya başlamasıyla işler değişir. Aynı silahla bir yaralama olayının olması ve ardından evin polis tarafından basılması sonucu silahtan kurtulmaya karar veren Eric, mafyatik elebaşından sıkı bir dayak yeyip bu dayağın g&ouml;r&uuml;nt&uuml;leri YouTube&rsquo;a d&uuml;ş&uuml;nce &ccedil;&ouml;z&uuml;m&uuml;&nbsp;<b>Cantona</b>&rsquo;nın &ouml;nerisiyle postacı ve taraftar arkadaşlarına danışmakta bulur. Manchester United&rsquo;ın Amerikalı işadamları tarafından satın alınmasına duyulan tepkiyle kurulan FC United&rsquo;ın bir deplasman ma&ccedil;ına beraber giden &uuml;&ccedil; otob&uuml;s dolusu taraftarla, &ldquo;Cantona Operasyonu&rdquo; verdikleri bir organizasyonla hep beraber mafyatik liderin evini sırtlarında formaları, kafalarında&nbsp;<b>Cantona</b>&nbsp;maskeleriyle basarlar. Boyalı su tabancalarıyla &ccedil;ete &uuml;yelerini boyamakla ve beyzbol sopalarıyla evlerini darmadağın etmekle kalmayıp silahı da par&ccedil;alarlar. T&uuml;m bu olanları video kameraya &ccedil;ekip mafyayı, en korktuğu silahla, YouTube&rsquo;a d&uuml;ş&uuml;p rezil olmakla tehdit ederler. B&ouml;ylelikle &ouml;nce Ryan&rsquo;ın ve dolayısıyla k&uuml;&ccedil;&uuml;k kardeş Jess&rsquo;in başındaki sorun Eric ve arkadaşlarının birlikte dayanışmasıyla &ccedil;&ouml;z&uuml;l&uuml;r. Futbolcu Eric&rsquo;in insanın en zor anlarında bile her zaman daha fazla se&ccedil;eneğinin olduğunu hatırlatıp takım arkadaşlarına, attığı pasın gol olacağına inancının tam olması gibi, g&uuml;venmenin her koşulda sonu&ccedil; vereceğini işaret etmesi birlikten doğacak kuvvetin bir sonucu olur dolayısıyla.&nbsp;<b>Cantona</b>&rsquo;nın, &ldquo;eğer senden hızlılarsa, onları ge&ccedil;meye &ccedil;alışma. Eğer uzunlarsa, &uuml;stlerinden atlama; eğer solları g&uuml;&ccedil;l&uuml;yse, sağlarından git. Onları şaşırtmak i&ccedil;in &ouml;nce kendini şaşırt&rdquo; diyerek farklı se&ccedil;eneklerin olasılığını hatırlatması g&uuml;n&uuml;m&uuml;z&uuml;n kapitalist d&uuml;nyasına bir direnişin de g&ouml;stergesi olduğuna inandırır bizleri.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><img src="/images/yazilar/looking-for-eric1_520x347.jpg" alt="looking-for-eric1 520x347" width="520" height="347" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&ldquo;Otoparklar yalan s&ouml;ylemez&rdquo;</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Kapitalizme direniş noktalarından başka bir tanesi ise Manchester United&rsquo;ın Amerikalı işadamları tarafından gasp edildikten sonra bu duruma bir tepki olarak aynı takımın taraftarları tarafından kurulan FC United oluyor. Tıpkı Wimbledon FC&rsquo;nin, kul&uuml;b&uuml; satın alan şirket tarafından başka bir şehre taşınmasına tepki olarak taraftarların biraraya gelerek kendi kul&uuml;plerini, AFC Wimbledon&rsquo;ı kurmaları gibi artık futbol ma&ccedil;larına biletlerin y&uuml;ksekliği nedeniyle gidemeyen, (ki filmde Eric 10 yıldır canlı bir ma&ccedil; seyredemediğini s&ouml;yl&uuml;yor Old Trafford&rsquo;da), takımı para i&ccedil;in satan zengin başkanlardan usanan ger&ccedil;ek taraftarın sesi haline geliyor FC United. AFC Wimbledon taraftarının a&ccedil;tığı yoldan giderek kurulan FC United&rsquo;ın taraftarlarıyla, bir şampiyonlar ligi ma&ccedil;ını seyretmek i&ccedil;in&nbsp;<i>pub</i>&rsquo;a doluşan Manchester United&rsquo;lılar arasında end&uuml;striyel futbol &uuml;zerine yapılan tartışma, biraz da&nbsp;<b>Loach</b>&rsquo;ın&nbsp;<b><i>&Uuml;lke ve &Ouml;zg&uuml;rl&uuml;k</i></b>&nbsp;ile&nbsp;<b><i>&Ouml;zg&uuml;rl&uuml;k R&uuml;zgarı</i></b>&nbsp;filmlerindeki sıkı tartışmaları hatırlatıyor ister istemez. Ne var ki, g&ouml;r&uuml;nen k&ouml;ye kılavuz da gerekmez. Hangi takımı tutarlarsa tutsunlar, ma&ccedil; g&uuml;nleri stadların otoparklarında park etmiş arabalara baktıklarında karşılarına &ccedil;ıkan manzara herşeyi anlatır: İngiltere&rsquo;de futbol artık sadece &uuml;st sınıfın bir eğlencesidir. Aslında sadece İngiltere&rsquo;de değil, sponsorlarıyla, yayın haklarıyla, transferleriyle milyarlarca dolarlık bir pastayı paylaştıran ama buna karşılık futbolun seyir zevkinden alınacak hazzı en sona bırakan anlayışıyla diğer liglerde de aynı şey ge&ccedil;erli değil mi sanki? Stadlarda sessizce ma&ccedil; izleyen, gol olduğunda m&uuml;cevherlerini şıngırdatan ruhsuz bir taraftarlık anlayışına karşılık FC United&rsquo;lılar en azından sponsorsuz, g&ouml;n&uuml;lden gelen sevgileriyle futbolun g&ouml;rece saf halini yaşatmaya devam ediyorlar aslında.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Haliyle herkesin takım değiştirme durumunu desteklediğini iddia etmek doğru olmayacaktır.&nbsp;<i>Pub</i>&rsquo;daki tartışmada bir taraftarın, &ldquo;karını değiştirebilirsin, politik g&ouml;r&uuml;ş&uuml;n&uuml; değiştirebilirsin, dinini değiştirebilirsin ama asla ve asla tuttuğun takımı değiştiremezsin&rdquo; diyerek taraftarlığın her şeyin &uuml;zerinde bir anlamı olduğunu işaret etmesi FC United&rsquo;lıların, ilk g&ouml;z ağrıları Manchester United&rsquo;a karşı sevgilerinin yok olmadığının bir g&ouml;stergesi. Zira, s&ouml;yledikleri marşlardaki &ldquo;İki&nbsp;<i>United</i>&nbsp;ama tek ruh&rdquo; vurgusu ile bir ortayol buluyorlar. Halbuki, taraftarlık, fanatikliğin &ouml;tesinde bilin&ccedil;li bir h&acirc;l aldığında, insanın ismini alması gibi belirli bir zorunluluktan değil, farkındalıkla bağlantılı bir se&ccedil;im sonucunda olduğunda i&ccedil;i daha da doluyor.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&ldquo;Zar atmaktan korkan asla altı atamaz&rdquo;</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Ken Loach</span></b><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">&rsquo;un futbolun bir erkek oyunu olduğu &uuml;zerine kurarak sunduğu anlatı, nihayetinde problemlerin erkeklerin dostluk ve dayanışması ile &ccedil;&ouml;z&uuml;mlenmesini getirmekte. Kadınlara bu oyunda verilen rol, dayanışma ağının i&ccedil;inde yer almak değil, bir kenara itilmek oluyor. Bu ma&ccedil;o havayı filmin iki kadın oyuncusu Lily ve Sam&rsquo;in g&uuml;&ccedil;l&uuml; karakterleri dağıtıyor: Lily&rsquo;nin Sam&rsquo;i, Sam&rsquo;in ise k&uuml;&ccedil;&uuml;k bebeği Daisy&rsquo;yi hayatlarında bir erkek olmadan tek başlarına b&uuml;y&uuml;tmeleri ancak farklı t&uuml;rden bir dayanışma ile m&uuml;mk&uuml;n olabiliyor.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; line-height: 19px; font-family: Verdana;">Son s&ouml;z&uuml;&nbsp;<b>Eric Cantona</b>&rsquo;nın oyunculuğuna verebiliriz.&nbsp;<b>Cantona</b>&rsquo;nın futbolculuktan sonra sinema oyunculuğunu da başarıyla kıvırması, zar atmaktan korkmadan farklılıklara a&ccedil;ık olmasının bir sonucu. Zira, sinemadaki başarısından sonra aynı işi tiyatroda da yapması, denemekten gocunmaması, bize futboldan sonra da bir hayatın var olabileceğini ve bu hayatın g&uuml;zel olabileceğini g&ouml;steriyor.</span></p>', 186, 63, 'Yazarlarımızdan', '/images/yazilar/looking_for_eric2.jpg', '2017-02-27');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (32, 'ay-j153', 'bir-i-htimalsizlik-cemberi', 'Bir İhtimalsizlik Çemberi', 'Ali Rıza DÜRÜ', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Bir İhtimalsizlik &Ccedil;emberi</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Ali Rıza D&Uuml;R&Uuml;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><a href="mailto:ali.riza@hotmail.com" style="color: #895f37;">ali.riza@hotmail.com</a></b></span></p>\r\n<hr style="font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p class="style1" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 11px; padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;"><strong>Uzak İhtimal&nbsp;</strong>modern zaman ilişkilerinin hızına, t&uuml;keten yapısına ve tutkunun cazibesine kapılarak &ccedil;ift ilişkisinde tekleşmeye, karşısındakini kendi b&uuml;nyesinde eritme &ccedil;abalarına d&ouml;nen aşklara antitez oluşturan ilişki bi&ccedil;imlerine bir &ouml;rnektir. G&uuml;n&uuml;m&uuml;z d&uuml;nyasında her şey gibi aşk da t&uuml;ketim end&uuml;strisinin pazarı halini almış, hızlı ve aşırı t&uuml;ketim bi&ccedil;imi, duygusal t&uuml;ketim, tek gecelik ilişkiler seremonisi ve kullan-at formatında portatif bir şekle girmiştir. Her şey birbiriyle yakın ihtimaller halindedir. Belki de bu tablonun i&ccedil;inde ihtimal verilmeyen şey insanın &ouml;z&uuml;, algısı, benlik b&uuml;t&uuml;nl&uuml;ğ&uuml;, duygusal ve fizyolojik algısının sınırlarındaki doyum noktasıdır. Modern yaşam bi&ccedil;imleri, modern ara&ccedil;-gere&ccedil;ler, modern insanlar, herkes ve her şey kendi uzaklığında ihtimaller serisi halinde doğanın d&ouml;ng&uuml;s&uuml;n&uuml; tuhaflaştırıp yeniden kurma &ccedil;abasına girişiyor. Kuşkusuz ki b&uuml;t&uuml;n yazarlar, senaristler kendi beklenti ya da g&ouml;zlemlerini sanatsallaştırıyor. Bize d&uuml;şen şey bu &uuml;retimleri yorumlamak.</span></p>\r\n<p class="style1" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/2.jpg" alt="2" width="319" height="480" /></p>\r\n<p class="style1" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;"><strong>Uzak İhtimal</strong>&rsquo;deki Musa kendine bir yol aramaktadır aslında. Kendisi gibi olmayana yani bir &ouml;tekiye y&ouml;nelmiştir ve karşılığında duygusal bir &ouml;d&uuml;l beklerken Clara&rsquo;ya ulaşamama ve onu sonsuza dek kaybetmekle cezalanmıştır. Clara&rsquo;yla olan mekansal yakınlıkları, ikisini sırlı bir perdenin arkasında gibi g&ouml;steren pencereler ve iki mutfak arasındaki apartman boşluğu onların ilişkisindeki uzaklığın diyalektik g&ouml;stergeleri olarak simgelenir. Pencerelerden birbirlerini g&ouml;rebilecek, duyabilecek bir yakınlıktayken, birbirlerine asla dokunamayacakları kadar da bir uzaklığa sahiptirler. Boşluğu hi&ccedil; dolduramayacaklar ve bu apartman boşluğunun varlığını hep hissedeceklerdir. Bu boşluk toplumsal bir uzaklığın, hoşg&ouml;r&uuml;s&uuml;zl&uuml;ğ&uuml;n, &ldquo;Kendin gibi olmayana y&ouml;nelme!&rdquo; arketipinin tipik bir g&ouml;stergesidir. Bu u&ccedil;urumu, uzaklığı, Musa&rsquo;nın cami hocasının evinde g&ouml;nl&uuml;ndeki kadını Hristiyan olduğu i&ccedil;in hocasına bir t&uuml;rl&uuml; s&ouml;yleyememesinde, Ayhan&rsquo;dan sır gibi saklamasında g&ouml;rmek m&uuml;mk&uuml;n.</span></p>\r\n<p class="style1" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt; font-family: Verdana;"><img src="/images/yazilar/5.jpg" alt="5" width="512" height="341" style="display: block; margin-right: auto; margin-left: auto;" /></span></p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana; text-align: justify;">Filmin bir diğer uzak ihtimali ise Ayhan&rsquo;ın Musa&rsquo;ya, Clara&rsquo;yı alıp M&uuml;sl&uuml;manlaştırırsa sevap işleyeceğini s&ouml;ylemesidir. Ayhan&rsquo;ın bu bilincine g&ouml;re Musa ve Clara kendi inan&ccedil;larını muhafaza ettik&ccedil;e bir araya gelmeleri i&ccedil;in gereken toplumsal izin hi&ccedil;bir zaman &ccedil;ıkmayacaktır. Bir araya gelmek i&ccedil;in birinden birinin inan&ccedil; bi&ccedil;iminden vazge&ccedil;mesi bir koşuldur. Bu g&ouml;rev ise toplumsal normlara g&ouml;re erkeğin kadını kendi b&uuml;nyesinde eritmesini &ouml;ng&ouml;r&uuml;yor. Bu nokta da yine erk zihniyetin toplumsal bilin&ccedil; hiyerarşisi i&ccedil;indeki baskın rol&uuml;n&uuml;n &ouml;nemli bir g&ouml;stergedir. Musa&rsquo;nın bir m&uuml;ezzin, Clara&rsquo;nın ise bir rahibe adayı olması onları toplum i&ccedil;inde daha uzak ve u&ccedil; ihtimallere s&uuml;r&uuml;kleyen bir unsurdur. Bu durum onların bir araya gelemezliğini bir par&ccedil;a daha keskinleştiriyor. Bu noktada bir başka fakt&ouml;r de gelip bu tablonun i&ccedil;inde yerini alıyor: aile kurumu. Musa ve Clara iki komşu olarak yaşayabilmekte, aynı bakkaldan ekmek, yağ, tuz alabilmekte, aynı asans&ouml;rle inip-&ccedil;ıkabilmekte fakat aile kuramamaktadırlar. Onlar toplumsal d&uuml;zlemde birbirleri i&ccedil;in birer uzak ihtimal giyinirken, seyirciye de aynı g&ouml;r&uuml;ş&uuml;n, d&uuml;ş&uuml;n&uuml;ş&uuml;n ve sorgulayışın ceketini giyerek onlarla aralarında yakın ihtimaller hayal etme işi kalıyor.</p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana;"><img src="/images/yazilar/3.jpg" alt="3" width="512" height="288" style="display: block; margin-right: auto; margin-left: auto;" /></p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana; text-align: justify;">B&ouml;yle bir pencereden bakınca kim kime uzak, kimler daha yakın olabilir diye bir profil &ccedil;izmek de kolaylaşıyor: herkes kendine benzeyenle yakın ihtimaller yaşayabilir.Musa&rsquo;nın camide ezan okurken elinde tuttuğu Clara&rsquo;ya ait ha&ccedil;lı kolye, gen&ccedil; kadının ne denli i&ccedil;ine işlediğinin ve derinlere uzandığının a&ccedil;ık bir g&ouml;stergesidir. M&uuml;ezzin olan Musa elinde bir ha&ccedil;la ezan okumaktadır. Hocasının uyarısıyla ha&ccedil;ı cebine koyar. Hocanın, onların ilişkisini kabul edemeyeceği ve bu y&uuml;zden hocanın evindeyken t&uuml;m ısrarlarına rağmen hocasına Clara&rsquo;dan bahsedemeyişi de anlam kazanır.</p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana;"><img src="/images/yazilar/1.jpg" alt="1" width="510" height="287" style="display: block; margin-right: auto; margin-left: auto;" /></p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana; text-align: justify;">Musa i&ccedil;inde bulunduğu toplumun yaşam şeklini kırmaya &ccedil;alışan bir karakterdir. Kendisi gibi olmayanla duygusal ve d&uuml;ş&uuml;nsel bir yakınlık kurmuştur. Clara&rsquo;yı İtalya&rsquo;ya gitmek &uuml;zere tren istasyonuna kadar g&ouml;t&uuml;r&uuml;nce artık onlar toplumsal uzaklığın yanında mek&acirc;nsal ve coğrafi olarak da birbirileri i&ccedil;in birer uzak ihtimal, hatta ihtimalsizlik halini alırlar. Bu uzaklık aynı apartmanda yaşarken de onların ilişkisini g&ouml;lgeler. Asans&ouml;rde, aynı evde, Şile&rsquo;de tatilde hep bir uzaklık i&ccedil;indedirler. Birbirleri i&ccedil;in &ccedil;izdikleri &ccedil;emberin yarı&ccedil;apı gibi sabitlenmiş bir uzaklık onların t&uuml;m davranışlarının altını doldurur. En yakın olacakları beklenen zaman bir fotoğraf karesi oluşturmak i&ccedil;in fotoğraf&ccedil;ının onları yakınlaştırma &ccedil;abalarına rağmen onlar b&uuml;t&uuml;n uzaklıklarıyla, ihtimalsizlikleriyle o fotoğrafta &ouml;l&uuml;ms&uuml;zleşirler. Fotoğrafla donuklaşan o bir anlık hayat karesi onların yakınlıklarının azami sınırını simgeler. Clara&rsquo;nın İtalya&rsquo;ya gitmeden &ouml;nce başka bir şey değil de o uzak duruşlu fotoğrafı Musa&rsquo;ya vermesi bu noktadan bakılınca anlamlı hale gelir. Clara gitmeden &ouml;nce onların birbirileri i&ccedil;in ne kadar uzak olduklarını Musa&rsquo;ya g&ouml;stermek istemiştir. Bir b&uuml;t&uuml;n olarak onların sevgisi mayasını uzaklığından alır. Onlar yakınlaşmak isteyen birer uzak ihtimaldirler. Elleri hi&ccedil; birleşmemiş, tenleri kendi sınırlarını korumuş, s&ouml;zc&uuml;kleri birbirilerinin kulağına &ccedil;arparken saygısını ve mesafesini hi&ccedil; yitirmemiş, pop&uuml;ler ilişki bi&ccedil;imlerinin &ccedil;ok uzağında bir ilişki ve iletişim &ouml;r&uuml;nt&uuml;s&uuml;d&uuml;r.</p>\r\n<p style="color: #000000; padding: 5px 10px; margin-bottom: 0px; font-size: 10pt; font-family: Verdana; text-align: justify;"><br /><strong>Uzak İhtimal</strong>, duygu d&uuml;nyasını her şeye rağmen bir şeylerin değişebileceğine dair beslediği umutla &ouml;renlerin filmidir.</p>', 187, 63, 'Yazarlarımızdan', '/images/yazilar/2.jpg', '2017-03-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (33, 'ay-j154', 'yilmaz-guney-filmlerinde-bati-sinemasinin-etkileri', 'Yılmaz Güney Filmlerinde Batı Sinemasının Etkileri', 'İlker Mutlu', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="color: #c43300; font-size: small;">İkisi de Cesurdu ve The Gunfighter Karşılaştırmalı &Ouml;rneğinde</span></h2>\r\n<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 15pt; color: #c43300;">Yılmaz G&uuml;ney Filmlerinde Batı Sinemasının Etkileri</span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>İlker Mutlu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b>&nbsp;<img src="/images/yazilar/yg.JPG" alt="" width="317" height="216" border="0" /></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">1</span></b><span style="font-size: 10pt;">960 ve 1970&rsquo;lerde yapım sayısında yapay bir artış g&ouml;steren T&uuml;rk Sinemasının &ouml;zelliklerinden biri, bol sayıda kullandığı yabancı kaynaklar ve bunun etkileri olur. Yabancı kaynak, etki ve t&uuml;rler &ccedil;ok&ccedil;a kullanılıp ticari sinemada bir tercih konumuna gelmiştir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinema, gerek bir sanat, gerekse bir end&uuml;stri olarak, &ouml;zellikle &ccedil;ok sayıda film &ccedil;evrilen &uuml;lkelerde yeni kaynaklar bulma zorluğuyla karşılaşır. Bu y&uuml;zden her &uuml;lke sineması, belli d&ouml;nemlerde, bir konu sıkıntısı sorunuyla karşı karşıya geldiğinde bir ge&ccedil;erlilik ya da bir rantabilite umut ettiği s&uuml;rece her t&uuml;rl&uuml; kaynağı &ccedil;ıkış noktası olarak b&uuml;y&uuml;k bir rahatlıkla kullanmıştır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Başka &uuml;lkelerin ticari sineması gibi, T&uuml;rk sineması da ulusal ve yabancı &ccedil;eşitli kaynaklardan yararlanmış ve bu kaynakların se&ccedil;imi, kullanılması ve yorumlanması T&uuml;rk sinemasının belli d&ouml;nemlerdeki ger&ccedil;ek ticari &ccedil;izgisini oluşturmuştur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Az zamanda &ccedil;ok işin yapıldığı bir ticari d&uuml;zende &ouml;zg&uuml;n &ouml;yk&uuml; ve senaryo, yorum ve zaman sorununu da beraberinde getirir. Yerli roman, &ouml;yk&uuml;, sahne oyunu başta bir araştırma, sonradan bir uygulama s&uuml;recini ve maliyet a&ccedil;ısından &ouml;nemli olabilecek bir telif hakkını gerektirir. Durum b&ouml;yleyken yabancı bir filmi, en azından &ccedil;ıkış noktası olarak kullanmak bir kolaylık, bir rahatlık getirmelidir diye d&uuml;ş&uuml;n&uuml;lebilir. Ancak, toplumlar arasında duygu, g&ouml;r&uuml;ş ve anlayış farklılıkları vardır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Senaryo yazarı ve y&ouml;netmen İlhan Engin: &ldquo;T&uuml;rk sinemasında bug&uuml;ne kadar prod&uuml;kt&ouml;r evvela işletmecinin etkisinde kalarak, artisti angaje eder. J&ouml;n&uuml;n karşısında oynayacak olan j&ouml;ndamı se&ccedil;er, sonra birka&ccedil; karakter oyuncusu ile de anlaşmasını yaptıktan sonra, filmin &ccedil;ekimine &ccedil;ok kısa bir zaman kala konu aramaya başlar. &ldquo;Sende Ayhanlık, G&ouml;ksel&rsquo;lik bir konu var mı?&rdquo; gibi s&ouml;zlere alışmış olan sekiz on senaryocu, dağarcıklarında bulunan &uuml;&ccedil; beş hikaye ve tretmanla artan konu ihtiyacını karşılayamadıkları i&ccedil;in denenmiş ve T&uuml;rkiye&rsquo;de iş yapmış ecnebi filmlerin konuları halla&ccedil; pamuğu gibi atılmaya başlanmıştır. Hatta bu işte o derece ileri gidilmiştir ki, birbirlerinden haberleri olmadığı i&ccedil;in, bir ecnebi filmin yerli birka&ccedil; kopyası birden oynamaya başlamıştır. Bu hal bug&uuml;n de devam etmektedir.&rdquo; (1965).</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>D&ouml;nemin bu &ouml;zelliğini vurgulaması a&ccedil;ısından şu veri dikkat &ccedil;ekici: 1967&rsquo;de &ccedil;ekilen 109 filmin senaryosu, yalnızca 11 senaryocunun elinden &ccedil;ıkmıştır ve bunlar arasında bir yılda tek başına 23 senaryo, 18 senaryo, 11 senaryo verenler vardır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yabancı film uyarlaması hi&ccedil;bir zaman sanıldığı kadar kolay olmamıştır. Yabancı kaynaktan alınan &ouml;yk&uuml; ne denli sağlam g&ouml;r&uuml;n&uuml;rse g&ouml;r&uuml;ns&uuml;n, daima bir p&uuml;f noktası &ccedil;ıkar. Ya &ccedil;evre uymaz, T&uuml;rkiye&rsquo;de karşılığını bulmaz, ya da kahraman bir &ccedil;eşit anti-kahraman, olumsuz kahraman olur ya da kişiler arası ilişkiler, davranışlar T&uuml;rk toplumuna ters d&uuml;şer. Hazır kurulmuş, t&uuml;m ayrıntıları yerli yerine konulmuş, işlenmiş bir &ouml;yk&uuml;n&uuml;n yapısından bir &ouml;ğeyi &ccedil;ıkartmaya kalkışınca t&uuml;m bina &ccedil;&ouml;k&uuml;p sarsılabilir ve &ccedil;ıkartmak zorunda kaldığınız bu &ouml;ğenin yerine bazen benzer, bazen de değişik, ancak seyirciye otantik g&ouml;r&uuml;nebilmesi i&ccedil;in gerekli, başka bir şeyler eklemek zorunda kalırsınız. Ve değiştire değiştire, bakarsınız, ortaya bambaşka bir &ouml;yk&uuml;, senaryo, film &ccedil;ıkıvermiş.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yılmaz G&uuml;ney&rsquo;in de, hele ki senede on-on iki film kotardığı &lsquo;60&rsquo;lardaki &Ccedil;irkin Kral d&ouml;neminde, benzer bir etki i&ccedil;inde olmaması d&uuml;ş&uuml;n&uuml;lemezdi. Ama bunda onu sinemaya &ccedil;eken unsurların da b&uuml;y&uuml;k &ouml;nemi vardı ve onu G&uuml;ney yapacak konular da bu kaynaklardan şekillenecekti. G&uuml;ney&rsquo;i anlatan biyografiler, onun sinemacı olmaya y&ouml;nlendiren yolun Adana&rsquo;daki gen&ccedil;lik yıllarında film şirketlerinde bobin taşıyıcısı olarak &ccedil;alışırken a&ccedil;ıldığını anlatırlar. Bu d&ouml;neminde sık sık film izleme imk&acirc;nı bulan ve seyrettiği bu filmlerin halk &uuml;zerindeki etkisini &ccedil;ok iyi g&ouml;zlemleyen G&uuml;ney, edindiği deneyimleri ileride filmlerinde kullanacaktı elbette. İzleme fırsatını bulabildiğimiz filmlerini incelediğimizde, Yılmaz G&uuml;ney&rsquo;in sadece bahse konu d&ouml;nemde değil, t&uuml;m hayatı boyunca da iyi bir sinema seyircisi olduğu anlaşılmaktadır.&nbsp; İzlediği filmlerden esinlenmelerini kendi yapıtlarına halkımızın da &ccedil;abucak benimseyeceği bir tarzda yerleştirdi; bir kopyalama değil, bir t&uuml;r yeniden yaratma ger&ccedil;ekleştirdi.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>İkisi de Cesurdu</span>&nbsp;</b><span>&nbsp;(1963)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y</span><span>&ouml;netmen</span></span><span>:&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">Ferit Ceylan</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>O</span><span>yuncular:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Samim Meri&ccedil; - Yılmaz G&uuml;ney - Semra Sar - Hilal Esen</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>S</span><span>enaryo:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Yılmaz G&uuml;ney</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y</span><span>apımcı:</span></span><span>&nbsp;M<span class="fs12ff2taltc00bgi21pl13pt07wp100">eri&ccedil; Film (Samim Meri&ccedil;)</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/ikisi%20de%20cesurdu.jpg" alt="" width="395" height="390" border="0" /></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>&nbsp;</span></i></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>İkisi de Cesurdu</span></i></b><span>, s&uuml;rg&uuml;ne g&ouml;nderilen ve geldiği kentte yerli kabadayılarca gelişi hoş karşılanmayan ve nam kazanmak isteyenlerin hedefi haline gelen Ali Duran&rsquo;ın hikayesini anlatır. Film, tipik bir Amerikan westerninin t&uuml;m &ouml;ğelerini barındırmaktadır ve aslen hikayesi de, artık bir western klasiği olan&nbsp;<b><i>The Gunfighter</i></b>&rsquo;dan gelir. Salonların yerini kahvehaneler almıştır. Yalnız kovboyun kaldığı salaş otel ve ona ilgi duyan k&uuml;&ccedil;&uuml;k kız &ccedil;ocuğu unsurları da bize uygun bir hikaye b&uuml;nyesine ustaca yedirilmiştir. Ve tabii ki kentin bir tren istasyonu vardır ve kahramanımız bir &ccedil;atışma sonrası, son nefesini burada verecektir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>The Gunfighter (Silahş&ouml;r)&nbsp;</span></b><span>(1950)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y</span><span>&ouml;netmen</span></span><span>:&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">Henry King</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>O</span><span>yuncular:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Gregory Peck, Helen Westcott, Millard Mitchell, Karl Madlen, Skip Homeier</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>S</span><span>enaryo:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>William Bowers, Andre de Toth (William Bowers&rsquo;ın &ouml;yk&uuml;s&uuml;nden)</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y</span><span>apımcı:</span></span><span>&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">Nunnally Johnson (Twentieth Century-Fox)</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/The_Gunfighter.jpg" alt="" width="307" height="435" border="0" /></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>The Gunfighter</span></i></b><span>, klasik kara film etkileri de taşıyan, farklı bir westerndir. Yaşlanmakta olan bir silahş&ouml;r, Jimmy Ringo, &ouml;ld&uuml;rmekten bıkmıştır, ama kendisini vurup nam yapmak isteyen serseriler s&uuml;rekli peşindedir. Bırakıp gitmek durumunda kaldığı karısını ve oğlunu g&ouml;rmek i&ccedil;in geldiği kasabada, artık şerif olan eski arkadaşı ile karşılaşır. Şerif bela yaratmaması i&ccedil;in onu uyarır. Daha &ouml;nce vurduğu başka bir serserinin kardeşleri de peşindedir, ama filmin sonunda, tam kasabadan ayrılırken, olduk&ccedil;a gen&ccedil; bir delikanlı olan ve film boyunca şişirilen Hunt, onu sırtından vurur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>The Gunfighter</span>&nbsp;</i></b><span>&nbsp;doğrudan Jimmy Ringo&rsquo;nun (Peck) &ccedil;&ouml;lde atla ilerleyişiyle a&ccedil;ılmaktayken,&nbsp;<b><i>İkisi de Cesurdu</i></b>&rsquo;da Ali Duran&rsquo;ı (G&uuml;ney) g&ouml;rmek i&ccedil;in on d&ouml;rd&uuml;nc&uuml; dakikayı beklememiz gerekir. Aslında,&nbsp;<b><i>İkisi de Cesurdu</i></b>, biraz da filmin yapımcısı olmasının hatırına, sahne &ccedil;okluğu bakımından Samim Meri&ccedil;&rsquo;e ağırlık vermektedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 486px; height: 296px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; width: 354px;" valign="middle"><img src="/images/yazilar/ikisidecesurdu1.jpg" alt="" width="352" height="288" style="display: block; margin-left: auto; margin-right: auto;" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" valign="middle">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Ali Duran, kendisini s&uuml;rg&uuml;ne getiren trenin penceresinde, arkasında iki jandarma, elleri kelep&ccedil;eli. Filmin yaklaşık olarak 14. dakikası.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Hikaye ger&ccedil;ekten de Ali Duran şehre gelinceye kadar Yal&ccedil;ın (Meri&ccedil;) &uuml;zerinden ilerler. Yal&ccedil;ın, şehrin en namlı kabadayısıdır. Kimse karşısında durmaya cesaret edememektedir. Ama o da bu durumdan hoşnutsuzdur. Sevgilisiyle (Sar) başka bir şehre gidip evlenmeye kararlıdırlar. Bunun i&ccedil;in Yal&ccedil;ın&rsquo;ın kardeşinin d&ouml;n&uuml;ş&uuml;n&uuml; beklerler. Yal&ccedil;ın, işletmekte olduğu kahvehaneyi kardeşine bırakıp &ouml;yle gidecektir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu sırada Ali Duran&rsquo;ın hapisten &ccedil;ıktığı ve s&uuml;rg&uuml;n i&ccedil;in altı aylığına şehre g&ouml;nderildiği haberi gelir. Bu durum t&uuml;m planları alt &uuml;st etmiştir. Yal&ccedil;ın&rsquo;ın kardeşi ağabeyini uyarmak ve Ali Duran gelmeden şehirden ayrılmasını sağlamak &uuml;zere erkenden gelir. İkisi de Ali Duran gelince Yal&ccedil;ın&rsquo;ın namına g&ouml;lge d&uuml;şeceğini ve olayların onu Ali Duran&rsquo;la kapışmaya zorlayacağını bilirler. Ka&ccedil;ınılmaz g&uuml;n gelir ve tren Ali Duran&rsquo;ı s&uuml;rg&uuml;n&uuml;n&uuml; ge&ccedil;ireceği şehre getirir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 488px; height: 296px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="357"><img src="/images/yazilar/ikisidecesurdu2.jpg" alt="" width="352" height="288" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Samim Meri&ccedil; ve Semra Sar.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Jimmy Ringo da Ali Duran gibi bir kabadayıdır, ancak onun gibi s&uuml;rg&uuml;ne gitmemektedir. Kasabaya kendi isteğiyle gitmektedir ve amacı yıllar &ouml;nce terk ettiği karısını ve hi&ccedil; g&ouml;rmediği oğlunu g&ouml;rmek, yaşamakta olduğu tehlikeli hayatı bırakmaktır.Yolu &uuml;st&uuml;nde uğradığı bir kasabada soluklanmak i&ccedil;in bir bara girdiğinde, ş&ouml;hreti orada da yakasını bırakmaz ve nam kazanmak isteyen gen&ccedil; bir serseri onu kapışmaya zorlar. Ringo uzak durur, ama gen&ccedil; ilah &ccedil;ekince onu vurmak durumunda kalır. Pişman olmuştur ama kasabadan hemen ayrılır. &Ccedil;ocuğun &uuml;&ccedil; erkek kardeşi peşine d&uuml;şer.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 485px; height: 430px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="326"><img src="/images/yazilar/ikisidecesurdu3.jpg" alt="" width="352" height="422" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Ringo, kendisine silah &ccedil;eken genci vurur.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo kasabaya ulaştığında, adamlarla arasında birka&ccedil; saat vardır ve film bu s&uuml;renin gerilimi &uuml;zerine kurulur. Bu a&ccedil;ıdan&nbsp;<b><i>High Noon</i></b>&nbsp;(Kahraman Şerif, 1952, Fred Zinnemann) ile de akrabalığı vardır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yal&ccedil;ın&rsquo;ın kardeşi Hamaloğlu adındaki bir kabadayının selamını getirmiştir. Hamaloğlu &ouml;ld&uuml;r&uuml;lm&uuml;şt&uuml;r. &Ouml;lmeden &ouml;nce Yal&ccedil;ın&rsquo;ın kardeşine Yal&ccedil;ın&rsquo;ın Ali Duran&rsquo;la kapışmamasını s&ouml;ylemiştir. O esnada kahvehanede bulunan bir serseri atıp tutmaktadır. &ldquo;Gelsin de bizim Yal&ccedil;ın kabadayılığın ne olduğunu &ouml;ğrensin ondan.&rdquo; der bir yerde. Yal&ccedil;ın bunu duyar ve adamı d&ouml;ver. Benzer konuşmalar başka yerlerde de olur ve Yal&ccedil;ın bunları işitir!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 491px; height: 296px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="326"><img src="/images/yazilar/ikisidecesurdu4.jpg" alt="" width="352" height="288" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Polis arkadaşı, Ali Duran&rsquo;ı uyarıyor.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo&rsquo;nun da Ali Duran&rsquo;ın da geldiği yerdeki polis g&uuml;c&uuml;n&uuml;n başı, ikisinin de eski arkadaşlarıdır. Ali Duran&rsquo;ın arkadaşı (Somer), onun &ccedil;ocukluk arkadaşıdır, fakat onun gittiği yolun aksine, kanunu se&ccedil;miştir. Ringo&rsquo;nun arkadaşı şerif ise Ringo gibi eski bir hayduttur, fakat uslanmıştır. İkisi de geldiklerinde bu arkadaşları tarafından uslu durmaları i&ccedil;in uyarılırlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>The Gunfighter</span></i></b><span>&rsquo;da da benzeri dedikodu sahneleri vardır ve Ringo&rsquo;nun geldiği kasabada kendini ispatlamaya &ccedil;alışan gen&ccedil; bir serseri olan Hunt (<span class="fs12ff2taltc00bgi21pl13pt07wp100">Homeier)</span>, bu konuşmalara sık sık şahit olur. Bir berber salonunda yine bu t&uuml;r bir konuşma ge&ccedil;ince, başta vurulan &ccedil;ocuk gibi o da &ldquo;Onun da iki eli yok mu?&rdquo; diye dalgasını ge&ccedil;er.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ali Duran&rsquo;ın da, Ringo&rsquo;nun da gelişleri b&uuml;y&uuml;k merak konusu olur. Halk peşlerine takılır, t&uuml;m hareketlerini izler. Halkın bu merakı ve aralarında konuşmaları, ana kahraman ile nam yapmak isteyen kabadayı arasında bir akıntı gibi gidip gelir iki filmde de.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ali Duran&rsquo;ın şehirdeki hik&acirc;yesi altı ay s&uuml;recektir. Bu nedenle bir otele yerleşir. Ringo&rsquo;nun ise kasabadan ayrılmak i&ccedil;in sadece birka&ccedil; saati vardır. O y&uuml;zden s&uuml;rekli olarak, Karl Malden&rsquo;in karakterinin işlettiği barda kalır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ali Duran&rsquo;ın amacı s&uuml;rg&uuml;n s&uuml;resini doldurup, bir an &ouml;nce memleketine d&ouml;nmek ve anasına kavuşmaktır. Odasına yerleşir yerleşmez ilk işi anasının resmini duvara asmak olur. Film boyunca sık sık anasına mektup yazar, ondan mektup alır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ccedil;ocuk unsuru iki filmde de &ouml;n plandadır. Merak &ccedil;ocukları bu haydutlara yakınlaştırır. Ali Duran, geldiği şehirde dostluğu, kaldığı odanın penceresinden odası g&ouml;r&uuml;nen k&uuml;&ccedil;&uuml;k bir kız &ccedil;ocuğunda bulur (Esen). Ringo ise, zaten oğlunu g&ouml;rmeye gelmiştir. Ama onun babası olduğunu bilmeyen &ccedil;ocukla arasında, Ali Duran ile kız arasındakine benzer bir ilişki gelişir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 493px; height: 296px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="355"><img src="/images/yazilar/ikisidecesurdu5.jpg" alt="" width="352" height="288" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Ali Duran ve k&uuml;&ccedil;&uuml;k kız (Hilal Esen).</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<table border="0" style="width: 493px; height: 271px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="355"><img src="/images/yazilar/ikisidecesurdu6.jpg" alt="" width="355" height="263" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Jimmy Ringo ve oğlu.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo, sevgilisine g&ouml;r&uuml;şmek i&ccedil;in haber salar ve şeriften de bu konuda yardımcı olmasını ister. Peşindeki adamlar gelmeden onları g&ouml;r&uuml;p, ayrılmak istemektedir. Ama kadın uzun s&uuml;re g&ouml;r&uuml;şmek istemez. G&ouml;r&uuml;şmeye karar verdiğindeyse s&uuml;re bayağı daralmıştır. Hunt bara gelir ve Ringo&rsquo;yu taciz eder. (&ldquo;Burada viskiye su katılıyormuş. Senin fikrin nedir?) Ama Ringo masanın altında tabancası olduğunu s&ouml;yleyerek Hunt&rsquo;ı alt eder. Hunt daha da hın&ccedil;lanmıştır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 494px; height: 277px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="367"><img src="/images/yazilar/ikisidecesurdu7.jpg" alt="" width="365" height="269" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Ringo, Hunt&rsquo;ı oyuna getiriyor..</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yal&ccedil;ın da bir barda Ali Duran&rsquo;ı taciz eder. (&ldquo;Bizim buralarda i&ccedil;kiler fazla sert. Bak bakalım, doğru mu?&rdquo;) Ama Ali Duran oyuna gelmez ve alttan alıp bardan ayrılır. Yal&ccedil;ın bunu korkma olarak algılar ve &ccedil;evresine havasını atar. Nam almak isteyen bir serseri, ki filmin başlarında yal&ccedil;ın&rsquo;ı gaza getirmeye &ccedil;alışanların başındadır, silahını alıp, Ali Duran&rsquo;ı takip eder. Ama Ali Duran onu yakalayıp bir g&uuml;zel benzetir. Otele geldiğinde, anasının resmine dert yanar: &ldquo;Oğlunu rahat bırakmıyorlar ana.&rdquo; Ali Duran bir barda bir zavallıyı hırpalayan adamları d&ouml;ver. Yal&ccedil;ın bunu kendisine verilen bir g&ouml;zdağı olarak algılar. Sevgilisiyle k&uuml;st&uuml;r ve olay &ccedil;ıkarmak i&ccedil;in bahane aramaktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo, sevgilisinin ikna edilip gelmesini beklerken vurulma tehlikesi atlatır. Barın karşısında oturan yalı bir adam, oğlunu &ouml;ld&uuml;rd&uuml;ğ&uuml; gerek&ccedil;esiyle Ringo&rsquo;yu vurmaya kalkar, ama adamın karısı duruma engel olur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yal&ccedil;ın&rsquo;ın sevgilisi Ali Duran&rsquo;a gelerek onun y&uuml;z&uuml;nden ayrıldıklarını, şehre geldiği i&ccedil;in kendisine lanete ettiğini s&ouml;yler. Ali Duran kızmıştır. Kendisini savunur. Benzer şekilde kasabanın kadınları da şerifin b&uuml;rosunda yalnız buldukları Ringo&rsquo;ya, onu tanımadan, kendisini şikaet ederler ve kasabaya huzursuzluk getirdiğini s&ouml;ylerler. Ringo kendisini savunurken şerif gelir ve kadınlara onun kimliğini a&ccedil;ıklar!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo&rsquo;nun karısı nihayet ikna olmuştur. Ringo, barın &uuml;st&uuml;ndeki odada &ouml;nce karısı, sonra da oğluyla konuşur ve işlerini d&uuml;zene koyup onları alacağını s&ouml;yler. Ama peşindeki adamlar gelmiş ve karşıya pusu kurmuşlardır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 465px; height: 282px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="375"><img src="/images/yazilar/ikisidecesurdu8.jpg" alt="" width="372" height="274" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Başımıza ne gelirse, kadınlardan gelir.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Nam peşindeki serseri, otelde Yal&ccedil;ın&rsquo;ın sevgilisinin Ali Duran&rsquo;ın odasından &ccedil;ıktığını g&ouml;rm&uuml;şt&uuml;r. Yal&ccedil;ın&rsquo;a durumu yetiştirir. &Ccedil;ok kızan Yal&ccedil;ın, Ali Duran&rsquo;ın peşine d&uuml;şer. Ali Duran ise, trenini beklerken soluklanmak i&ccedil;in bir bara gider. Yal&ccedil;ın onu burada bulur. Ali Duran&rsquo;a saldırır ama o karşılık vermez. O sırada bara gelen nam peşindeki serseri, &ouml;nce Ali Duran&rsquo;ı arkadan vurur, ardından da &uuml;zerine y&uuml;r&uuml;yen Yal&ccedil;ın&rsquo;a ateş eder ve gelen polislere gururla her şeyi itiraf eder. (&ldquo;Ali Duran&rsquo;ı vurdum! Yal&ccedil;ın&rsquo;ı da vurdum!&rdquo;) Ali Duran&rsquo;ın yetişmesi gereken bir tren vardır ve yaralı halde bardan &ccedil;ıkmıştır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ringo&rsquo;nun peşindekiler, şerifin yardımcısı tarafından yakalanırlar. Artık hi&ccedil;bir tehlikenin kalmadığını d&uuml;ş&uuml;nen şerif, Ringo&rsquo;yu dışarıya &ccedil;ıkartır ve atına bindirir. Vedalaşırlar. Ama hesaba katmadıkları biri vardır: serseri Hunt! Hunt, pusu kurduğu k&ouml;şeden &ccedil;ıkar ve Ringo&rsquo;yu arkadan vurur ve zafer nidalarıyla ortaya d&uuml;şer. Şerif onu bir yumrukta yere serer.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 480px; height: 284px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="370"><img src="/images/yazilar/ikisidecesurdu9.jpg" alt="" width="370" height="276" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Korkak Hunt, Ringo&rsquo;yu arkadan vurur...</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Serseri Ringo&rsquo;yu arkadan vurmuştur ve i&ccedil;eri atılacaktır, ama Ringo son nefesini vermeden &ouml;nce itiraz eder, &ldquo;&Ouml;nce ben silahımı &ccedil;ektim.&rdquo; der. Hunt&rsquo;a &ldquo;Bana teşekk&uuml;r etme&rdquo; der, &ldquo;Benim yaşadıklarımı sen de yaşayacaksın.&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ali Duran yaralı halde zorlukla tren istasyonuna gelir. Fakat trene yetişemez. K&uuml;&ccedil;&uuml;k kız ona sarılır ve ağlar. Polis arkadaşı da yanındadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<table border="0" style="width: 477px; height: 307px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" width="360"><img src="/images/yazilar/ikisidecesurdu10.jpg" alt="" width="359" height="299" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;">*Ali Duran&rsquo;ın sondaki yaralı y&uuml;r&uuml;y&uuml;ş&uuml;. Sinemamızın simge sahnelerinden biri olacak ve pek &ccedil;ok filmde farklı akt&ouml;rlerce tekrar edilecektir.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yılmaz G&uuml;ney&rsquo;in sondaki y&uuml;r&uuml;y&uuml;ş&uuml; bir efsane gibi anlatılır. Yani daha &ccedil;ok zamanında filmi g&ouml;rm&uuml;ş olanlar tarafından. Etkileyici olduğunu kabul etmek gerek. Fakat &ccedil;ok tekrarlanmış olması sahnenin bizim kuşak &uuml;zerinde bırakacağı etkiyi azaltıyor ne yazık ki. Aynı y&uuml;r&uuml;y&uuml;ş, benzer bir &ccedil;ekimle Samim Meri&ccedil;&rsquo;e de yaptırılıyor filmde. Ancak Meri&ccedil; yaralı değildir. Daha doğrusu g&ouml;nl&uuml; yaralıdır ve sevgilisinin evinin altına kadar neredeyse Ali Duran&rsquo;ın ge&ccedil;tiği yerlerin aynısından ge&ccedil;erek gelir, yağmur altında.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>The Gunfighter</span></i></b><span>&rsquo;ın Amerika&rsquo;da fazla iş yapmadığı s&ouml;yleniyor ve bunun nedeninin Gregory Peck&rsquo;in filmlerdeki genel tiplemesinin dışına &ccedil;ıkılması olduğu d&uuml;ş&uuml;ncesi hakim. St&uuml;dyo Peck&rsquo;in otantik d&ouml;nem bıyığından nefret etmiş, ki Peck neredeyse filmlerinin tamamında bıyıksız oynamaktadır. Aslında, Fox&rsquo;ta prod&uuml;ksiyonun başı olan Spyros P. Skouras, prod&uuml;ksiyon başladığında şehir dışındaymış. D&ouml;nd&uuml;ğ&uuml;nde ise, filmin b&uuml;y&uuml;k kısmı tamamlanmış olduğundan, Peck&rsquo;e traş olması ve sahneleri yeniden oynamasını emretmek i&ccedil;in vakit &ccedil;ok ge&ccedil;miş. Film gişede yatınca, Skouras&rsquo;ın Peck&rsquo;in &uuml;zerine y&uuml;r&uuml;d&uuml;ğ&uuml; ve &ldquo;Bıyık bize milyonlara maloldu.&rdquo; dediği s&ouml;ylenir. Diğer yandan, filmin bizde yaptığı işin b&uuml;y&uuml;kl&uuml;ğ&uuml; hakkında bir bilgiye ulaşamadım, ancak i&ccedil;eriği a&ccedil;ısından (sadakat, dostluk, kahramanlık, kabadayılık) bize yakın duran yapısıyla tutulmuş olacağını d&uuml;ş&uuml;n&uuml;yorum. Ama, &ouml;yle ya da b&ouml;yle, film G&uuml;ney&rsquo;i etkilemiş olmalı ki, &Ccedil;irkin Kral filmlerinde kullandığı kabadayı mitosunun temellerini attığı filmde bu filmin &ouml;yk&uuml;s&uuml;nden yararlandı. Keza, aslında oyun tarzları hi&ccedil; benzeşmeyen Peck&rsquo;&icirc;n oynadığı Jimmy Ringo da G&uuml;ney&rsquo;in suskun kabadayı tiplemesinin &ouml;zelliklerine benzeyen yapıda bir karaktere sahiptir ve G&uuml;ney&rsquo;in oyununun izini s&uuml;rerken bize şaşırtıcı ipu&ccedil;ları vermektedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Gregory Peck,&nbsp;<b><i>B&uuml;lb&uuml;l&uuml; &Ouml;ld&uuml;rmek</i></b>&rsquo;teki (To Kill a Mockingbird, 1962, Robert Mulligan) avukat Atticus Finch ile birlikte akt&ouml;rl&uuml;k yaşamı boyunca sergilediği en iyi iki performanstan birini Ringo&rsquo;da sergilemektedir. Hem de geneldeki &ccedil;izgisinin dışına &ccedil;ıkma pahasına! Ger&ccedil;ekten de,</span><span class="rkr"><span>&nbsp;Peck&rsquo;i d&uuml;ş&uuml;nd&uuml;ğ&uuml;n&uuml;zde, kravatıyla d&uuml;zg&uuml;n giyinmiş halde bir avukat, kasabanın sofistike bir bireyi ya da bir işadamı g&ouml;z&uuml;n&uuml;z&uuml;n &ouml;n&uuml;ne gelir. Ama, işte botlarını ve mahmuzlarını giydiğinde de en b&uuml;y&uuml;k oyunlarından birini veriyor. Y&ouml;netmen&nbsp;<b>Henry King</b>&rsquo;in de hakkını yememek lazım.</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span class="rkr"><b><span>John Wayne</span></b><span>&rsquo;in Jimmy Ringo&rsquo;yu oynamayı &ccedil;ok istediği s&ouml;ylenir. Hikaye Columbia Pictures adına&nbsp;<b>Harry Cohn</b>&nbsp;tarafından Wayne i&ccedil;in satın alınmış. Ama Wayne, gen&ccedil;ken kendisini ref&uuml;ze eden Cohn i&ccedil;in &ccedil;alışmayı reddetmiş. Cohn da bunun &uuml;zerine projeyi Twentieth Century Fox&rsquo;a satmış.&nbsp;</span></span><span>Film Yazarlar Birliği tarafından En iyi Yazılmış Amerikan Westerni &ouml;d&uuml;l&uuml;ne aday g&ouml;sterilmiş. Diğer Amerikan westernlerinin aksine kahramanı olduk&ccedil;a edilgen durumlarda bırakarak da fark yaratan film, genel western tarzından farklı duran minimalist anlatımıyla da 1950&rsquo;lerde &uuml;retilen en iyi yapımlar arasına giriyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Henry King</span></b><span>&rsquo;in değeri bilinmemiş bu filmi -<b><i>Kahraman Şerif</i></b>&nbsp;ve&nbsp;<b><i>Kahramanın Sonu&nbsp;</i></b>(The Man Who Shot Liberty Valance, 1962, John Ford) gibi filmler silahş&ouml;r bir kahraman olmanın neye mal olduğunu g&ouml;sterirken- Wyatt Earp efsanesinin başka bir y&uuml;z&uuml;n&uuml; ortaya koymaktadır. Film aslında ger&ccedil;ek bir kişilik olan eski batı haydutu John Ringo&rsquo;yu temel almaktadır. Ger&ccedil;ek Ringo acımasız bir katildi ve Doc Holliday, Wyatt Earp ve Earp Biraderlerle olan OK Corrall &ccedil;atışmasından sağ &ccedil;ıkmıştı. Ayrıca, yine filmin anlattıklarının aksine, ger&ccedil;ek John Ringo &ndash;ki ger&ccedil;ek adı budur- 1882&rsquo;de California&rsquo;da ailesini ziyaret ettikten sonra melankolik bir alkolik haline gelmiş ve yalnız başına bir ağacın altına oturup, kendi silahıyla hayatına son vermiş.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>İkisi de Cesurdu</span>&nbsp;</i></b><span>&nbsp;ise, aslında diğer &Ccedil;irkin Kral filmlerinden en fazla bir adım &ouml;nde durmakta. Filmin &ouml;nemi, oyun ve anlatım tarzından, g&ouml;r&uuml;nt&uuml;lerinden &ccedil;ok, G&uuml;ney&rsquo;in sinema yoluna kazandırdığı keskin d&ouml;neme&ccedil;ten ileri geliyor. Ger&ccedil;ekten de, hapiste ge&ccedil;en birka&ccedil; yılın ardından (ki daha isim yapmadan girmiştir i&ccedil;eri), adını &ouml;ne &ccedil;ıkaran film bu olmuştur.<b>&nbsp;</b>Seyirci onu burada kabul eder ve G&uuml;ney giderek maj&ouml;r firmaların dikkatini &ccedil;eker, her zaman&nbsp;<em>ustam&nbsp;</em>diye s&ouml;z&uuml;n&uuml; ettiği ve &ouml;ncesinde de &ccedil;alıştığı&nbsp;<b>Atıf Yılmaz</b>&nbsp;ve&nbsp;<b>L&uuml;tfi Akad</b>&nbsp;gibi y&ouml;netmenlerle filmler &ccedil;ekmeye başlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu olduk&ccedil;a al&ccedil;akg&ouml;n&uuml;ll&uuml; k&uuml;&ccedil;&uuml;k yapım, hem bir mitosu başlatması a&ccedil;ısından hem de başka bazı &ouml;zellikleriyle, yine de izlenmeyi hak ediyor. Yılmaz G&uuml;ney&rsquo;in doğal oyunuyla zenginleştirdiği suskun, h&uuml;z&uuml;nl&uuml; kabadayı,&nbsp;<b>Ersun Kazan&ccedil;el</b>&nbsp;ve&nbsp;<b>Ali Şen</b>&rsquo;in filmi renklendiren neşeli tiplemeleri, k&ouml;t&uuml; oynayan ama gayretli diğer oyuncular, dikkatli izleyicilerin g&ouml;z&uuml;nden ka&ccedil;mayacak seyrek ama &ouml;zenli &ccedil;er&ccedil;evelemeler (&ouml;zellikle sona doğru, Ali Duran bavulunu toplarken karşı camda onun dikkatini &ccedil;ekmeye &ccedil;alışan k&uuml;&ccedil;&uuml;k kızı bir arada g&ouml;steren &ccedil;ekim ve beni olduk&ccedil;a şaşırtan, son sahnedeki, trenin altından Ali Duran&rsquo;ın &ouml;l&uuml;m&uuml;n&uuml;n verildiği &ccedil;ekim gibi), acemi ama rastlantısal g&uuml;zellikte m&uuml;zik kullanımı (G&uuml;ney&rsquo;in bazı sokak ve otel sahnelerinde&nbsp;<b><i>West Side Story</i></b>&rsquo;den b&ouml;l&uuml;mler var, kısacık), betona boğulmamış şehir manzarası, G&uuml;ney sevenlerin aşina olduğu silah romantizmi, hatta ger&ccedil;ekten yakışıklı bir oyuncu olan&nbsp;<b>&Ouml;nder Somer&nbsp;</b>ve &ccedil;irkin (denilen) Yılmaz G&uuml;ney&rsquo;i yan yana g&ouml;rmek i&ccedil;in dahi seyredilebilecek bir kayıp klasik&hellip;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-weight: bold;">Kaynaklar:</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Karag&ouml;zden Sinemaya (Nijat &Ouml;z&ouml;n)</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">T&uuml;rk Sinema Tarihi (Giovanni Scognamillo)</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Yılmaz G&uuml;ney Westerni (İlker Mutlu, Sinema, Aralık 2003)</span></p>', 20, 63, 'Yazarlarımızdan', '/images/yazilar/yg.JPG', '2017-03-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (34, 'ay-j155', 'turkiye-de-sinemanin-i-lkleri-nedense-hep-son-yillarda-oluyor', 'Türkiye’de Sinemanın İlkleri Nedense Hep Son Yıllarda Oluyor!', 'Savaş Arslan', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 14pt;">T</span><span style="font-size: 14pt;">&uuml;rkiye&rsquo;de Sinemanın İlkleri Nedense&nbsp;Hep Son Yıllarda Oluyor!</span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Savaş Arslan</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>"Son d&ouml;nemlerde sinema d&uuml;nyası canlandı, bir&ccedil;ok y&ouml;netmen ilk filmiyle bu d&uuml;nyaya adım atıyor ve bir&ccedil;ok yapımcı da bu projelere destek veriyor". Bu c&uuml;mle &ldquo;ama&rdquo; diye devam ederek&nbsp;<b><i>Artist</i></b>&nbsp;ya da&nbsp;<b><i>Yıldız</i></b>&nbsp;dergisinin 1960&rsquo;lar ya da 1970&rsquo;lerde basılmış bir n&uuml;shasındaki herhangi bir yazının başlangı&ccedil; c&uuml;mlesi olabilirdi. Bu meşhur &ldquo;ama&rdquo;nın ardındansa, &ldquo;Kalite yok, sanatsal nitelik yok, d&uuml;nya &ccedil;apında filmimiz yok.&rdquo; vesaire gibi bir&ccedil;ok olumsuzluk sıralanabilirdi. Bu semptomatik durum, aslında bug&uuml;n de kolaylıkla tekrar edilebilecek bir şey. &Ouml;zellikle tam da T&uuml;rkiye&rsquo;de sinemanın k&uuml;llerinden yeniden doğduğu, 1980&rsquo;lerin sonundan bu yana ilk kez yılda 70 filmlik bir tempoya ulaşılabildiği g&uuml;nlerde...&nbsp;<br /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/supurrr.jpg" alt="" width="227" height="327" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&ldquo;Ama&rdquo; burada derdimiz bu filmlerin nasıl olduğu, kaliteleri ya da kalitesizlikleri &uuml;zerine değil de, son yıllarda ortaya &ccedil;ıkan bir belleksizlik, bir nisyan haliyle alakalı olacak &ccedil;&uuml;nk&uuml; bu filmleri &ccedil;ekenler ya da bunları pazarlayanlar alabildiğine atıyorlar. S&ouml;zgelimi, bug&uuml;nlerde yazılar ya da televizyon haberlerine konu olan, olduk&ccedil;a da ilgin&ccedil; g&ouml;r&uuml;nen &ndash; &ccedil;&uuml;nk&uuml; &ldquo;<i>curling</i>&rdquo; namlı d&uuml;nyanın en sa&ccedil;ma sporu olarak kabul edilen spor t&uuml;r&uuml; etrafında d&ouml;nen bir hikayesi var &ndash;&nbsp;<b><i>S&uuml;p&uuml;rrr</i></b><i>&nbsp;</i>adlı filmin y&ouml;netmeni<b>Yeşim Sezgin</b>&nbsp;gibi. Yeşim Hanım bu film i&ccedil;in yola &ccedil;ıktıklarında filmin &ldquo;sportif komedi&rdquo; olduğunu d&uuml;ş&uuml;nd&uuml;klerini ve yanılıp yanılmadığından emin olmasa da, bunun T&uuml;rkiye&rsquo;de ilk kez yapıldığını s&ouml;yl&uuml;yor. Yeşim Hanımın yarattığı &ldquo;sportif komedi&rdquo; t&uuml;r&uuml; diye bir t&uuml;r varsa eğer, kendilerine hemen aklımıza gelen&nbsp;<b><i>Şenol Birol Gool</i></b>&nbsp;(<b>Nejat Saydam</b>, 1965),&nbsp;<b><i>Ta&ccedil;sız Kral</i></b><i>&nbsp;</i>(<b>Atıf Yılmaz</b>, 1965),&nbsp;<b><i>Pembe Panter</i></b><i></i>(<b>Hulki Saner</b>, 1975),&nbsp;<b><i>Gol Kralı</i></b><i>&nbsp;</i>(<b>Kartal Tibet</b>, 1980),&nbsp;<b><i>Pehlivan</i></b><i>&nbsp;</i>(<b>Zeki &Ouml;kten</b>, 1984) ya da&nbsp;<b><i>Benim Zaferim</i></b><i>&nbsp;</i>(<b>&Uuml;nal K&uuml;peli</b>, 1991) gibi filmleri hatırlatsak bile bu semptomatik durum, yani nisyan aromalı bir premat&uuml;re hali sembolik bir yokluğa işaret etmesiyle olduk&ccedil;a ilgin&ccedil; g&ouml;r&uuml;n&uuml;yor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 5px;"><span>&nbsp;</span></p>\r\n<table border="0" id="table4" style="width: 480px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; text-align: center;" valign="top" width="191"><img src="/images/yazilar/ts%20ve%20ilkler1_senol%20birol%20goool.jpg" alt="" width="183" height="229" border="0" /></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; text-align: center;" valign="top" width="184"><span style="font-size: 10pt;"><img src="/images/yazilar/ts%20ve%20ilkler2_tacsiz%20kral.jpg" alt="" width="162" height="229" border="0" /></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; text-align: center;" valign="top"><span style="font-size: 10pt;"><img src="/images/yazilar/ts%20ve%20ilkler4_pehlivan.jpg" alt="" width="169" height="231" border="0" /></span></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Anadolu Ajansı&rsquo;nın ge&ccedil;tiği bir habere g&ouml;reyse de, 2009-2010 sezonunda 70 kadar film g&ouml;sterime girecek diye bir yaygara kopuyor ki, sormayın. Bundan &ccedil;ok&ccedil;a heyecanlanan AA muhabiri Burcu Bilgin&rsquo;in &ldquo;T&uuml;rk Sineması Tarihi Rekora Koşuyor&rdquo; başlıklı haberine g&ouml;re &ldquo;T&uuml;rk sinema tarihinde ilk kez bu kadar fazla sayıda yapım vizyona girecek.&rdquo; Haydi diyelim ki bu imkansıza teğet ge&ccedil;en durum hasıl oldu ve bu filmlerin hepsi bir şekilde salon buldu. Ama haber burada da durmuyor ve K&uuml;lt&uuml;r Bakanlığı&rsquo;nın Telif Hakları ve Sinema Genel M&uuml;d&uuml;r&uuml; Abdurrahman &Ccedil;elik&rsquo;in de yorumlarını aktarıyor. &Ccedil;elik, ge&ccedil;en sezon en &ccedil;ok hasılat yapan on filmin de yerli film olması &uuml;zerine demiş ki, &ldquo;Bu, gişe başarısı olarak inanılmaz, hi&ccedil; g&ouml;r&uuml;lmemiş bir şeydir ve &ccedil;ok sevindiricidir.&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Elbette T&uuml;rkiye&rsquo;de sinema sekt&ouml;r&uuml;n&uuml;n 1990&rsquo;lardaki nekahat d&ouml;neminin ardından yeniden canlanmış olması, yeniden gişede yerli filmlerin hakim olmaya başlaması gibi durumlar bizi de mutlu ediyor. &ldquo;Ama,&rdquo; bu durumun, yani T&uuml;rkiye&rsquo;de piyasaya Amerikalı yapım ve dağıtım şirketlerinin (Warner Brothers ve United International Pictures) girmesinin ardından tutulmaya başlayan istatistiklerin ortaya &ccedil;ıkarttığı g&ouml;stergelerle b&uuml;y&uuml;k iddiaların &ouml;ne s&uuml;r&uuml;lmesi asıl sorun &ccedil;&uuml;nk&uuml; T&uuml;rkiye&rsquo;de sinema tarihi bu istatistik d&ouml;neminden &ccedil;ok daha derin ve fazla bir tarihi i&ccedil;eriyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Evet, bellek nank&ouml;rd&uuml;r &ccedil;&uuml;nk&uuml; biz ge&ccedil;mişimizden k&ouml;t&uuml; detayları hatırlamayı sevmeyiz. Onun yerine &ccedil;ocukluğumuzun en g&uuml;zel anlarını hatırlar, hep ge&ccedil;mişi bir &ouml;zlemle anarız. &ldquo;Ama&rdquo; bellek o kadar da k&ouml;t&uuml; değildir, &ccedil;&uuml;nk&uuml; bug&uuml;n&uuml; pazarlamak i&ccedil;in ge&ccedil;mişi unutanları bize daima hatırlatır. Evet, belki T&uuml;rkiye sineması tarihi, bir bilgi, veri ve istatistiksizlikler tarihi. Evet, belki şu an yeni bir şey yaptığını d&uuml;ş&uuml;nen her sinemacı bu coğrafyadaki sinema tarihini bilmek zorunda değil. Evet, belki şu an sinemanın k&uuml;llerinden yeniden doğması kutlanacak bir şey. &ldquo;Ama&rdquo; bu durum hi&ccedil; bir şekilde nisyanı i&ccedil;ermemeli. Yılda &ccedil;ekilen filmin 60-70 olduğu bir d&ouml;nemin b&uuml;rokratı, yılda &ccedil;ekilen filmin 200&rsquo;lerin &uuml;zerinde ve hatta 300&rsquo;&uuml; g&ouml;rd&uuml;ğ&uuml; yılları unutmamalı. Yılda satılan biletin T&uuml;rkiye n&uuml;fusunun yarısı kadar olduğu bir sinema d&ouml;nemi, yılda satılan sinema biletinin T&uuml;rkiye n&uuml;fusunun yedi sekiz katı olduğu yılları unutmamalı. &ldquo;Ama&rdquo; hafıza-ı beşer nisyanla maluld&uuml;r.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Biraz hatırlatma babında&nbsp;<b>Nijat &Ouml;z&ouml;n</b>&nbsp;ve&nbsp;<b>Giovanni Scognamillo</b>&rsquo;nun toparladığı birka&ccedil; rakamı aktaralım. Yeşil&ccedil;am&rsquo;ın emeklemeye başladığı yıllarda, 1950&rsquo;de g&ouml;sterime giren toplan 252 filmin yalnızca 23&rsquo;&uuml; yerli filmken, satılan toplam bilet yaklaşık olarak 12 milyon; 1959&rsquo;da ise 345 filmin 95&rsquo;i yerli ve satılan bilet 25 milyon. Televizyonun olmadığı bu d&ouml;nemde yılda satılan bilet sayısı yaklaşık olarak T&uuml;rkiye&rsquo;nin n&uuml;fusu kadar. Yani kişi başına yılda bir bilet satılmış. 1978 yılına gelindiğindeyse, yalnızca yerli filmlerin toplam bilet satış sayısı, 58 milyon. Yeşil&ccedil;am&rsquo;ın &ccedil;&ouml;kmeye başladığı d&ouml;nemde ise, s&ouml;zgelimi 1985 yılında yine satılan bilet sayısı yaklaşık olarak T&uuml;rkiye&rsquo;nin n&uuml;fusu kadar. Yeşil&ccedil;am&rsquo;ın bitip artık bu memlekette sinema bitti diyenlerin bollaştığı d&ouml;nemlerden 1992 yılında ise 3 milyon bilet satışı s&ouml;z konusu. Şimdi bug&uuml;nlerde sinema canlandı, artık T&uuml;rkiye&rsquo;de post-Yeşil&ccedil;am ya da yeni sinemadan bahsediliyor. Bir&ccedil;okları ise bu yeni d&ouml;nemi Yeşil&ccedil;am&rsquo;ı unutarak biliyorlar ve ilk kez bu kadar film izleniyor, T&uuml;rkiye&rsquo;nin gelmiş ge&ccedil;miş en &ccedil;ok izlenen filmleri bu d&ouml;nemde &ccedil;ekildi diyorlar ya.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Biraz da g&uuml;ncel rakam aktaralım. S&ouml;zgelimi, 2006 yılında satılan toplam bilet sayısı 35 milyon. T&uuml;rkiye&rsquo;nin n&uuml;fusu ise 70 milyon. 2006 yılında sinema sayısı 400 civarındayken, salon sayısı 1300 civarında. &Uuml;lkedeki toplam koltuk sayısınınsa yarıya yakınını uluslararası şirketlere ait zincir sinemalar kontrol ediyor. Son yıllarda &ccedil;ekilen ve gişede 2 milyonun &uuml;st&uuml;nde seyirci &ccedil;ekmiş yerli filmlere bakacak olursak da, bunların da neredeyse yarısının dağıtımını WB ya da UIP ger&ccedil;ekleştirmiş.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sermayesi yerli ama yeşil olmayan Yeşil&ccedil;am&rsquo;ın en iyi yıllarını yaşadığı d&ouml;nemde, s&ouml;zgelimi 1970 yılında, 2242 sinema salonunda g&ouml;sterime giren yerli film sayısı 224 ve satılan bilet sayısı ise 246 milyon. 1970 yılında T&uuml;rkiye&rsquo;nin n&uuml;fusu ne? Yalnızca 35 milyon. Şimdi d&ouml;rt milyon seyirci &ccedil;eken filme T&uuml;rkiye&rsquo;de ilk film g&ouml;sterildiğinden bu yana en &ccedil;ok izlenen film muamelesi yapıyorlar ya, diyelim ki 1970&rsquo;te her filme eşit sayıda seyirci gitmiş olsun. Basit bir matematik işlemi bir şeyler anlatır umarım: 246 milyon b&ouml;l&uuml; 224, eşittir... Duyamadım...&nbsp;<i>S&uuml;p&uuml;rrr</i>!.. S&ouml;z&uuml;m meclisten dışarı, &ldquo;ama&rdquo; eşittir yani...</span></span></p>', 188, 63, 'Yazarlarımızdan', '/images/yazilar/supurrr.jpg', '2017-03-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (35, 'ay-j156', 'blender-ve-elephants-dream', 'Blender ve Elephants Dream', 'Oğuz Özgür Karadeniz', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span>Blender ve Elephants Dream</span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>O</b></span><b><span>ğuz &Ouml;zg&uuml;r Karadeniz</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">1</span></b><span style="font-size: 10pt;">990&rsquo;lar ve 2000&rsquo;lerde &uuml;&ccedil; boyutlu animasyon teknolojisinin yaygın olarak kullanılmaya başlanması ile bu alanda kullanılan ticari yazılım paketlerine alternatif olarak bir &ccedil;ok a&ccedil;ık kaynaklı yazılım geliştirildi.&nbsp;<i>3DStudio</i>&nbsp;<i>Max</i>,&nbsp;<i>Maya</i>&nbsp;ve&nbsp;<i>Lightwave</i>&nbsp;gibi dev ticari yazılımlara benzer fonksiyonları kaynak kodlarıyla birlikte &uuml;cretsiz olarak paylaşan bu g&uuml;&ccedil;l&uuml; &ouml;zg&uuml;r yazılımların arasında&nbsp;<i>Blender</i>; &ouml;zellikleri, kendine has kullanıcı topluluğu, kullanıldığı yapımlar ve belki biraz da sevimliliğiyle kendine &ouml;zg&uuml; bir yer edinmeyi başardı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Blender&rsquo;ın gelişimi diğer a&ccedil;ık kaynaklı projelerden farklı bir &ouml;yk&uuml;ye sahip. Blender, 1998 yılında Hollandalı animasyon şirketi&nbsp;<i>NeoGeo</i>&rsquo;nun kendi projelerinde kullanması i&ccedil;in&nbsp;<b>Ton Rosendaal</b>&nbsp;tarafından geliştirilmeye başlandı. Daha &ouml;nceden Amiga i&ccedil;in<i>Traces</i>&nbsp;isimli ray-tracing programını yazmış olan&nbsp;<b>Rosendaal</b>, programın gelişimini desteklemek i&ccedil;in&nbsp;<i>Not a Number Technologies&rsquo;i&nbsp;</i>(NaN) kurdu ve Blender NaN&rsquo;ın 2002&rsquo;deki iflasına kadar shareware lisansı ile dağıtıldı. NaN&rsquo;ın iflas etmesi ile Blender geliştiricileri programın kaynaklarını a&ccedil;ma kararı alarak bunun i&ccedil;in bir bağış kampanyası başlattılar. Toplanan 100.000 Euro&rsquo;luk bağış ile&nbsp;<i>Blender Foundation</i>kuruldu ve 7 Eyl&uuml;l 2002&rsquo;de GNU GPL lisansı ile Blender&rsquo;ın kaynak kodları a&ccedil;ıldı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/blender_orange_production.jpg" alt="" width="515" height="379" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Blender&rsquo;ın geliştirilmesi Blender Foundation b&uuml;nyesinde&nbsp;<b>Rosendaal</b>&nbsp;tarafından y&ouml;netilmeye devam etti. Şu an geldiği noktada Blender ticari programların sahip olduğu &ouml;zelliklerin hemen hepsine sahip. Modelleme ara&ccedil;ları arasında&nbsp;<i>primitifler</i>,<i>&ccedil;okgen modelleme</i>,&nbsp;<i>subdivision</i>&nbsp;gibi klasik ara&ccedil;ların yanında fare aracılığıyla &ccedil;amurdan heykel yapar gibi modelleme yapmaya olanak tanıyan&nbsp;<i>sculpt</i>&nbsp;aracı gibi yeni nesil ara&ccedil;lar da bulunmakta. Animasyon ara&ccedil;ları arasında&nbsp;<i>iskelet deformasyonu</i>,&nbsp;<i>inverse kinematics</i>&nbsp;gibi temel ara&ccedil;larla birlikte,&nbsp;<i>soft-body</i>, yani yumuşak, yer &ccedil;ekimi ile deforme olan cisimler,&nbsp;<i>akışkan dinamiği</i>,&nbsp;<i>par&ccedil;acık sistemleri</i>,&nbsp;<i>&ccedil;arpışma denetimi</i>&nbsp;<i>ara&ccedil;ları</i>&nbsp;gerek organik modellemeyi gerekse r&uuml;zgar, yer&ccedil;ekimi gibi efektleri kolay ve ger&ccedil;ek&ccedil;i bir şekilde ger&ccedil;ekleştirme olanağı vermekte. Dahası, b&uuml;nyesindeki oyun motoru sayesinde interaktif animasyonlar da programlanabilmekte.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/tekno_screenshot.jpg" alt="" width="465" height="372" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>G&ouml;r&uuml;nt&uuml; kalitesi a&ccedil;ısından da Blender ticari yazılımlarla benzer sonu&ccedil;lar &uuml;retebilmekte. İ&ccedil;sel render motoru sayesinde foto-ger&ccedil;ek&ccedil;i&rsquo;den&nbsp;<i>toon-shade</i>tekniği ile &uuml;retilen &ccedil;izgi film karelerine kadar uzanan farklı g&ouml;r&uuml;nt&uuml;ler oluşturabilirken istenirse dışsal render/ray-tracing motorları ile entegre &ccedil;alışabilme &ouml;zelliğine sahip. Bunun anlamı,&nbsp;<i>YafRay, PovRay&nbsp;</i>gibi g&uuml;&ccedil;l&uuml; &uuml;cretsiz ray-tracing motorlarının yanı sıra hatırı sayılır bir tutarı g&ouml;zden &ccedil;ıkarabilenler i&ccedil;in Pixar&rsquo;ın<i>RenderMan</i>&rsquo;i<i>&nbsp;</i>gibi ticari render motorlarının da Blender&rsquo;la birlikte kullanılabileceği.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu &ccedil;arpıcı teknik &ouml;zelliklerin yanında, Blender&rsquo;ın kullanıcı arabirimi i&ccedil;in kullanılabilecek en kibar ifade &ldquo;kullanıcı dostu bir arabirim olmadığı&rdquo;dır: Klasik Windows uygulaması kullanımına alışkın bir kullanıcı Blender&rsquo;da b&uuml;y&uuml;k olasılıkla hi&ccedil;bir aradığını aradığı yerde bulamayacaktır. Ekran benzer uygulamalarda olduğu gibi d&ouml;rde b&ouml;l&uuml;nm&uuml;ş değildir, kullanılacak ara&ccedil;ların pek &ccedil;oğu i&ccedil;in ekranda tıklanacak buton bulunmamaktadır. Ara&ccedil;ları kullanabilmek i&ccedil;in &ouml;ğrenilmesi gereken bir yığın klavye kısa yolu mevcuttur, fare tuşları bile Blender kullanımında beklenilenden farklı bir işleve sahiptir. Blender sizden alışmış olduğunuz yazılım kullanma bi&ccedil;imini terk etmenizi bekler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Blender&rsquo;ı &ouml;ğrenmenin bir başka zorluğu ise belgelendirmedir. Blender &ccedil;oğunlukla beraberinde hi&ccedil;bir dok&uuml;mantasyon olmadan dağıtılmaktadır. Piyasada 3DStudio Max ve benzeri ticari programlar i&ccedil;in mevcut kitap bolluğuna karşın Blender i&ccedil;in tek bir T&uuml;rk&ccedil;e kitap bulunmamaktadır. İngilizce bilen kullanıcı i&ccedil;in İnternet metin veya video formatında tutoriallarla dolu bir kaynak cenneti iken İngilizce bilmeyen kullanıcı i&ccedil;in b&ouml;yle bir destek s&ouml;z konusu değildir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ouml;ğrenmenin zorluğuna karşın Blender ilk yıllarından itibaren sevilen bir program oldu. Blender&rsquo;ın g&uuml;&ccedil;l&uuml; &ouml;zellikleri ve &ouml;zg&uuml;n kullanılış bi&ccedil;imi, bu programı seven ve onu başkalarına tanıtmak ve &ouml;ğretmek i&ccedil;in &ccedil;abalayan bir kullanıcı topluluğu oluşturdu. Blenderartists ve Blendernation gibi forum ve haber siteleri aracılığıyla haberleşen bu kullanıcılar internet ortamında blender ile yaptıkları &ccedil;alışmalarını, &ouml;neri yorum ve haberlerini, kendi hazırladıkları tutorialları paylaşmaktalar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Blender&rsquo;ın tanınmasının ve yaygınlaşmasının bir sebebi de kuşkusuz&nbsp;<b><i>Elephants</i></b><b><i>Dream</i></b>&rsquo;dir.&nbsp;<b><i>Elephants Dream</i></b>, Blender Foundation&rsquo;ın yapımcılığını yaptığı 2006 tarihli bir kısa animasyondur. 10 dakika s&uuml;ren kısa filmin &ouml;zelliği, tamamının başta Blender olmak &uuml;zere a&ccedil;ık kaynak ara&ccedil;larla &uuml;retilmiş olması ve filmin kendisinin de &uuml;cretsiz dağıtım ve kullanıma a&ccedil;ık olmasıdır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/elephants%20dream2.jpg" alt="" width="527" height="292" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmde &ldquo;m&uuml;kemmelliği kendinden menkul&rdquo; devasa bir makinenin i&ccedil;inde yaşayan Proog ve Emo&rsquo;nun &ouml;yk&uuml;s&uuml; anlatılmaktadır. Yaşlı ve deneyimli Proog, makinenin b&uuml;y&uuml;kl&uuml;ğ&uuml;ne ve karmaşıklığına b&uuml;y&uuml;k bir hayranlık duymakta ve onda b&uuml;y&uuml;leyici g&uuml;zellikler g&ouml;rmektedir. Proog&rsquo;un hayran olduğu bu makine aynı zamanda tehlikelidir de. Makine i&ccedil;inde yaşarken tehlikeden korunmak i&ccedil;in bazı kurallara uyulmalıdır:&nbsp; Belirli bir zamanlamayla adım atılmalı, bazı kapılar asla a&ccedil;ılmamalı, telefonlara cevap verilmemelidir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Proog&rsquo;a nazaran daha &ccedil;ocuksu ve maceracı olan Emo, makinede g&uuml;zellik g&ouml;rmemektedir. Emo&rsquo;ya g&ouml;re orada &lsquo;hi&ccedil;bir şey&rsquo; yoktur. Emo, makinenin m&uuml;kemmel olduğu s&ouml;ylemini kabul etmemekle kalmamakta, Proog&rsquo;un g&uuml;venli yaşamak i&ccedil;in koyduğu kurallara da uymak istememektedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/elephants%20dream.jpg" alt="" width="510" height="291" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Giderek Proog&rsquo;un denetiminden &ccedil;ıkan Emo, onun g&uuml;venli d&uuml;nyası i&ccedil;in bir tehdit oluşturmaya başlar. Emo&rsquo;nun duygusal tepkileri makinenin i&ccedil;inde Proog&rsquo;u korkutan organik yapılar oluşturmaktadır. Finalde, Proog artık kontrol edemediği Emo&rsquo;yu, sevgisine ve onu koruma isteğine rağmen bastonuyla vurarak &ouml;ld&uuml;r&uuml;r. Organik yapılar geri &ccedil;ekilir. Proog artık &ccedil;ok sevdiği makinenin i&ccedil;indeki tek canlıdır, makinenin m&uuml;kemmelliğini yadsıyacak kimse kalmamıştır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Y&ouml;netmen&nbsp;<b>Bassam Kurdali</b>, filmin &ouml;yk&uuml;s&uuml;n&uuml; d&uuml;ş&uuml;ncelerin evrensel ger&ccedil;ekler olarak dayatılmasına karşı bir eleştiri olarak a&ccedil;ıklamakta: &ldquo;<i>İnsanların d&uuml;ş&uuml;nceler / ger&ccedil;ekler / kurgular / sosyal ger&ccedil;eklikler yaratmaları ve bunları başkalarına iletmeleri ve dayatmaları ile ilgili. [...] Proog&rsquo;un makinesinin yerine pek &ccedil;ok d&uuml;ş&uuml;nceyi (para, din, sosyal kurumlar, m&uuml;lkiyet) koyabilirsiniz...</i>&rdquo; (Kurdali 2007)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/elephants%20dream4.jpg" alt="" width="522" height="290" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filme bu a&ccedil;ıdan bakıldığında Blender&rsquo;ın animasyon programları arasındaki yerinin filmin mesajı ile &ouml;rt&uuml;şt&uuml;ğ&uuml; s&ouml;ylenebilir. Genel olarak ticari animasyon programları (ve &ouml;zg&uuml;r yazılımların &ccedil;oğu) belirli bir modelin m&uuml;kemmelliği s&ouml;yleminden yola &ccedil;ıkarak bu modeli tekrarlamaktalar. Blender bu modeli olduğu gibi kabul etmemekte ve faklı bir yol izlemekte. Benzer yazılımlar binlerce dolara satılırken Blender &uuml;cretsiz dağıtılmakta ve kaynak kodlarını paylaşmakta. DVD&rsquo;ler dolusu dev yazılım paketlerinin yanında Blender 8 megabyte&rsquo;lık tek bir kurulum dosyasından oluşmakta. &ldquo;Kullanıcı dostu&rdquo; arabirimlerin arasında kendi &ouml;zg&uuml;n, alışılmadık arabirimiyle kullanılmakta.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sonu&ccedil; olarak Blender Proog&rsquo;ların d&uuml;nyasında Emo olma cesaretini g&ouml;steren bir anlayışın sonucu: Kolay ve g&uuml;venli bir kutu&nbsp; i&ccedil;inde yaşamak yerine keşfediyor, kapıları a&ccedil;ıyor, telefonları cevaplıyor; yazılım d&uuml;nyasının kurallarına farklı bir yerden bakıyor. &ldquo;Free software&rdquo;deki &ldquo;free&rdquo; kelimesinin&nbsp;<i>bedava</i>&nbsp;değil&nbsp;<i>&ouml;zg&uuml;r</i>anlamına geldiğini hatırlatan Blender belki de bu y&uuml;zden d&uuml;nyanın en sevilen animasyon programlarından biri.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><strong><span style="font-size: 10pt;"><span><span style="color: #c43300;">Kaynaklar:</span></span></span></strong></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><a href="http://maxforums.net/showthread.php?t=93390" target="_blank" style="color: #895f37;"><b><span style="font-size: 10pt; color: black;">Kurdali B. 2007</span></b></a><span style="font-size: 10pt; color: black;"><a href="http://maxforums.net/showthread.php?t=93390" target="_blank" style="color: #895f37;">, Maxforums.net, forum iletisi, 29 Kasım 2007.</a></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><a href="http://www.blender.org" target="_blank" style="color: #895f37;"><b><span style="font-size: 10pt; color: black;">Blender.org</span></b></a><span style="font-size: 10pt; color: black;"><a href="http://www.blender.org" target="_blank" style="color: #895f37;">, web sayfası, 29 Kasım 2007.</a></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><a href="http://www.mopi.nl/blogo/" target="_blank" style="color: #895f37;"><b><span style="font-size: 10pt; color: black;">Logo | NeoGeo</span></b></a><span style="font-size: 10pt; color: black;"><a href="http://www.mopi.nl/blogo/" target="_blank" style="color: #895f37;">, &ldquo;<i>Brief History of Blender Logo</i>&rdquo;, web sayfası , 1 Aralık 2007.</a></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: 10pt; color: black;">Elephants Dream 2007</span></b><span style="font-size: 10pt; color: black;">, kısa animasyon, Blender Foundation, Y&ouml;netmen: Bassam Kurdali,&nbsp;<a href="http://orange.blender.org/" target="_blank" style="color: #895f37;">http://orange.blender.org/</a></span><span style="font-size: 10pt;">adresinden indirilebilir.</span></p>', 189, 63, 'Yazarlarımızdan', '/images/yazilar/blender_orange_production.jpg', '2017-03-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (36, 'ay-j157', 'sinemanin-siiri-siirin-sinemasi', 'Sinemanın Şiiri - Şiirin Sineması', 'İlker Mutlu', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Sinemanın Şiiri - Şiirin Sineması</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><b>İ</b></span><b><span>lker Mutlu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span style="color: maroon;"><span>Canım, Sevdiğim, Y&uuml;reğim</span></span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span style="color: maroon;"><span>Bu duvarlar yetmiyor bizi ayırmaya bilesin...&nbsp;<br />Bu parmaklıklar, bu demir kapılar, bu hava, inan...&nbsp;<br />Bazen bir yumrukta yıkacak kadar g&uuml;&ccedil;l&uuml;,&nbsp;<br />Bazen bir ser&ccedil;e kadar g&uuml;&ccedil;s&uuml;zsem, bir nedeni vardır...&nbsp;<br />Hangi zorluğu yenmemiş insanoğlu.&nbsp;<br />Hele taşıyorsa i&ccedil;inde bu insanca sevgiyi.&nbsp;<br />G&uuml;zel g&uuml;nler zorlu duraklardan ge&ccedil;er sevdiğim.&nbsp;<br />Damla damla birikiyor insan.&nbsp;<br />Damla damla sevgili...&nbsp;<br />Bir g&uuml;n akıp gideceğiz hayata...&nbsp;<br />Duvarlar yıkılacak, a&ccedil;ılacak b&uuml;t&uuml;n kapılar bilesin.&nbsp;<br />Benim y&uuml;reğim sensin şimdi, seni vurur durur...&nbsp;<br />Ve yine damla damla &ccedil;oğalıyorsun i&ccedil;imde.</span></span><span>&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span style="color: maroon;"><span>Yılmaz G&uuml;ney</span></span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">Ş</span></b><span style="font-size: 10pt;">iir-sinema, sinema-şiir&hellip; B&ouml;yle tek bir kavram şeklinde d&uuml;ş&uuml;nmemiştim hi&ccedil;bir zaman şiir ve sinemayı. Şiirsel sinema duyduğum ve rağbet ettiğim bir kavramdı. B&uuml;t&uuml;n&uuml;yle şiir gibi akan ya da belli anları şiir gibi g&uuml;zel, etkili anlardan oluşan filmlerdi bunlar benim kafamda.&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in&nbsp;<b><i>Umutsuzlar</i></b>&rsquo;ındaki t&uuml;m konuşmasız sahneler ve&nbsp;<b>Seyyit Han</b>&rsquo;ındaki su boyunca yaralı y&uuml;r&uuml;y&uuml;ş&uuml; gibi,&nbsp;<b>Raj Kapoor</b>&rsquo;un&nbsp;<b><i>Avare</i></b>&rsquo;de izini kaybettiği kız arkadaşının resmine takıldığı an gibi,<b>Ingmar Bergman</b>&rsquo;ın&nbsp;<b><i>Yaban &Ccedil;ilekleri</i></b>&rsquo;nde ihtiyar adamın kelimeler kullanmadan konuşan bakışları gibi,&nbsp;<b>Giuseppe Tornatore</b>&rsquo;nin&nbsp;<b><i>Herkesin Keyfi Yerinde</i></b>&rsquo;sinde hani Marcello telefon ederken &ccedil;ocuğuna hayat durur ya, o anlar gibi, bir s&uuml;r&uuml; filmden bir s&uuml;r&uuml; &ouml;rnek verebileceğim haller bende şiirsel sinema etkisi yaratırdı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span>Yabancı filmlerde şiir kullanımı olduk&ccedil;a yaygın olduğu halde, bizde &ouml;rneklerin &ccedil;ok az olması da d&uuml;ş&uuml;nd&uuml;r&uuml;c&uuml;.&nbsp;<b><i>Fahriye Abla</i></b>&nbsp;gibi &ouml;yk&uuml;-şiir k&ouml;kenli filmler, ayrıksı &ouml;rnekler. İlgin&ccedil; bir durum bu, &ccedil;&uuml;nk&uuml; doğuştan şair(!) bir milletiz. İşin şakası bir yana, sinema-şiir ilişkisi bizde kopuktur, sinemamızda bir s&uuml;r&uuml; şair olmasına rağmen.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İlk aklıma gelenler arasında&nbsp;<b>Cahit Irgat</b>&nbsp;(1915-1971) ve&nbsp;<b>Nihat Ziyalan</b>&nbsp;(1936- ) bulunuyor. &Ccedil;ok sayıda kurum &ccedil;atısı altında &ccedil;alışarak tiyatro oyuncusu olarak &uuml;nlenen ve şairliği de boşlamayan&nbsp;<b>Irgat</b>&nbsp;bir&ccedil;ok sinema filminde de rol alır. Irgat bir film y&ouml;netip bir de roman yazmış. Siyah-beyaz filmlerin korkulan k&ouml;t&uuml; adamı.&nbsp;<b><i>İstanbul&rsquo;un Fethi</i></b>&nbsp;(1951),&nbsp;<b><i>Kızıltuğ</i></b>&nbsp;(1952) ve&nbsp;<b><i>Mor Defter</i></b>&nbsp;(1964) oynadığı filmlerden birka&ccedil;ı. Ve akla takılan bir dize:&nbsp;<i>bana &ccedil;arptık&ccedil;a anlar / yağmur yağmur olduğunu / r&uuml;zgar, r&uuml;zgar</i>&nbsp;(ağa&ccedil;).&nbsp;</span><span><b>Ziyalan</b>&nbsp;da tiyatrocu. &Ccedil;ocukluk arkadaşı&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in isteğiyle sinemaya ge&ccedil;er. Yetmişe yakın filmde irili ufaklı rol&uuml;n ardından, Yeşil&ccedil;am&rsquo;da seks filmleri furyasının başlamasıyla Avustralya&rsquo;ya g&ouml;&ccedil;er. 1980&rsquo;den beri Sydney&rsquo;de yaşamakta ve şiir, &ouml;yk&uuml; ve roman &uuml;retmekte. Bu da ondan bir dize:&nbsp;<i>doluştu kuşlar i&ccedil;eri / sağnağa yakalanmış u&ccedil;uşları</i></span><span>&nbsp;(kuş&ccedil;ul).</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Şiir, simgeselliği, toparlayıcılığı ve g&ouml;rselliği aracılığıyla sinemaya uyarlamaya en uygun edebiyat t&uuml;r&uuml; iken, bizde neden kullanılmıyor ya da kısmen de olsa faydalanılmıyor? T&uuml;m&uuml;yle faydalanılmadığını s&ouml;ylemek de haksızlık olur aslında.&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;<b><i>Arkadaş</i></b>&rsquo;ta&nbsp;<b>Ahmet Arif</b>&nbsp;okur.&nbsp;<b>S&uuml;reyya Duru</b>&rsquo;nun&nbsp;<b><i>Kara &Ccedil;arşaflı Gelin</i></b>&rsquo;inin sonunda, t&uuml;rk&uuml; formunda da olsa, yine&nbsp;<b>Ahmet Arif</b>&rsquo;in&nbsp;<i>Adiloş Bebem</i>&nbsp;şiiri okunur.&nbsp;<b>Sadri Alışık</b>&nbsp;filmlerinde şiirin ya da şairce konuşmanın yeri vardır.&nbsp;<b><i>Alageyik</i></b>,&nbsp;<b><i>Kızılırmak-Karakoyun</i></b>,&nbsp;<b><i>Irmak</i></b>&nbsp;ve&nbsp;<b><i>G&ouml;k&ccedil;e&ccedil;i&ccedil;ek</i></b>&nbsp;gibi k&ouml;y filmlerimizde diyaloglar şiir veya destansı s&ouml;ylem t&uuml;r&uuml;ndedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Avrupalı olsun Amerikalı olsun, yabancı sinemadaki &ouml;rneklerle oranlandığında bizde şiirin kullanımı geride kalır. Halbuki filmlerde şiir kullanımı seyirci &uuml;zerinde dramatik etki yaratmak bakımından umulanın &ouml;tesinde ilgin&ccedil; sonu&ccedil;lar ortaya &ccedil;ıkartmaktadır. Hatta şiirin sesli filmler d&ouml;neminin başlangıcından beri sinema i&ccedil;in iyi bir &ccedil;&ouml;z&uuml;m, bir etkileme aracı olduğu s&ouml;ylenebilir. Sinema bilin&ccedil;altına hitap ederken, şiir de buna katkıda bulunur.&nbsp;<b>Virginia Wolf</b>, Atlantic Montly dergisinde yayımlanan bir yazısında: &ldquo;<i>Film yapımcılarının d&uuml;ş&uuml;ncelerini iyi anlatacak yeni bir simge bulduklarında anormal zenginlik kazandıklarını</i>&rdquo; s&ouml;yler. Bu zenginlik simgelerin yarattığı soyut anlatım g&uuml;c&uuml;nden kaynaklanmaktadır. Simgelerin zengin kaynağı da bildiğiniz gibi şiirlerdir.&nbsp;<b>Kenneth Koch</b>, şiiri dil i&ccedil;inde dil olarak betimler ve şiir dilinde s&ouml;zc&uuml;klerin sesinin anlamlarına eşdeğer bir d&uuml;zeye &ccedil;ıktığını belirtir. Şiir, anlaşılmasa bile, okuyucusu &uuml;zerinde b&uuml;y&uuml;l&uuml; ve uyuşturucu bir etkiye sahiptir. Sinema da şiirin bu etkisinden yararlanır. Bir şiirden alınmış dizeler, tıpkı şiirin i&ccedil;ersindeki metaforlar gibi, anlatımı yoğunlaştırarak coşkuyu artırmaktadır.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir &ccedil;ocuk nasıl dadısının okuduğu ritimli tekerlemelerin etkisinde kalıyor, bir hoşluk duygusu eşliğinde y&uuml;reği &ccedil;arpıyorsa, şiirin yer aldığı bir filmi seyreden izleyici de &ouml;ylesine heyecanlanmaktadır. Şiir, duyguların, coşkunun ortaya &ccedil;ıkması bakımından m&uuml;zikal filmlerdeki şarkı ve dansın işlevini yerine getirmektedir. Şiirin dizeleri beynin dış tabakasında (cerebral corteks) titreşimler yaratarak izleyici sanki bu şiiri ilk kez okuyormuş, şiirle ilk kez karşılaşıyormuş&ccedil;asına etki yaratır ve perdedeki olaya tepki ve onu &ouml;z&uuml;mseme şiirle eşanlı olarak ortaya &ccedil;ıkar. Şiirsel (poetik) bir filmde karakter yatay (horizontal) planda dramayı geliştirirken, i&ccedil; konuşmalarla da dikey (vertical) bir piramit kurmaktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Uygulamalar &ccedil;er&ccedil;evesinde şiirin sinemada zaman kazandırıcı olduğu da ileri s&uuml;r&uuml;lm&uuml;şt&uuml;r. Şiir dilinin yoğun, eksiltmeli yapısı, az s&ouml;zc&uuml;k kullanarak &ccedil;ok şey anlatması, sinemanın sevdiği bir &ouml;zelliktir.&nbsp;<b>Marilyn Monroe&nbsp;</b>&ldquo;<i>şiir okumak zaman kazandırıyor</i>&rdquo; diyerek buna değinmiştir. Aynı olgu, senaryo yazarları i&ccedil;in birinci &ouml;nceliklidir. &Ouml;yle ki, doğru yerde doğru şiir kullanıldığında, karakterin i&ccedil; d&uuml;nyasının yansıtılması ve temanın unsurları bakımından iletimde zaman kazanılmaktadır.&nbsp;<b>Donald Hall</b>&nbsp;&ldquo;<i>şiirin s&ouml;ylenemeyeni s&ouml;ylemeyi olanaklı kıldığını</i>&rdquo;, yaşamda da dilsizi dile getiren, &ouml;zl&uuml; bi&ccedil;imde konuşturan bir sinema olduğunu s&ouml;ylemiştir. Bu &ccedil;er&ccedil;evede şiir sinemanın kızkardeşidir. Sanatsal kullanım a&ccedil;ısından aralarında bir aile dayanışması olduğu s&ouml;ylenir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tanımlar, kavramlar ve &ouml;rnekler &uuml;zerinden giderek konuyu daha geniş bir &ccedil;er&ccedil;evede, bu ilgi &ccedil;ekici alanın kuramcı y&ouml;netmenlerinin &ccedil;izdiği yol &uuml;zerinde ve daha da &ouml;nemlisi &ouml;znel/nesnel dengesi kurarak tartışmaya &ccedil;alışalım.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinemanın lirik şiirleri kendi i&ccedil;lerinde sessiz olan olaylar dizisini, hareketin, m&uuml;ziğin, diyaloğun ve g&ouml;r&uuml;nt&uuml;n&uuml;n katkısıyla duygu ve d&uuml;ş&uuml;nceleri g&ouml;r&uuml;n&uuml;r kılar ve kendini salt bu anlamıyla tanımlar. Bu yaklaşım film liriğin fonksiyonudur.&nbsp;<b>Weinberg</b>&rsquo;in&nbsp;<b><i>G&uuml;z Ateşi</i></b>&rsquo;ndeki (Autumn Fire) gibi hikaye par&ccedil;alarına sahip olabilir veya&nbsp;<b>Deren</b>&rsquo;in&nbsp;<b><i>&Uuml;lkede</i></b>&rsquo;sindeki (At Land) gibi tamamen resim şeklindeki g&ouml;r&uuml;nt&uuml;ler de i&ccedil;erebilir. Veya&nbsp;<b>Harrington</b>&rsquo;ın&nbsp;<b><i>Kenarda</i></b>&rsquo;sındaki (On the Edge) gibi &ouml;d&uuml;n&ccedil; alınmış (Ives&rsquo;tan) veya&nbsp;<b>Eisenstein</b>&rsquo;ın&nbsp;<b><i>Duygulu Aşk</i></b>&rsquo;ındaki (Romance Sentimentale) gibi &ouml;zel olarak bestelenmiş (Aleksandrov&rsquo;dan) m&uuml;zik kullanabilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Esasında bir filmi lirik kılan kullanılan &ouml;ğeler değil onların yarattığı etki. Yukarıdaki film-şiirler kullandıkları teknikler bakımından farklıdırlar, ama t&uuml;m&uuml; de ortak paydada duyarlılıkların ve hayallerin doğrudan iletişimini ama&ccedil;larlar. Benzer anlatılar saf şiirden uzak duran başka filmlerde de bulunabilir. B&ouml;yle durumlarda, iletişim doğrudanlıktan, samimiyetten, liriğin kişisel kalite &ouml;zelliğinden yoksun kalır. Bu aracılığıyla şiirin sadece s&uuml;z&uuml;ld&uuml;ğ&uuml; daha g&uuml;&ccedil;l&uuml; başka bir resmi unsurun varlığının sonucudur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/etoile.jpg" alt="" width="480" height="355" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Buna iyi bir &ouml;rnek&nbsp;<b>Dreyer</b>&rsquo;in&nbsp;<b><i>Jan Dark&rsquo;ın Tutkusu</i></b>&rsquo;nda (The Passion of Joan of Arc) vardır. Joan itiraf etmesi i&ccedil;in işkence g&ouml;rmek &uuml;zereyken, bize ondaki etkiler, zindandaki atmosfer, bir araya toplanan yargı&ccedil;lar, işkenceci, aletler verilir. Onun zincirli ayağının nasıl hissettiğinin g&uuml;&ccedil;l&uuml; g&ouml;rsel etkilerini; o işkence odasına y&uuml;r&uuml;y&uuml;ş&uuml;ndeki titreten korkuyu; bayılırkenki sendeleyişini, tehditkar g&ouml;r&uuml;nen ve hasta edici şekilde d&ouml;nen korkun&ccedil; gergiler, demirler ve tekerleklerin bir montajı i&ccedil;inde alırız. Biz bu duyguları g&uuml;&ccedil;l&uuml; bir şekilde hissetmeye devam ederken, film-şiirin &ouml;zelliği orada değildir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Aynısı&nbsp;<b>Truffaut</b>&rsquo;nun&nbsp;<b><i>400 Darbe</i></b>&rsquo;sinin (The 400 Blows) bazı kısımları i&ccedil;in de s&ouml;ylenebilir, &ouml;zellikle &ccedil;alınan daktiloyu geri g&ouml;t&uuml;ren &ccedil;ocuk karakola g&ouml;t&uuml;r&uuml;ld&uuml;ğ&uuml;nde. Biz onun g&ouml;zlerinden polis arabasının arkasından beri ge&ccedil;ilen karanlık sokakları g&ouml;r&uuml;r&uuml;z; insafsızca yitmekte olan yaşama dair şeylerin bir g&ouml;r&uuml;nt&uuml;s&uuml;d&uuml;r. Ama bu keskin ge&ccedil;işin t&uuml;m etkisi &ouml;zel durumlara dayanır; ve anlatımı şiirsellik y&uuml;kl&uuml; olduğu halde, film-şiir olarak alınamaz. Film-şiir &ouml;ncelikle kişisel, soyut (abstract) ifade şartlarında geliştirilmelidir; sadece bundan sonra gelen &ouml;yk&uuml;leyici veya başka herhangi bir bi&ccedil;imsel etki eklenebilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Film-şiir&nbsp;<i>ger&ccedil;ek</i>&nbsp;karakter ve durumları kullandığında, onları y&ouml;netmenin d&uuml;ş&uuml;nce ve duygularının sembolleri haline d&ouml;n&uuml;şt&uuml;rmelidir. Eğer kimliklerinin g&ouml;lgesinden daha fazlasını bırakıyorlarsa, kendileri &uuml;zerinde, &ouml;yk&uuml;,&nbsp;<i>ger&ccedil;ek&ccedil;ilik</i>&nbsp;vb. olmayı &ccedil;ok fazla ve taşkın lirik etkiler olmayı &ccedil;ok az yaşayacaklardır. Bu nedenle&nbsp;<b><i>Jan Dark&rsquo;ın Tutkusu</i></b>&nbsp;ve&nbsp;<b><i>400 Darbe</i></b>&rsquo;den &ouml;rnekler ne film-şiirdir; ne de b&ouml;yle olmaya niyetlidirler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Birka&ccedil; avangard film ve video y&ouml;netmeni, bir şiiri&nbsp;<i>canlandıracak</i>&nbsp;bir film yapmak ya da bir filme&nbsp;<i>eşlik etmesi</i>&nbsp;i&ccedil;in bir şiir kullanmak yerine, ne s&ouml;zl&uuml; ne de g&ouml;rsel metnin salt kendisi &uuml;zerinde &uuml;retemeyeceği anlamları, &ccedil;ağrışımları ve metaforları oluşturan şiir ve filmin bir sentezini yarattılar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu yan yana sıralanan şiirsel metinler ve sinemasal g&ouml;r&uuml;nt&uuml;ler uygulaması,&nbsp;<b>Charles Sheeler</b>&nbsp;ve&nbsp;<b>Paul Strand</b>&rsquo;ın kısa filmleri&nbsp;<b><i>Manhatta</i></b>&rsquo;yı ortaya koydukları 1921&rsquo;e kadar dayanır. New York şehrinden g&ouml;r&uuml;nt&uuml;leri 19. y&uuml;zyılın b&uuml;y&uuml;k Amerikan şairlerinden&nbsp;<b>Walt Whitman</b>&rsquo;ın bir &ccedil;ok şiirinden alıntılar ve yorumlarla birleştiren y&ouml;netmenler, sadece Amerikan şehirciliğini ve modern teknolojiyi &ouml;vmekle kalmadılar, bunun yanında şiirsel dilin ve hareketli g&ouml;r&uuml;nt&uuml;lerin dinamik ortakyaşarlığını araştırmakla ilgilenen film ve (daha yakında da) video sanat&ccedil;ılarını &ccedil;ekmeye devam eden yeni bir film t&uuml;r&uuml;n&uuml;, şiir-filmi başlattılar. Şiir-filmin diğer iki erken &ouml;rneği olan,&nbsp;<b>Man Ray</b>&rsquo;ın&nbsp;<b>Robert Desnos</b>&rsquo;un bir şiirinden kısımlarla b&uuml;t&uuml;nleşen&nbsp;<b><i>Deniz Yıldızı</i></b>&nbsp;(Etoile de Mer, 1928) ve yaylanan ve &ccedil;ok&ccedil;a kelime oyunu kullanan&nbsp;<b><i>Anemic Cinema</i></b>&nbsp;(1926) filmleri, Avrupalı avangard filmlerin ilk jenerasyonunun klasikleridir ve&nbsp;<b><i>Manhatta</i></b>&nbsp;&ldquo;Birleşik Devletler&rsquo;de &uuml;retilen ilk ger&ccedil;ek avangard film&rdquo; olarak sınıflandırılır. Bu filmin nasıl ger&ccedil;ekten avangard bir film olduğunu sorarsanız, ş&uuml;phe yoktur ki şiir-filmler avangard filmlerin Ortodoks olmayan temalar ve teknikler &ouml;zelliğine sıklıkla anlam katmışlardır. Diğer taraftan, ortada haklı olarak film şiir diye adlandırılabilecek bir &ccedil;ok avangard film vardır ve aslında erken avangard film denemeleri ritmik efektleri, karmaşık bi&ccedil;imsel ilişkileri ve metaforik ya da sembolik anlamları i&ccedil;in dikkatlice edit edilen, izlenimci veya yarı-soyut g&ouml;r&uuml;nt&uuml;lerden oluşturulan, anlatısı olmayan kısa filmler i&ccedil;in&nbsp;<i>sine-şiir</i>(cin&eacute;-poem) tanımını &uuml;rettiler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Avangard g&ouml;rsel araştırmaların arkasındaki kavramları teoriye d&ouml;kmeye başlayan deneysel film y&ouml;netmenleri ve eleştirmenlerden bu yana, şiirsellik d&uuml;ş&uuml;ncesi deneysel film uygulamalarının daha lirik olan yanının verimli bir modeli olarak g&ouml;r&uuml;ld&uuml;. Anlatısı &ouml;zg&uuml;rleşen y&ouml;netmenin &uuml;retim anlayışı, modernist şairle benzeşir g&ouml;r&uuml;nd&uuml;. Y&ouml;netmenin yaşam tarzı dahi romantik şairinkiyle benzeşiyordu. Bu durum, sinema sanat&ccedil;ılarının filmin ancak kendi dilinin &ouml;zelliklerini kullanarak y&uuml;kseldiğinde saygın bir sanat formu olabileceğini savunan, i&ccedil;inde sıklıkla filmin bağımsız bir sanat olarak &ouml;nemini b&uuml;y&uuml;tt&uuml;kleri bazı a&ccedil;ıklamaları nedeniyle bir &ccedil;elişki gibi g&ouml;r&uuml;nmektedir.&nbsp;<b><i>Kameralı Adam</i></b>\'ın (The Man With The Movie Camera) a&ccedil;ılış sekansında&nbsp;<b>Dziga Vertov</b>&nbsp;manifestosunu yazar: &ldquo;<i>Film, g&ouml;zlenebilir olayların sinemasal iletişim i&ccedil;indeki bir deneyini arayazıların yardımı olmaksızın (arayazısız bir film), bir senaryonun yardımı olmaksızın (senaryosuz bir film), sahnenin yardımı olmaksızın (akt&ouml;rs&uuml;z, setsiz bir film vb.)&nbsp; sunar. Bu deneysel &ccedil;alışma sinemanın tiyatro ve edebiyatın dilinden t&uuml;m&uuml;yle ayrı olmasına dayalı, ger&ccedil;ekten uluslararası olan mutlak dilini yaratmayı hedeflemektedir.&rdquo;&nbsp;</i>Bu ifadede Vertov seyircilerden ve y&ouml;netmenlerden, fark g&ouml;zetmeden, film yapmayı anlamlı olmak i&ccedil;in başka sanatlardan almaya ihtiya&ccedil; duymayacak bir dil, kendi dili ile bağımsız bir sanat olarak g&ouml;rmelerini ister.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/ManCamera2.jpg" alt="" width="400" height="342" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Benzer bir yaklaşım 1960&rsquo;ların Amerikan avangardı referans alınarak da &ouml;ne s&uuml;r&uuml;lebilir. &Ouml;nemli denemesi &lsquo;G&ouml;rme &Uuml;zerine Metaforlar&rsquo;da (Metaphors on Vision)&nbsp;<b>Stan Brakhage</b>&nbsp;şunu iddia eder: &ldquo;&hellip;<i>dile yabancı ve g&ouml;rsel iletişim &uuml;zerine kurulu olan, g&ouml;rsel bellekte bir gelişmeyi arzulayan ve d&uuml;nyanın orijinalindeki ve en derin hissindeki algıdan bağımsız bir bilgi arayışı vardır.</i>"</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmin diğer sanatlardan ayrılmasını destekleyen polemik tavrına rağmen, yukarıdaki yazarların t&uuml;m&uuml; kendi &ccedil;alışma modları ve şiir sanatı arasında paralellikler kurmanın uygun olduğunu hissettiler. Onlar kendilerini &lsquo;film şairleri&rsquo; ve filmlerini de &lsquo;film şiirler&rsquo; olarak adlandırdılar. Bu a&ccedil;ık &ccedil;elişki&nbsp;<b>Maya Deren</b>&rsquo;in yazılarında &ccedil;ok belirgindir.<b>&nbsp;Renata Jackson</b>&nbsp;şunu s&ouml;yler: &ldquo;</span><i><span>&hellip;Deren y&ouml;netmeni başka herhangi bir formdan yersiz bir şekilde &ouml;d&uuml;n&ccedil; almaya karşı uyarırken, a&ccedil;ık&ccedil;a kıyaslanabilir filmsel ve şiirsel yaratıcılığı tarif etmektedir. (&hellip;) Bundan yola &ccedil;ıkarak bizler onun (anlatısını edebiyat ve tiyatrodan alan) Hollywood sinemasına, (resmi taklit eden )soyut filme veya (Deren&rsquo;in bakışında, g&ouml;revi yeni formlar yaratmak yerine ger&ccedil;eği sunmak olduğu i&ccedil;in bir sanat formu olarak alınamayacak olan) belgesele dair olan eleştirel yaklaşımını a&ccedil;ık bir şekilde anlayabiliriz. Ger&ccedil;ek film sanatı doğrusal anlatıcı anlatımlarını, anime edilmiş resimleri veya belgesel ger&ccedil;ek&ccedil;iliğini i&ccedil;ermez; Deren i&ccedil;in, o daha şiirsel yaklaşımların sonucu olmalıdır.</span></i></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/autumn%20fire%2015.JPG" alt="" width="490" height="359" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Deren, Brakhage ve Vertov film ve şiir arasındaki paralellikle ilgilenen y&ouml;netmen ve teorisyenlerin sadece bir kısmıydı. Fikir 1920&rsquo;lerin ortalarında Fransız &lsquo;Empresyonistler&rsquo; (Germaine Dulac, Louis Delluc vs.), Man Ray, Hans Richter ve diğerleri tarafından ileri s&uuml;r&uuml;ld&uuml;ğ&uuml;nden beri, tartışma s&uuml;rekliliğini korudu ve paralellik bir takım farklı bakış a&ccedil;ılarından da g&ouml;r&uuml;lerek bir par&ccedil;a belirsizleşip &lsquo;film şiir&rsquo; terimine ulaştı. Bu bakış a&ccedil;ılarındaki farklılıklara rağmen, onların &ccedil;oğunu birbirine bağlayan onları yazanların filmin &ouml;ncelikle g&ouml;rsel bir dil olması gerektiğine olan inancı paylaşmaları ve eğer i&ccedil;inde herhangi bir şiir etkisi de varsa, bunun ger&ccedil;ek filmde de olması gerektiğiydi. Başka bir deyişle, şiirler filmin olduk&ccedil;a g&ouml;rsel doğasına dahil edilmeliydiler. &Ouml;zellikle Vertov ve Dulac gibi erken y&ouml;netmenler, s&ouml;zsel lisanın modern filmde gereksiz olacağına inandıklarından arayazı kullanmaktan uzak durdular.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Oysa, 1920&rsquo;lerle 1970&rsquo;ler arasında gelişen modernist avangarda dahil olanların hepsi de bir filmdeki şiirsel &ouml;zellikleri artırmak i&ccedil;in kelimelerin kullanılabileceği d&uuml;ş&uuml;ncesine karşı değildi. Hatta&nbsp;<b>Deren</b>&nbsp;gibi filmin g&ouml;rselliği konusunda &ccedil;ok g&uuml;&ccedil;l&uuml; inanca sahip olan bazıları dahi konuşma dilini kullanmanın filmin g&ouml;rsel değerine zarar verme olasılığını &ouml;nemsemedi. Bir &lsquo;Şiir ve Film&rsquo; sempozyumunda&nbsp;<b>Arthur Miller</b>&rsquo;in kelimelerin filmde kullanılamayacağı s&ouml;z&uuml;ne yanıt olarak: &ldquo;<i>...g&ouml;r&uuml;nt&uuml;den ayrı bir yansıtma olarak kullanıldıysa filmde fazlalık olacaktır Oysa, eğer kendi i&ccedil;inde b&uuml;t&uuml;n olan g&ouml;r&uuml;nt&uuml;den &ccedil;ıkmayan, ama onunla ilgili olan başka bir boyutta farklı bir d&uuml;zeye taşınırlarsa, o zaman ikisi birlikte bir şiiri oluşturan iki unsur olurlar&rdquo;</i>&nbsp;d&uuml;ş&uuml;ncesini &ouml;ne s&uuml;rd&uuml;.&nbsp;</span><span><b>Ian Hugo</b></span><span>&nbsp;1952 yapımı&nbsp;<b><i>Atlantis&rsquo;in &Ccedil;anları</i></b>&rsquo;nı (Bells of Atlantis) bu anlayışla &ccedil;ekti.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/autumn%20fire%20%205.jpg" alt="" width="430" height="331" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu g&ouml;r&uuml;nt&uuml; ve metin kombinasyonu&nbsp;<b>William Wees</b>&rsquo;in &lsquo;şiir-film&rsquo; t&uuml;r&uuml; diye adlandırdığı şeyi oluşturur. Onun &ouml;ne s&uuml;rd&uuml;ğ&uuml; gibi: &ldquo;<i>..bir ka&ccedil; avangard film ve video y&ouml;netmeni ne s&ouml;zsel ne de g&ouml;rsel metnin tek başına &uuml;retemeyeceği &ccedil;ağrışımlar ve metaforlar oluşturan bir şiir ve film sentezi yarattılar</i>&rdquo;<i>&nbsp;</i>Bu noktada,&nbsp;<b>Wees</b>&rsquo;in fazlaca kullanılan &lsquo;film şiir&rsquo; tanımına tutunmak yerine, yeni bir terim kullandığına dikkat etmek gerekir. O, s&ouml;z&uuml;n&uuml; şiir-filmlerin neden genellikle bir k&ouml;şeye atıldığının nedenlerini a&ccedil;ıklayarak s&uuml;rd&uuml;r&uuml;r: &ldquo;</span><i><span>...film şiirler uzun zaman avangard film geleneğinin merkezi olarak kabul edildiğinden, şiir-filmler &ouml;zel ilgiyi az &ccedil;ektiler (&hellip;) &ccedil;&uuml;nk&uuml; şiir-filmler melez sanatın bir t&uuml;r&uuml;yd&uuml; ve bu nedenle daha az &lsquo;saf&rsquo; ve y&uuml;ksek modernist anlayış a&ccedil;ısından esasen daha az sinemasaldılar.&rdquo;</span></i></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu yaklaşım ilk olarak Wees&rsquo;in 1984&rsquo;te yayımlanan etkili &ccedil;alışması &lsquo;Şiir Film&rsquo;de (The Poetry Film) sunuldu. Bu &ccedil;alışmada Wees bunun bir olasılıkla film şiirin eski tanımını bir kenara atmayan ama aynı zamanda yeni kombine formla da ilgilenen, y&ouml;netmen ve şair&nbsp;<b>Herman Berlandt</b>&nbsp;tarafından San Francisco&rsquo;da organize edilen şiir-film workshoplarında ortaya &ccedil;ıkan yeni film anlayışıyla ilgilenen şairler nedeniyle olduğunu iddia eder. Kombinasyon s&uuml;recini tanımlarken de şu g&ouml;r&uuml;şleri savunur: &ldquo;<i>...kelimelerin kendine &ouml;zg&uuml; anlamlarının ve &ccedil;ağrışımlara, metaforlara daha geniş alan &uuml;retecek g&ouml;r&uuml;nt&uuml;lerin sınırlı ikonik referanslarının &uuml;zerine yayılır. Aynı zamanda, kelimeler ve g&ouml;r&uuml;nt&uuml;lerdeki anlamın potansiyel olarak limitsiz olasılıklarına sınırlar koyar ve bazı somut&ccedil;a iletilebilir deneyimler doğrultusundaki etkilenmelerimizi y&ouml;nlendirir..</i>&rdquo; B&ouml;ylece, şiir-filmler g&ouml;rsel ve i&ccedil;eriksel bağlantıların olasılıklarını genişletir ve aynı zamanda işitsel-g&ouml;rsel tanımlamaların metaforik bağlantılarını olası kılarken, g&ouml;rsel metaforların araştırılmasında da farklı yollar sunarlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Şiir film kavramı bir ana akım haline geldik&ccedil;e tanımı da daha fazla bulanıklaşmaya başladı. Wees\'in yeni melez t&uuml;re temel olan&nbsp;<i>şiir-film</i>&nbsp;g&ouml;r&uuml;ş&uuml;, daha az sıklıkta kullanılır oldu ve kısa zamanda yeni şiir-filmler daha genel ve daha kullanışsız olan film şiir g&ouml;r&uuml;ş&uuml; altında sınıflandırıldılar, ki Wees bunu a&ccedil;ık&ccedil;a şiir-filme uzak ara farklı bir t&uuml;r/mod olarak g&ouml;rmekteydi.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tam da bu noktada durup,&nbsp;<b>Hugo</b>&rsquo;nun şiir-filmi&nbsp;<b><i>Atlantis&rsquo;in &Ccedil;anları</i></b>&nbsp;(1952) ile<b>Maya Deren&nbsp;</b>ve<b>&nbsp;Alexander Hammid</b>&rsquo;in film şiirleri&nbsp;<b><i>Meshes of the Afternoon</i></b>(1943) arasında da &ouml;ğretici bir karşılaştırma yapılabilir.&nbsp;<b><i>Meshes of the Afternoon</i></b>&rsquo;un &ccedil;ağrıştırdığı s&uuml;rreal, r&uuml;ya-benzeri durum tamamen g&ouml;rsel, sinemasal efektlere dayanır. Aslında, film Deren&rsquo;in&nbsp;<b>Teiji Ito</b>&nbsp;tarafından yapılan m&uuml;ziği eklemeye karar verdiği 1959 yılına kadar ses izine sahip değildi. M&uuml;zik &uuml;rpertici bir atmosfer ekleyince, filmin&nbsp;<i>şiiri</i>&nbsp;onun g&uuml;&ccedil;l&uuml;, davetkar g&ouml;r&uuml;nt&uuml;lerinden, (Deren tarafından oynanan) kahramanın dansımsı hareketlerinden ve filmin montajının &uuml;rettiği kalıplar ve &ccedil;ağrışımlardan t&uuml;rer.&nbsp;<b>Catrina Neiman</b>&rsquo;ın g&ouml;zlemlediği gibi: &ldquo;<i>Her bir g&ouml;r&uuml;nt&uuml;, her bir ge&ccedil;iş bir diğeriyle uyaklıdır ve r&uuml;ya ve devamlılığın yanılsamasını (illusion) yaratmak i&ccedil;in de, ger&ccedil;eklik arasındaki iki anlamlılığı kurmak i&ccedil;in de eninde sonunda gereklidir.</i>&rdquo; Filmi film şiirin g&uuml;&ccedil;l&uuml; bir &ouml;rneği yapan bu g&ouml;rsel&nbsp;<i>uyum</i>dur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ouml;te yandan&nbsp;<b>Bells of Atlantis,&nbsp;</b>su altı, rahim-benzeri<b>&nbsp;</b>bir ortamda s&uuml;r&uuml;klenen ve sonda kuru toprağa ve a&ccedil;ıklanmayan bir &ccedil;armıha gerilmeye ulaşan gizemli bir fig&uuml;r olarak Anais Nin&rsquo;in g&ouml;r&uuml;nt&uuml;leri eşliğinde, Nin&rsquo;in kendi novellası House of Incest&rsquo;ten şiirsel d&uuml;zyazı anlatıları onun sesinden verir. (Filmlerin tarihlerine bakıldığında ve Nin &ndash;ve muhtemelen Hugo- Deren&rsquo;in &ccedil;alışmasını iyi bildiği de dikkate alındığında,&nbsp;<b>Bells of Atlantis</b>&rsquo;in&nbsp;<b>Meshes of the Afternoon</b>&rsquo;dan etkilenmiş olduğu ş&uuml;phesi mantıklıdır.) Nin&rsquo;in metninin hayli iddialı dili filmin g&ouml;r&uuml;nt&uuml;lerinin sembolik anlamlarını b&uuml;y&uuml;t&uuml;r ve diğer taraftan, filmin dikkatle yapılandırılan &ccedil;ekimleri ve bindirmeleri, filtre edilmiş renkleri, akıcı y&ouml;netilmiş ve yansıtılmış elektronik m&uuml;zik sadece metnin havasını tamamlamaz, ona onun metaforik anlamlarını da g&uuml;&ccedil;lendiren ve b&uuml;y&uuml;ten duygusal bir boyut da verir. Film Nin&rsquo;in metninin g&ouml;rsel-işitsel bir terc&uuml;mesi veya sinematik &ldquo;okuma&rdquo;sı olarak d&uuml;ş&uuml;n&uuml;lebilir, ve metin film yapılmadan &ouml;nce var olduğundan, o şimdi g&ouml;r&uuml;nt&uuml;lerin anlamını aydınlatmaya hizmet eder. Kelime ve g&ouml;r&uuml;nt&uuml;n&uuml;n bu sembolik ilişkisi şiir-filmin varoluş nedenidir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yazar&nbsp;<b>Robert Speranza</b>&nbsp;bir s&ouml;yleşide, olduk&ccedil;a genel tanımlamalar veriyordu film şiir hakkında: "...<i>yeni alanlar ve fikirler uman şairlerin kendileri tarafından idare edilirler, veya alternatif olarak bu şairler yazdıkları şiir ve g&ouml;rsel malzeme arasında bir yerlerdeki bir alanı arıyor olabilirler.</i>". Sonrasında daha karmaşık ilerleyen, edebi olmayan film şiirleri toplama dahil etmek &ccedil;abasıyla şunu savunur: &ldquo;<i>...film şiir geleneksel bir Hollywood senaryosunun ya da geleneksel oyunun sahip olacağı bir yapıda olmaz. O, başka ritmler, yinelemeler gibi şiirin yapabileceğini s&ouml;yleyebildiğiniz, anlatıcı hale tercih edilecek bir hali hatırlatmayla ilgilenebileceğiniz şeyleri yapar.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Biz bu tanımlamada&nbsp;<b>Deren</b>&rsquo;in d&uuml;ş&uuml;ncelerinin yankısını duyabiliyorken, basit&ccedil;e Hollywood-dışı bir yapı olan film şiir nosyonu, sadece deneysel filmciliğin her t&uuml;r&uuml;n&uuml; kapsadığı i&ccedil;in değil, hatta daha sanatsal Avrupa gelenekli filmleri de kapsadığından &ccedil;ok faydalı değildir ve temelde b&uuml;t&uuml;n &ouml;yk&uuml;leyici-olmayan filmlerin birer film şiir olduğunu &ouml;ne s&uuml;rer.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>B&uuml;t&uuml;n bu tanım ve &ccedil;&ouml;z&uuml;mlemelerin toplamı, film şiir nosyonunun son seksen yıl i&ccedil;inde ne kadar kaotik bir yerde durduğunu ve belirli bir tanım &ccedil;er&ccedil;evesinde onun &ouml;zellikleri &uuml;zerine konuşmanın nasıl zor olduğunu g&ouml;stermektedir. Hatta film şiirin tarihsel analizleri onun kısmi &ouml;zelliklerini desteklemekle ilgilenen bireylerce sık&ccedil;a yazılmıştır. Belki de bir &ccedil;ok y&ouml;netmen ve eleştirmence herhangi olası bir perspektif g&ouml;z ardı edilmeksizin, ama hareketli g&ouml;r&uuml;nt&uuml;n&uuml;n araştırılmasına faydalı olabilecek eleştirel ve aydın bir yaklaşımla ortaya konan farklı anlayışların t&uuml;m&uuml;n&uuml;n hesaba katıldığı film ve şiir konseptlerini yeniden d&uuml;ş&uuml;nmenin zamanı gelmiştir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span style="color: #800000;"><b>K</b></span></span><b><span style="font-size: 10pt; color: maroon;">aynaklar:</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">Film As Poetry&nbsp;</span></b><span style="font-size: 10pt;">Ken Kelman ( Film Culture, No. 29, 1963, pp. 22-27.)</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">Poetry-Film &amp; The Film Poem: Some Clarifications&nbsp;</span></b><span style="font-size: 10pt;">Fil Ieropoulos, researcher on \'Film Poetry\' at the University College For The Creative Arts, Maidstone</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">Poetry-Films and Film Poems&nbsp;</span></b><span style="font-size: 10pt;">William C. Wees</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">Cinema and Latin Poetry&nbsp;</span></b><span style="font-size: 10pt;">William Haris, Prof. Em. Middlebury College</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">Abdullah Ş&uuml;kr&uuml;&nbsp;</span></b><span style="font-size: 10pt;">www. mevsimsiz.net&rsquo;teki yazısı.</span></p>', 20, 63, 'Yazarlarımızdan', '/images/yazilar/etoile.jpg', '2017-03-02');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (37, 'ay-j158', 'sinema-ve-psikoloji', 'Sinema ve Psikoloji', 'Doç. Dr. Faruk Gençöz', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span>Sinema ve Psikoloji</span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Do&ccedil;. Dr. Faruk Gen&ccedil;&ouml;z</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"><a href="mailto:fgencoz@metu.edu.tr" style="color: #895f37;">fgencoz@metu.edu.tr</a></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">P</span></b><span style="font-size: 10pt;">sikoloji, insan davranışlarının doğasını anlama gayretinde bir bilim dalıyken sinema, karmaşık insan davranışlarını t&uuml;m detay ve inceliği ile perdeye yansıtabilen bir sanat dalıdır. Aslında bir bilim dalını benzer konuyu ele alan bir sanat dalı ile karşılaştırmak uygun olmayabilir. Her ikisinin de hedeflerinde benzer noktalar olsa da kullandıkları metodlar farklı olduğu i&ccedil;in &ccedil;alışmalar sonucu ortaya &ccedil;ıkarılan &uuml;r&uuml;nler de birbirlerinden şekil olarak olduk&ccedil;a farklıdır. Bir elinizde tablolarında &ccedil;eşitli istatistiklerin ve barların bulunduğu bilimsel makalelerden oluşan bir psikoloji dergisini ve diğer elinizde de 5.1 Dolby ses d&uuml;zeneği ile kaydedilmiş geniş ekran bir film DVD&rsquo;si tuttuğunuzu d&uuml;ş&uuml;n&uuml;n. Bu &uuml;r&uuml;nleri şekil y&ouml;n&uuml;nden incelediğimizde, okuduğumuzda veya seyrettiğimizde her iki alanın birbirlerine bir hayli uzak d&uuml;şebilecekleri fikri doğabilir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İnsan davranışlarının t&uuml;m doğallığı ile sergilendiği g&uuml;nl&uuml;k kişilerarası ilişkilerimizde, psikoloji bilimsel metodlar ile; senarist, y&ouml;netmen veya oyuncu ise kendilerine has subjektif metodlarla incelemelerde bulunurlar. Sonu&ccedil;ta g&ouml;zlenen baz aynı olduğundan psikolojinin bilimsel yayınlarında ve sinemacıların &uuml;rettikleri filmlerin &ouml;z&uuml;nde insan davranışlarının a&ccedil;ıklanmasına dair paralellikler yakalayabilmek aslında olması gereken bir &ouml;zelliktir. İki ayrı alanın, eğer her ikisi de &ldquo;doğru yoldalarsa&rdquo;, aynı fenomeni inceleyip farklı noktalara varmasını bekle<i>me</i>memiz gerekir. Bununla birlikte fenomenin ele alınışındaki &ouml;zelliklerde, kısacası &ldquo;tarzda&rdquo; farklılıklar g&ouml;zleyebilmek de gayet doğaldır. Peki bu durumda sinema psikolojiden, psikoloji de sinemadan faydalanır mı? Bu sorunun cevabını dergimizin 9. sayısında sinemanın psikolojiden fayda bulup bulamayacağı &uuml;zerinde durarak kısmen ele almış, daha &ccedil;ok &ldquo;Sinema, psikolojiden faydalanmalı mıdır?&rdquo; sorusuna cevap vermiştik. Cevabımızda, sinemayla ilgili bir &uuml;retim peşinde olan kişinin doğuştan gelen kabiliyet ve h&uuml;nerlerinin dışında yeni a&ccedil;ılımlar hedeflediği durumlarda insan psikolojisi ile ilgili akademik bilgilerin kişiyi hedefine yaklaştırabileceği &uuml;zerinde durmuştuk. Bu cevap sadece sinema uğraşanları i&ccedil;in değil psikoloji bilimi ile uğraşanlar i&ccedil;in de aynı şekilde ge&ccedil;erlidir. Bilim, objektif olma gayreti ile daha &ccedil;ok evrensel nitelikteki bilgilerin peşindeyken sanat, subjektif y&uuml;z&uuml;yle ortaya &ccedil;ıkardığı &uuml;r&uuml;n&uuml;n kendine haslığını vurgular. Bilimin kendini, evrenselliğin soğukluğundan kurtarmaya &ccedil;alıştığı noktada sanatla ilgili daha insan&icirc; ve sıcak g&ouml;r&uuml;şler bilimin hedeflerini tamamlayabilir. Bu y&uuml;zden psikolojinin de sinema d&uuml;nyasından ilham alabileceği durumlar bulunmaktadır.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yazılan film senaryoları ve ortaya konan oyunculuk becerileri halihazırda insan&nbsp; psikolojisi alanında geliştirilmiş teorilerden faydalanabilme şansına sahiptir. Y&uuml;zeysel ve tekd&uuml;ze akan bir senaryoya renk katabilmenin en basit yolu karakterlerin psikolojisine veya kişilerarası ilişkilere irili ufaklı &ccedil;atışmalar veya detaylar katmaktır. &Ccedil;atışma veya detaylarla verilen derinlik &ccedil;ok &ccedil;eşitli kişilik gelişimi teorileri ışığında yapılabilir. &Ouml;rneğin senaryodaki karakterlere&nbsp;<b>Sigmund Freud</b>&rsquo;un psikanalitik teorisi a&ccedil;ısından &ccedil;eşitli savunma mekanizmaları, Oedipal rekabet veya cinsellikle ilgili problemler eklenebilir.&nbsp;<b>Woody Allen</b>&nbsp; filmlerinde, aşkın ortaya &ccedil;ıkardığı yoğun duygusal boyutu ele alamayıp duyguları entellekt&uuml;el bir havada ve teori yordamı ile &ccedil;&ouml;zmeye &ccedil;alışan ve sonunda herşeyi eline y&uuml;z&uuml;ne bulaştıran karakterlerle sık karşılaşırız.&nbsp;<b><i>Love and Death</i></b>&nbsp;(1975),&nbsp;<b><i>Annie Hall</i></b>(1977),&nbsp;<b><i>Manhattan</i></b>&nbsp;(1979) filmlerinde duyguları oldukları gibi ele alamayan kahramanlar yansıttıkları kişilik &ouml;zelliklerinin temelinde rasyonalizasyon savunma mekanizmasını kullanırlar<b>. Dustin Hoffman</b>&rsquo;ın<b>&nbsp;</b>başarı ile<b>&nbsp;</b>oynadığı&nbsp;<b><i>The Graduate&nbsp;</i></b>(1967) ve&nbsp;<b><i>Straw Dogs</i></b>&nbsp;(1971) filmlerinde oyunculuk başarısını getiren tema, Oedipal rekabet ve libidoya karşı koyma m&uuml;cadelesidir.&nbsp;<b>Hoffman</b>&nbsp;kendisine en iyi oyuncu Oskar &ouml;d&uuml;l&uuml;n&uuml; getiren&nbsp;<b><i>Rain Man</i></b>&nbsp;(1988)&nbsp; filminde de otistik savant rol&uuml;n&uuml; canlandırmış ve bu role adaptasyon i&ccedil;in uzun bir s&uuml;re kendini bu bozukluğun &ouml;zellikleri &uuml;zerinde eğitmiştir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/theGraduate2.jpg" alt="" width="532" height="294" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir başka kişilik gelişimi teorisyeni&nbsp;<b>Carl Gustav Jung</b>&rsquo;a g&ouml;re kollektif bilin&ccedil;dışımız, t&uuml;m insanlık tarafından paylaşılan ve arketip denilen ortak imajlardan oluşur. Bu imajların arkasındaki sembolizm yardımı ile birbirimizle iletişimimiz kolaylaşır. T&uuml;m insanlığın tarih boyunca ortak kullandığı imajlar sinemada sık sık belli karakterler olarak karşımıza &ccedil;ıkarlar.&nbsp;<b>Jung</b>&rsquo;un teorisine dayalı sembolizmde benliğin birincil simgesi &ldquo;kahraman&rdquo;, benliğin dışarıya sunduğumuz maskesi &ldquo;persona&rdquo;, benliğin gizlenen karanlık y&uuml;z&uuml; &ldquo;g&ouml;lge&rdquo; olarak isimlendirilir. Kollektif bilin&ccedil;dışındaki benliğimiz persona, g&ouml;lge gibi doğal par&ccedil;aların yanısıra benliğe yol g&ouml;sterici nitelikte bir bilge imajı, erotik kadın (anima) ve erkek (animus) imajları da i&ccedil;ermektedir. Kahramandan beklenen, hayat denen yolculukta benliğinin yukarıda sayılan ve imajlarla temsil edilen muhtelif par&ccedil;alarını keşfedip kendini gittik&ccedil;e daha &ldquo;b&uuml;t&uuml;n&rdquo; hissetmesidir; aynı&nbsp;<b><i>Star Wars</i></b>&nbsp;serisinde&nbsp; perdeye yansıtıldığı gibi. Luke Skywalker,&nbsp;<b><i>Star Wars</i></b>&nbsp;serisinin kahramanıdır. Skywalker&rsquo;ın g&ouml;lgesi Darth Vader, yol g&ouml;stericisi Obi-Wan<b>&nbsp;</b>Kenob<b>i,&nbsp;</b>ve animası Prenses Leila&rsquo;dır. Skywalker, seri boyunca benlik par&ccedil;alarını temsil eden diğer karakterlerle ilişkilerini ilk &ouml;nceleri zora sokup daha sonra zorlukları &ccedil;&ouml;zd&uuml;k&ccedil;e Jung&rsquo;un teorisi a&ccedil;ısından daha olgun ve &ldquo;b&uuml;t&uuml;n&rdquo; bir insan olur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/star%20wars.JPG" alt="" width="353" height="280" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Varoluş&ccedil;u akımın &ouml;nc&uuml;lerinden&nbsp;<b>Rollo May</b>&rsquo;e g&ouml;re insan, yaşadığı d&uuml;nyada bir yerlerde yaşama amacının veya anlamının bulunması gerektiğine inanır. Bununla birlikte kendi yaşamına baktığında bir anlam veya ama&ccedil; bulamadığında kaygı yaşamaya başlar. İnsanda &ccedil;elişki yaratan bu duruma &ldquo;varoluşsal &ccedil;atışma&rdquo;, hissedilen duyguya da &ldquo;varoluşsal kaygı&rdquo; denmektedir.&nbsp;<b>May</b>&rsquo;in &ccedil;atışma ve kaygıya karşı &ouml;nerdiği yol, kendi bilincimizin harekete ge&ccedil;irilmesidir. İnsan hayat yolculuğunda, kendi bilincini harekete ge&ccedil;irmesi a&ccedil;ısından d&ouml;rt evreden ge&ccedil;ebilir. Masumiyet evresinde kahraman, karşılaşacağı sorun &ouml;ncesinde, bunun d&uuml;nyadaki varlığından bile haberi yoktur veya bu soruna karşı bir ilgisi de yoktur. İsyan evresinde sorun, kahramanımızın kapısını bir şekilde &ccedil;alar ve kahramanın varoluşsal &ccedil;atışma i&ccedil;ine girmesine sebep olur. Sıradan bilin&ccedil; evresinde kahraman sorunun &ccedil;&ouml;z&uuml;lmesi yolunda bu d&uuml;nyaya ait bir hedef belirler ve kendini bu hedefe adar. Son olarak yaratıcı bilin&ccedil; evresinde ise d&uuml;nyaya ait yapılan rutin işlerin &ouml;z&uuml;ndeki ger&ccedil;eği anlar ve kendini aşar. Bu yolculuk bir &ccedil;ok film i&ccedil;in bir şablon olarak kullanılmıştır.&nbsp;<b><i>Star Wars</i></b>&nbsp;filmlerinde Luke Skywalker galaksinin ufak bir gezegeninde imparatorlukla isyancılar arasındaki &ccedil;atışmadan uzak masum bir &ccedil;ocuktur. Bu durum fazla uzun s&uuml;rmez; amcası ve teyzesi imparatorluk askerleri ve isyancılar arası &ccedil;atışma sırasında &ouml;ld&uuml;r&uuml;l&uuml;nce Skywalker isyan eder ve hissettiği intikam duygusu kendisini savaşın i&ccedil;ine &ccedil;eker. İlk başta bencil, intikam motivasyonu ile başlayan macera daha sonra Prenses Leila&rsquo;nın kurtarılması ve &Ouml;l&uuml;m Yıldızı&rsquo;nın yok edilmesi gibi daha sosyal hedeflere doğru y&ouml;nlenir. Dış d&uuml;nyanın &ccedil;atışmalarında &ccedil;eşitli başarılar elde etse de asıl rahatlama kendi Jedi kimliğini keşfetmesi ile i&ccedil; d&uuml;nyasında oluşur ve b&ouml;ylece Skywalker kendini aşar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu &ouml;rneklerde&nbsp;<b>Freud</b>&rsquo;un psikanalitik savunmalarının,&nbsp;<b>Jung</b>&rsquo;un arketiplerinin,&nbsp;<b>May</b>&rsquo;in varoluş&ccedil;u &ccedil;atışmayı &ccedil;&ouml;z&uuml;me ulaştıran yolculuğunun, sinema tarihi i&ccedil;inde &ouml;nemli yerleri olan filmlerin senaryolarına, i&ccedil;erdikleri karakterlerin formasyonuna ve oyunculuk becerilerine a&ccedil;ık&ccedil;a sızmış oldukları g&ouml;z&uuml;kmektedir. Bununla birlikte yukarıda sayılan filmleri &uuml;reten kadroların, senaryoyu veya oyunculuğu bilin&ccedil;li bir şekilde ne derece psikolojik teorilere dayandırdıkları tartışmalıdır. Ortaya &ccedil;ıkan bir sinema &uuml;r&uuml;n&uuml;n&uuml;n i&ccedil;inde psikolojik teorilerin izlerini bulabilmek, teorilerin bilin&ccedil;li bir şekilde kullanıldığını g&ouml;stermez. Yazımızın başında sinema ve psikolojinin bazlarının aynı olduklarını ve aynı bazın incelenmesiyle&nbsp; &uuml;retilen farklı &uuml;r&uuml;nlerin, y&ouml;ntem konusunda doğru bir izdelerse, ortak noktalarının olacağını belirtmiştik. Bu anlamda senarist, oyuncu veya y&ouml;netmenin kendi subjektif incelemeleri ile bilimin objektif incelemelerinin ortak bir noktaya gelebilmesi m&uuml;mk&uuml;nd&uuml;r. &Ccedil;&uuml;nk&uuml; her ikisi de insan hayatına odaklanırlar, g&ouml;rd&uuml;klerini kendilerine has y&ouml;ntemlerle taklit etmeye &ccedil;alışırlar. Ne yazılan bir bilimsel eser ne de DVD &uuml;zerindeki bir film, ger&ccedil;eğin kendisidir. Ger&ccedil;eğin kendisi, d&uuml;nya &uuml;zerinde yaşanan hayattır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;</span><img src="/images/yazilar/guguk2.JPG" alt="" width="338" height="236" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yukarıda bahsettiğimiz&nbsp;<b><i>Rain Man</i></b>&nbsp;(1988) filminde olduğu gibi, y&uuml;zeysel ve tekd&uuml;ze kalabilecek bir senaryoya psikolojik bir anormallik eklemek her zaman seyircinin ilgisini &ccedil;eken bir &ouml;zellik olmuştur. Psikolojik anormalliklerin sinemada konu edilmesi sadece seyircinin ilgisini &ccedil;ekmek i&ccedil;in değil senaryoyu yazanın aklını kurcalayan psikolojik problemin bir &ccedil;eşit &ccedil;&ouml;zme girişimi olarak da karşımıza &ccedil;ıkabilir. Psikolojik bozuklukların bilimsel olarak sınıflandırılması, bozuklukların tanılarının konması ve tedaviye y&ouml;n g&ouml;stermesi a&ccedil;ısından &ouml;nemlidir. Bu alanda &ccedil;eşitli sınıflandırma sistemleri bulunmaktadır ve bu sistemlerin sundukları bilimsel bozukluk tarifleri senaryo yazarları ve oyuncular i&ccedil;in pratik ve g&uuml;venilir bir kaynak teşkil ederler.&nbsp;<b>Jack Nicholson</b>, kazandığı &uuml;&ccedil; En İyi Oyuncu Oskarı&rsquo;nın ikisinde;&nbsp;<b><i>One Flew Over The Cuckoo&rsquo;s Nest</i></b>&nbsp;(1975) filminde antisosyal kişilik bozukluğunu,&nbsp;<b><i>As Good As It Gets</i></b>&nbsp;(1997) filminde de obsesif komp&uuml;lsif bozukluğu canlandırmıştır. T&uuml;m zamanların en iyi filmler listesinde daima &uuml;st sıralarda yer alan&nbsp;<b>Alfred Hitchkock</b>&rsquo;un&nbsp;<b><i>Psycho&nbsp;</i></b>(1960) filminde disosiyatif kimlik bozukluğu ele alınırken<b>, Billy Wilder</b>&rsquo;ın&nbsp;<b><i>Sunset Boulevard</i></b>&nbsp;(1950) filminde narsisistik kişilik bozukluğu &ouml;zellikleri filmin temelini teşkil etmektedir. Yakın tarihin 4 Oskarlı filmi&nbsp;<b><i>Akıl Oyunları&nbsp;</i></b>(A Beautiful Mind, 2001) paranoid şizofrenik bozukluğu yaşayan kişinin kendi g&ouml;z&uuml;nden bozukluğun &ouml;zelliklerini &ccedil;arpıcı bir şekilde bizlere sunmaktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/a_beautiful_mind.jpeg" alt="" width="480" height="628" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span class="postbody1"><span style="font-size: 10pt;">Sinemada karşılaştığımız hik&acirc;ye hi&ccedil;bir zaman ele almayı hedeflediği fenomeni tam bir&nbsp; ger&ccedil;eklik a&ccedil;ısından ele almaz. Hik&acirc;yenin i&ccedil;inde daima sinema estetiğine ve tekniğine uyacak şekilde bir hayal katılır. Sonunda ortaya &ccedil;ıkan &uuml;r&uuml;n ger&ccedil;eklerden&nbsp; &ccedil;eşitli derecelerde uzak bir hayali yansıtır. Seyirci, sinema salonuna, seyredeceği filmin hayali bir &uuml;r&uuml;n olduğu ve ger&ccedil;eği tam yansıtmayacağı bilinciyle girmesine rağmen salondan &ccedil;ıkarken ger&ccedil;eklik ve hayal arasındaki muhakemesinde daima ş&uuml;pheye d&uuml;şer. A&ccedil;ık bir zihinle girdiği salondan ş&uuml;pheli bir zihinle &ccedil;ıkar. Bu ş&uuml;pheyi uyandırabilmek sinemanın başarısının da bir &ouml;l&ccedil;&uuml;s&uuml;d&uuml;r. Bu başarının ardında senaryoda yer alabilecek ve yukarıda bahsedilen psikolojik detaylandırmaların yanısıra ortaya konan oyunculuğun da b&uuml;y&uuml;k bir payı bulunmaktadır. Oyuncunun, senaryonun t&uuml;m&uuml;n&uuml; bilmesine rağmen oynadığı her karede sanki&nbsp; bir kare sonrasını bilmiyormuş&ccedil;asına sadece o andaki karenin rol&uuml;n&uuml; oynaması&nbsp; beklenir. Bu durum, bir film &ccedil;ekimi sırasında değil&nbsp;<span style="color: black;">de ger&ccedil;ek hayatta yaşanacak olsa,</span><span style="color: #ff6600;"></span>normal bir insanda m&uuml;thiş bir i&ccedil; &ccedil;atışma yaratabilir. &Ccedil;atışma yaşayan insanın etrafındaki kişiler, &ccedil;atışmanın bariz izlerini doğal olarak o insanın &ccedil;elişkili davranışlarında g&ouml;zler ve hemen reaksiyon verebilirler: &ldquo;Yalan s&ouml;yl&uuml;yorsun!&rdquo;, &ldquo;İnanmadım!&rdquo;. Usta bir sinema seyircisini, g&uuml;nl&uuml;k hayatında bir s&uuml;rpriz hazırlamak &uuml;zere aldatmaya &ccedil;alışmak son derece zordur. Aldatmaya &ccedil;alışan kişinin s&ouml;yledikleri ile &ccedil;ok az da olsa &ccedil;elişen y&uuml;z hareketleri, ses tonu ve vucut dili uyanık seyirci tarafından kolayca yakalanabilir. Her normal insan karşıdaki insanın &ccedil;elişkisini sezebilecek ortalama bir muhakemeye sahiptir. Ustalaşmış bir sinema seyircisinde bu muhakeme ortalamanın &uuml;st&uuml;ne &ccedil;ıkmıştır ve bu seyirci buna rağmen etkilenme beklentisiyle salona gelmiştir. Hayallerin ger&ccedil;ekmiş gibi g&ouml;sterilmeye &ccedil;alışıldığı ve seyircinin de &uuml;st&uuml;n bir muhakeme g&uuml;c&uuml;ne sahip olduğu salonda seyirciyi etkileme misyonunu &uuml;stlenmiş oyuncunun psikolojisini &uuml;stlenmek zordur. Oyunculuğun zorluğu, seyirciler kendilerinin aldatılacağından tamamen emin olsalar bile, sanki hi&ccedil; b&ouml;yle bir şey yokmuş gibi sadece verilmek istenen duygu veya davranışa odaklanarak saf insan doğallığı ile seyirciye hitap edebilmekte yatar. Oyuncular kendilerini bu aktarımı kolaylaştırabilecek tekniklerle donatmaya &ccedil;alışırlar ve yapılan provaların amacının da oyuncunun karakteristik &ouml;zellikleri ile oynanacak oyunun ihtiya&ccedil;ları arasında bir arabulma s&uuml;reci olduğu d&uuml;ş&uuml;n&uuml;lebilir. Kimi oyuncu kendi karakteristiklerine uymayan oyunu kendine doğru &ccedil;ekmek ister, kimisi de rol&uuml;n gereklerine uymak i&ccedil;in kendini role uydurmaya &ccedil;alışır. Oyuncunun kendini zorlamaya &ccedil;alışması ile başlayan gelişim işleyişi yeni davranış, duygu ve d&uuml;ş&uuml;nce&nbsp; bi&ccedil;imlerinin &ouml;ğrenilmesi ve bunların i&ccedil;selleştirmesiyle devam eder. Bu yolculuğu kolaylaştırmak &uuml;zere geliştirilen eğitim metodları b&uuml;y&uuml;k &ouml;l&ccedil;&uuml;de psikolojideki &ccedil;eşitli &ouml;ğrenme teorilerinden beslenirler. &Ouml;rneğin&nbsp;<b>Ivan</b>&nbsp;</span></span><span style="font-size: 10pt;"><b><span>Pavlov</span>&nbsp;</b><span>&rsquo;un reaksiyonların koşullandırılarak &ouml;ğrenilmesine dayalı geliştirdiği teorisinin izlerini oyunculuk eğitiminde bir mihenk taşı olan<i>Stanislavski Sistemi</i>&rsquo;nde bulabiliriz. Bu sistemin zaman i&ccedil;indeki gelişimi sırasında ilk &ouml;nceleri oyuncunun doğru oynayabilmesi i&ccedil;in doğru duyguyu hissedip seyirciye yansıtabilmesi baz alınırken daha sonraları&nbsp;<b>Pavlov</b>&rsquo;un etkisi ile doğru aktarım i&ccedil;in ilk &ouml;nce doğru davranışların yapılması gereği &ouml;n plana &ccedil;ıkarılmış, doğru davranışı yapan oyuncunun daha sonra doğru duyguyu da kendiliğinden hissedebileceği&nbsp; &uuml;zerinde durulmuştur. Burada &ldquo;doğru davranış&rdquo; seyircinin kendisini sinemada film seyrediyor gibi değil, ger&ccedil;ek hayatı yaşıyormuş gibi hissetmesini getirecek s&ouml;zel olmayan davranışları i&ccedil;erir. Filmlerdeki diyaloglar seyircinin kendisini hangi noktada algılaması gerektiğine dair sadece genel &ccedil;er&ccedil;eveyi &ccedil;izerken, filmin inandırıcılığı, bu &ccedil;er&ccedil;evenin i&ccedil;inde g&uuml;nl&uuml;k hayatta farkında olmadan g&ouml;zlenen ve bilin&ccedil;altında kodlanan s&ouml;zel olmayan kodların iyi taklit edilmesine dayalıdır. G&uuml;nl&uuml;k hayatta bilin&ccedil;li bir muhakeme altında kodlanmayan bu davranışların tam olarak ne oldukları dile bir t&uuml;rl&uuml; gelmez ancak dile gelmeyen bu davranışların eksikliğinde oyunculuğun ne derece ger&ccedil;ekten uzak olduğu &ccedil;ok kolay bir şekilde dile getirilebilir. 9. sayıdaki yazımızda s&ouml;zel olmayan davranış &ouml;rneklerinden birisi olarak ger&ccedil;ek g&uuml;lme ile aldatıcı g&uuml;l&uuml;ş arasındaki y&uuml;z ifadelerinde oluşan farklılıklara değinmiştik. Psikoloji biliminin &uuml;rettiği bir detay olan ger&ccedil;ek g&uuml;lme ve aldatıcı g&uuml;l&uuml;ş arasındaki farkın oyuncuya &ouml;ğretilmesi ve oyuncunun bu referans noktasından, doğru duyguya doğru gidebilmesi, oyunculuğu kolaylaştıran &ldquo;oyuncu ko&ccedil;luğu&rdquo; veya eğitimi &ccedil;er&ccedil;evesinde değerlendirilebilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/sunset_bulvari.JPG" alt="" width="296" height="211" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Birer klasik haline gelen filmlerin ve etkileyici oyuncuların, arkalarından gelenler tarafından şablon halinde bolca taklit edildiğini de d&uuml;ş&uuml;necek olursak psikolojideki temel kişilik teorilerine, psikiyatrideki psikolojik bozukluk tanımlamaları ile paralel giden filmlerin olduk&ccedil;a fazla sayıda olduklarını belirtmeliyiz. Hatta &ouml;yle ki, ger&ccedil;ek insan hayatının sinemayı etkilediği kadar belirli bir sistem dahilinde &uuml;retilen &ccedil;ok sayıda sinema filminin de ger&ccedil;ek insan hayatını değiştirebilecek alışkanlıklar kazandırabileceğini&nbsp; s&ouml;ylemek abartılı olmaz. &Ouml;rneğin psikologlar arasında, gerek psikolojik bozuklukların eğitiminde ve araştırmalarında gerekse bu bozuklukların tedavisinde sinema bir kaynak olarak kullanılmaktadır. Bu konunun detaylarına bundan sonraki yazılarda girmeyi &uuml;mit ediyoruz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/star%20wars2.JPG" alt="" width="297" height="250" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yazımızın başında eğer sinema ve psikoloji &ldquo;doğru yoldalarsa&rdquo; aynı fenomeni farklı tarzlarla inceleleseler de farklı noktalara varmayabileceklerini belirtmiştik. Bununla birlikte iki alanın birbirlerinden bir hayli uzak d&uuml;şt&uuml;ğ&uuml; konular da bulunmakta ve bunlar genelde bilimi, &ouml;zelde psikolojiyi ve psikolojik bozuklukları ilgilendiren konular olmaktadır. Ele alınan baz aynıyken farklı noktalara varmanın k&ouml;keninde, incelemenin doğasında olmayan &ccedil;eşitli yan &ccedil;ıkarlar ortaya &ccedil;ıktığını ve hem bilim hem de sanat d&uuml;nyasının bu &ccedil;ıkarlar doğrultusunda&nbsp; bazen bilin&ccedil;li bazen de tamamen bilin&ccedil;siz bir tavır sergilediğini s&ouml;ylemek gerekir. Bu &ccedil;er&ccedil;evede ele alınabilecek &ouml;nemli konulardan biri&nbsp;<i>stigmadır</i>. Stigma kelimesinin toplumsal konular arasında m&acirc;n&acirc;sı &ldquo;damgalamak&rdquo;tır. Damgalamanın T&uuml;rk Dil Kurumu S&ouml;zl&uuml;ğ&uuml;&rsquo;nde verilen mecazlı anlamı ise &ldquo;Bir kimseye, ger&ccedil;eğe dayanmadan herhangi bir &ouml;zellik veya nitelik y&uuml;klemek&rdquo;tir. Sinemanın bir &ccedil;ok konuda stigma yaratmakta &ccedil;ok b&uuml;y&uuml;k bir potansiyeli olduğunu ve bilimin de bu gibi hurafelere karşı duruşu ile kimlik kazandığını ve bazen de bu kimlik oluşturma s&uuml;recinde bilim d&uuml;nyasının olduk&ccedil;a saplantılı ve tutucu hale gelebilediğini bilmekteyiz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Gelecek yazılarımızda sinema ve psikoloji bağı &ccedil;er&ccedil;evesinde a&ccedil;tığımız konuları daha detaylı bi&ccedil;imlerde ele alabilmek &uuml;midiyle şimdilik hoş&ccedil;akalın.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span style="color: #c43300;"><span><b>K</b></span></span><b><span><span style="color: #c43300;">aynaklar:</span></span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Blumenfeld, R. (2006).&nbsp;<b>Tools and techniques for character interpretation</b>. Limelight Editions.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Indick, W. (2007).&nbsp;<b>Senaryo yazarları i&ccedil;in psikoloji.</b>&nbsp;(&Ccedil;eviri). +1 Kitap</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Gen&ccedil;&ouml;z, F. (edit&ouml;r) (2007). Psinema<b>: Sinemada psikolojik bozukluklar ve sinematerapi</b>. HYB</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">Wedding, D., Boyd, M.A., &amp; Niemiec, R.M. (2005).&nbsp;<b>Movies and mental illness: Using films to understand psychopathology</b>. Hogrefe</span></p>', 190, 63, 'Yazarlarımızdan', '/images/yazilar/theGraduate2.jpg', '2017-03-02');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (38, 'ay-j159', 'recep-i-vedik-e-gulmek', 'Recep İvedik\'e Gülmek', 'Cem Kayalıgil', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Recep İvedik\'e G&uuml;lmek</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Cem Kayalıgil</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Recep İvedik 2</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>Y&ouml;netmen:</b>&nbsp;Şahan G&ouml;kbakar</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>Senaryo:</b>&nbsp;Şahan G&ouml;kbakar, Serkan Altuniğne, Togan G&ouml;kbakar</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>Oyuncular:</b>&nbsp;Şahan G&ouml;kbakar,&nbsp;</span><span>G&uuml;lsen &Ouml;zbakan, Efe Babacan,</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;">&Ccedil;ağrı B&uuml;y&uuml;ksayar</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni:</b>&nbsp;Ertun&ccedil;&nbsp;</span><span>Şenkay</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>M&uuml;zik:</b>&nbsp;Oğuz Kaplangı</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;">2009/105&rsquo;/T&uuml;rkiye</span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">Ş</span><span style="font-size: 10pt;">ahan G&ouml;kbakar</span></b><span style="font-size: 10pt;"><span>&rsquo;ın bol ratingli televizyon programı &ldquo;Dikkat Şahan &Ccedil;ıkabilir&rdquo;den &ccedil;ıkma &ldquo;şehirli maganda&rdquo;&nbsp;<b><i>Recep İvedik</i></b>, ge&ccedil;tiğimiz sene beyazperdede boy g&ouml;stermesinden bu yana, hi&ccedil; ş&uuml;phe yok, &uuml;lkedeki en pop&uuml;ler kurmaca karakter. 4,3 milyon seyirciyle buluşmasıyla birlikte marka değeri y&uuml;ksek mi y&uuml;ksek Turkcell&rsquo;in televizyonlarda en &ccedil;ok d&ouml;nen reklamlarında da sıklıkla karşımıza &ccedil;ıkmaya başlamış, sesi cep telefonlarına d&uuml;şm&uuml;ş, bir&ccedil;ok gazete yazısında konu edilmiş, &ccedil;ok izlenilirliği gazetelerin haftasonu eklerinde incelenip duran bir vakadan s&ouml;z ediyoruz. İkinci filmi ciddi sayıda bir kopyayla yeni g&ouml;sterime girmiş, ilk &uuml;&ccedil; g&uuml;ndeki gişe başarısı rekor kırmış, yapımcısının &ldquo;en az 5 milyon kişi&rdquo; tarafından seyredileceğini tahmin ettiği<i>&nbsp;</i>bu tek-adam g&ouml;sterisi, haliyle g&uuml;ncel sinema g&uuml;ndeminin de baş sıradaki konusu oluyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">&nbsp;<img src="/images/yazilar/recep.jpg" alt="" width="489" height="318" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Recep İvedik</span>&nbsp;</i></b><span>, seyirciyi g&uuml;lmekten kırıp ge&ccedil;iren bir tip. Sunduğu g&uuml;ld&uuml;r&uuml;n&uuml;n basitliği ve yalınlığı, bunu talep ve kabul eden seyirci kitlesinin sayısal b&uuml;y&uuml;kl&uuml;ğ&uuml;n&uuml; garantileyen cinsten. &ldquo;(Yazılı değil) s&ouml;zl&uuml; k&uuml;lt&uuml;re dayanıyor oluşumuz&rdquo; klişesini bir kez daha doğrulayan bir g&uuml;ld&uuml;r&uuml; bu: En a&ccedil;ık &ouml;rneklerini<i>Nasrettin Hoca&rsquo;</i>da, Bektaş&icirc; fıkralarında, Karag&ouml;z-Hacivat&rsquo;ta,&nbsp;<i>Turist &Ouml;mer</i>&rsquo;de ve&nbsp;<b><i>G.O.R.A&nbsp;</i></b>ile&nbsp;<b><i>A.R.O.G</i></b>&rsquo;un&nbsp;<i>Arif</i>&rsquo;inde bulabileceğimiz; anlık mizansenlere g&ouml;sterilen s&ouml;zl&uuml; reflekste kendisini ortaya koyan, toplumca onayladığımız bir hazırcevaplık;&nbsp;<b><i>Recep İvedik</i></b>&rsquo;i de komik kılan en temel &ouml;zellik.&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in s&ouml;zl&uuml; geleneğe hangi bi&ccedil;imde eklemlendiğini g&ouml;rmek i&ccedil;in, &ouml;nce, bu hazırcevaplık timsallerinin g&ouml;r&uuml;n&uuml;m&uuml; oldukları değerleri saptamak yerinde olacak:&nbsp;<i>Nasrettin Hoca</i>&nbsp;ve Bektaş&icirc; fıkralarını bitiren son s&ouml;zler (&ldquo;punchline&rdquo;), aklın (bir t&uuml;r g&ouml;rm&uuml;ş ge&ccedil;irmişliğin) bir &ccedil;ırpıda dile gelebilişindeki şaşırtıcılığa yaslanan bir g&uuml;zelliğe sahiptir; fıkra dinleyicisinde, kabul g&ouml;rm&uuml;ş bir &ouml;zl&uuml; s&ouml;z&uuml;n &ccedil;arpıcı d&uuml;ş&uuml;nd&uuml;r&uuml;c&uuml;l&uuml;ğ&uuml;ne yakın bir etki bırakır. Karag&ouml;z oyunlarında ise&nbsp;<i>Karag&ouml;z</i>&rsquo;&uuml;n<i>&nbsp;Hacivat</i>&rsquo;la girdiği diyalog, eğitimli akıl (bug&uuml;nden bakıldığında&nbsp;<i>rasyonel akıl</i>) ile eğitimsiz aklın &ccedil;arpışmasına sahne olur; belki diyalektik s&uuml;re&ccedil;le de bağdaştırılabilecek bu &ccedil;arpışma, &ldquo;aklın yolu&rdquo;nun t&uuml;rl&uuml; t&uuml;rl&uuml; oluşundaki zenginliği ortaya koyar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ouml;zellikle bu kaynaklarda parlayan s&ouml;zl&uuml; k&uuml;lt&uuml;r&uuml;n, g&uuml;ld&uuml;r&uuml; sinemamıza bir kahramanda v&uuml;cut bularak &ccedil;ıkartma yapışının en klasik &ouml;rneği olan&nbsp;<i>Turist &Ouml;mer</i>tiplemesinde&nbsp;<b>Sadri Alışık</b>; argosuna karşın ruhununun temizliği apa&ccedil;ık olan halk &ccedil;ocuğunun, kendisine yabancı ortamlarda ayakta kalışının komedisini sunar.&nbsp;<i>Turist &Ouml;mer</i>&nbsp;sıradan olmasına sıradan bir T&uuml;rk&rsquo;t&uuml;r; ama bu alt sınıftan sıradan vatandaşın hınzırlığındaki abartı, onu hem komik hem izlenilir hem de klasik kılar.&nbsp;<i>Turist &Ouml;mer</i>&rsquo;in 2000&rsquo;lerdeki ikizi olarak yorumlanabilecek&nbsp;<i>Arif</i>&rsquo;e<i>&nbsp;</i>(<b>Cem Yılmaz</b>) geldiğimizde hınzırlık artık k&ouml;şe d&ouml;nmeci kurnazlıkla eşanlamlı olmuştur.&nbsp;<i>&Ouml;mer</i>&rsquo;in yaşamda kalmasına yeten zeka, &ccedil;ok daha hırslı bir tip olan&nbsp;<i>Arif</i>&rsquo;te, i&ccedil;ine d&uuml;şt&uuml;ğ&uuml; ortamda bulabildiğinden fazlasını koparmaya y&ouml;nelik oyunların kurulması i&ccedil;in kullanılmaktadır.&nbsp;</span>&nbsp;&nbsp;&nbsp;&nbsp;<i>&nbsp;&nbsp;</i>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>En az&nbsp;<i>Turist &Ouml;mer&nbsp;</i>ve&nbsp;<i>Arif&nbsp;</i>kadar klasikleşmeye aday&nbsp;<i><b>Recep İvedik</b>&nbsp;</i>ise diğer ikisinin yanında hemen hi&ccedil; albenisi olmayan bir kurmaca lafazan. Tiksinti verecek raddede kıllı v&uuml;cuduyla, kaşları ve sakalıyla, pek de şirin olmayan iriliğiyle; kahkahası, patavatsızlığı, f&uuml;tursuzluğu, kabalığı, ilkelliği ve k&uuml;f&uuml;rbazlığıyla sinemamızın (ve reklam d&uuml;nyasının) g&ouml;r&uuml;p g&ouml;receği herhalde en itici tip (umarım daha beterini g&ouml;rmeyiz!). Gelgelelim t&uuml;m bu olumsuzluğuna karşın bir arzı var, ve o da hi&ccedil; mi hi&ccedil; elitizm eleştirisi veya iğren&ccedil;liğinin cazibesi falan değil.&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in bir &ccedil;ekiciliği veya g&uuml;ld&uuml;ren bir yanı varsa, bundaki b&uuml;t&uuml;n sır, şu ya da bu kişiye veya durum &uuml;zerine yapıştırdığı laflar (arada sırada da o şaklatmalı el hareketini &ccedil;ekişi). Neye ne tepki vereceği kesinlikle &ouml;ng&ouml;r&uuml;lemez birisi&nbsp;<i>Recep</i>: Yere d&uuml;şm&uuml;ş c&uuml;zdanı sahibine ulaştırmak i&ccedil;in İstanbul&rsquo;dan Antalya&rsquo;ya yol tepen, karşılığı olarak sunulan tatil teklifini samimiyetle reddeden (sonra &ccedil;ocukluk aşkına yakınlaşmak i&ccedil;in teklifi kabul eden), kendisi i&ccedil;in &ouml;nemli olan bir kese misketi yanından ayırmayacak kadar ahlaklı ve duygulu bir adam; aynı zamanda, vaktiyle &uuml;st komşusunu, yukarıdan bakkala sallandırdığı alışveriş sepetinin ipini &ccedil;ekerek aşağıya d&uuml;ş&uuml;rm&uuml;ş olduğu da ima edilen birisi; yol soran birine yanlış tarif vererek kendisini gideceği yere taşıtacak kadar edepsiz, suşi restoranında kulağını temizlemek i&ccedil;in kullandığı yemek &ccedil;ubuklarını masada az sonra karşısına ge&ccedil;ecek misafirininkilerle değiştirecek kadar f&uuml;tursuz. A&ccedil;ık b&uuml;fe nedir bilmeyen (&ouml;ğrenince de bunu s&ouml;m&uuml;recek kadar g&ouml;rg&uuml;s&uuml;z olan); suşiye, wasabiye, zincir caf&eacute;lerdeki kahve t&uuml;rlerine, aerobik ve yogaya, internette sevgili/partner bulma sitelerine hepten yabancı birisi&nbsp;<i><b>Recep İvedik</b>;</i>&nbsp;diğer taraftan t&uuml;pl&uuml; dalış takımı cihazlarından haberdar, pistte hi&ccedil; de fena dans etmiyor, saatlerce denizde kalabilecek kadar dayanıklı, şarap değerlendirme lisanını ve fotoşopla ilgili kimi detayları biliyor gibi g&ouml;r&uuml;n&uuml;yor, vs. İyi ama kimdir bu adam? Bir tipleme i&ccedil;in gereken asgari tutarlılığa bile sahip olmayan&nbsp;<i><b>Recep İvedik</b>&nbsp;</i>nedir, ger&ccedil;ek hayatta neye karşılık gelir ya da neyin abartısı olarak beyazperdeye yansımaktadır? A&ccedil;ık olan şu ki iki filmin senaryosunda da bu hi&ccedil; umursanmamış ve bundan bilin&ccedil;li olarak ka&ccedil;ınılmış:&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in kimliği &ouml;zellikle tutarsız ve belirsiz bırakılmış ki her sahnede (ske&ccedil;te) yapabilecekleri ve s&ouml;yleyebilecekleri sınırsız olsun.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">&nbsp;<img src="/images/yazilar/recep%20ivedik6.jpg" alt="" width="473" height="294" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ouml;yk&uuml;lerde doğal bir &ouml;rg&uuml; ve akışın kurulmasına da engel olan bu tavrı,&nbsp;<b><i>Recep İvedik</i></b>&nbsp;filmlerinin arkasındaki gişeci zihniyetin en bariz dışavurumu olarak g&ouml;r&uuml;yorum. Bu &ccedil;iğ zihniyet, b&uuml;t&uuml;n&uuml;yle abs&uuml;rt bir toplama olan&nbsp;<i><b>Recep İvedik&nbsp;</b></i>tipine filmlerde sağlanan &ouml;zg&uuml;rl&uuml;k alanının o denli sınırsız olmasına yol a&ccedil;mış ki bir&ccedil;ok mizansende figurasyona bile hi&ccedil; gerek g&ouml;r&uuml;lmemiş: &Ouml;rneğin ilk filmde aerobik sahnesinde&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in acayip kıyafetinin ve gaz &ccedil;ıkartmasının sadece Sibel tarafından g&ouml;r&uuml;lmesinde, teknede olanlara (<i>Recep</i>&rsquo;in dalış hocasına laf sokması, hareket &ccedil;ekmesi, Sibel&rsquo;in annesinin fenalaşması) hi&ccedil;kimsenin m&uuml;dahale etmemesinde,&nbsp;<i>Recep</i>&rsquo;in a&ccedil;ık b&uuml;feyi b&uuml;t&uuml;n&uuml;yle kendi &ouml;n&uuml;ne almasına sadece otel m&uuml;d&uuml;r&uuml;n&uuml;n ses &ccedil;ıkartmasında olduğu gibi; veya ikinci filmde market kasasında adamımızın m&uuml;şterinin mahremiyetini suistimal eden konuşmasına kimsenin karşılık vermemesinde, eczane sahnesinde eczane sahibinin&nbsp;<i>Recep</i>&rsquo;e t&acirc; sahnenin en sonunda &ccedil;ıkışmasında olduğu gibi... İki filmde de&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in dizginsizliğine yapılan vurgu o kadar esaslı ki &ccedil;ekim ve sahneleri bir tek o dolduruyor (bunda onun kocamanlığının da payı var), bir de &ndash;varsa- o sırada diyalogda olduğu diğer bir-iki kişi. &Ccedil;evreye verdiği rahatsızlığın niteliği ve niceliği sadece birka&ccedil; kişi ile seyircinin umurunda; sahnedeki diğer kişilerse sadece bedensel fon olarak bırakılıyorlar, tepkisizce oldukları yerde dikiliyorlar. Ya da &ccedil;ok &ccedil;ok, ikinci filmdeki kokteyl sahnesinde&nbsp;<b><i>Recep İvedik</i></b>&rsquo;in DJ masasını ele ge&ccedil;irmesinden sonra olanlar gibi, hoşlarına giden bir şeyle karşılaştıklarında buna doğrudan adapte oluyorlar, onun &ccedil;aldığı m&uuml;zikle derhal g&ouml;bek atmaya başlıyorlar, ama bir kez d&ouml;n&uuml;p de DJ&rsquo;e ne olduğuna bakmıyorlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İki filmde de adeta bir dokunulmazlığı ve g&ouml;r&uuml;nmezliği var kahramanımızın. Bunlar&nbsp; ve karakterindeki tutarsızlıklar -mesela ikinci filmde oyun konsolunda futbol oynayan, evine HD televizyon isteyen, &ouml;l&uuml;m d&ouml;şeğindeyken bile torununa okkalı bir k&uuml;fr&uuml; yapıştıran fırlama ninede olduğu gibi- bilin&ccedil;li bir abs&uuml;rt g&uuml;ld&uuml;r&uuml; anlayışıyla sunulsaydı,&nbsp;<i><b>Recep İvedik</b>&nbsp;</i>fikrinden, &ouml;zg&uuml;nl&uuml;k taşıyan yenilik&ccedil;i durum komedileri &ccedil;ıkartılabilirdi. Veya&nbsp;<b>Şahan G&ouml;kbakar</b>&rsquo;ın c&uuml;ssesine karşın rahatlıkla kotarabildiği beden komedisinden (ilk filmdeki dans sahnesini veya&nbsp;<i>Recep</i>&rsquo;in havuz kenarında arıyla cebelleşmesini hatırlayın) daha fazla yararlanılsaydı,&nbsp;<i><b>Recep İvedik</b>&nbsp;</i>&ccedil;ok daha nitelikli bir tipe d&ouml;n&uuml;şebilirdi.&nbsp;<b>&nbsp;</b>Ancak senaryo ve yapım ekipleri en kolayına gitmeyi se&ccedil;miş ve bu karman &ccedil;orman tipi basit bir yeni argo &uuml;reteci ve g&ouml;rg&uuml;s&uuml;zl&uuml;k timsali olarak kullanmakla yetinmiş. Karşılığında istedikleri şeyi fazlasıyla aldıkları ise g&uuml;n gibi ortada. Ankara&rsquo;da &ouml;ğleden itibaren her 20 dakikada bir, bir sinema salonunda&nbsp;<b><i>Recep İvedik 2</i></b>&rsquo;nin g&ouml;sterimi başlıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/recep%20ivedik67.jpg" alt="" width="364" height="540" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><i><span><b>Recep İvedik</b></span>&nbsp;</i><span>filmleri seyirciyi, kahramanın i&ccedil;ine d&uuml;şt&uuml;ğ&uuml;-girdiği ortamla olan uyumsuzluğuyla g&uuml;ld&uuml;r&uuml;yor. Bu g&uuml;ld&uuml;r&uuml; t&uuml;r&uuml;n&uuml;n &uuml;zerine kurulmuş &ouml;yk&uuml;lerin iki tipik finali vardır: Ortamla olan uyumsuzluğu envai &ccedil;eşit sorun &ccedil;ıkarttıktan sonra, kahraman ile &ccedil;evresi uzlaşır (kahraman genellikle &ldquo;kahraman&rdquo;laşır); uzlaşmanın ardındansa&nbsp; kahraman, ya &ouml;d&uuml;llendirilip daha mutlu bir geleceğe adım atar (&ouml;r. 80&rsquo;lerde &ccedil;ekilmiş bir&ccedil;ok&nbsp;<b>Kemal Sunal/<i>Şaban</i></b>&nbsp;filmi;&nbsp;<b><i>G.O.R.A</i></b>; daha eski zamanlardan&nbsp;<b>Chaplin</b>&rsquo;in kısa metrajlı kimi&nbsp;<i><b>Şarlo</b>&nbsp;</i>filmleri ve&nbsp;<b><i>Altına H&uuml;cum</i></b>&rsquo;u) ya da yine &ouml;d&uuml;llendirilir, ama alışık olduğu ortama, eski yaşamına geri d&ouml;nmek durumunda kalır (&ccedil;&uuml;nk&uuml; o &ldquo;oraya&rdquo; aittir &ndash; &ouml;r.&nbsp;<b><i>Turist &Ouml;mer Uzayda</i></b>;&nbsp;<b><i>Salak ile Avanak</i></b>; yine&nbsp;<b>Chaplin</b>&rsquo;in diğer kısa metrajlı&nbsp;<i><b>Şarlo</b>&nbsp;</i>filmleri ve&nbsp;<b><i>Sirk</i></b>&rsquo;i). Bu &ccedil;er&ccedil;evede ele alındığında&nbsp;<b><i>Recep İvedik</i></b>&nbsp;ikilemesi atipik g&ouml;r&uuml;n&uuml;yor: Kahramanımız<i>&nbsp;</i>ilk filmde Antalya&rsquo;dan bir dost &ccedil;evresi (kamyoncular derneği ve otel komisi) kazanarak ayrılıyor; ama filmin romantik anlatısı yarım yamalak kurulup (Sibel nasıl oldu da<i>Recep</i>&rsquo;ten hoşlanır hale geldi?) aceleyle sonlandırıldığından havada kalıyor. İkinci filmde ise&nbsp;<i>Recep&nbsp;</i>kaba kuvvetle bir saygınlık kazanıveriyor (bu nasıl olup da kuzeninin i&ccedil;ine sinebiliyor?), &ouml;nemli insanlarca alkışlanıyor; ama film orada bitmiyor, yapıştırma duran bir b&ouml;l&uuml;mle sona eriyor. İki filmde de&nbsp;<i>Recep&nbsp;</i>aslında hedeflerine tam anlamıyla ulaşamıyor (Sibel&rsquo;le bir araya gelemiyor; ninesinin &uuml;&ccedil; isteğinden birini karşılayamıyor) ve yaşamını kendi bildiği şekilde s&uuml;rd&uuml;r&uuml;yor - yalnız &ldquo;kendi&rdquo; bildiği şekilde: İki film izlememize karşın biz o yaşamı h&acirc;l&acirc; bilmiyoruz. Ait olduğu g&uuml;ld&uuml;r&uuml; t&uuml;r&uuml; bağlamındaki bu atipiklik; filmler kahramanla ve yabancı kaldığı ortamlarla bir tanışıklık kurabilmemizi sağlayabilselerdi,&nbsp;<i><b>Recep İvedik&nbsp;</b></i>ikilemesini t&uuml;rdeşlerinin yanında ayrıcalıklı kılabilirdi. Ancak şu haliyle bu atipiklik, sadece &ouml;yk&uuml;lerin başıboş akmalarından doğan bir şey; g&uuml;ld&uuml;r&uuml; anlayışımıza veya sinemaya yenilik katan hi&ccedil;bir &ouml;zel ve etkileyici yanı yok.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Recep İvedik</span></i></b><span>&rsquo;te g&uuml;l&uuml;n&ccedil; bulduğumuz şey,&nbsp;<b><i>Recep İvedik 1&nbsp;</i></b>ve&nbsp;<b><i>2</i></b>&rsquo;den geriye kalan yegane şey:&nbsp;<i>Recep</i>&rsquo;in<i>&nbsp;</i>en &ccedil;ok laflarında ortaya konan anlık tepkiselliği, yani bir &ccedil;uval &ldquo;asabi ve kompleksli&rdquo; replik. &Ccedil;ağlardır s&ouml;zl&uuml; k&uuml;lt&uuml;r&uuml; yeniden &uuml;retip duruyoruz ve g&uuml;ld&uuml;r&uuml;n&uuml;n en &ccedil;ok s&ouml;ze dayananını benimsiyoruz. Yok hayır, sorun bunda değil, buysak buyuz. Sorun, bizi g&uuml;ld&uuml;ren s&ouml;zlerin artık beyinden değil omurilikten &ccedil;ıkması.&nbsp;<i>Turist &Ouml;mer&nbsp;</i>ve&nbsp;<i>Arif</i>&rsquo;in de bizi g&uuml;ld&uuml;ren yanları, anlık s&ouml;zl&uuml; patlamalarıydı; ama bu patlamalarla en azından, bizim feleğimizi şaşırtacak durumlarda ayakta kalabiliyorlar, arzuladığımız hazırcevaplıkla hayallerimizi ger&ccedil;ekleştiriyorlardı. Lafazanlıkları sayesinde bağ kurabildiğimiz bir ideal kimliğe kavuşuyorlardı. G&uuml;n&uuml;m&uuml;z&uuml;n hazırcevabı&nbsp;<i><b>Recep İvedik</b>&nbsp;</i>ise hi&ccedil;bir şeyimizin karşılığı olmadan, sırf refleksleri &ccedil;alıştırarak, milyonlarca peynir gemisi y&uuml;r&uuml;tebiliyor.</span></span></p>', 64, 63, 'Yazarlarımızdan', '/images/yazilar/recep.jpg', '2017-03-02');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (39, 'ay-j160', 'radar-televizyon-sesli-sinema', 'Radar Televizyon Sesli Sinema', 'Ender Bazen', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Radar Televizyon Sesli Sinema</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Ender Bazen</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px; text-align: center;"><img src="/images/yazilar/radar-tv-sesli%20sinema%20kapak.jpg" alt="" width="283" height="382" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px; text-align: justify;"><b><span style="font-size: x-large;">İ</span></b><span style="font-size: 10pt;"><span>nkılap Kitabevi tarafından 1946 yılında ve 95 sayfa olarak &ccedil;ıkarılan kitabın asıl&nbsp;</span></span><span style="font-size: 10pt;">adı, i&ccedil;indeki konu sıralamasına bakılacak olursa Televizyon Sesli Sinema Radar olmalı. Yazarı Talat Tolunay. Kitabın bizi ilgilendiren, sesli sinemaya ayrılmış b&ouml;l&uuml;m&uuml;n&uuml;n yazılmasında 1937 ve sonrasında yazılmış yayınlar kaynak olarak kullanılmış.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinemanın tarih&ccedil;esini anlatırken d&ouml;nemin onayladığı resmi tarihten yararlanması kronolojik yanlışlara neden olmuş. Ses &ccedil;alışmalarının sessiz film g&ouml;sterimlerinden sonra başladığını s&ouml;ylemesi gibi. Oysa, ses eksikliğinin giderilme &ccedil;abaları &ccedil;ok daha &ouml;ncesine dayanır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>G&ouml;r&uuml;nt&uuml;n&uuml;n filme alınması s&uuml;recine değinildikten sonra asıl konumuz olan sesin filme alınmasına ge&ccedil;iliyor ve izlenen farklı kayıt teknikleri ve okuma y&ouml;ntemleri &uuml;zerinde ayrıntısıyla duruluyor. &Ccedil;eşitli kayıt ortamlarından film &uuml;zerine eş zamanlı kayıt dışında da işlem yapılabileceği anlatılır; dublaj ve ses efektlerinin eklenmesi &uuml;zerinde durulur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><img src="/images/yazilar/radar-tv-sesli%20sinema1.jpg" alt="" width="373" height="336" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;"><span>Renkli sinematografi ara başlığında verilen renk ve renk karışımı bilgilerinde, yıllardır tekrarlanan bilgi hatalarının ilk &ouml;rneklerinden birine rastlıyoruz. Kimyasal ve optik renk karışımları hem kendi i&ccedil;lerinde hem de birbirleriyle sık sık karıştırılır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Renkli filmin ge&ccedil;irdiği aşamalar ise &ccedil;ok daha doyurucu bilgiler &uuml;zerine kurulu ve g&uuml;n&uuml;m&uuml;z i&ccedil;in değerli bir arkeolojik alan olduğunu g&ouml;sterir cinsten: &ldquo;<i>Eğer stereoskopik &ccedil;iftin hayallerinden biri kırmızı, diğeri genel olmak &uuml;zere biri diğerinden hafif bir dekalajla basılır ve bu hayallere, kırmızı sol g&ouml;z&uuml;n yeşil sağ g&ouml;z&uuml;n &ouml;n&uuml;nden olmak &uuml;zere bir g&ouml;zl&uuml;kle bakılırsa, her g&ouml;z ancak mukabil renk i&ccedil;inde basılmış hayali g&ouml;r&uuml;r. Ve iki g&ouml;zle g&ouml;r&uuml;len g&ouml;r&uuml;ş i&ccedil;inde bir satıh &uuml;zerindeki iki hayalin &uuml;st &uuml;ste gelmesi kabartma ihsasını verir.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp; &nbsp;</span><img src="/images/yazilar/radar-tv-sesli%20sinema2.jpg" alt="" width="392" height="193" border="0" /><span>&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmin nasıl seslendirildiği ve sesli g&ouml;sterimin nasıl yapıldığı konularını merkezine alan, en &ouml;nemlisi aktardığı bilgileri &ccedil;izimlerle destekleyen ve 60 yılı aşan bir zaman &ouml;ncesinden gelen bir &ccedil;alışma.</span></span></p>', 19, 63, 'Yazarlarımızdan', '/images/yazilar/radar-tv-sesli%20sinema%20kapak.jpg', '2017-03-02');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (40, 'ay-j161', 'yilmaz-guney-filmlerinde-bati-sinemasinin-etkileri-ii', 'Yılmaz Güney Filmlerinde Batı Sinemasının Etkileri II', 'İlker Mutlu', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 14pt;">Yılmaz G&uuml;ney Filmlerinde Batı Sinemasının Etkileri II</span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>İlker Mutlu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-large;"><b>D</b></span><span style="font-size: 10pt;">izide ele alacağım ikinci film, &ldquo;&Ccedil;irkin Kral&rdquo; mitosuna &ccedil;ok şey katan ve&nbsp;<b>Yılmaz&nbsp;</b><b>G&uuml;ney</b>&rsquo;in daha sonra &ccedil;eşitli filmlerde tekrar kullanacağı, az konuşan, kirli sakallı, ağzında her daim bir şişe, kavgacı, attığını vuran Konyak&ccedil;ı fig&uuml;r&uuml;n&uuml;n ilk defa yer aldığı&nbsp;<b><i>On Korkusuz Adam</i></b>&nbsp;olacak.&nbsp;<b><i>On Korkusuz Adam</i></b>, esinini&nbsp;<b>Akira&nbsp;</b><b>Kurosawa</b>&rsquo;nın başka &uuml;lkelerde de uyarlamaları yapılmış ve en meşhurları da&nbsp;<b><i>The Magnifıcient Seven&nbsp;</i></b>(Yedi Silahş&ouml;rler, 1960, John Sturges) olan&nbsp;<b><i>Shinchinin No Samurai&nbsp;</i></b>(Seven Samurai / Yedi Samuray, 1954) alan, zamanında hasılat rekorları kıran ve ikinci derecede bir rolde olduğu halde,&nbsp;<b>G&uuml;ney</b>&rsquo;i filmin diğer yıldızlarının &ouml;n&uuml;ne ge&ccedil;iren bir yapımdı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>ON KORKUSUZ ADAM (1964) / THE MAGNIFICIENT SEVEN (1960)</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>ON KORKUSUZ ADAM</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y&ouml;netmen</span></span><span>:&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">Tun&ccedil; Başaran</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Senaryo:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Recep Ekicigil</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Oyuncular:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Tamer Yiğit - Yılmaz G&uuml;ney &ndash; Oktar Durukan &ndash; Işın Kaan &ndash; Adnan Şenses</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Yapım:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Artist Film</span></span></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>On Korkusuz Adam</span>&nbsp;</i></b><span>&nbsp;(<b><i>OKA</i></b>), Kıbrıs&rsquo;ta Rum &ccedil;etecilerin işgali altındaki bir k&ouml;y&uuml;n yardımına gitmek &uuml;zere Antalya&rsquo;da toplanıp yola &ccedil;ıkan on adamın macerasını anlatır. Film, kost&uuml;m, tiplemeler ve davranışlar a&ccedil;ısından tipik bir westernin t&uuml;m &ouml;ğelerini taşır. &Ouml;yk&uuml;s&uuml;, kendi de bir&nbsp;<b><i>Yedi Samuray</i></b>&nbsp;uyarlaması olan&nbsp;<b><i>Yedi Silahş&ouml;rler</i></b>&nbsp;filminden alınmadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;"></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>THE MAGNIFICIENT SEVEN</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Y&ouml;netmen</span></span><span>:&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">John Sturges</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Senaryo:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>William Roberts (Akira Kurosawa&rsquo;nın Shichinin no Samurai adlı filminden)</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Oyuncular:</span></span><span>&nbsp;</span><span class="fs12ff2taltc00bgi21pl13pt07wp100"><span>Yul Brynner &ndash; Eli Wallach - &nbsp;Steve McQueen &ndash; Charles Bronson &ndash; James Coburn</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span class="fs11ff2tc01talbbgi23wp98pl10pt03pb03tat"><span>Yapım:</span></span><span>&nbsp;<span class="fs12ff2taltc00bgi21pl13pt07wp100">John Sturges (The Mirisch Corporation)</span></span></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>The Magnificient Seven</span>&nbsp;</i></b><span>&nbsp;(<b><i>TMS</i></b>), &ouml;zg&uuml;n yapısıyla bir uyarlama olduğunu unutturan, &ccedil;ok tutulmuş ve &uuml;&ccedil; devam filmi, hatta televizyon dizisi de yapılmış, artık klasikleşmiş bir westerndir.&nbsp;</span><span class="fiyat"><span>Bir Meksika k&ouml;y&uuml; Calvera (<b>Eli Wallach</b>) ve &ccedil;etesi tarafından s&uuml;rekli soyulmakta, tehdit altında tutulmaktadır. K&ouml;yl&uuml;ler korunmak i&ccedil;in tutabilecekleri silahş&ouml;r arayışına girerler. Arayışları onları iki işsiz silahş&ouml;r olan Chris (<b>Yul Brynner</b>) ve Vin&rsquo;e (<b>Steve McQueen</b>) ulaştırır. Onlara&nbsp;<b>James Coburn</b>,&nbsp;<b>Charles Bronson</b>&nbsp;ve&nbsp;<b>Robert Vaughn</b>\'un da aralarında bulunduğu beş kanun ka&ccedil;ağı daha katılır ve b&ouml;ylece muhteşem yedili tamamlanır. Muhteşem Yedili k&ouml;y halkını kurtarıp tekrar &ouml;zg&uuml;rl&uuml;ğ&uuml;ne kavuşturmak i&ccedil;in g&uuml;&ccedil;lerini birleştirir.</span></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>, Calvera&rsquo;nın k&ouml;ye yaptığı talan ziyaretlerinden biri ile başlar. K&ouml;yl&uuml;ler ondan hayli korkmaktadır ve Calvera onların ellerindekileri kendi malıymış gibi rahat&ccedil;a toplar. Hatta evine girdiği k&ouml;yl&uuml;ye yaptığının haklı olduğuna, bunun adının yaşam m&uuml;cadelesi olduğuna dair vaaz verir. Toplanıp ayrılırlarken elindeki orakla kendisine saldırmaya kalkışan bir k&ouml;yl&uuml;y&uuml; vurur ve tekrar geleceğini s&ouml;yleyerek, &ccedil;etesiyle doludizgin, k&ouml;yden ayrılır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><img src="/images/yazilar/dr_nihat_%20olayi.jpg" alt="Dr. Nihat Olayı" width="262" height="195" style="margin-right: auto; margin-left: auto; display: block;" /><b><i><span>OKA</span>&nbsp;</i></b><span>&nbsp;da bir &ccedil;etenin saldırısıyla başlar, ama bu defaki bir Rum &ccedil;etesidir ve mekan Kıbrıs&rsquo;tır.&nbsp;<b>Mehmet Ali Akpınar</b>&rsquo;ın canlandırdığı Gregorias &ouml;nderliğindeki &ccedil;ete, T&uuml;rk k&ouml;ylerine saldırılar d&uuml;zenlemektedir. Daha ilk sahnede, 1963&rsquo;teki saldırıların artık simge g&ouml;r&uuml;nt&uuml;lerinden birini oluşturan, Binbaşı Doktor Nihat İlhan&rsquo;ın eşi ve iki &ccedil;ocuğunun sığındıkları banyo k&uuml;vetinin i&ccedil;inde hunharca katledilmeleri canlandırılır.Hemen peşinden akmaya başlayan jenerik boyunca, artistlerin&nbsp;</span><span>g&ouml;r&uuml;nt&uuml;leri ve isimleri yanında, d&ouml;nemin gazetelerinin baş sayfalarının resimlerinde o zamanın gelişmeleri verilmektedir. Filme d&ouml;n&uuml;ld&uuml;ğ&uuml;nde, saldırıları devam etmekte olan ve ihtiyar bir k&ouml;yl&uuml;y&uuml; sorguladıklarında hedeflerinin k&ouml;yl&uuml;y&uuml; silahlandırmaya&nbsp;<img src="/images/yazilar/gregorias.jpg" alt="Gregorias" width="262" height="190" style="font-size: 13px; margin-right: auto; margin-left: auto; margin-bottom: 5px; display: block;" />&ccedil;alışan Halil&rsquo;i (<b>Tamer Yiğit</b>) bulmak olduğunu &ouml;ğrendiğimiz&nbsp;&ccedil;eteciler k&ouml;yl&uuml;den yanıt alamayınca onu d&ouml;ver. Dayanamayan bir k&ouml;yl&uuml;, Gregorias&rsquo;a saldırır ve sonu<b><i>TMS</i></b>&rsquo;deki sekansta vurulan Meksika k&ouml;yl&uuml;s&uuml;yle aynı olur. Gregorias, geri d&ouml;neceklerini, o vakte kadar k&ouml;y&uuml; terk etmelerini s&ouml;yler ve ayrılır. Zulm&uuml;n ardı kesilmez tabi. İhtiyar adamı tarlasında vururlar. Babasına sarılan gen&ccedil; kız (<b>Sevda Ferdağ</b>) intikam yemini eder. Yine &ccedil;etecilerden birka&ccedil;ı da k&ouml;yl&uuml; kızlardan ikisine (<b>Selma G&uuml;neri</b>&nbsp;ve sinemamızda t&uuml;m zamanların en g&uuml;zel g&ouml;zl&uuml; aktrislerinden biri olan&nbsp;<b>Devlet Devrim</b>) tecav&uuml;z eder.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu arada Gregorias Halil&rsquo;i bulur. Onu d&ouml;vd&uuml;r&uuml;r ve kendisiyle birlikte dağa &ccedil;ıkanların yerini s&ouml;ylemeye zorlar. Gen&ccedil; direnince, esir k&ouml;yl&uuml;lerden birka&ccedil;ını getirtip, s&ouml;ylemezse onları u&ccedil;urumdan atacağı tehdidinde bulunur. Halil konuşmamakta direnir ve Gregorias her seferinde Halil&rsquo;e cevabını sorup, o sessiz kaldık&ccedil;a u&ccedil;urumdan bir k&ouml;yl&uuml;y&uuml; attırır. Halil bir boşlukta adamların elinden sıyrılır ve intikam i&ccedil;in d&ouml;neceğini s&ouml;yleyerek, u&ccedil;urumdan denize atlar. Arkasından ateş eden Gregorias onun &ouml;ld&uuml;ğ&uuml;n&uuml; d&uuml;ş&uuml;n&uuml;r.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>&rsquo;de ne kadar Calvera&rsquo;dan hala korkuyor olsalar da artık canlarına tak etmiş olan k&ouml;yl&uuml;ler, bu durumdan kurtulmanın yollarını beraberce arar ve sonunda k&ouml;y&uuml;n yaşlısının tavsiyesiyle başkaldırmaya karar verirler. Ancak ne silahları, ne de cesaretleri ve savaş bilgileri vardır. K&ouml;y&uuml; temsilen &uuml;&ccedil; kişi, varlarını yoklarını yanlarına alarak, &ccedil;&ouml;z&uuml;m bulmak &uuml;zere sınıra doğru yola &ccedil;ıkar.<br /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><img src="/images/yazilar/uc_ahbap_%20koylu.jpg" alt="&Uuml;&ccedil; Ahbap K&ouml;yl&uuml;" width="232" height="170" style="margin-right: auto; margin-left: auto; margin-bottom: 5px; display: block;" /><b><i><span>OKA</span></i></b><span>&rsquo;da ise, başkaldırı bir bakıma daha bireysel başlıyor. Yani, evet, yine canına tak demiş k&ouml;yl&uuml; topluluğu var burada da, ama direnişe &ouml;ncelikle karar verip, &ccedil;&ouml;z&uuml;m i&ccedil;in yola &ccedil;ıkan kişi, bir başına Halil oluyor. Bizde ayrıca tecav&uuml;z sahnelerine ve daha fazla vahşete yer verilmesi, hen&uuml;z sıcak olan ger&ccedil;ek olaylara vurgu yapma arzusundan olmalı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Halil, kendisine geldiğinde bir teknenin i&ccedil;inde yatmaktadır. R&uuml;stem (<b>Işın Kaan</b>) ve kız kardeşi (<b>Tijen Par</b>) onu kurtarmıştır. Bu tekne bir T&uuml;rk teknesidir ve sahibi olan R&uuml;stem de Kıbrıs olaylarını bilmekte ve bunlardan rahatsız olmaktadır. Halil arkadaşlarını kaybettiğini ve yeni bir ekip oluşturmak i&ccedil;in Antalya&rsquo;ya gideceğini s&ouml;yleyince, R&uuml;stem ilk g&ouml;n&uuml;ll&uuml;n&uuml;n kendisi olduğunu s&ouml;yler ve iki adam, ekibi toplamak &uuml;zere yola &ccedil;ıkar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>&rsquo;de bizim ikilimize karşılık gelen ikili olan Chris Adams (<b>Yul Brynner</b>) ve Vin (<b>Steve McQueen</b>) ise, bir medeniyet krizi (!) neticesinde yollarını birleştiriyorlar: Meksikalı k&ouml;yl&uuml;lerimizin vardığı sınır kasabasında bir &ouml;l&uuml;n&uuml;n cenazesi, adam zenci olduğu i&ccedil;in kaldırılmamaktadır. Cenazeyi mezarlığa g&ouml;t&uuml;rmeye kimse cesaret edemez. Olayı izleyenler arasındaki Chris işe talip olur. Macera arayan bir tip olduğu hemen belli olan Vin de teredd&uuml;ts&uuml;z yanına atlar. Araba ilerlerken t&uuml;m meraklı kasaba halkı ve bizim Meksikalılar gibi macera peşindeki, silahş&ouml;rl&uuml;ğe hevesli bir gen&ccedil; olan Chico da (<b>Horst Bucholz</b>) onları takip etmektedir. Neticede mezarlığa varılır ve orada ge&ccedil;en kısa bir &ccedil;atışmanın ardından ikili karşılarındakilere &uuml;st&uuml;n gelir ve &ouml;l&uuml; g&ouml;m&uuml;l&uuml;r. K&ouml;yl&uuml;ler aradıkları adamları bulduklarına karar verirler ve Chris&rsquo;i ziyaret ederler. Ona durumlarını anlatırlar. Hallerinden etkilenen Chris, onlara bizzat katılarak değil, ama silahş&ouml;r aradıklarını etrafa yayarak yardımcı olabileceğini s&ouml;yler. Dediğini de yapar ve k&ouml;yl&uuml;lerle birlikte bir mekanda başvuracak kişileri beklemeye başlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Halil ve R&uuml;stem, arayışlarını s&uuml;rd&uuml;rd&uuml;kleri Antalya&rsquo;da bir pazar yerinde diğer satıcıların haksız saldırısına uğrayan bir k&ouml;yl&uuml;y&uuml; kurtaran Ali Osman (<b>&Ouml;zkan Yılmaz</b>) ve Konyak&ccedil;ı (<b>Yılmaz G&uuml;ney</b>) ile karşılaşırlar ve cesaretlerinden etkilenirler. Ali Osman&rsquo;la g&ouml;zden ırak konuşur ve onu ikna ederler. Artık &uuml;&ccedil; kişidirler.<br /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/konyakci.jpg" alt="" width="379" height="273" border="0" /></span><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Yılmaz G&uuml;ney</span></b><span>&rsquo;in Konyak&ccedil;ı olarak g&ouml;r&uuml;nd&uuml;ğ&uuml; bu ilk sahne, aslında sinemamızın da d&ouml;n&uuml;m noktalarından biridir. &Ccedil;&uuml;nk&uuml;,&nbsp;<b><i>İkisi de Cesurdu</i></b>&nbsp;ile seyircisine ulaşmanın ilk adımlarını atan&nbsp;<b>G&uuml;ney</b>, bu defa, hem de rol&uuml; g&ouml;receli olarak az olduğu halde, şeytanın bacağını kırmıştır. &ldquo;Burada &ccedil;izdiği Konyak&ccedil;ı tipi,&nbsp;<b>G&uuml;ney</b>&rsquo;i bir anda yıldız yaptı. Halbuki Konyak&ccedil;ı, film boyunca hi&ccedil; konuşmayan, şişesi s&uuml;rekli ağzında, kirli sakallı, kovboy şapkalı, genelde geri planda gezinen bir tiplemeydi.&rdquo; (Yılmaz G&uuml;ney Westerni - İlker Mutlu, Sinema, Aralık 2003)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&ldquo;Bu, seyirciyle&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;arasında sempatik bir yakınlaşma sonucuydu. Konyak&ccedil;ı tipi&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in tutarlı olması i&ccedil;in belki de bir vesileydi. Asıl ger&ccedil;ek halk i&ccedil;inden gelmiş basit g&ouml;r&uuml;n&uuml;şl&uuml; bir kişinin halkın s&ouml;zc&uuml;l&uuml;ğ&uuml;n&uuml; yapmasıydı. İşte bu s&ouml;zc&uuml; toplumun alt katında yaşayan seyirciyi aşağılık duygusundan biraz olsun sıyırabildi. &Uuml;stelik bu katın seyircisi bebek y&uuml;zl&uuml; j&ouml;nleri tutan, genellikle evde kalmış resimli roman okuyucusu kızlardan daha az kaypaktı.&rdquo; (Sokaktaki Adam ya da Yılmaz G&uuml;ney, Agah &Ouml;zg&uuml;&ccedil;, Sinema 65, Temmuz 1965.)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tiplemenin bu denli tutması &uuml;zerine, Konyak&ccedil;ı&rsquo;nın hikayesi, yine&nbsp;<b>Tun&ccedil; Başaran</b>&rsquo;ın y&ouml;netiminde, ertesi yıl, bu defa etrafında hi&ccedil;bir j&ouml;n dolanmadan, tek başına devam eder (<b><i>Konyak&ccedil;ı</i></b>, 1965). &ldquo;B&uuml;t&uuml;n macerası bir konyak şişesine bağlanmış&rdquo; olan bu sessiz kahraman, G&uuml;ney&rsquo;in &ouml;nlenemez y&uuml;kselişine en b&uuml;y&uuml;k katkıyı yapacaktır. Bu, s&uuml;rekli sarhoş olduğu i&ccedil;in hor g&ouml;r&uuml;len, ancak sonunda silahlarını kuşanıp t&uuml;m k&ouml;t&uuml;leri haklayan, şapkası kaşına devrik, suskun silahş&ouml;r karakterine hepimiz pek &ccedil;ok kovboy filminden aşinayızdır. Burada k&ouml;t&uuml; adam, civar k&ouml;yleri baskı altında tutan bir ağadır ve bizim ayyaş bu ağaya ve adamlarına karşı savaş a&ccedil;ar ve zavallı k&ouml;yl&uuml;leri kurtarır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Konyak&ccedil;ı tiplemesine yakın karakterleri de&nbsp;<b>G&uuml;ney</b>&nbsp;tekrar kullanmıştır:&nbsp;<b><i>Kargacı Halil</i></b>&nbsp;(<b>Yavuz Yalınkılı&ccedil;</b>, 1968),&nbsp;<b><i>İbret&nbsp;</i></b>(<b>Yılmaz G&uuml;ney</b>, 1971).<br /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/chico.jpg" alt="" width="279" height="205" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span>Yeniden filmlerimize d&ouml;nelim.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Chris ve Meksikalılar silahşor adaylarını beklemektedirler. İlk gelen Chico olur. Ancak Chris bu hırslı delikanlıyı kısa bir deneme ile yıldırır. Chico ardına bakmadan orayı terk eder. Mekana gelen bir arkadaşı olan Harry Luck (<b>Brad Dexter</b>), Chris&rsquo;e kurmaya &ccedil;alıştığı ekipte olmak istediğini s&ouml;yler. G&uuml;n&uuml;n sonunda dinlenmek i&ccedil;in gittikleri lokantada Vin de vardır. Durumu ona da anlatırlar ve Vin de onlara katılmaya karar verir. Chris ve Vin, birlikte, cesareti hakkında &ccedil;ok şey duydukları O&rsquo;Reilly&rsquo;yi (<b>Charles Bronson</b>) bulmaya giderler. Onu bir &ccedil;iftlikte, karın tokluğuna odun keserken bulurlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><img src="/images/yazilar/odun.jpg" alt="Odun" width="275" height="197" style="margin-right: auto; margin-left: auto; margin-bottom: 5px; display: block;" /><span style="font-size: 10pt;">Benzer bir sahne&nbsp;</span><b style="font-size: 10pt;"><i>OKA</i></b><span style="font-size: 10pt;">&rsquo;da da var. R&uuml;stem, d&ouml;rd&uuml;nc&uuml; kişi olarak, eski tanıdığı cesur bir dostu olan Kadri&rsquo;yi (</span><b style="font-size: 10pt;">Abdullah Ferah</b><span style="font-size: 10pt;">) &ouml;nerir. Onu bir k&ouml;y evinin bah&ccedil;esinde, odun keserken bulurlar. Dertlerini anlattıklarında, o da</span><b style="font-size: 10pt;"><i>TMS</i></b><span style="font-size: 10pt;">&rsquo;deki O&rsquo;Reilly gibi ikna olur ve onlara katılmayı kabul eder. İkisinin de gerek&ccedil;esi aynıdır: Macera! Ekibin beşinci adamı olacak olan Suphi (</span><b style="font-size: 10pt;">Adnan Şenses</b><span style="font-size: 10pt;">) olayı barda duymuştur ve derhal onlarla olmaya karar verip, Halil&rsquo;in de kalmakta olduğu, R&uuml;stem&rsquo;in evine gelir. Suphi bu m&uuml;cadeleye katılmak istemektedir, &ccedil;&uuml;nk&uuml; veremdir ve &ccedil;ok az &ouml;mr&uuml; kaldığını bilir. Ancak, hastalığını diğerlerinden saklar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Chris ve Vin, trenyolu kenarındaki bir alanda, biraz da oradaki diğer kovboyların kışkırtmasıyla, kendisiyle kapışması i&ccedil;in bir adamın olduk&ccedil;a sıska olan ve kendi halinde uyuklamaya &ccedil;alışan Britt&rsquo;i (<b>James Coburn</b>) taciz edişine şahit olur. Britt, &ccedil;ok iyi bı&ccedil;ak kullanmaktadır. Adam tabancayla, Britt ise bı&ccedil;akla hamle edecektir. İlkinde bilerek ıskalayan Britt, adam &uuml;zerine gelmeye devam edince, ikincisinde hedefi vurur ve oradan ayrılır. Sonra bir barda toplanan k&ouml;yl&uuml;ler ve ekibin o ana dek toparlanan d&ouml;rt kişisinin konuşmalarından Chris&rsquo;in Britt ile konuştuğunu ama Britt&rsquo;in olayla pek ilgilenmediğini &ouml;ğreniriz. O sırada bara Chico girer. &Ccedil;ok sarhoştur. Chris&rsquo;e meydan okur, ama karşılık alamaz. &Ouml;fke kriziyle kendinden ge&ccedil;er. Chris tam bardan ayrılacakken, Britt karşısında belirir ve fikrini değiştirdiğini s&ouml;yler. Chris&rsquo;e bir dostunun kendisini beklediği s&ouml;ylenir. Vin&rsquo;le birlikte denen yere gittiklerinde, karşılarında Lee&rsquo;yi bulurlar. Lee (<b>Robert Vaughn</b>), olduk&ccedil;a şık giyinen bir silahş&ouml;rd&uuml;r ve eldiven takmaktadır. Beladan ka&ccedil;makta olduğu her halinden bellidir ve biraz da Meksika&rsquo;ya ge&ccedil;mek d&uuml;ş&uuml;ncesiyle maceraya katılmaya g&ouml;n&uuml;ll&uuml; olur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Halil, Kadri, Ali Osman, R&uuml;stem ve Suphi bir şeyler yemek &uuml;zere bir i&ccedil;kili lokantaya giderler. Az sonra, umursamaz tavırları ve kaşlarına indirdiği şapkasıyla Konyak&ccedil;ı gelir ve ayrı bir masaya yayılır. Peşinden de olduk&ccedil;a yakışıklı ve s&uuml;sl&uuml; giyimli, eldivenli ve bastonlu bir bey (<b>Tun&ccedil; Oral</b>) gelir lokantaya ve o da ayrı bir masaya oturur. Yakasında bir karanfil vardır ve bu da lakabının &lsquo;Karanfilli&rsquo; olmasının sebebidir. Lokantadaki birka&ccedil; serseri Karanfilli&rsquo;yi muhallebi &ccedil;ocuğu g&ouml;rerek ona sataşırlar. Karanfilli onları birka&ccedil; kez nazik&ccedil;e uyarır ama adamlar sarhoştur ve Karanfilli&rsquo;yi d&ouml;vmeyi kafaya koymuştur. Nihayet tartışma alevlenir ve Karanfilli adamları evire &ccedil;evire d&ouml;ver. Konyak&ccedil;ı, yine umursamazca, tek kelime etmeden şapkasını kaşına devirir ve lokantadan ayrılır. Halil&rsquo;in g&ouml;z&uuml; Karanfilli&rsquo;yi tutmuştur. Ona bir i&ccedil;ki ısmarlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Chico&rsquo;nun&nbsp;<b><i>OKA</i></b>&rsquo;daki muadili olan Mektepli, filmin 27. dakikasında ortaya &ccedil;ıkar. Halil ve R&uuml;stem gece eve d&ouml;nerlerken gencecik bir delikanlı olan Mektepli (<b>Ercan Tekkan</b>) birden karşılarına &ccedil;ıkar ve onlara Kıbrıs&rsquo;ta d&ouml;v&uuml;şecek adamlar aradıklarını duyduğunu ve g&ouml;n&uuml;ll&uuml; olduğunu s&ouml;yler. Onun gen&ccedil;liğini g&ouml;ren Halil olayı yalanlar. Gen&ccedil; hiddetlenir ve davalarına saygı duyan, &ouml;lmeye g&ouml;n&uuml;ll&uuml; bir gen&ccedil;le alay etmeye hakları olmadığını haykırır. R&uuml;stem &ccedil;ocuğun &ccedil;ok gen&ccedil; ve hassas olduğunu s&ouml;ylediğinde Halil, &ldquo;Kıbrıs &ccedil;ok gen&ccedil; ve hassas insanların cesetleriyle dolu.&rdquo; der ve artlarına bakmadan yola devam ederler. Mektepli&rsquo;yle ge&ccedil;en bu sahnedeki t&uuml;m konuşmalar,&nbsp;<b><i>TMS</i></b>&rsquo;de Chris ve Chico arasında, karşı karşıya geldikleri ilk sahnede ge&ccedil;en diyalogların neredeyse birebir aynıdır. Chico ile Mektepli arasındaki fark, Chico&rsquo;nun ş&ouml;hret hırsı, ancak Mektepli&rsquo;nin memleket sevdası olmasıdır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Meksikalı k&ouml;yl&uuml;ler ve bir araya gelen altı adamdan beşi, sınıra doğru yola koyulurlar. Lee ile sonradan buluşmak &uuml;zere s&ouml;zleşmişlerdir. Chico, yol boyunca onları uzaktan takip eder. Başta ona y&uuml;z vermeyen ekip, &ccedil;ocuğun ısrarından vazge&ccedil;meyeceğini anlayınca onu da aralarına alırlar ve Muhteşem Yedili oluşmuş olur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/yedili%20bir%20arada.jpg" alt="" width="250" height="159" border="0" /></span><span style="font-size: 10pt;"><br /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>OKA</span></i></b><span>&rsquo;da Britt&rsquo;e karşılık gelen K&uuml;rt Mahmut da (<b>Erol Taş</b>) yine ona nispeten ge&ccedil; bir zamanda, 29. dakikaya gelinirken karşımıza &ccedil;ıkar. Sahne, mizansen olarak aynıdır: K&uuml;rt Mahmut&rsquo;un hakkında ileri geri konuştuğunu iddia eden bir k&ouml;yl&uuml;, samanların yanında kestiren K&uuml;rt Mahmut&rsquo;a sataşır. Diğer k&ouml;yl&uuml;ler ve olaya şahit olan Halil de onları seyretmektedir. K&ouml;yl&uuml;, Mahmut&rsquo;a bir tırmıkla saldırır. Mahmut saldırıdan sıyrılır ve adamın elinden tırmığı alır, samanlığa atar. Yine umursamaz bir tavırla kasketini kaşına indirir. Hırsını alamayan k&ouml;yl&uuml; yeniden tırmığa sarılınca, Mahmut bı&ccedil;ağını atar ve adamı kolundan duvara &ccedil;iviler. Bı&ccedil;ak kullanmaktaki maharetinden etkilenen Halil, ona da teklifte bulunur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/kurt_%20mahmut.jpg" alt="" width="299" height="221" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>K&uuml;rt Mahmut rol&uuml;n&uuml; oynayan&nbsp;<b>Erol Taş</b>&nbsp;da&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;gibi, bu filmin unutulmaz karakterlerinden birini &ccedil;izer. Karakteristik y&uuml;z yapısına bu role has olarak dudağına yedirdiği mimikler ve anlamlı g&ouml;zleriyle yaşayan bir tiplemedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Halil, ekiptekilerin yeterli olduğuna karar vermiştir. R&uuml;stem&rsquo;in evinde son planı yaparlar. Ertesi g&uuml;n Aspendos&rsquo;ta buluşulacak ve R&uuml;stem&rsquo;in teknesiyle yola &ccedil;ıkılacaktır. Bu Aspendos buluşması sekansı da olduk&ccedil;a ilgin&ccedil;: &Uuml;rk&uuml;t&uuml;c&uuml; bir m&uuml;zik eşliğinde Halil tek başına ortaya geliyor. Onu &ouml;nce anfinin en &uuml;st basamağından yapılan bir &ccedil;ekimle g&ouml;r&uuml;r&uuml;z. Sonra kamera onu profilden alır ve Halil merakla kimlerin geleceğini araştırırca anfinin basamaklarına bakar. &Ouml;nce R&uuml;stem ve kızkardeşi, ardından Kadri ve Ali Osman, Karanfilli ve Suphi, K&uuml;rt Mahmut gelir. Tam yedide kaldıklarını d&uuml;ş&uuml;n&uuml;rlerken, bir ıslık sesine d&ouml;nerler ve merdivenlerin en tepesinde Konyak&ccedil;ı belirir. Aspendos&rsquo;tan ayrılırlarken onları uzaktan takip eden bir &ccedil;ift g&ouml;z vardır: Mektepli.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Akşam tekneye giderlerken, aslında amacı gizlenmek olup aynı ormana dalan İdamlık&rsquo;ın (<b>Oktar Durukan</b>) kendilerini izlediğini sanır ve onu pusuya d&uuml;ş&uuml;r&uuml;rler. İdamlık bir ka&ccedil;ak olduğunu s&ouml;yleyemez ve onlardan korkar. Ancak ondan hala ş&uuml;phelenmekte olan ekip, onu da araya alarak yola devam eder.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Tun&ccedil; Başaran</span></b><span>&rsquo;ın y&ouml;netimi filmin her anında pırıltılar i&ccedil;ermiyor elbette. Neticede&nbsp;<b><i>OKA</i></b>, y&ouml;netmenin ilk filmlerinden biri. &Ouml;rneğin karakterlerin kişiliklerini vurgulamak i&ccedil;in gerekli gereksiz kullandığı oyunlar bazı anlarda sırıtıyor (Veremli Suphi&rsquo;nin ikide bir mendil &ccedil;ıkarması ve Konyak&ccedil;ının durmadan i&ccedil;mesi gibi). Ama filmin genelde naif bir yapısı var ve bu acemi anlar, b&uuml;t&uuml;n&uuml;n i&ccedil;inde &ccedil;ok da rahatsızlık vermiyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tekneye varır ve İdamlık&rsquo;ı bir kamaraya kilitlerler. Suphi&rsquo;nin kız kardeşinin de teknede olması kahramanlarımızı rahatsız etmiştir. Ancak Suphi, &ouml;ks&uuml;z olduklarını ve kardeşinin onun yanında bir erkek gibi yetiştiğini s&ouml;yler. Kız da bir T&uuml;rk kızı olduğunu ve gerekirse g&ouml;ğ&uuml;s g&ouml;ğ&uuml;se &ccedil;arpışabileceğini anlatarak kendisini savunur. Bu arada Halil ile aralarında da platonik boyutta ilerleyen bir aşk başlamıştır. Kıbrıs&rsquo;a yapılan tekne yolculuğu karakterlerin daha da yakınlaşmasını sağlar. Y&ouml;netmen bunu bize karakterleri ikişer ikişer aldığı sahnelerle aktarır. K&uuml;rt Mahmut&rsquo;u Halil&rsquo;le, Kadri&rsquo;yi Suphi ile konuşturur. Film boyunca &ldquo;Benim i&ccedil;in fark etmez.&rdquo; repliği dışında neredeyse hi&ccedil; konuşmayan Konyak&ccedil;ı ve gran-tuvalet Karanfilli ise, yalnızca birbirlerine puro ve konyak vererek anlaşırlar. Bir ara İdamlık&rsquo;ı kilitledikleri odaya giren Halil, İdamlık&rsquo;la konuştuğunda, onun yolculuk esnasında dinlediklerinden etkilendiğini ve ekibe katılmak istediğini &ouml;ğrenir. &ldquo;Ucunda &ouml;l&uuml;m var.&rdquo; diyerek İdamlık&rsquo;ı uyarır Halil. İdamlık&rsquo;ın yanıtı ise, &ldquo;Ben zaten &ouml;l&uuml;y&uuml;m.&rdquo; olur. R&uuml;stem&rsquo;in adamı, teknenin alt kısmında ka&ccedil;ak bir yolcu bulmuştur. Bu yolcu Mektepli&rsquo;den başkası değildir. Onun kararlılığını g&ouml;ren ekip, onu da i&ccedil;lerine dahil etmeye karar verir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Nihayet Kıbrıs&rsquo;a &ccedil;ıkan ekip, koruyacakları yer olan Halil&rsquo;in k&ouml;y&uuml;ne doğru ilerlemeye başlar. Rumların yakıp yıktığı, ahalisinin terk ettiği bir k&ouml;yde konaklarlar. R&uuml;stem kız kardeşini omzunda uyuturken, Kadri &uuml;st&uuml; a&ccedil;ık yatmakta olan Mektepli&rsquo;nin &uuml;zerine paltosunu serer. İdamlık, yattığı yerde korkuyla, g&uuml;r&uuml;lt&uuml;yle sayıklamaktadır. K&uuml;rt Mahmut ve Halil onun başına gittiğinde, sayıklamalarından onun yanlış yere su&ccedil;lanan bir ka&ccedil;ak olduğunu anlar. Kendisinde olmadan bağıran İdamlık&rsquo;ı tokatlayarak uyandırırlar. Sabah kalktıklarında, Mektepli&rsquo;yi yerinde bulamazlar. K&ouml;y&uuml; didik didik ederler &nbsp;ama &ccedil;ocuk yoktur. Mektepli, etrafı dolaşırken rastladığı bir mezarlıktadır. Aniden bir silah sesine irkilirler ve Halil o y&ouml;ne koştuğunda Mektepli&rsquo;yi alnından vurulmuş bulur. Ka&ccedil;makta olan Rum katili vurur Halil ve hın&ccedil;la, t&uuml;m mermisini adamın &uuml;st&uuml;ne boşaltır. Mektepli, ekibin ilk kaybı olmuştur. Moralce sarsılan ekip, Mektepli&rsquo;yi g&ouml;mer ve yola devam eder.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/idamlik.jpg" alt="" width="297" height="221" border="0" /></span><span style="font-size: 10pt;"><br /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Halil&rsquo;in k&ouml;y&uuml;ne yaklaştıklarında k&ouml;yl&uuml; onları &ouml;nce d&uuml;şman zanneder ve silahla yola iner. Ancak, kafilenin başında &ouml;ld&uuml; sandıkları Halil&rsquo;i g&ouml;r&uuml;nce endişeleri sevince d&ouml;n&uuml;ş&uuml;r. Halil&rsquo;in kardeşi Sevda (<b>Sevda Ferdağ</b>) ve k&uuml;&ccedil;&uuml;k erkek kardeşi Ali, koşarak ona sarılırlar. Ekip neşeyle k&ouml;ye girerken fonda tempolu bir marş &ccedil;almaktadır! Ali, K&uuml;rt Mahmut&rsquo;u &ccedil;ok sevmiştir. Aralarında hemen bir dostluk oluşur. K&ouml;yl&uuml; kızlarından Emine (<b>Selma G&uuml;neri</b>) Konyak&ccedil;ı&rsquo;ya, kardeşi de (<b>Devlet Devrim</b>) Suphi&rsquo;ye ilgi duyacaktır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>&rsquo;nin yedilisi de vardığı k&ouml;yde &ouml;nce benzeri bir yabanilikle karşılaşır. K&ouml;y, adeta boşaltılmış izlenimi verir onlara. Bir tek k&ouml;y&uuml;n filmin başında da g&ouml;r&uuml;ş alınan bilgesi &ccedil;ıkar ortaya ve k&ouml;yl&uuml;lerin korktukları i&ccedil;in saklandıklarını s&ouml;yler. Bu esnada kilisenin &ccedil;anı g&uuml;r&uuml;lt&uuml;yle &ccedil;alar ve halk meydana d&ouml;k&uuml;l&uuml;r. &Ccedil;anı &ccedil;alan Chico&rsquo;dur ve toplanan k&ouml;yl&uuml;leri azarlar kendilerini karşılamadıkları i&ccedil;in. (<b>Toshiro Mifune</b>&rsquo;nin&nbsp;<b><i>Yedi Samuray</i></b>&rsquo;daki &ccedil;ılgın fır&ccedil;asının yerini tutmuyor, ama sekans aynı işlevi g&ouml;r&uuml;yor.) Chris, Chico&rsquo;nun bu &ccedil;ıkışını g&ouml;rd&uuml;kten sonra, &ldquo;Artık yedi olduk.&rdquo; der. K&ouml;yl&uuml;, silahş&ouml;rlerin gelişini kutlamak i&ccedil;in bir eğlence d&uuml;zenler.&nbsp;<b>John Sturges&nbsp;</b>de burada ekibi ikişer ikişer &ccedil;eşitli sahnelerde bir araya getirerek yakınlaştırır. O&rsquo;Reilly, bı&ccedil;ağıyla kamıştan bir d&uuml;d&uuml;k yapar ve kendisini izleyen &uuml;rkek kız &ccedil;ocuğuna verir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir &ccedil;ocuk telaşla gelir ve Chris&rsquo;le oturmakta olan k&ouml;yl&uuml;ye haydutların yakında olduğunu s&ouml;yler. Chris, telaşlanan adamı yatıştırır ve bunu halledeceğini s&ouml;yler. Britt&rsquo;e giderek ondan, haydutlardan birini yakalayıp kendisine canlı olarak getirmesini ister. Lee de Britt&rsquo;e katılır. Chico, gizlice onları takip eder. Bu arada, geride kalan ekip de silahlarını kuşanır ve etrafı kollar. Britt ve Lee haydutların kamp yerine vardıklarında, orada sadece haydutların atlarını bulurlar ve pusuya yatıp, onları beklemeye başlarlar. Bu arada geriye d&ouml;nen &uuml;&ccedil; haydut, Chico&rsquo;yu fark eder. Chico kendini savunur ve adamlardan birini vurur. Diğer ikisini de Britt vurur. Bu &uuml;&ccedil; haydut, Calvera&rsquo;nın k&ouml;y&uuml; izlemeleri i&ccedil;in g&ouml;nderdiği casuslardır. K&ouml;yl&uuml;ler bu &ccedil;atışmadan korkmuşlardır. Chris, onları cesaretlendiren bir konuşma yapar ve Calvera&rsquo;nın uzakta olduğunu, yakında olsa kendi geleceğini, dolayısıyla hazırlanmak ve ona s&uuml;rpriz yapmak i&ccedil;in zamanları olduğunu anlatır. Vakit kaybetmeden atış talimlerine ve k&ouml;y&uuml;n etrafına hendek a&ccedil;ıp tahkimat yapmaya başlarlar. O t&ouml;ren gecesi k&ouml;yde neredeyse hi&ccedil; kadın olmaması Vin&rsquo;in dikkatini &ccedil;ekmiştir. Ger&ccedil;ekten de, yediliden dahi &ccedil;ekinen k&ouml;yl&uuml;ler, kızlarını k&ouml;y&uuml;n dışında saklamaktadır. Ormanda gezindiği bir sekansta bu kızlardan birini bulan Chico, onu atının terkisine attığı gibi k&ouml;ye getirir ve k&ouml;yl&uuml;lerin ortasına indirir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>OKA</span></i></b><span>&rsquo;da da, Halil&rsquo;le R&uuml;stem&rsquo;in kız kardeşi dertleşirken, Ali telaşla gelir ve &ccedil;etecileri g&ouml;rd&uuml;ğ&uuml;n&uuml; s&ouml;yler. Halil, Kadri ve Osman&rsquo;a k&ouml;yde kalmalarını s&ouml;yler; Mahmut, Karanfilli ve R&uuml;stem&rsquo;le birlikte &ccedil;ocuğun s&ouml;ylediği yere doğru yola &ccedil;ıkar. Bu esnada Konyak&ccedil;ı da dere kenarında gezinmektedir. Karşıda dertli dertli oturmakta olan Emine&rsquo;yi g&ouml;r&uuml;r ve yanına gider. Konyak&ccedil;ı, kulağına bir &ccedil;i&ccedil;ek asmıştır. Onu kıza verir. Emine&rsquo;nin y&uuml;z&uuml; yumuşar. İdamlık da bir u&ccedil;urumun başında Sevda ile birliktedir.&nbsp;<b>Devlet Devrim</b>&nbsp;de mezarlıkta n&ouml;bet tutmakta olan Suphi&rsquo;nin yanına gitmiştir. Bu sekanslarla Halil&rsquo;in aşkına &uuml;&ccedil; aşk daha katılmış olur! Ancak, muhabbetler kısa s&uuml;rer, &ccedil;&uuml;nk&uuml; &uuml;&ccedil;&uuml; de bir anda duydukları silah sesiyle irkilir, k&ouml;ye koşar. K&ouml;yde toplandıklarında, Haliller&rsquo;in yakaladıkları bir &ccedil;eteciyi getirdiklerini g&ouml;r&uuml;rler. K&uuml;rt Mahmut adamı iterek, ortaya yuvarlar. Adamdan Rumların bir ge&ccedil;ide doğru ilerlediklerini &ouml;ğrenmişlerdir. Onlarla &ccedil;arpışmak &uuml;zere silahlarını omuzlar ve yola d&uuml;şerler. Ge&ccedil;itte, karşılarında sadece dokuz adam olduğunu g&ouml;ren Gregorias onları k&uuml;&ccedil;&uuml;mser. Ancak bu ona pahalıya mal olacak ve &ccedil;atışmada adamlarının yarısını kaybedip, geri &ccedil;ekilmek zorunda kalacaktır. Bu ekibin ilk zaferidir. &Ccedil;atışma esnasında dokuzlunun her biri, diğerini birer kez kurtarır ve bu da daha da yakınlaşmalarına neden olur. Tek kayıp vermeden &ccedil;atışmadan &ccedil;ıktıklarını anlayıp birbirlerini selamladıkları sahneye yine k&ouml;ye girerlerken &ccedil;alan tempolu marş eşlik eder!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Chris, meydanda k&ouml;yl&uuml;lere &ccedil;ekincelerini anladığını, ama kadınları Calvera bulursa, sonlarının asıl o zaman k&ouml;t&uuml; olacağını anlatır. Bunun &uuml;zerine kadınlar k&ouml;ye geri getirilir ve adamlarımızın karnına da b&ouml;ylece sıcak ev yemeği girer. Ancak, onlara en iyi yemeklerini verip, kendilerinin kuru ekmek ve mısır yediklerini &ouml;ğrenince, yemeklerini k&ouml;yl&uuml;yle paylaşırlar. Calvera, nihayet ziyaretini ger&ccedil;ekleştirmek &uuml;zere yoldadır. Chris dağ boyunca iyi bir g&ouml;zc&uuml; sistemi kurmuştur ve haber hemen k&ouml;ye ulaşır. K&ouml;y&uuml;n etrafı duvar ve hendeklerle &ccedil;evrelenmiş ve girişe b&uuml;y&uuml;k bir ağ gerilmiştir. K&ouml;yl&uuml;, her ihtimale karşı, mısırını da g&ouml;mm&uuml;şt&uuml;r. İki tarafın karşı karşıya gelmesine birka&ccedil; dakika vardır!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Calvera&rsquo;nun k&ouml;ye kırk adamıyla girdiği sekans ve&nbsp;<b><i>OKA</i></b>&rsquo;daki ge&ccedil;itteki &ccedil;atışma sekansı, hemen hemen aynı şekilde ilerlemektedir. Calvera da &ouml;nce Chris&rsquo;i ve Vin&rsquo;i g&ouml;r&uuml;r ve azımsar. Sonradan yedilinin gerisi teker teker ortaya &ccedil;ıktığında da azımsar ve &ouml;nce aradan &ccedil;ekilmelerini, gerekirse pay verebileceğini s&ouml;yler. Hatta, &ldquo;K&ouml;yl&uuml;leri niye soymayayım? Dinde bile yeri var: İncil&rsquo;de &lsquo;Tanrı kırpılmasını istemeseydi, koyunu yaratmazdı.&rsquo; yazar.&rdquo; der ve k&ouml;yl&uuml;leri s&uuml;r&uuml;ye benzetir. Olumsuz yanıt alınca sinirlenir ve adamlarına saldırı emri verir. K&ouml;yl&uuml;lerin de katıldığı şiddetli bir kapışmanın ardından canını birka&ccedil; adamıyla birlikte zor kurtaran Calvera, ardına bakmadan k&ouml;yden ka&ccedil;ar. K&ouml;yl&uuml;n&uuml;n neşesi ve cesareti yerine gelmiştir. Akşamleyin bir araya gelen k&ouml;yl&uuml;ler, cesaretlerini birbirlerine abartarak anlatır, iddialaşırlar. Artık Calvera&rsquo;nın kendilerini rahat bırakacağını d&uuml;ş&uuml;nmektedirler. Ancak, k&ouml;y&uuml;n yakınında mevzilenen &uuml;&ccedil; haydut, beklemedikleri anda k&ouml;ye ateş a&ccedil;ar. Yedili, onları vurmak &uuml;zere mevzilenir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>OKA</span></i></b><span>&rsquo;nın buradan &ouml;d&uuml;n&ccedil; aldığı cinsel yakınlaşma olgusunu burada Chico ile onun ormanda bulduğu kız temsil ediyor. Ona ilgi duymaya başlayan kız birka&ccedil; sahnede onun ilgisini &ccedil;ekmeye &ccedil;alışıyor, ama Chico aslında boş olmadığı kıza karşılık vermemeye &ccedil;abalıyor. Bu mevzilenme sahnesinde de &ouml;rneğin, Chico bir duvarın arkasından hedefini se&ccedil;meye &ccedil;alışırken kız gelir ve onunla konuşmaya &ccedil;alışır. K&uuml;&ccedil;&uuml;k &ccedil;ocuklar her iki filmde de sevimlilikleriyle bu vahşi filmlerin &ouml;yk&uuml;lerini yumuşatmaktadır. O&rsquo;Reilly&rsquo;yi seven &ccedil;ocuklar, o pusuya yatmış, haydutları g&ouml;zlerken dahi yanına gitmek isterler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yedili geri d&ouml;nd&uuml;ğ&uuml;nde onları buluşma evinde bekleyen k&ouml;yl&uuml;ler, Calvera&rsquo;nın gitmemiş ve yeni bir saldırıya başlamaya hazırlanıyor olduğu d&uuml;ş&uuml;ncesiyle tedirgindirler. İlk hamlenin Calvera&rsquo;dan gelmesini beklemeyi kararlaştırırlar. K&ouml;yl&uuml;ler yediliye yemek getirmek i&ccedil;in ayrıldıklarında, ekibin arasında hayatlarını sorgulayan bir konuşma ge&ccedil;er: Chico, g&uuml;nd&uuml;z yaptıkları &ccedil;atışmadan heyecan ve gurur duyduğunu hevesle ifade etmeye &ccedil;alışırken Vin ve Chris&rsquo;in yanıtları bir silahş&ouml;r&uuml;n aslında hi&ccedil;bir şeyi olmadığı olur. Konuşmanın ardından Chris, Chico&rsquo;yu ona verdiği Meksika şapkasıyla Calvera&rsquo;nın planlarını &ouml;ğrenmesi i&ccedil;in casusluğa yollar. Calvera ve adamları ormanda toplanmışlardır. On kadar adamını yitirmiş olan &ccedil;ete hın&ccedil;la doludur. Chico onlarınkine benzer bir kıyafetle aralarına sızar. Onun bir yabancı olduğunu Calvera dahi fark etmemiştir. Calvera, hala daha kalabalık olduklarını ve &ouml;len adamlarının kanlarını yerde bırakmayacaklarını s&ouml;yler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>OKA</span></i></b><span>&rsquo;nın k&ouml;t&uuml; adamı Gregorias ise, ilk &ccedil;atışmadaki yenilginin ardından &ouml;fkeli halde bekleyen grubuna, yine ormanda toplandıklarında, saldırılara devam edip, k&ouml;y&uuml;n şehirle irtibatını keseceklerini ve a&ccedil; ve &ccedil;aresiz bırakarak k&ouml;yl&uuml;leri oradan &ccedil;ıkmaya zorlayarak &ouml;ld&uuml;receklerini s&ouml;yler. Bu s&uuml;re&ccedil;te kendilerine erzak ve m&uuml;himmat da geleceğini ve daha da g&uuml;&ccedil;leneceklerini ekler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmdeki karakterler&nbsp;<b><i>TMS</i></b>&rsquo;dekilerle &ccedil;ok&ccedil;a karışmakta aslında. Bu da normal, &ccedil;&uuml;nk&uuml; karakter sayısını ona &ccedil;ıkardığınızda, ister istemez bir karakteri diğer filmdeki birka&ccedil; karaktere dağıtmak durumunda kalırsınız. Lee&rsquo;nin karakteri Karanfilli, İdamlık ve Konyak&ccedil;ı arasında, film boyunca &ccedil;ok az konuşan Britt&rsquo;in karakteri ise Konyak&ccedil;ı ve K&uuml;rt Mahmut arasında paylaştırılmış. Lee, s&uuml;rekli g&ouml;rd&uuml;ğ&uuml; kabuslar ve tedirgin halleriyle İdamlık&rsquo;a, s&uuml;s&uuml;ne d&uuml;şk&uuml;nl&uuml;ğ&uuml;yle de Karanfilli&rsquo;ye ilham vermiş. Lee&nbsp;<b><i>TMS</i></b>&rsquo;de korkak ve problemli olarak yorumlanıyor, ancak bizim filmde elbette korkaklara yer yok! Britt, bı&ccedil;ak kullanmaktaki ustalığını ve umursamaz tavırlarını K&uuml;rt Mahmut&rsquo;a &ouml;d&uuml;n&ccedil; verirken, suskun tavrı ve ataklığı Konyak&ccedil;ı&rsquo;ya kalıyor. Konyak&ccedil;ı&rsquo;nın ağzından ayırmadığı konyak şişesi Lee&rsquo;den hatıra.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İdamlık&rsquo;ın kabustan uyanma sahnesine benzer bir olayı Lee de yaşar. Yatmakta olduğu yatağında, bir elinde i&ccedil;ki testisi, kabus g&ouml;rmekte ve sayıklamaktadır. Birden korkuyla uyanır. G&uuml;r&uuml;lt&uuml;ye koşan iki k&ouml;yl&uuml;, onu yatıştırmaya &ccedil;alışır. Lee kendisine geldikten sonra, hipnoza girmiş gibi, i&ccedil;ini d&ouml;ker. Aslında orada bulunması, d&uuml;şmanlarından ka&ccedil;tığı i&ccedil;indir. Oraya aslında saklanmak i&ccedil;in geldiğini ve artık eskisi kadar hızlı olmadığını k&ouml;yl&uuml;lere itiraf eder. Benzer bir itirafı İdamlık da Sevda&rsquo;ya yapar: K&ouml;y&uuml;n i&ccedil;inde n&ouml;bet tuttuğu bir sahnede yanına gelen kadına i&ccedil;ini d&ouml;ker. Aslında, eşini &ouml;ld&uuml;rmekle yargılanan bir idam mahkumudur ve su&ccedil;suzdur. Asılmamak i&ccedil;in ka&ccedil;mıştır. Asılarak, bir su&ccedil;lu gibi &ouml;lmektense, Kıbrıs&rsquo;ta savaşarak &ouml;lmeyi tercih eder. O sırada ekibin gerisi, bir ge&ccedil;itte, Rumlara gelecek yardım konvoyunu bastırmak i&ccedil;in pusudadır. Onların yokluğunu fırsat bilen Gregorias, k&ouml;ye gizlice sızar. K&ouml;yl&uuml;lerden bir kısmı kaleye &ccedil;ekilmiştir. Gregorias gafil avladığı İdamlık&rsquo;ı, R&uuml;stem&rsquo;in kız kardeşini ve Sevda&rsquo;yı, k&ouml;yde kalan birka&ccedil; kişiyi daha esir alır. Geri kalanların nerede olduğunu sorar. Hi&ccedil;bir cevap alamayınca bir ağaca ip attırır ve İdamlık&rsquo;ı asacağını s&ouml;yler. Sevda, İdamlık&rsquo;ın &ouml;n&uuml;ne ge&ccedil;meye &ccedil;abalar. İdamlık ipe doğru y&uuml;r&uuml;r ve Sevda&rsquo;yı soğutmak i&ccedil;in ona, &ldquo;Sana yalan s&ouml;yledim. Karımı ben vurdum.&rdquo; der. Ge&ccedil;itte korkusuzların kalan kısmı ve silahlı birka&ccedil; k&ouml;yl&uuml; konvoyu beklemektedir. Nihayet yaklaşan konvoyun &ouml;n&uuml;n&uuml; keser ve &ccedil;atışarak kamyonlardaki t&uuml;m Rum askerlerini vururlar. Y&uuml;kl&uuml; bir silah ganimeti ele ge&ccedil;irmiştirler. Halil k&ouml;yl&uuml;lere, kamyonlarla k&ouml;y&uuml; &ccedil;evirmelerini, kendilerinin de doğruca k&ouml;ye gideceklerini s&ouml;yler. Marşımız, benzeri diğer sahnelerde olduğu gibi, tabii ki burada da &ccedil;almaktadır!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yine buluşma evinde toplanmışlardır. Harry Luck, bir yandan şakalar yaparak, daha &ouml;nceki bir sahnede de yaptığı gibi, k&ouml;yl&uuml;leri sakladıkları değerli şeyler hakkında sorgular. Calvera&rsquo;nın boşuna gelmediğini d&uuml;ş&uuml;nmektedir. Oysa k&ouml;yl&uuml;ler ger&ccedil;ekten fakirdir ve onun d&uuml;ş&uuml;nd&uuml;ğ&uuml; gibi bir durum yoktur! O sırada Chico d&ouml;ner. Calvera ve adamlarının beş parasız ve a&ccedil; olduklarını ve yeni bir saldırı i&ccedil;in hazırlandıklarını anlatır. K&ouml;yl&uuml;lerden bazıları korkmuş, telaşlanmıştır. Calvera&rsquo;ya her şeylerini verip kendilerini affetmesini istemeyi &ouml;nerirler ve yedilinin bir an &ouml;nce gitmesini isterler. Ama m&uuml;cadeleye devam etmek isteyen k&ouml;yl&uuml;ler &ccedil;oğunluktadır ve son s&ouml;z&uuml; Chris s&ouml;yler: &ldquo;Pes eden kişinin mezarı hemen kazılır!&rdquo; Bu toplantının ardından ayrı bir evde bir araya gelen ekip, k&ouml;yl&uuml;n&uuml;n cesaretsizliği ve k&ouml;y&uuml; korumaktaki isteksizliği, &ccedil;atışmalarda yedilinin yanında olmaması &uuml;zerine tartışır. Calvera&rsquo;nın tepkisi k&ouml;yl&uuml;lerden onların &uuml;st&uuml;ne d&ouml;nm&uuml;şt&uuml;r. Kimileri, zamanında &ccedil;ekilmenin ve k&ouml;yden bir an evvel kurtulmanın en iyi se&ccedil;enek olduğunu s&ouml;yler. Chris ise bir anlaşma yaptıklarını ve buna sonuna kadar bağlı kalacaklarını s&ouml;yleyerek noktayı koyar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Chico, bah&ccedil;ede k&ouml;yl&uuml; kıza yaşadığı macerayı anlatmaktadır. Nasıl cesaretle kılık değiştirip Calvera&rsquo;nın adamlarının arasına karıştığından ve yaşadıklarından sonra artık diğer silahş&ouml;rler gibi olduğundan bahseder. Amacı kendisine ilgi duymaya başlayan kızı kendinden uzaklaştırmaktır. Onlardan biri olduğunu ve gidecekleri zaman onlarla ayrılacağını, k&ouml;ye bağlanıp bir &ccedil;ift&ccedil;i olamayacağını s&ouml;yler. Ama kız onu dinlemez ve &ouml;per. Chris, k&ouml;yl&uuml;lere bir masanın başında planını anlatır. Calvera&rsquo;ya saldıracak ve en azından atlarını ka&ccedil;ırtacaklardır. Bu toplantının hemen ardından ekip yola &ccedil;ıkar. Calvera&rsquo;nın kampına vardıklarında, haydutların t&uuml;m&uuml;n&uuml;n oradan ayrılmış olduğunu g&ouml;r&uuml;rler. K&ouml;y&uuml;n dışına pusu kurmuş olan Calvera, yedilinin k&ouml;yden ayrılmasını fırsat bilip i&ccedil;eriye girmiş ve k&ouml;y&uuml; ele ge&ccedil;irmiştir. Yedili k&ouml;ye girer girmez etrafları Calvera&rsquo;nın adamları tarafından kuşatılır. Calvera Chris&rsquo;e, &ouml;lmekten başka se&ccedil;enekleri de olduğunu s&ouml;yler ve onu konuşmaya davet eder. Ona k&ouml;yl&uuml;leri fazla karar vermeye zorlayarak bunalttığını, kendisinin ise onlara sadece tek karar hakkı verdiğini, bu y&uuml;zden kendisini tercih ettiklerini s&ouml;yler. Korkak k&ouml;yl&uuml;lerden biri, Calvera&rsquo;yı i&ccedil;eriye sokmuştur. Calvera yediliyi serbest bırakacaktır. Yapmaları gereken sadece silahlarını bırakmaktır. Chris silahını teslim edince, ekibin diğer &uuml;yeleri de sırayla silahlarını bırakır. Sadece Chico kahramanlık yapmaya yeltenir ama Chris&rsquo;in tepkisiyle karşılaşır ve o da silahını verir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ele ge&ccedil;irdikleri silahlarla k&ouml;ye d&ouml;nen on korkusuzun sekizi, kendilerini bekleyen s&uuml;rprizden habersizdir. K&ouml;y&uuml;n meydanına vardıklarında, İdamlık&rsquo;ın ağa&ccedil;ta sallanan cesediyle karşılaşırlar. K&ouml;yde mevzilenmiş olan Gregorias ve adamları uygun anı beklerken, ellerinden kurtulan R&uuml;stem&rsquo;in kız kardeşi, ka&ccedil;maları i&ccedil;in bağırır. Gruplar arasında kıyasıya bir &ccedil;atışma başlar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yedili toparlanmaya başlamıştır. Chris ve Vin k&ouml;yl&uuml;y&uuml; umursamış olmaktan dolayı &uuml;z&uuml;nt&uuml;l&uuml;d&uuml;rler. O&rsquo;Reilly yanına gelip onunla gitmek istediklerini s&ouml;yleyen ve kendi babalarını su&ccedil;layan &ccedil;ocukları azarlar. Silahının kendisini &ccedil;ocukların babalarından daha cesur yapmadığını, onların ailelerinin sorumluluğunu taşımakla asıl cesareti g&ouml;sterdiklerini anlatır. K&ouml;yden ayrılıp yola koyulan ekibe eşlik eden haydutlar, yeterince uzaklaştıklarında yediliye silahlarını geri verir ve d&ouml;nerler. Ancak, yedili hen&uuml;z tamamen vazge&ccedil;miş değildir. Silahlarını yeniden kuşanan ekibin altısı, geri d&ouml;n&uuml;p m&uuml;cadele etme fikrinde birleşir. Onları delilikle su&ccedil;layan ve terk eden kişi ise, aslında &ccedil;ıkarcı bir karakteri olan Harry Luck&rsquo;tır. Ama dayanamayıp geri d&ouml;nen ve &ccedil;atışmada yediliden ilk &ouml;len de o olacaktır. Yedilinin k&ouml;ye girmesiyle m&uuml;thiş bir &ccedil;atışma başlar. Kazma, k&uuml;rek, balta, bulabildikleri ne varsa eline ge&ccedil;iren k&ouml;yl&uuml;ler de kavgaya girer. K&ouml;t&uuml; adamların hepsi &ouml;ld&uuml;r&uuml;l&uuml;r, ama &ccedil;atışmada bazı k&ouml;yl&uuml;ler ve yedilinin d&ouml;rd&uuml; de kaybedilir. Geriye sadece Chris, Vin ve Chico kalmıştır. K&ouml;yl&uuml;lerle vedalaşırlar, ancak ayrılırlarken sevdiği kıza veda edemeyeceğini anlayan Chico geri d&ouml;ner ve yedilinin ikisi ufka doğru at s&uuml;rer.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ccedil;atışmada, Halil ve R&uuml;stem hari&ccedil;, onlunun kalan t&uuml;m &uuml;yeleri teker teker can verir. Bu &ouml;l&uuml;mlerden &ouml;zellikle K&uuml;rt Mahmut&rsquo;unki,&nbsp;<b><i>TMS</i></b>&rsquo;deki O&rsquo;Reilly&rsquo;nin &ouml;l&uuml;m&uuml;yle paralellik taşıyor. O&rsquo;Reilly, kendisine koşan &ccedil;ocukları &ccedil;atışmaktan uzaklaştırmaya &ccedil;alışırken vurulur. K&uuml;rt Mahmut da, &ccedil;atışmanın ortasında kalan k&uuml;&ccedil;&uuml;k Ali&rsquo;yi korumak i&ccedil;in kucağına alır ve onu g&uuml;venli bir yere g&ouml;t&uuml;rmek ister. Bizimkinde bu sahne, normal olarak, fazlaca bize &ouml;zg&uuml;d&uuml;r: Arkadan peş peşe kurşun yiyen Mahmut, bir kez dahi sendelemeden, y&uuml;z&uuml; acıyı yansıtsa da &ccedil;ocuğa hep g&uuml;l&uuml;mseyerek, kamera onu &ouml;nden &ccedil;ekerken ilerler ve &ccedil;ocuğu kurtarır, &ouml;yle can verir. Konyak&ccedil;ı da yine bize &ouml;zg&uuml; bir sahnede, sevdiği kız vurulunca başına &ccedil;&ouml;ker ve onu severken arkadan haince vurulur. Bir de Karanfilli&rsquo;nin &ouml;l&uuml;m sahnesi ilgin&ccedil;. &Ccedil;atışmada &ccedil;i&ccedil;eği ezilen Karanfilli, yerden yeni bir &ccedil;i&ccedil;ek koparır, yakasına g&ouml;t&uuml;r&uuml;rken vurulur. O esnada yetişen Konyak&ccedil;ı da ateş edeni vurur ama ge&ccedil; kalmıştır. Birbirlerine g&uuml;l&uuml;mserler ve Konyak&ccedil;ı, yere d&uuml;şen &ccedil;i&ccedil;eği alıp Karanfilli&rsquo;nin yakasına koyar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>OKA</span></i></b><span>&rsquo;da da baş k&ouml;t&uuml;n&uuml;n &ouml;l&uuml;m&uuml;&nbsp;<b><i>TMS</i></b>&rsquo;deki gibi, esas oğlanın yani ekibin liderinin elinden olur. Konyak&ccedil;ı Gregorias&rsquo;ı tam sıkıştırmışken Halil gelir ve kendisine bırakmasını s&ouml;yler. Silahındaki kurşunların t&uuml;m&uuml;n&uuml; Gregorias&rsquo;ın &uuml;st&uuml;ne boşaltır. Geriye kalan R&uuml;stem, kız kardeşi ve Halil, silahlanan k&ouml;yl&uuml;yle birlikte kaleye &ccedil;ekilir. Kaleyi sonuna kadar savunmaya kararlıdırlar ama sayıları da azdır. Son anda T&uuml;rk jetlerinin g&uuml;r&uuml;lt&uuml;s&uuml; duyulur ve film marşlarla ve T&uuml;rk Kuşu&rsquo;nun g&ouml;sterileriyle biter!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>,&nbsp;<b>Akira Kurosawa</b>&rsquo;nın&nbsp;<b><i>Seven Samurai&nbsp;</i></b>filminin &ouml;yk&uuml;, form&uuml;l ve hatta diyaloglarının bazılarını tekrar ederken dahi, bir western olarak kendine &ouml;zg&uuml; unsurları filme nasıl yediriyorsa,&nbsp;<b><i>OKA</i></b>&nbsp;da bize &ouml;zg&uuml; &ouml;zellikleriyle zaman zaman&nbsp;<b><i>TMS</i></b>&rsquo;den ayrılmayı başarıyor. Bu farklar daha &ccedil;ok oyuncuların kendi tarzlarından ortaya &ccedil;ıkıyor belki, ama vatanseverliğe yapılan vurgu ve milliyet&ccedil;i s&ouml;ylem bizim filme başka bir hava katıyor. Diğer iki filmde ise, kahramanlarımızın genel olarak aradığı şey macera! Bizimkindeki milliyet&ccedil;i vurgular, ne yazık ki filmin lehine işlemiyor ve hikayede yer yer kopukluk yaratıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Elmer Bernstein</span></b><span>&rsquo;ın&nbsp;<b><i>TMS</i></b>&nbsp;i&ccedil;in yaptığı m&uuml;zik, sinema tarihinin en başarılı film m&uuml;ziklerinden biri olarak kabul ediliyor ve duyulduğunda hemen tanınıyor, akılda kalıyor.&nbsp;<b><i>OKA</i></b>&rsquo;da ise, d&ouml;nemindeki diğer yerli filmlerdeki gibi, orijinal m&uuml;zik kaygısı yok ve tutarlı bir m&uuml;zik yapısı da yok elbette. Coşkulu anlarda marşlar ve diğer anlarda da &ccedil;eşitli Amerikan yapımların m&uuml;zikleri &ccedil;alınıyor. Ama bu tuhaf karışımın da o zamanki yerli filmleri &ccedil;ekici kılan unsurlardan olduğu bir ger&ccedil;ek!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>&rsquo;de oynayan akt&ouml;rlerin sadece biri filmin &ccedil;ekildiği d&ouml;nemde stardı: O da&nbsp;<b>Yul Brynner</b>&rsquo;di. Kalanların &ccedil;oğu sonradan kendi başlarına birer yıldız haline geleceklerdi.&nbsp;<b><i>OKA</i></b>&rsquo;dakilerin ise,&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;hari&ccedil;, diğerlerinin t&uuml;m&uuml; o d&ouml;nemde hatırı sayılır pop&uuml;lariteye sahiptiler. Ama film en &ccedil;ok da&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;e yaradı. Tabi,&nbsp;<b>G&uuml;ney</b>&nbsp;de filme.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>TMS</span></i></b><span>&rsquo;de, &uuml;lkesi dışında, farklı bir &uuml;lkenin insanlarını kurtarmak i&ccedil;in &ccedil;arpışan silahş&ouml;rler, Amerika&rsquo;nın sonraki yıllarına işaret eder gibidir. Bug&uuml;n de Amerika, kendisinin hi&ccedil;bir şekilde ilgili olmadığı savaşlara dahil olmaya devam etmektedir.<b><i>OKA</i></b>&nbsp;ise, zul&uuml;m g&ouml;ren T&uuml;rkler i&ccedil;in m&uuml;cadele eden T&uuml;rkleri hikaye ediniyor.<b>Sturges</b>&rsquo;in filmi westernin kahramanlık temalarıyla dalgasını ge&ccedil;ebiliyor, hatta silahş&ouml;rlerden birini, Lee&rsquo;yi filmin son &ccedil;atışma sahnesine kadar, katıksız bir korkak olarak g&ouml;r&uuml;r&uuml;z.&nbsp;<b>Başaran</b>&nbsp;ise, bir Kıbrıs M&uuml;cadelesi filmi yapmaya soyunmuştur ve kahramanlardan hi&ccedil;birine b&ouml;yle bir konum verme şansı yoktur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Kahramanların belirgin tik ve kıyafetlerle simgelenmesi durumu,&nbsp;<b><i>OKA</i></b>&rsquo;da da vardır. &Ouml;rneğin, Konyak&ccedil;ı s&uuml;rekli olarak i&ccedil;kisinden yudumlar, başındaki kovboy şapkasını kaşının &uuml;st&uuml;nden pek kaldırmaz; K&uuml;rt Mahmut&rsquo;un dudaklarındaki tik abartılmıştır; Karanfilli, kavganın en doruk noktasında dahi yakasına takacak &ccedil;i&ccedil;ek arar; Veremli Suphi sık sık mendilini &ccedil;ıkarır ve kan t&uuml;k&uuml;r&uuml;r. Bizdeki bu &ouml;zellikler, sinemamızda genelde alışkın olduğumuz bir tarzda, sık kullanılmaktadır. Bu zaman zaman g&ouml;ze batmakla birlikte, şaşılacak şekilde filmin lehine işlemektedir. Karakterler ister istemez akılda kalmakta, filmin sahne sahne hatırlanmasına neden olmaktadır.<b><i>TMS</i></b>&rsquo;de elbette bu derecede şişirilmemektedir karakterler. Tedirgin hareketleriyle Lee ve &ccedil;ılgınlıkları, kaynayan kanıyla Chico belki.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Tun&ccedil; Başaran</span>&nbsp;</b><span>&nbsp;filminin başarısının &uuml;zerine, hemen ertesi yıl,&nbsp;<b>G&uuml;ney</b>&rsquo;i &ouml;d&uuml;llendirircesine ve onun &ouml;n&uuml;n&uuml; a&ccedil;an bir hamle yaparak, Konyak&ccedil;ı&rsquo;nın kendi macerasını &ccedil;eker. 1965&rsquo;te de, yine benzer bir &ouml;yk&uuml;y&uuml; anlatan&nbsp;<b><i>On Korkusuz Kadın</i></b>&rsquo;ı yapacaktır.&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;ise, &ccedil;ok sevdiği belli olan temayı&nbsp;<b><i>Yedi Belalılar</i></b>&rsquo;da (<b>Yılmaz G&uuml;ney</b>, 1970) ve&nbsp;<b><i>&Ccedil;irkin ve Cesur</i></b>&rsquo;da (<b>Nazmi &Ouml;zer</b>, 1971) da kullanır.&nbsp;<b><i>Yedi Belalılar</i></b>&nbsp;orijinale sadık kalarak kahraman sayısını yedide tutup, kullanılan kıyafetler ve &ccedil;atışma sahnelerinin kurgusuyla westerne&nbsp;<b><i>OKA</i></b>&rsquo;dan daha yakın dururken, silahş&ouml;r sayısının teke indiği&nbsp;<b><i>&Ccedil;irkin ve Cesur</i></b>&rsquo;da daha &ccedil;ok spaghetti western havası hakimdir.&nbsp;<b><i>Konyak&ccedil;ı</i></b>&rsquo;yı &ccedil;ok istediğim halde, kayıp bir film olduğu i&ccedil;in izleyemedim. Ama hikayenin bizde&nbsp;<b><i>Vadiler Aslanı</i></b>&nbsp;olarak bilinen&nbsp;<b><i>Shane&nbsp;</i></b>(<b>George Stevens</b>, 1953) filminden alındığını biliyoruz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir daha bir araya gelmeleri m&uuml;mk&uuml;n olmayacak olan ilgin&ccedil; kadrosuyla&nbsp;<b><i>On Korkusuz Adam</i></b>&rsquo;ı mutlaka g&ouml;r&uuml;n derim.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Kaynaklar:</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>- T&uuml;rk Sinema Tarihi (Scognamillo)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>- Sokaktaki Adam ya da Yılmaz G&uuml;ney (Agah &Ouml;zg&uuml;&ccedil;, Sinema 65, Temmuz 1965.)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>- Yılmaz G&uuml;ney Westerni (İlker Mutlu, Sinema, Aralık 2003)</span></span></p>', 20, 63, 'Yazarlarımızdan', '/images/yazilar/dr_nihat_%20olayi.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (41, 'ay-j162', 'hayallerin-pesinde-durmak', 'Hayallerin Peşinde Durmak', 'Burcu Atahan', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 15pt;"><span style="font-family: Verdana;">Hayallerin Peşinde Durmak</span></span></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Burcu Atahan</span></b></span><br />&nbsp;</p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: 10pt; font-family: Verdana;">Mezopotamya Denizi (M&eacute;hak)</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: 10pt; font-family: Verdana;">Y&ouml;netmen:&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana;">Erdim Dalgı&ccedil;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: 10pt; font-family: Verdana;">2006/10&rsquo;/T&uuml;rkiye</span><span style="font-size: 10pt; font-family: Verdana; color: #818386;"></span></b></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="40%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-family: Verdana;"><span style="font-size: x-large;">M</span></span><span style="font-size: 10pt; font-family: Verdana; color: black;">ezopotamya Denizi&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana; color: black;">yaşadığı y&ouml;renin ger&ccedil;ekleri ile kendi hayalleri arasında sıkışmış bir kadının ger&ccedil;ekleri kabullenerek yaşamını s&uuml;rd&uuml;rme &ccedil;abasının anlatmakta. İ&ccedil;ine doğduğumuz d&uuml;nyayla kuşatılmışlığımızın bire bir resmini &ccedil;izmiştir&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana; color: black;">Erdim Dalgı&ccedil;</span></b><span style="font-size: 10pt; font-family: Verdana; color: black;">. İşte bu noktada Mezopotamya Denizi hayallerin ger&ccedil;ekleşip ger&ccedil;ekleşmeme ayrımında bizlerden bağımsız davrandığını ortaya koyar. &Ccedil;&uuml;nk&uuml; insan doğada tek başına var olan bir varlık değildir. Ne &ccedil;evresinden ne yaşadığı y&ouml;reden kendini soyutlayarak var olamaz. Kendini tanımladığı, &ldquo;ben&rdquo;i g&ouml;rd&uuml;ğ&uuml; yer &ldquo;&ouml;teki&rdquo;dir. &ldquo;&Ouml;teki&rdquo;, &ldquo;ben&rdquo;i d&ouml;n&uuml;şt&uuml;recek benzeştirecek olandır. Dolayısıyla &ldquo;ben&rdquo; ya uyum sağlayacak ya da &ccedil;atışacaktır. &Ccedil;atışma ise dışlanmayı ve yok olmayı getirir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana; color: black;">Filmdeki kadın kahramanımız hayalleri i&ccedil;in m&uuml;cadele etmemeyi se&ccedil;er. Hadra k&uuml;&ccedil;&uuml;kken, uzakta olan babasının g&ouml;nderdiği resimdeki g&ouml;ky&uuml;z&uuml;n&uuml; deniz sanır. O g&uuml;n bir tutku &ouml;yk&uuml;s&uuml;n&uuml;n başladığı g&uuml;n olur. Hayali bir kez olsun denizi g&ouml;rmektir. Yıllar sonra g&uuml;vercinler aracılığıyla haberleştiği adam onu denize g&ouml;t&uuml;rme vaadiyle kandırır. Akşam deniz olarak g&ouml;rd&uuml;ğ&uuml; yerin sabah u&ccedil;suz bucaksız bir ova olduğunu g&ouml;ren Hadra&rsquo;nın hayalleri yerle bir olur. Bu ova Mezopotamya Denizi olarak ge&ccedil;en Mardin Ovası&rsquo;dır. Yıllarca bu ovaya denizmiş gibi bakan Hadra&rsquo;ya, zamanında annesinin s&ouml;ylediği &ldquo;sen kendi i&ccedil;indeki denize kulak ver&rdquo; s&ouml;z&uuml; Mezopotamya Denizi&rsquo;nin eskiden bir i&ccedil; deniz olmasıyla birleşince Hadra&rsquo;nın i&ccedil;indeki denizi bulduğuna inanabiliriz.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana; color: black;">Peki, i&ccedil;indeki denizi bulmak hayallerini ger&ccedil;ekleştirmekle eşdeğer midir? Hadra&rsquo;nın kızının yaptığı resme tersten bakması ve kızına da tersten bakmanın bazen doğru bakmaktan &ccedil;ok daha iyi olacağını s&ouml;ylemesi insanı kuşkuya d&uuml;ş&uuml;r&uuml;r. Kızı hayallerinin peşinden mi gitmelidir? Yoksa o da kendisi gibi değişmez kanunları kabullenerek ovayı deniz gibi g&ouml;r&uuml;p kaderine boyun mu eğmelidir? Bu sanki &ldquo;burada yaşadığın s&uuml;rece zaten hayallerini ger&ccedil;ekleştiremeyeceksin o y&uuml;zden mutlu olmak i&ccedil;in hayata başka t&uuml;rl&uuml; bakman gerekiyor&rdquo; demenin &uuml;st&uuml; &ouml;rt&uuml;l&uuml; ifadesidir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana; color: black;">Hadra&rsquo;nın ve annesinin kurduğu ailenin ilişkilerine baktığımızda: Hadra&rsquo;nın annesiyle babasının ilişkisinde aileden uzakta bir erkekle evin b&uuml;t&uuml;n sorumluluğunun kadına y&uuml;klenmişliği dikkat &ccedil;ekerken kendi eşiyle ilişkisinde evde ailesinin yanında ilgili-sıcak bir yaklaşımı olan ve eşiyle aynı y&ouml;ne bakan bir erkek vardır. Her ne kadar nesiller arası değişim bu iki aile ilişkisinde fark edilse de bu değişim evlerin duvarlarıyla da kendini g&ouml;stermektedir. Annesinin yaşadığı evin duvarları; duvarların arkasını g&ouml;rmenin neredeyse olanaksız olduğu bir y&uuml;kseklikteyken Hadra&rsquo;nın evinin duvarları dışarıyı rahat&ccedil;a g&ouml;rebilecek y&uuml;ksekliktedir. Tabii bu fark bile eve hapsolmuş duvarlar arasında sıkışmış kadınlar olmalarını değiştirmemektedir. Nitekim bunu Hadra&rsquo;nın deniz sandığı şeyin ova olduğunu g&ouml;rd&uuml;ğ&uuml;m&uuml;z sabahki evden anlayabiliriz. Ev tamamen demirlerle &ccedil;evrilidir, pencereler kapılar demirdir. Hadra bir adama ka&ccedil;mıştır ve onunevine adım attığı an tutsaklığı başlamıştır. Bu kuşatılmışlıktan sıyrılma şansı yoktur. Yazgısını kabullenmelidir. Oradaki b&uuml;t&uuml;n kadınlar ve yazgıları Hadra&rsquo;yla annesinde v&uuml;cut bulmuşlardır. Yani kuşaklar arasında ne kadar d&ouml;n&uuml;ş&uuml;m olursa olsun sabit kalan ve aslında hi&ccedil;bir değişime olanak tanımayan şeyler vardır. &Ccedil;&uuml;nk&uuml; bu y&ouml;redeki kadın belli kuralların i&ccedil;ine doğmuştur. Aynı şey erkekler i&ccedil;in ge&ccedil;erli olsa bile kadını sarmalayan zincirler kırılması daha zor olanlardır. Ve Hadra kızına kendi &ouml;yk&uuml;s&uuml;n&uuml; anlatır bir masalmış gibi. Bu masalsılık ise Doğu&rsquo;nun gelenek miras&ccedil;ılığını masallarla yaptığının,her şeyin masallarla meşrulaştırıldığının ve olağanlaştırılmaya &ccedil;alışıldığının g&ouml;stergesidir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana; color: black;">Bir nebze umutlanmamızı ve hayallerimize tutunmamızı sağlayansa Hadra&rsquo;nın hayallerininger&ccedil;ekleşeceğini d&uuml;ş&uuml;nd&uuml;ğ&uuml; g&uuml;n deniz resmini yanına almasıdır.</span></p>', 191, 63, 'Yazarlarımızdan', NULL, '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (42, 'ay-j163', 'mamma-magnani', 'Mamma Magnani', 'Gökhan Erkılıç', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Mamma Magnani</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>G&ouml;khan Erkılı&ccedil;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">&nbsp;<img src="/images/yazilar/magnani1.jpg" alt="" width="263" height="345" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İtalya&rsquo;nın Roma kentinde 7 Mart 1908 g&uuml;n&uuml; başlayan ve 26 Eyl&uuml;l 1973 g&uuml;n&uuml; sonlanan bir yaşam... Anna Magnani... İtalyan sinemasının oyunculuk tarihinin arızalı hallerinden birine eğilmek, &ouml;ncelikle bu a&ccedil;ıklanması zor &ccedil;ekim g&uuml;c&uuml;n&uuml;n ardındaki &ouml;yk&uuml;y&uuml; a&ccedil;ığa &ccedil;ıkarmayı gerekli kılıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Annesi tarafından g&ouml;zden &ccedil;ıkarılmış bir kenar mahalle &ccedil;ocuğu olmasının getirisi, &ccedil;ocuk yaşlardan başlayarak başının &ccedil;aresine bakmayı &ouml;ğrenmek oldu. Dipten başladığı hayata karşı duyduğu &ouml;fke ve onulmaz hırsı beklentilerini y&uuml;kseltti ve sahneyi hedefledi. 1926&rsquo;da sahneye &ccedil;ıkmaya ve gece kul&uuml;plerinde şarkı s&ouml;ylemeye başladı. Roma Dramatik Sanatlar Akademisi&rsquo;nde aldığı eğitim, akışına bırakılmış izlenimi veren kariyerine hatırı sayılır bir ivme kazandırdı. Eğitimin verdiği g&uuml;ven kontrols&uuml;z başarı a&ccedil;lığıyla birleşince y&uuml;kseliş de başlar. 1935 yılında y&ouml;netmen&nbsp;<b>Goffredo Alessandrini</b>&nbsp;ile ger&ccedil;ekleştirdiği evliliğin sekt&ouml;re girmesinde belli bir &ouml;l&ccedil;&uuml;de rol oynadığını da yadsımamak gerekir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinema oyunculuğuna &ndash;1928&rsquo;de &ccedil;ekilen bir&nbsp;<b>Augusto Genina</b>&nbsp;sessizi olan&nbsp;<b><i>Scampolo</i></b>&nbsp;ve bu filmde g&ouml;r&uuml;nmesi dikkate alınmadığından olsa gerek-<b>&nbsp;Nunzio Malasomma</b>&rsquo;nın 1934 yapımı&nbsp;<b><i>La Cieca di Sorrento</i></b>&nbsp;filmiyle başlamış ve zamanla alışacağımız &ouml;zg&uuml;n tipine tam oturmasa da karakter gelişiminde bir adım olarak nitelendirebileceğimiz 1941 yapımı&nbsp;<b><i>Teresa Venerdi</i></b>&nbsp;filminde yoluna&nbsp;<b>Vittorio de Sica</b>&nbsp;&ccedil;ıkmış olsa da, sevgilisi olduğu&nbsp;<b>Roberto Rossellini</b>&rsquo;nin&nbsp;<b><i>Roma Citta Aperta</i></b>filmine bir umut beslenen olarak başlar ve bir onanmış oyuncu olarak noktayı koyar. Ancak halkın sempati dağarcığındaki y&uuml;kselişi burada kesilmez; Pina d&uuml;nyayı dolaşıp y&uuml;rekler kazandık&ccedil;a&nbsp;<b>Magnani</b>&nbsp;sevgisi artar. Hayatı boyunca a&ccedil;lık &ccedil;ektiği sevgi, ilgi ve başarı konusunda ulaştığı doruk noktalarından ilkini yaşamaktadır. Bu s&uuml;recin doğal bir sonucu olarak, &ouml;nce&nbsp;<b>Alberto Lattuada</b>&rsquo;nın 1946 yapımı&nbsp;<b><i>Il Bandito</i></b>&rsquo;sunun Lidia&rsquo;sı olarak onurlandırılır ve ardından da&nbsp;<b>Luigi Zampa</b>&nbsp;y&ouml;netiminde &ccedil;ektiği ve senaryosuna da bulaştığı 1947 yapımı&nbsp;<b><i>L&rsquo;Onorevole Angelina</i></b>&nbsp;filmindeki rol&uuml;yle aynı yılın Venedik FF&rsquo;nde en iyi aktris &ouml;d&uuml;l&uuml;n&uuml; kazanır. Bir yıl sonra &ccedil;ekilen&nbsp;<b><i>L&rsquo;Amore</i></b>&nbsp;filminde yine&nbsp;<b>Rossellini</b>&rsquo;nin kanatları altındadır. Filmin&nbsp;<b><i>La Voce Umana</i></b>&nbsp;episodunda kamera y&uuml;z&uuml;ndeki en ufak duyu değişimlerini yakalarken, antolojilere malzeme sağlamak i&ccedil;in oynuyor gibidir. Unutmayalım ki,&nbsp;<b><i>Germania Anno Zero</i></b>&rsquo;nun (1947) &ccedil;alışmalarını bitirip Almanya&rsquo;dan d&ouml;nerlerken,&nbsp;<b>Rossellini</b>&rsquo;nin artık onu taşıyamayacağını bilen bir<b>Magnani</b>&nbsp;vardır. Perdeye yansıyan umut, istek, acı ve &ouml;zlem&nbsp;<b>Magnani</b>&rsquo;nin duygusal dengesizlikleri &uuml;zerine g&uuml;&ccedil;l&uuml; kanıtlar sunar. Anlaşılan, bizim g&ouml;rd&uuml;klerimiz yırtılan bir personadan ortalığa sa&ccedil;ılan g&ouml;lgenin izleridir.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/magnani3.jpg" alt="" width="390" height="294" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>1950&rsquo;li yıllar Magnani&rsquo;nin y&ouml;netmenler &uuml;zerindeki &ccedil;ekiciliğinin uluslararası bir kimliğe b&uuml;r&uuml;nd&uuml;ğ&uuml; yıllar olacaktır. Onunla &ccedil;alışmak konusunda saplantılı isimlerin &ouml;nde gelenlerinden biri olan&nbsp;<b>Luchino Visconti</b>, y&uuml;kselen yıldızın filmografisine en &ouml;nemli katkılardan birini&nbsp;<b><i>Bellissima</i></b>&nbsp;(1951) ile verir. Sıradan sezgileriyle &ouml;n&uuml;n&uuml; g&ouml;rmeye ve kızına parlak bir gelecek kurmaya &ccedil;alışan Maddalena, &ouml;zellikle &ccedil;enesi d&uuml;şt&uuml;ğ&uuml; anlarda Magnani&rsquo;nin kendi varoluş bi&ccedil;iminden derin esinler taşır. Oyuncuyla yeniden &ccedil;alışmak isteyen&nbsp;<b>Visconti</b>&rsquo;nin &ouml;n&uuml;ne&nbsp;<b><i>La Carrosse d&rsquo;Or&nbsp;</i></b>(1953) projesi &ccedil;ıkar ama yapımcılar son anda kendi vatandaşları&nbsp;<b>Jean Renoir</b>&rsquo;da karar kılarlar. Camilla paylaşılamayan bir kadın olarak kendini sınıfsal değerlerin g&ouml;lgesi altında yaşanan aşkları sorgularken bulur. B&uuml;y&uuml;k sınıfların k&uuml;&ccedil;&uuml;k aşklarının albenisi, Magnani/Camilla&rsquo;nın sanata duyduğu aşkın yanında s&ouml;n&uuml;k kalacaktır. Ardından yine&nbsp;<b>Visconti</b>...&nbsp;<b><i>Siamo Donne</i></b>&rsquo;nin (1953) yıldızın adını taşıyan episodu karşımıza sinirli, işini bilir ve bildiğini okuyan bir Magnani portresi &ccedil;ıkarır. G&uuml;nl&uuml;k yaşamının kalıplaşmış tutumlarıyla oyuncu kimliğinin dışavurumlarının &ouml;rt&uuml;şmesine bir kez daha tanıklık ederiz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/magnani4.jpg" alt="" width="311" height="250" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Daniel Mann</span>&nbsp;</b><span>&nbsp;y&ouml;netiminde &ccedil;evirdiği&nbsp;<b><i>The Rose Tattoo</i></b>&nbsp;(1955) filmi ile Amerikan sinemasında boy g&ouml;sterir ve eşinin &ouml;l&uuml;m&uuml;n&uuml;n ardından hayatını yeniden kurmak isteyen İtalyan asıllı Amerikalı dul g&uuml;zellemesi rol&uuml;yle yılın en iyi kadın oyuncu dalındaki Oscar &ouml;d&uuml;l&uuml;n&uuml; kazanır. Bunu&nbsp;<b>George Cukor</b>&nbsp;y&ouml;netiminde &ccedil;evirdiği ve &uuml;stlendiği Gioia rol&uuml;yle filmi tek başına s&uuml;r&uuml;klemekten aldığı zevkin g&ouml;zlerine vurduğu&nbsp;<b><i>Wild is the Wind</i></b>&nbsp;(1957) ile 1958 Berlin FF&rsquo;nde aldığı en iyi kadın oyuncu &ouml;d&uuml;l&uuml; izler. Ardından&nbsp;<b>Sidney Lumet</b>&rsquo;nin&nbsp;<b><i>Fugitive Kind</i></b>&nbsp;(1959) filmindeki, serseri Brando ile yarışan ka&ccedil;kınlığıyla g&ouml;ze &ccedil;arpar. Oynadığı Lady Torrance rol&uuml;, cinsel a&ccedil;lık &ccedil;eken ve en sonunda istediğini elde eden bir k&uuml;&ccedil;&uuml;k kasaba se&ccedil;kini olarak boşuna sunulmamıştır kendisine. Ancak bu d&ouml;nemin tek başarısı, kanımca rol&uuml;ne ısındığı her halinden belli olan&nbsp;<b><i>Wild is the Wind</i></b>&nbsp;filmindeki performansıdır. &Ouml;ncesi ve sonrasındaki iki filmin yapay b&ouml;nl&uuml;ğ&uuml; Magnani&rsquo;nin filmografisine g&ouml;sterişli eklentiler sağlamaktan &ouml;teye gitmez.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sonrası, 1950&rsquo;lerde seyrekleşmeye başlayan filmlerinden de anlaşılacağı gibi kopuş yıllarıdır. Perdeye yansıyan ve kendisini oynadığı son g&ouml;r&uuml;nt&uuml;leri&nbsp;<b>Fellini</b>&rsquo;nin&nbsp;<b><i>Roma</i></b>(1972) filminde yer alsa da, son &ouml;nemli filmi ama belki de sinema yaşamının da en &ouml;nemli filmi olarak g&ouml;sterilebilecek ve Magnani&rsquo;siz d&uuml;ş&uuml;n&uuml;lmesi olanaksız bir&nbsp;<b>Pasolini</b>&nbsp;filmi olan&nbsp;<b><i>Mamma Roma&nbsp;</i></b>(1962) oldu.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/magnani.jpg" alt="" width="411" height="577" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İ&ccedil;inde bulunduğu ruh halini ve karakterinin gelişimini filmlerinden izlemenin m&uuml;mk&uuml;n olduğu oyunculardan biriydi Magnani. Zafer, ilgi ve onanma a&ccedil;lığı &ccedil;eşitli anı kitaplarından ve belgesellerden &ouml;ğrendiğimiz dizgin tutmaz &ouml;fkesi ve cinsel kışkırtıcılığı ile birleşiyor ve perdeye delişmen bir ruhun ayarı bozuk g&ouml;lgeleri yansıyordu. Zaman zaman oyunculuğunun baskın kadınlık hallerinin altında can &ccedil;ekiştiğine tanık olduğumuz Magnani&rsquo;nin &uuml;st&uuml;n oyun g&uuml;c&uuml;ne kaynaklık eden de aynı olguydu. Buradan noktasız bir &ccedil;atışma s&uuml;reci yaşadığını &ccedil;ıkarabiliriz. İlkellikle ilişkilendirilebilecek tutumlar son derece duyarlı bir yaratıcılığı k&ouml;r&uuml;kl&uuml;yordu.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Geleneksel g&uuml;zellik &ouml;l&ccedil;&uuml;tlerinin ne y&uuml;z&uuml;ne ne de bedenine yansıdığı oyunculardan biriydi Magnani. &Ouml;zdeşleşme kimyasının klasik &ouml;l&ccedil;&uuml;tleri a&ccedil;ısından sınırlı bir kitleye seslendiği de s&ouml;ylenebilir. Ancak bu kitlenin onu ne denli sahiplendiğini de atlamamak gerekiyor. Kendini bu a&ccedil;ıdan seyircinin fantezilerine kapalı tutsa da, y&ouml;netmen ve oyuncuların karakteri bedenine yansıyan bu &ouml;zg&uuml;n kişiliğe ilgisiz kalamadıkları anlaşılıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/magnani5.jpg" alt="" width="523" height="384" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinema kariyerinin dikkate alınır tarafı Yeni Ger&ccedil;ek&ccedil;ilik akımının doğuşuyla başlayan, bir &ccedil;uval dolusu berbat filmin arasında birka&ccedil; &ouml;nemli y&ouml;netmenin elinde yıldızının parladığı filmlerle s&uuml;ren, ardından uluslararası piyasaya seslenen yapımlara uzanan Magnani, b&uuml;y&uuml;k olasılıkla katlanılabilirlik sınırlarını defalarca aşmasının bir sonucu olarak yalnızlığa itildi. Bunun sonucunda filmlerin arasına yıllar girmeye ve yeteneğini yansıtmaktan uzak soluk bir filmografi oluşmaya başladı. O solukluk yıldızını da k&ouml;reltti. &Uuml;zerinde durulmaya değer filmlerinin sayısı bir elin parmakları ile sınırlı olsa da, unutulmasını engellemeye yettiler.&nbsp;<b>Chris Vermorcken</b>&rsquo;in&nbsp;<b><i>Io Sono Anna Magnani</i></b>&nbsp;(1980) ve&nbsp;<b>Sandro Lai</b>&rsquo;nin&nbsp;<b><i>Anna Magnani</i></b>&nbsp;(2002) belgeselleri onu daha yakından tanımak isteyenlere sesleniyor.</span></span></p>', 45, 63, 'Yazarlarımızdan', '/images/yazilar/magnani1.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (43, 'ay-j164', 'unutulmuslugu-yenen-bir-oncu-lev-kuleshov', 'Unutulmuşluğu Yenen bir Öncü: Lev Kuleshov', 'Gökhan Erkılıç', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Unutulmuşluğu Yenen bir &Ouml;nc&uuml;:</h2>\r\n<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><b>Lev Kuleshov</b></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>G&ouml;khan Erkılı&ccedil;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: x-small;"><b><a href="mailto:editor@sekans.org" style="color: #895f37;">editor@sekans.org</a></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-large;"><b>K</b></span><span style="font-size: 10pt;"><span><b>uleshov</b>&nbsp;adı, yaşamını sinemaya adamış belli bir grup dışında, sinemayla amat&ouml;r ya da profesyonel olarak ilgilenen sinemacıların belleğinde ve bilgisinde ne &ouml;nem taşır ne de yer tutar, &ccedil;oğunlukla da tutar gibi yapılarak ge&ccedil;iştirilir. D&uuml;nya genelinde, &uuml;niversite &ccedil;evrelerinde bile yıllar boyu unutulmuşları oynadığı, hatta g&uuml;n&uuml;m&uuml;zde bile &uuml;&ccedil;&uuml;nc&uuml; d&uuml;nya akademisyenleri arasında kendine hen&uuml;z yol bulamadığı da g&ouml;z ardı edilmemeli. Oysa ki t&uuml;m zamanların değişmez ger&ccedil;eğini sorgulayan o &uuml;nl&uuml;, bilenle bilmeyenin bir olmadığı saptamasına dokunan, dokunduran bir alandır Kuleshov &ouml;ğretisi. Yıllara yayılan bir ilgisizlik! Varsın olsun,&nbsp;<b>Kuleshov</b>&nbsp;onlarsız da&nbsp;<b>Kuleshov</b>! Bu yazı, bu ilgisizliğe ve g&ouml;rmezliğe karşı duyulan isyan duygularıyla yazıldığı i&ccedil;in bilenler veya bir bilen gibi davrananlar i&ccedil;in yazılmadı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/Kuleshov.jpg" alt="" width="300" height="417" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Y&ouml;netmen ya da bir sinema teorisyeni olmaktan &ouml;te, kurgu kuramını ortaya atan sinema adamı olarak bakılmalıdır&nbsp;<b>Kuleshov</b>&rsquo;a. Onun yaşam &ouml;yk&uuml;s&uuml; 14 Ocak 1899&rsquo;da Tambov&rsquo;da başlar,&nbsp;<b>Lev Vladimirovich Kuleshov</b>&nbsp;adıyla. Bu denli yoğunlaşmış bir ilgi, sevgi ve &uuml;retme arzusunu nasıl duyup hayata ge&ccedil;irdiğini anlamak zor olsa da, onu daha 17 yaşında d&ouml;nemin &uuml;nl&uuml; yapımcısı&nbsp;<b><span style="text-decoration: underline;">Kanconkov</span>&nbsp;</b>&rsquo;un st&uuml;dyosunda dekorat&ouml;r olarak buluruz. D&ouml;neme ilişkin kayıtlardan yine d&ouml;nemin &ouml;ne &ccedil;ıkan y&ouml;netmenlerinden&nbsp;<b>Evgeni Bauer</b>&rsquo;in y&ouml;netiminde &ccedil;alıştığını &ouml;ğreniyoruz. Hen&uuml;z 18 yaşında ilk sinema yazılarına ve ilk y&ouml;netmenlik girişimine tanık oluruz. Gen&ccedil;liğin ataklığını ve &ouml;ğrenme tutkusunu taşıyan bu yazılarda ne yapacağını bilen, yeri geldiğinde yol g&ouml;steren ve durmaksızın arayışlarını s&uuml;rd&uuml;ren bir insanla karşılaşırız. Hemen ardından 1918-19 yıllarının i&ccedil; savaş ortamına elinde kamerasıyla s&uuml;r&uuml;klenir. Moskova&rsquo;ya d&ouml;ner d&ouml;nmez, 1 Mayıs 1920&rsquo;de kuruluşunda da emek harcadığı Devlet Sinema Okulu&rsquo;nun &ouml;ğretim kadrosuna alınır, yaş 21! İlerleyen yıllarda yetiştirdiği &uuml;nl&uuml;lerle &uuml;nlenecek olan at&ouml;lyesini 1922&rsquo;de oluşturur ve ham film yokluğu nedeniyle filmsiz film deneylerine başlar. Olanaksızlıkların insanın hayalg&uuml;c&uuml;n&uuml; hangi noktalara taşıyabileceğinin en elle tutulur, g&ouml;zle g&ouml;r&uuml;l&uuml;r &ouml;rneklerinden biridir&nbsp;<b>Kuleshov</b>&nbsp;denemeleri.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Y&ouml;netmenin herşeyden daha &ouml;nemli bir konuma sahip olduğu d&uuml;ş&uuml;ncesiyle yola koyulur. Bunu kurgunun sinema sanatının en &ouml;nemli &ouml;ğesi olduğu g&ouml;r&uuml;ş&uuml; izler. Sovyetler Birliği&rsquo;nde kurgu s&ouml;zc&uuml;ğ&uuml;n&uuml; ilk kullanandır. Filmsel zaman ve zaman boşluğu kavramları attığı &ouml;nemli adımlar olur.&nbsp;<b>Kuleshov</b>&rsquo;u kurguya y&ouml;nlendiren iki temel etken vardı. Bunlardan biri doğrudan sinemadan geliyordu ve anlatım dilinin zenginliği ile&nbsp;<b>Kuleshov</b>&rsquo;u bir hayli etkileyen&nbsp;<b>David W. Griffith</b>&nbsp;sinemasıydı. Diğeri ise &uuml;lkesinin g&uuml;&ccedil;l&uuml; yazı geleneğine dayanan, gelişkin &ouml;rnekleri &ouml;zellikle&nbsp;<b>Tolstoy</b>&nbsp;ve&nbsp;<b>Puşkin</b>&rsquo;in yapıtlarında karşımıza &ccedil;ıkan kurgusal anlatım teknikleriydi.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinema tarihine Kuleshov Efekti diye giren kurgusal yorum &ccedil;eşitlemesi dikkat &ccedil;ekicidir. Tanınmış oyuncu&nbsp;<b>Ivan Mosjukin</b>&rsquo;in bir y&uuml;z &ccedil;ekimini, sırayla yemek, &ccedil;ocuk ve tabut &ccedil;ekimlerine ekler. Oyuncunun y&uuml;z&uuml;ndeki anlam, her eşlemede farklı duygusal bir tepki taşıyormuş algısı uyandırır. Orijinali kayıp olan bu kurgu &ccedil;alışmaları &uuml;&ccedil; temel okuma ilkesine dayanır: kurgunun yoruma d&ouml;n&uuml;kl&uuml;ğ&uuml;, anlamın son katmanının seyirci tarafından belirlenmesi ve karşıtlıklar algısı. Onun deneysel kurgu &ccedil;alışmaları giderek ayrıntılara y&ouml;neldi ve par&ccedil;a-b&uuml;t&uuml;n ilişkisine odaklandı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><b>Kuleshov&rsquo;</b>a g&ouml;re kurgu bilincine varan ilk y&ouml;netmen&nbsp;<b>Griffith</b>, kendisi de kurguyu kuramsallaştıran ilk isimdi. Kurgusal anlatıma g&ouml;re ger&ccedil;ekleştirilmiş ilk Rus yapımı 1917&rsquo;de &ccedil;ektiği&nbsp;<b>Proyekt Injenera Praita</b>&nbsp;(M&uuml;hendis Praita&rsquo;nın Projesi) filmiydi.<br />&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/bolshevik.jpg" alt="" width="320" height="236" border="0" /></span><br /><span style="font-size: 10pt;"><span><b>Resim:</b>&nbsp;The Extraordinary Adventures of&nbsp;<br />Mr. West in the Land of the Bolsheviks, 1924<br />&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><b>Kuleshov</b>&nbsp;at&ouml;lyesinin artık herkes tarafından duyulan deneyleri, ham filme kolay ulaşılmaya başlandığı 1923 yılıyla birlikte daha bir yoğunluk kazanır. Bu d&ouml;nem,&nbsp;<b>Kuleshov</b>&rsquo;u bir teorisyen olmaktan &ccedil;ıkarıp, aynı zamanda bir y&ouml;netmen olarak da tanınmasına neden olacak yapıtlarını barındırır.&nbsp;<b>Kuleshov</b>&nbsp;adının &ouml;nemli bir ad olduğu s&ouml;ylemini taşıyan ilk film, Bolşevik d&uuml;nyasına uyum sağlama problemleri &ccedil;eken bir Batılı tiplemesinin başından ge&ccedil;enlerin anlatıldığı&nbsp;<b>The Extraordinary Adventures of Mr. West in the Land of the Bolsheviks</b>&nbsp;(Bay Batı&rsquo;nın Bolşevikler &Uuml;lkesindeki Olağan&uuml;st&uuml; Ser&uuml;venleri, 1924) olur. Film, propaganda &uuml;zerine kurulu &ouml;zg&uuml;n bir g&uuml;ld&uuml;r&uuml;d&uuml;r. &Ouml;ğrencisi olan bir diğer &uuml;nl&uuml; sinema adamı,&nbsp;<b>Vsevolod Pudovkin</b>&nbsp;filmin senaristi, dekor tasarımcısı ve oyuncusu olarak&nbsp;<b>Kuleshov&rsquo;</b>a b&uuml;y&uuml;k destek verir. Beş yıl &ouml;nce hayatına giren filmin kadın oyuncusu Alexandra Khokhlova&rsquo;nın, y&ouml;netmenin hem &ouml;zel hem sanat yaşamında zirveye &ccedil;ıktığı anlaşılır. &Uuml;&ccedil;l&uuml; bir yıl sonra ve aynı g&ouml;rev dağılımıyla, ayrıntılarla zengin kılınan atmosferi, psikolojik derinliği ve sanatsal arayışlarıyla propaganda sinemasını aşan&nbsp;<b>&Ouml;l&uuml;m Işını</b>&rsquo;nı (Luc Smierti, 1925) ger&ccedil;ekleştirir. Artık&nbsp;<b>Kuleshov&rsquo;</b>un &ouml;n&uuml;nde başyapıtı olarak g&ouml;sterilen&nbsp;<b>Dura Lex</b>&rsquo;in yapım &ouml;ncesi &ccedil;alışmaları uzanmaktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<div style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;">\r\n<table border="1" style="width: 746.4px;" cellspacing="0" cellpadding="0" align="center">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;">\r\n<p style="font-size: 11px; text-transform: uppercase; margin-bottom: 0px;"><span style="font-size: 10pt;"></span><span style="font-size: 10pt;"></span></p>\r\n<p style="font-size: 11px; text-transform: uppercase; margin-bottom: 0px;"><span style="font-size: 10pt;"><strong>&nbsp; &nbsp;PO ZAKONU</strong></span><strong style="font-size: 2em;"><span style="font-size: 10pt;">/</span><span style="font-size: 10pt;">DURA LEX</span></strong></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>&nbsp;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>senaryo:&nbsp;</span></b><span>Victor Shklovski, Lev Kuleshov</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>g&ouml;r&uuml;nt&uuml; y&ouml;n:&nbsp;</span></b><span>Konstantin Kuznetsov</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>dekor:&nbsp;</span></b><span>Isaak Makhliss</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>oyuncular:&nbsp;</span></b><span>Alexandra Khokhlova, Sergei Komarov, Vladimir Fogel, Piotr Galadzhez</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>1926/61&rsquo;/1673 mt/s&amp;b/sessiz</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt;"><b><span>&nbsp;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 10pt;"><span><img src="/images/yazilar/dura-lex.jpg" alt="" width="320" height="633" border="0" />&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt;"><span>Jack London&rsquo;ın kısa bir &ouml;yk&uuml;s&uuml;nden yola &ccedil;ıkan Kuleshov, yarattığı klostrofobik atmosferin sağladığı psikolojik gerilimle beslenen &ccedil;arpıcı bir Alaska westerni ger&ccedil;ekleştirir. Ortamın ıssızlığı i&ccedil;inde i&ccedil;g&uuml;d&uuml;sel davranış eğilimleri g&ouml;steren, para tutkusunun &ouml;ld&uuml;rmeyi sıradanlaştıran &ccedil;ekiciliğinin emrine girmiş ve i&ccedil;inde barındırdığı sadizmi dışa vurmakta kendini kontrol edemeyen bir altın arayıcısının &ouml;yk&uuml;s&uuml;...</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt;"><span>Biri kadın olan, Amerikan r&uuml;yasına dalmış s&uuml;r&uuml;klenen diğer iki yol arkadaşı, yaşamlarının riske girdiğini farkederler ve silahını elinden alırlar. Adamı bir kul&uuml;beye tıkarlar ve bahar gelinceye kadar orada g&ouml;zaltında tutmaya karar verirler. Bahar, ardında cinayetler olan adamın yargı yoluyla cezalandırılması i&ccedil;in uygun hava ve ulaşım koşullarını yaratacaktır. Ancak, bir akşam kul&uuml;beye d&ouml;nd&uuml;klerinde, su&ccedil;lunun ardında onlara şans dileyen bir not bırakarak ka&ccedil;mış olduğunu g&ouml;r&uuml;rler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmografisinin ilk yazınsal uyarlamasını ger&ccedil;ekleştiren&nbsp;<b>Kuleshov</b>, filmde b&uuml;t&uuml;n&uuml;yle montaja dayalı bir anlatım dilini benimser.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/dura-lex2.jpg" alt="" width="296" height="439" border="0" /></span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><b>Kuleshov&nbsp;</b>ilerleyen yıllarda Stalin rejiminin saplantılı ideologlarınca fazla entelekt&uuml;el ve burjuva kalıntısı olanlar arasında g&ouml;sterilecek ve bu durum y&ouml;netmenin yaratıcı doğasından uzaklaşmasına neden olacaktır. Filmler &ccedil;ekecek ancak zirveye yeniden tırmanamayacaktır. K&uuml;sk&uuml;nl&uuml;ğ&uuml;n&uuml; &uuml;zerinden atamayan Kuleshov, ilerleyen yıllarda bir tek&nbsp;<b>B&uuml;y&uuml;k Avutucu&nbsp;</b>(The Great Consoler, 1933) filmiyle eski g&uuml;nlerinin &ccedil;izgisini yakalar. 1941&rsquo;de Film Y&ouml;netiminin Temel İlkeleri adlı yapıtını yayınlar.&nbsp;<b>Khoklova</b>&nbsp;ile ortak y&ouml;nettiği&nbsp;<b>Biz Urallar&rsquo;danız</b>&nbsp;(We from the Urals, 1944) son filmi olur ve aynı yıl Moskova Film Enstit&uuml;s&uuml;&rsquo;n&uuml;n y&ouml;netimine getirilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/great-consol.jpg" alt="" width="469" height="373" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span><b>Resim:</b>&nbsp;</span><span>The Great Consoler, 1933</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>50&rsquo;lerle başlayan yıllar Avrupa gezileri, film festivallerinde j&uuml;ri &uuml;yelikleri, toplu g&ouml;sterimlerine davetler ve film g&ouml;sterimlerini destekleyen derslerle ge&ccedil;er. 30 Mart 1970&rsquo;deki &ouml;l&uuml;m&uuml;n&uuml;n ardından yıllarca unutulmuşları oynayacak, nedense Batı onaylamadığı s&uuml;rece kimsenin adamdan sayılmadığı bu evrende, unutulmuşluğu er ge&ccedil; yenecek d&uuml;zeydeki yeteneği, emeği ve yapıtları sayesinde yeniden g&uuml;ndemimize taşınacaktır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt;">1917</span></b><span style="font-size: 10pt;">&nbsp;The Project of Engineer Prite</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1917</b>&nbsp;An Unfinished Love Song</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1919-20</b>&nbsp;Kronika</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1920</b>&nbsp;On the Red Front</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1924</b>&nbsp;The Extraordinary Adventures of Mr. West in the Land of the Bolsheviks</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1925</b>&nbsp;Luc Smierti</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1926</b>&nbsp;Dura Lex</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1927</b>&nbsp;The Journalist Girl</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1929</b>&nbsp;The Happy Canary</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1930</b>&nbsp;Dva-Bouldi-Dva</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1931</b>&nbsp;Forty Hearts</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1932</b>&nbsp;Gorizont</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1933</b>&nbsp;The Great Consoler</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1940</b>&nbsp;The Siberians</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1941</b>&nbsp;Happening on the Volcano</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1943</b>&nbsp;Timur&rsquo;s Oath</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>1944</b>&nbsp;We from the Urals</span></p>', 45, 63, 'Yazarlarımızdan', '/images/yazilar/Kuleshov.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (44, 'ay-j165', 'kentin-sakin-goruntusunun-i-cinde-mies-van-der-rohe-ve-sinematik-zaman', 'Kentin Sakin Görüntüsünün İçinde: Mies van der Rohe ve Sinematik Zaman', 'Lutz Robbers', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Kentin Sakin G&ouml;r&uuml;nt&uuml;s&uuml;n&uuml;n İ&ccedil;inde:&nbsp;<br /><b>Mies van der Rohe ve Sinematik Zaman</b></h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><span><b>Lutz Robbers</b></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>&Ccedil;ev: İlker Mutlu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px; text-align: center;"><span style="font-size: medium;"><b>1</b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">1927&rsquo;de&nbsp;<b>Siegfried Kracauer</b>&nbsp;<b><i>Frankfurter Zeitung</i></b>&rsquo;da Weissenhof&rsquo;taki bir modern mimarinin şimdilerde &uuml;nlenmiş olan kalıcı vitrinine ge&ccedil;ici bir b&uuml;t&uuml;nleyici unsur olarak yapılan modern konutun sergilendiği, Stuttgart&rsquo;taki Deutsche Werkbund sergisi &lsquo;Die Neue Wohnung&rsquo;u (Yeni Konut) haber yapar. Eleştirel yorumlarında Neue Bauen&rsquo;in fonksiyonelliğine dair soğuk beğeni ile g&ouml;steriş ve abartıyla yapılan burjuva i&ccedil; mekanlarının debdebesindeki alaycılık arasında bocalar. Yine de yazısının sonunda,&nbsp;<b>Mies van der Rohe</b>&nbsp;ve&nbsp;<b>Lilly Reich</b>&rsquo;ın Glasraum&rsquo;unun keşfi &uuml;zerine mimari bir aydınlanma yaşar [Res. 14-1].&nbsp;<b>Kracauer</b>&nbsp;cam formu hareketli g&ouml;r&uuml;nt&uuml;lerin olağan&uuml;st&uuml; manzarası olarak betimler:</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><img src="/images/yazilar/Resim%2014-1%20Mies%20Glasraum.jpg" alt="Mies Glasraum" width="213" height="160" style="margin-right: 10px; float: left;" /><span style="font-size: x-small;"><span style="font-family: Verdana;">"</span></span><span style="font-size: 10pt; font-family: Verdana;">Glasraum,&nbsp;<b>Mies van der Rohe</b>&nbsp;ve&nbsp;<b>Lilly Reich</b>tarafından rasyonel bir şekilde yaratılan garip bir odadır. Duvarları s&uuml;t&uuml;ms&uuml; ve koyu-renkte camlarla kaplıydı. Transparan, cam bir kutu; komşu odaların i&ccedil;ine uzanmış. İ&ccedil;erisindeki her cihaz ve her hareket, b&uuml;y&uuml;l&uuml; bir bi&ccedil;imde, g&ouml;lgeleri duvar &uuml;zerine yansıtıyor, havada s&uuml;z&uuml;len ve cam odanın ayna g&ouml;r&uuml;nt&uuml;lerine karışan bedensiz sil&uuml;etler. Tıpkı ışık-tepkileri gibi bir kaleidoscope şeklinde değişen bu manevi, kristal hayaletin b&uuml;y&uuml;s&uuml;, yeni evin hen&uuml;z son kapsamına erişmediğini g&ouml;steriyor."</span><span style="font-size: small;"></span><b><span style="font-size: x-small;">(1)</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Belli ki, Werkbund sergisinin ortasında&nbsp;<b>Mies</b>&rsquo;in cam odasının keşfi&nbsp;<b>Kracauer</b>&rsquo;i şaşkın bıraktı. Kısa bir an i&ccedil;in, kristal pavyon, sonradan &uuml;nl&uuml; bir sinema uzmanı olarak k&uuml;lt&uuml;r eleştirmenine d&ouml;n&uuml;şecek deneyimli mimarı kendine getirdi&nbsp;</span><span style="font-size: x-small;"><b>(2)</b>,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">ki bu mimarinin kurtarıcı potansiyelinde uzun s&uuml;reli bir inan&ccedil; kaybı demekti. O,&nbsp;<b>Mies</b>&rsquo;in cam odasına adımını attığı anda, mimari b&uuml;y&uuml;s&uuml;nden kurtulunan modern s&uuml;bjeye bir "son kapsam" duygusu y&uuml;kleme g&uuml;c&uuml; ile yeniden donanmış hale gelir. Aynı zamanda "garip" ve "rasyonel tasarlanmış" bu modern Wunderkammer&rsquo;in (harikalar kabini) i&ccedil;inde, sihir ve teknoloji, sanat ve bilim arasındaki ayrım anlamsız kalmaktadır. Kısa bir an i&ccedil;in cam oda&nbsp;<b>Kracauer</b>&rsquo;i melankolik kaybın ve fetişistik par&ccedil;alanmanın doğal sonucunu kabul etmek durumunda kalmaksızın s&uuml;recin b&uuml;y&uuml;s&uuml; i&ccedil;inde şaşkın, kalakalmış halde bırakır&nbsp;</span><span style="font-size: x-small;"><b>(3)</b>.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Benim g&ouml;stermeye &ccedil;alışacağım şey&nbsp;<b>Kracauer</b>&rsquo;in epifani (Tanrı&rsquo;nın g&ouml;r&uuml;n&uuml;ş&uuml;) anının &ndash;onun entelekt&uuml;el gelişiminde ayrıcalıklı bir yer tutan sanatsal ifadenin iki formu- mimari ve sinemanın d&uuml;şsel bir b&uuml;t&uuml;nl&uuml;kte kesiştikleri nadir ortamlardan birini işaretlediğidir.&nbsp;<b>Mies</b>&rsquo;in Glasraum&rsquo;u mimari ve sinema arasındaki ayrım &ccedil;izgisini bulanıklaştıran yansıtmaların, hareketli g&ouml;lgelerin, y&uuml;zen sil&uuml;etler ve i&ccedil; i&ccedil;e ge&ccedil;miş g&ouml;r&uuml;nt&uuml;lerin bir hacmidir. Ve sinema gibi olan, onun sinematik ara&ccedil;larının işlevini ve etkilerini taklit eden mimari bir yapı olmanın aksine, cam oda sinemadır. Pavyonun kendisi bir yansıtıcı aparat, dalmış seyirciyi s&uuml;bjektif olmanın sınırlamalarından kendilerini kurtarmaya ve kendi g&ouml;r&uuml;nt&uuml;ler oluşturma kapasiteleriyle oynamaya başlamaya teşvik eden bir medya makinesi haline gelir.&nbsp;<b>Kracauer</b>&rsquo;in titiz duyarlılığı Glasraum&rsquo;da ve iki yıl sonra Tugendhat Evi&rsquo;nde ve Barselona Pavyonu&rsquo;nda &uuml;r&uuml;n vermeye gelirkenki Miesyen yapı d&uuml;ş&uuml;ncesinin&nbsp;<b>Mies</b>&rsquo;in hareketli g&ouml;r&uuml;nt&uuml;n&uuml;n yeni g&ouml;rsel k&uuml;lt&uuml;r&uuml;ne aktif katılımının hangi şekillerde ger&ccedil;ekleştiğini sormaya y&ouml;nlendirir. Sinemanın&nbsp;<b>Mies</b>&rsquo;in &ccedil;alışmasını etkilediği k&uuml;lt&uuml;rel deneyimin yollarını g&ouml;stermek suretiyle, ben, ilkin, mimari avantgarde &uuml;st&uuml;ne yeni bir perspektif koymayı umuyor ve ikinci olarak da, sinema ve mimari arasındaki etkileşimi bunların zaman kategorisi doğrultusundaki benzerliğini vurgulayarak teorize etmenin yeni denemeleri i&ccedil;in bir tarihsel iskelet oluşturuyorum.&nbsp;<b>Mies</b>&rsquo;in "sinematik" mimarisi&nbsp;<b>Dominique Paini</b>&rsquo;nin "materyali zaman olan nesneler"in yeni t&uuml;rleri olarak tanımladığı şeyin gelişine kanıt oluşturur</span><span style="font-size: x-small;"><b>(4)</b>.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Bununla birlikte, tarihsel kanıtlardan bazılarını sunmadan &ouml;nce, benim "sinema" kavramından ne anladığımı kısaca a&ccedil;ıklamam gerekiyor.&nbsp;<b>Raymond Bellour</b>&rsquo;un ardından giderek, sinemayı aktif olarak bir "ikinci uzam", "i&ccedil;inde izleyicinin kendi d&uuml;ş&uuml;nmesinin g&ouml;r&uuml;nt&uuml;lerini, hareket eden ve etkileyen (mouvant, &eacute;mouvante) koşullarını geri yansıtan ışık ile karşı karşıya olmayı bırakmadan kendi devinimsiz yolculuğunun zihinsel doğasını daha iyi kavrayacak bir gezgin haline geldiği"&nbsp;</span><span style="font-size: x-small;"><b>(5)</b></span><span style="font-size: 10pt; font-family: Verdana;">bir oluşturma t&uuml;r&uuml; kuran bir y&ouml;ntem olarak tanımlamayı &ouml;neriyorum. Sinema derken bizim duygusal, dokunsal ve i&ccedil;sel deneyimlerimizi "d&uuml;ş&uuml;nme"mize olanak veren uzaysal bir uygulamayı ifade ediyorum.&nbsp;<b>Bellour</b>&rsquo;un sinema tanımlaması birleştirilmiş, tek, homojen s&uuml;bjeyi katılaştırılmış, durağan objeden ayıran Albertyen yansıtma hacmine radikal bir alternatif varsayımı sunar.&nbsp;<b>Bellour</b>&rsquo;un sinema tanımı, bunun aksine, bizi estetik ve d&uuml;ş&uuml;nsel bir hacmin, beden ve zihin arasındaki ayrım &ccedil;izgisini yok eden bir hacmin i&ccedil;ine sokar. Bu durumda,&nbsp;<b>Gilles Deleuze</b>&rsquo;&uuml;n "İnsanlar neden sinemaya gider?" sorusuna verdiği yanıt aynı şekilde mimariye de uygulanabilir: "zaman (&hellip;.) i&ccedil;in: kayıp ya da harcanmış ya da hen&uuml;z sahip olunmamış zaman i&ccedil;in."</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b><span style="font-size: medium;">2</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; font-family: Verdana;">Sinema end&uuml;strisinin g&uuml;nl&uuml;k yayını&nbsp;<b><i>Film-Kurier</i></b>&rsquo;de &ccedil;ıkan kısa bir yazı bir s&uuml;rpriz havasında "<b>Mies van der Rohe</b>&nbsp;sinemeya nasıl girdi?" diye sorar [Fig.14-2].&nbsp;<b>Mies</b>&rsquo;in sinemaya girişine a&ccedil;ık kanıt sunmak yerine, adsız yazar genel ve doğrulanmamış bir yorumla yetinmektedir: "Zamanımızın entelekt&uuml;el konularında yer edinen bir kişi olarak onun film sorunsallarıyla ilgilendiği s&ouml;ylenmemeye devam ediyor. Ve &ccedil;&uuml;nk&uuml; o yorumları &ouml;zel ilgi hak eden herhangi bir kurumdan değil."</span><span style="font-size: x-small;"><b>&nbsp;(6)</b></span><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in ger&ccedil;ek yorumunun ne olduğu karanlıkta durmaktadır. Aynı derecede anlaşılmaz ve dayanaksız olan bir şey de yazının başlığı: "<b><i>Filmk&auml;mpfer von au&szlig;en</i></b>" ("Film i&ccedil;in dışarıdan savaşan") onun tarafsız bir yabancı olarak rol&uuml; kadar sinemaya dair bir tutkuyu da &ccedil;ağrıştırmaktadır.&nbsp;<br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/Resim%2014.2%20Filmkurierdeki%20Makale.JPG" alt="" width="329" height="454" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b><span style="font-size: 9pt; font-family: Verdana;">Resim 14.2:</span></b><span style="font-size: 9pt; font-family: Verdana;">&nbsp;<i>Filmkurier</i>&rsquo;deki Makale</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 12pt; color: black;"><br /></span><span style="font-size: 10pt; font-family: Verdana;">Ve aslında, mimari &uuml;zerine filmlerin &uuml;retiminde aktif olarak g&ouml;rev alan, film sahnesi setlerini dizayn eden ya da senaryolar yazan&nbsp;<b>Le Corbusier</b>,&nbsp;<b>Hans Poelzig</b>&nbsp;veya&nbsp;<b>Bruno Taut</b>&nbsp;gibi mimari avangardın &ccedil;ağdaş &uuml;yelerinin aksine,&nbsp;<b>Mies</b>&nbsp;film &uuml;retiminin ger&ccedil;ek s&uuml;re&ccedil;lerine asla katılmadı. Bununla beraber,&nbsp;<b>Mies</b>&rsquo;in Berlin yıllarını kapsayan arşiv malzemesi yeni sinema ortamına b&uuml;y&uuml;k ilgi duyduğunu g&ouml;stermektedir.&nbsp;<b>Hans Richter</b>,&nbsp;<b>Viking Eggeling</b>&nbsp;ve&nbsp;<b>Werner Graett</b>&nbsp;gibi Berlin avangardının &ouml;nderleri ile bu &uuml;&ccedil;&uuml;n&uuml;n ilk ritmik ve soyut filmlerini geliştirdikleri bir d&ouml;nemde kişisel bağlar kurduğuna ş&uuml;phe yoktur.&nbsp;<b>Richter&nbsp;</b>sonradan&nbsp;<b>Mies</b>&nbsp;ile ilk kez 1921&rsquo;de, tam da o ve&nbsp;<b>Eggeling</b>&nbsp;ilk soyut filmleri &uuml;zerinde &ccedil;alışmakta oldukları yılda tanıştıklarını hatırlayacaktır. Sonradan&nbsp;<b>Mies</b>&rsquo;in "sadece benim ya da&nbsp;<b>Mondrian</b>&rsquo;ın &ccedil;izimlerine benzemeyen, ancak hakkında konuştuğumuz g&ouml;rsel m&uuml;zik (&hellip;) ve bizim filmlerimizde ger&ccedil;ekleştirdiğimiz m&uuml;zik gibi olan"&nbsp;</span><span style="font-size: x-small;"><b>(7)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">mimari planlarını keşfettiğindeki şaşkınlığını hatırlayacaktır.&nbsp;<b><i>Material zur elementaren Gestaltung</i></b>&nbsp;(1923-1926)&nbsp; dergisi &uuml;st&uuml;ndeki işbirliğine nihayet uyduğundan, rastlantının d&uuml;nya geneline yayılacağı kanıtlandı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">1925 Mayısı&rsquo;nda&nbsp;<b>Mies</b>&rsquo;in başkan olarak g&ouml;rev aldığı "Novembergruppe"nin organize ettiği efsanevi film matinesi "Der Absolute Film" esnasındaydı. Burada,&nbsp;<b>Richter</b>,&nbsp;<b>Eggeling</b>,&nbsp;<b>Walter Ruttmann</b>,&nbsp;<b>Ren&eacute; Clair</b>,&nbsp;<b>Francis Picabia</b>,&nbsp;<b>Oskar Fischinger&nbsp;</b>ve&nbsp;<b>Hischfeld-Mack</b>&rsquo;ın deneysel filmleri daha b&uuml;y&uuml;k bir topluluk karşısında ilk defa sunulmaktaydı. Beş yıl sonra&nbsp;<b>Mies</b>&rsquo;in adı&nbsp;<b>Richter</b>,&nbsp;<b>Graeff</b>,&nbsp;<b>Ruttmann</b>,&nbsp;<b>Karl Nierendorf</b>,&nbsp;<b>Lotte Reiniger</b>&nbsp;ve&nbsp;<b>Asta Nielsen</b>&nbsp;arasında &lsquo;Liga f&uuml;r den unabh&auml;ngigen Film&rsquo;in (Bağımsız Film Birliği) &ndash;film aracılığıyla "ger&ccedil;eğin katıksız şekillendirilmesi" ve "zamanın ifadesi"&nbsp;</span><span style="font-size: x-small;"><b>(8)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">i&ccedil;in savaşan bir sanat&ccedil;ı ve y&ouml;netmenler topluluğu &ndash; idare komitesinin bir &uuml;yesi olarak anılacaktı [Res. 14-3.].&nbsp;<b>Mies</b>&rsquo;in filme olan ilgisi, 1934&rsquo;te Reich&rsquo;ın M&uuml;nih&rsquo;teki Sanat Dairesinin&ndash;&nbsp;<b>Joseph Goebbels&nbsp;</b>tarafından 1933&rsquo;te Alman K&uuml;lt&uuml;r&uuml;&rsquo;n&uuml;n yerleştirilmesi (Gleichschaltung) i&ccedil;in kurulan k&ouml;t&uuml; &uuml;nl&uuml; devlet kurumu &ndash; başkanı&nbsp;<b>Mies</b>&rsquo;ten filmin sanatlardaki rol&uuml; &uuml;zerine olan, listelenen alt başlıklardan birinin "filmdeki mimari" olduğu bir tartışma organizasyonuna katılmasını istediğinde dahi g&ouml;lgelenmedi. Mies daveti memnuniyetle kabul etti.</span><span style="font-size: x-small;">&nbsp;<b>(9)</b><span style="color: windowtext;"><br />&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/Resim%2014.3%20Filmreunde.JPG" alt="" width="265" height="405" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b><span style="font-family: Verdana;"><span style="font-size: 9pt;">Resim 14.3:</span></span></b><span style="font-family: Verdana;"><span style="font-size: 9pt;"></span><i><span style="font-size: 9pt;">Filmreund</span></i></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b><span style="font-size: 12pt; color: windowtext;"><br /></span><span style="font-size: medium;">3</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; font-family: Verdana;">Belli ki, sinema olayı&nbsp;<b>Mies</b>&rsquo;i b&uuml;y&uuml;lemişti. Hatta aynı derecede a&ccedil;ıktır ki, onun y&ouml;netmenleri sık sık ziyaret etmesi ve enstit&uuml; d&uuml;zeyinde bağımsız sinemayı desteklemesi, filmin kıyassız g&ouml;rsel ger&ccedil;ekliği ya da kalabalık bir izleyici grubu &uuml;zerindeki b&uuml;y&uuml;leyici etkisi i&ccedil;in değildi. Tartışmak istediğim şu ki,&nbsp;<b>Mies</b>, filmin yapısal &ouml;zelliklerini s&uuml;bjektivitenin yeni formlarını ve hacim ve zamanın şimdiye değin bilinmeyen kesişme noktalarını keşfetmek i&ccedil;in araştıran&nbsp;<b>Richter&nbsp;</b>ve&nbsp;<b>Eggeling&nbsp;</b>gibi sanat&ccedil;ılardan etkilenmişti. Bu ilgi, tartışmak isterim, 1920lerin başında tetiklenmemiş, ancak daha geriye, 1911 ve 1912 yıllarına,&nbsp;<b>Mies</b>&rsquo;in &ouml;zel ve profesyonel hayatında ancak yeni yeni bilimsel olarak ilgi toplandığı, geliştirici bir d&ouml;neme kadar gitmektedir.</span><b><span style="font-size: x-small;">&nbsp;(10)</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in gelecekteki eşi&nbsp;<b>Ada Bruhn</b>&nbsp;ile karşılaşması olasılıkla Berlin &Uuml;niversitesi&rsquo;nde felsefe profes&ouml;r&uuml; ve&nbsp;<b>Mies</b>&rsquo;in ilk m&uuml;şterisi olan&nbsp;<b>Alois Riehl</b>&nbsp;tarafından organize edilen bir toplantı sırasında oldu.&nbsp;<b>Bruhn</b>, &uuml;nl&uuml; İsvi&ccedil;reli besteci, dans eğitmeni ve ritmik dansın kurucusu olan&nbsp;<b>&Eacute;mile Jaques-Dalcroze</b>&rsquo;nin &ouml;ğrencisi oluyordu. 1910&rsquo;da&nbsp;<b>Jaques-Dalcroze</b>, Fransız şair&nbsp;<b>Paul Claudel</b>&rsquo;in &lsquo;yeni insanlığın laboratuarı&rsquo; olarak adlandırmasıyla o zamanda &uuml;nl&uuml; olmuş Dresden-Hellerau&rsquo;ya taşındı.&nbsp;<b>Walter Dohrn</b>&nbsp;ve Dresdner Werkst&auml;tten&rsquo;in kurucusu&nbsp;<b>Karl Schmidt</b>tarafından başlatılan bu b&uuml;t&uuml;nc&uuml;l Lebensreform projesi, sanat ve end&uuml;stri, beden ve zihin aracılığıyla modernitenin yabancılaştırıcı deneyimine kafa tutan bir sosyo-k&uuml;lt&uuml;rel Gesamtkunstwerk olan yaşam reformu hareketinin kentsel materyalizasyonu olarak ifade edilmekteydi</span><span style="font-size: x-small;"><b>&nbsp;(11).</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Burada&nbsp;<b>Jaques-Dalcroze</b>"insani hisleri ve duyguları, insanın iradesi ile uyum i&ccedil;erisinde, bilimin bizim zek&acirc;mızı y&uuml;kselttiği aynı seviyeye &ccedil;ıkartma"yı&nbsp;</span><span style="font-size: x-small;"><b>(12)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">kastetmektedir. Bu, yazarlar, sanat&ccedil;ılar ve mimarlar arasında,&nbsp;<b>Kurt Schwitters</b>,&nbsp;<b>Hugo Ball</b>,&nbsp;<b>Johannes Baader</b>,&nbsp;<b>Rainer Maria Rilke</b>,&nbsp;<b>Franz Kafka</b>,&nbsp;<b>Raoul Hausmann</b>&nbsp;benzerleri ya da gen&ccedil;&nbsp;<b>Le Corbusier</b>&rsquo;den Dresden&rsquo;in kenar mahallelerine kadar b&uuml;y&uuml;k bir heyecana neden oldu.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana;">Hellerau&rsquo;ya da gitti. Aralarında&nbsp;<b>Mary Wigman</b>&rsquo;ın da bulunduğu başka &uuml;&ccedil; dans &ouml;ğrencisi ile aynı evi paylaşan gelecekteki eşini &ccedil;eşitli gerek&ccedil;eler yaratarak ziyaret etti&nbsp;</span><span style="font-size: x-small;"><b>(13)</b>.&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Ne yazık ki, g&ouml;rd&uuml;ğ&uuml; ve karşılaştıklarına dair kanıtlar kendisi tarafından ne kaydedilmiş, ne de onlardan s&ouml;z edilmiştir. Bununla birlikte, o zamanda&nbsp;<b>Peter Behrens</b>&rsquo;in ofisinde &ccedil;alışmış olan&nbsp;<b>Mies</b>&rsquo;in&nbsp;<b>Jaques-Dalcroze</b>&rsquo;nin Ritmik Dans Enstit&uuml;s&uuml;&rsquo;ne ev sahipliği yapan reformcu yerleşke Hellerau&rsquo;nun merkezi olan "Festspielhaus"un [Fig.14-4.] yapımı ve tamamlanmasına (1910-12) yakından tanıklık etmiş olması gerektiğini d&uuml;ş&uuml;nebiliriz. Ve daha m&uuml;mk&uuml;n&uuml; şudur ki, o şahsen Hellerau&rsquo;nun merkezini,&nbsp;<b>Heinrich Tessenow</b>&rsquo;un İşvi&ccedil;reli kuramcı ve sahne tasarımcısı&nbsp;<b>Adolphe Appia</b>&rsquo;nın yanı sıra&nbsp;<b>Jaques-Dalcroze</b>, Rus ressam&nbsp;<b>Alexander von Salzmann</b>&nbsp;ile işbirliği i&ccedil;inde tasarladığı, Festsaal denilen ana performans alanını deneyimledi.</span><span style="font-size: x-small;"><br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/Resim%2014-4a%20Festsaal%20Dresden-Hellerau.jpg" alt="" width="268" height="202" border="0" />&nbsp;&nbsp;<img src="/images/yazilar/Resim%2014-4b%20Festsaal%20Dresden-Hellerau.jpg" alt="" width="256" height="200" border="0" /></p>\r\n<div style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-4a</b>: Festsaal, Dresden-Hellerau &nbsp;<b>Resim14-4b</b>: Festsaal, Dresden-Hellerau</span></p>\r\n&nbsp;\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Festsaal s&uuml;slemelerden, sabit sahne malzemelerinden ya da sahne ve salon arasındaki klasik b&ouml;l&uuml;n&uuml;m &ccedil;izgisi olan sahne &ouml;n&uuml;nden mahrum, tek, tamamen değiştirilebilir bir hacimdi. Bununla beraber, bu performans hacmini "zamandan yapılmış" mimari objeleri i&ccedil;eren tartışmamız i&ccedil;in &ouml;zellikle ilgili kılan şey, nun ışıklandırma kurulumudur: bu beyaz, boş k&uuml;b&uuml;n duvar ve tavanları arkasına farklı renklerdeki 10000 lambanın yerleştirildiği yarı-saydam beyaz kumaş ile kaplıydı. [Res. 14-5] Uzam ayrıca bu ışık panellerinin &ccedil;eşitli kısımlarının isteğe g&ouml;re aktive edilebildiği ve dahası, lambaların parlaklık şiddetinin tamamen karanlıktan ışıldayan parlaklığa kadar &ccedil;eşitlenebildiği bir yer olması nedeniyle &ccedil;ok esnekti. Festsaal&rsquo;in ışıklandırma kurulumu performans hacmini basit&ccedil;e sahnedeki g&ouml;r&uuml;nt&uuml;y&uuml; aydınlatmayan, ancak dans&ccedil;ılarla birlikte ritmik şekilde &ccedil;ınlayarak, kendi d&uuml;zeli, materyal kalitesini kazanan bir hayli etkileyici bir ruhani ışığa boğuyordu. "Aydınlatılmış bir hacim yerine", yazar&nbsp;<b>von Salzmann</b>, "biz ışık &uuml;reten bir hacme sahibiz. Işık boşluğun i&ccedil;inden kendisini iletiyor (&hellip;)"</span><span style="font-size: x-small;">&nbsp;<b>(14)</b>.&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana;">Salzmann</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;ın ışık kurulumunda</span><span style="font-size: x-small;">&nbsp;<b>(15)</b>&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana;">Salzmann</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;ın ışık kurulumunda</span><span style="font-size: x-small;">&nbsp;<b>(16)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">tarafından geliştirilene benzeyen bir ışık kubbesi &uuml;zerindeki anonim bir sinematografik aparat ile hareketli g&ouml;r&uuml;nt&uuml;ler yansıtmak suretiyle hareket kazandırmak fikrindeydi. [Res. 14-6.] İkincisi 1902&rsquo;den itibaren klasik tiyatronun perspektife dikkat edilen arkaplan &ccedil;izimlerini bulut efektleriyle hareketlendirilmiş sonsuz bir g&ouml;k-benzeri boşluk i&ccedil;ine dağıtan mobil, kubbe şekilli cycloramaların i&ccedil;inde geliştirilen, ipek kumaşlar &uuml;st&uuml;ne ışık yansımalarıyla denenmişti.&nbsp;<b>Salzmann</b>&rsquo;ın gizli ışık panelleri yanı sıra,&nbsp;<b>Fortuny</b>&rsquo;nin yarık&uuml;resel ekranı da ondokuzuncu y&uuml;zyıl burjuva tiyatrosunun perspektivist sahne d&uuml;zenlerine uzamsal alternatifler sunar.</span><span style="font-size: x-small;"><br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 12pt; color: windowtext;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<img src="/images/yazilar/Resim%2014-5%20Salzmannisiktesisati.jpg" alt="" width="467" height="372" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-5</b>: Salzmann, Işık tesisatı</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-6%20Fortuny%20Cyclorama.jpg" alt="" width="273" height="359" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-6</b>: Fortuny Cyclorama</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: x-small;"><br /></span><span style="font-size: 10pt; font-family: Verdana;">Efekt olağan&uuml;st&uuml;l&uuml;ğ&uuml; denedi. [Fig. 14-7.]&nbsp;<b>Gluck</b>&rsquo;un operası&nbsp;<b><i>Orfeo</i></b>&rsquo;nun Haziran 1912&rsquo;deki sahnelenmesine tanıklık eden bir izleyiciye g&ouml;re, performans "imgelemin &ouml;tesindeydi. Uzam canlıydı ve hayatın bir yardımcı-yaratıcısıydı."</span><span style="font-size: x-small;">&nbsp;<b>(17)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Ve performans esnasında orada olan Amerikalı yazar&nbsp;<b>Upton Sinclair</b>&nbsp;ş&ouml;yle yazdı: "O g&ouml;r&uuml;n&uuml;r kılınan m&uuml;zikti; ve perde Orfeo ve gelininin mutlulukları &uuml;zerine d&uuml;şm&uuml;ş olduğunda, bir alkış fırtınası salonu sarstı. Erkekler ve kadınlar yeni bir sanat formunun esinindeki zevklerini haykırır halde kaldılar."</span><span style="font-size: x-small;">&nbsp;<b>(18)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Gelecekteki eşi sahnede g&ouml;sterisini yaparken,&nbsp;<b>Mies</b>&rsquo;in hareketli bir ışık i&ccedil;ine batmış ritmik bedenlerin bu kolektif katarsisinde zevklerini haykıranların arasında bulunmuş olması olasıdır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 12pt; color: windowtext;"><img src="/images/yazilar/Resim%2014-7%20Dresden-HelleraudakiOrfeo.jpg" alt="" width="427" height="349" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt; color: windowtext;"><b>Resim 14-7</b>: Dresden-Hellerau&rsquo;daki Orfeo</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><b><span style="font-size: medium;">4</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt; font-family: Verdana;">Bu eşi benzeri g&ouml;r&uuml;lmemiş uzamsal deneyim&nbsp;<b>Appia</b>&rsquo;nın 1890ların başında geliştirmeye başlamış olduğu deneysel sahne tasarımları ve tiyatro estetiğine dair teorik uygulamalarının bir devamı olarak g&ouml;r&uuml;lebilir. O, akt&ouml;rlerin ill&uuml;zyonist perspektife uygun bir arkaplan &ouml;n&uuml;ne sahneye sa&ccedil;ılmış objeler ve sahne malzemeleri ile bedensel varlıklarını yan yana bulunduran geleneksel teatral uzaysal kompozisyonuna alıştırılmış g&ouml;zlerin "k&ouml;rl&uuml;ğ&uuml;n&uuml;" devam ettirdiğini iddia eder.</span><span style="font-size: x-small;"><b>(19)</b>&nbsp;[Res. 14-8]&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">&Ouml;te yandan, ışık, "bizim g&ouml;r&uuml;n&uuml;mler d&uuml;nyamızın bitip t&uuml;kenmeden değişen g&ouml;r&uuml;nt&uuml;s&uuml;n&uuml; tam ve yaşayan anlamda aktarma"da bir "ger&ccedil;ekten g&uuml;&ccedil;l&uuml; yaratıcı kapasite" ile aşılanmıştır.</span><span style="font-size: x-small;">&nbsp;<b>(20)</b></span><span style="font-size: 10pt; font-family: Verdana;">Hareket verilmiş, elektrik &uuml;reten sahne aydınlanmaları ışığa m&uuml;ziğinkine eşit bir rol y&uuml;kl&uuml;yordu: "ışık m&uuml;ziğin partisyonda sahip olduğu temsil ifadelerindeki işlevlerin aynısına sahiptir: o g&ouml;r&uuml;nebilene karşı anlamlı bir elemandır ve aynen m&uuml;zik gibi, o da g&ouml;rmenin gerekli unsurlarının b&uuml;t&uuml;nleşik bir par&ccedil;asından başka bir şeyi ifade edemez."</span><span style="font-size: x-small;"><b>(21)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Işık, m&uuml;zik gibi, "uzaya serpilir, onu yaşayan renkle ve s&uuml;rekli değişen bir atmosferin sınırsız varyasyonları ile doldurur."</span><span style="font-size: 12pt;"></span><b><span style="font-size: x-small;">(22)</span></b><span style="font-size: 12pt;"></span><b><span style="font-size: 10pt; font-family: Verdana;">Appia</span></b><span style="font-size: 10pt; font-family: Verdana;">&nbsp;b&ouml;ylece en eski felsefi metaforları ters y&uuml;z eder: onun anlayışında ışık neticede &ouml;l&uuml; şeyi aydınlatan g&ouml;r&uuml;nmez bir etmendir. Hatta ışık bilin&ccedil; ve nesne i&ccedil;in her yerde bulunur hale gelir. Hatta ışık bilin&ccedil; ve nesne i&ccedil;in i&ccedil;kin hale gelir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-8%20Appia%20Ritmik%20Hacimler.jpg" alt="" width="447" height="304" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-8</b>: Appia Ritmik Hacimler</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Şeyleri s&uuml;re&ccedil;ler ve uzamları da olaylar olarak yeniden d&uuml;şlemeye başlayabiliriz.&nbsp;<b>Appia</b>,&nbsp;<b>Benjamin</b>&rsquo;in S&uuml;rrealizm denemesindeki ifadesini kullanmak &uuml;zere bir "Y&uuml;zde Y&uuml;z oranında G&ouml;r&uuml;nt&uuml;-Boşluğu" kurar,</span><span style="font-size: x-small;">&nbsp;<b>(23)</b>,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">hem seyretme, hem de fantazmagorik estetizasyon aracılığıyla kendine mal etme aşırılığına ka&ccedil;an bir boşluk, "aksiyonun kendisinin (&hellip;) g&ouml;r&uuml;nt&uuml; olduğu (&hellip;), t&uuml;m&uuml; yan yana olan ve b&uuml;t&uuml;nleşik ger&ccedil;eklik olduğu"&nbsp;</span><span style="font-size: x-small;"><b>(24)</b>&nbsp;bir boşluk.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Appia</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;nın askıya alınmış, taşlaştırılmış zaman kavramı&nbsp;<b>Mies</b>&rsquo;i &ccedil;eşitli d&uuml;zeylerde etkilemiş g&ouml;r&uuml;nmekteydi. En ger&ccedil;ek d&uuml;zeyde,&nbsp;<b>Mies</b>&rsquo;in bir "ışık-&uuml;reten" uzay elde etmek &uuml;zere Festsaal&rsquo;in ışık-filtreleyici, ışığı yayıcı duvar &ccedil;izimi sistemine &ouml;zenme eğiliminde olduğunun kanıtı bulunmaktadır.&nbsp;<b>Mies</b>&nbsp;i&ccedil;in teknik ressam olarak &ccedil;alışmış olan&nbsp;<b>Sergius Ruegenberg</b>&rsquo;e g&ouml;re, onun Berlin&rsquo;deki Am Karlsbad&rsquo;daki ofis/dairesinde bulunan oturma odası t&uuml;m&uuml;yle beyaz ya da bej ipekle kaplanmıştı.</span><span style="font-size: x-small;"><b>(25)</b>&nbsp;&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Ofisteki değişmez (Mies&rsquo;i zamanında banyoda uyumaya zorlayan) alan darlığı sorununa rağmen, odayı daima boş tuttu. Hatta onun "feminen &ccedil;evresi"ndeki "<b><i>Zehner-Ring</i></b>"den&nbsp;</span><span style="font-size: x-small;"><b>(26)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">meslektaşları ile yaptığı toplantılar esnasında yapılan alaycı yorumlara dahi katlandı.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Hem g&ouml;rsel sınır hem de s&uuml;z&uuml;c&uuml; bir alan-yaratıcı ara&ccedil; olarak kullanılabilen, doğal ya da yapay ışığı yayan ve hareketlendiren yarı-ge&ccedil;irgen kumaşların kullanımı,&nbsp;<b>Mies</b>&rsquo;in mimari repertuarının bir par&ccedil;ası olarak kaldı. &Ouml;rneğin, 1927&rsquo;de Berlin&rsquo;deki ipek end&uuml;strisi sergisinde,&nbsp;<b>Mies</b>&nbsp;ve&nbsp;<b>Lilly Reich</b>&nbsp;&uuml;zerine &ccedil;eşitli renklerde ipek kumaşların asılı olduğu armat&uuml;rler gibi kullandıkları birka&ccedil; kavisli borudan oluşan &ccedil;er&ccedil;evelerle "Caf&eacute; Samt und Seide"yi (Caf&eacute; Kadife ve İpek) yarattılar.&nbsp;<b>Mies</b>&rsquo;in Brno&rsquo;daki Tugendhat Evi&rsquo;ndeki (1930) perdeler kaleydoskobik bir değişir ışık kırılma oyunu yaratan siyah opak ipek ve beyaz saydam kadifeden yapılmıştı. Ve şu da ileri s&uuml;r&uuml;lebilir ki,&nbsp;<b>Mies</b>&rsquo;in Barselona Pavyonu i&ccedil;in olan tasarımında g&ouml;ze &ccedil;arpan bir konuma yerleştirdiği buzlu cam ışık-duvarı &ndash;oranın tek yapay ışık kaynağı-, bir "ışık-&uuml;retici" alan kavramının bir sonraki aşamasını g&ouml;steren bir eklemdir. [Res. 14-9]</span></p>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-9%20MiesBarcelonaisikduvari.jpg" alt="" width="351" height="415" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-9</b>: Mies, Barcelona, ışık</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Festsaal&rsquo;daki &ccedil;ift b&ouml;l&uuml;nm&uuml;ş duvar gibi, beyaz, opak cam duvar alandaki gizil objeleri aydınlatmaya hizmet eden bir ışık kaynağı g&ouml;revini dahi g&ouml;rmez. Aksine, beyaz camların soğuk materyalliğini &lsquo;alevlendiriyor&rsquo; ve belirgin bir karanlığı kuşatmış objeleri gizliyordu.&nbsp;<b>Ruegenberg</b>&rsquo;e g&ouml;re,&nbsp;<b>Mies</b>&nbsp;ışık-duvarın kendilerini "uzaydaki sil&uuml;etler" olarak algılamaya başlayan ziyaret&ccedil;ilerdeki bir "psikolojik endişe"yi tetiklediği ger&ccedil;eğiyle b&uuml;y&uuml;lenmişti</span><span style="font-size: 10pt;"><b>&nbsp;(27)</b>.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><b><span style="font-size: 14pt;">5</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><b><span style="font-size: 10pt; font-family: Verdana;">Kracauer</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in&nbsp;<b>Mies</b>&rsquo;in Glasraum&rsquo;u &uuml;st&uuml;ne olan a&ccedil;ıklamasını kullanmak &uuml;zere benimsenmiş olan "bedensiz sil&uuml;etler" ve canlı "ışık&uuml;reten" alanlar arasındaki bu diyalektik,&nbsp;<b>Mies</b>&rsquo;in eserinde yinelenen bir motiftir. Fr&uuml;hlicht&rsquo;teki 1922 yılına ait bir yazıda kendisinin Friedrichstra&szlig;e kolajlarına dair tanımlamalarında&nbsp;<b>Mies</b>&nbsp;"ışık yansımalarının tasarlanmış oyunu"na "cadde uzantısı g&ouml;r&uuml;nt&uuml;s&uuml; ile uzam oluşturmak (Baumasse im Strassenbild) s&ouml;z&uuml;yle karşı &ccedil;ıkar&nbsp;</span><span style="font-size: 10pt;"><b>(28)</b>.&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Başka bir deyişle, foto kolajlarında bizi g&ouml;rselliğin iki karşıt ayrıcalığına dayanan sisteminin diyalektiğiyle y&uuml;zleştirir: bir yanda, dingin sağlamlığı (Baumasse) bi&ccedil;im ve işaretlerin bağlayıcı kodlamalarıyla doyurulmuş perspektife uygun, fotografik g&ouml;r&uuml;nt&uuml;n&uuml;n temsili kodlarına &ouml;nceden uygulanmış, cisimleştirilmiş kent; &ouml;te yanda, kaleydoskobik yansımaların algısal olarak y&uuml;zen, sınırlı ve hareketli g&ouml;rsel bir sahası. Daha ikna edicisi,&nbsp;<b>Mies</b>&rsquo;in karakalem g&ouml;kdelen cephesi &uuml;zerine olan &ccedil;alışmaları, siyah ev sil&uuml;eti ve ritmik şekilde hareketlendirilmiş ışık-alanı arasındaki karşıtlığı vurgulamaktadır [Res. 14-10].</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-10%20Mies,%20karakalem%20eskiz,%20Friedrichstrasse.jpg" alt="" width="258" height="344" border="0" /></p>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-10</b>: Mies, karakalem eskiz, Friedrichstrasse</span></p>\r\n&nbsp;\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt; font-family: Verdana;">Ve yine, bunlar&nbsp;<b>Appia</b>&nbsp;sahne tasarımlarıyla yan yana konduklarında vurucu analojiler a&ccedil;ığa &ccedil;ıkmaktadır:&nbsp;<b>Appia</b>&rsquo;nın "Rheingold" set tasarımı&nbsp;<b>Mies</b>&rsquo;inkiyle aynı tasarım fikrini sergiler. [Res. 14-11] G&ouml;r&uuml;nt&uuml;n&uuml;n kendi kadar mekan da temsil gerektiren bir bilinen değildir. Her ikisi de zamanda bir s&uuml;re&ccedil; olarak &uuml;retilirler.&nbsp;<b>Mies&nbsp;</b>sonradan "Bir ev inşa etmek istediğimde kendime asla bir g&ouml;r&uuml;nt&uuml; oluşturmam," diyecekti</span><span style="font-size: 10pt;"><b>&nbsp;(29)</b>.&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&nbsp;ve&nbsp;<b>Appia</b>&rsquo;nın anladığı şekilde g&ouml;r&uuml;nt&uuml;, bundan dolayı bir şipşak fotoğraf &ccedil;ekimi algısındaki taklit&ccedil;i g&ouml;r&uuml;nt&uuml; değil,&nbsp;<b>Benjamin</b>&rsquo;in yazdığı gibi, "bi&ccedil;im &ouml;ğesinin &ouml;ğe oyunuyla tamamen yer değiştirdiği"&nbsp;</span><span style="font-size: 10pt;"><b>(30)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">sinematik bir g&ouml;r&uuml;nt&uuml;d&uuml;r. Sonu&ccedil; olarak, g&ouml;r&uuml;nt&uuml;lere dayanan tasarımlar yerine, ziyaret&ccedil;iyi oyuna, onun yeni g&ouml;r&uuml;nt&uuml;ler oluşturmasına izin verecek şekilde, daima yeni uzamsal elit yaratımlarla oynamaya kışkırtmak, tasarımcının g&ouml;revi haline gelir.</span></p>\r\n<table border="0" style="width: 517px; height: 303px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" valign="top" width="321">\r\n<p><img src="/images/yazilar/Resim%2014-11a%20Friedrichstrasse.jpg" alt="" width="298" height="212" border="0" /><br /><span style="font-size: 9pt; font-family: Cambria; color: windowtext;"><b>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<br />&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</b></span><span style="font-size: 9pt;">&nbsp;&nbsp;&nbsp;&nbsp;<b>Resim 14-11a</b>: Friedrichstra&szlig;e</span></p>\r\n<p><span style="font-size: 9pt;"></span></p>\r\n<p><span style="font-size: 9pt;"></span><span style="font-size: 9pt; font-family: Cambria; color: windowtext;"><b>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</b></span><span style="font-size: 9pt;"><b>Resim 14-11b</b>: Friedrichstra&szlig;e</span></p>\r\n</td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" valign="top"><img src="/images/yazilar/Resim%2014-11b%20Friedrichstrasse.jpg" alt="" width="206" height="293" border="0" /></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 10pt; font-family: Verdana;">Stuttgart Glasraum tamamiyle izleyiciyi sihirli bir ışık oyununun kendi s&uuml;reci i&ccedil;ine daldırırken, onun g&ouml;kdelen kolajları, sanki&nbsp;<b>Mies</b>&nbsp;bir ışık kırılması alanını maddeleştirilmiş nesnelerin tasvirleri ile kasten yan yana koymuş gibi, kendine kasteder tarzda didaktiktir. Friedrichstra&szlig;e kolajları halen perspektife uygun, taklit&ccedil;i devinimsiz&nbsp; bir g&ouml;r&uuml;nt&uuml; olan "yol uzantısı g&ouml;r&uuml;nt&uuml;s&uuml;" ve camdan y&uuml;kselişin ritmik g&ouml;rsel alanı olan "ışık yansıması oyunu" arasında a&ccedil;ık bir ayrımı ortaya koyar. 1922 Glashochhaus fotomontajında bu diyalektiği g&uuml;&ccedil;leştirir: ger&ccedil;ek bir cam nodeli - Friedrichstra&szlig;e kolajları gibi bulanık bir karakalem &ccedil;izim değil-, kaba, ger&ccedil;ek&ccedil;i olmayan oyuncak minyat&uuml;rlerden daha fazla bir şey olma iddiası bile taşımayan geleneksel Wilhelmine tarzı apartman binalarının kilden modelleri ile &ccedil;evreler. [Res. 14-12] Sol kenarda, yaprakları r&uuml;zgarda hışırdar g&ouml;r&uuml;nen bir ağacın belli belirsiz &ccedil;izgileri fark edilebilir. Arkadaki sağ alt kenarda, cam modelden yansıyan, silindirik bir yapının dış &ccedil;izgileri g&ouml;r&uuml;lebilir. İlk bakışta g&ouml;r&uuml;nen,&nbsp;<b>Mies</b>&rsquo;in cam g&ouml;kdeleni, bir g&uuml;nl&uuml;k "cadde uzantısı g&ouml;r&uuml;nt&uuml;s&uuml;" i&ccedil;ine bi&ccedil;imsel olarak yerleştirerek karşıtlık oluşturmak eğiliminin, ger&ccedil;ekte o kadar da &ccedil;eşitli stillerin değil, ama mimari manifestolarındaki &ccedil;eşitli kabul d&uuml;zenlerinin &ouml;zenle oluşturulmuş bir montajı olarak ortaya &ccedil;ıktığıdır. Silindirik yapı ger&ccedil;ekte bir panorama, ondokuzuncu y&uuml;zyıldaki kolektif g&ouml;rsel eğlencenin yaygın bir kentsel yerleşim haline geliyordu.[Res. 14-13]&nbsp;<b>Stephan Oettermann</b>&rsquo;ın &ouml;ne s&uuml;rd&uuml;ğ&uuml; gibi, panoramalar, sinemaya bir &ouml;nc&uuml; olarak, &lsquo;ilk yaygın optik medya&rsquo; idiler&nbsp;</span><span style="font-size: x-small;"><b>(31)</b>.&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Onlar modernleşen s&uuml;bjelerin algısal alışkanlıklarındaki değişimlere tanıklık ettiler. Panoramanın merkezinde rotondun t&uuml;m i&ccedil; &ccedil;evresini kaplayacak, eşit olarak aydınlatılmış, izleyicinin 360 derecelik resme g&ouml;z&uuml;n&uuml; dikerek bakacağı karartılmış bir seyir platformu bulunur. Seyretmekte olan g&ouml;z&uuml;n g&ouml;r&uuml;nt&uuml;n&uuml;n &ouml;n&uuml;nde sabit bir pozisyon bulmasına yardımcı olacak hem arka plan hem de resmin orta-zemin yokluğu, s&uuml;bjede bir &ccedil;eşit baş d&ouml;nd&uuml;r&uuml;c&uuml; somutlaşma keyfi yaratır. Bu sersemletici efekt, resmin kendisinden ışır g&ouml;r&uuml;nen olduk&ccedil;a dağınık, g&ouml;lgesiz ışık aracılığıyla arttırılır.</span></p>\r\n<table border="0" style="width: 543px; height: 394px; margin-right: auto; margin-left: auto;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; width: 315px;" valign="top">\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-12%20Mies,%20Glashochaus.jpg" alt="" width="204" height="334" border="0" /></p>\r\n</td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; width: 315px;" valign="top">\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-13%20Panorama%20kesiti.jpg" alt="" width="195" height="277" border="0" /></p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; text-align: center;" width="315">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 9pt;"><b>Resim 14-12</b>: Mies, Glashochaus</span></p>\r\n</td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px; text-align: center;">\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><span style="font-size: 9pt;"><b>Resim 14-13</b>: Panorama kesiti</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<div>&nbsp;<br />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in bu unsurları fotomontajına dahil etmesi, kesinlikle rastlantı değildir. Benim buradaki s&ouml;ylemim şudur:&nbsp;<b>Mies</b>, mimarinin tarihsel gelişimini g&ouml;rselliğinkiyle analoji kurarak, kendisine ait bir tarzda tasarlar. Arkada g&ouml;rmekte olduğumuz panorama, Berlin&rsquo;de y&uuml;zyılın başında "Deniz panoraması" olarak bilinmekteydi&nbsp;</span><span style="font-size: x-small;"><b>(32)</b>&nbsp;[Res. 14-14.].&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Binanın New York şehir limanındaki hayali bir gemiden g&ouml;zlenen Manhattan sil&uuml;etinin panoramik bir sahnesine ev sahipliği yapması [Res.14-15.]&nbsp;<b>Mies</b>&rsquo;in ironik bir kelime oyunu yapıyor olabileceğini &ccedil;ağrıştırır. O, Amerika&rsquo;nın 1. D&uuml;nya Savaşı sonrasındaki yıllarda kollektif ve &ouml;zellikle, mimari imge &uuml;zerine uyguladığı yaygın &ccedil;ekiciliği iyice alaya almış olabilir; bu,&nbsp;<b>Mies</b>&rsquo;in 1921&rsquo;deki Friedrichstra&szlig;e yarışmasının j&uuml;risinden &ccedil;ıkarılma kararı &uuml;zerinde etkisi olabilecek bir eğilimdir.</span></p>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-14%20Deniz%20panoramasi.jpg" alt="" width="316" height="211" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-14</b>: Deniz panoraması</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-15%20Deniz%20panoramasiNew%20York%20liman.jpg" alt="" width="520" height="169" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-15</b>: Deniz panoraması, New York liman g&ouml;r&uuml;n&uuml;ş&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in kolajında bir panoramaya yer verme se&ccedil;imi pre-sinemasal g&ouml;r&uuml;nt&uuml; panoraması ve g&ouml;rkemli g&ouml;kdelen arasındaki algısal benzerliklere bir ipucu olarak g&ouml;sterilebilir: her biri yeni bir bilimsel uzak g&ouml;r&uuml;şl&uuml;l&uuml;k taşıyan, tarihsel olarak rastlantısal, perspektif &ouml;ğrenme makineleridir. Her biri izleyiciyi d&uuml;ş&uuml;ncelere dalmaktan uzaklaştırır ve onu &ccedil;ılgın g&ouml;rselliğiyle b&uuml;y&uuml;ler. Bu durum,&nbsp;<b>Manfredo Tafuri</b>&rsquo;nin&nbsp;<b>Appia</b>&rsquo;nın sahne teorileri ile&nbsp;<b>Mies</b>&rsquo;in Barselona Pavyonu arasında kurduğu karşılaştırmayı kullanmaya, "hi&ccedil;bir anlamı olmayan işaretler arasındaki imsel varlıkların kentsel labirentinde gezinmeyi sağlayan bir pandomim sergilemeye"</span><span style="font-size: x-small;">&nbsp;<b>(33)&nbsp;</b>zorlar.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Benzer bir tarzda,&nbsp;<b>Mies</b>&nbsp;Tugendhat evinde (1928-30) farklı algılama d&uuml;zenlerinin didaktik bir gezintisini tasarlar. Varışında ziyaret&ccedil;i manzaranın &ccedil;er&ccedil;eveli bir g&ouml;r&uuml;nt&uuml;s&uuml; ile karşılaşır. Sonra aynen ziyaret&ccedil;inin bir g&ouml;rsel deneyim bolluğu sunan bir boşluk i&ccedil;inde y&uuml;celmek &uuml;zere karanlık ve d&ouml;ner bir merdivenden aşağıya inmek durumunda kaldığı bir panoramik binadaki gibi, buzlu-cam ge&ccedil;ide girer. Mekan ne sınırsız bir panoramaya a&ccedil;ılır, ne de eve girişte karşılaşılan g&ouml;r&uuml;nt&uuml;y&uuml; tekrarlar. Aksine, salkım s&ouml;ğ&uuml;t&uuml;n dalları ile g&ouml;r&uuml;nt&uuml;y&uuml; kasıtlı olarak kapar [Res. 14-16].<b>Mies</b>&nbsp;g&ouml;r&uuml;nt&uuml;ye hareket kazandırır: ışık ve g&ouml;lgelerin s&uuml;rekli olarak değişen s&uuml;ss&uuml;z kırılma oyunu, bundan dolayı, &nbsp;u&ccedil;suz bucaksız manzara sahnesi &uuml;zerindeki panoramik g&ouml;r&uuml;nt&uuml;n&uuml;n konvansiyonelleştirilmiş g&ouml;rsel t&uuml;ketimini baltalayarak cam y&uuml;zeyden yayılır. Ağa&ccedil;lar ve su gibi elemanların, mimari stabiliteyi karşılayan, şansa dayalı ya da ritmik harekete sahip olan elemanların bu gerekli katkısı, Mies&ccedil;i mekanın kavranması i&ccedil;in &ccedil;ok &ouml;nemlidir. Sinemanın &ouml;nc&uuml; isimlerinden&nbsp;<b>Georges M&eacute;li&egrave;s</b>, ger&ccedil;ek sinematiğin Lumi&egrave;re ailesini kahvaltıda g&ouml;steren, onların ilk kısalarından biri olan 1895 tarihli &nbsp;<b><i>Le Repas de B&eacute;b&eacute;</i></b>&nbsp;filminin fig&uuml;ratif &ouml;n plan sahnesinde bulunmadığını vurgular. Ger&ccedil;ek sinematik deneyimin arka plandaki hışırdayan yaprakların rastgele hareketinde bulunduğunda ısrarcı olur.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-16%20Tugendhat%20eskizi.jpg" alt="" width="509" height="176" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-16</b>: Tugendhat eskizi</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><b><span style="font-size: 12pt; color: windowtext;"><br /></span><span style="font-size: medium;">6</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in fotomontajlarında konumuz i&ccedil;in bahse değer g&ouml;r&uuml;nen son bir g&ouml;r&uuml;ş daha vardır. O s&uuml;rekli ve tekrar tekrar titizlikle kontrol edilmiş kompozisyonlarında insan fig&uuml;rlerine yer vermekte ısrar eder. Hareket halindeki hayaletimsi sil&uuml;etler ve hayalet-benzeri beden izleri, ışık kırılmalarının dinamik sahası ve varolan kentin somutlaştırılmış g&ouml;r&uuml;nt&uuml;leri yanında &uuml;&ccedil;&uuml;nc&uuml; bir unsur olarak belirmektedir.&nbsp;<b>Mies</b>&rsquo;in dahil etmek istediği bu insan fig&uuml;rleri herhangi bir fotoğrafik ger&ccedil;eklikten yoksundur ve cam kulenin ritmik kompozisyonel mantığını tekrar da etmezler. Onun kolajlarındaki insan fig&uuml;rleri genellikle "lekeli"dir; durgun g&ouml;r&uuml;nt&uuml;ler değillerdir, ancak mekandaki hareket eden bedenler olarak fotoğrafın ışığa duyarlı y&uuml;zeyi &uuml;st&uuml;nde zamanın s&uuml;rekliliğini kaydederler. [Res.14-17] Uzun poz s&uuml;relerine g&ouml;re fotoğrafın erken bir d&ouml;neminde yaygın olan bu efekt,&nbsp;<b>Mies</b>&rsquo;in kolajlarında planlanmış bir se&ccedil;im haline gelmiştir. İtalyan f&uuml;t&uuml;rist&nbsp;<b>Anton Giulio Bragaglia</b>hareketli bedenlerin y&ouml;r&uuml;ngelerini a&ccedil;ığa &ccedil;ıkararak, fotoğraflar &uuml;zerinde deneyler yaptı. [Res. 14-18]&nbsp;<b>Bragaglia</b>&nbsp;i&ccedil;in "kronofotoğraf&ccedil;ılık" zamanı hareket eden insan bedeninin maddesel formundan bağımsız hale gelecek olduğu bir "d&ouml;rd&uuml;nc&uuml; uzaysal boyut" olarak hatırlatmak &uuml;zere, mekanı zamana d&ouml;nd&uuml;rmenin bir yolu idi</span><span style="font-size: x-small;"><b>(34)</b>.&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana;">Sophie Taeuber-Arp</span></b><span style="font-size: 10pt; font-family: Verdana;">, hen&uuml;z g&ouml;rd&uuml;ğ&uuml;m&uuml;z gibi, Hellerau&rsquo;da&nbsp;<b>Mies</b>&rsquo;in ilkin tanıştığı&nbsp;<b>Mary Wigman</b>&rsquo;ın mekanda dans eden bedenin maddi g&ouml;r&uuml;n&uuml;m&uuml;n&uuml; sunmayı deneyen &ccedil;ifte-pozlu resmini &ccedil;ekti. [Res. 14-19] T&uuml;m bunlar modern mekan fikirlerine alternatifler &ouml;neren s&uuml;re&ccedil; fig&uuml;rleridir. Artık mekanı taşlaşmış zaman dilimlerinin bir sekansı olarak sunmanın dar geldiği bu "bedensiz sil&uuml;etler" (<b>Kracauer</b>)&nbsp;<b>Mies</b>&rsquo;in sinematik cam odasının ziyaret&ccedil;ilerinin &ouml;nceden canlandırılmasıdır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-17%20Fotomontajda%20insan.jpg" alt="" width="449" height="324" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-17</b>: Foto-montajda insan fig&uuml;r&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-18%20Bragaglia.jpg" alt="" width="300" height="416" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-18</b>: Bragaglia</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><img src="/images/yazilar/Resim%2014-19%20Wigman.jpg" alt="" width="226" height="295" border="0" /></p>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: center;"><span style="font-size: 9pt;"><b>Resim 14-19</b>: Wigman</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><br /><span style="font-size: 10pt; font-family: Verdana;">Toparlarsak:&nbsp;<b>Bragaglia&nbsp;</b>&uuml;zerinden&nbsp;<b>Appia</b>&rsquo;dan&nbsp;<b>Eggeling</b>&nbsp;ve&nbsp;<b>Richter</b>&rsquo;e b&uuml;t&uuml;n bir kuşağı d&ouml;kerek; Bauhaus işlevselciliğinden ve Sovyet yapısalcılığından ayrı olan Mies&ccedil;i modern uzam kavramını, yeni sinema k&uuml;lt&uuml;r&uuml; i&ccedil;in potansiyel taşıyan bir d&uuml;ş&uuml;nceyi ileri s&uuml;rmek istedim.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&nbsp;otonom &ouml;znelliğin bi&ccedil;imlendirdiği bir inan&ccedil; beslediği i&ccedil;in, beklenmeyen olayların bir par&ccedil;ası olarak tasarlanabilecek aktif ve aktifleştirici bir mimariyi kurarken, fonksiyonculuk ve yapısalcılık rastlantısal ve kazara olan her şeyi atmayı denemişti. Durgun bir g&ouml;r&uuml;nt&uuml;y&uuml; d&uuml;zenlemek yerine, o konuyu marjinal, bi&ccedil;imsiz, olasılıklara dayalı ve ritmik, bi&ccedil;im verici formlar arasında s&uuml;regelen tartışmalara gereksinen bir se&ccedil;kinler topluluğuna sunmayı tercih eder&nbsp;</span><span style="font-size: 10pt;"><b>(35)</b>.&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana;">Mies</span></b><span style="font-size: 10pt; font-family: Verdana;">&rsquo;in yaptığı modern mimari materyallerinin zamanın i&ccedil;inde ya da onunla birlikte bi&ccedil;imlendirilmesinin uzamsal bir uygulamasıdır.&nbsp;<b>Jean-Fran&ccedil;ois Lyotard</b>&rsquo;dan aktarırsak, "&ouml;yle bir yolda ki, o y&uuml;ksek oranda bir rastlantı istiyor."&nbsp;</span><span style="font-size: 10pt;"><b>(36)</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana;">Mimar, modernite koşulu altında mimariyi anlamlı kılmak &uuml;zere, inşa edilmiş ve edilebilir olan arasında ge&ccedil;işken bir aray&uuml;zey &uuml;retmek, bir olayı "sahne"lemek zorunda kalır.<b>Mies</b>&rsquo;in sinema ile olan kontakları aracılığıyla ger&ccedil;ekleştirmiş olabileceği şey, &ouml;l&uuml; nesneyi aydınlatan zihin değil, bir nesne olarak kullanıma hazırladığı akıcı ve ge&ccedil;ici yapı materyalidir.&nbsp;<b>Kracauer</b>&rsquo;in Glasraum&rsquo;daki hazzı&nbsp;<b>Mies</b>&rsquo;in bu zaman-objelerin ge&ccedil;iciliklerini bi&ccedil;imlendirmeyi ve d&uuml;zenlemeyi, onları gezgine d&ouml;n&uuml;şen izleyicinin bilincinin akış veya ritmi ile buluşturmaya inanmış olduğunu akla getirir.</span></p>\r\n<div>&nbsp;<hr /></div>\r\n<div>\r\n<div>\r\n<div>\r\n<div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(1) Siegfried Kracauer</span>&nbsp;</b><span>, "<b><i>Das Neue Wohnen: Zur Stuttgarter Werkbund Ausstellung \'Die Wohnung\'</i></b>," Frankfurter Zeitung, 31 Temmuz&nbsp; 1927. Anılmadığı yerlerde &ccedil;eviriler bana aittir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(2) Kracauer</span>&nbsp;</b><span>&nbsp;(1889-1966) M&uuml;nih&rsquo;te&nbsp;<b>Theodor Fischer</b>&rsquo;in altında mimarlık &ouml;ğrenmişti. 1911&rsquo;de mezun olduktan sonra&nbsp;<b><i>Frankfurter Zeitung</i></b>&rsquo;un editoryal ekibinin tam zamanlı bir &uuml;yesi olmak &uuml;zere mesleği nihayet tamamen bıraktığı 1921&rsquo;e kadar &ccedil;eşitli mimarlar i&ccedil;in &ccedil;alıştı.&nbsp;<b>Kracauer</b>&rsquo;in bir mimar olarak kariyeri ve bir k&uuml;lt&uuml;rel eleştirmen haline gelmesindeki bu değişim &uuml;zerine bakınız&nbsp;<b>Gerwin Zohlen</b>, "<b><i>Schmugglerpfad: Siegfried Kracauer, Architekt und Schriftsteller</i></b>,"&nbsp;<b>Siegfried Kracauer</b>: Neue Interpretationen&rsquo;de, ed.<b>Michael Kessler</b>&nbsp;ve&nbsp;<b>Thomas Y. Levin</b>&nbsp;vol. (T&uuml;bingen: Stauffenberg, 1990). 325-44.</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(3) Kracauer</span>&nbsp;</b><span>&rsquo;in tarih yazımı metodu i&ccedil;in bakınız&nbsp;<b>Thomas Elsaesser</b>, "<b><i>Cinema - The Irresponsible Signifier or the Gamble with History</i></b>," (Sinema &ndash; G&uuml;venilmez Şahit ya da Tarih ile Kumar) New German Critique (Yeni Alman Eleştirisi), no. 40 (Winter 1987).&nbsp;<b>Theodor W. Adorno</b>, "<b><i>Der wunderliche Realist: &Uuml;ber Siegfried Kracauer</i></b>," Noten zur Literatur vol. III &lsquo;te (Frankfurt a.M.: Suhrkamp, 1965).</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(4) Dominique Pa&iuml;ni</span>&nbsp;</b><span>,&nbsp;<b><i>Le temps expos&eacute;</i></b>&nbsp;(Paris: Cahiers du Cin&eacute;ma, 2002). 15.</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(5) Raymond Bellour</span>&nbsp;</b><span>, "<b><i>La chambre</i></b>," Trafic, no. 9 (1994). 50.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b>(6)</b>&nbsp;"<b><i>Filmk&auml;mpfer von au&szlig;en</i></b>," Film-Kurier, 1 Ocak&nbsp; 1931.</span></p>\r\n</div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(7) Hans Richter</span>&nbsp;</b><span>,&nbsp;<b><i>K&ouml;pfe und Hinterk&ouml;pfe</i></b>&nbsp;(Z&uuml;rich: Arche, 1967). 70.<b>Richter</b>&nbsp;sonradan&nbsp;<b>Mies</b>&rsquo;in 1924&rsquo;ten Tuğladan Kır Evi i&ccedil;in planı ve 1919&rsquo;dan onun Pr&auml;ludium &ccedil;izimi arasındaki g&ouml;rsel karşılaştırmayı &ccedil;izecekti. Bununla beraber,&nbsp;<b>Mies</b>&rsquo;in st&uuml;dyosuna yaptığı ilk ziyaret esnasında keşfettiği &ccedil;izimler belirsiz kalır. Muhtemelen, zaten o farklı bina kısımları veya Petermann Evi&rsquo;ndekiler (1921) arasındaki dinamik-asimetrik bir ilişki sergileyen Mies&rsquo;in ger&ccedil;ekleştirilmemiş Mimar Evi (1914) &ccedil;izimlerini g&ouml;rd&uuml;. bakınız&nbsp;<b>Westheim, Paul</b>. "<b><i>Mies van der Rohe - Entwicklung eines Architekten</i></b>." Das Kunstblatt 11 (1927), 57-58.</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b>(8)</b>&nbsp;"Bağımsız Film Birliği" 1929&rsquo;da, uluslar arası sinema avangardının&nbsp;<b>H&eacute;l&egrave;ne de Mandrot</b>&rsquo;un davetinde, La Sarraz&rsquo;da buluştuğu zamanda kuruldu. Bu toplantının bir yıl &ouml;ncesinde, aralarında&nbsp;<b>Le Corbusier</b>&nbsp;ve&nbsp;<b>Sigfried Giedion</b>&rsquo;un da bulunduğu mimari avangard &uuml;yeleri La Sarraz&rsquo;da Congr&egrave;s Internationaux d&rsquo;Architecture Moderne&rsquo;yi (CIAM) kurmak i&ccedil;in bir araya geldiler. "Birlik"in Alman birimi Berlin-Halensee&rsquo;deki "Rote M&uuml;hle"de Kasım 1930&rsquo;da kuruldu.</span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b>(9)</b>&nbsp;3 Aralık 1934 tarihli bir mektupta, Reichskammer&rsquo;in başkanı<b>Mies</b>&rsquo;i y&ouml;netmenle yapılacak bir tartışma organizasyonuna davet etti. 18 Aralık&rsquo;ta&nbsp;<b>Mies</b>&nbsp;yanıt verir: "Memnuniyetle katılırım (&hellip;). Heil Hitler."&nbsp;<b>Mies</b>&rsquo;in bu organizasyona katılıp katılmadığı bilinmiyor.&nbsp;<b>Mies</b>&rsquo;in yazışmaları i&ccedil;in bakınız "<b><i>Mies van der Rohe: Research Papers</i></b>," (Mies van der Rohe: Araştırma Belgeleri).&nbsp;<b>Mies van der Rohe</b>&nbsp;ve Modern Sanatlar M&uuml;zesi&rsquo;nin Mies van der Rohe Arşivinin kurulması ile ilgili belgeler, Kanada Mimarlık Merkezi&rsquo;nde (CCA)&nbsp;<b>Ludwig Glaeser</b>&nbsp;tarafından derlenen arşiv malzemesi koleksiyonu, CCA, Montreal.</span></p>\r\n</div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(10) Fritz Neumeyer</span>&nbsp;</b><span>,&nbsp;<b>Mies</b>&rsquo;in&nbsp;<b>Ada Bruhn</b>&nbsp;ile&nbsp;<b>Alois Riehl</b>&rsquo;in evinde &ouml;zel g&ouml;r&uuml;şmelerde bir araya geldiğini &ouml;ne s&uuml;rer. 1907&rsquo;de&nbsp;<b>Mies</b>Riehl&rsquo;in Berlin-Neubabelsberg&rsquo;deki evini dizayn etti &ndash;&nbsp;<b>Mies</b>&rsquo;in ilk işiydi bu. Bakınız,&nbsp;<b>Fritz Neumeyer</b>, "<b><i>Mies\'s First Project: Revisiting the Atmosphere at Kl&ouml;sterli</i></b>," (Mies&rsquo;in ilk projesi: Kl&ouml;sterli&rsquo;deki Atmosferi Tekrar Ziyaret) Berlin&rsquo;de&nbsp;<b>Mies</b>&rsquo;te, ed.<b>Barry Bergdoll</b>&nbsp;ve&nbsp;<b>Terence Riley</b>&nbsp;vol. (New York: Museum of Modern Art &ndash; 2001). 309-318.</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b>(11)</b>&nbsp;Reform proje Hellerau, &ouml;zellikle onun mimari g&ouml;r&uuml;n&uuml;şleri i&ccedil;in bakınız,&nbsp;<b>Marco De Michelis</b>,&nbsp;<b>Heinrich Tessenow</b>&nbsp;(Milan: Electa, 1991)</span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(12) Jaques-Dalcroze</span>&nbsp;</b><span>,&nbsp;<b>Kristiana Hartmann</b>, "\'Reformbewegeungen\',"da,<b><i>Entwurf zur Moderne</i></b>&rsquo;de s&ouml;yl&uuml;yor.&nbsp;<b><i>Hellerau: Stand Ort Bestimmung</i></b>, ed.&nbsp;<b>Werner Durth</b>&nbsp;vol. (<b><i>Stuttgart: Deutsche Verlags Anstalt</i></b>, 1996).</span></span></p>\r\n</div>\r\n<div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(13) Mary Wigman</span>&nbsp;</b><span>&nbsp;<b>Jaques-Dalcroze</b>&nbsp;ve&nbsp;<b>Rudolf Laban</b>&rsquo;ın bir &ouml;ğrencisiydi. Sonradan, kendi hareket teorilerini geliştirerek, &uuml;nl&uuml; bir kareograf-dans&ccedil;ı oldu.&nbsp;<b>Wigman</b>&nbsp;Miesler&rsquo;in hayat boyu arkadaşları olarak kaldı. 1920lerde Berlin&rsquo;den ge&ccedil;erken o ve onun dans topluluğunun &uuml;yeleri&nbsp;<b>Mies</b>&rsquo;in Am Karlsbad dairesinde kalacaktılar. Bakınız,&nbsp;<b><i>Mary Wigman ile G&ouml;r&uuml;şme</i></b>, kaset kaydı, "<b><i>Mies van der Rohe: Research Papers</i></b>&nbsp;(Araştırma Belgeleri)," Kanada Mimarlık Merkezi (CCA), Montreal.</span></span></p>\r\n</div>\r\n</div>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-family: \'Courier New\'; font-size: 10pt;"><b><span>(14) Alexander von Salzmann</span>&nbsp;</b><span>, "<b><i>Licht, Belichtung und Beleuchtung</i></b>," Claudel-Programmbuch&rsquo;ta vol. (Hellerau: 1913). 70.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><span style="font-size: 10pt;"><b><span style="font-family: \'Courier New\';">(15)&nbsp;<i>Bl&auml;tter f&uuml;r Architektur und Kunsthandwerk</i></span>&nbsp;</b><span style="font-family: \'Courier New\';">, no. 6 (1913). 21. yazara g&ouml;re&nbsp;<b>Alexander von Salzmann</b>&nbsp;&lsquo;ın ışık kurulumu 70000 Mark tutuyordu&ndash; o zaman i&ccedil;in olağan&uuml;st&uuml; bir paha.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(16) Fortuny&nbsp;</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">sayısız tiyatroyu kendi ışıklandırma sistemi ve katlanabilir sikloramalarla donattı &ndash;1907&rsquo;de Berlin&rsquo;deki Kroll Tiyatrosu da bunların arasındadır.&nbsp;<b>Max Reinhardt</b>&nbsp;da&nbsp;<b>Fortuny</b>&nbsp;ile tanıştı ve kendi verdiği isimle "Himmelskuppeln"lerinden biri olan, Berlin&rsquo;deki Deutsche Tiyatrosunda ona kurdurttu. 1906&rsquo;da&nbsp;<b>Fortuny</b>AEG (Allgemeine Elektrizit&auml;tsgesellschaft) ile birlikte kubbeyi ışıklandırma sistemiyle birlikte pazarlamak i&ccedil;in bir ortaklık kurar.&nbsp;<b>Mies</b>&rsquo;in 1906&rsquo;dan itibaren Berlin&rsquo;de yaşadığı ger&ccedil;eği dikkate alınırsa, sikloramayı duymuş olması kuvvetle muhtemel. İlaveten, 1908 ve 1912 yılları arasında, 1907&rsquo;de AEG tarafından uyumlu bir firma imajı geliştirmesi i&ccedil;in g&ouml;revlendirilen&nbsp;<b>Peter Behrens</b>&nbsp;i&ccedil;in &ccedil;alışmak suretiyle,&nbsp;<b>Mies Fortuny</b>&nbsp;ile olan işbirliğini de i&ccedil;eren bilgiye sahip olmuş olmalıydı.&nbsp;<b>Fortuny&nbsp;</b>&uuml;zerine bakınız,&nbsp;<b>Guillermo De Osma</b>,&nbsp;<b><i>Mariano Fortuny: His Life and Work</i></b>&nbsp;(Hayatı ve Eseri) (London: Aurum, 1980). 65-75.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(17)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;Bilinmeyen anlatıcı&nbsp;<b>Adolphe Appia</b>&rsquo;da bildirmektedir,&nbsp;<b>Adolphe Appia</b>:&nbsp;<b><i>Essays, Scenarios, and Designs</i></b>&nbsp;(Denemeler, Senaryolar ve Tasarımlar), ed.&nbsp;<b>Richard Beacham</b>&nbsp;(Ann Arbor: University of Michigan Press, 1989). 15.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(18) Upton Sinclair</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>World&rsquo;s End</i></b>&nbsp;(D&uuml;nyanın Sonu)(New York: Literary Guilt of America(Amerika&rsquo;nın Edebi Su&ccedil;u), 1940),5</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(19) Adolph Appia</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>Die Musik und die Inscenierung</i></b>&nbsp;(M&uuml;nchen: Bruckmann, 1899). 32.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(20) Appia</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;(1899), 17.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(21) Appia</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>La musique et la mis-en-sc&egrave;ne</i></b>&nbsp;(1897). Osma&rsquo;da aktarılmaktadır, 65.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(22)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;<b>Adolphe Appia</b>,&nbsp;<b>Appia</b>&rsquo;daki "<b><i>Eurhythmics and the Theatre</i></b>," (Ritmik Dans ve Tiyatro) (1911),&nbsp;<b>Adolphe Appia</b>:&nbsp;<b><i>Essays, Scenarios, and Designs</i></b>&nbsp;(Denemeler, Senaryolar ve Tasarımlar). 138.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(23) Walter Benjamin</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>Gesammelte Schriften</i></b>&rsquo;teki "<b><i>Der S&uuml;rrealismus - Die letzte Momentaufnahme der europ&auml;ischen Intelligenz</i></b>,", ed.&nbsp;<b>Rolf Tiedemann</b>&nbsp;ve&nbsp;<b>Hermann Schweppenh&auml;user</b>&nbsp;vol. 2 (Frankfurt a.M.: Suhrkamp, 1977). 309. Benjamin, Se&ccedil;me Yazılar, vol. 2&rsquo;de terc&uuml;me edilmiş, ed.&nbsp;<b>Michael W. Jennings</b>,&nbsp;<b>Howard Eiland</b>, ve&nbsp;<b>Gary Smith</b>, &ccedil;ev.&nbsp;<b>Rodney Livingstone</b>&nbsp;ve diğerleri. (Cambridge, Mass.: Harvard University Press, 1999), 217.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(24)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;Aynı yazıda. Benim &ccedil;evirim.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(25)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;"<b>Mies van der Rohe</b>&nbsp;&ndash;&nbsp;<b><i>Research Papers</i></b>"&rsquo;ta&nbsp;<b>Sergius Ruegenberg</b>ile yapılan rop&ouml;rtaj, CCA.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(26) Ruegenberg&nbsp;</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">ile yapılan rop&ouml;rtaj.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(27)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;Aynı yazıda.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(28) Ludwig Mies van der Rohe</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">, "<b><i>Hochhausprojekt f&uuml;r Bahnhof Friedrichstrasse in Berlin</i></b>," Fr&uuml;hlicht, no. 1 (1922). 122.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(29) Mies</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;ile yapılan r&ouml;portaj, Ekim 1964&rsquo;teki RIAS kaydı, "<b>Mies van der Rohe</b>&nbsp;&ndash;&nbsp;<b><i>Research Papers</i></b>", CCA.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(30)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;<b>Walter Benjamin</b>,&nbsp;<b><i>Gesammelte Schriften</i></b>&rsquo;deki "<b><i>Das Kunstwerk im Zeitalter seiner mechanischen Reproduzierbarkeit</i></b>,", ed.&nbsp;<b>Hermann Schweppenh&auml;user</b>&nbsp;and&nbsp;<b>Rolf Tiedemann</b>&nbsp;vol. VII (Frankfurt a.M.: Suhrkamp, 1980). İkinci Versiyon, 369.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(31) Stephan Oettermann</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>Das Panorama: Die Geschichte eines Massenmediums</i></b>&nbsp;(Frankfurt a.M.: Syndicat, 1980). 9.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(32)&nbsp;</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">"<b><i>Marine Panorama</i></b>" (Deniz Panoraması) Lehrter Stadtbahnhof&rsquo;un civarına yerleştirilmiştir. Cam modelin&nbsp;<b>Mies&rsquo;</b>in dairesinin balkonundan &ccedil;ekilen fotoğraflarından bazılarının kentin farklı bir yerine konulduğu bilinmektedir. Bundan dolayı bu fikrin se&ccedil;iminin planlı olduğu anlaşılabilir. "Deniz Panoraması" sonradan bir modern sanatlar sergi salonu ve en son da ağa&ccedil; işleri i&ccedil;in bir mağaza olarak kullanılmıştır.&nbsp;<b>Mies&nbsp;</b>1905&rsquo;e kadar Berlin&rsquo;de yaşamıştır ve mobilya tasarımcısı&nbsp;<b>Bruno Paul</b>&nbsp;i&ccedil;in yaptığı &ccedil;alışma sayesinde bu ayrıcalıklı binanın ayırtına varabilmiştir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(33) Manfredo Tafuri</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">,&nbsp;<b><i>The Sphere and the Labyrinth</i></b>&nbsp;(K&uuml;re ve labirent) (Cambridge, Mass.: MIT Press, 1987). 111.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(34) Marta Braun</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">, "<b><i>Anton Giulio Bragaglia und die Fotografie des Unsichtbaren</i></b>," Im Reich der Phantome: Fotografie des Unsichtbaren vol.&rsquo;da (Ostfildern-Ruit: 1997). 111.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(35)</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&nbsp;Sinemadaki hadise ve zamanlama konsepti &uuml;zerine&nbsp;<b>Marie Ann Doane</b>,&nbsp;<b><i>The Emergence of Cinematic Time</i></b>&rsquo;a (Sinematik Zamanın Oluşumu) bakınız (Cambridge, Mass.: Harvard University Press, 2002)140-71.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; text-align: justify;"><b><span style="font-size: 10pt; font-family: \'Courier New\';">(36) Doane</span></b><span style="font-size: 10pt; font-family: \'Courier New\';">&rsquo;de aktarılmıştır, 140.</span></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', 192, 63, 'Yazarlarımızdan', '/images/yazilar/Resim%2014-1%20Mies%20Glasraum.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (45, 'ay-j166', 'varlik-evi-nden-kovulan-cocuklar', 'Varlık Evi\'nden Kovulan Çocuklar', 'Nagihan Konukcu', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><i>Varlık Evi</i>\'nden Kovulan &Ccedil;ocuklar</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Nagihan Konukcu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><a href="mailto:tasarim@sekans.org" style="color: #895f37;">tasarim@sekans.org</a></b></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="line-height: 14px; font-family: Verdana; font-size: 10pt; font-weight: bold;">İki Dil Bir Bavul</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Y&ouml;netmen</b>:<span style="font-size: 10pt;">&nbsp;&Ouml;zg&uuml;r Doğan, Orhan Eskik&ouml;y</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Senaryo</b>:&nbsp;<span style="font-size: 10pt;">Orhan Eskik&ouml;y</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Oyuncular</b>:&nbsp;<span style="font-size: 10pt;">Emre Aydın; Rojda Huz, Vehip Huz, Z&uuml;lk&uuml;f Huz, Zilkif Yıldırım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni</b>:&nbsp;<span style="font-size: 10pt;">Orhan Eskik&ouml;y</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Kurgu</b>:&nbsp;<span style="font-size: 10pt;">Orhan Eskik&ouml;y, Thomas Balkenhol</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Yapımcı</b>:&nbsp;<span style="font-size: 10pt;">&Ouml;zg&uuml;r Doğan, Orhan Eskik&ouml;y</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;"><b>Ortak Yapımcı</b>:&nbsp;<span style="font-size: 10pt;">Pieter Van Huystee, Yama&ccedil; Okur, Nadir &Ouml;perli</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Cambria;"><span style="font-size: x-small;"></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-weight: bold;">&Ouml;D&Uuml;LLER</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* 15. Gezici Film Festivali - G&uuml;m&uuml;ş Boğa &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* 15. Londra T&uuml;rk Film Festivali - Seyirci &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Antalya Altın Portakal Film Festivali - En İyi İlk Film &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Abu Dabi 9. Orta Doğu Film Festivali - En İyi Orta Doğu Belgesel Film &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Uluslararası Romanya Film Festivali - En İyi Belgesel Film &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Adana Altın Koza Film Festivali - B&uuml;y&uuml;k J&uuml;ri Yılmaz G&uuml;ney &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Adana Altın Koza Film Festivali - Sinema Yazarları Derneği (SİYAD) En İyi Film &Ouml;d&uuml;l&uuml;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* 5. ZagrebDox - LITTLE STAMP En İyi Film</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-style: italic;">* Saraybosna Film Festivali - EDN Talent</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-family: Cambria;"><b>&nbsp;<span style="font-size: x-small;"><br /></span></b></span><span style="font-family: Verdana; font-size: 10pt; line-height: 14px; font-weight: bold;">2009 / 81&rsquo; / T&uuml;rkiye &ndash; Hollanda</span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px; text-align: justify;"><span style="font-size: x-large;"><span style="font-family: Verdana;">İ</span></span><span style="font-family: Verdana; font-size: 10pt; line-height: 14px;">nsan, salt kendi dilinde konuşmak/konuşulduğunu duymak yoluyla kimliğinin ve tarihinin, sınırlarını hayal g&uuml;c&uuml;yle dahi &ccedil;izemediği coğrafyalara uzandığı duygusuna kapılır. Benzer şekilde aidiyetlerimizi el yordamıyla edindiğimiz yaşamda, bizi var kılan tek şeye sarılırız hep; dilimize. &Ccedil;&uuml;nk&uuml; sadece dil, varlığımızın evidir (<b>Heidegger</b>).</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px;">Şimdi bu s&ouml;ylemi az sonra &lsquo;a&ccedil;ılım&rsquo;ını yapacağımız filmimize uyarladığımızda o evi temelinden sarsmak gerekecek; &ouml;teki&rsquo;nin &lsquo;ben&rsquo; ve &lsquo;devlet&rsquo; kıskacındaki tekilliği/tekinsizliği, etnik profilinden bilin&ccedil;li olarak damıtılmış haliyle, yabancılaşma anlatısının merkezinde yeniden kurulacak/kurgulanacak.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-family: Verdana; font-size: 10pt; line-height: 14px;">A&ccedil;ılan ilk &ccedil;er&ccedil;eve aracın &uuml;zerinde bi&ccedil;imsizce duran bir bavul g&ouml;r&uuml;nt&uuml;s&uuml;nden, aracın i&ccedil;indeki hipnotize edilmiş gibi kameraya &lsquo;g&ouml;z&uuml;n&uuml; diken&rsquo; esas k&ouml;yl&uuml;ye oradan da sadece camdan dışarıyı seyreden &lsquo;yolcu&rsquo;ya kayar. İki karakterin g&ouml;r&uuml;nt&uuml;s&uuml; arasındaki benzeşlik, iki ayrı d&uuml;nyayı tanımanın, tanımlamaya &ccedil;alışmanın eşiğinde kurulur. K&ouml;ye varıldığında &lsquo;yolcu&rsquo;nun bavulunu indiren adamın kameraya fırlattığı kısa ve b&ouml;l&uuml;nm&uuml;ş bakışla pekişen bu sahne fotoğraf olarak değil belki ama filmin ger&ccedil;ek yaşamla i&ccedil; i&ccedil;e kurgulanmış anlatı ekseni a&ccedil;ısından değerlidir.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/001.jpg" alt="" width="520" height="292" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">İlk valizini bir K&uuml;rt şehrine hazırlayan horozkentli &lsquo;&ouml;ğretmen&rsquo; Emre, K&uuml;rt&ccedil;e bilmez, T&uuml;rk&ccedil;e&rsquo;yi de aksanlı s&ouml;yler; abc&rsquo;sini, yana yatık &ccedil;izgilerini, sincapla cevizin hikayesini kapıp gelmiştir T&uuml;rkiye&rsquo;nin batısından aksi istikametteki Demirci K&ouml;y&uuml;&rsquo;ne. Okulun bitişiğindeki sadece adı lojman olan &lsquo;oda&rsquo;sının kapısından i&ccedil;eriye attığı ilk adım ile yaşadığı hayal kırıklığına, zaman i&ccedil;inde kentte &lsquo;elinin altında&rsquo; olan ve fakat bu topraklardaki yaşam pratiğinde kendine yer bulamayan bir&ccedil;ok şeyin yokluğu eklenir. Sıradan olanaklara bile sahip değildir artık. Evinden uzağa d&uuml;şmenin arazlarını paylaşmak, gsm şebekesi aracılığıyla anneye d&uuml;şer.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">İlk g&uuml;n hi&ccedil;bir &ouml;ğrencisi okula gelmeyince, &ccedil;areyi &ccedil;ocukların evlerini dolaşmakta bulan, bu sayede ertesi g&uuml;n sınıfın yarıdan fazlasını ancak doldurabilen ve &ccedil;ocuklara kendini tanıtırken, daha &ouml;nce hi&ccedil; &ouml;ğretmenlik yapmamış olmasına &ccedil;ekine &ccedil;ekine vurgu yapan Emre &ouml;ğretmen, anlatısını anlamlı kılmak i&ccedil;in idealist bir karakter gereksinen film i&ccedil;inde, kendisini sadece irade ve se&ccedil;im yokluğu nedeniyle sistemin &ouml;ğretisinin temsilcisi konumuna indirgediği noktada izleyici karşısında ya ilk sıfırını &ccedil;eker ya da olağan&uuml;st&uuml; sempati toplar. Karşılıklı iletişimsizliğin temelinde kendisinin payı olduğunu hi&ccedil; d&uuml;ş&uuml;nmez &ccedil;&uuml;nk&uuml; normal olan kendisidir, T&uuml;rk&ccedil;e biliyor ve konuşuyor olmasıdır; kabul g&ouml;rmemesi i&ccedil;in hi&ccedil;bir neden yoktur. Bu anlamda K&uuml;rt&ccedil;e bilmeyen &ouml;ğretmenin T&uuml;rk&ccedil;e bilmeyen &ouml;ğrencileriyle olan iletişimsizliği &uuml;zerine &lsquo;g&ouml;sterilen&rsquo; ve/veya &lsquo;kurulan&rsquo; dramı i&ccedil;in tasarlanan mesajda, emre &ouml;ğretmenin bir sorgulama ve &ccedil;&ouml;z&uuml;m &uuml;retme mekanizmasına sahip olduğu tezi var idiyse eğer, bunun bir i&ccedil; sesten fazlası olduğunu g&ouml;rmeliydik. &Ccedil;&uuml;nk&uuml; gerek filmin y&ouml;netmenlerinin gerek bir&ccedil;ok eleştirmenin ağız birliği ettiği şey, vatana millete faydalı bir &ouml;ğretmen olmak mitiyle donanıp onca yolu tepmiş bir idealistle karşı karşıya olduğumuz. Oysaki seyrettiğimiz idealize edilememiş bir idealistten fazlası değildir. Karakterin izleyici ile paylaştığı biricik sorgu, &lsquo;neden onun orada, bu koşullarda olduğu&rsquo;dur. Gerisi zaten vatan-millet-cehalet &uuml;&ccedil;genidir.<br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/007.jpg" alt="" width="520" height="292" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Bu &uuml;&ccedil;genin tabanında yer alan ve &ouml;yk&uuml;y&uuml; ger&ccedil;eğe en yakın haliyle kuşanan sınıf, klasik t&uuml;rk &ouml;ğretisi i&ccedil;in gerekli kompozisyona sahiptir. Duvarlarda salınan T&uuml;rk bayrakları, belirli g&uuml;n ve haftalar ile tarih &ccedil;izelgesi gibi eğitsel birtakım eşyalarda tasvirleşen milliyet&ccedil;i/&ouml;zc&uuml; kimlik, hemen sonra yakın coğrafyası i&ccedil;in anadil, anakarası i&ccedil;in &lsquo;yabancıca&rsquo; olan K&uuml;rt&ccedil;e&rsquo;nin &ouml;dev olarak kendisine getirilmesi karşısında &ccedil;ocukları tek ayak &uuml;zerinde bekleterek hizaya sokmaya &ccedil;alışan, gelenek&ccedil;i ve &ouml;ğrenilmiş bilgiye/bilgisizliğe sahip, enformatik a&ccedil;ıdan yetersizken şimdi fiziksel koşulları nedeniyle de sakatlanan bir &ouml;ğretmen prototipiyle tamamlanır. Sınıfta K&uuml;rt&ccedil;e konuşmak yasaktır, &ccedil;&uuml;nk&uuml; &ouml;ğretmen (baskın g&ouml;r&uuml;ş&uuml;n/ulusal dilin temsilcisi) K&uuml;rt&ccedil;e bilmemektedir, &ccedil;ocukların (&ouml;teki&rsquo;nin/alt k&uuml;lt&uuml;r&uuml;n/etnik unsurun temsilcileri) bu durumda genel/olumlanmış/tartışılmaz olana itaati en doğrusu olacaktır. Devlet baba, &ouml;ğretmen oğlu eliyle bunu buyurmuştur ve oğul bunu sorgulamayacak olanlar arasından kura ile se&ccedil;ilmiştir. Ders anlatırken elindeki sopayı, yanına &ccedil;ağırdığı &ouml;ğrencinin eline tutuşturan Emre &ouml;ğretmenin, bir &ccedil;ocukla iletişim kurmak i&ccedil;in bir diğer &ccedil;ocuğu aracı konumuna getirerek, dolayımlı iletişim kurma &ccedil;abası da bu d&uuml;ş&uuml;nceyi doğrular. (Yabancı) bir dil &ouml;ğretmek i&ccedil;in ka&ccedil;ınılmaz iletişim s&uuml;recinin salt konuşma/konuşturma ile değil, T&uuml;rk&ccedil;e&rsquo;den sonra &ouml;ğretmeyi planladığı&nbsp;<i>hayat bilgisi</i>yle beraber işlediği bilgisi insan olmanın kitabında varsa da, milli eğitimin m&uuml;fredatında yer almaz. Tuvalete gitmek i&ccedil;in izin isterken, kaleminin ucunu a&ccedil;arken, okul bah&ccedil;esine ilk fidanını dikerken anadilinden, varlık evinden kovulur Rojda, Vehip, Bahar; Zilkif Z&uuml;lk&uuml;f oluverir. Kağıt sıkıştırılarak kapanan sınıf kapısı, bir sistemin, egemen k&uuml;lt&uuml;rle &lsquo;aynı&rsquo;lık taşımayanı, dilini kapının dışında bırakmaya zorladığı bilin&ccedil;altının temsilidir. Sistem &ouml;teki&rsquo;ni yok etmez, ama kabul de edemez; aynılaştıramıyorsa, yabancılaştırma aklını &uuml;retir. Başkasının varlık evinde sığıntı yapar &ccedil;ocukları, kendi &lsquo;ev&rsquo;lerinin penceresinden baktıklarında bir laf c&uuml;mb&uuml;ş&uuml;, hep bir ağızdan bağırış &ccedil;ağırıştan başka bir şey gibi durmayan &lsquo;and&rsquo;lar okutur onlara, karnelerini zoraki pekiyilerle donatır.<br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/003.jpg" alt="" width="520" height="292" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Okula gitmenin, tarlada &ccedil;alışılmayan, derede &ccedil;amaşır d&ouml;v&uuml;lmeyen, kardeşlere bakılmayan zamanlarda oyun oynamanın bir başka hali olduğu fikri g&ouml;zlerinden, &ouml;zensiz &uuml;st başlarından aşikar &ccedil;ocuklar ve onlara iyi davrandığı ve karne i&ccedil;in para istemediği s&uuml;rece annelerinin iyi olarak belleyecekleri &ouml;ğretmen arasındaki isim karmaşası, bir komedi unsuru gibi dursa da, filmin en kilit okuma metnini a&ccedil;ık eder. Z&uuml;lk&uuml;f ile Zilkif arasındaki fark insanın kendisi &lsquo;olabilme/kalabilme&rsquo; hali ile m&uuml;dahale edilerek &lsquo;belirlenme/farklılaşma&rsquo; hali arasındaki gerilimdir. Zilkif dilini s&ouml;z&uuml;n&uuml; anlamadıkları bir yabancıyla oynadıkları bu oyundan &ccedil;ok sıkıldığından (kısaca Z&uuml;lk&uuml;f olmaktan) ya da bu farklılaşma halini ve bunun ka&ccedil;ınılmazlığını sezinlediğinden olacak, &ouml;ğretmeni tarafından uyarılana kadar ya da arkadaşlarının y&uuml;reklendirmeleriyle işlerin hi&ccedil; de fena gitmediğini anlayana kadar &ccedil;antasını sırtından d&uuml;ş&uuml;rmez. Okuldan eve d&ouml;nd&uuml;ğ&uuml;nde ise &ouml;nl&uuml;ğ&uuml; &ccedil;ıkarmak i&ccedil;in sabır g&ouml;steremeyen Z&uuml;lk&uuml;f, bunu yardım almadan beceremez; &ouml;nl&uuml;ğ&uuml; sıyırınca &uuml;zerinden, Zilkif olur yine i&ccedil;inden &ccedil;ıkıveren. Tanıdığı, bildiği yerde, g&uuml;vendedir şimdi. Yarın yeniden Z&uuml;lk&uuml;f olana kadar&hellip;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Peki T&uuml;rk&ccedil;e&rsquo;nin kendileri i&ccedil;in bir sesler k&uuml;mesi, işittikleri herhangi bir &lsquo;şey&rsquo; olmaktan &ouml;teye gidemediği K&uuml;rt &ccedil;ocuklara, &ouml;ğrenmeye &ccedil;alıştıkları şeyin sadece bir dil olmadığını, beraberinde tabi tutuldukları bu yabancılaşmanın, bu topraklarda yıllardır s&uuml;regiden etnik kimlik &ccedil;atışmaları ve milliyet&ccedil;ilik sorunlarının g&ouml;lgesinde, iktidarların ve ulus-devletlerin d&uuml;ellosu olduğunu anlatabilir mi Emre &ouml;ğretmen? Kendisi bilir mi bu tarihi? K&ouml;yl&uuml;lerden birinin K&uuml;rt&ccedil;enin dilden sayılmadığına dair anlattığı trajikomik enstantaneye &lsquo;işte bu yanlış&rsquo;tan &ouml;te yorum getiremeyen eğitimsiz eğitimci, dilini d&ouml;nd&uuml;remediği bir dili yadsımak yetisiyle donatılmıştır. &Ccedil;&uuml;nk&uuml; o mevcut sistemin ve ideolojinin korunmasının yegane g&uuml;vencesidir; edilgenliğiyle a&ccedil;ık&ccedil;a şunu s&ouml;yler: &lsquo;Ben bu toplumun konuşmayan vicdanı, devletin dipten y&uuml;kselen i&ccedil; sesi, biricik vatanımın tek dilli, orta yollu evladıyım. Devletimin menfaati i&ccedil;in, devletim &ouml;yle istediği i&ccedil;in, bizimle aynı dili konuşmayanlara karşı hoşg&ouml;r&uuml;l&uuml; olmayacağıma, bu uğurda b&uuml;t&uuml;n bireysel yiğitliklerimi ulu orta sergileyeceğime and i&ccedil;erim!&rsquo;&nbsp;&nbsp;<br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/016.jpg" alt="" width="520" height="292" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Ana karakter &uuml;zerinden &ccedil;ıkarsamaya m&uuml;sait t&uuml;m bu ger&ccedil;eklik ve kurgu katmanlarının izlenme ve okunma evreleri arasındaki d&uuml;ş&uuml;nsel s&uuml;re&ccedil;lerini dikkate alarak&nbsp;<b><i>İki Dil Bir Bavul</i></b>&rsquo;u a&ccedil;ılımlama eğilimi, iki katmanlı bir etki d&uuml;zeyi yaratır; birincisi g&ouml;sterdiği &uuml;zerinden yarattığı etkidir. Bir diğeri ise tarafsız durma gayreti ile &uuml;zerine kendi c&uuml;mlelerini s&ouml;ylemeyerek dışarıda bıraktığı - ya da filmin i&ccedil;ine al(a)madığı- ve fakat işaret ettikleri ile izleyicinin yargısı ve bellek muhasebesi &uuml;zerindeki uyarıcı etkisi. Bir kurmaca film i&ccedil;in fazla doğrusal, bir belgesel i&ccedil;inse fazla bi&ccedil;imli duran anlatı, ana karakterinin genel ruh hali ve konuya hem &ccedil;ok yakın hem &ccedil;ok &ouml;telenmiş duran maddi varlığıyla, filmi rastlantısal b&uuml;t&uuml;nl&uuml;ğ&uuml; i&ccedil;inde ger&ccedil;eklikle ilişkilenmesindeki kırılma noktalarıyla salınır halde bırakır. İnsani bir zaafa d&ouml;n&uuml;şmekten kendini kurtaramayan ve etki g&uuml;c&uuml;n&uuml; de bundan alan &ouml;yk&uuml; niyet ekseninde denklemin &ouml;b&uuml;r tarafına değer kaybetmeden ge&ccedil;se de, dramatik unsur &lsquo;aşırı tarafsızlık&rsquo; nedeniyle politik bir proteze d&ouml;n&uuml;şerek filmi &lsquo;kolay&rsquo; bir&nbsp;<i>dil</i>&nbsp;ve g&ouml;r&uuml;nt&uuml; evreninin ağına d&uuml;ş&uuml;r&uuml;r.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Emre &ouml;ğretmen burada ge&ccedil;ireceği bir yılının, T&uuml;rkiye&rsquo;de bir yandan eşelenip, bir yandan &uuml;st&uuml; &ouml;rt&uuml;len bir ger&ccedil;ekliğe &ccedil;engel atacak bir yaşanmışlık değeri olacağını kendisi de kestiremezdi belki ancak i&ccedil;imizden &ccedil;ekip &ccedil;ıkarılmış bu karakterle kurulan &ouml;zdeşlik sayesinde, sinemamızın tarihi kayıtları i&ccedil;inde uzun s&uuml;redir doldurulmayı bekleyen bir boşluk &ndash; ki o boşluk tam olarak neden kaynaklanır, bununla ilgili bir bilgiye sahip olamıyoruz!- gişesi &ouml;d&uuml;llerle tescillenmiş filmleri sarıp sarmalama i&ccedil;g&uuml;d&uuml;selliği ile&nbsp;<b><i>İki Dil Bir Bavul</i></b>&nbsp;sayesinde doldurulmuş olur! T&uuml;rk seyircisinin de nicedir beklediği bir atılımdır bu. &lsquo;Belgesel mi, kurmaca mı; biraz ondan, biraz bundan mı?&rsquo; tartışmalarının &ouml;n&uuml;, filmin &ouml;yk&uuml;s&uuml;n&uuml; y&ouml;netmenlerden&nbsp;<b>&Ouml;zg&uuml;r Doğan</b>&rsquo;ın &ouml;z yaşam &ouml;yk&uuml;s&uuml;nden esinler taşıyan bir ge&ccedil;mişten aldığı y&ouml;n&uuml;ndeki bilgi ile kesilip, film i&ccedil;in ş&uuml;phe duymadan belgesel yakıştırması yapılır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Her ne kadar işimize yarayacak olan kurulmamış, rol&uuml; ezberletilmemiş, hani o &lsquo;bizden biri&rsquo; olarak g&ouml;r&uuml;nesi bir karakterse de, Emre &ouml;ğretmen kameranın varlığı karşısında her oyuncu kadar &ndash; t&uuml;m kendiliğindenliğine rağmen yine de oynamaktadır &ccedil;&uuml;nk&uuml; - şekil değiştirir; durağan ve devinimsiz kamera kullanımları ve ille de hareket edilecekse zoom ile sağlanan zoraki yakınlık ve uzaklıkla beraber, uğradığı değişimi, bir bakıma kamera dışında ve bizim g&ouml;rmediğimiz zamanlarda yaşar, kadraja daha sonra dahil olur. Bu başkalaşmanın zamansal sı&ccedil;ramalarının anne ile yapılan konuşmaların g&uuml;ndemi, &ouml;ğrencilerle yaşanılan iletişimsizliğin yarattığı baskı ve mevsim ge&ccedil;işleri &uuml;zerinden verilmesi ve t&uuml;m bunların arka fonundan m&uuml;ziğin kovulması, filmin nefesini idareli kullanma i&ccedil;g&uuml;d&uuml;s&uuml;d&uuml;r; &ccedil;&uuml;nk&uuml; bu filmin dili, seyircinin dili olmalıdır!&nbsp;&nbsp;&nbsp; &nbsp;<br />&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/iki%20dil%20bir%20bavul5.jpg" alt="" width="520" height="309" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify; line-height: 16px;"><span style="font-size: 10pt; line-height: 14px; font-family: Verdana;">Bununla beraber seyirci filmin final sahnesinde s&ouml;z hakkını &ccedil;ocuklara kaptırır. Okul biter bitmez horozkentli Emre memleket yollarına d&uuml;şer&nbsp;<i>bir dil bir bavul</i>; &ccedil;ocuklar da kendilerini oyuna bırakırlar; &ccedil;ocuk olmanın şeffaflığında kaybolur gider b&uuml;t&uuml;n bir yılın telaşı. Dil sorunsalı&nbsp;<i>yılan hikayesi</i>ne d&ouml;ner; dokunmazsan&nbsp;<i>taş</i>&nbsp;gibi durur da &ouml;ylece yerinde. Sadece kimine g&ouml;re kara, kimine g&ouml;re yeşildir, hepsi bu. Koşarak k&ouml;y&uuml;n deresine atlar &ccedil;ocuklar, şen şakrak g&uuml;l&uuml;şleri arasından akar gider yılanın hikayesi de. Kamera Emre &ouml;ğretmeni bırakmıştır artık, &ccedil;ocukların ardına d&uuml;şer varlık evlerinin yolunu tutturmuş giderlerken peşi sıra.&nbsp; Şimdi &ouml;ğretmen de &ccedil;ocuklar da eskisi kadar mutludur kendi sığ sularının kıyılarında&hellip;</span></p>', 70, 63, 'Yazarlarımızdan', '/images/yazilar/001.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (46, 'ay-j167', 'sakli-yuzler-in-anlati-eksenleri', 'Saklı Yüzler\'in Anlatı Eksenleri', 'Cem Kayalıgil', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Saklı Y&uuml;zler\'in Anlatı Eksenleri</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Cem Kayalıgil</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>&nbsp;</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Y&ouml;netmen:</span>&nbsp;</b><span>&nbsp;Handan İpek&ccedil;i</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Senaryo:</span>&nbsp;</b><span>&nbsp;Handan İpek&ccedil;i</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Oyuncular:</span>&nbsp;</b><span>&nbsp;Şenay Aydın, İştar G&ouml;kseven, Cem Bender, Berk Hakman, F&uuml;sun Demirel</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Yapımcı:&nbsp;</span>&nbsp;</b><span>Handan İpek&ccedil;i</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni:</span>&nbsp;</b><span>&nbsp;Feza &Ccedil;aldıran</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Kurgu:</span>&nbsp;</b><span>&nbsp;Aytekin Birkon</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>M&uuml;zik:</span>&nbsp;</b><span>&nbsp;anima</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Dağıtımcı:&nbsp;</span>&nbsp;</b><span>Bir Film</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>2006/127&rsquo;/T&uuml;rkiye &ndash; Almanya</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-small;"></span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/sakli%20yuzler.jpg" alt="" width="441" height="633" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">Y</span></b><span style="font-size: 10pt;">eni T&uuml;rk sinemasının politik tavır sahibi y&ouml;netmenlerinden&nbsp;<b>Handan İpek&ccedil;i</b>, tamamlanması bir hayli gecikmiş &uuml;&ccedil;&uuml;nc&uuml; filminde kadın sorununun en vahim bi&ccedil;imiyle g&ouml;r&uuml;n&uuml;rl&uuml;k kazandığı olgulardan birisi olan&nbsp;<i>namus cinayetlerine</i>&nbsp;eğiliyor.<b>İpek&ccedil;i</b>&rsquo;nin bir &ouml;nceki filmi&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk&nbsp;</i></b>(2001)<i>,&nbsp;</i>toplumsal-tarihi-politik-siyasal boyutlarıyla yumaklanıp her g&uuml;n daha da acılaşan K&uuml;rt meselesinin, bireysel bir d&ouml;n&uuml;ş&uuml;m &ouml;yk&uuml;s&uuml; &ccedil;er&ccedil;evesinde ele alınma &ccedil;abasıydı. Y&ouml;netmeninin adının geniş bir seyirci kitlesince duyulmasını sağlayan bu film, aşağıda a&ccedil;acağım nedenlerle, aslında sinemasal bir &ouml;zg&uuml;nl&uuml;k taşımıyor ve seyirciyi duygulandırdığıyla, ona&nbsp;<i>min&ouml;r&nbsp;</i>bir duyarlılık kazandırdığıyla kalıyordu.&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin yeni filmi&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;de<b><i>&nbsp;</i></b>ise bu kadarıyla yetinmeyerek konuya daha uygun olan bir tavır sergilediğini; eleştirel duruşunu bir&nbsp;<i>estetik y&ouml;nelim</i>&nbsp;&uuml;zerinden kurmayı g&ouml;zeterek [1], sanatsal ve politik a&ccedil;ılımları aracılığıyla toplumsal bilinci uyandırmakta &ccedil;ok daha yetkin bir yapıta imza atmış olduğunu iddia edebiliriz.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</span></i></b><span>; meseleye bakışında devletin s&ouml;ylemini en arı haliyle sunan emekli bir hakimin, dilini duymayı reddettiği, k&uuml;lt&uuml;r&uuml;n&uuml; yok saydığı k&uuml;&ccedil;&uuml;k bir K&uuml;rt kızına ağır ağır bağlanışını anlatıyordu. Seyirciyle arasında bir vicdan ortaklığı kurmaya baştan yatkın &ouml;yk&uuml;s&uuml; sayesinde film b&uuml;y&uuml;k ilgi g&ouml;rm&uuml;ş ve beğeni toplamıştı. Ancak eser, iki kritik sorundan muzdaripti: &Ouml;ncelikle, ele aldığı meseleyi &ldquo;zıt karakterler&rdquo; motifine indirgeyip ana karakteri salt&nbsp;<i>temsil ettiği&nbsp;</i>şeylerle tarif ederek kolaya ka&ccedil;an bir senaryoya dayanıyordu. Karakterler arasındaki zıtlık, sosyal-sınıfsal-dilsel ayrımlar ile yaş ve cinsiyet farkları bağlamına oturtuluyordu. Ama buradaki temellendirme &ouml;ylesine beylik kodlarla işleniyordu ki emekli hakim, resmi s&ouml;ylemin dolaysız v&uuml;cut bulmuş hali olmak dışında hemen hi&ccedil;bir &ouml;zellik taşımıyordu. Bu y&uuml;zden filmin konu edindiği d&ouml;n&uuml;ş&uuml;m de,&nbsp;<i>&ouml;znesiz</i>&nbsp;ve yapay bir s&uuml;re&ccedil; i&ccedil;erisinde cereyan ediyordu: Karakter, kendi kendine bir d&ouml;n&uuml;ş&uuml;m ge&ccedil;irmekten &ccedil;ok, filmin seslendiği vicdan &ouml;yle gerektirdiği i&ccedil;in &mdash;yani filmin kendi estetik evrenine dışsal olan koşullanmalarla&mdash;&nbsp; izlenmesi arzulanan bir değişim şablonuna&nbsp;<i>itaat ediyordu</i>.&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b>&rsquo;ın ikinci temel sorunu ise &uuml;zerine sinen donuk teatral havanın bir t&uuml;rl&uuml; kırılamamasıydı. Gerek başrol oyuncusunun sinemadan &ccedil;ok tiyatroya yakışan oyunculuğunun gerekse kameranın sade bir kayıt cihazı d&uuml;zeyinde kullanımının yarattığı etki y&uuml;z&uuml;nden film,&nbsp;<i>temsil</i>formunda &ccedil;ekilmiş gibi duruyordu. Bu y&ouml;n&uuml;yle de g&ouml;rsel değil&nbsp;<i>s&ouml;zsel&nbsp;</i>bir metin d&uuml;zeyinde akan eser, sinemasal duyarlılıktan yoksun kalmış oluyordu. [2]&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Saklı Y&uuml;zler</span></i></b><span>&rsquo;i anlatı eksenleri a&ccedil;ısından &ccedil;&ouml;z&uuml;mlemeye ge&ccedil;meden &ouml;nce&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b>&rsquo;tan s&ouml;z etmeyi &ouml;zellikle istedim; &ccedil;&uuml;nk&uuml;&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin yeni filminin başarılı y&ouml;nlerini doğru tespit edebilmek i&ccedil;in, &ouml;nceki filminin barındırdığı sorunları tanımak gerekiyor. Bu noktada herhalde şunu vurgulamam icap ediyor:&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b><i>,</i>&nbsp;burada yapacağım eleştiri bağlamında,&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in y&ouml;netmeninin &ouml;nceki filmi olması dolayısıyla değil; toplumsal sorunlara eğilen bir sinema eserinin hangi y&ouml;nlerden zayıf kalabileceğini iyi bir bi&ccedil;imde &ouml;rneklediği i&ccedil;in &ouml;zel bir &ouml;nem arz ediyor. Fazlasıyla bilindik g&ouml;stergelere ve &ouml;yk&uuml;leme motiflerine yaslanarak doğrudan seyircinin&nbsp;<i>vicdanına&nbsp;</i>y&ouml;nelme y&ouml;ntemini, politik bir duyarlılık barındıran eserler i&ccedil;in kolaycı bulduğumu yukarıda ima etmiştim. Bu y&ouml;ntem, bu t&uuml;rden bir eserin yaratılmasında ve alımlanmasında sağladığı kolaylıklar y&uuml;z&uuml;nden, y&ouml;netmenler i&ccedil;in, karşı koymanın zor olduğu bir cazibeye sahip olsa gerektir. Diğer yandan bu cazibeye kapılan bir y&ouml;netmen de, eserin estetik d&uuml;zeyini aşağı &ccedil;ekme ve &ouml;zg&uuml;nl&uuml;ğ&uuml;n&uuml; zayıflatma riskini g&ouml;ze alıyor demektir.&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b>, işte bu y&ouml;ntem izlendiğinde ortaya &ccedil;ıkacak filmin nasıl bir şey olduğunu g&ouml;stermesi bakımından bizlere iyi bir &ouml;rnek teşkil ediyor.&nbsp;<b><i>Saklı Y&uuml;zler&nbsp;</i></b>ise, sinema yoluyla politik bir duyarlılık geliştirirken estetikten taviz verilmesinin gerekmediğini ortaya koyarak,&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk&nbsp;</i></b>gibi filmlerin karşısında konumlanıyor. Bu yazıda&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in politik duruşunun, filmin estetik (anlatısal-&ouml;yk&uuml;sel ve sinematografik) iskeletiyle ilintisini inceleyeceğiz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>İpek&ccedil;i</span></b><span>&rsquo;yi<b><i>&nbsp;Saklı Y&uuml;zler</i></b>&rsquo;i &ccedil;ekmeye g&ouml;t&uuml;ren s&uuml;re&ccedil;, &ouml;nce namus cinayetlerine eğilen bir belgesel yapma niyetiyle başlamış; ancak y&ouml;netmen daha sonra bu fikirden vazge&ccedil;ip, temasını aynı tutarak kurmaca bir film senaryosu yazmaya y&ouml;nelmiş. [3] Ancak yine de namus cinayetleri &uuml;zerine &ccedil;ekilmiş bir kurmaca belgeseli (<b><i>Saklı Y&uuml;zler</i></b>&rsquo;deki y&ouml;netmen karakterinin &ccedil;ekmiş olduğu &ldquo;Namus Cinayetleri&rdquo; isimli film),<i></i>bir anlatı ekseni oluşturacak şekilde filmine eklemlemiş.&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in ilk yarısını, bu belgeselin merkezde olduğu, &uuml;&ccedil; anlatı eksenli bir film olarak izliyoruz. Bu eksenler farklı bi&ccedil;emlerle sunulup &ccedil;apraz kurguyla i&ccedil;i&ccedil;e ge&ccedil;iriliyor. Filmin ikinci yarısında ise, &ldquo;filmin asıl &ouml;yk&uuml;s&uuml;&rdquo; olarak g&ouml;rebileceğimiz, anlatı eksenlerinden &ldquo;şimdiki zaman&rdquo;da ge&ccedil;eni &uuml;zerinden akan olaylar dizisini takip ediyoruz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İlk yarıda merkezdeki ekseni oluşturan&nbsp;<i>derinlemesine m&uuml;lakatın filmi</i>nde (film-i&ccedil;i-film: &ldquo;Namus Cinayetleri&rdquo; belgeseli), &ldquo;t&ouml;re&rdquo; gereği kurban edilmesi gereken Z&uuml;hre&rsquo;nin &ouml;ld&uuml;r&uuml;lmesi girişimlerini ve Z&uuml;hre&rsquo;nin kurtuluşunu, onun ağzından dinliyoruz. İki-renkli (siyah-beyaz ve ara tonlar) olarak &ccedil;ekilmiş bu film-i&ccedil;i-filmde Z&uuml;hre&rsquo;nin y&uuml;z&uuml;n&uuml;n karartılarak verilmesi (<i>saklı y&uuml;z</i>), onun gizliliğinin korunması ama&ccedil;lı olduğu kadar&nbsp;<i>anonim</i>&nbsp;bir t&ouml;re mağduru olarak resmedilebilmesine de yarıyor (saklı y&uuml;z<i>ler</i>). Tipik bir dramatik belgesel tarzının g&uuml;d&uuml;ld&uuml;ğ&uuml; bu anlatı, seyircide, &ldquo;asıl film&rdquo;&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in b&uuml;t&uuml;n&uuml;n&uuml;n&nbsp;<i>kurgusal</i>&nbsp;oluşunu gizleyen bir yanılsama yaratabiliyor: &Ouml;zellikle &ldquo;asıl film&rdquo;in, salt bu belgeselin par&ccedil;alarını kullandığı kısımlarda (yani belgesel, doğrudan biz seyircilerin bakmakta olduğu perdeye yansıtıldığında), belgeseldeki s&ouml;zl&uuml; anlatımın&nbsp;<b>Handan İpek&ccedil;i</b>&rsquo;nin kaleminden &ccedil;ıkmış olduğunu unutabiliyor; y&uuml;z&uuml; karartılan kadının bir film karakteri değil de<i>yaşadığımız d&uuml;nyadan</i>&nbsp;birisi olduğunu d&uuml;ş&uuml;nebiliyoruz. (Dolayısıyla belgeseldeki karakter,&nbsp;<i>bir film karakteri olarak</i>&nbsp;değil; kendisi &mdash;g&uuml;ya&mdash; bizzat seyircinin d&uuml;nyasında yaşadığı halde&nbsp;<i>anonimleştirildiği</i>&nbsp;<i>i&ccedil;in</i>, namus cinayeti mağduru kadınların t&uuml;m&uuml;n&uuml;n bir temsilcisi d&uuml;zeyine y&uuml;kseliyor:&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b>&rsquo;ın emekli hakiminin simgeselliğine kıyasla daha sahici, daha &ouml;zg&uuml;n ve &ccedil;ok daha g&uuml;&ccedil;l&uuml; bir temsilci.)&nbsp;&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in temasının, i&ccedil;inde bulunduğumuz toplumun bug&uuml;nk&uuml; bir sorunu olduğunu aklımızdan &ccedil;ıkarmadan baktığımızda; filmin genel ger&ccedil;eklik d&uuml;zeyinde kurulan bu&nbsp;<i>estetik &ldquo;tezgah&rdquo;ın&nbsp;</i>[4]<i>&nbsp;&nbsp;</i>yarattığı yanılsamanın da &ldquo;sağlıklı&rdquo; ve geliştirilmek istenen duyarlılığa d&ouml;n&uuml;k olarak &ldquo;faydalı&rdquo; olduğunu kabul etmeliyiz. Filmin diğer anlatı eksenlerininse, bu yanılsamayı hafifletme (izlediğimizin bir film olduğunu bize hatırlatma) işlevlerinin bulunduğunu g&ouml;r&uuml;yoruz. (Eksenler arasındaki ger&ccedil;eklik d&uuml;zeyi farklarının&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;e ne kattığına yazımızın aşağıdaki paragraflarında değineceğiz.)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/sakli%20yuzler11.jpg" alt="" width="481" height="274" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Film-i&ccedil;i-filmin eksenine dolaşık olan ikinci anlatı ekseni, bir&nbsp;<i>flashback</i>&nbsp;yatağı işlevi g&ouml;r&uuml;yor: Burada, Z&uuml;hre&rsquo;nin belgeselde s&ouml;zel olarak sunduğu olay ve durumlar &mdash;ve bunlarla aynı bağlamda (Z&uuml;hre&rsquo;yle yapılan m&uuml;lakat &ouml;ncesi zamanda, Z&uuml;hre&rsquo;nin ailesinin k&ouml;y&uuml;nde) ger&ccedil;ekleşmiş diğer ilgili olaylar&mdash; g&ouml;rselleştiriliyor. Seyirci olarak &ouml;ncelikle Z&uuml;hre&rsquo;nin ge&ccedil;mişini etraflıca &ouml;ğrenmemize yarayan bu b&ouml;l&uuml;mde&nbsp;<b><i>Saklı Y&uuml;zler</i></b><i>&rsquo;</i>in &ouml;nemli karakterlerini de tanıma imkanı buluyoruz: Z&uuml;hre&rsquo;nin amcası Ali, Z&uuml;hre&rsquo;nin Almanya&rsquo;da bulunan b&uuml;y&uuml;k amcasının yokluğundaki iktidar boşluğunda, aileyi &ldquo;t&ouml;re&rdquo;yi uygulamaya zorlamaktadır. Z&uuml;hre&rsquo;nin erkek kardeşi, cinayetle su&ccedil;landığında yaşının k&uuml;&ccedil;&uuml;kl&uuml;ğ&uuml; y&uuml;z&uuml;nden ceza indirimi alacağı bilindiğinden, Ali tarafından Z&uuml;hre&rsquo;yi &ouml;ld&uuml;rmekle g&ouml;revlendirilmiştir. Ancak delikanlı g&uuml;c&uuml; yettiği &ouml;l&ccedil;&uuml;de t&ouml;reye karşı koymaya &ccedil;alışmaktadır. Ailede nelerin d&ouml;nd&uuml;ğ&uuml;n&uuml; &ccedil;ok iyi bilen, ama delil yetersizliğinden Ali&rsquo;yi tutuklatamayan otoriter ve ana&ccedil; &ldquo;Savcı Hanım&rdquo;, Z&uuml;hre&rsquo;ye kol kanat germektedir. (Z&uuml;hre&rsquo;nin ailenin elinden kurtulmasını da o sağlayacaktır.) Son olarak, &ldquo;Namus Cinayetleri&rdquo; belgeselinin y&ouml;netmeni, aslında Z&uuml;hre&rsquo;nin beraber olmuş olduğu oğlanın abisidir. (Y&ouml;netmen, kardeşinin, Z&uuml;hre&rsquo;yi de mahkum eden t&ouml;re y&uuml;z&uuml;nden kendisini &ouml;ld&uuml;rmesi &uuml;zerine, kamerasını namus cinayetleri olgusuna ve bizzat Z&uuml;hre&rsquo;ye &ccedil;evirecek; t&ouml;re y&uuml;z&uuml;nden pek &ccedil;ok kişinin &ouml;l&uuml;m&uuml;nden sorumlu tuttuğu Ali&rsquo;nin yargılanabilmesini kendi hayat davası olarak algılayacaktır.)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Saklı Y&uuml;zler</span></i></b><span><i>&rsquo;</i></span><span>in ilk yarısında Z&uuml;hre&rsquo;nin y&uuml;z&uuml;n&uuml; g&ouml;rebildiğimiz tek yer olan bu flashback-temelli anlatıda doygun renklerin kullanımı dikkat &ccedil;ekiyor. G&ouml;rsel renklilik, film bu eksende seyrederken,&nbsp;<i>kurmaca&nbsp;</i>bir şey izlediğimizin altını &ccedil;iziyor. Bu b&ouml;l&uuml;m, hem Z&uuml;hre&rsquo;nin nasıl bir &ccedil;evre ve ge&ccedil;mişten geldiğini &ouml;yk&uuml;lemesiyle hem de renk kullanımının getirdiği yabancılaştırmayla, Z&uuml;hre&rsquo;nin belgeseldeki sunumundaki anonimliğini kırıyor; onu bir birey ve bir kurmaca film kahramanı haline getiriyor: Neler yaşamış olduğunu belgeseldeki anlatımından &ouml;ğrendiğimiz bu &ldquo;saklı&rdquo; kişinin &ouml;yk&uuml;s&uuml;ne, bir kez de doğrudan ve g&ouml;rsel olarak tanık edilmemiz; onun, filmin kendi sinemasal ger&ccedil;ekliğinden de nasiplenmesini sağlıyor. Diğer deyişle,&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk</i></b>&rsquo;ın, arı bir &ldquo;s&ouml;ylem temsilcisi&rdquo; olarak ger&ccedil;ekliğini bile sorgulayabileceğimiz karakterine karşı&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in Z&uuml;hre&rsquo;si; film-i&ccedil;i-filmin yarattığı yanılsamayla&nbsp;<i>kurmaca olamazmış</i>&nbsp;gibi g&ouml;r&uuml;nen ger&ccedil;ekliğinin yanısıra kurmaca olduğu a&ccedil;ık bir ger&ccedil;ekliğe (estetik ger&ccedil;ekliğe) &mdash;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in ikinci anlatı ekseninde&mdash; doğal olarak kavuşması sayesinde, hem biz seyircilerin yaşadığı evrene hem de&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin filminin kendi evrenine ait bir &ouml;zne olabiliyor. Karakterin bu şekilde &ccedil;ift ger&ccedil;eklik kazanmasının, filmin&nbsp;<i>ger&ccedil;ek&ccedil;iliğini&nbsp;</i>g&uuml;&ccedil;lendirdiği gibi politik ve estetik hedeflerinin i&ccedil;i&ccedil;e ge&ccedil;mesini sağladığını da d&uuml;ş&uuml;n&uuml;yorum.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmin şimdiki zamanda kurulan &uuml;&ccedil;&uuml;nc&uuml; anlatı eksenindeyse, &ldquo;Namus Cinayetleri&rdquo; belgeselinin y&ouml;netmeninin başat karakter olduğu, gerilimli bir takip-ka&ccedil;ış-kovalama ser&uuml;veni oturuyor. Bu eksene ge&ccedil;meden &ouml;nce, aradaki zaman diliminde olmuş olayları &ouml;zetlememiz gerekiyor: Savcı Hanım, Z&uuml;hre&rsquo;yi &ouml;ld&uuml; g&ouml;sterip k&ouml;y&uuml;nden ka&ccedil;ırmış, ona yeni bir kimlik sağlayıp bir koca bulmuştur; kendisi de İstanbul&rsquo;a taşınmıştır. Z&uuml;hre artık başka bir isimle, uzak bir yerde yaşamakta ve Savcı Hanım hari&ccedil; olmak &uuml;zere &ouml;nceki hayatına ait kim varsa hepsinden saklanmaktadır. Diğer yandan Y&ouml;netmen de namus cinayetleri &uuml;zerine bir belgesel &ccedil;ekme arzusuyla Savcı Hanım&rsquo;a ulaşmış, ısrarlı bir &ccedil;aba sonucunda da Savcı Hanım&rsquo;ın, kendisini Z&uuml;hre&rsquo;ye g&ouml;t&uuml;rmesini sağlamıştır. Bu arada Z&uuml;hre&rsquo;nin erkek kardeşi, Z&uuml;hre&rsquo;nin yalan &ouml;l&uuml;m&uuml;nden sorumlu tutularak 5 yılını hapiste ge&ccedil;irmiştir ve bundan sonra da Almanya&rsquo;ya, B&uuml;y&uuml;k Yenge&rsquo;sinin yanına gitmiştir. Almanya, Z&uuml;hre&rsquo;nin belgeselini tamamlayan y&ouml;netmenin de yeni ikamet yeridir ve &ldquo;Namus Cinayetleri&rdquo; burada g&ouml;sterime girer. Ali&rsquo;nin bu filmi izlemesiyle Z&uuml;hre&rsquo;nin h&acirc;l&acirc; hayatta olduğu ortaya &ccedil;ıkar; Ali, Z&uuml;hre&rsquo;yi bulmak ve yarım kalan işin tamamlanması i&ccedil;in elinden geleni ardına koymayacaktır. Meselenin &ouml;teki tarafındaysa Y&ouml;netmen&rsquo;in davası hen&uuml;z bitmiş değildir: Z&uuml;hre&rsquo;nin Almanya&rsquo;daki akrabaları birer ikişer filmi izlemeye geldik&ccedil;e Y&ouml;netmen de el kamerasıyla onları gizli gizli &ccedil;ekmektedir. Dahası, Ali&rsquo;yi de &ouml;zel olarak g&ouml;z/kamera hapsine almıştır. Filmin ikinci yarısı, Z&uuml;hre&rsquo;ye &ouml;nce kimin (Ali&rsquo;nin mi, yoksa Y&ouml;netmen&rsquo;le birleşmiş olan aile eşrafının mı) ulaşacağı d&uuml;ğ&uuml;m&uuml;ne gebe olacaktır.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>İpek&ccedil;i</span></b><span>&rsquo;nin bize<b>&nbsp;</b>belgeseli izlemek i&ccedil;in sinemaya gelen karakterleri izlettirmesi, bu film-i&ccedil;i-filmin yaratabildiği ger&ccedil;eklik yanılsamasına da b&uuml;sb&uuml;t&uuml;n kapılmamızı engelliyor. Belgeselin doğrudan seyircileri olmadığımız bu gibi bağlamlarda, onun ger&ccedil;ekliğinin de&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in kurmaca&nbsp; karakterlerinin ger&ccedil;eklikleri d&uuml;zeyinde olduğunu kabulleniyoruz. Filmin, belgeselin sunumuna kılıf olan (belgeseli dolaylı yoldan veya doğrudan izlememize olanak tanıyan) &uuml;&ccedil;&uuml;nc&uuml; anlatı ekseni, beraberinde seyirciye yeni bir &ldquo;g&ouml;z&rdquo; de sunuyor: Y&ouml;netmen&rsquo;in dijital kamerası. Filmin &uuml;&ccedil;&uuml;nc&uuml; anlatı eksenindeki olaylara, genellikle,&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin kamerası dışında Y&ouml;netmen&rsquo;in kamerası aracılığıyla da tanık oluyoruz. (Elbette Y&ouml;netmen&rsquo;in belgeselini de Y&ouml;netmen&rsquo;in kamerasından izlemiştik; ama orada bir anlatının varolabilmesi i&ccedil;in o kameranın da varolması bir&nbsp;<i>zorunluluktu</i>. Şimdiki eksendeyse Y&ouml;netmen&rsquo;in kamerasının varlığı, anlatının oluşması i&ccedil;in zorunlu bir koşul değil: Bu y&uuml;zden &ldquo;&ouml;zel&rdquo; bir durum arz ediyor.) B&ouml;yle bir tanıklık, kullanılan kameranın, &ccedil;ektiği g&ouml;r&uuml;nt&uuml;leri ham halleriyle aktardığıyla kalması dolayısıyla bizi o anki kurgulanmış ger&ccedil;eklikten uzaklaştırıyor. Bunu başka bir şekilde ifade edecek olursam, kullanılan kameranın teknik &ouml;zellikleri y&uuml;z&uuml;nden, kameranın (ve kamerayı y&ouml;neten Y&ouml;netmen&rsquo;in) &ccedil;evresinde yaşanılanlara tanıklığımız, estetik d&uuml;zeyde değil de, tipik bir&nbsp;<i>gizli kamera</i>&nbsp;&ccedil;ekiminin dayandığı ve kaydettiği g&uuml;ndelik/yaşanan ger&ccedil;eklik d&uuml;zeyinde cereyan ediyor. B&ouml;ylelikle filmin şimdiki zamanının ger&ccedil;ekliği,<i>bizim</i>&nbsp;şimdiki zamanımızın ger&ccedil;ekliğine &ldquo;sızıyor&rdquo;:&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin kamerası, filmin şimdiki zamanını bize film-dışı bir noktadan seyrettiriyorken Y&ouml;netmen&rsquo;in kamerası bizi filmin i&ccedil;ine alıyor, filmdeki karakterlerin arasına sokuyor ve olan bitenleri bize &ldquo;naklen&rdquo; sunuyor. Bu &ccedil;er&ccedil;evede,&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin kamerasının dışında bir başka kameraya da başvurulması,<b>&nbsp;</b>filmdeki dramatik etkiyi (gerilimi, ritmi ve tempoyu) g&uuml;&ccedil;lendiriyor ve filmin anlatım olanaklarını zenginleştiriyor. Ancak bunun filmin politik duruşu bakımından asıl &ouml;nemli olan getirisi,&nbsp;<i>namus cinayetleri&nbsp;</i>sorununun g&uuml;ncelliğinin ve yanıbaşımızdalığının vurgulanması oluyor. [5]</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filme &uuml;&ccedil;&uuml;nc&uuml; anlatı ekseninde katılan bu yeni &ldquo;g&ouml;z&rdquo;&uuml;n, es ge&ccedil;emeyeceğimiz bir başka işlevi daha oluyor: Y&ouml;netmen&rsquo;in kamerası,&nbsp;<b>İpek&ccedil;i</b>&rsquo;nin kamerasının&nbsp;<i>metaforu</i>olarak da &ccedil;alışıyor. Bu, en a&ccedil;ık ve işlevsel haline filmin finalinde kavuşuyor: Şimdiki zamandaki ser&uuml;venin &ccedil;&ouml;z&uuml;mlendiği bu sahnede, Z&uuml;hre&rsquo;nin b&uuml;y&uuml;k yengesi hari&ccedil; b&uuml;t&uuml;n karakterlerin film i&ccedil;indeki rol&uuml; şu ya da bu bi&ccedil;imde bitiyor; geriye sadece, kocasından miras kalan iktidarıyla g&uuml;&ccedil;l&uuml; bir kadın portresi &ccedil;izmiş olan bu karakter ve Y&ouml;netmen&rsquo;in el kamerası kalıyor. K&ouml;t&uuml; g&uuml;nlerini belgelediği i&ccedil;in Y&ouml;netmen&rsquo;in &ccedil;ekim yapmasına defalarca itiraz etmiş (ama onu kamerayı kullanmaktan yine de alıkoyamamış) olan kadının bu nesneye hi&ccedil;bir zaman ısınmamış olduğunu, filmin buraya kadarki akışından biliyoruz. Final sahnesinin ger&ccedil;ekleştiği mekan (Z&uuml;hre&rsquo;nin yeni hayatını s&uuml;rd&uuml;rd&uuml;ğ&uuml; evine giden patika), karakterlerin gidişiyle boşalıyor; karakterlerin yokluğunda anlamını da kaybetmiş olan doğal dekoru,&nbsp; kısmen uzun bir s&uuml;re i&ccedil;in Y&ouml;netmen&rsquo;in kamerasından g&ouml;r&uuml;yoruz. Yana devrilmiş olan kamera, eğik kadrajı ve boşluğu kaydediyor oluşuyla, kendisini y&ouml;nlendirecek bir bilin&ccedil; gereksinimi duyan dijital bir cihaz d&uuml;zeyine iniyor. Ve nihayet beklenen şey ger&ccedil;ekleşiyor: Kadın kamerayı eline alıyor ve &ccedil;ekimi y&ouml;nlendirmeye başlıyor. Kadının bu cihazla uzlaşması, hi&ccedil; mi hi&ccedil; istemeyeceği bir bi&ccedil;imde sonlanmış olan ser&uuml;veninden artakalanları başkalarına izleteceğinin ve artık, hi&ccedil; olmazsa başka ailelerin namus cinayetleriyle yıkılmaması i&ccedil;in yaşayacağının işaretini veriyor. Sorun arzeden bir olguyu filme almanın (veya kamerayı b&ouml;yle bir olguya y&ouml;neltmenin) &ouml;neminin altını &ccedil;izen bu final, elbette&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in de varlık gerek&ccedil;esini ortaya koyuyor. Ama tabii bu finalle i&ccedil; yakan bir ger&ccedil;ek de vurgulanıyor: Kadın karakterin kayıdı s&uuml;rd&uuml;rme arzusu,&nbsp;<i>kayıdın s&uuml;rmesi gerekliliğini</i>&nbsp;de anımsatarak, bizleri, namus cinayetleri olgusunun h&acirc;l&acirc; var olduğuyla ve somut bir adım atılmadığı s&uuml;rece kadınlar başta gelmek &uuml;zere daha nice hayatın s&ouml;neceği ger&ccedil;eğiyle y&uuml;zleştiriyor.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><span>&nbsp;<img src="/images/yazilar/sakli%20yuzler12.jpg" alt="" width="477" height="262" border="0" /></span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Saklı Y&uuml;zler</span></i></b><span>, ana &ouml;yk&uuml;s&uuml;n&uuml;n basitliğini, &ouml;yk&uuml;ye başka anlatı eksenleri ekleyerek kırıyor. Bu eksenleri i&ccedil;i&ccedil;e ge&ccedil;irme estetiğindeki başarısı, filme; farklı &mdash;ama birbirlerine sıkı sıkıya d&uuml;ğ&uuml;mlenmiş&mdash; ger&ccedil;eklik d&uuml;zeylerinde kurulan &ccedil;ok boyutlu bir ger&ccedil;ek&ccedil;i atmosfer kazandırıyor. Bu yazıda bu estetik yapının nasıl işlediği &uuml;zerinde durarak, filmin politik duruşunun nasıl oluştuğunu &ccedil;&ouml;z&uuml;mlemeye &ccedil;alıştık. Ancak buradaki &ccedil;&ouml;z&uuml;mleme; filmin ele aldığı namus cinayetleri sorununun kendisine, gereksinimini duyduğu feminist bir duyarlılıkla yaklaşmamıza (ya da filme dayanarak namus cinayetleri sorununa feminizm ışığında bakmamıza) izin vermedi. Dahası, bu yazıda filmin politik duruşuna karşı eleştirel bir tavır da geliştiremedik: &Ouml;rneğin, kurum olarak devletin namus cinayetleri sorunu bağlamındaki &ldquo;var&rdquo;lığına ve etkisine ilişkin bir s&ouml;z oluşturmakta filmin yetersiz kaldığını farketmemize karşın&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in<b><i>&nbsp;</i></b>&nbsp;bu aczini ortaya koyacak bir &ccedil;er&ccedil;eveyi burada sunamadık. [6] Gerek&nbsp;<b>Handan İpek&ccedil;i</b>&rsquo;nin filminin estetik g&uuml;c&uuml; gerekse namus cinayetleri olgusunun g&uuml;ncelliği ve vehameti,&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in başka &ouml;l&ccedil;eklerde de incelenip eleştirilmesini zorunlu kılıyor. Bu yazının &ccedil;&ouml;z&uuml;mlemeye giriştiği alanın dışladıklarının, filmin ve konusunun hak ettikleri şekilde değerlendirilmelerinin zeminini oluşturacağının başkalarınca da g&ouml;r&uuml;lmesini diliyoruz.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Notlar:</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[1] &ldquo;Estetik y&ouml;nelim&rdquo; kavramını, sanat&ccedil;ının &ndash;şu ya da bu mesajı verme kaygısında olsa bile- yapıtını &ouml;ncelikle estetiğin mecrasının i&ccedil;erisinde tasarlama bilincini karşılamak i&ccedil;in kullanıyorum. Bu doğrultuda sanat&ccedil;ının &ldquo;eleştirel duruşunu bir estetik y&ouml;nelim &uuml;zerinden kurduğunu&rdquo; s&ouml;ylerken de, ilkin, yapıtın barındırdığı eleştirinin (ahlaksal, toplumsal, politik, vd. d&uuml;zlemlerdeki eleştirel a&ccedil;ılımlarının) &ccedil;ıplak bırakılmış tezlerle verilmediğini; bunun yerine yapıtın estetik harcına yedirilmiş olduğunu vurguluyorum. Bunun devamında da, b&ouml;yle bir yapıtın estetik &ouml;ğelerinin &ccedil;&ouml;z&uuml;mlenmesinin, eleştirel a&ccedil;ılımlarını kavramaya denk bir &ccedil;aba olacağını ima ediyorum. (Bu bakımdan bu yazıda&nbsp;<b><i>Saklı Y&uuml;zler</i></b>&rsquo;in anlatı eksenlerine ilişkin yapılan &ccedil;&ouml;z&uuml;mleme de aslında, filmin politik duruşunun g&ouml;stergelerini ortaya koyma iddiasını taşıyor.)&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[2]&nbsp;<b><i>B&uuml;y&uuml;k Adam K&uuml;&ccedil;&uuml;k Aşk&nbsp;</i></b>gibi bir filmin sinemasal duyarlılıktan yoksun olmasının niye &ldquo;kritik bir sorun&rdquo; oluşturduğuna takılmak isteyecek bir okurun, sinemanın estetiğini kendisine ne kadar dert edindiğini sorgulamaya da hevesli olacağını sanıyorum.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[3]&nbsp;<a href="http://www.sinema.com/makale/4-5762/handan-ipekci-eteklerimdeki-taslari-dokemedim" target="_blank" style="color: #895f37;">&ldquo;Eteklerimdeki taşları d&ouml;kemedim!&rdquo;</a>&nbsp;(sinema.com&rsquo;un y&ouml;netmenle yaptığı s&ouml;yleşi<span style="font-size: 13px;">)</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[4] &ldquo;Estetik tezgah&rdquo;ı, kabaca, &ldquo;sanatsal yalan&rdquo; ile eşanlamlı olarak kullanıyorum. Burada &ldquo;estetik&rdquo;i sıfat olarak kullanırken, &ldquo;tezgah&rdquo;ın kendisine bir &ldquo;g&uuml;zellik&rdquo; payesi iliştirdiğimi (tezgahın &ldquo;g&uuml;zel&rdquo; olduğunu d&uuml;ş&uuml;nd&uuml;ğ&uuml;m&uuml;) yadsıyacak değilim; ama esas derdim, &ldquo;tezgah&rdquo;ın t&uuml;r&uuml;n&uuml; belirlemek: &ldquo;Tezgah&rdquo;ın,&nbsp;<i>sanata i&ccedil;kin</i>&nbsp;yollarla kurulduğunu vurgulamak; bir&nbsp;<i>estetik y&ouml;nelimle</i>&nbsp;tasarlandığını hatırlatmak.&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[5] Bu getiri ile film-i&ccedil;i-filmin (belgeselin) uyandırdığı yanılsamanın &ldquo;sağlıklı&rdquo; ve &ldquo;faydalı&rdquo; bulmuş olduğum etkisi aynı iki şey midir (bunlar eş/denk şeyler midir)? Buna şu aşamada kesin bir cevap vermekten ka&ccedil;ınıyorum. Cevap muhtemelen; gizli kamera g&ouml;rselliği ile belgesel g&ouml;rselliğinin seyircide yaratacağı ger&ccedil;eklik algılarının ne denli benzer (eş) veya farklı olduklarıyla ilgili tartışmada saklıdır. Ancak kendimi bu tartışmaya şimdi girmeye hazır bulmuyorum.&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[6] Filme bu t&uuml;r bir eleştiriyle yaklaşan bir yazı i&ccedil;in bkz:&nbsp;<a href="http://evrensel.net/v2/haber.php?haber_id=20845" target="_blank" style="color: #895f37;">&ldquo;Saklı Y&ouml;netmenin Saklı Y&uuml;zleri&rdquo;</a>, Ani Ceylan Hazinedar, Evrensel Gazetesi, 23/11/2007.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;">Bu yazıyı, &uuml;lkemiz gazetelerinde &ccedil;ıkan tipik &ldquo;film eleştirisi&rdquo; yazılarıyla benzer bir oylumda olduğu halde, konu edindiği filmi onlardan &ccedil;ok daha kapsamlı ele alma başarısı y&uuml;z&uuml;nden de &ouml;nemsiyorum.</span></p>', 64, 63, 'Yazarlarımızdan', '/images/yazilar/sakli%20yuzler.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (47, 'ay-j168', 'gorunmeyen-adam-i-stanbul-u-terk-etti', 'Görünmeyen Adam İstanbul’u Terk Etti', 'İlker Mutlu', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">G&ouml;r&uuml;nmeyen Adam İstanbul&rsquo;u Terk Etti</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>İlker Mutlu</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-small;"></span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-large;"><b>N</b></span><span style="font-size: 10pt;">e &ccedil;ok insanı alıp g&ouml;t&uuml;r&uuml;yor ve ne &ccedil;oklarını yaşatıyor sinema. &Ouml;yle bir b&uuml;y&uuml;s&uuml; var ki, oyuncuları &ouml;l&uuml;ms&uuml;zleştiriyor, &ouml;m&uuml;rlerine &ouml;m&uuml;r katıyor. O insanları unutmanız m&uuml;mk&uuml;n olmuyor artık.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu duruma d&uuml;şman olan zamanın kendisi ve zaman i&ccedil;inde ortaya &ccedil;ıkan modalar, akımlar, değişen jenerasyon. Ama yine de bir şekilde fig&uuml;rler ayakta durmayı başarıyor. Beni hep şaşırtan bir durumdur: Nostalji, kelime anlamıyla da &ouml;zlem i&ccedil;erir hani. İnsan da yaşadığı bir şeyi &ouml;zler, &ouml;yle ya. Ama bug&uuml;n pek &ccedil;ok gen&ccedil; insanda da birebir yaşamadığı d&ouml;nemlere dair bir nostalji olgusu oluşmakta. &ldquo;K&uuml;lt film&rdquo; ve &ldquo;k&uuml;lt sanat&ccedil;ı&rdquo; kavramlarının oluşması ve yaygınlaşmasıyla genci yaşlısı, &ouml;n&uuml;ndeki yepyeni, teknolojinin t&uuml;m nimetlerinden faydalanılarak yapılmış, kimileri de sanat harikası olarak nitelendirilen yapıtlardan uzaklaşıp, onları da es ge&ccedil;meksizin, aslında yabancısı oldukları olguları i&ccedil;eren eski yapıtlara y&ouml;nelmeye, onları aramaya, eski sanat&ccedil;ıları sahiplenmeye başladılar. Bizde&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in &ouml;l&uuml;m&uuml;nden o kadar yıl sonra tekrar pop&uuml;lerleşmesi de b&ouml;yle bir durum.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Benim&nbsp;<b>Turan Seyfioğlu</b>&rsquo;nu keşfim de b&ouml;yle bir ortamda ger&ccedil;ekleşti. Ger&ccedil;i yukarıda bahsettiğimden hayli farklı bir s&uuml;re&ccedil;te oldu bu. K&uuml;ltleşmeye aday bir ikon olmakla beraber,&nbsp;<b>Seyfioğlu</b>, en azından şimdilik, sinema tarihimizin bu derece ilgi &ccedil;eken bir fig&uuml;r&uuml; değil. Babamla ne yazık ki &ccedil;ok seyrek yaptığımız, ama k&uuml;&ccedil;&uuml;kl&uuml;ğ&uuml;mden bu yana sinemaya ilgimin gelişmesine olan katkısını yadsıyamayacağım sanat konuşmalarımızda &uuml;&ccedil; isim devamlı ge&ccedil;mekteydi:&nbsp;<b>Yılmaz G&uuml;ney</b>,&nbsp;<b>Ahmet Tarık Tek&ccedil;e</b>&nbsp;ve&nbsp;<b>Turan Seyfioğlu</b>. Belki başkalarının da isimlerini anıyordu babam, ama bunlar, sanırım d&ouml;nemlerine yetişemememden ve filmlerinden &ouml;rnekleri de &ccedil;ok fazla izlememiş olmamdan dolayı &ccedil;ok ilgimi &ccedil;ekmekteydi.&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in filmlerinin bir kısmı daha sonra g&ouml;sterilmeye başlandı ve onlara ulaşabildim.&nbsp;<b>Ahmet Tarık Tek&ccedil;e</b>, aralarında filmi en sık &ccedil;ıkandı, ama babamın sevgi dolu s&ouml;zlerinden sonra onu da sıkı takip etmeye başlamıştım. Ama, gelgelelim,&nbsp;<b>Turan Seyfioğlu</b>&rsquo;na,&nbsp;<b><i>İstanbul&rsquo;un Fethi</i></b>,&nbsp;<b><i>Berduş</i></b>&nbsp;ve&nbsp;<b><i>Katil&nbsp;</i></b>filmleri hari&ccedil; bir t&uuml;rl&uuml; ulaşamıyordum. Onun hayranı olmamı sağlayan filmler ise bu &uuml;&ccedil;&uuml;nden &ccedil;ok sonra, sanırım&nbsp;<b>Erman Şener</b>&rsquo;in &Ccedil;arşamba Sineması adlı programda, trt&rsquo;de g&ouml;sterdiğinde ilk olarak izlediğim,&nbsp;<b>Şadan Kamil</b>&nbsp;filmi<b><i>&nbsp;Ka&ccedil;ak</i></b>&nbsp;ve&nbsp;<b>L&uuml;tfi Akad</b>&nbsp;filmi&nbsp;<b><i>Meyhanecinin Kızı</i></b>&rsquo;ydı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/seyfioglu3.jpg" alt="" width="423" height="474" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Seyfioğlu araştırmasına tam iki sene &ouml;nce başladım. İlk hedefim, sadece detaylı filmografisini edinmek, bunların tamamını bir şekilde g&ouml;rmek ve eleştirilerini de derleyip, kendi yorumlarımı da katarak kapsamlı bir yazı haline getirmekti. Ancak, kısa s&uuml;rede fark ettim ki, oyuncu olarak kadrosunda yer aldığı yirmi altı filmin yarısından fazlasına ulaşmak bug&uuml;n artık m&uuml;mk&uuml;n değil. Bir g&ouml;r&uuml;şmemde&nbsp;<b>İlhan Arakon</b>&rsquo;un da s&ouml;ylediği gibi, &ldquo;T&uuml;rk sineması &uuml;&ccedil; b&uuml;y&uuml;k yangın ge&ccedil;irmiştir.&rdquo; ve iki b&uuml;y&uuml;k depo yangını, korumasız haldeki bir s&uuml;r&uuml; sinema hazinemizin sonsuza dek yok olmasına neden olmuştur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bunun &uuml;zerine, ulaşamadığım filmleri haklarında yazılanlardan keşfetme yoluna gittim, ancak bu araştırma da başarısızlıkla sonu&ccedil;landı, &ccedil;&uuml;nk&uuml; ulaşabildiğim bu tarzdaki iki yayın olan&nbsp;<b>Agah &Ouml;zg&uuml;&ccedil;</b>&rsquo;&uuml;n&nbsp;<b><i>T&uuml;rk Filmleri S&ouml;zl&uuml;ğ&uuml;</i></b>&nbsp;ve&nbsp;<b>Nijat &Ouml;z&ouml;n</b>&rsquo;&uuml;n&nbsp;<b><i>T&uuml;rk Sineması Kronolojisi</i></b>, sadece filmler hakkındaki &ouml;zet bilgilerden oluşmaktaydı. Bu durum beni ister istemez sanat&ccedil;ının yaşam &ouml;yk&uuml;s&uuml;n&uuml;, kişiliğini araştırmaya y&ouml;nlendirdi ve kendimi bir anda dipsiz bir kuyunun başında buldum. Dipsiz kuyu diyorum, &ccedil;&uuml;nk&uuml; devrinde bu denli hayran kazanmış, ama hakkında kaynağa bu kadar zor ulaşılan bir sanat&ccedil;ı yoktur herhalde ve bunun yanında hareketli ve sırlarla dolu bir hayat yaşadığı. Onunla &ccedil;alışmış, arkadaşlığı olmuş, hayattaki kişilerden ulaşabildiğim sekiziyle (<b>Atıf Yılmaz</b>,&nbsp;<b>Sırrı G&uuml;ltekin</b>,&nbsp;<b>Lale Oraloğlu</b>,&nbsp;<b>İlhan Arakon</b>,<b>&nbsp;Sezer Sezin</b>,<b>&nbsp;Kenan Pars</b>&nbsp;ve daha yakında&nbsp;<b>Orhan G&uuml;nşiray</b>&nbsp;ve&nbsp;<b>Fikret Hakan</b>) yaptığım g&ouml;r&uuml;şmelerden edindiğim izlenim de kendisini a&ccedil;ık eden bir insan olmadığı y&ouml;n&uuml;nde. Bu sanat&ccedil;ıların t&uuml;m&uuml; onun efendi bir kişiliği olduğu, işine saygı duyduğu, kaprissiz olduğu gibi &ouml;zelliklerini anlattılar. Fakat, bu g&ouml;r&uuml;şmelerde maceracı y&ouml;n&uuml;, aile yapısı, yaşadığı sevdalar ve &ouml;l&uuml;m nedeni gibi konularda ancak kırıntılarla yetinmek durumunda kaldım. &Ccedil;&uuml;nk&uuml; devamı gelmiyordu ve pek &ccedil;ok konunun ucu a&ccedil;ıkta kalıyordu. &Ouml;zellikle lejyona katılma &ouml;yk&uuml;s&uuml; tam bir kapalı kutuydu ve t&uuml;m bu gizem her bir aşamada insanı daha da i&ccedil;ine &ccedil;ekmekteydi.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/seyf.jpg" alt="" width="377" height="432" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bug&uuml;ne değin hakkında &ccedil;ıkan yazılara&nbsp; ve verdiği r&ouml;portajlara ulaşmayı denedim. Fark ettim ki, d&ouml;nemindeki &uuml;nl&uuml;ler arasında en az r&ouml;portaj veren, manşetlere &ccedil;ıkan&nbsp;<b>Turan Seyfioğlu</b>&rsquo;ydu. Ger&ccedil;ekten de, t&uuml;m o fırtınalı filmlerde ge&ccedil;en Yeşil&ccedil;am d&ouml;nemi boyunca o, setler dışında iken sinema ortamından uzak bir yaşam s&uuml;rm&uuml;şt&uuml;.&nbsp;<b>Orhan G&uuml;nşiray</b>&nbsp;onun film &ccedil;ekimi dışındaki meclislerde sinemadan asla bahsetmediğini ve bu konuda ısrarlı davranılan meclisleri de terk ettiğini anlattı. Beni şaşırtan ketum tarafına tamamen ters bir tarzda, muzip bir kişiliğe de sahip olduğundan bahsetmesi oldu herkesin. &Ouml;rneğin&nbsp;<b>İlhan Arakon</b>&nbsp;bu &ouml;zelliğini ş&ouml;yle anlatıyor: &ldquo;Tabi, gerek kardeşim, gerekse Turan&rsquo;da bir zafiyet vardı; biraz i&ccedil;kiye d&uuml;şk&uuml;nd&uuml;ler. Akşam saat 6 falan oldu muydu bunlar artık şey gibi, s&uuml;nger gibi i&ccedil;erlerdi. İ&ccedil;ince de etrafa saldırırlardı. Yani, &lsquo;saldırırlardı&rsquo;dan maksadım, takılırlardı, alay ederlerdi filan falan. Hatta, ş&ouml;yle bir hadise olduydu: Bir g&uuml;n, Levent&rsquo;te bir evimiz vardı, orada oturuyoruz akşam&uuml;zeri vakti. Saat, gece saat on-on bu&ccedil;uk filan, bunlar geldiler. Ayakları yere basmıyor. Rakı vardı, falan vardı, işte u&ccedil;tu gitti o. Arkasından, başladılar, duvarları da yeni sarı renge boyatmıştık, &ldquo;Ulan bu ne bi&ccedil;im duvar boyası!&rdquo; diyerek duvarlara daldılar. Ondan sonra oturdular, elleriyle duvar boyasını silip, birbirlerinin suratına, derken benim suratıma, derken de karımın suratına&hellip; B&ouml;yle şakayla, yani keyifli bir hayatları vardı. Rakı i&ccedil;tikten sonra da, gene b&ouml;yle b&ouml;yle keyiflerine devam ederlerdi. B&ouml;yle insanlardı&hellip; Yani bunları bu şekilde s&ouml;ylememin sebebi, bunların i&ccedil;meleri, i&ccedil;kiden sonraki hayatları &ccedil;ok keyifliydi. Kendileri de keyifli. Hani bazı insanlar vardır, i&ccedil;ki i&ccedil;tikten sonra bulaşırlar, kavga &ccedil;ıkarırlar bunlar, bunlarda b&ouml;yle bir şey yoktu. Zaten, gerek kardeşim, gerek&nbsp;<b>Turan Seyfioğlu</b>, fevkalade yumuşak başlı, fevkalade sakin, kimseyle bir hırıltı bir dırıltı &ccedil;ıkarmamak i&ccedil;in gayret eden insanlardı. Evet, boyları, posları, şunları bunları, hoşluk tarafları iyiydi, ama b&ouml;yle taltif edilecek bir tarafları yoktu. Kendilerine eğlenceleri... yani &ccedil;ocuk gibiydiler, bu şekilde insanlardı.&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Neticede, hayatı ilgin&ccedil; anekdotlarla dolu bu macera adamının&nbsp;<b>Turan Seyfioğlu</b>&rsquo;nun hayatı bir roman mevzusu olacak kadar etkileyici g&ouml;r&uuml;n&uuml;yor. 1951&rsquo;de Atlas Film&nbsp;<b><i>İstanbul&rsquo;un Fethi</i></b>&nbsp;filmini &ccedil;ekmeye karar verdiğinde Ulubatlı Hasan rol&uuml;n&uuml; oynayacak atletik yapılı bir gen&ccedil; bulmak i&ccedil;in bir yarışma d&uuml;zenler. Seyfioğlu burada keşfedilir. Dikkat &ccedil;ekmesine neden olan sportif y&ouml;n&uuml; yaptığım s&ouml;yleşilerde herkes tarafından &ouml;zellikle belirtilmiştir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sanat&ccedil;ı kişiliği ele alındığında pek &ccedil;ok insan onun iyi bir oyuncu olmadığını ama sinemaya uygun bir tipi olduğunu s&ouml;yl&uuml;yor. Buna rağmen filmlerini &ccedil;evirdiği d&ouml;nemde hakkında &ccedil;ıkan eleştiriler onun başarılı oyunlar verdiğini vurgulamaktadır. Hatta 1953&rsquo;de T&uuml;rk Film Dostları Derneği onu&nbsp;<b>Akad</b>&rsquo;ın&nbsp;<b><i>Katil</i></b>&nbsp;filmindeki rol&uuml; nedeniyle yılın en iyi d&ouml;rt erkek oyuncusundan biri olarak se&ccedil;miş ve En İyi Erkek Oyuncu &ouml;d&uuml;l&uuml;n&uuml; vermiştir. 1955&rsquo;de aynı kurumun aynı kategorideki &ouml;d&uuml;l&uuml;n&uuml;&nbsp;<b>Şadan Kamil</b>&rsquo;in&nbsp;<b><i>Ka&ccedil;ak</i></b>&nbsp;filmindeki rol&uuml;yle kazanır. Ger&ccedil;ekten de, bug&uuml;nden dahi bakıldığında, b&uuml;t&uuml;n sinema tarihimiz boyunca onun &ccedil;izdiği k&ouml;t&uuml; adam tiplemelerindeki kadar modern oyunculuğa az rastlanmaktadır. Rollerine, bilin&ccedil;li ya da bilin&ccedil;sizce, Amerikanvari bir oyun tarzı katmıştır. Durgun, biraz tutuk ama kesinlikle ger&ccedil;ek&ccedil;idir oyunculuğu. T&uuml;rkiye&rsquo;nin&nbsp;<b>Humphrey Bogart</b>&rsquo;ıdır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/seyfioglu.jpg" alt="" width="365" height="504" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Kadri Yurdatap</span></b><span>&nbsp;Yeni Yıldız&rsquo;ın 1956 tarihli 82. sayısındaki Ğerdemizin K&ouml;t&uuml; Adamı Turan Seyfioğlu başlıklı yazısında onun oyunculuğundan ş&ouml;yle bahsediyor: &ldquo;<i>Sinemamızda k&ouml;t&uuml; adam rol&uuml;ne &ccedil;ıkan başka artistler de vardır. Ve bunların &ouml;n planında Turan Seyfioğlu gelir. Amerikan filmciliğinde&nbsp;<b>bad man</b>&nbsp;sıfatı verilen hain, her şeyi bozan ve film sonunda cezasını bulan k&ouml;t&uuml; adam rol&uuml;, rollerin en zorudur desek yeridir. Filmdeki hareketleri ile oyuncunun&nbsp;</i>(seyircinin demek istiyor sanırım)<i>&nbsp;sempatisini kazanmaya imkan olmayan b&ouml;yle artistlerin tek tesellisi başarılı oyunları ile kavuşacakları ş&ouml;hrettir.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Seyfioğlu</span></b><span>&rsquo;nu araştırmaya başladığımda yazıştığım ilk kişi olan&nbsp;<b>Alican Sekme&ccedil;</b>, benim onunla&nbsp;<b>Yılmaz G&uuml;ney</b>&nbsp;arasında paralellik kurmamı eleştirmişti. Ger&ccedil;ekten de, ona yazdığım ilk mailde, bu iki sanat&ccedil;ıyı kendi d&ouml;nemlerinin &ldquo;&ccedil;irkin kral&rdquo;ları olarak tanımlayan ve bu y&ouml;nde karşılaştıran bir yazı hazırlığında olduğumu belirtmiştim. &Ouml;yle d&uuml;ş&uuml;n&uuml;yordum ve hala da aynı g&ouml;r&uuml;şteyim, &ccedil;&uuml;nk&uuml; aynen<b>&nbsp;G&uuml;ney&nbsp;</b>gibi&nbsp;<b>Seyfioğlu</b>&nbsp;da kendi d&ouml;nemindeki diğer j&ouml;nlerin aksine, g&uuml;zel adam normlarının dışında bir &ccedil;ehreye sahipti. İkisinin de tutulma sebeplerinin başında bu &ouml;zdeşleşebilirlik &ouml;zelliklerinin olduğunu d&uuml;ş&uuml;n&uuml;yorum.&nbsp;<b>Seyfioğlu</b>&nbsp;da kendi d&ouml;neminde donuk bakışları, sert ifadesi ve &ccedil;ok da yakışıklı olmayan &ccedil;ehresiyle başrol oyuncusu olarak hayli ayrıksıydı. Oyununda kendisini kasmadığı, değiştirmediği i&ccedil;in sıradan, seyircinin arasından biri gibiydi. Bu sadelik belki de onun ger&ccedil;ekten de iyi bir oyuncu olmayışından ileri geliyordu, ama onu sevdiren ve&nbsp;<b>Turan Seyfioğlu</b>&nbsp;olarak seyircisinin beynine kazıtan da bu sıradanlığın getirdiği farklılık olmuştu.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>14 Eyl&uuml;l 1920&rsquo;de İstanbul&rsquo;da, deniz subayı (deyip de ge&ccedil;meyelim, Piri Reis ve T&uuml;rk denizcilik tarihine ait bir&ccedil;ok değerli inceleme yazıları ve kaynak kitaplar yazmış) bir babanın oğlu olarak doğdu&nbsp;<b>Turan Seyfioğlu</b>. İlk ve orta okulu İstanbul&rsquo;da okuduktan sonra Ankara Maarif Koleji&rsquo;nden &ccedil;ıktı. O d&ouml;nemde Londra Ziraat Ataşeliğine tayin olan babası ile İngiltere&rsquo;ye gitmek istedi, fakat babası uygun g&ouml;rmedi. Macerayı seven bir kişiliğe sahipti. 1.84 boyunda, atletik yapılı bir gen&ccedil;ti ve iyi bir y&uuml;z&uuml;c&uuml;yd&uuml;. Hatta T&uuml;rkiye 400 ve 1500 metre y&uuml;zme şampiyonu olmuş, yıllarca bu rekoru elinde tutmuştu. Denizi &ccedil;ok seviyordu ve deniz &ouml;lene kadar en yakın arkadaşı olarak kalacaktı.&nbsp;<b>Orhan G&uuml;nşiray</b>&nbsp;onun en yakın arkadaşlarının balık&ccedil;ılar olduğunu anlattı ve yaşayanlardan birka&ccedil;ının adını verdi.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Babası onu yanında g&ouml;t&uuml;rmeyince aklına koyduğunu yaptı ve 2. D&uuml;nya Savaşı esnasında, 1942&rsquo;de, o yıllarda Fransızların elinde olan Suriye&rsquo;ye ge&ccedil;ti. Burada yakalandı ve hapse atıldı. İki bu&ccedil;uk aylık hapis hayatında h&uuml;cre arkadaşı, sonradan devlet başkanı olup suikast sonucu &ouml;len Suriyeli&nbsp;<b>Albay H&uuml;sn&uuml; Zaim</b>&rsquo;di. Hapisten kurtulmak i&ccedil;in lejyon birliklerine yazıldı ve Fransızlar adına paralı asker olarak &ccedil;&ouml;llerde bir bu&ccedil;uk yıl boyunca savaştı. Bu ser&uuml;venler esnasında bir yolunu bulup, 1943 Eyl&uuml;l&rsquo;&uuml;nde yurda d&ouml;nd&uuml;. Caddebostan&rsquo;a yerleşti. Burada &ccedil;ok sevdiği denizle ve balık&ccedil;ılıkla sık&ccedil;a ilgilenme fırsatı bulacaktı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinemaya girişi de bu macera arayışının bir par&ccedil;ası aslında.&nbsp;<b>İlhan Arakon</b>&nbsp;bu s&uuml;reci ş&ouml;yle anlattı: &ldquo;<i>Şimdi, 1950 senesinde&nbsp;<b>İstanbul&rsquo;un Fethi</b>&nbsp;filmi i&ccedil;in bir m&uuml;sabakamsı veyahut da araştırmamsı bir şey a&ccedil;tık. O zaman Atlas Film vardı, sonradan dağıldılar onlar. Bu şeye birtakım gen&ccedil;ler geldiler. Aradığımız mesele ş&ouml;yle idi: Ata binmesini bilecek, v&uuml;cut &ouml;l&ccedil;&uuml;leri yeterli olacak, oyun imkanları olacak falan gibi bir şey&hellip; Buraya bir&ccedil;ok insanlar geldiler. Bunların i&ccedil;erisinde g&ouml;z&uuml;m&uuml;z&uuml;n en &ccedil;ok tuttuğu&nbsp;<b>Turan Seyfioğlu&nbsp;</b>oldu.<b>&nbsp;Turan Seyfioğlu</b>&nbsp;o zamanlar, 20-22 yaşlarında, 22 yaşlarında, korkusuz bir delikanlı. Kapı gibi, &ccedil;ok sevimli, g&ouml;z&uuml;n&uuml; budaktan sakınmayan, b&ouml;yle &ccedil;ok hevesli bir insandı. O &ccedil;ocukcağız şeyde &ccedil;alıştı,&nbsp;<b>İstanbul&rsquo;un Fethi</b>&nbsp;filminde &ccedil;alıştı. J&ouml;n olarak değil, ama ikinci j&ouml;n olarak &ccedil;alıştı ve &ccedil;ok da sevimli, yani şu bakımdan; sinema sevenler, sinemaya gidenler, bu filmi seyredenler, ki bu filmin &ccedil;ok seyircisi oldu, hala 29 Mayıslarda bir yerlerden bulup, &ccedil;ıkarıp, oynatıyorlar filmi. Orada pop&uuml;ler hale geldi. Oradaki ismi de şey zannediyorum, Ulubatlı Hasan.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu film &ccedil;ok tutulmuş, halen ilgiyle izlenen, hatta yıllar sonra renkli baskısı yapılarak tekrar g&ouml;sterime &ccedil;ıkmış, tekrarı yapılamamış bir &uuml;st&uuml;n yapım denemesiydi. Sonradan&nbsp;<b>C&uuml;neyt Arkın</b>&rsquo;ı C&uuml;neyt Arkın yapacak olan&nbsp;<b><i>Kara Murat&nbsp;</i></b>tiplemesinin &ouml;nc&uuml;l&uuml; gibi bir rold&uuml;&nbsp;<b>Seyfioğlu</b>&rsquo;nunki, ama kesinlikle &ccedil;ok daha farklı bir yerdeydi.&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ardından hemen başrol geldi ve yine&nbsp;<b>Aydın Arakon</b>&rsquo;un y&ouml;nettiği,&nbsp;<b>Esat Mahmut Karakurt</b>&rsquo;tan uyarlama ve başrolleri&nbsp;<b>Zeynep Sırmalı</b>&nbsp;ile paylaştığı, d&ouml;neminde hayli olumlu eleştiriler alan, Avrupai havasıyla da &ouml;v&uuml;len kayıp bir film olan&nbsp;<b><i>Ankara Ekspresi&rsquo;</i></b>nde (1952) oynadı.&nbsp;<b>Kenan Pars</b>, bu filmi ilk izlediğinde hayli heyecanlandığını, filmi benzersiz bulduğunu anlattı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Uuml;&ccedil;&uuml;nc&uuml; filmi olan ve yine başrolde oynadığı&nbsp;<b><i>Kızıltuğ&nbsp;</i></b>(Aydın Arakon, 1952), ilk filmi gibi bir tarihsel maceraydı ve ş&ouml;hretini pekiştirdi. O zamanki seyirci,&nbsp;<b>Abdullah Ziya Kozancıoğlu</b>&rsquo;nun &ccedil;ok tutulmuş &uuml;nl&uuml; romanında sevdiği Delig&uuml;n Budaktepe Timu&ccedil;in Cengizhan&rsquo;ın yiğit arkadaşı Otsukarcı rol&uuml;nde&nbsp;<b>Seyfioğlu</b>&rsquo;nu benimsemiş ve ona bir taht vermişti. O da on yıllık sinema macerası boyunca bu tahtta kalmayı başaracaktı. İngiliz asıllı eşiyle bu filmin &ccedil;ekilmekte olduğu Uludağ&rsquo;da tanışmıştılar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sıradan bir macera filmi olarak nitelendirilen&nbsp;<b>&Ouml;l&uuml;m Yarışı</b>&rsquo;nın (İsmet Hayal, 1953) ardından bir başka efsane, bir başka kayıp hazine olan,&nbsp;<b>L&uuml;tfi Akad&nbsp;</b>imzalı&nbsp;<b><i>&Ouml;ld&uuml;ren Şehir</i></b>&nbsp;geldi. Bu film ve bunu izleyen&nbsp;<b><i>Katil</i></b>&nbsp;(Akad, 1953) ve&nbsp;<b><i>Altı &Ouml;l&uuml; Var/İpsala Cinayeti</i></b>&nbsp;(Akad, 1953), ki sonuncusu da kayıptır, onun k&ouml;t&uuml; adam olarak &ouml;ne &ccedil;ıktığı filmlerdir. Bu rollerde dahi &ouml;n planda kalmayı başarmış, başrol oyuncusunun altında ezilmemiştir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Onun başrolde &uuml;nlenmiş bir yıldızken k&ouml;t&uuml; adam rollerini de kabul etmesini kaprissizliğine bağlıyorlar.&nbsp;<b>İlhan Arakon</b>&nbsp;olsun,&nbsp;<b>Sezer Sezin</b>&nbsp;olsun,<b>&nbsp;Seyfioğlu</b>&rsquo;nun paraya kıymet vermeyen, işte &ccedil;ok se&ccedil;ici olmayan, biraz da her şeye macera g&ouml;z&uuml;yle bakan biri olduğunda birleşiyorlar. O derece ki,&nbsp;<b>Sırrı G&uuml;ltekin</b>&nbsp;anlatıyor: &ldquo;<b><i>Allı Yemeni</i></b>&rsquo;<i>yi &ccedil;ekiyoruz. Sağlığı artık &ccedil;ok k&ouml;t&uuml;leşmiş. Atla gitmesi gereken bir sahne var. Dubl&ouml;r kullanmamıza izin vermedi. Yalvardık yakardık, yok. O yorulmasın diye tek seferde &ccedil;ektik sahneyi.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Altı &Ouml;l&uuml; Var</span></i></b><span>&rsquo;ın ardından, d&ouml;nemine g&ouml;re olduk&ccedil;a modern ve hayli erotik bir anlatıma sahip olan&nbsp;<b><i>Ka&ccedil;ak</i></b>&rsquo;taki başrol gelir.&nbsp;<b>Sezer Sezin</b>&nbsp;orada k&ouml;t&uuml; kadın rol&uuml;ndedir ve polisten ka&ccedil;arak onun yaşadığı &ccedil;iftliğe sığınan&nbsp;<b>Turan</b>&rsquo;ı baştan &ccedil;ıkartmaya &ccedil;alışır. Bir samanlıkta baş başa kaldıkları sahne hele, &ccedil;ıplaklık i&ccedil;ermediği halde, g&uuml;&ccedil;l&uuml; bir erotizme sahiptir.&nbsp;<b>Seyfioğlu</b>, sadece bu filmdeki oyunuyla dahi efsaneleşmeyi hak eder.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Murat Sertoğlu</span></b></span><span style="font-size: 10pt;">&rsquo;nun romanından sinemaya uyarlanan&nbsp;<b><i>Bulgar Sadık/Ka&ccedil;ın T&uuml;rkler Geliyor</i></b>&rsquo;da&nbsp; (1954) yine&nbsp;<b>Akad</b>&rsquo;la &ccedil;alışır. Ardından bir&nbsp;<b>Peyami Safa</b>uyarlaması olan&nbsp;<b><i>Cing&ouml;z Recai/Beyaz Cehennem</i></b>&rsquo;de (<b>Metin Erksan</b>, 1954) oynar. Sakız &ccedil;iğneyen k&ouml;t&uuml; adamlarıyla Amerikan filmlerine &ouml;zenen bir yapısı vardır filmin, ama su&ccedil; işlerken bir yandan da polise yardımcı olan sevimli sabıkalı rol&uuml;nde&nbsp;<b>Seyfioğlu</b>&nbsp;hi&ccedil; yadırganmaz. (Filmde gencecik bir&nbsp;<b>Fikret Hakan</b>&rsquo;ı da &ccedil;ete elemanı olarak izleriz.). Bu filmlerin ikisi de d&uuml;zg&uuml;n macera filmleridir ve &ccedil;ok tutulmuştur.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>&Ouml;l&uuml;m Korkusu</span>&nbsp;</i></b><span>(Mehdi &Ouml;zg&uuml;rel, 1955),&nbsp;<b><i>Kızımla Beraber Ağladık&nbsp;</i></b>(Arşavir Alyanak, 1955) ve<b><i>&nbsp;Kardeş Kurşunu</i></b>&nbsp;(Akad, 1955) filmlerinde k&ouml;t&uuml; adamlığa geri d&ouml;nd&uuml;kten hemen sonra bir başka hit olan&nbsp;<b><i>G&ouml;r&uuml;nmeyen Adam İstanbul&rsquo;da&rsquo;</i></b>da (<b>L&uuml;tfi Akad</b>, 1955) oynadı. O d&ouml;nem seyircileri, filmin b&uuml;y&uuml;k kısmında y&uuml;z&uuml; g&ouml;r&uuml;lmediği halde, sırf&nbsp;&nbsp;<b>Turan Seyfioğlu</b>&nbsp;oynadığı i&ccedil;in o filme gittiklerini anlatırlar. Ama yabancı bir korku klasiğinin yerli uyarlaması olarak hayli ilgin&ccedil; bir deneme olduğu muhakkak. Bir kopyası ortaya &ccedil;ıksa da izlesek!</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/seyfioglu2.jpg" alt="" width="391" height="394" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>G&ouml;r&uuml;nmeyen Adam</span></i></b><span>&rsquo;ı takiben oynadığı altı melodram arasında gişesi, pop&uuml;laritesi ve rol&uuml;n&uuml;n g&uuml;zelliği a&ccedil;ısından &ouml;ne &ccedil;ıkan,&nbsp;<b>Osman Seden</b>&rsquo;in 1957 tarihli&nbsp;<b>Zeki M&uuml;ren</b>&nbsp;filmi&nbsp;<b><i>Berduş</i></b>&rsquo;tur. Bu filmdeki rol&uuml; başkası oynasa sırıtacak derecede şematik, gaddar bir kişilik olmasına rağmen,&nbsp;<b>Turan&nbsp;</b>role inandırıcılık katmayı başarmıştır. Bu film aynı zamanda&nbsp;<b>Feridun Karakaya</b>&rsquo;nın sonradan &ccedil;ok meşhur olacak&nbsp;<b><i>Cilalı İbo</i></b>&nbsp;tiplemesinin ilk defa g&ouml;z&uuml;kt&uuml;ğ&uuml; yapımdır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>S&ouml;z&uuml;n burasında filmografiye biraz ara verelim isterseniz.<b>&nbsp;Turan Seyfioğlu</b>, 1961 yılında, 41 yaşında, gen&ccedil; &ouml;ld&uuml;. Filmlerini izleyin, bakın, 1958&rsquo;e kadar ulaşılabilen t&uuml;m filmlerinde sanat&ccedil;ı dimdik, atletik yapıda, sağlıklı g&ouml;r&uuml;n&uuml;şte. Sonraki tarihlerdeki filmlerinde olsun, fotoğraflarında olsun, o din&ccedil; yapıdan eser yoktur. Ha&nbsp;<b>Seyfioğlu</b>&nbsp;yine&nbsp;<b>Seyfioğlu</b>&rsquo;dur, ama otuzlu yaşlarda olmasına rağmen, ihtiyar bir&nbsp;<b>Seyfioğlu</b>&rsquo;dur.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu durumu sorduğumda, &ccedil;oğu bunu i&ccedil;kiye bağladı. Ama sağlıklı, heyecanlı, sportmen, hayatı seven bir adamın nasıl sağlığını bozacak derecede, intihar eder gibi i&ccedil;kiye d&uuml;şt&uuml;ğ&uuml; sorusu vardı ortada. &Ccedil;alışma arkadaşlarının anlattıklarını birleştirince ortaya bir yasak ilişki mevzuu &ccedil;ıkıyor: Evliliği mutlu bir şekilde s&uuml;r&uuml;p gitmekte olan&nbsp;<b>Turan</b>, d&ouml;nemin &uuml;nl&uuml; bir spikeri olan&nbsp;<b>D&uuml;rnev Tunaseli</b>&nbsp;ile tanışıyor ve ona kapılıyor. Bu olay evle de arasını a&ccedil;ıyor ve karısı onu terk edip İngiltere&rsquo;ye gidiyor &ccedil;ocuğuyla birlikte.&nbsp;<b>Seyfioğlu</b>&nbsp;da&nbsp;<b>Tunaseli</b>&nbsp;ile birlikte fırtınalı bir birliktelik yaşamaya başlıyor.&nbsp;<b>Atıf Yılmaz&nbsp;<i>S&ouml;ylemek G&uuml;zeldir</i></b>&rsquo;in 154. sayfasında anlatıyor: &ldquo;<b><i>Yaşamak Hakkımdır</i></b><i>,&nbsp;<b>Turan Seyfioğlu</b>&rsquo;yla &ccedil;evirdiğim ilk ve son film oldu. Filme başladığımız sıralarda&nbsp;<b>Turan</b>,&nbsp;<b>D&uuml;rnev Tunaseli</b>&rsquo;yle birlikte yaşıyordu. Birbirlerini yok etmek, t&uuml;ketmek &uuml;zerine kurulu bir ilişki.&nbsp;<b>Turan</b>&rsquo;ın alkol komasından s&uuml;r&uuml;klenerek sete getirildiği sabahları hatırlıyorum: onu ayıltıp işe başlatmak i&ccedil;in saatler harcadığımızı&hellip; D&uuml;rnev&rsquo;e aşırı &ouml;fke duyduğum o sabahları&hellip;&nbsp;<b>Turan</b>&nbsp;i&ccedil;in &ccedil;ok şey anlatılırdı. Yabancılar Lejyonunda paralı askerlik yaptığı&hellip; Suriye Cumhurbaşkanıyla aynı h&uuml;crede hapis yattığı&hellip; Bir de aşırı kuvvetini anlatan hikayeler&hellip; iri yarı bir adamı yakasından tutup tek koluyla havaya kaldırdığı falan filan&hellip; O&nbsp;<b>Turan</b>&rsquo;ın&nbsp;<b>Yaşamak Hakkımdır</b>&nbsp;&ccedil;ekiminde incecik&nbsp;<b>&Ccedil;olpan</b>&rsquo;ı kucağına alıp kaldıramadığını g&ouml;rmek ger&ccedil;ekten &uuml;z&uuml;nt&uuml; vericiydi. Gene de, b&uuml;t&uuml;n film boyunca, aşırı terbiyesi ve saygısıyla elinden geleni yaptığını, başarılı bir oyunculuk sergilediğini s&ouml;ylemeliyim.</i>&rdquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><i><span>Yaşamak Hakkımdır</span></i></b><span>, 1955&rsquo;te &ccedil;ekilmiş bir yol filmi. İstanbul&rsquo;dan G&uuml;neydoğu Anadolu&rsquo;ya kadar s&uuml;ren bir ka&ccedil;ışı anlatıyor.&nbsp;<b>Yılmaz</b>&rsquo;ın&nbsp;<b>Halit Refiğ</b>&rsquo;le senaryosunu yazdığı film, o senenin en iyi filmlerinden biri olarak anılıyor. Ama o da kayıp bir hazine.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Alican Sekme&ccedil;</span></b><span>&rsquo;e g&ouml;re&nbsp;<b>Seyfioğlu</b>&nbsp;onu &ouml;l&uuml;me g&ouml;t&uuml;ren hastalığı, yine 1955&rsquo;te &ccedil;ekilen, başrollerini&nbsp;<b>Sezer Sezin</b>&rsquo;le paylaştığı&nbsp;<b>Akad&nbsp;</b>filmi,&nbsp;<b><i>Meyhanecinin Kızı&rsquo;</i></b>nda kapıyor. Filmin kış aylarında &ccedil;ekildiğini ve bir sahnede Seyfioğlu&rsquo;nun denize atlaması gerektiğini anlattı. Kaprissiz kişiliği itiraz etmesini engelliyor ve atlıyor suya. O d&ouml;nemde hastalanıyor ve zaten i&ccedil;ki nedeniyle hayli zayıf d&uuml;şen b&uuml;nyesi iyice harap oluyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Son yıllarında &ccedil;evirdiği birka&ccedil; filmin ardından iyice yorgun d&uuml;şen&nbsp;<b>Seyfioğlu</b>, tedavi i&ccedil;in İngiltere&rsquo;ye, eşinin yanına gitti. Oradan d&ouml;nen cesediydi. 22 Kasım 1961 tarihli Sinema dergisi (sayı 54) cenazeyi ş&ouml;yle anlatıyor: &ldquo;<i>Osman Ağa Camii&rsquo;nde g&ouml;r&uuml;lmemiş bir kalabalık vardı&hellip;&nbsp;<b>Seyfioğlu</b>&rsquo;nun ay-yıldızlı bayrağa sarılı naaşı omuzlar &uuml;zerindeydi. Kamyonet &uuml;zerinde bir operat&ouml;r (<b>Orhan &Ccedil;ağman</b>) Aktun&ccedil; Film adına bu merasimi filme alıyordu... Omuzlar &uuml;zerindeki cenaze ilk molayı Fenerbah&ccedil;e stadyumunun yanındaki bir orta okulun &ouml;n&uuml;nde verdi. Bu okulda&nbsp;<b>Turan</b>&rsquo;ın &uuml;&ccedil; yılı ge&ccedil;mişti.<b>&nbsp;Turan</b>&nbsp;orta okulu burada bitirmişti. Ay-yıldızlı tabut burada cenaze arabasına konuldu. Konvoy Caddebostan&rsquo;a kadar b&ouml;ylece gitti. İkinci mola orada verildi&hellip;. Ortalığı klakson sesleri doldurmuştu. Otuz otomobil ve &uuml;&ccedil; otob&uuml;s hep birlikte klakson &ccedil;alıyorlardı. Caddebostan&rsquo;dan Erenk&ouml;y&rsquo;e kadar b&ouml;ylece gidilmişti. Kalabalık dağılıyordu. &Uuml;&ccedil; metre yerin altında koskoca bir insan yatıyordu. &Uuml;st&uuml;nde tahtalar, betonlar, topraklar ve &ccedil;elenkler vardı. Baş ucundaki &ccedil;elenkin &uuml;st&uuml;nde &ldquo;Eşi ve &ccedil;ocuğu&rdquo; yazıyordu.</i>&rdquo; D&ouml;nemin neredeyse t&uuml;m &uuml;nl&uuml; sinema &ccedil;alışanları cenazedeydiler. Erkenden s&ouml;n&uuml;p giden bir ışık&hellip;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Seyfioğlu</span></b><span>, d&ouml;neminde oyunculuğa getirdiği yenilik&ccedil;i tavırla sinemamıza &ccedil;ok şey katmıştır. Filmleri, sanat&ccedil;ı kişiliği ve hayatı, kapsamlı bir şekilde ele alınmalı ve incelenmelidir. Tez zamanda kayıp filmlerine de ulaşılması dileğiyle&hellip;</span><br /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>&nbsp;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Filmografi</span></b></span></p>\r\n<div style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;">\r\n<table border="0" style="border-style: solid; width: 450px; margin-left: 105px;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>İstanbul&rsquo;un Fethi</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1951</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Aydın Arakon</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Ankara Ekspresi</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1952</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Aydın Arakon</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Kızıltuğ</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1952</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Aydın Arakon</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Altı &Ouml;l&uuml; Var/İpsala Cinayeti</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1953</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>&Ouml;ld&uuml;ren Şehir</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1953</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>&Ouml;l&uuml;m Yarışı</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1953</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>İsmet Hayal</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Ka&ccedil;ak</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1954</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Şadan Kamil</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Beyaz Cehennem/Cing&ouml;z Recai</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1954</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Metin Erksan</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Bulgar Sadık/Ka&ccedil;ın T&uuml;rkler Geliyor</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1954</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Kardeş Kurşunu</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>&Ouml;l&uuml;m Korkusu</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Mehdi &Ouml;zg&uuml;rel</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Ebediyete Kadar</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Turgut Eting&uuml;</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Kızımla Beraber Ağladık</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Arşavir Alyanak</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Bataktaki Kız</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Şinasi &Ouml;zonuk</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>G&ouml;r&uuml;nmeyen Adam İstanbul&rsquo;da</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1955</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Tuzak Oteli</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1956</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Aydın Arakon</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Miras Uğrunda</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1956</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Aydın Arakon</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Yetimler Ahı</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1956</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Muharrem G&uuml;rses</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Berduş</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1957</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Osman Seden</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>&Ccedil;&ouml;lde Bir İstanbul Kızı</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1957</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Faruk Ken</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Me&ccedil;hul Kahramanlar</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1958</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Agah &Uuml;n</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Meyhanecinin Kızı / Mapushane &Ccedil;eşmesi&nbsp;</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1958</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>L&uuml;tfi Akad</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Yaşamak Hakkımdır</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1958</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Atıf Yılmaz</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Allı Yemeni</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1958</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Sırrı G&uuml;ltekin</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Yavrum İ&ccedil;in</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1958</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>Muharrem G&uuml;rses</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Devlerin &Ouml;fkesi</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>1960</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;"><span>Nevzat Pesen</span></span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>İ&ccedil;imizden Biri</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>1960</span></span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;"><span>T&uuml;rker İnanoğlu</span></span></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 20, 63, 'Yazarlarımızdan', '/images/yazilar/seyfioglu3.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (48, 'ay-j169', 'sinemanin-klasik-cagi', 'Sinemanın Klasik Çağı', 'Eric Rohmer', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">Sinemanın Klasik &Ccedil;ağı</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="color: #800000; font-size: 10pt;"><span><b>E</b></span><b><span>ric Rohmer</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>&Ccedil;ev: Cem Kayalıgil</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><b><span style="font-size: x-small;">&nbsp;<img src="/images/yazilar/boulogne.jpg" alt="" width="220" height="290" border="0" /></span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tuhaf bir kompleksten yana dertliyiz şu g&uuml;nlerde, tarih kompleksinden.&nbsp;<b><i>Les Dames du Bois du Boulogne&nbsp;</i></b>&uuml;zerine bu kadar tantana edilmesine şaşırmıştı birileri, &ldquo;Bunda yeni ne var ki?&rdquo; diye. Bunun &uuml;zerine, bir yapıtın değerlendirmesinin sadece kendi tamamlanmışlığı &uuml;zerinden yapılması gerektiği cevabını yetiştirebilecek birilerinin &ccedil;ıkmasını isterdim.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Gelişme evresindeki b&uuml;t&uuml;n sanatlar &ccedil;eşitlenme gereksinimi duyarlar. Yenilik bundan sonra gelen bir &ouml;l&ccedil;&uuml;tt&uuml;r; tıpkı yıkıp d&ouml;kme arzusunun, &ccedil;&ouml;kt&uuml; &ccedil;&ouml;kecek yapılarla hemen bastırılabildiği &ccedil;alkantılı d&ouml;nemlerde olduğu gibi.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Klasik &ccedil;ağının eşiğinde duran sinema &ouml;nc&uuml;llerini keşfediyor; ama ortokromatik ve sessiz g&ouml;r&uuml;nt&uuml;lerin hoş ve &ouml;mr&uuml;n&uuml; doldurmuş d&uuml;nyasının kalıntılarını değil, artık &ouml;l&uuml;ms&uuml;z olduğunu bildiği ve incelikli kurallarını &ccedil;&ouml;zmeye talip olduğu bir g&uuml;zelin arketiplerini. O halde, mermerden yontulmayı istemesi ve orta &ccedil;ağındayken kof bir cesaretle ve memnuniyetle kendisine yakıştırmış olduğu&nbsp;<i>şimdinin sanatı&nbsp;</i>sıfatını reddediyor olması; sinema i&ccedil;in &ccedil;ok mu &ccedil;ocuk&ccedil;a, &ccedil;ok mu d&uuml;ş&uuml;ncesizce bir şeydir?&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sahicilik, doğallık, yer ve eylemdeki birlik, psikolojik derinlik... Sinemanın &ccedil;alışma alanını haber kuşakları ve dedektif &ouml;yk&uuml;leriyle sınırlamaya herkesten daha fazla heves eden eleştirmenlerin, bu kavramları irdelemekten &ccedil;ok tekrar edip durdukları iddiasındayım. Kim bilebilir ki? İ&ccedil;lerinden birisi Aubignac&rsquo;ın &ldquo;La pratique du th&eacute;atre&rdquo;ını [1] yeniden okumayı akıl etmiş olsaydı, delicesine aradığı ifadeyi orada bulabilirdi. Hen&uuml;z olgunlaşmamış oluşuyla iftiracıları huzursuz eden bir klasisizme bağlanalım hadi. Ama ne olursa olsun şu iddiamızdan da kuşku duymayalım: Endişeye gerek yok. Sinemanın klasik &ccedil;ağını geride bırakmış değiliz, daha var ona.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Beyazperdedeki set birdenbire genişleyip kendi başına bir oyuncu haline geldi. Edebiyat ise d&uuml;nyayı keşfetmeyi &ouml;ğrenmişti: 3000 yıllık pratiğinin keskinleştirdiği kahinlik insanlığa o kadar derin işlemişti ki keskinleşmiş bakışının, g&ouml;r&uuml;nenin anlamsız ve kaotik g&ouml;sterisi &uuml;zerine kurulacağı g&uuml;nlere gelinecekti artık. Edebiyatın asıl işi olan, bir şeyi g&ouml;stermeden a&ccedil;ıklama g&ouml;revine bu bilin&ccedil;teki bir arzuyla karşı &ccedil;ıkışını anlayışla karşılayabiliriz; ama sinemanın buna zıt y&ouml;nde ilerleyip insanı keşfetmesine hangi hakla engel olabiliriz ki? &Ouml;teki sanatların anca katettiği bir yolun son noktasının h&acirc;l&acirc; bir hayli uzağında olan sinema; sinemadan doğup ona onun ancak soluk bir yansımasını sunabilen bir edebiyatı niye &ouml;rnek almak zorunda olsun?</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Kanımca, sinemanın evrimi başlangı&ccedil;ta resim ve şiirinkiyle &ccedil;akışıyordu; sonrasındaysa &ldquo;yenilenmeyi&rdquo; kabalaşmakta buldu. Bu doğrultuda d&uuml;ş&uuml;nd&uuml;ğ&uuml;mde de&nbsp;<b>Marc Sennett, Buster Keaton&nbsp;</b>veya&nbsp;<b>Charlie Chaplin</b>&rsquo;deki s&uuml;rrealizmi&nbsp;<b><i>Bir End&uuml;l&uuml;s K&ouml;peği&nbsp;</i></b>veya&nbsp;<b><i>Altın &Ccedil;ağ</i></b>&rsquo;dakinden daha ger&ccedil;ek buluyorum.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/bunuel.jpg" alt="" width="190" height="253" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ayrışma artık tamamlandı. İster inanın ister inanmayın, Faulkner&rsquo;a kıyasla Diderot daha modern bir senarist. Kaldı ki &ouml;rnek bulmak i&ccedil;in ge&ccedil;mişi eşelemeye de gerek yok. Bug&uuml;n&uuml;n en iyi senaristleri, değerinden bir şeyler kaybedebileceğine ihtimal vermedikleri bir edebiyatın pırıltısı karşısında b&uuml;y&uuml;lenerek, kendilerinde saklı duran ahlaksal ve psikolojik eğilimleri k&ouml;reltmekteler.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Tutkuların, kişiliklerin ve zihinsel s&uuml;re&ccedil;lerin bizler i&ccedil;in &ccedil;oktan t&uuml;kenmiş kategoriler oldukları ve bunların ifadelerinin de aklımıza ancak teğet ge&ccedil;ebileceği ne malum?<b>John Ford</b>&rsquo;un&nbsp;<b><i>Gazap &Uuml;z&uuml;mleri</i></b>&rsquo;ne ve&nbsp;<b>Andr&eacute; Malraux</b>&rsquo;n&uuml;n&nbsp;<b><i>Espoir</i></b>&rsquo;ına getirebileceğimiz tek eleştiri, bunların, baştan okumaya artık hi&ccedil; de heves etmediğimiz romanların sinemasal uyarlamaları olmaları olabilir. Sanat, &ccedil;ağımızın bir yansıması olduğu kadar panzehiri de değil mi? Merhametsizlik k&uuml;lt&uuml;, huzurlu &ccedil;ağların<b>&nbsp;</b>k&ouml;t&uuml; alışkanlıklarındandır; bizim &ccedil;ağımızınsa daha yetkin bir ilaca ihtiyacı var. İnsan hakkındaki her şey s&ouml;ylenmiş değil; yeni bir sanat s&ouml;z hakkı almak i&ccedil;in sabırsızlanıyor. Ona kulak vermeye hazır olduğumuzu g&ouml;relim; modaya uyma uğruna kendimizi bile isteye k&uuml;&ccedil;&uuml;ltmemize neden olan ve g&ouml;z&uuml;k&ouml;r bağlılığımızın elinde can veren kalıplaşmış sanattan yıldık artık. Hem &ccedil;ağımızın en katışıksız ifade bi&ccedil;imleri bile (şarkı, dans, &ouml;yk&uuml; serileri) taklitten &ouml;te bir şey değilse, gelecekte, bug&uuml;nleri baştan değerlendirmeyi kim isteyecektir ki?</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/gazap_uzumleri.jpg" alt="" width="451" height="305" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>D&uuml;nya naifliğini yitirmekte. Sanatsal ifadenin en doğal bi&ccedil;imlerinin de koflaştığı şu &ccedil;ağ, sadece duyarlılık ve aklımızın daha arı kaynaklarına yaslanmamıza imkan tanıyabiliyor. Şansımızın değerini bilelim. Kader ve tarih bizden yana.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sinema sinemadır. Onun kendisiyle zıtlaşması da zekice bir d&uuml;mendir. Bırakalım hayal&icirc; bir saflığın yitirilişinin yasını tutanlar i&ccedil;in şu sır ne ifade edecekse etsin: Dilden, yani en olağan g&ouml;stergeden yoksun olan sessiz film karakterleri, ruhlarını bizlere a&ccedil;abilecek incelikli bir y&ouml;ntemde ustalaştılar. Orada her şey bir g&ouml;steren veya simgeye d&ouml;n&uuml;şt&uuml;. Zekasının y&uuml;celtilmesinden y&uuml;reği yağ bağlayan seyirci ise anlamak i&ccedil;in didindi durdu ve g&ouml;rmeyi unuttu. Ama sesli filme ge&ccedil;ilmesiyle birlikte, kendine yabancı olan bu &ouml;devden kurtulmuş olan beyazperde i&ccedil;in şimdi, asıl g&ouml;revine d&ouml;nme zamanıdır: işaretlere başvurmadan sergileme g&ouml;revine.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sesli filmlerde, g&ouml;r&uuml;nen şey, t&ouml;zd&uuml;r ve i&ccedil; d&uuml;nyanın &ouml;z&uuml;n&uuml; kendinde bulur: &ouml;yle bir d&uuml;nya ki, g&ouml;r&uuml;nen, onun v&uuml;cut bulmuş halidir, g&ouml;stereni değil.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Huzursuz bir y&uuml;zde duygunun kendisinden &ouml;tede olup da farketmeyi isteyeceğimiz bir şeyler daha hi&ccedil; mi yoktur?&nbsp;<b>Chaplin</b>&rsquo;in, sinemanın en ger&ccedil;ek dehası olduğunu iddia etmek ne kadar da tuhaf! Asıl ustalarımız olarak hadi&nbsp;<b>Murnau</b>&rsquo;yu,&nbsp;<b>Stroheim</b>&rsquo;ı veya&nbsp;<b>Dreyer</b>&rsquo;i selamlayalım. Seyirciye g&ouml;z kırpanların t&uuml;m&uuml;nden, kendilerine su&ccedil; ortağı arayanlardan ve ne denli sağduyulu olursa olsun şefkatimizi bekleyen her şeyden sakınalım. Mesafeli durmayı &ouml;ğrenmemiz şart. Yeniden &ouml;z&uuml;ne kavuşmuş olmasıyla gururlanan sinemanın, ikiy&uuml;zl&uuml; bir tavırla onda bulacaklarımızdan daha fazlasını vereceğini iddia ediyoruz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><b>N</b></span><b><span>otlar</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">*&nbsp;<i>Maurice Cherer</i>&nbsp;imzasıyla,&nbsp;<i>Combat</i>&rsquo;ın 15 Haziran 1949 tarihli sayısında yayınlnamıştır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">[1]&nbsp;<i>Fran&ccedil;ois Hedelin, abb&eacute; d&rsquo;Aubignac&nbsp;</i>(Aubignac başrahibi); kısaca&nbsp;<i>Aubignac</i>: 1604-1676 yılları arasında yaşamış Fransız oyun yazarı. (&ccedil;ev.)</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">&ldquo;La Pratique du th&eacute;atre&rdquo;: 1657 yayınlanmış olan bu eser, klasik oyun yazarı Racine i&ccedil;in temel bir rehber işlevi g&ouml;rm&uuml;şt&uuml;.</span></p>', 193, 63, 'Yazarlarımızdan', '/images/yazilar/boulogne.jpg', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (49, 'ay-j170', 'koklerimi-salsaydim-derinlere', 'Köklerimi Salsaydım Derinlere', 'Burcu Atahan', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">K&ouml;klerimi Salsaydım Derinlere</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Burcu Atahan</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b>&nbsp;</b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; line-height: 16px;"><span style="font-size: 10pt;"><b><span>Deli Deli Olma</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Y&ouml;netmen:&nbsp;</span>&nbsp;</b><span>Murat Sara&ccedil;oğlu</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Senaryo:&nbsp;</span>&nbsp;</b><span>Hazel Sevim &Uuml;nsal</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni:&nbsp;</span>&nbsp;</b><span>Mustafa Kuş&ccedil;u</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>M&uuml;zik</span>&nbsp;</b><span>: Mehmet Erdem, &Ouml;zg&uuml;r Akg&uuml;l</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Kurgu</span>&nbsp;</b><span>: Mustafa Preşeva, Erkan Tekemen</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Oyuncular:&nbsp;</span>&nbsp;</b><span>Tarık Akan, Şerif Sezer, Levent T&uuml;lek, Zuhal Topal, Korel Cezayirli,Cemile Nihan Turhan, Ozan Erdoğan</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Yapımcı:&nbsp;</span>&nbsp;</b><span>Tolga Aydın</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>2009/100&rsquo;/T&uuml;rkiye</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: x-large;">B</span></b><span style="font-family: Verdana; font-size: 10pt;"><span>ir ayrık otu gibi gittiği yerden s&ouml;k&uuml;len Malakanların Mişka&rsquo;da can bulmasının hem h&uuml;z&uuml;nl&uuml; hem g&uuml;ld&uuml;ren &ouml;yk&uuml;s&uuml;yle,&nbsp;<b><i>120</i></b>&nbsp;ve&nbsp;<b><i>O.. &Ccedil;ocukları</i></b>&rsquo;ndan sonra karşımıza yeniden &ccedil;ıkar&nbsp;<b>Murat Sara&ccedil;oğlu</b>. B&ouml;ylece&nbsp;<b>Şerif G&ouml;ren</b>&rsquo;in&nbsp;<b><i>Yol</i></b>&nbsp;filminden sonra&nbsp;<b>Tarık Akan</b>&rsquo;la&nbsp;<b>Şerif Sezer</b>&rsquo;in &ldquo;yol&rdquo;larının yıllar sonra yeniden kesişmesine vesile olur. Ancak oyuncularına rağmen &ouml;nceki filmlerinin &ccedil;ektiği izleyiciyi gerek tanıtımın yetersizliği gerek afiş tasarımıyla kaybetmiş olabileceği d&uuml;ş&uuml;n&uuml;len bir yapım&nbsp;<b><i>Deli Deli Olma</i></b>. İsmi ise &ouml;yk&uuml;n&uuml;n ge&ccedil;tiği Kars&rsquo;a &ouml;zg&uuml; bir kullanım &ldquo;aklını başına topla&rdquo; anlamında. &Ouml;yk&uuml; 1877&ndash;1878 Osmanlı Rus Savaşı&rsquo;ndan (93 Harbi) sonra Rusların Malakan Kavmi&rsquo;ni Kars&rsquo;a g&ouml;&ccedil;e zorlamasıyla başlar. Kars&rsquo;a g&ouml;&ccedil; eden ailelerden biri de Mişka&rsquo;nın ailesidir. G&uuml;n&uuml;m&uuml;ze gelindiğinde ise Mişka k&ouml;ydeki tek Malakandır.&nbsp; Kars&rsquo;a g&ouml;&ccedil; ettirilme nedenlerine gelince: asıl adı Rus&ccedil;ada Molakan olan -Molak: s&uuml;t,&nbsp; Molakan: s&uuml;t i&ccedil;en- Malakanlar yaşam bi&ccedil;imleri nedeniyle Rus Ortodoks kilisesiyle anlaşmazlık yaşamaktadırlar. Anlaşmazlık nedenleri ise Rusların haftada yalnızca iki g&uuml;n s&uuml;t i&ccedil;meyi uygun g&ouml;r&uuml;p daha fazlasını yasaklamalarına karşın Molakanların her g&uuml;n s&uuml;t i&ccedil;mekte bir sakınca g&ouml;rmemeleri yani &ldquo;perhizi bozma&rdquo;larıdır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;"><span>&Ouml;yk&uuml;deki diğer bir karakter Pobu&ccedil;&rsquo;tur. Pobu&ccedil; b&uuml;t&uuml;n k&ouml;yle &ouml;zellikle de Mişka&rsquo;yla anlaşmazlık i&ccedil;indedir. Ancak Pobu&ccedil;&rsquo;un her t&uuml;r sert ve kavga &ccedil;ıkartmaya bahane arayan davranışlarına Mişka&rsquo;nın gayet sakin ve neredeyse tepkisiz karşılık vermesinin arkasında; Mişka&rsquo;nın ge&ccedil;mişte yaptığı hatanın su&ccedil;luluğuyla &ouml;r&uuml;lm&uuml;ş bir boyun eğmişlik ve teslimiyet varsa da bunu &ouml;tekileşmişliğe de, Malakanların &ccedil;atışmaya kapalı &ouml;z&uuml;ne dayandırmak da m&uuml;mk&uuml;nd&uuml;r. Nitekim 1921&rsquo;de askerlik kanununun &ccedil;ıkarılması &uuml;zerine insan &ouml;ld&uuml;rmeye ve savaşa karşı oldukları i&ccedil;in Malakanların b&uuml;y&uuml;k &ccedil;oğunluğu T&uuml;rkiye&rsquo;yi terk etmişlerdir. Aynı şekilde Pobu&ccedil;&rsquo;un bu karşı konulamaz hır&ccedil;ınlığı da; yaşayamadığı aşkla katılaşan ve kendi aşkla tutuşurken hi&ccedil; sevilmemiş olduğu d&uuml;ş&uuml;ncesini taşıyamayan yaralı y&uuml;reğinin isyanıyla hatasını an be an y&uuml;z&uuml;ne vurarak Mişka&rsquo;nın &ouml;mr&uuml;n&uuml; su&ccedil;luluk i&ccedil;inde acı &ccedil;ekerek ge&ccedil;irmesini hedef alır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><img src="/images/yazilar/deli%20deli%20olma1.JPG" alt="" width="520" height="346" style="display: block; margin-right: auto; margin-left: auto;" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Pobu&ccedil;&rsquo;un torunu k&uuml;&ccedil;&uuml;k Alma&rsquo;nın ise Mişka&rsquo;nın elmalarını gizlice yeme heyecanı: Mişka&rsquo;nın evinden y&uuml;kselen piyano sesinin Alma&rsquo;da var olan m&uuml;zik aşkını tetiklemesiyle birleşince Alma-Mişka dostluğuna tanık oluruz. &Ouml;yle ki Mişka&rsquo;nın onun i&ccedil;in evine telefon bağlattığı ve arar diye umutla beklediği Dimitri&rsquo;yle konuşma hayali Alma&rsquo;yla ger&ccedil;ekleşir. Telefon kapanmıştır ama Alma anlık bir kararla Rusya&rsquo;yla konuşuyormuş gibi yapar ve Mişka&rsquo;nın hastalığının son g&uuml;nlerinde y&uuml;z&uuml;n&uuml;n sevin&ccedil;le g&uuml;lmesini sağlar. Alma evde yemek sırasında y&uuml;r&uuml;tt&uuml;ğ&uuml; kaz etini alıp Mişka&rsquo;ya getirir. Annesinin g&ouml;nderdiğini s&ouml;yler. Kars&rsquo;ta kaz etinin misafire ya da en sevilene sunulan en iyi armağan olmasının da Mişka i&ccedil;in ifade ettiği anlam b&uuml;y&uuml;k olur Alma sayesinde.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Pobu&ccedil;&rsquo;un borcu olduğunu &ouml;ğrenip Mişka&rsquo;nın kapısına dayanmasıyla yeni bir boyut kazanır Alma&rsquo;nın piyano aşkı ve k&ouml;y ahalinin piyanoyla ilişkisi. Artık k&ouml;yde borcu olan piyanoyu verir bor&ccedil; kapatmak i&ccedil;in &ccedil;&uuml;nk&uuml; ne olduğunu ne işe yaradığını kimse bilmemekte ayrıca kimseyi de ilgilendirmemektedir Alma ve Mişka&rsquo;dan başka. Yer kaplayan ayağa dolaşmasın diye ahıra atılan, y&uuml;kl&uuml;k olarak ya da tavuklar i&ccedil;in kullanılan bir tahta par&ccedil;asıdır, verelim de kurtulalım d&uuml;ş&uuml;ncesiyle verilir ve kurtulunur. Bu sefer alanın başına dert a&ccedil;ar. Oysa Ruslar i&ccedil;in piyanoya ya da m&uuml;ziğe verilen değeri Malakanların Kars&rsquo;a g&ouml;&ccedil; ederken piyanolarını da gittikleri yere g&ouml;t&uuml;rmelerinden; onu sıkıca sarıp sarmalayıp her t&uuml;r tehlikeden: kardan, &ccedil;amurdan, &ccedil;arpıp kırılmadan korumaya d&ouml;n&uuml;k aldıkları &ouml;nlemden anlamak m&uuml;mk&uuml;nd&uuml;r. Rusların dışında T&uuml;rkler arasında da piyanonun değerini anlayan iki velet vardır. Alma ve yakın arkadaşı Tavşan piyanonun k&ouml;yde dolaştığı ailelerde başına bir şey gelmesin diye k&acirc;h babasının d&uuml;kk&acirc;nının camını kırıp şekerleri &ccedil;alıp &ccedil;ocuklara verirler k&acirc;h kar k&uuml;rerler. Piyanoya savrulan bir tekme ise kavga sebebidir. Babası Şemistan&rsquo;ın dudak değmez yarışmasını kazanmasıyla Alma piyanosuna yeniden kavuşur. Annesi Pobu&ccedil;&rsquo;un akrabasına gitmesini fırsat bilip Şemistan&rsquo;ın Mişka&rsquo;yı eve alması ise Pobu&ccedil;&rsquo;un erken d&ouml;nmesiyle ortaya yeni bir &ccedil;atışma &ccedil;ıkarır. Mişka hasta haliyle ve piyanosuyla kapının &ouml;n&uuml;ne konur. Bu ise şaşırtıcı bir şekilde Alma&rsquo;nın Mişka&rsquo;ya sorduğu sorunun yanıtını ortaya &ccedil;ıkaracaktır. Ailesinden kalan altınları. Mişka bu altınların Alma&rsquo;nın eğitimi i&ccedil;in kullanılmasını istediğini s&ouml;yler, &ouml;l&uuml;m d&ouml;şeğindeyken. Bu da Malakanların &ccedil;ocuklara b&uuml;y&uuml;k &ouml;zen g&ouml;sterdiklerinin, sosyal yardımlaşmanın Malakan topluluğu i&ccedil;inde ne kadar &ouml;nemli olduğunun da filmdeki yansımasıdır ki Malakanların bilinen &ouml;zelliklerinden biri de evlat edindikleri &ccedil;ocuklardır. &Ccedil;ocukları olmadığında hi&ccedil; teredd&uuml;ts&uuml;z evlat edinirler, o &ccedil;ocuklara sıkıntısız, rahat bir yaşam sunulacağının farkındalığıyla.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: x-small;"><img src="/images/yazilar/deli%20deli%20olma2.JPG" alt="" width="520" height="341" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;"><span>Piyano arka planda k&ouml;yde bir modernlik işaretidir, değişimin g&ouml;stergesidir. Rus-T&uuml;rk toplumları arasındaki farkın da bir yansımasıdır. 1877&rsquo;de Ruslarda bir m&uuml;zik ya da sanat bilinci gelişmiş olmasına ve o zamandan kalan bir piyano olmasına karşın bu zamanda T&uuml;rkler i&ccedil;in piyano tahta yığınından başka bir şey değildir &Ccedil;&uuml;nk&uuml; T&uuml;rklerin geneline h&acirc;kim olan m&uuml;zik k&uuml;lt&uuml;r&uuml; d&uuml;nyaya d&ouml;n&uuml;k değil kendi k&uuml;lt&uuml;r&uuml;ne d&ouml;n&uuml;k bir m&uuml;zik k&uuml;lt&uuml;r&uuml;d&uuml;r. Bunu ise &ldquo;dudak değmez&rdquo; gecelerinden (iki dudağın arasına iğne koyup iğneyi dudağa batırmadan saz eşliğinde mani okumak) anlayabiliriz. Bilinen &ccedil;algı sazdır ve onun dışındaki &ccedil;algılara y&ouml;nelik bir bilin&ccedil; gelişmemiştir. Tabii piyanonun da saz gibi bir &ccedil;algı olduğunun anlaşılması ve Alma&rsquo;nın bu &ccedil;algının eğitimini alması s&ouml;z konusu olunca k&ouml;ydeki herkes teredd&uuml;ts&uuml;z bu eğitimi onaylar. Bu da aslında kendilerinde var olan bilgiden kaynaklanır. Bu bilgi m&uuml;ziğin iyi bir şey olduğu bilgisidir ve bunun yanıtını vermek i&ccedil;in dışarıya bakmalarına gerek yoktur, kendilerine bakmaları yeterlidir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/deli%20deli%20olma3.JPG" alt="" width="520" height="346" border="0" /><b><span style="font-size: x-small;"><br />&nbsp;</span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Pobu&ccedil;&rsquo;un k&ouml;ydeki otoritesi Alma&rsquo;nın piyano eğitimi alması i&ccedil;in Kars&rsquo;a gitmesinin g&uuml;ndeme gelmesiyle yıkılır. Bu sefer kimse ona boyun eğmeye niyetli değildir. Ve dengeler de değişmeye başlar. Piyano&rsquo;yla beraber değişimin başlatıcısı aynı zamanda kentli olan Metin &Ouml;ğretmendir. Hem Alma&rsquo;nın yeteneğini fark etmesi hem de onun bu yeteneğinin değerlendirilmesi i&ccedil;in g&ouml;sterdiği &ccedil;abayla Metin &Ouml;ğretmen k&ouml;y yaşamının statik durumunun artık devinmeye başlamasının da ger&ccedil;ekleştiricisi olur. Dolayısıyla k&ouml;ylere eğitim g&ouml;t&uuml;rmenin &uuml;lkedeki d&ouml;n&uuml;ş&uuml;me ve aydınlanmaya katkısının tartışılamaz derecede b&uuml;y&uuml;kl&uuml;ğ&uuml;ne vurgu yapar. Alma&rsquo;nın geleceği kurtulacaktır. Aslında Alma k&ouml;ylerdeki b&uuml;t&uuml;n &ccedil;ocukların bir temsilidir. Geleceği doğmadan belirlenmiş &ccedil;ocukların ve &ouml;zellikle cinsiyeti nedeniyle daha sınırlı bir d&uuml;nyaya hapsedilen-hapsedilmeye &ccedil;alışılan kız &ccedil;ocuklarının aynasıdır o. Ve bu sadece bir &ccedil;ocuğun yaşamının kurtulmasıyla kısıtlı değildir. Bu &ouml;rnek o k&ouml;y insanlarına yakılan bir ışıktır. Bu ışığı nesiller boyu yakmak onların elindedir tabii yanlarındaki &ouml;ğretmenlerle.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: x-small;"><img src="/images/yazilar/deli%20deli%20olma4.JPG" alt="" width="520" height="346" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"><br /><span style="font-size: 10pt;">Metin &Ouml;ğretmenin tezatını oluşturan kentli bir &ouml;ğretmen &ouml;rneğine de Alma&rsquo;nın konservatuar sınavına giren j&uuml;ride rastlarız. Burada kentlinin k&ouml;yl&uuml;ye bakışının en aşağılık versiyonuyla karşılaşmak bizi derinden yaralasa da; bunun &uuml;lkemizin bir ger&ccedil;eği olduğu d&uuml;ş&uuml;ncesiyle y&uuml;zleşmek ise &ccedil;arpık eğitim sistemimizle nasıl keskin bir bı&ccedil;ağın &uuml;zerinde y&uuml;r&uuml;d&uuml;ğ&uuml;m&uuml;z&uuml;n de en canlı &ouml;rneğini tekil eden, artık kullanılmaktan epey yıpranmış bir ayna tutuyor bize. K&ouml;y &ccedil;ocuğuna sanki kendisi gibi ana rahminden &ccedil;ıkmış bir varlık değilmiş&ccedil;esine bakan &ouml;ğretmen(!) zihniyeti bizi u&ccedil;urumdan aşağı d&uuml;ş&uuml;recek sonu da beraberinde getiriyor. &Ouml;d&uuml;m&uuml;z kopuyor bu harika eğitilmiş(!) &ouml;ğretmen mi m&uuml;svedde mi olduğu ilk bakışta fark edilen insanlarca(!) &ldquo;ya Alma konservatuara alınmazsa&rdquo; diye. Ne de olsa burası T&uuml;rkiye! Her t&uuml;r s&ouml;z&uuml;n ağızda &ccedil;iğnenen sakız olmaktan &ouml;teye gitmediği g&uuml;zelim &uuml;lke! Halbuki biz Alma&rsquo;nın ciğerini biliyoruz. Neyse ki Metin &Ouml;ğretmen gibi bir &ouml;ğretmenle daha karşılaşıyoruz j&uuml;ride de y&uuml;reğimize su serpiliyor.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Mişka&rsquo;nın &ouml;l&uuml;m&uuml;n&uuml;n ardından, Mişka ve Pobu&ccedil;&rsquo;un gen&ccedil; halleriyle g&ouml;ky&uuml;z&uuml;ne y&uuml;kselme (cennette buluşma) sahnesi filmin b&uuml;t&uuml;n b&uuml;y&uuml;s&uuml;n&uuml; bozar. Buna gerek var mıdır? Filme bir anlam katmış mıdır? Hayır, tam tersi filmden alıp g&ouml;t&uuml;rm&uuml;şt&uuml;r. Kendimizi başka bir filmden alınıp buraya yapıştırılmış gibi hissetmemize ve filmle olan &ouml;zdeşleşmemizin kırılmasına neden olmuştur.&nbsp;<b>Tarık Akan</b>&rsquo;ın oğlu&nbsp;<b>Barış &Uuml;reg&uuml;l</b>&rsquo;&uuml;n babasının yeteneğinden bir nebze bile almadığına an be an şahit oluruz ki filmde tek bir hissizce bakışın bile filmin havasını nasıl bozduğunu &uuml;z&uuml;lerek fark ederiz. Tabi g&ouml;ğe y&uuml;kselme d&uuml;nyadaki b&uuml;t&uuml;n sınırların ortadan kalktığının da g&ouml;stergesidir. Mişka ve Pobu&ccedil; etnik ya da dini hi&ccedil;bir sınırın, kuşatmanın olmadığı bir yerde mutlu bir şekilde birlikte olabileceklerdir. Ancak filmin b&uuml;t&uuml;n&uuml;nden kopuk bir sahnedir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Mişka&rsquo;yla Pobu&ccedil;&rsquo;un kavuşamama nedeni, annesinin Mişka&rsquo;nın ayaklarına kapanıp gitmemesi i&ccedil;in yalvarmasıdır. Nedeninin karmaşık bir şey olduğunu d&uuml;ş&uuml;n&uuml;rken gayet basit olması bizi şaşırtır en başta. Ama aslında hi&ccedil; de &ouml;yle g&ouml;r&uuml;nd&uuml;ğ&uuml; gibi basit değildir. Tarihi bir ger&ccedil;ek bu şekilde y&uuml;z&uuml;m&uuml;ze vurulur. Malakanların T&uuml;rklerden dolayı nasıl bir tehdit altında olduğunu anlarız ki T&uuml;rkiye&rsquo;nin d&ouml;rt bir tarafındaki gayrim&uuml;slimler askerden muaf tutulurken Malakanların askere alınması zorunluluğunun getirilmesinin nedeni de zaten savaş karşıtı oldukları i&ccedil;in T&uuml;rkiye&rsquo;den gitmelerinin sağlanmasıdır. D&ouml;nemin Meclis H&uuml;k&uuml;meti bir yandan Bolşeviklerle iyi ge&ccedil;inmeye &ccedil;alışır bir yandan da sosyalist d&uuml;ş&uuml;ncenin yaygınlaşması tehlikesine karşı her t&uuml;r &ouml;nlemi almaktadır ki burada g&ouml;rd&uuml;kleri tehlikelerden biri de Malakanlardır. Kazım Karabekir bile askerlik sorununun Malakanları harekete ge&ccedil;irecek en b&uuml;y&uuml;k koz olduğunu dile getirir. &Ouml;nce T&uuml;rkiye&rsquo;yi terk edin uyarısı yapılır. Bu &ccedil;&ouml;z&uuml;m olmayınca 20 Ocak 1921&rsquo;e kadar T&uuml;rkiye&rsquo;yi terk etmezseniz askere alınırsınız kararı &ccedil;ıkarılır Meclis&rsquo;te. Halbuki Rusya&rsquo;yla yapılan anlaşmada askerliğin g&uuml;ndeme gelmemesi karara bağlanmıştır ancak T&uuml;rkiye bu karara uymaz. Kendileri gitmediklerindeyse Anadolu&rsquo;dan getirilen g&ouml;&ccedil;menler Malakanların yerine yerleştirilmeye &ccedil;alışılıp Malakanlar ahırlarda a&ccedil; susuz yaşamaya mahkum edilir. T&uuml;rkler tarafından evlerine tarlalarına girilme, mallarının yağmalanması, hırsızlık, zul&uuml;m, işkence gibi her t&uuml;r insanlık dışı muameleye maruz bırakılırlar. &Ccedil;ar d&ouml;neminde bile b&ouml;ylesi muameleye maruz kalmamışlardır. Acı olansa bu k&ouml;t&uuml; muamelenin savaş sırasında değil savaş sonrasında Bolşevizm korkusuyla yapılmış olmasıdır. Malakanların &ccedil;ok b&uuml;y&uuml;k bir b&ouml;l&uuml;m&uuml; askerlik kanunuyla, geri kalanı ise 1962&rsquo;de T&uuml;rkiye&rsquo;yi terk etmişlerdir. Yani Mişka&rsquo;nın Pobu&ccedil;&rsquo;la ka&ccedil;mamasının nedeni &ouml;yle hafife alınacak bir neden değildir. &Ccedil;&uuml;nk&uuml; kızları bir Malakanca ka&ccedil;ırılmış olan T&uuml;rklerin, buna vereceği tepki kalan b&uuml;t&uuml;n Malakanları kılı&ccedil;tan ge&ccedil;irmekten geri bir tepki olmayacaktır. Bu da &ouml;tekileştirmenin geleceği son noktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Ve son Malakan&rsquo;ın, Mişka&rsquo;nın yaşamını &ouml;zetleyen şarkı &ccedil;ıkagelir: &ldquo;Bir Sarmaşık Olsaydım&rdquo;.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir Sarmaşık Olsaydım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sıkıca tutunsaydım bir yere</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>S&ouml;k&uuml;l&uuml;p atılmasaydım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>K&ouml;klerimi salsaydım derinlere</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir sarmaşık olsaydım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Dolasaydım g&ouml;vdemi d&ouml;ne d&ouml;ne</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>G&uuml;nlerce aynı yerde kalsaydım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Hareketsizlikten uyusaydım</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bense ayrık otuyam</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Her &ccedil;ıktığı yerden s&ouml;k&uuml;len</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sarmaşık olmak isteyip de</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Basit bir ot bilinen</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bir ayrık otuyam</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>K&ouml;k&uuml; olmayan sevilmeyen</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Sarmaşık olmaya &ouml;zenen&hellip;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Mişka&rsquo;nın şarkısında ben bir ayrık otuyam deyişi &ouml;teki olmanın ve bulunduğu yere ait olamayan b&uuml;t&uuml;n Malakanların sesidir. Ne sarmaşık gibi Rusya&rsquo;ya sıkıca sarılabilmişlerdir ne de T&uuml;rkiye&rsquo;ye. Her gittikleri yerden ayrık otuymuş&ccedil;asına koparılıp atılmaya &ccedil;alışılmışlar yani &ldquo;&ouml;teki&rdquo; olmaktan &ldquo;benzer&rdquo; olmaya yıllar, yıllar boyu ge&ccedil;ememişlerdir. Hayatlarını da ayrık otu olarak sonlandırmışlardır. Hayatta kalarak yaşadıkları yere ait olamamışlardır; ancak &ouml;l&uuml;p toprakla b&uuml;t&uuml;nleştiklerinde, g&ouml;m&uuml;ld&uuml;kleri yere k&ouml;k salma şansını yakalamışlardır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><img src="/images/yazilar/deli%20deli%20olma5.jpg" alt="" width="500" height="281" border="0" /></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><br /><span style="font-size: 10pt;">&Ouml;yk&uuml;n&uuml;n sonunda Pobu&ccedil;&rsquo;u Mişka&rsquo;yı kendi rit&uuml;elleriyle toprağa verirken g&ouml;r&uuml;r&uuml;z. Pobu&ccedil; k&ouml;yde bunu bilen tek kişidir ama bunu yapma nedeni tek bilenin kendisi olması kesinlikle değildir. Yaşarken Mişka&rsquo;nın yanında olamamıştır ama &ouml;l&uuml;m&uuml;nde yanında sadece kendisi vardır. Bu da Pobu&ccedil;&rsquo;un trajik sonudur.&nbsp; Pobu&ccedil; Kars deyimiyle &ouml;zbaşına kalır.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 12pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>&Ouml;yk&uuml;de zamansal belirsizlik g&ouml;ze &ccedil;arpar. 1878&rsquo;de Mişka&rsquo;nın babasıyla başlar 2009&rsquo;a gelindiğinde ise Mişka&rsquo;nın babası yeni yaşamını yitirmiştir. Ne bug&uuml;n&uuml;n tarihi verilir. Ne de 1878&rsquo;den sonraya d&ouml;n&uuml;k bir tarih verilir. G&ouml;&ccedil; edenler Mişka&rsquo;nın dedesidir diye d&uuml;ş&uuml;nebilecekken piyanonun dededen değil babadan yadig&acirc;r olduğunu belirterek bizi yeniden belirsizliğe iter Mişka. Tabii bu &ldquo;baba&rdquo; tabiri &ldquo;ata&rdquo; anlamına gelmiyorsa. Yani ancak seyircinin eşelemeleriyle ulaşabileceği bir nokta oluyor zaman konusu. Bu konu daha net bir bi&ccedil;imde aktarılabilinirdi kuşkusuz. Ancak her şeye rağmen&nbsp;<b>Murat Sara&ccedil;oğlu</b>&rsquo;nun ellerine sağlık. &Ccedil;ok hoş, insanın i&ccedil;ini ısıtan sımsıcak bir film olmuş. Film bittiğinde insanın y&uuml;z&uuml;nde b&uuml;y&uuml;cek bir tebess&uuml;m kalıyor&hellip; sarmaşık misali h&uuml;zne dolanmış.</span></span></p>', 191, 63, 'Yazarlarımızdan', '/images/yazilar/deli%20deli%20olma1.JPG', '2017-03-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (50, 'ay-j171', 'lean-e-bir-gecit-david-lean', 'Lean\'e Bir Geçit - David Lean', 'Nagihan Konukcu', '<h2 style="font-size: 20px; margin-top: 0px; margin-bottom: 0px; line-height: normal; color: #9a1212; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 15pt;">Lean\'e Bir Ge&ccedil;it - David Lean (1908-1991)</span></h2>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Nagihan Konukcu</b></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b><i>&ldquo;Sinema, dramatize edilmiş bir ger&ccedil;ekliktir ve y&ouml;netmenin işi onun ger&ccedil;ekmiş gibi g&ouml;r&uuml;nmesini sağlamaktır... Seyirci kullanılan y&ouml;ntemin farkına varmamalıdır.&rdquo;</i></b></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b><i>&ldquo;Benim ayrıksı yeteneğim, insanları mikroskop altına yatırmak, belki diğer bazı y&ouml;netmenlerden bir iki katman daha derine inebilmek.&rdquo;</i></b></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b><span style="font-size: x-large;">L</span><span style="font-size: 10pt;">ean</span></b><span style="font-size: 10pt;">&nbsp;onu yola/yoldan &ccedil;ıkaran tutkusunu, bir dizi belirlenmiş ama&ccedil; ve beklentiler yoluyla kısır kılınan sinemanın tekinsizliğine bulaştırmadan kendi yolunu &ccedil;izmeyi başarmış bir idealisttir. End&uuml;strinin &ouml;n&uuml;ne konan &ldquo;&uuml;r&uuml;n&rdquo;&uuml;, yaratım s&uuml;recini g&ouml;zetmeksizin bir yandan ekonomik sonu&ccedil;ları, diğer yandan da sağladığı estetik tatmin ile sınadığı bir d&ouml;nemde, hareketli g&ouml;r&uuml;nt&uuml;lerin bu kısa tarihinde kendi yaşam alanını yaratmış ve &ccedil;ok az y&ouml;netmenin boy &ouml;l&ccedil;&uuml;şebildiği bir başarı yakalamıştır.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">25 Mart 1908&rsquo;de İngiltere Croydon&rsquo;da d&uuml;nyaya gelen&nbsp;<b>Lean</b>, sinemayla ilgilenmesine şiddetle karşı &ccedil;ıkan, Kuveykır &ouml;ğretisine sıkı sıkıya bağlı bir anne ile kendi mesleğini s&uuml;rd&uuml;rmesi beklentisi i&ccedil;indeki muhasebeci bir babanın &ccedil;ocuğudur. İ&ccedil;ine doğduğu &ouml;ğretinin ve filmlerin yasaklardan nasibini aldığı bir d&ouml;nemin her t&uuml;rl&uuml; alıkoyuculuğuna rağmen &ccedil;evresinde olan bitene karşı duyduğu ilgiden ve tutkudan, babasının g&uuml;nah, zaman ve para kaybı olarak nitelediği sinemaya gitme keyfinden asla vazge&ccedil;mez. Kariyerinin b&uuml;y&uuml;k b&ouml;l&uuml;m&uuml;nde &ouml;zel yaşamına dair ayrıntılar konusunda gardını d&uuml;ş&uuml;rmez, nadiren &uuml;zerine s&ouml;z s&ouml;ylemeye ikna olduğunda da, sinema salonlarının sessizliğinde doğan tutkusunun &ouml;yk&uuml;s&uuml;n&uuml;, filmleri &uuml;zerinden &ouml;zg&uuml;r bırakır...</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/lean%207.jpg" alt="" width="449" height="304" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">1920&rsquo;li yıllarda Gaumont-British Picture Corporation&rsquo;ın Lime Grove St&uuml;dyoları&rsquo;nda klaket&ccedil;i olarak &ccedil;alışır bir s&uuml;re; sesli film d&ouml;nemiyle birlikte de edit&ouml;rl&uuml;k g&uuml;nleri başlar. Sinemaya kelimenin ger&ccedil;ek anlamıyla teknik bir adam olarak adım atan&nbsp;<b>Lean</b>, bir s&uuml;re yardımcılığını yaptığı&nbsp;<b>Anthony Asquith</b>&rsquo;in gerek kurgusal gerekse anlatısal deneyimlerinden de yararlanma fırsatı bulur.&nbsp;<b>Asquith</b>&rsquo;in belgesele yakın duran sinematik eğilimleri ve hemen her yapıtında kendini hissettiren duyarlıklı ve dolaysız anlatımı,&nbsp;<b>Lean</b>&rsquo;in y&ouml;netmenlik kimliğinde, sınırlarını genişleterek yolunu bulacak stiline esin kaynağı olur ş&uuml;phesiz. 1933 yılında&nbsp;<b>Bernard Vorhaus</b>&rsquo;un&nbsp;<i><b>Money for Speed</b></i>&nbsp;ve&nbsp;<i><b>The Ghost Camera</b></i>&nbsp;filmlerinin de aralarında olduğu d&uuml;ş&uuml;k b&uuml;t&ccedil;eli bazı yapımların edit&ouml;rl&uuml;ğ&uuml;n&uuml; yapar &ouml;nce. 1936&rsquo;da&nbsp;<b>Paul Czinner</b>&rsquo;in&nbsp;<b><i>As You Like It&nbsp;</i></b>&nbsp;filminin ve 1938 yılında,&nbsp;<b>Bernard Shaw&rsquo;</b>ın o d&ouml;nem &ccedil;ığır a&ccedil;an&nbsp;<i><b>Pygmalion&rsquo;</b></i>unun sinema versiyonunun edit&ouml;rl&uuml;ğ&uuml;n&uuml; yaptıktan sonra, bir diğer başarılı&nbsp;<b>Shaw</b>&nbsp;uyarlaması olan 1941 yapımı&nbsp;<b><i>Major Barbara</i></b>&nbsp;filminin edit&ouml;rl&uuml;ğ&uuml; ve yardımcı y&ouml;netmenliğini &uuml;stlenir. Kimilerince katı ve zorlayıcı bulunan tekniğinin onu adeta bir efsane haline getirecek olan ilk &lsquo;ger&ccedil;ek&rsquo; halkası&nbsp;<b>Noel Coward</b>&nbsp;ile birlikte &ccedil;alıştığı 1942 yapımı, bir propaganda filmi olan&nbsp;<b><i>Denizler Hakimi&nbsp;</i></b>(In Which We Serve, 1942) olur. Senaryosunu&nbsp;<b>Coward</b>&rsquo;ın yazdığı filmde, İkinci D&uuml;nya Savaşı&rsquo;nda batırılan İngiliz Kraliyet donanmasına bağlı Torrin savaş gemisindeki personelin kurtarılmayı ve hatta &ouml;lmeyi bekleyişi konu edilir. Savaş yıllarında sinema d&uuml;nyasının yaşadığı durgunluğu, &ccedil;oklukla savaşı değişik y&ouml;nleriyle yansıtmayı ve cephedekilere moral vermeyi ama&ccedil;layan filmlerle aşmaya &ccedil;alıştığı ezberi burada da bozulmamakla birlikte, film sorularını sor(dur)maktan geri durmaz. Karakterlerine flashbacklerle olaydan &ouml;nceki yaşamlarını, ailelerini ve en &ouml;nemlisi &lsquo;kim i&ccedil;in ve neden savaştıklarını&rsquo; anımsatarak, savaşın nedenleri ve sonu&ccedil;larına dair s&ouml;yleminin kapılarını aralık bırakır. Aynı d&uuml;sturu, 15 yıl sonra&nbsp;<b>Lean</b>,&nbsp;<i><b>Kwai K&ouml;pr&uuml;s&uuml;</b></i>\'nde (The Bridge on the River Kwai, 1957) yineleyecektir; sadece savaşın temsili &lsquo;yıkılacak&rsquo; bir k&ouml;pr&uuml; olacaktır bu defa.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Filmin getirdiği başarının ardından&nbsp;<b>Coward</b>&nbsp;ve&nbsp;<b>Lean</b>, filmin yapımcısı&nbsp;<b>Anthony Havelock-Allan</b>&nbsp;ve g&ouml;r&uuml;nt&uuml; y&ouml;netmeni&nbsp;<b>Ronald Neame</b>&nbsp;ile biraraya gelerek&nbsp;<b><i>Cineguild</i></b>&nbsp;yapım şirketini kurarlar. İlk &uuml;&ccedil; işleri de&nbsp;<b>Coward</b>&nbsp;oyunlarının uyarlamaları olur. Diyalog ustası&nbsp;<b>Coward</b>&nbsp;ve teknik ve g&ouml;rsel dehasıyla&nbsp;<b>Lean</b>, ilk &uuml;r&uuml;nleri&nbsp;<b><i>Mutlu Kuşak</i></b>&rsquo;ta (This Happy Breed, 1944) iki d&uuml;nya savaşıarasındaki s&uuml;re&ccedil;te alt-orta sınıf Gibbons ailesinin yaşantısı &uuml;zerinden, stoacılığı, İngiliz insanının tabiatını ve zorlukları yenme g&uuml;c&uuml;n&uuml; betimler. Thames Nehri&rsquo;nin kuşbakışı g&ouml;r&uuml;n&uuml;m&uuml; ile başlayan ve Gibbons<b>&rsquo;</b>ların evinin &ouml;n kapısını dolaşan a&ccedil;ılış sekansı&nbsp;<b>Lean</b>&rsquo;in bu ilk solo y&ouml;netmenlik &ccedil;alışmasında sinematografik başarısını kutsar adeta. Hemen bir yıl sonra gelen<i>&nbsp;<b>Ben &Ccedil;ağırmadım</b></i>&nbsp;(Blithe Spirit, 1945)&nbsp;<b>Lean</b>&rsquo;in İngiliz usul&uuml; g&uuml;ld&uuml;r&uuml;de deneme alanı olur kendisini.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: center;"><span style="font-size: 10pt;"><b><img src="/images/yazilar/lean.jpg" alt="" width="375" height="454" border="0" /></b></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Cineguild&rsquo;in &uuml;&ccedil;&uuml;nc&uuml; yapımı ve fakat diğerlerinden farklı bi&ccedil;imde klasik bir romantik dram olan&nbsp;<i><b>Kısa Rastlantı</b></i>&nbsp;(Brief Encounter, 1945) haftalık rutinleri i&ccedil;inde rastlantısal olarak bir tren istasyonunun kafeteryasında tanışan ve bir s&uuml;re sonra kendilerini &lsquo;yasak&rsquo; bir ilişkinin kucağına bırakan evli bir kadın ve erkeğin romansına tanıklık eder. D&uuml;zen ve bireyselliğin orta yerinde, İngilizlerin, alışılmışın da &ouml;tesinde gizlilikleri, suskunlukları ve romantik aşırılıkları arasındaki &ccedil;atışmayla yolunu &ccedil;izen film, sınırlı &ndash; iki savaş arası- bir d&ouml;nemin moral d&uuml;nyasını yansıtmak konusunda yine o d&ouml;nemin i&ccedil;inde taşıdığı kaygıların engeline takılır. Bu aşkı imkansız kılan/varsayan, kendilerini &ccedil;evreleyen mekan ve zamanın dışında, kadın ve erkeğin en sıradan tutkularını bile bastırmış olmalarından ileri gelen yaşamsal pratikleri ve deneyimlenmemiş olanın imkansızmış gibiliğidir oysaki.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lean</b>&nbsp;bu defa, zaman zaman uzlaşı alanlarını zorladıkları, buna rağmen uzun soluklu bir birliktelikle yola devam edecekleri oyuncu&nbsp;<b>Alec Guinness</b>&rsquo;in işbirliğinde,&nbsp;<b>Charles Dickens</b>&nbsp;uyarlamalarına d&ouml;ner y&uuml;z&uuml;n&uuml;. &Ouml;nc&uuml;llerinin, klasiklerin beyaz perdeye uyarlanmalarındaki t&uuml;rl&uuml; zorlukları kotarmak konusunda karşı karşıya kaldıkları eleştirileri ve &ouml;nyargıları kırmayı başarır.&nbsp;<b><i>B&uuml;y&uuml;k Umutlar</i></b>&rsquo;da (Great Expectations, 1946) insanın duyarlılığı ve bunun g&ouml;rsel sunumunun g&ouml;rkemi arasındaki kusursuz denge&nbsp;<b><i>Oliver Twist</i></b>&rsquo;e (1948) oranla daha derinliklidir. Dickensvari atmosferin g&ouml;rsel kodlarla yeniden yaratımında, masalsı bir anlatının s&uuml;zgecinden ge&ccedil;irilmiş sosyal ger&ccedil;eklik dokusunun, karakterleri sarmalayan karanlığın perdesini aralamakta &ccedil;aresiz kalmamak adına romanın toplumsal eleştirisinden &ccedil;ok trajedi kısmına g&ouml;rece ağırlık verilir.<b><i>&nbsp;Oliver Twist&nbsp;</i></b>ise y&ouml;netmenin olgunluk d&ouml;nemini imler. &Ccedil;izdiği basit ger&ccedil;eklikle g&uuml;tt&uuml;ğ&uuml; ama&ccedil;, filmin anlatısal yapısını kurmakta başvurduğu kompleks dekorların yarattığı ironiye karşın yine de nesnel olmaktır. Nesnesi ile alıcısının arasına koyduğu mesafe ve a&ccedil;ılar yoluyla g&ouml;r&uuml;nt&uuml;n&uuml;n maddi ger&ccedil;ekliğine eklemlediği duygusal ve karakteristik ger&ccedil;eklik, fiziksel bir varetme bi&ccedil;imi değildir; dramatik, ciddi, g&uuml;l&uuml;n&ccedil; ya da nitelikli anlamların hepsinin bir aradalığıdır sadece. Her iki yapım da&nbsp;<b>Dickens</b>&nbsp;romanlarının g&uuml;l&uuml;n&ccedil;, acımasız ve vahşi doğasını yansıtır.<i></i></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; padding: 5px 10px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/lean%202.jpg" alt="" width="346" height="397" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">50&rsquo;li yıllar&nbsp;<b>Lean&rsquo;</b>in filmografisi i&ccedil;inde, g&ouml;rece az bilinen ancak kariyerinde d&ouml;n&uuml;m noktaları olmuş yapımların d&ouml;nemidir. Cineguild i&ccedil;in yaptığı son iki film&nbsp;&nbsp;<b><i>Seven Kalpler</i></b>&nbsp;(The Passionate Friends, 1949) ve&nbsp;<i><b>H&uuml;k&uuml;m G&uuml;n&uuml;&nbsp;</b></i>(Madeleine, 1950) teknik olarak ayakları yere sağlam basan filmler olmakla birlikte, genelde y&ouml;netmenin kişisel bakış a&ccedil;ısından, &ouml;zelde de erken d&ouml;nem &ccedil;alışmalarının duygusal yoğunluğundan yoksun olmakla eleştirilir. Cineguild<b>&rsquo;</b>in ardından&nbsp;<b>Lean&rsquo;</b>in&nbsp;<b>Alexander Korda</b>&nbsp;i&ccedil;in &ccedil;ektiği, ses duvarını ge&ccedil;en bir pilotun &ouml;yk&uuml;s&uuml;n&uuml; anlatan 1952 yapımı&nbsp;<i><b>Ses Duvarı</b></i>&nbsp;(Sound Barrier), y&ouml;netmen i&ccedil;in kariyerinin ikinci yarısının &ouml;ng&ouml;r&uuml;s&uuml; niteliğindeki destansı yapımların ilk ayağını oluşturması a&ccedil;ısından değerlidir.<b>Harold Brighouse&rsquo;</b>un bir sahne komedisinden sinemaya uyarlanan&nbsp;<b><i>Hobson&rsquo;ı</i></b><strong><i>n Se&ccedil;imi</i></strong>&nbsp;(Hobson&rsquo;s Choice, 1954) Lean ve daha sonrasında beş filmde daha birlikte &ccedil;alışacakları, oyuncu&nbsp;<b>John Mills</b>&rsquo;i yeniden biraraya getirir. 1955 yapımı&nbsp;<i><b>Venedik Tatili&nbsp;</b></i>(Summertime)&nbsp;<b>Katherine Hepburn</b>&rsquo;&uuml;n yıldızı altında&nbsp;<b>United Artists</b>&rsquo;in ortak yapımcılığında ve&nbsp;<b>Lean</b>&rsquo;e artık st&uuml;dyo bağımlı &ccedil;alışma bi&ccedil;imini terketmesi y&ouml;n&uuml;nde ciddi bir karar aldırır.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">D&uuml;nyanın politik ve sosyal tarihi gibi&nbsp;<b>Lean</b>&rsquo;in de yaratım s&uuml;recinde bir sı&ccedil;rama eşiği ka&ccedil;ınılmazdır artık. İnsanın tarihsel, politik ve sosyo-k&uuml;lt&uuml;rel ortam ile ilişkilenmesinde &ouml;yk&uuml;s&uuml;n&uuml; ve g&ouml;rsel &ccedil;er&ccedil;evesini, dışardan i&ccedil;eri yapılandırır&nbsp;<b>Lean</b>; yani toplumsal ve tarihsel alandan, insanın kendi &ouml;z yaşam pratiğine ve kırılmaz d&ouml;ng&uuml;s&uuml; i&ccedil;indeki varoluşsal savaşımına doğru. Nihayetinde&nbsp;<b>Lean</b>&rsquo;in karakterleri de d&uuml;nyayı kendi beklentileri doğrultusunda değiştirmenin peşine d&uuml;şm&uuml;ş, sıradan hayalperestler ve kahramanlardır bir bakıma. Hep direnmiş olmanın yorgunluğunu sırtlamış savaş yorgunları...</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; padding: 5px 10px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/lean%206.jpg" alt="" width="366" height="356" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">S&ouml;z konusu, &uuml;lkelerin siyasi tarihleri olunca, politik s&ouml;ylemlerini &ccedil;&uuml;r&uuml;tmek ya da doğrulamak derdi g&uuml;tmediği izlenimi/yanılsaması yaratarak, gittiği topraklarda imparatorluk sonrası İngiltere&rsquo;sinin s&ouml;zc&uuml;l&uuml;ğ&uuml; yapan&nbsp;<b>Lean</b>, filmleriyle aşağıladığı d&uuml;ş&uuml;n&uuml;len &uuml;lkelerin bile alkışlarını toplayacaktır. Hal b&ouml;yleyken epik filmler d&ouml;nemine 1957 yapımı&nbsp;<i><b>Kwai K&ouml;pr&uuml;s&uuml;</b></i>&nbsp;(The Bridge on the River Kwai) ile atar adımını. İkinci D&uuml;nya Savaşı yıllarıdır... İngiliz Albay Nicholson, birliğiyle birlikte Japonlara esir d&uuml;şer. Kwai Nehri &uuml;zerine kurulacak k&ouml;pr&uuml;n&uuml;n yapımında subayların da askerler gibi ağır koşullarda &ccedil;alıştırılmasına Cenevre S&ouml;zleşmesi&rsquo;ne dayanarak direnen albay, zaman i&ccedil;inde t&uuml;m adamları ile birlikte neredeyse g&ouml;n&uuml;ll&uuml; olarak &ccedil;alışır. A&ccedil;ılımlandığı askeri zeminde, gerek İngiliz, gerek Japon askeri y&ouml;netimlerinin ve kanunlarının dayattığı sınırlar i&ccedil;indeki aidiyet ve itaat sorunsalı &uuml;zerinden Kwai K&ouml;pr&uuml;s&uuml;, İngilizlere atfettiği yenilmezliği, Japonların sembolik olarak &ccedil;izilen varlıkları karşısında g&uuml;&ccedil;l&uuml; kılması y&ouml;n&uuml;yle, filmin gerek anlatısal kaygısı gerek karakterleri a&ccedil;ısından, inandırıcılığında &ccedil;atlaklar taşır. Nicholson&rsquo;ın, filmin ilk yarısındaki inat&ccedil;ı, dik kafalı ve cesur tavrı -ki filmin ikinci kısmında bu cesaretin anlamını sorgulamak gerekir-, ikinci yarıda neredeyse Japon komutan Saito ile olan işbirliği, Saito&rsquo;nun g&uuml;c&uuml;n&uuml; elinden alan denetimsiz &ndash;belki de fazla kontroll&uuml; bi&ccedil;imde- karakter yaratımı, filmin iki karşıt karakteri i&ccedil;in ironik bir uzlaşı alanı yaratır. İngiliz komutanın kendi inan&ccedil; ve ilkeleri doğrultusunda &uuml;lkesinin varlığını ve g&uuml;c&uuml;n&uuml; koruma m&uuml;cadelesinin ardındaki batılı refleksi, i&ccedil;inde bulunulan koşulların da itici g&uuml;c&uuml;yle zaaflar yaratarak - en iyisini yapmak, en iyi olmak- filmi psikolojik bir zemine de oturtan yapısıyla tarafların hem kendi i&ccedil;lerinde hem de birbirlerine karşı olan &ccedil;atışma ve uzlaşı alanlarını genişletir.&nbsp;<b><i>Kwai K&ouml;pr&uuml;s&uuml;</i></b>&rsquo;n&uuml;n teknik kriterleri g&ouml;z &ouml;n&uuml;nde tutulduğunda da; uzun planlar ve genel &ccedil;ekimlerin de katkısı ile mekana kazandırılan durağanlık, filmin dramatik yapısını zayıflatıyorsa da, s&ouml;zgelimi k&ouml;pr&uuml;n&uuml;n havaya u&ccedil;urulduğu sahne, y&ouml;netmenin kamerada a&ccedil;ı ve &ouml;l&ccedil;ek kullanımındaki yetkinliğinin altını &ccedil;izmekten geri durmaz ve başarısı aldığı ilk Oscar ile tescillenir.<i></i></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; padding: 5px 10px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/lean%208.jpg" alt="" width="390" height="373" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lean</b>&nbsp;bireyin tarihsel savaşımını,&nbsp;<b>Peter O\'Toole, Alec Guinness, Anthony Quinn</b>,&nbsp;<b>Jack Hawkins</b>&nbsp;ve&nbsp;<b>&Ouml;mer Şerif\'</b>in rolleriyle &ouml;zdeşleşmiş oyunculuklarında, 1962 yapımı&nbsp;<i><b>Arabistanlı Lawrence</b></i>&nbsp;(Lawrence of Arabia) ile yineleyecektir. Kendi i&ccedil;inde bir birlik ve d&uuml;zenden yoksun Arap D&uuml;nyası&rsquo;nı Osmanlı Devleti&rsquo;ne karşı ayaklanmaları i&ccedil;in kışkırtarak, İngiltere&rsquo;nin safhına katmaya &ccedil;alışan İngiliz casus Lawrence&rsquo;in kişiliğinde, milliyet&ccedil;i bir s&ouml;ylem savunucusu yaratmanın &ouml;tesinde, u&ccedil;suz bucaksız &ccedil;&ouml;llerde kimliği ve yalnızlığı ile baş başa kalan bir insanın psikolojisini aralamak derdindedir. İngilizlerin emperyalist politikalarının aracı olmak yoluyla Araplara &ouml;zg&uuml;rl&uuml;klerini kazanmaları konusunda &ouml;n ayak olan İngiliz casusu, kendi &ouml;zg&uuml;rl&uuml;ğ&uuml; konusunda ne yapabil(eme)diğiyle de y&uuml;zleştirir bir bakıma. İ&ccedil;ine d&uuml;şt&uuml;ğ&uuml; karmaşada, Lawrence&rsquo;ın bastırılmış eşcinsel motivasyonu ile cinsel kimlik kavramını da g&ouml;rece nesnel bi&ccedil;imde tırnak i&ccedil;ine alır&nbsp;<b>Lean</b>. Arapları barbar, iki y&uuml;zl&uuml; ve aşağılık ilan ettiği şeklinde filme y&ouml;nelen eleştirilere gelince; bu barbarlığı ve iki y&uuml;zl&uuml;l&uuml;ğ&uuml; tetikleme ve y&ouml;netme g&ouml;revini İngiliz casus Lawrence\'ın &uuml;stlendiği ve zaman i&ccedil;inde bir Arap gibi yaşamaya ve hissetmeye-&ouml;ld&uuml;rmenin zevkine varır &ccedil;&uuml;nk&uuml;- başladığı d&uuml;ş&uuml;n&uuml;l&uuml;rse, Araplara atfedilen k&ouml;t&uuml; maya, aslında İngilizlerin doğasına eleştiri getirmek konusunda filmin su g&ouml;t&uuml;rmez bir dramatik unsuru olarak belirmez mi?</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lean</b>&nbsp;yoluna başka bir g&ouml;rkemli yapımla devam eder:&nbsp;<i><b>Doktor Zhivago</b></i>&nbsp;(Doctor Zhivago, 1965).&nbsp;<b>Boris Pasternak</b>&rsquo;ın romanından uyarlanan film, 1917 Ekim Devrimi sonrası, h&uuml;k&uuml;metlerin d&uuml;şt&uuml;ğ&uuml;, orduların &ccedil;arpıştığı tarihsel ve politik fonunda, bir aşkın herşeye rağmen nasıl olup da dolu dizgin s&uuml;regittiğinin tanıklığında, tam da yazarının arzusuna uygun bi&ccedil;imde, daha iyi bir Rusya vizyonu yaratır. Zhivago&rsquo;nun dramı, devrim ile birlikte değerlerinin ger&ccedil;ekliği ile y&uuml;zleşmek zorunda kalan aydının portresidir; ge&ccedil;irdiği evrimi ise iki farklı sosyal sınıftan gelen karısı ve sevgilisi temsil eder.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; padding: 5px 10px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/jivago2.jpg" alt="" width="486" height="321" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Beş yıllık bir aradan sonra&nbsp;<b>Lean</b>&nbsp;<i><b>İrlandalı Kız</b></i>&nbsp;(Ryan&rsquo;s Daughter, 1970) ile &ccedil;ıkagelir. Arka planda 1916 yılında i&ccedil; savaşla sarsılan Kuzey İrlanda. Savaşın g&ouml;lgesinde İngiliz egemenliğine alaysamayla diren&ccedil; g&ouml;steren k&ouml;yl&uuml;ler, suya sabuna dokunmayan ve elindekinden fazlasını istemeyen bir k&ouml;y &ouml;ğretmeni, aidiyet sorununa bir de evliliğinde yaşadığı mutsuzluk eklenen gen&ccedil; karısı ve onun aşığı İngiliz subay. Bağımsızlık savaşı veren bir halkı &ccedil;evreleyen işgal, sivil-asker &ccedil;atışması ve ahlaki korkaklık temaları ekseninde, u&ccedil;larda seyreden karakterler filmin dramatik dozuna katkı sağlamakla birlikte, teatral bir atmosfer yaratma eğilimi de g&ouml;sterir. Belki de bu nedenle, daha kısa olmayan &ouml;nceki filmlerine g&ouml;sterilen ilgi, bu filmde yerini, aşırı uzun, yavaş ve y&ouml;netmenin seyrettiği modern sinema &ccedil;izgisinden uzak olduğu y&ouml;n&uuml;ndeki eleştirilere bırakır.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lean</b>, bu eleştirileri &ccedil;ok ciddiye almış olacak ki on d&ouml;rt yıl boyunca film yapmaz. 1984 yılında&nbsp;<b>E. M. Forster</b>\'ın kitabının uyarlaması olan&nbsp;<i><b>Hindistan\'a Bir Ge&ccedil;it</b></i>&nbsp;(A Passage to India) ile iddialı bir d&ouml;n&uuml;ş yapar. Birinci D&uuml;nya Savaşı&rsquo;nın ardından, Hindistan&rsquo;da yargı&ccedil;lık yapan oğlunu ziyarete giden Bayan Moore ve ona eşlik eden oğlunun nişanlısı Adela burnu havada İngiliz y&ouml;neticilerden farklı davranmak, tabuları yıkmak niyetindedirler. Gen&ccedil; Doktor Aziz bu iyi niyete karşılık verir ve&nbsp; Marabar Mağaraları\'na bir gezi d&uuml;zenler ancak burada beklenmedik olaylar meydana gelir ve iki ırk arasındaki d&uuml;şmanlık had safhaya ulaşır. Aziz\'in İngilizleri anlama &ccedil;abası uğradığı tecav&uuml;z su&ccedil;laması ile yerini hayal kırıklığına bırakır. Hintlilere karşı İngiltere y&ouml;netimindeki Hindistan\'ı, iki farklı k&uuml;lt&uuml;re ait insanların yakınlaşma &ccedil;abalarını engelleyen &ouml;nyargıları ve yanlış anlamaları &uuml;zerinde doğu-batı sorunsalını a&ccedil;ılımlayan film, Hindistan&rsquo;ın mistik karmaşası i&ccedil;inde, Hintlilerin saflıklarını ve dar g&ouml;r&uuml;şl&uuml;l&uuml;klerini iyimser bir tavırla sunarken, İngilizlerin kendini beğenmişliklerini ve nezaketsizliklerini alaya alır. Doğulu ve batılı stereotiplerinin &uuml;zerine kurulu karakterleriyle film, iki ırk arasında emperyalizm, ırk&ccedil;ılık ve &ouml;nyargılar ekseninde alanını genişletirken &ouml;tekilik kavramını da sorgular. Filmin, Hintlilerin ulusal kimlikleri nedeniyle maruz kaldıkları ayrımcılığın, beraberinde diğer &ouml;tekilikler &ndash;k&uuml;lt&uuml;rel, t&ouml;resel, ekonomik ve politik- konusunda da bir farkındalık kazandırdığı rahatlıkla s&ouml;ylenebilir. İngilizlerin Hintlilerle aralarındaki yaşamsal kaygılar, ahlaki koşullanmalar, geleneksel kodlar ve insani tutumlar bakımından ayrıksı duruşlarını kırmaya y&ouml;nelik girişimler İngiltere&rsquo;den Hindistan&rsquo;a bir ge&ccedil;it sağlamak konusunda ne kadar başarılı olabilmiştir? Akademinin filme bahşettiği iki &ouml;d&uuml;l kadar mı?</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/a%20passage%20to%20india.jpg" alt="" width="430" height="338" border="0" /></span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lean</b>&rsquo;in t&uuml;m filmografisi i&ccedil;inde, g&ouml;r&uuml;nt&uuml;lerin ve arketiplerin, &ouml;yk&uuml;y&uuml; aktarmak ve belirli bir duygu ve bakış a&ccedil;ısını iletmekteki başarısından hareketle tutarlı bir stil ve d&uuml;nya g&ouml;r&uuml;s&uuml; taşıdığı bilgisine de sahip oluruz. İnsanların ilgilendikleri şeyin diyalog değil g&ouml;r&uuml;nt&uuml;ler olduğu savından yola &ccedil;ıkan&nbsp;<b>Lean</b>, &ouml;yk&uuml;lerini ve karakterlerini g&ouml;r&uuml;nt&uuml;lerle ifşa eder. Karakterlerinin en b&uuml;y&uuml;k kusuru ise, a&ccedil;ık&ccedil;a ortada duran herhangi bir veriyi, bir davranışı bile &ccedil;&ouml;z&uuml;mlemelerine imkan bırakmayacak &ouml;l&ccedil;&uuml;de sahip oldukları ben-merkezcilikleridir.</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Kariyerine teknik adam olarak adım atan&nbsp;<b>Lean</b>, girdiği kurgu odasından, g&ouml;rkemli filmlerin y&ouml;netmeni olarak anılacağının &ouml;ng&ouml;r&uuml;s&uuml; ile &ccedil;ıkmış olmalıydı ki,&nbsp; m&uuml;kemmeliyet&ccedil;iliğini takıntı olarak niteleyenlerin s&ouml;zlerini boşa &ccedil;ıkaracaktı filmografisi boyunca. Yaşamı da, g&ouml;rkemli sahneleri kadar kalabalık mıydı bilinmez ama ortaya &ccedil;ıkacak şeyden &ccedil;ok s&uuml;rece kafayı takışı, zihninin kalabalıklığını onayan bir yanıttı kuşkusuz. Dışardaki hayatta uzlaştırıcı ve al&ccedil;ak g&ouml;n&uuml;ll&uuml; kişiliğiyle bilinen<b>Lean</b>, filmleri s&ouml;z konusu olduğunda son derece k&uuml;stah ve c&uuml;retkar bir adam oluveriyordu. 1991\'de zat&uuml;rreden &ouml;ld&uuml;ğ&uuml;nde&nbsp;<b>Joseph Conrad</b>&nbsp;uyarlaması&nbsp;<b><i>Nostromo</i></b>\'yu &ccedil;ekmeye hazırlanıyordu. Yazık ki, yıllar boyu attığı b&uuml;y&uuml;k ama tedbirli adımlarına birini daha eklemeye soluğu yetmemişti...</span></p>\r\n<p style="margin-bottom: 0px; line-height: 1.71429; font-size: 11px; color: #564b47; padding: 5px 10px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 10pt;"><b>Filmografi:</b></span></p>\r\n<div style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; margin-left: 60px; text-align: center;">\r\n<table border="0" style="border-style: solid; width: 411.2px; margin-left: 90px;">\r\n<tbody>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1984&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; A Passage to India</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1979&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Lost and Found: The Story of Cook\'s Anchor</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1970&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; Ryan\'s Daughter</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1965&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Doctor Zhivago</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1962&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; Lawrence of Arabia</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1957&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; The Bridge on the River Kwai</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1955&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; Summertime</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1954&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Hobson\'s Choice</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1952&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; The Sound Barrier</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1950&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Madeleine</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1949&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; The Passionate Friends</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1948&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Oliver Twist</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1946&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; Great Expectations</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1945&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; Brief Encounter&nbsp;</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1945&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; Blithe Spirit</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp;1944&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;"><span style="font-size: 10pt;">&nbsp; This Happy Breed</span></td>\r\n</tr>\r\n<tr>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp;1942&nbsp;</span></td>\r\n<td style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; margin: 8px;" bgcolor="#e1ddd9"><span style="font-size: 10pt;">&nbsp; In Which We Serve</span></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 70, 63, 'Yazarlarımızdan', '/images/yazilar/lean%207.jpg', '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (51, 'ay-j172', 'gunumuz-belgeseli-uzerine-bir-sorusturma', 'Günümüz Belgeseli Üzerine Bir Soruşturma', 'Ece Özdemir', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">G&uuml;n&uuml;m&uuml;z Belgeseli &Uuml;zerine Bir Soruşturma</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Ece &Ouml;zdemir</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 11pt;"></span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 11pt;">&ldquo; Bu bir meydan okumadır; sinemacının tutkusu ve &ouml;yk&uuml;s&uuml;ne g&uuml;venmesiyle aşılan bir meydan okumadır.&ldquo; (B. Kopple)</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 11pt;"></span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><i><span style="font-size: 11pt;">&ldquo; D&uuml;nyanın Doğusunun ve G&uuml;neyinin hikayeleri giderek Batılı ve Kuzeyli bir hal alıp yeknesaklaşıyorlar&hellip;&ldquo;&nbsp; (E. Ocak)</span></i></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: 11pt;"></span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b>&nbsp;<span>1) 21. y&uuml;zyılda belgesel filmdeki ana y&ouml;nelimler nelerdir?</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><i><span>&nbsp;</span></i></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Tolga &Ouml;rnek:</span>&nbsp;</b><span>Belgesel son altı-yedi senede eskisine kıyasla politik konulara odaklanmış durumda. Eskiden daha sık&ccedil;a g&ouml;rebildiğimiz klasik anlatım tarzındaki tarihi belgeseller ve biyografilerin sayısı azaldı. Seyirciye en rahat ulaşan ve uluslararası platformlarda ilgi g&ouml;ren filmler &ccedil;evre, insan hakları ve devletlerin b&uuml;y&uuml;k global şirketlerle ilişkilerini anlatan&nbsp; belgeseller oluyor. Bu i&ccedil;erikteki y&ouml;nelim. Tarz olarak bakıldığındaysa, kameraların k&uuml;&ccedil;&uuml;lmesiyle daha cesurlaşan, daha hareketli ve i&ccedil;eriği prod&uuml;ksiyon değerinin &ouml;n&uuml;nde tutan belgesellerin arttığını s&ouml;yleyebiliriz. Y&uuml;ksek prod&uuml;ksiyon değerine sahip tarihi ve doğa belgeselleriyse artık sadece ZDF, BBC, PBS ve &nbsp;KANAL+ tarafından yapılıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Laila Pakalnina:</span>&nbsp;</b><span>Belgesel filmi &lsquo;belgesel&rsquo; ve &lsquo;film&rsquo; yapan şey ger&ccedil;eklikte doğmuş imgedir. Aslında bu ge&ccedil;miş y&uuml;zyıldakiyle hemen hemen aynı. Fark şu; şu anda belgesel filmin etrafında daha &ouml;nce olduğundan &ccedil;ok daha fazla sınır var. Belgesel film alanının etrafı televizyon yayını, kurgu, ev veya cep telefonu videosu ve bilgisayar animasyonuyla &ccedil;evrelenmiş durumda. Ama ana y&ouml;nelim bu sınırların bir veya daha fazlasına dahil olmak.&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/Laila_darbavietasFons.jpg" alt="" width="483" height="332" border="0" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: center;"><span style="font-size: 10pt;">Laila Pakalnina</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span><br />Necati S&ouml;nmez:</span>&nbsp;</b><span>Bunun tesbitini yapmak i&ccedil;in belki hen&uuml;z erken ama genel anlamda ve benim takip edebildiğim kadarıyla belgesel alanında; sosyopolitik konulara daha &ccedil;ok eğilen, bir anlamda medya manip&uuml;lasyonlarının yarattığı devasa boşluğu doldurmaya başlayan ve aynı nedenle azımsanmayacak bir ilgiye de mazhar olan filmler &ouml;ne &ccedil;ıktı son 10 yılda. D&uuml;nyanın giderek daha kaotik bir yer haline gelmesine paralel olarak, yine son d&ouml;nem belgesellerinde muhalif bir damarın ağırlık kazandığını s&ouml;ylemek m&uuml;mk&uuml;n. Bir yandan da, gazetecilik işinin sinemadaki uzantısı gibi duran g&uuml;ndemdeki sıcak meselelerle ilgili filmlerin azımsanmayacak bir alt t&uuml;r oluşturduğunu s&ouml;yleyebiliriz.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filistin-İsrail sorunu &uuml;zerine yapılan ya da daha hen&uuml;z savaş devam ederken, Irak işgali &uuml;zerine yapılan ve anında festivallerde/televizyonlarda seyirciye ulaşan onca filmi d&uuml;ş&uuml;n&uuml;n. &Ouml;te yandan, savaş g&ouml;r&uuml;nt&uuml;lerinin ve basında &ccedil;ıkan haberlerin ABD&rsquo;nin Vietnam&rsquo;dan &ccedil;ekilmesindeki etkisine karşılık, Irak&rsquo;tan gelen onca g&ouml;r&uuml;nt&uuml;n&uuml;n neden benzer bir etkiyi yaratamadığı &uuml;zerine d&uuml;ş&uuml;nmek de ilgin&ccedil; olabilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Belgesel sinemadaki genel durum konusunda lafımı kısa kesip, bu soruya yanıt olarak&nbsp;<i>Sight &amp; Sound</i>&nbsp;dergisinin belgesele &ouml;zel bir b&ouml;l&uuml;m ayrılan Eyl&uuml;l 2007 tarihli sayısındaki ufuk a&ccedil;ıcı yazıları &ouml;nerebilirim.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/NSonmez.jpg" alt="" width="427" height="281" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">Necati S&ouml;nmez</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Lucia Rikaki:</span>&nbsp;</b><span>Y&ouml;netmenler sosyal ve politik bazlı konulara y&ouml;nelmeye başladı. B&ouml;ylece yapıtlarında bug&uuml;n&uuml;n toplumunun kaygılarını yansıtıyorlar.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/Lucia%20Rikaki.jpg" alt="" width="351" height="367" border="0" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: center;"><span style="font-size: 10pt;">Lucia Rikaki</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Uğur Kutay:</span>&nbsp;</b><span>Belgesel sinemanın yeni y&uuml;zyıldaki temel objesi, tek bir s&ouml;zc&uuml;kle ifade etmek gerekirse &lsquo;insan&rsquo;dır. Daha &ouml;nce de insana dair belgeseller yapılıyordu tabii, ama gerek d&uuml;nyada gerekse T&uuml;rkiye&rsquo;de &uuml;retilmiş filmlere baktığınızda, doğrudan insan hikayeleri anlatan filmler yerine arkeolojik bulgulara ve doğal yaşama dair filmlerin &ccedil;oğunlukta olduğunu g&ouml;r&uuml;rs&uuml;n&uuml;z. Bunu k&ouml;t&uuml; bir şey olarak nitelemiyorum, i&ccedil;inden &ccedil;ıkıp geldiğimiz halde bilincinde olmadığımız tarihsel yapının ya da etrafımızı kuşattığı halde farkına varmadığımız &ndash;ya da olumsuz anlamda vardığımız!- doğanın filmlerle izleyiciye ulaştırılması tabii ki iyi bir şeydir. Fakat &ouml;yle bir hale geldi ki, belgesel dendiğinde insanların aklına sadece aslanın ceylanı nasıl yediği ya da &ouml;rneğin İznik &ccedil;inileri geliyor. Bu sadece izleyici i&ccedil;in değil, ne yazık ki belgesel &uuml;rettiğini s&ouml;yleyen bir &ccedil;ok kişi ve kuruluş i&ccedil;in de ge&ccedil;erli... K&uuml;lt&uuml;r Bakanlığı Sinema Destekleme Kurulu&rsquo;nda &uuml;ye olarak g&ouml;rev yaptığım iki yıl boyunca -2005/2006 d&ouml;nemi- y&uuml;zlerce belgesel film projesi okudum; bunların ne yazık ki en az y&uuml;zde 95&rsquo;i, daha &ouml;nce defalarca filme alınmış konulara dair &ouml;zelliksiz ve &ouml;l&uuml; projelerdi: Şu kentin tarih&ccedil;esi, şuradaki kale duvarları, şuradaki bakır el iş&ccedil;iliği, şuradaki taş işleme sanatı... &Ouml;zelliksiz; &ccedil;&uuml;nk&uuml; zaten suyunun suyu &ccedil;ıkarılmış ve TRT başta olmak &uuml;zere bir &ccedil;ok yerde defalarca yayınlanmış filmlerden hi&ccedil;bir farkı yoktu. &Ouml;l&uuml;; &ccedil;&uuml;nk&uuml; bu projelerin ortak y&ouml;n&uuml;, yaşayan insanı kadraj dışı bırakmalarıydı. İnsana yer veriyormuş gibi g&ouml;r&uuml;nenleriyse, ancak &ouml;l&uuml; insanların hayat hikayelerinin anlatıldığı bilgisel film projeleriydi. İşte bu, bitiyor artık. D&uuml;nyada &ccedil;oktan bitmişti. Uluslararası belgesel film festivallerinde bu t&uuml;r filmler g&ouml;remezsiniz; hatta&nbsp; National Geographic ya da Discovery gibi kanallarda bile b&ouml;yle şeyler izleyemezsiniz. Bunları ancak T&uuml;rkiye gibi &uuml;lkelerde ve TRT gibi kanallarda g&ouml;rebilirsiniz. Belgesel sinema artık tam da sokaktaki haliyle ve tam da yaşadığı gibi insan hikayeleri anlatıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/ugur%20kutay.jpg" alt="" width="434" height="288" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">Uğur Kutay</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span><br />Destekleme kurulundan &uuml;&ccedil; kuruş para alabilmek i&ccedil;in s&uuml;rekli ısıtılıp g&uuml;ndeme getirilen k&ouml;hnemiş belgesel anlayışını da aslında &ccedil;ok &ouml;nemsememek lazım &ccedil;&uuml;nk&uuml; T&uuml;rkiyeli belgeselciler artık son derece sıradan, i&ccedil;imizden, bizden insanların hikayelerini filmleştirmeye başladı bile... &Ouml;rnek vermek gerekirse,&nbsp;<b>Belmin S&ouml;ylemez&nbsp;</b>muhteşem filmi&nbsp;<b><i>Bıyık</i></b>&rsquo;ta T&uuml;rkiye&rsquo;deki bıyık k&uuml;lt&uuml;r&uuml;n&uuml;, dolayısıyla erkeklik k&uuml;lt&uuml;n&uuml; m&uuml;thiş bir mizah duygusuyla ve neredeyse bir k&uuml;lt&uuml;rel antropoloji &ccedil;alışması titizliğiyle ele alıyordu.&nbsp;<b>Bing&ouml;l Elmas</b>&nbsp;harikulade filmi&nbsp;<b><i>Ağustos Karıncası</i></b>&rsquo;nda, sırf&nbsp;<b>Timur Sel&ccedil;uk</b>&rsquo;tan piyano dersleri alabilmek i&ccedil;in bir &ccedil;ok işte &ccedil;alışan belediye iş&ccedil;isi İbo&rsquo;nun sıradışı hikayesini başarılı bir sinema estetiğiyle anlatıyordu.&nbsp;<b>Emel &Ccedil;elebi</b>&nbsp;ve&nbsp;<b>Necati S&ouml;nmez</b>&nbsp;son derece sade ve g&uuml;zel filmleri&nbsp;<b><i>G&uuml;ndelik&ccedil;i</i></b>&rsquo;de temizlik&ccedil;i kadınların d&uuml;nyasını tam da o d&uuml;nyanın i&ccedil;inden g&ouml;rmeye &ccedil;alışıyordu.&nbsp;<b>Doğa Kılcıoğlu</b>&nbsp;<b><i>&Uuml;&ccedil; Kulaklı</i></b>&nbsp;adlı inanılmaz derecede incelikli filminde g&ouml;zleri g&ouml;rmeyen bir &ccedil;iftin g&ouml;rebilen &ccedil;ocuklarıyla ilişkisine tanıklık ediyordu. Bu saydığım filmlerden&nbsp;<b><i>&Uuml;&ccedil; Kulaklı</i></b>,&nbsp;<b><i>Ağustos Karıncası</i></b>&nbsp;ve&nbsp;<b><i>G&uuml;ndelik&ccedil;i</i></b>&rsquo;nin son &uuml;&ccedil; sene Altın Portakal&rsquo;la &ouml;d&uuml;llendirilmesi de T&uuml;rkiye&rsquo;de belgeselin yeni y&ouml;nlenişi konusunda bir g&ouml;sterge olarak tanımlanabilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Barbara Kopple:</span>&nbsp;</b><span>Bence 21. y&uuml;zyıl belgesel filmlerde yeni bir d&ouml;nemi m&uuml;jdeliyor. İnsanların d&uuml;nya &ccedil;apında karşılaştıkları &ouml;l&uuml;m kalım meselesi haline gelmiş siyasi konular ile kamera ve dijital kurgu alanındaki yeni teknolojilerin birleşmesi dijital filmin gelişmesine olanak sağladı. İnsanlar karmaşık sorulara cevap ararken diğerleriyle ortak bir anlayış geliştirmek istiyorlar ve belgeseller de bu meydan okumadaki talebi karşılayacak g&uuml;&ccedil;te olduklarını g&ouml;sterdiler. ABD&rsquo;de giderek daha fazla sayıda belgeselin Hollywood filmleriyle yan yana g&ouml;sterime girdiğini g&ouml;r&uuml;yoruz. Belgesel y&ouml;netmenleri de, belgeselleri bir adım daha yukarıya taşıdıklarına ger&ccedil;ekten inandığım bir şekilde daha fazla risk alıyor ve yaratıcılıklarını kam&ccedil;ılıyorlar. Bir belgesel y&ouml;netmeni ya da belgesel film hayranı olmak i&ccedil;in &ccedil;ok heyecan verici bir d&ouml;nem.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><img src="/images/yazilar/Barbara-Kopple-Photo.jpg" alt="" width="355" height="440" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;">Barbara Kopple</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span><br />Ersan Ocak:</span>&nbsp;</b><span>20. y&uuml;zyıl sonundan başlayarak, 21. y&uuml;zyılda belgesel sinema birka&ccedil; yeni eğilimi bir arada g&ouml;stererek kendini yeniden yapılandırmaya girişir. Bu yeniden yapılanmanın başat eğilimleri ş&ouml;yle sıralanabilir:</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Belgesel sinema konularını iyiden iyiye genişletir ve hemen her konu &uuml;zerine belgesel sinema yapılabileceğini ilan eder. Belgesel sinemacının toplumun &lsquo;&ouml;ncelikli&rsquo; meselelerini, olaylarını ve kişilerini ele alma ve bunları &lsquo;nesnel&rsquo; bi&ccedil;imde değerlendirme vazifesi bir grup belgesel sinemacı tarafından koruma altında tutulurken, toplumsal &ouml;ncelik atfedilemeyecek olaylar, meseleler; yaşamımızın i&ccedil;inde duran ama miyopluktan g&ouml;remediğimiz konular ve hatta eşyalar; sokakta rastlayıp ge&ccedil;tiğimiz kişiler &uuml;zerine belgeseller yapılır, yapılmaktadır. Ayrıca bu olayları, meseleleri, konuları, eşyaları ve kişileri &lsquo;nesnel&rsquo; ele alma zorunluluğu olmadığı gibi belgesel sinemacının &ouml;znel duruşu, tavrı, ilişki kurma bi&ccedil;imi filmin kurucu unsuru haline gelir. Bu eğilimin vardığı u&ccedil; nokta otobiyografik belgesel film &ouml;rnekleri olabilir ki giderek sayıları artmaktadır.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Buna paralel bir başka eğilimse, aşırı-ciddiyetli-toplumsal-bek&ccedil;i-belgesel-sinemacı tipinden sıyrılan ama &ouml;te yandan siyasetin, b&uuml;rokrasinin, medyanın, akademinin la&ccedil;kalaştığı d&uuml;nyamızda d&uuml;nya meselelerine sahip &ccedil;ıkan ve fakat bunları ironik ve alegorik bi&ccedil;imde ele alan yeni bir belgesel sinema anlayışının yaygınlaşmasıdır.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Belgesel sinemada &ouml;nemli bir yeni eğilim de sinema dilindeki muğlaklaşmadır ki bu kendini kurmaca ve belgesel sinemanın giderek birbirlerine yakınlaşması ve kurmaca ile belgesel &lsquo;arasında&rsquo; bir dil arayışına girmeleriyle g&ouml;sterir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Bing&ouml;l Elmas:</span>&nbsp;</b><span>D&uuml;nyada olup biten kritik zaman dilimlerinde, yaşadığımız savaşlar, gerginlikler, işgaller ve bununla birlikte gelen &ccedil;eşitli durumlar nedeniyle belgesel sinemanın daha &ccedil;ok buna eğildiğini ve bununla ilgilenmeye başladığını d&uuml;ş&uuml;n&uuml;yorum ve izlediğim filmlerde bunları g&ouml;zlemliyorum. Tarihsel &ouml;yk&uuml;ler, g&uuml;nl&uuml;k insan hikayeleri ve bu g&uuml;nlerde yaşanan politik durumlar &ccedil;ok &ouml;n planda. Mesela Irak&rsquo;ın işgalinden hemen sonra festivallere gelen filmlerin bu konuya y&ouml;neldiğini g&ouml;r&uuml;yoruz. Filmlerin b&uuml;y&uuml;k bir &ccedil;oğunluğu bu durumla karşı karşıya kalan insanların yaşadığı sıkıntıları ve savaşın yansımlarını g&ouml;zler &ouml;n&uuml;ne seriyor. Filistin&rsquo;le ilgili pek &ccedil;ok film gelmesi de bu duruma &ouml;rnek olabilir.&nbsp; Avrupa sinemasından da daha &ccedil;ok insan hikayeleri geliyor; oradaki insanların psikolojik durumlarını, hallerini tarif eden filmler bunlar. T&uuml;rkiye&rsquo;de ise metinli, m&uuml;zikli ve ge&ccedil;mişe d&ouml;n&uuml;k hikayelerden ziyade metinsiz, tanıklığa dayalı, m&uuml;ziğin daha az kullanıldığı filmler yapılıyor. Teknolojinin verdiği fırsatla daha fazla alanı g&ouml;zlemleyebilen bir belgesel sinemanın ortaya &ccedil;ıktığından s&ouml;z edebiliriz.&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: 10pt;"><b><span><img src="/images/yazilar/bingolelmas.jpg" alt="" width="401" height="283" border="0" />&nbsp;<br /></span></b>Bing&ouml;l Elmas</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span><br />2) Modern teknoloji belgesel film estetiğini nasıl bi&ccedil;imlendiriyor?</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>T.&Ouml;:</span></b><span>&nbsp;Yukarıda belirttiğim gibi ilerleyen teknoloji &ouml;nceden girilmesi ve g&ouml;r&uuml;lmesi m&uuml;mk&uuml;n olmayan mekanlar ve konular hakkında da filmler yapma olasılığını veriyor. Bir insan beynini, bir &ccedil;ocuğun doğum s&uuml;recini anlatan belgeseller eskiden tahmini g&ouml;r&uuml;nt&uuml;lerle yapılabiliyordu. Artık bu konular her anı ger&ccedil;ek g&ouml;r&uuml;nt&uuml;lerle tespit edilip, son teknoloji animasyonlarla da a&ccedil;ıklanabiliyor. Teknoloji mikro ve makro konular arasındaki ge&ccedil;işleri &ccedil;ok daha g&uuml;&ccedil;l&uuml; ve yumuşak hale getirdi. Gelişen bilim, sanat ve bilim buluşmasını g&uuml;&ccedil;lendiriyor ve seyirciyi evrenle ilgili bildiği ve bilmediği şeylerle daha fazla şaşırtıyor. Sonu&ccedil;ta kaba kurallar kalmıyor; filmciler konuları işlemede son derece &ouml;zg&uuml;r davranıyor. Bug&uuml;n ge&ccedil;erli olan bir y&ouml;ntem yarınki bir teknolojik buluşla anında ge&ccedil;ersiz kalabiliyor. Devingen, s&uuml;rekli arayış i&ccedil;inde olan bir tarz ya da tarzlar birleşimi &ccedil;ıktı ortaya.&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>L.P:</span></b><span>&nbsp;Duruma g&ouml;re değişir. G&ouml;r&uuml;n&uuml;r ya da g&ouml;r&uuml;nmez olabilir ama her durumda rol&uuml; b&uuml;y&uuml;k. &Ouml;rneğin ben, g&ouml;r&uuml;n&uuml;r &ouml;zel efektler kullanmayı sevmem ama montaja gelince &ccedil;ekimleri direk kesmeyi severim. Ama aynı zamanda modern renk d&uuml;zeltme programlarını kullanmayı severim. Tabii ki modern &ccedil;ekim sistemlerini kullanıyorum (&ouml;rneğin, modern teknoloji olmadan &ccedil;ekilemeyecek yerlerde &ccedil;ekimler yapıyorum -kuş yuvaları gibi). Ve modern ses kayıt, ses montaj ve miksaj sistemleri kullanıyorum. B&uuml;t&uuml;n bunlar filmlerimizi daha iyi hale getiriyor.&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>N.S:</span>&nbsp;</b><span>Belgesel sinema estetiğini belirlemenin de &ouml;tesinde, modern teknoloji g&uuml;n&uuml;m&uuml;zde belgeseli var eden etkenlerin başında yer alıyor. Hatta şunu da s&ouml;ylemek m&uuml;mk&uuml;n: Eğer teknolojinin getirdiği kolaylık ve ucuzluk olmasaydı, g&uuml;n&uuml;m&uuml;z şartlarında belgeselin ayakta kalması &ccedil;ok zor olurdu. Dijital &ccedil;ağın yeni olanakları kurmaca sinemasına &ndash;g&ouml;zalıcı efektler dışında- sinema dili a&ccedil;ısından pek yeni bir şey katmadı. Sinema filmleri hala temelleri 1920&rsquo;lerde atılmış olan kurgu prensiplerine ve estetik temellere dayanarak yapılıyor. Oysa belgeselde ve kısa filmde k&ouml;pr&uuml;n&uuml;n altından &ccedil;ok sular aktı; bu filmlerdeki yaratıcı potansiyel hem estetik hem de i&ccedil;erik anlamında, giderek genişledi ve genişlemeye devam ediyor. Kameralar k&uuml;&ccedil;&uuml;ld&uuml;k&ccedil;e ve elden ele dolaştık&ccedil;a, belgeselciler hayatın gizli dehlizlerine daha kolay girmeye başladı. Dijital kurgudaki olanaklar da, sinema yapma işini imtiyazlı bir z&uuml;mrenin elinden alıp onun demokratikleşmesini sağladı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Fakat tam da bu noktada,&nbsp;<b>Abbas Kiarostami</b>&rsquo;nin bir masterclassta dile getirdiği ve &ccedil;ok hoşuma giden o lafı aklıma geliyor: &lsquo;Digital olanaklarla &ccedil;ekilmiş o kadar &ccedil;ok k&ouml;t&uuml; film g&ouml;rd&uuml;m ki, neredeyse şunu &ouml;nereceğim: Dijital kameraların kullanımı kontrol altına alınmalı, hatta silah ruhsatına benzer bir belgeye tabi tutulmalıdır!&rsquo;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>L.R:</span></b><span>&nbsp;Teknoloji, sanat&ccedil;ının &ouml;zg&uuml;rl&uuml;ğ&uuml;n&uuml; ve yaratıcılığını ciddi anlamda desteklemekte ve k&ouml;r&uuml;klemekte. Teknoloji sayesinde sanat&ccedil;ılar artık hem daha bağımsız filmler &ccedil;ekebiliyorlar hem de daha eleştirel bakabiliyorlar. Dolayısıyla artık ana akım sinemayla boy &ouml;l&ccedil;&uuml;şen pek &ccedil;ok belgesel yapılıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>U.K:</span></b><span>&nbsp;Video kameraların k&uuml;&ccedil;&uuml;lmesi ve fiyatlarının d&uuml;şmesi, bir &ccedil;ok kişi tarafından&nbsp;<i>g&ouml;r&uuml;nt&uuml; &uuml;retiminin demokratikleşmesi</i>&nbsp;olarak tanımlanan yeni bir s&uuml;re&ccedil; başlattı. Evet, bir yanıyla &ouml;yleydi, artık 35 mm. ile sınırlı bir sinema d&uuml;nyasından kurtuluyorduk. Anlatmak istediğimiz &ouml;yk&uuml;leri artık son derece ekonomik y&ouml;ntemlerle anlatabilecektik. Kendi filmlerimizi &ccedil;ekip evlerimizde kurgulayabilecektik. Fakat beklenenin &ccedil;ok dışında ve genel olarak sinema anlayışını zedeleyen şeyler de yaşandı: K&uuml;&ccedil;&uuml;len kameralar ve ucuzlayan teknoloji, tam da postmodern d&ouml;nemin ruhuna uygun bi&ccedil;imde t&uuml;m kavramları alt &uuml;st etmeye başladı. Artık eline kamerayı alan herkes film yaptığını zannediyor. Eline bir kalem kağıt ge&ccedil;irip bir şeyler yazan herkese yazar diyebilir miyiz? Fakat nasıl olduysa eline kamerayı ge&ccedil;iren herkese &lsquo;sinemacı&rsquo; ya da &lsquo;belgeselci&rsquo; denilebildiği g&uuml;nlerde yaşıyoruz. Hatta bir sanat akademisyeninin yurtdışında bir m&uuml;zeyi gezerken yaptığı &ccedil;ekimleri getirip &lsquo;Hadi &ccedil;ektiğim belgeseli izleyelim!&rsquo; diyebildiği bir d&ouml;nem bu... Kamera yoluyla elde edilen &lsquo;tanıklıklar&rsquo;ın, &lsquo;belgeleme&rsquo; lerin aslında belgesel olmadığını, olamayacağını s&ouml;ylemek zorunda kalmak bile ayıp; bu iki artı ikinin sonucunu s&ouml;ylemek gibi bir şey ama ortaya &ccedil;ıkıp belki de bağıra &ccedil;ağıra s&ouml;ylememiz lazım: &lsquo;Kamerayla kaydettiğiniz her olay belgesel değildir!!! Belgesel yapabilmek i&ccedil;in, kaydettiğiniz olay ve olguları belirli bir estetik yaklaşım &ccedil;er&ccedil;evesinde yeniden yorumlamanız, başlangı&ccedil; karesinden bitiş jeneriğine kadar her ayrıntısını bi&ccedil;im-i&ccedil;erik ilişkisi d&uuml;zleminde incelikle tasarlamanız gerekiyor!&rsquo; Bu &ccedil;ok &ouml;nemli olumsuzluğun dışında, g&ouml;rsel &uuml;retim teknolojisinin gelişmesi ve ucuzlaması sayesinde bir &ccedil;ok iyi belgeselci kazandık. &Ouml;rneğin yukarıda ismini saydığım o g&uuml;zel filmler, bu teknolojik imkanlar olmasaydı belki de yapılamayacaktı...</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>B.K:</span>&nbsp;</b><span>Dijital video tekniklerinin belgesel &uuml;zerindeki etkisini ger&ccedil;ekten azımsayamayız. Daha ufak kameralar bize geleneksel film ekipmanının &ccedil;ekim yapmakta zorlanacağı yerlere girme imkanı sağlıyor. DV kasetler filmden &ccedil;ok daha ucuz olduğu i&ccedil;in daha fazla &ccedil;ekim yapabiliyoruz ve &ouml;nceden ka&ccedil;ırılabilecek k&uuml;&ccedil;&uuml;k hareketleri yakalayabiliyoruz, filmlerimizi de izleyiciye yeni ve yaratıcı yollarla &ndash;DVD&rsquo;den podcaste kadar- buluşturabiliyoruz. Ayrıca teknolojinin daha &ouml;nce filmlerini &ccedil;ekme ve sunma alanında diğerleriyle eşit şansa sahip olmayan belgesel sinemacılara da bir kapı a&ccedil;tığına inanıyorum. Bence daha d&uuml;ş&uuml;k maliyetli yapım ve kurgu ekipmanı her şeyden &ouml;nce i&ccedil;inde daha fazla &ccedil;eşitlilik barındıran bir sinema camiası oluşmasına katkı sağladı. Sinemada ve genel olarak sanat i&ccedil;inde farklı sesleri cesaretlendirmeye hala ihtiyacımız olmasına rağmen, bana kalırsa bu farklılığın olumlu etkisini seyrettiğimiz &ouml;yk&uuml;lerde ve onların aktarılış bi&ccedil;iminde g&ouml;rmeye başladık bile.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>E.O:</span>&nbsp;</b><span>Modern teknoloji belgesel sinema estetiğine giderek daha fazla televizyon estetiğinin bulaşmasına ve karışmasına neden oluyor. Daha doğrusu, teknoloji bunu kendisi yapabilecek bir &ouml;zne olmadığına g&ouml;re, belgesel sinemacılar elektronik g&ouml;r&uuml;nt&uuml; teknolojisindeki gelişmeleri&mdash;ki bu teknoloji televizyon k&ouml;kenli bir teknoloji&mdash;giderek daha &ccedil;ok belgesel sinema i&ccedil;erisinde kullanıyorlar. Bunun bir nedeni, televiz&uuml;el g&ouml;r&uuml;nt&uuml; estetiğinin kuşatıcı etkisi altındaki hegemonyası, diğer yandan belgesel filmin birincil yatırımcısı ve alıcısının televizyon kanalları olması.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Diğer yandan şunu da teslim etmeli ki bu durum salt belgesel sinemaya has bir durum değil. Topyekun sinema televiz&uuml;el g&ouml;rsel estetiğin etki sahasına girmiş durumda.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>B.E:&nbsp;</span></b><span>İki<b>&nbsp;</b>y&ouml;nde etkiliyor bana kalırsa. &Ouml;ncelikle film &ccedil;ekmeyi olduk&ccedil;a kolaylaştırdığı i&ccedil;in yeterince hazırlık yapılmadan &ccedil;abucak &uuml;retilen filmler oluşmaya başladı. Bir &ouml;yk&uuml; yakalayıp, ışık, ses vs&hellip; donanıma &ccedil;ok aldırmadan filmin hemen &ccedil;ekilmesi y&ouml;n&uuml;nde bir eğilim s&ouml;z konusu. Diger bir yandan ise gelişen teknolojiyi filmlerine daha iyi ses, ışık, g&ouml;r&uuml;nt&uuml; olarak yansıtarak filmini daha g&uuml;&ccedil;l&uuml; kılan y&ouml;netmenler de var. &Ouml;zellikle yurtdışından gelen belgesellerin &ccedil;ok iyi &ouml;n hazırlık yapılmış, teknolojinin her olanağından yararlanılarak yapılmış filmler olduğunu g&ouml;r&uuml;yoruz. Yani bir yandan estetiği &ccedil;ok g&uuml;&ccedil;l&uuml; filmler izlerken diğer yandan &ouml;zensiz ve kolaya ka&ccedil;ılmış filmler izliyoruz.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>&nbsp;</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>3) Belgesel sinemanın &ouml;n&uuml;nde duran engeller nelerdir?</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>T.&Ouml;:</span></b><span>&nbsp;Para ve dağıtım engelleri. Belgesel, drama ve haber programlarının i&ccedil; i&ccedil;e ge&ccedil;tiği d&ouml;nemde belgeselin tanımlanması zorlaştığı i&ccedil;in dağıtımdaki yerinin belirlenmesi de zorlaşıyor. Artan kanallar, internet ne yazık ki belgeselin dağıtım payından yiyor. Belgesel zaten hassas bir konumdaydı ve korunmaya ihtiyacı vardı. Hi&ccedil;bir zaman ticari bulunmadı zaten. Ama ben d&uuml;nyada belgeselin etrafındaki koruma duvarının git gide inceldiğini, bağımsız belgesellere verilen desteğin azaldığını g&ouml;r&uuml;yorum.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>L.P:</span></b><span>&nbsp;Bazen ve hatta inanıyorum ki başka &uuml;lkelerde &ccedil;oğu zaman, resmi g&ouml;revliler ve resmi kurallar (9/11 den sonra bu daha da &ccedil;ok olmaya başladı). &Ouml;rneğin benim iki kere otob&uuml;s durağında &ccedil;ekim yapmam yasaklandı. Ve bir engel ve aynı zamanda aşılması sizi geliştirecek bir zorluk olarak ışık ve ışıklandırmayı da ekleyebilirim.&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>N.S:</span></b><span>&nbsp;En &ouml;nemlisi, filmlerin seyirciye ulaşmasının &ouml;n&uuml;ndeki engeller. Belgeselin son yıllardaki hızlı y&uuml;kselişine, festivallerde baştacı edilmesine ve &uuml;retilen onca g&uuml;zel filme rağmen, bu filmler ticari sinemalarda hak ettiği yeri alamıyor. Avrupa&rsquo;da g&ouml;sterime giren belgesel sayısı ve bunlara kapılarını a&ccedil;an salonlar artmakla beraber, bunlar uzun metrajlı ve genellikle b&uuml;y&uuml;k festivallerde &ouml;d&uuml;l almış şanslı bir avu&ccedil; filmle sınırlı.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Kimi fonlar dışında Avrupa&rsquo;da belgeselin arkasındaki yegane mali kaynak ARTE, ZDF, YLE vs. gibi televizyon kanalları. Bunun getirdiği tehlikeli bir tektipleşmeden ya da yıldan yıla değişen trendlerden de s&ouml;z edilebilir. Ama bu kanalların desteği olmasa, belgesel t&uuml;r&uuml; yine muhtemelen ya tarihe karışır ya da deneysel sinema gibi dar bir &ccedil;evrenin uğraşı olarak kalırdı. Belgesel sekt&ouml;r&uuml;yle organik ilişkisi olması bir yana, bu alanda neler yapıldığı hakkında bilgisi dahi olmayan tv kanallarımızla T&uuml;rkiye&rsquo;deki durumun vehametini artık varın siz d&uuml;ş&uuml;n&uuml;n.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>L.R:</span>&nbsp;</b><span>Belgesel &ccedil;ekmenin &ouml;n&uuml;nde hi&ccedil;bir engel g&ouml;remiyorum doğrusu. Burada sadece, yaratıcı-y&ouml;netmenin kendisini aşma kaygısının ve d&uuml;nyayı ilgilendiren sorunların bir hayli fazla olup a&ccedil;ıkg&ouml;r&uuml;şl&uuml;, yaratıcı bir ruhla ele alınmaları gerekliliğinin zorluk &ccedil;ıkartabileceğini sanıyorum.&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>U.K:</span></b><span>&nbsp;B&ouml;yle bir soruya bir &ccedil;ok kişi&nbsp;<i>maddi sorunlar</i>&nbsp;şeklinde cevap verecektir. Oysa belgesel sinemanın &ouml;n&uuml;ndeki en b&uuml;y&uuml;k engel, sinema k&uuml;lt&uuml;r&uuml;nden ve estetik tartışmalardan yoksun kafalardır. Siz neyin hikayesini ni&ccedil;in ve nasıl anlatacağınızı sağlam bir estetik &ccedil;er&ccedil;evede tasarlayabiliyorsanız gerisini halletmek kolay. Tabii burada ger&ccedil;ekten b&uuml;y&uuml;k b&uuml;t&ccedil;e gerektiren uluslararası yapımlardan bahsetmiyorum;&nbsp;<b><i>&Uuml;&ccedil; Kulaklı</i></b>,&nbsp;<b><i>Ağustos Karıncası</i></b>,<b><i>&nbsp;G&uuml;ndelik&ccedil;i</i></b>&nbsp;gibi, &ccedil;ekiminden kurgusuna kadar &uuml;retimine tanıklık ettiğim filmler hi&ccedil; de y&uuml;ksek b&uuml;t&ccedil;elerle değil, sinematografik ve estetik kaygılarla &ccedil;ıktı ortaya. Bu sorunu &ccedil;&ouml;zmenin tek yolu da, bol bol film izlemekten -hem kurmaca hem de belgesel filmler- ve o filmler &uuml;zerine bol bol tartışmaktan ge&ccedil;iyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>B.K:</span>&nbsp;</b><span>Belgesel film yapmak hi&ccedil;bir zaman kolay bir iş değildir, ama buna her zaman değer. Genel sorunlardan bir tanesi finansal kaynak bulmak. Bazı belgesellerin son birka&ccedil; yılda kazandığı parasal başarıya rağmen, karlı olarak tanımlanan bir alan değil. Para kazanmak neredeyse hi&ccedil;bir zaman birinin kamerayı alıp belgesel &ccedil;ekmeye başlama sebebi değildir. Biz bu hikayeleri anlatırız &ccedil;&uuml;nk&uuml; anlatılmaları gerekmektedir. &Ccedil;&uuml;nk&uuml; i&ccedil;imizden bir şey bize bu insanın sesinin duyulması gerektiğini ya da şu ger&ccedil;eğin ortaya &ccedil;ıkarılması gerektiğini s&ouml;yler. B&ouml;ylece de filmlerimizi yaparız ve şu ya da bu şekilde seyahat, film stoğu ve kurgu ile montaj işlemleri i&ccedil;in para toplama m&uuml;cadelesine girişiriz. Bu bir meydan okumadır; sinemacının tutkusu ve &ouml;yk&uuml;s&uuml;ne g&uuml;venmesiyle aşılan bir meydan okumadır.&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>E.O:</span></b><span>&nbsp;Belgesel sinemanın &ouml;n&uuml;nde duran bir engel olduğunu d&uuml;ş&uuml;nm&uuml;yorum. Tam tersine belgesel sinemanın zamanlarında yaşıyoruz; kişilerin ve toplumların her t&uuml;r ger&ccedil;eklikle başının belada ve aklının karışık olduğu bu zamanlarda herkes belgesel sinemadan bir medet umuyor. Belki belgesel sinema yapmanın &ouml;n&uuml;ndeki engellerden bahsetmek m&uuml;mk&uuml;n ki bu hep olan bir sorun yumağıydı&mdash;ve yine salt belgesel sinemaya has bir durum değil-; sanat yapmanın &ouml;n&uuml;nde hep engeller oldu. Bence, d&uuml;nyanın Doğulu ve G&uuml;neyli belgesel sinemacıları olarak biz, hepimiz belgesel film yapmanın &ouml;n&uuml;ndeki &lsquo;maddi&rsquo; engellerle birleşerek b&uuml;y&uuml;yen daha ciddi bir engelle karşı karşıyayız. Kendi &uuml;lkelerimizdeki ulusal kaynaklar yetersiz. Bu nedenle, giderek artan oranda d&uuml;nyanın Batılı ve Kuzeyli fon kaynaklarına başvuruyoruz. Buradaki fon kaynaklarının temel &ouml;nkoşullarının arkaplanındaysa d&uuml;nyayı Batılı ve Kuzeyli g&ouml;rme ve hikayeleme bi&ccedil;imleri i&ccedil;inde ele alma ve buna bağlı g&ouml;rsel-işitsel rejimler geliştirme, ritimler kurma ve belli formatlara sadık kalma kuralları var. Bunun sonucunda d&uuml;nyanın Doğusunun ve G&uuml;neyinin hikayeleri giderek Batılı ve Kuzeyli bir hal alıp yeknesaklaşıyorlar. Bu meseleyi uzun ve derin d&uuml;ş&uuml;nmek, tartışmak gerekiyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>B.E:</span>&nbsp;</b><span>&Ouml;ncelikle finans elbette; ikinci olarak da &uuml;retilenlerin ulaştırılması. Sponsorlar daha pop&uuml;ler ve vitrine dayalı işlere yatırım yapmak istiyorlar. Filmlerinizi de kendi &ccedil;abanız sonucunda yaratacağınız alanlarda g&ouml;sterebiliyorsunuz ancak. Festivaller de bir şekilde buna vesile oluyor. Filmlerin kısıtlı alanlarda g&ouml;sterilmesi b&uuml;y&uuml;k bir engel, hem &uuml;retilen filmin ulaşmasına hem de yeni film &uuml;retilmesine.</span></span></p>', 194, 63, 'Yazarlarımızdan', '/images/yazilar/Laila_darbavietasFons.jpg', '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (52, 'ay-j173', 'askin-kanununu-yazsam-yeniden', 'Aşkın Kanununu Yazsam Yeniden', 'Serhan Mersin', '<h2 style="font-size: 20px; color: #9a1212; line-height: normal; padding: 5px 10px; margin-top: 0px; margin-bottom: 0px; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">Aşkın Kanununu Yazsam Yeniden</h2>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Serhan Mersin</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b>&nbsp;</b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Benim Aşk Pastam</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>My Blueberry Nights</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>Y&ouml;netmen:</span>&nbsp;</b><span>&nbsp;Wong Kar-Wai</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Senaryo:</span>&nbsp;</b><span>&nbsp;Wong Kar-Wai &amp; Lawrence Block</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Oyuncular:</span>&nbsp;</b><span>&nbsp;Norah Jones, Jude Law, David Strathairn, Rachel Weisz, Natalie Portman</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni:</span>&nbsp;</b><span>&nbsp;Darius Khondji</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Kurgu:</span>&nbsp;</b><span>&nbsp;William Chang</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>M&uuml;zik:</span>&nbsp;</b><span>&nbsp;Shigeru Umebayashi</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Dağıtımcı:&nbsp;</span>&nbsp;</b><span>Pinema</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: 10pt;"><b><span>2007/111&rsquo;/Hong Kong-&Ccedil;in-Fransa</span></b></span></p>\r\n<hr style="color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: left;" size="4" width="35%" />\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><b><span style="font-size: x-small;"></span></b><span style="font-size: x-small;"><img src="/images/yazilar/ask%20pastam3.jpg" alt="" width="492" height="332" style="display: block; margin-right: auto; margin-left: auto;" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-large;">F</span></b><span style="font-size: 10pt;">ilm teorisi &uuml;zerine yaptığı s&ouml;yleşilerden birinde&nbsp;<b>Zizek</b>, hakkında yazmış olduğu filmlerin yarısını g&ouml;rmediğini, film tanıtımlarını yahut filmle ilgili yazılanları okuyarak kafasında bir teori oluşturduğunu, bu teoriye dayanarak film hakkında yazdığını s&ouml;yl&uuml;yor ve ger&ccedil;ek deneyimi yani film seyretme eylemini feda edilebilecek bir unsur olarak g&ouml;rd&uuml;ğ&uuml;n&uuml; ifade ediyordu.</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Zizek&rsquo;in g&ouml;r&uuml;şlerini destekler gibi yaparak&nbsp;<b>Wong Kar-Wai</b>&nbsp;&uuml;zerine yazmaya kalkarsak nereden yola &ccedil;ıkacağımızı biliriz. &Ccedil;&uuml;nk&uuml;, Kar-Wai&rsquo;nin herhangi bir filmini seyretmeden &ouml;nce filmde neler g&ouml;receğimizi, nelerle karşılaşacağımızı tahmin edebiliriz: Aynı y&uuml;zlerin, aynı b&uuml;y&uuml;l&uuml; atmosferin kapalı mekanlarda, otel odaları ya da paylaşılan apartman dairelerinde ge&ccedil;en, tekrarlanan hikayeleri ve bu hikayelerin farklı tefrikalarını, eklektik ve &ccedil;oğu zaman doğrusal olmayan kurgusunu, hep aynı yavaş temponun, aynı g&ouml;rsel bi&ccedil;im, motif ve renklerle&nbsp; canlandırılışını, dar sokakları, umutsuz meyhaneleri, karşılıksız aşkları, s&ouml;ylenmemiş, s&ouml;ylenenememiş s&ouml;zleri, bitmesi zorunlu ilişkileri, hışımla ge&ccedil;en trenleri, yakın planları ve yavaş &ccedil;ekimleri, kadınların i&ccedil;lerinde bir biblo gibi g&ouml;z&uuml;kt&uuml;kleri elbiseleri, muhteşem m&uuml;ziklerin s&ouml;zlerden daha fazlasını anlattığı, hikaye anlatımını g&uuml;&ccedil;lendirdiği, ıstırap, g&ouml;zyaşı ve hayal kırıklığından sonra elde kalan kayıp hatıraları ve mutlaka ama mutlaka i&ccedil; sızısı serenatının ge&ccedil;tiği, aşkın etrafında d&ouml;nen hep aynı temaları.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İşte bu y&uuml;zden onun filmleri hep aynı filmi seyrediyormuş duygusu yaratır.&nbsp;<b>Wittgenstein</b>&rsquo;in dil oyunu olarak tabir ettiği birbirine benzer &ouml;zellikler, akrabalıklar barındıran ama birbirinden faklı olayların aynı grup i&ccedil;erisinde değerlendirilebilmesi gibi Kar-Wai&rsquo;nin de kendine ait bir oyunu olduğunu s&ouml;yleyebiliriz. Bu oyunda benzer &ouml;zellikler (Wittgenstein&rsquo;ın terimiyle &ldquo;aile benzerlikleri&rdquo;), filmlerinde farklı &ouml;zellikleri [&ouml;rneğin&nbsp;<b><i>Zamanın K&uuml;lleri</i></b>&rsquo;nde (Ashes of Time, 1994) d&ouml;v&uuml;ş sanatları, Arjantin&rsquo;de ge&ccedil;en<i>&nbsp;<b>Mutlu Beraberlik</b>&rsquo;</i>te (Happy Together, 1997) eşcinsel &ccedil;iftin birlikteliği,&nbsp;<b><i>2046</i></b>&rsquo;daki (2004) bilimkurgu,&nbsp;<b><i>G&ouml;zyaşları Aktık&ccedil;a</i></b>&rsquo;da (As Tears Goes By<i>,&nbsp;</i>1988<i>)</i>&nbsp;yeraltı d&uuml;nyası] i&ccedil;erse de mevzu bahis temalar değişik filmlerde benzerlikler g&ouml;sterir. Hikayeden daha &ccedil;ok g&ouml;r&uuml;nt&uuml;yle ilgilendiği filmleri olduğu gibi,&nbsp;<b><i>Vahşi G&uuml;nler</i></b>&nbsp;(Days of Being Wild<i>,&nbsp;</i>1991<i>)&nbsp;</i>filmindeki gibi &uuml;&ccedil;l&uuml; eklektik doğrusal bir &ouml;yk&uuml;den alnının akıyla &ccedil;ıkabilir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: x-small;">&nbsp;<img src="/images/yazilar/ask%20pastam.jpg" alt="" width="505" height="340" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><b><span style="font-size: x-small;"><br /><span style="font-size: 10pt;">&Ouml;nce ağa&ccedil;lar...</span></span></b></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Kar-Wai, ilk olarak doğa&ccedil;lama hikaye anlatım y&ouml;ntemleriyle &ouml;ne &ccedil;ıkan bir y&ouml;netmendir. Doğa&ccedil;lamadaki başarısı ise hikaye anlatımındaki başarısını sollayan bir spontanlık, adeta filmin &ccedil;ekim sırasında yeniden yazımına yol a&ccedil;an bir savrukluğa neden olur.&nbsp; Bu da aslında sinemasındaki en ciddi soruna işaret eder: Senaryo. İroni gibi gelecek ama mesleğe senaryo yazarı olarak başlamasına rağmen b&ouml;yledir bu. İşte bu savrukluk&nbsp;<i>2046</i>\'nın 5 yılda bitirilmesine, 2004 yılında Cannes Film Festivali&rsquo;nin yarışma b&ouml;l&uuml;m&uuml;nde g&ouml;sterilen kopyanın da hala tam anlamıyla sonu&ccedil;landırılmamış bir kopya olmasına neden olmuş, Cannes\'daki g&ouml;sterimden ancak yaklaşık bir yıl sonra filmin kurgusu ve gerekli &ouml;zel efektler tamamlanarak film g&ouml;sterime girebilmişti. Bu savrukluğun diğer g&ouml;stergeleri, filme başlamadan &ouml;nce bırakın oyuncuları, kendisinin elinde bile sonu&ccedil;landırılmış bir senaryo olmaması, oyuncuların filmin konusu hakkında bile en ufak bilgilerinin bulunmaması, bu yazının konusu olan&nbsp;<b><i>Benim Aşk Pastam</i></b>&rsquo;a kadar ki d&ouml;nemde Hollywood\'da &ccedil;ekmeyi planladığı filmlerin s&uuml;rekli ertelenmesinin ardındaki neden olarak sadece ve sadece elinde bitmiş, hazır bir senaryonun bulunmuyor olmasının yatması vardır (<i>Benim Aşk Pastam</i>&rsquo;ın senaryosunu tek başına değil,&nbsp;<b>Lawrence Block</b>&rsquo;la beraber yazmıştır). Senaryo sorunu &ouml;yle kanıksanmıştır ki, filmlerinin bir numaralı ismi,&nbsp;<b><i>Aşk Zamanı</i></b>&rsquo;yla Cannes&rsquo;da en iyi erkek oyuncu &ouml;d&uuml;l&uuml;n&uuml; alan&nbsp;<b>Tony Leung</b>, 1997 yapımı&nbsp;</span><span><b><i>Mutlu Beraberlik</i></b></span><span>&rsquo;te eşcinsel rol&uuml; oynayacağını filme başladıktan sonra, baştaki &ouml;p&uuml;şme sahnesiyle &ouml;ğrenmişti. Filmlerinin &ccedil;ekim s&uuml;recinde filmdeki t&uuml;m oyuncularına filmin başrol oyuncusunun kendileri olduğunu d&uuml;ş&uuml;nd&uuml;rtmesi, sadece &ccedil;ekim d&ouml;nemi değil, &ccedil;ekim sonrası gelen montaj d&ouml;neminin uzunluğu ve bu s&uuml;re&ccedil;te de hikayesi başta olmak &uuml;zere filmin t&uuml;m&uuml;yle değişecek hale gelmesi bahsedilen diğer &ouml;zelliklerindendir. Buna rağmen t&uuml;m filmlerinde eklektik hikayelerinin kaotik yapısı, hikayecinin bir anda yer değiştirebildiği ama hi&ccedil; de sırıtmayan bir b&uuml;t&uuml;nl&uuml;ğe sahiptir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Kendisiyle yapılan s&ouml;yleşilerin birinde, yazmaktan nefret ettiğini, &ouml;nce senaryoyu yazıp sonra film &ccedil;ekmeyi sıkıcı bulduğunu, film &ccedil;ekiminin t&uuml;m aşamalarını d&uuml;ş&uuml;nmenin gereksiz olduğunu s&ouml;ylerken kendisinin nasıl bir s&uuml;re&ccedil;ten ge&ccedil;tiğini de anlatmaktan geri durmuyor: &ldquo;<i>&Ouml;rneğin, bir mimar &ouml;nce binayı tasarlar, sonra da &lsquo;eh, şimdi de binanın &ouml;n&uuml;nde ağa&ccedil;lar olmalı&rsquo; der ve ağa&ccedil;ları girişe yerleştirir. Ben ise &ouml;nce ağa&ccedil;ları koyuyorum, &ccedil;&uuml;nk&uuml; elimde bir par&ccedil;a arazi, bir de ağa&ccedil;lar var. Sonra, &lsquo;sıra binada, ağa&ccedil;ların arkasında bina olmalı&rsquo; diyorum. &Ouml;ncelikle t&uuml;m bu par&ccedil;aları kafamda oluşturuyor ve sonra filme koyuyorum. Film &ccedil;ekme s&uuml;recini m&uuml;mk&uuml;n olduğunca ilgin&ccedil; ve heyecanlı hale getirmeye &ccedil;alışıyorum. &Ccedil;&uuml;nk&uuml; elimde &ccedil;ok fazla par&ccedil;a var ve bunları biraraya topluyor, filmlerime farklı k&uuml;&ccedil;&uuml;k hikayelerle başlıyorum. Bu y&uuml;zden pek &ccedil;ok filmim kısa b&ouml;l&uuml;mlerden oluşuyor.&rdquo;</i>(1). Bu s&uuml;re&ccedil;&nbsp;<b>Godard</b>\'ın &ldquo;<i>eğer bir filmi &ccedil;ekmeden &ouml;nce t&uuml;m&uuml;yle tamamladıysanız, filmi &ccedil;ekmemelisiniz</i>&rdquo; dediği itiraz noktasına rağmen, Kar-Wai&rsquo;nin Godard&rsquo;ın da &ouml;tesine ge&ccedil;en ve asla &ccedil;ekim senaryosu kullanmayan, bir filme başlarken nasıl biteceğini bilmeyen&nbsp;<b>Rossellini</b>&rsquo;nin tarafını se&ccedil;tiğini g&ouml;steriyor.&nbsp;&nbsp;</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Senaryo yazımı ve hikaye anlatımındaki bu uzun ve yorucu cebelleşmeleri&nbsp; sonucunda&nbsp; ortaya &ccedil;ıkan eserleri hi&ccedil; de başarısız kabul edilmemiş olmalı ki, tanınmışlığı ve filmlerine duyulan hayranlık onu 2007 yılında Cannes&rsquo;da j&uuml;ri başkanlığına taşımıştı. Avrupalı<i>&nbsp;cineaste</i>ların<i>&nbsp;</i>onun filmlerine duyduğu yakınlığın en &ouml;nemli nedeni, Kar-Wai sinemasının Avrupa sinemasına doğudan bakmayı sağlayan bir şekilde arzı endam etmesi olsa gerek. Nasıl ki s&uuml;rekli olarak doğuya gittik&ccedil;e karşımıza batı &ccedil;ıkarsa Wong&rsquo;un filmleri de bizi kulağı uzun tarafından tutarak Batı&rsquo;ya, Avrupa sinemasına g&ouml;t&uuml;r&uuml;yor:&nbsp;<b>Fassbinder</b>&rsquo;den&nbsp;<b>Godard</b>&rsquo;a,&nbsp;<b>Resnais</b>&rsquo;den&nbsp;<b>Kieslowski</b>&rsquo;ye kadar hep Avrupa sinemasının en g&uuml;zel &ouml;rnekleriyle karşılaşmamızı sağlıyor. Zira, onun filmlerinde anlatılan hep yalnız bireylerin, &ouml;rneğin, Hong Kong gibi s&uuml;rekli devinim halinde, kalabalığın insanın &uuml;st&uuml;ne &uuml;st&uuml;ne geldiği bir şehir-devlette, yahut Buenos Aires&rsquo;teki o &ccedil;ılgın futbol derbisinde bile yalnız kalan insanların hikayeleridir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: x-small;">&nbsp;<img src="/images/yazilar/ask%20pastam4.jpg" alt="" width="505" height="340" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>Sonra Yollar...</span></b></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><b><span>&Ouml;zdemir Asaf</span></b><span>, o &uuml;nl&uuml; dizelerinde &ldquo;<i>yalnızlık paylaşılmaz / paylaşılırsa yalnızlık olmaz</i>&rdquo; diye tanımlamıştı yalnızlığı. Yalnızlığı kategorize etmeye kalkarsak yalnızlığın ve yalnız kalmanın tercih edildiği durumlarda belki de yalnızlığın derecesini d&uuml;ş&uuml;k olarak nitelendirmek isteyebiliriz, bu yalnızlık paylaşılmak istenmeyebilir ama en yalnız olduğumuzu anladığımız anlar, bu yalnızlığı paylaşacak kimselerin olmadığını farkettiğimiz anlardır. Başlarda kocasını aldatan k&ouml;t&uuml; kadın rol&uuml;yle karşımıza &ccedil;ıktığını d&uuml;ş&uuml;nd&uuml;ğ&uuml;m&uuml;z Sue Lynne&rsquo;in<i>&nbsp;</i>(<b>Rachel Weisz</b>)&nbsp;<b><i>Benim Aşk Pastam</i></b>&rsquo;da hikayesinin kendi tarafını anlattığında, hala vadesi dolmuş bir aşkın peşinde koşan kocasına olan kızgınlığını ka&ccedil;arak atlatmaya &ccedil;alıştığını, onun hep orada kollarını a&ccedil;mış bir şekilde geri d&ouml;nmesini beklediğinden bahsediyordu. Kocasının &ouml;ld&uuml;ğ&uuml;n&uuml; hayal eden ama ger&ccedil;ekten de &ouml;ld&uuml;ğ&uuml; zaman artık geri d&ouml;necek kimsesinin olmadığını anladığı ve yalnızlığının farkına vardığı zaman bunun ona d&uuml;nyada en acı veren şey olduğunu itiraf ediyordu. Aynı şekilde babası gibi bir kumarbaz olan ama her kumarbazın talihi gibi yalnız kalmayı se&ccedil;en Leslie&rsquo;nin (<b>Natalie Portman</b>) babasının &ouml;ld&uuml;ğ&uuml;ne bir t&uuml;rl&uuml; inanmak istemeyecek kadar duyduğu ıstırap, sadece her başı sıkıldığında geri d&ouml;nebileceği, para isteyebileceği bir yakınının değil, artık ger&ccedil;ekten de yalnız kaldığını farkettiği ana denk d&uuml;ş&uuml;yordu. Ne yazık ki, filmde t&uuml;m bu yalnızlık duygusu bize o kadar bariz bir şekilde anlatılıyor ki, film sonrası aklımızda kalan anların azlığından bizi m&uuml;starip bırakıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İşte bu y&uuml;zden y&ouml;netmenin&nbsp;<b><i>Benim Aşk Pastam</i></b>&rsquo;daki en b&uuml;y&uuml;k başarısızlığı seyircinin duyacağı hazzı ortadan kaldırması olarak değerlendirilebilir. &Ouml;rneğin her &ouml;p&uuml;şmeden sonra dondurmanın pasta i&ccedil;erisinde eriyişini g&ouml;z&uuml;m&uuml;ze g&ouml;z&uuml;m&uuml;ze soktuğunda. Zira, &ouml;nceki filmlerinden farklı olarak senaryo niyetine kullandığı şarkılar veya renkler, hareketler, yavaş &ccedil;ekimler yerlerini kartpostaldan gelen haberlere bırakıyor. Filmdeki gelişmeleri, Elizabeth&rsquo;in (<b>Norah Jones</b>) olaylara bakışını ve herşeyden &ouml;nemlisi kendi kişisel değişimlerini g&ouml;nderdiği kartpostallardan bize okumasıyla bir kez daha duyuyor ve &ouml;ğreniyoruz. Ondan &ouml;ncesi ise sanki hi&ccedil; ara vermeden devam ediyormuş gibi gelen alışılmadık derecede uzun olan ve bu y&uuml;zden filmi boğan diyaloglar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px;"><span style="font-size: x-small;">&nbsp;<img src="/images/yazilar/ask%20pastam2.jpg" alt="" width="505" height="340" style="display: block; margin-right: auto; margin-left: auto;" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Bu a&ccedil;ıdan filmi iki b&ouml;l&uuml;me ayırmakta bir sorun olmayacağını s&ouml;yleyebiliriz: Elizabeth&rsquo;in yolculuğa başlamadan &ouml;nceki d&ouml;nemi ve sonrası. &Ouml;ncesinde zamanın bir &ouml;nemi yok. Zaman, ne zamanki Elizabeth yola &ccedil;ıkıyor, o andan itibaren varolmaya başlıyor. Kar-Wai filmlerinden alışık olduğumuz klostrofobik mekana ev sahipliği yapan kafede ge&ccedil;irilen zamanla ilgili ise bir bilgimiz yok. Gerek de yok, aslında. Bu mini d&uuml;nyada ge&ccedil;irilen d&ouml;nem sadece ve sadece Elizabeth&rsquo;in hala i&ccedil;inde kırıntıları kalan umudu s&ouml;nd&uuml;receği ve herşeyin bir nedeninin olmayacağını, yapılan se&ccedil;imlerin her zaman a&ccedil;ıklanamayacağını &ouml;ğreneceği bir d&ouml;nem. Aşkın hala imkansız olduğunu d&uuml;ş&uuml;nd&uuml;ğ&uuml; bu kafe onun i&ccedil;in konuşacak birilerine ihtiya&ccedil; duyduğu zaman sığınacağı bir liman. Bu limanda m&uuml;davimi olduğu kafenin sahibi ve yitik aşklar koleksiyoncusu Jeremy&rsquo;nin (<b>Jude Law</b>) ilgisine mazhar olsa da o bu ilgiye karşılık verecek kadar kendini hazır hissetmiyor, her ne kadar a&ccedil;ık bir kapı bıraksa da. Jeremy ise herkesin d&ouml;n&uuml;p dolaşıp herkes tarafından kolaylıkla bulunabilecek bir buluşma noktası yaratırken etrafındaki aşklara edilgen g&ouml;zlerle ve yenilmiş bir kahraman edasıyla bakmakta. Ta ki Elizabeth gelene kadar.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>İkinci b&ouml;l&uuml;mde ise akan zamanı ve mesafeyi ekranda g&ouml;r&uuml;len g&uuml;n ve mesafe rakamlarıyla izliyoruz. Zamanın ge&ccedil;işine tanıklığımız&nbsp;<b><i>Mutlu Beraberlik</i></b>&rsquo;te Buenos Aires&rsquo;teki meydanda yer alan saatin ilerleyişi gibi, k&ouml;r g&ouml;z&uuml;ne parmak sokarcasına veriliyor. Gelgelelim, t&uuml;m bunların sonunda ise seyirci edilgen olarak bir yol filminde esas kızın kişisel değişimini seyretmekle kalıyor. &Uuml;stelik bir yol filminde karşımıza &ccedil;ıkabilecek t&uuml;m &ouml;ng&ouml;r&uuml;lerle beraber, farklı okumalara izin vermeyen yapısıyla.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Yol filmleri her zaman farklı olandan (<b><i>Benim Aşk Pastam</i></b>&rsquo;da farklı olan Weisz ve Portman&rsquo;ın canlandırdığı kişilikler) bir şeyler &ouml;ğrenmek &uuml;zerinedir, paylaşılan yaşanmışlıklar &uuml;zerinedir. Y&ouml;netmen&nbsp;<b>Walter Salles</b>&rsquo;ın dediği gibi &ldquo;<i>Yol filmleri karakterlerin i&ccedil;sel değişiminin izini s&uuml;rer, filmler neler g&ouml;r&uuml;lebildiği yahut dile getirilebildiği hakkında değildir, daha ziyade neler hissedilebildiği hakkındadır &ndash;g&ouml;r&uuml;lemezin g&ouml;r&uuml;nebiliri tamamlaması hakındadır</i>&rdquo; (2). Yol filmlerinde herkesin birbirinden &ouml;ğreneceği birşeyler mutlaka vardır ve &ouml;nemli olan da birbirini değiştirebilmektir.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Filmin ikinci b&ouml;l&uuml;m&uuml; Elizabeth&rsquo;in yola &ccedil;ıkışı, eski sevgilisini aşığıyla beraber apartman dairesinde g&ouml;rmesi ve t&uuml;m umutlarını kaybetmesiyle başlıyor. Filmin sonunda itiraf edeceği &uuml;zere yola &ccedil;ıktığı o gece Jeremy&rsquo;nin işlettiği kafenin kapısından girmiş olsaydı değişemeyecek olması, karşı tarafa en uzak yoldan ge&ccedil;meye karar vermesine neden oluyor. Kar-Wai&rsquo;nin&nbsp;<b><i>Aşk Zamanı&nbsp;</i></b>(In the Mood For Love<i>,&nbsp;</i>2000),<i>&nbsp;<b>Chungking Expresi</b>&nbsp;(Chungking Express,&nbsp;</i>1994)<i>&nbsp;ve&nbsp;<b>2046</b></i>&rsquo;da &uuml;zerinde durduğu gibi aşk bir zamanlamanın tanımıdır, er ya da ge&ccedil; doğru insanı bulmak değildir. Doğru zaman o gece değildir. Doğru zaman i&ccedil;in beklemek ve bir ama&ccedil;la uzaklaşmak gerekir. Ama&ccedil; ise, daha &ouml;nce onlarcası yapılmış &ouml;rnekleri gibi, kendini tanıma, hayattan ne istediğini anlama, &ouml;ğrenme arzusudur. B&ouml;ylelikle aşkın eski kanununu, o bilindik hikayeyi, Kar-Wai yeni bir &uuml;lkede tekrar yazıyor: Eğer aşk acısı &ccedil;ekiyorsanız, terkedildiyseniz, uzaklaşın, ıstırabınızı unutmak i&ccedil;in sabah-akşam durmadan &ccedil;alışın, kendinizi tanıyıp gelin, eğer şanslıysanız d&ouml;nd&uuml;ğ&uuml;n&uuml;zde sizin i&ccedil;in bekleyen yeni birisini bulursunuz. Bu arada para biriktirip yeni bir araba bile alabilirsiniz kendinize.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: center;"><span style="font-size: x-small;">&nbsp;<img src="/images/yazilar/chunking.jpg" alt="" width="465" height="296" border="0" /></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Araba da alınıyor, geri de d&ouml;n&uuml;l&uuml;yor. Geri d&ouml;n&uuml;len kafede bekleyen de bulunuyor ama ciddi bir samimiyet sorunu hala devam ediyor. Bu samimiyetsizlik sanki y&ouml;netmenimizin herşeyiyle tanıdığı, bildiği insanları değil de, sadece filmlerde g&ouml;rd&uuml;ğ&uuml; insanların filmini yapmaya &ccedil;alıştığı i&ccedil;in ortaya &ccedil;ıkıyor. Sorun olan, karakterlerin varlığı değil; zayıf &ccedil;izilmiş ve karikat&uuml;rleştirilmiş olmaları. Toplum dışılara olan merakıyla bilinen y&ouml;netmenin bu filmindeki toplum dışılar olduk&ccedil;a naif ka&ccedil;ıyor, ilgimizi bir t&uuml;rl&uuml; cezbedemiyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>T&uuml;m bu hoşnutsuzlukların altında değerlendirme normlarımızın değişmiş olma olasılığı var mıdır? Zira, Kar-Wai&rsquo;nin Hollywood hayalini tatmin etmek amacıyla ABD&rsquo;ye gelmesiyle artık karşımızda Hong Kong Sineması&rsquo;nın bir filmi yok. Biz de haliyle etiyle buduyla bir Hollywood filmini seyredip yorumluyoruz. Y&ouml;netmenin belki de kolaya ka&ccedil;arak, kendini bulma duygusuyla uzaklaşarak bir yerlere gitmeyi anlatma &ccedil;abası, Hong Kong film tarzından yol filmi t&uuml;r&uuml;ne atlaması sonucunu doğuruyor. Ne var ki, daha &ouml;nceki filmlerinden farklı olarak bu filminde Wong Kar-Wai imzasını eksik kılan bildiği insanların&nbsp; hikayesini yapmaması, bu film t&uuml;r&uuml;yle aşka dair yarattığı sinemasal dile uzak kalması. Bu y&uuml;zden de yol filmleri t&uuml;r&uuml;n&uuml;n doğduğu Amerikan topraklarına yol filmi yaparak başlangı&ccedil; yapması belki de&nbsp;<b>Fazıl Say</b>&rsquo;ın Viyana&rsquo;da&nbsp;<b>Mozart</b>&nbsp;konseri vermesine benziyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;"><span>Daha &ouml;nceden o yollardan onlarca kez ge&ccedil;tiği i&ccedil;in g&ouml;zlerimiz yeni bir şeyler ararken, bize ilgin&ccedil; gelen Amerika&rsquo;da ge&ccedil;en bir hikaye değil, Hong Kong&rsquo;un varoşlarında karşılıksız aşkların bizde yarattığı&nbsp;</span><i><span>d&eacute;j&agrave;</span></i><span><i>&nbsp;vu</i>&nbsp;duygusu, yavaş &ccedil;ekim h&uuml;zn&uuml;d&uuml;r. Kim bilir? Bilinmez ama bizim payımıza da&nbsp;<b>Zizek</b>&rsquo;in yaptığını yapıp, Kar-Wai&rsquo;nin bu filmini feda etsek ne kaybederiz diye d&uuml;ş&uuml;nmek kalıyor.</span></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: x-small;"></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">(1)&nbsp;<a href="http://www.wkw-inthemoodforlove.com/eng/LivingRoom/tv/MakingOf.asp" target="_blank" style="color: #895f37;">Wong, Kar Wai, Making of,&nbsp;<i>Aşk Zamanı Filmi Resmi Web Sitesi</i>, 2000.</a><a href="http://www.wkw-inthemoodforlove.com/eng/LivingRoom/tv/MakingOf.asp" target="_blank" style="color: #895f37;"></a></span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span style="font-size: 10pt;">(2)&nbsp;<a href="http://www.nytimes.com/2007/11/11/magazine/11roadtrip-t.html?pagewanted=all&amp;_r=0" target="_blank" style="color: #895f37;">Salles, Walter. &ldquo;Notes for a Theory of the Road Movie&rdquo;,&nbsp;</a></span><a href="http://www.nytimes.com/2007/11/11/magazine/11roadtrip-t.html?pagewanted=all&amp;_r=0" target="_blank" style="color: #895f37;"><i style="font-size: 10pt;">The</i><span style="font-size: 10pt;"></span><i style="font-size: 10pt;">New York Times</i><span style="font-size: 10pt;">, 11 Kasım 2007.</span></a></p>', 186, 63, 'Yazarlarımızdan', '/images/yazilar/ask%20pastam3.jpg', '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (53, 'ay-j174', 'ankara-nin-sinema-dergileri', 'Ankara’nın Sinema Dergileri...', 'Ankara\'da Kültür ve Sanat, Şubat 2005', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span>Ankara&rsquo;da K&uuml;lt&uuml;r ve Sanat, Şubat 2005</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span>G&ouml;khan Erkılı&ccedil;</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinema dergilerimizin &ccedil;oğunluğunun İstanbul&rsquo;da yayınlanmış olması son derece normal. Sayısal olarak kapatılması olası g&ouml;z&uuml;kmeyen bu b&uuml;y&uuml;k fark, iş niteliğe ve tam da sinemanın hak ettiği t&uuml;rden sanatsal i&ccedil;eriğe gelince anlamını yitiriyor. Olay, nerede &ccedil;okluk orada popluk&nbsp; t&uuml;r&uuml;nden, eski s&ouml;z&uuml;n yeni versiyonunu s&ouml;ylemeyi zorunlu kılıyor. Ger&ccedil;ekten de sinema dergiciliği alanında Ankara oldum olası &ccedil;ok uyuşuk bir kent, hele İstanbul&rsquo;la karşılaştırıldığında. Ancak bu uyuşukluğun sıkı nedenleri var. Bir kere Cumhuriyet &ouml;ncesi d&ouml;nemde, sanata d&uuml;şk&uuml;n yabancıların ve onlara &ouml;zentili yerli sanat adamlarının yuvalandığı tek yer olan Pera, g&uuml;n&uuml;m&uuml;zdeki adıyla Beyoğlu, İstanbul&rsquo;un atardamarı olagelmiş. Ankara&rsquo;nın adı bile yok o sıralar. Zamanın gereği olarak magazinelliği aşamayan yabancı dergiler ve onların yerli kopyaları, kendilerine İstanbul&rsquo;u mesken tutmuşlar. D&uuml;nya basını sinemaya sanat stat&uuml;s&uuml; tanındığını kanıtlayan yayınlarına başladığı yıllarda, İstanbul eski huyunu s&uuml;rd&uuml;rm&uuml;ş.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Pop&uuml;ler olanın getirisinden vazge&ccedil;meyen İstanbul&rsquo;a sinema dergiciliğinin yeni ilgi alanlarını, ilk kuramsal adımları ve ulusal olana eğilmenin gerekliliğini g&ouml;steren ilk Ankaralı dergi,&nbsp;<b>Nijat &Ouml;z&ouml;n</b>-<b>Halit Refiğ</b>&nbsp;ikilisinin 1956&rsquo;da yayınladığı Sinema olmuş. B&uuml;y&uuml;k boy d&ouml;rt sayfa &ccedil;ıkan dergi sekiz ay yayınlanmış. Yerli sinemaya ağırlık veren dergi, yabancı sinemalara da kucak a&ccedil;mış. Az basılan ve okurun kemikleşmiş alışkanlıklarına ters d&uuml;şt&uuml;ğ&uuml;n&uuml;n bir g&ouml;stergesi olarak az satılan Sinema, 15 Mart-15 Ekim tarihleri arası kısa bir yayın hayatına sahip olmuş. Sinema&rsquo;dan g&uuml;n&uuml;m&uuml;ze, kendi sayıları dışında,&nbsp;<b>&Ouml;z&ouml;n</b>&rsquo;&uuml;n Sinema Sanatı adlı kitabı kalmış. &Uuml;&ccedil; yıl sonra, 1959 yılının Mart ayında, Sinema-Tiyatro adıyla &ccedil;ıkan bir başka Ankara dergisi, 1959 Haziran sayısı olan T&uuml;rk Sineması &Ouml;zel Sayısı ile sinema adına yaptığı tek &ouml;nemli işi ger&ccedil;ekleştirmiş. Yıllar sonra, 1989 Kasım ayında yayına başlayan, kendi s&ouml;ylemiyle, beş bin satarken bile sekt&ouml;rden yeterli destek bulamadığını gerek&ccedil;e g&ouml;stererek, 1990 Mayıs ayında kapanan, ancak değişen kadrosuyla birlikte İstanbul&rsquo;a taşınarak 1990 Eyl&uuml;l ayında bir sayı daha &ccedil;ıkan Beyazperde, toplam sekiz sayı boyunca, ağırlığı pop&uuml;lerliğe vererek, arada bir g&uuml;zel işler de &ccedil;ıkardı. Y&ouml;netmenler, T&uuml;rk Sineması ve İstanbul FF dosyaları kaldı geriye. Bir Ankara&rsquo;lı olarak yayınına devam etmemesi &uuml;zm&uuml;şt&uuml; bizi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Ve sonra, aradan yıllar ge&ccedil;mesine rağmen, halen T&uuml;rkiye&rsquo;nin en iyi sinema dergisi olarak g&ouml;sterilen 25. Kare &ccedil;ıktı sahneye. Yıl: 1990. Amat&ouml;r ruhla yola koyulan ama amat&ouml;rce işler yapan dergi, Ali Karadeniz&rsquo;in işe el koymasıyla zaman i&ccedil;inde d&uuml;zene girdi. Belli bir d&ouml;neminde bizim de ucundan tuttuğumuz dergi, artıları eksilerine g&ouml;re daha fazla olan tercihleriyle on bir yıl ayakta kaldı. Karadeniz, 31 nolu 2000 yılı Bahar-Yaz sayısıyla dergiye son noktayı koydu. Genellikle akademisyenlerin sevdiği ve desteklediği dergi belirli alan, t&uuml;r ve temalara g&ouml;sterdiği ilgi nedeniyle kendi kendini sınırlamıştı. Akademik olanın niteliği garanti etmemesi ya da entelekt&uuml;el birikimin d&uuml;nya g&uuml;ndemini yakalamak ve sorunlara &ccedil;&ouml;z&uuml;m bulmaktan uzak kalması, 25. Kare&rsquo;nin sorunu ve sonu oldu.&nbsp;<b>Oğuz Onaran</b>,&nbsp;<b>Se&ccedil;il B&uuml;ker</b>,&nbsp;<b>Ruken &Ouml;zt&uuml;rk</b>,&nbsp;<b>Sadi Konuralp</b>,&nbsp;<b>Nilg&uuml;n Abisel</b>&nbsp;ve&nbsp;<b>Nejat Ulusay&nbsp;</b>gibi, dergiyi &uuml;retim ve nitelik konusunda s&uuml;r&uuml;kleyen yazar kadrosunun Ankara&rsquo;lı olması da ayrı bir keyifti doğrusu. Ne yazık ki bitti.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Ve sıra şimdi Sekans&rsquo;ın... Sekans, sinema dergiciliğinde g&ouml;rd&uuml;ğ&uuml;m&uuml;z boşluğun doğal bir sonucu olarak ortaya &ccedil;ıktı. Sinema Dostları Derneği olarak, yaptığımız anketlerden sinemayla ilgilenenlerin beşte d&ouml;rd&uuml;n&uuml;n ara sıra bile olsa bir sinema dergisi okumadığını &ouml;ğrendik. Pop&uuml;ler olanın dışında kalana l&uuml;tfederek yer verenler, akademik mast&uuml;rbasyon yapanlar ya da sinemayı ideolojik bir ara&ccedil; olarak kullananların gelebilecekleri nokta bundan &ouml;te bir sonu&ccedil; doğurmuyor. Sinemanın ve sinema yayıncılığının derdi sinema olan bir sinema dergisine gereksinimi vardı. Sekans bu boşluğu doldurmak i&ccedil;in &ccedil;ıkacak. İnan&ccedil;, enerji, bilgi, arşiv ve yayıncılık gibi konularda kendimizi formda hissediyoruz. Bizim ve okurun g&ouml;rmeyi istediği bir dergi olabilmek, konu zenginliğine ulaşmayı gerektiriyor. Bu nedenle, Sekans&rsquo;ta &ccedil;ok sayıda b&ouml;l&uuml;m başlığıyla karşılaşacaksınız. G&uuml;ndem, Vizyon, Vizyon-Eleştiri, Sinestatistik, Sinema Kitaplığımız, Festivallerden, Sinema Arkeolojisi, S&ouml;yleşiler, Sinemanın M&uuml;ziği, Biyografi, Filmografi, Kuram/Yorum, Tekno-Sinema ve Kısa/Belgesel her sayıda yer vereceğimiz başlıklar. Yine her sayıda bir dosya ile karşınıza &ccedil;ıkmayı planlıyoruz. İlk sayı &lsquo;savaş ve sinema&rsquo; adını taşıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sunduğumuz yapı &ouml;zg&uuml;n yazılar kadar &ccedil;evirilere de ku&ccedil;ak a&ccedil;makta. Sekans&rsquo;ı araştırmacı ve d&uuml;zeyli olması a&ccedil;ısından akademik, g&uuml;ndemle ve g&ouml;rsel t&uuml;keticilerle olan ilişkileri bağlamında pop&uuml;ler ve kapsadığı alana sevgiyle yaklaştığı i&ccedil;in sinematografik bir dergi olarak tanımlamak olası. Hangi a&ccedil;ıdan ele alırsanız alın, &ouml;l&ccedil;&uuml; birimimiz nitelik olacak. Sekans yazınsal ve g&ouml;rsel a&ccedil;ıdan doyurucu, bilgiye duyulan gereksinimi karşılama derdinde, yeni g&ouml;r&uuml;ş ve gelişmeler karşısında ılımlı ve tartışmalara a&ccedil;ık bir kimlik taşıyacak bi&ccedil;imde kurgulandı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="line-height: 15.3333px; font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sekans&rsquo;ın sinematografik d&uuml;şlerinizin, d&uuml;ş&uuml;ncelerinizin, &uuml;retiminizin ve duyarlılıklarınız buluşma noktası olmasını ama&ccedil;lıyoruz. Aramıza katılmak i&ccedil;in bunu bir teklif olarak değerlendirmenizi diliyoruz. Sekans ile sinemamız ve yayıncılığımız i&ccedil;in sekanslar kurmak i&ccedil;in artık işimize d&ouml;n&uuml;yoruz.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (54, 'ay-j175', 'sinema-ab', 'Sinema AB', 'Ankara\'da Kültür ve Sanat - Ocak, 2005', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Ankara\'da K&uuml;lt&uuml;r ve Sanat - Ocak, 2005</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Avrupa sineması dendiğinde, akla, sanatsal s&ouml;ylemler ve entelekt&uuml;el bir boyut taşıyan bir sinema gelir ki &ouml;ncelikle Fransa ve İtalya&rsquo;ya vurgu yapan ama arada bir de İngiltere, İspanya veya Almanya&rsquo;ya da dokunduran bir sinema coğrafyasıdır kastedilen. Doğu Avrupa sineması ise &ouml;zg&uuml;n bir Avrupa sineması sunar yıllardır. Duvarlar aşılalı on beş yıl ge&ccedil;ti, yeni yeni dalgalar da beklentiler de boşa &ccedil;ıktı. Doğu Avrupa saman alevleriyle varlığını s&uuml;rd&uuml;rmekte. Devlet yardımı ortadan kalkınca k&uuml;&ccedil;&uuml;k b&uuml;t&ccedil;eli yapımlar bile destek bulamaz oldu. TV d&uuml;nyası olaya karışmasa olay neredeyse t&uuml;kenecek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sinema AB&rsquo;nin patronları, &uuml;rettikleri patates, krem, mayo gibi filmin de bir meta olduğunu ileri s&uuml;ren ABD&rsquo;nin karşısında olduklarını avaz avaz haykırıp, sonra da seyirciden uzak d&uuml;şmemek i&ccedil;in Hollywood &ccedil;ayırlarında otlamayı s&uuml;rd&uuml;r&uuml;yorlar. K&uuml;lt&uuml;rel farkların korunması konusunda her platformda başı &ccedil;eken Fransızlar, ne kadar &ccedil;ene &ccedil;alarlarsa o kadar sanat yaptıklarını d&uuml;ş&uuml;n&uuml;yorlar. İtalyanların kış uykusu kıştan başka mevsimin olmadığı bir kısır d&ouml;ng&uuml; yarattı. Bireysel yaratıcılık &ouml;zg&uuml;rl&uuml;ğ&uuml;, ancak toplumsal g&ouml;zlem i&ccedil;in kullanıldığında değerli sonu&ccedil;lar vermekte. Onlar bunu yaparken en uyduruk filmleri de &uuml;retmeyi s&uuml;rd&uuml;r&uuml;yorlar. B&uuml;y&uuml;k y&ouml;netmenler kuşağını yitirmiş olan AB&rsquo;nin genel olarak i&ccedil;e kapanık ve seyirciden kopuk bir sinema &uuml;rettiği s&ouml;ylenebilir. Auteurist eğilimleriyle tanınan o kuşak kendi auteur seyircisini yaratmayı başarmıştı. G&uuml;n&uuml;m&uuml;z y&ouml;netmen kuşağı ise kendin pişir kendin ye trendinde yuvarlanıp gidiyor. Geveze y&ouml;netmenler kuşağı algı k&ouml;rl&uuml;ğ&uuml;nden sabıkalı seyirciyle didişiyor. Belleksiz kitlelerin karşısına kimlik sorunlarıyla boğuşan y&ouml;netmenler &ccedil;ıkartılıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yazmayan insanın yazının, d&uuml;ş&uuml;nmeyen insanın d&uuml;ş&uuml;ncenin değerini bilmemesi gibi, toplum da kendi k&uuml;lt&uuml;rel değerlerini yaşayamadığı i&ccedil;in k&uuml;lt&uuml;rel emperyalizmi &ouml;nemsemiyor. &Ccedil;&uuml;nk&uuml; yitip gidenin kendisi olduğunu g&ouml;remiyor. K&uuml;lt&uuml;r adamları bu halktan ne&nbsp; bekliyor?&nbsp;<b>Rousseau</b>&rsquo;nun k&ouml;rler memleketindeki şaşıların &ouml;zlendiği yıllar... Şaşılar memleketinde kralın adı ABD.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Altyapısının olmayışı, alternatifsizlik ger&ccedil;eği ve eğitimsizlik gibi nedenlerle se&ccedil;iciliğini ve se&ccedil;kinliğini yitirmiş seyirci tiplemesi, artık iyiden iyiye benimsenir olmuş. Onun se&ccedil;me &ouml;zg&uuml;rl&uuml;ğ&uuml; bile yok. Salonlarda yıllardır aynı filmleri izlemek bile rahatsız etmiyor onları. Diyelim ki salonları kurtardınız, bu seyirciyi oraya nasıl getireceksiniz. Sinema kitlelerin g&ouml;z&uuml;nde &ouml;nce bir meraktı, sonra eğlence oldu. Derken sanat olduğu kabul edildi. Şimdi yeniden eğlence denildi adına ancak kendisi yetmediği i&ccedil;in mısırla t&uuml;ketilir oldu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">AB sinemasının AB dağıtım ağı i&ccedil;inde bile kısıtlı kaldığı d&uuml;ş&uuml;n&uuml;l&uuml;rse, g&uuml;&ccedil;l&uuml; bir AB sinemasında s&ouml;z etmek m&uuml;mk&uuml;n m&uuml;? Ulusal renklerini beş y&uuml;z yıllık bir s&uuml;re&ccedil; i&ccedil;inde ve acı-tatlı rekabetle keskinleştirmiş &uuml;lkelerin filmleri, daha ilk beş on dakika i&ccedil;inde k&uuml;lt&uuml;rel orijinini ele veriyorsa AB sineması nasıl tanımlanacak? Birleşen Avrupa&rsquo;nın birleşemeyen k&uuml;lt&uuml;r&uuml; ve de sinemasının geleceği nasıl olacak? Ekonomik ve politik birleşmenin doğurduğu g&uuml;c&uuml;n k&uuml;lt&uuml;rel farklılıkları koruma konusunda &ccedil;aba sarfetmesini dilemekten başka yapacak bir şey yok gibi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sinematografik ulusal kodlar a&ccedil;ısından bakıldığında ortada AB kodlu bir sinema yok. Umarım olmaz da. Bu ulusal skala korunmalı. Hollywood filmlerinin AB pazarının y&uuml;zde seksenini ele ge&ccedil;irmesi umut kırıcı. Son yirmi yıllık s&uuml;re&ccedil;te, AB&rsquo;li Hollywood seyircisi sayısı aşağı yukarı sabit kalırken, AB sineması AB&rsquo;li seyircisinin y&uuml;zde seksenden fazlasını yitirmiş durumda. Sorun nerede? Sanırım, AB&rsquo;nin kendini her alanda olduğu gibi kitle k&uuml;lt&uuml;r&uuml; konusunda da yenilemekte ge&ccedil; kalmasında. Ortalıkta T&uuml;rk, İngiliz, Alman yapımı Amerikan filmleri dolaşırken zorlu bir s&uuml;recin AB sinemasını beklediğini s&ouml;ylemek zor değil. Kaldı ki AB i&ccedil;in k&uuml;lt&uuml;rel d&uuml;nyası en g&uuml;&ccedil;l&uuml; olduğunu sandığı yerdir. Sinema, bug&uuml;n AB i&ccedil;in uluslararası k&uuml;lt&uuml;r savaşının simgesel olgusudur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">AB medya tartışmalarında imaj &ccedil;&ouml;pl&uuml;ğ&uuml; sorunu teknoloji &ccedil;&ouml;pl&uuml;ğ&uuml; sorununu aşmış durumda. Mesaj yoğunluğundan da &ouml;te sinemanın AB kimliğini ne denli yansıttığı sorunu kafaları kurcalıyor. &Ccedil;&uuml;nk&uuml; k&uuml;lt&uuml;rel kirlilik &ccedil;evre kirliliğinden daha yıkıcı sorunlar doğuruyor. AB, Amerikan k&uuml;lt&uuml;r hegemonyasının karşısına &ccedil;ıkarmak i&ccedil;in entelekt&uuml;el &ccedil;&ouml;pl&uuml;ğ&uuml;nde kendi&nbsp;<b>Bin Laden</b>&rsquo;ini arıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">T&uuml;rkiye Hollywood yalakası y&ouml;netmenlerin en son kuşağını 90&rsquo;larda tanıdı. &Uuml;&ccedil; beş yıla kalmaz, AB ile de onun yalakalar kuşağı işbaşı yapar. Sanat sinemasının T&uuml;rkiye&rsquo;deki bi&ccedil;imi, kişisel bunalım ve takıntı filmleri olarak varlığını s&uuml;rd&uuml;rmekte. Takıl ona, senin de bir takıntın olsun. AB&rsquo;nin ulusal sinemamıza ne kazandıracağını zaman g&ouml;sterecek, ne kaybettireceğini de!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (55, 'ay-j176', 'yeniden-kur-beni', 'Yeniden Kur Beni', 'Ankara\'da Kültür ve Sanat - Kasım, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Ankara\'da K&uuml;lt&uuml;r ve Sanat - Kasım, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b><br /></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir yapıtın kurulma s&uuml;recindeki yapaylık, kendisini sarıp sarmalayan g&uuml;ndelik ger&ccedil;ekle nasıl bir ilişki kurar? Yapıtın kurmacaya dayanan karakteri, sanat&ccedil;ının &ouml;n&uuml;nde dikilen ger&ccedil;ekten ne denli ve nasıl beslenir? Bazı zamanlar &ccedil;ok uzayan bu &ccedil;arpışmalar silsilesi sırasında &ouml;zg&uuml;nl&uuml;ğ&uuml;nden ne denli &ouml;d&uuml;n verir? Bu alışveriş sırasında onu farklı kılan ruhunu sıradanlığa satamaz mı? Kurmacanın d&uuml;nyası yaşamdan ne kadar uzaklaşabilir? Bitip t&uuml;kenmez sorular...</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yapıtların sonu &uuml;zerine olasılıklardan hareket edelim. En k&ouml;t&uuml;s&uuml; silikleşir ve yitip gider: Yenilgi. Veya iki arada bir derede kalır ama oluşumunu tamamlar: Varlık. Ve en g&uuml;zeli, ger&ccedil;eği aşar ve bağımsızlaşır: Yengi. Kalıcılık. &Ouml;zg&uuml;nl&uuml;k. Sanat.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Asıl ilgin&ccedil; olan, sanat&ccedil;ının, bu işkence s&uuml;reci karşısındaki durumudur? S&uuml;reci bir haz kaynağı olarak g&ouml;rebilir. Suskunluğa g&ouml;m&uuml;lerek adımını geri &ccedil;eker, bitmemiş başyapıtlara davetiye &ccedil;ıkarır. Dayanabilirse başarının hazzı d&uuml;nyayı dolaşır. &Ccedil;ıkmazla karşılaştığımızda aradığımız nedir, ilham meleği mi? Sanat&ccedil;ının &ouml;mr&uuml;n&uuml;n b&uuml;y&uuml;k kısmı ilham meleğini aramakla ge&ccedil;iyor ve araya sayısız kelekler giriyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Diğer sanatlarla kıyaslanınca, sinemada meleklerin sayısının azlığı gelişig&uuml;zel bir araştırmayla bile kanıtlanabilir bir ger&ccedil;ektir. Yazının m&uuml;kemmelinin sinemanın m&uuml;kemmeli ile buluştuğu başyapıtların azlığına şaşırmamak gerek. En ilgin&ccedil; buluşmalar, yazarların d&uuml;nyasının sinemada su y&uuml;z&uuml;ne &ccedil;ıkmasıyla ger&ccedil;ekleşiyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Sergei Paradjanov</b>&rsquo;un g&ouml;z&uuml;nden, 18. yy. Ermeni şairi&nbsp;<b>Sayat Nova</b>&rsquo;nın dinin, sanatın, insanın, g&uuml;ncel olayların, g&uuml;zelliğin ve en &ccedil;ok da aşkın karşısında nasıl durduğunun kurmaca &ouml;yk&uuml;s&uuml;n&uuml; anlatır,&nbsp;<b><i>Narın Rengi</i></b>. Ardından&nbsp;<b>Joseph Losey</b>&rsquo;in&nbsp;<b><i>Romantik İngiliz Kadın</i></b>&rsquo;ı gelir ki kıskan&ccedil;lık fantezileriyle beslenen bir kurmaca olay &ouml;rg&uuml;s&uuml;d&uuml;r karşımızdaki.&nbsp;<b>Andre Belvaux&nbsp;<i>Benvenuta</i></b>&rsquo;da alışkanlıklarımızı kırar ve anımsanan anlar &uuml;zerine kurulu d&uuml;şlere ortak eder bizi. Yeniden kurmanın, ge&ccedil;mişin yaşanılan ana d&uuml;şen g&ouml;lgesiyle tırmanan huzursuzluğunu yansıtan ilk modernist &ouml;rnektir belki de. Daha yakına gelecek olursak,&nbsp;<b>Joel Coen</b>&rsquo;in&nbsp;<b><i>Barton Fink</i></b>&rsquo;inde, yapıtı kurma s&uuml;recini bi&ccedil;imlendiren en &ouml;nemli etmenin yazarın beynindeki labirent olduğunu;&nbsp;<b>Michael Radford</b>&rsquo;un&nbsp;<b><i>Postacı</i></b>&rsquo;sında ise, aşk gibi herkese a&ccedil;ık olan alanlara eğilen kurmacanın, bizleri kendi derdine ortak etmek konusundaki yetkinliğini &ouml;ğreniriz. Son saptama,&nbsp;<b><i>Havuz&nbsp;</i></b>ile&nbsp;<b>Fran&ccedil;ois Ozon</b>&rsquo;dan gelir: Sanat&ccedil;ı kurduğu yapıtla ger&ccedil;ek d&uuml;nya arasında kalmak istemediğinde bir aracı kullanabilir. B&ouml;ylece, kurulan &ouml;yk&uuml;, kendi i&ccedil;inde kurduğu d&uuml;ş&uuml; bize yansıtır ki bu sonuncusu, sanat&ccedil;ının asıl hedefi, takıntısıdır aslında. Sanatın kurmaca eylemini tartışmak i&ccedil;in en b&uuml;y&uuml;k olanaklara sahip olan dilin adı sinemadır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ve final... Cannes FF&rsquo;nin bence en &ouml;nemli &ouml;d&uuml;l&uuml; olan Altın Kamera, 2003 yılında Danimarka&rsquo;dan&nbsp;<b>Christoffer Boe</b>&rsquo;nın&nbsp;<b>Reconstruction</b>&nbsp;(Yeniden Sev Beni) filmine gider. Her yazar, kariyerinin a&ccedil;mazlarla karşılaştığı d&ouml;nemlerinde yeniden yapılanmaya gereksinim duyar. Yaratım s&uuml;recine en benzer, en yakın duran olgu aşk değil de nedir? Bir başka s&ouml;ylemle, bu s&uuml;reci tetikleyen en g&uuml;&ccedil;l&uuml; olgudur aşk. Deneyimli yazarımız, aşkın tarifini yeniden yapmasına neden olan kadını, kurduğu yapay d&uuml;nyanın d&uuml;şleminde &ouml;zg&uuml;r bırakarak, onu &ccedil;etin bir sınavdan ge&ccedil;irir. Sevdiği kadına ger&ccedil;ek ve kurmaca d&uuml;nyasında geniş bir hareket serbestisi sağlar. Onu zora s&uuml;rer. Kendisine de, karşısına ger&ccedil;ek hayatta &ccedil;ıksa, kazanma şansının zayıf olduğu bir rakip yaratır ve esin kaynağı sevgiliyi onun karşısına &ccedil;ıkarır. Ancak son anda, onun kendisinin olduğunu kanıtlamak istercesine ger&ccedil;eğe d&ouml;ner. Bu oyunun kurallarını o belirlemiştir. Bunu herkes bilmelidir. B&ouml;ylece, yaşamdan aldığı kadını, kurmacasında dilediğince kullandıktan sonra, yeniden yaşama bırakır. Finale kendi adını yazdırmalıdır, kaybeden o olmamalıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Rakibinin sıradan bir kadın olan sevgilisi ile kendisinin b&uuml;y&uuml;l&uuml; bir &ccedil;ekicilikle kutsanan sevgilisinin aynı kadın olması rastlantı değildir. Yazarın kadınının b&ouml;ylesine farklı durmasından daha doğal ne olabilir? Yazar yarattığı ve aşığı olduğu kadını paylaşmaya razı değildir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Filmin kendisinden &ccedil;ok, yazarın bilin&ccedil; ve bilin&ccedil;altını y&uuml;z y&uuml;ze getiren o bildik karmaşa ortamına tanıklık etmek b&uuml;y&uuml;k bir keyifti. Bu enerjik ve yıpratıcı s&uuml;re&ccedil; tam anlamıyla b&ouml;yle işliyor. Zaman kaymaları, bakış a&ccedil;ısındaki &ccedil;eşitlilik, geri d&ouml;n&uuml;şler ve ka&ccedil;ınılmaz yinelemeler işin doğasında var ve unutmayalım ki yazarın bi&ccedil;imlendirdiği yapıtın i&ccedil;inde biz de yolculuk yapıyoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sevgiliyle birlikte gelen romantizm, yazarlığın kolay yara alan tenine &ccedil;abuk işler. Aşkın psikolojik d&uuml;zlemde yarattığı dalgalanmalar dramı besler. Herkes kendi derdini, yazar herkesin derdini yaşar. T&uuml;kenir ama her t&uuml;kenişin ardından yeniden gelmelidir. Aşk yaratma tutkusunun bir g&ouml;stergesi olsa gerek. Az olanla yetinmek istemem, aşkı sana bırakıyorum. Sen, benim i&ccedil;in en iyi olanı yap, yeniden kur beni!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (56, 'ay-j177', 'milcho-manchevski-ile-yagmurdan-once', 'Milcho Manchevski ile Yağmurdan Önce…', 'Kinorama 9, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 9, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yeşim Aslan</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">1959 yılınsa &Uuml;sk&uuml;p&rsquo;de doğan&nbsp;<b>Milcho Manchevski</b>, belgesel, deneysel, m&uuml;zik videosu ve reklam t&uuml;r&uuml;nde 50&rsquo;nin &uuml;zerinde kısa film &ccedil;ekti&hellip;&nbsp; Ger&ccedil;ek sinema tutkunları iyi bilirler, T&uuml;rkiye&rsquo;de ve d&uuml;nyada en iyi filmler arasına giren, senaristliğini ve y&ouml;netmenliğini yaptığı&nbsp;<b><i>Before the Rain</i></b>&nbsp;(Yağmurdan &Ouml;nce) (1994) ile uluslararası festivallerde 30 &ouml;d&uuml;l kazandı, 1995 yılında en iyi yabancı film dalında oscara aday g&ouml;sterildi. Venedik Film Festivali&rsquo;nin a&ccedil;ılışında g&ouml;sterilen 2001 yapımı&nbsp;<b><i>Dust</i></b>-Toz ise &ccedil;ok tartışıldı. &ldquo;T&uuml;rk d&uuml;şmanı&rdquo; etiketi yapıştırılan film, T&uuml;rkiye&rsquo;de hi&ccedil; g&ouml;sterime girmedi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Milcho Manchevski</b>&nbsp;ile 23 Temmuz 2004 tarihinde saat 08.00&rsquo;de tenha Beyoğlu&rsquo;nda y&uuml;r&uuml;me şansını yakaladım. Balkan savaşlarından, bug&uuml;n&uuml;n sinemasına, gen&ccedil; sinemacılardan Hollywood sinemasına ve kendisine yapılan haksız eleştirilere kadar geniş bir yelpazede uzun bir s&ouml;yleşi yaptık.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Onun yağmuru &ccedil;oktan dinmiş olsa da, d&uuml;nya hep yeni yağmurlara gebe&hellip;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&Uuml;sk&uuml;p&rsquo;de liseden mezun olmadan &ouml;nce bir &ccedil;ok kısa film &ccedil;ekmişsiniz. O zamanlarda film &ccedil;ekmek, yaşamınıza sinemayı sokmak konusunda &ccedil;ok gen&ccedil; ve kararlı bir farkındalık gerektiriyor. İlk kısa filminizi &ccedil;ekmeden &ouml;nce tam olarak ne d&uuml;ş&uuml;nd&uuml;n&uuml;z? Bu kararlılığın nedeni neydi?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Liseden mezun olmadan &ouml;nce film okuluna girebilmek i&ccedil;in kendime bir portf&ouml;y oluşturmak &uuml;zere bazı kısa filmler &ccedil;ektim. O zamanlar vaktimi daha &ccedil;ok yazarak ge&ccedil;iriyordum. Yazmayı seviyordum, hala da yazmayı film &ccedil;ekmekten daha &ccedil;ok seviyorum. Yazarken kendimi daha rahat ve g&uuml;venli hissediyorum. Film &ccedil;ekmeye başlamamamın nedeni yazılarımı geliştirmek i&ccedil;in verdiğim bir karardı. Aslında yazılarımı daha &ccedil;ok insana ulaştırmanın yolunu arıyordum. Sinemayı bu y&uuml;zden se&ccedil;tim &ccedil;&uuml;nk&uuml; bir &ccedil;ok insan okumuyor. &Ouml;zellikle Makedonya&rsquo;da yazıyorsanız &ccedil;ok fazla insana ulaşma şansınız yok &ccedil;&uuml;nk&uuml; Makedonca k&uuml;&ccedil;&uuml;k bir dil. Ayrıca o zamanlar lisedeydim. Bir&ccedil;ok profesyonel dergide yazıyordum. Daha 19 yaşındayken yaklaşık 200 makalem yayınlanmıştı. İşte bu zamanlarda okuldaki profes&ouml;r&uuml;m, ne yapacağımı sordu. Ben de bir yazar, gazeteci olacağımı s&ouml;yledim. Onun eşi de gazeteciydi ve bana gazeteciliğin i&ccedil;inde bulunduğu durumu g&ouml;rm&uuml;yor musun dedi. Sans&uuml;rden bahsediyordu. Edit&ouml;rler yazınızı değiştirebilirler, başlığı değiştirebilirler, anlamı değiştirebilirler. Yazmanıza izin verilmeyen konular vardır. Profes&ouml;r&uuml;m&uuml;n haklı olduğunu d&uuml;ş&uuml;nd&uuml;m. Belki de gazetecilik &ccedil;ok sınırlanan bir alandı. Bana neden okulda sahne oyunları yazmadığımı sordu. Ben de evet iyi fikir diye d&uuml;ş&uuml;nd&uuml;m. Yani şans eseri gelişti. Şans eseri verilmiş bir karar da olsa, daha sonra bu konuda &ccedil;ok ciddi &ccedil;alışmaya başladım. Bu kadar uzun yıllardan sonra, filmin 19. y&uuml;zyıl romanı olarak bir hikaye anlatma aracı olduğunu fark ettim. &Ouml;yk&uuml; yapısı konusunda kendimi hep rahat hissettim. Film &ccedil;ekerken bana yardım eden de buydu. Jenerikte adı senarist olarak ge&ccedil;mese bile y&ouml;netmen ger&ccedil;ek bir hikaye anlatıcısıdır. &Ccedil;&uuml;nk&uuml; hikayeyi anlatmak i&ccedil;in sadece kelimeleri değil, bir &ccedil;ok şeyi kullanırsınız.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Gazetecilikteki sans&uuml;rden bahsettiniz. Aynı şey film sekt&ouml;r&uuml;nde de olmuyor mu? Fark ne?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ccedil;ok fark yok! Sans&uuml;r&uuml;n ve diktat&ouml;r&uuml;n d&uuml;ş&uuml;ncesi kendisini g&ouml;stermek i&ccedil;in her zaman bir &ccedil;ok yol bulacaktır. Film yapımında bunu &ccedil;ok belirgin hissedersiniz. Bunun k&ouml;klerinde diğer insanları kontrol etme ihtiyacı yatar. Sanırım bu durum, kendileri ile ilgili iyi şeyler hissetmeyen insanlara kadar gidiyor. Kendilerine kızdıkları i&ccedil;in başkalarını kontrol altına alıyorlar. Ben, filmlerim başka &uuml;lkelerde g&ouml;sterilmeye başlandığında sans&uuml;rle karşılaştım. Hayatımdaki en &ouml;nemli şeylerden biri, sans&uuml;rle savaşmak. Ama bu savaşı &ccedil;alışmalarımla s&uuml;rd&uuml;rmek. Eğer bu hi&ccedil; film yapmamak, hi&ccedil;bir şey &uuml;retmemekse, sans&uuml;rle savaşmak i&ccedil;in benim se&ccedil;eceğim yol bu olacaktır. &Ccedil;ok ilgin&ccedil;tir, sans&uuml;r i&ccedil;in &ouml;nemli olan konular değildir. &Ccedil;oğu zaman diğer insanları bastırmak i&ccedil;in yine diğer insanların etki g&uuml;c&uuml; kullanılır. Eğer kendi d&uuml;ş&uuml;ncelerini size başka insanlar aracılığıyla dayatıyorlarsa, konu hi&ccedil; &ouml;nemli değildir. Tarihsel olarak bu genelde din konusunda olmuştur ama her zaman din konusunda olmak zorunda değildir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Aradan yıllar ge&ccedil;ti. D&ouml;n&uuml;p o g&uuml;nlere baktığınızda, bu kararınızı nasıl değerlendiriyorsunuz?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hi&ccedil;bir şeyi değiştiremem. Bu nedenle kendimi değerlendirmek i&ccedil;in ge&ccedil;mişe d&ouml;n&uuml;p bakmıyorum. En azından bilin&ccedil;li olarak yapmıyorum bunu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>1995 yılında Cineaste Dergisi&rsquo;nde yayınlanan s&ouml;yleşinizde kendinizi ne bir Balkan ne de orada yaşamanıza rağmen bir Amerikalı gibi hissetmediğinizi s&ouml;yl&uuml;yorsunuz. Amerikalı hissetmemeniz anlaşılır bir şey. Ama&nbsp;<i>Before The Rain</i>&rsquo;de de g&ouml;r&uuml;ld&uuml;ğ&uuml; gibi Makedonya&rsquo;ya karşı duyarlısınız. Makedonya&rsquo;ya dışarıdan bakan bir film değil&nbsp;<i>Before The Rain</i>. Bu bir film hilesi miydi, yoksa aslında Makedonya&rsquo;yı y&uuml;reğinizde hissediyor musunuz?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Makedonya i&ccedil;in &ccedil;ok g&uuml;&ccedil;l&uuml; duygular hissediyorum. Bunun birka&ccedil; nedeni var.&nbsp; Birincisi, orada yaşayan insanlar konusunda &ccedil;ok g&uuml;&ccedil;l&uuml; hislerim var. Sevdiğim bir &ccedil;ok insan orada yaşıyor. İkincisi ise, fark ettiğim şeyler. Bunlar; g&ouml;r&uuml;nt&uuml;ler, yerler, kelimeler, y&uuml;zler&hellip; Bunlar iyi ya da k&ouml;t&uuml; olduklar i&ccedil;in değil, sadece ben fark ettiğim i&ccedil;in benim i&ccedil;in &ouml;nemli olan şeyler. Nesnel olarak, kendi &uuml;lkenizin daha iyi olduğunu s&ouml;yleyemezsiniz. &Ccedil;oğu zaman, ger&ccedil;ekten &ccedil;ok k&ouml;t&uuml;, &ccedil;irkin yerlerden gelen insanlar kendi &uuml;lkeleri i&ccedil;in &ccedil;ok kuvvetli duygular besleyebiliyorlar. Ben bu durumun farkındalıkla ilgili olduğunu d&uuml;ş&uuml;n&uuml;yorum. 10 ya da 20 yıl &ouml;nce deneyimlediğiniz bir şeyi yeniden fark ettiğinizde, &ccedil;ok g&uuml;zel bir bağlantı kuruluyor beyninizde. Sanırım bununla da ilgisi var. Bazen kendimi dışarıdan g&ouml;zlemliyorum. Makedonyalı ve Balkan yurttaşlarımı g&ouml;zlemliyorum. Ve kendimi d&uuml;ş&uuml;nd&uuml;ğ&uuml;m, yaptığım şeylerde Makedon ya da Balkan bir insandan farklı g&ouml;r&uuml;yorum. Beden dilimin, konuşma tonumun, etnik algımın &ccedil;ok farklı olduğunu g&ouml;r&uuml;yorum. Aslında daha da &ouml;nemlisi ben genellemelere karşıyım. İnsanlar sizi belirgin bir kategoriye koymaya &ccedil;alışıyorlar. Eğer birisini Alman, Yunanlı&nbsp; ya da İskandinav olarak genellerseniz, bu insanı ırk&ccedil;ılığınızın bir sembol&uuml; haline getirirsiniz. Fransa&rsquo;da bir eleştirmen bana&nbsp;<b><i>Before The Rain</i></b>&rsquo;in bir doğu Avrupa filmi gibi g&ouml;r&uuml;nmediğini s&ouml;yledi. Bunun bir kompliman olup olmadığını anlayamadım. Ama kesinlikle ırk&ccedil;ılık kokuyordu. Bir doğu Avrupa filmi nedir?&nbsp;<b>Milos Forman</b>&nbsp;doğu Avrupalı mıdır?&nbsp;<b>Roman Polanski</b>&nbsp;Doğu Avrupalı mıdır? Ya da sadece&nbsp;<b>Krzysztof Kieslowski&nbsp;</b>Doğu Avrupalı mıdır?&nbsp;<b>Dusan Makavejev</b>&nbsp;Doğu Avrupalı mıdır? &Ouml;rneğin ben kişisel olarak&nbsp;<b>Kieslowski&nbsp;</b>ve&nbsp;<b>Makavejev</b>&nbsp;arasında bir benzerlik g&ouml;rm&uuml;yorum. Yani birisi doğu Avrupa estetiğinden bahsediyorsa, benim filmimin nasıl olması gerektiği konusundaki beklentisi ırk&ccedil;ıdır. Filmi, bir film olarak izleyip sevmelisiniz, bir doğu Avrupa filminin nasıl olması gerektiğine dair beklentilerinize g&ouml;re değil. İki filmimde de, &ouml;zellikle&nbsp;<b><i>Dust</i></b>&rsquo;da, klişelerden ka&ccedil;ındım. Yeni şeyler, arketipler kullanmaya &ouml;zen g&ouml;sterdim. Sonu&ccedil; olarak, klişeleri reddeden bir film yapmalısınız. B&uuml;y&uuml;k ihtimalle &ccedil;alışmanıza karşı &ccedil;ok b&uuml;y&uuml;k tepkiler gelecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Savaş muhabiri Alexander&rsquo;ın &ouml;yk&uuml;s&uuml; (<i>Before the Rain</i>) sizin yaşantınızdan esintiler taşıyor mu?</b>&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">A&ccedil;ık&ccedil;ası bazı benzerlikler var, ama ben bunları bilin&ccedil;li olarak yapmadım. Biliyorsunuz orada benim de yaşadığım gibi, uzun yıllardan sonra bir eve d&ouml;n&uuml;ş duygusu var. Ama&nbsp;<i>Alexander</i>&rsquo;ın &ouml;yk&uuml;s&uuml; ile benim &ouml;yk&uuml;m birbirinden &ccedil;ok farklı. Eğer d&uuml;r&uuml;st bir &ccedil;alışma yapıyorsanız, filmdeki her karakter, her g&uuml;&ccedil;l&uuml; duygu sizin daha &ouml;nceden deneyimlediğiniz bir şeye dayanır.&nbsp; Karakterler sizin kim olduğunuza dair bazı ipu&ccedil;ları i&ccedil;erir. Hayallerinizdeki karakterler, sizin yansımalarınızdır. Ama orada bilin&ccedil;li bir &ccedil;aba yoktu. Akt&ouml;rle &ccedil;alışırken, onun babam gibi y&uuml;r&uuml;d&uuml;ğ&uuml;n&uuml;, babam gibi konuştuğunu fark ettim. Fazla konuşmuyordu. Karakterde &ccedil;ok fazla kişisel izler vardı. Ama &ouml;yk&uuml; tamamen kurgusaldı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Etnik, dini ve k&uuml;lt&uuml;rel farklılıkların aşkın ve dostluğun &ouml;n&uuml;nde aşılamayacak denli k&ouml;kl&uuml; engeller yarattığını d&uuml;ş&uuml;n&uuml;yor musunuz?&nbsp;<i>Before The Rain</i>&rsquo;deki kadar acımasız ve karanlık bir gelecek mi uzanıyor &ouml;n&uuml;m&uuml;zde?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu kişiye bağlı. Bazı insanlar diğer insanlardan nefret etmek i&ccedil;in etnik ve dini farklılığı bir &ouml;z&uuml;r gibi kullanıyorlar. Eğer bu &ouml;zre sahip değillerse, farklı bir neden bulacaklar. Yani ben bunun etnik farklılıktan kaynaklandığını d&uuml;ş&uuml;nm&uuml;yorum. Bu sadece nefret etme ihtiyacı&hellip;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>Dust</i></b><b>&rsquo;da &ouml;yk&uuml; Osmanlı İmparatorluğu&rsquo;nun Balkanları terk ettiği yıllarda başlayıp New York&rsquo;da sona eriyor. Bu durum b&ouml;lge &uuml;zerindeki politik hakimiyetin el değiştirmesine bir g&ouml;nderme mi?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hayır,&nbsp;<b><i>Dust&nbsp;</i></b>bir tarih dersi değil. Tarih, coğrafya gibi konularda insanlara bir şey &ouml;ğretmek i&ccedil;in yapılan filmler sanat filmleri değildir. Bu t&uuml;r filmler CNN&rsquo;e ya da NationalGeoraphic&rsquo;e aittir, sanat sinemasına değil. Ben insanların i&ccedil;inde bulundukları durumlarla, insan kalbiyle, ruhuyla ilgileniyorum. İnsanların nasıl sevdikleriyle, nasıl acı &ccedil;ektikleriyle ilgileniyorum. Ve eğer Osmanlı İmparatorluğu&rsquo;nda insanların aşk y&uuml;z&uuml;nden acı &ccedil;ektikleri bir durum varsa, filmi Osmanlı İmparatorluğu&rsquo;nda &ccedil;ekerim. Eğer antik Mısır&rsquo;da olursa, filmi antik Mısır&rsquo;da &ccedil;ekerim. Eğer gelecekte oluyorsa, filmi gelecekte &ccedil;ekerim. Bu film bir tarih dersi değildir.&nbsp;<b><i>Before the Rain</i></b>&nbsp;de Balkan savaşı hakkında bir tarih dersi değildi. Balkan savaşı konusunda &ccedil;ekilen ger&ccedil;ek bir film&nbsp;<b><i>Before The Rain&rsquo;</i></b>den &ccedil;ok daha farklı olurdu.&nbsp;<b><i>Before the Rain</i></b>&nbsp;&uuml;&ccedil; aşk hikayesini anlatıyordu. Şimdi,&nbsp;<b><i>Dust&nbsp;</i></b>bir tarih dersi değil. Ama filmi tarihin belirli bir b&ouml;l&uuml;m&uuml;n&uuml; baz alarak &ccedil;ekmeye karar verdiğimiz zaman, kendimi tarihsel olayların doğruluğunu yansıtmak konusunda sorumlu hissettim. &Ouml;nce&nbsp;<b><i>Dust</i></b>, aynı karakterler ve aynı hikaye ile Meksika&rsquo;da &ccedil;ekilecekti. Meksika devrimi ve Makedonya komitesi&rsquo;nin Osmanlı İmparatorluğu&rsquo;na karşı verdiği savaş arasında paralellik vardı. İnsan ilişkileri hemen hemen aynıydı. Filmi Meksika&rsquo;da &ccedil;ekmeye karar verdiğimizde tarihsel olarak b&uuml;t&uuml;n araştırmaları yaptım. Filmin &ccedil;ekimini Makedonya&rsquo;ya kaydırdığımızda da tarihsel olarak bir hata yapılmaması i&ccedil;in d&ouml;nemin Amerikan vahşi batısı, Osmanlı İmparatorluğu ve Makedonya hakkında 160 kitap ve makale okudum. Bu makale ve kitapların &ccedil;oğu o d&ouml;nemde yazılmıştı. İlgin&ccedil;tir, film Venedik Film Festivali&rsquo;nin a&ccedil;ılışında g&ouml;sterildiğinde &ccedil;ok tartışmalar oldu. Bir &ccedil;ok insan&nbsp;<b><i>Dust</i></b>&rsquo;da Makedonya&rsquo;nın &ccedil;ağdaş savaşının metaforunu g&ouml;rd&uuml;. Eğer bir g&uuml;n bu filmi izleme şansınız olursa, konunun bu olmadığını siz de g&ouml;receksiniz. Umuyorum T&uuml;rk seyircisi bir g&uuml;n&nbsp;<b><i>Dust</i></b>&rsquo;ı izleme ve ne d&uuml;ş&uuml;nmeleri gerektiğini s&ouml;yleyen bir sans&uuml;r olmaksızın yorumlama şansını elde eder. Bir &ccedil;ok eleştirmen, filmi nasıl g&ouml;rmek istedilerse &ouml;yle g&ouml;rd&uuml;ler. B&ouml;ylesine agresif bir s&uuml;r&uuml; mantığı karşısında hayrete d&uuml;şt&uuml;m. &Ouml;ncelikle s&ouml;ylemeliyim bu filmi &ccedil;ekmek yedi yılımı aldı. Geleceğe bakıp yedi yıl &ouml;nceden Makedonya savaşı hakkında bir film yapamazdım. Film Makedonya savaşı sırasında &ccedil;ıktı. Ama zaten &ouml;nceki yedi yıl boyunca yapılıyordu. Filmde bunun bir metafor olduğunu s&ouml;yleyen hi&ccedil;bir şey yok. Yani burada kendi fikirlerini ve ırk&ccedil;ılıklarını film aracılığıyla g&ouml;stermek isteyen insanlar vardı. İngiliz bir eleştirmen, filmde T&uuml;rk ordusunun g&ouml;steriliş bi&ccedil;imi nedeniyle, filmin T&uuml;rkiye karşıtı olduğunu s&ouml;yledi.&nbsp; O an, sorusunu y&uuml;celtmemek i&ccedil;in cevap vermeye bile gerek g&ouml;rmedim &ccedil;&uuml;nk&uuml; bunun doğru olmadığı filmde son derece a&ccedil;ıktı. İngiliz eleştirmenin &ccedil;ok farklı bir g&uuml;ndemi vardı. Filmi yapan İngiliz şirkete karşıydı. &Ccedil;ok sonra aynı kişiyi Kuzey İrlanda&rsquo;da ırk&ccedil;ı faaliyetlere katılırken g&ouml;rd&uuml;m.&nbsp; Yani o aslında kendi ırk&ccedil;ılığını g&ouml;stermeye &ccedil;alışıyordu.&nbsp; Eğer&nbsp;<b><i>Dust</i>&rsquo;</b>ı izlerseniz, T&uuml;rkiye&rsquo;nin değil, ordunun betimlemesini g&ouml;r&uuml;rs&uuml;n&uuml;z. Yani eğer betimlenen askerlerin geri zekalı olduğunu g&ouml;r&uuml;rseniz, bunun nedeni orduların yaptığı gibi &ouml;ld&uuml;rmenin mantığının geri zekalıca olduğudur. İkicisi, orada g&ouml;sterilen T&uuml;rk ordusu değil, Osmanlı ordusudur. Eleştirmenin bilmediği, Osmanlı ordusunda T&uuml;rklerin, Arnavutların, M&uuml;sl&uuml;man Makedonyalıların vs. olduğuydu. &Uuml;&ccedil;&uuml;nc&uuml;s&uuml;, filmde sadece Osmanlı ordusu vahşi olarak g&ouml;sterilmiyor. Makedonya Komitesi (gerillaları), Arnavut ve Yunan &ccedil;eteleri, Amerikan kovboyları, yani elinde silah olan herkes vahşi olarak g&ouml;steriliyor. Sadece belli bir grup insanın vahşi olabileceği fikri başlıbaşına ırk&ccedil;ılıktır. Sonu&ccedil; olarak,&nbsp;<b><i>Dust&nbsp;</i></b>bir tarih dersi değil ama tarih &uuml;zerine kurulu bir filmdir. Filmde kullanılan fotoğraflar, &ouml;rneğin Osmanlı askerlerinin kesik kafalarla poz verdikleri fotoğraflar ger&ccedil;ek fotoğraflardı. Osmanlı ordusunun vahşi bir ordu olduğu ger&ccedil;eğiyle y&uuml;zleşilmesi gerek. Sivilleri &ouml;ld&uuml;r&uuml;yorlardı, k&ouml;yleri yakıyorlardı, tecav&uuml;z ediyorlardı. Bunların hepsi belgelenmiş. Bir &ccedil;ok ordu bunu yaptı, hala da yapıyorlar&hellip; Balkan savaşları sırasında Yunan, Bulgar ve Sırp orduları da aynı şeyi yaptılar ve bunlar da belgelendi. T&uuml;m bunların inkar edilmesi, ge&ccedil;mişteki tutumların d&uuml;zeltilmesi i&ccedil;in şuanda hi&ccedil;bir şey yapılamamasının tarihsel nedeni. &ldquo;Tamam, bunlar oldu, şimdi ben bunları kınıyorum ve şu anda ben yapmıyorum&rdquo; demek ilerlemenin tek yolu. Almanya bu duruma &ccedil;ok g&uuml;zel bir &ouml;rnek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Avrupa gibi tarafsızlık komedisini oynadığınızda g&ouml;rmezden geldiğiniz şiddetin g&uuml;c&uuml;nden yana tavır alıyorsunuz. Taraf olduğunuzda şiddetin i&ccedil;ine d&uuml;ş&uuml;yorsunuz. Hayat varoluş&ccedil;u bir paradoks mu?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bilmiyorum. Politikada tarafsızlık yoktur. İnsanlar tarafsızlarmış gibi davranırlar. Birey olarak, felsefeci olarak belki tarafsız davranabilirsiniz ama politikanın doğası sizin ger&ccedil;ekten tarafsız olmanıza izin vermez. Aslında Avrupa da tarafsız değildi. Avrupa da dahil oldu. Yugoslavya&rsquo;nın dağılışını abarttılar. Almanlar, Fransızlar, İngilizler, Yunanlılar, her biri Birleşik Avrupa&rsquo;ya ait olmayan, kendi ayrı g&uuml;ndemlerine sahiplerdi. Tabi ki savaşı Avrupa yaratmadı. Size olan her şey sizin sorumluluğunuzdur. Ama Avrupa&rsquo;lı politikacılar Yugoslavya&rsquo;nın dağılışı sırasında katıldıkları ve sonra kendi hareketlerinin sonu&ccedil;ları &ouml;l&uuml;mc&uuml;l olmaya başladığı zaman ortadan kayboldukları i&ccedil;in sorumlular.</span></p>', 195, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (57, 'ay-j178', 'yalnizca-gercek', 'Yalnızca Gerçek', 'Kinorama 7, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 7, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Louis Marcorelles</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&Ccedil;eviren: Burak Benk</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Araştırmaya kalktığınızda hakkında eli y&uuml;z&uuml; d&uuml;zg&uuml;n hemen hi&ccedil;bir yazıya ulaşamadığınız, 60&rsquo;lı yılların sonunda efsaneleşme aşamasına gelerek neredeyse unutulmaya oynayan Sinema-Ger&ccedil;ek (Cinema-Verite) akımı bir belgesel sinema akımıdır. Bu yazı, akımın hemen b&uuml;t&uuml;n k&ouml;kenlerinin temsilcilerinin bir araya geldiği bir buluşmanın &ouml;yk&uuml;s&uuml;n&uuml; anlatmaktadır. Dergimiz unutulmaya ve silinmeye karşı bir eylem olarak, Sightand Sound dergisinin Yaz-1963 sayısında yayınlanan bu yazının sizlerle buluşmasını sağlamayı bir g&ouml;rev olarak g&ouml;rmektedir. Akımlarla ilgili herhangi bir kitapta adı bile ge&ccedil;meyen bu akımın &ouml;nemini, tırmanışta olduğu ve kendine yeni anlatım formları aradığı bir d&ouml;nemde verdiği bazı yapıtlar aracılığıyla a&ccedil;ığa vuran bu yazı, d&ouml;neminin &ccedil;ok y&ouml;nl&uuml; ve y&ouml;netmenin &ouml;zg&uuml;nl&uuml;ğ&uuml;n&uuml; kutsayan anlayışını ortaya &ccedil;ıkarması a&ccedil;ısından bir kaynak niteliği taşımaktadır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Birka&ccedil; ay &ouml;nce Lyons&rsquo;ta ger&ccedil;ekleşen &uuml;&ccedil; g&uuml;nl&uuml;k bir konferans, son g&uuml;nlerdeki herhangi bir sinema deneyimi kadar inanılmaz derecede kışkırtıcıydı. RTF (radyo ve televizyon) b&uuml;nyesindeki Araştırma Servisi&rsquo;nin yol g&ouml;stericisi ve bir&nbsp;<i>musique concrete</i>&nbsp;d&uuml;şk&uuml;n&uuml; olan&nbsp;<b>Pierre Schaeffer</b>, olduk&ccedil;a aceleyle isimlendirilmiş g&uuml;ncel bir film hareketi olan&nbsp;<i>cinema-verite</i>&rsquo;in &ouml;nde gelen temsilcilerini Lyons&rsquo;ta bir araya getirmişti. ABD&rsquo;den&nbsp;<b>Robert Drew</b>,&nbsp;<b>Richard Leacock</b>,&nbsp;<b>Albert</b>&nbsp;ve&nbsp;<b>David Maysles</b>&nbsp;kardeşler; Kanada&rsquo;dan&nbsp;<b>Michel Brault</b>; Fransa&rsquo;dan&nbsp;<b>Edgar Morin</b>,&nbsp;<b>Jean Rouch</b>&nbsp;ve&nbsp;<b>Mario Ruspoli</b>&nbsp;gelmişti.&nbsp;<b>JorisIvens</b>&nbsp;ve&nbsp;<b>Georges Rouquier</b>&nbsp;de g&ouml;rkemli ge&ccedil;mişle ilişki kurmak i&ccedil;in oradaydı. İngiltere&rsquo;de &ccedil;alışırken&nbsp;<b>Nice Time</b>&rsquo;ı yapan ama şimdilerde &ccedil;alışmalarının t&uuml;m&uuml;n&uuml; kendi &uuml;lkeleri olan İsvi&ccedil;re&rsquo;de ger&ccedil;ekleştiren&nbsp;<b>Claude Goretta</b>&nbsp;ve&nbsp;<b>AlainTanner</b>,&nbsp;<i>&Ouml;zg&uuml;r Sinema</i>&rsquo;yla ilgili bağlantıyı sağladı; Godard ve Truffaut&rsquo;nun kameramanı&nbsp;<b>Raoul Coutard</b>&nbsp;ise bizlere&nbsp;<i>Yeni Dalga</i>&rsquo;yı hatırlatmak i&ccedil;in gelmişti. Bir&ccedil;ok teknik uzman ve ara&ccedil;-gere&ccedil; &uuml;reticisi arasında Nagra kayıt-cihazının yaratıcısı İsvi&ccedil;reli m&uuml;hendis&nbsp;<b>Kudelski</b>&nbsp;ve kendi adını taşıyan ultra-hafif kamerayı tasarlayan Fransız&nbsp;<b>Andre Coutant</b>&nbsp;da Lyons&rsquo;da bulunuyordu.&nbsp;<b>Richard Leacock</b>&nbsp;ve&nbsp;<b>Albert Maysles</b>&nbsp;de kendi &ouml;zel kameralarını yanlarında getirmişlerdi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu konferans, hem yeni sinematik tekniklerin evriminde televizyonun oynadığı temel rol&uuml;, hem de bu tekniklerin yol a&ccedil;tığı estetik sonu&ccedil;ları &ccedil;ıkarsamada televizyonun g&ouml;sterdiği başarısızlığı ortaya koyuyordu. Bu &ccedil;eşit bir işin Fransız televizyonunda yapıldığını g&ouml;rmek &ouml;zellikle keyif ka&ccedil;ırıcıydı ve insanların ekrana &ccedil;ıkıp konuşmasının ger&ccedil;eğin t&uuml;m&uuml;yle ortaya &ccedil;ıkmasına yeteceği gibi basit bir d&uuml;ş&uuml;nceye dayanan bu anlamsız TV gevezelikleri karşısında&nbsp;<b>Leacock</b>&rsquo;un tahamm&uuml;ls&uuml;zl&uuml;ğ&uuml; anlaşılır bir hal alıyordu. Burada sinemanın ger&ccedil;ek işi ve dinamizmi bir hi&ccedil;e indirgeniyor ve sahte bir entelekt&uuml;el y&uuml;zeyin altında entelekt&uuml;el tembellik zafer kazanıyordu. Bu Fransız televizyon y&ouml;netmenlerine karşı adil olabilmek i&ccedil;in, onların hala &ccedil;oğunlukla ağır ve idare etmesi g&uuml;&ccedil; te&ccedil;hizatlarla &ccedil;alışmak zorunda kaldıklarını hatırlamak durumundayız. Herşeye rağmen ger&ccedil;eği ortaya &ccedil;ıkarmanın, hangi bi&ccedil;imi alırsa alsın, neredeyse &ouml;l&uuml;mc&uuml;l bir g&uuml;nah olduğunu d&uuml;ş&uuml;n&uuml;yor g&ouml;r&uuml;nmeleri, bazı yurttaşlarımdaki ger&ccedil;ek kusurun tabiatlarından kaynaklandığı izlenimini uyandırıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Lyons&rsquo;daki tartışmaları iki kişi y&ouml;nlendiriyor ve bu, sinema hakkındaki iki temel ve birbirine zıt eğilimi ifade ediyordu:&nbsp;<b>Richard Leacock</b>&nbsp;ve&nbsp;<b>Jean Rouch</b>. Ve aslında bakış a&ccedil;ılarındaki bariz d&uuml;şmanlığın, yalnızca olayları farklı yerlerden g&ouml;r&uuml;yor olmalarının uyuşmazlığından değil, daha &ccedil;ok iki uygarlık&nbsp; bi&ccedil;imi arasındaki anlayış farkından, Fransızlık ve Anglo-Saksonluktan kaynaklandığı izlenimini uyandırıyordu.&nbsp;<b>Leacock</b>, bir &ccedil;eşit sinematik Rousseauculuk varsayıyordu, bazı yerlerde ustası&nbsp;<b>Flaherty</b>&rsquo;yi tekrarlayarak: insanları ve nesneleri doğal hallerinde ortaya serelim, ger&ccedil;ekliğin devinimini tekrar keşfedelim ve b&ouml;ylece sinemayı, d&uuml;nyanın g&uuml;zelliğini a&ccedil;ığa &ccedil;ıkarmak olan birincil işlevine d&ouml;nd&uuml;relim.&nbsp;<b>Rouch</b>&nbsp;i&ccedil;in -ki şaşırtıcı bir şekilde onun da&nbsp;<b>Flaherty</b>&rsquo;ye hayranlığı daha az değildir- asıl mesele, &ccedil;ok basit olan ger&ccedil;eklerden ka&ccedil;ınmak, ilkel ve uygar yaşamın benzer bi&ccedil;imde bize empoze ettiği sosyal komedinin &ouml;z&uuml;ne n&uuml;fuz etmeye &ccedil;alışmaktır. Leacock, anlam ve yorumlara zorlamaya &ccedil;alışmakla, insanları basit&ccedil;e kendileri olmaktan alıkoymakla eleştirir&nbsp;<b>Rouch</b>&rsquo;u. Buna karşılık&nbsp;<b>Rouch</b>&nbsp;da, &ldquo;Amerikan tarzı yaşam&rdquo; fikrinin i&ccedil;erdiği her şeyi b&uuml;y&uuml;k bir rahatlıkla ve eleştirmeksizin kabul etmesiyle, fazlasıyla d&uuml;ş&uuml;ncelere dalmış bulduğu tavrını eleştirir&nbsp;<b>Leacock</b>&rsquo;un. Tartışma &ccedil;&ouml;z&uuml;ms&uuml;z kalır. Eklemeliyim ki, sinemadaki bu heyecan verici ve devrimci hareketin iki &ouml;nc&uuml;s&uuml;n&uuml; bu kadar s&uuml;r&uuml;ncemede kalmış bir anlaşmazlık halinde g&ouml;rmek cesaret kırıcıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Robert Drew</b>&nbsp;ve&nbsp;<b>Richard Leacock</b>, ge&ccedil;en sonbahar ve kışın yoğun bi&ccedil;imde &uuml;st&uuml;nde &ccedil;alıştıkları iki filmin d&uuml;nya galasını Lyons&rsquo;ta ger&ccedil;ekleştirdiler:&nbsp;<b>Gregory Shuker</b>&rsquo;in d&uuml;zenlemesini yaptığı,&nbsp;<b>Richard Leacock</b>&rsquo;un aktif işbirliğiyle &ccedil;ekilen&nbsp;<b>The Chair</b>; ve &ccedil;oğunluğunu DrewAssociates&rsquo;in arkasındaki &uuml;&ccedil;&uuml;nc&uuml; kişi olan&nbsp;<b>Donald Pennebaker</b>&rsquo;in kotardığı&nbsp;<b>Jane</b>. Bu filmlerin son kurgularında&nbsp;<b>Robert Drew</b>&rsquo;un oynadığı temel rol&uuml; de belirtmek gerekir: son karar ve sorumluluklar onundur. Belki bir g&uuml;n,&nbsp;<i>Life</i>&rsquo;ın eski muhabiri, tutkulu bir sinema d&uuml;şk&uuml;n&uuml;, film eleştirisinin SherlockHolmes&rsquo;u olan biri,&nbsp;<b>Robert Drew</b>&nbsp;ve&nbsp;<b>Richard Leacock</b>&nbsp;ortaklığında her ikisinin &uuml;stlendikleri farklı rolleri a&ccedil;ığa &ccedil;ıkarabilir. Ve başlangı&ccedil; noktası da,&nbsp;<b>Drew</b>&rsquo;un, yaptıkları işlerden her zaman &ldquo;beyazperde gazeteciliği&rdquo; diye bahsetmesi, fakat&nbsp;<b>Leacock</b>&rsquo;un bu terimi hi&ccedil; kullanmaması olabilir. Ama belki de, ne kadar dikkate değer olsa da, onların girişimi asıl kişiliğini, ancak ikisi de yaptıkları tarzdaki sinemanın bile her filmin arkasında tek bir yaratıcı zihni gerektirdiğini kavramaya hazır olduklarında kazanacak. Bu ger&ccedil;eği arayış &ouml;znelliğe gereksinim duyduğunu itiraf edebildiğinde, kurgu film kendi alanındaki haklarını yeniden ele ge&ccedil;irdiğinde; doğrudanlığını ve bizi insanlarla &ouml;zel bir d&uuml;zeyde yakınlaştırarak biraraya getirme yetisini&nbsp;<i>cinema-verite</i>&rsquo;den alan bu yenilik&ccedil;i sinema, misyonunu yerine getirmiş olacaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu arada, s&ouml;ylenmelidir ki, Lyons&rsquo;taki seyirci&nbsp;<b><i>The Chair&nbsp;</i></b>ve&nbsp;<b><i>Jane</i></b>&rsquo;i aynı zamanda hem heyecanlandırıcı, hem de kafa karıştırıcı bulmuştur: İki film de&nbsp;<b>Leacock</b>&nbsp;i&ccedil;in, arzuladığı gibi &ccedil;elişkili tepkiler uyandırarak kesinlikle tatminkar olmuştur.&nbsp;<b>Jean Rouch</b>, iki filmden de etkilendiğini, fakat aynı zamanda sert bi&ccedil;imde olumsuz olmalarından rahatsızlık duyduğunu belirtmiştir. Ge&ccedil;en temmuzda New York&rsquo;tayken&nbsp;<b>Negro Paul Crump</b>&rsquo;un kaderi -ki davası&nbsp;<b><i>The Chair&nbsp;</i></b>filminin konusudur- Chicago&rsquo;da belli olmuştu.&nbsp;<b>Drew</b>,&nbsp;<b>Leacock</b>&nbsp;ve meslektaşları -her ne kadar film, getirdiği yorumla tuhaf bir bi&ccedil;imde muğlak olsa da- ciddi olarak &ccedil;alkalanmalarına yol a&ccedil;an bir konuya tepki g&ouml;sterdiler. Mesele, eyaletin, hapiste ge&ccedil;irdiği dokuz yılın ardından t&uuml;m&uuml;yle başka birine d&ouml;n&uuml;şm&uuml;ş bir su&ccedil;luyu elektrikli sandalyeye yollayacak ahlaki hakkının artık olmamasıydı. Eğer Crump elektrikli sandalyeye g&ouml;nderilseydi, film adaletsizliğin su g&ouml;t&uuml;rmez bir kanıtı olarak baki kalacaktı. Eğer affedilseydi (ki &ouml;yle oldu), yapıtın durumu herşeye rağmen &ccedil;arpıcılığını kaybetmeyecekti. Peki o zaman niye film hakkında bir hoşnutsuzluğumuz var?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Buna karar verebilmek i&ccedil;in, bize sunulduğu haliyle filmin yapısını ayrıntılı bi&ccedil;imde analiz etmemiz gerekecek; vurgunun Crump&rsquo;tan, avukatı olan&nbsp;<b>Don Moore</b>&rsquo;a ne kadar kaydığını hesaba katarak &ndash;&ccedil;ekim şartlarının ve nerede, nasıl &ccedil;ekilmek istendiğiyle ilgili &ouml;zel sorunların zorunlu bir sonucu olarak-; ve daha basit insani ger&ccedil;eklerin kurgu esnasında, nereye kadar Hollywood tarzı belirsiz uydurma unsurlara kurban edildiğine dikkat ederek. Filmdeki bir sekans t&uuml;m&uuml;yle&nbsp;<b>Richard Leacock</b>&rsquo;ın işi ve olduk&ccedil;a da sıradışı:&nbsp;<i>Don Moore</i>&nbsp;ofisinde iki telefon beklemektedir, ki ilkinden, j&uuml;rinin, m&uuml;vekkilinin &ouml;l&uuml;m cezasını hafifletme kararına varıp varmadığını, ikincisinden de, Illinois Valisi&rsquo;nin ceza indirimini kabul edip etmediğini &ouml;ğrenecektir. Telefonlar gelir; sonu&ccedil;lar adildir. Rahatlayan Moore, birdenbire, dava nihayet bittiği i&ccedil;in artık tadını &ccedil;ıkarabileceği huzur &uuml;zerine doğa&ccedil;lama bir şiir s&ouml;ylemeye başlar. Kamera burada &ouml;znesiyle birleşmiş gibidir ve sonu&ccedil;, ancak sinemanın bu derece bir yoğunlukla yakalayabileceği lirik duygu patlamalarından biridir. Aniden, bu y&ouml;ntemleri kullanıp, onlardan bir karakteri t&uuml;m derinliğiyle g&ouml;stermek i&ccedil;in yararlanacak bir kurgu sineması hayal ederiz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Jane</b>, aktris&nbsp;<b>Jane Fonda</b>&rsquo;nın bir yıldız olarak Broadway&rsquo;de ilk defa sahneye &ccedil;ıkışıyla ilgilidir; filmin kusurları ve &uuml;st&uuml;nl&uuml;kleri &ccedil;oğunlukla benzerdir. Her ne kadar kabaca olayların kronolojisine uygun bir d&uuml;zen kurgu esnasında oluşturulmuşsa da, konunun inşa edilişi sorunlu. Ve boşlukları sonradan yamamak yeterli olmuyor. &Ccedil;oğu zaman hatırı sayılır bir ustalıkla ve hoş Bayan Fonda&rsquo;nın tam işbirliğiyle &ccedil;alışan&nbsp;<b>Pennebaker</b>&nbsp;ve ekibi bizi sahne arkasına davet ediyor. Onu, k&uuml;&ccedil;&uuml;k bir New York tiyatrosunda olduk&ccedil;a sıradan bir oyun i&ccedil;in prova yaparken; ardından, şehir dışı denemeleri olarak Philadelphia ve Wilmington&rsquo;da oyunculuğunu kusursuzlaştırırken; ve sonra da, dehşete d&uuml;şm&uuml;ş New York eleştirmenlerinin &ouml;n&uuml;nde Broadway a&ccedil;ılışında izliyoruz. A&ccedil;ılıştan sonra eve gidip gergin bir şekilde ilk eleştirileri okurken g&ouml;r&uuml;yoruz. Oyun tam bir başarısızlık oluyor &ndash;aslında &ouml;yle olması ger&ccedil;ekten muhtemel g&ouml;r&uuml;n&uuml;yordu. Oyunun sonlandırılmasına karar veriliyor ve şirket bu kararı tartışmak i&ccedil;in son defa toplanıyor. Şafak vakti Jane ve y&ouml;netmeni Andreas, ki aynı zamanda nişanlısıdır, tiyatroyu terk ediyorlar. Oyunun afişleri &ccedil;oktan kaldırılmıştır bile.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İnsan, filme harcanan yaratıcı &ccedil;abayı takdir ettiği kadar ne olduğunu tam kestiremediği bazı teredd&uuml;tlere de d&uuml;ş&uuml;yor. &Ouml;ncelikle &ndash;burada&nbsp;<b>Rouch</b>&rsquo;un anlaşılır bir nedeni vardır-, filmde t&uuml;m bu koca Amerikan şov d&uuml;nyası mitine dair bir eleştirellik &ouml;nerisi yoktur, ki&nbsp;<b>William Gibson</b>,&nbsp;<b><i>The Seesaw Log</i></b>&rsquo;da bu bulaşıcı deliliği olağan&uuml;st&uuml; bir bi&ccedil;imde incelemiştir. Ve sonra, insanın kendine sorması gerekiyor:&nbsp;<b>Sidney Lumet</b>, iyi bir senaryonun yardımı,&nbsp;<b>Franz Planer</b>&rsquo;ın takdire şayan kamera &ccedil;alışması ve&nbsp;<b>Susan Strasberg</b>&rsquo;in performansıyla&nbsp;<b>Stage Struck</b>&rsquo;ta bu işi &ccedil;ok iyi yapmadı mı? Cevaplaması incelik isteyen bir soru bu. İlk izlenim d&uuml;zeyinde, film &ccedil;ekilirken bir şeylerin ger&ccedil;ekten olmasına dair somut his anlamında&nbsp;<b>Jane</b>&nbsp;b&uuml;t&uuml;n kartları elinde tutuyor. Bir &ccedil;ekimde ger&ccedil;ek Jane Fonda&rsquo;yı sahne korkusuyla titreyerek sırasını beklerken, ve bir başkasında, sahneye &ccedil;ıkmış, olduk&ccedil;a yapay bir performans sergilerken g&ouml;rd&uuml;ğ&uuml;m&uuml;zde, sorgulanan daha ziyade dramatik sanatın kendisi oluyor. Leacock tarzı sinemanın eşsizliği bu &ccedil;eşit ayrıntılarda ortaya &ccedil;ıkıyor. Sinema oyunculuğu ve tiyatro oyunculuğunun aynı olmadığını; ve&nbsp;<b>Jane Fonda</b>&rsquo;nın kendisinin,&nbsp;<b>Joshua Logan</b>&nbsp;tarafından y&ouml;netilen&nbsp;<b><i>Tall Story</i></b>&nbsp;filminde sergilediği performansında daha az yapay, m&uuml;thiş spontanlığıyla &ldquo;ger&ccedil;ek&rdquo; Jane Fonda&rsquo;dan daha farklı olmadığını farkediyoruz. Belki de Donald Pennebaker, oyuncularının&nbsp;<b>Jane</b>&rsquo;de sahnede olmadıkları zamanki gibi oynadığı bir ger&ccedil;ek kurgu film yapmalıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Daha &ouml;nce DrewAssociates&rsquo;te &ccedil;alışan&nbsp;<b>Albert</b>&nbsp;ve&nbsp;<b>David Maysles</b>&nbsp;kardeşler, Boston&rsquo;lu tanınmış film adamı&nbsp;<b>Joe Levine</b>&rsquo;ın yaşamı ve &ccedil;alışmalarıyla ilgili filmleri&nbsp;<b><i>Showman</i></b>&rsquo;le bize bazı soruların cevabını vermemizde yardımcı olabilir. Burada filmin konusuyla ilgili herhangi bir yapay &ldquo;belirsizlik&rdquo; iddiası ve kendi kendine yetme durumu yoktur. Film ne duygusallaştırılarak, ne de herhangi bir k&ouml;t&uuml; niyetlilikle yapılmıştır.&nbsp;<b>Levine</b>&rsquo;ın kendisi, bu &ccedil;arpıcı portresine ne tepki verirdi bilemiyorum. Ama ş&uuml;phesiz ki film, bu tipik Amerikan başarı &ouml;yk&uuml;s&uuml;yle ilgili son bir yıl veya daha fazla s&uuml;rede b&uuml;y&uuml;k Amerikan dergilerinde sarfedilen t&uuml;m s&ouml;zleri yerli yerine koymaktadır.&nbsp;<b>Albert Maysles</b>&nbsp;kamerada, kardeşi&nbsp;<b>David&nbsp;</b>ses ekipmanlarında olmak &uuml;zere, New York, Boston, Hollywood, Roma ve Cannes&rsquo;da festival zamanlarında&nbsp;<b>Joe Levine</b>&rsquo;ın izini s&uuml;rm&uuml;şler. Yorum olmaksızın, bizleri, b&uuml;y&uuml;k iş pazarlığının bu garip t&ouml;renine, Cannes&rsquo;da Carlton Oteli&rsquo;nde&nbsp;<b>Levine</b>&rsquo;ın bir Avrupalı dağıtımcıya eşsiz jargonuyla &ldquo;Sen benim filmime iyi davran, ben de sana &ccedil;ok iyi davranayım&rdquo; şeklindeki a&ccedil;ıklamasına tanıklık ediyorlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ge&ccedil;en yaz New York&rsquo;ta filmin kurgulanmamış halini g&ouml;rd&uuml;ğ&uuml;mde takdire değer bir materyal olduğunu d&uuml;ş&uuml;nd&uuml;m, ama yine de, kurgulama esnasında bununla ne yapılabileceği ve sonucun ne olabileceğini kestirmek zordu.&nbsp;<b>Albert Maysles&rsquo;</b>le filmin nihai halini tartışırken,&nbsp;<b>Eisenstein</b>&nbsp;tarzı bir montaj planlıyor olabileceğini sandım. Ama yalın, kısaltılmış ve&nbsp;<b>Norman Rosten</b>&nbsp;tarafından yazılıp seslendirilmiş beylik fakat titiz bir yorumla son haline kavuştu&nbsp;<b><i>Showman</i></b>.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Drew</b>&nbsp;ve&nbsp;<b>Leacock</b>&nbsp;filmlerine y&ouml;nelttiğim tarz eleştiriler bu filmin &ouml;n&uuml;nde yerle bir oluyor. Sanırım bunun i&ccedil;in bir neden, hatta sadece bir neden, g&ouml;rebiliyorum:&nbsp;<b>Albert Maysles</b>&rsquo;in kamerasıyla durmadan yaptığı ilham verici &ccedil;alışması &ndash;ve tabii, eşzamanlı ses kaydı. Mesela &ouml;zellikle, kameranın bizi ofisinde oturup konuşmakta olan&nbsp;<b>Joe Levine</b>&rsquo;ley&uuml;zy&uuml;ze getirmek i&ccedil;in, ayakta olan iki kişi arasından ge&ccedil;iş bi&ccedil;imini d&uuml;ş&uuml;n&uuml;yorum.&nbsp;<b>Levine</b>ve meslektaşları konuşmalarını s&uuml;rd&uuml;r&uuml;rlerken kameranın 45 derecelik bir a&ccedil;ıyla sola d&ouml;n&uuml;p, belirli bir an i&ccedil;in&nbsp;<b>Levine</b>&rsquo;ı perdede tek başına &ccedil;er&ccedil;eve i&ccedil;ine alması. Burada kameraman ve &ouml;znesi arasındaki bağ &ouml;yle yakın g&ouml;r&uuml;n&uuml;yor ki, aralarında işleyen bir &ccedil;eşit değiş tokuştan bahsedebilir insan.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Biz sadece film yapmayı seviyoruz&rdquo;,&nbsp;<b>Albert Maysles</b>&rsquo;in, kendi ilk d&ouml;nem filmlerini unutan ve&nbsp;<b>Maysles</b>&rsquo;leri &ldquo;sanat&rdquo; &uuml;retmedikleri ve formsuz, bi&ccedil;imsiz olana y&ouml;nelik tehlikeli modern tutku uğruna &ccedil;ok fazla şeyi harcadıkları i&ccedil;in eleştiren agresif&nbsp;<b>Roberto Rossellini</b>&rsquo;ye verdiği muhteşem yanıttı.&nbsp;<b>Rossellini</b>&rsquo;nin kendi&nbsp;<b>VaninaVanini</b>&rsquo;si, o fazlasıyla g&uuml;zel film, anlamsız bir estetizmin ne kadar tehlikeli olabildiğini g&ouml;sterir. Ve, sinemada bu kadar samimi bir inan&ccedil; itirafını duymak y&uuml;reklendiriciydi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu deneylerin zıt kutbunda&nbsp;<b>Jean Rouch</b>&rsquo;un, hi&ccedil;bir şeyin &ouml;nceden d&uuml;zenlenmeden, prova edilmeden veya tekrar sahnelenmeden doğrudan filme alındığı&nbsp;<b>La Punition</b>&rsquo;ıdurur, ki bu,&nbsp;<b>Rouch</b>&rsquo;un&nbsp;<b>Chroniqued&rsquo;un Et&eacute;</b>&nbsp;ve&nbsp;<b>Rose et Landry</b>&rsquo;den hemen sonra, 1960&rsquo;da&nbsp;<i>National Film Board of Canada</i>&nbsp;i&ccedil;in Abidjan&rsquo;da (Afrika) &ccedil;ektiği bir &ldquo;psikodrama&rdquo;dır.&nbsp;<b>Leacock</b>&nbsp;ve&nbsp;<b>MayslesKardeşler</b>&rsquo;in aksine&nbsp;<b>Rouch</b>, filmlerindeki insanların kendi kendilerinin ses kayıt&ccedil;ıları olmalarını sağlar; klapa veya kravatlarına taksınlar diye minyat&uuml;r mikrofonlar verir ve b&ouml;ylece hem onları her yerde takip edebilir hem de sesleri senkronize bir bi&ccedil;imde kayıt edebilir. Başka bir deyişle, başlangı&ccedil;ta, y&ouml;netmen ve beyazperdedeki yorumcuları arasında bir su&ccedil; ortaklığı vardır. İki g&uuml;n s&uuml;resince kesintisiz filme alınmış olan&nbsp;<b>La Punition</b>, bizlere,&nbsp;<b>Rouch</b>&rsquo;un&nbsp;<b>La Pyramide Humaine</b>&rsquo;indeki gen&ccedil; kızı, felsefe okumakta olduğu Paris okulundan hen&uuml;z atılmış&nbsp;<b>Nadine Ballot</b>&rsquo;u g&ouml;sterir. Gezinmeleri sırasında &ccedil;eşitli insanlarla karşılaşır: kendisine aşık olduğunu ilan edip sonra onu terk eden bir &ouml;ğrenciyle, kendisiyle beraber yaşamasını isteyen orta yaşlı bir adamla. Oyuncular yazılı bir metin olmadan, ama kısmen y&ouml;netmen tarafından onlar i&ccedil;in hazırlanmış bir yolu izlerler ve sonu&ccedil; kesinlikle tatmin edicilikten uzaktır.&nbsp;<b>Becker</b>&rsquo;in&nbsp;<b>Edouard et Carolin</b>&rsquo;inde Caroline rol&uuml;n&uuml; oynayan&nbsp;<b>Anne Vernon</b>,&nbsp;<i>UNESCO Film Club</i>&rsquo;da yapılan bir tartışma toplantısı esnasında, yaşlı adamlı b&ouml;l&uuml;mdeki oyunculuğun yapaylığını g&ouml;stermekte hi&ccedil; zorluk &ccedil;ekmez.&nbsp;<b>Nadine Ballot</b>&nbsp;da kendi karakterinin, sahneye koyduğu bi&ccedil;imiyle kendisine olduk&ccedil;a ger&ccedil;ek dışı geldiğini kabul eder.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>Rose et Landry</i></b><i>&rsquo;</i>de&nbsp;<b>Rouch</b>, biri erkek diğeri kız olan iki Afrikalı &ouml;ğrenci arasındaki konuşmayı, ge&ccedil;miş ve şimdinin nasıl i&ccedil; i&ccedil;e ge&ccedil;tiğini, atadan kalma geleneklerin bu Afrikalı entelekt&uuml;ellere hala ne kadar yakın g&ouml;r&uuml;nd&uuml;ğ&uuml;n&uuml; ve her ne kadarını &ouml;z&uuml;mseyebiliyorlarsa da bizim beyaz uygarlığımızın onlara hala nasıl yabancı ve gizemli geldiğini; ikisinin diyaloğundaki ritmi esas alıp&nbsp;<i>cross-cutting</i>&rsquo;le (&ccedil;apraz-kesme) g&ouml;stererek, neredeyse&nbsp;<b>Griffith</b>&rsquo;inkini hatırlatan bir sadelikle sahneye koyar.&nbsp;<b>Rouch</b>&rsquo;un direktifleri doğrultusunda&nbsp;<i>National Film Board</i>&rsquo;dan&nbsp;<b>Jacques Godbout</b>&rsquo;ın kurguladığı film, y&ouml;netmenin, konuşma ve dil yoluyla hakiki bir &ccedil;atışmayı ortaya &ccedil;ıkarma d&uuml;şk&uuml;nl&uuml;ğ&uuml;n&uuml;n sınırlarını zorlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Rouch</b>&rsquo;unki &ouml;zellikle bir d&uuml;ş&uuml;nce ve tartışma sinemasıdır ve her zaman i&ccedil;in sanatın d&uuml;zlemini terkedip bilimsel araştırmanınkine girme noktasındadır. Yalnızca tesad&uuml;fen bir g&ouml;steridirki bu, bir eleştiri olarak g&ouml;r&uuml;nebilir. Ama bu,&nbsp;<b><i>Moi un Noir</i></b>&rsquo;ın yaratıcısının bize test ettirip sorgulatmak istediği film denen g&ouml;sterinin doğasıdır; hem toplumsal işlevi a&ccedil;ısından (iletişimin &ouml;nemi) hem de estetik işlevi a&ccedil;ısından (ger&ccedil;ek nerede başlar ve nerede biter?).&nbsp;<b>Rouch</b>&nbsp;da&nbsp;<b>Leacock</b>&nbsp;da kendi farklı yollarıyla bizi &ccedil;ıkmaz yollara doğru y&ouml;nlendiriyor g&ouml;r&uuml;n&uuml;yorlar ve belki de Kanada&rsquo;dan&nbsp;<b>MichelBrault</b>&rsquo;un &ccedil;alışmaları bunda bir &ccedil;ıkar yol sunuyor bize:&nbsp;<b>Mario Ruspoli</b>&rsquo;nin&nbsp;<b><i>Les Inconnus de la Terre ve Regard sur la Folie</i></b>&rsquo;sinde olduğu gibi&nbsp;<b>Brault</b>&rsquo;un&nbsp;<b><i>Chroniqued&rsquo;un Et&eacute;</i></b>&nbsp;ve La Punition&rsquo;unda da kameranın kontrol&uuml; kendisindedir ve hızlıca ardarda yaptığı bu iki film, daha iyi bir kelimeye ihtiya&ccedil; duymamıza rağmen hala&nbsp;<i>cin&eacute;ma-v&eacute;rit&eacute;</i>&nbsp;demek durumunda olduğumuz akımın perspektiflerini genişletir g&ouml;r&uuml;nmektedir. Verili bir tema &uuml;zerine kolektif bir doğa&ccedil;lama olan, t&uuml;m&uuml;yle Montreal &Uuml;niversitesi &ouml;ğrencileri tarafından&nbsp; tasarlanmış, oynanmış ve &uuml;retilmiş, ancak&nbsp;<b>Brault</b>&rsquo;un &ccedil;ektiği ve&nbsp;<i>Film Board</i>&rsquo;dan&nbsp;<b>Gilles Groulx</b>&rsquo;un kurguladığı, diğerlerinden daha az &ouml;nemli &ccedil;alışması&nbsp;<b>Seul ouaveclesautres</b>&nbsp;pek sempatiktir. Nicole adında gen&ccedil; bir &ouml;ğrenci &uuml;niversiteye d&ouml;ner. D&uuml;ş&uuml;nceleri erkeklere odaklanmıştır, ama en fazla &ouml;nem verdiği kişi olan Pierre her zaman başka şeylerle meşguld&uuml;r. T&uuml;m &uuml;niversite kamp&uuml;s&uuml; ve Nicole&rsquo;&uuml;n &ccedil;evresindeki herkes aşkla meşgul g&ouml;r&uuml;nmektedir. &Ccedil;oğu zaman&nbsp; telefoto lensle filme aldığı ve kamerasına sabitlenmiş bulunan &uuml;&ccedil; lensi kullandığı filmde&nbsp;<b>Brault</b>, oyuncularını (ki taşınabilir mikrofonlar kullanmaktadırlar) t&uuml;m hareketlerinde serbest bırakmıştır. Ger&ccedil;ek bir gen&ccedil;lik hissiyatı, daha &ouml;nce &ouml;ğrenci yaşamı &uuml;zerine izlediğimiz &ccedil;oğu filmin net bir bi&ccedil;imde yapay g&ouml;r&uuml;nmesini sağlayacak kadar başarıyla aktarılmıştır. Ama&nbsp;<b>Michel Brault</b>&rsquo;un yakın zamanda tamamladığı filmi&nbsp;<b>Pour la Suite du Monde</b>&nbsp;&ccedil;ok daha &ouml;nemli bir &ccedil;alışmadır ve burada yapılabileceğinden daha uzun bir değerlendirmeyi gerektirir. Kanada folklor&uuml; uzmanı olan&nbsp;<b>Pierre Perrault</b>&rsquo;un işbirliğiyle yapılan film, Quebec&rsquo;in elli mil kadar uzağında, Saint Lawrence nehrindeki bir adada yaşayan, Fransızca konuşan k&uuml;&ccedil;&uuml;k bir Kanadalı topluluk &uuml;zerinedir.&nbsp;<b>Perrault</b>,&nbsp;<b>Brault</b>&nbsp;ve ses m&uuml;hendisi&nbsp;<b>Marcel Carri&eacute;re</b>, konuşulan dilin hala 17.yy Fransızcası olduğu, insanlarının belli y&ouml;nlerden&nbsp;<i>Nanook Eskimoları</i>&rsquo;ndan pek de farklı g&ouml;r&uuml;nmediği, fakat ka&ccedil;ınılmaz olarak modern uygarlıkla bağlantıları bulunan k&ouml;yde bir yıl yaşamıştır.&nbsp;<b>Perrault</b>&nbsp;ve&nbsp;<b>Brault</b>, kendi i&ccedil;ine kapalı bir toplulukta, bir &ccedil;eşit iş senfonisi ortaya koymuştur. Peki b&ouml;ylece, bu meşhur&nbsp;<i>cin&eacute;ma-v&eacute;rit&eacute;&rsquo;</i>ye nihayet yakışacak başyapıtı ortaya koymuşlar mıdır? Tam olarak değil. Hala&nbsp;<i>cin&eacute;ma-v&eacute;rit&eacute;&rsquo;</i>nin&nbsp;<i>Nanook</i>&rsquo;unu bekliyoruz. Ama bu filmde, kurgunun t&uuml;m ritmi, akımın değerlerini yeniden keşfeder. Basit bir anlatım bi&ccedil;iminin &ouml;tesi vardır; ses kaydının oynadığı rol temeldir. Ge&ccedil;mişin b&uuml;y&uuml;k belgesellerinde eksik olan her şeyi farketmemizi zorunlu kılan, daha acil, daha capcanlı bir bi&ccedil;im ortaya konmuştur. Konuşma dili, kendi hakiki yerini geri alır filmde: hareketin t&uuml;m ritmine i&ccedil;kinleşmiş, daha sonraki bir aşamada eklenmemiştir filme.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><i>Cin&eacute;ma-v&eacute;rit&eacute;&nbsp;</i>kendi i&ccedil;inde her &ccedil;eşit sanatsal sorunu barındırır ve&nbsp;<b>Pour la Suite du Monde&nbsp;</b>gibi bir film bunların &ccedil;&ouml;z&uuml;m&uuml;nde ilk aşamayı oluşturur. Buradan hareketle, bir dramatik sinemanın, kurgusal inceliklerini bu direkt &ccedil;ekim y&ouml;ntemlerini kullanarak nasıl zenginleştirebileceği sorununa y&ouml;neliriz. Bu y&ouml;n, şimdi sinemada y&uuml;ce sanat olarak addedileni daha zenginleştirici bir yere vardırabilir mi? Eğer katıksız belgesel ile kurgusal sinemanın nihai bir bir araya gelişini hayal edemiyorsak, Brechtvari tiyatronun bazı epik &ouml;zelliklerini beyazperde i&ccedil;in tekrar keşfeden bir sinemaya varabiliriz. Yaşandığı bi&ccedil;imiyle bizi g&uuml;ndelik yaşama yakınlaştıran&nbsp;<i>cin&eacute;ma-v&eacute;rit&eacute;</i>, katı ve &ccedil;abuk kuralların olmadığını ve deneyimin testler ve keşiflerden oluşan bir s&uuml;reklilik olduğunu keşfetmemize yardım edebilir.</span></p>', 196, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (58, 'ay-j179', 'soylesi-stratos-kersanidis', 'Söyleşi: Stratos Kersanidis', 'Kinorama 7, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 7, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Pınar Karababa, Cem Kayalıgil</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yunanca&rsquo;dan &Ccedil;eviren: Pınar Karababa</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><i>Mayıs ayında yapılmış olan 7. U&ccedil;an S&uuml;p&uuml;rge Uluslararası Kadın Filmleri Festivali j&uuml;risinde g&ouml;rev yapan Yunan film eleştirmeni&nbsp;<b>Stratos Kersanidis</b>&nbsp;ile Yunan sineması &uuml;zerine birr s&ouml;yleşi yaptık. Uluslarası İstanbul Film Festivali&rsquo;nin de daimi j&uuml;ri &uuml;ylerinden olan&nbsp;<b>Kersanidis</b>, Yunan Film Eleştirmenleri Derneği&rsquo;nde başkan yardımcılığı yapıyor.&nbsp;&nbsp;</i></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&nbsp;</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yunan Sineması&rsquo;nı cunta &ouml;ncesi &ndash; cunta sonrası gibi ifadelerle belirli d&ouml;nemlere ayırabilir miyiz? Eğer ayırabiliyorsak, y&ouml;netmen ve film isimleri vererek bu d&ouml;nemleri bize tanıtabilir misiniz? Bug&uuml;nk&uuml; Yunan Sineması sizce nasıl bir yerde duruyor?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İlk d&ouml;nemin 1930&rsquo;a kadar s&uuml;rd&uuml;ğ&uuml;n&uuml; s&ouml;yleyebiliriz, &ouml;nc&uuml;lerin d&ouml;nemi. O zamanın &ouml;nemli isimleri Manakia Kardeşler&rsquo;di. Bundan sonraki d&ouml;nem ise 1931-1940 yılları arasındaki d&ouml;nem. Bu d&ouml;nemin &ouml;nemli bir filmi,&nbsp;<b>Orestis Laskos</b>&rsquo;un&nbsp;<b><i>Dafnes ve Chloe</i></b>&rsquo;si (1931). Bu d&ouml;nemde &ccedil;ekilen filmler &ouml;nemli sayılamayacak, halk temalı, genelde 1821 Yunan İhtilali ile ilgili halk &ouml;yk&uuml;lerinden oluşan filmlerdi. Bu d&ouml;nemdekilere benzer bir bi&ccedil;imde bir sonraki d&ouml;nem olan 1941-1945 arasında, 2. D&uuml;nya Savaşı ve Alman işgalinin olduğu yıllarda &ccedil;ekilen filmler de &ouml;nemli filmler değildir. Yunan Sineması &ouml;zellikle 4. d&ouml;nemde, 1946-1967 arasında,&nbsp; kendini g&ouml;stermeye başlamıştır. Bu olduk&ccedil;a uzun, 1967&rsquo;ye yani Yunanistan&rsquo;da diktat&ouml;rl&uuml;ğ&uuml;n ilan edildiği zamana kadar s&uuml;ren bir d&ouml;nemdir. Dram ve komedi başta gelmek &uuml;zere &ccedil;ok sayıda filmin &ccedil;ekildiği, ticari sinemanın geliştiği,&nbsp; &ccedil;ekilen bin tane &ccedil;ok da iyi olmayan filmin arasından bazı iyi &ouml;rneklerin g&ouml;ze &ccedil;arptığı yıllardır. Bu d&ouml;nemde b&uuml;y&uuml;k bir yapımcı ortaya &ccedil;ıktı: Yunanistan&rsquo;da uzun yıllardır varlığını s&uuml;rd&uuml;ren en b&uuml;y&uuml;k yapım şirketlerinden bir olan Finos Film&rsquo;in sahibi&nbsp;<b>Filopimin Finos</b>. Yine bu d&ouml;nemde &ouml;nemli y&ouml;netmenler tarafından &ccedil;ok &ouml;nemli filmlerin &ccedil;ekildiğini g&ouml;r&uuml;yoruz; mesela&nbsp;<b>Nikos Koundouros</b>&rsquo;un&nbsp;<b><i>The Ogre Of Athens</i></b>&nbsp;adlı filmi (O Drakos, 1956).</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ardından 1967&rsquo;den 1974&rsquo;e kadar diktat&ouml;rl&uuml;ğ&uuml;n h&uuml;k&uuml;m s&uuml;rd&uuml;ğ&uuml; d&ouml;neme ge&ccedil;ildi. Bu d&ouml;nem i&ccedil;inde &ccedil;ekilen filmler genellikle komediler, m&uuml;zikaller, dramlar ve milliyet&ccedil;i yapıdaki filmlerdi. Ancak b&ouml;ylesine zor bir ortamda, 1970&rsquo;li yılların başında&nbsp;<b>Theo Angelopoulos</b>&nbsp;tarafından &ccedil;ekilen&nbsp;<b><i>Reconstruction</i></b>&nbsp;(Anaparastasi, 1970) adlı filmle&nbsp;<b>Yeni Yunan Sineması</b>&nbsp;doğmuş oldu.&nbsp;<b>AleksisDamianos</b>&rsquo;un&nbsp;<b><i>Evdokia</i></b><i>&rsquo;</i>sı da (Eudokia, 1970) yine bu d&ouml;nemin &ouml;nemli filmlerinden birisidir.Yeni Yunan Sineması d&ouml;nemi, diktat&ouml;rl&uuml;kten sonra da 1990&rsquo;a dek&nbsp; s&uuml;rm&uuml;şt&uuml;r. Bunun ilk yıllarında, diktat&ouml;rl&uuml;k d&ouml;neminin &ccedil;ok &ouml;ncesinden beri s&uuml;regelen baskının kalkmasıyla &ccedil;ok sayıda siyasi film &ccedil;ekilmiştir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yeni Yunan Sineması&rsquo;nın birka&ccedil; &ouml;nemli filmine değinecek olursak,&nbsp;<b>Theo Angelopoulos</b>&rsquo;un&nbsp;<b><i>Kumpanya</i></b>&rsquo;sı (Thiasos, 1975) ile&nbsp;<b>PantelisVoulgaris</b>&rsquo;in&nbsp;<b><i>The Engagement of Anna&nbsp;</i></b>(To Proksenio Tis Annas, 1972) adlı filmlerini sayabiliriz. D&ouml;nemin diğer &ouml;nemli y&ouml;netmenleri arasındaysa&nbsp;<b>Costas Ferris</b>,&nbsp;<b>Lakis Papastathis</b>,&nbsp;<b>Nikos Nikolaidis</b>,&nbsp;<b>Yorgos Tsemberopoulos</b>,&nbsp;<b>Frieda Liappa</b>,&nbsp;<b>Tonia Marketaki</b>,&nbsp;<b>Nikos Papayotopulos</b>,&nbsp;<b>Yorgos Panousopoulos</b>&nbsp;ve&nbsp;<b>Nicos Perakis</b>&nbsp;vardır.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">1985&rsquo;e kadar her şey yolunda gitti. Ancak video ve televizyonun yayılmasıyla &ouml;nceden sinyallerini aldığımız bir kriz patlak verdi. &Ccedil;ekilen film sayısı senede 4-5&rsquo;e kadar d&uuml;şt&uuml;. B&ouml;ylece Yunan Sineması g&uuml;c&uuml;n&uuml; kaybetmeye başladı. 1985&rsquo;ten 1990&rsquo;a kadarki d&ouml;nemde ortaya &ccedil;ıkan yeni y&ouml;netmenler, siyasi konular dışındaki konularla ilgilenir oldular.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Tabii ki krizin etkisi bug&uuml;n de varlığını s&uuml;rd&uuml;r&uuml;yor ancak diyebiliriz ki 2000&rsquo;li yıllara gelindiğinde sinemada bir patlama oldu ve yeni yapım şirketleri ortaya &ccedil;ıktı, &ccedil;ok sayıda film yapılmaya başlandı ve bunlardan bazıları iyi gişe hasılatı yapan filmler oldu. Şu an i&ccedil;in yılda 15 kadar film &ccedil;eken ve bu filmlerinden 5-6&rsquo;sı iyi hasılat yapan bir Yunan Sineması&rsquo;ndan bahsetmek m&uuml;mk&uuml;n. Fakat bu filmler iyi olmakla beraber, bir değişim getirebilecek filmler değiller.&nbsp;<b>Constantinos Yannaris</b>,&nbsp;<b>Sotiris Goritsas</b>,&nbsp;<b>Pericles Hoursoglou</b>,&nbsp;<b>Katerina Evangelakou</b>&nbsp;ve&nbsp;<b>Nikos Grammatikos</b>&nbsp;bu d&ouml;nemin sayabileceğimiz &ouml;nemli isimleri arasındadır.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kanımca bug&uuml;n Yunan Sineması&rsquo;nın durumu bundan ibaret. &Ccedil;ok sayıda filmin &ccedil;ekilmesi ve bunların gelir getiren filmler olması g&uuml;zel bir şey, &ccedil;&uuml;nk&uuml; bu, sinema a&ccedil;ısından sistemin iyi işlediğine ve birka&ccedil; yıl &ouml;ncesine kadar &ouml;ld&uuml;ğ&uuml;n&uuml; sandığımız Yunan Sineması&rsquo;nın dirildiğine dair bir işaret.&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yurtdışında adını duyuran gen&ccedil; Yunan y&ouml;netmenlerden kimlerin adını anmak istersiniz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yurtdışında tanınan &ccedil;ok sayıda Yunan y&ouml;netmen yok. Uluslararası festivallerde bazı y&ouml;netmenlerin filmi g&ouml;steriliyor ama bunlar sonradan o &uuml;lkelerin sinemalarında g&ouml;sterime girmiyorlar, sadece festivallere giden sinefiller tarafından tanınıyorlar. Bu y&uuml;zden yurtdışında adını duyuran y&ouml;netmenlerden bahsedemeyeceğim. Yurtdışında fazla tanınmamanın sebebi bence y&ouml;netmenlerin iyi filmler &ccedil;ekmelerine rağmen ilgi &ccedil;ekici işlere girişmemeleri. Uluslararası festivallerde tanınan tek y&ouml;netmenimiz Angelopoulos.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Peki Angelopulos&rsquo;tan sonra Yunan Sineması&rsquo;nda oluşabilecek durum &uuml;zerine neler s&ouml;yleyebilirsiniz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hala Angelopoulos&rsquo;un i&ccedil;inde bulunduğu, film &ccedil;ektiği d&ouml;nemde bulunuyoruz. Buna rağmen g&uuml;&ccedil;l&uuml; bir tarzı olan ve ileriki yıllarda bir yenilik getireceklerine inandığım y&ouml;netmenler ortaya &ccedil;ıktı. Ancak bu y&ouml;netmenler Angelopoulos&rsquo;tan &ccedil;ok Avrupa sinemasının, mesela Fransız, İngiliz Sineması&rsquo;nın ya da Amerikan Sineması&rsquo;nın iyi &ouml;rneklerinin etkilerini taşıyorlar. Bir &ouml;rnek vermek gerekirse bence şu an Yunanistan&rsquo;daki en &ouml;nemli y&ouml;netmen İngiltere&rsquo;de&nbsp;</span><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">okuyup ilk filmlerini orada &ccedil;ekmiş olan ve son yıllarda da Yunanistan&rsquo;da &ccedil;ektiği birka&ccedil; filmi olan&nbsp;</span><b style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Konstantinos Giannaris</b><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">. Kendine &ouml;zg&uuml; bir stile sahip, sosyal konularla ilgili, &ccedil;ok g&uuml;&ccedil;l&uuml;, Angelopoulos&rsquo;un aksine &ccedil;ok hızlı akan filmleri var. İnsanların toplum i&ccedil;indeki yeri, g&ouml;&ccedil;menlerin Yunanistan&rsquo;daki konumu ile ilgili filmler &ccedil;ekiyor. &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yunan sinema tarihinin en iyi 10 filmi size g&ouml;re nedir?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">On değil, on iki, hatta daha fazla isim vermek m&uuml;mk&uuml;n:&nbsp;<b>Yorgos Javellas</b>&nbsp;-&nbsp;<b><i>The False Lira</i></b>&nbsp;(Kalpiki Lira, 1955),&nbsp;<b>Nikos Koundouros</b>&nbsp;&ndash;&nbsp;<b><i>The Ogre of Athens</i></b>&nbsp;(O Drakos, 1956),&nbsp;<b>Theo Angelopoulos</b>&nbsp;-&nbsp;<b><i>Reconstruction</i></b>&nbsp;(Anaparastasi, 1970),&nbsp;<b>Aleksis Damianos&nbsp;</b>-&nbsp;<b><i>Evdokia</i></b>&nbsp;(Eudokia, 1970),&nbsp;<b>Takis Kanellopoulos</b>&nbsp;-&nbsp;<b><i>Sky</i></b>&nbsp;(Uranos, 1962),&nbsp;<b>Pantelis Voulgaris</b>&nbsp;&ndash;&nbsp;<b><i>The Engagement of Anna</i></b>&nbsp;(To Proksenio Tis Annas, 1972),&nbsp;<b>Michalis Cacoyannis</b>&nbsp;&ndash;&nbsp;<b><i>Stella&nbsp;</i></b>(1955),&nbsp;<b>Nikos Nikolaidis</b><i>&ndash;&nbsp;<b>Sweet Gang</b></i>&nbsp;(GlikiaSimmoria, 1983),&nbsp;<b>Vasilis Gheorghiadis</b>&nbsp;&ndash;&nbsp;<b><i>The Red Lamps</i></b>&nbsp;(Ta Kokkina Fanaria, 1963),&nbsp;<b>Costas Ferris</b>&nbsp;&ndash;&nbsp;<b><i>Rembetiko</i></b>&nbsp;(Rebetiko, 1983),&nbsp;<b>Theo Angelopoulos</b>&nbsp;&ndash;&nbsp;<b><i>Kumpanya&nbsp;</i></b>(Thiasos, 1975),&nbsp;<b>Grigoris Grigoriou</b>&nbsp;&ndash;&nbsp;<b><i>Bitter Bread</i></b>&nbsp;(Pikro Psomi, 1951).</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yunan sineması dışa a&ccedil;ılma ve dış satım hususunda ne t&uuml;r politikalar &uuml;retiyor? Film yapımıaşamasında etkin olduğunu g&ouml;rd&uuml;ğ&uuml;m&uuml;z devletin bu konudaki &ccedil;alışmaları ne kadar etkili?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Uzun yıllardan beri filmlerin &ccedil;oğunun dışa a&ccedil;ılmasında rol oynayan kuruluş&nbsp;<b>Yunan Sinema Merkezi</b>&rsquo;dir. Bir&ccedil;ok film Yunan Sinema Merkezi ile ortaklaşa yapılır. Bu devlet destekli bir kuruluştur, her yıl toplanan bir kurul gelen senaryoları değerlendirir ve hangilerine destek verileceğini belirlerler. Yalnız bu kurulda bulunanlar devletle ilgili kimseler değil de eleştirmenler, y&ouml;netmenler gibi sinema ile ilgili insanlardır. Fakat verilen maddi destek genelde yeterli olmadığı i&ccedil;in y&ouml;netmenler Avrupa Birliği gibi &ouml;rg&uuml;tlerde bulunan programlara başvurarak maddi destek sağlarlar veya başka &uuml;lkelerle ortak yapım ger&ccedil;ekleştirirler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yunanistan&rsquo;daki sinema eğitiminin bug&uuml;nk&uuml; durumu nedir? Yunanca veya yabancı bir dilde eğitim veren sinema kurumları var mı?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu acılı bir hikaye. Yunanistan&rsquo;da &uuml;niversitelerde sinema ile ilgili bir b&ouml;l&uuml;m yok. Uzun yıllardır, sinema ile ilgili insanlar olarak bunu talep ediyoruz, h&uuml;k&uuml;metler her sene s&ouml;z veriyorlar ancak bug&uuml;ne kadar hi&ccedil;biri s&ouml;z&uuml;n&uuml; tutmadı.&nbsp; Atina&rsquo;da iki tane &ouml;zel sinema okulu var, &uuml;niversite d&uuml;zeyinde değil orta d&uuml;zeyde eğitim veriyorlar; dersleri &uuml;&ccedil; sene s&uuml;r&uuml;yor. Bu y&uuml;zden insanlar ekonomik durumları yeterliyse yurtdışındaki &uuml;niversitelerde okumaya gidiyorlar ya da y&ouml;netmenlerin yanında &ccedil;alışarak sinema yapmayı &ouml;ğreniyorlar.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&Uuml;lkenizde sinema yayıncılığının durumu nasıl?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yunanistan&rsquo;da bug&uuml;n film eleştirisiyle ilgili ciddi yayınlar yok. &lsquo;70&rsquo;li yıllarda &ccedil;ok sayıda vardı. Sadece&nbsp;<b>Sinema</b>&nbsp;diye bir dergi var fakat teoriyle ilgili bir dergi değil daha &ccedil;ok sezon filmleriyle ilgili yazılar &ccedil;ıkıyor. Bir de internette &ccedil;ıkan bir dergi var, ismi&nbsp;<b>Sinema ve İletişim</b>&nbsp;(Kinimatografos ke Epikinonia). Bence varolan tek ciddi dergi bu, bunun dışında hi&ccedil;bir şey yok. Ayrıca gazetelerde bazı ciddi sinema eleştirisi k&ouml;şeleri var fakat son yıllarda gazetelerin imtiyaz sahipleri bizden ciddi eleştiriler yerine dedikodu yazmamızı istiyorlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Şu an Yunanistan&rsquo;da iki grup eleştirmen var: birinci grupta film eleştirisini ciddiye alıp niteliklerini korumaya &ccedil;alışan insanlar yer alıyor. İkinci gruptakiler ise gen&ccedil; gazeteciler ve -bunun k&ouml;t&uuml; bir şey olduğunu s&ouml;ylemiyorum ama- eleştiri yapmak yerine r&ouml;portaj yapmayı, hangi filmde kimin oynadığını, filmlerin maliyetini ve ne kadar gişe hasılatı yaptığını yazmayı se&ccedil;iyorlar. Film eleştirisinin ciddi bir şekilde yapılması konusunda&nbsp;<b>Yunan Film Eleştirmenleri Derneği</b>&nbsp;(Panellinia Enosi Kritikon Kinimatografu) &ccedil;aba sarf eden bir &ouml;rg&uuml;t.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Zorluklarla karşılaşıyor ancak &ccedil;aba sarf etmeye devam ediyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ayrıca her yıl Selanik Film Festivali i&ccedil;in &ouml;nemli yayınlar &ccedil;ıkarılıyor. O sene hangi y&ouml;netmenin onuruna veya anısına &ouml;zel bir b&ouml;l&uuml;m ger&ccedil;ekleştirilecekse o y&ouml;netmenlerin filmleriyle ilgili bilgilerin ve eleştirilerin toplandığı kitaplar basılıyor. Bunun yanı sıra bizim derneğimiz de (Yunan Sinema Eleştirmenleri Derneği-PEKK) i&ccedil;inde bir &ouml;nceki senenin b&uuml;t&uuml;n filmleriyle ilgili eleştirilerin ve sinema ile ilgili &ccedil;eşitli teorik konuların yer aldığı bir almanak &ccedil;ıkarıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bir film eleştirmeni olarak son d&ouml;nem d&uuml;nya sineması &uuml;zerine (egemen sinema ve ulusal sinemalar bağlamında) neler d&uuml;ş&uuml;n&uuml;yorsunuz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sanıyorum sinemanın bir geleceği var ve bu iyi bir gelecek. Sinemanın bittiğine değil aksine hen&uuml;z tarihinin başında olduğuna inanıyorum. Eğer gelişen yeni teknolojileri filmlerde iyi kullanabilirsek sinemanın gelişmesine de katkıda bulunabiliriz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ancak tabii bug&uuml;n ciddi bir durum var, Holywood&rsquo;un yıkıcı etkisi. G&ouml;r&uuml;yoruz ki ulusall sinemalar bu y&uuml;zden yok olma tehdidiyle karşılaşıyorlar. Ancak sanırım yavaş yavaş bu durumun &uuml;stesinden gelmeye başladık.&nbsp; Şu an bir &ccedil;ok &uuml;lkede insanlar Amerikan filmlerini izlemeyi tercih ediyorlar. Bunun sebebi a&ccedil;ık: Amerikan Sineması&rsquo;nın maddi g&uuml;c&uuml; &ccedil;ok b&uuml;y&uuml;k, bir film g&ouml;sterime girmeden aylar &ouml;nce reklamını yapmaya başlıyorlar. Ama &ouml;rneğin bence &ccedil;ok iyi bir y&ouml;netmen olan&nbsp;<b>Nuri Bilge Ceylan</b>&nbsp;Cannes Film Festivali&rsquo;nde &ouml;d&uuml;l almış bir film yapsa da aynı &ouml;l&ccedil;&uuml;de filminin reklamını yapamıyor. Başka bir deyişle aynı maddi imkanlar onun elinde olsaydı, bug&uuml;n&nbsp;<b><i>Truva</i></b>&nbsp;filmi hakkında değil onun &ccedil;ektiği filmler hakkında konuşuyor olurduk.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Buna ek olarak insanların d&uuml;ş&uuml;nmesine olanak vermemeye &ccedil;alışan bir sistem var. Sinema, kitaplar, televizyon, dergiler hepsi bir yerde bu sisteme hizmet ediyor. En &ccedil;ok da eğitim sistemi bunun &uuml;zerine kurulu. Bizleri sadece bir işte uzmanlaşmış ve hayatı bu işten ibaret olan insanlar yapmak istiyorlar. Hepsi sistemin &ccedil;ıkarı, kar sağlaması i&ccedil;in yapılıyor. Sinemayla uğraşan insanlar olarak film &ccedil;ekerken, eleştiri yaparken buna karşı direnmemiz gerekiyor. Ve sanırım bu direnişte ufak yengiler elde etmeye de başladık. &Ouml;rneğin Fransa sineması, İngiliz Sineması, İspanyol Sineması buna &ouml;rnek. İran ve &Ccedil;in Sineması da bu konuda bir karşı &ccedil;ıkış ortaya koyuyor.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Film eleştirisinde tercih ettiğiniz bir eleştiri t&uuml;r&uuml; var mı (Marksist, ideolojik, feminist vb.)?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">S.K: Eleştirmen olarak ideolojik bir yaklaşımım var. Bu yaklaşımın sol hatta Marksist bir bakış a&ccedil;ısıyla oluştuğunu s&ouml;yleyebilirim ama asla dogmatik değil. &Ouml;rneğin ideolojik bir niteliği olmayan bir Amerikan filmi izlerken,&nbsp;<b><i>Kill Bill&nbsp;</i></b>diyelim mesela, filmin iyi y&ouml;netilip y&ouml;netilmediğinin dışında &ouml;nyargıyla bir şeyler bulup &ccedil;ıkarmaya &ccedil;alışmam. Ama genelde sosyal i&ccedil;erikli, insanların g&uuml;nl&uuml;k yaşamına politik a&ccedil;ıdan yaklaşan filmler seyretmeyi tercih ederim.&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>T&uuml;rk sinemasının izlediğiniz &ouml;rneklerini g&ouml;z &ouml;n&uuml;ne alarak tarihsel gelişimi &uuml;zerine bize neler s&ouml;yleyebilirsiniz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Tarihsel gelişim &uuml;zerine fazla bir şey bilmiyorum ancak 1970&rsquo;lerde Yunanistan&rsquo;da d&ouml;nemin ticari T&uuml;rk filmlerini izlerken T&uuml;rk Sineması ile ilgili yerleşmiş bir g&ouml;r&uuml;ş&uuml;m yoktu; ta ki 1975&rsquo;te&nbsp;<b>Yılmaz G&uuml;ney</b>&rsquo;in filmini seyredene kadar. Daha sonra Selanik&rsquo;teki ve İstanbul&rsquo;daki festivallerde başka T&uuml;rk filmleri izledim ve sanıyorum ki T&uuml;rkiye&rsquo;de bazı &ouml;nemli y&ouml;netmenler var. Mesela her iki filmini de &ccedil;ok beğendiğim&nbsp;<b>Nuri Bilge Ceylan</b>; bu yıl U&ccedil;an S&uuml;p&uuml;rge Film Festivali&rsquo;nde de bir filmi yer alan&nbsp;<b>Yeşim Ustaoğlu</b>; &ouml;nceki filmini de izleyip beğendiğim, diğerleri gibi &ccedil;ok iyi bir y&ouml;netmen olduğunu d&uuml;ş&uuml;nd&uuml;ğ&uuml;m&nbsp;<b>Derviş Zaim</b>&nbsp;ve son filmini &ccedil;ok beğendiğim&nbsp;<b>Zeki Demirkubuz</b>. Bu isimleri hatırlıyorum &ccedil;&uuml;nk&uuml; beni etkilediler. Bu y&ouml;netmenlerin ileride sinemaya yenilik getirecek y&ouml;netmenler olduğunu d&uuml;ş&uuml;n&uuml;yorum. Tabii iyi olmayan T&uuml;rk filmleri de izledim ama bu zaten her &uuml;lke i&ccedil;in ge&ccedil;erli bir şey.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Efharistume ya toreportaz! (S&ouml;yleşi i&ccedil;in teşekk&uuml;r ederiz)</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Efharisto ke ego. (Ben teşekk&uuml;r ederim)</span></p>', 197, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (59, 'ay-j180', 'robert-bresson', 'Robert Bresson', 'Kinorama 7, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 7, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Arkadin</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&Ccedil;eviren: Elif Beşer</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><i>Aşağıdaki yazı, Fransız sineması i&ccedil;inde son derece &ouml;zg&uuml;n bir sinematografi anlayışı geliştirmesiyle tanınan ve bu y&ouml;n&uuml;yle Avrupa sinemasının sanat sineması etiketini kazanmasında &ouml;nemli rol oynamış&nbsp;<b>Robert Bresson</b>&rsquo;un sanat&ccedil;ı kimliği &uuml;zerine az ama &ouml;z ipu&ccedil;ları taşımaktadır. Yazı Sightand Sound dergisinin Kış 1962/63 sayısından alınmıştır.</i></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kim ne derse desin, ben&nbsp;<b>Bresson</b>&rsquo;un&nbsp;<b><i>Proc&eacute;s de Jeanned&rsquo;Arc</i></b>&rsquo;ını (Jeanned&rsquo;Arc&rsquo;ın Yargılanması) beğendim. Yazıya b&ouml;yle sinirli başlamamın sebebi, Londra festivalinde &ccedil;oğu meslektaşımın ilk kez seyrettikleri bu filmi beğenmemiş olmalarıdır. En azından g&ouml;rebildiğim kadarıyla &ouml;yleydi. En hevesli Bressoncular bile sanki hayal kırıklığına uğramıştı. Elbette burası bunları tartışacak yer değil; hepimiz film yeni yılda Londra&rsquo;da g&ouml;sterime girene kadar &ouml;vg&uuml; ve yergilerimizi kendimize saklamaya karar verdik. Şimdilik, festival s&uuml;resince burada bulunan&nbsp;<b>Bresson</b>&rsquo;la yaptığım sohbetin bazı par&ccedil;alarını ve izlenimlerimi aktarmayı uygun g&ouml;r&uuml;yorum.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bresson</b>&rsquo;un filmlerini izlemiş ve benim hissettiklerimi hissetmiş her hangi biri, onu karşısında g&ouml;r&uuml;verse, dahası onunla y&uuml;z y&uuml;ze konuşma fırsatı bulsa, Tanrı&rsquo;yla &ccedil;ok &ouml;zel bir g&ouml;r&uuml;şme yapmakta olduğunu d&uuml;ş&uuml;n&uuml;rd&uuml;; ulaşılmaz uzaklıkta olmayan, elini uzatsa dokunabileceği bir Tanrı&rsquo;yla... Sakin, hatta &ccedil;ekingen duruşu, yumuşak y&uuml;z hatları ve kırlaşmış sa&ccedil;larıyla, arada bir toprağa ayak basma ihtiyacı duyup bulunduğu yerden usulca yere doğru kayan &uuml;rkek bir ağa&ccedil; kurt&ccedil;uğunu andırıyor&nbsp;<b>Bresson</b>. S&uuml;sl&uuml; tabağının i&ccedil;indeki &ccedil;ikolatalı tatlıyı mutlu mutlu seyrederken &ldquo;Bu krema da ne lezzetliymiş&rdquo; diye mırıldanıyor.&nbsp;<b><i>Jeanned&rsquo;Arc&nbsp;</i></b>gibi bir filmi Londra&rsquo;da g&ouml;sterime sokmak i&ccedil;in en uygun zamanı kollayan uyanık iş adamı tavırları, kafanızda yer etmiş &ldquo;Bresson&rdquo; imgesini siliyor. Karşınızdaki, filmini &ccedil;ekerken hi&ccedil; bir ayrıntıyı atlamayan, işini asla şansa bırakmayan o titiz planlama uzmanı değil artık. &ldquo;İlham bana setteyken gelir&rdquo; diyor. &ldquo;Elimde&nbsp;<b><i>Proc&eacute;s de Jeanned&rsquo;Arc</i></b>&rsquo;ın tamamlanmış senaryosu vardı. Sabah işe başlarken ne &ccedil;ekeceğimi biliyordum ama nasıl &ccedil;ekeceğim konusunda pek fikrim olmuyordu. Sanırım bu, filmin &uuml;&ccedil;te birlik kısmı i&ccedil;in ge&ccedil;erli.&nbsp;<b><i>Pickpocket</i></b>&rsquo;ta (Yankesici) ise bu bile yoktu; yankesicilik sahnelerinde ne yapmış olduğumuzu iş tamamen bittiğinde anlayabildim.&rdquo;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ancak, sohbet koyulaştık&ccedil;a ve derine dalmaya başladığınızda, kendi d&uuml;nyasını her y&ouml;n&uuml;yle bug&uuml;nden soyutlamış bir m&uuml;nzeviye toslayıveriyorsunuz. Son d&ouml;nem Fransız y&ouml;netmenleri hakkında neler d&uuml;ş&uuml;nd&uuml;ğ&uuml;n&uuml; sorunca, &ouml;z&uuml;r dilercesine &ldquo;Ben pek sinemaya gitmiyorum.&rdquo; diyor. &ldquo;Bir zamanlar giderdim ama artık katlanamıyorum. Oyuncuları izlemekten nefret ediyorum; &ouml;ylesine yanlış ve yapaylar ki! Hatta boş bir sinema salonuna girip tek başıma koltuğa oturup karşımda gerili boş perdeye bakmaya&nbsp; bile dayanamam..&rdquo; Aslına bakılırsa,&nbsp;<b>Bresson</b>&rsquo;un &ccedil;alışmalarından haberdar olduğu iki gen&ccedil; y&ouml;netmen var: Birisi, akademik kuralları ve disiplini hi&ccedil;e saymakla iyi bir şey yaptığına inandığı&nbsp;<b>Jean-Luc Godard</b>, diğeri&nbsp;<b>Godard</b>&rsquo;dan daha az yaratıcı olmakla birlikte daha zeki bulduğunu s&ouml;ylediği&nbsp;<b>Louis Malle</b>.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kendi filmini &ccedil;ekmediği zamanlarda başkalarının neler &ccedil;ektiğini merakla araştıran, filmlerle kafayı bozmuş y&ouml;netmenlere alıştığımızdan, her t&uuml;rl&uuml; dış etkiye kendini sımsıkı kapamış b&ouml;ylesi bir tavır olduk&ccedil;a şaşırtıcı geliyor insana.&nbsp;<b>Bresson</b>&nbsp;kendi filmlerine bile fazla ilgi duymuyor gibi. &ldquo;Bir iki yıl sonra kendi filmlerimi bile fazla hatırlamıyorum, artık bu filmlerin babası gibi hissetmiyorum kendimi. Hele şu kopyalar; &uuml;zerleri &ccedil;izilmiş, bozulmuş, kırılmış...&nbsp; Bunları izlemek işkence. Bir filmin g&ouml;sterime girmesinden yaklaşık altı ay sonra geriye kalan tek şey, orijinalin komik taklitleridir.&rdquo;&nbsp;<b><i>Les Anges du P&eacute;ch&eacute;</i></b>&nbsp;ve&nbsp;<b><i>Les Damesdu Bois de Boulogne</i></b>&nbsp;(Boulogne Ormanı Kadınları) ise tamamen&nbsp;<b>Bresson&nbsp;</b>kimliği taşımasına rağmen, en az ilgi duyduğu filmleri. Bunun sebebi, başından beri sinemada profesyonel oyuncuları kullanmanın yanlışlığını savunmasına rağmen parasal getiri sağlayacak ticari koşulların kendisini buna zorlamış olması. Daha sonraki filmleri i&ccedil;in de gevşek bir ilgi besliyor. Yapılan yorumların hi&ccedil;birini kişisel almıyor. &Ouml;rneğin,&nbsp;<b><i>Pickpocket</i></b>&rsquo;tan aldığım zevkin&nbsp;<b><i>Le Journald&rsquo;un Cur&eacute; de Campagne</i></b>&nbsp;(Bir&nbsp; K&ouml;y Papazının G&uuml;nl&uuml;ğ&uuml;) veya&nbsp;<b><i>Un Condamn&eacute; &agrave; Mort s&rsquo;est Echapp&eacute;</i></b>&rsquo;deki (Bir İdam Mahkumu Ka&ccedil;tı) kadar olmadığını &ccedil;&uuml;nk&uuml; rol&uuml;n&uuml; hak ettiği şekilde taşıması gereken esas akt&ouml;r&uuml;n sergilediği performansı yeterince tatmin edici bulmadığımı s&ouml;ylediğim zaman hi&ccedil;bir duygusal tepki g&ouml;stermiyor ve haklı olabileceğimi, ne var ki; Uruguay&rsquo;dan geldiği ve Fransızcası pek iyi olmadığı i&ccedil;in &ouml;zellikle bu oyuncuyu (Martine Lassalle) tercih ettiğini, zaten niyetinin, akt&ouml;r&uuml;n oyunculuk yeteneğini seyircinin g&ouml;z&uuml;ne sokmak olmadığını belirtiyor. Ve t&uuml;m bunlar &uuml;zerine&nbsp;<b>Bresson&nbsp;</b>şu c&uuml;mleleri dile getiriyor:</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Rol, pi&ccedil; bir sanat olan tiyatro i&ccedil;indir. Film sanatı ise ger&ccedil;eğin yansımasıdır. Yazar, ger&ccedil;ek yaşamdan kesitler alıp onları &ouml;yle bir d&uuml;zenler ki; her biri birbiri ardına sıralandığında artık d&ouml;n&uuml;ş&uuml;m ge&ccedil;irmiş olurlar. Sanat, d&ouml;n&uuml;şt&uuml;rmektir. Her &ccedil;ekim, kendi başına hi&ccedil;bir şey ifade etmeyen ya da &ccedil;ok fazla şey ifade ettiği i&ccedil;in ilk anda anlamsız g&ouml;r&uuml;nen bir kelime gibidir. Şiirde de kelime d&ouml;n&uuml;şt&uuml;r&uuml;l&uuml;r; etrafına yerleştirilmiş diğer kelimelerle birlikte anlamı eşsiz kılınır. Aynı şekilde, bir filmdeki tek bir &ccedil;ekim diğer &ccedil;ekimlerle oluşturduğu b&uuml;t&uuml;n i&ccedil;inde anlamını bulacaktır. Her &ccedil;ekim kendisinden &ouml;nce gelenin a&ccedil;ılımıdır. Bu, son &ccedil;ekime kadar b&ouml;yle devam eder. Kestirmeden gitmek, &ouml;zetleyerek anlamı vermeye &ccedil;alışmak bu bakımdan olanaksızdır. Anlam, b&uuml;t&uuml;n &ccedil;ekimlerin toplamıdır. Rol&uuml;n t&uuml;m bunlarla hi&ccedil; ilgisi yoktur. Rol, siz filminizde yol alırken kendiliğinden ortaya &ccedil;ıkandır. Filmde oyuncunun kendi iradesi dahilinde yaptıklarını &ouml;ne &ccedil;ıkarmak durumundasınız. Film &ccedil;ekmek oyuncunun yaptığı rol&uuml; değil, bizzat kendisini kullanmaktır.&rdquo;</span></p>', 198, 63, 'Yazarlarımızdan', NULL, '2017-03-05');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (60, 'ay-j181', 'propaganda-kizi-riefenstahl', 'Propaganda Kızı: Riefenstahl', 'Kinorama 6, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 15.3333px;">Kinorama 6, 2004</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 15.3333px;">Arkadin</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><strong><span style="line-height: 15.3333px;">&Ccedil;eviren: Burak Benk</span></strong></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><span style="line-height: 15.3333px;">Yaratıcı dehaya sahip y&ouml;netmenler, herhangi birini kaybetmeyi g&ouml;ze alabilecegimiz kadar &ccedil;ok degiller. Tabii, mesela,&nbsp;<b>Dreye</b>r&rsquo;in filmlerini birbirinden ayıran veya&nbsp;<b>Sternberg</b>&rsquo;in edimsiz/&uuml;r&uuml;ns&uuml;z ge&ccedil;irdigi yılları hesaba katarak aksini de d&uuml;ş&uuml;nebilirsiniz.&nbsp;</span>Bambaşka, politik nedenlerle (temelde,&nbsp;<b><i>Triumph of the Will&nbsp;</i></b>ile kazandigi Nazi propagandasi &uuml;n&uuml; nedeniyle)&nbsp;<b>Leni Riefenstahl&nbsp;</b>yirmi yıldır film yapmıyordu. Fakat artık, nihayet, yeni bir film &ccedil;ekiyor. Şimdilerde kurgusuyla uğraştığı filmi, eğitim ve asimilasyonun eşiğinde geleneksel yapılarını sonsuza kadar kaybetme tehlikesiyle y&uuml;zy&uuml;ze olan, Sudan&rsquo;daki Nuba kabilesinin yaşamı hakkında renkli &ccedil;ekilmiş bir belgesel. En sonunda, &uuml;zerinde &ccedil;alışmakta olduğu bazı materyalleri g&ouml;rmek (ki muhteşem g&ouml;r&uuml;n&uuml;yorlardı) ve sıradışı kariyeri hakında konuşmak i&ccedil;in, efsanevi Bayan&nbsp;<b>Riefenstahl&nbsp;</b>ile tanişma firsatına M&uuml;nih&rsquo;te eriştim. İşte, kısaca, t&uuml;m olanları nasıl algıladığı &uuml;zerine s&ouml;yledikleri.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i><span style="line-height: 15.3333px;">Triumph of the Will&nbsp;</span></i></b>hakkında: &ldquo;Hitler, iktidara geldikten kısa bir s&uuml;re sonra beni &ccedil;agırıp, Parti Kongresi &uuml;zerine bir film istedigini anlattı ve filmi benim &ccedil;ekmemi istedi. İlk tepkim, bu tarz bir işin yapılma bi&ccedil;imi veya Parti &ouml;rg&uuml;tlenmesinin işleyişi hakkında hi&ccedil;bir fikrim olmadığı i&ccedil;in yanlış g&ouml;r&uuml;nt&uuml;leri &ccedil;ekerek kimseyi memnun edemeyecegimi s&ouml;ylemek oldu. Hatta, bir belgesel &ccedil;ekebileceğimi varsayarak s&ouml;yl&uuml;yordum bunları ki daha &ouml;nce &ccedil;ekmişliğim de yoktu. Oysa Hitler, bu iş i&ccedil;in beni uygun g&ouml;rmesinin nedeninin tam da bu olduğunu s&ouml;yledi: &Ccedil;&uuml;nk&uuml;, kimi insanların, grupların ve diğer unsurların g&ouml;reli &ouml;nemi hakkında fikri olan biri ayrıntıcı ve kesin bir film yapabilecekken, onun istediği bu değildi. O, kongreyi uzman olmayan birinin g&ouml;z&uuml;yle, sanatsal olarak tatmin edici g&ouml;r&uuml;nt&uuml;lerle g&ouml;stermek istiyordu denebilir. Politikaya ilgisi olmayan izleyiciye de cazip gelecek, onu etkileyip harekete ge&ccedil;irecek bir film istiyordu.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Bu bi&ccedil;imiyle, Parti i&ccedil;inden bir&ccedil;ok karşı &ccedil;ıkışla y&uuml;zy&uuml;ze gelebileceğimi s&ouml;ylediğimde beni olumladı; ama beni bundan koruyacağını ve filmi t&uuml;m&uuml;yle herhangi bir m&uuml;dahale olmadan &ccedil;ekebileceğimi s&ouml;yledi. Kongre iki-&uuml;&ccedil; hafta sonra ger&ccedil;ekleşeceği i&ccedil;in o yıl &ccedil;ekime hazırlanacak vaktim yoktu; fakat en azından hissiyatını yakalayabilmek i&ccedil;in&nbsp;<b><i>Victory of Faith</i></b>&nbsp;adında kısa bir r&ouml;portajını yaptım.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Ve ardından, gelecek yıl i&ccedil;in hazırlanmaya başladım. Hitler, m&uuml;dahale olmaması konusunda s&ouml;z&uuml;n&uuml; tuttu; hatta kendisi bile bir kere dışında m&uuml;dahale etmeye yeltenmedi. O da&nbsp;<b>Wehrmacht</b>&nbsp;(Silahlı Kuvvetler) ile ilgiliydi. &Ouml;zellikle etkileyici g&ouml;r&uuml;nm&uuml;yorlardı. &Uuml;stelik ge&ccedil;it t&ouml;reni esnasında onlar ge&ccedil;erken yağmur da yağmıştı; bunun &uuml;zerine ben de o &ccedil;ekimleri filmin bitmiş halinde kullanmadım. Fakat durum bir şekilde Hitler&rsquo;in kulağına gitti ve bunun sorun yaratacağını s&ouml;ylemek i&ccedil;in beni &ccedil;ağırttı. O g&ouml;r&uuml;nt&uuml;leri bir şekilde koyamaz mıydım? Hayır, dedim, materyal k&ouml;t&uuml;yd&uuml; ve doğru g&ouml;r&uuml;nmezdi. O halde, diye &ouml;nerdi, onları tatmin etmek i&ccedil;in&nbsp;<b>Wehrmacht&rsquo;</b>ın tarihi hakkında bir girizgah ekleyemez miydim? U&ccedil;ağın bulutların i&ccedil;inden gelişini g&ouml;steren bu g&uuml;zel ve yavaş girişi tasarlamıştım ve başka bir g&ouml;r&uuml;nt&uuml;n&uuml;n filmi katledeceğini d&uuml;ş&uuml;n&uuml;yordum, bu y&uuml;zden hayır dedim. &lsquo;Peki, Leni,&rsquo; dedi Hitler, &lsquo;istediğin gibi yap; sana s&ouml;z verdim. Ama seni uyarıyorum, buradan &ccedil;ıkacak sorundan seni koruyamam.&rsquo; Duyduklarım hoşuma gitmemişti, ama ne olursa olsun filmimi hi&ccedil; kimse i&ccedil;in mahvetmeyecektim; işte bu y&uuml;zden t&uuml;m filmde&nbsp;<b>Wehrmacht</b>&nbsp;ile ilgili tek bir &ccedil;ekim yoktu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Tabii ki bununla ilgili bir&ccedil;ok sorun &ccedil;ıktı -<b>Goebbels</b>&nbsp;zaten benden nefret ediyordu ve bu işimi zorlaştırıyordu-; ama sonunda&nbsp;<b>Hitler</b>, durumu d&uuml;zeltmek i&ccedil;in &ouml;zellikle&nbsp;<b>Wehrmacht&nbsp;</b>&uuml;zerine bir film &ccedil;ekmeyi kabul etmemi &ouml;nerdi. Son politik filmim olması d&uuml;ş&uuml;ncesiyle ve bunda anlaşarak kabul ettim. Birka&ccedil; g&uuml;n i&ccedil;inde&nbsp;<b><i>Day of Freedom&nbsp;</i></b>isimli kısa bir film &ccedil;ektim ve artık herkes memnundu, &ouml;zellikle de ben, &ccedil;&uuml;nk&uuml; iyi bir iş &ccedil;ıkmıştı. G&ouml;r&uuml;nen o ki film t&uuml;m&uuml;yle ortadan kayboldu, ki &ccedil;ok yazık oldu, &ccedil;&uuml;nk&uuml; ben onu t&uuml;m&uuml;yle sıkı, dinamik bir kurgunun &uuml;r&uuml;n&uuml; olarak g&ouml;r&uuml;yorum ki muhtemelen de yaptığım en iyi şey odur.&rdquo;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i><span style="line-height: 15.3333px;">Penthesilea&nbsp;</span></i></b>hakkında: &ldquo;Bu ger&ccedil;ekten de t&uuml;m kariyerimin en b&uuml;y&uuml;k hayal kırıklığıdır.&nbsp;<b><i>The Blue Light&rsquo;</i></b>tan beri hep Kleist&rsquo;in trajedisini filme &ccedil;ekmeyi d&uuml;şlemişimdir, kısmen oyuncu olarak -&uuml;mitsizce oynamak istediğim bir b&ouml;l&uuml;md&uuml;r- ama asıl y&ouml;netmen olarak. Fakat, &ouml;ncelikle&nbsp;<b><i>Triumph of the Will</i></b>, sonra da&nbsp;<b><i>Olympiad&nbsp;</i></b>ile hedefimden saptırıldım. Nihayet t&uuml;m hazırlıkları tamamladığım 1939 yılındaysa savaş &ccedil;ıktı ve ertelenmek durumunda kaldı, bu kez sonsuza kadar. Oysa t&uuml;m&uuml; aklımda kuruluydu, ki hala da &ouml;yle. Bildiğim kadarıyla şimdiye dek hi&ccedil; kimse, b&uuml;y&uuml;k bir şiirsel metnin ciddi olarak filmini yapmaya ger&ccedil;ekten kalkışmadi. Anlatmaya &ccedil;alıstığım şey, hem filmin hem de şiirin hakkını tamamıyla verecek bir film yapmak. Bence&nbsp;<b>Olivier&rsquo;</b>in&nbsp;<b>Shakespeare</b>&nbsp;filmleri bayağı hayal kırklıklığına uğratıcıdır, &ccedil;&uuml;nk&uuml; &ouml;nce birini sonra diğerini kurban ederek bocalar: şimdi bir par&ccedil;a&nbsp;<b>Shakespeare</b>, şimdi bir par&ccedil;a sinema, şimdi yine bir par&ccedil;a&nbsp;<b>Shakespeare</b>.&nbsp;<b>Orson Welles&nbsp;</b>muhteşem g&ouml;r&uuml;nt&uuml;ler &ccedil;izer; ama onun filmleri, Shakespeare&rsquo;in kendisi olmaktan &ccedil;ok&nbsp;<b>Shakespeare&nbsp;</b>tarafindan &ouml;nerilmiş opera veya baleler gibidir.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;Bana g&ouml;re hepsi g&ouml;reli yogunluklarla ilgili. Herhangi bir şiirsel metin, değişken elektrik akımında olduğu gibi, dalga hareketi tarzında bir gelişim g&ouml;sterir: en y&uuml;ksek şiirsel yoğunluk durumuna ancak bir veya iki satırda, veya en fazla bir konuşmada ulaşir, sonra d&uuml;şer, ardından yine y&uuml;kselir. Bir film de g&ouml;rsel olarak aynı bi&ccedil;imde hareket eder: izleyiciyi g&uuml;zellik ve ihtişamla boğamazsınız; bunun i&ccedil;in, bir sahnenin g&ouml;rsel ifade g&uuml;c&uuml;n&uuml; bir nevi doruk noktasına kadar yogunlaştırır, daha sonra tekrar y&uuml;kselmek &uuml;zere s&ouml;nmesine izin verirsiniz. Yapılması gereken, bu iki dalga hareketini karşılaştırıp oransal olarak birbirlerini dengelemelerine bakmaktır. Bu, kelimenin tam anlamıyla sağlam bir filmin nasıl olması gerektiğiyle ilgili temel unsurlardan birisidir: ritm her şeyin temelindedir.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;<b><i>Penthesilea</i>&rsquo;</b>yı doğal bir &ccedil;evrede, ama onu t&uuml;m&uuml;yle ger&ccedil;ekdışı bir şekilde kullanarak sahnelemek istedim. Bazı g&ouml;r&uuml;nt&uuml;ler olduk&ccedil;a ayrıntılı olacaktı; zarif bir bi&ccedil;imsellikle, antik duvar s&uuml;slemeleri ruhuyla tasarlanmış g&ouml;rsellik ve onu kuşatan, muazzam b&uuml;y&uuml;kl&uuml;ğ&uuml; ve &uuml;rpertici g&uuml;zelliğiyle bir ay veya alev alev yanan, engin ve destansı bir g&uuml;neş. Metnin şiirsel yoğunluğu arttık&ccedil;a, en m&uuml;thiş satırların yer aldığı sahnelerin g&ouml;rsel yoğunluğu azalacak ve belki de herşey, sadece ana hatlarıyla, yalın betimlenen iki g&ouml;r&uuml;n&uuml;me indirgenecekti.&nbsp;<b><i>Penthesilea&nbsp;</i></b>baş yapıtım, kariyerimin tepe noktası olabilirdi...&rdquo;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ama tabii o da, pek &ccedil;ok savaş ertesi projesi gibi hi&ccedil;bir yere varmadı: &Ccedil;ağdaş giyimli, kayakları &uuml;st&uuml;nde bir&nbsp;<b><i>Penthesilea&nbsp;</i></b>olan&nbsp;<i><strong>T</strong><b>he Red Devil</b></i>;&nbsp;<b>Cocteau&rsquo;</b>nun yazacağı ve iki karakteri de oynayacağı&nbsp;<b><i>Voltaireand Frederick</i></b>; &ccedil;ekimlerine başlanan, ama Bayan&nbsp;<b>Riefenstah</b><strong>l</strong>&rsquo;ın bir otomobil kazasında yaralanmasıyla sona eren, k&ouml;lelik hakkında bir belgesel olan&nbsp;<b><i>Black Cargo</i></b>;&nbsp;<b><i>The Blue Light</i>&rsquo;</b>in,&nbsp;<b><i>The Red Shoes&nbsp;</i></b>ile paralellikleri olan bale tarzı bir yeniden &ccedil;evrimi. Ancak şimdi, nihayet 1954&rsquo;te kurgulanan ve yayınlanan son filmi&nbsp;<b><i>Tiefland</i>&rsquo;</b>i &ccedil;ekişinin yirmi yıl ardından, bu kez ger&ccedil;ekten işinin başında.</span></p>', 198, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (61, 'ay-j182', 'sinema-her-seyiyle-durust-olmali', 'Sinema Her Şeyiyle Dürüst Olmalı', 'Kinorama 5, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: 18px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 20px;">Kinorama 5, 2004</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: 18px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i><span style="line-height: 20px;">&ldquo;Sinemada ahlaki iyileşme geri d&ouml;n&uuml;ş&uuml; olmayan bir s&uuml;re&ccedil;tir.&rdquo;</span></i></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: 18px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i><span style="line-height: 20px;">Elem Klimov</span></i></b></span></p>\r\n<p><b style="font-family: arial, helvetica, sans-serif; font-size: 13.3333px; text-align: justify;"><span style="line-height: 20px;">&Ccedil;eviren: Elif Beşer</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: 18px;"><span style="font-size: 10pt; line-height: 20px; font-family: arial, helvetica, sans-serif;">9 Temmuz 1933&rsquo;de Stalingrad&rsquo;da doğdu. 1957-58 yılları arasında, Moskova yapım evlerinde, radyo ve merkez televizyonunda baş yazar kadrosunda &ccedil;alıştı. 1964&rsquo;de VGIK&rsquo;de Yapımcılar Fak&uuml;ltesi&rsquo;nden mezun oldu. 27 Ekim 2003 g&uuml;n&uuml; &ouml;ld&uuml;. &Ouml;nemli filmleri:&nbsp;<b><i>Bir Diş&ccedil;inin Maceraları&nbsp;</i></b>(1965),&nbsp;<b><i>Veda&nbsp;</i></b>(1980),&nbsp;<b><i>Gel ve G&ouml;r&nbsp;</i></b>(1985)</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: 18px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 20px;">&Uuml;lkemizde yaşanan değişimler karşısında Sovyet sinemasının tutumu nasıl oldu?</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sovyet Sinema Emek&ccedil;ileri Birliği&rsquo;nin beşinci kongresi 1986 Mayısında toplandı ve burada, son birka&ccedil; yıldır Sovyet sinema end&uuml;strisini etkisi altına almış tutuculuğa ve end&uuml;strideki durgunluğa savaş ilan edildi. Bunun temeli ş&uuml;phesiz Sovyetler Birliği Kom&uuml;nist Partisi (CPSU) 27. kongresinde atılmıştır. O kongrede sadece yeni &ccedil;alışma y&ouml;ntemlerine y&ouml;nelik ani bir değişimin varlığı saptanmakla kalınmamış, bu değişim i&ccedil;in gerekli olan politik, ideolojik ve dilerseniz psikolojik &ouml;n g&ouml;stergeler de yaratılmıştır. A&ccedil;ık&ccedil;ası &ccedil;oğumuz b&ouml;yle g&uuml;nleri g&ouml;recek kadar uzun yaşayacağımızı d&uuml;ş&uuml;nm&uuml;yorduk ama b&ouml;yle g&uuml;nler geldi işte. Birlik kongresinin delegeleri kategoriler halinde, Sovyet sinemasındaki radikal değişikliklerin savunuculuğunu yaptılar; başka bir s&ouml;ylemle, iki-&uuml;&ccedil; sene &ouml;ncesine kadar insana hayal gibi gelen d&uuml;ş&uuml;nce ve &ouml;ng&ouml;r&uuml;lerin biran &ouml;nce somutlaştırılmasının gereğini savundular.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Sovyet sinemasının gelişimindeki i&ccedil; eğilimler hakkında fazla bilgisi olmayan bir kişi s&ouml;z&uuml;n&uuml; ettiğiniz radikal değişikliklerin neden gerekli olduğunu merak edebilir. Sonu&ccedil;ta, Sovyetler Birliği&rsquo;nin bilinen bir sinema end&uuml;strisi var.&nbsp; Yılda yaklaşık 150 konulu film (ek olarak 100 TV filmi), 1000&rsquo;in &uuml;zerinde belgesel, 130 civarında animasyon &uuml;retiliyor. &Uuml;lkemizde sinema en pop&uuml;ler sanat formu. Biletlerin yıllık satışı yaklaşık d&ouml;rt milyar, bu da demektir ki; istatistiksel ortalamaya g&ouml;re insanlar yılda en az on d&ouml;rt kez sinemaya gidiyor. Sovyet filmleri d&uuml;nyada y&uuml;z otuz d&ouml;rt &uuml;lkede g&ouml;steriliyor ve en b&uuml;y&uuml;k festivallerde &ouml;d&uuml;l kazanıyor.</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">T&uuml;m bunlar doğru. Ne var ki; sanat tartışmaları rakamlara dayanarak yapılamaz. Yirmi yılı aşkın s&uuml;redir, başarı raporlarını pek sevenlerin &uuml;zerine basa basa vurgulayıp durdukları tek şey rakamlar. Film &uuml;retimi y&ouml;netiminin g&ouml;n&uuml;ll&uuml; ve b&uuml;rokratik bir anlayışla şekillendirdiği ilkeler bizi bir &ccedil;ıkmaza s&uuml;r&uuml;klemiştir. 1950&rsquo;lerde ve 1960&rsquo;ların ilk yıllarında Sovyet sineması s&uuml;rekli y&uuml;kselen bir &ccedil;izgi izlerken, bu tırmanış birtakım kişisel kazanımlara rağmen bir gerilemeye yol a&ccedil;tı, yani Sovyet filmleri giderek toplumumuzda d&uuml;şmanlığı arttırıcı, nefret dolu fikirler taşıyan, seviyesi d&uuml;ş&uuml;k, sanat algısı gelişmemiş bir gurup seyirci kitlesine yaranmak istenircesine &uuml;retilmeye başlandı. &Ccedil;ok sayıda form değişiminin sonucu olarak, 1950&rsquo;lerde ve 1960&rsquo;ların ilk yıllarında Sovyet filmlerinin ayarını belirleyen sosyal ve yerel değerler, ihtiya&ccedil; duyulan filmlerin yapılabilmesi adına giderek artan &ouml;l&ccedil;&uuml;de &ouml;zlerinden yitirdiler. Film yapımcılarının destek&ccedil;ileri, daha a&ccedil;ık bir ifade ile film d&uuml;nyasının kurnaz satıcıları ortalığa &ccedil;ıktılar. Bu adamlar, komisyonlarını aldıkları s&uuml;rece ve filmler hi&ccedil;bir engele takılmadan iyi para getirdiği s&uuml;rece, ne olursa g&ouml;stermeye hazırlardı. T&uuml;m bunların sonucunda &ccedil;&uuml;r&uuml;me başladı, &ccedil;ekemezlik, yalakalık ve bir s&uuml;r&uuml; başka olumsuz fenomen aldı y&uuml;r&uuml;d&uuml;.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Beşinci kongrenin delegeleri bunları acı bir dille ifade etti. Ama yaptıkları asıl şey, Birliğin &ouml;nceki liderlerini eleştirmekti. Bu liderlerin etkinlikleri &ccedil;ekingen bir tavır i&ccedil;inde Goskino&rsquo;ya kısa s&uuml;reli asistanlık yapmakla sınırlandırılmıştı. Her biri, uzun s&uuml;redir eleştiriden ve nesnel halk değerlendirmesinden uzak kalmak suretiyle sinemanın bilirkişileri haline gelmiş belirli bir z&uuml;mreye rahat bir yaşamın garantisini veren rit&uuml;ellerin peşinden gitmiştir.</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Beşinci kongrede asıl &ouml;nemli olan geniş &ouml;l&ccedil;&uuml;de unutulmuş bir inancın yeniden diriltilmiş olmasıdır. O da şudur: Ger&ccedil;eğin ve ahlakın diyarında belirsiz noktalar, &ouml;nemsiz ayrıntılar olamaz. Her şey &ouml;nemlidir. Birliğin yeni liderleri b&uuml;y&uuml;k ve k&uuml;&ccedil;&uuml;k t&uuml;m sorunların &ccedil;&ouml;z&uuml;m&uuml;nde bu inancı esas almıştır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Peki nedir asıl sorun?</b>&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Film &uuml;retimi i&ccedil;in, kanımca, i&ccedil;inde bulunduğumuz konumu t&uuml;m&uuml;yle değiştirecek yeni bir model geliştirdik. Bu model iki temel ilkeye dayanıyor: Demokratikleşme ve otoritenin alt birimlere dağılımı. B&ouml;yle bir modeli yaratmak hi&ccedil;bir şekilde kolay olmadı. &Ccedil;ok fazla zaman ve &ccedil;aba harcadık. Şartlar eskiden nasılsa şimdi de &ouml;yle. K&ouml;kl&uuml; yeniden yapılandırma i&ccedil;in ilk adımı atma ve yeni modele g&ouml;re filmler &uuml;retme projesini geliştirme işi Goskino&rsquo;nun sırtına binmemiştir; bu, Sinema Emek&ccedil;ileri Birliğinin g&ouml;revidir. Bu reform hareketinin kurallarını belirlerken girdiğimiz m&uuml;cadele olduk&ccedil;a uzun ve yorucu bir s&uuml;reci kapsıyor. Bazıları, kendilerini iki ya da &uuml;&ccedil; tane st&uuml;dyoda edinecekleri deneyimle sınırlı tutarak bu deneyimlerin, &ouml;rneğin 90&rsquo;ların sonuna kadar nasıl sonu&ccedil;lanacağını g&ouml;rmeyi istedi. Kimisi &ouml;zel bir kozmetik onarımı yani altyapıyı değiştirmeksizin y&uuml;zeydekini d&uuml;zeltmeye gitmeyi &ouml;nerdi. Hatta yeniden yapılandırma modeline karşı fikirler geliştirip bunları savunanlar oldu. Bunların mantığına g&ouml;re Goskino bize baskı uygulamaktan vazge&ccedil;mişti, Birliğin konumu belirginleşmişti ve filmler, &uuml;zerlerinde fazlaca bir d&uuml;zeltme yapılmaksızın kabul ediliyordu. Daha ne isteyebilirdik? Ne diye ortalığı dalgalandırmamız gerekiyordu? Oysa emin olduğumuz şey, dalga &ccedil;ıkarmak zorunda olduğumuzdur. Bu tembelliğin &uuml;stesinden başka nasıl gelinir ki? Yaptığımızın derin kırışıklıkları bir s&uuml;reliğine gizlemek adına ustaca uygulanmış bir makyaj olmadığını belirtmek istiyorum. Amacımız kalıcı &ccedil;&ouml;z&uuml;me ulaşmak. Oluşturduğumuz yeni modele g&ouml;re, y&ouml;netimin bundan &ouml;nce h&uuml;k&uuml;m s&uuml;rm&uuml;ş idari formlarından ekonomik alanlara ge&ccedil;iş yapmamız gerekiyor. Goskino artık film yapımcıları &uuml;zerindeki kontrol&ouml;r konumunda olmayacak. Film yapımındaki t&uuml;m sorumluluğu, kendine g&uuml;veni tam ve&nbsp; kendine yeterli bi&ccedil;imde &ccedil;alışan st&uuml;dyo &uuml;stlendi. Kendine yeterlilikten kasıt giderin gelirden karşılanması. Gelirin tek kaynağı ise film g&ouml;sterimlerinden elde edilen girdiden sağlanacak ve st&uuml;dyonun kendisi dağıtıcılarla ilişki halinde olacak.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Yurt dışındaki film &uuml;retimi ile bu yeni model arasında bir benzerlik var mı?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hayır, hi&ccedil; yok. Sekt&ouml;r&uuml;n işletilmesinde devletin ve toplumun birbirleriyle etkileşimi ve kaynaşması ve birlikte ortaya bir şeyler koymaları yeni bir tecr&uuml;be ve yalnızca &uuml;retim ara&ccedil;larının sosyalist m&uuml;lkiyete ait olduğu yerlerde g&ouml;r&uuml;nen bir olay. Aklıma gelmişken, model araştırmamıza diğer sosyalist &uuml;lkelerdeki meslektaşlarımız da fazlasıyla ilgi g&ouml;sterdi. Onların elde edecekleri tecr&uuml;beler bizim i&ccedil;in &ouml;nemli. Birbirimizi tanıyarak daha &ccedil;ok zenginleşeceğiz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Sovyet sinema end&uuml;strisinin Batıdan yararlı bir şeyler alabileceğini d&uuml;ş&uuml;n&uuml;yor musunuz? &Ouml;rneğin Amerikan sinema end&uuml;strisinden...?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Tecr&uuml;belerini hesaba katmak yararlı olabilir. Amerika&rsquo;ya yaptığım bir ziyarette seyirci talebini araştırmak adına hi&ccedil;bir &ccedil;aba ve kaynak harcanmadığını g&ouml;rd&uuml;m. &Uuml;lkemizde ise bu s&uuml;re&ccedil; ağır ve sadece şartlar &ouml;yle gerektirdiği zaman işliyor. Aslında izleyicilerimizi tanımıyoruz. Bu y&uuml;zden film ve seyirci arasındaki bağı kuramıyoruz. Neyse ki; yeni modelimizi tanıttık&ccedil;a, sosyologlar ve psikologlar ger&ccedil;ek film &uuml;retim s&uuml;recine dahil olabilecekler. Şu anda hızlı bir şekilde kurulmakta olan sosyoloji servisi, pazarın durumunu araştıracak, filmlerin ve izleyicilerin tipolojik a&ccedil;ıdan incelenmesinin sonu&ccedil;larını filmleri &uuml;retirken ve g&ouml;sterime sokarken yansıtma olanağı bulacağız. Tema planlamasının modası ge&ccedil;miş kurallarını kaldırıp atacağız. Bu kurallar altında, temalandırma aşaması &ccedil;ok&ccedil;a Goskino ofislerinin o ağır havasında uzun uzun yoğrulmuştur veya g&uuml;ncelleştirme&nbsp; dediğimiz ve senaristin ya da y&ouml;netmenin kendi filminde bulup &ccedil;ıkartmak zorunda kaldığı ve bu y&uuml;zden &ouml;znel bir yorum taşıyan olgunun tamamen dışında yaratılmıştır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Filmlerinizin, &ouml;rneğin&nbsp;<i>Come and See</i>&nbsp;ve&nbsp;<i>Agony</i>&rsquo;nin k&ouml;t&uuml; bir kaderleri vardı. 1965&rsquo;te &ccedil;ektiğiniz&nbsp;<i>The Adventures of a Dentist</i>&nbsp;ise genel g&ouml;sterime yeni girdi.</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Neyse ki, bu film komite sayesinde g&ouml;sterilebildi. Genelde, rafa kaldırılmış filmleri izlediğimizde bir s&uuml;r&uuml; s&uuml;rprizle karşılaşıyoruz.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İlk keşfettiğimiz şey, hayal ettiğimizden daha &ccedil;ok filmin raflar i&ccedil;inde tozlanmaya terk edilmiş olduğuydu. Sonra, son birka&ccedil; yıldır sinemamızdan esirgenenin sadece ilgin&ccedil; bir iki &ccedil;alışma olmadığını, bu &ccedil;alışmaların fevkalade &ouml;nemli yapıtlar olduğunu hatta somut akımların başını &ccedil;eken olduk&ccedil;a başarılı film &ouml;rnekleri olduklarını g&ouml;rd&uuml;k. Bu sorun, diğerlerinin yanında, son derece &ouml;nemli ahlaki bir boyut barındırıyor. Raftan &ccedil;ekilmiş her filmin ardında bir insanın baltalanmış kariyeri, hatta y&ouml;n&uuml; saptırılmış kaderi yatıyor. Ge&ccedil;mişi kara bir perde gibi kaplamış bu d&uuml;zensizlikle ve adaletsizlikle başa &ccedil;ıkmadan, bir gelecekten bahsetmek imkansız. Neyse ki; yeni zamanlar geldi, bu harika bir şey. Şimdi, bu filmleri ve senaryoları hayata d&ouml;nd&uuml;r&uuml;yoruz ve i&ccedil;lerine girdik&ccedil;e, bize nasıl hayat verdiklerini hissediyoruz, yeniden yapılanıyoruz, ger&ccedil;ek kimliklerimizi yani i&ccedil;imizde ger&ccedil;ekten bulunan ve bir şekilde ayakta kalmış kişiliğimizi tekrar kazanıyoruz. Komite, g&ouml;sterim i&ccedil;in &ouml;zel bir filmi tavsiye ederken &ouml;zellikle bu ger&ccedil;eği g&ouml;z &ouml;n&uuml;nde bulunduruyor, yani Sovyet sinemasını meydana getiren t&uuml;m &uuml;r&uuml;nlerin seyirciyle buluşması gerektiği ger&ccedil;eğini. Komitenin başkanı film eleştirmeni&nbsp;<b>Andrei Plakhov</b>. Tanınmış yapımcıların dışında (&ouml;rneğin, y&ouml;netmenlerden&nbsp;<b>Nikolai Gubenko</b>,&nbsp;<b>Ali Khamrayev</b>&nbsp;ve&nbsp;<b>Nikita Mikhalkov</b>) komiteyi oluşturanlar Goskino&rsquo;nun temsilcileri. Her şeyde a&ccedil;ıklık havası hakim. Sinema emek&ccedil;ileri, Komite&rsquo;nin &ccedil;alışmalarını ilgi ve umutla izliyor. Komite başarısız g&ouml;rd&uuml;ğ&uuml; filmlerin g&ouml;steriminde ısrar etmiyor. Burada kesinlikle g&ouml;z &ouml;n&uuml;nde tutulması gereken şey, bireylerin değerlendirilmesinin adil ve nesnel bir şekilde yapılabilmesi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bu soru i&ccedil;in l&uuml;tfen bağışlayın, basında ve başka yerlerde hakkınızda &ccedil;ıkan yargılayıcı birtakım yazılar &uuml;zerine soruyorum: Şu anda her şeyin sizin zevk ve tercihlerinize g&ouml;re d&uuml;zenlendiği s&ouml;yleniyor, b&ouml;yle bir şeyle gurur duyacak birisi olmadığınızı biliyorum, ama merak ediyorum, bununla nasıl başa &ccedil;ıkacaksınız?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Daha &ouml;nce b&ouml;yle bir durumla y&uuml;zleşmek zorunda kalmamıştım hi&ccedil;. İki sene &ouml;nce neysem şimdi de o olmama rağmen, bana karşı davranışların değiştiğini g&ouml;rebiliyorum. &Uuml;stelik ilişkide olduğum kişiler aynı. Bana ise başka birisiymişim gibi davranıyorlar. &Ccedil;&uuml;nk&uuml; ben &uuml;st bir pozisyona geldim,&nbsp;<i>şef</i>&nbsp;oldum. Bu &ccedil;ok can sıkıcı bir durum. İster inanın, ister inanmayın, kendi yaptığım işler hakkında daima &ccedil;ok eleştirel oldum, bu konuda da olduk&ccedil;a başarılıyımdır. Kendi filmlerimin en acımasız eleştirmeniyim ve bu y&uuml;zden bitirdiğim bir filmi izlemekten &ouml;zellikle ka&ccedil;ınmak gibi bir kural belledim. &Ccedil;&uuml;nk&uuml; filmde g&ouml;rd&uuml;ğ&uuml;m kusurlar beni bunalıma itiyor. İleride kendim i&ccedil;in de benzer bir y&ouml;ntem uygulamayı planlıyorum. Tabi, hayatım bu anlamda &ccedil;ok karmaşıklaştı. &Ouml;nceden sadece bir y&ouml;netmendim. Bir filmi tasarlayıp, gerekli işlemleri yapıp &uuml;zerinde &ccedil;alışmaya başlardım, bu ortamda, olması gerektiği gibi &ouml;zg&uuml;rd&uuml;m. Kendimi geleceğe y&ouml;nelik d&uuml;ş&uuml;ncelerden soyutlayabiliyordum. Şimdi ise bir film yapmaya kalksam-ki, kafamda bu fikri d&ouml;nd&uuml;r&uuml;p duruyorum- b&ouml;ylesi bir soyutlama &ccedil;ok zor olacaktır. Her hareketim tetkik edilecek. &Ccedil;alışmalarıma k&ouml;t&uuml; niyetli ilgilerin y&ouml;nelmesi olasılığından da korkuyorum. Bu doğal elbette. Yeniden yapılandırma adına bir s&uuml;r&uuml; kişiye rahatsızlık verdik. Sinema end&uuml;strisinde olup biten değişimler, d&uuml;zg&uuml;n yaşamlarını, maddi g&uuml;vencelerini sarstı. Birliğin &ccedil;alışmalarından duydukları hoşnutsuzluğu genelden &ouml;zele yani bireylere indirgediler, ben de nasibimi alıyorum.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bir seyirci, bir y&ouml;netmen ve Birlik&rsquo;in başkanı olarak sinemadan beklentileriniz neler?</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Seyirci olarak film sanatının daha da m&uuml;kemmelleşmesini umuyorum. Benim uzun s&uuml;redir benimsediğim fikrime g&ouml;re, sinema, yery&uuml;z&uuml;n&uuml;n en ilgin&ccedil; ve karmaşık yaratığı olan insanın i&ccedil; d&uuml;nyasının derinliklerine sızabilme potansiyeline sahiptir. İnsan, yine bir y&ouml;netmen olarak ilgimin odağı. Benim i&ccedil;in, insana yaklaşma,&nbsp; her zaman bir deneyim, daha doğrusu, deneyimlerin doğurduğu yeni keşiflerle beslenen bir sanat bi&ccedil;imi olmuştur. Aslında, bu deneyimlerin meydana getirdiği yol, ufuk &ccedil;izgisinin gerisinde uzanmakta, yani sonsuz, tıpkı insan gibi. Eskilerin her şeyin &ouml;l&ccedil;&uuml;t&uuml; saydığı insan, hi&ccedil;bir &ouml;l&ccedil;&uuml;ye sığmıyor. Bu nedenle, film sanatında, araştırmanın sonu yoktur. Birliğin lideri olarak, bu sanatın iyi &ouml;rneklerini g&ouml;rmeyi bekliyorum. Elbette, konulu filmlerin, belgesellerin, animasyonların iyi &ouml;rnekleri şu ana dek yapıla geldi. Bu t&uuml;rlerin yeni &uuml;r&uuml;nlerini g&ouml;rebilme hevesi i&ccedil;indeyiz. Bu tarz &uuml;r&uuml;nler, d&ouml;n&uuml;ş&uuml;ml&uuml; olarak sinema sanatında yayılıp gelişen kavramlarla bağlantılı yeni sanatsal vasıfların varlığını zorunlu kılar. Elbette, bu gelişmenin genişliği iyi filmler yaratmada yeterli değil. Bunu sadece y&ouml;netmen ve seyirci arasında kurulan d&uuml;r&uuml;st bir ilişki sağlayabilir. Seyirci, bir sorun t&uuml;m y&ouml;nleriyle ortaya konduğunda veya oyuncu &ccedil;abasını c&ouml;mert&ccedil;e sergilediğinde, kendisine samimi bir şekilde hitap edildiğini sezecektir. Ger&ccedil;ekte oyun yoktur. Bu dediğim, filmde işlenen konu sosyal, tarihsel ya da her neyse hepsi i&ccedil;in ge&ccedil;erli. İleride filmlerimizin toplum yaşamındaki sosyal ve ahlaki sorunları ortaya &ccedil;ıkartıp &ccedil;&ouml;z&uuml;mlerken ger&ccedil;ek&ccedil;i bir tutum izlemesini istiyorum. Tutarsızlık m&uuml;cadele ile giderilir. Sovyet sineması nesnel ger&ccedil;ekliği takip etmelidir. Elbette, her sene &uuml;retilen y&uuml;z elli filmin her birinin bir baş yapıt niteliğinde olacağını s&ouml;ylemiyorum; en azından daha kalitelileri i&ccedil;in uğraşmalıyız. Son zamanlarda farklı &uuml;lkelere gitme şansım oldu. Sovyetler Birliğinde g&uuml;n&uuml;m&uuml;zde olan değişimler, &uuml;lke halkında, dış &uuml;lkelere karşı sıradan bir merakın &ouml;tesinde gittik&ccedil;e artan bir ilgi uyandırıyor. Diğer &uuml;lkelerdeki iyi niyetli meslektaşlarım Sovyet oyuncuların yeteneğine inandıklarını s&ouml;yl&uuml;yorlar. Demek istediğim; bizim d&uuml;nyaya s&ouml;yleyecek &ccedil;ok s&ouml;z&uuml;m&uuml;z var. Ge&ccedil;mişe takılı kaldığımız m&uuml;ddet&ccedil;e, kendi uyanışımızı yaratarak hep birlikte d&uuml;nyaya yeni bir anlayış getirebilme fırsatını ka&ccedil;ırırız. İnsanın ne adına ve nasıl yaşaması gerektiğini, bug&uuml;n&uuml;n d&uuml;nyasında maneviyatını ne şekilde koruyup paylaşacağını s&ouml;yleyebilme şansını yitiririz. Bu &uuml;lkenin &ccedil;ok uluslu k&uuml;lt&uuml;r&uuml; ardında biriktirdiği onca gelenekte manevi değerleri s&uuml;rekli barındırmıştır. Şimdi, tarihin bu noktasında bu değerlere sarılabilirsek b&uuml;y&uuml;k yaratıcı potansiyelimizi kullanabilme olanağımız olacaktır.</span></p>', 199, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (62, 'ay-j183', 'gunaydin-gece-ve-marco-bellocchio', 'Günaydın Gece ve Marco Bellocchio...', 'Kinorama 5, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: 18px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 20px;">Kinorama 5, 2004</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: 18px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 20px;">G&ouml;khan Erkılı&ccedil;</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Marco Bellocchio</b>... 1960&rsquo;lı yılların karşıt ve yıkıcı s&ouml;ylemlerle y&uuml;kselen İtalyan politik sinemasının &ouml;nde gelen isimlerinden biri. 1939 doğumlu y&ouml;netmen yarıda bıraktığı felsefe eğitiminin ardından sinema eğitimi aldı. 1965-70 yılları arası &ccedil;ektiği ilk d&ouml;nem filmleri, kimi sinemacıların,&nbsp;<b>Godard</b>&rsquo;ın Fransa&rsquo;da oynadığı rol&uuml; İtalya&rsquo;da onun oynadığı yorumunu yapmalarına neden oldu. &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Daha ilk filmi olan&nbsp;<b><i>Cepteki Yumruklar</i></b><i>&nbsp;</i>(1965) ile sosyal &ccedil;&ouml;z&uuml;lmenin bir &ouml;rneğini g&uuml;&ccedil;l&uuml; bir ger&ccedil;ek&ccedil;i eğilimle &ccedil;izen y&ouml;netmen, ilgi alanları olarak sosyal yapının en k&uuml;&ccedil;&uuml;k h&uuml;cresi olan aile d&uuml;zenini, k&ouml;hne dini kurumları ve hızlı bir değişim ge&ccedil;iren sosyal kurumları belirlemişti. Topluma bireyselin ne denli toplumsal, marjinalin ne denli sıradan olduğunu &ouml;ğretenlerden biri olarak tanındı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>&Ccedil;in Yakındır</i></b>&rsquo;da (1967) gelenek&ccedil;i d&uuml;zen ile 1968 ruhunun &ccedil;atışmasını, farklı sınıfların etkileşimlerinin ve d&uuml;zenin korunmasından &ouml;d&uuml;n verilmeksizin onay verilen değişimlerin &uuml;zerinden anlattı.<i>&nbsp;</i></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>Baba Adına</i></b>&rsquo;da (1970) otoritenin ve onun yerleşik değer ve kurumlarının anlamsızlığı &uuml;zerinde durdu.&nbsp;<b><i>Baş Sayfada Saldıran Canavarlar</i></b>&rsquo;da (1972) ideolojik aşırılığın &ouml;z ve ama&ccedil;tan uzaklaşmaya neden olduğu d&uuml;ş&uuml;ncesini işledi.&nbsp;<b><i>Deliliğin &Ccedil;&ouml;z&uuml;m&uuml;</i></b>&rsquo;nde (1973) deliliğin toplumdan gizlenmeye &ccedil;alışıldığı, gizlenemediği durumlarda da toplumdan soyutlanmaya &ccedil;alışıldığı mesajını vererek ilgili kurumların işlevsizliğini g&ouml;sterdi.&nbsp;<b><i>Zafer Marşı</i></b>&rsquo;nda (1976) militarizmin kişilikleri t&ouml;rp&uuml;leyen doğasını kışladan &ccedil;ıkardı ve anlamsız ilişkilerin yaşandığı g&uuml;nl&uuml;k militarizme taşıdı.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>Boşluğa Atlayış</i></b>&nbsp;(1980) ge&ccedil;mişte kaldığı sanılan burjuva değerlerinin yeniden canlanması ve bağımlılığın ortadan kalkmasıyla değişen dengelerin yarattığı huzursuzluk &uuml;zerinde durur.&nbsp;<b><i>Enrico IV</i></b><i>&nbsp;</i>(1984) deliliğin toplumun bencilliğine ve ikiy&uuml;zl&uuml;l&uuml;ğ&uuml;ne duyulan tepkinin bilin&ccedil;li bir dışavurumu olduğu konusunda kuşku dolu bir yaklaşımda bulunur.&nbsp;<b><i>V&uuml;cuttaki Şeytan</i></b><i>&nbsp;</i>(1986) evliliğin cinselliğe olan bağımlılığına dikkat &ccedil;eker.<i>&nbsp;<b>Yargı&nbsp;</b></i>(1991) baştan &ccedil;ıkarılmaya hazır olmanın aldatılma i&ccedil;indeki rol&uuml;n&uuml; bir yargılama s&uuml;recinde ortaya koyar. Sevişmenin, bilincin kutusuna kapatıldığı anlardan &ouml;r&uuml;l&uuml; olması ve buna rağmen bilin&ccedil; ortamında yargılanmasının ikilemi ilgin&ccedil;tir.&nbsp;<b><i>Kelebeğin D&uuml;ş&uuml;</i></b>&nbsp;(1994) dilsizliğin geri planında yatan farkındalığı ve &ouml;zg&uuml;rleşme &ccedil;abasını,&nbsp;<b><i>S&uuml;t Anne</i></b>&nbsp;(1999) yetişme evresinde yaşanılan bir psiko-sosyal dramı işler.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Son yıllar,&nbsp;<b>Bellocchio</b>&rsquo;nun sosyal koşullar i&ccedil;inde kendine &ccedil;ıkış yolu arayan sıradışı bireye y&ouml;neldik&ccedil;e silikleştiğini ortaya &ccedil;ıkaran yıllardır. Yola politik s&ouml;ylemlerle &ccedil;ıkan&nbsp;<b>Bellocchio</b>, &ouml;nce sosyal eleştiriye ve ona ortam hazırlayan delilik &ouml;yk&uuml;lerine, ardından da cinselliğe y&ouml;nelen bir rota izler.&nbsp;<b><i>G&uuml;naydın Gece</i></b>, y&ouml;netmenin uzun bir aradan sonra politik s&ouml;ylemine yeniden d&ouml;nd&uuml;ğ&uuml; film olur.<b>&nbsp;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&uuml;naydın Gece...</b>&nbsp;&nbsp;&nbsp; &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bellocchio</b>&nbsp;g&ouml;zde alanlarından biri olan politikaya yeniden d&ouml;nerken, İtalyan tarihinin en derin yaralarından biri olan&nbsp;<b>Aldo Moro</b>&nbsp;cinayetine eğilmeyi tercih ederek, bir anlamda olaydan tam 25 yıl sonra kendi hesaplaşmasını yapıyor. Ge&ccedil;en yıllarla birlikte, y&ouml;netmenlik yaşamının ilk yıllarındaki sosyal eleştiri d&uuml;zeyi y&uuml;ksek filmlerindeki politik a&ccedil;ılımlardan uzak d&uuml;şen&nbsp;<b>Bellocchio</b>, eski g&uuml;nlerini yeniden yaşatacak bir fırsat&nbsp; yakalamışken,&nbsp;<b>Moro</b>&nbsp;olayını yer yer belgesel g&ouml;r&uuml;nt&uuml;lerle destekleyerek politik ve tarihsel bir arka plan yaratmaya kalkışsa bile son derece duygusal ve insani y&ouml;n&uuml;yle ele alarak doğrusu şaşırtıcı bir tercih yapmış. &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Y&ouml;netmenin&nbsp;<b>Moro</b>&nbsp;cinayetine eğilmesinde, 1995&rsquo;de ger&ccedil;ekleştirdiği ve İtalyan siyasal tarihinin son elli yılını ikisi eski Kızıl Tugaylar &uuml;yesi d&ouml;rt uzmanın anıları ve arşiv g&ouml;r&uuml;nt&uuml;leri ile anlattığı&nbsp;<b><i>Sogni Infranti</i></b>&nbsp;filminin rol oynadığını d&uuml;ş&uuml;n&uuml;yorum. Bu belgeselin, y&ouml;netmene,&nbsp;<b>Moro</b>&nbsp;olayının kendisi a&ccedil;ısından halen a&ccedil;ık bir dosya olarak durduğunu hatırlattığı kanısını taşıyorum.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Moro</b>&nbsp;Kızıl Tugaylar &ouml;rg&uuml;t&uuml;n&uuml;n bir h&uuml;cresi tarafından 16 Mart 1978 g&uuml;n&uuml; ka&ccedil;ırılır ve işi g&uuml;c&uuml; olan bir ailenin yaşadığı izlenimi verilen bir evde gizli bir b&ouml;lmeye kapatılır. &Ouml;yk&uuml;n&uuml;n bundan sonrası, daha &ccedil;ok eve hapsolunmuş ter&ouml;ristlerin yaşamları &uuml;zerine kurulur. Anlaşmazlık ve &ccedil;atışmalar kendi aralarındaki duygusal gelgitlerden ve o ortamı yaşamayan k&ouml;k&uuml; dışarıda elebaşılarının verdiği emirlerin yarattığı gerginliklerden doğar.&nbsp;<b>Moro</b>&rsquo;nun bazısı adresine ulaştırılmayan ve hayatını analiz ettiği mektupları ile gen&ccedil; kadın ter&ouml;rist&nbsp;<b>Chiara</b>&rsquo;nın insani ve yer yer de kadınca tepkileri, bu ulusal trajediyi d&ouml;rt duvar arasına kapatır. &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">&Ouml;rg&uuml;t &uuml;yelerinin aval, s&ouml;ylev meraklısı ve kopuk tipler olduğunun farkına varan ve yaptıklarının &ouml;z&uuml;nde vahşetten başka birşey olmadığını sezen&nbsp;<b>Chiara</b>, filmde&nbsp;<b>Moro</b>&rsquo;dan daha &ouml;zenli &ccedil;izilmiş. Bu durum, her ne kadar y&ouml;netmenin bilin&ccedil;li tercihi de olsa, olayın siyasal k&ouml;kenlerinden uzaklaşmasına, dışarıda olup bitenden soyutlanmasına ve neredeyse bir aile dramasına d&ouml;n&uuml;şmesine neden oluyor. B&ouml;yle&nbsp;&nbsp; ter&ouml;ristler olduktan sonra,&nbsp;<b>Andreotti</b>&nbsp;bile ka&ccedil;ırılmak isterdi diye d&uuml;ş&uuml;nmeden edemiyorsunuz. &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Finale kadar s&uuml;ren bu toz pembe ev hapsi s&uuml;reci, duygusallığa prim tanımayan politik g&uuml;&ccedil;lerin &ouml;d&uuml;ns&uuml;zl&uuml;ğ&uuml; ve kendilerini kanıtlamak isteyen Kızıl Tugaylar &ouml;rg&uuml;t&uuml;n&uuml;n direnci arasında kalan&nbsp;<b>Aldo Moro</b>&rsquo;nun cesedinin bir araba bagajında bulunmasıyla sonlanıyor. Geride&nbsp;<b>Moro</b>&nbsp;cinayetinden &ccedil;ok, ter&ouml;ristlerin ne de g&uuml;zel şeyler olabileceği d&uuml;ş&uuml;ncesi kalıyor. Ancak Şirinlerin arasında kalmış Şirine s&ouml;z&uuml;n&uuml; ge&ccedil;iremiyor. Politik restleşmenin kıskacında insancıl olanın yenik d&uuml;şmesi, partiler arası uzlaşının mimarlarından&nbsp;<b>Moro</b>&rsquo;nun yitirilmesi ve ter&ouml;ristlerin yakalanarak yaşamlarını cezaevlerinde t&uuml;ketecek s&uuml;recin başlaması neredeyse bir masalın tepeden inme mutlu sonu gibi sunuluyor. &nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Moro-Kızıl Tugaylar-Devlet &uuml;&ccedil;l&uuml;s&uuml;n&uuml;n&nbsp;<b>Andreotti&nbsp;</b>ile temsil edilen devlet ayağı g&ouml;r&uuml;n&uuml;rde ma&ccedil;ı kazanan taraf. Nasıl olmasın ki? Politik arenadaki bir rakip ortadan silinmiş, devletin &ouml;d&uuml;n vermezliği kanıtlanmış ve &ouml;rg&uuml;t &uuml;yelerinin bir kısmı i&ccedil;eri atılmış. Meydan, yıllar sonra devleti bir su&ccedil; şebekesi olarak kullandığı a&ccedil;ığa &ccedil;ıkarılacak olan&nbsp;<b>Andreotti</b>&rsquo;ye kalmış. Soru: Bu cinayetin tetik&ccedil;isi olan Kızıl Tugaylar&rsquo;ın bir h&uuml;cresi, azmettirici rol&uuml;ndeki derin devletle ilişki kurmuş olamaz mı?&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bellocchio</b>&rsquo;nun filmini izlerken aklıma bir taraftan&nbsp;<b><i>Sogni Infranti</i></b>&nbsp;diğer taraftan da&nbsp;<b>Giuseppe Ferrara</b>&rsquo;nın&nbsp;<b><i>Moro Olayı</i></b><i>&nbsp;</i>(1987) filmleri takıldı. Sogni Infranti 1968 ruhunun ve sonrasının 1980&rsquo;li yıllarda t&uuml;mden tarihe g&ouml;m&uuml;ld&uuml;ğ&uuml;n&uuml;, onu bi&ccedil;imlendirenlerin dilinden anlatırken, o d&ouml;neme &ouml;zg&uuml; anlatıların artık bir masal havasında yansıtıldığını s&ouml;ylemek ister gibiydiler.&nbsp;<strong>F</strong><b>errara</b>&rsquo;nın filmi ise unutulmaz&nbsp;<b>Gian Maria Volonte</b>&rsquo;nin Moro&rsquo;yu merkeze oturtan ustalıklı yorumu, belgeselci yaklaşımı, anlatıdaki satır atlamayan kronolojik rotası ve tarihsel fona verdiği &ouml;nemle&nbsp;<b><i>G&uuml;naydın Gece&rsquo;</i></b>den daha sağlam bir yapıttı. S&ouml;z&uuml;n&uuml;z&uuml;n zamanlamasını doğru yapmazsanız geceye b&ouml;yle g&uuml;naydın dersiniz!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (63, 'ay-j184', 'kendi-kabugunda-uc-hayal-dusler-tutkular-suclar', 'Kendi Kabuğunda Üç Hayal: Düşler, Tutkular, Suçlar', 'Kinorama 5, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 5, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Cem Kayalıgil</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">60&rsquo;larda b&uuml;y&uuml;l&uuml; bir şey vardı, &ouml;yle ki bizler... şey, ş&ouml;yle diyelim,&nbsp;<i>d&uuml;şl&uuml;yorduk.&nbsp;</i>Sinemayı, politikayı, m&uuml;ziği, cazı, rock&rsquo;nroll&rsquo;u, seksi ve felsefeyi harmanlıyorduk.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sinemanın yaşayan en b&uuml;y&uuml;k ustalarından&nbsp;<b>Bernardo Bertolucci</b>,<b><i>&nbsp;Son Tango</i>&rsquo;</b>da ayrıldığı Paris&rsquo;e d&ouml;n&uuml;ş filmi&nbsp;<b><i>The Dreamers</i></b>&rsquo;da<sup>&nbsp;&lsquo;</sup>68 gen&ccedil;liğinin politik coşkusu, entelekt&uuml;el ilgileri ve bedensel arayışlarını buluşturuyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Film, ABD&rsquo;den Paris&rsquo;e gelen&nbsp;<b>Matthew</b>&rsquo;un, kendisi gibi sinema tutkunuolan ikiz kardeşlerle (<b>Isabelle</b>&nbsp;ve&nbsp;<b>Theo</b>) beraber ge&ccedil;irdiği 3 aylık zaman dilimine yayılıyor. &Uuml;&ccedil;l&uuml;,&nbsp;<b>HenriLanglois</b>&rsquo;in 9 Şubat 1968 g&uuml;n&uuml; Paris Sinemateki y&ouml;neticiliğinden men edilişinden Mayıs&lsquo;taki &ouml;ğrenci ayaklanmasına dek ge&ccedil;en s&uuml;renin &ccedil;oğunu evde, kendilerini dışarıda olup bitenden yalıtarak ge&ccedil;iriyorlar.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Biz de; hem Fransa&rsquo;daki siyasi gelişmelere hem de ikizlerin &ccedil;ocuksu ve kapalı d&uuml;nyasına yabancı olan&nbsp;<b>Matthew</b>&rsquo;un g&ouml;z&uuml;nden, onun ve ikizlerin ağırlıklı olarak sinemadan devşirdikleri d&uuml;şsel bir d&uuml;nya i&ccedil;erisinde ger&ccedil;eğe direnmelerine tanıklık ediyoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Uuml;&ccedil;&uuml; arasında b&uuml;y&uuml;yen aşk (ya da, aslında,&nbsp;<b>Menand</b>&rsquo;ın tabiriyle &ldquo;<b>Matthew</b>&rsquo;unandrojen bir ideale, metafiziksel bir b&uuml;t&uuml;n&uuml;n erkek ve kadın yarılarına duyduğu aşk&rdquo;) onları İlk bakışta tatmin edebiliyorken, yadsınamayacak karşıtlıkları bertaraf edemiyor. Nitekim filmin sonunda da&nbsp;<b>Theo</b>&rsquo;nun &ouml;ng&ouml;rd&uuml;ğ&uuml; ayrılış ger&ccedil;ekleşiyor;&nbsp;<b>Isabelle</b>&nbsp;ile&nbsp;<b>Theo</b>&rsquo;nun birlikte, şiddete başvuran eylemcilerin safına katıldığı,&nbsp;<b>Matthew</b>&rsquo;un ise bir başına olduğu eski d&uuml;zenine d&ouml;neceğinin ima edildiği bu son sahnedeki ayrılışla birlikte, &uuml;&ccedil;l&uuml;n&uuml;n ortak d&uuml;ş&uuml; de resmen sona eriyor:&nbsp; Burada ikizler &ldquo;kitlenin&rdquo; paylaştığı yeni bir d&uuml;şe atılırlarken&nbsp;<b>Matthew</b>&rsquo;un y&uuml;z&uuml;nde, her d&uuml;ş&uuml;n yalnızca bir &ldquo;d&uuml;ş&rdquo; olarak kalışı ger&ccedil;eğini g&ouml;r&uuml;yoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&ldquo;D&uuml;ş&rdquo; teması,&nbsp;<b>Bertolucci</b>&rsquo;nin bakışını artık b&uuml;t&uuml;n bir tarihsel d&ouml;neme &ccedil;evirip s&ouml;ylemini genişlettiği bu son sahneye dek, filmin &uuml;&ccedil; karakterinin odağında toplanıp g&uuml;&ccedil;lendiriliyor. Buraya kadar onları bir arada tutmuş olan d&uuml;ş, formunu,&nbsp;<b>Matthew</b>&rsquo;un ikiz birliğe duyduğu aşkta buluyor. İlkin&nbsp;<b>Matthew</b>&rsquo;un,&nbsp;<b>Isabelle</b>&nbsp;ile&nbsp;<b>Theo</b>&rsquo;nun ailesiyle birlikte yediği yemeğin sonundaki, evrendeki bi&ccedil;imsel uyuma ilişkin tiradında kendisini g&ouml;steren bu d&uuml;ş; seyirci olan bizleri de kuşatıp aldatıyor. Zaten &ouml;yk&uuml;n&uuml;n anlatıcısı olması dolayısıyla &ouml;zdeşleştiğimiz&nbsp;<b>Matthew</b>&rsquo;la birlikte bizler de aynı d&uuml;ş&uuml; g&ouml;rmeye başlıyoruz ve film boyunca da onun aşkının nesnel karşılığını bulduğu sanısına kapılıyor, katılıyoruz. Oysa bi&ccedil;imsel uyum da sadece &ldquo;bi&ccedil;imsel uyum&rdquo; olarak kalıyor ve&nbsp;<b>Matthew</b>&rsquo;u hi&ccedil;bir tinsel ger&ccedil;eğe vardıramadan y&uuml;z &uuml;st&uuml; bırakıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>The Dreamers</i></b>&rsquo;ın b&uuml;t&uuml;n&uuml;n&uuml; bir &ldquo;tek taraflı aşk&rdquo; &ouml;yk&uuml;s&uuml;n&uuml;n &ccedil;evresinde kuran&nbsp;<b>Bertolucci</b>, g&uuml;d&uuml;k kalan bi&ccedil;imsel uyum d&uuml;ş&uuml;n&uuml;n alegorisini de aynalar &uuml;zerinden yaratılan bir sinematografi ile yapıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Filmin, resimsel g&uuml;c&uuml;yle akıllara hemen kazınan k&uuml;vet sahnesinde;&nbsp;<b>Matthew</b>,&nbsp;<b>Theo</b>&nbsp;ve&nbsp;<b>Isabelle</b>&rsquo;in y&uuml;zlerini dip dibe duran &uuml;&ccedil; ayrı aynadaki akislerinden g&ouml;r&uuml;yoruz. &Ouml;te yandan, &uuml;&ccedil;l&uuml;n&uuml;n hem bedensel hem de hayali halleriyle bitiştikleri bu sahnenin kendisi de, aksini (ve ikinci kere yazmak gerekirse: &ldquo;aksini&rdquo;), bir başka sahnede g&ouml;steriyor:&nbsp;<b>Isabelle</b>&rsquo;in, enikonu kendisine ayırdığı d&uuml;ş&uuml;ne, kendi yatak odasına, bir MiloVen&uuml;s&uuml; hayali şeklinde daldıktan sonra karşıdaki &uuml;&ccedil; aynadan birden yansımasında.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">D&uuml;şlerin (ama sadece &ldquo;d&uuml;şlerin&rdquo;) buluştuğu bu aşk anı, nesnel karşılığın yitimi y&uuml;z&uuml;nden elbette &ccedil;ok fazla s&uuml;remeyecek ve sonunda krizi doğuracaktır. Bir sonraki sahnedeyse &uuml;&ccedil; karakterin &uuml;&ccedil;&uuml;n&uuml; de filmde ilk kez kendi odalarına &ccedil;ekilmiş bir halde buluyoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">D&uuml;şler dışlayabildikleri ger&ccedil;ek kadar vardır ve tıpkı&nbsp;<b>Theo</b>&rsquo;nun &ccedil;&ouml;pten getirdikleri arasında g&uuml;zel kalmış tek şey olan muz gibi, kabukları onları koruduk&ccedil;a temiz kalabilirler. Oysa ger&ccedil;ek&nbsp;<i>kırıcıdır</i>; kimi zaman &ouml;l&uuml;m bile onun karşısında sadece bir d&uuml;ş olarak kalır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İşte&nbsp;<b>Bertolucci</b>&nbsp;de filminde,&nbsp;<b>Isabelle</b>&rsquo;in deyimiyle &ldquo;sokağın eve girdiği&rdquo; sahnede bize bunu g&ouml;steriyor &ndash; orada, &uuml;&ccedil;l&uuml;yle birlikte biz de uykumuzdan uyanıyoruz.&nbsp;<b>Matthew</b>, kuşkusuz bir s&uuml;re daha aynı d&uuml;ş&uuml; s&uuml;rd&uuml;rme gayretiyle ikizlerin peşinden sokağa &ccedil;ıkıyor. Fakat bilmediği şey, g&ouml;rd&uuml;kleri d&uuml;ş&uuml;n artık aynı olmadığı oluyor. Onun evrensel uyum hayali sokakta noktalanırken bizler de, ger&ccedil;eğin ateşinin &ouml;n&uuml;nde,&nbsp;<b>Edith Piaf</b>&rsquo;ın direnişini dinliyoruz:</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; line-height: 15.3333px; font-family: arial, helvetica, sans-serif;">&ldquo;Hayır, hi&ccedil;bir şeye &ndash; pişman değilim hi&ccedil;bir şeye.&rdquo;</span></p>', 64, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (64, 'ay-j185', 'yesim-ustaoglu-ile-dunden-bugune', 'Yeşim Ustaoğlu ile Dünden Bugüne', 'Kılavuz, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Kılavuz, 2004</span></b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Ece &Ouml;zdemir</span></b></span><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;"></span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><i><span style="font-size: 10pt;">1960 yılında doğdu. Mimarlık &ouml;ğrenimi g&ouml;rd&uuml;. Sinema &uuml;zerine yazılar yazıp,&nbsp; &ouml;d&uuml;ll&uuml; kısa filmlere imzasını attı. İlk uzun metrajlı filmi&nbsp;<b>İz</b>\'i 1994 yılında &ccedil;ekti. Sonraki filmi&nbsp;<b>G&uuml;neşe Yolculuk</b>&nbsp;(1999), y&ouml;netmene uluslararası tanınmışlık sağladı. Hen&uuml;z g&ouml;sterime girmemiş olan filmi&nbsp;<b>Bulutları Beklerken&nbsp;</b>(2004), y&ouml;nettiği &uuml;&ccedil;&uuml;nc&uuml; uzun filmidir. Bu filminin araştırma aşamasında da ilk belgeseli olan&nbsp;<b>Sırtlarındaki Hayat</b>\'ı (2004) &ccedil;ekmiştir.</span>&nbsp;</i></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Sinemayla ilk tanışıklığınız hayatınızın hangi d&ouml;nemine denk d&uuml;ş&uuml;yor?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ouml;ğrencilik d&ouml;nemlerime. Mimarlık &ouml;ğrenimim sırasında bir &ccedil;eşit kararla sinemacı olmak istedim. İstanbul\'a d&ouml;nd&uuml;ğ&uuml;m zaman restorasyon mastırım sırasında da fiilen uğraşmaya başladım. İFSAK kanalıyla &ouml;nce sinema kul&uuml;b&uuml;nde &ccedil;alıştım, sonra ilk kısa filmimi &ccedil;ektim. Ondan beridir de uğraşıyorum.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Kendi filmlerinizi &ccedil;ekme ya da kendi sinemanızı oluşturma fikri nasıl belirdi?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">İlk filmimden beri. İlk kısa filmimde kendi &ouml;yk&uuml;mle başladım, kendi senaryomu yazdım, kendim prod&uuml;ksiyon yaptım, y&ouml;nettim. Başından sonuna kadar projenin i&ccedil;indeydim. Her alanında &ccedil;alıştım ve ondan itibaren de o projeyle beraber kendi hikayelerim ve kendi d&uuml;nyamı yaratmak, geliştirmek, yaşatmak &uuml;zere bir sinema anlayışıyla; d&ouml;rt kısa film, &uuml;&ccedil; uzun metraj ve bir belgesel yaptım.&nbsp;</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Sinemaya kısa filmle başladınız. İzleyici olarak hala ilginizi s&uuml;rd&uuml;r&uuml;yor musunuz? Kısayı&nbsp;ayrı&nbsp;bir kulvar olarak g&ouml;renlerden misiniz, yoksa sizin i&ccedil;in de uzuna ge&ccedil;mek i&ccedil;in bir basamak mı?&nbsp; Uzundan sonra kısaya d&ouml;nmenin zorluğunu biliyoruz ama yeni kısa film projeleriniz olabilir mi?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Tabii, bir anlamda aslında yaptığım belgesel kısa bir film. İkisi birbirinden &ccedil;ok ayrı&nbsp;değil aslında. Her ikisi de bir yaratım s&uuml;reci. Bir hikayeyi anlatıyorsunuz ve o hikayeyi yaratıyorsunuz. Bunu belki doksan dakika i&ccedil;inde yapmayı&nbsp;d&uuml;ş&uuml;n&uuml;yorsunuz, daha geniş&nbsp; yani. Ya da daha kompakt bir hikaye d&uuml;ş&uuml;n&uuml;p yeniden aynı&nbsp;şekilde g&ouml;rsel bir anlatımla sinemalaştırıyorsunuz. Sonu&ccedil;&nbsp;olarak; biri diğerinden farklı&nbsp;değil ama kısa film yapma d&ouml;nemi, tabii ki daha uzun projeler i&ccedil;in bir tecr&uuml;be&nbsp; kazandırıyor insana. &Ouml;zellikle oyuncu y&ouml;netimi &ccedil;ok daha derin ve anlamlı bir sinemayı yaratmak, kişisel bir sinema yaratmak a&ccedil;ısından kısa film yapma d&ouml;nemi &ccedil;ok b&uuml;y&uuml;k bir tecr&uuml;be d&ouml;nemi mutlaka. Tabii ilk yapılan filmle, olgunlaştık&ccedil;a yapılan filmler arasında fark var. Ama, sadece kısa film yaparak da filmografisini s&uuml;rd&uuml;ren y&ouml;netmenler de var. Bu bir anlayış, yaşamını s&uuml;rd&uuml;rebiliyorsa da bir yandan tabii. Dışarıda daha &ccedil;ok şansı var kısa filmle hayatını s&uuml;rd&uuml;rebilmek i&ccedil;in. Dağıtım alanı daha geniş dışarıda. Sadece kısa film, animasyon veya sadece belgesel yaparak sinemasını s&uuml;rd&uuml;ren y&ouml;netmenler var. S&ouml;yleyeceği s&ouml;z&uuml; daha geniş bir alana yayarak s&ouml;ylemek isteyenler ve bir par&ccedil;a da ticari nedenle uzun filme ge&ccedil;iyor bir s&uuml;re sonra sinemacılar.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Bir s&ouml;yleşinizde de kendi sinema dilinizi yarattığınıza inandığınız anda uzun metrajlı&nbsp;film yapacağınızı s&ouml;ylemiştiniz.</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Başından sonuna kadar bir filmi oluşturma s&uuml;recinde hemen her noktada daha olgun olduğunu hissettiğinde insan tabii ki daha b&uuml;y&uuml;k bir cesaret duyuyor. Bende de oldu. Sinema yapmanın en zor noktalarından biri oyuncu y&ouml;netimidir. Kısa filmlerimdeki daha naif, daha tecr&uuml;besiz oyuncu y&ouml;netiminden sıyrılmaya başladığımı&nbsp;hissettiğimde İz\'i &ccedil;ekmeye karar verdim. &Ccedil;&uuml;nk&uuml;&nbsp;kocaman bir film yapıyorsunuz, bunu izleyiciye aktarmaya &ccedil;alışırken başta kendinizin o hesaplaşmayı yapmanız gerekiyor. Karakterlerinizi ne kadar yansıtabildiniz, ne kadar oynatabildiniz, nasıl bir g&ouml;rsel derinlik yaratabildiniz? Bu &ccedil;ok &ouml;nemli bir şey, &ccedil;ok zaman isteyen bir s&uuml;re&ccedil;.&nbsp;</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Yeşim Ustaoğlu&rsquo;na ait bir sinema dilinden s&ouml;z edebilir miyiz? Edersek &ouml;zellikleri nelerdir?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Aslında &ccedil;ok yalın bir kamera kullanımının olduğu, fotoğraflarıyla, kompozisyonuyla bir i&ccedil;&nbsp;dinamizmin yakalandığı, karakterlerinde de &ouml;zellikle i&ccedil;&nbsp;dinamizmin, i&ccedil;&nbsp;d&uuml;nyaların&nbsp;&ouml;ne &ccedil;ıktığı&nbsp; bir sinema ve tabii ki, mutlaka arkasında da bir sorunsalı&nbsp;didikleyen bir sinema yapıyorum sanırım son d&ouml;nemlerde.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><strong><i><span style="font-size: 10pt;">İz</span>&nbsp;</i><span style="font-size: 10pt;">ve&nbsp;</span></strong><span style="font-size: 10pt;"><i><b>G&uuml;neşe Yolculuk</b></i></span><b><span style="font-size: 10pt;">&nbsp;yurt dışında da g&ouml;sterim imkanı buldu. Filmleriniz yurt dışında amat&ouml;r ve profesyonel &ccedil;evrelerde nasıl karşılandı?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><i><span style="font-size: 10pt;">İz</span></i></b><span style="font-size: 10pt;">\'i şimdi hatırlamıyorum. &Uuml;zerinden uzun zaman ge&ccedil;ti de,&nbsp;<b><i>G&uuml;neşe Yolculuk&nbsp;</i></b>daha taze anı olarak.&nbsp;<b><i>G&uuml;neşe Yolculuk</i></b>&nbsp;d&uuml;nyanın hemen her yerinde g&ouml;sterildi. Sadece festivallerde değil, sinemalarda da g&ouml;sterildi.Yani vizyona girdi d&uuml;nyanın hemen her yerinde. Bir&ccedil;ok g&ouml;steriminde bulundum, galalarında &ouml;zellikle. Japonya\'daki seyirciden Kanada\'daki seyirciye, Diyarbakır\'dakine kadar benzer bir heyecanı g&ouml;rd&uuml;m. Oradaki insanlar bizde yaşanan problemi bilmemesine rağmen, genel bir anlayışla &ouml;zellikle &ouml;teki insanın problemini hissetme noktasında buradakiyle aynı şekilde buluştu, aynı şekilde Mehmet\'i ve Berzan\'ı anlayabildi. Dolayısıyla genel olarak filmin &ccedil;ok kabul g&ouml;rd&uuml;ğ&uuml;n&uuml;, filmdeki duyguların d&uuml;nyanın her yerindeki insanlara ge&ccedil;tiğini hissettim. Buna ilişkin derslerde verdim d&ouml;nem d&ouml;nem; yerel boyutta evrensel sinemaya ge&ccedil;iş konusunda &ouml;zellikle.<br /></span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Filmlerinizin yabancı&nbsp;festivallerde aldığı &ouml;d&uuml;llerle uyandırdığı&nbsp;yankıda, eleştirmenlerin film okuma s&uuml;recinde takındığı&nbsp;politik yanlılığın etkisi olabilir mi?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Yok, yok b&ouml;yle politikalar girmiyor hi&ccedil;&nbsp;aslında. Aksine sadece politik bir şeye dayanan, arkada ger&ccedil;ek anlamda bir sinema olmayan hi&ccedil;bir yapıt hi&ccedil;bir yere gitmiyor. O bir anlamda klişe ve slogancı&nbsp;bir yerde kalıyor. Hi&ccedil;&nbsp;kimsenin de umrunda olmuyor.&nbsp;<b><i>G&uuml;neşe Yolculuk</i></b>\'un başarısı, belki bundan sonra da&nbsp;<b><i>Bulutları Beklerken</i></b>\'in seyirciler tarafından kabul g&ouml;rebilme ihtimali, samimiyetine dayanacak her şeyden &ouml;nce. Ve dediğim gibi &ccedil;ok yerel, &ccedil;ok bize ait bir temayı, &ccedil;ok evrensel bir boyutta işlemiş olması. Aynı ayrımcılığı Japonya\'da da yaşayanlar var, Kanada\'da da, İsrail\'de de, Filistin\'de de, Pakistan\'da da, Amerika\'nın g&ouml;beğinde de yaşayanlar var. Bu nedenle herkes aynı şekilde hissedebildi, g&ouml;rd&uuml;, anladı Berzan\'ın ve Mehmet\'in dramını. Onların derinliğini, onları hissettiler onlar. Sadece politik ger&ccedil;ekliği tartışmadılar. Bunu yaratmak &ouml;nemli tabii hangi yapıtta olursa olsun. B&ouml;yle bir derinliği yaratmak lazım.&nbsp;</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><strong><i><span style="font-size: 10pt;">G&uuml;neşe Yolculuk</span>&nbsp;</i><span style="font-size: 10pt;">ve&nbsp;</span><span style="font-size: 10pt;"><i><b>Bulutları Beklerken</b></i></span></strong><b><span style="font-size: 10pt;">\'in ekibi hemen hemen aynı kişiler. &Ouml;zelikle g&ouml;r&uuml;nt&uuml; y&ouml;netmeniniz Jacek Petrycki &ouml;nemli bir isim (Kieslowski\'nin de &ccedil;alıştığı isimlerden biri). Ekibi kurmak ve tekrar bir araya gelmek zor oldu mu?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir anlamda bir inan&ccedil;, g&uuml;ven meselesi bu. Birbirini tanıyan insanlar bir araya geliyor. Bir &ouml;nceki ekipten pek &ccedil;ok insan vardı bu projede de. G&ouml;r&uuml;nt&uuml; y&ouml;netmenimle de bizi bağlayan ortak bir sinema anlayışı olduğu i&ccedil;in bir araya geldik.&nbsp;<b><i>G&uuml;neşe Yolculuk</i></b>\'un senaryosunu &ccedil;ok beğenmişti. Ondan sonra da &ccedil;ok g&uuml;zel bir &ccedil;alışma yaptık. Birbirimizi &ccedil;ok yakından anladık, g&ouml;rsel olarak da aynı noktada birleştik. Dolayısıyla da ayrılırken de &ccedil;ok g&ouml;n&uuml;lden bir şekilde, yeni projen ne zaman başlıyor diyerek gitti zaten.&nbsp;<b><i>Bulutları Beklerken</i></b>&rsquo;in de senaryosunu okur okumaz ilk tepkisi, &ldquo;Hayatım boyunca b&ouml;yle bir film yapmak istemiştim&rdquo; oldu. G&ouml;rsel zenginliği farketmiş, bunun yanısıra da m&uuml;thiş bir karakter derinliği olduğunu anlamıştı filmde. &Ccedil;ok hoş bir &ccedil;alışma olacak dedi ve koşa koşa geldi zaten.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><strong><i><span style="font-size: 10pt;">G&uuml;neşe Yolculuk</span></i><span style="font-size: 10pt;">,&nbsp;<i><b>Bulutları Beklerken&nbsp;</b></i>ve&nbsp;</span><span style="font-size: 10pt;"><i><b>Sırtlarındaki Hayat</b></i></span></strong><b><span style="font-size: 10pt;">\'ı g&ouml;z &ouml;n&uuml;ne alarak; Yeşim Ustaoğlu sineması sosyal eleştiriye a&ccedil;ık bir sinemaya doğru gidiyor diyebilir miyiz?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Yaşadığı toplumu anlatan, hisseden, eleştiren bir sinemam var tabii ki. Psikolojik dramalar yapıyorum. İnsanların psikolojileri, karakterleri beni yoğun olarak ilgilendiriyor ve bunu anlatıyorum. Ama her zaman i&ccedil;in bunların arkasında da yaşadığım yerin, d&uuml;nyanın bir eleştirisi de var. Şimdilik b&ouml;yle gider gibi g&ouml;z&uuml;k&uuml;yor.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">T&uuml;m bu &ouml;yk&uuml;leri şehirli, eğitimli ve bu yaşamlara uzak bir insan olarak anlatırken i&ccedil;selleştirmek konusunda sıkıntılar &ccedil;ektiniz mi?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Hayır, hi&ccedil; &ouml;yle uzak da değilim aslında. Benim de hayatım bu sorunların i&ccedil;inde ge&ccedil;ti yoğun olarak. Hi&ccedil;bir zaman kopmadım sokaktaki hayattan. Nerede olursam olayım, sokaktaki dinamizm beni her zaman cezbetti ve b&uuml;t&uuml;n o sorunların i&ccedil;inde yaşadım, ya da bir şekilde g&ouml;zlemledim, uzakta tutmadım kendimi. Bir konu aklıma gelip de b&ouml;yle onu didiklemek &uuml;zere birdenbire konsantre olup araştırmaya başlamıyorum. Bildiğim şeyler, yaşadığım, g&ouml;zlemlediğim, beni etkileyen şeyler gelip d&uuml;rt&uuml;kl&uuml;yor bir şekilde, &ouml;yle bir ser&uuml;vene ge&ccedil;iyorum ben de.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Sizce T&uuml;rk sinemasının son d&ouml;nemde yavaş yavaş&nbsp;kıpırdanmaya başlaması bizi yeni bir T&uuml;rk sinemasından s&ouml;z etmek y&ouml;n&uuml;nde heyecanlandırmalı&nbsp; mı? Yoksa yaşananlar tesad&uuml;f m&uuml;? T&uuml;rk sineması ger&ccedil;ekten yol alıyor mu?</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Bundan sonraki arkadaşların projeleriyle de devam edecek tabii, ama şu anda hoş bir şey var. Yeni bir kuşak var her şeyden &ouml;nce. Beni en &ccedil;ok sevindiren projeleren biri Ahmet\'in (Ulu&ccedil;ay) projesi mesela. Onu tamamlayabilmiş, &ccedil;ekmiş olması ve &ccedil;ok iyi bir proje olması beni sevindiriyor mesela. Ahmet\'in devam etmesini, buna benzer yeni filmler &ccedil;ekmesini isterim ger&ccedil;ekten. &Ccedil;&uuml;nk&uuml; ger&ccedil;ek bir sinemacı kimliğine sahip. B&ouml;yle insanların, sinema yapmak isteyen insanlara, b&ouml;yle yapıtlarla, benimki dahil Ahmet\'inki dahil yol g&ouml;stermesi gerekir. &Ccedil;&uuml;nk&uuml; &ccedil;ok hızla gelişen, değişen bir d&uuml;nya da yaşıyoruz. Herşey &ccedil;ok hızla gelip ge&ccedil;iyor. Bu biraz iletişim imkanlarıyla, biraz internetle ilgili. Hızlı yaşayan bir gen&ccedil;lik var aslında. Onun yanında da bizim gibi insanlar var, Ahmet gibi insanlar var. Bambaşka d&uuml;nyalardan gelip ortaya birşeyler &ccedil;ıkarıyorlar. Onun kalıcılığını ve g&uuml;c&uuml;n&uuml; g&ouml;rmesini isterim seyircinin, etkilenmesini de isterim. Sonraki kuşağın yapacağı şeyleri etkilemesini isterim.<br /></span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Seyircinin ger&ccedil;ek anlamda anlayabildiğini d&uuml;ş&uuml;n&uuml;yor musunuz sizi? Ahmet Ulu&ccedil;ay\'ı, N. B. Ceylan\'ı, Zeki Demirkubuz\'u ve bu kuşak i&ccedil;inde sayabileceğimiz diğerlerini.</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 10pt;">Sanırım Ahmet ve ben seyirci anlamında daha yoğun bir sayıya ulaşabiliyoruz. Biraz daha geniş&nbsp;bir izleyici kitlemiz oluştu artık. Devam etmesini de isterim bunun. Bilge ve Zeki biraz daha az izleniyor, yani seyirci potansiyeline baktığım zaman. Ama, tabii ki pop&uuml;ler sinemanın&nbsp; &ouml;tesinde bir izleyici kitlemiz var. Bunun daha &ccedil;ok ve kalıcı&nbsp; olmasını&nbsp;talep ediyorum ben de kendi adıma. Burada &ccedil;ok &ouml;nemli bir emek var, s&ouml;ylenen s&ouml;zler var aslında. Sinemacıların da &ouml;tesinde, seyircinin de kendi kendini zorlaması lazım aslında. Takip etmesi lazım, ulaşması lazım, &ouml;rneğin sinema kitabına &ouml;yle değil mi?<br /></span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif;"><b><span style="font-size: 10pt;">Peki teşekk&uuml;r ederim.</span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ben de.</span></p>', 194, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (65, 'ay-j186', 'once-kara-tren-vardi', 'Önce Kara Tren Vardı...', 'Kılavuz 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Denilebilir ki sinema d&uuml;nyaya g&ouml;zlerini a&ccedil;tığında karşısında onu buldu. &Ouml;ylesine sinejenik bir duruşu vardı ki kameranın ilgisini &ccedil;ekmemesi d&uuml;ş&uuml;n&uuml;lemezdi. Sinemanın o &ccedil;ok sevdiği aksiyon ve ritm onun doğasında vardı. Vazge&ccedil;ilmezliğinin bilincinde, sinemayı yıllarca peşinden koşturdu. Zaman i&ccedil;inde başrollere bile &ccedil;ıktı ve sinemanın unutulmazları arasında kendine sağlam bir yer edindi. U&ccedil;suz bucaksız topraklar &uuml;zerinde zaman zaman yolcusu olarak taşıdığı kameranın rahat devinmesi i&ccedil;in raylarını ona miras bıraktı. Sinemanın halka ulaşması i&ccedil;in yıllarca &ccedil;abaladı; filmleri o k&ouml;y senin, bu k&ouml;y benim nazlanmaksızın taşıdı durdu ve b&ouml;ylece onların eğlenmesine olduğu kadar eğitilmesine de destek verdi. Sinemanın ilk yıldızlarından biri olmakla yetinmeyerek &ouml;nemli işlerin altına adına yazdırmayı başardı: hem g&uuml;&ccedil;l&uuml; ve yorulmak bilmez bir set iş&ccedil;isi, hem de onu d&uuml;nyanın kuş u&ccedil;maz kervan ge&ccedil;mez y&ouml;relerine dek g&ouml;t&uuml;rmeyi kendine g&ouml;rev edinmiş bir sinema delisi... tren, kara tren! Sizleri, yıllar boyunca sayısız filmin g&ouml;r&uuml;nt&uuml; karelerinden bize ulaşan tren &ouml;yk&uuml;lerinden derlenmiş, &ouml;znel ve nostaljik bir yolculuk bekliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Karanlık salonun aydınlık perdesine yansıyan titrek g&ouml;r&uuml;nt&uuml;ler... Bir tren sessiz devinimler i&ccedil;inde Ciotat garına yaklaşıyor. S&ouml;ylenceye g&ouml;re, &uuml;zerlerine gelen trenin kendilerini ezeceğinden korkan seyircilerden kimisi kendini salonun dışına atarken, kimisi salondaki g&ouml;rece daha g&uuml;venli yerlere ka&ccedil;ışıyor. Kalanların izledikleri yapıt,&nbsp;<b>Louis Lumiere</b>&rsquo;in ilk belge-filmlerinden&nbsp;<b><i>Trenin Gara Varışı</i></b>&nbsp;(L&rsquo;Arriveed&rsquo;un Train en Gare, 1895). Derken ilk başrol&uuml;ne &ccedil;ıkıyor tren ve&nbsp;<b>Edwin Porter</b>&rsquo;ın westernin &ouml;nc&uuml;lerinden&nbsp; olan&nbsp;<b><i>B&uuml;y&uuml;k Tren Soygunu</i></b>&rsquo;nda (Great Train Robbery, 1903) beğeni topluyor olacak ki bundan sonraki hemen t&uuml;m westernlerde kendini g&ouml;stereceği bir rol kapmayı beceriyor. Bunların i&ccedil;inde biri var ki b&uuml;t&uuml;n&uuml;yle onun &uuml;zerine kurulmuş bir film.&nbsp;<b>John Ford</b>&rsquo;un Doğu&rsquo;yu Batı&rsquo;ya bağlayan demiryollarının yapımını anlatan&nbsp;<b><i>Demir At</i></b>&nbsp;(Iron Horse, 1924) filminde uygarlığın sembol&uuml; olarak vurgulanıyor. S&ouml;m&uuml;rgeci beyazların bu bakışının karşısında, kendilerini topraklarından s&uuml;rerek k&uuml;lt&uuml;rlerini yok eden bu yıkıcı anlayışın sembol&uuml; olarak g&ouml;rd&uuml;kleri trene demir at adını yakıştıran yerlilerin bakışı duruyor. Doğu-Batı demiryolu ağı, Kızılderili uygarlığının sonunu hazırlayan gelişmelerden biri olarak, treni kapitalist d&uuml;nyanın yayılmacı anlayışının g&ouml;zdesi haline getiriyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ccedil;ağımıza damgasını vuran şu bildik Amerikan r&uuml;yasını ger&ccedil;eğe d&ouml;n&uuml;şt&uuml;rme s&uuml;recinde, &ouml;zellikle de Amerikan İ&ccedil; Savaşı sırasında dengeleri değiştirecek roller &uuml;stlenen trenlerden birinin &ouml;yk&uuml;s&uuml; sinemanın da ilgisini &ccedil;eker.&nbsp;<b>Buster Keaton</b>&nbsp;ve&nbsp;<b>Clyde Bruckman</b>&rsquo;ın y&ouml;nettiği&nbsp;<b><i>The General</i></b>&nbsp;(1926), savaşın gidişatını değiştiren, kırılgan ve bazen de komikleşen bir kahramanlık &ouml;yk&uuml;s&uuml;n&uuml;n başkahramanı olarak bir trenin &ouml;yk&uuml;s&uuml;n&uuml; anlatır.&nbsp;<b>Dziga Vertov</b>&rsquo;un kendisi de bir teknoloji &uuml;r&uuml;n&uuml; olan kameranın &ccedil;ağın teknolojik gelişimine ve yaşam k&uuml;lt&uuml;r&uuml;ne tanıklık ettiği&nbsp;<b><i>Kameralı Adam</i></b>&nbsp;(The Man with a Movie Camera, 1929) filmi, birka&ccedil; sahneyle &ccedil;ağın hıza ve g&uuml;ce olan tutkusunu trenler ve raylar &uuml;zerinde dile getirir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Demiryolları y&uuml;zyılın başındaki bu &ouml;nc&uuml; konumunu zamanın akışı, değişen değerler ve teknolojik gelişmeler karşısında yitirdi. Ancak onun insan yaşamına girmesini sağlayan nedenler ge&ccedil;erliliklerini koruduğu i&ccedil;in vazge&ccedil;ilmezlerden biri olmayı s&uuml;rd&uuml;rd&uuml;. Kendini s&uuml;rekli yenileyen teknolojisiyle yeni kuşaklar i&ccedil;in de &ccedil;ekici kalmayı bildi. ABD, Japonya, Rusya ve Hindistan gibi &uuml;lkelerde taşıma ve ulaşımın olmazsa olmazı konumunu korusa da d&uuml;nya genelinde eski sempatisini taşımadığı da bir ger&ccedil;ek. Demiryolları &ouml;zellikle ulaşım konusunda &ouml;ncelikli tercih olmaktan &ccedil;ıkınca, sinema ile olan ilişkisi de ilk d&ouml;nemdeki kadar i&ccedil;li dışlı olamadı. Westernlerin ortadan kalkmasıyla g&ouml;zlerimiz onları daha az g&ouml;r&uuml;r oldu. Zaman ilerledik&ccedil;e, filmler bize insanların sosyo-ekonomik sınıflarına g&ouml;re giderek artan bir bi&ccedil;imde otob&uuml;s ve u&ccedil;ağı tercih ettiklerini, hatta kendi arabalarına tapınmaya başladıklarını g&ouml;steriyordu. Ancak sinema trenleri ve demiryollarını g&uuml;ndeminden eksik etmedi. Rayların &uuml;zerinde ge&ccedil;mişin izlerini aradı, &ouml;l&uuml;m ve yaşamı sorguladı. Aşklara, savaşlara, s&uuml;rg&uuml;n ve g&ouml;&ccedil;lere tanıklık eden trenlerin peşine d&uuml;şt&uuml;. Trenleri sık&ccedil;a &ouml;l&uuml;m kamplarına ve aşklara doğru yol alırken g&ouml;rd&uuml;k. Ve bazıları belleğimizde silinmez tortular bıraktı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir tren garını ve yolcuları zamanın durduğu bir anı yaşayan perondaki bir treni &ouml;l&uuml;m ve yaşam kavramlarının sorgulandığı bir alan olarak kullanan, sinemamızda soyut ve d&uuml;ş&uuml;nsel sinemanın az sayıdaki &ouml;rneklerinden biri aklımıza ilk gelenlerden.&nbsp;<b>Metin Erksan</b>&rsquo;ın tv i&ccedil;in &ccedil;ektiği ve bir Sait Faik uyarlaması olan&nbsp;<b><i>M&uuml;thiş Bir Tren</i></b>&nbsp;(1976), bu t&uuml;r sinemanın ulusal sinemamıza &ccedil;ok ge&ccedil; yansımış ancak bir s&uuml;r&uuml; anlamsız eleştiriyi ardına taksa da başarılı ve ayrıksı &ouml;rneklerinden biri.&nbsp;<b>Vittorio de Sica</b>&rsquo;nın&nbsp;<b><i>Termini Garı&nbsp;</i></b>(Stazione Termini, 1953) ise geleneksel sinemaya &ccedil;ok daha yakın bir anlatımla, son randevusuna tanıklık etsin diye kendine Roma garını se&ccedil;en bir yasak aşkı &ouml;yk&uuml;ler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yaşamın sorgulamasını, &ccedil;ok canlı, inişli-&ccedil;ıkışlı bir anlatımla ger&ccedil;ekleştiren&nbsp;<b>Jozsef Pacskovszky</b>&rsquo;nin&nbsp;<b><i>Kornel Esti&rsquo;nin Muhteşem Yolculuğu</i></b>&nbsp;(The Wondrous Voyage of Kornel Esti, 1994) filmi, bizi yazar Esti&rsquo;nin &ccedil;ıktığı iki tren yolculuğuna konuk eder. Trenlerden biri d&uuml;ş&uuml;nceli ve &ouml;l&uuml;m&uuml;n kıyısında duran yaşamını g&ouml;zden ge&ccedil;iren olgun Esti&rsquo;yi Almanya&rsquo;ya, diğeri ise otuz yıl &ouml;ncesinde kalmış gen&ccedil; ve yaşam zevklerinin peşinde koşan gen&ccedil; Esti&rsquo;yi İtalya&rsquo;ya taşır. Sonu&ccedil;: Ne varsa g&uuml;neyde var! Aşk, gizem, kuşku ve ger&ccedil;eklik kavramlarını tartışan bir başka film de,&nbsp;<b>Andre Delvaux</b>&rsquo;nun klasik denilebilecek trendeki kadın temasından modern bir &ccedil;&ouml;z&uuml;mlemeye ulaşan&nbsp;<b><i>Bir Gece, Bir Tren</i></b>&nbsp;(Un Soir, un Train, 1968).</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Trenlerle &ccedil;ok sık rastlaştığımız t&uuml;rlerden biri de savaş filmleri... &Ouml;zellikle 2. B&uuml;y&uuml;k Savaş sırasında &ouml;l&uuml;mc&uuml;l &ccedil;ağrışımlar yaparak k&ouml;t&uuml; &uuml;n kazanan trenler, insanlığın t&uuml;kenişinin kanıtları oldular. Binlerce kez milyonlarca askeri &ouml;l&uuml;me, milyonlarca sivili &ouml;l&uuml;m kamplarına, a&ccedil;lığa ve yoksulluğa taşıdılar. Dolu dolu giden vagonlar ya boş olarak ya da cesetlerle geri d&ouml;nd&uuml;ler. Bazıları da &ouml;l&uuml;m b&ouml;lgesinden uzaklara taşıdılar insanları; sayıca s&ouml;z&uuml; edilmeye değmeyecek kadar azdılar. Tren demek &ouml;l&uuml;m demekti ve bu ger&ccedil;ek insanlığın ortak belleğinde silinmez izler bıraktı.&nbsp;<b>Steven Spielberg</b>&rsquo;in&nbsp;<b><i>Schindler&rsquo;in Listesi</i></b>&nbsp;(Schindler&rsquo;sList, 1995) elinden geldiği kadar &ccedil;ok sayıdaki Yahudi&rsquo;yi işyerinde &ccedil;alıştırarak trenlere y&uuml;klenmesini! engellemeye &ccedil;alışan bir işadamının &ouml;yk&uuml;s&uuml;n&uuml; anlatır.&nbsp;<b>Radu Mihaileanu</b>&rsquo;nun&nbsp;<b><i>Hayat Treni</i></b>&nbsp;(Train de Vie, 1998) filminde anlatılan, Nazilerden ka&ccedil;mak i&ccedil;in doğa&ccedil;lama bir beceriyle &ccedil;iziktirdikleri ka&ccedil;ış &ouml;yk&uuml;s&uuml;n&uuml;n gereği olarak, onarıp &ccedil;alışır duruma getirdikleri bir trene doluşan ve kendilerini raylara vuran, Doğu Avrupa k&ouml;kenli bir grup Yahudi k&ouml;yl&uuml;s&uuml;n&uuml;n kurtuluş &ouml;yk&uuml;s&uuml;d&uuml;r. &Ouml;l&uuml;mc&uuml;l bir nefretten ka&ccedil;an topluluğun i&ccedil;inde biri de sevgi ve ilgiden boğulurum korkusuyla aşktan uzak durmayı kafasına&nbsp; koymuştur. Sonu&ccedil;: Aşk &ouml;l&uuml;mc&uuml;l bir savaştır! Savaşa uzaktan bakan veya bakıyormuş gibi yapan &ccedil;ok g&uuml;&ccedil;l&uuml; filmler de var. Slav romantizminin yanına g&uuml;ld&uuml;r&uuml;s&uuml;n&uuml; de koymayı başaran&nbsp;<b>Jiri Menzel</b>&rsquo;in&nbsp;<b><i>Sıkı Denetlenen Trenler</i></b>&rsquo;i (Closely Watched Trains, 1966) bu t&uuml;rden. Bohemya&rsquo;da bir tren istasyonunda haberci olarak &ccedil;alışan, sıradan hayatını inişleri ve &ccedil;ıkışlarıyla, arzuları ve &ccedil;elişkileriyle s&uuml;rd&uuml;ren gen&ccedil; bir adamın, s&uuml;r&uuml;p giden savaşın istasyona yansıyan izlerine tanıklık etmesi ve ger&ccedil;eğin perdesini aralayan g&ouml;zlemleri. Hayatı sevmenin doğurduğu g&uuml;l&uuml;msemelerin karşısına, savaşın Almanlar i&ccedil;in artık tersine d&ouml;nd&uuml;ğ&uuml;n&uuml; g&ouml;steren ceset y&uuml;kl&uuml; vagonların trajikliği dikilir. Doğrudan savaşı anlatan binlerce filmin arasında&nbsp;<b>Rene Clement</b>&rsquo;in&nbsp;<b><i>Demiryolu Savaşı</i></b>&nbsp;(La Batailledu Rail, 1948) &ouml;ne &ccedil;ıkıyor. Fransızların 2. B&uuml;y&uuml;k Savaş sırasında Almanlara g&ouml;sterdikleri direnişin en g&uuml;&ccedil;l&uuml; olduğu alanlardan biri de demiryolları olmuştur. Taşıdıkları stratejik değerden de &ouml;te elde tutulmalarının ya da Almanlarca kullanılmasının &ouml;n&uuml;ne&nbsp; ge&ccedil;ilmesinin verdiği psikolojik g&uuml;&ccedil;, demiryollarının &ouml;nemini ortaya koyarken, &ouml;te yandan da filmin bir direniş belgesi olarak g&ouml;r&uuml;lmesine de neden olmakta.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Rainer Werner Fassbinder</b>&rsquo;in&nbsp;<b><i>İstasyon Şefinin Karısı</i></b>&nbsp;(Bolwieser, 1977) ve&nbsp;<b>Jos Stelling</b>&rsquo;in&nbsp;<b><i>De Wisselwachter</i></b>&nbsp;(1986) filmleri istasyon g&ouml;revlilerini konu edinirler. Fassbinder&rsquo;in kahramanı istasyon şefliğini y&uuml;ksek bir stat&uuml; olarak g&ouml;ren, g&ouml;z&uuml; işinden başka birşey g&ouml;rmeyen bir adam olarak &ccedil;izilse de filmi s&uuml;r&uuml;kleyen hayatın sıradanlığını aşmak i&ccedil;in aşk peşinde koşan karısıdır. Abarttığı stat&uuml;s&uuml; ve kendini g&uuml;&ccedil;l&uuml; olduğuna inandırdığı toplumsal rol&uuml; gereği, eşinin s&uuml;rd&uuml;ğ&uuml; hayata ilgisiz kalan istasyon şefi &ouml;ncelikle kendini aşmak zorunda kalacaktır ki bu yıkımın ta kendisidir. Stelling&rsquo;in filmi ise, bir yanlışlık sonucunda, yolu kuş u&ccedil;maz kervan ge&ccedil;mez bir y&ouml;redeki k&uuml;&ccedil;&uuml;k bir istasyona d&uuml;şen &ccedil;ekici ve başına buyruk bir kadının, i&ccedil;ekapanık bir demiryolu g&ouml;revlisinin &uuml;zerinde yarattığı sarsıntılı tutku ve d&uuml;şkırıklıkları &uuml;zerine olağan&uuml;st&uuml; g&uuml;zellikte bir &ccedil;alışma.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Raylar &uuml;zerinde ge&ccedil;en filmlere gelince: Biri &ccedil;ok bildik, diğeri ise az ile hi&ccedil; arasında biliniyor.&nbsp;<b>Sidney Lumet</b>&rsquo;nin&nbsp;<b><i>Doğu Ekspresinde Cinayet</i></b>&nbsp;(Murder on the Orient Express, 1974) filmi, bir tren vagonunu duruşma salonuna &ccedil;evirmesiyle bilinir. Bilinmeyinin adı&nbsp;<b><i>Ekspres Ekspres</i></b>&nbsp;(1996), y&ouml;netmeni de&nbsp;<b>Igor Sterk</b>. Nereye gideceği konusunda zerre kadar d&uuml;ş&uuml;ncesi olmayan, tren yolculuğunu saplantı haline getirmiş bir adamın raylar &uuml;zerinde s&uuml;r&uuml;p giden komik &ouml;yk&uuml;s&uuml;.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">S&uuml;rg&uuml;n ve g&ouml;&ccedil;lere su&ccedil; ortaklığı yapan trenlerin &ouml;yk&uuml;s&uuml; de sinemada sık&ccedil;a rastlananlardan. Kısır topraklardan g&ouml;rece daha verimli &ccedil;iftlik topraklarına taşınmak zorunda kalan k&ouml;yl&uuml;lerin &ouml;yk&uuml;s&uuml;n&uuml; anlatan filmler arasında en &ouml;nemlilerinden biri&nbsp;<b>Veljko Bulajic</b>&rsquo;in&nbsp;<b><i>Tarifesiz Tren&nbsp;</i></b>(Train without a Timetable, 1959) filmidir. G&uuml;c&uuml;n&uuml; yeni-ger&ccedil;ek&ccedil;i &ccedil;izgisinden alan film, treni kitlelerin yoksulluklarını ardında bırakmalarını sağlayan bir ara&ccedil;, bir sosyal basamak olarak betimler. Politik kararlarla zorunlu g&ouml;&ccedil;&uuml;, s&uuml;rg&uuml;n&uuml; yaşamak zorunda kalan topluluklarla ilgilenen filmlerin sayısı sanıldığı kadar fazla değil. Bunun ardında politik sinemanın giderek zayıf d&uuml;şmesinin ya da bu t&uuml;r sorunlara genellikle yol a&ccedil;an &uuml;lkelerin kendi tezlerine karşıt olarak kullanılabilecek &ccedil;alışmalara hoşg&ouml;r&uuml; g&ouml;stermemelerinin b&uuml;y&uuml;k rol&uuml; var. S&uuml;rg&uuml;n edilenlerin ise kendi belgesellerini &ccedil;ekmeye sıra gelinceye kadar, &ouml;nlerinde birikmiş &ccedil;ok daha yaşamsal sorunları var.&nbsp;<b>Pamela Rooks</b>&rsquo;un &ccedil;ektiği&nbsp;<b><i>Pakistan Treni</i></b>&nbsp;(Train to Pakistan, 1997), ilgisini Hindistan tarihinin bir sayfasına y&ouml;neltiyor. 1947 yılında Pencap eyaletinde huzurlu ortama rağmen zorunlu kılınan ve etnik seyreltme ama&ccedil;lı g&ouml;&ccedil;ler, &uuml;lke tarihinde &ouml;nemli rol oynayan demiryollarının politik bir ara&ccedil; olarak kullanıldığını g&ouml;sterir. Klasik tip s&ouml;m&uuml;rgeci anlayışın kalıntıları olan bu demiryolları &uuml;st&uuml;nde işleyen her tren, gittiği her yere arkada bırakıldığı sanılan huzursuzluğu da taşıyacaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Son s&ouml;z&uuml; sinema &uuml;zerine s&ouml;ylenmiş s&ouml;z&uuml; olan filmlere verelim: &Ccedil;ocuk yaşlarda seyrettiği Bazıları Sıcak Sever filmi nedeniyle sinemaya tutulan, kendinde yeni bir Marilyn Monroe havası yakalayan gen&ccedil; bir kızın &ouml;yk&uuml;s&uuml;...&nbsp;<b>Radoslaw Piwowarski</b>&rsquo;nin&nbsp;<b><i>Hollywood Treni</i></b>&nbsp;(Train to Hollywood, 1987) filmi, kendisini buralardan kurtaracağını d&uuml;ş&uuml;nd&uuml;ğ&uuml; &uuml;nl&uuml; y&ouml;netmen BillyWilder&rsquo;a yazdığı mektuplara yanıt alamasa da, trenlerde bira satarak s&uuml;rd&uuml;rd&uuml;ğ&uuml; yaşamı d&uuml;şlerinin ger&ccedil;ekleşebilirliği inancını zora sokup zedelese de yolundan d&ouml;nmeyen bir sinema sevdalısını tanıtmıştı bizlere. Son filmimiz bir belgesel:&nbsp;<b>Chris Marker</b>&rsquo;dan&nbsp;<b><i>Y&uuml;r&uuml;yen Tren</i></b>&nbsp;(Le Train en Marche, 1970). Deneysel yanı da olan filmleriyle tanıdığımız Rus y&ouml;netmen AleksandrMedvedkin&rsquo;in 1930&rsquo;lu yıllarda yaptırdığı ve ekibiyle kullandığı sinema treni, evet yanlış okumuyorsunuz, sinema treni Marker&rsquo;ın &ccedil;ok hoşuna gider. Tren bir film yapımevi gibi &ccedil;alışmaktadır. Vagonlarından biri yataklı, diğeri baskı at&ouml;lyesi, &ouml;teki &ccedil;ekim gere&ccedil;leri deposu, beriki projeksiyon odası olarak hizmet veren bir r&uuml;ya tren! Bu d&ouml;nemin &ouml;ncesi ve sonrasında, kırsal b&ouml;lge ve y&ouml;relerde eğitim filmleri, haber belgeselleri ve konulu eğlendirici filmlerin g&ouml;sterimini yapan agit-trenlerin varlığı, Sovyetler Birliği&rsquo;nde sinemanın yaygınlaşması ve sevilmesinde b&uuml;y&uuml;k rol oynamıştır. Medvedkin&rsquo;in projesi ise doğrudan &uuml;retimi ama&ccedil;ladığı i&ccedil;in Marker&rsquo;ın ilgisini &ccedil;ekmiştir. Ve bu durmayı sevmeyen, oradan oraya gezinen trenini &ouml;yk&uuml;s&uuml;n&uuml; filme alarak belgeler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Burada, trenin şu ya da bu şekilde karıştığı filmlerden derlenmiş bir sinema &ouml;yk&uuml;s&uuml; daha sonlanıyor. Gelişen teknoloji trenleri &ccedil;ağın gereklerine g&ouml;re yeniledik&ccedil;e, yenileri eskiyen rayların yerlerini alıp demiryolu ağlarını genişlettik&ccedil;e, trenler ve kameralar rayların &uuml;zerinde yeni sinema &ouml;yk&uuml;leri yazmayı s&uuml;rd&uuml;recekler.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (66, 'ay-j187', 'oscar-ivir-zivir-bir-gecmisin-i-zinde', 'Oscar! Ivır Zıvır Bir Geçmişin İzinde...', 'Kılavuz 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Topu topu 6400 kadar kişinin kendi arasındaki itişme, kakışma, hesaplaşma, &ouml;p&uuml;şme, restleşme, yağlama, haddini bildirme ve sataşmaların şimdilik 75 fasik&uuml;lden oluşan &ouml;yk&uuml;s&uuml; olduğu halde, nedense b&uuml;t&uuml;n d&uuml;nyanın kendine dert edinip tv ekranlarına g&ouml;m&uuml;ld&uuml;ğ&uuml;, aslında olan bitene kıyısından k&ouml;şesinden de olsa ortak edilmediği seyircisinin kimisine karalar bağlatan, kimisine de naralar attıran Akademi &ouml;d&uuml;lleri, bilinen adıyla Oscar &ouml;d&uuml;lleri, neresinden bakarsınız bakın trajikomik bir ge&ccedil;mişe sahip.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İlk heykelcik, -b&ouml;yle dememin nedeni o tarihte hen&uuml;z adı konmamış olduğu i&ccedil;in n&uuml;fusa kayıtlı olmaması- 1927-28 sinema sezonu i&ccedil;in 1929&rsquo;da verilmiş. Tarihin ilk ve son en iyi arayazı &ouml;d&uuml;l&uuml; bu yılın. Sonradan cennetten kovulacak olan&nbsp;<b>Chaplin</b>, Sirk filmi i&ccedil;in bir &ouml;d&uuml;l alarak &Ouml;zel Oscar geleneğinin başlamasına neden olmuş.&nbsp;<b>Chaplin</b>, &ldquo;kesseniz bir daha d&ouml;nmem&rdquo; dediği Hollywood topraklarına 1972 t&ouml;reninde eline tutuşturulan &Ouml;zel Oscar i&ccedil;in kuzu kuzu d&ouml;nm&uuml;ş. Kimi &uuml;stadlar, bunu Hollywood&rsquo;un&nbsp;<b>Chaplin&nbsp;</b>&ouml;n&uuml;nde diz &ccedil;&ouml;kmesi olarak yorumluyor, yorum sizin! Bir yıl sonra da, 1952&rsquo;de &ccedil;ektiği Limelight filmi i&ccedil;in 1973&rsquo;deki t&ouml;rende en iyi m&uuml;zik &ouml;d&uuml;l&uuml;n&uuml; almış. Bunu ben de anlamadım. Tarihin ilk en iyi erkek oyuncu &ouml;d&uuml;l&uuml; de bir Alman olan&nbsp;<b>Emil Jannings</b>&rsquo;e gitmiş. Notlara g&ouml;re, 1930 yılında hem 1928/29, hem de 1929/30 sezonu i&ccedil;in iki kez &ouml;d&uuml;l t&ouml;reni yapıldığı anlaşılıyor. Bu, t&ouml;renin sonraki &uuml;&ccedil; yılın birinde yapılmadığı sonucunu doğuruyor. Derken, heykelcik 1931&rsquo;de adıyla tanışmış. Burası tam bir hikaye olduğu i&ccedil;in gereğini yerine getirelim: Bir varmış bir yokmuş, g&uuml;nlerden bir g&uuml;n, Akademi &ccedil;alışanlarından bir sayın bayan, bu terminat&ouml;r &ouml;ncesi tiplemeye bakıp, Oscar amcasına ne kadar benzediğini s&ouml;ylemişmiş. İşte o g&uuml;n bug&uuml;nd&uuml;r, sinema k&ouml;y&uuml;n&uuml;n akıllısı delisi, enteli danteli bu platinyum kaplamalı zatı Oscar adıyla &ccedil;ağırır olmuş. -Demek ki bu işi T&uuml;rkler yapsaydı ve bir hanım kızımız &ccedil;ıkıp, &ouml;d&uuml;l&uuml;n Abuzittin amcasına benzediğini pekala s&ouml;yleyebilirdi!- Oscar zamanla &ouml;yle &ouml;nemli işler yapmış ki g&ouml;ğe y&uuml;kselmiş. O da yılda bir kez ortaya &ccedil;ıkıp, aşağıdakilerin kafasına d&uuml;şecek elmaları g&ouml;kten aşağıya atar olmuş. D&uuml;ş&uuml;ncem odur ki bu elmaların &ccedil;ok az bir kısmı tam isabet kaydetmiş. Bu nedenle olsa gerek, Oscar tarihi, bazılarının adları sinema kaynaklarında bile ge&ccedil;meyen, bazıları ise ge&ccedil;se de &ccedil;oktan unutulmuş filmler mezarlığı gibidir. Şaşırmayın, &ccedil;&uuml;nk&uuml; son yıllarda &ouml;d&uuml;le boğulan filmlerin bir&ccedil;oğunu, zamanı gelince, siz de tarih&ccedil;iler de hatırlamayacak ve işi sinema arkeologlarına bırakacaksınız. Sanırım, Oscar amcası da, kendisini d&uuml;ş&uuml;rd&uuml;ğ&uuml; bu acınası durum i&ccedil;in, &ouml;lene dek yeğenine s&ouml;ylemediğini bırakmamıştır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Oscar tarihine eğilmenin iyi bir yanı var, acayip eğleniyorsunuz. Tam anlamıyla bir ıvır zıvır denizinin ortasında gariplikler, sa&ccedil;malıklar, anlamsızlıklar k&ouml;şe kapmaca oynuyor. Kimi zaman olan bitene ağzınız a&ccedil;ık kalıyor; trajik durumlar bile, nasıl olsa bu bir masal demeye zorlayan ger&ccedil;ek&uuml;st&uuml;c&uuml; bir atmosferde komediye d&ouml;n&uuml;ş&uuml;yor. Hollywood&rsquo;un penceresinden bakarsanız, bazı d&ouml;nemlerde &ouml;d&uuml;llere genel bir uyum, bir uzlaşı havası hakim. &Ccedil;elişkiler, bu mantığın kendine ters d&uuml;şt&uuml;ğ&uuml; durumlarda veya sinema adına doğruları bulalım dediğiniz noktada ipin ucu ka&ccedil;tığı i&ccedil;in ortaya &ccedil;ıkıyor. Belki de tutarlılık beklentisiyle yaklaşmak yanlış. Bu &ouml;d&uuml;l, sonu&ccedil;ta sinemaya verilmiyor. Filmlerin ve sinemacıların gelir pastasındaki dilimleri paylaştıkları devasa bir arenada olduğumuzu unutmamamız gerekiyor. Kolay değil, ortada film başına 50 milyon doların altına d&uuml;şmeyen ekstra bir gelir var. Sinemanın canı cehenneme durumları, işin &ouml;znel se&ccedil;im ve duyarlılıklara yaslanan tarafı. Nesnel olan kendi i&ccedil;inde yaşanılan terslikler. &Ccedil;&uuml;nk&uuml;, yıllara yayılan Oscar meydan savaşlarının kimi evrelerinde, Oscarların Hollywood&rsquo;a ihanet ettiğini d&uuml;ş&uuml;nd&uuml;ren se&ccedil;imlerde g&ouml;zleniyor. S&ouml;zgelimi, Hollywood&rsquo;u Hollywood yapan&nbsp;<b>Garbo</b>,&nbsp;<b>Dietrich&nbsp;</b>ya da<b>&nbsp;Monroe</b>&nbsp;gibi nicelerini Oscar &ouml;p&uuml;lmeye değer bulmamış. Zamanı gelince, Amerikan sinema tarihinin olmazsa olmazı&nbsp;<b>Welles</b>&rsquo;in&nbsp;<b><i>Yurttaş Kane</i></b>&nbsp;filmini pas ge&ccedil;miş. &Ccedil;alışmak i&ccedil;in Britanya semalarını se&ccedil;en&nbsp;<b>Kubrick</b>&rsquo;in filmleri&nbsp;<b><i>Dr. Strangelove</i></b>&nbsp;ve&nbsp;<b><i>2001: A Space Odyssey</i></b>&nbsp;ise yok gibi davranılanlar arasında.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hollywood&rsquo;un ge&ccedil;en y&uuml;zyılın ilk yarısında anlatmayı en &ccedil;ok sevdiği ve Oscar&rsquo;ın da bayıldığı &ouml;yk&uuml;ler, Amerikan r&uuml;yasına bandırılmış sınıf atlama, emeksiz ve zahmetsiz para ve otorite sağlama &ouml;yk&uuml;leri olsa gerek. Kendisi de bir d&uuml;ş fabrikası olduğu i&ccedil;in, bu &ouml;yk&uuml;lerde ger&ccedil;eğin d&uuml;şlere yenik d&uuml;şmesi ka&ccedil;ınılmaz g&ouml;r&uuml;n&uuml;yor. Oscar bu d&ouml;nemde, dur durak bilmeksizin salon komedilerinin, m&uuml;zikallerin, &ccedil;ok satan romanların, ilgi toplayan oyunların, gece hayatının, vamp kadınların, savaşın ve yarattığı kahramanların, mutlu aile tablosu &ccedil;iziktiren aşkların ve Batı&rsquo;nın uygarlaştırılma hikayelerinin peşinden koşar. Kapılarını eğlenceye sonuna kadar a&ccedil;arken, d&uuml;ş&uuml;nd&uuml;ren ve sorgulayanı elinin tersiyle iter.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">1950&rsquo;li yıllarda Amerikan Karşıtı &Ccedil;alışmaları Araştırma Komisyonu ile işbirliği yapan Oscar, kom&uuml;nistlikle su&ccedil;lanarak &ccedil;alışma hayatından dışlanan insanlara acımasız davranır. &Ccedil;oğunluğu senarist olan bu adamlar, engelleri a&ccedil;mak i&ccedil;in takma ad kullanmayı tercih ederler ve ortaya g&uuml;l&uuml;n&ccedil; durumlar &ccedil;ıkar.&nbsp;<b>Dalton Trumbo</b>&nbsp;1956 &ouml;d&uuml;llerinde kazandığı Oscarı, ancak sular durulduktan sonra, 1975&rsquo;te alabilir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">1960&rsquo;lı yılların başlarında b&uuml;t&uuml;n d&uuml;nya birbiri ardına patlayan sinema akımları ile sarsılır ve yeni anlatım teknikleriyle deneysel ve yenilik&ccedil;i bir hava h&uuml;k&uuml;m s&uuml;rerken, Hollywood tatile &ccedil;ıkmış bir playboyun rehaveti i&ccedil;indedir. Bir yere kadar da gelenekselci anlayışında direnir. D&ouml;nemin sonuna doğru bir kıpırdanma g&ouml;ze &ccedil;arpar. Bunda toplumsal huzursuzluğun ve politik &ccedil;&ouml;k&uuml;ş&uuml;n de yadsınmaz katkısı vardır. Oscar,&nbsp;<b>Nichols</b>&rsquo;ın&nbsp;<b><i>Mezun</i></b>&rsquo;unun ve&nbsp;<b>Penn</b>&rsquo;in&nbsp;<b><i>Bonnie ve Clyde</i></b>&rsquo;ının g&ouml;nl&uuml;n&uuml; almakla yetinir. Değişimin ilk a&ccedil;ık &ouml;rneği&nbsp;<b>Schlesinger</b>&rsquo;ın&nbsp;<b><i>Geceyarısı Kovboyu</i></b>&nbsp;olur.&nbsp;<b>George C. Scott</b>,&nbsp;<b>Brando</b>,&nbsp;<b>Redgrave</b>&nbsp;ve&nbsp;<b>Fonda</b>&nbsp;gibi isimler, Oscarı politik ve toplumsal d&uuml;ş&uuml;ncelerini a&ccedil;ıklamak i&ccedil;in bir platform olarak kullanırlar. Bu başkaldırı asla affedilmez. Genel &ccedil;izgileriyle Oscar anlayışına aykırı duran bu d&ouml;nem kısa &ouml;m&uuml;rl&uuml; olur ve 1976&rsquo;da sona erer.&nbsp;<b>Reagan&nbsp;</b>tutuculuğunun ve saldırgan politikasının 1979&rsquo;daki zaferiyle Holywood eski s&ouml;ylemine d&ouml;ner ve Oscar&rsquo;ın g&ouml;sterişli ve y&uuml;z&uuml; genel seyirci kitlesine d&ouml;n&uuml;k filmleri tercih ettiği bir d&ouml;nem a&ccedil;ılmış olur. 1960 &ouml;ncesinin ruhu dişlerini daha da keskinleştirerek geriye d&ouml;nm&uuml;ş ve gelişimin verdiği destekle bir tekno-hortlak olarak işin başına ge&ccedil;miştir. Hollywood teknolojiye, efektlere ve şiddete y&ouml;nelse de Oscar bu sulara girmekte son yıllara kadar s&uuml;ren bir direnme g&ouml;stermekte. Ve yine kimi &ouml;nemli filmleri g&ouml;zardı etmeyi s&uuml;rd&uuml;rmekte.&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">S&ouml;z, hazır g&ouml;zardı etme konusundan a&ccedil;ılmışken, bu durumun Oscar amcanın &ccedil;ocukluğundan kalma bir huyu, daha doğrusu huysuzluğu olduğunu s&ouml;ylemekte yarar var. Anlayacağınız, yedisinde neyse, yetmişinde de o! Bu travmatik yaklaşımına tanıklık edenler arasında neler yok ki... D&uuml;nden bug&uuml;ne uzanacak olursak;&nbsp;<b><i>Muhteşem Ambersonlar</i></b>,&nbsp;<b><i>&Ccedil;ifte Tazminat</i></b>,&nbsp;<b><i>Kızgın Boğa</i></b>,&nbsp;<b><i>Right Stuff</i></b>,&nbsp;<b><i>Nashville</i></b>,&nbsp;<b><i>Kıyamet</i></b>,&nbsp;<b><i>Bir Cinayetin Anatomisi</i></b>,&nbsp;<b><i>Sıkı Dostlar</i></b>,&nbsp;<b><i>Piyano</i></b>,&nbsp;<b><i>Ucuz Roman</i></b>,&nbsp;<b><i>Yedi </i></b>ve<b><i> İnce Kırmızı &Ccedil;izgi</i></b>&nbsp;gibileri Oscar&rsquo;ın antipatik davrandığı bazı &ouml;nemli yapıtlar arasındalar. Bu filmlerin y&ouml;netmenlerinin &ccedil;oğu Oscar&rsquo;sız bir hayat s&uuml;rerken, Leone aday bile g&ouml;sterilmezken, John Ford d&ouml;rt &ouml;d&uuml;l kazanabilmiş. Ve aynı Oscar, Perde A&ccedil;ılıyor filmine 14 adaylık verip,<b><i>&nbsp;Ben Hur</i></b>&nbsp;ve&nbsp;<b><i>Titanik</i></b>&nbsp;filmleri 11 dalda kazanırken aşırı bir c&ouml;mertlik sergilemiş. Titanik batmasaydı, bu &ouml;d&uuml;llerin ağırlığıyla batardı diye d&uuml;ş&uuml;nmekten kendimi alamıyorum. Bir de Walt Disney ger&ccedil;eği var. &Ccedil;eşitli dallarda ve doğrudan kendisine veya st&uuml;dyosuna verilen Oscar sayısı sanırım 40 civarında! Anlaşılan, Akademi &uuml;yelerinin bir yerlerinin yaş ortalaması olduk&ccedil;a d&uuml;ş&uuml;k, başlarını hen&uuml;z eğlenceden kaldıramıyorlar. Disney de kendi alanında uzun yıllar s&uuml;ren rakipsizliğinin tadını doyasıya &ccedil;ıkarıyor. Daha ne olsun!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Oyuncularda da pek farklı olmayan bir durumla karşı karşıyayız. Bu alanda kopan kıyametler bir hayli farklı ve zamanında &ccedil;ok ses getirmiş. 1934&rsquo;te&nbsp;<b>Bette Davis</b>&nbsp;i&ccedil;in &ouml;d&uuml;l sisteminde değişikliğe bile gidilmiş. St&uuml;dyo patronlarının hatunlarının &ouml;d&uuml;l kazanması az kaldı geleneksel hale gelecekmiş. 1943&rsquo;te&nbsp;<b><i>Casablanca&rsquo;</i></b>yı seyredip&nbsp;<b>Bogart</b>&rsquo;ı farkedemeyenlerin ilerleyen yıllarda da bazı filmlerdeki ağırlıklarını g&ouml;remedikleri oyuncular olmuş:&nbsp;<b>Shirley MacLaine</b>,&nbsp;<b>Anne Bancroft</b>,&nbsp;<b>Robert de Niro&nbsp;</b>veya&nbsp;<b>Whoopi Goldberg</b>&nbsp;gibi. Bu arada, her nasılsa KatharineHepburn d&ouml;rt &ouml;d&uuml;l kazanırken, Hollywood uzmanlarının gelmiş ge&ccedil;miş en b&uuml;y&uuml;k kadın oyuncu olarak g&ouml;sterdikleri&nbsp;<b>Meryl Streep&nbsp;</b>d&ouml;rt atıp bir tutturan bir performans sergiliyor. O, yine de mutlu olanlardan.&nbsp;<b>Burton</b>&nbsp;ve&nbsp;<b>O&rsquo;Toole</b>&nbsp;yedi kez aday g&ouml;sterilip sıfır &ccedil;ekenlerden.&nbsp;<b>Tatum O&rsquo;Neal</b>&nbsp;on yaşındayken&nbsp;<b><i>Paper Moon</i></b>&nbsp;ile kazandığı en iyi yardımcı kadın oyuncu &ouml;d&uuml;l&uuml; ile en gen&ccedil; sevindirik.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Oyuncu &ouml;d&uuml;llerini kazanan yabancı oyunculara gelince, onlar oyunculuk a&ccedil;ısından daha bir &uuml;st noktada duranlar arasından &ccedil;ıkmış. Aralarında&nbsp;<b>Laurence Olivier</b>,&nbsp;<b>Daniel Day Lewis</b>,&nbsp;<b>Glenda Jackson</b>,&nbsp;<b>Vivien Leigh</b>,&nbsp;<b>Alec Guinness</b>,&nbsp;<b>Simone Signoret</b>,&nbsp;<b>Ingrid Bergman</b>,&nbsp;<b>Sophia Loren</b>,&nbsp;<b>Maximilian Schell</b>&nbsp;ve&nbsp;<b>Anna Magnani&nbsp;</b>var. Bazılarını anlamak ne kadar kolaysa, diğerlerini anlamak da o kadar zor!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu arada Oscar&rsquo;ın siyahı sevmediği de s&ouml;ylenebilir. Sekt&ouml;rde son yıllarda giderek ağırlıklarını duyursalar da &ouml;d&uuml;llerde oransal olarak temsil edilmedikleri de, ulaştıkları konumların ise olduk&ccedil;a kişisel başarı &ouml;yk&uuml;lerine dayandığı da a&ccedil;ık bir ger&ccedil;ek. Siyahlara verilen ilk &ouml;d&uuml;l&nbsp;<b>Hattie McDaniel</b>&rsquo;in ve 1939&rsquo;da yardımcı kadın oyuncu dalında. Yıllar sonra, 1963&rsquo;de&nbsp;<b>Sidney Poitier</b>&nbsp;en iyi erkek oyuncu &ouml;d&uuml;l&uuml;n&uuml; almış. Bir siyah-beyaz aşkının olanaklılığının bile ancak 1992&rsquo;de&nbsp;<b>Houston-Costner</b>&nbsp;ikilisiyle kabul g&ouml;rd&uuml;ğ&uuml; Hollywood i&ccedil;in&nbsp;<b>Denzel Washington</b>&nbsp;ve<b>&nbsp;Halle Berry</b>&rsquo;nin aldığı &ouml;d&uuml;ller neredeyse bir devrim niteliğinde.&nbsp;&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Oscar&rsquo;ın diğer siyahları da kadınların y&ouml;netmen olanları... Anlaşılan o ki, kadın rollerini erkeklere oynatarak onları t&uuml;mden sekt&ouml;r dışına atmanın form&uuml;l&uuml;n&uuml; hen&uuml;z bulamayan, belki de salt ekonomik nedenlerle onlara katlanan Hollywood dinozorlarının, Oscar gecelerinde kadın y&ouml;netmenleri g&ouml;rmeye tahamm&uuml;l&uuml; yok. S&ouml;zgelimi, yaptığı işleri başarılı bulup aday listelerinde sırtı sıvazlansa da, Akademi&rsquo;nin&nbsp;<b>Barbra Streisand</b>&rsquo;ı y&ouml;netmenden saymadığı ve radikal &ccedil;ıkışlarından dolayı hoşlanmadığı biliniyor. Belleğim beni yanıltmıyorsa, bug&uuml;ne kadar adları aday listelerinde ge&ccedil;en kadın y&ouml;netmenlerin hepsi yabancıydı:&nbsp;<b>Lina Wertm&uuml;ller</b>,&nbsp;<b>Jane Campion</b>&nbsp;ve&nbsp;<b>Nana Djordjadze.</b>&nbsp;Evet, onlar da siyah ama haberleri yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Gelelim, son derece k&uuml;&ccedil;&uuml;k bir azınlığı temsil eden kimileri i&ccedil;in Oscar &ouml;d&uuml;llerindeki tek &ouml;nemli kategori olan en iyi yabancı film &ouml;d&uuml;l&uuml;ne... &Ouml;d&uuml;llerin b&uuml;y&uuml;k &ccedil;oğunluğu Avrupa filmleri tarafından kazanılmış. Adayların &ccedil;oğunluğu Avrupa&rsquo;dan başvurduğu i&ccedil;in bunda şaşılacak birşey yok. Bu daldaki ilk &ouml;d&uuml;l&uuml;,&nbsp;<b>De Sica</b>&rsquo;nın&nbsp;<b><i>Kaldırım &Ccedil;ocukları</i></b>&nbsp;1947 &ouml;d&uuml;llerinde almış. D&uuml;nden bug&uuml;ne verilmiş b&uuml;t&uuml;n &ouml;d&uuml;llerin &uuml;lkelere g&ouml;re dağılımında, her d&ouml;rt &ouml;d&uuml;lden birini kazanmış olan İtalyan sineması liderliğini s&uuml;rd&uuml;r&uuml;yor. Bunda, Akademi &uuml;yelerinin k&ouml;ken olarak İtalyan olanlarının sayısının &ccedil;ok ve etkin olmasının rol oynadığını d&uuml;ş&uuml;n&uuml;yorum.&nbsp;<b>De Sica&nbsp;</b>ve&nbsp;<b>Fellini,</b>&nbsp;aralarında&nbsp;<b><i>Bisiklet Hırsızları</i></b>,&nbsp;<b><i>Sonsuz Sokaklar</i></b>&nbsp;ve&nbsp;<b><i>Amarcord</i></b>&rsquo;un da bulunduğu d&ouml;rder filmle Oscar&rsquo;a boğulmuş y&ouml;netmenler. Onları &uuml;&ccedil; &ouml;d&uuml;lle İsve&ccedil;&rsquo;ten&nbsp;<b>Bergman&nbsp;</b>izliyor. &Uuml;lkeler sıralamasında,&nbsp;<b><i>Amcam,Siyah Orfe</i></b>,&nbsp;<b><i>Z</i></b>,&nbsp;<b><i>Burjuvazinin Gizli &Ccedil;ekiciliği</i></b>&nbsp;gibi filmleriyle Fransa ikinci sırada bulunuyor. Fransa&rsquo;nın &ouml;d&uuml;llerinin yarısı uyduruk ve &ccedil;oktan unutulmuşlar arasına girmiş filmler tarafından kazanılmış. Son yıllarda Fransa &ccedil;ok &ouml;n plana &ccedil;ıkartılmıyor. Bunda, Avrupa&rsquo;da Hollywood&rsquo;a karşı &ccedil;ıkan &uuml;lkelerin başını Fransa&rsquo;nın &ccedil;ekiyor olmasının &ouml;nemli payı olsa gerek. Fransa&rsquo;nın ardından a&ccedil;ık ara farkla SSCB/Rusya, Japonya, İsve&ccedil;, &Ccedil;ek Cumhuriyeti ve İspanya geliyor. &Ouml;d&uuml;l kazanan diğer &uuml;lkeler arasında Hollanda, Almanya, Arjantin, Macaristan, Danimarka, İsvi&ccedil;re, Tayvan ve Bosna-Hersek bulunuyor.&nbsp;<b><i>Umuda Yolculuk&nbsp;</i></b>gibi bir filmin nasıl olup da &ouml;d&uuml;l kazanabildiği t&uuml;r&uuml;nden tartışmaların da yaşandığı bu kategoride &ccedil;ok ilgin&ccedil; tercihlere de rastlanıyor. &Ouml;rneğin,&nbsp;<b>Salvatores</b>&rsquo;in&nbsp;<b><i>Akdeniz</i></b>&rsquo;inin&nbsp;<b>Yimou</b>&rsquo;nun&nbsp;<b><i>Kırmızı Fenerler</i></b>&rsquo;inin,&nbsp;<b>Trueba</b>&rsquo;nın&nbsp;<b><i>G&uuml;zel &Ccedil;ağ</i></b>&rsquo;ının&nbsp;<b>Kaige</b>&rsquo;nin&nbsp;<b><i>Elveda Cariyem&rsquo;</i></b>inin ve&nbsp;<b>Hung</b>&rsquo;un&nbsp;<b><i>Yeşil Papaya&rsquo;nın Kokusu</i></b>&rsquo;nun,&nbsp;<b>Benigni</b>&rsquo;nin&nbsp;<b><i>Hayat G&uuml;zeldir</i></b>&rsquo;inin&nbsp;<b>Salles&rsquo;</b>in&nbsp;<b><i>Merkez İstasyonu</i></b>&rsquo;nun veya&nbsp;<b>Lee</b>&rsquo;nin&nbsp;<b><i>Kaplan ve Ejderha</i></b>&rsquo;sının&nbsp;<b>Inarritu</b>&rsquo;nun&nbsp;<b><i>Aşklar K&ouml;pekler&rsquo;</i></b>inin karşısında nasıl &uuml;st&uuml;nl&uuml;k sağladığı hep tartışmalı konular. Bir de 1992 adayları arasındaki&nbsp;<b>Aristarain</b>&rsquo;in&nbsp;<b><i>D&uuml;nyada Bir Yer</i></b>&nbsp;filminin yarattığı skandal var ki b&ouml;ylesi ne duyuldu ne de g&ouml;r&uuml;ld&uuml;. Filmin Uruguay adına yarışacağının a&ccedil;ıklanmasından sonra, Arjantin haklı olarak karşı &ccedil;ıktı ve itirazı kabul edildi. Ancak film adaylar arasından &ccedil;ıkarılarak, bir bakıma Arjantin de cezalandırıldı. Akademidir ne yapsa yeridir, olacak o kadar! Bu arada, &ouml;zellikle son yıllarda, b&uuml;t&uuml;n Avrupa&rsquo;lı sinema &ccedil;evreleri, ağız birliği etmişcesine, Akademi&rsquo;nin Avrupa sinemasını anlamadığını, okuyamadığını ve doğru değerlendiremediğini s&ouml;yl&uuml;yorlar. G&uuml;naydın!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Son yıllarda &ouml;d&uuml;l listeleri sanki Akademi &uuml;yeleri fazla zorlanmasın ve sinema d&uuml;nyasının ulu manituları tarafından belirlenen esas filmi, esas oğlanı ve kızı karıştırıp şaşırmasınlar, ekranlardaki boş atıp dolu tutturan yorumcular ve evde ekranları başında kendinden ge&ccedil;en izleyici de Oscar-Toto&rsquo;dan &uuml;&ccedil; beş tutturmanın hazzını sabah uykularının r&uuml;yalarına taşısınlar diye hazırlanıyor gibi.&nbsp;<b><i>Schindler&rsquo;in Listesi</i></b>,&nbsp;<b><i>Forrest Gump</i></b>,&nbsp;<b><i>Cesur Y&uuml;rek</i></b>,&nbsp;<b><i>Titanik</i></b>,&nbsp;<b><i>Aşık Shakespeare</i></b>,&nbsp;<b><i>Amerikan G&uuml;zeli&nbsp;</i></b>ya da&nbsp;<b><i>Gladyat&ouml;r&nbsp;</i></b>filmlerini anımsamanız yeter. &Ouml;d&uuml;ller a&ccedil;ıklandığında, g&uuml;nler ve haftalardan beri, sinema adına Oscar&rsquo;dan başka ağzından s&ouml;z &ccedil;ıkmayan yorumcular ve yazarlar bir hafta daha konuşmayı s&uuml;rd&uuml;recek ve olayı ne kadar iyi bildiklerini size kanıtlamakla zamanınızı alacaklar. Hollywood ve Oscar i&ccedil;in harcadıkları &ccedil;abanın onda birini &ouml;tekiler i&ccedil;in harcamayı &ccedil;ok sayarak!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">S&ouml;ylediğim gibi, siz bunları okurken 2003 yılının Oscar &ouml;d&uuml;lleri a&ccedil;ıklanmış olacak. Tahminler ve sonu&ccedil;lar yeniden masaya yatırılacak. Bir karış derinliğinde pek m&uuml;him analizler yapılacak ve kişisel skorlar a&ccedil;ıklanacak. Bendenize gelince, ne tahminim ne de ayıracak zamanım var. Doğrusunu s&ouml;ylemem gerekirse, adayları bile bilmiyorum ve umurumda da değil. Bu yazının, acınası ve dokunaklı durumumun nedenlerini fazlasıyla a&ccedil;ıkladığı inancındayım. Biliyorum ki daha s&ouml;ylenecek &ccedil;ok s&ouml;z var. Bazı notlarımı unuttum, bazılarını da yazmak istemiyorum ama artık bu Oscar Amca muhabbetinden sıkıldım, benim kendi sinemalarıma d&ouml;nmemin zamanı da geldi &uuml;stelik!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (67, 'ay-j188', 'hitchcock-sinemasi', 'Hitchcock Sineması', 'Kılavuz, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">G&uuml;ndemi izleyenler bilirler, kitabevlerinin sinema raflarına d&uuml;şen en taze kitaplardan biri de&nbsp;<b>Hitchcock Sineması</b>&nbsp;adını taşıyor.&nbsp;<b>Robin Wood</b>&nbsp;tarafından yazılan kitap,&nbsp;<b>Ertan Yılmaz</b>&rsquo;ın &ccedil;evirisiyle dilimize kazandırıldı. Kitabın kapağını kapattığım an,&nbsp;<b>Wood&rsquo;</b>un b&uuml;t&uuml;n &ccedil;ıplaklığıyla sunduğu karakteristik &ouml;zelliklerinin, d&uuml;nya &uuml;zerine olan g&ouml;zlemlerinin ve değer yargılarının, bundan da &ouml;te onları dışa vurmada g&ouml;sterdiği a&ccedil;ıklığın, zaman karşısında evrim ge&ccedil;iren film &ccedil;&ouml;z&uuml;mlemelerine kıyasla &ccedil;ok daha ilgin&ccedil; olduğunu d&uuml;ş&uuml;nd&uuml;m. Doyurucu &ccedil;&ouml;z&uuml;mlemeleri beğeni toplayan, en g&ouml;zde yorumları sıklıkla y&uuml;r&uuml;t&uuml;len ve eleştiri anlayışına &ouml;yk&uuml;n&uuml;len bu adamın başarısının ardında, d&uuml;nyayı yorumlamada alabildiğine &ouml;znel olan yaklaşımının etkinliği ve &ouml;zel yaşam se&ccedil;imlerinin sağladığı duygusal enerjiyi eleştiri alanına y&ouml;nlendirme becerisi uzanıyordu. Bu durum, bir&ccedil;ok a&ccedil;ıdan eleştiri dendiğinde savunduğum değerleri ortaya &ccedil;ıkardığı i&ccedil;in, kendime yeni bir dayanak bulmanın hazzını yaşattı bana. Bu nedenle, aşağıda,<b>&nbsp;Hitchcock</b>&nbsp;&uuml;zerine yapılmış &ccedil;&ouml;z&uuml;mlemeler hakkında ne d&uuml;ş&uuml;nd&uuml;ğ&uuml;m&uuml; değil, bir eleştirmenin ardına kadar a&ccedil;ılmış d&uuml;nyasında neler olabileceği veya neler olması gerektiği &uuml;zerine, yalnız &ccedil;ıkış noktalarını&nbsp;<b>Wood</b>&rsquo;un kişiliğinden alan bir yazı, &ouml;znelliğe k&uuml;&ccedil;&uuml;k &ccedil;aplı değinilerle yakılmış bir ağıt bulacaksınız.&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">İyimserlik yaşadığımız d&uuml;nya koşulları d&uuml;ş&uuml;n&uuml;ld&uuml;ğ&uuml;nde ger&ccedil;ekleri g&ouml;rmeyi engelleyen bir olgu. &Ccedil;ağımız koşullarında, insanın kendisi tarafından &uuml;retilen sentetik bir duygu. Kişisel isteklendirme yani bir işe motive olma konusunda işe yaradığı bilinen iyimserlik, ger&ccedil;ek&ccedil;i nedenlere dayanmadığında bir sonraki aşamada karşımıza karamsarlık olarak dikiliyor. İnsanların değişken ve sorunlu kişiliklerinde &ouml;nemli bir etken, adına şu iyimserlik denen şey. S&ouml;z&uuml;n kısası, iyimserliğe neden olmadığı durumlarda iyimserliğe a&ccedil;ık kapı bırakılmamalı. Eleştiride zenginliğin &ouml;n koşulu &ouml;znellik. Nesnellik diye tutturanların yıllar boyu yaptığı ortada. Dar bir kulvarda tepinenler, herkesin g&ouml;rd&uuml;ğ&uuml;n&uuml; yalnız kendisinin g&ouml;rd&uuml;ğ&uuml;n&uuml; sanarak gerinenler ve ortaya d&ouml;k&uuml;len zevksizlik &uuml;r&uuml;nleri. Nesnellik ancak niteliksiz &ouml;znelliğin bir adım &ouml;n&uuml;nde giden bir sığlık olsa gerek. Nesnelliğin yaratıcılıktan dizleri titreyenler, &ouml;znel olana hep korkuyla bakanlar ve kendini g&uuml;vende hissetmek isteyenler i&ccedil;in vazge&ccedil;ilmez olduğu bir ger&ccedil;ek. Ya eleştirmenin taşıdığı &ouml;zellikler? Eleştirmenin eleştirisinin etkinlik alanı kendisini de kapsamalıdır. Bu durum kimliğin sunumu ve s&ouml;ylemde a&ccedil;ıklık politikasını, kendini bilmeyi, samimiyeti ve tutarlılığı getirir. Eleştiri eleştirmenin kimliğini taşımalıdır. Kişiliğin sağlamlığı eleştirinin sağlamlığı i&ccedil;in &ouml;nemli bir &ouml;l&ccedil;&uuml;d&uuml;r. Kendini tanımayan insanlarla her iş zordur ama bir de bunlar kendilerine d&uuml;ş&uuml;nce alanını se&ccedil;mişlerse işimiz daha da zorlaşır. Bu nedenle olsa gerek, bu tipteki insanlar d&uuml;ş&uuml;ncenin ardından gelen eleştiride kaybolur giderler. Eleştirinin&nbsp; yapıta doğru sorular y&ouml;neltmek olduğu d&uuml;ş&uuml;n&uuml;lecek olursa, yanlış olanın ve yanlışını g&ouml;remeyenin doğru soruları nasıl &uuml;reteceği konusu bir &ccedil;ıkmazdır. Nesnel olanın bile altından kalkamayanın, aranan yanıtların &ccedil;oğulcu okumaya dayandığı &ouml;znelliği yakalaması nasıl d&uuml;ş&uuml;n&uuml;lebilir ki?&nbsp; Bir de sinemanın bizler i&ccedil;in neyi ifade ettiği konusu var. Karşımıza zamanımızı &ouml;ld&uuml;rmekten tutun da hayatımızın olmazsa olmazı olmaya kadar &ccedil;ok &ccedil;eşitli se&ccedil;eneklerle &ccedil;ıkan sinema en son noktada bize ne verebilir? Zamana, yaşama ve &ouml;l&uuml;me karşı dayanıklılığı ve direnmeyi. Sinema varoluş&ccedil;uluğun şimdilik en yeni ve son versiyonudur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">D&uuml;nya sinema yayıncılığının dergi kulvarında koşan yapıtlar arasında a&ccedil;ık ya da gizli s&uuml;ren bir savaş var. İ&ccedil;eriklerindeki kuram zenginliği, g&uuml;ndemi yakalama becerileri ve g&ouml;rsellikleriyle olduğu kadar yayınlandıkları dille de olumlu veya olumsuz bir g&ouml;r&uuml;n&uuml;m edinirler. &Ouml;zellikle listenin &uuml;st sıralarında, i&ccedil;erikle tanınmışlık ters orantılı bir g&ouml;r&uuml;n&uuml;m sunar. Bianco e Nero&rsquo;nun Cahiers du Cinema&rsquo;dan aşağı kalır yanı yoktur ama dergi dendi mi akla Sight and Sound&rsquo;un gelmesi bu ger&ccedil;eği doğrular. Uluslararası bir dille yayınlanıyor olmalarının avantajını kullanan İngilizce yayınlar i&ccedil;in &ccedil;alıp &ccedil;ırpmanın sonu yoktur. Sight and Sound tanınmış olmanın y&uuml;klediği pop&uuml;lerlik tuzağına d&uuml;şm&uuml;ş bir dergi. O, globalleşmenin lideri olmasıyla silikleşti. Fransızca ve İtalyanca yayınlar bir adım geride dursalar da daha yoğun ve &ouml;zg&uuml;nd&uuml;rler. Kimlik erozyonuna daha dayanıklı oldukları g&ouml;r&uuml;l&uuml;r. &Ccedil;ağın &ouml;teki olanı susturmaya veya kontrol etmeye d&ouml;n&uuml;k politikası &ccedil;ağın &ouml;nemli dergilerinin bildik dağıtım kanallarıyla elimize ulaşmasını engelliyor. Orijinalin kitleselleşmemesi, ulusal yayıncılığı &ccedil;eviriler konusunda cesaretli kılıyor.&nbsp; &Ouml;zg&uuml;n yapıtın &uuml;remesini engelleyen de bu bağımlılık olsa gerek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bunuel</b>&nbsp;der ki: Şeytan eteklerin altındadır. İster maksi ister mini olsun, etek bir mikro yansımadır. Etek D&uuml;nya&rsquo;nın ta kendisidir aslında. İ&ccedil;indeki insanlar ve onların sonu gelmez istekleri de şeytanı temsil eder. &Ccedil;oklu cinsiyet d&uuml;nyayı &ccedil;ok y&ouml;nl&uuml; okumaya olanak tanıyorsa eğer, eleştiriye de &ccedil;ok y&ouml;nl&uuml; bir a&ccedil;ılım sağlayabilir. Girilmedik alanın kapsama alanına dahil edilmesi yeni bir renk, ses ve s&ouml;z dağarcığı getirerek &ccedil;ok katmanlı yorumun &ouml;n&uuml;n&uuml; a&ccedil;abilir. G&ouml;stergebilim konusu, &uuml;zerine konuşurken bile sıkıntı veren şu sorunlar yumağı olan konu. Kuramsal sunumunu, yenilik&ccedil;ilik altında sunulan yinelemeci tutumu ve eleştiri ve &ccedil;&ouml;z&uuml;mlemedeki izd&uuml;ş&uuml;mlerini d&uuml;ş&uuml;nd&uuml;ğ&uuml;mde, adının g&ouml;sterişbilim olarak değiştirilmesini &ouml;neresim geliyor. Bu bile, g&ouml;stergebilim tarihinde epey bir ilerlemeye karşılık gelecek bir adım olmalı. Acaba, anlam yoksunluğunun anlamı &uuml;zerine, ben de g&ouml;sterişbilimsel bir safra &uuml;retsem mi? G&ouml;stergebilim bir y&ouml;n&uuml;yle de egemen ideolojinin akademik formasyondaki dayatmacılığının g&ouml;stergesi(!) olamaz mı? Egemen ideoloji karşısında sergilenmesi gereken bilin&ccedil; -siz buna isterseniz kontr-bilin&ccedil; deyin- veya algının yoğunlaşması ile sağlanan diren&ccedil;, en azından bireysel olarak ayakta kalmanın yolu olmalı. Esir d&uuml;şmeyenlerin hayatları beni hep bu iki noktanın altının &ccedil;izilmesi gerektiği y&ouml;n&uuml;nde uyarıyor. Kişiliğin sorgu sonrasında ortaya &ccedil;ıkan bilin&ccedil;li kısmı, doğrudan kazanılarak kabullenilmiş olan sorgulamaya kapalı kısmıyla karşılaştırılınca, ne denli dar bir bilin&ccedil; evreniyle yaşadığımız, hatta ne kadar sıradan bir hayat s&uuml;rd&uuml;ğ&uuml;m&uuml;z ortaya &ccedil;ıkar. Asıl sorunlu evre de bundan sonra başlar. Sorgulamaya kapalı tutulan alan eleştiriye tutularak sorgulandığında, d&uuml;n&uuml;n doğruları bir bir yıkılır ve ardında ideolojik y&ouml;nlendirmelerin yattığı a&ccedil;ığa &ccedil;ıkar. Birey kendisini &ccedil;epe&ccedil;evre saran zincirlerinden kurtulur kurtulmasına ama artık g&uuml;n, alt &uuml;st olmuş yaşamın dengelerini yeni baştan kurma &ccedil;abasının ilk g&uuml;n&uuml;d&uuml;r.&nbsp; Sinema dilinde bi&ccedil;im ve bireysel stil&nbsp; her zaman sosyo-politik anlamlarla &ouml;r&uuml;l&uuml;d&uuml;r. Bir &uuml;lkenin, bir coğrafyanın veya bir auteur&uuml;n d&uuml;nyasını farklı kılan, &ouml;tekilerden ayıran da bu sosyo-politik embriyo i&ccedil;inde değişim ge&ccedil;iren bi&ccedil;im ve &ouml;znel duruştur.Bir başka ilgin&ccedil; konu da Berlin Duvarı&rsquo;nın yıkılışı sonrası k&uuml;lt&uuml;rel s&ouml;ylemlerde ortaya &ccedil;ıkan ve ilkellik &ouml;ncesi d&ouml;nemden fırlamışa benzeyen politik laforizmalar. C&uuml;helatif gazeteciler ve yazarlardan sonra bazı uyduruk akademisyenler (halen neden şu akademik d&uuml;nyayı &ouml;nemseyip korumaya &ccedil;alışıyorsam!?) de zaman zaman, Sovyet Devrimi&rsquo;nin Rusya&rsquo;daki ilerici sanat anlayışını sona erdirdiğinden dem vuruyorlar. Halt etmişler! Resim, tiyatro ve edebiyata bakarak ahkam kesmek kolay. Bunlar bile geleneksel olanın yanına yeniyi koyarak ilerlemeyi s&uuml;rd&uuml;rd&uuml;ler. Yurtdışına ka&ccedil;an sanat&ccedil;ıları d&uuml;ş&uuml;nseniz bile Rus halk k&uuml;lt&uuml;r&uuml;n&uuml;n değerinden bir şey yitirmediğini g&ouml;rebilirsiniz. Eğitimli ve modern sanatı temsil edenlere gelince, onların yıllar boyunca Batı anlayışını yeniden yaratmanın dışında ne yaptıkları sorusuna, hangi sanat tarih&ccedil;isi bu laforizmaları doğrulayacak bir onay verebilir? Sovyetler &ouml;ncesinde, Rusya&rsquo;daki sanat, halk k&uuml;lt&uuml;r&uuml;n&uuml; temsil edenin dışında, Fransız yalakalığına indirgenmiş bir sanat anlayışıydı. Ger&ccedil;ek, devrimin ileri gelenlerinin &ouml;ncelikli konuma y&uuml;kselttikleri sinemanın diğer sanat dallarına olan ilginin sesini kısmış olmasıdır. Bir diğer ger&ccedil;ek, sinemada d&uuml;nya &ccedil;apında sağlanan başarının, sona erdirildiği s&ouml;ylenen ilerici adımların kat kat fazlasını doğurmuş olduğudur.&nbsp;<b>Kuleshov</b>,<b>&nbsp;Pudovkin</b>,&nbsp;<b>Vertov</b>&nbsp;ve&nbsp;<b>Eisenstein</b>&rsquo;ın bir tanesi bile s&ouml;z&uuml; edilen boşluğu doldurmaya yeter de artar bile. Bug&uuml;n kim hatırlanıyor, gelecekte kim hatırlanacak?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Wood</b>&rsquo;un en &ccedil;ok akılda kalan ve tartışılmaya değer saptamalarından biri de eğitim ve kariyer arasındaki rol değişimi &uuml;zerine olanı. G&uuml;n&uuml;m&uuml;z&uuml;n &ouml;ğretim sisteminde atılan her adım kariyer adına atılıyor. Eğitimsiz kariyer olmayacağını d&uuml;ş&uuml;n&uuml;yorsanız kendinizi aldatıyorsunuz. Ortalık bunun ayaklı kanıtlarından ge&ccedil;ilmiyor. Adına ister genel k&uuml;lt&uuml;r, ister alan k&uuml;lt&uuml;r&uuml; ve hatta isterseniz &ouml;zel k&uuml;lt&uuml;r deyin, hi&ccedil; ama hi&ccedil;bir şeyden nasiplenmemiş bir kuşak yetişiyor ve onların ilk dalgası bazı yerlerde &ouml;nemli koltukları da şimdiden kapmış durumdalar. Kariyerist &ouml;ğretim politikası eğitimi komalık etti. Ve bunun sancıları &ouml;zellikle iki yerde, akademik d&uuml;nyada ve kent k&uuml;lt&uuml;r&uuml;nde fazlasıyla sırıtmaya başladı. Eskiden bu anlayışın ilk dalga temsilcilerine ot gibi deniyordu, otun bir yaşam belirtisi taşıdığı unutularak!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Eğer evrim kanunlarına inananlardansanız &ndash;kurama inananların dışında kalan d&uuml;nya n&uuml;fusunun &uuml;&ccedil;te birinin evrim kanununu bilmediğini, &uuml;&ccedil;te birinin kutsal kitapların da bilgiden yoksun inan&ccedil;ları gereği reddettikleri bu kurama destek veren satırlar taşıdığını bilmediklerini ya da bilseler bile işlerine gelmediğini, &uuml;&ccedil;te birinin de evrim kanununun yaşayan &ouml;rnekleriyle her g&uuml;n karşılaştığını g&ouml;rmezlikten geldiğini d&uuml;ş&uuml;nerek b&ouml;yle bir giriş yapmak zorunda kalıyorum.-, bu paragraf sizler i&ccedil;in. İnsan ırkının bir evrim hatasına kurban gittiğini d&uuml;ş&uuml;nen&nbsp;<b>Wood</b>, bu s&ouml;ylemiyle kurama inananları da şoke eden bir noktaya geliyor. İşin esprisi bir yana, bu tersten de okunabilir bir d&uuml;ş&uuml;nce. İnsanı d&uuml;nyada &ouml;ne &ccedil;ıkaranın vahşiliği, k&ouml;t&uuml;l&uuml;ğe ve yıkıcılığa kodlanmış genetik yapısı, her t&uuml;rden a&ccedil;lık duygusu ve paradoksal ruh yapısı olduğunu d&uuml;ş&uuml;nmek i&ccedil;in elimizde her t&uuml;rden kanıt var. Toplumsal &ouml;rg&uuml;tlenmeye gelince, demokratik yollardan se&ccedil;ilenlerin anti-demokratik g&uuml;&ccedil;ler olması trajikomik bir saptama. Aslına bakarsınız, demokrasi hi&ccedil; uygulanmıyor değil, se&ccedil;ici sınıflar i&ccedil;inde ve eşit g&uuml;&ccedil;lerin birbiri &uuml;zerinde denetim uygulayabildiği koşullarda zoraki de olsa uygulanabilirliği yok değil. Ekonomik &uuml;retimin iplerini ellerine dolayanların ve onların kontrol&uuml;ndeki medyanın desteği ile anti-demokratik olan karşımıza demokratik rol&uuml;ne kendini kaptırmış bir sistem i&ccedil;inde sunuluyor. G&uuml;n&uuml;m&uuml;zde, ana g&ouml;revi b&uuml;y&uuml;klere masallar okuyarak kitleleri oyalamak olan, eleştiride kantarın topuzunu, acı biberin tutamını kendisi ayarlayan ve b&ouml;ylece demokratik, şeffaf ve eşitlik&ccedil;i olduğu iddiasını s&uuml;rd&uuml;ren bir medya var.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">B&uuml;t&uuml;n bunlar varsayalım ki doğru ve g&uuml;zel tespitler. İyi ama ne yapmalı? Sıkıntılı ve zorlu s&uuml;re&ccedil;lerden ge&ccedil;iyoruz. Eğer bunu bir rahatlama ve ferahlama s&uuml;reci izliyorsa doğru ve g&uuml;zel olanın basamaklarını &ccedil;ıkıyoruz demektir. Aslolan zora girmek, &ccedil;abalamak ve &uuml;retmek. Olumsuzluklara direnmek, ucunda &uuml;retim ve eylem olan bilgiye ve d&uuml;ş&uuml;nceye dayanarak ger&ccedil;ekleşmeli. &Uuml;retimsiz bilgi ve eylemsiz d&uuml;ş&uuml;nce, bunlar hoş ama boş işler. Peki ya birey, onun rol&uuml; ve konumu ne olmalı? Basamakları &ccedil;ıkan her birey biraz da kendi yalnızlığına doğru rol alır. Vandallık ve s&uuml;r&uuml; anlayışının yerini, birey olarak kendini varedebilme becerisi alır. Geleneksel olana ve tabulara direniş akıntıya karşı k&uuml;rek &ccedil;ekmek anlamına gelse bile yaşayan bir &ouml;l&uuml; olmadığınızı fısıldar. Yalnızlık &ouml;z&uuml;nde g&uuml;zeldir ve yaşayan bir varlıksanız paylaşarak ve &uuml;reterek toplumla olan bağın kopmasını engellersiniz. Dışlanmışlık ve yalnızlık, &ouml;zg&uuml;n olduğunuz saptamasını tek başlarına doğurmasalar da izlerini taşıyabilir. S&uuml;r&uuml;n&uuml;n dışında olmak, k&uuml;lt&uuml;rel derinliğinizin, zamanla yapılandırdığınız &ouml;zg&uuml;nl&uuml;ğ&uuml;n&uuml;z&uuml;n, &ouml;zg&uuml;r olma isteğinizin, yaratıcılığınızın sınırsızlığının, yaşama karşı direnişinizin, er ya da ge&ccedil; ortaya d&ouml;k&uuml;lecek olan haklılığınızın ve eleştirme hakkınızın bir t&uuml;r dışavurumudur. Film eleştirisi, &ccedil;ağımızı hızlı bir değişime sokan insanın insan olma y&ouml;n&uuml;nde attığı b&uuml;t&uuml;n adımlara tanıklık eden sinemayı sorgulayabildiği ve ger&ccedil;eği ortaya &ccedil;ıkartmayı ama&ccedil;ladığı i&ccedil;in anlamlıdır.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-06');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (68, 'ay-j189', 'dumanalti-filmler', 'Dumanaltı Filmler', 'Kılavuz, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Belleğinizi bir ad, bir kavram i&ccedil;in ilk anda yokladığınızda &ouml;n&uuml;n&uuml;ze hemen d&uuml;ş&uuml;veren imgeler vardır ya hani, işte bu işlemi t&uuml;t&uuml;ne uyguladığınızda bellek koridorlarınızı bir t&uuml;ts&uuml; &ccedil;eşnisi kaplar &ouml;nce, ardından dumana boğulan &ccedil;er&ccedil;evenizden s&uuml;z&uuml;l&uuml;p gelenleri ayıklamaya &ccedil;abalarsınız? Hadi durmayın, filmlerin t&uuml;t&uuml;nden nargileye, sigaradan puroya belleğinize neler bıraktığını bir d&uuml;ş&uuml;n&uuml;n. &Ouml;nce bir konuda anlaşalım: Puroyu b&uuml;t&uuml;n sinemacılar i&ccedil;inde karizmasına, iriden &ouml;te bedenine ve ayartıcı imajına en yakışır ve en sağlam bi&ccedil;imde taşıyan adam&nbsp;<b>Orson Welles</b>&rsquo;tir, &ouml;yle ki onu elinde sigarayla hayal bile edemezsiniz. Anlaştıysak, belleğimize kazınmış imajların izini s&uuml;rmeyi s&uuml;rd&uuml;rebiliriz.&nbsp;<b>L&uuml;tfi Akad</b>&rsquo;ın&nbsp;<b><i>Vesikalı Yarim&nbsp;</i></b>(1968) filminde&nbsp;<b>T&uuml;rkan Şoray</b>&rsquo;ı vesikasızlardan ayıran, i&ccedil;meyi beceremediği duygusunu uyandıran eğretiliğiyle sigara değil mi? Ya da ağzında emzik niyetine dolaştırdığı sigaranın, alt dudağında a&ccedil;tığı o sigara kanalıyla Red Kit? Peki ya&nbsp;<b>Halit Refiğ</b>&rsquo;in&nbsp;<b><i>Karakolda Ayna Var</i></b>&nbsp;(1966) filminde doğal afetliğe soyunan&nbsp;<b>Fatma Girik</b>&rsquo;in ağzına pek bir g&uuml;zel yakışan sigara ağızlığı?&nbsp;<b>Clint Eastwood</b>&rsquo;un ağzından d&uuml;şmeyen cigarlarından t&uuml;ten dumanların&nbsp;<b>Sergio Leone</b>&nbsp;westernlerini birbirine kurguladığı d&uuml;ş&uuml;ncesi kurgu teorisinde fantastik bir devrime yol a&ccedil;ar mı?&nbsp;<b>Humphrey Bogart</b>&rsquo;ın filmlerde kadınlarına doğrudan s&ouml;yleyemediği satır arası s&ouml;ylemlerini sigarasının dumanına y&uuml;klediği tezime ne buyurulur?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Gangsterlerin &ouml;ld&uuml;rd&uuml;kleri Baba&rsquo;ların ağızlarına tıkıştırıp yakmayı da unutmadıkları puroların &lsquo;v&uuml;cuduma evet ama puroma asla dokunma&rsquo; yasasına g&ouml;sterdikleri incelikli saygı sahneleri de unutulur cinsten değil! Bir de şu bizim Kızılderili dostların barış &ccedil;ubuğunu dolandırdıkları geleneksel t&ouml;renleri &ccedil;ıkmaz aklımdan, hemen her zaman Hollywood tarafından aldatılmaya &ccedil;alışılsam da onlardan biri gibi, hi&ccedil; olmadı o &ccedil;adırdaymış gibi hissederim kendimi. Western ve gangster filmlerinin olmazsa olmazıdır cigar, film-noir da ise yarattığı duman bulutuyla g&ouml;rsel atmosferin ta kendisidir! Filmlere bakınca, t&uuml;t&uuml;n&uuml;n hangi ada b&uuml;r&uuml;n&uuml;rse b&uuml;r&uuml;ns&uuml;n, zengin-yoksul, cahil-entelekt&uuml;el, beyaz-siyah ve benzeri t&uuml;rden ayrımları tanımadığı ortada. Buna bir de t&uuml;t&uuml;n end&uuml;strisinin &ouml;zellikle Amerikan ve Fransız sinemasını reklam panosu gibi kullandığı g&ouml;zlemimi eklemeliyim. D&uuml;nyada&nbsp;<b>Philip Morris</b>&nbsp;tarafından desteklenen festival ve film haftaları olduğunu da bilmelisiniz. Evet, sigara bir stat&uuml; g&ouml;stergesi, bir haz nesnesi ve boşalım anlarının en yakın arkadaşıdır derken, sinemanın yalancısı olduğumu unutmayın.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu ilk &ccedil;ağrışımlardan sonra, sinemanın t&uuml;kettiği t&uuml;t&uuml;ne biraz daha &ouml;telerden ve az bilinir olan noktalardan bakalım. T&uuml;t&uuml;n son yıllarda a&ccedil;ılan davalarla epeyce b&uuml;y&uuml;k yaralar alsa da halen devasa bir end&uuml;stri olma &ouml;zelliğini koruyor. Bazı &uuml;lkelerde yeni yasal d&uuml;zenlemelerle sinema salonlarına girmesi yasaklandığı gibi, filmlere de eskisi gibi sızamıyor. Filmler, bu end&uuml;stri &uuml;r&uuml;n&uuml; ve haz nesnesine, &uuml;retiminden t&uuml;ketimine dek her aşamasında tanıklık ederler. D&uuml;nyaca &uuml;nl&uuml; Habana purolarının &ouml;yk&uuml;s&uuml;n&uuml;&nbsp;<b>Tomas Gutierrez</b>&nbsp;&ndash;Strawberry and Chocolate-&nbsp;<b>Alea</b>&rsquo;nın&nbsp;<b><i>El Arte del Tabacco</i></b>&nbsp;(1974, K&uuml;ba) belgeselinde &ouml;ğrenmiş ve onların bir t&uuml;t&uuml;n işleme at&ouml;lyesinde &ccedil;alışan iş&ccedil;ilerin ellerinde adım adım ortaya &ccedil;ıkışlarına tanıklık etmiştim. &Uuml;retimi yapılan t&uuml;t&uuml;n &uuml;r&uuml;nleri d&uuml;nyanın d&ouml;rt bir yanına yayılıyor, yerleştikleri raflarda ve albenili paketleri i&ccedil;inde nasiplenecekleri ağızları beklemeye koyuluyorlardı. G&ouml;r&uuml;nen o ki bu bekleyiş uzun s&uuml;rm&uuml;yordu. Alıcılarıyla buluştukları yerlerden biri de&nbsp;<b>Wayne</b>&nbsp;&ndash;Chinese Box-&nbsp;<b>Wang</b>&rsquo;ın&nbsp;<b><i>Smoke</i></b>&nbsp;(1995, ABD) filminde bir&nbsp;<b>Paul Auster</b>&nbsp;adamına d&ouml;n&uuml;şm&uuml;ş olan&nbsp;<b>Harvey Keitel</b>&rsquo;ın t&uuml;t&uuml;nc&uuml; d&uuml;kkanıydı. Yaşam kırıklıkları yalnızlıklarına, yalnızlıkları yaşam kırıklıklarına yansımış &uuml;&ccedil; erkeğin dumanlı d&uuml;nyası i&ccedil;in vazge&ccedil;ilmez bir yer olan bu t&uuml;t&uuml;nc&uuml; d&uuml;kkanı onların yaşam alanı, buluşma noktalarıydı. T&uuml;t&uuml;n&uuml;n birleştirici ve paylaşımcı rol&uuml;ne dikkat buyurun! Bu nefis filmin senaryo ve yapım-y&ouml;netim aşamaları emin olun ki bir duman bulutu altında ger&ccedil;ekleşmiştir. Biraz &ouml;ncekilere t&uuml;t&uuml;n&uuml;n yaratıcı rol&uuml;n&uuml; de ekleyin l&uuml;tfen!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sigaralarımızı d&uuml;kkandan alıp &ccedil;ıktığımıza g&ouml;re, dumandan g&ouml;z g&ouml;z&uuml; g&ouml;rmez sohbetlerimize artık başlayabiliriz. Bu noktada herşeyi &ouml;zetleyen bir kısamız, daha doğrusu&nbsp;<b><i>Coffee and Cigarette</i></b>&nbsp;(1986-89-93, ABD) ortak adıyla bir seri oluşturan kısalarımız var. Hepsinin y&ouml;netmeni&nbsp;<b>Jim</b>&nbsp;&ndash;Stranger Than Paradise-&nbsp;<b>Jarmusch</b>. Sigarayı tesad&uuml;fi karşılaşmaların ilk anında soğukluğu eriten ve sohbete kapı aralayan bir ara&ccedil; olarak kullanan y&ouml;netmen, bu yaklaşımla sigaraya iletişim alanında y&uuml;ksek lisans yaptırıyor. Bu, işin eğlenceli ve bireyci &ccedil;ıkarımlara dayalı boyutu ama tek boyutu değil. Bunun karşısına sigaraya toplumsal sorunların değişmez g&ouml;stergesi olarak bakan bir anlayışı koymak m&uuml;mk&uuml;n. &Ccedil;ok sayıda filmin arasında&nbsp;<b>Bruno Stagnaro</b>&nbsp;ve&nbsp;<b>Adrian Caetano</b>&rsquo;nun ilk filmleri olan&nbsp;<b><i>Pizza, Beer, Smokes</i></b>&nbsp;(1997, Arjantin) &ouml;ne &ccedil;ıkıyor. Geleceği olmayan, g&uuml;n&uuml; &ccedil;alıp &ccedil;ırparak kurtaran bir kuşağın &ouml;yk&uuml;s&uuml;n&uuml; anlatan film, tek eğlencesi birayı sigaraya, sigarayı biraya katık etmek olan gen&ccedil;liğin dramını g&ouml;zler &ouml;n&uuml;ne serer. Y&uuml;zyıl başında Arjantin&rsquo;de yaşanan seri krizler d&uuml;ş&uuml;n&uuml;ld&uuml;ğ&uuml;nde, filmin yaptığı toplumsal analizle geleceği g&ouml;rmek gibi g&uuml;&ccedil; bir işi başardığı da ortada. Bu noktada, sigara t&uuml;ketiminin ulaştığı boyutun, gerek bireyin mutsuzluğu gerek toplumun huzursuzluğu a&ccedil;ısından ortaya bir veri koyduğu d&uuml;ş&uuml;n&uuml;lmeli. Sinemanın tanıklıklarının dikkate alınması gerektiği bir kez daha ortaya &ccedil;ıkıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Konumuz a&ccedil;ısından, entelekt&uuml;el sinema adına s&ouml;z alan y&ouml;netmen&nbsp;<b>Alain</b>&nbsp;&ndash;Hiroshima, Mon Amour-&nbsp;<b>Resnais</b>&nbsp;olacak. Sigaranın &ouml;yk&uuml;leme tekniği a&ccedil;ısından hareket noktası olarak işlevselleştirildiği&nbsp;<b><i>Smoking &ndash; No Smoking</i></b>&nbsp;(1993) adlı interaktif ikizlerinde, deneysever karakterini bir kez daha s&ouml;zhakkı veriyor Resnais. Ama hi&ccedil; mi hi&ccedil; iyi yapmıyor.&nbsp;<b>Sabine Azema</b>&rsquo;nın sigarayı i&ccedil;mek veya i&ccedil;memek doğrultusunda vereceği kararın, &ccedil;ok y&ouml;nl&uuml; ve değişken finalli bir anlatı yapısı kurması ve &ouml;yk&uuml; akışının kontrolden &ccedil;ıkması, seyircide de kontrol yitimine neden olarak dayanılmaz bir sigara i&ccedil;me isteği uyandırıyor. Ters bir bakış: &Ccedil;ileden &ccedil;ıkma noktasındaki seyirci, hatta bug&uuml;ne kadar ağzından sigarayı hi&ccedil; d&uuml;ş&uuml;rmemiş olanlar bile, bir daha ne sigara i&ccedil;meyi ne de film izlemeyi g&ouml;ze alır mı dersiniz? Resnais, bu a&ccedil;ıdan bakıldığında, ne denli etkili ve g&uuml;&ccedil;l&uuml; bir y&ouml;netmen olduğunu kanıtlamak istemiş olabilir mi?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">T&uuml;t&uuml;n&uuml;n sinemaya yansıyan g&ouml;r&uuml;nt&uuml; ve &ouml;yk&uuml;lerinden bir derleme okudunuz. Bazı karakterlerin sigarayla yere daha sağlam bastığı da, sigara i&ccedil;menin kimi durumlarda somut g&ouml;stergeler sunduğu da, hatta bazen işleri kolaylaştırıp samimiyeti kurduğu da, hepsi ama hepsi ger&ccedil;ek. Ancak bu ger&ccedil;ek perdenin hep &ouml;te tarafında kalsa, ne de g&uuml;zel olacak!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (69, 'ay-j190', 'bir-amerikan-ruyasi-elia-kazan', 'Bir Amerikan Rüyası... Elia Kazan', 'Kılavuz, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">O, her bahar deri değiştiren yılanları kıskanırdı. Bu &ouml;zelliğin kaygıları ve pişmanlığı sileceğini d&uuml;ş&uuml;nerek... Bunları s&ouml;ylerken, kendi derisinin bir &ouml;m&uuml;r boyu ona yoldaşlık edeceğinin bilincindeydi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Dile kolay, her t&uuml;rden acı, sancı ve zorluğun &ccedil;arpıcı başarılarla yaşanır hale geldiği ve tam 94 yıl s&uuml;ren bir hayat.&nbsp;<b>Elia Kazan</b>&rsquo;ın &ouml;l&uuml;m&uuml;, ge&ccedil;en yılın sinema elvedaları i&ccedil;inde en y&uuml;kl&uuml; olanıydı kanımca. Bu yazıda, onun yaşamını, deyim yerindeyse orasından burasından ele alacak ve analiz etmeye &ccedil;alışacağız. &Ccedil;ağına tanıklık eden bu yaşamın herkese &ouml;ğretici olabilecek nitelikte dersler taşıdığına inanıyoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Osmanlı İmparatorluğu vatandaşı olarak, 7 Eyl&uuml;l 1909&rsquo;da İstanbul&rsquo;da başlayan bir hayat... Elia Kazancıoğlu... &Ccedil;ocukluk yıllarının yarısını Anadolu&rsquo;da, yarısını ABD&rsquo;de yaşamak durumunda kalan Kazan i&ccedil;in, zorlu ama bir o kadar da &ouml;ğretici bir d&ouml;nem. Ona t&uuml;rl&uuml; t&uuml;rl&uuml; s&uuml;rprizler hazırlayan hayat, hen&uuml;z Elia&rsquo;nın kendisine hazırladığı deneysel tuzaklardan haberdar değil. Anadolu ruhunun g&ouml;lgesi, bu gen&ccedil; Amerikalının &uuml;zerine d&uuml;şm&uuml;ş. Zamanla Elia da bu durumun farkına varacak.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Girdiği sanat ortamında, &ouml;nceleri 1934-45 yılları arasında yoğun olarak &ccedil;alıştığı ve 1938&rsquo;de&nbsp;<b><i>Liliom</i></b>&rsquo;da&nbsp;<b>Ingrid Bergman</b>&nbsp;ile aynı sahneyi paylaşmasını sağlayan tiyatroya y&ouml;neldi. Akt&ouml;r, y&ouml;netmen ve eğitmen olarak tiyatroda adını duyurdu ancak elde ettikleri ona yetmez olunca, 1930&rsquo;lu yılların sonuna doğru sinemaya yakınlaşmaya başladı. Oysa bu yıllarda oyuncu y&ouml;netimi dışında sinemadan anladığı yoktu. Sinemada gezinen bir oyuncu, bir tiyatrocuydu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinemada senaryosunu da katıldığı&nbsp;<b><i>Gentleman&rsquo;s Agreement</i></b>&nbsp;(1947; Oscar, en iyi film) ile dikkate alındı. İlk &ouml;nemli filmi olan ve saplantılı bir aşk &ccedil;eşitlemesi olan&nbsp;<b><i>Arzu Tramvayı</i></b>&nbsp;(A Streetcar Named Desire, 1951),&nbsp;<b>Marlon Brando</b>&rsquo;nun uluslararası tanınmışlığında &ouml;nemli rol oynadı. Filmi ne zaman izlesem, Kazan&rsquo;ın kişiliğinin Brando&rsquo;un canlandırdığı karaktere iyiden iyiye sindiğini d&uuml;ş&uuml;nm&uuml;ş&uuml;md&uuml;r. Kazan&nbsp;adıyla neredeyse &ouml;zdeşleşen&nbsp;<b><i>Viva Zapata!</i></b>&nbsp;(1952; Brando, Cannes&rsquo;1952 FF en iyi akt&ouml;r), erk yetkisinin yozlaştırıcı y&ouml;n&uuml;n&uuml; ince saptamalarla ortaya koyarken, halktan uzak d&uuml;şm&uuml;ş bir devrim &ccedil;iziktirdiği, kahraman yaratma sevdasıyla bireyci ideolojinin tuzağına d&uuml;şt&uuml;ğ&uuml; ve ger&ccedil;ekleri yansıtmadığı gerek&ccedil;esiyle eleştiriler aldı. Aynı yıl, Amerikan Karşıtı &Ccedil;alışmaları Araştırma Komisyonu&rsquo;na yaptığı a&ccedil;ıklamaların ve bir d&ouml;nem birlikte &ccedil;alıştığı arkadaşlarını kom&uuml;nist oldukları gerek&ccedil;esiyle ele vermesinin, ona Hollywood&rsquo;un kapılarının ardına kadar a&ccedil;ılmasında yadsınmaz rol&uuml; vardır. O, herşeyi g&ouml;ze almıştı ve yoluna devam etti. Hi&ccedil;bir zaman pişmanlık duymasa da ge&ccedil;en yılların ardından huzursuzluğunu a&ccedil;ığa vuran a&ccedil;ıklamalar yaptı.&nbsp;<b><i>Rıhtımlar &Uuml;zerinde</i></b>&nbsp;(On the Waterfront, 1954; Oscar, en iyi film, y&ouml;netmen, akt&ouml;r, yrd. aktris) filmiyle liman iş&ccedil;ilerinin d&uuml;nyasına eğilerek, sendikaların emek&ccedil;ilerle olan &ccedil;atışmasını işledi. Filmin başkarakteri olan, olayları b&uuml;t&uuml;n &ccedil;ıplaklığıyla anlatan, kişileri ele verecek denli cesarete sahip olan ve su&ccedil;luluk psikolojisiyle ruhunu hafifletmek i&ccedil;in doğru olduğuna inandığı her eylemi yapabilecek&nbsp;<b>Terry</b>&rsquo;si ile&nbsp;<b>Kazan&nbsp;</b>arasındaki benzerlikler bazılarının g&ouml;z&uuml;nden ka&ccedil;maz. Sıklıkla eleştirilen kahraman olarak birey yaratma anlayışını, tipik bir Hollywood anlayışı olarak ele almak gerekir. Limanı haraca bağlayan gangsterlerin sendika ile yer değiştirmesini ise, emeğe saygı duyan ancak sendikal &ouml;rg&uuml;tlenmenin yarattığı &ccedil;ıkarlara karşı duran bir anlayışa bağlayabiliriz. Anlaşılan o ki &ouml;nyargılarımız bir yerden &ouml;tesini yalnız olasılıklara dayanan yanlışlarıyla kavramamıza el veriyor. Karşımızda sola selam, yola devam anlayışı duruyor.<b>&nbsp;Kazan</b>&nbsp;doğası gereği taşıdığı sol s&ouml;ylemi, liberal ve bireyci bir s&ouml;ylemle s&uuml;sl&uuml;yor ve kendi a&ccedil;mazına g&ouml;ndermede bulunuyor.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Y&ouml;netmenin 1950&rsquo;li yıllarda &ccedil;ektiği filmler, Hollywood&rsquo;un klasik anlatı sinemasının g&uuml;&ccedil;l&uuml; &ouml;rnekleri olarak,&nbsp;<b>Kazan</b>&nbsp;adını doruğa taşıdılar. Bu nedenle, bu d&ouml;nem boyunca Amerikan sineması denince akla gelen ilk isim Kazan oldu. 1960&rsquo;larda kendisinin &ccedil;ok sevdiği&nbsp;<b><i>Wild River&nbsp;</i></b>(1960) ve beğendiği&nbsp;<b><i>America</i></b><i>,<b>&nbsp;America</b></i>&nbsp;(1963) filmleriyle başarılı olmasına karşın, sinemadan giderek uzaklaştı ve bu yılları &ccedil;ekilmemesinin daha iyi olacağını s&ouml;ylediği&nbsp;<b><i>The Arrangement&nbsp;</i></b>(1969) ile noktaladı. Yine bu on yıllık d&ouml;nemde, y&ouml;netmenlik yerini giderek artan bir tempoyla yazarlığa bıraktı. &Ccedil;ok okudu ve Dostoyevski&rsquo;yi en g&ouml;zde yazarı olarak g&ouml;sterdi. Kazan en &ccedil;ok tanınan yapıtlarından biri olan ve aynı adı taşıyan filmine kaynaklık eden America, America ile yazarlığını da kabul ettirmekte gecikmedi. Hollywood &uuml;zerine olan ilk ve son filmi olan&nbsp;<b><i>The Last Tycoon</i></b>&nbsp;(1976) ile y&ouml;netmenlik yaşamına son noktayı koydu ve t&uuml;mden yazarlığa y&ouml;neldi. Oyuncu olarak yeraldığı son film,&nbsp;<b>Z&uuml;lf&uuml; Livaneli</b>&rsquo;nin y&ouml;nettiği&nbsp;<b><i>Sis&nbsp;</i></b>(1988) oldu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Elia Kazan</b>&nbsp;i&ccedil;in son s&ouml;zler neler olmalı? Hangi&nbsp; y&ouml;n&uuml;n&uuml; ele alsanız dengesini bulamamış bir kişilikle karşılaştığınız bu y&ouml;netmen i&ccedil;in ne demeli? Aklı Anadolu&rsquo;da kalmış bir Amerikalı... Kaygılarından doğan pısırıklığını, a&ccedil;ıks&ouml;zl&uuml;l&uuml;ğ&uuml; ve saldırgan ihtirasıyla alt etmeye &ccedil;abaladı. Kendini hi&ccedil;bir yerin adamı olamama durumuna sokan k&ouml;ks&uuml;zl&uuml;ğ&uuml;, onu sonu gelmeyen arayışlara itti. Yalnızlık duygusu &ccedil;ıkar hırsını kabarttı. Yaşamı bir zevk d&uuml;nyası olarak g&ouml;rmesi sınırsız h&uuml;zn&uuml;n&uuml; dizginleyemedi. İ&ccedil;e kapanıklığı, dış d&uuml;nyada olanaksızlıklarla savaşmasını ve b&uuml;y&uuml;k oynamasını engellemedi. Anlaşılmazdı ama anlaşılması konusundaki en b&uuml;y&uuml;k engel, taşıdığı ve ka&ccedil; tane olduğu bilinmez karakter sayısıydı. Politik a&ccedil;ıdan yerden yere vurulan karakter bozukluğunun, bazı durumlarda yaratıcılığın kaynağı olduğunun canlı kanıtıydı. &Ccedil;ocukluğu ve gen&ccedil;liğindeki dışlanmışlık, yaşamdan &ouml;&ccedil; alırcasına başarılı olmasını sağlayan itici bir g&uuml;&ccedil;t&uuml;. O, kendini başarmaya zorunlu kılmıştı. Kadınlar onun başarma g&uuml;c&uuml;n&uuml; sınadığı bir alandı. İlişkilerine bağlı kalmayı beceremedi ama bunun, ilişkilerinin uzun s&uuml;reli olmasının tek nedeni olduğunu s&ouml;yleyerek sorunu kendince &ccedil;&ouml;zm&uuml;şt&uuml;. Ailesini, eşlerini ve Steinbeck veya Strasberg gibi dostlarını yitirmesinin ardından, &ouml;l&uuml;mleri trajedik ayrılıklar olarak g&ouml;r&uuml;yordu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Onun sinemasını zengin kılan unsurlar g&ouml;rkemli anlatı tekniği ile karakterleri derinlikli işlemesi ve oyuncu y&ouml;netme becerisiydi. &Uuml;retkenliği, hırsı, fırsat&ccedil;ılığı, &ouml;fkesi, yeteneği ve kişilik bozukluğunun yaratıcılığını tetiklemesi sayesinde hızla y&uuml;kselmişti. 28 Eyl&uuml;l 2003 g&uuml;n&uuml; &ouml;len Kazan, Anadolu ruhunu &uuml;st&uuml;nden t&uuml;mden atamadığı gibi, Amerikan r&uuml;yasını iliklerine kadar yaşadığı halde, kendini bir yabancı gibi hissetmenin huzursuzluğunu asla aşamamıştı.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (70, 'ay-j191', 'luis-bunuel-1900-83', 'Luis Bunuel: 1900-83', 'Kinorama 4, 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 4, 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Dan Yakir</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;"><b>&Ccedil;eviren: Cem Kayalıgil</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Luis Bunuel</b>&nbsp;bir İspanyol deyişinde s&ouml;ylendiği gibi &ldquo;y&uuml;zyılla beraber yaşlandı&rdquo;; &ouml;yle ki, 1900&rsquo;de doğdu ve 83&rsquo;&uuml;nde, Temmuz ayında &ouml;ld&uuml;. 1972&rsquo;de&nbsp;<b><i>Burjuvazinin Gizli &Ccedil;ekiciliği</i></b>&nbsp;i&ccedil;in Oscar almasının &ouml;ncesinde Bunuel &ouml;d&uuml;l&uuml; kazanacağını tahmin edip şerefi i&ccedil;in 25,000 Dolar verdiğini s&ouml;yleyerek film d&uuml;nyasını sarsmıştı. Daha sonra da kendinden emin bir tavırla &ldquo;Amerikalılar&rsquo;ın d&uuml;r&uuml;st işadamları olduğunu size s&ouml;ylemiştim,&rdquo; a&ccedil;ıklamasında bulunmuştu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bunuel&nbsp;</b>hayalg&uuml;c&uuml;n&uuml;n katıksız masumiyeti adına psikolojik &ccedil;&ouml;z&uuml;mlemelerden ka&ccedil;ınıyor ve&nbsp; kendi ahlaki duruş noktası da onun o &ccedil;ok iyi bilinen ateizminde şiddetini g&ouml;steriyordu. 1981&rsquo;de Cannes Şenliği&rsquo;nde onur &ouml;d&uuml;l&uuml; almasının &uuml;zerine, &ccedil;ok sevdiği ve sıklıkla beraber &ccedil;alıştığı&nbsp;<b>Jean-Claude Carriere</b>&rsquo;in&nbsp;<b><i>Le Matin</i></b>&rsquo;de yazdığı gibi: &ldquo;O, orta&ccedil;ağı bilen yegane film yapımcısı. . . ve hala da İspanya kırsalındaki o hayali ve sakin &ccedil;ocukluk d&ouml;nemine karşı nostaljik biri. &lsquo;O vakitler kişinin i&ccedil;sel bir yaşamı da olurdu,&rsquo; der&nbsp;<b>Bunuel</b>.&rdquo;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Son on yılını, yaptığı her filminin en sonuncusu olduğunu s&ouml;yleyerek ge&ccedil;irmişti.&nbsp;<b><i>Arzunun O Belirsiz Nesnesi&nbsp;</i></b>(1977)&rsquo;nin ardından&nbsp;<b>Carriere</b>&rsquo;nin &ldquo;bir m&uuml;nzevinin bakış a&ccedil;ısından kendi &ccedil;ağı&rdquo; şeklinde tarif ettiği bir film yapmayı planlıyordu. Hi&ccedil;bir zaman yapamadı. Sinema tutkunları &ndash;Meksika, Fransa ve İspanya&rsquo;daki- &uuml;&ccedil; d&ouml;neminde &ccedil;ıkardığı işle teselli bulmak durumunda kalıp, Hollywood&rsquo;un bir d&ouml;rd&uuml;nc&uuml;s&uuml;n&uuml; ona tanımayışına i&ccedil;leniyorlardı. 1981&rsquo;de Fransız&nbsp;<i>France Soir Magazine</i>&nbsp;ile yaptığı bir s&ouml;yleşisinde&nbsp;<b>Bunuel</b>, MGM&rsquo;in&nbsp;<b><i>Altın &Ccedil;ağı</i></b><i>&rsquo;</i>nın başarısı &uuml;zerine kendisini Hollywood&rsquo;a &ccedil;ağırmasıyla&nbsp;<b>Greta Garbo</b>&rsquo;nun kendi sahnesine hazırlandığı bir sete katılışını anımsamıştı. &ldquo;Beni g&ouml;rd&uuml;,&rdquo; demişti&nbsp;<b>Bunuel</b>, &ldquo;a.d.&rsquo;yi &ccedil;ağırdı; a.d. de yanıma gelip kolumdan tuttuğu gibi beni dışarı attı! Bir daha da geri d&ouml;nmek istemedim. Hollywood&rsquo;daki &ccedil;ıraklığım b&ouml;yle olmuştur.&rdquo;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bunuel</b>&rsquo;in &ccedil;ok tuttuğu oyuncuları da olmuştu:&nbsp;<b>Michel Piccoli</b>,&nbsp;<b>Julien Bertheau</b>,&nbsp;<b>Delphine Seyrig</b>&nbsp;ve&nbsp;<b>Jeanne Moreau</b>. İspanya&rsquo;dayken ise, kimi filmlerinde &ccedil;oğunlukla y&ouml;netmenin alter-egosu olarak g&ouml;z&uuml;ken&nbsp;<b>Fernando Rey</b>&rsquo;i değil de&nbsp;<b>Francisco Rabal</b>&rsquo;ı anmıştır. Aşağıda, beraber &ccedil;alıştığı bazı insanların&nbsp;<b>Bunuel</b>&rsquo;le olan hatıralarını bulacaksınız:</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>CATHERINE DENEUVE</b>:&nbsp;<b>Bunuel</b>&nbsp;&ccedil;ok konuşmayı sevmezdi. Bu onu bedenen yorardı. Fakat aramızda sessiz bir uyum vardı.&nbsp;<b><i>Tristana</i></b>&rsquo;nın &ccedil;ekimi&nbsp;<b><i>G&uuml;nd&uuml;z G&uuml;zeli</i></b>&rsquo;ninkinden daha iyi ge&ccedil;mişti, &ccedil;&uuml;nk&uuml; onda daha tatlı bir yapımcı vardı, ama asıl sebep&nbsp;<b>Bunuel</b>&rsquo;in&nbsp;<b><i>Viridiana</i></b>&rsquo;dan beri ilk kez İspanya&rsquo;da &ccedil;ekim yapıyor olmaktan &ouml;t&uuml;r&uuml; duyduğu mutluluktu.&nbsp;<b>Bunuel</b>&nbsp;hazcı biriydi. Şahane bir espri anlayışı vardı. Vurguladığı bir şey, &ldquo;Her şey bir yana, psikoloji istemem!&rdquo; idi. Bunu o s&ouml;ylediği i&ccedil;in de i&ccedil;tenlikle benimsedim. &nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>JEANNE MOREAU</b>: Onu İspanyol babam olarak kabul ettim ve ona da b&ouml;yle hitap ettim. Onunla tamamen box-office kaygıları y&uuml;z&uuml;nden tanıştık:&nbsp;<b><i>Bir Oda Hizmet&ccedil;isinin G&uuml;nl&uuml;ğ&uuml;&nbsp;</i></b>i&ccedil;in hangi aktristi se&ccedil;eceğini bilememiş, yapımcılar da beni &ouml;nermişti. St.Tropez&rsquo;deki bir dairede &ouml;ğle yemeği i&ccedil;in buluştuk ve birbirimizden o denli keyif aldık ki akşam yemeğini de beraber yedik. Muhteşem bir insandı. Tanıdıklarım i&ccedil;erisinde hi&ccedil;bir sahneyi &ccedil;&ouml;pe atmayan tek y&ouml;netmendi. Filmi ezbere bilirdi. &ldquo;Kamera&rdquo; ve &ldquo;kes&rdquo; dediğinde, ikisi arasında ne olmuşsa aynen korunacağını bilirdiniz. En &ccedil;ok hareketlerimin &uuml;zerinde dururdu. Karakterim &uuml;zerine pek konuşmazdık. Ama, hayatta da olduğu gibi, bazen başka bir şey hakkında konuşarak kendini daha iyi ifade eder, daha &ccedil;ok şey s&ouml;ylemiş olursun.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>FRANCO NERO</b>: Bunuel bana hep en iyisinin, seyirciye her şeyi g&ouml;stermeden onun hayal g&uuml;c&uuml;n&uuml; tetiklemek olduğunu s&ouml;ylerdi.&nbsp;<b><i>Tristana</i></b>&rsquo;da&nbsp;<b>Catherine Deneuve</b>&rsquo;&uuml;n &ccedil;ıplak olarak pencerede durup, meydandan onu biraz olsun g&ouml;rmeye &ccedil;alışan oğlana baktığı bir sahne vardı. Kamera onun y&uuml;z&uuml;ne sabitleniyordu. Seksiydi, ama hi&ccedil; a&ccedil;ık vermiyordu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">B&uuml;t&uuml;n dehaların &ccedil;ocuk gibi olduğunu d&uuml;ş&uuml;n&uuml;r&uuml;m. İtalyan şair&nbsp;<b>Giovanni Pascoli</b>&nbsp;ş&ouml;yle der: &ldquo;Her kişide bir &ccedil;ocuğun ruhu gizlidir &ndash; ruh onu terk ettiğinde o da yok olur.&rdquo; Bir sabah&nbsp;<b>Bunuel</b>&nbsp;sete gelmiş, &ccedil;antasını bulamamıştı. B&uuml;t&uuml;n ekip onu arıyor,&nbsp;<b>Bunuel</b>&nbsp;de o bulunmadan &ccedil;ekimi başlatmıyordu. &Ccedil;ocuk gibi &ldquo;&Ccedil;antam! &Ccedil;antam!&rdquo; diye feryat edip duruyordu. Sonunda &ccedil;anta bulundu, o da onu kaptığı gibi bir k&ouml;şeye ka&ccedil;ıp siniverdi. Takip ettim ve bir de baktım ki &ccedil;antasından jambonlu bir sandvi&ccedil; &ccedil;ıkarmış onu yiyor. Acıkmış yani. Beni g&ouml;r&uuml;nce yerinden sı&ccedil;radı, &ldquo;Ne yapıyorsun?&rdquo; dedi. &ldquo;Kimseye s&ouml;yleme l&uuml;tfen. Acıktım... Beni g&ouml;r&uuml;rlerse k&ouml;t&uuml; &ouml;rnek olurum, herkes yemek ister &ccedil;&uuml;nk&uuml;. Ama ben a&ccedil;ım...&rdquo; Başka bir g&uuml;n de &ndash;sağır olduğunu s&ouml;ylerdi ama kuşkuluyum- dilsiz bir adamı &ccedil;evirip &ldquo;Sen dilsiz misin? Ben de sağırım!&rdquo; demiş, yarım saat boyunca buna g&uuml;l&uuml;p durmuştu.&nbsp;&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>BULLE OGIER</b>: Oyuncular y&ouml;netmenin fikirlerini aktaran ara&ccedil;lardır &ndash; ondan &ouml;t&uuml;r&uuml; de ben b&uuml;t&uuml;n rollerimi zor bulmuşumdur. Zira y&ouml;netmene ihanet edemem. Oysa&nbsp;<b><i>Burjuvazinin Gizli &Ccedil;ekiciliği</i></b>&rsquo;nde yapacağım &ccedil;ok bir iş yoktu.&nbsp;<b>Bunuel&nbsp;</b>oyuncularını insan olarak sever, onlara iyi davranırdı; ama oyuncular olarak onlara karşı tamamen kayıtsızdı &ndash; kim neyi oynamış, ben kimmişim... Onun i&ccedil;in &ouml;nemli olan filmin senaryoyu yansıtmasıydı, &ccedil;&uuml;nk&uuml; her zaman bir yazar olmayı istemişti. Yazdığını birebir uygulamak zorundaydınız. Ondan hi&ccedil;bir şekilde ayrılamazdınız.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>MICHEL PICCOLI</b>: Psikolojik a&ccedil;ıklamalar yapmayı veya şevkinizi tartışmayı hi&ccedil; sevmezdi. &Ccedil;ok kibar ve sevimli birisiydi; insanlara karşı &ccedil;ok duyarlıydı ve şahane bir espri anlayışı vardı. Bir de m&uuml;thiş bir g&ouml;zlem g&uuml;c&uuml;. Bir hata veya nahoş bir espri yaptığınızda ya da birini incittiğinizde sizi derhal yargılardı. Onun dışında &ccedil;ok şekerdi &ndash; tabii o muazzam otoritesine eşlik eden durgunluğuyla. Oyuncularına karşı &ccedil;ok nazik davranır, incelikle tavsiyelerde bulunurdu ve onlar da onun haklı olduğunu bilirlerdi. İşi hakkında hi&ccedil;bir kararsızlığa kapılmadığını bilirlerdi, en k&uuml;&ccedil;&uuml;k bir kuşkuya bile.&nbsp;<b><i>G&uuml;nd&uuml;z G&uuml;zeli</i></b>&rsquo;nin bir sahnesinde&nbsp;<b>Georges Marchal&nbsp;</b>yakın planda merdivenlerden aşağı inerken onun da mast&uuml;rbasyon yaptığını d&uuml;ş&uuml;nebilirdiniz. Kolay değildi.&nbsp;<b>Bunuel</b>&nbsp;ona &ldquo;Batan g&uuml;neşi d&uuml;ş&uuml;n,&rdquo; demişti. Muhteşem bir şeydi: Başka hi&ccedil;bir a&ccedil;ıklama yapmazken &ndash;yalnız aşağı inmesini s&ouml;ylemişti- oyuncusuna onu bir g&uuml;neş gibi hayal ettiğini de s&ouml;yl&uuml;yordu. Hayata karşı haşindi ve &ccedil;ok zor hoşnut olurdu. Doğuştan ger&ccedil;ek bir İspanyol burjuvasıydı ve &ccedil;ok disiplinliydi. B&uuml;t&ccedil;eyi aşmadan &ccedil;alışmakta epey başarılıydı, &ccedil;&uuml;nk&uuml; gen&ccedil;liğinde, &ouml;zellikle ABD&rsquo;deyken parasal g&uuml;&ccedil;l&uuml;kler &ccedil;ekmişti. M&uuml;tevazi bir yaşam s&uuml;rerdi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">M&uuml;thiş eğlenirdik. &Ccedil;ocuk gibi şakalaşır, habire aynı esprileri yapardı. &Ccedil;ok gerekli bir durum olmadık&ccedil;a asla mektup yazmazdı. Her defasında &ldquo;B&uuml;t&uuml;n kabalığımla,&rdquo; diyerek imzalardı. Ben kendi payıma onunla, onu yaratanın&nbsp;<b>Catherine Deneuve</b>&rsquo;le ben olduğumuzu s&ouml;yleyerek dalgamı ge&ccedil;erdim.&nbsp;Biz<b>&nbsp;<i>G&uuml;nd&uuml;z G&uuml;zeli</i></b>&rsquo;ni &ccedil;ekene dek yıllarca filmlerini entellekt&uuml;eller hari&ccedil; kimse g&ouml;rmemiştir,&rdquo; derdim. Bayağı neşelenir, onaylar, &ldquo;Haklısın, teşekk&uuml;r ederim,&rdquo; derdi. Her zaman g&uuml;ler ve şakalaşırdık. Kahkahası kederinden doğar ama hi&ccedil; kesilmezdi.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir seferinde Fransız televizyonu onunla İspanya&rsquo;da bir s&ouml;yleşi yapmak i&ccedil;in iki kamyonuyla gelen bir ekip yollamıştı. Onlara &ldquo;B&uuml;t&uuml;n bunları buraya taşımak i&ccedil;in yaptığınız masrafla ben bir film &ccedil;ekerdim,&rdquo; demişti. S&ouml;yleşiyi Toledo&rsquo;da yapmayı tercih edeceğini s&ouml;ylemişti. Orayı &ouml;zellikle mi sevdiğini sorduklarında &ldquo;Yok canım, tiksinirim oradan. Sinek kaynar,&rdquo; diye karşılık vermişti. Ona sonra&nbsp;<i>EL</i>&rsquo;deSade&rsquo;dan mı etkilendiğini sorduklarında, &ldquo;Hayır,&rdquo; diye cevapladı. S&ouml;yleşiyi yapan &ldquo;Filmde adam kadının vajinasını dikiyor,&rdquo; diye ısrar etti.&nbsp;<b>Bunuel&nbsp;</b>ş&ouml;yle bir karşılık verdi: &ldquo;Karın seni aldatınca gider sarhoş olursun. Bense onu sadece dikerim. Bunda da sadist&ccedil;e hi&ccedil;bir yan yok.&rdquo;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Başkalarına h&uuml;rmet ederdi.&nbsp;<b>De Richaux</b>&rsquo;un vefatında onun hakkında konuşmak &uuml;zere radyoya gitmiştim. Ona da b&ouml;yle bir şey yapmayı isteyip istemediğini sorduğumda dedi ki: &ldquo;Hayır. &Ouml;lm&uuml;ş dostlar hakkında asla konuşmam. Ben sadece, senin bir restorana yapacağın gibi, yıldız veririm:&nbsp;<b>Sadoul</b>, 5 yıldız.&nbsp;<b>De Richaux</b>, 4.&rdquo;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>G&uuml;nd&uuml;z G&uuml;zeli</i></b>&rsquo;ni &ccedil;ekerken&nbsp;<i>Lui</i>&nbsp;dergisi i&ccedil;in poz vermiştim ve&nbsp;<b>Bunuel&nbsp;</b>de bunları g&ouml;rd&uuml;, &ldquo;Sen buna oyuncu mu diyorsun? Kukla bu yahu! B&uuml;y&uuml;k oyuncu Piccoli&rsquo;nin yaptığına bak! Felaket bir şey!&rdquo; dedi. Dergiyi katlayıp koltuk altına sıkıştırmış, &ccedil;ekim boyunca da s&uuml;rekli orada tutup habire atıfta bulunmuştu. Severdim onu.</span></p>', 200, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (71, 'ay-j192', 'kent-kultursuzlugunde-sinema', 'Kent Kültürsüzlüğünde Sinema', 'Ankara\'da Kültür ve Sanat &ndash; Nisan-Kasım-Aralık, 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Ankara&rsquo;da K&uuml;lt&uuml;r ve Sanat &ndash; Nisan-Kasım-Aralık, 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><b style="font-size: 13px; text-align: justify;">G&ouml;khan Erkılı&ccedil;</b></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kent k&uuml;lt&uuml;r&uuml;, teknoloji &ccedil;ağının ve toplumsal uzlaşmanın bi&ccedil;imlendirdiği bir k&uuml;lt&uuml;r olarak ele alınır. Bu iki etken, sinema ve kent olgularını birbirine bağlar. Gelişen teknoloji sanatlar arasında sinemaya &ouml;ncelik tanır. Egemen sinema en d&uuml;zeysizinden bir toplumsal uzlaşma yaratmaya can atar. Sinema kitlesel bir iletişim aracı olduğu savunusunu izleme bi&ccedil;imine dayandırır. Sanat&nbsp; kentleşmenin ve teknolojik gelişimin direkt etkilerine a&ccedil;ıktır. Şimdi soruyu sormanın tam sırası: Sinema k&uuml;lt&uuml;rel bir birikim veya yarar sağlar mı? Bu, sinemadan ne anladığınıza bağlı. Bazı filmler yararlanmayı ve &ccedil;&ouml;z&uuml;mlemeyi bilen i&ccedil;in k&uuml;lt&uuml;rel verilerle y&uuml;kl&uuml;d&uuml;r, t&uuml;ketim sinemasının &uuml;r&uuml;nleri olan bazısı da izleyicide olduğu varsayılan k&uuml;lt&uuml;rel altyapıyı kemirir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kent insanı sinema karşısında &ccedil;ift karakterli bir kitle g&ouml;r&uuml;n&uuml;m&uuml;ne b&uuml;r&uuml;n&uuml;r. Bu kitlenin neredeyse tamamına yakınının zamanı &ccedil;ok dolu ve işleri acayip yoğun olduğu i&ccedil;in sanat ve sinemaya boş zaman se&ccedil;eneği olarak bakarlar. Yaşamı boyunca y&uuml;zlerce kez sinemaya gidenler i&ccedil;inde sinemayla hi&ccedil; tanışmamış olanların &ccedil;oğunluğu oluşturduğuna şaşırmamak gerek. Onlar boş zamanlarında film izlerler. Filmler eğlence k&uuml;lt&uuml;r&uuml;n&uuml;n bir par&ccedil;ası olarak soytarılık g&ouml;revlerini yerine getirebilirler ama... Sinema boş zaman kavramının tercihi olmayı sevmez.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kent k&uuml;lt&uuml;r&uuml;n&uuml;n, adına sanat sineması dediğimiz kavramın peşinde koşan, g&ouml;rece daha bilin&ccedil;li ve k&uuml;lt&uuml;rl&uuml; olanları da etkilediği bir ger&ccedil;ek. Kentli kimliklerimiz i&ccedil;in sanat filmleri, festivaller, film haftaları, toplu g&ouml;steriler, en iyiler ve se&ccedil;kiler ne anlama gelir? İzleyici profili &uuml;zerine ger&ccedil;ekleştirilen anketlerin sonu&ccedil;ları bu soruya yanıt vermek konusunda bize yorum yapma olanağı tanıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bilin&ccedil;li ve k&uuml;lt&uuml;rl&uuml; nitelemelerini yakıştırdığımız izleyici kitlesine yakından bakacak olursak, &ccedil;ok değişken bir karaktere sahip olduğunu g&ouml;r&uuml;r&uuml;z. Bu, kitle i&ccedil;inde bulunma nedenlerini de bir hayli &ccedil;eşitlendirir. En &ccedil;abuk y&uuml;z y&uuml;ze gelebilecekleriniz sosyalleşme arayışlarına sinema salonlarında &ccedil;are arayanlardır. Kendilerini hemen herkesi tanımaya zorlarlar. Karşı kıyıda kalanlara umursamaz davranırlar. Dayanaksız eleştirel s&ouml;ylemleri, kısa s&uuml;rede, kişiliklerinin doğal bir &ccedil;ıkıntısı haline gelir. Varolmayan bir elitizmin ilk aksırıklarıdır bunlar. Yakın zamanda onlardan biri olabileceklerinin kokusunu erken aldıklarından sinemanın sahte otoritelerine &ccedil;abuk teslim olurlar. &Ccedil;elişki, sinema k&uuml;lt&uuml;r&uuml;n&uuml; edinme ve sinemasal &uuml;retim bi&ccedil;iminin bireysel bir &ccedil;abayı gerektirmesinden doğar. Kentli olmakla sinema k&uuml;lt&uuml;r&uuml;ne sahip olmanın aynı sancılı yol &uuml;zerinde y&uuml;r&uuml;mek anlamına geldiğini kavrama anı, sosyal ilişkiler tarihinde zor g&ouml;r&uuml;l&uuml;r bir d&ouml;n&uuml;m noktasıdır. Varsın olsun, dostlar bizi festivallerde ve elitist salonlarda g&ouml;redursun da denilebilir. Sosyalleşmecilik oyununda bunun da zaferler kazanmaya yeterli olduğu test edilip onaylanmıştır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kent k&uuml;lt&uuml;r&uuml;nde sinema yolculuğumuzun bir başka durağı cinsellik! K&uuml;lt&uuml;r&ndash;sanat ortamları, cinsel arayışlara &ccedil;anak tuttukları, her t&uuml;rden cinsel kimliği kolay benimsedikleri ve yargılamadıkları inancıyla yanıltıcı bir albeniye sahiptir. Sinema ortamlarının, cinsel aktiviteler i&ccedil;in bol kep&ccedil;eden fırsatlar sunduğu y&ouml;n&uuml;ndeki t&uuml;mden yanlış olmayan bu &ouml;nyargı, sekt&ouml;r&uuml; aklı orasındakilerin uğrak yeri haline getirir. Cinselliğin sinemanın beslendiği ana kaynaklardan biri olması, d&uuml;şlerini ger&ccedil;ekleştirmeyi dileyenlerin iştahını kabartır. Bu durumda, sinema sanatının cinsellik karşısında şansı olduğunu d&uuml;ş&uuml;nmek de sinemasal bir masaldır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir de sekt&ouml;rel &ccedil;ıkarların sinemaya ittiği pazarlamacılar vardır. Doktor, avukat ve &ouml;ğretmenlerin adı &ccedil;ıkmıştır ama her meslek grubunda sinema ortamlarında bulunmayı g&ouml;rev bilen, ortaklaşmacı grup psikolojisini yaşatmayı hedefleyen ve bu doğrultuda en entel alan olarak sinemayı g&ouml;zlerine kestirenler vardır. Filmler mezedir, iş randevuları antraktlara verilir ve sinema &ccedil;ıkışlarında filmsel sohbetlerle tatlandırılan derin iş analizleri yapılır. &Ouml;te yandan, stresini boşaltacak yer arayanların soluğu sinemada aldığı garip bir s&uuml;re&ccedil;ten ge&ccedil;iyoruz. Ağlayacağı bir omuz, sinirlerini yıpratacağı bir dost, eğleneceği bir arkadaş, yolacağı bir kaz, k&uuml;f&uuml;r edeceği bir y&ouml;netmen/oyuncu, kaprislerini boşaltacağı bir salon g&ouml;revlisi veya hayatın y&uuml;k&uuml;n&uuml; paylaşacağı birilerini arayanlar i&ccedil;in sinema tam bir şenliktir!&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ouml;ğrenme arayışındakiler ise seyircinin y&uuml;zakıdır. Genelde vitrine &ccedil;ıkmazlar. Sinemayı bir uzmanlık alanı olarak g&ouml;r&uuml;p, &ouml;ğrendikleriyle yetinmezler. Kent k&uuml;lt&uuml;rs&uuml;zl&uuml;ğ&uuml;ne k&uuml;lt&uuml;r kazandırmak konusunda kendilerini yalnız hissetmelerinin sıkıntısı y&uuml;zlerinden okunur. Sinemayı sevgi d&uuml;zeyinde yaşamayı aşarak &uuml;retim d&uuml;zeyinde yaşatırlar. İ&ccedil;lerinden kimilerinin tek sorunu &uuml;rettiklerini dev aynasında g&ouml;rmeleridir. Zamanla ya doğal sınırlarına &ccedil;ekilirler ya da k&ouml;y&uuml;n Fellini&rsquo;si olarak ortalıkta dolaşırlar. Sanatsal arayışların sinemaya &ccedil;ektiği kitleye gelince: İ&ccedil;lerinde sinemayla geliştirdikleri ilişki sayesinde k&uuml;lt&uuml;rel donanımını daha da g&uuml;&ccedil;lendirenler bulunduğu gibi, sinemada da dikiş tutturamayınca arayışlarını bir kenara bırakan ve o &ccedil;ok değerli sanatsal anılarını aktaracağı k&ouml;şesine &ccedil;ekilebilmek i&ccedil;in bir an &ouml;nce gongun &ccedil;almasını bekleyenler vardır.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kimileri i&ccedil;in de prestij &ouml;nemlidir. Sinema &ccedil;evresine kapıdan olmazsa bacadan girip bunu sağlayabileceğini d&uuml;ş&uuml;nenlerin sayısı hi&ccedil; de az değildir. Prestijin bira bardaklarının i&ccedil;ine d&uuml;şerek, seyredilen filmler &uuml;zerine aykırı laforizmalar yumurtlayarak ya da pek m&uuml;him festival salonlarında &ccedil;alım satarak sağlanamadığını anladıklarında, sıra sudan &ccedil;ıkmış balık rol&uuml;n&uuml; oynamalarına gelir. Bu noktada self-test i&ccedil;in sinemaya balıklama dalanları da unutmamak gerek. Deneme yanılma y&ouml;ntemiyle yol alırlar ve bir g&uuml;n karşılarına &ccedil;ıkan ne yazık ki sinema olur. Onu da dener ve becerirler! Tanrı sinemayı -serseri mayından farksız olan bu deneycilerden- korusun!</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Varsayalım ki -kimileri size dokunsa bile- b&uuml;t&uuml;n bunlara katıldınız. G&uuml;zel ama ne yapmalı? Yazımızın eleştirel dozajının y&uuml;ksekliğinin ardında 80 yıllık bir beceriksizliğin sancıları uzanıyor. &Ouml;zel veya devlet ayrımı olmaksızın sekt&ouml;rel, bireysel, kuramsal ve kurumsal yoksulluğu en derininden yaşayan sinemamız i&ccedil;in ne yapmalı, nasıl bir yol izlemeli? İş, &ouml;ncelikle sinemanın bir sekt&ouml;r, kurum, sanat ve bilim alanı olduğu ger&ccedil;eğini g&ouml;renlere d&uuml;ş&uuml;yor. Burası &ccedil;ok &ouml;nemli, &ccedil;&uuml;nk&uuml; ge&ccedil;mişi yaşatanların ve onların kuyruklarının ayıklanması s&uuml;recinde dikkatli ve d&uuml;r&uuml;st olmak gerekiyor. S&ouml;z&uuml;n &ouml;z&uuml;, k&uuml;lt&uuml;rs&uuml;zl&uuml;ğ&uuml;n kendi akış s&uuml;recinde k&uuml;lt&uuml;r&uuml; yaratacağını beklemek bir masal. Kent k&uuml;lt&uuml;r&uuml; ancak k&uuml;lt&uuml;rs&uuml;zl&uuml;ğe tepkinin bir sonucu olarak, bir karşı-s&ouml;ylem olarak doğabilir. Bu noktada, sinemanın her y&ouml;n&uuml;yle kent k&uuml;lt&uuml;r&uuml;nce bi&ccedil;imlenen ve ona bi&ccedil;im veren bir olgu olduğunu yeniden anımsatalım. Ve sinemanın kent k&uuml;lt&uuml;r&uuml;n&uuml;n ana motiflerinden biri olması adına atılması gerekli adımlar konusundaki d&uuml;ş&uuml;ncelerimize kısa kısa değinelim.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ouml;ncelikli olarak sinema k&uuml;lt&uuml;r&uuml;n&uuml;n yaygınlaşması, eğitimli ve bilgisini &uuml;retime aktarabilen kuşakların yetiştirilmesi, sinema yayıncılığının gelişmesi, izleyen s&uuml;re&ccedil;te de programlarının bilin&ccedil;lice oluşturulduğu festival ve film haftalarının d&uuml;zenlenmesi i&ccedil;in dernek, vakıf ve sinema kurumlarının g&uuml;&ccedil;lenmesi gerekli. &Ouml;zg&uuml;nl&uuml;klerini yitirmeden ger&ccedil;ekleştirebilecekleri bir birleşmenin sağlayacağı avantajlar ve ortak y&ouml;netim d&uuml;ş&uuml;ncesi de kulağa hoş geliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sinemanın kaleleri olan sinematekler, t&uuml;m d&uuml;nyada olduğu gibi yıllar sonra yeniden g&uuml;ndemimize giriyor. Programlama a&ccedil;ısından en sorunlu kurumlar olarak g&ouml;r&uuml;len sinematekler, programlarını oluştururken film se&ccedil;icilerin bilgi d&uuml;zeyini, tanıtım olanaklarını ve izleyici kitlesinin k&uuml;lt&uuml;r d&uuml;zeyini dikkate almalı. Dolgu filmler ideal bir sinematek izleyicisinin beklentilerini karşılamaya yetmiyor. Geniş d&uuml;ş&uuml;nmek, zor ulaşılana ulaşmak ve eski-yeni, klasik-modern yapıtlarla kitlenin beğeni ve bilgi d&uuml;zeyini yukarılara &ccedil;ekmek gerekiyor. Sinematek b&uuml;y&uuml;k oynamayı ve d&uuml;ş&uuml;nmeyi ister. Sinemanın kalesi olan &uuml;lkelere baktığınızda, kent k&uuml;lt&uuml;r&uuml;n&uuml; oluşturan en &ouml;nemli kurumlar arasında sinematekleri g&ouml;r&uuml;rs&uuml;n&uuml;z.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Adını, a&ccedil;ıkladığı programı yıl boyu g&ouml;sterimde tutmasından alan program sinemaları ise bir başka &ouml;nerim. T&uuml;m&uuml;yle kentlere &ouml;zg&uuml;ler. Daha &ccedil;ok ekonomik sorunlarını aşmış ve b&uuml;y&uuml;cek bir bilin&ccedil;li seyirci sayısına ulaşmış &uuml;lkelerde g&ouml;r&uuml;len bu tip merkezler i&ccedil;in sponsor veya devlet desteği ka&ccedil;ınılmaz. K&uuml;lt&uuml;r Bakanlığını veya belediyeleri bu işe y&ouml;nlendirmek gerekiyor. Ağırlıklı olarak klasik sinema &ouml;rneklerini g&ouml;sterdikleri i&ccedil;in yararları tek bir noktada toplansa bile, geleceğin kent k&uuml;lt&uuml;r&uuml;n&uuml;n gerektirdiği altyapıya sahip seyircisini oluşturmak i&ccedil;in varlıkları ka&ccedil;ınılmaz g&ouml;r&uuml;n&uuml;yor.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İşletmecilik a&ccedil;ısından bakıldığında, sinemadan en &uuml;st d&uuml;zeyde yararlanmanın koşulu, herkese sinemanın salt bir eğlence ve boş zaman aracı olmadığını &ouml;ğretmekten ge&ccedil;iyor. Burada s&ouml;ylendiği kadar kolay bir iş değil bu. Bunun i&ccedil;in, sevgili vatanımın beyin k&ouml;rl&uuml;ğ&uuml;n&uuml; aşması gerekiyor. İşte, sinemanın &ouml;n&uuml;ndeki ekonomik engeller tam da bu nedenle kaldırılmalı. Sinema bir g&ouml;rme işi ve bizim g&ouml;rme kusurumuzu aşabilmemiz i&ccedil;in &uuml;retim, dağıtım ve izleme koşullarının iyileştirilmesi gerekiyor. K&uuml;lt&uuml;r&uuml;n kente yayılması buna dayanıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sinemanın politikacısından araştırmacısına, &ouml;ğretmeninden sanat&ccedil;ısına geniş bir ilgili kitlesi olagelmiştir. Onun bir bilgi, iletişim ve k&uuml;lt&uuml;r taşıyıcısı olarak da kullanılırlığının ayırdına varılması, kullananın ama&ccedil;ları doğrultusunda rol oynamasına neden olduğundan yararlı da olabilir zararlı da. Ancak bu bilin&ccedil;, kitle yararı doğrultusunda kullanıldığında, sinemanın kentli insanın g&uuml;ndelik yaşam pratiğine sağlayacağı katkılar olacaktır ki bu da sinemanın kitleler tarafından yeniden benimsenmesinin nedeni olabilir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Gelelim sinema yayıncılığına... Sinemanın kent k&uuml;lt&uuml;r&uuml;ne vereceği desteğin salt seyirle sağlanamayacağı &ccedil;ok a&ccedil;ık. Bu desteğin d&uuml;zenli,bilin&ccedil;li ve s&uuml;rekli olmasının koşullarından biri de sinema yayınlarının sayısının artması ve dağıtım alanının genişlemesi. B&uuml;ltenler, dergiler, gazeteler, kitaplar, cdler ve internet ortamı bu hedef uğrunda kullanılmayı bekliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Son &ouml;nerimiz doğrudan sinema adına olmayan, diğer sanat dallarına da eğitim, &uuml;retim ve sunum şansı tanıyan bir &ouml;neri. Kentlerin mutlaka sahip olması gereken kamusal alanlardan biri de, sanat &uuml;retimi yapan sivil kurumların yerleşimine, kullanımına ve &uuml;retimine a&ccedil;ık k&uuml;lt&uuml;r merkezlerinin kurulmasıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Kent k&uuml;lt&uuml;r&uuml;, kendisi &uuml;zerine konuşulmayı, tartışılmayı, sahiplenilmeyi ve s&uuml;rekli yeniden &uuml;retilmeyi sever. Ve sinema, kent k&uuml;lt&uuml;r&uuml;n&uuml;n bu gereksinmelerini karşılayabilecek g&uuml;&ccedil;te bir birikime ve yaratıcılığa sahiptir. Halk, pop&uuml;ler, kitle, entelekt&uuml;el; k&uuml;lt&uuml;r kavramını bunların hangisiyle eşlerse eşleyin, sonu&ccedil; değişmez: Sinemasız bir kent k&uuml;lt&uuml;r&uuml; d&uuml;ş&uuml;n&uuml;lemez. Kentin k&uuml;lt&uuml;rs&uuml;zl&uuml;ğ&uuml; sinemanın olanaklarının yerli yerinde kullanılmadığının a&ccedil;ık bir kanıtıdır.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (72, 'ay-j193', 'soylesi-sachi-hamano', 'Söyleşi: Sachi Hamano', 'Kinorama 3, 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 3, 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Civan &Ouml;zcivanoğlu</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;"><i>6. Uluslararası Kadın Filmleri Festivali kapsamında Japon kadın y&ouml;netmen Sachi Hamano&rsquo;nun Zambak Festivali adlı filmi de yer aldı. Festival konuğu olarak Ankara&rsquo;ya gelen y&ouml;netmenin katılımıyla ger&ccedil;ekleşen film g&ouml;steriminin ertesinde yapmış olduğumuz s&ouml;yleşiyi sunuyoruz. &Ouml;nce filme dair k&uuml;&ccedil;&uuml;k bir &ouml;zet sunalım; Yaşları 69-90 yaşları arasında değişen bir grup yaşlı kadının oturduğu apartmana 70 li yaşlarını s&uuml;ren ve kadın ruhundan olduk&ccedil;a iyi anlayan bir adam taşınır. Kibar ve olgun bir erkeğin aralarına katılmasıyla yaşlı hanımların yaşamları, sihirli bir değnek dokunmuşcasına değişecektir. O, &ccedil;oktan unutulmaya y&uuml;z tutmuş tutkular, aşk duygusu ve tabii cinselliğin &uuml;zerindeki k&uuml;ller savrulacaktır d&ouml;rtbir yana..</i></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Filminizi izledikten sonra, bizim toplumumuzda yaşlı hanımların cinselliği yaşama olgusu hakkındaki tabular geliyor akla... Filminiz salt konu olarak ele alındığında anlatılanlar bizde de &ouml;yle kolay kolay yenilir yutulur cinsten değil. Hal b&ouml;yleyken filminizde bu radikal &ldquo;&ouml;z&uuml;&rdquo; anlatış bi&ccedil;iminiz ılımlı, espirili bir atmosferden besleniyor. Deyim yerindeyse acı hapı belli etmeden yutturuyorsunuz izleyiciye... Japon k&uuml;lt&uuml;r&uuml; penceresinden bakıldığında&nbsp; b&ouml;ylesi &ldquo;&ouml;z-bi&ccedil;im&rdquo; ilişkisini, anlatılmak isteneni izleyiciyi &uuml;rk&uuml;tmeden vermek i&ccedil;in mi se&ccedil;tiniz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Japon toplumunda da yaşlı insanların cinselliği yaşamasına tamamen bir tabu olarak bakılıyor. Ben, y&ouml;netmen olarak bu tabuya karşı &ccedil;ıkmak istedim ve bu y&uuml;zden de b&ouml;yle bir konu se&ccedil;tim. Bi&ccedil;ime gelince; Anlatmak istediklerimi daha &ccedil;ok seyirciye verebilmek ve bu tabuyu onlara bir daha sorgulatabilmek i&ccedil;in b&ouml;yle bir bi&ccedil;im se&ccedil;tim Japonya&rsquo;da 2. D&uuml;nya Savaşı yıllarında gen&ccedil;liklerini yaşamış, daha &ccedil;ok erkeklere hizmet ederek g&uuml;nlerini ge&ccedil;irmiş ve bu tutumun iyi, doğru olduğuna inanmış, inandırılmış olan bugun&uuml;n yaşlı hanımlarına &ldquo;obacan&rdquo; deniyor. Bu yaşlı hanımlar i&ccedil;in cinsellik tamamen uzak durulması gereken bir olgudur. Yaşlı hanımların cinselliği bir yana, gen&ccedil; olanların da cinselliği yaşamaları ancak &ccedil;ocuk doğurma işlevinin sığ sularında geziniyor. Bana g&ouml;re, cinsellik, kadınların hayatında bir denge unsuru olarak &ccedil;ok &ouml;nemli bir yer tutuyor. Ben de bu cinsellik hakkını vurgulamak ve bunu &ouml;zellikle de erkek izleyicilere iletmek i&ccedil;in b&ouml;yle bir film &ccedil;ekmeye karar verdim. Tabii bu kabul edilmesi g&uuml;&ccedil; olguyu onlara kabul ettirebilmek i&ccedil;in &ldquo;&ouml;z&uuml;&rdquo; saldırgan olmayan, ılımlı ve espirili bir &ldquo;bi&ccedil;im&rdquo;i&ccedil;inde anlatmaya &ccedil;alıştım.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Ulusal Japonya sinemasının bug&uuml;nk&uuml; durumu hakkındaki g&ouml;r&uuml;şlerinizi alabilir miyiz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Ne yazık ki hareketli bir sinemanın varlığından s&ouml;z edemeyeceğim. Japonya&rsquo;da filmler &ouml;zel şirket ve televizyon kanallarıyla ortak bir şekilde &uuml;retiliyor. Tabii bir ortak iş ve gelir-gider dengesi s&ouml;z konusu olduğu i&ccedil;in de para yatırılacak filmin herşeyden &ouml;nce geniş halk kitleleri tarafından sevilmesi &ouml;n planda tutuluyor. B&ouml;ylece, sanat kaygısı geri plana atılmaya ve sinema bir eğlence aracı olarak &uuml;retilmeye ve algılanmaya başlandı.Yatırılan paranın geri gelmesi i&ccedil;in geniş kitleler tarafından benimsenecek konulara &ouml;ncelik veriliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Japonya&rsquo;da filmler daha &ccedil;ok erkek izleyicilerin seveceği şiddet i&ccedil;erikli macera, d&ouml;v&uuml;ş, mafya konularını işliyor. O y&uuml;zden izleyicilerin b&uuml;y&uuml;k bir &ccedil;oğunluğu erkeklerden oluşuyor. Bu filmlerde sunulan kadın suretlerine gelince. Kadın oyuncular, &ouml;ncelikle erkekler tarafından beğeni g&ouml;recekler arasından se&ccedil;iliyor. Yani perdeye yansıyan kadının gen&ccedil; ve g&uuml;zel olması bir şart ve bu kadınların erkek bakış a&ccedil;ısına hizmet edecek şekilde bir &ccedil;ıplaklık ve cinselliği de pazarlaması gerekiyor. O y&uuml;zden Zambak Festivali gibi bu tabloya ters d&uuml;şecek bir filme para yatıracak sponsor bulmaını &ccedil;ok g&uuml;&ccedil; olduğunu belirtmeliyim.&Ccedil;&uuml;nk&uuml; benim oyuncularım gen&ccedil; ve g&uuml;zel değil ve daha da &ouml;tesi edindikleri yeni bir yaşam deneyiminin ardından bir cinsellik hakkı yaşamayı talep ediyor ve sonunda da bunu yaşıyorlar. Bunun geniş halk kitlelerinin istediğiyle yakından uzaktan bir ilişkisi yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Demek ki Japonya&rsquo;da da diğer &uuml;lkelerde olduğu gibi bir Hollywood mantığı egemen ve bu y&ouml;nde bir izleyici de yaratılmış.</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Eskiden sanat filmleri g&ouml;steren ve ticari kaygıların uzağında duran k&uuml;&ccedil;&uuml;k sinema salonları vardı. Ancak giderek bu salonların sayısı ne yazık ki azaldı. Bug&uuml;ne gelindiğinde, artık zeminin Holywood filmleri g&ouml;steren b&uuml;y&uuml;k sinema salonlarına kaldığını s&ouml;ylemek gerek. Şunu da eklemeliyim ki herşeye rağmen k&uuml;&ccedil;&uuml;k de olsa olumlu kıpırdanmalar var. Japonya&rsquo;da K&uuml;lt&uuml;r Bakanlığı&rsquo;nın desteği sayesinde senede on kadar nitelikli filmler &ccedil;ekilebiliyor. Her sene a&ccedil;ılan senaryo yarışmalarında beğenilenler filme &ccedil;ekiliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Olumlu bir durum ancak nitelikli filmlerin yaşamasını s&uuml;rd&uuml;rebilmek i&ccedil;in parasal desteğin yanısıra izleyiciye de yatırım yapmak gerekiyor. Yani iyi sinemayı talep edecek ve ona ivme kazandıracak eğitimli bir seyircinin varlığı b&uuml;y&uuml;k &ouml;nem arz ediyor. İzleyiciyi geliştirmenin yolu sizce nerelerden ge&ccedil;iyor ?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Maalesef Japonya&rsquo;da nitelikli ve eğitimli bir izleyiciden bahsetmek &ccedil;ok zor. Bu durum bu &uuml;lkede yaşayan bir y&ouml;netmen olarak beni &ccedil;ok &uuml;z&uuml;yor. Japonya&rsquo;da sadece seyirci değil yapımcılar da eğitimsiz. Ticari kaygıları arka plana atabilecek sanat dostu yapımcılar bulmak o kadar zor ki..Herşeyden &ouml;nce sinemanın bir k&uuml;lt&uuml;r olarak ele alınması gerekiyor. Eğitim kurumlarına gelince...Japonya&rsquo;da devlet tarafından kurulan ve y&ouml;netilen bir sinema okulu mevcut değil. Bu durumda, sinema okulları ve eğitimi &ouml;zel sekt&ouml;rdeki girişimcilere kalıyor. Bu okullar bana bu olumsuz sinema ortamında bir umut veriyor, &ccedil;&uuml;nk&uuml; bu okullardan mezun olacak gen&ccedil; bir kuşağın yakın gelecekte kaliteyi arttıracağına inanıyorum. Şu an &ccedil;ekilen filmler her ne kadar niteliksiz olsalar da bu okullardan mezun olacakların &ccedil;ekecekleri filmler yeni bir sinema k&uuml;lt&uuml;r&uuml;n&uuml; besleyecekler diye d&uuml;ş&uuml;n&uuml;yorum.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Şunu da eklemeliyim ki teknolojinin ilerlemesi y&ouml;netmenlerin &ouml;n&uuml;nde yeni ve &ouml;zg&uuml;r bir alan a&ccedil;makta. El videosuyla &ccedil;ekilen ve b&uuml;t&ccedil;e gerektirmeyen filmlerin varlığı insanı sevindiriyor. Şu an Japonya&rsquo;da yirmi kadın y&ouml;netmen var ve bunların &ccedil;oğu el videosuyla yapıtlarını veriyorlar.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">El videosu ile &ccedil;ekilen filmlerden oluşan bir film festivali d&uuml;zenlemesi kanımca işe doğru bir yerden başlamak olacak.</span></p>', 201, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (73, 'ay-j194', 'savasin-karsisinda-bir-sinema', 'Savaşın Karşısında Bir Sinema', 'Kılavuz 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">&Ouml;zg&uuml;r d&uuml;nya kavramı, d&uuml;nyayı y&ouml;netme işini yalnız kendilerine has bir yetenek olarak g&ouml;renler i&ccedil;in anlam taşıyor olsa gerek. İşin sırrı y&ouml;nettiğince &ouml;zg&uuml;r, &ouml;zg&uuml;rl&uuml;ğ&uuml;nce y&ouml;netici sayılmanda. ABD&rsquo;nin, kendini, &ccedil;iftliği gibi g&ouml;rd&uuml;ğ&uuml; d&uuml;nyanın g&uuml;&ccedil;l&uuml; ve &ouml;zg&uuml;r y&ouml;neticisi, diğerlerini ise &ccedil;iftliğinin kahyası, atı, sap samanı, &ccedil;iti ve hatta g&uuml;bresi olarak hissedebilmesi i&ccedil;in arada bir hır &ccedil;ıkarıp savaşması gerekmekte. Kaldı ki d&uuml;nyanın yarısından fazlası yukarıda saydıklarımdan biri olabilmek i&ccedil;in &ccedil;ırpınıyor, bazıları da &ccedil;oktan razı ama takıları arttırmak i&ccedil;in naz yapıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Tarih, ABD politikasının savaş alanındaki &ouml;nc&uuml; birliğini Amerikan ordusunun, ardıl birliğini de Hollywood&rsquo;un oluşturduğunu belgeliyor. ABD&nbsp;<b>Kennedy</b>&rsquo;den&nbsp;<b>Bush</b>&rsquo;a kadar, neredeyse 35 yıldır, bir t&uuml;rl&uuml; kurtulamadığı hastalıklı bir ruh hali i&ccedil;inde her yana saldırıyor. Savaş filmlerinin y&uuml;zde doksan kadarı Hollywood yapımı ve zorunlu olarak ordu destekli, dolayısıyla ordu ve savaş olgularına sempatik yaklaşmak gerekir. &Ouml;zellikle 2. B&uuml;y&uuml;k Savaş sırasında, savaşla ilgili haberleri yaymak amacıyla sinemadan yararlanılır. İlk Irak-ABD savaşının tv ekranlarından canlı yayınlanması, kendilerine g&uuml;ndelik yaşamdan ka&ccedil;ış alanı arayan s&uuml;r&uuml;ler ile her akşam masalarda t&uuml;kettikleri engin k&uuml;lt&uuml;rel birikimlerine yeni beyaz sayfalar eklemek isteyen entelleri pek bir mutlu etmişti, anımsayın. Kaldı ki Hollywood&rsquo;da da mutlu sonlar ka&ccedil;ınılmazdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Sivil kurumlar ve &uuml;niversitelerden b&uuml;y&uuml;k destek g&ouml;ren Amerikan ve D&uuml;nya solu 60&rsquo;larda en &ouml;nemli direnişlerinden birini Vietnam&rsquo;a karşı vermiş ve başarılı da olmuştu. ABD&rsquo;nin ardında 60.000 &ouml;l&uuml; ve bir o kadar da kalıcı sakat bırakarak Vietnam&rsquo;ı terketmesinden daha &ouml;nemli olan, yenilmezliğinin artık bir masal olmasıydı. Mutlu son yoksa, b&ouml;lgeye y&ouml;nelik nostaljik, turistik ve ekonomik getiri koşulları yaratılana kadar Vietnam unutulmalıydı. &Ouml;yle de oldu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Oysa, şimdi ge&ccedil;mişe d&ouml;n&uuml;p bakınca, savaş t&uuml;r&uuml;n&uuml; &ouml;nemli kılanın Vietnam olduğu &ccedil;ok a&ccedil;ık.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Hollywood&rsquo;un Vietnam &ccedil;ıkarması &ccedil;ok temkinli ger&ccedil;ekleşti. Yenilgi saplantılı ve yılgın bir ruh hali doğurmuştu. Savaş filmleri i&ccedil;inde Vietnam&rsquo;ın bu denli &ouml;ne &ccedil;ıkması normal karşılanmalı. Vietnam&rsquo;da yenilen Amerikan ordusunu Hollywood&rsquo;da kazandırmak gerekiyordu. İlk adım hen&uuml;z savaş bitmeden atıldı.&nbsp;<b>Yeşil Bereliler</b>&nbsp;(Green Berets,&nbsp;<b>John Wayne-Ray Kellogg</b>, 1968) Vietnam&rsquo;a davet edilen bir gazetecinin g&ouml;z&uuml;nden savaşın haklılığını kanıtlamaya &ccedil;alıştı. Olmadı. Savaş yitirilince kolay lokma olan bireysel dramlar furyası başladı ve mendiller hazır tutuldu. Ortada savaş karşıtı bir s&ouml;ylem olmasa da g&ouml;zler b&ouml;yle g&ouml;rmek, y&uuml;rekler b&ouml;yle hissetmek istiyordu. Orta sınıfın savaşa olan isteksizliğini vurgulayan&nbsp;<b><i>Eve D&ouml;n&uuml;ş</i></b>&nbsp;(Coming Home<b>, Hal Ashby</b>, 1978), aşka boğulmuş bireysel bir Vietnam sonrası dram olarak etkilidir ancak savaştan bihaber g&ouml;z&uuml;k&uuml;r. Vietnam&rsquo;ın Rus k&ouml;kenli azınlığın yaşamını değiştirmesini fazlaca bireysel bir &ouml;yk&uuml;ye dayandırarak veren&nbsp;<b><i>Avcı&nbsp;</i></b>(The Deer Hunter,&nbsp;<b>Michael Cimino</b>, 1978) gerici ve nasyonalist bir finale saplanıp intihar eder. Nedense savaş t&uuml;r&uuml;n&uuml;n en &uuml;nl&uuml;lerinden biri sayılan&nbsp;<b><i>Kıyamet&nbsp;</i></b>(Apocalypse Now,&nbsp;<b>F. F. Co</b><strong>ppola</strong>, 1979), Amerikalıların silahları ve bastıramadıkları korkularıyla doğallığa ve ilkelliğe dayanan mutlu ortamı bozulan bu coğrafyayı, Vietnam&rsquo;dan Kambo&ccedil;ya&rsquo;ya uzanan ve bireyin i&ccedil;sel d&ouml;n&uuml;ş&uuml;m&uuml;n&uuml; ger&ccedil;ekleştirdiği yolculuğa fon olarak kullanır. &Ouml;te yandan, Hollywood kendisine yakışanı yaparak, olmadık Vietnam &ouml;yk&uuml;leri yumurtlamaya başlar ve&nbsp;<b><i>İlk Kan</i></b>&nbsp;(First Blood,&nbsp;<b>Ted Kotcheff,</b>&nbsp;1982) ile tanışırız. İyi ile k&ouml;t&uuml; arasında gidip gelen bir grup askerin &ccedil;atışmasında debelenen bir savaş atmosferi &ccedil;iziktiren&nbsp;<b><i>Platoon</i></b>&nbsp;(<b>Oliver Stone</b>, 1986 ) g&ouml;rselliği ve kurgusuyla baş d&ouml;nd&uuml;r&uuml;r.&nbsp;<b>Stanley Kubrick&nbsp;<i>Full Metal Jacket</i></b>&nbsp;(1987) ile keskin sirkenin k&uuml;p&uuml;ne zarar vermesinin &ouml;yk&uuml;s&uuml;n&uuml; savaşa uyarlar. Ve Hollywood en sonunda, savaşın askerler değil, politikacı ve b&uuml;rokratlar nedeniyle yitirildiği kararına varır. Savaşın bir hata olduğunu savaşarak &ouml;ğrenen bir savaş gazisinin yalnızlığını işleyen ve bizleri ileride daha &ccedil;ok savaşların beklediğini g&ouml;steren&nbsp;<b><i>Doğum G&uuml;n&uuml; 4 Temmuz&nbsp;</i></b>(Born on the Fourth of July,&nbsp;<b>Oliver Stone,</b>&nbsp;1989) ile savaş ortamının kriminal ve psikopat karakterleri su y&uuml;z&uuml;ne &ccedil;ıkarttığının g&ouml;stergesi olan ve ABD&rsquo;nin olur olmaz yerlerde ne aradığı sorusunu kendisine y&ouml;neltmesi gerektiğini savlayan&nbsp;<b><i>Savaş G&uuml;nahları</i></b>&nbsp;(Casualties of War<b>, Brian de Pal</b><strong>ma</strong>, 1989) değişimin kanıtlarıdırlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bu filmler, Hollywood&rsquo;un Vietnam sendromundan veya savaşsever kimliğinden kurtulamadığını g&ouml;steren diğer filmler sayesinde yalnızlık &ccedil;ekmezler:&nbsp;<b><i>Git Ispartalılara Anlat&nbsp;</i></b>(Go Tell the Spartans,&nbsp;<b>Ted Post</b>, 1977),&nbsp;<b><i>B&uuml;y&uuml;k Kırmızı Bir&nbsp;</i></b>(The Big Red One,&nbsp;<b>Samuel Fuller</b>, 1980),&nbsp;<b><i>Birdy</i></b>&nbsp;(Alan Parker, 1984),&nbsp;<b><i>&Ouml;l&uuml;m Tarlaları&nbsp;</i></b>(The Killing Fields,&nbsp;<b>Roland Joffe</b>, 1984),&nbsp;<b><i>Hamburger Tepesi</i></b>&nbsp;(Hamburger Hill,&nbsp;<b>John Irvin</b>, 1987),&nbsp;<b><i>Saigon</i></b>&nbsp;(<b>Christopher Crowe</b>, 1988) ve&nbsp;<b><i>İnce Kırmızı Hat</i></b>&nbsp;(Thin Red Line,&nbsp;<b>Terrence Malick</b>, 1999). Ancak, ge&ccedil;en yıllar g&ouml;sterir ki bunların sonunu beklemek boşunadır, &ccedil;&uuml;nk&uuml; hemen herkesin anlatacağı bir başka Vietnam ya da bir başka savaşın anısı vardır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Bir savaşın &ouml;ncesinden sonrasına sinema ile uzanmak isterseniz, sırayla&nbsp;<b><i>Full Metal Jacket</i></b>,&nbsp;<b><i>Casualties of War</i></b>&nbsp;ve&nbsp;<b><i>Born on the Fourth of July&nbsp;</i></b>filmlerini izlemek se&ccedil;eneklerden biri. Ya da savaş filmleri tarihinden bir derleme izlemek istiyorsanız,&nbsp;<b><i>Batı Cephesinde Yeni Birşey Yok</i></b><i>&nbsp;(</i>All Quiet on the Western Front,&nbsp;<b>Lewis Milestone</b>, ABD,1930),&nbsp;<b><i>Zafer Yolları</i></b>&nbsp;(Paths of Glory,&nbsp;<b>Stanley Kubrick</b>, ABD,1957),&nbsp;<b><i>Kwai K&ouml;pr&uuml;s&uuml;</i></b>&nbsp;(The Bridge on the River Kwai,&nbsp;<b>David Lean</b>, Britanya, 1957),&nbsp;<b><i>Salvador&nbsp;</i></b>(<b>Oliver Stone</b>, ABD, 1986) ve&nbsp;<b><i>Stalingrad</i></b>&nbsp;(<b>Joseph Vilsmaie</b>r, Almanya, 1992) beşlisi doyurucu olacaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Savaşla ilgilenen tek sinema Hollywood değil kuşkusuz. Hemen her &uuml;lke, kendi politikası doğrultusunda propaganda filmleri &ccedil;evirmiş, kazandığı savaşları destansı bir g&ouml;rsellikle yeniden yaratmış ancak savaş karşıtı olmak gibi zor bir işe nadiren ilgi duymuştur. Siz ger&ccedil;ekten savaş karşıtı olan bir film izlediğinizi d&uuml;ş&uuml;n&uuml;yor musunuz? Yukarıda adı ge&ccedil;enlerin hepsini de izleseniz bu soruya evet yanıtı vermeniz doğru mu? Sizin bir filmi nasıl okuduğunuz değil burada &ouml;nemli olan, onun taşıdığı mesaj ve i&ccedil;erik. B&ouml;yle bakınca, adı savaş karşıtına &ccedil;ıkmış bir&ccedil;ok filmin seyircinin duygusal yorumlarıyla bu misyonu taşır hale geldikleri a&ccedil;ık. En ağır eleştirileri getiren ve savaşın ger&ccedil;ek y&uuml;z&uuml;n&uuml; g&ouml;steren filmlerin bunlar olmadığı da a&ccedil;ık. Savaş karşıtı filmler politik &ccedil;&ouml;z&uuml;mlemelere, insanlık su&ccedil;larına, barış &ouml;zlemine, yitirilenlerin yarattığı boşluğun kalıcılığına, işlenen su&ccedil;ların a&ccedil;ığa &ccedil;ıkarılmasına ve kanıtlara dayanıyor. Son derece bireysel ve sınıflandırmaları aşan, savaş g&ouml;r&uuml;nt&uuml;lerine bağımlı kalmayıp olayın d&uuml;ş&uuml;nsel analizini yapan filmler de var. S&ouml;zgelimi,&nbsp;<b>Godard</b>&nbsp;ve&nbsp;<strong>Gorin</strong>&rsquo;in y&ouml;nettiği&nbsp;<b><i>Jane&rsquo;e Mektup</i></b>&nbsp;(Letter to Jane, Fransa, 1972),&nbsp;<b>Jane Fonda</b>&rsquo;nın kişiliğinde Amerikan solunun Vietnam olayına bakışını tartıştığı savındadır. Y&ouml;netmenler, Amerikan solunun analizinde pasifliği, g&uuml;vensizliği ve ikiy&uuml;zl&uuml; liberalliği vurgulamaya &ccedil;alışsalar da g&uuml;n&uuml; ve koşulları g&ouml;rmekten uzaktırlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Savaş kimi zaman ka&ccedil;ınılmazdır, sizi zorla yok etmeye &ccedil;alışanlar karşısında yitireceğiniz hi&ccedil;bir şey kalmamışsa... İspanya İ&ccedil; Savaşı &uuml;zerine yapılmış filmlerden biri olan&nbsp;<b><i>Madrid&rsquo;de &Ouml;lmek</i></b>&nbsp;(Mourir a Madrid,&nbsp;<b>Frederic Rossif</b>, Fransa, 1965) yıkımın ne boyutlara ulaşabileceğinin canlı tanıklarından biri. Sonu&ccedil;ları a&ccedil;ısından, bir y&ouml;n&uuml;yle de sanat d&uuml;nyasına karşı yapılmış bir savaş izlenimi veren İspanya İ&ccedil; Savaşının g&ouml;r&uuml;nt&uuml;leri, uğrunda &ouml;len kameramanlarını haklı &ccedil;ıkartan kesintisiz bir ger&ccedil;ekliğe sahip. D&uuml;nya o g&uuml;nlerde olduğu gibi, bug&uuml;n de savaşa karşı savaşan uluslararası tugayların varlığına gereksinim duyuyor. G&uuml;n&uuml;m&uuml;z&uuml;n savaşları, eskisi gibi &ouml;zg&uuml;rl&uuml;k kazanmak i&ccedil;in değil, başkalarından kazanacağı ile kendine daha geniş bir &ouml;zg&uuml;rl&uuml;k alanı yaratmak isteyenlerce &ccedil;ıkarılıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Savaş filmlerinin g&ouml;z&uuml;nden bakılınca, asıl fatura savaş sonrasında &ouml;denmektedir. Savaşta &ouml;ld&uuml;rmek ya da &ouml;ld&uuml;r&uuml;lmek ikilemine d&uuml;şen ve sağ kalmayı başaran ancak yaşadığı deneyimin k&ouml;t&uuml; izlerinden arınamayan bireyler, savaş sonrasında başıboş bırakılan ve umursanmamaya bir tepki olarak su&ccedil; işleyen askerler, yaşamının kalan kısmını sakat olarak ve/veya s&uuml;rekli psikolojik destekle s&uuml;rd&uuml;rmek zorunda kalanlar savaşın bilan&ccedil;o defterlerinin kapanmasına engel olurlar.&nbsp;<b><i>Sevgili Amerika: Vietnam&rsquo;dan Eve Mektuplar</i></b>&nbsp;(Dear America: Letters Home from Vietnam,&nbsp;<b>Bill Couturie</b>, ABD, 1987), savaş sırasında amat&ouml;r kameralarla &ccedil;ekilmiş g&ouml;r&uuml;nt&uuml;lere arşiv filmlerinin eklenmesiyle kurulmuş bir film. Vietnam&rsquo;dan g&ouml;nderilen ve her nasılsa adresine ulaşmış mektuplardan derlenen anlatısı savaşın ger&ccedil;ek y&uuml;z&uuml;n&uuml; ortaya koyması a&ccedil;ısından az bulunur bir zengin s&ouml;ylem yaratıyor. Mektuplar ger&ccedil;ek, sevgililer ger&ccedil;ek, &ccedil;ocuklar ger&ccedil;ek, kan ve &ouml;l&uuml;m ger&ccedil;ek ama Amerika uğruna &ouml;l&uuml;nmeye değer bir sevgili mi? Soruya en doğru yanıtı verecek olanlar ya mezarlarında ya da kayıp listelerinde bir satıra sıkışmış, suskun duruyorlar. Bir başka &ccedil;arpıcı film:&nbsp;<b><i>&Uuml;z&uuml;lerek Bildiririz ki...&nbsp;</i></b>(Regret to Inform,&nbsp;<b>Barbara Sonneborn</b>, ABD, 1998). B&uuml;rokrasi askerlerin &ouml;l&uuml;m haberlerini ailelerine nedense hep &uuml;z&uuml;lerek bildirir. Oysa b&uuml;rokrasi &uuml;z&uuml;lemez, duyguları yoktur. K&ouml;r, sağır, dilsiz, kalpsizdir ama daha da &ouml;nemlisi beyinsizdir. &Uuml;z&uuml;len, yıllar sonra kendini yollara vurur, sevdiğinin izini s&uuml;rer, y&ouml;netmenin yaptığı gibi. Ve karşısında kendi kayıplarına karşı aynı duyarlılığı taşıyan karşı cephenin kadınlarını bulur. Askerlerin savaşı biter ancak halkın savaşı kuşaklar boyu s&uuml;rer.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">Yazının sonuna en zorunu sakladım. Beş y&ouml;netmenin beş kısa filminden oluşan&nbsp;<b><i>&Ccedil;ocukluğun &Ouml;tesinde</i></b>&rsquo;nin (<b>Oltre L&rsquo;Infanzia</b>, İtalya, 1996)&nbsp;<b>Gianni Amelio</b>&nbsp;tarafından y&ouml;netilen&nbsp;<b><i>Barış Bitmedi, Yani Savaş</i></b>&nbsp;(<b>Non e finita la pace,&nbsp;</b>cioe la guerra) adlı b&ouml;l&uuml;m&uuml;n&uuml;, izlemek ne kadar zorsa &ccedil;ekmek de bir o kadar zor olmuştur, eminim.&nbsp;<b>Amelio</b>, savaşın hemen ardından gittiği Saraybosna&rsquo;da, savaşa tanık olan değil yaşayan ve bunun etkilerini bir &ouml;m&uuml;r boyu bedenlerinde ve ruhlarında taşımak zorunda kalacak &ccedil;ocukları kamerasının karşısına alır. Onlardan savaşı anlatmalarını ister. B&uuml;t&uuml;n&uuml; bir yakın-plan &ccedil;alışması olarak sıradışı bir anlatıma sahip olan, i&ccedil;eriğiyle de savaşların a&ccedil;tığı y&uuml;rek yaraları ve doğurduğu kin nedeniyle yeni savaşların yolunu a&ccedil;tığı mesajını taşıyor.&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: arial, helvetica, sans-serif;">İşte size savaşa karşı durmak i&ccedil;in d&ouml;rt g&uuml;&ccedil;l&uuml; film, d&ouml;rt dayanak. Savaşlar başlar, sona ermez. D&ouml;rt filmden ikisinin Amerikan yapımı olmasına şaşmamak gerek. Faturayı karşıtları kadar kendileri de &ouml;d&uuml;yor, &ouml;deyecek. Hayatımız boyunca hep aynı viz&ouml;rden bakmaya zorlandığımızı hi&ccedil; d&uuml;ş&uuml;nmedik mi? Değişiklik istediğimizde a&ccedil;ımızı değiştirmenin yeterli olacağı s&ouml;z&uuml;nden hi&ccedil; kuşkulanmadık mı? Uzatmayalım, siz hi&ccedil; savaşı bir Vietkongun, bir Iraklının ya da bir Bosnalının g&ouml;z&uuml;nden anlatan film izlediniz mi? Ve bunun savaş karşıtlığı ile olan ilgisini şu an kendinize soruyor musunuz?</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (74, 'ay-j195', 'denize-dusen-sinema', 'Denize Düşen Sinema', 'Kılavuz, 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kılavuz, 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinemanın da kendine &ouml;zg&uuml; mevsimleri olduğunu hi&ccedil; d&uuml;ş&uuml;nd&uuml;n&uuml;z m&uuml;? Bir taraftan t&uuml;keticisi olan bizlerin mevsimlik se&ccedil;imlerimize ayak uydurmaya &ccedil;alışan sinema, &ouml;te taraftan b&uuml;t&uuml;n&uuml;yle kendi yapım politikası ve i&ccedil; dinamikleri doğrultusunda değişken bir mevsimler dizisi yaşar. Sinemanın mevsimleri bizimkiler gibi sıralı bir bi&ccedil;imde ve iyi k&ouml;t&uuml; bir uyum i&ccedil;inde akmaz. Zamanla kendini sınırlamaz ve yeri geldiğinde dilediğince uzatarak mevsimin tadını &ccedil;ıkarır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Yaz gelince insanın aklı alıp başını gitse de suyun &ouml;nemini anımsamadan ve denize uğramadan edemez. Alışkanlıklar, &ouml;zlemler, zorunluluklar bizi suya &ccedil;eker ve deniz kıyısına inmeye iter. Sinema oldum olası denize sevdalıdır ve sayısız kez soluğu onun yanıbaşında almıştır. Ancak bu su ve deniz ile sinema arasındaki ilişki her zaman g&uuml;zel sonu&ccedil;lar vermez. İ&ccedil;lerinde denizin keyfini &ccedil;ıkaranlar olsa da sinema tarihi sudan &ccedil;ıkmış balığa d&ouml;nen, denize d&uuml;ş&uuml;p boğulan, deniz tutan, sulu kazalara kurban giden, bir kaşık suda boğulan, gemi batığına &ouml;zenen ve kendini unutturmaya &ccedil;alışan sayısız filmden s&ouml;zeder.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Toplumsal sorunlar &uuml;zerine kurulu olan filmler i&ccedil;inde bazıları doğrudan suyun yaşamsal &ouml;nemini veya su sorununu işler. Su, bu t&uuml;r filmlerde toplumlar arasında uzlaşmazlık kaynağı olarak ortaya &ccedil;ıkar ve politik bir g&uuml;&ccedil; stat&uuml;s&uuml;ne y&uuml;kselir. Bazı filmlerin kendine yaşam alanı se&ccedil;tiği yer g&ouml;l veya denizlerdir ki bunları bir alt film t&uuml;r&uuml; olarak g&ouml;rme eğiliminde olanlar vardır. Yapım zorlukları a&ccedil;ısından bakıldığında denizde &ccedil;ekilen filmlerin b&uuml;t&ccedil;esi ulaşım g&uuml;&ccedil;l&uuml;kleri, &ccedil;ekim s&uuml;resinin belirsizliği, hava durumu, personelin sağlık sorunları ve &ouml;ng&ouml;r&uuml;lemeyen yaşam koşulları nedeniyle hemen her zaman oynaktır ve bu durum bir film i&ccedil;in genellikle k&ouml;t&uuml;ye işler. Su sorununu işleyen toplumsal filmler i&ccedil;in belli bir d&ouml;nem yoktur. Ancak deniz filmleri genel olarak ser&uuml;ven filmlerinin veya İkinci B&uuml;y&uuml;k Savaş sonrası &ccedil;ekilen savaş filmlerinin bir alt t&uuml;r&uuml; olarak sınıflanabilir. Bu yazıda kitlesel sinemaya d&ouml;n&uuml;k bu filmler yerine bireysel sinemanın peşine takılarak alabildiğine &ouml;znel bir se&ccedil;im yapacağız, hemen her zaman yapageldiğimiz &uuml;zere.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Rusya&rsquo;nın Sakhalin adasının donmuş topraklarında ve t&uuml;mden denize bağımlı bir yaşam s&uuml;ren Nyvkh kabilesi &uuml;zerine olan&nbsp;<b><i>Deniz Kıyısında Koşan K&ouml;pek</i></b>&nbsp;(Dog Running at the Edge of the Sea, 1990) filmi deniz &uuml;zerine olan filmlerin en &ccedil;izgidışı olanlarından biri. Deniz onlar i&ccedil;in balıklarıyla yiyecek, foklarıyla ge&ccedil;im demek. Kabilenin gen&ccedil;lerinden on yaşındaki Kirisk aile b&uuml;y&uuml;kleriyle &ccedil;ıktığı ilk fok avcılığında hayatının deneyimini kazanır. Engin deniz bu ilk buluşmalarında ona iyi davranmaz. Her yanlarını g&ouml;z alabildiğine sis kaplar. Teknelerindeki yiyecek ve suları azalınca, yaşlılar kabilenin geleceğini d&uuml;ş&uuml;nerek intiharı se&ccedil;erler. Etnografik belgesellerin tadını taşıyan g&ouml;rselliğiyle &ccedil;arpan film, Moskova FF&rsquo;nden B&uuml;y&uuml;k &Ouml;d&uuml;l sahibi ve&nbsp;<b>Karen Gevorkyan</b>&rsquo;a da en iyi y&ouml;netmen &ouml;d&uuml;l&uuml; kazandırdı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Su bazı zamanlar ardında &ouml;zlem duyulan yaşamları saklar.&nbsp;<b>Tomris Giritlioğlu</b>&rsquo;nun 1991 yapımı&nbsp;<b><i>Suyun &Ouml;te Yanı</i></b>&nbsp;filmi, &ouml;te yana duyulan &ouml;zlemin kayıtsız kalınamayacak cinsten bir &ouml;rneğini işler. 60&rsquo;larındaki Sıdıka Hanım 1924 Girit Anlaşması ile Cunda&rsquo;ya yerleşmiş ve kendisini d&ouml;rt duvarıyla dış d&uuml;nyaya kapatan bir pansiyon işletmektedir. 80&rsquo;li yılların başında adaya gelen bir kadın ve bir erkek pansiyona yerleşir. Adam tutuksuz yargılanmak &uuml;zere serbest bırakılmış bir &ouml;ğretim g&ouml;revlisidir. Kaldıkları bir hafta i&ccedil;inde ada insanıyla yakın ilişki kurarlar. Cunda&rsquo;ya sığınmış bir Yunan avukatın &ouml;yk&uuml;s&uuml; adamı &ccedil;ok etkiler. Israrla kendi &ouml;yk&uuml;s&uuml; ile k&ouml;pr&uuml;ler kurmaya &ccedil;abalar. Adam adaya yeniden geldiğinde bu kez yalnızdır ve suyun &ouml;te yanına ge&ccedil;me isteği depreşmektedir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bir başka denize sevdalanma &ouml;yk&uuml;s&uuml; de g&uuml;n&uuml;m&uuml;z&uuml;n &ouml;nemli adlarından&nbsp;<b>Takeshi&nbsp;</b>&ndash;<b><i>Sonatine</i></b>&nbsp;(1993) ve&nbsp;<b><i>Kikujiro</i></b>&nbsp;(1999)-<b>&nbsp;Kitano</b>&rsquo;nun 1991&rsquo;de ger&ccedil;ekleştirdiği&nbsp;<b><i>Bir Deniz Manzarası</i></b>&rsquo;nda (A Scene at the Sea) anlatılır. &Ccedil;&ouml;p toplama işinde yarım g&uuml;n &ccedil;alışarak ge&ccedil;imini sağlayan Shigeru ve kız arkadaşı Takako&rsquo;nun ortak &ouml;zelliği duyma &ouml;z&uuml;rleridir. Shigeru bir g&uuml;n karıştırdığı &ccedil;&ouml;plerin i&ccedil;inde bir s&ouml;rf tahtası bulur. Bu onun denizle olan tanışıklığında yeni bir evre demektir. Her g&uuml;n denize inerek yavaş yavaş s&ouml;rf becerisini geliştirir. Shigeru&rsquo;nun kararlılığını g&ouml;zlemleyen bir adam s&ouml;rf elbisesi ve bir yarışma başvuru belgesi verir. Anonsları duymadığı i&ccedil;in yarıştan diskalifiye edilir ama deniz ve s&ouml;rf sevgisi kısa s&uuml;re sonra başarıyı getirecektir. Sonunda yazın sonu g&ouml;z&uuml;k&uuml;r ama Takako ile olan ilişkileri artık s&ouml;rf &ouml;ncesindeki konumunda değildir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Deniz &uuml;zerine yapılmış filmler arasında en tanınan edebiyat uyarlamalarından biri olan&nbsp;<b><i>Yaşlı Adam ve Deniz</i></b>&nbsp;(The Old Man and the Sea, 1958), Ernest Hemingway&rsquo;in aynı adlı &ouml;yk&uuml;s&uuml;nden yola &ccedil;ıkılarak,&nbsp;<b>John Sturges</b>&nbsp;tarafından 1958 yılında &ccedil;ekildi. Sinematografik olarak zayıf olan filmde, balık&ccedil;ıyı&nbsp;<b>Spencer Tracy&nbsp;</b>canlandırdı. Yaşam kavgasını vereceği yer olarak denizi se&ccedil;en yaşlı balık&ccedil;ının dev bir kılı&ccedil;balığı ile girdiği savaşım masalsı ve destansıdır. Yaşlı balık&ccedil;ının g&uuml;nler ve geceler sonra yakalayabildiği balık, yaşamın hedefinin mutluluk olduğunu g&ouml;steren bir sembol gibidir. Yakaladığı balığı tekneye &ccedil;ekmek ister ama başaramaz. G&uuml;neş, yorgunluk, uykusuzluk ve susuzluk onda da dermen bırakmamıştır. Geriye balığı kıyıya kadar teknenin yedeğinde &ccedil;ekmek se&ccedil;eneği kalır. Balık kıyıya varmasına varır ama tekneye bağlı olarak s&uuml;rd&uuml;rd&uuml;ğ&uuml; yolculuk boyunca etinden olarak. Yaşlı balık&ccedil;ı kıyıya vardığında balıktan geriye yalnız iskeleti kalacaktır. Yaşlı adam yaşamın kendisine sunduğunun yoksunluğunu &ccedil;abuk unutacak, denize karşı verdiği savaşın gururu herşeyin &ouml;n&uuml;ne ge&ccedil;ecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Su &uuml;zerindeki bir başka savaşım da&nbsp;<b>Roman Polanski</b>&rsquo;nin ilk uzunu olan&nbsp;<b><i>Sudaki Bı&ccedil;ak</i></b>&nbsp;(Noz W Wodzie, 1962) filminde yaşanır. Hafta sonunu teknelerinde ge&ccedil;irmeyi planlayan bir &ccedil;ift, Andrzej ve Kristina yolları &uuml;zerinde rastladıkları bir genci arabalarına alırlar. Gen&ccedil; &ccedil;iftin kadın olanının isteği &uuml;zerine isimsiz gen&ccedil; tekneye de alınır. G&ouml;l &uuml;zerindeki tekne iki erkeğin ve onlara kayıtsız g&ouml;r&uuml;nen gen&ccedil; kadının savaş alanı olarak, g&ouml;zlerden ve kıyıdan uzak olmasıyla dikkat &ccedil;ekici bir se&ccedil;imdir. G&uuml;&ccedil; dengesinin bozukluğu, Andrzej&rsquo;in gen&ccedil; &uuml;zerinde g&ouml;vde ve zeka g&ouml;sterisi yapması i&ccedil;in uygun zemin hazırlar. Gerilim her adımda giderek tırmanır. Gen&ccedil; hayatta sahip olduğu tek şey gibi g&ouml;r&uuml;nen bı&ccedil;ağı ile s&uuml;rekli oynar. Andrzej i&ccedil;in bı&ccedil;ağın ele ge&ccedil;irilmesi demek, &uuml;st&uuml;nl&uuml;ğ&uuml;n zorla kabul ettirilmesi demektir. Bı&ccedil;ak iki erkek arasındaki g&uuml;&ccedil; savaşının simgesel aksesuarıdır. Kıskan&ccedil;lık, g&uuml;&ccedil; ve ayak oyunlarının ardı arkası kesilmez. Dengelerin g&ouml;stergesi olan bı&ccedil;ak i&ccedil;in yapılacak bir kavga ka&ccedil;ınılmazdır. Sonu&ccedil;ta y&uuml;zme bilmediğini s&ouml;yleyen isimsiz gen&ccedil; suya d&uuml;şer ve kaybolmuş rol&uuml; oynar. Su, bu savaşta rol &ccedil;alan ve finalin oynandığı yer olur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Kıyamet sonrası toplumun bir fantazyası olarak tanımlayabileceğimiz&nbsp;<b><i>Su D&uuml;nyası</i></b>&nbsp;(Waterworld, 1994), sinema tarihine&nbsp;<b>Kevin Reynolds</b>&nbsp;tarafından oyuncu-yapımcı&nbsp;<b>Kevin Costner</b>&rsquo;e rağmen &ccedil;ekilen ve tamamlanan bir &uuml;st&uuml;nyapım olarak ge&ccedil;ti. Ancak bu sıfat, filmin sinema tarihinin en b&uuml;y&uuml;k fiyaskolarından biri olmasına engel olmadı. Ona Costner&rsquo;ın denizin dibini taradığı film desek daha doğru olur. U&ccedil;suz bucaksız okyanuslarla kaplı bir d&uuml;nyada kuru kalmış tek toprak par&ccedil;asını elde etmek i&ccedil;in verilen savaşın &ouml;yk&uuml;s&uuml;. Bu boyuttta bir sa&ccedil;malığı Hollywood dışında bir yerin becermesi de olası değil.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bizim i&ccedil;in &ccedil;ok bildik bir Anadolu sorunu olan susuzluğa değinen&nbsp;<b><i>Susuz Yaz</i></b>&nbsp;ile &ccedil;eşnimizi noktalayalım. Susuzluk dedik ama bu, zorunlu bir susuzluğun, susuzluğunda &ouml;tesinde bir kuraklığın &ouml;yk&uuml;s&uuml;.&nbsp;<b>Metin Erksan</b>&rsquo;ın 1964 Berlin FF Altın Ayı &ouml;d&uuml;l&uuml;n&uuml; kazanarak T&uuml;rk sinemasında bir ilki ger&ccedil;ekleştiren filmi, odağına bir ağabey ve kardeş olan Hasan ve Osman ile k&ouml;y&uuml;n g&uuml;zeli Bahar arasında yaşanan ilişkileri yerleştirir. Susuzluk ise k&ouml;y halkı ile bu &uuml;&ccedil;l&uuml; arasında yaşanan gerilime &ccedil;anak tutuyor. Hasan ve Bahar&rsquo;ın evliliği, k&ouml;y halkı ile sularını kesen Osman arasındaki kırgınlıklar ve ardından yaşanan kavganın &ouml;l&uuml;mle sonu&ccedil;lanması, Hasan&rsquo;ın &ouml;l&uuml;mle su&ccedil;lanarak tutukevine girmesi, &ccedil;ıktığında kandırdığı Bahar&rsquo;la evli bulduğu Osman&rsquo;ı su kanalında boğarak &ouml;ld&uuml;rmesi ve en sonunda k&ouml;yle aralarının a&ccedil;ılmasına neden olan seti yıkarak k&ouml;y&uuml;n suyunu a&ccedil;ması&nbsp;<b><i>Susuz Yaz</i></b>&rsquo;ın &ouml;yk&uuml;s&uuml;ndeki d&ouml;n&uuml;m noktalarını oluşturuyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinema, parmakları yeri hissetmediği s&uuml;rece denizde huzursuzlananlar sınıfına giriyor. Ama onsuz da edemiyor. Sinemanın denizdeki ser&uuml;veninin bende bıraktığı izler bu kadar. Sizin ağınıza takılan filmler daha bol ve &ccedil;eşitli olsun. Rastgele!</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (75, 'ay-j196', 'sinema-ve-mit', 'Sinema ve Mit', 'Kinorama 1-2, 2003', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 1-2, 2003</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Geoffrey Nowell-Smith</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>&Ccedil;eviren: Civan &Ouml;zcivanoğlu</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Seyircinin herhangi bir filme bakabildiği iki u&ccedil; bulunur: filme girenler ve filmden &ccedil;ıkanlar. Y&ouml;netmen ile seyirci arasında iletişim -o da varsa- pek seyrek bi&ccedil;imde m&uuml;kemmel olabildiğinden, yaratma s&uuml;recinde y&ouml;netmenin filme koydukları ile seyircinin bunlardan algıladıklarının aynı olmasına gerek yoktur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Eğer biliyorsa, işlevi bu bakış a&ccedil;ıları arasındaki ilişkiler hakkında d&uuml;ş&uuml;nmek olan eleştirmen de şimdi her iki tarafa da eğilerek, bir iletişim kurulmasına yardımcı olmaya &ccedil;alışır. Fakat şu ya da bu nedenden dolayı, belki film end&uuml;strisinin yapısına, belki insan zihninin &ccedil;alışma bi&ccedil;imine, belki de iletişimin kendi doğasına bağlı olarak, eleştirmenimizin &ccedil;abaları seyrek&ccedil;e tamamen başarılıdır. Bazen, sinemanın ger&ccedil;ekte hi&ccedil; de bir iletişim bi&ccedil;imi olmadığı d&uuml;ş&uuml;n&uuml;lebilirse de bunun tersine box-office&rsquo;deki nakit para da dikkate alınabilir. Ancak sanat &ouml;zenle tartışılmaksızın uğraşıldığında y&ouml;ntemlerin ne olacağı konusunda bir bilgi yoktur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu deneme, benim i&ccedil;in satır aralarına alınmaları uygun g&ouml;r&uuml;nen, tanınan ya da tanınmayan bazı mitlere (sinemanın direkt iletişim deneyimi) eğilerek, iletişim boşluğunun bir b&ouml;l&uuml;m&uuml;n&uuml; dolaylı olarak kapatmak adına bir girişimdir. Niyetim, hi&ccedil;bir temel sorunu &ccedil;&ouml;zm&uuml;ş gibi davranmak değildir (belki de ger&ccedil;ek temel sorunların k&ouml;kl&uuml; &ccedil;&ouml;z&uuml;mleri yoktur). Ancak aklımdaki &ccedil;eşitli mitlerin sinemada oynadıkları role eleştirel bir bakışla birşeylere ulaşılacağına ilişkin g&uuml;&ccedil;l&uuml; bir inancım var.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinema hakkında - şu karanlığa girmek, rahim gibi mağaralara dalmak ve titreyen perdedeki uzak d&uuml;şsel g&ouml;r&uuml;nt&uuml;leri seyretmek hakkında- &ouml;nde gelen bir şey var; sinemayı bilin&ccedil;altı seviyesinde &ouml;zellikle verimli bir mitos kaynağı yapan bir şey. Sadece&nbsp;<b>Vigo</b>,&nbsp;<b>Bunuel&nbsp;</b>ya da&nbsp;<b>Resnais&nbsp;</b>gibi y&ouml;netmenlerin, yalnız entelekt&uuml;llerde afyon etkisi yapan şok edici g&ouml;r&uuml;nt&uuml;leri&nbsp; değil, aynı zamanda ticari sinemanın bazı tema ve g&ouml;r&uuml;nt&uuml;leri de t&uuml;m etkileriyle olmasa da bilin&ccedil;altının bilinmeyen hareketleri &uuml;zerinde &ccedil;alışarak aynı etkiye ulaşır. Korku filmleri tam da bu seviyede &ccedil;alışır, ancak eklemek gerekir ki vamplar olduğu gibi vampirler de vardır.<b>&nbsp;Eva Marie Saint</b>,&nbsp;<b>Norht by Northwest</b>&nbsp;filminin ilk yarısında tam bir sarışın, kana susamış harika bir vampirdir. Sonra herşey değişir ve bu kadın uğrunda savaşmaya ve kazanmaya değecek ideal bir sevgili oluverdiğinde,&nbsp;<b>Hitchcock</b>&rsquo;un yaptığı şey aslında seyirciyi kendi bilin&ccedil;dışı fantazyalarının olası sonu&ccedil;ları karşısında &ouml;zg&uuml;r bırakmaktır. Ancak,&nbsp;<b>Rohmer</b>&nbsp;ve&nbsp;<b>Chabrol</b>&rsquo;un yaptığı gibi&nbsp;<b>Hitchcock</b>&rsquo;un mitolojisi, &ouml;nem ve anlamları psikolojik değil, metafizik ve hatta teolojik olan bilin&ccedil;&uuml;st&uuml; fikirleri a&ccedil;ısından da g&ouml;r&uuml;lebilir. Ve eleştirinin ama&ccedil;ları a&ccedil;ısından ş&uuml;phe yok ki mitosları bu şekilde nesnelleştirebilmek yararlıdır. B&ouml;ylece, bilin&ccedil;dışı fantazyalar, g&ouml;sterim ve tanımlama aşamaları, tıpkı kahramanlık miti gibi, bilin&ccedil; mitleri seviyesinde ele alınırlar. Ve doğrudan tamamen ger&ccedil;ek bir deneyime direkt olarak bağlanmasına gerek olmayan, bilin&ccedil; seviyesindeki mitler, sadece y&ouml;nlendirici fikirler olduğundan, eleştirinin aydınlatma &ccedil;abasının bir filmin nasıl algılandığı&nbsp; sorusunu aydınlatmak yerine ger&ccedil;ekleri saptırma tehlikesi bulunmaktadır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Amacımız a&ccedil;ısından eşit değere sahip bir unsur da olguların mitsel a&ccedil;ıdan g&ouml;r&uuml;lmesindeki genel eğilimlerdir. Mit kelimesini kullanmak genelleştirilmiş imgeleri ya da birinin şeyler hakkında sahip olduğu d&uuml;ş&uuml;ncelerini (ancak ger&ccedil;ek deneyim ve bilginin yerini aldığı &ouml;l&ccedil;&uuml;de mitsel olan d&uuml;ş&uuml;ncelerini) kapsamakta yetersiz kalır.&nbsp;<b><i>Saturday Night and Sunday Morning</i></b>&nbsp;filmini bir&ccedil;ok orta sınıf seyircisi (ve eleştirmeni), konu hakkındaki belirsiz d&uuml;ş&uuml;ncelerine (elbette mitsel ama kelimenin en geniş anlamıyla) uygun d&uuml;şt&uuml;ğ&uuml;nden, filmi iş&ccedil;i sınıfının hayatına dair ger&ccedil;ek&ccedil;i bir film olarak kabul etmişlerdir. Diğer taraftan, bu film bir&ccedil;ok orta sınıf seyirci i&ccedil;in dar anlamda bir mitdir.&nbsp;<b>Arthur Seaton</b>&nbsp;ge&ccedil;mişine karşı kahramanca tavırlarıyla g&ouml;ze &ccedil;arpar, seyircilerin ahlaksal olarak ya da ger&ccedil;ekte yapmaya korktukları ya da yapamayacakları şeyler yapar; canı &ccedil;ektiğinde zilzurna şarhoş olmak, arkadaşının karısıyla yatmak gibi... ve seyirciler onu ideal ve mitsel bir kahraman olarak g&ouml;r&uuml;rler. Bu kahraman,&nbsp;<b>Marlon Brando</b>&nbsp;veya&nbsp;<b>Kirk Douglas</b>&nbsp;tarafından insan kılığına sokulmuş, daha yerel ve ulaşılabilir tipteki, zamanımızın ve mekanımızın kahramanlarından farklıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">B&uuml;t&uuml;n&uuml;yle rasyonel birisinin bakış a&ccedil;ısından, durum biraz farklı g&ouml;r&uuml;n&uuml;r. Mit bir kere g&ouml;r&uuml;nd&uuml;ğ&uuml;nde bu ne &ccedil;eşit bir mit olabilir; B&uuml;y&uuml;k Amerika Miti, Oedipus Miti... Mitler birer yalandır, akıl ve ger&ccedil;eğin d&uuml;şmanlarıdır. Bu tavır hem keyif ka&ccedil;ırıcı hem de kafa karıştırıcıdır. En rasyonel sinemada bile, herhangi &ccedil;eşit bir mit i&ccedil;in bir yerler olmalıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Plato gibi kendimize hangi mitlerin kabul edildiğini ve hangilerinin reddedildiğini sormalıyız, ancak kriterimiz bu kişinin tersine ahlaksal değil mantıksal olacaktır. Bu, hangi mitlerin tehlikeli ve &ouml;l&uuml;mc&uuml;l olacağı sorunu değildir (<b><i>Triumph of the Will</i></b>&rsquo;deki State and Volk veya Sovyet sinemasındaki Nevski, Ivan). Sorun mitlerin, bir masal şeklinde film yapısının bir par&ccedil;ası olarak mı yoksa bir imge şeklinde seyircinin kafasında mı &ccedil;alıştığı sorunudur. Bu t&uuml;rden kavramsal ayrımlar, kelimenin kendi &ccedil;ok anlamlılığı sayesinde &uuml;zerimizde baskı kurarlar</span><span style="color: red;">.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Film dilinden t&uuml;m saf s&ouml;zl&uuml; dillerin engellerini aşması beklenir. Bu, eski sessiz sinema i&ccedil;in bile doğru değildir. Yabancı birinin tavırları bir yabancının konuşmaları gibi kavranamaz yapıdadır. Hoşa gitsin gitmesin, yabancı filmler farklıdır ve farklı bi&ccedil;imde yargılanırlar. Nasıl eğitimli Amerikalılar kendi filmlerini aptalca, Avrupa&rsquo;da ya da daha uzakta &ccedil;ekilen filmleri ise, kesinlikle Amerikan geleneklerine ve yaşamına &ccedil;ok yabancı olduklarından,&nbsp; ciddi ve ağırbaşlı buluyorlarsa, Amerikan sinemasını hen&uuml;z keşfeden Avrupalılar da eğlenmişler ve dehşete d&uuml;şm&uuml;şlerdir. B&ouml;yle bir tavır, huysuz, snob ve temel olarak yaşam karşıtıdır.Bu tavıra nesnel olarak eğildiğimizde g&ouml;rd&uuml;ğ&uuml;m&uuml;z, son zamanlarda Avrupanın Amerikan sineması hakkındaki moda olan takıntısının aynadaki yansıyan g&ouml;r&uuml;nt&uuml;s&uuml;nden başka bir şey değildir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Amerikalı yabancı sanat d&uuml;şmanı, artistik değerleri ve ayırdedici imzaları kesin ve kolaylıkla beğenilen&nbsp;<b>Antonioni</b>&rsquo;lerin,&nbsp;<b>Bergman</b>&rsquo;ların ve&nbsp;<b>Mizoguchis&rsquo;</b>lerin yanısıra, yapayda olsa en azından merak uyandıran a&ccedil;ık s&ouml;ylemli birka&ccedil; filme g&uuml;venle yaklaşır. Ancak bir makineden &ccedil;ıkmış gibi g&ouml;r&uuml;nen kendi yerel &uuml;r&uuml;nlerine gelince, ger&ccedil;eklikten deneyime uzanan bir dizi titiz eleştiri s&uuml;re&ccedil;leri devreye sokar. Tanrı bilir ya ger&ccedil;ek&ccedil;ilik sinemada herşey demek değildir ve standartları her zaman da kolaylıkla uygulanamaz. Ancak ne zaman bir seyircinin neyin ger&ccedil;ek olup olmadığı hakkında kesin bir fikri olsa, başka bir seyirci de yanlış, basitleştirilmiş ve sıradan g&ouml;r&uuml;nen herhangi bir karaktere ya da arkaplana ters bir şekilde hemen tepki verir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">G&uuml;&ccedil; ve seks hakkında daha y&uuml;ksek genel bir ger&ccedil;ekten bahseder gibi g&ouml;r&uuml;n&uuml;nceye kadar,&nbsp;<b><i>Advise and Consent</i></b>&nbsp;ve hatta&nbsp;<b><i>The Chapman Report&nbsp;</i></b>gibi bir film, kelimesi kelimesine ger&ccedil;ek ve kesin olarak hissedilmesi gerekir. Ve eğer&nbsp;<b>Preminger&rsquo;</b>in yerel psikolojiye pot kıran yaklaşımı ve Cukor&rsquo;un t&uuml;m sosyolojik &ouml;nyargılı eserleri bir&ccedil;ok duyarlı ve zeki Amerikalının acıdan boğazlarını d&uuml;ğ&uuml;ml&uuml;yorsa onlara kendilerini mutlu hissetmelerini s&ouml;ylemek i&ccedil;in bizler de kim oluyoruz ki?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">A</span><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">merikan sinemasının dışındakiler olarak Avrupalılar Amerikan filmlerini yargılamak i&ccedil;in farklı ve &ccedil;ok katı olmayan bir kritere sahiptir. Roller değişmiştir ve onunla birlikte sinemasal değerlerin t&uuml;m hiyerarşisi de...</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Fransızlar bir&ccedil;ok durumda &ccedil;ok iyi birer Amerika&nbsp; hayranı olarak bilinirler. Bu tutku iki d&uuml;zeye sahiptir: Maddesel ve d&uuml;ş&uuml;nsel. Y&uuml;zeyde, ancak sadece y&uuml;zeyde, her kafedeki tilt makineleri ve m&uuml;zik kutuları coca-koloninazyonun t&uuml;m tuzak&ccedil;ı materyalleri. Daha derinde fakat daha az yaygın olarak entelekt&uuml;llerin bir b&ouml;l&uuml;m&uuml;ne bakılırsa, Amerikanın anti-Fransız olan mitsel g&ouml;r&uuml;nt&uuml;leri.&nbsp;<b>Miles Davis</b>&rsquo;den&nbsp;<b>Marlon Brando</b>&rsquo;ya,&nbsp;<b>William Faulkner</b>&rsquo;dan &ccedil;izgi filmlere kadar, Amerikan k&uuml;lt&uuml;r&uuml; bir&ccedil;ok Fransıza şiirsel, şiddete a&ccedil;ık ve &ouml;zg&uuml;r yeni d&uuml;nyanın g&ouml;r&uuml;nt&uuml;lerini sunar.&nbsp;<b>La Princesse de Clevers</b>&rsquo;dan&nbsp;<b>Rene Clair</b>&rsquo;e uzanan, akademik, ısmarlanmış burjuva geleneğinin karşısına pozitif bir karşı-imaj olarak &ccedil;ıkar. Sovyet super-egosunu b&uuml;y&uuml;k Amerikan kimliği ile birlikte kabul etmeye hazır olan ve a&ccedil;ık&ccedil;a uyuşmaz olan&nbsp;<b>Sartre</b>,&nbsp;<b>Malraux</b>,&nbsp;<b>Buotor</b>,&nbsp;<b>Breton</b>&nbsp;ve ger&ccedil;ek&uuml;st&uuml;c&uuml;ler ve yeni kuşaktan bir&ccedil;ok film yapımcısı (<b>Resnais</b>,&nbsp;<b>Reinbach</b>,&nbsp;<b>Melville</b>,&nbsp;<b>Godard</b>,&nbsp;<b>Truffaut</b>&nbsp;ve&nbsp;<b>Jacques Demy</b>) gibi uyuşmaz olanları i&ccedil;in de bir ortak merak alanı sağlayan bu Amerikan hayranlığı, aşırı sol kesimde bile etkili olur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu liste abs&uuml;rd g&ouml;r&uuml;lebilir.Aynı mitin farklı formlarda da a&ccedil;ıklanabileceği vurgulanmalıdır. Amerikan edebiyatı veya filmleri bir miti ima etmekte en &ouml;n sıralarda yer almaz. Italyan yeni ger&ccedil;ek&ccedil;ilik akımı bu noktada bir &ouml;rnektir<i>.&nbsp;<b>Visconti</b></i><b>, The Postman Always Rings Twice Postacı&nbsp;</b>adlı Amerikan romanını&nbsp;<b>Passion&nbsp;</b>adıyla filme uyarlarken, Amerika etkisi a&ccedil;ık&ccedil;a dışarıda kalmıştır ve merkezi konuları ve &ouml;ncelikleri etkilemez.&nbsp;<b>The Moon and the</b>&nbsp;<b>Bonfires</b>&nbsp;adlı klasik romanında bir g&ouml;&ccedil;menin g&ouml;z&uuml;nden Amerika&rsquo;yı mitleştiren&nbsp;<b>Pavese</b>&nbsp;bile miti asimile etmeyi rededer ama miti bir eleştiri aracı olarak kullanmayı dener. Yeni ger&ccedil;ek&ccedil;i sinema t&uuml;m Amerikan mitini g&ouml;rmezden gelir. Kendi davet ettiği yeni mitolojiye direnemediği noktalar olsa da eskiye &ouml;d&uuml;n vermez.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Fransızlarda, hernasılsa,&nbsp;<b>Sartre&nbsp;</b>ile başlayan mit başından beri oradadır. B&uuml;y&uuml;k politik se&ccedil;imlerin ıstırapları &uuml;zerine eğilen&nbsp;<b>Les Chemins de la Libert&eacute;</b>&nbsp;isimli romanındaki karakterlerin Amerikanlara &ouml;zg&uuml; bir durum değildir ama yine de onların davranışlarını s&uuml;rd&uuml;rmekten de &ccedil;ok uzak değildir. G&ouml;r&uuml;n&uuml;şte,&nbsp;<b>L&rsquo;Etre et le N&eacute;ant&nbsp;</b>da akla yatkın bir şekilde başka yenilenmiş kaynaklardan Amerikan sinemasından yararlandığı kadar yararlanmaz. (&Ouml;zellikle de savurgan ve anlamsız bir hayranlık duyduğu savaş &ouml;ncesi korku t&uuml;r&uuml;nden yararlanır) Mit, bir soyutlama olarak arka kapıdan girer. Aynı şey&nbsp;<b><i>Camus&rsquo;</i></b>n&uuml;n &uuml;nl&uuml; style blanc&rsquo;ının ahlakla ele ele gittiği&nbsp;<b>Le Peste</b>&rsquo;i i&ccedil;inde s&ouml;ylenebilir. Amerika&rsquo;nın Amerikan Miti&rsquo;ne bağlılıklarından dolayı ne&nbsp;<b><i>Sartre&nbsp;</i></b>ne de&nbsp;<b><i>Camus&nbsp;</i></b>su&ccedil;lanamaz. Onların asıl eğilimi kendi mitlerini yaratmaktır ya da daha kesin s&ouml;ylemek gerekirse &ouml;yk&uuml;y&uuml; oluşturmak i&ccedil;in idealize edilmiş belli Amerikan davranışlarını kullanırlar. Ve ikisi arasında bir farklar d&uuml;nyası vardır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Buradaki, Amerika&rsquo;nın Amerikan miti ile (kolay kandırılabilir Avrupalı&rsquo;larca hevesle i&ccedil;selleştirip değer verilen&nbsp;<b>Giants<i>&nbsp;</i></b>&ouml;rneğinde olduğu gibi) kolaylıkla idealize edilmiş imgelere d&ouml;n&uuml;şt&uuml;r&uuml;len Atlantik dışı elementleri i&ccedil;eren ve bu tarafta yaratılan mit arasındaki bu ayrım &ouml;nemlidir. Bu durum sadece&nbsp;<b><i>Sartre&nbsp;</i></b>gibi yazarları mit hastalığından kurtarmakla kalmaz aynı zamanda da bu anlamda ger&ccedil;ek birer mit hayranı olan belli sinema d&uuml;şk&uuml;nlerinin elinde, mitin nasıl tamamen kendini s&uuml;rd&uuml;rebilir hale geldiğini ve kendi kuralları dışında nasıl anlamsız hale geldiğini de a&ccedil;ıklar. Bu ve bu gibi durumlarda herhangi bir konunun i&ccedil;ine inşa edilen ve sadece seyircilerin bilicinde varolan (objektif ve subjektif, masal ve imge) teorikde bir ayrı duran bir mit vardır. Genellikle, hernasılsa, bu iki element bir uyum i&ccedil;inde davranır ve birbirinden ayrı durmaz. Eğer film tam da seyircinin aradığı miti hazır olarak veriyorsa, masal / imgesendromu s&uuml;rekli bir hızlanma/yavaşlama şeklinde &ccedil;alışır ve tıpkı Frankenstein gibi&nbsp;<b><i>Bogart&nbsp;</i></b>ve&nbsp;<b><i>James Dean</i></b>&nbsp;vakaları da yaratıcılarının kontrol&uuml; dışına &ccedil;ıkarlar.<b><i>&nbsp;Dean</i></b>&nbsp;ve&nbsp;<b><i>Bogart&nbsp;</i></b>&ouml;lmeden &ccedil;ok &ouml;nce ger&ccedil;ek olmayan varlıklar konumuna gelmişlerdir</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu duruma karşı duran&nbsp;<b>Two Weeks in Another Town</b>&nbsp;adlı filmiyle bir&nbsp;<b><i>Vincent Minelli</i></b>&nbsp;vardır. Burada, kendiliğinden s&uuml;rekli bir yaklaşımın tersine kendiliğnden yıkıcı tersine bir tutum s&ouml;z konusudur. Bu filme değer vermekte zorlanırız &ccedil;&uuml;nk&uuml; bu filmi beğenmek bizim ideal Amerikan sineması hakkındaki (ve y&ouml;netmenin kendisi hakkındaki) imgelerimize ters d&uuml;şen bir Hollywood imgesini&nbsp; kabul etmek anlamına gelecektir. Her filmine aynı değeri vermese de&nbsp;<b><i>Minneli&rsquo;</i></b>yi en iyi olarak g&ouml;ren bir kişi, bu zorlukla karşılaşmayacaktır. Ona g&ouml;re,&nbsp;<b>Two Weeks in Another Town</b>, belirsizliklerin maskesini kaldırmak i&ccedil;in neredeyse t&uuml;m kalbiyle &ccedil;aba g&ouml;stererek, durumun belirsizliğine eğilen bir filmdir (film i&ccedil;inde film, yanılsama i&ccedil;inde yanılsama) Donanımsız sinema seyircisinin aklı karışırken, bilin&ccedil;li ve bilgili seyirci, hızlı bir &ccedil;ift okumayla, herşeyi&nbsp; ger&ccedil;eğin ve yanılsamanın karmaşık bir diyalektiğine &ccedil;evirir. Ne yazık ki, bu,&nbsp;<b><i>Minneli</i></b>&rsquo;nin filmi ile&nbsp;<b><i>Antonioni&rsquo;</i></b>nin&nbsp;<b>La Signora Senza Camilie</b>&nbsp;filmi arasındaki temel farktır- Ger&ccedil;ek yoktur; ger&ccedil;ek sadece g&ouml;sterilen bir yanılsamadır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu noktada, sıradan bir seyirci ile daha iyi bir d&uuml;nya isteyen ve daha iyi bir tanım isteğiyle benim humanist diyeceğim kişi arasında a&ccedil;ık bir ilkesel farkla karşı karşıya geliriz. H&uuml;manist i&ccedil;in sinema ger&ccedil;eğin bir aynasıdır, ve t&uuml;m imgeleri doğal bir yanılsamadan ibaret olsa da bu imgeler yansıttıkları ger&ccedil;ek ile ilişkili olabilirler ve &ouml;yle de olmalıdırlar.Sinemadaki yansıma, ancak, ger&ccedil;eğin kabul edilebilir bir modelini sunduğu ya da ger&ccedil;eğe bağlandığı s&uuml;rece ilgin&ccedil; olabilir. Klasik, bir western ve klasik, saf olmayan bir m&uuml;zikal, ger&ccedil;ekle bağı k&ouml;t&uuml; ya da hi&ccedil; olmayan yanılsamalar sunar ve bu y&uuml;zden de ilgin&ccedil; değildirler. Sıradan bir seyirci i&ccedil;in, yanılsama, nedense sinemanın en &ouml;nde gelen temelidir ve sinema tarafından oynanan oyun bir sondur,bir anlam değil. Sinema sadece bir sel&uuml;loid şeriti değildir, aynı zamanda eğlencenin de bir birimidir. Ve u&ccedil; durumlarda, eğlence, tamamiyle kendine d&ouml;n&uuml;kt&uuml;r ve dışarıdaki şeylerle ancak baştan savma bir ilişkisiye gereksinim duyar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Rio Bravo</b>&nbsp;gibi bir film harikadır. &Ccedil;&uuml;nk&uuml; ilk olarak organik, artistik bir b&uuml;t&uuml;nd&uuml;r, kendi başına ayakta durur, kendi i&ccedil;inde tutarlıdır, uyumludur ve g&uuml;zel bir şekilde dengelenmiş ritmini izleyiciye zorla kabul ettirir İkincisi (ki bu daha tehlikeli bir varsayımdır) film, dış d&uuml;nyadaki ger&ccedil;eklerden değil bir sinema geleneğinden başlar. Ve film, dışarıdaki d&uuml;nyaya başvurmadan, sadece&nbsp;<b>Hawk</b><i>&rsquo;</i>ın diğer filmleri ya da diğer Western filmlerinin unsurlarıyla yargılanabilir.&Uuml;&ccedil;&uuml;nc&uuml; olarak, sıradan seyirci pek de &ouml;nemsemese de, insana dair bir iletisi olmakla birlikte (sıradan izleyici pek &ouml;nemsemese de) bu ileti son derece genelleştirilmiş bir iletidir. Sinemaya b&ouml;yle bir yaklaşım,sadece miti, sinemanın temel bir elemenaı olarak misafir etmek i&ccedil;in kapıları ardına kadar a&ccedil;makla kalmaz, sinemanın kendi b&uuml;t&uuml;n&uuml;n&uuml; bir mit yapar. Folklor geleneğinden beslenen bir film olan&nbsp;<b>Rio Bravo</b>&nbsp;sadece bir masal değildir ve b&ouml;ylece efsanevi ya da mitsel bir yapıyla kurulur. Ancak film,&nbsp; izleyicinin filmden ve genel olarak sinemadan beklediği ve arzuladıklarıyla ( ideal, kendi d&uuml;nyasına d&ouml;n&uuml;k, mitsel deneyim) şartlandırılmış, yapay bir forma sahiptir. Uyku vakti geldiğinde iyi babaların &ccedil;ocuklarına masal anlatığı gibi,&nbsp;<b>Hawk<i>s</i></b>&nbsp;i&ccedil;ten i&ccedil;e kendisinden beklenen r&ouml;l&uuml; yerine getirir ve izleyicinin taleplerini tatmin eder ; Peki, ya&nbsp;<b>Hawks<i>&nbsp;</i></b>arada sırada aynı hikayeyi iki kere anlatacak olsa ya da d&uuml;ş&uuml;n&uuml;p taşınıp bazı &ouml;zel beklentileri boşuna &ccedil;ıkarırsa, ve eğer &ccedil;ocuklardan biri arasıra &ldquo;&nbsp;<i>Babacığım o ger&ccedil;ekten sen değilmiydin, hani şu u&ccedil;aktaki adam, şu maceraperest</i>&rdquo; sorusunu sormaya y&ouml;nlendirilirse? İşte, bu oyunun tamamı budur. Ancak g&uuml;n&uuml;n birinde &ccedil;ocuklardan bazıları&nbsp;<b>Vico</b>&nbsp;veya&nbsp;<b>Hegel</b>&nbsp;ya da&nbsp;<b>Jung<i>&nbsp;</i></b>okumaya başlayacak ve bu oyunda b&ouml;ylece sona erecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Humanist ve sıradan izleyici arasında var olan derin iletişim boşluğu ne şaşırtıcıdır ne de &ouml;zellikle kaygı verici...&nbsp;<b><i>Funny Face</i></b>&nbsp;ve&nbsp;<b><i>La Terra Trema</i></b><i>&nbsp;</i>filmlerinin ikisini sevebilme kapasitesine sahip insanların olabilceği durumlarda, bu iki filmin kıyaslanmasının sa&ccedil;ma bir şey olacağı belli belirsiz tahmin edilir. Bu filmlerden sadece birisini seven insan, diğer filmi seven insanla bir ilişkisi olmayacağı konuma &ccedil;ekilir.Ve aramızda her iki filmi de sevenler, b&ouml;l&uuml;nm&uuml;ş kişiliklerimizi barıştırmak i&ccedil;in ıstırap dolu kişisel sınavlara y&uuml;z vermek i&ccedil;in y&ouml;nlendirilmeyiz. Ancak,&nbsp;<b><i>Funny Face&rsquo;</i></b>&nbsp;den hoşlanmak i&ccedil;in, radikal ve &ccedil;aba gerektiren bir inan&ccedil;sızlığın pratiğini yapmak, aklımı tamamen kapatmak, bildiğim ger&ccedil;ek Paris&rsquo;i unutarak filmde verilen mitsel Paris&rsquo;e kendimi hazırlamak, tamamiyle rahatlamak ve filmi, renk ve devinim bağlamında m&uuml;mk&uuml;n olduğunca soyut bir şekilde g&ouml;rmek zorunda olduğumu biliyorum. Bir eğlendirici rol&uuml;yle&nbsp;&nbsp;<b>Hicthcock</b>&nbsp;bunu talep eder, zorla empoze ederek işleri kolaylaştırır. Diğer taraftan,<i>&nbsp;<b>La Terra Trema</b>&nbsp;</i>s&ouml;zkonusu olduğunda izleyicinin,izleyicinin bir kenara atmak zorunda olduğu inan&ccedil;lar mitlerdir.Geri kalanlar i&ccedil;in, izleyici her zaman dışarıda varolan sorunlarla boğuşmaya &ccedil;ağrılır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Film, katarsis durumu proveke etmek i&ccedil;in, sorunları kwendi ama&ccedil;ları doğrultusunda c&ouml;zebilir. Ancak ger&ccedil;ek hayatta sorunlar halen orada durmaktadır. Teorik olarak bu iki deneyim şekli birbiriyle karşılaştırılamaz., ancak pratikte bunlar birbirini tamamlayıcı olarak d&uuml;ş&uuml;n&uuml;lebilir-</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">U&ccedil; durumlarla uğraştığımız ve eğlence sinemasını mitle, ger&ccedil;ek dışıyla ve kendine d&ouml;n&uuml;k fantazya deneyimiyle tanımlamayı becerdiğimiz s&uuml;rece..</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bu modeli &ccedil;alışmaz kılan şey şudur;&nbsp;<b><i>To Have and Have Not</i>,&nbsp;<i>Tirez sur le Pianiste</i>,&nbsp;<i>La Regle du</i></b><i>&nbsp;<b>Jeu</b></i><b>,&nbsp;<i>Ugestu,</i>&nbsp;<i>The Eclipse</i></b>&nbsp;gibi her iki u&ccedil;ta da bulunmayan, ancak her iki t&uuml;r seyircinin de sevdiği filmler bu iki u&ccedil; ortasında d&uuml;z bir satıhta ortaya &ccedil;ıkmazlar. Bu filmler daha &ccedil;ok sendromun değişik elemenlarının değişik seviyelerinde yer almaya eğilim g&ouml;sterirler.&nbsp;<b><i>Ugetsu,</i></b>&nbsp;gizli,a&ccedil;ığa vurulmamış bir ama&ccedil; doğrultusunda a&ccedil;ık s&ouml;ylemli masal formunu kullanır.&nbsp;<b>Tirez&nbsp;</b>ger&ccedil;ek&ccedil;ilik ve fantasya arasında, ve &ccedil;evresinde d&ouml;nd&uuml;ğ&uuml; a&ccedil;ık bir mit ile filmin şiirsel merkezi olan &uuml;st&uuml; kapalı bir mit arasında gidip gelir<b>.&nbsp;<i>La R&eacute;gle Du Jeu</i></b>&nbsp;m&uuml;kemmel bi&ccedil;imde ger&ccedil;ek&ccedil;idir, ancak ağlencenin formuna ve cazibesine de sahiptir.&nbsp;<b><i>To Have</i></b><i>&nbsp;<b>and Have Not</b>&nbsp;</i>eğlendiricidir ve&nbsp;<b>Bogart<i>&nbsp;</i></b>mitini gidebildiği yere kadar &ouml;ne s&uuml;rer, ancak bu durumda, ger&ccedil;ek&ccedil;i&nbsp;<b>Renoir</b>&rsquo;nın bile tuhaf olabileceği hesaba katıldığında da, bir tuhaflık yoktur. Son olarak&nbsp;<b><i>The Eclipse</i>,</b>&nbsp;artistik olarak ayakları &uuml;zerinde durur ancak her zaman daha geniş bir d&uuml;nyanın sorunlarına bakar, kendi i&ccedil;ine d&ouml;n&uuml;k olmaktan uzaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Olası kombinasyonların sayısı ve bu kombinasyon seviyeleri sonsuzdur ve model tarafından verilen kriter bu filmlerin neden iyi ya da k&ouml;t&uuml; olduğuyla son derece ilgisizdir. Bu mantıklı g&ouml;r&uuml;nebilir, b&ouml;ylece, model tamamiyle ortadan kaldırılabilir.Sorun kimsenin bunu yapmak istememesidir. İki yıl &ouml;nceki kritik bir tartışma,&nbsp;<b><i>Tanım ve Oxford G&ouml;r&uuml;ş&uuml;</i></b>&rsquo;n&uuml;n i&ccedil;ten i&ccedil;e &ccedil;ift kutupluluğu kabul ederek tarafını belirleyen ve karşı tarafı cephelerini bırakmaya zorlamak ve gerekirse yok etmek i&ccedil;in yaylım ateşine tutan iki tarafı i&ccedil;erdiğini s&ouml;yler. Son zamanlarda, bu savaş,daima temel bir karşı kutup &uuml;zerinde y&uuml;kselen ve anlaşmazlıklar alanında s&uuml;ren bir &ccedil;ekişmeye d&ouml;n&uuml;şm&uuml;şt&uuml;r. Yine bir soğuk savaşın i&ccedil;indeki taraflar, doğrusunu s&ouml;ylemek gerekirse, tarafsız bir b&ouml;lgenin ortasında film tanımlamalarını kendilerine uyarlamayı denemeye eğilim g&ouml;sterirler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bir western hatta bir m&uuml;zikal, ger&ccedil;ek hayat durumlarını aydınlatan ger&ccedil;ek&ccedil;i fimler olarak g&ouml;sterilebilir ve ideal modele asimile edilirken, humanist bunun kendi tanımlaması olduğunu iddia eder. Tersine, Caheirs okumuş donanaımlı bir seyirci, herhangi bir filmi hırsızlama şekilde kaplamak i&ccedil;in kendi alanını genişletir ve&nbsp;<b><i>Viridinia</i>&nbsp;</b>gibi bir filmi bir derecede kendi modeline uyarlayabilir ( iyi ve tatmin edici bir sinemanın i&ccedil;eriye d&ouml;n&uuml;k bir bakış ideali).. Bu, ortak olan alana, karşı tanımlamalarla bakma alışkanlığı, doğrudan uyumsuzluktan &ccedil;ok daha fazla bir kızgınlığı ortaya &ccedil;ıkarır. Bu da ka&ccedil;ınılır bir durumdur- ya da &ouml;yle olmalıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">U&ccedil; pozisyonların sadece &uuml;st&uuml; kapalı bi&ccedil;imde tutulduğunu s&ouml;ylemiştim. Bu pozisyonları kategorik olarak tutanların dergilerde yazanların t&uuml;m&uuml;n&uuml;n olmadığını s&ouml;ylemek daha yerinde olur. Aşırı humanist pozisyonu, sadece sinemaya arasıra giden ve onun hakkında bir duyguya sahip olmayan kişiler tarafından tutulur. Naif sinema delisi pozisyonu, rahatsız edici bir bi&ccedil;imde belirli filmlere &ccedil;ok d&uuml;şk&uuml;n olanlarca sahiplenilir. Bu, ne Movie&rsquo; de ne de Cahiers yazarlarının kesin ya da belli oranda a&ccedil;ığa vurulan bir pozisyonu değildir.Bu yazarlar benim donanımlı sinema sever demeyi tarcih ettiğim kişilerdir. Onlar, son d&ouml;nem&nbsp;<b>Andre Bazin</b>&nbsp;geleneğinde, naif pozisyonu terketmemişler, ancak &ccedil;eşitli yollarla bunu ge&ccedil;meyi ya da aşmayı ama&ccedil;lamışlardır.&nbsp;<b>Bazin</b>&rsquo;in en iyi halinde b&uuml;y&uuml;k ve sezgileri kuvvetli bir eleştirmendir ve ikincil olarak bir mitler katilidir.&nbsp;<b>Bazin</b>&nbsp;en k&ouml;t&uuml; halinde bir ahtapot gibi yazar, vantuslarını t&uuml;m y&ouml;nlerde herşeyi kucaklayacak şekilde t&uuml;m y&ouml;nlere uzatırlar. Ve &ldquo;sinemanın varoluşu onun &ouml;nde gelen &ouml;z&uuml;d&uuml;r&rdquo; ve &ldquo;T&uuml;m ger&ccedil;eklik tek bir plan &uuml;zerindedir&rdquo; gibi &ouml;nermelere d&ouml;n&uuml;şen anlaşılmaz koyu m&uuml;rekkep damlalarını fışkırtmıştır. Bu t&uuml;rden &ouml;nermelerin radikal uygulamaları,&nbsp;<b>Bazin</b>&rsquo;i ve onun takip&ccedil;ilerini hemen yanıbaşındaki naif sinemaseverlerin d&uuml;nyasını soğurmalarını ve başka bir değilse, sinemayı Kesin olanla birleştirmelerini sağlamıştır. Ne yazık ki ahtapot istiridyeyi yutmayı başarsa da hi&ccedil; bir zaman ilk &ouml;nce kabuğunu kırmayı başaramamıştır. Bazin&rsquo;in sineması tamamiyle kendine d&ouml;n&uuml;k kalmıştır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Metafizik jargon sinemanın ger&ccedil;ekle olan ilişkisini aydınlatmaktan uzaktır ve yeni sinemaseverin, biraz daha kafası karışmış ve akıl karıştırcı olmanın &ouml;tesinde, son bağlamda eskisinden pek bir farkı yoktur. Tamamiyle bağışık değilse de Movie metafizik &ccedil;ılgınlık konusunda babasından daha az ıstırap vermektedir. Cahiers&rsquo;e olan borcu, ana &ccedil;izgilerde dergideki karşı &ccedil;ıkma eğiliminedir. Bunun dışında naif pozisyona sıkı sıkıya bağlıdır. Eğer Movie yazarları incelemelrinde bir filmin i&ccedil;eriğini a&ccedil;ıklamak i&ccedil;in &ccedil;ok fazla yer bağışlıyorlarsa, bunun nedeni, i&ccedil;eriğin,perdede ger&ccedil;ekten neler olduğu ve kamera hareketleri ve yapıyla ilgili olmasıdır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Eğer onlar&nbsp;<b>Preminger<i>&rsquo;</i></b>in İsrail hakkında s&ouml;ylemek zorunda oldukları ve&nbsp;<b>Rosselini<i>&rsquo;</i></b>nin&nbsp;<b><i>Vanina Vanini</i>&rsquo;</b>de &ouml;zg&uuml;rl&uuml;k hakkında s&ouml;ylemek zorunda oldukları hakkında kafa yoruyorlarsa, bunun nedeni&nbsp;<b>Preminger</b>&rsquo;in<b><i>&nbsp;</i></b>(bu durumda belki&nbsp;<b><i>Rosselini&rsquo;</i></b>nin) bunu s&ouml;ylemesidir ve&nbsp;<b>Preminger</b>&nbsp;ve&nbsp;<b>Rosselini Donen<i>,&nbsp;</i>Minelli</b>&nbsp;ve&nbsp;<b>Hawks<i>&nbsp;</i></b>gibi&nbsp;<b><i>Doğru Kilise&rsquo;nin</i></b>&nbsp;&uuml;yeleridir. Bir&ccedil;ok peygambere sahip olsa da bir tane&nbsp;<b><i>Doğru Kilise</i></b>&nbsp;vardır ve neredeyse mistik ve tamamıyla Hermetik bir sinema deneyimi olan tek bir k&uuml;lt bulunur. Halen eksik duran şey istiridyenin kabuğunu a&ccedil;mak i&ccedil;in bir girişimin bulunmamasıdır. Şu an metafiziğin anaforu i&ccedil;inde yutulmamıştır, fakat yalan s&ouml;ylemesi i&ccedil;in bırakılmıştır.- dini saygının kutsanmış bir nesnesi ve naif bir şekilde yaratıcısının niyetini saygın bir yere koyması beklenen</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Ne&nbsp;<b><i>Cahiers</i></b>&nbsp;ne de&nbsp;<b><i>Movie</i></b>&nbsp;naif sinema delisi pozisyonunu aşmak ya da ge&ccedil;meye girişmemiş ve bu pozisyonu daha kabul g&ouml;r&uuml;r kılmak i&ccedil;in bir şey yapmamıştır. Ger&ccedil;ekte, hayranlığını saf sinemaya ayırmış olan sinemasever&nbsp;<b>Antonioni<i>,&nbsp;</i>Resnais</b>&nbsp;ya da&nbsp;<b>Bunuel<i>&rsquo;</i></b>i peşin peşin d&uuml;ş&uuml;nmeden seven donanımlı sinema seyircisinden daha g&uuml;venli bir yerdedir.&nbsp;<b>Antonioni&nbsp;</b>onu iletişimsizliğin denizine s&uuml;r&uuml;klediğinde veya&nbsp;<b>Bunuel<i>&nbsp;</i></b>burjuvazinin ikiy&uuml;zl&uuml;l&uuml;ğ&uuml;n&uuml; sirkeye batırılmış ıslak bir s&uuml;nger gibi suratına fırlattığında, ya da&nbsp;<b>Resnais<i>,</i></b>&nbsp;<b><i>Guarnica,</i>&nbsp;<i>Nuit et</i></b><i>&nbsp;<b>Broulliard</b></i><b>&nbsp;</b>veya&nbsp;<b><i>Hiroshima</i>&nbsp;</b>da ıstırapların hatırlatmasını bilincine batırarak yaptığında, donanımlı sinema seyircisi &ldquo; Ama bu sanat,hayat değil, sadece hayat değil ama sanat&rdquo; ağlayışına sığınamayacaktır.&nbsp;<b>Bazin Bunuel</b>&rsquo;in&nbsp;<b><i>Las Hurdes</i>&rsquo;</b>inin insan sefaletinin bir allegorisi olduğunu s&ouml;yler ve bu insan sefaleti, allegori i&ccedil;inde &ldquo;G&uuml;zellik&rdquo;e d&ouml;n&uuml;şm&uuml;şt&uuml;r.&nbsp;<b>Bazin<i>&nbsp;</i></b>yanılıyordu.<i>&nbsp;<b>Las Hurdes</b></i>&nbsp;bir metafor değil bir ger&ccedil;ektir ve g&uuml;zel falan da değildir<b>.&nbsp;<i>Las Hurdes</i>,</b>&nbsp;<b><i>Virdiana</i>,&nbsp;<i>Nuit at Broulliard</i></b>&nbsp;ve hatta&nbsp;<b><i>L&rsquo;Avventura</i></b>&nbsp;u&ccedil; durumlardır. Bazı filmler acıklı ve dokunaklıdır veya s&ouml;ylendiği &uuml;zere ıstırabı akla getirirler. Istırap &ccedil;ekmek b&uuml;y&uuml;k sanatın tek konusu da değildir. Ama tartışma değişmeden kalır. Filmlerin &ccedil;oğu, b&uuml;y&uuml;k ya da k&uuml;&ccedil;&uuml;k &ouml;l&ccedil;&uuml;de kendine d&ouml;n&uuml;k sinema deneyiminin sınırlarını aşarlar. Ve her film tek başına sinema tarafından sağlanan deneyimine bağlı olmaktan &ccedil;ok bir şekilde i&ccedil; veya dış deneyimin daha geniş alanlarına bağlıdır. Onu aştığı durumlarda bile sinema ger&ccedil;ek &uuml;zerindeki bir parazittir ve mitler bile ait olacağı bir d&uuml;nya olmadan ne iseler o olamazlar. Sinemayla uğraşmak, temelde akıl ve dış d&uuml;nya arasında ama aynı zamanda fantezi ve psikolojik d&uuml;zeydeki deneyim arasındaki karmaşık objektif ve subjektif&nbsp; ilişkilerle uğraşmak anlamına gelir. Bu yavan (veya yavanlıklar serisi) olabilir ve tekrarlamaya gereksinimi yoktur. Fakat benim dikkate aldığım bazı davranışlar rehberdir ve yavan, basmakalıp değildir ve bunu bir kez daha s&ouml;ylemekle bir şey kaybetmeyiz.</span></p>', 202, 63, 'Yazarlarımızdan', NULL, '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (76, 'ay-j231', 'dipten-gelen-yeni-dalga-yg', 'Dipten Gelen Yeni Dalga: YG', 'Kinorama 6, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 6, 2004</b></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&ouml;khan Erkılı&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">T&uuml;rk sineması denince akla gelen ilk isim, kelimenin tam anlamıyla bir marka. D&uuml;nya genelinde hemen hemen t&uuml;m kaynaklarda yer alan tek T&uuml;rk sinemacı olduğu s&ouml;ylencesi, b&uuml;y&uuml;k olasılıkla yeni tarihli kaynaklara bakılmadığı i&ccedil;in yinelenip duruyor. &Ccedil;ok iyi bir sinemacı olduğunu s&ouml;yleyenler, Batı&rsquo;nın vermiş olduğu &ouml;d&uuml;l ve destekleri kanıt olarak sunuyorlar. Acaba, <b>G&uuml;ney&rsquo;</b>le ilgili s&ouml;ylemlerinde sinemanın nerede, ka&ccedil;ıncı sırada durduğu tartışmaya a&ccedil;ık olan &ccedil;oğu Fransız olan bu amcalar olmasa, <b>G&uuml;ney</b>&rsquo;in ardında bu denli durabilirler mi? <b>G&uuml;ney</b> filmografisinin filmleri, bu dayanaklar olmadan, sinema tarihimizin en iyileri listelerinde kendilerine halen zirvede yer bulabilirler mi? Neden kendi gerek&ccedil;eli kararlarımızı &uuml;retmekte bu denli yeteneksiziz? Ve neden bundan en &ccedil;ok zarar g&ouml;ren, 20 yıl &ouml;ncesinde kalmış &ouml;l&uuml;m&uuml;yle, <b>Yılmaz G&uuml;ney</b>&rsquo;in sineması?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>YG </b>hakkında &ccedil;ok abuk sabuk tartışmalar yaşandı. Bir insanı sevip sevmemek, benimseyip benimsememek veya yakın durup durmamak kişiden kişiye değişir. Ondan bug&uuml;ne kalan ve yaşam ger&ccedil;eğini en yakından analiz etmemizi sağlayan en &ouml;nemli bulguları sinemasal yapıtları olduğuna g&ouml;re, bakmamız gereken pencere sinemanın penceresi. O &ccedil;ok tartışılan kişiliği, beni sinemaya yansıdığı y&ouml;n&uuml;yle &ccedil;ekiyor ve ilgilendiriyor. Yazılanlara baktığımda, b&uuml;y&uuml;k &ccedil;oğunluğun onu ve d&ouml;neminin koşullarını hi&ccedil; tanımadan atıp tuttuğunu, filmleri &uuml;zerine &ccedil;&ouml;z&uuml;mleme yapamamalarının ardında filmlerini anlamadan, hatta izlemeden ve yalnız bakmakla yetinerek yorum yapma alışkanlıklarının yattığını d&uuml;ş&uuml;nmeden edemiyorum.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Anlattığı olay, &ccedil;evre ve kişilerin derinlikli &ccedil;izilmesi ve onları yakından tanıdığının a&ccedil;ık olması, bir taraftan b&uuml;y&uuml;k adımlarla aşmaya &ccedil;alıştığı entelekt&uuml;el zayıflığının onu dur durak bilmeksizin hayata y&ouml;neltmesine, diğer yandan da yaratıcılığının g&uuml;ndemin peşine takılıp bile isteye tek y&ouml;nl&uuml; beslenmesine bağlanabilir. Yaşayan karakterleri, soluk alıp verdiğini işittiğiniz diyalogları ve &ouml;yk&uuml;lerini ger&ccedil;ek&ccedil;i kılma yetisi artılarıydı. Mesaj verme derdine d&uuml;şt&uuml;ğ&uuml;nde t&ouml;kezlemesi ve i&ccedil;inden ge&ccedil;eni filmlerine gelişig&uuml;zel serpiştirmesinin neden olduğu tutarsızlıklar ise eksileri. Onun sinemasında yoğun sezgilerinin ve d&ouml;nemsel gel-gitlerin rol&uuml; b&uuml;y&uuml;k. Bu nedenle, en uyduruk filmlerinde bile, beklenmedik bir anda yaratıcı bir patlama, bir pırıltı yakalamak ya da belleklerimize yerleşen bir bakış veya s&ouml;zle karşılaşmak m&uuml;mk&uuml;n. &Ccedil;&uuml;nk&uuml; yaşamın ta i&ccedil;inden gelen bir bakış ve duyarlılık taşıyor. Bu durum, d&uuml;nya &uuml;zerinde biricikliğine s&ouml;z s&ouml;ylenmez Anadolu ma&ccedil;oluğunu melodramlara nasıl taşıdığını, mahallenin yoksul koruyuculuğuna nasıl y&uuml;kseldiğini, erişte westernlerde asıl adama bizden bir kimliği nasıl aşılayabildiğini ve b&uuml;t&uuml;n bunların doğal bir sonucu olarak, kitlelerle nasıl &ouml;zdeşleşerek efsane bir oyuncu haline geldiğini de a&ccedil;ıklamakta. <b>G&uuml;ney</b>&rsquo;in yaşamı da filmlerinden &ccedil;ıkıp gelmişcesine bir yol izler. Filmlerinin etkisinde kalan halk yığınları mıdır yoksa kendisi midir?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Yaratıcı doğasının perdedeki dışavurumunu en doğru bi&ccedil;imiyle kendisinin yansıtabileceğini anladığında, soluğu kameranın arkasında da aldı. <b><i>Seyyit Han</i></b>, <b><i>Umut</i></b>, <b><i>Acı</i></b>, <b><i>Baba</i></b>, <b><i>Ağıt</i></b> ve <b><i>Umutsuzlar</i></b> filmleri, perdeye yoksulluğun, umutsuzluğun ve dipte olmanın zorluğunu ve anlaşılırlığı zor anlamını taşıdılar. Bu, bir anlamda, memleketin i&ccedil;inde bulunduğu politik a&ccedil;mazları, yetersizlikleri, yeteneksizlikleri, başıboşluğu, sahipsizliği de g&ouml;zler &ouml;n&uuml;ne sermek demekti ki ona y&ouml;nelik bir kuşku ve nefretin doğmasına neden oldu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Derken, dipten gelen dalga, y&uuml;zeye &ccedil;ıkıp, &uuml;n&uuml;n doğasında taşıdığı ve hayatında ilk kez karşılaşması nedeniyle hazırlıksız yakalandığı fırtınaya dur diyemeyince, hayatının, sonraları ağır karalamalara hedef olacak sakat adımları ardı ardına geldi. İşin i&ccedil;inde bir şekilde yer alan herkesin &ccedil;abasıyla bir siyasi ikon yaratıldı. <b>G&uuml;ney</b>, akıntıya kapılmış, s&uuml;r&uuml;kleniyordu. Aslına bakarsanız, durum, &ccedil;ok şey yapan adamın yanlışı da &ccedil;ok olur, durumuna bir başka &ouml;rnekti. Pazarlanmasından başarılı sonu&ccedil;lar sağlanan politik kimliğin ağırlığı da zamanla arttı. Taşıdığı haklılık, er ya da ge&ccedil;, bir egemen g&uuml;&ccedil; olarak, kendine diğerlerini hi&ccedil;leştirerek varlığını pekiştirecek oyuncaklar arayan Batı&rsquo;da karşılık bulacaktı. Bunu filmlerinin toplanma s&uuml;reci izledi. Bir &uuml;&ccedil;&uuml;nc&uuml; d&uuml;nya politik komedisi olarak, cezayı onun yerine filmleri &ccedil;ekti. Ve ne gariptir, toplatılan filmleri, yery&uuml;z&uuml;nden silinmeye &ccedil;alışılan varlığına inat, diğer sıfatları arasına &lsquo;sinema tarihinin en fazla haksızlığa uğrayan adamı&rsquo; sıfatını da ekleterek, prestij ve &ouml;nem kazandırdı. O, hep kendini yansıttığını, kendini taşıdığını sanıyordu. Oysa omuzlarında her zaman değişen dengeleriyle &ccedil;elişik imajlar taşıyordu. Bunun rotasını sinemasında g&ouml;zlemlemek m&uuml;mk&uuml;nd&uuml;r.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&uuml;ney</b>&rsquo;in d&uuml;ş&uuml;nce, yazı ve sinema &uuml;retiminin hayat &ccedil;izgisine koşut bir ivme sergilediğini kabul edersek, en dipten gelerek tanımı zor bir noktaya ulaştığı doğrudur. &Uuml;&ccedil; d&ouml;rt yıl &ouml;ncesinde kalmış bir ağız dalaşının taraflarınca s&ouml;ylenecek olursa, l&uuml;mpenlikten (!) uluslararası sinema d&uuml;nyasının auteurl&uuml;ğ&uuml;ne uzanan bir &ccedil;izgi bu. Saldıranların değersiz, d&uuml;zeysiz ve kişilik bunalımlarını a&ccedil;ığa vuran yorumları, sinema ve genel k&uuml;lt&uuml;rden yoksunluklarının bilmem ka&ccedil;ıncı sefer g&ouml;r&uuml;c&uuml;ye &ccedil;ıkmasını ve vasat kelimesinin yeniden tanımlanmasını zorunlu kılıyordu. Kanımca, <b>G&uuml;ney</b>&rsquo;in &ouml;zel yaşamına d&uuml;nden bug&uuml;ne s&uuml;ren saldırılar, onun sanat ve sinemasına d&ouml;n&uuml;k s&ouml;z s&ouml;yleyecek k&uuml;lt&uuml;rel bir birikime sahip olmamaktan kaynaklanıyor. Ancak bu soytarıca &ccedil;ıkışlar, bug&uuml;ne dek olageldiği gibi, d&ouml;n&uuml;p dolaşıp, <b>G&uuml;ney</b> imajını besler hale geliyor, bu da <b>G&uuml;ney</b> ile -yaşarken bile kendisine zor anlar yaşatan- imajı arasındaki makası daha da a&ccedil;ıp pop&uuml;leriteye hizmet ediyor. Ge&ccedil;mişe bakacak olursak, filmleri bolca konuşuldu, filmlerdeki imajı ve yaşamındaki &ccedil;alkantılar da &ouml;yle, ama <b>G&uuml;ney</b> ger&ccedil;eği bunların &ccedil;ok gerisinden geldi. Neden mi? Medya zibidileri bir sinemacıyı sinemasıyla yargılayamadıkları i&ccedil;in, Yılmaz&rsquo;ın <b>G&uuml;ney</b>&rsquo;iyle değil de P&uuml;t&uuml;n&rsquo;&uuml;yle uğraşabildikleri i&ccedil;in. Birileri tarihin &ccedil;&ouml;p sepetine g&ouml;m&uuml;l&uuml;rken, biri de ka&ccedil;ınılmaz olarak tarihe ge&ccedil;ecek. Sinemanın farkı da burada olsa gerek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Aynı sancılı ge&ccedil;miş kusurların erdemlere, sığlıkların yeteneğe ve cahilliğin bilgiye karıştığı bir g&ouml;r&uuml;n&uuml;m &ccedil;iziyor. Ama &ouml;nemli olan, kendisiyle kimliğinin &ouml;rt&uuml;şmemesinin bedelini halen &ouml;deyen <b>G&uuml;ney</b>&rsquo;in katettiği zorlu yol. Bu denli uzun bir yolun, dar alanda kısa paslaşmalar benzeri yazılarla kavranamayacağı, dolayısıyla anlatılamayacağı ve dolayısıyla hakkının verilemeyeceği a&ccedil;ıktır. Başlangı&ccedil; noktası, hani neredeyse sıfır noktası olup, eline kalem almış ve g&ouml;z&uuml;n&uuml; viz&ouml;re dayamış bir adamın aldığı yol, onun hakkında yazmış olanların aldığı yola bakınca g&ouml;z&uuml;me daha da hoş g&ouml;r&uuml;n&uuml;yor. İşin bir başka ilgin&ccedil; yanı, sinema yazarları dururken, k&ouml;şelerinde ne aradıklarını merak ettiğim bir&ccedil;ok k&ouml;şe yazarının kalemlerine sarılmış olmalarıydı. Onları anlıyorum, anlamadığım bizimkiler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>G&uuml;ney</b>&rsquo;in sinemasının T&uuml;rk sineması i&ccedil;inde nerede durduğu, nereden gelip nereye gittiği konusu &uuml;zerinde durulması gerekiyor. T&uuml;rk sinema tarihinin &uuml;zerine en &ccedil;ok yazı yazılmış y&ouml;netmeni olmasına rağmen, d&ouml;nemsel etkilenimleri ve etkileri &uuml;zerinde daha fazla durulması gerektiği kanısını taşıyorum. <b>G&uuml;ney</b> sineması i&ccedil;in <b>Atıf Yılmaz</b>&rsquo;ı at&ouml;lye, <b>L&uuml;tfi Akad</b>&rsquo;ı &ccedil;ıkış noktası olarak kabul edersek ve Anadolu k&uuml;lt&uuml;r&uuml;n&uuml; sinemaya taşıdığı s&uuml;recin folklorik bir halkası olan <b><i>Seyyit Han</i></b> ve sonrasını da kendi sinemasının olgunlaşma s&uuml;reci dersek, kendinden sonrasıyla ilgili hangi bağlantıları kurabiliriz? Doğrusu, <b>G&uuml;ney</b>&rsquo;in sineması d&ouml;nemin koşullarından fazlaca beslenen bir sinemaydı ve bu nedenle d&ouml;nemsel &ouml;zellikler taşıyordu. D&ouml;nemin dışına taşıldığında şematikleşme ve groteskleşme &ouml;zelliği vardı. Ona y&ouml;nelik &ouml;yk&uuml;nmelerin &ccedil;oğunun durumunu aydınlığa kavuşturan da bu saptama olsa gerek. <b>Hauff</b>, <b>Kusturica</b>, <b>Kazan</b> ve <b>Annaud</b>&rsquo;nun <b>G&uuml;ney</b> sinemasına nasıl baktığı &ouml;nemlidir ama sonu&ccedil;ta i&ccedil;imizden biri gibi bakamayacakları i&ccedil;in onların g&ouml;rd&uuml;ğ&uuml; farklıdır. <b>G&uuml;ney</b>&rsquo;e &ccedil;ok yakın gibi duran <b>Solanas</b>&rsquo;ın sinema ger&ccedil;eği bile farklı bir algı rotasındadır. Onların ve diğerlerinin ne dediği &uuml;zerinden yapılan onamalar, g&uuml;&ccedil;s&uuml;z ve kendine g&uuml;vensizin, nerede durduğunu bilemeyenin sığınma &ccedil;abası, kendini ispat etme saplantısıdır. Varsan varsındır ve &ouml;nemli olan bizim ne g&ouml;rd&uuml;ğ&uuml;m&uuml;zd&uuml;r. Ger&ccedil;ekten etkilenme var mıdır, doğrudan ya da zorlama? <b>Erden Kıral</b> <b><i>Kanal</i></b> ve <b><i>Bereketli Topraklar &Uuml;zerinde</i></b> ile, <b>Ali &Ouml;zgent&uuml;rk <i>Hazal</i></b> ve <b><span style="text-decoration: underline;">At</span></b>&rsquo;la, <b>Yavuz &Ouml;zkan </b><b><i>Maden</i></b>&rsquo;le veya <b>Tun&ccedil; Okan</b> <b><i>Otob&uuml;s</i></b>&rsquo;le bu etkilenmeye kanıt olarak g&ouml;sterilebilir mi? Belki bir iki &ouml;rnek daha verilebilir ama ilk anda aklıma gelenler bunlar oldu. Yoksa bu &ouml;rneklere, aynı <b>G&uuml;ney</b> sinemasında olduğu gibi, d&ouml;neme &ouml;zg&uuml; atmosferin bereketi olarak mı bakmalı?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Haklı haksız saptamalar ve yalan yanlış bilgilerle aldığı &ouml;d&uuml;ller de tartışma konusu yapıldı. S&ouml;zgelimi, bazı kaynaklarda <b><i>S&uuml;r&uuml;</i></b>&rsquo;n&uuml;n Londra FF&rsquo;nde en iyi film &ouml;d&uuml;l&uuml;n&uuml; kazandığı bilgisi var. Gelin g&ouml;r&uuml;n ki bu festivalin b&ouml;yle bir &ouml;d&uuml;l&uuml; hi&ccedil; olmadı. Hemen b&uuml;t&uuml;n uluslararası yarışmaların &ouml;d&uuml;l aritmetiğinde politik bileşenin belli bir ağırlığı, değişken bir dozajı vardır. Dozaj, sanatsal bileşenin eksiklerini kapatmak i&ccedil;in duyulan ihtiyaca g&ouml;re ayarlanır. <b><i>Yol</i></b>&rsquo;u yoldan &ccedil;ıkaran anlatı dili kusurlarının ve kapatılamayan teknik yetersizlik izlerinin doğurduğu boşluğun y&uuml;ksek dozda politik desteğe ihtiya&ccedil; duyması ka&ccedil;ınılmazdı. Anlaşılıyor ki bu itici g&uuml;&ccedil;, festival ortamında yakalanan r&uuml;zgarda fazlasıyla vardı. Cannes FF tarihi bu politik oyunun b&uuml;t&uuml;n renkleriyle oynandığına tanıklık eden &ouml;rneklerle doludur ve festivaller liginde her zaman ilk &uuml;&ccedil;te yer almasında, sansasyonelliğe tanıdığı prim kadar bunun da &ouml;nemli rol&uuml; vardır. <b>Şerif G&ouml;ren</b>&rsquo;in y&ouml;nettiği <b><i>Yol</i></b>&rsquo;un da bundan payını almasına şaşmamak gerek. Altın Palmiye &ouml;d&uuml;l&uuml; ikide bir olağan&uuml;st&uuml; hal &ouml;d&uuml;l&uuml;ne d&ouml;n&uuml;ş&uuml;r. Kaldı ki bazı j&uuml;ri &uuml;yelerinin &ouml;d&uuml;l kriterlerinde sinematografik değerlerden s&ouml;z etmiş olması da durumu tersinden okumayı gerekli kılan zorunlu bir itiraftır. <b>G&uuml;ney</b> sinemasının &ouml;d&uuml;lleri arasında ayakları yere sağlam basanını aramak gerekiyorsa, adres <b>Zeki &Ouml;kten</b>&rsquo;in <b><i>S&uuml;r&uuml;</i></b>&rsquo;s&uuml;n&uuml;n kazandığı 1979 Locarno FF Altın Leopar &ouml;d&uuml;l&uuml;d&uuml;r. Bu arada, bana &ouml;yle geliyor ki, <b><i>S&uuml;r&uuml;</i></b>, <b>Yılmaz G&uuml;ney</b> sinemasının ulaştığı en y&uuml;ksek noktayı temsil etmektedir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Cezaevinde kaldığı d&ouml;nemlerin onun &ouml;n&uuml;n&uuml; tıkadığı, sinemadan uzaklaştırdığı ve yapabileceklerini yapamadığı gibi genel bir kanı var. Bana tam tersi gibi geliyor. &Uuml;retiminin en yoğun ve en ses getiren d&ouml;nemi cezaevi yıllarına ait ya da ondan esinleniyor. Sanki bazı &ouml;nemli yapıtlar başka t&uuml;rl&uuml; ortaya &ccedil;ıkmazdı diyesim geliyor. Kaldı ki <b>G&uuml;ney</b>&rsquo;in filmlerinde başından beri bir cezaevi saplantısı var sanki. Oraları benden sorulur ya da bensiz olmaz gibi bir yaklaşım bu. Filmografisi bu &ccedil;ekim g&uuml;c&uuml;n&uuml; a&ccedil;ığa vuran &ouml;rneklerle dolu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">B&uuml;t&uuml;n bu a&ccedil;ıklamaların ardından, bir de <b>G&uuml;ney</b>&rsquo;in aşılıp aşılamadığı sorunu var. T&uuml;rk sinema tarihinde imajlarının toplamı a&ccedil;ısından aşılabilirliği g&uuml;&ccedil; olsa da sinemasının aşılmadığını s&ouml;ylemek ne denli inandırıcı olabilir? Bunu s&ouml;ylemekle haksızlık ettiğimiz y&ouml;netmenlerimiz yok mu? Bir başka a&ccedil;ıdan bakacak olursak, bunca yılın ardından, &ccedil;eşitli kuşaklara ait y&ouml;netmenlerimizle onu boy &ouml;l&ccedil;&uuml;şt&uuml;rme &ccedil;abaları, sinemamızın genel d&uuml;zeyinin d&uuml;ş&uuml;kl&uuml;ğ&uuml;ne veya tembelliğine dikkat &ccedil;eken tehlikeli bir g&ouml;sterge mi? Yoksa <b>G&uuml;ney</b> sineması, kendi d&ouml;nemine damgasını vurmasını sağlayan toplumsal, dramatik ve siyasal tercihleriyle, sonraki kuşakların karşılaştığı apolitik s&uuml;recin ve sosyal g&ouml;r&uuml;n&uuml;m&uuml; netlemeyi zorlaştıran hızlı değişimin ağırlığı altında ezilen yeni kuşak y&ouml;netmenlerin toplumdan uzak d&uuml;şmelerinin ve bireysel s&ouml;ylemlere sıkışıp kalmalarının keyfini mi s&uuml;r&uuml;yor? İmaj bolluğundan &ccedil;elişkiler yumağı haline gelen <b>G&uuml;ney</b>&rsquo;i ve sinemasını yerli yerine oturtup yolumuza devam etmek istiyorsak, bu sinemayı d&ouml;neminin koşulları &ccedil;er&ccedil;evesinde analiz etmeli ve tarihsel film eleştirisini g&ouml;reve &ccedil;ağırmalıyız. Artık, <b>Yılmaz G&uuml;ney</b>&rsquo;e, sinemamıza yaptığı olumlu katkılar nedeniyle, bir&ccedil;oklarınca esirgenen bir teşekk&uuml;r yollayarak, veda etmenin zamanıdır.</span></p>', 45, 63, 'Yazarlarımızdan', NULL, '2017-03-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (77, 'ay-j232', 'soylesi-jean-claude-carriere', 'Söyleşi: Jean Claude Carriere', 'Kinorama 7, 2004', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kinorama 7, 2004</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>CARRIERE: &ldquo;Her uyandığınızda babanızı &ouml;ld&uuml;r&uuml;n; annenize tecav&uuml;z, &uuml;lkenize de ihanet edin.&rdquo;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>S&ouml;yleşi: Atasay Ko&ccedil;</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><i>Jean Claude Carriere</i></b><i> 100&rsquo;&uuml; aşkın sinema filmine yazar olarak attığı imzayla d&uuml;nya sinemasının dev isimlerinden biri. Tabii onun &uuml;n&uuml; bu kadar sayıda &uuml;r&uuml;n vermesinden &ouml;te &uuml;r&uuml;nlerin kalitesinden doğuyor. <b>Luis Bunuel&rsquo;</b>den <b>Milos Forman</b>&rsquo;a, <b>Volker Schl&ouml;ndorff&rsquo;</b>ten <b>Terry Gilliam</b>&rsquo;a bir&ccedil;ok b&uuml;y&uuml;k y&ouml;netmenle &ccedil;alışmış ve denediği b&uuml;t&uuml;n farklı tarzlarda da başarılı olmuş biri. Dolayısıyla b&ouml;yle bir ismi bulunca kendisinden senaryo yazarlığı konusunda ipucu almak konusunda b&uuml;t&uuml;n eforumuzu sarfettik. Umarız bu s&ouml;yleşi geleceğin senaryo yazarları i&ccedil;in ihtiya&ccedil; duydukları ipu&ccedil;larını verecektir.</i></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Sinema tarihininde &ccedil;ok farklı tarzlarda &ccedil;alışan ancak hemen hepsi de başarıyı yakalamış bir&ccedil;ok y&ouml;netmen ile &ccedil;alıştınız ve hemen hepsiyle de başarıyı yakaladınız. Bunca başarının arkasında yatan sır nedir?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Sinema bi&ccedil;imi gereği &ccedil;ok farklı performans alanlarını i&ccedil;inde barındırma şansına sahip ve b&ouml;yle d&uuml;ş&uuml;n&uuml;nce de bir film i&ccedil;in yapılacak her &ccedil;aba değerlidir. Atılacak her adım &ouml;rneğin bir oyuncunun senaryoyu okuması, sahnenin &ccedil;izilmesi ya da fotoğraflanması, yazıya d&ouml;k&uuml;len her c&uuml;mle bizi filme daha da yakınlaştıracaktır. Arkadaş diyebileceğiniz bir akt&ouml;r varsa etrafınızda senaryonun ilk halini okutun. Bir oyuncu olarak kendisi de bir hareket katma ihtimalinin yanı sıra sizin seyirci koltuğundan bakarken g&ouml;rebileceğiniz eksiklikler veya diğer seyircilerin tepkisi senaryonuza bir&ccedil;ok şey katacaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>O zaman siz filme başlamadan &ouml;nce her şeyin yine zihinde bitmiş olması gerekliliğinden yanasınız?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Bazen, mesela radikal bir &ouml;rnek olarak Melies gibi, her bir kareyi &ouml;nceden &ccedil;izebilirsiniz. Bu t&uuml;r senaryoları biz kutsal kitap diye adlandırıyoruz. Bunlara dokunulamaz, y&ouml;netmen bile akt&ouml;rlerin y&ouml;nleri dışında bir şey değiştiremezler. Bir yandan da <b>Bunuel</b> gibi bir y&ouml;netmen de filmin &ccedil;ekileceği sahneyi g&ouml;rmeden hi&ccedil;bir hazırlığa girmezdi. Ben daha &ccedil;ok filme başlamadan &ouml;nce her t&uuml;rl&uuml; ihtimalin en azından d&uuml;ş&uuml;n&uuml;lm&uuml;ş olmasından yanayım.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Siz sadece &ouml;zg&uuml;n senaryolarınızla değil adaptasyonlarınızla ve tiyatro &ccedil;alışmalarınızla da tanınıyorsunuz. Farklı alanlarda &ccedil;alışmanın ne gibi farklılıkları var?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Her zaman i&ccedil;in &ouml;nemli olan sadece adaptasyon ya da tiyatro değil, <i>her eserde testtir</i>. Biz <b>Cyrano de Bergerac</b> i&ccedil;in <b>Gerard Depardieu</b> ile &ccedil;alışırken senaryo bitince hepsini kasete okumasını istedik ve bunun sonucunda senaryoyu ne kadar değiştirdiğimizi tahmin bile edemezsiniz. Başka bir yol da oyuna m&uuml;mk&uuml;n olan her bakış a&ccedil;ısından bakmak.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Her karakterin hatta en k&uuml;&ccedil;&uuml;ğ&uuml;n&uuml;n bile kimliğine girerek onların bakış a&ccedil;ılarından bakmak size hi&ccedil; aklınıza gelmeyecek olasılıkları bile g&ouml;rme imkanı verebilecektir. Bunun gibi sizin imkanlarınızla alakalı olarak ya da eksik g&ouml;rd&uuml;ğ&uuml;n&uuml;z noktalara &ccedil;&ouml;z&uuml;mler bulmak amacıyla kendiniz testler de &uuml;retin ve uygulayın, &ccedil;ok b&uuml;y&uuml;k faydasını g&ouml;receksiniz. Ama tiyatro ile sinema arasındaki fark i&ccedil;in s&ouml;yleyebileceğim bir şey <i>ger&ccedil;eklik</i>. En basiti <b>Cyrano De Bergerac</b>&rsquo;ı tiyatro oyunundan uyarlarken biz burnunu &ccedil;ok daha ger&ccedil;eğe yakın yapmak zorunda kaldık. &Ccedil;&uuml;nk&uuml; sinemanın imkanlarının fazlalığı ger&ccedil;eğe yakın olması konusunda imkanlar veriyor. Bunları kullanmayınca da seyirciye istediğiniz ortama &ccedil;ekme şansını bulamıyorsunuz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Filmografinize bakıldığında bir&ccedil;ok &uuml;nl&uuml; y&ouml;netmenle yapılmış &ccedil;alışmalar g&ouml;r&uuml;yoruz. Ama Bunuel adı daha bir &ouml;n plana &ccedil;ıkıyor ve neredeyse başarıyı yakaladığı her filmde sizin adınız da ge&ccedil;iyor. Bunuel&rsquo;le nasıl bir &ccedil;alışma ortamınız vardı?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Bunuel</b> benim hayatımda &ccedil;ok &ouml;nemli bir yer kaplıyor. Onunla &ccedil;alışırken daha &ccedil;ok herkesten, her t&uuml;rl&uuml; sorumluluktan kopacağımız ortamları se&ccedil;erdi. Sezona hazırlanan bir futbol takımı gibi kampa &ccedil;ekilir ve b&uuml;t&uuml;n g&uuml;n senaryo &uuml;zerine &ccedil;alışırdık. Bundan &ouml;nce s&ouml;ylediğim &ccedil;alışma tarzı da aslında ondan bana hatıradır. Onunla filmi izleyen iki seyirci ya da başka g&uuml;n filmden iki karakter kılığına girerek onlar gibi davaranır, kendi filmimizi dışardan g&ouml;zlerle &ccedil;&ouml;z&uuml;mlemeye &ccedil;alışırdık. Ama tabii her &ccedil;alışma arkadaşınızdan &ouml;ğrendikleriniz oluyor. Tabii Bunuel gibi g&uuml;&ccedil;l&uuml; karakterler de sizin &uuml;zerinizde daha &ccedil;ok etkide bulunabiliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Mesela ben nasıl deneysel olunabileceğini ve bunun size kazandırabileceklerini ondan &ouml;ğrendim. İlgin&ccedil;tir, <b>Bunuel </b>iyi eleştiriler almayı k&ouml;t&uuml;ye işaret sayardı. Bir filmi i&ccedil;in uzun s&uuml;re k&ouml;t&uuml; eleştiri yayınlanmamıştı ve bu da onu bayağı bir sıkıntıya sokmuştu. Neyse ki Newsweek&rsquo;te k&ouml;t&uuml; bir eleştiri yayınlandı da o da rahat bir nefes aldı.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>O zaman siz de deneysellikten yanasınız?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">&Ouml;yle tabii ama kuralları kırmadan &ouml;nce onu &ouml;ğrenmeli ve test etmelisiniz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Neden yazarlıkta kaldınız? Y&ouml;netmenliği denemek hi&ccedil; i&ccedil;inizden ge&ccedil;medi mi?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Y&ouml;netmenlik de yapmadım değil ama sonu&ccedil;ta benim &ccedil;alışma tarzım da her zaman prod&uuml;ksiyona da dahil olmak olduğu i&ccedil;in, film bitene kadar &ccedil;alışan bir elemanı olmak zaten beni tatmin ediyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Kısa film i&ccedil;in senaryo yazmakta ne gibi farklılıklar g&ouml;r&uuml;yorsunuz?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Temelde bir fark var denemez ama kısa filmde aynı miktarda hikayeyi geliştirmenize gerek yok. Her şey daha a&ccedil;ık olmalı ki seyirci karakterlerinizi &ccedil;ok daha kısa bir zamanda tanıyabilsin. Kısa filmde yoğun diyaloglar ve kompleks ilişkiler i&ccedil;in zaman yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b>Son olarak senarist olmak isteyenlere tavsiyeleriniz var mı?</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;">Her an a&ccedil;ık olsunlar. Demek istediğim tecr&uuml;be sahibi &ccedil;ocuklar olabilmek onlara her g&uuml;n yeni birka&ccedil; şey &ouml;ğrenme imkanı verecektir, hayat tecr&uuml;besi de bir senaristin hikayeleri i&ccedil;in en b&uuml;y&uuml;k kaynağıdır. Mesela ben Fransa da sumo g&uuml;reşi yayınlarına sunuculuk yapıyorum ve bu y&uuml;zden &ouml;ğrendiğim bilgileri bile &ccedil;alışmalarımda kullanabiliyorum. Başka bir nokta da hayalg&uuml;c&uuml;. Bunu ne kadar geniş tutabilirseniz o kadar orijinal &ccedil;alışmalar yapabilirsiniz. Her uyandığınızda babanızı &ouml;ld&uuml;r&uuml;n; annenize tecav&uuml;z, &uuml;lkenize de ihanet edin.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: arial, helvetica, sans-serif; font-size: 10pt;"><b><span style="line-height: 15.3333px;">Teşekk&uuml;rler&hellip;</span></b></span></p>', 203, 63, 'Yazarlarımızdan', NULL, '2017-03-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (78, 'ay-j197', 'aktor-tuncel-kurtiz', 'Aktör Tuncel Kurtiz', 'Burçak Evren', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><img src="/images/kitaplik/kurtiz.jpg" alt="kurtiz" width="236" height="228" style="margin-right: 20px; margin-bottom: 10px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Bur&ccedil;ak Evren</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Altın Koza Yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/252 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Oyuncu&nbsp;<b>Tuncel Kurtiz</b>&rsquo;in birbirinden ayrı tutulması zor ve anlaşılan o ki olanaksız olan &ouml;zel ve sanat hayatı &uuml;zerine kapsamlı izlenimi veren bir &ccedil;alışma. Ama sadece bu izlenimi vermekle kalıyor. Kısa zamanda toparlandığı belli ancak bu gerek&ccedil;e kitabın savunusunu yapmak i&ccedil;in yeterli değil, kaldı ki b&ouml;yle bir gerek&ccedil;e &uuml;retilemez. Kitap gelişig&uuml;zel bir derleme. Peki ama neden? Bir kitabı değil ancak bir yazıyı besleyebilecek &ccedil;apta bir biyografik derleme tercih edilmiş. Kaynaklar hatalı olunca ve yapılan alıntılar da kontrol edilmeyince ortaya eksik ve kopuk kopuk ilerleyen metinlerden oluşan bir yazı &ccedil;ıkıyor. Buna filmografi hataları ve bu hatalardan dolayı girilmeyen a&ccedil;ıklamalar da ekleniyor. G&ouml;rsel materyalin kullanımı belli bir estetik ve işlevsel se&ccedil;ime dayanmıyor. Edit&ouml;rl&uuml;k ve redakt&ouml;rl&uuml;k işlemleri ise tamamen unutulmuş. Son d&ouml;nemlerde &ouml;zellikle festivallerin &ccedil;ıkardığı, ambalajı g&ouml;sterişli, artistik puanları y&uuml;ksek, i&ccedil;eriği a&ccedil;ısından sayfa sayısı başına bir sorun d&uuml;şen, kurumların ne yapacaklarını bilemedikleri paralarıyla rezil olduğu cinsten bir şey. Bizim gibi okura d&uuml;şen: Biraz sinir bozukluğu, &uuml;st&uuml;ne de az &uuml;z&uuml;nt&uuml;. Sahiplenene d&uuml;şen: korkarız ki m&uuml;kemmel iş &ccedil;ıkardığını sanmanın dayanılmaz hafifliği.</span></p>', 62, 31, 'Sinema Kitaplığı', '/images/kitaplik/kurtiz.jpg', '2017-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (79, 'ay-j198', 'sinemasinin-aynasinda-turkiye', 'Sinemasının Aynasında Türkiye', 'oğuz demiralp', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/sinemanin_aynasinda_turkiye.jpg" alt="sinemanin aynasinda turkiye" width="255" height="391" style="margin-right: 20px; margin-bottom: 10px; float: left;" />oğuz demiralp</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">yky &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">2009/165 sf.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b>Doğu Şenkoy</b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">Demiralp&rsquo;in i&ccedil;ten, i&ccedil;inden geldiği gibi ve eleştirel bir sorgulama yerine perdeden i&ccedil; d&uuml;nyasına yansıyanları aktardığı bir kitap. Bu y&ouml;n&uuml;yle bireysel bir yansımalar toplamı. Tanımadığınız yazarla sıcakkanlı ve al&ccedil;akg&ouml;n&uuml;ll&uuml; s&ouml;ylemi sayesinde kalben bağ kursanız da yapıttan doyurucu tatlar alamıyorsunuz. Neden? Yazıların b&uuml;y&uuml;k &ccedil;oğunluğu bitmemişlik duygusu uyandırıyor, bir. Bazı yazılar değindiği filmin y&uuml;k&uuml;n&uuml; taşımaktan hayli uzak d&uuml;ş&uuml;yor, iki. Yazarını da aşan bir sorun olarak, kitabın editoryal ve redaksiyon &ccedil;alışmalarındaki &ouml;zensizlik sizi yavaş yavaş soğutuyor, &uuml;&ccedil;. Eleştirel bir yapıt arayanlara g&ouml;re olmasa da bireysel bir sinema yolculuğunun g&ouml;zlemci notlarında keyif arayanlara &ouml;nerilir.</p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/sinemanin_aynasinda_turkiye.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (80, 'ay-j199', 'kieslowski-ya-da-maddeci-teoloji', 'Kieslowski Ya Da Maddeci Teoloji', 'slavoj žižek', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><img src="/images/kitaplik/kieslowski.jpg" alt="kieslowski" width="227" height="304" style="margin-right: 20px; margin-bottom: 10px; float: left;" />slavoj žižek</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">encore yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">2009/111 sf.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b>Nagihan Konukcu</b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">Hayattaki en b&uuml;y&uuml;k korkusu &lsquo;kabul g&ouml;rmek&rsquo; olan bir adamın kitabı karşınızdaki. Bir y&uuml;z&uuml;&nbsp;<b>Lacan</b>&rsquo;a, bir y&uuml;z&uuml;&nbsp;<b>Hegel</b>&rsquo;e d&ouml;n&uuml;k s&ouml;ylemlerinin orijini bu defa&nbsp;<b>Kieslowski</b>.&nbsp;<b><i>Dekalog</i></b>&rsquo;larının On Emir&rsquo;le olan bağlantısı/bağlantısızlığı ile kendi i&ccedil; g&ouml;ndermeleri, birinin diğerini t&uuml;retmesi ya da belirsizleştirmesi bağlamında yaptığı sunum ile s&ouml;ze girer&nbsp;<b>Zizek</b>. Bu kitabın yazılış nedeninin salt&nbsp;<b>Kieslowski</b>&rsquo;yi, onun sinemasını ya da sinemasallığını irdelemek olmadığı ortada. T&uuml;mevarımcı bir y&ouml;ntemle, dinin ger&ccedil;ekliğini belli tinsel ve dogmatik inan&ccedil;lardan değil, h&uuml;manist boyutunu saklı tutmak koşuluyla sistemlerin politik, ekonomik ve psikanalitik tabanından g&uuml;&ccedil; alarak kazandığını ispata girişen&nbsp;<b>Zizek</b>, bunu da en somut şekliyle, tanrıyı kişilikleştirerek aramızda dolaştırmak suretiyle&nbsp;<b>Kieslowski</b>&rsquo;nin yaptığının altını &ccedil;izer bir bakıma.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">Kitabın hemen t&uuml;m b&ouml;l&uuml;mlerinde&nbsp;<b>Kieslowski</b>&nbsp;filmlerindeki benzeş konular, karakterler ve roller &uuml;zerinden başka sinema yapıtlarına ilişkin sunduğu &ouml;rneklemlerle&nbsp;<b>Zizek</b>, insanın hayattaki se&ccedil;imlerinde ahlak-etik, zayıflık-g&uuml;&ccedil;, g&ouml;rev-ama&ccedil;-yaşam, seks&uuml;ellik-politika-psikoloji eksenli bir hat &uuml;zerinden gittiği yolları betimler. Referans aldığı filmler yoluyla ger&ccedil;ekliğin ve insanın se&ccedil;imlerinin değişkenliğini ortaya koyarken,&nbsp;<b>Kieslowski</b>&nbsp;filmlerinde ise ortak yapıdaki karakterlerin bakış a&ccedil;ılarının değişmesi ile ger&ccedil;ekliğin ve se&ccedil;imlerin sadece g&ouml;recelik kazandığını g&ouml;sterir.&nbsp;<b><i>&Uuml;&ccedil; Renk &Uuml;&ccedil;lemesi, Veronique&rsquo;in &Ccedil;ifte Yaşamı, Aşk &Uuml;zerine Kısa Bir Film, &Ouml;ld&uuml;rme &Uuml;zerine Kısa Bir Film, No End</i></b>&nbsp;gibi&nbsp;<b>Kieslowski</b>&nbsp;sinemasının mihenk taşı filmlerinde kadın-erkek bakışını ters k&ouml;şeye yatırarak, birinin diğeri &uuml;zerinden varolma ya da ortadan kalkma bi&ccedil;imlerini tartışır. Ancak&nbsp;<b>Zizek</b>&rsquo;in s&ouml;z konusu ettiği filmlerin &ouml;yk&uuml;lerinin ve bunlara eklemlediği yorumların ardından sizi rahat bırakacağını sanıyorsanız, yanılıyorsunuz. &Ccedil;&uuml;nk&uuml;&nbsp;<b>Kant</b>,&nbsp;<b>Kleist</b>&nbsp;ve&nbsp;<b>Freud</b>&nbsp;gibi isimleri anmamak ve onların fikirlerine de yer vermemek olmazdı. Bu y&uuml;zden bu kitabı ayaklarınız yere basarken ve noktasına virg&uuml;l&uuml;ne okumanızda fayda var. Kaldı ki bir kitabı &ouml;ncelikle son sayfalarına g&ouml;z atarak okuma alışkanlığı olanlar i&ccedil;in, notlar b&ouml;l&uuml;m&uuml; bile i&ccedil;eriğin neler vaat ettiğine dair bir &ouml;ng&ouml;r&uuml; sağlayabilir.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b>Kieslowski</b>&nbsp;sineması insanın ve tanrının se&ccedil;imleri arasındaki karşıtlıkların &uuml;zerine kuruludur.&nbsp;<b>Kieslowski</b>&rsquo;nin senaryo ve filmlerindeki farklılığı besleyen de g&ouml;r&uuml;nt&uuml;n&uuml;n hayata ge&ccedil;işinde bu ilişkilenmenin yarattığı gerilimdir. İşte bu y&uuml;zden kitabın sarsıntısı da kısa ama şiddetlidir.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">&Ouml;zetin &ouml;zeti:&nbsp;<b><i>Kırmızı</i></b>&rsquo;nın ardından olta-kitap eşlikli bir yaşamın tercih edilmesinin sırasıdır deyip inzivaya &ccedil;ekilen&nbsp;<b>Kieslowski</b>, filmlerinde g&ouml;sterdiklerini bu defa kendisi deneyimler. Ancak talihi filmlerindekinden &ccedil;ok da farklı olmaz, kendi kendisinin tanrısı olma erdemini boşa &ccedil;ıkarır. Film &ccedil;ekmeden hayatta kalamamıştır; &ccedil;&uuml;nk&uuml; son emre kulak vermemiştir:&nbsp;<i>&lsquo;Benden başka Tanrın olmayacak!&rsquo;</i></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/kieslowski.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (81, 'ay-j200', 'matrix-ya-da-sapkinligin-i-ki-yuzu', 'Matrix ya da Sapkınlığın İki Yüzü', 'slavoj žižek', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><img src="/images/kitaplik/matrix_450x654.jpg" alt="matrix 450x654" width="450" height="654" style="margin-right: 20px; margin-bottom: 10px; float: left;" />slavoj žižek</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">encore yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">&ccedil;ev: bahadır turan</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;">2009/102 sf.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b>Burcu Atahan</b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b>Žižek</b>, bu kitapta&nbsp;<b><i>Matrix</i></b>&rsquo;in ne olduğunu Lacancı &ldquo;B&uuml;y&uuml;k &Ouml;teki&rdquo; kavramı &uuml;zerinden a&ccedil;ıklayıp,&nbsp;<b>Matrix</b>&rsquo;in de aynı şekilde&nbsp;<b>Lacan</b>&rsquo;ın izinden y&uuml;r&uuml;meye başlayıp sonra neden t&ouml;kezlediğini&nbsp;<b>Lacan</b>&rsquo;ın d&uuml;ş&uuml;nceleri ve&nbsp;<b><i>Matrix</i></b>&rsquo;in savunmaya &ccedil;alıştığı kanıtlar &uuml;zerinden a&ccedil;ıklamaya &ccedil;alışır.&nbsp;<b><i>Matrix</i></b>&rsquo;in kendi i&ccedil;indeki tutarsızlıkları ve ortaya koyduğu iddiaları temellendirmeye &ccedil;alışırkenki dayanaklarıyla nasıl &ccedil;eliştiğini, filmden &ouml;rneklerle anlatır. &ldquo;B&uuml;y&uuml;k &Ouml;teki&rdquo;yi&nbsp;<b>Habermas</b>&rsquo;ın iletişimsel cemaatiyle de &ouml;rt&uuml;şt&uuml;rerek a&ccedil;ıklar.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b>Žižek</b>,&nbsp;<b>Lacan</b>,&nbsp;<b>Kant</b>&nbsp;ve&nbsp;<b>Hegel</b>&rsquo;e g&ouml;re &ldquo;<i>Ger&ccedil;ek</i>&rdquo;in ne olduğunu tartışıp bunu&nbsp;<b><i>Matrix</i></b>&rsquo;in matriksi &uuml;zerinden değerlendirir. Bu değerlendirmeyi yaparken&nbsp;<b>Levi Strauss</b>&rsquo;un&nbsp;<i>Yapısal Antropoloji</i>&rsquo;sinden &ouml;rnek bir &ccedil;&ouml;z&uuml;mlemeye başvurur. Bu &ccedil;&ouml;z&uuml;mlemede simgesel kodların devreye girmesiyle&nbsp;<b>Saussure</b>&rsquo;un klasik şemasının&nbsp;<b>Lacan</b>&nbsp;tarafından değiştirilerek vardığı sonu&ccedil;la birleştirip tekrar&nbsp;<b>Strauss</b>&rsquo;un analizindeki &ldquo;<i>Ger&ccedil;ek</i>&rdquo;e d&ouml;ner. Buradan sanattaki &ldquo;<i>Ger&ccedil;ek</i>&rdquo;e ge&ccedil;er. &Ccedil;ağdaş sanatın&nbsp;<i>imgesel-simgesel-ger&ccedil;ek</i>&nbsp;olmak &uuml;zere &uuml;&ccedil; boyutunun olduğunu; bu &uuml;&ccedil; boyutun ise yeniden &ldquo;<i>Ger&ccedil;ek</i>&rdquo; &uuml;zerinden tanımlandığına işaret eder.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">İnsanın zihniyle bedeni arasındaki ilişkinin &ldquo;Matrix&rdquo; ve &ldquo;Ger&ccedil;ek&rdquo; ayrımıyla Neo ve Morpheus &uuml;zerinden tanımlanamayıp (ya da yanlış tanımlanıp); bunun Ajan Smith&rsquo;in ağzından <i>Freudyen</i> ifadeyle az bu&ccedil;uk kotarılmaya &ccedil;alışıldığının altını &ccedil;izer.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b>Žižek</b><i>,&nbsp;</i><b>Matrix</b>&nbsp;&rsquo;in matriksten tamamen &ccedil;ıkmayı vaat edip sonrasında insanların bu matriks i&ccedil;inde kalmaya mahkum k&ouml;leler olduğunu dile getirerek&nbsp;<b><i>Matrix</i></b>&rsquo;in insanları matriksten kurtarmak i&ccedil;in bir &ccedil;&ouml;z&uuml;m getirmemesini ise&nbsp;<b>Adorno</b>cu yaklaşımla ele alır.</p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;">Sonu&ccedil; olarak&nbsp;<b>Žižek</b>&rsquo;e g&ouml;re&nbsp;<b><i>Matrix</i></b>&rsquo;te tutarsızlıklarla &ouml;r&uuml;len d&uuml;ş&uuml;nce&nbsp;<b><i>Matrix Reloaded</i></b>&rsquo;ta daha da tutarsızlaşarak katılaşır ve bu tutarsızlık karmaşasının i&ccedil;inden &ccedil;ıkılamayarak&nbsp;<b><i>Matrix Revolutions</i></b>&nbsp;filminde b&uuml;t&uuml;n&uuml;yle alt&uuml;st olup ellerinde patlar. Ve bu,&nbsp;<b><i>Matrix</i></b>&nbsp;efsanesinin de sonu olur.</p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/matrix_450x654.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (82, 'ay-j201', 'david-lynch-ya-da-gulunc-yucenin-sanati', 'David Lynch ya da Gülünç Yücenin Sanatı', 'slavoj žižek', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><img src="/images/kitaplik/lynch.jpg" alt="lynch" width="264" height="392" style="margin-right: 20px; margin-bottom: 10px; float: left;" />slavoj&nbsp;<span style="font-size: 13px;">ž</span>ižek</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">encore yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><span style="font-size: 13px;">&ccedil;ev: sabri g&uuml;rses</span></span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">2009/79 sf.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><span style="font-size: 10pt;"><b>Serap Zeren</b></span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Žižek</b>&nbsp;tanınmış y&ouml;netmenlerden&nbsp;<b>David Lynch</b>&rsquo;in k&uuml;lt filmlerinden&nbsp;<b><i>Lost Highway</i></b>&rsquo;a odaklandığı kitabında fantezi ve ger&ccedil;ekliğin sınırlarına, Hollywood Prod&uuml;ksiyon Yasasına, İ&ccedil;kin İhlal Yasasının getirdiklerine, klasik ve neo-noir t&uuml;rlerinin yarattığı femme fatale karakterler arasındaki farka ve filmlerdeki ikircikli yapıya değinerek zengin bir tartışma alanında ger&ccedil;ekleşen bir a&ccedil;ılış yapmakta. &Ouml;ncelikle bu konuları başka filmler ve karakterler &uuml;zerinden karşılaştırmalar yaparak ele alır, sonra bu &ccedil;er&ccedil;eve i&ccedil;erisinde&nbsp;<b>Lynch</b>&rsquo;in&nbsp;<b><i>Lost Highway</i></b>&nbsp;filmini Lacan&rsquo;cı bir okuma sistemiyle &ccedil;&ouml;z&uuml;mler. Ancak bu &ccedil;&ouml;z&uuml;mlemeyi&nbsp;<i>post kuramcı</i>&nbsp;kimliğini Lacan&rsquo;cı sinema incelemelerinin kapsamlı bir reddi &uuml;zerine kuran son d&ouml;nem bilişselci sinema incelemelerine eğilerek yapar.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Klasik-noir ve neo-noir t&uuml;rlerinin femme fatale karakterlerini &ouml;rnekler vererek karşılaştırırken, klasik-noir femme fatale &ouml;rneklerini ataerkil egemenliğin fantazmatik desteği olarak g&ouml;r&uuml;r. Neo-noir femme fatale &ouml;rneklerinin de doğrudan sahneye konulmasının dışında pek farklı olmadığını &ouml;ne s&uuml;rer. Ve femme fatale&rsquo;nin her iki versiyonu da Žižek&rsquo;e g&ouml;re kusurludur, ideolojik tuzağa d&uuml;şm&uuml;şt&uuml;r. Yine ona g&ouml;re&nbsp;<b><i>Lost Highway</i></b>&nbsp;filmi, klasik ve post-modern noir t&uuml;rlerinin femme fatale kimlikleri arasındaki karşıtlık &uuml;zerine yorum yapar. Bu başarısı&nbsp;<b>Lynch</b>&rsquo;in başka bir yapıtı olan&nbsp;<b><i>Blue Velvet</i></b>&nbsp;ile karşılaştırılır ve bu karşıtlık&nbsp;<b>Hitchcock</b>&rsquo;un&nbsp;<b><i>Psycho</i></b>&rsquo;sundaki karşıtlığa benzetilir.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;">Yazar&nbsp;<b><i>Lost Highway</i></b>&rsquo;in fantazmatik &ccedil;ıkış yolunun sahte bir &ccedil;ıkış yolu olduğunu, hayal edilebilen b&uuml;t&uuml;n evrenlerde bizi bekleyen b&uuml;t&uuml;n şeylerin başarısızlık olduğunu &ouml;ne s&uuml;rer. Film &ccedil;&ouml;z&uuml;mlemesinde kişilik d&ouml;n&uuml;ş&uuml;mlerini de bu zeminde ele alır ve bu d&ouml;n&uuml;ş&uuml;m&uuml;n filmde nasıl cinsiyet&ccedil;i bir sosyal tanıma neden olduğuna dikkat &ccedil;eker.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif;"><span style="font-size: 10pt;">Film fantezi &uuml;zerine kurulmuştur ve bize fantezinin nerede başlayıp, ger&ccedil;ekliğin nerede sona erdiği sorusunu sordurur. Doğrudan psikanalitik okumanın sınırları oluşur, film belli &ouml;l&ccedil;&uuml;lerde de Stalinist terimlerle a&ccedil;ıklanır. &Ccedil;&ouml;z&uuml;mleme, etkileyici olduğu tartışılmaz &uuml;&ccedil; sahneye odaklanarak ger&ccedil;ekleşir. Sonu&ccedil; olarak, derdi &ccedil;&ouml;z&uuml;mleme olanın dikkatini vermesi gereken bir &ccedil;alışma.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/lynch.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (83, 'ay-j202', 'hitchcock-ya-da-bir-filmi-yeniden-cekmenin-ozel-bir-yolu-var-mi', 'Hitchcock ya da Bir Filmi Yeniden Çekmenin Özel Bir Yolu Var Mı?', 'slavoj žižek', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana;"><img src="/images/kitaplik/hitchcock_453x650.jpg" alt="hitchcock 453x650" width="453" height="650" style="margin-right: 20px; margin-bottom: 10px; float: left;" /></span></b><span style="font-size: 10pt; font-family: Verdana;">slavoj žižek</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;">encore yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;"><span style="font-size: 13px;">&ccedil;ev: sabri g&uuml;rses</span></span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">2009/93 sf.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><span style="font-size: 10pt;"><b>G&ouml;khan G&ouml;kdoğan</b></span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Lacan</b>&nbsp;ve&nbsp;<b>Hegel</b>&nbsp;tartışmayı yaşam bi&ccedil;imi haline getirmiş &uuml;nl&uuml; Slovak d&uuml;ş&uuml;n&uuml;r&nbsp;<b>Slavoj Žižek</b>&rsquo;in&nbsp;<b>Hitchcock</b>&nbsp;sinemasını ele aldığı ve onun sinemasının b&uuml;y&uuml;s&uuml;n&uuml; a&ccedil;ıklamaya &ccedil;alıştığı, bu sırada <b>Shakespeare</b>&rsquo;den <b>Orwell</b>&rsquo;e, <b>Bentham</b>&rsquo;dan <b>Dickens</b>&rsquo;a ve <b>Wagner</b>&rsquo;den <b>Lacan</b>&rsquo;a &ccedil;eşitli yaratıcılar ve d&uuml;ş&uuml;n&uuml;rlerle paslaştığı &ccedil;alışma.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;">Eserin bir b&ouml;l&uuml;m&uuml;nde,&nbsp;<b>Hitchcock</b>&rsquo;un bir &ouml;yk&uuml;den yola &ccedil;ıkarak buna sinemasal bir dil oluşturmadığını, aksine kendini esir alan bazı imgeleri hayata ge&ccedil;irebilmek i&ccedil;in &ouml;yk&uuml; yazdığını s&ouml;yleyerek s&ouml;ze başlayan&nbsp;<b>Žižek</b>, bu imgelerin k&ouml;keninde yatan libidinal enerjiyi&nbsp;<b>Lacan</b>&rsquo;dan aldığı destekle masaya yatırıyor. Bu sırada&nbsp;<b>Wagner</b>&rsquo;in operalarındaki ve&nbsp;<b>Stalin</b>&rsquo;in son anlarındaki&nbsp;<b>Hitchcock</b>&rsquo;la y&uuml;zleştiriyor bizi.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;">Nasıl ki&nbsp;<b>Dickens</b>, romanlarında kullandığı, paralel kurgu ve sinemadaki yakın &ccedil;ekime denk d&uuml;şen &ouml;ğelerle, sinematografiden &ouml;nce sinemayı d&uuml;şleyen adam olarak anılıyor ise,&nbsp;<b>Hitchcock</b>&nbsp;da filmlerindeki &ccedil;oklu sonlar ile (iki farklı sonun diyalektik bir sonucu olan asıl final) g&uuml;n&uuml;m&uuml;z dijital evrenini &ouml;nceden haber veren sanat&ccedil;ılar arasında g&ouml;steriliyor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;">Kayıp bakış b&ouml;l&uuml;m&uuml;nde ise,&nbsp;<b>Žižek</b>,&nbsp;<b>Hitchcock</b>&rsquo;un i&ccedil;indeki&nbsp;<b>Lacan</b>&rsquo;ı bir kez daha g&uuml;n y&uuml;z&uuml;ne &ccedil;ıkarır. Roma d&ouml;neminde, eski su kemerlerinin &uuml;zerinde bulunan heykellere, yer seviyesinden g&ouml;z&uuml;kmeyeceğini bile bile, ince ince işlemeler yapan, o olanaksız bakışın (<b>Žižek</b>&rsquo;e g&ouml;re fantazmatik bakış) bağımlıları gibi,&nbsp;<b>Hitchcock</b>&nbsp;filmlerini izleyen bizlerin de&nbsp;<b>Lacan</b>&rsquo;cı bakış kuramı uyarınca (izleyen &ouml;zneye karşılık nesnenin bakışı), bu y&uuml;ce deneyimini yaşadığımızı iddia eder&nbsp;<b>Žižek</b>.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Žižek</b>&nbsp;eserde yer yer sinema tarihindeki&nbsp;<b>Hitchcock</b>&nbsp;yeniden yapımları ve&nbsp;<b>Hitchcock</b>&nbsp;sinemasına saygı duruşu i&ccedil;eren sahneler &uuml;zerinden, ideal bir &lsquo;<b>Hitchcock</b>&nbsp;yeniden yapımı&rsquo;nın kendince nasıl olması gerektiğini de irdeler.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-family: Verdana; font-size: 10pt;">Kitap,&nbsp;<b>Malevich</b>&rsquo;in &uuml;nl&uuml; siyah kare tablosu misali,&nbsp;<b>Hitchcock</b>&nbsp;filmlerindeki, bizi su&ccedil;larımızdan kurtardığını sandığımız o farklı ontolojik d&uuml;zene ge&ccedil;iş olarak hizmet eden siyah kareleri d&uuml;ş&uuml;nmemizi sağlar. İşte tam da bu sırada&nbsp;<b>Hitchcock</b>&nbsp;filmlerinde, bizi filme bağlayan o &ouml;zenle kurulmuş olay &ouml;rg&uuml;s&uuml;nden &ccedil;ok daha fazlasının olduğunu bir kez daha fark ederiz.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0.0001pt; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt;"><b>Žižek</b>&rsquo;in &ouml;zellikle&nbsp;<b><i>Psycho&nbsp;</i></b>(1960) filmi &uuml;zerine yaptığı a&ccedil;ılımlar kitabın en keyifli b&ouml;l&uuml;mleri. Farklı disiplinler arası yaptığı ge&ccedil;işlerle zenginleşen bu&nbsp;<b>Žižek-Hitchcock-Lacan</b>&nbsp;birlikteliğinden ağzımızda kalan son tat ise,&nbsp;<b><i>Psycho</i></b>&nbsp;filmindeki Bates Motel&rsquo;in mimari yapısı ile ilgili, yine&nbsp;<b>Žižek</b>&rsquo;in sinema ile bambaşka bir alanı bir araya getirdiği iddia oldu: &lsquo;<i>Eğer Bates Motel, Norman&rsquo;ın annesinin eski evi ile d&uuml;z modern motelin doğrudan melez bir yeni tasarımı halinde birleştirilmesiyle inşa edilmiş olsaydı, Norman&rsquo;ın kurbanlarını &ouml;ld&uuml;rmesine gerek kalmayacaktı.</i>&rsquo;</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/hitchcock_453x650.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (84, 'ay-j203', 'turk-sinemasi-ve-din', 'Türk Sineması ve Din', 'Yalçın Lüleci', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/ts_ve_din.jpg" alt="ts ve din" width="266" height="401" style="margin-right: 20px; margin-bottom: 10px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Yal&ccedil;ın L&uuml;leci</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Es Yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/220 sf&nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">&Ccedil;alışma alanını sinema ve din ilişkisi olarak belirlemiş, kapalı bir kitle i&ccedil;inde &uuml;reticisi ve t&uuml;keticisi aynı kaynaktan beslenen, &uuml;reticisinden t&uuml;keticisine iletişim s&ouml;zc&uuml;s&uuml; olarak g&ouml;revli kılınan filmler ve &uuml;retim anlayışı &uuml;zerine bir kitap.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Dinin g&ouml;rsel sanatlar, sinema ve T&uuml;rk sineması ile s&uuml;rd&uuml;rd&uuml;ğ&uuml; ilişkinin a&ccedil;ıklanmasının ardından ulusal sinemadaki eğilimlerden akımlar başlığı altında s&ouml;z ediliyor. Bu ayrımda 1950&rsquo;lerde ger&ccedil;ekleştirilen bazı filmler milli/dini sinema i&ccedil;in &ouml;nc&uuml; olarak tanımlanıyor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Dinle ilişkilendirilen filmlerin 2000&rsquo;lerde yapılanları &uuml;zerine geniş ve ayrıntılı tanıtım, alıntı ve eleştiriler yapılmışken, &ouml;nceki yıllarda &ccedil;ekilen ve milli/dini sinemayı anlamak i&ccedil;in &ccedil;ok daha &ouml;nem taşıyan filmler kavram ve konu başlıklarına indirgenmiş &ccedil;er&ccedil;evelerde tartışılıyor. Ve olduk&ccedil;a yetersiz olan bu yazılar salt bir film veya bir y&ouml;netmen &uuml;zerine odaklanıyor. Yazarın merakla beklediğimiz kendi yorumları ise yok. Alıntılar dur durak bilmeksizin alıntıları izliyor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Kitabın son s&ouml;z&uuml;n&uuml;n yazarı ve edit&ouml;r&uuml;&nbsp;<b>Veysel Atayman</b>, kitabın taşıdığı bu alıntı yeknesaklığına, yorum yoksulluğuna ve d&uuml;ş&uuml;nsel &ccedil;ıkmazına bir &ccedil;are olarak kaleme aldığı yazısında olabildiğince arızaları onarıyor, eksikleri perdelemeye &ccedil;alışıyor ve sonu&ccedil; olarak yapıtın barındırdığı tek d&uuml;ş&uuml;nsel &ccedil;&ouml;z&uuml;mlemeyi ger&ccedil;ekleştiriyor. Bu kısa metin olduk&ccedil;a ilgin&ccedil; saptamalara değiniyor, aslında olmayan anlatı/&ouml;zg&uuml;n dengesinin &ouml;zg&uuml;n kefesine hacminden daha fazlasını y&uuml;kl&uuml;yor ve kitaptan daha hoşnut bir vedayla ayrılmanızı sağlıyor. Ancak bu da kitabın ana metninin sorunlarını daha bir a&ccedil;ık ve anlaşılır hale getiriyor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Artık yazmanın ve s&ouml;ylemenin anlamı olmasa da, ki işin aslı nicedir yok, dizinsiz ve d&uuml;zeltisiz kitaplar kervenına biri daha eklenmiş oluyor. Yaptığımız kurgu gereği en sona kalmış olsa da sanırız en &ouml;nemli tesbitimiz, kitabın girişinde ilk dini filmlerle ilgili olarak verilen bilgilerde, olasılıkla eski kaynakların taşıdığı bilgilerin bir yansıması olarak hatalar bulunması.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/ts_ve_din.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (85, 'ay-j204', 'joris-ivens-tehlikeli-yasamak', 'Joris Ivens - Tehlikeli Yaşamak', 'Hans Schoots', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/tehlikeli_yasamak.jpg" alt="tehlikeli yasamak" width="227" height="347" style="margin-right: 20px; margin-bottom: 10px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Hans Schoots</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Hayal Et Kitap &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/412 sf</span></p>\r\n<p style="padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; font-size: 11px; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;"><b>Joris Ivens</b>... Belgesel denince akla gelen &uuml;&ccedil; beş isimden biri olan Hollandalı y&ouml;netmenin yaşam &ouml;yk&uuml;s&uuml;ne duyarsız kalmak belgesel tutkunu sinemaseverler i&ccedil;in olanaksız. Onun gen&ccedil;lik yıllarından &ouml;l&uuml;m&uuml;ne uzanan s&uuml;re&ccedil;te sinemasal etkinliklerine odaklanan, g&uuml;nl&uuml;k ayrıntıların inceliklerinde soluklanan, aşk trafiğinde &ouml;znesini takip etme isteğini hi&ccedil; yitirmese de bunda zorlanan ve benzerleri arasında olduk&ccedil;a &uuml;st bir noktada duran sıkı bir &ccedil;alışma, detaylı bir kaynak ve yapılması planlanan biyografi &ccedil;alışmaları i&ccedil;in &ouml;rnek bir yapıt.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Kitabın &ccedil;ekiciliğini sağlayan iki &ouml;nemli nokta var. İlki,&nbsp;<b>Ivens</b>&rsquo;in kendi filmleriyle kurduğu ilişki ve onlara y&ouml;nelttiği eleştirilerdeki soğuk tutumu. Sırası gelmişken, yazarın daha &ccedil;ok filmlerin yapım s&uuml;re&ccedil;lerine odaklandığını, bununla yetinmeyip filmlerin sinema basınındaki yankılarına ve eleştirel yazılara geniş&ccedil;e yer vermiş olsaydı, yapıtın g&uuml;c&uuml;ne g&uuml;&ccedil; katacağını s&ouml;ylememiz gerekiyor. İkincisi ise&nbsp;<b>Ivens</b>&rsquo;in hayat yolculuğuna katılanların onunki kadar ilgin&ccedil; &ouml;yk&uuml;leri. Yine de bir uyarıyla hatırlatmakta yarar var. Ulaşılmaz gibi duran bu hayatların yakın ve ayrıntı planlarına inince o tanrısallaştırılmış hayatların aslında ne denli doğal, yer yer sıradan olduğunu g&ouml;rmek şaşırtıcı olmamalı. Şaka değil,&nbsp;<b>Ivens</b>&rsquo;in g&uuml;zelliği kendine rağmen &ouml;nemsenecek &ccedil;alışmalara imzasını atabilmesinde. Kitap işte bu &ccedil;elişkilerle &ouml;r&uuml;l&uuml; yaratıcı s&uuml;recin, &ouml;znesini&nbsp;<b>Ivens</b>&nbsp;kılmış doyurucu bir &ouml;zeti.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Kitabın genel olarak ve işin başında taşıdığı &ccedil;ekici ve olumlu hava, okuyup inceledik&ccedil;e ve ayrıntılara inip tartıştık&ccedil;a hızla kayboldu ve yerini itici ve zorlama bir ilişki aldı. Bu durum, kitabın orijinali ile okuduğumuz arasındaki farklardan kaynaklanıyor: yetersiz ve hatalı &ccedil;eviri. Bu t&uuml;r kitapların olmazsa olmazı olan fotoğraf hi&ccedil; kullanılmamış, oysa nasıl da zengin bir g&ouml;rsel materyal birikimi var. Benzeri bir işlevi olan dizinlere yer verilmemiş. Kitaplarla ilgili ilk izlenimi &ccedil;oğu zaman arka kapak yazılarına bor&ccedil;lu olduğumuz ger&ccedil;eği burada kendini esaslı bir şekilde hatırlatıyor: Kitap bir edit&ouml;re ve redakt&ouml;re sahip olmamasının sancısını ilk andan itibaren yaşıyor. Ancak, ne olursa olsun, belgesel ve/veya&nbsp;<b>Ivens</b>&nbsp;s&ouml;zc&uuml;kleri sizin i&ccedil;in yeterli g&ouml;r&uuml;n&uuml;yorsa, başta da s&ouml;ylediğimiz gibi, emek yoğunluklu ve &ouml;rnek alınabilecek bir biyografi &ccedil;alışması sizi bekliyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/tehlikeli_yasamak.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (86, 'ay-j205', 'hurrem-erman-i-zlenmemis-bir-yesilcam-filmi', 'Hürrem Erman - İzlenmemiş Bir Yeşilçam Filmi', 'Rıza Kıraç', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/hurrem.jpg" alt="hurrem" width="200" height="275" style="margin-right: 20px; margin-bottom: 10px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Rıza Kıra&ccedil;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Can Yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/294 sf</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Son yıllarda salgın haline gelen ama nitelikten nasibini almamış T&uuml;rk sineması araştırmalarına, b&ouml;yle bir derdi olmasa da yol ve y&ouml;ntem &ouml;ğretecek cinsten bir &ccedil;alışma ile karşı karşıyayız. Kitabı sahiplenmemizin nedeni sadece &ouml;zg&uuml;n bir anlayışla kurduğu yapı değil, kaldı ki bu y&ouml;n&uuml; &ccedil;ok da g&uuml;&ccedil;l&uuml; değil; onu &ouml;nemli kılan nedenler arasında en ağır basanı i&ccedil;tenliği.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">T&uuml;rk sinemasının kilit isimlerinden biri &uuml;zerinden ger&ccedil;ekleştirilmiş ve farklı d&ouml;nemlerin egemen anlayışları konusunda aydınlatıcı bir sinema yolculuğu.&nbsp;<b>Kıra&ccedil;</b>&rsquo;ın kılavuzluğunda yeşil&ccedil;am &uuml;zerine izlenir kılınan bir film. Soru: Kitaba ek olarak verilecek bir belgesel hazırlama olanağı yok muydu? Sanki bu noktadan bakınca bir belgesele ulaşmak uzak duran bir hedef gibi g&ouml;z&uuml;km&uuml;yor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Kitabımızın keyif ka&ccedil;ıran tarafları yok mu derseniz, kadı kızı hesabı olan t&uuml;r&uuml;nden olanları var: bir sinema kitabında olması gerekene g&ouml;re fotoğraf sayısı &ccedil;ok az, olanlar da gelişig&uuml;zel konulmuş. &Uuml;nl&uuml; şair ve sinema yazarı&nbsp;<b>Philippe Soupault&nbsp;</b>dizine alıntı yapılan metindeki yanlış ad yazımı d&uuml;zeltilmeden konulmuş. Bilgisine sık sık başvurulan&nbsp;<b>İlhan Arakon</b>&nbsp;kaynak&ccedil;a dizininde unutulmuş.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">T&uuml;rk sinemasında &ccedil;ok tartışılan yeşil&ccedil;am ve yapımcı olguları &uuml;zerine, yıllanmış sorulara yanıtlar bulabileceğiniz ve yeni sorular sorulmasına neden olan bir yapıt, her &ouml;nemli yapıt gibi.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/hurrem.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (87, 'ay-j206', 'bakis-ve-ses', 'Bakış ve Ses', 'Pascal Bonitzer', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/bakisveses1.jpg" alt="bakisveses1" width="236" height="114" style="margin-right: 20px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Pascal Bonitzer</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Metis Yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/147 sf</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;"><b>Bonitzer</b>&nbsp;2006&rsquo;da yine Metis tarafından yayınlanan K&ouml;r Alan ve Dekadrajlar&rsquo;ın ardından bir kez daha g&uuml;ndemde ancak bu kez sahaya inerek.&nbsp;<b>Godard</b>&nbsp;ve&nbsp;<b>Straub</b>&rsquo;un keişen sinemasal duyarlılıkları &uuml;zerine olan J-L G ve J-M S yazısı ardında ufuk a&ccedil;ıcı nitelikte bir &ccedil;abayı gizliyor. Retro duygusunun &uuml;zerlerine sindiği iki klasik,&nbsp;<b><i>Lacombe Lucien</i></b>&nbsp;ve&nbsp;<i><b>Il Portiere di Notte</b></i>&nbsp;&uuml;zerine yaptığı &ccedil;&ouml;z&uuml;mlemeler zamana karşı ayakta kalmayı başarmış.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Filmler adı altında topladığı eleştiri yazıları ise sinemanın d&uuml;ş&uuml;nsel zenginliğinin keyfini s&uuml;rd&uuml;ğ&uuml; yıllardan kalma, &ouml;zg&uuml;n ve keyifle okunan bir se&ccedil;ki sunuyor.&nbsp;<b>Fellini</b>&rsquo;den&nbsp;<b>Littin</b>&rsquo;e,&nbsp;<b>Bunuel</b>&rsquo;den&nbsp;<b>Antonioni</b>&rsquo;ye ve&nbsp;<b>Taviani</b>&rsquo;den&nbsp;<b>Duras</b>&nbsp;sinemasına uzanan ve yazarlık yeteneğini su y&uuml;z&uuml;ne vuran, g&uuml;n&uuml;m&uuml;ze ulaşamamış bir anlayışın ortaya &ccedil;ıkardığı &uuml;r&uuml;nlerin bir derlemesi.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;"><img src="/images/kitaplik/bakisveses2.jpg" alt="bakisveses2" width="236" height="250" /></span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/bakisveses1.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (88, 'ay-j207', 'turk-film-arastirmalarinda-yeni-yonelimler-7', 'Türk Film Araştırmalarında Yeni Yönelimler 7', 'Ed. Deniz Bayrakdar', '<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><img src="/images/kitaplik/yonelimler.jpg" alt="yonelimler" width="283" height="461" style="margin-right: 20px; margin-bottom: 10px; float: left;" /><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Ed. Deniz Bayrakdar</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Bağlam Yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span lang="TR" style="font-size: 10pt; font-family: Verdana;">2008/535 sf</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: right;"><b><span lang="TR" style="font-size: 10pt; font-family: Verdana;">Doğu Şenkoy</span></b></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Yıllık bir konferans dizisi olan T&uuml;rk Film Araştırmalarında Yeni Y&ouml;nelimler&rsquo;in yedincisi olarak 2006 yılında ger&ccedil;ekleştirilen sinema ve para ilişkisi konulu konferansta sunulan yazı, bildiri ve sunumlar ile ger&ccedil;ekleşen panellerin metinlerini kapsayan kitap serinin &ouml;nceki kitaplarına g&ouml;re bir hayli hacimli duruyor. Tema sinema a&ccedil;ısından olmazsa olmaz bir konuda olunca hem s&ouml;ylenecek s&ouml;z artıyor hem de s&ouml;z&uuml; olanlar.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Bu t&uuml;r kitapların editoryal &ccedil;alışması konferansın organizyon yeteneği hakkında yeterli ip u&ccedil;ları verir. G&ouml;r&uuml;nen, konferansın mutfak kısmında daha iyi &ouml;rg&uuml;tlenmeye y&ouml;neldiği, işb&ouml;l&uuml;m&uuml;ne ge&ccedil;tiği ve bunun da &uuml;r&uuml;ne yansıdığı y&ouml;n&uuml;nde.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Metinler ağırlıklı olarak T&uuml;rk sineması &uuml;zerine odaklanması araştırma alanı nedeniyle doğal olsa da &ouml;rneklem a&ccedil;ısından Britanya, Almanya ve Sırp sinemalarına yayılması yapıtın sınırlarını Avrupa&rsquo;ya doğru a&ccedil;ıyor.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Kitabın en ilgi &ccedil;ekici yazılarının olduğu b&ouml;l&uuml;mler filmlerde paranın oynadığı rollere odaklanmış olanı. Anlatılan, paranın bir değişim ve satın alma aracı olarak ana karakterlerden rol &ccedil;almasının &ouml;yk&uuml;leri. Bağımsız sinemada yapım, yapımcı, yapımcı-y&ouml;netmen pozisyonlarında parayla kurulan ilişkinin değişken renklerine odaklanmak da deneyimler ortak noktalardan &ccedil;ok tekil olaylar &ouml;rneğinde geliştiğinden daha &ouml;ğretici.</span></p>\r\n<p style="font-size: 12px; padding: 5px 10px; margin-bottom: 0px; color: #564b47; font-family: Verdana, Arial, SunSans-Regular, sans-serif; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana;">Yerli ve yabancı spons&ouml;rl&uuml;klerin oynadığı rol&uuml; a&ccedil;ıklayan istatistiksel verileri ortaya koyan ve yeni teknolojilerin uygulama alanı olarak kısa filmdeki yansımalarına yer veren metinler &ouml;ne &ccedil;ıkıyor. Kitabın hacimsel b&uuml;y&uuml;kl&uuml;ğ&uuml;n&uuml;n artmasına paralel olarak kaynak yazı niteliğine sahip olan yazıların arttığını g&ouml;rmek sevindirici.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yonelimler.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (89, 'ay-j208', 'benden-sonra-tufan-olmasin', 'Benden Sonra Tufan Olmasın', '', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/benden_sonra_tufan_olmasin.jpg" alt="benden sonra tufan olmasin" width="180" height="265" style="margin: 0px 20px 10px 0px; float: left;" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">muhsin ertuğrul</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">remzi kitabevi &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2007 / 669 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">T&uuml;rk sineması denince hemen her zaman eksikliğinden, &ccedil;elişkilerinden ve yanlışlarından dem vurulan tarihsel a&ccedil;ılımların kısır kalmasının ardındaki en &ouml;nemli nedenlerden biri de &ouml;nc&uuml; rolleri &uuml;stlenmiş isimlerin arkalarında kendi kalemlerinden &ccedil;ıkma anılarını bırakmamış olmalarıdır. Ertuğrul&rsquo;un tiyatro-sinema d&uuml;nyamızdaki konumu, kaleme aldığı ancak yaşarken yayınlayamadığı ve &Ouml;zdemir Nutku&rsquo;nun &ccedil;abalarıyla bizlere ulaşan anılarını sadece biyografik notlar ve mesleki değiniler olarak değil, tarihsel kaynak olarak değerlendirmeyi gerektiriyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Son derece i&ccedil;ten, duyarlı ve al&ccedil;ak g&ouml;n&uuml;ll&uuml; bir anlayışla kaleme alınmış olan bu yazıların ardından eksiklik, a&ccedil;lık ve yarım yamalaklık hisleri duymamıza engel olamadık. Oysa ne kadar da ayrıntılı başlamıştı. Yakınlıkların, paylaşımların ve konuşmaların aktarımından yapılan &ccedil;alışmaların i&ccedil;eriğine d&ouml;n&uuml;k bilgilere bir t&uuml;rl&uuml; sıra gelmiyor. Tiyatro g&ouml;rece daha şanslı. Dikkatimiz daha &ccedil;ok tiyatrocuların sinema &ccedil;alışmalarına odaklanmıştı, &ouml;zellikle de Reşat Rıdvan&rsquo;ın eğilimlerine. Geriye Alman, Sovyet ve Amerikan sinemasının işleyişi &uuml;zerine bildik g&ouml;zlemler kalıyor. Unutmadan, bu, yapıtın ikinci baskısı ve &ouml;zge&ccedil;mişlerde g&uuml;ncellenmemiş ufak noktalar g&ouml;ze &ccedil;arpmakta.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/benden_sonra_tufan_olmasin.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (90, 'ay-j209', 'postmodern-kaos-sinema', 'Postmodern Kaos & Sinema', 'rıdvan şentürk', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/postmodern_kaos.jpg" alt="postmodern kaos" width="200" height="312" style="margin-right: 20px; margin-bottom: 10px; float: left;" />rıdvan şent&uuml;rk</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">iz yayıncılık &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2007 / 477 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin: 0cm 0cm 0.0001pt 354pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Son derece ilgi &ccedil;ekici konusu, klasizm-modernizm-postmodernizm &uuml;&ccedil;geninde g&ouml;zlenen değişimleri tarih-d&uuml;ş&uuml;n-estetik-sanat potasında &ccedil;ok boyutlu &ccedil;&ouml;z&uuml;mlemesi ve değişimin sinemadaki izd&uuml;ş&uuml;mlerini akımlar ve t&uuml;rler kapsamında yorumlamasıyla dikkat &ccedil;eken bir yapıt. Sorunları yok mu, var... &uuml;stelik de &ouml;nemli sorunları. &Ouml;ncelikle k&uuml;lt&uuml;rel bilgi alanlarını siyah ve beyaz olarak g&ouml;rmek gibi bir hataya d&uuml;ş&uuml;yor ve siyahların beyazlarını veya beyazların siyahlarını yok sayarak hasarlı bir sonu&ccedil; s&ouml;ylemine ulaşıyor. Politik, k&uuml;lt&uuml;rel, estetik ve d&uuml;ş&uuml;nsel s&ouml;ylemin izlediği yolun a&ccedil;mazları konusunda &ccedil;okcasına katıldığımız saptama ve a&ccedil;ıklamalar, s&uuml;recin k&ouml;kenleri ve nedenleri bağlamında sunulan olgu ve gerek&ccedil;elere sorgulayıcı bir g&ouml;zle yaklaşmamızı ve inandırıcılıkları konusunda uzak durmamızı engellemiyor.</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ouml;nemli bilgi ve yazım hataları arasında ilk bakışta dikkat &ccedil;ekenler okuma s&uuml;recini baltalamakta:</span></p>\r\n<ul style="line-height: 20px; margin-top: 10px; margin-bottom: 10px;">\r\n<li style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">La Revolution en Russie&rsquo;nin y&ouml;netmeni Ferdinand Zecca olarak veriliyor ama Lucien Nonguet.</span></li>\r\n<li style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Mecki değil Zemeckis.</span></li>\r\n<li style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">D&ouml;neminin &ouml;nemli yapımcılarından Cecil Hepworth&rsquo;un 1905 tarihli Rescued by Rover filminin y&ouml;netmeni L.F. Haim değil, yapımevinin kıdemli y&ouml;netmenlerinden Lewis Fitzhamon ve kayıtlarda Hepworth da ortak y&ouml;netmen olarak ge&ccedil;mekte.</span></li>\r\n<li style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Enrico Guazzoni&rsquo;nin filminin adı Quo Vadis? ve yapım yılı da 1912.</span></li>\r\n<li style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">1914 yapımı Cabiria filminin y&ouml;netmeninin takma adının doğru yazılımı Piero Tosco&rsquo;dur ve ger&ccedil;ek adı da Giovanni Pastrone&rsquo;dir.</span></li>\r\n</ul>\r\n<p><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bu t&uuml;r hataların yanlış ve eksik d&uuml;zenlenmiş olan indekse de bulaştığını belirtelim.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bunlara rağmen, kitabın işlediği Yeni Ger&ccedil;ek&ccedil;ilik ve Yeni Dalga gibi akımlar ve film-noir, korku, bilim-kurgu ve şiddet gibi bi&ccedil;im/t&uuml;rler &uuml;zerine verdiği bilgi ve tematik kapsamda yaptığı &ccedil;&ouml;z&uuml;mlemeler &ouml;nem taşıyor. Toplamda d&uuml;ş&uuml;nce yolculuğunun sinemadaki yansımaları ve ekoller arasındaki etkileşimin kırılgan rotaları g&ouml;zler &ouml;n&uuml;ne seriliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Sanırız ki kitabın en &ouml;nemli a&ccedil;mazı postmodernist kaosun etkisine yenik d&uuml;şen yazı dili. Se&ccedil;tiğimiz iki kısa alıntı bu saptamamızı bizden daha iyi bir bi&ccedil;imde dillendiriyor d&uuml;ş&uuml;ncesindeyiz: &ldquo;... modern-sek&uuml;ler uygarlık tarihinin esas anlamı d&uuml;nyayı, hayatı ve yaşama tarzlarını, &ouml;znenin teknolojik-bilimsel ve akli kıstaslarına uygun olarak mobilize etmek...&rdquo; ve &ldquo;... estetik ge&ccedil;-modernizmde olduğu gibi, sanat eseri, okunamaz, anlaşılamaz olmak ve m&uuml;mk&uuml;n b&uuml;t&uuml;n anlatım tekniklerini, yapılarını kullanarak, seyircinin/okuyucunun arzusunun s&uuml;rece katılımını engellemek suretiyle, seyircinin/okuyucunun şuurunda oluşturulan bir mesafe sebebiyle, kendini tecrit ediyor.&rdquo;</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/postmodern_kaos.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (91, 'ay-j210', '10-yonetmen-ve-turk-sinemasi', '10 Yönetmen ve Türk Sineması', 'ertekin akpınar', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><span style="font-size: 10pt;"><img src="/images/kitaplik/10_yonetmen_turk_sinemasi.jpg" alt="10 yonetmen turk sinemasi" width="270" height="413" style="margin: 0px 20px 10px 0px; float: left;" />ertekin akpınar</span></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">agora kitaplığı &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">2005 / 272 sf.</span><span style="font-family: \'Times New Roman\', serif; font-size: 12pt;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin: 0cm 0cm 0.0001pt 354pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Ertekin Akpınar, genellemelerin yanılgıları doğuracağı olasılığıyla, &ldquo;T&uuml;rk sinemasını on y&ouml;netmeninin &ouml;zeline sığdırmak ve bu konuşmalardan &ccedil;ıkan sonu&ccedil;la, T&uuml;rk sineması &uuml;zerine &ccedil;eşitli genellemeler yapmak doğru değil.&rdquo; a&ccedil;ıklamasıyla, sağlıklı bir başlangı&ccedil; yapıyor. Akpınar, kitabına eklemediği ama T&uuml;rk sinemasında &ouml;nemli olduklarını d&uuml;ş&uuml;nd&uuml;ğ&uuml; Metin Erksan, &Ouml;. L&uuml;tfi Akad, Yılmaz G&uuml;ney, Zeki &Ouml;kten ve Yavuz Turgul gibi isimleri de vurguladıktan sonra kitabının &ccedil;ıkış noktası olan &ldquo;Bir y&ouml;netmen film &ccedil;ekmeye nasıl karar verir?&rdquo; sorusunu se&ccedil;tiği on y&ouml;netmene soruyor. Senaryo yazım aşamasından oyuncu tercihlerine, renk d&uuml;zenlemesinden ışık kullanımına, m&uuml;zikten mekan se&ccedil;imine kadar &ccedil;alışma sistemleriyle ilgili sorularla mesleklerine bakışlarını deşifre etmeye &ccedil;alışıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&Ouml;ğrencilik hayatlarıyla başlayan s&ouml;yleşiler, sinemayla nasıl ilgilenmeye başladıkları, etkilendikleri filmler, T&uuml;rk sinemasının gelişimini ve kendi filmlerini nasıl değerlendirdikleri, sinemanın dışında nelerden beslendikleri ve sanata bakışları gibi &ouml;zellerine inildik&ccedil;e a&ccedil;ığa &ccedil;ıkan anılarla, keyifli bir okuma s&uuml;reci yaşanıyor. &Ouml;zellikle, Yavuz &Ouml;zkan&rsquo;ın mekan se&ccedil;imindeki titizliği; &Ouml;mer Kavur&rsquo;un film &ccedil;ektiği mekanlara bir daha gitmeyecek kadar duygusal yaklaşımı; Memduh &Uuml;n&rsquo;&uuml;n &ccedil;ektiği ticari filmleriyle ilgili samimi itirafları; Halit Refiğ&rsquo;in sinemada ger&ccedil;ek&ccedil;ilik ve ulusal kimlik iddiası ve &uuml;zerindeki Visconti etkileri; Erden Kıral&rsquo;ın kendi deyimiyle, Gen&ccedil; Sinema Dergisi&rsquo;ni nasıl batırdığı ve sans&uuml;re bakışını &ldquo;Franco olmasaydı, belki de Saura bu kadar b&uuml;y&uuml;k bir sinemacı olamayacaktı.&rdquo; diye a&ccedil;ıklaması; Ali &Ouml;zgent&uuml;rk&rsquo;&uuml;n ilk sahnesini &ccedil;ekmesinde Atıf Yılmaz&rsquo;ın rol&uuml; ve Tun&ccedil; Başaran&rsquo;ın b&uuml;t&uuml;n eğitimini, &ccedil;ocukluğundaki sinemalarda tamamladığı ve sinemanın kadife perdesiyle ilk tanışması gibi anılar ve yaşanmışlıklar, sinemaya g&ouml;n&uuml;l vermenin anlamını barındırıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Ertekin Akpınar, &ouml;zellikle d&ouml;neme ışık tutmasıyla kitabın bir s&ouml;zl&uuml; tarih &ccedil;alışması niteliği taşıdığını ve satır aralarına bu anlamda &ouml;zen g&ouml;sterilmesini okurdan istiyor. Halbuki sans&uuml;r ve darbelerin kitaptaki b&uuml;t&uuml;n y&ouml;netmenlerle ve yapıtlarıyla olan ilişkisi, satır aralarına gerek bırakmıyor. &ldquo;10 Y&ouml;netmen ve T&uuml;rk Sineması&rdquo; y&ouml;netmenlerin filmlerini &ccedil;&ouml;z&uuml;mlememizde, filmleriyle ilgili kendi a&ccedil;ıklamalarının yardımcı olacağını d&uuml;ş&uuml;n&uuml;rsek, &ouml;nemli bir kaynak niteliği taşıyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/10_yonetmen_turk_sinemasi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (92, 'ay-j211', '50-cagdas-sinemaci', '50 Çağdaş Sinemacı', '', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><img src="/images/kitaplik/50-Cagdas_Sinemaci.jpg" alt="50-Cagdas Sinemaci" width="354" height="551" style="margin: 0px 20px 10px 0px; float: left;" /></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: verdana, geneva; font-size: 10pt;">der:yvonne tasker</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: verdana, geneva; font-size: 10pt;">&ccedil;ev: nur g&ouml;k&ccedil;eoğlu &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: verdana, geneva; font-size: 10pt;">dost yayınları</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: verdana, geneva; font-size: 10pt;">nisan 2007 / 524 sf.</span></p>\r\n<p style="text-align: right;"><span style="font-family: verdana, geneva; font-size: 10pt;"><b>doğu şenkoy</b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: verdana, geneva; font-size: 10pt; color: #564b47;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>Sinema d&uuml;nyasında y&ouml;netmenlerle ilgilenmek ağırlıklı olarak pop&uuml;ler basın ve izleyici a&ccedil;ısından &ouml;nemini yitirmeyen bir olgu. 52 &ccedil;ağdaş sinemacı &uuml;zerine 50 yazıdan oluşan bu kitap, akademik d&uuml;nyanın y&ouml;netmene verdiği &ouml;nemi a&ccedil;ığa vurmakta. Yazılar uluslararası sinemanın yapay da olsa ayrı tutulan iki kulvarını, sanatsal ve ticari sinema alanlarını yaratıcılık, etkileşim ve &uuml;retim koşulları a&ccedil;ısından irdelemeyi ama&ccedil;lıyor. Her y&ouml;netmene yaratım s&uuml;re&ccedil;leri a&ccedil;ısından toplamın bir birleşeni olarak farklı bir model olarak bakılmakta.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>Kuzey Amerika&rsquo;dan 28, Avrupa&rsquo;dan 12 ve Asya&rsquo;dan 12 ismin yer aldığı se&ccedil;ki, y&ouml;netmenlerin kıtalara dağılımı a&ccedil;ısından &ccedil;ağdaşlığın adresinin Amerika, &ouml;len değerin Avrupa ve y&uuml;kselen değerin de Asya olduğunu vurguluyor. &Ccedil;alışmalarını ABD&rsquo;de s&uuml;rd&uuml;renleri de eklediğimizde bu dengesizlik dengesi daha da bozuluyor.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>Bu t&uuml;r se&ccedil;kilerin bireysel eğilimlerle ortaya &ccedil;ıkması ka&ccedil;ınılmaz ama &ccedil;elişkiler de ka&ccedil;ınılmaz olsa gerek. Yapıtını &uuml;&ccedil; kıta ile sınırlamasına sıcak bakmadığımız Tasker kendini kabul g&ouml;rm&uuml;ş isimlere yer vermek zorunda hissetmediğini s&ouml;yl&uuml;yor ve Godard&rsquo;ı es ge&ccedil;iyor. Onu haklı buluyoruz ama burada Beineix, Bertolucci veya Coppola gibi isimlerin ne aradığını da anlamıyoruz. &Ccedil;ağdaş sinema i&ccedil;in ne ifade ettiklerini anlamasak da yazıların &ouml;ğretici olma &ouml;zelliği onlarınkiler i&ccedil;in de ge&ccedil;erli. Se&ccedil;ilen isimlerden, &ccedil;ağdaş sinemayı ağırlıklı olarak 1940&rsquo;lı ve 1950&rsquo;li yıllarda doğanların belirlediği sonucu &ccedil;ıkıyor. Kaldı ki se&ccedil;ici kim olursa olsun, &ccedil;ağdaş sinemaya kimliğini kazandıranlar arasında Kusturica, Sokurov, Ozon, Kwan, Kitano ve Almodovar isimlerine yer verilmesi gerekmez mi? Bazı &uuml;lkeler neden &ouml;nceki kuşaklar tarafından temsil ediliyor? Neden tek bir Rus yok? Soğuk savaş d&ouml;nemi se&ccedil;kileri bile bu denli ileri gitmemişlerdi.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>A. Anders, S. Aoyama, G. Araki, J.J. Beineix, C. Burnett, J. Chan, J. Dash, A. Egoyan, T. Haynes, J. Jarmusch, K. Kieslowski, S. Lee, M. Mann, J. Sayles, S. Spielberg, T. Hark, W. Wang ve W. Kar-wai &uuml;zerine yazılan yazılar diğerlerini g&ouml;lgede bırakıyor.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>Bu t&uuml;r se&ccedil;kilerin ortak kaderi, zamana &ccedil;ok kısa s&uuml;rede yenik d&uuml;şmeleri olsa gerek. 2002&rsquo;de yayınlanan kitap, gerek eskiyen ve yenilenmeye gereksinim duyan filmografilerin gerek beş yıl gibi bir s&uuml;rede yıldızı parlayan yeni isimlerin ortaya &ccedil;ıkmasının da g&ouml;sterdiği gibi &ccedil;ok hızlı bir s&uuml;rede yabancı dillere kazandırılmayı zorunlu kılıyor.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: verdana, geneva; font-size: 10pt;"><span>İzleyici se&ccedil;imlerinde y&ouml;netmenin artan &ouml;nemine vurgu yapması, yıldız kavramının y&ouml;netmenlere ve hatta yapımcılara kaymakta olduğunun neden ve kanıtlarını sergilemesi ve en &ouml;nemlisi yazıların b&uuml;y&uuml;k &ccedil;oğunluğunun kaynak niteliği taşıması, 50 &Ccedil;ağdaş Sinemacı&rsquo;yı son zamanların en &ouml;nemli yayınlarından biri konumuna getiriyor.</span></span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/50-Cagdas_Sinemaci.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (93, 'ay-j212', 'devrimden-sonra-birinci-yuzyil-yonetmenlerin-i-zinde-macar-sinemasi', 'Devrimden Sonra Birinci Yüzyıl - Yönetmenlerin İzinde Macar Sineması', 'tolga yalur', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/yonetmenlerin_izinde_macar_sinemasi.jpg" alt="yonetmenlerin izinde macar sinemasi" width="349" height="505" style="margin-right: 20px; margin-bottom: 10px; float: left;" />tolga yalur</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">phoenix &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 168 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 8.5pt; font-family: Verdana, sans-serif;"><span style="font-size: 10pt;"></span></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 8.5pt; font-family: Verdana, sans-serif;"><span style="font-size: 10pt;">D&uuml;nya sineması i&ccedil;inde kendine &ouml;zg&uuml;l&uuml;ğ&uuml;yle ayrıksı bir yerde duran, &uuml;lkemizde meraklısı &ccedil;ok olsa da bileni az olan Macar sineması &uuml;zerine dilimizde kaleme alınan bu ilk kitap, her şeyden &ouml;nce</span><span style="font-size: 10pt;">&nbsp;<b>Tolga Yalur</b></span><span style="font-size: 10pt;">&rsquo;un Macar sinemasıyla kurduğu ilişkinin i&ccedil;tenliğiyle g&ouml;z doldurmakta. Yazarın sunuş b&ouml;l&uuml;m&uuml;nde de değindiği &uuml;zere film ve yazılı materyallerine ulaşılması &ccedil;ok da kolay olmayan bu sinemaya dair sınırları dar tutulmak zorunda kalınmış bir &ccedil;alışma olsa da Macar sineması adına sahip olunması gereken ilksel bilgileri kapsayıp, bu sinemaya dair b&uuml;t&uuml;nl&uuml;kl&uuml; bir resim sunabildiği i&ccedil;in &ouml;nemli bir noktada durmaktadır.</span></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yedi ana başlıkla b&ouml;l&uuml;mlenen &ccedil;alışma, Macar sinemasını bir hat olarak belirlenen sosyalizmin &ouml;ncesi ve sonrasındaki durumu &uuml;zerinden</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Zoltan Fabri</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Zoltan Huszarik</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Istvan Szabo</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Miklos Jancso</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Marta Meszaros</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Karoly Makk</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bela Tarr</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">gibi pek &ccedil;ok y&ouml;netmen eşliğinde incelemeye &ccedil;alışmakta. Y&ouml;netmenlerin sinema &ouml;zge&ccedil;mişlerini es ge&ccedil;meden, &ouml;nemli filmleri &uuml;zerinden sinemalarının temel izlekleri vurgulanıp hem onların meydana getirdiği Macar sineması hem de bu sinema i&ccedil;inde durdukları yere değinilerek, genel bir &ccedil;er&ccedil;eve &ccedil;izilmektedir. Kitabın Doğu ve Orta Avrupa sinemalarında k&ouml;kl&uuml; bir geleneğe sahip olan canlandırma sinemasına değinilen son b&ouml;l&uuml;m&uuml;, Macar sinemasının bu &ouml;nemli kanadına dair de genel bir &ccedil;er&ccedil;eve &ccedil;izerek alanla ilgilenecek olanların yola &ccedil;ıkış bilgilerini barındırmaktadır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yalur</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;un bu ilk &ccedil;alışmasının incelediği konuya dair &ccedil;izdiği genel &ccedil;er&ccedil;eve, Macar sinemasına dair daha ayrıntılı ve geniş bir okuma yapmaya &ouml;zlem duyanların beklentilerini karşılayamayarak eleştiri mekanizmasını işletebilir. Ancak yazarın daha kitabın başında a&ccedil;ık ettiği niyeti ve oluşturduğu hattı belli etmesi bizim eleştirimizin y&ouml;n&uuml;n&uuml; buradan editoryal &ccedil;alışmaya kaydırmamıza neden olmakta. Kitapta karşımıza &ccedil;ıkan dizgi ve redaksiyon hataları ile g&ouml;rsel kalitesinin d&uuml;ş&uuml;kl&uuml;ğ&uuml; editoryal &ccedil;alışmanın zayıflığına işaret ederken, yazar-edit&ouml;r işbirliğinin &ccedil;alışmalardaki &ouml;nemini de bir kez daha g&ouml;zler &ouml;n&uuml;ne sermekte.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yonetmenlerin_izinde_macar_sinemasi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (94, 'ay-j213', 'dram-sanati-ve-sinema', 'Dram Sanatı ve Sinema', '', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/dram_sanati.jpg" alt="dram sanati" width="283" height="426" style="margin: 0px 20px 10px 0px; float: left;" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">y&ouml;r&uuml;khan &uuml;nal</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">hayalet kitap &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2008 / 276 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Anlatım formlarının doğuşunu hazırlayan nedenleri, yapılarını, gelişim evrelerini ve toplumsal yaşamla olan ilişkisini ayrıntılı ve &ouml;rneklemlerle destekleyerek ortaya koyan kaynak niteliğinde bir yapıt. Epos-Drama &ccedil;atalında y&ouml;n&uuml;n&uuml; dramaya &ccedil;eviren, yaratıcı ve doğa&ccedil; bir s&ouml;ylemden mekanik ve kuralcı bir bir yapıya evrilişin gereklerini ortaya koyan &ccedil;alışma, dram sanatını &ouml;nce dnalarına ayırıyor, sonra da tıpkı dramın yapısına uygun olarak dikiş izlerini g&ouml;r&uuml;nmez kılıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Kitabın bizi daha yakından ilgilendiren b&ouml;l&uuml;m&uuml; dramatik yapının sinematografik anlatımın evriminde &uuml;stlendiği rol&uuml; anlatıyor. Sinemanın kendi anlatım dilini yaratırken izlediği yol ve dramla kurduğu tatlı-sert ilişkinin d&ouml;n&uuml;m noktaları tutarlı saptamalarla verilmiş. Dramatik yapının gelişme evreleri işlenirken egemen sinema tarihinin a&ccedil;tığı yol izlenerek sadece &uuml;&ccedil; beş kişi ve iki &uuml;lke &uuml;zerinden gidilmesi ve onlar kadar &ouml;nemli olan isimlerin yine yok sayılması tatsız olsa da adı ge&ccedil;enlerin rollerinin abartıdan uzak bir dille ortaya konulması yerinde olmuş. Bir de yazarımız film notlarını derlemek yerine filmleri kendi izleyip yazsaymış &ccedil;ıtayı daha y&uuml;kseğe taşırmış, buna kuşku yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Birka&ccedil; nokta &uuml;zerinde fazla ayrıntıya girmeden durmakta yarar var: 1896 Kiss filminin Kinetoscope i&ccedil;in &uuml;retilen ilk film olduğu bilgisi ağır bir hata. Griffith&rsquo;in &ouml;nceli olarak Porter&rsquo;ı g&ouml;stermek hem ara evreleri yok saydığı i&ccedil;in eksik bilgiye dayanan hem de birilerini tarihten silmeye &ccedil;alışan tarihsel hatalardan birinin tekrarı. G&ouml;rsel ve dizin yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Sinema drama ile tanışınca ne olmuş, tanışmış da iyi mi olmuş&hellip; sorularına yanıt arayanlar veya yanıtlarına &ccedil;eşni katmak isteyenler i&ccedil;in sağlam bir kitap.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/dram_sanati.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (95, 'ay-j214', 'fikret-hakan-eskimeyen-yesilcamli', 'Fikret Hakan - Eskimeyen Yeşilçamlı', '', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/fikret_hakan.jpg" alt="fikret hakan" width="283" height="444" style="margin: 0px 20px 10px 0px; float: left;" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">nigar p&ouml;steki</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">umuttepe yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 296 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Sinemamızın oyuncu tayfasının &ouml;ne &ccedil;ıkan isimlerinden biri olan, emeğini kimsenin g&ouml;rmezden gelemeyeceği, eskimediği saptamasına bizim de katıldığımız</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Fikret Hakan</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&uuml;zerine gecikmiş bir &ccedil;alışma. İlk olan her &ccedil;alışma gibi ilgi &ccedil;ekici ve eksik giderici ancak beklentiyi artıran ve &ccedil;ıtayı yetersiz bulmamıza neden olan bir tarafı da var. Sorunun kaynağı yazarın kurgusu da olabilir, oyuncunun sağladığı olanaklar da... kapalı kapıların ardını bilmiyoruz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">İ&ccedil;indekiler sayfasında 6., kitapta 7. b&ouml;l&uuml;m olan 1960&rsquo;lar T&uuml;rk Sineması &uuml;zerine odaklanan b&ouml;l&uuml;m, hem i&ccedil;erik olarak yeni birşey s&ouml;ylemiyor olması hem de kitabın anlatısını b&ouml;ld&uuml;ğ&uuml; i&ccedil;in bize işlevsiz ve katkısız geldi. B&uuml;t&uuml;n bu bilgiler filmlerin daha ayrıntılı olarak ele alınması sayesinde anlatının i&ccedil;ine yedirilebilirdi d&uuml;ş&uuml;ncesindeyiz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Eskimeyen Yeşil&ccedil;amlı</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nın en renkli ve yararlı b&ouml;l&uuml;m&uuml; Hakan&rsquo;ın &ouml;yk&uuml; yazarı ve şair olarak portresini &ccedil;izen son b&ouml;l&uuml;m. Yazarın bu b&ouml;l&uuml;mdeki analizleri de sağlıklı. Ancak bu yoğunlaşma,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Hakan</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın y&ouml;netmenlik anlayışı ve y&ouml;nettiği filmler &uuml;zerinde daha ayrıntılı durulması gerektiği sonucunu doğuruyor. Scognamillo ile yapılan s&ouml;yleşinin kitaba sağladığı bir katkı da yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kitapta&nbsp;<b>Hakan</b>&rsquo;ın kendisine 25 yıl kadar &ouml;nce y&ouml;nelttiği bir soru var ki samimiyetin ve bir de &Ccedil;ıtanak-Hakan &ccedil;atışmasının su y&uuml;z&uuml;ne &ccedil;ıkmasının kanıtı olarak okunmalı: &ldquo;Bunca yıl emek verdiğim adamdan gerekli yapıtları &ccedil;ıkaramamak sancısı... Ben bu adama niye bu kadar emek verdim ki?&rdquo; Burada sanatın dayanılmaz ağırlığı yatıyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/fikret_hakan.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (96, 'ay-j215', 'film-cozumlemeleri', 'Film Çözümlemeleri', '', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/film_cozumlemeleri.jpg" alt="film cozumlemeleri" width="283" height="397" style="margin: 0px 20px 10px 0px; float: left;" /></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">der: seyide parsa</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">multilingual yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2008 / 215 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bir derleme olan kitabımızın yazarları</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Seyide Parsa</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Dilek İman&ccedil;er</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Alev Parsa</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">G&uuml;liz Ulu&ccedil;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Mehmet Yılmaz</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Z&uuml;hal &Ouml;zel</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Seda Olgundeniz</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Nazım Ankaralıgil</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Burcu Balcı</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve <strong>A</strong></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">slı Karamollaoğlu</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">. Kendine sorulacak olursa, anlamın a&ccedil;ığa &ccedil;ıkarılmasını ama&ccedil; edinmiş bir film &ccedil;&ouml;z&uuml;mlemesi kitabı. Bir başka deyişle, anlamın karakterini kendine dert edinmiş; derdi</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>ne</i>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">değil,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>nasıl</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yazarının her nedense adını vermekten ka&ccedil;ındığı giriş yazısında verilen bilgi ve a&ccedil;ıklamaların &ccedil;&ouml;z&uuml;mleme/eleştiri yazılarında &ccedil;oğunlukla karşılığını bulmamış olmasına bir anlam veremedik. Ancak yazının asıl sorunu kullandığı &ccedil;ok sayıda kavram ve tanımın (metin, metin &ccedil;&ouml;z&uuml;mlemesi, eleştiri, analiz, yapısalcılık) birbiriyle olan ilişkisini i&ccedil;selleşmiş bir bilgiye d&ouml;n&uuml;şt&uuml;rememiş olmasının g&ouml;stergeleriyle dolu olması.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ouml;te yandan, eleştiri ve &ccedil;&ouml;z&uuml;mlemenin girift ilişkisi ve &ccedil;&ouml;z&uuml;mleme t&uuml;rleri olarak sunulan yaklaşımlar arasındaki ge&ccedil;işler/kapsama alanları a&ccedil;ıklanamamış. Hiyerarşik duruş adına iki altbaşlık altında toplanan yazıların bu işlevsiz sınıflandırması da dolaylı yoldan sorunun varlığına bir başka kanıt; yaklaşımlar uzaklaşımların altını daha net &ccedil;izmiş. Ancak, daha geniş bakılacak olursa, bu durumun tam da olması gerektiği gibi uygulama alanında zaten karşılığını bulamayan bir ayrıştırma olduğunu s&ouml;ylemek gerekiyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">G&ouml;stergebilimsel araştırma t&uuml;rleri diye adları sıralanan &ccedil;&ouml;z&uuml;mleme yaklaşımlarından (sign, paradigmatic!, syntagmatic! ve intertextuality!) hi&ccedil;biri ne y&ouml;nteminde ne de sonucunda g&ouml;stergelere ve g&ouml;stergebilime dayanıyor. Batı kuramsal evriminin geldiği noktada zorlama yapılar ve ilişkilerle kendi a&ccedil;mazını &ouml;r&uuml;yor ve bir &ccedil;ıkmaz sokakta oyun oynuyor. Adları ne olursa olsun, amacı g&ouml;stergebilimsel eleştiri/&ccedil;&ouml;z&uuml;mleme olmayan yaklaşımlar uygulamada da ama&ccedil;sız, anlamsız ve işlevsiz kalıyor. Oyun &uuml;&ccedil;&uuml;nc&uuml; d&uuml;nya liginde de taklit emeklerle s&uuml;r&uuml;yor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yazılara gelince, g&ouml;sterge &ccedil;&ouml;z&uuml;mlemeleri başlığı altındaki Beynelmilel film afişinin &ccedil;&ouml;z&uuml;mlemesi &ouml;ğretici ve eğlenceli; reklamla ilgili ve kitaba yabancı olan bir başkası ise serbest u&ccedil;uştan mustarip, aşırı yoruma giren yazınsal g&ouml;ndermeleri ise sadece matrak. Diğer yazılar arasında da Others filmi &uuml;zerine olan, ekonomik anlatısı ve amacı doğrultusunda sergilediği yaklaşımı ile farklı duruyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kitabın g&ouml;stergeleri en iyi anlayan, yaşayan, yakalayan ve değerlendiren yazıları nedense eleştirel &ccedil;&ouml;z&uuml;mleme yaklaşımları (ne demekse!, sanırım olmuşlar ile hen&uuml;z olamamışları ayrıştırmak i&ccedil;in kullanılan bir psiko-discourse) başlığı altında toplanmış. Oysa g&ouml;stergebilime saplanıp kalmasalar da g&ouml;sterge avcılığının hakkını veren ve ideolojik, t&uuml;r ve feminist eleştiri t&uuml;rlerine yaslanan bu yazılar kitabın ortalama değerini yukarılara &ccedil;ekiyor. Bu yazılarda fotoğraflara yer verilmiş olması da &ouml;zenin bir başka g&ouml;stergesi olarak bir rastlantı olmasa gerek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Derlemeyi oluşturan yazıların belli bir plan &ccedil;er&ccedil;evesinde hazırlanmadığı, elde bulunanlardan bir derlemeye gidildiği daha ilk bakışta anlaşılıyor. Yayınlanmış yazılardan alınan destek bile kapsamı ve &ouml;rneklemleri geniş ve zengin kılmıyor. &Ccedil;&ouml;z&uuml;mlemeler/eleştiriler ağırlıklı olarak Hollywood filmleri &uuml;zerine. Sığ suların g&uuml;ven verdiği bir ger&ccedil;ek ama zaman, bilgi ve enerjiyi s&ouml;z&uuml;n&uuml; daha seyrederken ortaya kusan ve haklarında zaten her şeyin yazılmış olduğu bu filmlere harcamak kolaycılık oluyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/film_cozumlemeleri.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (97, 'ay-j216', 'geceyarisi-filmleri', 'Geceyarısı Filmleri', 'kaya özkaracalar', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/geceyarisi_filmleri.jpg" alt="geceyarisi filmleri" width="312" height="479" style="margin-right: 20px; margin-bottom: 10px; float: left;" />kaya &ouml;zkaracalar</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">+1 Kitap&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">mayıs 2007 / 519 sf.</span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right; line-height: normal; margin-bottom: 0pt;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 8.5pt;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Ankara kaynaklı Geceyarısı Sineması dergisinin yaratıcılarından Kaya &Ouml;zkaracalar&rsquo;ın yazılarının derlemesinden oluşan bu kitap, hatırı sayılır bir toplama ulaşmakla kalmıyor; &ouml;zellikle kitaba adını veren saatlere &ouml;zg&uuml; t&uuml;r ve alt-t&uuml;rler konusunda bilgilendirici bir kaynak olarak keyif veriyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Kendi i&ccedil;inde b&ouml;l&uuml;mlere ayrılan kitabın y&ouml;netmenlerden oyunculara, t&uuml;rlerden sans&uuml;re, Yeşil&ccedil;am&rsquo;dan T&uuml;rk-İtalyan ortak yapımlarına ve &ccedil;izgi film d&uuml;nyasına uzanan geniş bir yelpazesi var. Onları yazarın Radikal gazetesinde yayınlanan yazıları izlemekte. Bu başlıklar altında&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Lucio Fulci</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">,&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Jean Rollin</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">,&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Koji Wakamatsu&nbsp;</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">ve&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Soledad Miranda&nbsp;</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">gibi isimlerle veya Japon ve T&uuml;rk-İtalyan sinemasının g&uuml;n y&uuml;z&uuml;ne &ccedil;ıkan filmleriyle karşılaşmak sinema arkeolojisine g&ouml;nl&uuml;n&uuml; kaptıran her okur i&ccedil;in değerli olsa gerek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Sinema d&uuml;nyasının &ouml;teki etiketini taşıyan bu karanlık y&uuml;z&uuml;ne duyulan sevgi a&ccedil;lığını a&ccedil;ığa vuran bu okkalı kitabın sayfalarında hi&ccedil; mi kusur yok derseniz, yanıtımız bedeni oranında var olur. Başından sonuna doğru gidecek olursak; İ&ccedil;indekiler b&ouml;l&uuml;m&uuml;nde Avrupalı y&ouml;netmenler arasına bir Uzak Doğulu sızmış, &Ccedil;izgi Film&rsquo;in bir b&ouml;l&uuml;m başlığı olduğu vurgulanmamış ve Radikal Film eleştirileri b&ouml;l&uuml;m&uuml;nde bir film atlanmış.&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Jacques Tourneur&nbsp;</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">imzalı&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><i><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Cat People&nbsp;</span></i></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">(1942) filminin y&ouml;netmeni, anlatımdan dolayı&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Val Lewton&nbsp;</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;"></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">olarak algılanmakta. Aynı isim, ilerleyen sayfalarda 1940&rsquo;ların en &uuml;nl&uuml; korku film y&ouml;netmeni olarak g&ouml;steriliyor ancak Lewton bildiğimiz kadarıyla &uuml;n&uuml;n&uuml; yazar-yapımcı olarak kazanmış bir isim.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Bunların dışında, okuma zevkini bir hayli bozan hatalar var. Bazıları fotoğraf altı yazıları ile tarihlendirmelerin ve &ouml;nemlice bir kısmı da anlatım bozukluklarının doğurduğu hatalar. Ama en can sıkıcı olanları sık tekrarlanan isim hataları. Bu t&uuml;r hataların her on sayfada bir yapıldığını d&uuml;ş&uuml;n&uuml;rseniz sorunun &ouml;nemi daha iyi kavranacaktır. Genel bir okuma ve d&uuml;zeltinin yapılmadığı &ccedil;ok a&ccedil;ık.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Kitabın ilgi alanının eşsiz bir &ccedil;ekicilik taşıması ikinci bir baskının yapılması olanağını doğurduğu i&ccedil;in, geleceğe d&ouml;n&uuml;k bazı &ouml;neriler de getirilebilir. Yazıların yayınlandığı yayın organları ve tarihlerinin belirtilmesi, 2000&rsquo;li yılların başında kesilen yazıların yeni tarihli yazılarla desteklenmesi ve en &ouml;nemli eksik olarak g&ouml;rd&uuml;ğ&uuml;m&uuml;z bir dizin eklenmesi kitabı &ccedil;ok daha &ouml;nemli kılacaktır. Sinemanın karanlık y&uuml;z&uuml;ne yapılan yolculuk &ouml;yk&uuml;lerini barındıran Geceyarısı Filmleri, bu &ouml;zenin g&ouml;sterilmesini hak eden bir yapıt.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/geceyarisi_filmleri.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (98, 'ay-j217', 'kadina-melodram-yakisir-turk-melodram-sinemasinda-kadin-i-mgeleri', 'Kadına Melodram Yakışır - Türk Melodram Sinemasında Kadın İmgeleri', 'hasan akbulut', '<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/kadina_melodram.jpg" alt="kadina melodram" width="283" height="413" style="margin-right: 20px; margin-bottom: 10px; float: left;" />hasan akbulut</span></p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">bağlam yayınları&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">2008 / 371 sf.</span></p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: right;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">doğu şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Melodramlar ideolojik olarak y&ouml;nlendirici pop&uuml;ler filmler midir? Melodram bazı auteurlerin elinde en azından izlenir hale gelirken ulusal sinema &ouml;rneklerinde neden pespayelikten bir adım &ouml;teye ge&ccedil;emez? Melodram</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&nbsp;<b>R.W. Fassbinder</b>&nbsp;</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">sinemasında ideolojik ve sosyal sorunlara yakın temas s&uuml;rt&uuml;nd&uuml;ğ&uuml; i&ccedil;in mi sınıf atlamış havası verir? Melodramın tarihin herhangi bir d&ouml;neminde Avrupalı entelekt&uuml;ellerce tanındığı olmuş mudur? Melodram sosyo-ekonomik bir baskı &uuml;r&uuml;n&uuml; m&uuml;d&uuml;r yoksa o baskının yarattığı bir &uuml;r&uuml;n m&uuml;d&uuml;r? Yeşil&ccedil;am meloları hollyeuro melolarından sadece &ccedil;ekim &ouml;l&ccedil;eği (front shots) kullanımından doğan bir farkla nasıl olup da radikal bir fark yaratabilir; ayrıca d&uuml;nyanın geri kalanından farklı bir uygulama olmadığına g&ouml;re bu farkın radikal bir yanı var mıdır?</span></p>\r\n<p>&nbsp;</p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Bu soruları sormamıza neden olan kitabımız melodramın kodlarını, melodram filmlerinin sosyal d&uuml;zenin devamının sağlanmasındaki rol&uuml;n&uuml; ve filmler &ouml;zelinde de melo-toplum yapısı ve ruhunu ortaya &ccedil;ıkarmaya &ccedil;alışıyor. Melonun hollywoodca tarihi, karakter ve anlatım kalıpları &ccedil;&ouml;z&uuml;mlemesi girişi zengin kılmakta. Araştırmanın yapısı gereği olan tekrarların okuma keyfini zorladığı a&ccedil;ık. Bir sayfada hollywood tarihinin &ouml;zetini yapmakta (79); kitabı arşivlik kılmaya bu bile yeter. Bir başka sayfada bilimsel eleştirinin melodrama olan ilgisi &uuml;zerinde durulmakta (116); ancak mal iyi olmayınca bilimsel eleştiri ne yapsın? G&uuml;nl&uuml;k ve şiirin cinsiyet&ccedil;i s&ouml;ylem uzantıları &uuml;zerine yapılan a&ccedil;ıklama bizi erkekliğin &ouml;l&uuml;m&uuml; &uuml;zerine d&uuml;ş&uuml;nmeye itti (128). Bir başka cinsiyet&ccedil;i a&ccedil;ılım, patentini feminist kuramdan alan, kadının y&uuml;z ve bedeninin par&ccedil;alı sunumunun kaynağında eril bakışın olduğuna dayanan s&ouml;ylem (175). Hayat pratiğinin cinsiyet ayrımı yapmadan doğruladığı bu saptama, bu s&ouml;ylemden yola &ccedil;ıkarak yapılan &ccedil;&ouml;z&uuml;mlemeleri de eksik ve yanlış kılıyor. Kadın-melodram ilişkisine gelince, kitabın &uuml;zerinde d&uuml;ş&uuml;nmemize neden olduğu olgulardan biri, sinemanın melo modelleri kadın d&uuml;nyasından alıp paketledikten sonra yeniden kadın d&uuml;nyasına sunması oldu.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Bazı filmlerde yapılmayan a&ccedil;ıklamalara, s&ouml;ylenmemiş s&ouml;zlere veya olmayan g&ouml;ndermelere rağmen yapılmış yorum ve varılmış kararlar var. Bunlar melonun baskın karakterinin ipleri eline almasından mı, yoksa yorumun sınır tanımazlığından mı, anlamadık.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Bu t&uuml;r ciddi emek harcanan &ccedil;alışmalara yakışmayan eksikleri var kitabın: g&ouml;rsel kullanımı sıfır &ndash;oysa ki ne kadar da fark yaratırdı- ve dizin yok. Redaksiyon ve isim hataları da g&ouml;ze &ccedil;arpmakta. &Ouml;te yandan, melodram denilen ruh halini sadece hollywood tarihi &uuml;zerinden anlatmanın sınırlı saptamalara neden olduğu kanısındayım. Yeşil&ccedil;am melosu doğumelo ve batımelo niteliklerini bir araya getiren bir harman aslında. İşte bu nedenle Mısır ve Bollywood dikkate alınmalıydı. Ama gelin g&ouml;r&uuml;n ki, melodram ger&ccedil;ekten de asıl hollywood&rsquo;a yakışıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="margin-bottom: 0pt; line-height: normal; font-size: 12px; color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Melodram ve melodram sineması &uuml;zerine şu ana kadar okuyup bildiklerimizi olabilecek en derli toplu bi&ccedil;imde veren, ikinci bir kaynağı gereksiz kılacak derecede zengin bir kurguya sahip ve b&uuml;t&uuml;n bunların &uuml;zerine meraklısına melodramatik kadın imgeleri veren &ouml;nemli bir &ccedil;alışma.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/kadina_melodram.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (99, 'ay-j218', 'ne-kadar-gamli-bu-aksam-vakti-safa-onal-kitabi', 'Ne Kadar Gamlı Bu Akşam Vakti "Safa Önal Kitabı"', 'söy: yasemin arpa', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/safa_onal_kitabi.jpg" alt="safa onal kitabi" width="283" height="434" style="margin-right: 20px; margin-bottom: 10px; float: left;" />s&ouml;y: yasemin arpa</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">iş bankası yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 476 sf.</span><span style="font-family: \'Times New Roman\', serif; font-size: 12pt;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">1931&rsquo;de başlayan ve yolu 1953&rsquo;de sinemanın yolu ile kesişen bir hayatın, sahibi tarafından dile getirilen d&ouml;n&uuml;m noktalarının bu eğlenceli anlatısı, sadece kendine tanıklık etmiyor; olaylar, tanıklıklar, anılar ve kişilerle ardına kadar a&ccedil;ılan canlı bir belleğin labirentine konuk ettiği bizleri bu samimi kılavuzu aracılığıyla sinema tarihimizin yolculuğuna &ccedil;ıkarıyor. Ge&ccedil;mişe sıkı sıkıya tutunan bu melo kılavuz, geleceği dramdan ibaret olarak algılamakla bir d&ouml;nemin sinema anlayışının da artık ge&ccedil;mişin malı olduğunu kanıtlıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeşil&ccedil;am ile bunca b&uuml;t&uuml;nleşmiş, melo ruhunu iliklerine kadar yaşayan &Ouml;nal&rsquo;ın bizi de ilgilendiren ve sık sık tartışılan iki konuda sitemi -belki de &ouml;fkesi- var ki bunları Yeşil&ccedil;am&rsquo;ın sitemi olarak da g&ouml;rebiliriz. Bunların biri emeklilik/sosyal g&uuml;venlik hakları konusunda, diğeri de bunca &uuml;retken ve başarılarla dolu olarak nitelediği sinemacı kimliğine d&ouml;n&uuml;k yapılan eleştiriler. İlki &uuml;zerine: &ldquo;...ev partileri veriyorsunuz, d&uuml;nya g&uuml;zeli kızlar, cumartesi &ouml;ğleden sonraları geliyorlar, akşama kadar dans ediyorsunuz, eğleniyorsunuz, ona g&ouml;re iki dirhem bir &ccedil;ekirdek giyiniyorsun, modayı izliyorsun, film ka&ccedil;ırmıyorsun, yeni bir m&uuml;zik varsa dinliyorsun falan... ...hi&ccedil; durmadan yazıyorsun... karşılığında artırabileceğin kadar değil, ama alıştığın yaşamı s&uuml;rd&uuml;rebileceğin kadar bir para veriliyor, elbet onu da yiyorsun. Beş kuruş artırmıyorsun, artırmak aklının ucundan ge&ccedil;miyor!..&rdquo; (sf. 329). İkincisi &uuml;zerine: &ldquo;Bir internet sitesinde &lsquo;D&ouml;rt y&uuml;z senaryo yazmış da ne olmuş? Nitelik mi nicelik mi? Bu</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Safa &Ouml;na</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">l&rsquo;ın başarısıysa, T&uuml;rk sinemasının kederidir.&rsquo; gibi bir yazı d&ouml;kt&uuml;rm&uuml;ş bir hanımefendi!&rdquo; (sf. 402). Devamlarını okumanızı &ouml;neririm.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeşil&ccedil;am ger&ccedil;ek&ccedil;i kriterlerle analiz edilmiyor. Karınca ile ağustos b&ouml;ceğinin rolleri birbirine karışıyor. Nicelik nitelik, nitelik de nicelik olarak kabul g&ouml;r&uuml;yor. Bunları son kez olsun, bir kez daha tartışalım.. ve bu defterleri artık kapatalım.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/safa_onal_kitabi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (100, 'ay-j219', 'reha-erdem-sinemasi-ask-ve-i-syan', 'Reha Erdem Sineması: Aşk ve İsyan', 'editör: fırat yücel', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/reha_erdem.jpg" alt="reha erdem" width="255" height="385" style="margin-right: 20px; margin-bottom: 10px; float: left;" />edit&ouml;r: fırat y&uuml;cel</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&ccedil;itlembik yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 191 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">dursun veli es</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kesin olan şu: Bir y&ouml;netmenimizin d&uuml;nyasını hem bir b&uuml;t&uuml;nl&uuml;k i&ccedil;inde hem de tematik &ccedil;er&ccedil;evelerin daraltılmış alanında işleyerek bize yakın kılmak i&ccedil;in harcanan &ccedil;abaların en doyurucu &ouml;rneklerinden biri karşımızda durmakta. &Ccedil;er&ccedil;eveler hayatımızda ve sinemada ne kadar kesişiyorsa kitapta da o kadar kesişmekte. Hayatın akışında sıkıcı olan ne varsa, burada, d&uuml;zenlenmiş haliyle sıkı dokunmuş bir d&uuml;nyaya evrilmekte.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Erdem sineması yaralardan sızarak insana ulaşır. Yarattığımız ve yaratılan sınırları aşmak i&ccedil;in hayalleri yardıma &ccedil;ağırdığı da olur. S&ouml;z ge&ccedil;iremediğimiz ruhumuz ve bedenimizle d&uuml;şe kalka yol alır, &ouml;rseleniriz. Sınırları &ccedil;izilen oyun alanımızda soluğumuz yettik&ccedil;e &ccedil;evremizi yontmaya &ccedil;alışırız ve onun yontuları bizim yaralarımız olur. Derken &ouml;nceki yaraları k&uuml;&ccedil;&uuml;mseyen edasıyla aşk &ccedil;ıkagelir, &ccedil;oğu zaman davetsizce. İşte&nbsp;<span class="apple-converted-space"></span><em>Aşk ve İsyan&nbsp;</em>bu kaotik yapıyı ince ince işliyor.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Ger&ccedil;eklik-hayal &ccedil;izgisi, k&uuml;lt&uuml;r, kent-taşra ikiliği, beden ve/veya karakter temelli &ccedil;atışmalar, modernitenin s&uuml;r&uuml;klediği ve aşkın ilgi alanı olarak se&ccedil;tiği karakterler&hellip; Filmler yazıları doyurucu kılıyor; kurgulanmış s&ouml;yleşiler de bir o kadar besleyici. Odaklanılması gereken b&ouml;l&uuml;m ise&nbsp;<span class="apple-converted-space"></span><strong>Reha Erdem&nbsp;</strong>imzasını taşıyan ve kitabımıza adını veren son b&ouml;l&uuml;m. Ve bizim de bir iki s&ouml;z etmemizin nedenidir.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bir kırılma noktası olan&nbsp;<span class="apple-converted-space"></span><em>Beş Vakit</em>,&nbsp;<span class="apple-converted-space"></span><strong>Erdem&nbsp;</strong>sinemasının tanımadığı bir d&uuml;nyaya uzaktan bakabilmesinin zengin getirisini taşır. Zamanın kendi haline bırakıldığı bir coğrafyada bulunmak; insanı kendinden uzak ve ne kadar b&uuml;y&uuml;rse b&uuml;y&uuml;s&uuml;n k&uuml;&ccedil;&uuml;k kılan, kazanma hırsında ve para tutkusunda boğan &ccedil;ılgın kalabalıktan uzağa d&uuml;şmek y&ouml;netmenin en sonunda demlenmesini sağlamıştı. Onun d&uuml;ş&uuml;nsel g&ouml;z&uuml; akıp giden hayatı b&uuml;t&uuml;n par&ccedil;alanmışlığının izlerini s&uuml;rerek &ccedil;&ouml;z&uuml;mlemiş olsa da &uuml;zerine d&uuml;şen kentin g&ouml;lgesinden sıyrılamamıştı. D&uuml;ş&uuml;ncesini, insana sadece t&uuml;keten bir mal olmasını buyuran kentin g&ouml;r&uuml;nmez elleri kıskaca almıştı.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ccedil;ıkmazı g&ouml;ren insan eğer bir d&uuml;ş&uuml;nen insansa &ccedil;ıkışı arar. Aramayan bir d&uuml;nyanın arayan bireyinin portresi &ccedil;ok grotesk ve yaşamla ilintili olmaktan uzaktı. Durduğu yerde duran taşra ise, taşra d&uuml;ş&uuml;n&uuml;n&uuml;n zenginliğinin farkında bile değil. Ona dışarıdan bakan, taşıdığı kentli değerlerin &uuml;stten bakma alışkanlığının boşunalığını anlayarak bakabilen bir g&ouml;z kavrar &ouml;nemini.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span class="style71"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kendine ihsan edilen perdeye sırtını &ccedil;evirip kendi perdelerini yaratmak i&ccedil;in yaralarına film &ccedil;ektirmeyi, film &ccedil;ekerken acı &ccedil;ekmeyi, hayatın akıntısına karşı k&uuml;rek &ccedil;ekmeyi g&ouml;ze alan bir y&ouml;netmenin sinemasını anlamak yolunda elinden &ccedil;ok şey gelen bir yol arkadaşı bu kitap.</span></span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/reha_erdem.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (101, 'ay-j220', 'senaryo-kitabi', 'Senaryo Kitabı', 'öktem başol', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/senaryo_kitabi.jpg" alt="senaryo kitabi" width="424" height="616" style="margin-right: 20px; margin-bottom: 10px; float: left;" />&ouml;ktem başol</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">pana film yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2010 / 622 sf.</span><span style="font-family: \'Times New Roman\', serif; font-size: 12pt;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">İşin başlangı&ccedil; noktasının ne olduğunu bilenler i&ccedil;in senaryonun &ouml;nemi yadsınamaz. Ancak iş &ouml;ğrenmeye gelip dayanınca kimden, hangi kaynaktan, hangi filmler, hangi okuldan gibi soruların ardı arkası kesilmez. Senaryo denince b&uuml;t&uuml;nl&uuml;kl&uuml;, kapsayıcı bir kitap &ouml;nerebileni de bulamazsınız. Tarihsel, hukuksal, formal veya &ouml;rnekleme a&ccedil;ısından zengin bir kaynak arasanız kendinizi &ccedil;ıkmazda bulursunuz. &Ccedil;eviri kitaplar terminolojik a&ccedil;ıdan sorunlar yaratır. Deneyimli senaristler g&uuml;&ccedil; g&ouml;sterisi yapmak i&ccedil;in varını yoğunu ortaya koyar ama yazdıklarını bir tek kendileri anlar. Bu işin &ccedil;ok denklemli bir kimya sorunu olduğu unutularak ortaya konan form&uuml;ller &ndash;hele bir de tek atımlık da olsa tutmuşsa- kanun gibi sunulur.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ouml;ktem Başol</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;un</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Senaryo Kitabı</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;na gelince, kimden sorusuna g&uuml;&ccedil;l&uuml; bir alternatif, kaynak arayışına doyurucu bir yanıt ve &ouml;rnekleme zenginliğiyle zirveye oturan bir eser. Senaryoya tarihsel ge&ccedil;mişinden bakarak yaklaşması, bi&ccedil;imsel veya teknik olarak değişen gereksinimlere nasıl uyum sağladığını a&ccedil;ığa &ccedil;ıkarması, dramatizasyonun gelişim aşamalarını sergilemesi, senaristin elindeki kozları &ouml;rnekleriyle ortaya koyması ve senaryo formları arasındaki girift yapıyı g&ouml;stermesi eserin değerini arttıran &ouml;zellikler.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Senaryo terminolojisinin olduk&ccedil;a doyurucu ve anlaşılır bi&ccedil;imde kullanılmış olması, konuya duyulan ilgiyi ve sahip olunan birikimi yansıtıyor. Ana dilde yazılmış olması ise piyasadaki rakipleriyle arasındaki olası karşılaştırmaları lehine &ccedil;evirebilecek &ouml;nemli bir &ouml;zelliği.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kitabın ayrıntı zenginliğinin &ouml;rt&uuml;k bir olumsuz a&ccedil;ılımı da beraberinde barındırdığı d&uuml;ş&uuml;ncesindeyim. Kısaca, bilgi bombardımanının ters tepmesi bir olasılık. Eser &uuml;&ccedil; beş okumayla &ouml;z&uuml;msenecek cinsten değil. O, &ccedil;ok tipik bir kaynak kitap. Bu arada, hafif ve taşınabilir bir versiyonunun kullanımını kolaylaştıracağı kanısındayım.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Ne yapmalı? Denemeli, tartışmalı, yazmalı, &ccedil;izmeli, gerekirse yeniden başlamalı. Salt okumanın yararı sınırlı tutacağı &uuml;zerinde kendisi de duran &ndash;doğru s&ouml;ze ne denir!-</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Senaryo Kitabı</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nı bu s&uuml;re&ccedil;te deneyimli bir yol g&ouml;sterici olarak başucu kitabı yapmakta yarar var.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/senaryo_kitabi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (102, 'ay-j221', 'senaryo-yazimi-sinema-ve-televizyon-i-cin', 'Senaryo Yazımı - Sinema ve Televizyon İçin', 'william miller', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/senaryo_yazimi.jpg" alt="senaryo yazimi" width="312" height="482" style="margin-right: 20px; margin-bottom: 10px; float: left;" />william miller</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">hayalbaz kitap&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><span style="font-size: 10pt;">&ccedil;ev: yılmaz b&uuml;y&uuml;kerşen, nesrin esen, yal&ccedil;ın demir</span></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">2009 / 280 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right; line-height: normal; margin-bottom: 0pt;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">doğu şenkoy</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Bazı &ccedil;eviri yetersizliklerini, t&uuml;mce sorunlarını ve anlatım bozukluklarını dikkate almam derseniz, senaryo &uuml;zerine en &ouml;nemli ayrıntıları anlaşılır bir dille aktaran ve hatta fazlasını barındıran, g&ouml;r&uuml;lmemiş &ccedil;oklukta &ouml;rnek barındıran bu kitabı mutlaka edinin. Edinmenin de bir riski var, eğer ki okuyup da halen senaryo konusunda kendinizi donanmış hissetmiyor veya &uuml;rettikleriniz senaryomsunun &ouml;tesine ge&ccedil;emiyorsa bilin ki size &ouml;nerilebilecek başka bir kitap yok.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Senaryonun geliştirim aşamalarına uymasa da bilgiyi kurguladığınızda b&uuml;t&uuml;nc&uuml;l bir senaryo bilgisine ulaşabiliyorsunuz. Aslına bakarsanız, kitapta senaryo &uuml;zerine gerekli temel bilginin fazlası var: komedi, uyarlama ve kurmaca-dışı başlıklarında verilen daha ayrıksı senaryo bilgisi.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Miller&rsquo;ın bakışının belki de en farklı yanı, form&uuml;ler yapımın dışında kalan sinemaya olan ilgisinde samimi olması ve ona tanıdığı yaşam alanını &ouml;nemsediğini g&ouml;steren bilgisi. Sadece filmler &uuml;zerinden verdiği &ouml;rnekleri izleyenler bile film bilgisini bir hayli arttırabilir (&ouml;rnekler eski tarihli filmler &uuml;zerinden verilmekte: kitabın baskı tarihi 1980) ve sinema bilgisinin ilk basamaklarını &ccedil;ıkabilir. Bu a&ccedil;ıdan en &ouml;nemlisi, filmi izlerken senaryosunu g&ouml;rebilme yetisini kazanabilmek.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Sinema tarihini 1980 yılıyla başlatanlar i&ccedil;in a&ccedil;ıklarını anlamaları ve kapatmaları i&ccedil;in iyi bir neden.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/senaryo_yazimi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (103, 'ay-j222', 'sinemanin-arkeolojisi', 'Sinemanın Arkeolojisi', 'c. w. ceram', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/sinemanin_arkeolojisi.jpg" alt="sinemanin arkeolojisi" width="293" height="453" style="margin-right: 20px; margin-bottom: 10px; float: left;" />c. w. ceram</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">agora kitaplığı&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">222 syf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right; line-height: normal; margin-bottom: 0pt;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">nagihan konukcu</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: \'Times New Roman\', serif; font-size: 12pt;"></span><span style="font-family: Verdana, sans-serif; font-size: 8.5pt;"><br /></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&Ouml;ns&ouml;z&uuml;nde de not d&uuml;şt&uuml;ğ&uuml; gibi sinemanın teknolojik anlamda doğuşu eksenli arkeik bir &ccedil;alışmaya girişen kitap, sinemanın teknik tarihini &ndash;bir anlamda bu yeni sanatın tarih &ouml;ncesini ve ilk yıllarını&ndash; miras&ccedil;ısı olduğu koşulları yaratan k&uuml;lt&uuml;rel &ouml;nc&uuml;ller &uuml;zerinden g&ouml;rsel bir arşiv eşliğinde g&ouml;zler &ouml;n&uuml;ne seriyor. Bu bağlamda kitabın kuramsal olmaktan &ouml;te &ldquo;belge&rdquo;sel bir kaynak olma kaygısı g&uuml;tt&uuml;ğ&uuml; s&ouml;ylenebilir.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Daha ilk b&ouml;l&uuml;m&uuml;nde sinemanın kavramsal olarak bile &uuml;lkeden &uuml;lkeye farklı k&uuml;lt&uuml;rel kodlara denk d&uuml;şt&uuml;ğ&uuml;ne yapılan vurgu, ilerleyen sayfalarda fotoğrafik g&ouml;r&uuml;nt&uuml;y&uuml; ger&ccedil;ekliğin &ldquo;hareketli g&ouml;r&uuml;nt&uuml;ler dizisi&rdquo;ne d&ouml;n&uuml;şt&uuml;rme yolunda g&ouml;sterilen &ccedil;abaların ortak bir dile evrilmesi noktasında &ouml;nemini yitiriyor. Bir icadın kendinden &ouml;ncekinden biraz daha geliştirilmiş ve kimi zaman sadece kopyalanmış olması (İngiliz optik&ccedil;i Robert William Paul&rsquo;&uuml;n Edison&rsquo;un icadını yeniden &uuml;retmiş olması gibi, syf. 162,163) yoluyla sinemayı end&uuml;striyel bağlamda kozasından gitgide &ccedil;ıkaran girişimler kronolojik bir sıralamaya sadık kalması ile de zihnimizdeki tarihsel s&uuml;recin gelişimine katkı sağlıyor. Kitapta s&ouml;z&uuml; ge&ccedil;en ilk icatların, sinemanın gelişiminde birincil derecede rol oynayan kişilere dair &ccedil;izilmiş portrelerle birlikte verilmiş olmasıyla da &ldquo;kameralı adam&rdquo;ın ger&ccedil;ekliği keşfi, efsane olmaktan &ccedil;ıkarak ilk başta sanatsal ve giderek ticari bir pratik haline geliyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Yazar, sinemayı &ldquo;dikiz eğlencesi&rdquo; kimliği bir yana, i&ccedil;inde d&ouml;nemin siyasal, toplumsal ve sınıfsal koşullarına dair ipu&ccedil;larına da yer bulan bir sanat formu oluşu &ccedil;er&ccedil;evesinde betimlerken eğitsel ve anlatısal &ouml;zelliklerinin altını da &ccedil;iziyor. Diğer yanda fotoğraf ve g&ouml;r&uuml;nt&uuml; arasındaki &ouml;zg&uuml;l farkların algılanamamış olmasının yarattığı eksikliği tarihi ve teknolojik evrim bazında doldurma g&ouml;revini de &uuml;stleniyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Son sayfalarda geniş yer bulan ve kitabın &uuml;zerinde temellendiği &ccedil;ok sayıda kaynak&ccedil;anın varlığı da dikkat edici. Ancak yazarın incelemeleri sırasında &ccedil;ok sayıda hatayla karşı karşıya geldiğini dillendirmesi referans g&ouml;sterilen tarihlere ihtiyatlı yaklaşılması gerektiği telkinini de beraberinde getiriyor. Bu ve daha fazla kaynak&ccedil;aya doğrudan ulaşma şansımız olsaydı eğer, bizim de yazımızın sonuna ekleyebileceğimiz d&uuml;zeltiler olacaktı hi&ccedil; kuşkusuz.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Sinemanın tarih &ouml;ncesi ve bug&uuml;n geldiği nokta arasında bu 222 sayfadan da fazlasının olduğu/ olması gerektiğinin bilgisiyle ayracımızı, sinemanın end&uuml;striyel anlamda doğuşunun &ouml;yk&uuml;s&uuml;nde bırakıyoruz.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/sinemanin_arkeolojisi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (104, 'ay-j223', 'turk-film-arastirmalarinda-yeni-yonelimler-8-sinema-ve-politika', 'Türk Film Araştırmalarında Yeni Yönelimler 8 - Sinema ve Politika', 'yayın haz: deniz bayrakdar', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt; text-align: justify;"><img src="/images/kitaplik/t&uuml;rk_film_araştırmalarında_yeni_y&ouml;nelimler_8.jpg" alt="t&uuml;rk film araştırmalarında yeni y&ouml;nelimler 8" width="427" height="680" style="margin-right: 20px; margin-bottom: 10px; float: left;" />yayın haz: deniz bayrakdar</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">bağlam yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 438 sf.</span><span style="font-family: \'Times New Roman\', serif; font-size: 12pt;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 8.5pt; font-family: Verdana, sans-serif;"><br /></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Tanıdık konferans dizisinin sekizincisi, ortaya &ccedil;ıkan kitabın hacmine bakılınca verimli ge&ccedil;mişe benziyor. Yazılar &ccedil;oğaldık&ccedil;a kendini yıldan yıla giderek hissettiren bir durum a&ccedil;ığa &ccedil;ıkar oldu. Ya benzer b&uuml;t&uuml;n konferanslarda kabul g&ouml;recek kadar &ouml;zg&uuml;n, kapsamlı, &ouml;zenli ve kalıcı yazılar ve &ouml;te yanda sıradan, yoksul, ham, u&ccedil;ucu yazılar. Bir de her iki sınıfta da bulunabilen tema dışı yazılar g&ouml;ze &ccedil;arpmakta. A&ccedil;ılışı yapan</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Ella Shohat</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Kutsal S&ouml;z, D&uuml;nyevi G&ouml;r&uuml;nt&uuml;: Uyarlamanın Teolojileri</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Serdar &Ouml;zt&uuml;rk</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;&uuml;n</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>S&ouml;ylemsel İnşalardan &Uuml;retilen Sans&uuml;r ve Denetim Efsanesi (1896-1923)</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">, bir</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Ayşe Bayramoğlu&nbsp;</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">-&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Deniz Ceyhan Arman&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">-&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Sezin Bozacı&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ortak yapımı olan</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Darbe-Muhtıra Ortak Yapımı: K&uuml;&ccedil;&uuml;k Birey</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Zahit Atam</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın ideolojinin sığ derinliğini aydınlatan</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>T&uuml;rkiye&rsquo;de Sinema İdeolojiyi Hatırlarken</i>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve&nbsp;</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Giacomo Manzoli</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nin y&ouml;netmeni anlamayanlara inat ince dokundurmalarla bezediği</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Pasolini&rsquo;nin Politik Bakışının &Ccedil;ağdaş İtalyan Sinemasına Etkileri</i>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">adlı yazıları ele aldıkları konu &uuml;zerindeki birikimlerini belirgin bi&ccedil;imde ortaya koyarak konferansı zengin kılan &uuml;r&uuml;nler olarak &ouml;ne &ccedil;ıktılar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">İki yazı var ki konferansın &ccedil;ıtasını y&uuml;kseltmelerine rağmen, farklı a&ccedil;ılardan &uuml;zerinde durmak gerekiyor. Biri</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Savaş Arslan</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>J&ouml;n T&uuml;rk Shakespeare&rsquo;in Hamletleri</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">, diğeri de</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Dina Iordanova</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nın</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Bu Kimin Hafızası? Balkan Sinemasında Suskun Anlatılar ve Se&ccedil;ici Hatırlama</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">. İlkinin bu se&ccedil;kide ne aradığı, ikincisinin ise ulusal sinemanın politik s&ouml;ylem ve kimliğini nasıl kazanacağı &uuml;zerine yol g&ouml;stericiliği &uuml;zerinde durulması gerekiyor. Ve konferansın doruğunda bir</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<b>Zeynep T&uuml;l Akbal S&uuml;alp</b>&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">yazısı tek başına duruyor:</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&nbsp;<i>Yabanıl, Dışarlıklı ve L&uuml;mpen &lsquo;Hi&ccedil;lik&rsquo; Kutsamaları</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Okura k&uuml;&ccedil;&uuml;k bir uyarı ile veda edelim. Bunun bir tercihten mi kaynaklandığını bilmiyoruz ama s&ouml;yleşiler her daim bir fiyasko olma &ouml;zelliğini koruyor. Katılımcılar ve hatta bazı y&ouml;neticilerin &uuml;zerine konuştukları konu hakkında i&ccedil;selleşmemiş bilgiye sahip oldukları veya ona bile sahip olmadıkları &ccedil;ok &ccedil;abuk anlaşılıyor. S&ouml;yleşilerin ortalama d&uuml;zeyini y&uuml;kselttiğini d&uuml;ş&uuml;nd&uuml;ğ&uuml;m&uuml;z sorulara yazık oluyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/t&uuml;rk_film_araştırmalarında_yeni_y&ouml;nelimler_8.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (105, 'ay-j224', 'turk-sinemasinda-akim-arastirmasi', 'Türk Sinemasında Akım Araştırması', 'esin coşkun', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/turk_sinemasinda_akim_arastirmasi.jpg" alt="turk sinemasinda akim arastirmasi" width="398" height="576" style="margin-right: 20px; margin-bottom: 10px; float: left;" />esin coşkun</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">phoenix yayınları&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">2009 / 92 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right; line-height: normal; margin-bottom: 0pt;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">erol b&uuml;y&uuml;kyazıcı</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">T&uuml;rk sinema tarihi &uuml;zerine odaklanan hemen her kitabın izlediği yolda bir kez daha y&uuml;r&uuml;yoruz. İzini s&uuml;rd&uuml;ğ&uuml;m&uuml;z şey</span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&nbsp;<b>Coşkun</b></span><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&rsquo;un kitabın &ouml;ns&ouml;z&uuml;nde de belirttiği gibi olmayan bir şey: sinemamızda bir akım bulmak. Yoksa niye y&uuml;r&uuml;yoruz, biz de bilmiyoruz. Y&uuml;r&uuml;yoruz. Aslına bakarsanız, olmayanın olmadığını ortaya &ccedil;ıkarmak da &ouml;nemli bir iş.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify; line-height: normal; margin-bottom: 0pt;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">İki b&ouml;l&uuml;m olarak d&uuml;zenlenmiş kitabın ilk b&ouml;l&uuml;m&uuml;nde konumuzla ilgili olmayan bir başka yolda y&uuml;r&uuml;meyi s&uuml;rd&uuml;r&uuml;yoruz. Bu b&ouml;l&uuml;m başlangıcından 1960&rsquo;lara kadar sinemamızın tarihini &ouml;zetlemekte. Tiyatrocular D&ouml;nemi diye adlandırılan bu s&uuml;re&ccedil;te tiyatrocuların sinema &uuml;zerinde oyun, y&ouml;netmenlik veya konu se&ccedil;imi a&ccedil;ısından ne kadar etkin olduklarından ve bu d&ouml;nem i&ccedil;inde yer alan 1915-48 yılları arasına Muhsin Ertuğrul&rsquo;un vurduğu damgadan s&ouml;z ediyor. D&ouml;nemin sonunda bir sonraki b&ouml;l&uuml;mde işlenen hareketlenmenin ilk &ouml;rnekleri &uuml;zerinde duruluyor. Ve ikinci b&ouml;l&uuml;m bu hareketlerin T&uuml;rkiye&rsquo;nin o zamanki siyasal ve toplumsal ortamından beslendiğini ve bu doğrultuda &uuml;retilen filmler olduğu &uuml;zerinde duruyor. Bu hareketler sırasıyla toplumsal ger&ccedil;ek&ccedil;ilik, halk sineması, ulusal sinema, milli sinema ve gen&ccedil; sinema başlıklarında işlenmekte ve y&ouml;netmenler, filmler ve yayınlardan yola &ccedil;ıkılarak bağlantılar a&ccedil;ıklanmakta ve &ouml;rnekler verilmekte. Coşkun, &ouml;zet olarak akımların oluşması i&ccedil;in nelerin gerektiğini ve nelerin eksik olduğunu a&ccedil;ıklıyor. Meraklısının ilgisini &ccedil;ekecek t&uuml;rden bir kitap olduğuna ş&uuml;phe olmasa da, bazı noktalara dikkat &ccedil;ekmek isterim. Metin kes-yapıştır tarzında kurulduğundan olsa gerek, alıntıdan ge&ccedil;ilmiyor. Filmlerle ilgili yapılan a&ccedil;ıklamalarda g&ouml;r&uuml;len orantısızlık, olasılıkla bazı filmlerin izlenmemiş olmasından kaynaklanıyor. Gereksiz b&ouml;l&uuml;mler şişirilmişken, akım araştırmasına odaklı b&ouml;l&uuml;m yeterince işlenmemiş. Kitabı bir akımımızın bile olmadığı ger&ccedil;eğiyle y&uuml;zleşmek &uuml;zere kapatırken, başka sorulara yanıtlar arıyoruz. &Ouml;ns&ouml;zde konumuzla hi&ccedil; ilgisi olmasa da karşımıza &ccedil;ıkan ve yanıtını net olarak alamadığımız bir sorumuz oldu: Amerikan sinemasında akım var mı, yok mu? Amerikan ger&ccedil;ek&ccedil;i sineması denen akım hangi akım? D&ouml;nemin akımlarının sinemamızı etkilediği s&ouml;ylense de, kronolojik olarak bakıldığında ortada bir terslik var. Hollywood r&ouml;nesansının ardındaki g&uuml;&ccedil;, bizim olmayan sinema akımlarımız olabilir mi?</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/turk_sinemasinda_akim_arastirmasi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (106, 'ay-j225', 'turk-sinematek-dernegi-turkiye-de-sinema-ve-politik-tartisma', 'Türk Sinematek Derneği -Türkiye\'de Sinema ve Politik Tartışma-', 'hakkı başgüney', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;"><img src="/images/kitaplik/turk_sinematek_dernegi.jpg" alt="turk sinematek dernegi" width="198" height="306" style="margin-right: 20px; margin-bottom: 10px; float: left;" />hakkı başg&uuml;ney</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">libra yayınları&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">2010 / 197 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: right;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">g&ouml;khan g&ouml;kdoğan</span></b></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Başg&uuml;ney</span></b><span style="font-family: Verdana, sans-serif; font-size: 10pt;">&rsquo;in y&uuml;ksek lisans tezini bizlerle paylaşmasıyla ortaya &ccedil;ıkan eser, T&uuml;rk sineması i&ccedil;in yadsınamayacak bir yeri olan <b>Sinematek Derneği</b>&rsquo;nin, gelişimini, sinemamızın gelişimindeki etkilerini, o d&ouml;nem T&uuml;rkiye&rsquo;sine getirdiği yenilikleri ve &ccedil;eşitli gruplarla d&uuml;şt&uuml;ğ&uuml; fikir ayrılıklarını enine boyuna tartışmayı vaat ediyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Kitap birinci b&ouml;l&uuml;mde, &ouml;nceliği sanatsal bir form olarak sinemayı değerlendirmeye verir. Sonrasında s&ouml;z&uuml; 60lar ve 70lere, daha da &ouml;nemlisi T&uuml;rkiye ve T&uuml;rk sinemasına getirene kadar &ccedil;ok da kendini belli etmeyen bir b&uuml;t&uuml;nl&uuml;k i&ccedil;erisinde, d&uuml;nya sosyo-k&uuml;lt&uuml;rel tarihi, sinema tarihi ve aralarındaki ilişki &uuml;zerinde dolandırıyor. Ardından, d&ouml;nemin T&uuml;rkiye&rsquo;sinin k&uuml;lt&uuml;rel, sanatsal ve politik ortamını, i&ccedil;ine sinemayı ve bazen de Sinematek Derneği&rsquo;ni katık etmesiyle bitiyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">İkinci b&ouml;l&uuml;mde ise tam da yazarın vaat ettiği gibi, konu Sinematek Derneği&rsquo;nin oluşumu, o d&ouml;nem T&uuml;rkiye&rsquo;sine kattıkları ve değiştirdikleri &uuml;zerinden ilerlemeye başlıyor. Derneğin, odağını kendini tanımaktan d&uuml;nyayı tanımaya doğru kaydıran bir toplumu d&uuml;nyanın değişik b&ouml;lgelerinden gelen sanat filmleriyle tanıştırarak d&ouml;nemin k&uuml;lt&uuml;r-sanat ortamına sağladığı katkılara değiniliyor. &Uuml;&ccedil;&uuml;nc&uuml; b&ouml;l&uuml;mde, derneğin <b>Ulusal Sinemacılar</b>&rsquo;la d&uuml;şt&uuml;ğ&uuml; fikir ayrılıkları iki bakış a&ccedil;ısından da değerlendirilip, &ouml;nce derneğin i&ccedil;inden kopan&nbsp;<b>Gen&ccedil; Sinema Topluluğu</b>&rsquo;ndan, sonra da derneğin odağının sinemadan siyasete kaymasından yani tabiri caizse &ccedil;&ouml;k&uuml;ş d&ouml;neminden bahsediliyor. Ulusal Sinemacılar&rsquo;ın Batı&rsquo;ya gereksiz &ouml;yk&uuml;nme olarak yorumlamasına rağmen Sinematek&ccedil;iler&rsquo;in evrensel sanata ulaşma olarak adlandırdığı sinema hareketi &uuml;zerine iki tarafın savunularını yaptığı b&ouml;l&uuml;m, o d&ouml;nem &uuml;lke sineması &uuml;zerine faydalı bilgiler aktarıyor. Doğu-Batı, Evrensellik-Yerellik, Bireycilik- Halk&ccedil;ılık ve Gelişmişlik-Az Gelişmişlik eksenleri &uuml;zerinden t&uuml;m sinema gruplarının konumlandırılması d&ouml;rd&uuml;nc&uuml; b&ouml;l&uuml;m&uuml;n tartışma alanı olarak g&ouml;ze &ccedil;arpıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Sinema ve Devrim isimli son b&ouml;l&uuml;mde ise son 5-6 sayfaya kadar bırakın Sinematek Derneği&rsquo;ni T&uuml;rk sinemasından bile hemen hi&ccedil; bahsedilmezken, <b>Godard</b> başta olmak &uuml;zere politik sinemanın &ouml;nc&uuml;leri &uuml;zerinden sinemada bi&ccedil;im ve i&ccedil;erik sorunu politik bir bakış a&ccedil;ısıyla ele alınıp, avangart ve &uuml;&ccedil;&uuml;nc&uuml; &uuml;lke sineması kavramları inceleniyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">Kitabın &ouml;nemli problemlerinden biri olarak odağın T&uuml;rk Sinematek Derneği başlığından kaymasını g&ouml;sterebiliriz. Kitabın girişinde, T&uuml;rk sinema tarihi &ccedil;alışmalarında yeterli &ouml;l&ccedil;&uuml;de yer verilmemiş bu derneğe bir yer a&ccedil;mayı &ccedil;alışmasının hedefi olarak belirten yazar, aynı hataya d&uuml;şerek kitabının isminde kullanmasına rağmen, i&ccedil;erikte derneği yardımcı oyuncu olarak kullanıyor. Bir diğer problem olarak kaynak yetersizliği g&ouml;sterilebilir. Yazılı olarak ulaştığı tek kaynak olan &lsquo;Yeni Sinema&rsquo; dergisinin t&uuml;m sayılarına ulaşan biri olarak belirtmek istediğim şudur: Dergi ile verilen g&ouml;sterim programlarının sayfa numarası taşımasını, ciltlenmek i&ccedil;in tasarlandıkları bi&ccedil;iminde yorumlamak dayanaksız. Programların sayfaları dağıtıldıkları dergilerin sayfa numarasını izleyecek bi&ccedil;imde numaralandırılmıştır. Ayrıca Federico Fellini, Roberto Rosselini, Pierre Paolo Passolini, Satyajit Ray, Krzysztof Zanussi, Mahmut Tali &Ouml;ng&ouml;ren, Andrej Wajda ve Maria Faranturi gibi hatalı isim kullanımları &ouml;zensizliğin kanıtları olarak g&ouml;ze &ccedil;arpıyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/turk_sinematek_dernegi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (107, 'ay-j226', 'yeni-i-ran-sinemasi-siyaset-temsil-ve-kimlik', 'Yeni İran Sineması - Siyaset, Temsil ve Kimlik', 'editör: richard tapper', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/yeni_iran_sinemasi.jpg" alt="yeni iran sinemasi" width="262" height="400" style="margin-right: 20px; margin-bottom: 10px; float: left;" />edit&ouml;r: richard tapper</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt; text-align: justify;">kapı yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-family: Verdana, sans-serif; font-size: 10pt; text-align: justify;"><span style="font-size: 13px;">&ccedil;ev: kemal sarıs&ouml;zen</span></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-family: Verdana, sans-serif; font-size: 10pt;">ocak 2007 / 340 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 12pt; font-family: \'Times New Roman\', serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">1999 yılında Londra National Film Theater&rsquo;da yapılan İran Film Festivali kapsamında ger&ccedil;ekleştirilen konferans sunumlarının g&ouml;zden ge&ccedil;irilmesiyle oluşturulan bir derleme kitap. İranlıların &ccedil;oğunlukta olduğu yazar kadrosu bug&uuml;ne kadar İran sineması &uuml;zerine yazılmışlar arasında en nitelikli ve en kapsamlılarından&nbsp; biri olan bu kitabın ortaya &ccedil;ıkmasında en &ouml;nemli etken.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Bazı yazılar yapıtın niteliğini y&uuml;kseltmek konusunda başrol&uuml; &uuml;stlenmiş durumdalar. İran&rsquo;da Film K&uuml;lt&uuml;r&uuml;n&uuml;n İslamileştirilmesi: Hatemi Sonrasının G&uuml;ncel Verileri adlı yazısı yerinde bir se&ccedil;imle başa konulan Hamid Nefisi&rsquo;nin anlatım dili kadar bilgi donanımı da etkileyici. Yerli yapımlar &uuml;zerine &uuml;retim ve sans&uuml;r istatistikleri, İslami sinemanın nitelikleri, &uuml;retim ve g&ouml;sterimi d&uuml;zenleyen koşullar, satın alınan yabancı filmler &uuml;zerine istatistikler, kamu ve &ouml;zel sekt&ouml;r&uuml;n yapımcı rol&uuml;ne bağlı olarak ortaya konulan sayısal veriler, &uuml;retimin film t&uuml;rlerine g&ouml;re sınıflandırılması ve Hatemi sonrası sinemanın durumu gibi &ccedil;ok zengin bir birikimin a&ccedil;ığa &ccedil;ıkmasını sağlıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">İstatistiklerle desteklediği İran Sinema Sanayiinde Kriz ve H&uuml;k&uuml;metin Rol&uuml; adlı yazısıyla, H&uuml;seyin Gaziyan sekt&ouml;r&uuml;n kamusal &ccedil;ıkmazları &uuml;zerinde duruyor. Sans&uuml;r ve otosans&uuml;r&uuml;n işleyiş koşulları ve bir &ccedil;ıkış yolu olan film festivallerinde İran sinemasının sergilediği performansa odaklanan yazısıyla Azade Ferahmend; Muhsin Mahmelbaf sinemasındaki değişim evreleri &uuml;zerine son derece a&ccedil;ıklayıcı yazısıyla Hamid Dabaşi; İran sinemasında savaş teması &uuml;zerine &ccedil;ekilen filmleri i&ccedil;lerinden iki filmi &ouml;ne &ccedil;ıkararak yaptığı saptamalarla dikkat &ccedil;eken Roxanne Varzi; İran Filmlerinde Fiziksel Mekan ve K&uuml;lt&uuml;rel Kimlik adlı yazısıyla, yapımcısından seyircisine uzanan bir zincirde bir filmin k&uuml;lt&uuml;rel &uuml;r&uuml;n olarak algılanmasında mekanın rol&uuml; &uuml;zerine etkileyici bir bakış sunan Mihrnaz Said-Vefa; İffetli Taş Bebekler İffetsiz Taş Bebekler başlığı altında devrim sonrasında &ccedil;ok tartışılan kadının sunumu konusunu işleyen Şehla Lahici; yine &uuml;zerinde &ccedil;ok durulan &ccedil;ocuğun sunumu &uuml;zerine, &Ccedil;ağdaş İran Sinemasında &Ccedil;ocuklar: Biz &Ccedil;ocukken adlı yazısıyla Hamid Rıza Sadr ve İran sinemasının kilometre taşı yapıtlarından, Behram Beyzayi&rsquo;nin Başu: K&uuml;&ccedil;&uuml;k Yabancı filmini &ccedil;&ouml;z&uuml;mlediği, &ccedil;&ouml;z&uuml;mlerken ulusal sinemanın hemen b&uuml;t&uuml;n &ouml;nemli noktalarına değinerek &ouml;rnek bir film &ccedil;&ouml;z&uuml;mlemesi yapan Nesrin Rahimiye sunulan geniş vizyonun oluşmasında birbirlerinin g&ouml;r&uuml;şlerini b&uuml;t&uuml;nleyen etkileyici bir toplama ulaşıyorlar.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Son s&ouml;z&uuml; yazma onuru verilen Laura Mulvey ise entelekt&uuml;el Batılı tiplemesi &ccedil;izdiği yazısında, i&ccedil;tenlik sosuna bulanmış da olsa g&uuml;venli sularda y&uuml;zen o bildik teorik s&ouml;ylemlerini yinelemesi ve son noktada Kiyar&uuml;stemi sinemasına gelip dayanmasıyla yadırgatmadı.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yeni_iran_sinemasi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (108, 'ay-j227', 'yesilcam-hatirasi', 'Yeşilçam Hatırası', 'mesut kara', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/yesilcam_hatirasi.jpg" alt="yesilcam hatirasi" width="283" height="449" style="margin-right: 20px; margin-bottom: 10px; float: left;" />mesut kara</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">+1 Kitap &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2005 / 254 sf.</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">doğu şenkoy</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 12pt; font-family: \'Times New Roman\', serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Artizler Kahvesi</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeşil&ccedil;am&rsquo;da Unutulmayan Y&uuml;zler&nbsp;</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve şimdi de&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeşil&ccedil;am Hatırası</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">... Mesut Kara T&uuml;rk sinemasının belleklere kazınmış y&uuml;zlerini, filmlerden kitap sayfalarına dur durak demeden indirmeyi s&uuml;rd&uuml;r&uuml;yor. &Uuml;nl&uuml;s&uuml; &uuml;ns&uuml;z&uuml;, unutulmuşu unutulmazı, unutulmaya y&uuml;z tutanlarla adını geleceğe yazdırmış olanları, başrolleri yan rolleri, eskileri yenileri, kameranın &ouml;n&uuml;ndekileri arkasındakileri, g&uuml;ld&uuml;renleri ağlatanları ayırt etmeden s&uuml;rd&uuml;r&uuml;yor bu uğraşı. Kara&rsquo;nın &ccedil;ocukluğundan ve gen&ccedil;liğinden kopup gelen, siyah-beyazı ve renklisiyle bu kareler d&uuml;n&uuml; bug&uuml;ne ve giderek yarına kurguluyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kara nesnel davranmıyor her zaman, duygusal ve yanlı &ccedil;&ouml;z&uuml;mlemeler yapıyor. Ama &ccedil;oktandır unutulan haklı bir neden var bunun ardında: Yeşil&ccedil;am&rsquo;a duyulan sevgi ve zamana direnmeyi başarmış g&uuml;&ccedil;l&uuml; bir &ouml;zlem. Ama bu durum bazı sorunların da kaynağını oluşturuyor. Bazı isimler &uuml;zerine yazdıkları yeterli doyuruculuktan uzak kalıyor, kaynak değeri taşımaktan uzak d&uuml;ş&uuml;yor, eksiklerinin tamamlanmasını yazarından istiyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kara kitabının giriş yazısında genel &ccedil;izgileriyle sinemaya olan yaklaşımını a&ccedil;ıklıyor. Yeşil&ccedil;am ile halk arasındaki sıcak ilişkinin &uuml;zerinde duruyor. Ardından kopuş yıllarını ve tv ile sağlanan dostluk ve kaybedilen değerlerin yeniden hatırlanmasını dile getiriyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeşil&ccedil;am Hatırası iki ana b&ouml;l&uuml;mden oluşuyor. Bazen arkasına ge&ccedil;miş olsalar da kameranın &ouml;n&uuml;ndeki halleriyle anımsananlar ve kamera arkasındakiler. İlk b&ouml;l&uuml;mde&nbsp;<b>Cahide Sonku</b>,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Ayhan Işık</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Belgin Doruk</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Sadri Alışık&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">gibi &ouml;nde gelen isimlerin yanında&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Orhon Murat Arıburnu</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Atıf Kaptan&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Necdet Mahfi Ayral&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">gibi &ouml;nemli isimlerle karşılaşmak g&uuml;zeldi. Sonku yazısında oyuncunun elimizdeki bilgilerde y&ouml;netmen olarak g&ouml;z&uuml;kt&uuml;ğ&uuml; &uuml;&ccedil; filmden sadece biri,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Vatan ve Namık Kemal&nbsp;</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">dikkate alınmış. Kaynaklarda ortak olan ve tanıklıklarla da desteklenen&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Beklenen Şarkı&nbsp;</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">B&uuml;y&uuml;k Sır&nbsp;</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">es ge&ccedil;ilmiş. Benzer bir durum,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Nazım Hikmet</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;te de g&ouml;ze &ccedil;arpıyor. Bir başka nokta, 1963 yılında &ouml;len&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Suphi Kaner&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">nasıl oluyor da 1964 yapımı filmlerde oynuyor ve y&ouml;netmenlik yapıyor? Bu ve benzeri durumlar aslına bakarsanız diğer kaynaklarda da var. Anlaşılan o ki yazarlar kesin kanıt olmayınca kendi yorumlarıyla hareket ediyor; yapım yılı yerine filmlerin g&ouml;sterim tarihini dikkate alıyor. Tarih yazımında aslolan yapım yılıdır. Jenerikleri dikkate alır, magazini ardına eklersiniz, eğer dilerseniz. Bazı &ouml;l&uuml;m tarihleri eksik ve tarih karışıklıkları da var.&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Turgut &Ouml;zatay</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Danyal Topatan&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Neriman K&ouml;ksal&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">yazıları g&ouml;rece zayıf kalıyor. Bu t&uuml;r yazılar &ccedil;oşkun ifadelerle kaleme alınabilir ama kaynak değeri taşımasını engelleyecek eksiklere ve hatalara yer verilmemeli. Ancak, en azından kendi adıma,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Danyal Topatan</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın 1962&rsquo;de ger&ccedil;ekleştirdiği ilk ve son y&ouml;netmenlik deneyimini &ouml;ğrenmek bile değerli.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kaynak değeri taşıyan yazıların &ccedil;oğunluğu kitabın ikinci b&ouml;l&uuml;m&uuml;nde yer alıyor. &Ouml;zellikle&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Halit Refiğ,&nbsp;</span></b><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Nazım Hikmet</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">,&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Nedim Otyam&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ve&nbsp;</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">H&uuml;seyin Kuzu&nbsp;</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">yazıları onların d&uuml;nyalarına girmenin &ouml;tesinde, genel sinema k&uuml;lt&uuml;r&uuml; a&ccedil;ısından da besleyici nitelikte yazılar.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yesilcam_hatirasi.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (109, 'ay-j228', 'yonetmen-sinemasi-dervis-zaim', 'Yönetmen Sineması: Derviş Zaim', 'haz: ayşe pay', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/yonetmen_sinemasi_dervis_zaim.jpg" alt="yonetmen sinemasi dervis zaim" width="485" height="791" style="margin-right: 20px; margin-bottom: 10px; float: left;" />haz: ayşe pay</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">k&uuml;re yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 96 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">nagihan konukcu</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><span style="font-size: 8.5pt; font-family: Verdana, sans-serif;"><b style="font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></b></span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kitap, izini ancak geleneksel olanla yakından kurduğu ilişki sayesinde s&uuml;rebildiğimiz </span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Zaim</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in, dilinin ve estetik anlayışının, yaşadığı toplumun tarihinden ve g&uuml;ndeminden beslendiği filmografisi ile beraber hayattaki &lsquo;değer &uuml;retme &ccedil;abası&rsquo;nı tartışmaya a&ccedil;ıyor. Bunu yaparken de farklı yazarların </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in filmlerine ilişkin kaleme aldıkları &ccedil;&ouml;z&uuml;mlemelerden yararlanıyor. &Ccedil;oklukla mekan-karakter-sembolizm odaklı bu &ccedil;&ouml;z&uuml;mlemelerin temel tartışma alanı ise, </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in başlangı&ccedil; ve bitiş &ccedil;izgisi arasında ge&ccedil;irdiği evrimlerin sinemasına yansıma bi&ccedil;imlerinin, filmleriyle yakınlık kurmamızda &ouml;n&uuml;m&uuml;ze koyduğu engeller. &Ccedil;&ouml;z&uuml;mlemelerin bu engelleri a&ccedil;ıklığa kavuşturmak konusunda başarılı olduğunun altını &ccedil;izmekte yarar var. &Ccedil;&uuml;nk&uuml; </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in filmografisinin y&uuml;zeyden dibe doğru giden anlatı eksenine karşın, yazarlar filmleri dipten y&uuml;zeye &ndash;ge&ccedil;mişten bug&uuml;ne- bir bakışla irdeliyorlar; y&ouml;netmenin seyirci ile kuramadığı bağı, kitabın okuyucu ile kurması bu anlamda kayda değer.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Tabutta R&ouml;vaşata&nbsp;</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ile başlayıp </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b><i>Nokta</i></b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"> ile şimdilik noktalanmış bir filmografi, t&uuml;m filmlerini izleyenler i&ccedil;in </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in T&uuml;rk sinemasında nerede durduğu/nereye gittiği konusunda belirsizlik yaratır. &Ccedil;oklukla seyircinin g&ouml;z&uuml; &ouml;n&uuml;nde denemeye dayalı bu sinema anlayışı, kendisini temsil etmesinin &ouml;n&uuml;n&uuml; tıkar. Kitabın birincil niyeti, bu kendini a&ccedil;ık etmezlik halinin, dilini yaratmak konusunda </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;i, filmlerine dahil olmak noktasında da bizi nelerden mahrum bıraktığını/bırakmış olabileceğini sorgulamaktır.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Tabutta R&ouml;vaşata</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nın aidiyetsizliği, </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b><i>Filler ve &Ccedil;imen</i></b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in rastlantısallık vurgusu, </span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ccedil;amur</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;un sembolik karmaşası, </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b><i>Cenneti Beklerken</i></b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in geleneksel dinamiği ve </span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Nokta</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;nın su&ccedil; ve ceza eksenli anlatısı hem </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"> sinemasının temsil ettiklerini hem de </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in sinemasını temsil eden kavramları harekete ge&ccedil;irir. Bireyin &ccedil;ıkmazından, politik ilişki ağlarına; mitolojiden hat sanatına filmlerine katkı sağlayan konular ve malzemeler </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in bi&ccedil;imsel kaygılarını g&uuml;d&uuml;ler, peki yan anlamlar arasında sıkışıp kalmış filmler ve bu filmleri g&uuml;d&uuml;leyen ger&ccedil;ek niyetler, filmografisi &uuml;zerinden </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;i okumaya, onunla &ouml;zdeşlik kurmaya ne kadar imkan tanır? </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in bu &ouml;zdeşliği bilin&ccedil;li olarak kırmak i&ccedil;in sergilediği mesafeli duruş, onu seyirciden uzak bir noktaya fırlatır; kitap bu anlamda okuyucuyu yakın bir noktaya geri getirip, seyircinin </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;e bir şans vermesini sağlıyor.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Filmlere ilişkin &ccedil;&ouml;z&uuml;mleme yazılarından sonra </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"> ile yapılan bir s&ouml;yleşiye de yer veren kitap hemen ardından da </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b>Zaim</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;in biyografisi ve filmografisini okuyucu ile paylaşıyor ki, bu i&ccedil;erik kurgusu kitabın kapak ve i&ccedil; tasarımı ile birleşince, ortaya &ccedil;oğu sinema kitabında yazık ki g&ouml;remediğimiz &ouml;zenli bir &ccedil;alışma &ccedil;ıkıyor.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yonetmen_sinemasi_dervis_zaim.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (110, 'ay-j229', 'yonetmen-sinemasi-nuri-bilge-ceylan', 'Yönetmen Sineması: Nuri Bilge Ceylan', 'haz: ayşe pay', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/Yonetmen_Sinemasi_Nuri_Bilge_Ceylan.jpg" alt="Yonetmen Sinemasi Nuri Bilge Ceylan" width="485" height="791" style="margin-right: 20px; margin-bottom: 10px; float: left;" />haz: ayşe pay</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">k&uuml;re yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 76 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">burcu atahan</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; line-height: 15.3333px; font-family: Verdana, sans-serif;"></span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Sosyal bilimler &uuml;zerine olan yayınları okuyucularla buluşturan K&uuml;re Yayınları ilgi alanına sinemayı da katmış g&ouml;r&uuml;n&uuml;yor. Y&ouml;netmen Sineması dizisinde Derviş Zaim, Zeki Demirkubuz ve Nuri Bilge Ceylan kitapları bulunuyor. Dizinin Ceylan sinemasına odaklanan kitabının &ouml;ns&ouml;z&uuml; diğerlerinde de olduğu gibi İhsan Kabil&rsquo;den. Filmleri haklarında hi&ccedil;bir bilgi verilmeyen d&ouml;rt yazar değerlendirmekte. <i>Nuri Bilge Ceylan&rsquo;ın Taşrası&rsquo;</i>nı değerlendiren Hilal Turan Cumhuriyet&rsquo;in kuruluşundan beri gerek politikadaki taşraya y&ouml;nelik s&ouml;ylemin, gerek romanlarda taşranın konumlandırılma bi&ccedil;iminin yarattığı &ccedil;arpıklığın Ceylan&rsquo;ın sinemasıyla kırıldığını belirterek; bundan hareketle Kasaba ve Mayıs Sıkıntısı&rsquo;nı Deleuze&rsquo;&uuml;n <i>kristal &ouml;yk&uuml;leme</i> kavramıyla &ouml;rt&uuml;şt&uuml;r&uuml;r. Ceylan sinemasında taşra &uuml;zerinden <i>iktidar, hiyerarşi </i>ve <i>otorite</i>&rsquo;nin nasıl bi&ccedil;imlendiğini a&ccedil;ıklamaya &ccedil;alışır. <i>Kavramsal Bir Mesafe Olarak Uzak&rsquo;</i>ta ise Esra Bulut, Uzak&rsquo;ı taşradan kente g&ouml;&ccedil; ederek doğadan kopan insanın &ouml;z&uuml;ne yabancılaşarak &lsquo;hi&ccedil;leşmesi&rsquo; &ccedil;er&ccedil;evesinde ele alır. Modern yaşamın tetiklediği bireysellikle <i>&ouml;teki</i>&rsquo;ne olan mesafenin </span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">b&uuml;y&uuml;d&uuml;ğ&uuml;n&uuml; belirtip Ceylan&rsquo;ın <i>aidiyet</i>, <i>kimlik</i>, <i>mahremiyet </i>ve <i>bellek</i> kavramlarının altını &ccedil;izdiğini s&ouml;yler. Ayrıca Ceylan&rsquo;ın filmografisini d&ouml;nemlere ayırır ancak derinlemesine incelemez.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Yeni Kutsal&rsquo;a &Ouml;denen Bedel</span></i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;le</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ayşe Pay </b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Tanrının yerini alan Sanat&ccedil;ı ve modernizmle kutsallığını kaybeden dinin yerini kapan Sanat&rsquo;tan yola &ccedil;ıkar. &Ouml;yle ki sanat artık din ya da ahlak gibi kutsal kabul edilen eylemlerin &ccedil;ok &ccedil;ok &uuml;zerinde bir kutsallıkla sarmalar kendisini. Sanatın kendini var ettiği her alan kutsallaştırılıp sanatın sorgusu da bir kenara atılır. Sanat bir put halini alır tapınılan. B&ouml;ylece ger&ccedil;ek sanatı, sanat eserini ayırt etmek zorlaşır.</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan </b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ise sinemanın</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><i> sanat </i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">olduğu ger&ccedil;eğiyle y&uuml;zleştirir bizi.</span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"> İklimler</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;den yola &ccedil;ıkarak sanata y&uuml;klenen kutsallığın ortaya &ccedil;ıkardığı soruların yanıtını bulmaya &ccedil;alışır</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Pay</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">. Ancak yanıtları ararken</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> İklimler</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;de gerek kadın ve erkeğin konumlandırılış bi&ccedil;imlerini gerek karakterlerin kendi i&ccedil;sel b&uuml;t&uuml;nl&uuml;klerinin yaratımını tersten okumak ya da anlamak istediği gibi anlamak gibi bir yanılgıya d&uuml;şer. Sanki değindiği</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> İklimler </b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">değil de kendi kafasında oynayan bir filmdir. B&ouml;yle olunca da filme y&uuml;klenen ve filmden &ccedil;ıkarılan anlam haliyle asıl anlamından kopup başka tarafa evrilir. </span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Fuat Er</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><i> &Uuml;&ccedil; Maymun: Cehennemde Bir Fotoğraf&rsquo;</i></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">ta fotoğraf ve fotoğrafik ger&ccedil;ekliğin</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan </b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">sinemasının hayati unsuru olduğundan hareketle fotoğrafın dikizleyen bakışının kentin g&ouml;r&uuml;nen ger&ccedil;eklerine değil karanlık k&ouml;şelerine d&ouml;nd&uuml;ğ&uuml;n&uuml; s&ouml;yler.</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın anlatısını a&ccedil;ık u&ccedil;lu imgeler &uuml;zerinden kurduğunu, işlenen konuların sinemamızda yeni olmamasına karşın farkın</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın dilinde ve yarattığı mesafede olduğunun altını &ccedil;izer. Keza</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b><i> &Uuml;&ccedil; Maymun</i></b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;da anlatılan klasik bir konu olmasına rağmen </span><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Ceylan</span></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;da bambaşka bir hale b&uuml;r&uuml;n&uuml;r. Sesin kullanımı ise karakterlerin ruh hallerini ve i&ccedil; &ccedil;atışmalarını yansıtması bakımından &ouml;nemlidir.</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan</b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın diğer filmlerinde, işlediği taşra hayatının da kusurları olduğunu g&ouml;stermesine rağmen</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b><i> &Uuml;&ccedil; Maymun</i></b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;da tam bir cehennem resmettiğini vurgular.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kuramsal dayanağı olmamasına rağmen,</span><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><b> Ceylan </b></span><span style="font-size: 10pt; font-family: Verdana, sans-serif;">sinemasını anlamak isteyenlere yarattığı tartışma alanları sayesinde olduk&ccedil;a faydalı olacak bir kitap. Ancak </span><b><i><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Uzak</span></i></b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&rsquo;ın Cannes&rsquo;da aldığı J&uuml;ri B&uuml;y&uuml;k &Ouml;d&uuml;l&uuml;&rsquo;n&uuml;n J&uuml;ri &Ouml;zel &Ouml;d&uuml;l&uuml; olarak yazılmasının burada da yinelenmesi g&ouml;zlerden ka&ccedil;mıyor. Kapak tasarımı ise yayınevinin i&ccedil;erik kadar g&ouml;rselliğe de verdiği &ouml;nemin, bakmayı bilenlerden bakıldığını bilenlere y&ouml;nelen bir s&ouml;z&uuml;n kanıtı.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/Yonetmen_Sinemasi_Nuri_Bilge_Ceylan.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (111, 'ay-j230', 'yonetmen-sinemasi-zeki-demirkubuz', 'Yönetmen Sineması: Zeki Demirkubuz', 'haz: ayşe pay', '<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"><img src="/images/kitaplik/yonetmen_sinemasi_zeki_demirkubuz.jpg" alt="yonetmen sinemasi zeki demirkubuz" width="484" height="791" style="margin-right: 20px; margin-bottom: 10px; float: left;" />haz: ayşe pay</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">k&uuml;re yayınları &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">2009 / 128 sf.</span></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: right;"><b><span style="font-size: 10pt; font-family: Verdana, sans-serif;">serap zeren</span></b></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 8.5pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Reddedilerek var olmayı tercih eden, k&ouml;t&uuml;l&uuml;ğ&uuml; anlatarak erdemi anlatmanın peşine d&uuml;şen ve &lsquo;<strong>Dostoyevski</strong>, edebiyat olmasaydı sinemacı olmamda hem teknik hem manevi bir şeyim olmazdı&rsquo; diyen <span class="apple-converted-space"></span><strong>Demirkubuz</strong>&rsquo;un sinemasının sinematografisini, temalarının ortak s&ouml;ylemini, karakterlerinin i&ccedil;d&uuml;nyasını ve yapıtlarının anlatı dilini &ccedil;eşitli disiplinlerden gelen yazarlar psikanalitik ve felsefi a&ccedil;ıdan &ccedil;&ouml;z&uuml;mlemesini yaparak inceliyorlar.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">&Ouml;zellikle varoluş&ccedil;u &ccedil;er&ccedil;evede ve <span class="apple-converted-space"></span><strong>Dostoyevski </strong>&uuml;zerinden ele aldıklarında veya <strong>Heidegger</strong>, <span class="apple-converted-space"></span><strong>Nietzsche</strong>, <span class="apple-converted-space"></span><strong>Alain Badiou</strong>, <span class="apple-converted-space"></span><strong>Bakhtin</strong>, <span class="apple-converted-space"></span><strong>Barthes </strong>gibi d&uuml;ş&uuml;n&uuml;rlerin g&ouml;z&uuml;nden karşılaştırdıklarında <span class="apple-converted-space"></span><strong>Demirkubuz </strong>sinemasının felsefi bir var olma noktasına gelemediğini; anlatımının arabesk patetik olduğunu; karakterlerin sınıfsal kimliklerden, sosyolojik, toplumsal ve felsefi boyuttan &ccedil;ok yaptıkları eyleme odaklandıklarını; nihilizm, inan&ccedil;sızlık ve sıkıntı &uuml;zerine uzun deme&ccedil;lerindeki umarsız tavrının sinir bozucu bir narsizm i&ccedil;erdiğini, &ouml;znesi olmayan kolektif bir s&ouml;ylem i&ccedil;inden seslendiğini; maj&ouml;r dil &uuml;zerinden min&ouml;r bir sinema yaptığını ve anlatımının da kapalı bir anlamlılık i&ccedil;erdiğini vurguluyorlar.</span></p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;"></span></p>\r\n<p>&nbsp;</p>\r\n<p class="style7" style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; margin-top: 0cm; margin-right: 0cm; margin-bottom: 0.0001pt; text-align: justify;"><span style="font-size: 10pt; font-family: Verdana, sans-serif;">Kitabın sonundaki s&ouml;yleşide <span class="apple-converted-space"></span><strong>Demirkubuz </strong>insanların genelde sırtlarını, akıllarını şahsi vicdanlarına değil de makama ve otoriteye dayandırdıklarını, karakterlerinin felsefi bir profil &ccedil;izmesi i&ccedil;in &ccedil;aba g&ouml;stermediğini ve hi&ccedil;bir şeye hizmet etmediklerini, &ccedil;ıplak insanı anlattığını dile getiriyor.<span class="apple-converted-space"></span><em>&lsquo;Daha d&uuml;n yery&uuml;z&uuml;n&uuml; rastgele dolaştım, &uuml;zerinde dolaştığım binlerce yol beni hi&ccedil;bir yere g&ouml;t&uuml;rmedi; &ccedil;&uuml;nk&uuml; onlar başkalarının yollarıydı. Bug&uuml;n yalnızca tek bir yolum var; nereye gittiğini tanrı bilir ama o benim yolum.&rsquo;</em><span class="apple-converted-space"></span>diyen <span class="apple-converted-space"></span><strong>Sartre</strong>&rsquo;ın <span class="apple-converted-space"></span><em><b>Sinekler </b></em>adlı romanının kahramanı Orestles gibi <span class="apple-converted-space"></span><strong>Demirkubuz </strong>da s&ouml;yleşisinde<span class="apple-converted-space"></span><em>&lsquo;Benim yolum bu.&rsquo; </em><span class="apple-converted-space"></span>diyor. Kendine ait dertleri, arayışları olan, sorgulamaya ve yaşadığını anlamaya &ccedil;alışan ve rastlantılar sonucu sinemanın kapısına geldiğini s&ouml;yleyen <span class="apple-converted-space"></span><strong>Demirkubuz </strong>ve sinemasını (ve anlamsızlığın anlamını) anlamamız adına &ouml;nemli bir &ccedil;alışma.</span></p>', 1, 31, 'Sinema Kitaplığı', '/images/kitaplik/yonetmen_sinemasi_zeki_demirkubuz.jpg', '2017-03-16');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (112, 'ay-j123', 'sekans-film-elestirisi-yarismasi-2016', 'Sekans Film Eleştirisi Yarışması 2016', '', '<p style="text-align: right;"><a href="/docs/duyurular/yarisma2016duyuru.pdf" target="_blank" rel="noopener noreferrer"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/yarisma2016.gif" alt="yarisma2016" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında &uuml;r&uuml;n veren amat&ouml;r veya profesyonel yazarların &uuml;r&uuml;nlerini değerlendirmek ve b&ouml;ylece film eleştirisi &uuml;retimini desteklemek ve &ouml;zendirmek; sinema k&uuml;lt&uuml;r&uuml;n&uuml;n gelişmesine katkı ve bu alanda &uuml;retim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında &uuml;retilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının &ouml;n&uuml;n&uuml; a&ccedil;mak amacıyla d&uuml;zenlediği <strong>Sekans Film Eleştirisi Yarışması&rsquo;nın beşincisini</strong> ger&ccedil;ekleştirecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ul>\r\n<li><em>Başvurular elektronik olarak (e-mail yoluyla) yapılacaktır. Yazının elimize ulaştığı bilgisi, başvuru sahibine iletilir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>T&uuml;rkiye yapımı filmler</strong> &uuml;zerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha &ouml;nce yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar en &ccedil;ok iki yazıyla başvurabilir.</em></li>\r\n<li><em>&Ccedil;eviri eleştiri yazılarıyla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto, &ccedil;ift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, t&uuml;r&uuml; vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin k&uuml;nyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: Filmin Adı, Yılı, S&uuml;resi, Y&ouml;netmen, Senaryo, G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni, Sanat Y&ouml;netmeni, M&uuml;zik, Kurgu, Oyuncular.</em></li>\r\n<li><em>Yazıların dili T&uuml;rk&ccedil;e olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar a&ccedil;ısından amat&ouml;r-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan t&uuml;m yazıların yayın haklarının 1 Haziran 2017 g&uuml;n&uuml;ne kadar SEKANS SİNEMA GRUBU&rsquo;na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde &ouml;n elemeyi aşamazlar.</em></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU Y&Ouml;NTEMİ</strong></p>\r\n<p>Yarışma başvuruları, son başvuru tarihi olan <strong>20 Mayıs 2016 Cuma</strong> g&uuml;n&uuml;ne kadar yarisma@sekans.org adresine yapılır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME S&Uuml;RECİ</strong></p>\r\n<p><strong>&Ouml;n Değerlendirme</strong></p>\r\n<p>Yazıların &ouml;n elemesini ger&ccedil;ekleştirecek olan Eleme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır.</p>\r\n<p><em>&Ouml;n değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve &ccedil;&ouml;z&uuml;mleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Se&ccedil;ici Kurul Değerlendirmesi</strong></p>\r\n<p>&Ouml;n değerlendirmeden ge&ccedil;en en fazla 10 yazı <strong>Se&ccedil;ici Kurul</strong> tarafından değerlendirilecek ve yarışmanın birinci, ikinci ve &uuml;&ccedil;&uuml;nc&uuml;l&uuml;ğe değer bulunan eleştiri yazıları belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Se&ccedil;ici Kurul</strong></em></p>\r\n<p style="padding-left: 35pt;">Zeynep T&uuml;l Akbal S&uuml;alp (Akademisyen)</p>\r\n<p style="padding-left: 35pt;">Arzu &Ccedil;evikalp (Sinema Yazarı)</p>\r\n<p style="padding-left: 35pt;">Taşkın Takış (Yayıncı)</p>\r\n<p style="padding-left: 35pt;">Serdar Gergerlioğlu (Sinefil)</p>\r\n<p style="padding-left: 35pt;">Altuğ Kaan Pa&ccedil;acı (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONU&Ccedil; DUYURUSU</strong></p>\r\n<p>Yarışma sonu&ccedil;ları <strong>30 Mayıs 2016 Pazartesi</strong> g&uuml;n&uuml; Sekans web sitesinde ve medyada duyurulacaktır. &Ouml;d&uuml;l alan yazılar, elektronik dergimiz SEKANS Sinema K&uuml;lt&uuml;r&uuml; Dergisi\'nde yayımlanmak &uuml;zere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/yarisma2016_sponsorlari_1060x94.gif" alt="yarisma2016 sponsorlari 1060x94" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2016-03-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (113, 'ay-j124', 'film-elestirisi-yarismasi-sonuclari', 'Film Eleştirisi Yarışması Sonuçları', 'FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2021', '<p><strong>FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2021</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Zuhal Çetin Özkan&nbsp;(Akademisyen)</p>\r\n<p>Ertan Tunç&nbsp;(Sinema Yazarı)</p>\r\n<p>Yavuz Akyıldız&nbsp;(Akademisyen)</p>\r\n<p>Derya Akman&nbsp;(Sekans - Sinema Yazarı)</p>\r\n<p>Evin Konuk&nbsp;(Sinefil)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Çözümlemesi Yarışması</strong></p>\r\n<p>Birinci:<strong> Atifet Sena Keleşoğlu&nbsp;</strong>– Bir Subtopia Atlası ya da Kentin&nbsp;<em>Hayaletler</em>’i&nbsp;(Hayaletler&nbsp;/ Azra Deniz Okyay)</p>\r\n<p>İkinci:<strong> Görkem Önal</strong>&nbsp;– Bal ve Barutun Analojisi:&nbsp;<em>Kovan&nbsp;</em>(Kovan&nbsp;/ Eylem Kaftan)</p>\r\n<p>Üçüncü:<strong> Yasin Dereli&nbsp;</strong>– Pelin Esmer’in <em>İşe Yarar Bir Şey</em>&nbsp;Filminin Göstergebilimsel&nbsp;Açıdan Çözümlenmesi&nbsp;(İşe Yarar Bir Şey&nbsp;/ Pelin Esmer)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Eleştirisi Yarışması</strong></p>\r\n<p>Bu kategoride dereceye giren yarışmacı bulunmamaktadır.</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong>FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2020</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Ayhan Çınar&nbsp;(Sinefil)</p>\r\n<p>Erdem İlic&nbsp;(Sinema Yazarı)</p>\r\n<p>Lale Kabadayı&nbsp;(Akademisyen - Sinema Yazarı)</p>\r\n<p>Mine Tezgiden&nbsp;(Sekans - Sinema Yazarı)</p>\r\n<p>Zehra Yiğit&nbsp;(Akademisyen - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Eleştirisi Yarışması</strong></p>\r\n<p>Birinci:<strong> Murat Çağıltay</strong>&nbsp;– Hayallerim, İstanbul ve Punk (Arada&nbsp;/ Mu Tunç)</p>\r\n<p>İkinci:<strong> Esra Ballım</strong>&nbsp;– Densizlik Ömür Boyu... (Rüzgarda Salınan Nilüfer&nbsp;/ Seren Yüce)</p>\r\n<p>Üçüncü:<strong> Ş. Gülbin Paytar</strong>&nbsp;– <em>Kelebekler</em>&nbsp;Ya Da Yitip Gidenler (Kelebekler&nbsp;/ Tolga Karaçelik)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Çözümlemesi Yarışması</strong></p>\r\n<p>Birinci:<strong> Sevcan Sönmez</strong>&nbsp;– Distopik Durumdan Üreyen Ütopya:&nbsp;<em>Körfez</em>&nbsp;(Körfez&nbsp;/ Emre Yeksan)</p>\r\n<p>İkinci:<strong> Azmi Recep Özdaş</strong>&nbsp;– Gündeliğin Bilinci: İyi Günlerde Kirlenmek (Toz Bezi&nbsp;/ Ahu Öztürk)</p>\r\n<p>Üçüncü:<strong> Onur Keşaplı&nbsp;</strong>–&nbsp;<em>Aidiyet</em>&nbsp;ve Arınma (Aidiyet&nbsp;/ Burak Çevik)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong>FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2019</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Ulaş Başar Gezgin&nbsp;(Akademisyen)</p>\r\n<p>Barış Saydam&nbsp;(Sinema Yazarı)</p>\r\n<p>Emrah Günok&nbsp;(Sinefil)</p>\r\n<p>Gökhan Erkılıç&nbsp;(Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Eleştirisi Yarışması</strong></p>\r\n<p>Birinci:<strong> Murat Çağıltay</strong>&nbsp;– Post Travmatik Türküler (Kaygı&nbsp;/ Ceylan Özgün Özçelik)</p>\r\n<p>İkinciliğe ve üçüncülüğe uygun yazı bulunamamıştır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Çözümlemesi Yarışması</strong></p>\r\n<p>Birinci:<strong> Çisel Bilgen Ceylan</strong>&nbsp;– Zamansız Oğullar,&nbsp;<em>Ali’nin Sekiz Günü</em>&nbsp;Üzerine (Ali’nin Sekiz Günü&nbsp;/ Cemal Şan)</p>\r\n<p>İkinci:<strong> Esra Ballım</strong>&nbsp;– <em>Beş Vakit</em>’te Büyümekle Büyüyememek Arasında (Beş Vakit&nbsp;/ Reha Erdem)</p>\r\n<p>Üçüncü:<strong> Zeynep Tekin Taş </strong>–&nbsp;Eril Dünyanın <em>Kuyu</em>’su (Kuyu&nbsp;/ Metin Erksan)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong>FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2018</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Hakan Karaş&nbsp;(Akademisyen)</p>\r\n<p>Neşe Ürel&nbsp;(Sinema Yazarı)</p>\r\n<p>Semih Erelvanlı&nbsp;(Sinefil)</p>\r\n<p>Sertaç Koyuncu&nbsp;(Sinefil)</p>\r\n<p>Ekin Eren&nbsp;(Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Eleştirisi Yarışması</strong></p>\r\n<p>Birinci:<strong> Kezban Özgün </strong>–&nbsp;Yolunda A.Ş.&nbsp;(<em>Yolunda A.Ş.</em>&nbsp;/ Emre Budak)</p>\r\n<p>İkinciliğe ve üçüncülüğe uygun yazı bulunamamıştır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Film Çözümlemesi Yarışması</strong></p>\r\n<p>Birinci:<strong> Zeynep Duran </strong>–&nbsp;Bir Neden Arayışı Olarak Yaşamak ya da Ölmek:&nbsp;<em>İşe Yarar Bir Şey</em>&nbsp;(İşe Yarar Bir Şey&nbsp;/ Pelin Esmer)</p>\r\n<p>İkinci:<strong> İbrahim Karabiber </strong>–&nbsp;<em>Üç Maymun</em>&nbsp;(Üç Maymun&nbsp;/ Nuri Bilge Ceylan)</p>\r\n<p>Üçüncü:<strong> Baki Demirtaş </strong>– Nefes mi <em>Buğday</em> mı? (Buğday&nbsp;/ Semih Kaplanoğlu)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p style="line-height: 1.71429;"><strong>FİLM ELEŞTİRİSİ VE ÇÖZÜMLEMESİ YARIŞMASI 2017</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Serdar Öztürk&nbsp;(Akademisyen)</p>\r\n<p>Tunca Arslan&nbsp;(Sinema Yazarı)</p>\r\n<p>Yaşar Hız&nbsp;(Yayıncı)</p>\r\n<p>Mustafa Ertekin&nbsp;(Sinefil)</p>\r\n<p>Seda Usubütün&nbsp;(Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p>Birinci:<strong> Yusuf Emre Yalçın </strong>–&nbsp;Sinemanın Kanatsız Lilith’i: Sibel (Duvara Karşı&nbsp;/ Fatih Akın)</p>\r\n<p>İkinci:<strong> Mustafa Cihan Camcı </strong>–&nbsp;Özgün Bir Tutku Öyküsü:&nbsp;<em>Kader</em>&nbsp;(Kader&nbsp;/ Zeki Demirkubuz)</p>\r\n<p>Üçüncü:<strong> Süheyla Tolunay İşlek </strong>–&nbsp;<em>Koca Dünya</em>: Bir Masal Evreninde Yollarını ve Babalarını&nbsp;Bulamayan Çocuklar (Koca Dünya&nbsp;/ Reha Erdem)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p style="line-height: 1.71429;"><strong>FİLM ELEŞTİRİSİ YARIŞMASI 2016</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p style="line-height: 1.71429;">Zeynep Tül Akbal Süalp (Akademisyen)</p>\r\n<p style="line-height: 1.71429;">Arzu Çevikalp (Sinema Yazarı)</p>\r\n<p style="line-height: 1.71429;">Taşkın Takış (Yayıncı)</p>\r\n<p style="line-height: 1.71429;">Serdar Gergerlioğlu (Sinefil)</p>\r\n<p style="line-height: 1.71429;">Altuğ Kaan Paçacı (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;">Birinci:<strong> İbrahim Karabiber</strong>&nbsp;<span style="color: #333333;">–</span>&nbsp;<em>Babam ve Oğlum</em>&nbsp;(Babam ve Oğlum / Çağan Irmak)</p>\r\n<p style="line-height: 1.71429;">İkinci:<strong> Gizem Çınar</strong>&nbsp;– Çürümenin Merkezi Olarak Aile ve Modernite (Pandora\'nın Kutusu / Yeşim Ustaoğlu)</p>\r\n<p style="line-height: 1.71429;">Üçüncü:<strong> Özgür Erdi Akbaba</strong>&nbsp;– Zehirli Fikirler (Sarmaşık / Tolga Karaçelik)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong><strong style="color: #333333;">FİLM ELEŞTİRİSİ YARIŞMASI</strong> 2015</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Dilek Tunalı (Akademisyen)</p>\r\n<p>Banu Bozdemir (Sinema Yazarı)</p>\r\n<p>Hakan Tanıttıran (Yayıncı)</p>\r\n<p>Haluk Güriz (Sinefil)</p>\r\n<p>İlker Mutlu (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p>Birinci:<strong> Osman Özarslan</strong> – <em>Yeraltı</em>’nın İnsanı (Yeraltı / Zeki Demirkubuz)</p>\r\n<p>İkinci:<strong> Süheyla Tolunay</strong>&nbsp;– <em>Babamın Sesi</em>: Seslerin İzinde Geçmiş Zamana ve Geçmemiş Acılara Yolculuk (Babamın Sesi / Zeynel Doğan ve Orhan Eskiköy)</p>\r\n<p>Üçüncü:<strong> Recep Özdaş</strong>&nbsp;– Gerilim Olur musun? (Köksüz / Deniz Akçay)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong><strong style="color: #333333;">FİLM ELEŞTİRİSİ YARIŞMASI</strong> 2014</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Oğuzhan Ersümer (Akademisyen-Sinema Yazarı)</p>\r\n<p>Gül Yaşartürk (Akademisyen-Sinema Yazarı)</p>\r\n<p>Cem Kayalıgil (Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p>Birinci:<strong> Dilan İlhan&nbsp;</strong>– İnsan Yazgısının Yalın Hikayelerinden Biri: <em>Kasaba</em>&nbsp;(Kasaba / Nuri Bilge Ceylan)&nbsp;</p>\r\n<p style="text-align: justify;">İkinci:<strong>&nbsp;Halil Sanbur </strong>–<strong> &nbsp;</strong><em>Karnaval</em> (Karnaval / Can Kılcıoğlu)</p>\r\n<p>Üçüncü:<strong>&nbsp;Dila Madenoğlu </strong>–<strong> &nbsp;</strong><em>Atlıkarınca</em>: Ve At Karıncayı Ezdi (Atlıkarınca / İlksen Başarır)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong><strong style="color: #333333;">FİLM ELEŞTİRİSİ YARIŞMASI</strong> 2013</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Seçici Kurul</strong></p>\r\n<p>Barış Kılıçbay (Akademisyen)</p>\r\n<p>Şenay Aydemir (Sinema Yazarı)</p>\r\n<p>Nagihan Konukcu (Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p>Birinci:<strong> Ulaş Başar Gezgin&nbsp;</strong>– Türkiye Sinemasında Karlı Bir Doruk: <em>Ağrı Dağı Efsanesi</em>&nbsp;Üstüne (Ağrı Dağı Efsanesi / M. Ün)&nbsp;</p>\r\n<p style="text-align: justify;">İkinci:<strong>&nbsp;Öktem Aykut&nbsp;</strong>– <em>İklimler</em> ve Nuri Bilge Ceylan (İklimler / N. B. Ceylan)</p>\r\n<p>Üçüncü:<strong>&nbsp;Mikail Boz </strong>–<strong>&nbsp;</strong><em>Uzak</em>&nbsp;(Uzak / N. B. Ceylan)</p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p><strong><strong style="color: #333333;">FİLM ELEŞTİRİSİ YARIŞMASI</strong> 2012</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul</strong></p>\r\n<p>Hakan Savaş</p>\r\n<p>Ahmet Gürata</p>\r\n<p>Ece Özdemir</p>\r\n<p>&nbsp;</p>\r\n<p>Birinci:<strong> Altuğ Kaan Paçacı&nbsp;</strong>– Pencerenin Ardı (Bir Zamanlar Anadolu’da / N.B. Ceylan)</p>\r\n<p>İkinci:<strong>&nbsp;İbrahim Karabiber&nbsp;</strong>– <em>Masumiyet</em> (Masumiyet / Z. Demirkubuz)</p>\r\n<p>Üçüncü:<strong>&nbsp;Nur Engindeniz&nbsp;</strong>– <em>Pippa’ya Mektubum</em>&nbsp;(Pippa’ya Mektubum / B. Elmas)</p>', 1, 64, 'Duyuru', NULL, '2016-03-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (114, 'ay-j130', 'sekans-film-elestirisi-yarismasinin-besincisi-sonuclandi', 'Sekans Film Eleştirisi Yarışmasının Beşincisi Sonuçlandı', '', '<p style="text-align: right;">&nbsp;</p>\r\n<p><strong><img src="/images/duyurular/yarisma2016.gif" alt="yarisma2016" style="margin-left: 20px; float: right;" /></strong>Film eleştirisi alanında &uuml;r&uuml;n veren amat&ouml;r veya profesyonel yazarların &uuml;r&uuml;nlerini değerlendirmek ve b&ouml;ylece film eleştirisi &uuml;retimini desteklemek ve &ouml;zendirmek; sinema k&uuml;lt&uuml;r&uuml;n&uuml;n gelişmesine katkı ve bu alanda &uuml;retim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında &uuml;retilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının &ouml;n&uuml;n&uuml; a&ccedil;mak i&ccedil;in Sekans Sinema Grubu tarafından bu yıl beşincisi d&uuml;zenlenen Sekans Film Eleştirisi Yarışması sonu&ccedil;landı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları Kalkedon Yayıncılık, Kolektif Kitap, Say Yayınları ve Doğu Batı Yayınları oldu.</p>\r\n<p>&nbsp;</p>\r\n<p><strong style="line-height: 1.71429;">Se&ccedil;ici Kurul Değerlendirmesi</strong></p>\r\n<p>&Ouml;n elemeyi ge&ccedil;en d&ouml;rt eleştiri yazısı arasından <strong>Zeynep T&uuml;l Akbal S&uuml;alp</strong>,<strong> Arzu &Ccedil;evikalp</strong>,<strong> Taşkın Takış</strong>,<strong> Serdar Gergerlioğlu</strong>, ve<strong> Altuğ Kaan Pa&ccedil;acı</strong>\'dan oluşan j&uuml;rinin değerlendirmesi aşağıdaki gibi sonu&ccedil;landı:</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Birinci: İbrahim Karabiber</strong> - "Babam ve Oğlum" (Babam ve Oğlum / &Ccedil;ağan Irmak)</p>\r\n<p><strong>İkinci: Gizem &Ccedil;ınar</strong> - "&Ccedil;&uuml;r&uuml;menin Merkezi Olarak Aile ve Modernite" (Pandora\'nın Kutusu / Yeşim Ustaoğlu)</p>\r\n<p><strong>&Uuml;&ccedil;&uuml;nc&uuml;: &Ouml;zg&uuml;r Erdi Akbaba</strong> - "Zehirli Fikirler" (Sarmaşık / Tolga Kara&ccedil;elik)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/yarisma2016_sponsorlari_1060x94.gif" alt="yarisma2016 sponsorlari 1060x94" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/yarisma2016.gif', '2016-05-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (115, 'ay-j135', 'sekans-si-nema-grubu-semi-nerleri-i-ki-baslikta-aciliyor', 'SEKANS SİNEMA GRUBU SEMİNERLERİ İKİ BAŞLIKTA AÇILIYOR', '1. FİLM ÇÖZÜMLEMESİ SEMİNERİ', '<p id="yui_3_16_0_ym19_1_1477160384853_3594" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;"><strong style="font-size: 14px;">1. FİLM &Ccedil;&Ouml;Z&Uuml;MLEMESİ SEMİNERİ</strong></p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3592" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">Sinemanın g&uuml;c&uuml; ancak filmlerin taşıdığı anlam a&ccedil;ığa &ccedil;ıkarıldığında anlaşılabilir. &Ccedil;&ouml;z&uuml;mleme bilgisi, film &ccedil;&ouml;z&uuml;mlemelerinde belli tekniklerin kullanılması alışkanlığını yerleştireceği gibi, film eleştirisine ge&ccedil;iş konusunda da &ouml;nemli bir altyapının kurulmasını sağlar.</p>\r\n<p>&nbsp;</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3586" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">Seminerde, film &ccedil;&ouml;z&uuml;mlemesinde kullanılan gelenek&ccedil;i ve modernist yaklaşımlar &ouml;rneklerle aktarılmaktadır. Anlatı &ccedil;&ouml;z&uuml;mlemesi t&uuml;rleri ve film &ccedil;&ouml;z&uuml;mlemesinde odaklanılan anlatısal ve sinemasal &ouml;ğeler &uuml;zerinde durulmaktadır. Her &ccedil;&ouml;z&uuml;mleme modeli i&ccedil;in &ouml;rnek filmlerin &ccedil;&ouml;z&uuml;mlemesi yapılmaktadır.</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3763" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">Seminer 5 ay olup toplam 20 oturumdan oluşmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3964" class="yiv3708626558MsoNormal" style="font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif; font-size: 14px; font-weight: bold; color: #000000; padding: 0px; margin-bottom: 0px;">2. G&Ouml;R&Uuml;NT&Uuml; TASARIMI SEMİNERİ</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3741" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">G&ouml;r&uuml;nt&uuml; &ouml;ğelerinin temelini oluşturan kamera, kamera a&ccedil;ıları ve hareketleri, &ccedil;ekim &ouml;l&ccedil;ekleri, aydınlatma, sanat y&ouml;netimi, ses gibi teknik unsurlar ve temel kavramlar &uuml;zerinde detaylı olarak durulmaktadır. Bunların yanı sıra, anlatının g&uuml;c&uuml;n&uuml; belirlediğine inandığımız bi&ccedil;im-i&ccedil;erik ilişkisi her teknik unsur i&ccedil;in ayrıntılı bir şekilde tartışılmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3858" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">Senaryo Yazım Teknikleri Semineri ve Kurgu Semineri ile birlikte Temel Sinema Eğitimi Seminer dizisinin bir par&ccedil;asıdır.</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3859" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">G&ouml;r&uuml;nt&uuml; Tasarımı Semineri&rsquo;nin s&uuml;resi 4 aydır.</p>\r\n<p>&nbsp;</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_4026" class="yiv3708626558MsoNormal alert alert-info" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">&Ouml;NEMLİ NOT:</p>\r\n<p class="yiv3708626558MsoNormal" style="margin-bottom: 0px; margin-left: 60px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">1)<span style="font-size: 7pt; line-height: normal; font-family: \'times new roman\';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>Seminerlerimiz Ankara&rsquo;da ger&ccedil;ekleştirilmektedir.</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3750" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; margin-left: 60px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">2)<span style="font-size: 7pt; line-height: normal; font-family: \'times new roman\';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>Katılmak isteyenler i&ccedil;in son başvuru tarihi 6 Kasım Pazar g&uuml;n&uuml;d&uuml;r.</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3751" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; margin-left: 60px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">3)<span style="font-size: 7pt; line-height: normal; font-family: \'times new roman\';">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>Seminerlerimizin ilk oturum g&uuml;n ve saatleri, katılımcıların tercihlerine g&ouml;re belirlenecektir. L&uuml;tfen m&uuml;sait olduğunuz ya da olmadığınız g&uuml;n ve saatleri belirtiniz. Seminerlerimiz genelde hafta i&ccedil;i akşam (19:00-21:00) ve hafta sonu &ouml;ğleden sonra yapılmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_4052" class="yiv3708626558MsoNormal tip-title" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">İletişim (ANKARA):</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3874" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">Halil Sanbur</p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3762" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;"><a href="mailto:halilsanbur@sekans.org" target="_blank" rel="nofollow" style="margin: 0px; padding: 0px; text-decoration: underline; color: #196ad4; outline: none;" shape="rect">halilsanbur@sekans.org</a></p>\r\n<p id="yui_3_16_0_ym19_1_1477160384853_3761" class="yiv3708626558MsoNormal" style="margin-bottom: 0px; padding: 0px; color: #000000; font-family: \'Helvetica Neue\', \'Segoe UI\', Helvetica, Arial, \'Lucida Grande\', sans-serif;">0533 516 8021 (WhatsApp ile de ulaşabilirsiniz)</p>', 1, 64, 'Duyuru', NULL, '2016-10-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (116, 'ay-j141', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2017', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2017', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS%20FİLM%20ELEŞTİRİSİ%20YARIŞMASI-2017.pdf" target="_blank" rel="noopener noreferrer" title="Duyuru 2017"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/SekansFilmYarismasi2017_600x450.jpg" alt="SekansFilmYarismasi2017 600x450" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında &uuml;r&uuml;n veren amat&ouml;r veya profesyonel yazarların &uuml;r&uuml;nlerini değerlendirmek ve b&ouml;ylece film eleştirisi &uuml;retimini desteklemek ve &ouml;zendirmek; sinema k&uuml;lt&uuml;r&uuml;n&uuml;n gelişmesine katkı ve bu alanda &uuml;retim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında &uuml;retilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının &ouml;n&uuml;n&uuml; a&ccedil;mak amacıyla d&uuml;zenlediği <strong>Sekans Film Eleştirisi Yarışması&rsquo;nın altıncısını</strong>&nbsp;ger&ccedil;ekleştirecektir.</p>\r\n<p>&nbsp;Bu yıldan itibaren yarışmaya g&ouml;nderilen yazılar film eleştirisi ve film &ccedil;&ouml;z&uuml;mlemesi olmak &uuml;zere iki ayrı kategoride değerlendirilecek, &ouml;d&uuml;l almaya uygun g&ouml;r&uuml;len ilk &uuml;&ccedil; yazı her iki kategori i&ccedil;in ayrı olarak belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular elektronik olarak (e-posta yoluyla) yapılacaktır. Yazının elimize ulaştığı bilgisi, başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>T&uuml;rkiye yapımı filmler</strong> &uuml;zerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha &ouml;nce yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar aynı veya farklı kategorilere en &ccedil;ok iki yazıyla başvurabilir.</em></li>\r\n<li><em>&Ccedil;eviri eleştiri veya &ccedil;eviri &ccedil;&ouml;z&uuml;mleme yazılarıyla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve &ccedil;ift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, t&uuml;r&uuml; vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin k&uuml;nyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: Filmin Adı, Yılı, S&uuml;resi, Y&ouml;netmeni, Senaristi, G&ouml;r&uuml;nt&uuml; Y&ouml;netmeni, Sanat Y&ouml;netmeni, M&uuml;zik, Kurgu, Oyuncular.</em></li>\r\n<li><em>Yazıların dili T&uuml;rk&ccedil;e olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar a&ccedil;ısından amat&ouml;r-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan t&uuml;m yazıların yayın haklarının 1 Haziran 2018 g&uuml;n&uuml;ne kadar SEKANS SİNEMA GRUBU&rsquo;na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde &ouml;n elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU Y&Ouml;NTEMİ</strong></p>\r\n<p>Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film &ccedil;&ouml;z&uuml;mlemesi) son başvuru tarihi olan <strong>21 Mayıs 2017 Pazar</strong>&nbsp;g&uuml;n&uuml;ne kadar yarisma@sekans.org adresine yapılır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME S&Uuml;RECİ</strong></p>\r\n<p><strong>&Ouml;n Değerlendirme</strong></p>\r\n<p>Yazıların &ouml;n elemesini ger&ccedil;ekleştirecek olan Eleme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. &Ouml;n değerlendirme kurulu tarafından yazıların değerlendirileceği başvuru kategorisinde değişiklik yapılabilir.</p>\r\n<p><em>&Ouml;n değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve &ccedil;&ouml;z&uuml;mleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Se&ccedil;ici Kurul Değerlendirmesi</strong></p>\r\n<p>Her iki yarışma kategorisi i&ccedil;in &ouml;n elemeden ge&ccedil;en en fazla 10\'ar yazı <strong>Se&ccedil;ici Kurul</strong> tarafından değerlendirilecek ve yarışmanın her iki kategorisinde birinci, ikinci ve &uuml;&ccedil;&uuml;nc&uuml;l&uuml;ğe değer bulunan yazılar belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Se&ccedil;ici Kurul</strong></em></p>\r\n<p style="padding-left: 35pt;">Serdar &Ouml;zt&uuml;rk (Akademisyen)</p>\r\n<p style="padding-left: 35pt;">Tunca Arslan (Sinema Yazarı)</p>\r\n<p style="padding-left: 35pt;">Yaşar Hız (Yayıncı)</p>\r\n<p style="padding-left: 35pt;">Mustafa Ertekin (Sinefil)</p>\r\n<p style="padding-left: 35pt;">Seda Usub&uuml;t&uuml;n (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONU&Ccedil; DUYURUSU</strong></p>\r\n<p>Yarışma sonu&ccedil;ları <strong>31 Mayıs 2017 &Ccedil;arşamba</strong>&nbsp;g&uuml;n&uuml; Sekans web sitesinde ve medyada duyurulacaktır. &Ouml;d&uuml;l alan yazılar elektronik dergimiz SEKANS Sinema K&uuml;lt&uuml;r&uuml; Dergisi\'nde yayımlanmak &uuml;zere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/yarisma_sponsorlari.jpg" alt="yarisma sponsorlari" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2017-01-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (117, 'ay-j237', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2017-on-eleme-sonuclari-aciklandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2017 Ön Eleme Sonuçları Açıklandı!', '', '<p style="text-align: right;">&nbsp;</p>\r\n<p>Sekans Film Eleştirisi ve Film &Ccedil;&ouml;z&uuml;mlemesi 2017 yarışmasında finale yaklaştık. Her iki kategori i&ccedil;in toplam 30 başvuru elimize ulaştı.&nbsp;Sekans &Ouml;n Eleme Kurulu, 21 Mayıs tarihinde sona eren başvurular i&ccedil;inde Eleştiri Kategorisi altında yarışacak kriterlere sahip ve yeterli sayıda yazı belirleyememiştir.&nbsp;&Ccedil;&ouml;z&uuml;mleme Kategorisi i&ccedil;in Se&ccedil;ici Kurul&rsquo;a ulaştırılan başvurular ise aşağıda listelenmiştir. T&uuml;m katılımcılarımıza başarılar dileriz.</p>\r\n<p>&nbsp;</p>\r\n<p>Abdi Cangı - <em>Kosmos</em> veya İnsan Nedir Ki?</p>\r\n<p>Arzu Karacaoğlu - <em>Kader B&ouml;yle İstedi</em> Filminin Greimas&rsquo;a G&ouml;re &Ccedil;&ouml;z&uuml;mlenmesi</p>\r\n<p>M. Baki Demirtaş - <em>Sarmaşık</em> Film &Ccedil;&ouml;z&uuml;mlemesi</p>\r\n<p>Mustafa Cihan Camcı - &Ouml;zg&uuml;n Bir Tutku &Ouml;yk&uuml;s&uuml;: <em>Kader</em></p>\r\n<p>Oğuzhan Dursun - Sarı Otlar Aşkına</p>\r\n<p>Oğuzhan Dursun - B&uuml;t&uuml;nden Bir Par&ccedil;a: <em>Karag&ouml;zl&uuml;m</em></p>\r\n<p>Rıdvan Karaman - Dairede Durup Merkezi Kollayanlar</p>\r\n<p>S&uuml;heyla Tolunay İşlek - <em>Koca D&uuml;nya</em>: Bir Masal Evreninde Yollarını ve Babalarını Bulamayan &Ccedil;ocuklar</p>\r\n<p>Şeyma Kalınca - &Ccedil;ocukluk mu? B&uuml;y&uuml;mek mi? Hangisi Yaşanılır Kılar Bu Hayatı?</p>\r\n<p>Yusuf Emre Yal&ccedil;ın - Sinemanın Kanatsız Lilith&rsquo;i: Sibel</p>', 1, 64, 'Duyuru', NULL, '2017-05-28');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (118, 'ay-j238', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2017-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2017 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/SekansFilmYarismasi2017_600x450.jpg" alt="SekansFilmYarismasi2017 600x450" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından bu yıl iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları <strong>Dört Mevsim Kitap</strong>, <strong>Ekslibris Yayıncılık</strong>, <strong>Gece Kitaplığı</strong>, <strong>Kalkedon Yayınları</strong>, <strong>Küre Yayınları</strong> ve <strong>Seyyah Kitap</strong> oldu.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Her iki kategoride tarafımıza ulaşan toplam 30 başvuru içinde Sekans Ön Eleme Kurulu Eleştiri Kategorisi altında yarışacak kriterlere sahip ve yeterli sayıda yazı belirleyememiş, Çözümleme Kategorisi altında ise 10 başvuru Seçici Kurula sunulmuştur.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Serdar Öztürk</strong> (Akademisyen), <strong>Tunca Arslan</strong> (Sinema Yazarı), <strong>Yaşar Hız </strong>(Yayıncı), <strong>Mustafa Ertekin</strong> (Sinefil) ve <strong>Seda Usubütün</strong>\'den (Sekans - Sinema Yazarı) oluşan Seçici Kurulun değerlendirmesi aşağıdaki gibi sonuçlandı:</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Birinci: Yusuf Emre Yalçın&nbsp;</strong>- "Sinemanın Kanatsız Lilith’i: Sibel" (<em>Duvara Karşı</em> / Fatih Akın)</p>\r\n<p><strong>İkinci: Mustafa Cihan Camcı&nbsp;</strong>- "Özgün Bir Tutku Öyküsü: <em>Kader</em>" (<em>Kader</em> / Zeki Demirkubuz)</p>\r\n<p><strong>Üçüncü: Süheyla Tolunay İşlek&nbsp;</strong>- "<em>Koca Dünya</em>: Bir Masal Evreninde Yollarını ve Babalarını&nbsp;Bulamayan Çocuklar" (<em>Koca Dünya</em> / Reha Erdem)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/yarisma_sponsorlari.jpg" alt="yarisma sponsorlari" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/SekansFilmYarismasi2017_600x450.jpg', '2017-05-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (119, 'ay-j244', 'film-elestirisi-semineri-2018', 'Film Eleştirisi Semineri 2018', 'SEKANS SİNEMA GRUBU Yeni Dönem Film Eleştirisi Semineri AÇIYOR!', '<p>SEKANS SİNEMA GRUBU Yeni Dönem Film Eleştirisi Semineri AÇIYOR!</p>\r\n<p>&nbsp;</p>\r\n<p>Hakkında en çok konuşulan, en çok yapılan ama en az bilinen alanlardan biridir eleştiri. Oysa eleştiri bireysel yaratıcılıktan beslendiği ölçüde eleştirel yöntemlere de dayanır. Seminerimiz, dileyenin eleştiri alanında atölye tarzı üretim gerçekleştirmek için, dileyenin de salt eleştiri türlerini öğrenmek için katılabileceği bir yapıdadır. Seminer içeriğimiz, dünden bugüne ağırlıklı olarak kullanılan tüm eleştiri türlerine yer vermekte ve örnek uygulamalarını gerçekleştirmektedir.&nbsp;</p>\r\n<p><br />Herkesin film eleştirisi hakkında temel bilgileri edinmesiyle başlayıp zaman içerisinde kendi eleştiri modelini geliştirmesini amaçladığımız seminerimizin alt konu başlıkları şunlar:<br />&nbsp; &nbsp; • Film eleştirisi nedir?<br />&nbsp; &nbsp;&nbsp;• Film eleştirmeni kimdir?<br />&nbsp; &nbsp;&nbsp;• Yorum ve eleştiri<br />&nbsp; &nbsp;&nbsp;• Sosyolojik eleştiri<br />&nbsp; &nbsp;&nbsp;• Göstergebilimsel eleştiri<br />&nbsp; &nbsp;&nbsp;• Tarihsel eleştiri<br />&nbsp; &nbsp;&nbsp;• İdeolojik eleştiri<br />&nbsp; &nbsp;&nbsp;• Psikanalitik eleştiri<br />&nbsp; &nbsp;&nbsp;• Feminist eleştiri<br />&nbsp; &nbsp;&nbsp;• Film türleri ve eleştiri<br />&nbsp; &nbsp;&nbsp;• Bir film eleştirisi modeli</p>\r\n<p>…………………………</p>\r\n<p>Seminer 20 hafta sürecektir.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer periyodu: Haftada bir gün.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer son başvuru tarihi: 26 Ocak 2018</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer başlangıç tarihi: Kursiyerlerin tercihlerine göre belirlenecek.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer adresi: Konur - 2 Sokak No: 63 / 6, Kızılay / Ankara (Su’dem üstü)</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerle ilgili ayrıntılı bilgiyi 0 531 480 5544 nolu telefondan (Gülşah Altuğ) veya seminer@sekans.org e-posta adresi ile iletişim kurarak edinebilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', NULL, '2018-01-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (120, 'ay-j245', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2018', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2018', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS%20FİLM%20ELEŞTİRİSİ%20YARIŞMASI-2018.pdf" target="_blank" rel="noreferrer" title="Duyuru 2017"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/SekansYarisma2018a_600x450.jpg" alt="SekansYarisma2018a 600x450" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması’nın yedincisini</strong>&nbsp;gerçekleştirecektir.</p>\r\n<p>Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular e-posta yoluyla yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri eleştiri veya çeviri çözümleme yazılarıyla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: Filmin Adı, Yılı, Süresi, Yönetmeni, Senaristi, Görüntü Yönetmeni, Sanat Yönetmeni, Müzik, Kurgu, Oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Haziran 2019 gününe kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p>Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>20 Mayıs 2018 Pazar</strong>&nbsp;gününe kadar yarisma@sekans.org adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p>Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön eleme sırasında yazıların hangi kategoriye uygun olduğu da değerlendirilecek olup yazıların başvuru kategorisinde değişiklikler yapılabilecektir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>Her iki yarışma kategorisi için ön elemeden geçen en fazla 10\'ar yazı <strong>Seçici Kurul</strong> tarafından değerlendirilecek ve yarışmanın her iki kategorisinde birinci, ikinci ve üçüncülüğe değer bulunan yazılar belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Seçici Kurul</strong></em></p>\r\n<p style="padding-left: 35pt;">Hakan Karaş (Akademisyen)</p>\r\n<p style="padding-left: 35pt;">Neşe Ürel (Sinema Yazarı)</p>\r\n<p style="padding-left: 35pt;">Semih Erelvanlı</p>\r\n<p style="padding-left: 35pt;">Sertaç Koyuncu (Sinefil)</p>\r\n<p style="padding-left: 35pt;">Ekin Eren (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p>Yarışma sonuçları <strong>31 Mayıs 2017 Perşembe&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/SekansYarisma%202018b_880x120.jpg" alt="SekansYarisma 2018b 880x120" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2018-03-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (121, 'ay-j249', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2018-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2018 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/SekansYarisma2018a_600x450.jpg" alt="SekansYarisma2018a 600x450" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları <strong>Bağlam Yayınları, Dergâh Yayınları, Doruk Yayınları, Evrensel Basım Yayın, Kor Kitap, </strong><strong>Küre Yayınları, Redingot Kitap</strong> ve <strong>Yitik Ülke Yayınları</strong>&nbsp;oldu.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Hakan Karaş</strong>&nbsp;(Akademisyen), <strong>Neşe Ürel</strong>&nbsp;(Sinema Yazarı), <strong>Semih Erelvanlı</strong>, <strong>Sertaç Koyuncu</strong>&nbsp;(Sinefil) ve <strong>Ekin Eren</strong>\'den (Sekans - Sinema Yazarı) oluşan Seçici Kurulun değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Kezban Özgün&nbsp;</strong>- <em>Yolunda A.Ş.</em> (<em>Yolunda A.Ş.</em>&nbsp;/ Emre Budak)</p>\r\n<p>İkinciliğe ve üçüncülüğe uygun yazı bulunamamıştır.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Zeynep Duran&nbsp;</strong>- Bir Neden Arayışı Olarak Yaşamak ya da Ölmek:&nbsp;<em>İşe Yarar Bir Şey</em>&nbsp;(<em>İşe Yarar Bir Şey</em>&nbsp;/ Pelin Esmer)</p>\r\n<p><strong>İkinci: İbrahim Karabiber&nbsp;</strong>- <em>Üç Maymun</em>&nbsp;(<em>Üç Maymun</em>&nbsp;/ Nuri Bilge Ceylan)</p>\r\n<p><strong>Üçüncü: Baki Demirtaş&nbsp;</strong>- "Nefes mi Buğday mı?" (<em>Buğday</em>&nbsp;/ Semih Kaplanoğlu)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/SekansYarisma2018_SponsorYayinevleri.jpg" alt="SekansYarisma2018 SponsorYayinevleri" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/SekansYarisma2018a_600x450.jpg', '2018-05-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (122, 'ay-j255', 'sekans-si-nema-grubu-semi-nerleri-2018-2019', 'SEKANS SİNEMA GRUBU SEMİNERLERİ – 2018 / 2019', '', '<h3><strong>SEKANS SİNEMA GRUBU SEMİNERLERİ – 2018 / 2019</strong></h3>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>SİNEMA AKIMLARI SEMİNERİ</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p>Sinema akımlarının Futurizm’den Cinema Cedid’e kadar kronolojik sıraya göre tanıtılıp incelendiği ve örnek film analizleriyle desteklendiği bu seminer, sinema tarihinin tema, anlatı dili, estetik ve biçim açısından gelişim evrelerini akımlar üzerinden aktarıyor.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer üç bölüm halinde planlanmış olup, her bölüm kendi içinde farlı karakteristik özellikleri olan akımlara yer vermektedir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Akımları Semineri -1</strong></p>\r\n<p>Farklı sanat dallarına ait akımların sinema üzerindeki etkisiyle ortaya çıkan sinema akımlarına odaklanan bu bölümde, klasik veya dönemi için çağdaş sanat akımlarının sinemanın Yedinci Sanat olarak adlandırılmasında oynadıkları roller üzerinde durulacak. Bu nedenle, önceliğimiz Akım kavramı ve Sanat Akımları olacak. Ardından Futurizm akımı ile başlayıp Sürrealizm akımı ile bu bölümü noktalayacağız.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Akımları Semineri -2</strong></p>\r\n<p>Sinemanın giderek kendi karakterini bulduğu ve kendine özgü yöntemlerle yol aldığı yılların tarihçesinin aktarımı akımlar üzerinden sürecek. Sinemanın tarihsel ve sosyolojik açıdan etkilenme ve etkileme boyutunun öne çıkacağı bu bölüm İngiliz Belgesel Ekolü ile başlayıp İngiliz Yeni Dalga akımı ile son bulacak.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Sinema Akımları Semineri -3</strong></p>\r\n<p>Sinemanın modernizm tarihinin yazıldığı, sanat sineması coğrafyasının hızla büyüdüğü ve bir sanat olarak doruğa çıktığı, Üçüncü Sinema’nın doğuşuna tanık olduğumuz yıllar akımlar açısından da zengindir. Akımlar arası etkileşimlerle tanışacağımız bu bölüm Fransız Yeni Dalga akımı ile başlayacak ve Cinema Cedid akımı ile son bulacak.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Sinema Akımları Semineri’nin süresi: 3 ay + 3 ay + 3 ay olmak üzere 9 aydır.</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>GÖRÜNTÜ TASARIMI SEMİNERİ</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p>Prodüksiyon sürecinin en zorlu ve en fazla hazırlık, koordinasyon ve konsantrasyon gerektiren aşaması çekimlerdir. Elinizdeki senaryonun görüntüye aktarımı çok sayıda unsurun tasarlanmasını ve bazen sıralı bazen eşzamanlı biçimde uygulanmasını gerektirir.</p>\r\n<p>&nbsp;</p>\r\n<p>Görüntü Tasarımı Semineri bu unsurların tamamını kapsayan, detaylandırılmış bilgilerle zenginleştirilmiş, biçim ve içerik arasındaki ilişkiyi de gözler önüne seren bir seminerdir. Çerçevelemeden görüntü düzenlemesine, görüş noktasından kamera açılarına, çekim ölçeklerinden aydınlatmaya, donatımdan sese geniş bir kapsam sunmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Görüntü Tasarımı Semineri’nin süresi 4 aydır.</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>ÖNEMLİ</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Seminer Periyodu: </strong>Haftada bir gün. (Gün kursiyerlerin tercihlerine göre belirlenecektir.)</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Seminer Son Başvuru Tarihi: </strong>30 Eylül 2018</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer başlangıç tarihi:</strong> Kursiyerlerin tercihlerine göre belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer adresi:</strong> Konur - 2 Sokak No: 63 / 6, Kızılay / Ankara (Su’dem üstü)</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerle ilgili ayrıntılı bilgiyi 0 531 480 5544 nolu telefondan (Gülşah Altuğ) veya seminer@sekans.org e-posta adresi ile iletişim kurarak edinebilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', NULL, '2018-09-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (123, 'ay-j261', 'film-cozumlemesi-semineri-2019', 'Film Çözümlemesi Semineri - 2019', '', '<p>&nbsp;</p>\r\n<p>Sinemanın anlam ve anlatım zenginliği ancak filmlerin taşıdığı anlam açığa çıkarıldığında anlaşılabilir. Çözümleme teknikleri bilgisi, filmlerin çok boyutlu okunmasında farklı yöntemlerin kullanılması alışkanlığını yerleştireceği gibi, film eleştirisine geçiş konusunda da önemli bir altyapının kurulmasını sağlar. Seminerimizin amacı, seyir sürecinin anlamlandırma süreciyle bağını kurmaktır.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer kapsamında film çözümlemesinde kullanılan gelenekçi ve modernist yaklaşımlar detaylı biçimde aktarılacak ve örnek filmlerle pratiğe dökülecektir. Son örnek çözümlemede tüm sinemasal çözümleme teknikleri kullanılarak bir filmin çözümlemesi yapılacaktır.</p>\r\n<p>&nbsp;</p>\r\n<p>Herkesin film çözümlemesi hakkında temel bilgileri edinmesiyle başlayıp zaman içerisinde kendi çözümleme modelini geliştirmesini amaçladığımız seminerimizin alt konu başlıkları şunlar:</p>\r\n<p>- Film çözümlemesi nedir?<br /> - Yorum, okuma ve çözümleme<br /> - Anlatı çözümlemesi türleri<br /> - Film çözümlemesinde temel yöntemler<br /> - Yapısalcı çözümleme<br /> - Göstergebilimsel çözümleme<br /> - Psikanalitik çözümleme<br /> - Sosyolojik çözümleme<br /> - Bir film çözümlemesi modeli</p>\r\n<p>&nbsp;</p>\r\n<p>---------------------------------------------</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer <strong>5 ay</strong> olup toplam <strong>20 oturum</strong>dan oluşmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer periyodu:</strong> Haftada bir gün</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer son başvuru tarihi:</strong> 4 Ocak 2019</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer başlangıç tarihi:</strong> Kursiyerlerin tercihine göre belirlenecek.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer adresi:</strong> Konur-2 Sokak No: 63 / 6, Kızılay / Ankara (Su’dem üstü)</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerle ilgili ayrıntılı bilgiyi <a href="mailto:seminer@sekans.org" target="_blank">seminer@sekans.org</a> e-posta adresiyle iletişim kurarak edinebilirsiniz.</p>', 1, 64, 'Duyuru', NULL, '2018-12-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (124, 'ay-j263', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2019', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2019', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS_FILM_ELESTIRISI_YARISMASI-2019.pdf" target="_blank" rel="noreferrer" title="Yarışma 2019"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/SekansYarisma_2019_600x420.jpg" alt="SekansYarisma 2019 600x420" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması’nın sekizincisini</strong>&nbsp;gerçekleştirecektir.</p>\r\n<p>Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular e-posta yoluyla yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: Filmin Adı, Yılı, Süresi, Yönetmeni, Senaristi, Görüntü Yönetmeni, Sanat Yönetmeni, Müzik, Kurgu, Oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Haziran 2020 gününe kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p>Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>22 Mayıs 2018 Çarşamba</strong>&nbsp;gününe kadar yarisma@sekans.org adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p>Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön değerlendirme kurulu tarafından yazıların değerlendirileceği başvuru kategorisinde değişiklik yapılabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>Her iki yarışma kategorisi için ön elemeden geçen en fazla 10\'ar yazı <strong>Seçici Kurul</strong> tarafından değerlendirilecek ve yarışmanın her iki kategorisinde birinci, ikinci ve üçüncülüğe değer bulunan yazılar belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Seçici Kurul</strong></em></p>\r\n<p style="padding-left: 35pt;">Ulaş Başar Gezgin (Akademisyen)</p>\r\n<p style="padding-left: 35pt;">Barış Saydam (Sinema Yazarı)</p>\r\n<p style="padding-left: 35pt;">Emrah Günok&nbsp;(Sinefil)</p>\r\n<p style="padding-left: 35pt;">Gökhan Erkılıç (Sekans - Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p>Yarışma sonuçları <strong>31 Mayıs 2019 Cuma&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/SekansYarisma_2019sponsor_1181x202.jpg" alt="SekansYarisma 2019sponsor 1181x202" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2019-03-09');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (125, 'ay-j272', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2019-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2019 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/SekansYarisma_2019_600x420.jpg" alt="SekansYarisma 2019 600x420" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları <strong>6:45 Yayınları, Bağlam Yayınları, Çizgi Kitabevi, Hayalperest Kitap, İlkim Ozan Yayınları, İthaki Yayınları, Japon Yayınları, Kalkedon Yayınları,&nbsp;</strong><strong>Küre Yayınları, Ütopya Yayınevi </strong>ve<strong> Yurt Kitap</strong>&nbsp;oldu.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Ulaş Başar Gezgin</strong> (Akademisyen), <strong>Barış Saydam</strong> (Sinema Yazarı), <strong>Emrah Günok</strong> (Sinefil) ve <strong>Gökhan Erkılıç</strong>’tan (Sekans - Sinema Yazarı) oluşan Seçici Kurulun değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Murat Çağıltay</strong> – Post Travmatik Türküler (<em>Kaygı</em> / Ceylan Özgün Özçelik)</p>\r\n<p>İkinciliğe ve üçüncülüğe uygun yazı bulunamamıştır.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Çisel Bilgen Ceylan</strong> – Zamansız Oğullar, <em>Ali’nin Sekiz Günü</em> Üzerine (<em>Ali’nin Sekiz Günü&nbsp;</em>/ Cemal Şan)</p>\r\n<p><strong>İkinci: Esra Ballım</strong> – ‘<em>Beş Vakit</em>’te Büyümekle Büyüyememek Arasında (<em>Beş Vakit</em> / Reha Erdem)</p>\r\n<p><strong>Üçüncü: Zeynep Tekin Taş –</strong>&nbsp;Eril Dünyanın ‘<em>Kuyu</em>’su (<em>Kuyu</em> / Metin Erksan)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/SekansYarisma_2019sponsor_1181x202.jpg" alt="SekansYarisma 2019sponsor 1181x202" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/SekansYarisma_2019_600x420.jpg', '2019-05-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (126, 'ay-j277', 'si-nema-akimlari-semi-neri-2019-2020', 'SİNEMA AKIMLARI SEMİNERİ – 2019 / 2020', '', '<h3><strong>SEKANS SİNEMA GRUBU SEMİNERLERİ – 2019 / 2020</strong></h3>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>SİNEMA AKIMLARI SEMİNERİ</strong></span></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p>Sinema akımlarının Futurizm’den Cinema Cedid’e kadar kronolojik sıraya göre tanıtılıp incelendiği ve örnek film analizleriyle desteklendiği bu seminer, sinema tarihinin tema, anlatı dili, estetik ve biçim açısından gelişim evrelerini akımlar üzerinden aktarıyor.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer üç bölüm halinde planlanmış olup, her bölüm kendi içinde farklı karakteristik özellikleri olan akımlara yer vermektedir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Akımları Semineri -1</strong></p>\r\n<p>Farklı sanat dallarına ait akımların sinema üzerindeki etkisiyle ortaya çıkan sinema akımlarına odaklanan bu bölümde, klasik veya dönemi için çağdaş sanat akımlarının sinemanın Yedinci Sanat olarak adlandırılmasında oynadıkları roller üzerinde durulacak. Bu nedenle, önceliğimiz Akım kavramı ve Sanat Akımları olacak. Ardından Futurizm akımı ile başlayıp Sürrealizm akımı ile bu bölümü noktalayacağız.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Akımları Semineri -2</strong></p>\r\n<p>Sinemanın giderek kendi karakterini bulduğu ve kendine özgü yöntemlerle yol aldığı yılların tarihçesinin aktarımı akımlar üzerinden sürecek. Sinemanın tarihsel ve sosyolojik açıdan etkilenme ve etkileme boyutunun öne çıkacağı bu bölüm İngiliz Belgesel Ekolü ile başlayıp İngiliz Yeni Dalga akımı ile son bulacak.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Sinema Akımları Semineri -3</strong></p>\r\n<p>Sinemanın modernizm tarihinin yazıldığı, sanat sineması coğrafyasının hızla büyüdüğü ve bir sanat olarak doruğa çıktığı, Üçüncü Sinema’nın doğuşuna tanık olduğumuz yıllar akımlar açısından da zengindir. Akımlar arası etkileşimlerle tanışacağımız bu bölüm Fransız Yeni Dalga akımı ile başlayacak ve Cinema Cedid akımı ile son bulacak.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><span style="text-decoration: underline;"><strong style="font-size: 12pt;">ÖNEMLİ</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p><strong><strong>Sinema Akımları Semineri’nin süresi: 3 ay + 3 ay + 3 ay olmak üzere 9 aydır.</strong><br /></strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer Periyodu: Haftada bir gün. (Gün kursiyerlerin tercihlerine göre belirlenecektir.)</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><strong>Seminer Son Başvuru Tarihi: 30 Eylül 2019</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer başlangıç tarihi:</strong> <strong>Kursiyerlerin tercihlerine göre belirlenecektir.</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminer adresi:</strong> <strong>Konur - 2 Sokak No: 63 / 6, Kızılay / Ankara</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seminerle ilgili ayrıntılı bilgiyi seminer@sekans.org adresiyle iletişim kurarak Tansu Ayşe Fıçıcılar\'dan edinebilirsiniz.</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', NULL, '2019-09-19');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (127, 'ay-j279', 'film-elestirisi-semineri-2019-2020', 'Film Eleştirisi Semineri 2019 / 2020', '', '<h3><strong>SEKANS SİNEMA GRUBU SEMİNERLERİ – 2019 / 2020</strong></h3>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>FİLM ELEŞTİRİSİ SEMİNERİ</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p>Hakkında en çok konuşulan, en çok yapılan ama en az bilinen alanlardan biridir eleştiri. Oysa eleştiri bireysel yaratıcılıktan beslendiği ölçüde eleştirel yöntemlere de dayanır. Seminerimiz, dileyenin eleştiri alanında atölye tarzı üretim gerçekleştirmek için, dileyenin de salt eleştiri türlerini öğrenmek için katılabileceği bir yapıdadır. Seminer içeriğimiz, dünden bugüne ağırlıklı olarak kullanılan tüm eleştiri türlerine yer vermekte ve örnek uygulamalarını gerçekleştirmektedir.&nbsp;</p>\r\n<p><br />Herkesin film eleştirisi hakkında temel bilgileri edinmesiyle başlayıp zaman içerisinde kendi eleştiri modelini geliştirmesini amaçladığımız seminerimizin alt konu başlıkları şunlar:<br />&nbsp; &nbsp; • Film eleştirisi nedir?<br />&nbsp; &nbsp;&nbsp;• Film eleştirmeni kimdir?<br />&nbsp; &nbsp;&nbsp;• Yorum ve eleştiri<br />&nbsp; &nbsp;&nbsp;• Sosyolojik eleştiri<br />&nbsp; &nbsp;&nbsp;• Göstergebilimsel eleştiri<br />&nbsp; &nbsp;&nbsp;• Tarihsel eleştiri<br />&nbsp; &nbsp;&nbsp;• İdeolojik eleştiri<br />&nbsp; &nbsp;&nbsp;• Psikanalitik eleştiri<br />&nbsp; &nbsp;&nbsp;• Feminist eleştiri<br />&nbsp; &nbsp;&nbsp;• Film türleri ve eleştiri<br />&nbsp; &nbsp;&nbsp;• Bir film eleştirisi modeli</p>\r\n<p>…………………………</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer 20 hafta sürecektir.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer periyodu: Haftada bir gün.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer son başvuru tarihi: 30 Eylül 2019</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer başlangıç tarihi: Kursiyerlerin tercihlerine göre belirlenecek.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer adresi: Konur - 2 Sokak No: 63 / 6, Kızılay / Ankara</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerle ilgili ayrıntılı bilgiyi seminer@sekans.org adresiyle iletişim kurarak Tansu Ayşe Fıçıcılar\'dan edinebilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', NULL, '2019-09-11');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (128, 'ay-j281', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2020', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2020', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS_FiLM_ELEsTiRiSi_YARIsMASI-2020.pdf" target="_blank" rel="noreferrer" title="Yarışma 2020"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/SekansYarisma2020a1_600x420.jpg" alt="Sekans Yarisma 2020" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması’nın dokuzuncusunu</strong>&nbsp;gerçekleştirecektir.</p>\r\n<p>Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular elektroinik olarak (e-posta yoluyla) yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: filmin adı, yılı, süresi, yönetmeni, senaristi, görüntü yönetmeni, sanat yönetmeni, müzik, kurgu, oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Haziran 2021 gününe kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p>Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>19 Mayıs 2020 Salı</strong>&nbsp;gününe kadar yarisma@sekans.org adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p>Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön değerlendirme kurulu tarafından yazıların değerlendirileceği başvuru kategorisinde değişiklik yapılabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>Her iki yarışma kategorisi için ön elemeden geçen en fazla onar adet yazı <strong>Seçici Kurul</strong> tarafından değerlendirilecek ve her iki kategorinin birinci, ikinci ve üçüncülüğe değer bulunan yazıları belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p>Yarışma sonuçları <strong>1 Haziran 2020 Pazartesi&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2019-12-13');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (129, 'ay-j283', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2020-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2020 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/yarisma_2020_sonuc.jpg" alt="yarisma 2020 sonuc" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları <strong>Ayrıntı Yayınları, <strong>Ütopya Yayınevi,&nbsp;<strong>Pharmakon Yayınları</strong></strong>&nbsp;</strong>ve<strong> <strong>Kalkedon Yayınları&nbsp;</strong></strong>oldu.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>&nbsp;</p>\r\n<p><b>Ayhan Çınar</b> (Sinefil), <strong>Erdem İlic</strong>&nbsp;(Sinema Yazarı), <strong>Lale Kabadayı</strong>&nbsp;(Akademisyen - Sinema Yazarı),&nbsp;<strong>Mine Tezgiden</strong>&nbsp;(Sekans - Sinema Yazarı) ve&nbsp;<strong>Zehra Yiğit</strong>\'ten&nbsp;(Akademisyen - Sinema Yazarı) oluşan Seçici Kurulun değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Murat Çağıltay</strong> – Hayallerim, İstanbul ve Punk (<em>Arada</em> / Mu Tunç)</p>\r\n<p><strong>İkinci: Esra Ballım</strong>&nbsp;– Densizlik Ömür Boyu... (<em>Rüzgarda Salınan Nilüfer</em>&nbsp;/ Seren Yüce)</p>\r\n<p><strong>Üçüncü: Ş. Gülbin Paytar</strong>&nbsp;– \'<em>Kelebekler\'</em>&nbsp;Ya Da Yitip Gidenler (<em>Kelebekler</em>&nbsp;/ Tolga Karaçelik)</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Sevcan Sönmez</strong>&nbsp;– Distopik Durumdan Üreyen Ütopya:&nbsp;<em>Körfez</em>&nbsp;(<em>Körfez</em><em>&nbsp;</em>/ Emre Yeksan)</p>\r\n<p><strong>İkinci: Azmi Recep Özdaş</strong>&nbsp;– Gündeliğin Bilinci: İyi Günlerde Kirlenmek (<em>Toz Bezi</em><em>&nbsp;</em>/ Ahu Öztürk)</p>\r\n<p><strong>Üçüncü: Onur Keşaplı </strong>– <em>Aidiyet</em>&nbsp;ve Arınma (<em>Aidiyet</em>&nbsp;/ Burak Çevik)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/yarisma_2020_sponsorlar.jpg" alt="yarisma 2020 sponsorlar" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/yarisma_2020_sonuc.jpg', '2020-05-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (130, 'ay-j295', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2021', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2021', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS_fiLM_ELEsTiRiSi_YARisMA_DUYURUSU_2021.pdf" target="_blank" rel="noreferrer" title="Yarışma 2020"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p><strong><img src="/images/duyurular/SEKANS_FİLM_ELEŞTİRİSİ_YARIŞMA_DUYURUSU_2021_Afiş.jpg" alt="SEKANS FİLM ELEŞTİRİSİ YARIŞMA DUYURUSU 2021 Afiş" style="margin-left: 20px; float: right;" />SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması’nın onuncusunu</strong>&nbsp;gerçekleştirecektir.</p>\r\n<p>Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular elektroinik olarak (e-posta yoluyla) yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: filmin adı, yılı, süresi, yönetmeni, senaristi, görüntü yönetmeni, sanat yönetmeni, müzik, kurgu, oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Haziran 2022 gününe kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p>Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>19 Mayıs 2021 Çarşamba</strong>&nbsp;gününe kadar yarisma@sekans.org adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p>Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön değerlendirme kurulu tarafından yazıların değerlendirileceği başvuru kategorisinde değişiklik yapılabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>Her iki yarışma kategorisi için ön elemeden geçen en fazla onar adet yazı <strong>Seçici Kurul</strong> tarafından değerlendirilecek ve her iki kategorinin birinci, ikinci ve üçüncülüğe değer bulunan yazıları belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p>Yarışma sonuçları <strong>1 Haziran 2021 Salı&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/duyurular/yarisma_sponsorlari_2021.png" alt="yarisma sponsorlari 2021" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2020-12-30');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (131, 'ay-j296', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2021-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2021 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/SEKANS_FİLM_ELEŞTİRİSİ_YARIŞMA_DUYURUSU_2021_Afiş.jpg" alt="SEKANS FİLM ELEŞTİRİSİ YARIŞMA DUYURUSU 2021 Afiş" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması\'nın <strong>onuncusu</strong> sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p>Yarışmanın sponsor kurumları <strong>Bağlam Yayınları</strong>, <strong>Hece Yayınları</strong>, <strong>Çizgi Kitabevi</strong>, <strong>İlkim&nbsp;</strong><strong>Ozan Yayınları</strong>, <strong>Japon Yayınları</strong>, <strong>Nobel Akademik Yayıncılık</strong>, <strong>Pharmakon Yayınları</strong> ve&nbsp;<strong>Ütopya Yayınları&nbsp;</strong>oldu.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Zuhal Çetin ÖZKAN</strong> (Akademisyen), <strong>Ertan TUNÇ</strong> (Sinema Yazarı), <strong>Yavuz AKYILDIZ&nbsp;</strong>(Akademisyen), <strong>Derya AKMAN</strong> (Sekans - Sinema Yazarı) ve <strong>Evin KONUK</strong>’tan (Sinefil) oluşan Seçici Kurul\'un değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci: Atifet Sena KELEŞOĞLU </strong>– Bir Subtopia Atlası ya da Kentin <em>Hayaletler</em>’i<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>HAYALETLER</em> / Azra Deniz Okyay)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İkinci: Görkem ÖNAL</strong>&nbsp;– Bal ve Barutun Analojisi: <em>Kovan</em><br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>KOVAN</em> / Eylem Kaftan)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Üçüncü: Yasin DERELİ </strong>– Pelin Esmer’in “<em>İşe Yarar Bir Şey</em>” Filminin Göstergebilimsel&nbsp;Açıdan Çözümlenmesi<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;(<em>İŞE YARAR BİR ŞEY</em> / Pelin Esmer)</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p>Bu kategoride dereceye giren yarışmacı bulunmamaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;<strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/yarisma_sponsorlari_2021.png" alt="yarisma sponsorlari 2021" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/SEKANS_FİLM_ELEŞTİRİSİ_YARIŞMA_DUYURUSU_2021_Afiş.jpg', '2021-06-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (132, 'ay-j303', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2022', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2022', '', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS_2022_YARISMA_DUYURUSU.pdf" target="_blank" rel="noreferrer" title="Yarışma 2022"><img src="/images/duyurular/Adobe_PDF_file_icon_32x32.png" alt="Adobe PDF file icon 32x32" /></a></p>\r\n<p style="text-align: justify;"><strong><img src="/images/duyurular/yarisma2022duyuru_x450.jpeg" alt="yarisma2022duyuru x450" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; word-spacing: -2px;"><strong>SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek, sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması</strong>’nın bu yıl <strong>onbirincisini</strong> gerçekleştirecektir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular e-posta yoluyla yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: filmin adı, yılı, süresi, yönetmeni, senaristi, görüntü yönetmeni, sanat yönetmeni, müzik, kurgu, oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Haziran 2023\'e kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>19 Mayıs 2022 Perşembe</strong>&nbsp;gününe kadar yarisma@sekans.org adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön Değerlendirme Kurulu yazıların değerlendirileceği başvuru kategorisinde değişiklik yapabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Her iki yarışma kategorisi için ön elemeden geçen en fazla onar adet yazı <strong>Seçici Kurul</strong> tarafından değerlendirilecek ve her iki kategorinin birinci, ikinci ve üçüncülüğe değer bulunan yazıları belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><em>Seçici Kurul</em></strong></p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Sevcan Sönmez (Akademisyen)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Çiçek Coşkun (Akademisyen)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Sabriye Kabayel (Sinefil)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Şahan Yatarkalkmaz (Sinema Yazarı)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Gökhan Gökdoğan (Sekans Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA ÖDÜLLERİ</strong></p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• <strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine <strong>3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediyesiyle sponsor olmaktadır.</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Şimdiye kadar kesinleşen sponsor yayınevlerimiz <strong>ÇİZGİ</strong>, <strong>HECE</strong>,&nbsp;<strong>İLETİŞİM</strong>,<strong> KÜRE</strong>,<strong> NOBEL AKADEMİK YAYINCILIK</strong> ve<strong> PHARMAKON</strong>’in sağladığı kitaplardan oluşan karma setler derece alanlara hediye edilecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/yarisma2022sponsorlar.png" alt="yarisma2022sponsorlar" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma sonuçları <strong>1 Haziran 2022 Çarşamba&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', '/images/duyurular/Adobe_PDF_file_icon_32x32.png', '2022-02-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (133, 'ay-j313', 'sekans-sinema-grubu-yaz-seminerleri-2022', 'Sekans Sinema Grubu Yaz Seminerleri 2022', '', '<p>&nbsp;</p>\r\n<p><strong>FİLM ÇÖZÜMLEMESİ SEMİNERİ</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sinemanın anlam ve anlatım zenginliği ancak filmlerin taşıdığı anlam açığa çıkarıldığında anlaşılabilir. Çözümleme teknikleri bilgisi, filmlerin çok boyutlu okunmasında farklı yöntemlerin kullanılması alışkanlığını yerleştireceği gibi, film eleştirisine geçiş konusunda da önemli bir altyapının kurulmasını sağlar. Seminerimizin amacı, seyir sürecinin anlamlandırma süreciyle bağını kurmaktır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Seminer kapsamında film çözümlemesinde kullanılan gelenekçi ve modernist yaklaşımlar detaylı biçimde aktarılacak ve örnek filmlerle pratiğe dökülecektir. Son örnek çözümlemede tüm sinemasal çözümleme teknikleri kullanılarak bir filmin çözümlemesi yapılacaktır.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Herkesin film çözümlemesi hakkında temel bilgileri edinmesiyle başlayıp zaman içerisinde kendi çözümleme modelini geliştirmesini amaçladığımız seminerimizin alt konu başlıkları şunlar:</p>\r\n<ul>\r\n<li>Film çözümlemesi nedir?</li>\r\n<li>Yorum, okuma ve çözümleme</li>\r\n<li>Anlatı çözümlemesi türleri</li>\r\n<li>Film çözümlemesinde temel yöntemler</li>\r\n<li>Yapısalcı çözümleme</li>\r\n<li>Göstergebilimsel çözümleme</li>\r\n<li>Psikanalitik çözümleme</li>\r\n<li>Sosyolojik çözümleme</li>\r\n<li>Bir film çözümlemesi modeli</li>\r\n</ul>\r\n<div>&nbsp;</div>\r\n<div dir="ltr"><em><strong>ÖNEMLİ</strong></em></div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr">Seminer <strong>5&nbsp;ay</strong> olup toplam <strong>20 oturum</strong>dan oluşmaktadır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer periyodu</strong>: Haftada bir gün.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer son başvuru tarihi</strong>: 27 Mayıs 2022</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer başlangıç tarihi</strong>: Kursiyerlerin tercihlerine göre belirlenecek.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer adresi</strong>: Konur - 2 Sokak No: 63 Kızılay / Ankara</div>\r\n<div>&nbsp;</div>\r\n<div dir="ltr" style="text-align: justify;">Seminerle ilgili ayrıntılı bilgiyi&nbsp;<a href="mailto:seminer@sekans.org"></a><a href="mailto:seminer@sekans.org">seminer@sekans.org</a>&nbsp;e-posta adresiyle&nbsp;iletişim kurarak Esra Ballım’dan edinebilirsiniz.</div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div><strong>.........................................................................</strong></div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;&nbsp;</div>\r\n<div>\r\n<div dir="ltr"><strong>SİNEMAYA YANSIYAN TARİH</strong></div>\r\n<div>&nbsp;</div>\r\n<div dir="ltr" style="text-align: justify;">Tarih bilgisini sinema, sinema bilgisini tarih üzerinden geliştirmek isteyenler için hazırlanan bu seminer programı, tarih ve sinema alanlarının karşılıklı etkileşimleri üzerine&nbsp; odaklanmaktadır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr" style="text-align: justify;">Katılımcıların tercihleriyle belirlenecek filmler tarihsel eleştiri ve ilgili çözümleme yöntemi kullanılarak sinema-tarih ilişkisinin evreleri, hedefleri ve ideolojisi tartışılacaktır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr" style="text-align: justify;">Katılımcıların içinden film seçimi yapacakları film havuzu oluşturulurken aşağıdaki temalara uygun filmler seçilmiştir:</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr">Politika &nbsp;&nbsp;&nbsp; Kadın&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; İnsan Hakları&nbsp;&nbsp;&nbsp; Göç&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Sınıf&nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Terör</div>\r\n<div dir="ltr">Kültür&nbsp; &nbsp; &nbsp; &nbsp;Savaş&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; Nasyonalizm&nbsp;&nbsp;&nbsp; Özgürlük&nbsp; &nbsp; &nbsp;Çocuk&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Globalizm</div>\r\n<div dir="ltr">Azınlık&nbsp; &nbsp; &nbsp; Cinsiyet &nbsp;&nbsp;&nbsp; İş-İşçi&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Ekonomi&nbsp; &nbsp; &nbsp; Medya&nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;Propaganda&nbsp;</div>\r\n<div dir="ltr">Kent&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Yargı&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp; Toplum&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Eğitim&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Şiddet&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Etnik</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr" style="text-align: justify;">Seminerin konu başlıkları arasında; Tarih Yazımı, Filmlerde Tarihin Sunumu, Evreleriyle Sinema-Tarih İlişkisi, Filmlerde Söylem Odakları, Tarihsel Filmlerin Karakteristik Özellikleri ve Tarihsel Eleştiri yer almaktadır.</div>\r\n<div>&nbsp;</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><em><strong>ÖNEMLİ</strong></em></div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr">Sinemaya Yansıyan Tarih semineri <strong>3 ay</strong> olup toplam <strong>12 oturum</strong>dan oluşmaktadır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer periyodu</strong>: Haftada bir gün.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer son başvuru tarihi</strong>: 27 Mayıs 2022</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer başlangıç tarihi</strong>: Kursiyerlerin tercihlerine göre belirlenecek.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr"><strong>Seminer adresi</strong>: Konur - 2 Sokak No: 63 Kızılay / Ankara</div>\r\n<div>&nbsp;</div>\r\n<div dir="ltr">Grubun oluşumunda başvuru sırası göz önüne alınacaktır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr">Seminerimizin ilk oturumu 30 Mayıs – 3 Haziran 2022 tarihleri arasında yapılacaktır.</div>\r\n<div dir="ltr">&nbsp;</div>\r\n<div dir="ltr">Seminerle ilgili ayrıntılı bilgiyi&nbsp;<a href="mailto:seminer@sekans.org"></a><a href="mailto:seminer@sekans.org">seminer@sekans.org</a>&nbsp;e-posta adresiyle iletişim kurarak Esra Ballım’dan edinebilirsiniz.</div>\r\n</div>', 1, 64, 'Duyuru', NULL, '2022-05-18');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (134, 'ay-j314', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2022-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2022 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/yarisma2022duyuru_x450.jpeg" alt="SEKANS FİLM ELEŞTİRİSİ YARIŞMA DUYURUSU 2021 Afiş" width="450" height="450" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması\'nın <strong>on birincisi</strong>&nbsp;sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Yarışmanın Sponsor Kurumları</strong></span></p>\r\n<p><strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine <strong>3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediyesiyle sponsor oldu.<br />Ayrıca <strong>ÇİZGİ KİTABEVİ</strong>, <strong>HECE YAYINLARI</strong>, <strong>İLETİŞİM YAYINLARI</strong>, <strong>KÜRE YAYINLARI</strong>, <strong>NOBEL AKADEMİK YAYINCILIK</strong> ve <strong>PHARMAKON YAYINLARI</strong> bu yılki yarışmanın sponsoru oldular.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Seçici Kurul Değerlendirmesi</strong></span></p>\r\n<p><strong>Çiçek Coşkun</strong> (Akademisyen), <strong>Gökhan Gökdoğan</strong> (Sekans - Sinema Yazarı), <strong>Sabriye Kabayel</strong> (Sinefil), <strong>Sevcan Sönmez</strong> (Akademisyen) ve <strong>Şahan Yatarkalkmaz</strong>’dan (Sinema Yazarı) oluşan Seçici Kurul’un değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci:&nbsp;Baran BARIŞ </strong>– Gökalp Gönen’in ‘<em>Lâl</em>’ Filminin Psikanalitik ve Göstergebilimsel Çözümlemesi<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>Lâl</em> / Gökalp Gönen)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İkinci: Gülşah GÜNEŞ</strong>&nbsp;–&nbsp;<em>Çatlak</em>: Geleneksel Aı̇le Çemberı̇nde Hayaller Parı̇s<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>Çatlak</em> / Fikret Reyhan)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Üçüncü:&nbsp;İrem TURHAN </strong>–&nbsp;1980’li Yıllar Türk Sineması Ekseninde Atıf Yılmaz Sinemasına Bakış: <em>Kadının Adı Yok</em> Örneği<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;(<em>Kadının Adı Yok</em> / Atıf Yılmaz)</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p>Ön Jüri değerlendirmesinin sonucunda Seçici Kurul değerlendirmesine sunulacak uygunlukta yazı bulunamamıştır.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;<strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/yarisma2022sponsorlar.png" alt="yarisma sponsorlari 2021" width="900" height="138" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/yarisma2022duyuru_x450.jpeg', '2022-06-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (135, 'ay-j317', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2023', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2023', 'PDF', '<p style="text-align: right;"><a href="/docs/duyurular/SEKANS 2023 YARISMA DUYURUSU.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: justify;"><strong><img src="/images/duyurular/yarisma-2023-afis.jpeg" alt="yarisma2023" width="450" height="363" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p style="text-align: justify;"><strong>SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek, sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması</strong>’nın bu yıl <strong>onikincisini</strong> gerçekleştirecektir.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular e-posta yoluyla yapılacaktır. Yazının elimize ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: filmin adı, yılı, süresi, yönetmeni, senaristi, görüntü yönetmeni, sanat yönetmeni, müzik, kurgu, oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının <strong>1 Temmuz 2024</strong>\'e kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>19 Haziran 2023 Pazartesi</strong>&nbsp;gününe kadar <span style="text-decoration: underline;"><strong>yarisma@sekans.org</strong></span> adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön Değerlendirme Kurulu yazıların değerlendirileceği başvuru kategorisinde değişiklik yapabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Her iki yarışma kategorisi için ön elemeden geçen en fazla onar adet yazı Seçici Kurul tarafından değerlendirilecek ve yarışmanın her iki kategorisinde birinci, ikinci ve üçüncülüğe değer bulunan yazılar belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul</strong></p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Aydan Özsoy (Akademisyen)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Gamze Hakverdi (Sinema Yazarı)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Fırat Osmanoğulları (Sinema Yazarı)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Didem Özkavukçu (Sinefil)</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Esra Ballım (Sekans Sinema Yazarı)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA ÖDÜLLERİ</strong></p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• <strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine <strong>3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediye etmektedir.</p>\r\n<p style="text-align: justify; padding-left: 35pt; word-spacing: -2px;">• Şimdiye kadar kesinleşen sponsor yayınevlerimiz <strong>AYRINTI YAYINLARI, </strong><strong>İLETİŞİM YAYINLARI</strong>,<strong> NOBEL AKADEMİK YAYINCILIK</strong> ve<strong>&nbsp;ÜTOPYA YAYINLARI</strong>’nin sağladığı kitaplardan oluşan karma setler derece alanlara hediye edilecektir.</p>\r\n<p><img src="/images/duyurular/sponsorlar23.png" alt="sponsorlar23" width="1451" height="192" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma sonuçları <strong><em>1 Temmuz 2023 Cumartesi</em>&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', '/images/duyurular/yarisma-2023-afis.jpeg', '2023-03-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (136, 'ay-j319', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2023-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2023 Sonuçlandı', '', '<p style="text-align: right;"><strong><img src="/images/duyurular/yarisma-2023-afis2.jpeg" alt="SEKANS FİLM ELEŞTİRİSİ YARIŞMA DUYURUSU 2021 Afiş" width="450" height="362" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p>Film eleştirisi ve çözümlemesi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ve çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi ve çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak için Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;Sekans Film Eleştirisi ve Çözümlemesi Yarışması\'nın <strong>on ikincisi</strong>&nbsp;sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Yarışmanın Sponsor Kurumları</strong></span></p>\r\n<p><strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine <strong>3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediyesiyle sponsor oldu.<br />Ayrıca <strong>AYRINTI YAYINLARI,&nbsp;</strong><strong>ÇİZGİ KİTABEVİ</strong>, <strong>İLETİŞİM YAYINLARI</strong>, <strong>NOBEL AKADEMİK YAYINCILIK</strong> ve <strong>ÜTOPYA YAYINLARI</strong> bu yılki yarışmanın sponsoru oldular.</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Seçici Kurul Değerlendirmesi</strong></span></p>\r\n<p><strong>Aydan ÖZSOY</strong>&nbsp;(Akademisyen), <strong>Didem ÖZKAVUKÇU AYGÜN</strong>&nbsp;(Sinefil), <strong>Esra BALLIM</strong>&nbsp;(Sekans - Sinema Yazarı), <strong>Fırat OSMANOĞULLARI</strong>&nbsp;(Sinema Yazarı) ve <strong>Gamze HAKVERDİ</strong>’dan (Sinema Yazarı) oluşan Seçici Kurul’un değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Çözümlemesi Yarışması</strong></span></p>\r\n<p><strong>Birinci:&nbsp;Mahmut CERAN</strong> – Marx’ın Cevapsız Çağrısı: <em>Eve Dönüş</em> Filminin Eleştirel Söylem Analizi<br />&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>Eve Dönüş</em> / Ömer Uğur)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İkinci:&nbsp;Çisil ALTAY İPEKÇİ </strong>– Radyo Verı̇cı̇sı̇nden Yayılan Hegemonı̇k Erkek Seslerı̇:&nbsp;<em>Kaybedenler Kulübü</em><strong><br /></strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>Kaybedenler Kulübü</em> / Tolga Örnek)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Üçüncü:&nbsp;Evren DEMİRYÜREK </strong>– Hak Edilmiş Bir Mahvoluşun Serüveni: <em>Anayurt Oteli</em><strong><br /></strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; (<em>Anayurt Oteli</em> / Ömer Kavur)</p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;"><strong>Film Eleştirisi Yarışması</strong></span></p>\r\n<p>Bu kategoride dereceye giren yazı bulunmamaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;<strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/duyurular/sponsorlar23-2.png" alt="yarisma sponsorlari 2021" width="1262" height="220" style="display: block; margin-left: auto; margin-right: auto;" /></p>', 1, 64, 'Duyuru', '/images/duyurular/yarisma-2023-afis2.jpeg', '2023-07-01');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (137, 'ay-j322', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2024', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2024', 'PDF', '<p style="text-align: right;"><a href="/docs/duyurular/Sekans_2024_Yarisma_Logolu_duyuru.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: justify;"><strong><img src="/images/duyurular/13.Yarisma_2024_afisi_logolu-2.jpg" alt="yarisma 2024" width="450" height="376" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p style="text-align: justify;"><strong>SEKANS SİNEMA GRUBU</strong>, film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek, sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması</strong>’nın bu yıl <strong>onüçüncüsünü</strong> gerçekleştirecektir.</p>\r\n<p>&nbsp;</p>\r\n<p style="word-spacing: -2px; text-align: justify;">Yarışmaya gönderilen yazılar film eleştirisi ve film çözümlemesi olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı ayrı belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KAPSAM VE KOŞULLAR</strong></p>\r\n<ol>\r\n<li><em>Başvurular e-posta yoluyla yapılacaktır. Yazının tarafımıza ulaştığı bilgisi başvuru sahibine iletilecektir.</em></li>\r\n<li><em>Yarışmaya katılacak yazılar <strong>Türkiye yapımı filmler</strong> üzerine olmalıdır.</em></li>\r\n<li><em>Yazıların daha önce (internet dahil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></li>\r\n<li><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></li>\r\n<li><em>Çeviri yazılarla yarışmaya başvurulamaz.</em></li>\r\n<li><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></li>\r\n<li><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></li>\r\n<li><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır: filmin adı, yılı, süresi, yönetmeni, senaristi, görüntü yönetmeni, sanat yönetmeni, müzik, kurgu, oyuncular.</em></li>\r\n<li><em>Yazıların dili Türkçe olmalıdır.</em></li>\r\n<li><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></li>\r\n<li><em>Katılımcılar açısından amatör-profesyonel ayrımı yoktur.</em></li>\r\n<li><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></li>\r\n<li><em>Yarışmaya katılan tüm yazıların yayın haklarının <strong>1 Temmuz 2025</strong>\'e kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></li>\r\n<li><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p><strong>BAŞVURU YÖNTEMİ</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>19 Haziran 2024 Çarşamba</strong>&nbsp;gününe kadar <span style="text-decoration: underline;"><strong>yarisma@sekans.org</strong></span> adresine yapılabilir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DEĞERLENDİRME SÜRECİ</strong></p>\r\n<p><strong>Ön Değerlendirme</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön Değerlendirme Kurulu yazıların değerlendirileceği başvuru kategorisinde değişiklik yapabilir.</p>\r\n<p><em>Ön değerlendirme kriterleri:</em></p>\r\n<p style="padding-left: 35pt;">a. Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması</p>\r\n<p style="padding-left: 35pt;">b. Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul Değerlendirmesi</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Her iki yarışma kategorisi için ön elemeden geçen en fazla onar adet yazı Seçici Kurul tarafından değerlendirilecek ve yarışmanın her iki kategorisinde birinci, ikinci ve üçüncülüğe değer bulunan yazılar belirlenecektir.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Seçici Kurul</strong><br />• Özgür İpek (<em>Akademisyen</em>)<br />• Ürün Yıldıran Önk (<em>Akademisyen</em>)<br />• Hakan Bıçakcı (<em>Sinema Yazarı</em>)<br />• Can Öktemer (<em>Sinefil</em>)<br />• Süheyla Tolunay İşlek (<em>Sekans Sinema Yazarı</em>)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA ÖDÜLLERİ</strong></p>\r\n<ul>\r\n<li><strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine <strong>3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediye etmektedir.</li>\r\n<li>Şimdiye kadar kesinleşen sponsor yayınevlerimiz&nbsp;<strong>AKADEMİM YAYINLARI</strong>, <strong>ESPAS YAYINLARI,&nbsp;</strong><strong>İLETİŞİM YAYINLARI</strong>, <strong>NOBEL AKADEMİK YAYINCILIK</strong> ve <strong>ÜTOPYA YAYINLARI</strong>’nın sağladığı kitaplardan oluşan karma setler derece alanlara hediye edilecektir.</li>\r\n</ul>\r\n<p><img src="/images/13.Yarisma_2024_afisi_logolar.jpg" alt="yarisma_2024_logo.png" width="1138" height="228" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>SONUÇ DUYURUSU</strong></p>\r\n<p style="text-align: justify; word-spacing: -2px;">Yarışma sonuçları <strong><em>1 Temmuz 2024 Pazartesi</em>&nbsp;</strong>günü Sekans web sitesinde ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz SEKANS Sinema Kültürü Dergisi\'nde yayımlanmak üzere değerlendirilecektir.</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', '/images/duyurular/13.Yarisma_2024_afisi_logolu-2.jpg', '2024-03-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (138, 'ay-j324', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2024-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2024 Sonuçlandı', 'PDF', '<p style="text-align: right;"><a href="/docs/duyurular/Sekans%20Film%20Elestirisi%20ve%20Film%20Cozumlemesi%20Yarismasi%202024%20Sonuclandi.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: justify;"><strong><img src="/images/duyurular/13.Yarisma_2024_afisi_logolu-2.jpg" alt="yarisma 2024" width="450" height="376" style="margin-left: 20px; float: right;" /></strong></p>\r\n<p style="text-align: justify;">Film eleştirisi alanında ürün veren amatör veya profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek, sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak ve ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla Sekans Sinema Grubu tarafından iki kategoride düzenlenen&nbsp;<strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması</strong>’nın&nbsp;<strong>onüçüncüsü&nbsp;</strong>sonuçlandı.</p>\r\n<p>&nbsp;</p>\r\n<div style="padding-bottom: 10px;">\r\n<p><span style="text-decoration: underline;"><strong>Yarışmanın Sponsor Kurumları</strong></span></p>\r\n</div>\r\n<ul style="list-style-type: disc;">\r\n<ul>\r\n<li><strong>MUBI</strong>, kategori birincilerine <strong>1 YILLIK</strong>, ikincilerine<strong> 3 AYLIK</strong>, üçüncülerine ise <strong>1 AYLIK</strong> üyelik hediyesiyle yarışmanın sponsoru oldu.</li>\r\n<li><strong>AKDEMİM YAYINLARI</strong>, <strong>ESPAS YAYINLARI</strong>, <strong>İLETİŞİM YAYINLARI</strong>, <strong>NOBEL AKADEMİK YAYINCILIK</strong> ve <strong>ÜTOPYA YAYINLARI</strong> değerli kitap seçkileri ile bu yılki yarışmanın sponsoru oldular.&nbsp;</li>\r\n</ul>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<div style="padding-bottom: 10px;">\r\n<p><span style="text-decoration: underline;"><strong>Seçici Kurul Değerlendirmesi</strong></span></p>\r\n</div>\r\n<p style="text-align: justify; word-spacing: -2px;"><strong>Can ÖKTEMER</strong> (Sinefil), <strong>Hakan BIÇAKCI</strong> (Sinema Yazarı),<strong> Özgür İPEK</strong> (Akademisyen), <strong>Süheyla TOLUNAY İŞLEK</strong> (Sekans-Sinema Yazarı) ve <strong>Ürün Yıldıran ÖNK</strong>’ten (Akademisyen) oluşan seçici kurulun değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p style="padding-left: 30px;"><em><strong>Film Çözümlemesi Yarışması</strong></em></p>\r\n<p style="padding-left: 60px;"><strong>Birinci: Ömer Yavuz ÖZASLAN</strong> – Yeni Dönem Türk Sinemasında İktidar ve Eril Tahakküm Meselesi: <em>Daha</em> ve <em>Sarmaşık</em> Filmlerinin Analizi</p>\r\n<p style="padding-left: 90px;">(<em>Daha</em> /Onur Saylak, <em>Sarmaşık</em> / Tolga Karaçelik)</p>\r\n<p style="padding-left: 60px;"><strong>İkinci: Gülper ALKAN</strong> – İktidar Meselesi: <em>Okul Tıraşı</em></p>\r\n<p style="padding-left: 90px;">(<em>Okul Tıraşı</em> / Ferit Karahan)</p>\r\n<p style="padding-left: 60px;"><strong>Üçüncü: Cenibe ERTEN ESEN</strong> – Görünenin Ötesi: <em>Kuru Otlar Üstüne</em></p>\r\n<p style="padding-left: 90px;">(<em>Kuru Otlar Üstüne</em> / Nuri Bilge Ceylan)</p>\r\n<p>&nbsp;</p>\r\n<p style="padding-left: 30px;"><em><strong>Film Eleştirisi Yarışması</strong></em><br />Bu kategoride dereceye giren yarışmacı bulunmamaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>YARIŞMA SPONSORLARI</strong></p>\r\n<p><img src="/images/13.Yarisma_2024_afisi_logolar.jpg" alt="yarisma_2024_logo.png" width="1138" height="228" style="display: block; margin-left: auto; margin-right: auto;" />&nbsp;</p>', 1, 64, 'Duyuru', '/images/duyurular/13.Yarisma_2024_afisi_logolu-2.jpg', '2024-07-12');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (139, 'ay-j329', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2025-sonuclandi', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2025 Sonuçlandı', 'Seçici Kurul Değerlendirmesi Hüseyin Can Ataç (Görüntü Yönetmeni), Dr. Öğr. Üyesi Emre Doğan (Akademisyen), Övgü Gökçe (Sinema Yazarı), Doç. Dr. Ece Vitrinel (Akademisyen-Sinema Yazarı), Sevilay Gedik’den (SEKANS-Sinefil', '<p><strong><span style="font-size: 14pt;">Seçici Kurul Değerlendirmesi</span></strong><br />Hüseyin Can Ataç (Görüntü Yönetmeni), Dr. Öğr. Üyesi Emre Doğan (Akademisyen), Övgü Gökçe (Sinema Yazarı), Doç. Dr. Ece Vitrinel (Akademisyen-Sinema Yazarı), Sevilay Gedik’den (SEKANS-Sinefil) oluşan seçici kurulun değerlendirmesi aşağıdaki gibi sonuçlanmıştır:</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style="font-size: 14pt;"> 2025 Sekans Film Eleştirisi Yarışması Sonuçları</span></strong><br /> <br /><br /><strong>Birinci:</strong> Muharrem DERİN- Barın Işıkları Sönüyor: Yüzeyde Şiddetli, Derinde Sessiz <br />(Barda / Hande Türkel / 2024)</p>\r\n<p><br /><strong>İkinci:</strong> Kemal YAŞAV- Bir Toplumcu Gerçeklik Filmi Olan ‘Maden’ Filminde Mizansen, Kostüm ve Müzik Kullanımı Üzerine Eleştiri<br />(Maden / Yavuz Özkan / 1978)</p>\r\n<p><br /><strong>Üçüncü:</strong> Buse DURSUN- Tereddüt Çizgisi <br />(Tereddüt Çizgisi / Selman Nacar / 2023)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: left;"><strong><span style="font-size: 14pt;">2025 Sekans Film Çözümlemesi Yarışması Sonuçları</span></strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Birinci</strong>: Akın TUNÇ- Toroslarda Uyanan Travmatik Bellek: Karanlık Gece<br />(Karanlık Gece / Özcan Alper/ 2022)</p>\r\n<p><br /><strong>İkinci</strong>: Bihter İŞLER- Balık Filminde Deleuzeyen Zaman<br />(Balık / Derviş Zaim / 2014)</p>\r\n<p><br /><strong>Üçüncü</strong>: Berfin TUTUCU- Ah Güzel İstanbul’u (1966) Sinematografik Yöntemlerle Yeniden “Görmek”<br />(Ah Güzel İstanbul / Atıf Yılmaz / 1966)</p>\r\n<p>&nbsp;</p>', 1, 64, 'Duyuru', NULL, '2025-03-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (140, 'ay-j341', 'sekans-film-elestirisi-ve-film-cozumlemesi-yarismasi-2026', 'Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2026', '', '<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><img src="/images/PHOTO-2026-05-05-22-32-25.jpg" alt="yarışma_2026.jpg" width="1264" height="763" style="display: block; margin-left: auto; margin-right: auto;" /></span></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>SEKANS SİNEMA GRUBU</strong>, film eleştirisi/film çözümlemesi alanında ürün veren amatör/ profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi ile film çözümlemesi üretimini desteklemek ve özendirmek; sinema kültürünün gelişimine katkı vererek bu alanda üretim yapan kişilere ortam sağlamak, ulusal sinemanın, film eleştirisi/film çözümlemesi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmak amacıyla düzenlediği <strong>Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması’nın on beşincisini </strong>gerçekleştirecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;">Yarışmaya gönderilen yazılar “film eleştirisi” ve “film çözümlemesi” olmak üzere iki ayrı kategoride değerlendirilecek, ödül almaya uygun görülen ilk üç yazı her iki kategori için ayrı olarak belirlenecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p dir="ltr"><span style="font-size: 12pt;"><strong>KAPSAM VE KOŞULLAR</strong></span></p>\r\n<ol>\r\n<li><span style="font-size: 12pt;"><em>Başvurular elektronik olarak (e-posta yoluyla) yapılacaktır. Yazının tarafımıza ulaştığı bilgisi, başvuru sahibine iletilecektir.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yarışmaya katılacak yazılar Türkiye yapımı filmler üzerine olmalıdır.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yazıların daha önce (internet dâhil hiçbir ortamda) yayımlanmamış olması gerekmektedir.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yarışmaya gönderilen eleştiri ve çözümleme yazıları tek bir film üzerine olmalıdır. </em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Her yazar, her iki kategoriye de, kategori başına en fazla iki yazıyla başvurabilir.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Çeviri eleştiri veya çözümleme yazılarıyla yarışmaya başvurulamaz.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yazılar Times New Roman karakterinde, 12 punto ve çift satır aralıklı olmalıdır.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yazılara konu olan filmlerin yapım yılı, türü vb. konusunda bir sınırlama yoktur.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Filmin künyesine ait sayılan bilgilerin tamamı yazının girişinde yer almalıdır. (Filmin Adı, Yılı, Süresi, Yönetmeni, Senaryo Yazarı, Görüntü Yönetmeni, Sanat Yönetmeni, Müzik, Kurgu, Oyuncular)</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yazıların dili Türkçe olmalıdır.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yazarların bir sayfayı aşmayan biyografilerini iletmeleri zorunludur.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Katılımcılar açısından amatör / profesyonel ayrımı yoktur.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Başvuru, yazıların yazarları tarafından yapılır. Eser sahipliği ve telif hakları konusunda yaşanacak herhangi bir hukuki sorun karşısında başvuru sahibi sorumludur.</em></span></li>\r\n<li><span style="font-size: 12pt;"><em></em><em>Yarışmaya katılan tüm yazıların yayın haklarının 1 Temmuz 2027 tarihine kadar SEKANS SİNEMA GRUBU’na ait olduğu, katılımcılar tarafından kabul edilmiş sayılır.</em></span></li>\r\n</ol>\r\n<p><span style="font-size: 12pt;"><em></em><em>Yarışmaya katılan herkes bu kapsam ve koşulları kabul etmiş sayılır ve yerine getirmedikleri takdirde ön elemeyi aşamazlar.</em></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>BAŞVURU YÖNTEMİ</strong></span></p>\r\n<p><span style="font-size: 12pt;">Yarışma başvuruları, başvuru kategorisi belirtilerek (film eleştirisi veya film çözümlemesi) son başvuru tarihi olan <strong>30 Haziran 2026 Salı </strong>gününe kadar <a href="mailto:yarisma@sekans.org"></a><strong><a href="mailto:yarisma@sekans.org">yarisma@sekans.org</a></strong> adresine yapılır.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>DEĞERLENDİRME SÜRECİ</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>Ön Değerlendirme</strong></span></p>\r\n<p><span style="font-size: 12pt;">Yazıların ön elemesini gerçekleştirecek olan Ön Değerlendirme Kurulu, Sekans Sinema Grubu yazarlarından oluşmaktadır. Ön Değerlendirme Kurulu tarafından yazıların değerlendirileceği başvuru kategorisinde değişiklik yapılabilir.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><em>Ön değerlendirme kriterleri:&nbsp;</em></span></p>\r\n<p><span style="font-size: 12pt;">1<em>-</em>Yazının yukarıda yer alan yarışma kapsam ve koşullarını karşılaması&nbsp; &nbsp;</span></p>\r\n<p><span style="font-size: 12pt;">2-Yazının bilinen eleştiri ve çözümleme tekniklerine uygunluğu</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>Seçici Kurul Değerlendirmesi</strong></span></p>\r\n<p><span style="font-size: 12pt;">Her iki yarışma kategorisi için ön elemeden geçen en fazla 10’ar yazı Seçici Kurul tarafından değerlendirilecek ve yarışmanın her iki kategorisindeki birinci, ikinci ve üçüncülüğe değer bulunan yazılar belirlenecektir.</span></p>\r\n<h2><span style="font-size: 12pt;"><strong>SONUÇ DUYURUSU</strong></span></h2>\r\n<p><span style="font-size: 12pt;">Yarışma sonuçları <strong>11 Temmuz 2026 Cumartesi </strong>günü Sekans web sayfasında ve medyada duyurulacaktır. Ödül alan yazılar elektronik dergimiz olan SEKANS Sinema Kültürü Dergisi’nde yayımlanmak üzere değerlendirilecektir.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style="font-size: 12pt;"><strong>Sekans Sinema Grubu</strong></span></p>\r\n<p><span style="font-size: 12pt;"><a href="http://www.sekans.org"></a><a href="http://www.sekans.org">http://www.sekans.org</a></span></p>\r\n<p><span style="font-size: 12pt;">Sinemanın yaşamında önemli bir rol oynadığını düşünen, onu bir yaşam biçimi olarak gören bireylerin kurduğu Sekans Sinema Grubu, yanına inandığı değerleri alarak yola çıktı: Sinemanın kitlelerce önemli görülen eğlence yönü, karakteristik açılımlarından biri olmakla kalmaz, tüketim toplumunun yaratıcısı ve besleyicilerinden biridir de. Sinema salt bir sanat değil, görsel-işitsel bir dil ve sınırsız bir veri bankasıdır.</span></p>\r\n<p><span style="font-size: 12pt;">Grubumuzun ana uğraşısını eğitim seminerleri oluşturmaktadır. Bunun nedeni, sinemanın varsıllaşamaması konusunda gördüğümüz en büyük engelin eğitim ve bilgi boşluğu olduğuna inanmamızdır.</span></p>\r\n<p><span style="font-size: 12pt;">Yapım, yayıncılık, yayımcılık, arşiv, organizasyon ve kültürel etkinlik konularında gerçekleştirdiğimiz çalışmalarla sinema kültürünün ve sevgisinin gelişip güçlenmesini sağlamak, sinema çalışanlarının ve sinemaseverlerin sosyal ve kültürel gereksinimlerini karşılamak, öncelikli amaçlarımız arasındadır.</span></p>', 1, 64, 'Duyuru', '/images/PHOTO-2026-05-05-22-32-25.jpg', '2024-03-03');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (141, 'ay-j128', 'sekans-sinema-yazilari-seckisi', 'Sekans Sinema Yazıları Seçkisi', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_1_KAPAK_450x650.jpg" alt="SEKANS KITAP 1 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Reconstruction / Postmodern Bir Kurgu Oyunu</p>\r\n<p>&nbsp;Ger&ccedil;eklik Sorgusunda Sonbahar</p>\r\n<p>&nbsp;&Uuml;&ccedil; Maymun&rsquo;da Kadın Temsili</p>\r\n<p>&nbsp;Pontypool: K&uuml;resel Dilin Yapıs&ouml;k&uuml;m&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;James Monaco ile Bir S&ouml;yleşi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM YORUM</strong></p>\r\n<p>&nbsp;Punctum&rsquo;dan Freeze Frame&rsquo;e: Fotoğraf ve Sinemanın Etkileşimi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Svanetia i&ccedil;in Tuz</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA ARKEOLOJİSİ</strong></p>\r\n<p>&nbsp;Holivut D&uuml;nyası</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BİYOGRAFİ</strong></p>\r\n<p>&nbsp;Ahmet Tarık Tek&ccedil;e / Bir K&ouml;t&uuml; Adam ve Par&ccedil;alanan Koltuklar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong></p>\r\n<p>&nbsp;Askerin T&uuml;rk&uuml;s&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANI / NOSTALJİ</strong></p>\r\n<p>&nbsp;Vera Chytilova / Risk Taşımayan Hi&ccedil;bir Ger&ccedil;ek Dava Tanımıyorum</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;Yeşil&ccedil;am&rsquo;ın Partici Gen&ccedil;leri ve &Ouml;tekilerin Karşılaştığı Mekanlar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;Larisa Shepitko ile Bir S&ouml;yleşi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA</strong></p>\r\n<p>&nbsp;Borom Sarret / Saftan Bir Arabacı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DOSYA: MİMARLIK</strong></p>\r\n<p>&nbsp;İ&ccedil;inde Yaşanacak Bir Film</p>\r\n<p>&nbsp;Filmlerdeki Kent İmajları</p>\r\n<p>&nbsp;Suha Arın Belgesel Sinemasında G&ouml;rsel Bir Eylem Olarak Bi&ccedil;im</p>\r\n<p>&nbsp;G&uuml;neşi Y&uuml;kseltmek: Karanlık Kent</p>\r\n<p>&nbsp;K&uuml;p: Kontrolden &Ccedil;ıkmış Bir &lsquo;M&uuml;kemmel&rsquo;</p>\r\n<p>&nbsp;Mon Oncle ile Modern Mimarlıktan Yerel Mimarlığa Yolculuk</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Film &Ccedil;&ouml;z&uuml;mlemeleri</p>\r\n<p>&nbsp;Ne Kadar Gamlı Bu Akşam Vakti "<span style="color: #333333;">Safa &Ouml;nal Kitabı</span>"</p>\r\n<p>&nbsp;Fikret Hakan - Eskimeyen Yeşil&ccedil;amlı</p>\r\n<p>&nbsp;Kadına Melodram Yakışır - T&uuml;rk Melodram Sinemasında Kadın İmgeleri</p>\r\n<p>&nbsp;Dram Sanatı ve Sinema</p>\r\n<p>&nbsp;Senaryo Yazımı - Sinema ve Televizyon İ&ccedil;in</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İSTATİSTİK</strong></p>\r\n<p>&nbsp;Okur Profili</p>\r\n<p>&nbsp;En İyi Film / Y&ouml;netmen</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_1_KAPAK_450x650.jpg', '2016-05-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (142, 'ay-j129', 'sekans-sinema-yazilari-seckisi-2', 'Sekans Sinema Yazıları Seçkisi 2', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KİTAP_2_KAPAK_450x650.jpg" alt="SEKANS KİTAP 2 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Parlak Yıldız / O, Weep for Adonais!</p>\r\n<p>&nbsp;Achilles ve Tosbağa / Achilles &Ccedil;ok Tosbağa Yok</p>\r\n<p>&nbsp;Kız Kardeşim/Mommo / Yaşamın Kıyısında İki Minik Y&uuml;rek</p>\r\n<p>&nbsp;Nefes: Vatan Sağolsun / Yasak &Ouml;l&uuml;m ve Yaşam Arasında Ger&ccedil;eği Aramak</p>\r\n<p>&nbsp;Kırık Kucaklaşmalar / Tutku S&ouml;z Dinlemez!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Pascal Bonitzer ile S&ouml;yleşi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Bilişsel Film Kuramında Anlatı ve Duygusal Yapı: G&ouml;lgesizler Filmi &Uuml;zerine Bir &Ccedil;&ouml;z&uuml;mleme</p>\r\n<p>&nbsp;Ge&ccedil;mişi (Yeniden) Betimlemek: Tomris Giritlioğlu&rsquo;nda S&ouml;ylem ve Kimlik</p>\r\n<p>&nbsp;Alan-Dışından Akan Tekinsiz Hayat</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Leacock&rsquo;ın İzinde Kontrols&uuml;zl&uuml;ğe &Ouml;vg&uuml;</p>\r\n<p>&nbsp;Pop&uuml;ler K&uuml;lt&uuml;r ve Bir Karşı S&ouml;ylem Aracı Olarak Belgesel Sinema</p>\r\n<p>&nbsp;Furuğ&rsquo;un Şiirindeki İnsan Lekeleri</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA</strong></p>\r\n<p>&nbsp;Ah Minel Aşk!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;Yeni D&uuml;nya D&uuml;zeni ve Sinema</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;D&uuml;şlerin Dediği / Ahmet Ulu&ccedil;ay&rsquo;ın Anısına</p>\r\n<p>&nbsp;Gidenin Ardından Bir Zeki &Ouml;kten Ağıtı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Y&Ouml;NETMEN</strong></p>\r\n<p>&nbsp;Zaim&rsquo;i Beklerken</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;T&uuml;rk Sinematek Derneği - T&uuml;rkiye\'de Sinema ve Politik Tartışma</p>\r\n<p>&nbsp;Y&ouml;netmen Sineması: Zeki Demirkubuz</p>\r\n<p>&nbsp;T&uuml;rk Sinemasında Akım Araştırması</p>\r\n<p>&nbsp;Y&ouml;netmen Sineması: Nuri Bilge Ceylan</p>\r\n<p><span style="color: #333333;">&nbsp;Y&ouml;netmen Sineması: Derviş Zaim</span></p>\r\n<p>&nbsp;T&uuml;rk Film Araştırmalarında Yeni Y&ouml;nelimler 8</p>\r\n<p>&nbsp;T&uuml;rk Sinemasında Karakterler ve Tipler</p>\r\n<p>&nbsp;Senaryo Kitabı</p>\r\n<p>&nbsp;Y&ouml;netmenlerin İzinde Macar Sineması</p>\r\n<p>&nbsp;Reha Erdem Sineması: Aşk ve İsyan</p>\r\n<p>&nbsp;</p>\r\n<p><span style="color: #222222; font-family: arial, sans-serif; font-size: small;"></span></p>\r\n<p><strong>DOSYA: SİNEMA VE FELSEFE</strong></p>\r\n<p>&nbsp;G&ouml;rmenin &Ouml;nselliği ve Sinema</p>\r\n<p>&nbsp;Sinema ve Felsefe</p>\r\n<p>&nbsp;Metropolis&rsquo;te Aydınlanma&rsquo;nın Diyalektiği</p>\r\n<p>&nbsp;Sartre, Hi&ccedil;lik Felsefesi ve Modern Melodram</p>\r\n<p>&nbsp;B&eacute;la Tarr&rsquo;ın Ger&ccedil;ekliği Yaratıcı Keşfi&rsquo;nde Sanat ve Felsefe Olarak Sinema</p>\r\n<p>&nbsp;Sinema ve Felsefe İlişkisi &Uuml;zerine Bir Soruşturma</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KİTAP_2_KAPAK_450x650.jpg', '2016-05-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (143, 'ay-j132', 'sekans-sinema-yazilari-seckisi-3', 'Sekans Sinema Yazıları Seçkisi 3', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_3_KAPAK_450x650.jpg" alt="SEKANS KITAP 3 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Deccal / Deccal: Şeytanın Kilisesi, Kadının Bedeni</p>\r\n<p>&nbsp;Pus / Paslı Bi&ccedil;im Puslu Anlam</p>\r\n<p>&nbsp;Film Sosyalizm / Sonun Sonu</p>\r\n<p>&nbsp;Ayrılık / Erkeğin &Ouml;yk&uuml;s&uuml;nden &Ccedil;ıkış Yok!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;G&uuml;neş Karabuda&rsquo;nın Sinemasalı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM-YORUM</strong></p>\r\n<p>&nbsp;Sinemanın Etik Bağlamı: &Ouml;zne ve İlişki Arayışları</p>\r\n<p>&nbsp;Tarihsel Etkilenme, Malezya Sineması ve Japon İşgali</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Kosmos ve Derridacı Misafirperverlik</p>\r\n<p>&nbsp;Dişil Bakışla Afrika&rsquo;yı ve Kadın Bedenini Yeniden Kurgulamak</p>\r\n<p>&nbsp;Y&uuml;ce&rsquo;nin Kanlı Arenası</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Michael Glawogger</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Rock and Roll Deyip Ge&ccedil;me: &lsquo;Rockumentary&rsquo;, Dolaysız Sinema ve Performans Sergileme</p>\r\n<p>&nbsp;</p>\r\n<p><strong>M&Uuml;ZİK</strong></p>\r\n<p>&nbsp;60&rsquo;lı Yıllarda İngiliz Yeni Dalga Sinemasında Caz: Sir John Dankworth ile S&ouml;yleşi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ARKEOLOJİ</strong></p>\r\n<p>&nbsp;Sinema Tarihi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;Canlı Sinema: İ&ccedil;erik ve &lsquo;G&uuml;ncellik&rsquo;</p>\r\n<p>&nbsp;Film &Uuml;zerine Tartışmalar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;Sayat Kino-Nova... Sergo Paracanov</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong></p>\r\n<p>&nbsp;Sinema Onları &Ouml;lmez Kıldı... Frankenstein, Anita Garibaldi, Puşkin</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Sinemekan Sinemada Mimarlık</p>\r\n<p>&nbsp;B&uuml;y&uuml;k Sinema Kuramları</p>\r\n<p>&nbsp;Kameramanlık Mesleğine Giriş</p>\r\n<p>&nbsp;Biyografya 8 T&uuml;rkan Şoray</p>\r\n<p>&nbsp;Films and Dreams</p>\r\n<p>&nbsp;Yeşil&ccedil;am G&uuml;nl&uuml;ğ&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DOSYA: KISA FİLM</strong></p>\r\n<p>&nbsp;Kısa Filmin Poetikasına Doğru</p>\r\n<p>&nbsp;Kısa S&uuml;reli Film, Samimiyet ve Birka&ccedil; Başka Husus</p>\r\n<p>&nbsp;Kısa Film &Ouml;ld&uuml;: Yolun Başındaki Sinemacının Yeni Bir Kartvizit Edinmesinin Vaktidir</p>\r\n<p>&nbsp;Kısa Kurmaca Filmde &Ouml;yk&uuml; Tasarımı</p>\r\n<p>&nbsp;Lars Henrik Gaas ile Kısaca</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_3_KAPAK_450x650.jpg', '2016-05-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (144, 'ay-j133', 'sekans-sinema-yazilari-seckisi-4', 'Sekans Sinema Yazıları Seçkisi 4', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_4_KAPAK_450x650.jpg" alt="SEKANS KITAP 4 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Kray / Gulag İle Alternatif Bir Y&uuml;zleşme</p>\r\n<p>&nbsp;Un Homme Qui Cire / Suskunluğunca Haykıran Adam</p>\r\n<p>&nbsp;Ses / Psikolojik Gerilime Terfi &Ccedil;abası</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Serpil Aydos ile Ulusal Sinema &Uuml;zerine</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM-YORUM</strong></p>\r\n<p>&nbsp;Seyircinin Zihnindeki Film: Adorno ve Kluge&rsquo;nin Sinema Anlayışları ve Montaj</p>\r\n<p>&nbsp;Diyalektik Film Eleştirisi: Walter Benjamin&rsquo;in Tarih Yazımı, K&uuml;lt&uuml;rel Eleştiri ve Arşivleme</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Prensesin Uykusu, Bizim B&uuml;y&uuml;k &Ccedil;aresizliğimiz ve Kaybedenler Kul&uuml;b&uuml;:</p>\r\n<p>&nbsp;Yalnız, Mutsuz, K&ouml;ks&uuml;z ve B&uuml;y&uuml;meyen Erkeklere Dair</p>\r\n<p>&nbsp;Olanaksız Ge&ccedil;işler: Lola + Bilidikid ve Yurtdışı Turnesi&rsquo;nde Toplumsal Cinsiyet ve Melankoli</p>\r\n<p>&nbsp;Siyah Kuğu ve Bir Anlatısal &Ccedil;&ouml;z&uuml;mleme Denemesi</p>\r\n<p>&nbsp;Kızların Peşinde: Yeni Queer Sinemada Lezbiyenleri Tavlamak</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Rock &amp; Roll Deyip Ge&ccedil;me: &lsquo;Rockumentary&rsquo;, Dolaysız Sinema ve Performans Sergileme</p>\r\n<p>&nbsp;</p>\r\n<p><strong>AREKOLOJİ</strong></p>\r\n<p>&nbsp;Harmankaya - Yıldızlar Ne Diyor</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong><br />&nbsp;Sinemanın &Ouml;z&uuml;: G&ouml;rsel D&uuml;ş&uuml;nce</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong><br />&nbsp;Sivastopol Savunması</p>\r\n<p>&nbsp;</p>\r\n<p><strong>MİNİ S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;B&eacute;la Tarr&rsquo;ın &lsquo;Hayat&rsquo; G&ouml;r&uuml;ş&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Godard: Sanat&ccedil;ının Yetmiş Yaşında Bir Portresi</p>\r\n<p>&nbsp;Ulusal Sinema Kavgası</p>\r\n<p>&nbsp;Y&ouml;netmen Sineması: Ahmet Ulu&ccedil;ay</p>\r\n<p>&nbsp;Bağımsız Sinema</p>\r\n<p>&nbsp;Sinema Araştırmaları: Kuramlar, Kavramlar, Yaklaşımlar</p>\r\n<p>&nbsp;Sentezler</p>\r\n<p>&nbsp;Y&ouml;netmen Sineması: Semih Kaplanoğlu</p>\r\n<p>&nbsp;Senaryo Yazımı</p>\r\n<p>&nbsp;Politik Film: &Uuml;&ccedil;&uuml;nc&uuml; Sinemanın Diyalektiği</p>\r\n<p>&nbsp;Doğu Asya Sineması</p>\r\n<p>&nbsp;Eşcinsel Sineması</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DOSYA: GLAUBER ROCHA</strong></p>\r\n<p>&nbsp;Cinema Novo&rsquo;nun Rocha&rsquo;sı</p>\r\n<p>&nbsp;Manifestolar</p>\r\n<p>&nbsp;Kendinden Ge&ccedil;miş &Uuml;lke</p>\r\n<p>&nbsp;Ozansı Bir Fırtına:&nbsp; Glauber Rocha</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_4_KAPAK_450x650.jpg', '2016-05-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (145, 'ay-j134', 'sekans-sinema-yazilari-seckisi-5', 'Sekans Sinema Yazıları Seçkisi 5', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_5_KAPAK_450x650.jpg" alt="SEKANS KITAP 5 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Zenne / Bir &ldquo;Misyon&rdquo; Filmi Olarak Zenne</p>\r\n<p>&nbsp;Unutma Beni İstanbul / Hatırlanmaya Yazgılı Olanın Belleğinde Yaşamak</p>\r\n<p>&nbsp;Gelecek Uzun S&uuml;rer / Gelecek &lsquo;Uzun&rsquo; S&uuml;r&uuml;yor</p>\r\n<p>&nbsp;Eyl&uuml;l / Y&ouml;netmenin Nedensiz Kendine G&uuml;ven Hali, Filmin Yalpalayan Hali</p>\r\n<p>ve Korkarım &lsquo;Bir Kısım Sinema&rsquo;mızın Gelecek Zaman Hali</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Pirselimoğlu Sinemasının Ruh Hali</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;T&uuml;rk Sinemasında Aşkın T&uuml;rl&uuml; Halleri:</p>\r\n<p>&nbsp;Tutulan, Acı &Ccedil;eken, Başka Dilde, Geliyorum Demeyen ve Tesad&uuml;fleri Seven Aşklar</p>\r\n<p>&nbsp;Alman RAF&rsquo;ın Politik Sinemada Temsili</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA FİLM</strong></p>\r\n<p>&nbsp;Başak Emre ile Kars &Ouml;yk&uuml;leri</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ARKEOLOJİ</strong></p>\r\n<p>&nbsp;Yıldız - 1948 Yıllık / İhtiya&ccedil; Olan Bir Par&ccedil;a Himmet</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong><br />&nbsp;Il Posto</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong><br />&nbsp;Oynayan Dudaklar: Karnından Konuşan Sinema</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;Andrzej Munk&rsquo;un Yolcu&rsquo;su</p>\r\n<p>&nbsp;Muzaffer Tema - Aileden Biri Daha Gitti</p>\r\n<p>&nbsp;Akad... Işık Karanlığa Y&uuml;r&uuml;d&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong><br />&nbsp;Enoch Arden: Bir Şiirimsinin Katli</p>\r\n<p>&nbsp;</p>\r\n<p><strong>PANEL</strong><br />&nbsp;12 Eyl&uuml;l ve Sinema</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Sinema ve Ger&ccedil;eklik / Tarihsel Bir İnceleme</p>\r\n<p>&nbsp;T&uuml;rk Film Araştırmalarında Yeni Y&ouml;nelimler 9</p>\r\n<p>&nbsp;&Uuml;&ccedil;&uuml;nc&uuml; D&uuml;nya Sineması ve Batı</p>\r\n<p>&nbsp;Sinemada Zaman - Ritmik Tasarım; T&uuml;rb&uuml;lans ve Akış</p>\r\n<p>&nbsp;Giovanni Scognamillo\'nun G&ouml;z&uuml;yle Yeşil&ccedil;am</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DOSYA: SİNEMA VE EDEBİYAT</strong></p>\r\n<p>Zeki Demirkubuz Filmleri &Uuml;zerine Bir Deneme: Sinema Edebiyat İlişkisi</p>\r\n<p>İki &Ouml;yk&uuml;, &Ccedil;eşitli Uzamlar: İsmail Kadar&eacute;&rsquo;nin Edebiyatı ve Walter Salles&rsquo;in Sineması</p>\r\n<p>Gabito&rsquo;nun Sineması</p>\r\n<p>Ayna Filminde Arseniy Tarkovsky Şiirinin Okuyucusu Olarak Andrey Tarkovsky</p>\r\n<p>&Ouml;yk&uuml;leri Sinemaya Dokunan Yazar: Cemil Kavuk&ccedil;u</p>\r\n<p>Panterin G&ouml;z&uuml;: Rilke ve Sinema Denilen Makine</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_5_KAPAK_450x650.jpg', '2016-05-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (146, 'ay-j136', 'sekans-sinema-yazilari-seckisi-6', 'Sekans Sinema Yazıları Seçkisi 6', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_6_KAPAK_450x650.jpg" alt="SEKANS KITAP 6 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Akasyalar / Bir Akasya Karacığı K&ouml;k Salar Y&uuml;reğime<br />&nbsp;Geriye Kalan / Geriye Kalma(ma) İhtimali<br />&nbsp;Le Havre / Mavi G&ouml;zlerinden Dolayı...</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;9 &rsquo;dan Nar&rsquo;a &Uuml;nal Sineması</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong><br />&nbsp;50 Yaşındaki Bir Filmi Yeniden İzlemek</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong><br />&nbsp;Karartma Geceleri &Uuml;zerinden İki İsim</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong><br />&nbsp;Kamera Operat&ouml;r&uuml;n&uuml;n İntikamı Bir Kinok &Ccedil;ekirgenin Aşk G&uuml;nl&uuml;ğ&uuml;nden<br />&nbsp;The Heart of an Indian</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong><br />&nbsp;Ethem &Ouml;zg&uuml;ven&rsquo;de Kurmaca ve Hakikat Anlayışı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SORUŞTURMA</strong><br />&nbsp;Altyazının Nitelikle Senkronizasyonu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Senaryo Tekniği (Teorisi ve Pratiği)</p>\r\n<p>&nbsp;Faşizmin Etkisinde T&uuml;rkiye\'de Sinema (1939-1945)</p>\r\n<p>&nbsp;2000 Sonrası T&uuml;rk Sinemasına Eleştirel Bir Bakış</p>\r\n<p>&nbsp;K&uuml;resel Hollywood</p>\r\n<p>&nbsp;Yakın Plan Yeni T&uuml;rkiye Sineması</p>\r\n<p>&nbsp;Ingmar Bergman / Sinematografi İnsan Y&uuml;z&uuml;d&uuml;r</p>\r\n<p>&nbsp;Saniyede 24 Kare &Ouml;l&uuml;m</p>\r\n<p>&nbsp;Arada Kalmak</p>\r\n<p>&nbsp;T&uuml;rk Sinemasının Felsefi Arka Planı - Sinemayı Felsefe İle D&uuml;ş&uuml;nmek</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DOSYA: SİNEMA VE AŞK</strong><br />&nbsp;Sinemada Modernizm ve Son Bakışta Aşk<br />&nbsp;Sinemada Aşk ve Arzu</p>\r\n<p>&nbsp;Sevgi Neydi</p>\r\n<p>&nbsp;Kutsal &Ouml;rt&uuml;: Pe&ccedil;enin Altında Aşk ve Cinsellik</p>\r\n<p>&nbsp;Romantizmin Sonu: Postmodern &Ccedil;ağda Aşkın Yok Olan Gizemi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANKET</strong></p>\r\n<p>&nbsp;Sekans Sinema Eğilimleri Anketi 2</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_6_KAPAK_450x650.jpg', '2012-06-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (147, 'ay-j137', 'sekans-sinema-yazilari-seckisi-7', 'Sekans Sinema Yazıları Seçkisi 7', 'ELEŞTİRİ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_7_KAPAK_450x650.jpg" alt="SEKANS KITAP 7 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Bir Zamanlar Anadolu&rsquo;da / Pencerenin Ardı<br />&nbsp;Sezar &Ouml;lmeli / Cesare Kalmadı, Brutus Verelim<br />&nbsp;Lal Gece / Kurban Kim?<br />&nbsp;Pl&uuml;ton&rsquo;da Kahvaltı / Pl&uuml;ton&rsquo;da Kahvaltıya İnanmak</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Faruk G&uuml;naltay&rsquo;la Eurimages&rsquo;dan Strasbourg Film G&uuml;nlerine</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong><br />&nbsp;G&ouml;r&uuml;nenler Kutsanmış mıdır? Sinemanın Kaderi Olarak Cisimleşme<br />&nbsp;Yeni T&uuml;rk Sineması - T&uuml;rk Ruhunun Yersiz Yurtsuzluğu &Uuml;zerine D&uuml;ş&uuml;nceler</p>\r\n<p>&nbsp;</p>\r\n<p><strong>M&Uuml;ZİK</strong><br />&nbsp;Sally Potter&rsquo;ın Orlando Filmindeki M&uuml;zikal Zenginlikle Belirsizliği ve Tutkuyu Yakalamak</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ARKEOLOJİ</strong><br />&nbsp;1956 Sinema Yıllığı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BİYOGRAFİ</strong><br />&nbsp;Roy Andersson / &Ouml;l&uuml; Yaşamlarımız İ&ccedil;in Bir Dakikalık Kahkaha</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong><br />&nbsp;&Ouml;l&uuml;mler Bizi &Ouml;zg&uuml;rleştirebilir mi?</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong><br />&nbsp;Bebek Jane&rsquo;e Ne Oldu?<br />&nbsp;Susturulmuşun Sesi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong><br />&nbsp;Chris Marker - Son Olasılık Mavi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong><br />&nbsp;Yaşlı Ulunun Ayrılışı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>GRAFİK TASARIM</strong><br />&nbsp;1990 Sonrası T&uuml;rk Sinemasında Film Jenerikleri: Dijital Teknoloji ve Sınırsız Evren</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;1990 Sonrası T&uuml;rk Sineması (1990-2011)</p>\r\n<p>&nbsp;Bir Kapıdan Gireceksin - T&uuml;rkiye Sineması &Uuml;zerine Denemeler</p>\r\n<p>&nbsp;Sinema G&ouml;stergebilimi</p>\r\n<p>&nbsp;Sinemada Psikoloji - Anormal Davranışlar</p>\r\n<p>&nbsp;Melodramatik İmgelem</p>\r\n<p>&nbsp;Kitle K&uuml;lt&uuml;r&uuml; Sineması ve B Filmi</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_7_KAPAK_450x650.jpg', '2012-12-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (148, 'ay-j138', 'sekans-sinema-yazilari-seckisi-8', 'Sekans Sinema Yazıları Seçkisi 8', 'ÖNSÖZ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_8_KAPAK_450x650.jpg" alt="SEKANS KITAP 8 KAPAK 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>&Ouml;NS&Ouml;Z</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Aziz Ayşe / Direnişin Mekanları</p>\r\n<p>&nbsp;R&uuml;zgarlar / Kapıldım Gidiyorum Bahtımın R&uuml;zgarına</p>\r\n<p>&nbsp;İklimler</p>\r\n<p>&nbsp;Kelebeğin R&uuml;yası / Şairin Yolculuğu ve Karşılaşmalar</p>\r\n<p>&nbsp;T&uuml;rkiye Sinemasında Karlı Bir Doruk: &ldquo;Ağrı Dağı Efsanesi&rdquo; &Uuml;st&uuml;ne</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Farid Mirkhani ile Dereden Tepeden</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM YORUM</strong></p>\r\n<p>&nbsp;Par&ccedil;a-B&uuml;t&uuml;n Ayrımına Hapsolan Sinema Analizlerine K&ouml;ktenci Bir Yaklaşım: M&uuml;nsterberg&rsquo;in Dolaysız Kuramı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA</strong></p>\r\n<p>&nbsp;Kısa&rsquo;ca Polanski</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Christopher Nolan Sinemasına Toplu Bir Bakış</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Şiirin Kırık Fayları &Uuml;zerinde Beklemek</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ARKEOLOJİ</strong></p>\r\n<p>&nbsp;Film D&uuml;nyası&rsquo;nın D&uuml;nyası</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANI/NOSTALJİ</strong></p>\r\n<p>&nbsp;Arzunun T&ouml;reni / Daniel Schmid Sinemasının Kapısını Aralamak</p>\r\n<p>&nbsp;</p>\r\n<p><strong>AKIM</strong></p>\r\n<p>&nbsp;Nova Vlna: Doğu Avrupa&rsquo;da Bir Yeni Dalga Akımı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>TARİH</strong></p>\r\n<p>&nbsp;Kekeleyen İran Sineması</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;&ldquo;Eşitlik Nereden Gelir: to be&rsquo;den mi, to exist&rsquo;den mi?&rdquo; ya da &ldquo;Eşitliği Ne Bozar?&rdquo;</p>\r\n<p>&nbsp;Y&uuml;zleşmekle Y&uuml;zleşmenin Y&uuml;zs&uuml;zl&uuml;ğ&uuml;</p>\r\n<p>&nbsp;Su&ccedil;luluk Kulesinden Gayet &ldquo;Normal&rdquo; Manzaralar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;Bunuel&rsquo;e Selam Olsun! Bir End&uuml;l&uuml;s K&ouml;peği &Uuml;zerine</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong></p>\r\n<p>&nbsp;İkisi de Cesurdu</p>\r\n<p>&nbsp;Kurak Hayatlar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Şamil Aliyev: Hayat Mit Değildir</p>\r\n<p>&nbsp;</p>\r\n<p><strong>100. YAŞINDA</strong></p>\r\n<p>&nbsp;Fantomas B&ouml;l&uuml;m 1: Giyotinin G&ouml;lgesinde</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Sinema ve Psikanaliz - Filmler ve Bilin&ccedil;dışı</p>\r\n<p>&nbsp;Filmozofi</p>\r\n<p>&nbsp;T&uuml;rk Sinemasının Ekonomik Yapısı (1986-2005)</p>\r\n<p>&nbsp;Sinema Okuryazarlığı</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_8_KAPAK_450x650.jpg', '2013-06-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (149, 'ay-j139', 'sekans-sinema-yazilari-seckisi-9', 'Sekans Sinema Yazıları Seçkisi 9', 'ÖNSÖZ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_9_450x650.jpg" alt="SEKANS KITAP 9 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>&Ouml;NS&Ouml;Z</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p><span style="color: #333333;">&nbsp;Kutsal Motorlar</span></p>\r\n<p><span style="color: #333333;">&nbsp;Sen Aydınlatırsın Geceyi / Acemi M&uuml;ezzin\'e Başlasam mı?</span></p>\r\n<p>&nbsp;K&ouml;ks&uuml;z / &Ccedil;ukurda Kalmak</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p style="line-height: 1.71429;">&nbsp;Belmin S&ouml;ylemez ile Kentin, Kadının, Yaşamın Şimdisi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Yarım Kalmış Mutluluk: Sınıf Sınırları ve T&uuml;rk Melodramında \'İmkansız Aşk\'</p>\r\n<p>&nbsp;Gelecek Uzun S&uuml;rer&rsquo;in Ger&ccedil;ek&ccedil;iliği</p>\r\n<p>&nbsp;</p>\r\n<p><strong>MİNİ S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Carlos Reygadas ile Son Filmi Karanlıktan Aydınlığa, Sanat, Siyaset ve Sinema &Uuml;zerine</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA</strong></p>\r\n<p>&nbsp;Demir Parmaklıklı Pencereler</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM YORUM</strong></p>\r\n<p>&nbsp;S&ouml;m&uuml;rgecilik ve \'Kanun ve D&uuml;zen\' Eleştirisi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;Yolda, Ben ve Edgar</p>\r\n<p>&nbsp;Andrey\'e Yaklaşma &Ccedil;abaları</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Uuml;LKE SİNEMASI</strong></p>\r\n<p>&nbsp;Devrimden Bu Yana 20 Yıl: Romanya Sinemasının Ortaya &Ccedil;ıkışı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SORUŞTURMA</strong></p>\r\n<p>&nbsp;Festivallerin Kısa Filmle İmtihanı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Su, Sis ve Toprak - Yeni T&uuml;rkiye Sinemasının Film İmgeleri</p>\r\n<p>&nbsp;Eleştiriye Giriş: Edebiyat-Sinema-K&uuml;lt&uuml;r</p>\r\n<p>&nbsp;Ve Sinema</p>\r\n<p>&nbsp;T&uuml;rk Sineması ve Arabesk</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_9_450x650.jpg', '2013-11-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (150, 'ay-j140', 'sekans-sinema-yazilari-seckisi-10', 'Sekans Sinema Yazıları Seçkisi 10', 'ÖNSÖZ', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/secki/SEKANS_KITAP_10_450x650.jpg" alt="SEKANS KITAP 10 450x650" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong>&Ouml;NS&Ouml;Z</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>ELEŞTİRİ</strong></p>\r\n<p>&nbsp;Tepelerin Ardında / Tepelerin Ardında G&uuml;nah Hep Vardı ... Cem Kayalıgil</p>\r\n<p>&nbsp;Onur Savaşı / \'Av\' ve \'Lin&ccedil;\' ... Ebubekir &Ccedil;etinkaya</p>\r\n<p>&nbsp;11\'e 10 Kala / Deneyim Sineması ... Azmi Recep &Ouml;zdaş</p>\r\n<p>&nbsp;G&ouml;z&uuml;m&uuml;n Nuru / Retinama Evet, Ruhuma Asla! ... G&ouml;khan Erkılı&ccedil;</p>\r\n<p>&nbsp;İnsan Yazgısının Yalın Hikayelerinden Biri: Kasaba ... Dilan İlhan</p>\r\n<p>&nbsp;Sıradan Bir Karnaval ... Halil Sanbur</p>\r\n<p>&nbsp;Atlıkarınca / ve at, karıncayı ezdi ... Dila Naz Madenoğlu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANA S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Quay Kardeşler ... s&ouml;y: Altuğ Kaan Pa&ccedil;acı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KURAM YORUM</strong></p>\r\n<p>&nbsp;Batı Doğu\'ya Bakıyor: Yasujiro Ozu\'nun Wim Wenders ve Peter Handke &Uuml;zerine Etkisi ... Kathe Geist, &ccedil;ev: Seda Usub&uuml;t&uuml;n</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KISA</strong></p>\r\n<p>&nbsp;İzd&uuml;ş&uuml;mlerinin D&uuml;nyasında Burak Ko&ccedil;ak ... s&ouml;y: Mine Tezgiden</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&Ccedil;&Ouml;Z&Uuml;MLEME</strong></p>\r\n<p>&nbsp;Her: Theo\'nun Yolu ... G&uuml;l Yaşart&uuml;rk</p>\r\n<p>&nbsp;Ayna, İlham Perisi, Medusa: Tehlikeli Deney ... Thomas Elsaesser, &ccedil;ev: Serta&ccedil; G&uuml;rel</p>\r\n<p>&nbsp;Volchok ... Hakan Karaş</p>\r\n<p>&nbsp;Sinemada Uyarlama: Albert Camus\'un Yabancı Romanıyla Zeki Demirkubuz\'un Yazgı Filminin Karşılaştırılması ... Mikail Boz</p>\r\n<p>&nbsp;</p>\r\n<p><strong>BELGESEL</strong></p>\r\n<p>&nbsp;Veysi Altay ile "Politik Kamera"sı &Uuml;zerine... \'Bir S&ouml;zl&uuml; Tarih ve Bellek &Ccedil;alışması Olarak Belgesel\' ... s&ouml;y: Nagihan Konukcu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ARKEOLOJİ</strong></p>\r\n<p>&nbsp;Sinema Alb&uuml;m&uuml; ... Ayhan Yılmaz</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANI -NOSTALJİ</strong></p>\r\n<p>&nbsp;Lev Tolstoy ... &ccedil;ev: Tansu Ayşe Timu&ccedil;in</p>\r\n<p>&nbsp;Solntseva ve Dovzhenko / &Ouml;l&uuml;m&uuml;n &Ouml;tesine Ge&ccedil;en Bir Birliktelik &Uuml;zerine ... Altuğ Kaan Pa&ccedil;acı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>DENEME</strong></p>\r\n<p>&nbsp;Rendezte Miklos Jancso ... G&ouml;khan Erkılı&ccedil;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>ANISINA</strong></p>\r\n<p>&nbsp;Bir Alain Resnais Belgeseli: Van Gogh ... Ender Bazen</p>\r\n<p>&nbsp;Jarman Requiem ... Tutku Mavi Erkılı&ccedil;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. YAŞINDA</strong></p>\r\n<p>&nbsp;Mutlak Savaş &amp; Dr. Garipaşk Ya da Bombadan Endişe Etmeyi Bırakıp Onu Sevmeyi Nasıl &Ouml;ğrendim ... İlker Mutlu</p>\r\n<p>&nbsp;</p>\r\n<p><strong>MİNİ S&Ouml;YLEŞİ</strong></p>\r\n<p>&nbsp;Marleen Gorris\'le Filmleri &Uuml;zerine ... s&ouml;y: Altuğ Kaan Pa&ccedil;acı</p>\r\n<p>&nbsp;</p>\r\n<p><strong>SİNEMA KİTAPLIĞI</strong></p>\r\n<p>&nbsp;Sanat&ccedil;ı ile Buluşma: Theo Angelopoulos ... Seda Usub&uuml;t&uuml;n</p>\r\n<p>&nbsp;Andrey Tarkovski ... Serta&ccedil; Koyuncu</p>\r\n<p>&nbsp;Kara Perde - İran Y&ouml;netmen Sineması &Uuml;zerine Okumalar ... F. Ayt&uuml;l Kaplan</p>\r\n<p>&nbsp;Dijital Film Yapımı - D&uuml;ş&uuml;k B&uuml;t&ccedil;eli Film Yapımı İ&ccedil;in Vazge&ccedil;ilmez Bir Rehber ... Serta&ccedil; Koyuncu</p>\r\n<p>&nbsp;Lacan ve &Ccedil;ağdaş Sinema ... Nuriye Bilici</p>\r\n<p>&nbsp;İsyan ve Devrim Filmleri ... Serta&ccedil; G&uuml;rel</p>\r\n<p>&nbsp;Sinema Savaşları - Bush-Cheney D&ouml;neminde Hollywood Sineması ve Siyaset ... Kadir G&uuml;len</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/secki/SEKANS_KITAP_10_450x650.jpg', '2014-07-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (151, 'ay-j142', 'sekans-sinema-kulturu-dergisi', 'Sekans Sinema Kültürü Dergisi', 'Gündem ve Haberler', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/dergi/SEKANS_1_KAPAK.jpg" alt="SEKANS 1 KAPAK" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>G&uuml;ndem ve Haberler</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Festivallerden</strong></p>\r\n<p>Rotterdam Film Festivali</p>\r\n<p>Sundance Film Festivali</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Vizyon</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Vizyon - Eleştiri</strong></p>\r\n<p>Kahraman</p>\r\n<p>Bulutları Beklerken</p>\r\n<p>G&ouml;n&uuml;l Yarası</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&ouml;yleşi</strong></p>\r\n<p>Serra Yılmaz</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kuram</strong></p>\r\n<p>Şiirsel Adalet</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kısa</strong></p>\r\n<p>Tan Tolga Demirci S&ouml;yleşisi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Belgesel</strong></p>\r\n<p>Jean Rouch</p>\r\n</td>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>Sinemanın M&uuml;ziği</strong></p>\r\n<p>Cahit Berkay S&ouml;yleşisi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Tekno - Sinema</strong></p>\r\n<p>Video Devrimi: Y&uuml;ksek &Ccedil;&ouml;z&uuml;n&uuml;rl&uuml;k</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Dosya: Sinema ve Savaş</strong></p>\r\n<p>Savaşın Sinemasının Savaşı</p>\r\n<p><span style="color: #333333;">&nbsp; İspanyol Toprağı</span></p>\r\n<p>&nbsp; Şili\'nin Savaşı</p>\r\n<p>Sinemasal Tarih: İspanya İ&ccedil; Savaşı</p>\r\n<p>Yerli Savaş</p>\r\n<p>Savaşın Tanıkları</p>\r\n<p>Savaş İ&ccedil;inde Savaş: Platoon / M&uuml;freze</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Arkeolojisi</strong></p>\r\n<p>Sinema Dergilerinden İlk S&ouml;zler</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İstatistiklerin Dili</strong></p>\r\n<p>2004\'te Salonlara Aktık!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Kitaplığı</strong></p>\r\n<p>Nasıl Bir Sinema Kitaplığı</p>\r\n<p>Film M&uuml;ziği Tarih&ccedil;e Yazılar</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/dergi/SEKANS_1_KAPAK.jpg', '2005-03-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (152, 'ay-j143', 'sekans-sinema-kulturu-dergisi-2', 'Sekans Sinema Kültürü Dergisi 2', 'Gündem ve Haberler', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/dergi/SEKANS_2_KAPAK_612x544.jpg" alt="SEKANS 2 KAPAK 612x544" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>G&uuml;ndem ve Haberler</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Festivaller</strong></p>\r\n<p>U&ccedil;an S&uuml;p&uuml;rge Kadın FF\'2005</p>\r\n<p>İstanbul FF\'2005</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Vizyon</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Vizyon - Eleştiri</strong></p>\r\n<p>D&ouml;n&uuml;ş</p>\r\n<p style="line-height: 1.71429;">Alacakaranlık Samurayı</p>\r\n<p>İ&ccedil;imdeki Deniz</p>\r\n<p>Ağlayan &Ccedil;ayır</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&ouml;yleşi</strong></p>\r\n<p>Theo Angelopoulos</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kuram - Yorum</strong></p>\r\n<p>Marker, Varda, Resnais: Sol Yaka</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kısa</strong></p>\r\n<p>Hilmi Etikan S&ouml;yleşisi</p>\r\n<p>Diyaloğun Boyutları ve Jan Svankmajer</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Belgesel</strong></p>\r\n<p>&Uuml;lkemizde Sualtı Belgeseli Tarihi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinemanın M&uuml;ziği</strong></p>\r\n<p>Erkan Oğur S&ouml;yleşisi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Tekno - Sinema</strong></p>\r\n<p>İnteraktif Sinema &Uuml;zerine İnteraktif Bir Yazı</p>\r\n</td>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>Dosya: Sinema ve Sans&uuml;r</strong></p>\r\n<p>D&uuml;nden Bug&uuml;ne Sans&uuml;r Hukuku</p>\r\n<p><span style="color: #333333;">T&uuml;rk Sineması: Sans&uuml;r&uuml;n &Ouml;yk&uuml;s&uuml;</span></p>\r\n<p>Sans&uuml;r &Uuml;zerine Bir Soruşturma</p>\r\n<p>"Sans&uuml;r Her Zaman Her Koşulda Olmalı!" Fevzi K&ouml;r&uuml;kl&uuml;: Bir Sans&uuml;r Kurulu &Uuml;yesi ile S&ouml;yleşi</p>\r\n<p>Sopa - Havu&ccedil; Diyalektiği / İran Sinemasında Sans&uuml;r ve Devlet Desteği</p>\r\n<p>Sovyetlerde Sinema ve Y&ouml;netim İlişkisi</p>\r\n<p>G&ouml;r&uuml;nmeyen Sinema</p>\r\n<p>Başı Dertten Kurtulmayanlara Adanmıştır!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Arkeolojisi</strong></p>\r\n<p>Saf Sinema Konusunda Comedia\'nın Yaptığı Anket &Uuml;zerine</p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Sinema ve Hukuk</strong></p>\r\n<p>&Ouml;zlem Abacıoğlu ile Hukuk &Uuml;zerine S&ouml;yleşi</p>\r\n<p>&nbsp;</p>\r\n<p><strong>İstatistik</strong></p>\r\n<p>&Uuml;lkeler ve Sinema Salonlarımız</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>Mini Sinema</strong></p>\r\n<p>Bağdat\'ın G&uuml;l&uuml;</p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Biyografi</strong></p>\r\n<p>Alejandro &nbsp;Amenabar</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Kitaplığı</strong></p>\r\n<p>Sinema Adına: Es Yayınları</p>\r\n<p>T&uuml;rk Sinemasında Şener Şen</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/dergi/SEKANS_2_KAPAK_612x544.jpg', '2005-05-17');
