INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (158, 'ay-j149', 'sekans-sinema-kulturu-dergisi-8', 'Sekans Sinema Kültürü Dergisi 8', 'Sekans\'tan', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/dergi/SEKANS_8_KAPAK.jpg" alt="SEKANS 8 KAPAK" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>Sekans\'tan</strong></p>\r\n<p><em>K&ouml;r Alan ve Dekadrajlar</em></p>\r\n<p>&nbsp;</p>\r\n<p><strong>G&uuml;ndem</strong></p>\r\n<p>K&uuml;lt&uuml;r Bakanlığı\'na 439 Başvuru</p>\r\n<p>&Ccedil;ok Y&ouml;netmenli Film: <em>Paris, Seni Seviyorum</em></p>\r\n<p>T&uuml;rkiye\'de Sinema Bileti Satışlarında 27.8\'lik Artış</p>\r\n<p>Bu Festivalde Hayal Kurmak Serbest</p>\r\n<p>Sinebir Kuruldu</p>\r\n<p>Filmmor\'un Kadrajında \'Namus\' Vardı</p>\r\n<p>Karadeniz\'e Film St&uuml;dyoları</p>\r\n<p>2. Uluslararası İş&ccedil;i Filmleri Festivali Yola &Ccedil;ıkmaya Hazır</p>\r\n<p><em>Ulak</em> Yola &Ccedil;ıktı</p>\r\n<p>ODT&Uuml; Psikoloji\'den S<em></em>inema Filmlerine Duyarlılık<i><br /></i></p>\r\n<p>&nbsp;"Herkesin Bir Sineması Vardı..."</p>\r\n<p>Resfest 14-23 Mart Tarihleri Arasında T&uuml;rkiye\'de</p>\r\n<p>Scorsese ve Jagger <em>Uzun &Ccedil;alar</em> İ&ccedil;in Birarada</p>\r\n<p>7. Paso &Ouml;ğrenci Filmleri Festivali</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Eleştiri</strong></p>\r\n<p>Hırsız / Breaking and Entering</p>\r\n<p>Bent Familia / Tunusiennes / A Girl From a Good Family</p>\r\n<p>Adem\'in Trenleri</p>\r\n<p>Grbavica</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Bir Film Bir Y&ouml;netmen</strong></p>\r\n<p>&Ouml;l&uuml;m ve Yaşamın Kaynağında Bir Dovjenko Filmi: Toprak /Zemlya / Earth</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kuram-Yorum</strong></p>\r\n<p>Bağımsız Bir Sanat Formu Olarak Sinema</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kısa F