INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (159, 'ay-j150', 'sekans-sinema-kulturu-dergisi-9', 'Sekans Sinema Kültürü Dergisi 9', 'Sekans\'tan', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/dergi/SEKANS_9_KAPAK_285x412.jpg" alt="SEKANS 9 KAPAK 285x412" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>Sekans\'tan</strong></p>\r\n<p><em>&nbsp;</em></p>\r\n<p><strong>G&uuml;ndem</strong></p>\r\n<p>Cannes\'da En &Ccedil;ok Polanski ve <em>Herkesin Kendi Sineması</em>&nbsp;Filmi Konuşuldu</p>\r\n<p>10. Uluslararası 1001 Belgesel Film Festivali Başlıyor</p>\r\n<p>&Ccedil;ocuk Oyunculara Denetleme</p>\r\n<p>Semih Kaplanoğlu\'ndan Bal, S&uuml;t, Yumurta &Uuml;&ccedil;lemesi</p>\r\n<p>Politik Animasyon <em>Persepolis</em> Kasım\'da G&ouml;sterimde</p>\r\n<p>IICFF K&uuml;&ccedil;&uuml;k Sinemacıları Arıyor</p>\r\n<p>Chavez Sinemaya da El Attı</p>\r\n<p>Moore\'dan Bush\'a Bir &Ccedil;alım Daha</p>\r\n<p>Karl Marx\'ın Gen&ccedil;liği Sinema Filmi Oluyor</p>\r\n<p>KozaVisual</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Eleştiri</strong></p>\r\n<p>Beethoven\'ı Anlamak / Copying Beethoven</p>\r\n<p>Kaynak / The Fountain</p>\r\n<p>Yaşamın Kıyısında / Bringing Out the Dead</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&ouml;yleşi</strong></p>\r\n<p>J&oacute;zsef Pacskovszky ile D&uuml;nden Bug&uuml;ne...</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kısa Film</strong></p>\r\n<p>Siyahlı Kadının Kokusu ve Şafak\'ın Heper\'i...</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Belgesel</strong></p>\r\n<p style="line-height: 1.71429;">&Ccedil;&uuml;nk&uuml; "Nasıl Olduğunu" Anlamak İstiyorum</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>Film M&uuml;ziği</strong></p>\r\n<p style="line-height: 1.71429;">Film M&uuml;ziğinin Altın &Ccedil;ağı 2</p>\r\n<p>&nbs