NS_9_KAPAK_285x412.jpg', '2007-08-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (160, 'ay-j151', 'sekans-sinema-kulturu-dergisi-10', 'Sekans Sinema Kültürü Dergisi 10', 'Sekans\'tan', '<div style="float: left; max-width: 450px; padding-right: 10px;"><img src="/images/dergi/SEKANS_10_KAPAK.jpg" alt="SEKANS 10 KAPAK" style="vertical-align: top;" /></div>\r\n<div>\r\n<table style="padding-right: 10px;">\r\n<tbody>\r\n<tr>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p><strong>Sekans\'tan</strong></p>\r\n<p>Yansılar: Antonioni</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Festival</strong></p>\r\n<p>Gezici Festival Yine Yollarda</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Eleştiri</strong></p>\r\n<p>On Birinci Yıl / Odinnatsatyi / The Eleventh</p>\r\n<p>Kaldırım Ser&ccedil;esi / La M&ocirc;me / La Vie En Rose</p>\r\n<p>Goya\'nın Hayaletleri / Goya\'s Ghosts</p>\r\n<p>&nbsp;</p>\r\n<p><strong>S&ouml;yleşi</strong></p>\r\n<p>Jean-Pierre Limosin</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kuram-Yorum</strong></p>\r\n<p>Ger&ccedil;eklik G&ouml;sterisi ve Belgesl Film</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Belgesel</strong></p>\r\n<p style="line-height: 1.71429;">Ger&ccedil;eğin Dramaturjisi</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>Film M&uuml;ziği</strong></p>\r\n<p style="line-height: 1.71429;">Film M&uuml;ziğinin Altın &Ccedil;ağı 3</p>\r\n<p>Chaplin Filmlerinde M&uuml;zik ve Ses</p>\r\n</td>\r\n<td style="padding-left: 10px;" valign="top" width="50%">\r\n<p style="line-height: 1.71429;"><strong>Arkeoloji</strong></p>\r\n<p style="line-height: 1.71429;">Film / Le Film</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Biyografi</strong></p>\r\n<p style="line-height: 1.71429;">Prenses Olmaya Yazgılı Bir Kadın: Grace Kelly</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>Akım</strong></p>\r\n<p style="line-height: 1.71429;">Cin&eacute;ma-V&eacute;rit&eacute;: Akan Zamanın Peşinde</p>\r\n<p>&nbsp;</p>\r\n<p><strong>50. Yaşında</strong></p>\r\n<p>Yaban &Ccedil;ilekleri / Smultronst&auml;llet</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Nostalji</strong></p>\r\n<p>Berlin: B&uuml;y&uuml;kkent Senfonisi / Berlin: Die Sinfonie der Grosstadt</p>\r\n<p>Bergman\'a Mektuplar</p>\r\n<p>&nbsp;</p>\r\n<p><strong style="color: #333333;">Deneme</strong></p>\r\n<p>Sinemanın Edebiyatla Yapacağı Bir Şey Yok!</p>\r\n<p>&nbsp;</p>\r\n<p style="line-height: 1.71429;"><strong>Anısına</strong></p>\r\n<p style="line-height: 1.71429;">Kurosawa\'nın Samurayından Uluslarası Yıldızlığa: Toshiro Mifune</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Mini S&ouml;yleşi</strong></p>\r\n<p>Walter Salles: G&ouml;r&uuml;ş&uuml;n&uuml; Kirletme!</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Sinema Kitaplığı</strong></p>\r\n<p>50 &Ccedil;ağdaş Sinemacı</p>\r\n<p>Sine-G&ouml;z</p>\r\n<p>Geceyarısı Filmleri</p>\r\n<p>Ger&ccedil;eği Arayış: Belgesel Film Yapım Sanatı</p>\r\n<p>Sinema K&ouml;şelerinde</p>\r\n<p>Vesikalı Şehir</p>\r\n<p>Story (Senaryo Yazımının &Ouml;z&uuml;, Yapısı, Tarzı ve İlkeleri)</p>\r\n<p>Kullanılmış Biletler</p>\r\n<p>Sinemada Ulusal Tavır: Halit Refiğ Kitabı</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>', 1, 65, 'Basılı Sayılar', '/images/dergi/SEKANS_10_KAPAK.jpg', '2007-12-17');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (161, 'ay-j114', 'sekans-egitim', 'Sekans Eğitim', 'Bilgi boşluğunun sinemanın gelişmesinin önündeki en büyük engel olduğuna inanmamız nedeniyle eğitim seminerleri grubumuzun hep gündeminde oldu. Sinema eğitiminde kuramın tarihle desteklenmeden, tekniğin çözümleme ve eleş', '<p>Bilgi boşluğunun sinemanın gelişmesinin önündeki en büyük engel olduğuna inanmamız nedeniyle eğitim seminerleri grubumuzun hep gündeminde oldu. Sinema eğitiminde kuramın tarihle desteklenmeden, tekniğin çözümleme ve eleştiri bilgisiyle yoğrulmadan eksik kalacağı düşüncesi hareket noktamızdı. Seminerlerimizin konu başlıkları ve içeriği dostlarımızın istekleri ve ihtiyaçlarıyla her geçen gün daha da zenginleşti.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerlerimiz Ankara\'da gerçekleştirilmekte olup içeriklerine aşağıdan ulaşabilir, devam eden ve açılacak olan eğitim programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<ul>\r\n<li style="height: 100px;"><a href="index.php?option=com_content&amp;view=article&amp;id=116:temel&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr">Temel Sinema Eğitimi Seminerleri</a> <a href="index.php?option=com_content&amp;view=article&amp;id=116:temel&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"><br /></a>\r\n<ul>\r\n<li style="margin-top: 5px;"><a href="index.php?option=com_content&amp;view=article&amp;id=116:temel&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422#Senaryo">Senaryo Yazım Teknikleri Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=116:temel&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422#Goruntu">Görüntü Tasarımı Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=116:temel&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422#Kurgu">Kurgu Semineri</a></li>\r\n</ul>\r\n</li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=117:sinema-akimlari&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr">Sinema Akımları Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422">Film Çözümlemesi Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422">Film Eleştirisi Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422">Yönetmenlerden Ülkelere Film Çözümlemeleri Semineri</a></li>\r\n<li><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422">Sinemaya Yansıyan Tarih</a></li>\r\n</ul>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (162, 'ay-j115', 'film-elestirisi-ve-film-cozumlemesi-yarismasi', 'Film Eleştirisi ve Film Çözümlemesi Yarışması', 'Sekans Sinema Grubu, 2012 yılından bu yana Sekans Film Eleştirisi Yarışması düzenlemektedir. Amacımız:', '<p>Sekans Sinema Grubu, 2012 yılından bu yana Sekans Film Eleştirisi Yarışması düzenlemektedir. Amacımız:</p>\r\n<ul>\r\n<li>Film eleştirisi alanında ürün veren amatör/ profesyonel yazarların ürünlerini değerlendirmek ve böylece film eleştirisi üretimini desteklemek ve özendirmek,</li>\r\n<li>Sinema kültürünün gelişmesine katkı ve bu alanda üretim yapan kişilere ortam sağlamak,</li>\r\n<li>Ulusal sinemanın, film eleştirisi alanında üretilen yazılar aracılığıyla daha geniş bir platformda tanınması ve tartışılmasının önünü açmaktır.</li>\r\n</ul>\r\n<p>Her yıl Ocak-Şubat aylarında ilk duyurusunu yapan ve Nisan-Mayıs aylarında ilk üç ödüle hak kazanan yazarları açıklayan yarışma sürecinde film eleştirisi alanında üretim yapan çok sayıda yazarın ulusal sinemanın örnekleri üzerine düşünmesi, yazması ve tartışma platformlarına katkı yapması sağlanmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Sekans Film Eleştirisi Yarışması, jüri üyeliği yapan sinema akademisyeni, sinema yazarı, yayıncı ve sinefiller; yarışmaya sponsor olarak destek veren yayınevleri; ve yarışmaya katılarak film eleştirisi yazınını zenginleştiren amatör/profesyonel sinema yazarlarının her yıl artan ilgi ve katkılarıyla çoğalarak yoluna devam etmektedir.</p>\r\n<p>&nbsp;</p>\r\n<p>2018 yılından itibaren yarışma iki kategori halinde düzenlenmeye başlamıştır. Yazılar film eleştirisi veya film çözümlemesi kategorilerinde değerlendirilmekte ve her iki kategorinin de dereceye giren yazıları belirlenmektedir. Bu yılın yarışma duyurusuna aşağıdaki bağlantıdan ulaşabilirsiniz:</p>\r\n<p><a href="https://www.sekans.org/index.php?option=com_content&amp;view=article&amp;id=341:yarisma-2026&amp;catid=35:duyurular&amp;Itemid=423&amp;lang=tr">Sekans Film Eleştirisi ve Film Çözümlemesi Yarışması 2026</a></p>\r\n<p>&nbsp;</p>\r\n<p>Geçen yılların Sekans Film Eleştirisi Yarışması sonuç duyuruları için <a href="https://www.sekans.org/index.php?option=com_content&amp;view=category&amp;id=35&amp;Itemid=423&amp;lang=tr">tıklayınız</a>.</p>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-23');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (163, 'ay-j116', 'temel-sinema-egitimi-seminerleri', 'Temel Sinema Eğitimi Seminerleri', 'Kısa, belgesel hatta uzun metraj film yapımını deneyimlemek isteyen ya da film yapım sürecini tüm aşamalarıyla yakından tanımak isteyenler için hazırlanmış bir eğitim semineri dizisidir. Üretim aşamalarını detaylı olarak', '<p>Kısa, belgesel hatta uzun metraj film yapımını deneyimlemek isteyen ya da film yapım sürecini tüm aşamalarıyla yakından tanımak isteyenler için hazırlanmış bir eğitim semineri dizisidir. Üretim aşamalarını detaylı olarak tartışabilmek amacıyla ve üretimin farklı branşlarına odaklanmak isteyenlerin ihtiyaçlarının farklılaşabileceği değerlendirilerek bu uzun soluklu serüven üç aşamalı olarak tasarlanmıştır:</p>\r\n<ul style="margin-bottom: 10px;">\r\n<li>Senaryo Yazım Teknikleri Semineri</li>\r\n<li>Görüntü Tasarımı Semineri</li>\r\n<li>Kurgu Semineri</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>Temel Sinema Eğitimi Seminerleri Ankara\'da gerçekleştirilmekte olup toplam süresi 12 aydır.</p>\r\n<p>&nbsp;</p>\r\n<h3 style="font-size: 20pt; color: #8e2671;">Senaryo Yazım Teknikleri Semineri <a id="Senaryo"></a></h3>\r\n<p>Temel Sinema Eğitimi seminerimizin ilk ayağı olan Senaryo Yazım Teknikleri Semineri uygulamalı olarak gerçekleştirilmektedir. Sinema için nitelikli senaryo üretiminin ipuçlarına odaklanan seminerimizin içeriği, hem yazım tekniklerini öğrenmek isteyenler hem de senaryo uygulamalarına odaklanmak isteyenler için verim sağlayacak şekilde kurgulanmıştır.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerimizin alt konu başlıkları şunlardır:</p>\r\n<ul style="margin-bottom: 10px;">\r\n<li>Senaryo: Tanım ve Gelişim Evreleri</li>\r\n<li>Klasik Anlatıda Gelişim Çizgisi</li>\r\n<li>Senaryoda Dramaturjik Unsurlar</li>\r\n<li>Senaryoda Kavram Analizleri</li>\r\n<li>Diyalog</li>\r\n<li>Senaryo Kusurları</li>\r\n<li>Senaryo Türleri</li>\r\n<li>Tür ve Yöntemler Üzerine Uygulamalar</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>Senaryo Yazım Teknikleri Semineri\'nin süresi 4 aydır.</p>\r\n<p>&nbsp;</p>\r\n<h3 style="font-size: 20pt; color: #8e2671;">Görüntü Tasarımı Semineri <a id="Goruntu"></a></h3>\r\n<p>Senaryo Yazım Teknikleri Seminerimizi, Görüntü Tasarımı Semineri izlemektedir. Görüntü öğelerinin temelini oluşturan kamera, kamera açıları ve hareketleri, çekim ölçekleri, aydınlatma, sanat yönetimi, ses gibi teknik unsurlar ve temel kavramlar üzerinde detaylı olarak durulmaktadır. Bunların yanı sıra, anlatının gücünü belirlediğine inandığımız biçim-içerik ilişkisi her teknik unsur için ayrıntılı bir şekilde tartışılmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Görüntü Tasarımı Semineri’nin süresi 4 aydır.</p>\r\n<p>&nbsp;</p>\r\n<h3 style="font-size: 20pt; color: #8e2671;">Kurgu Semineri <a id="Kurgu"></a></h3>\r\n<p>Temel Sinema Eğitimi seminerimizin son aşaması dijital tabanlı kurgu semineridir. Bu aşamada kurgu programlarındaki işlemler, kurgu ilkeleri, uygulamalar ve yarattıkları anlam üzerinde durulmaktadır. Kurgu işlemlerinin ağırlıklı olarak kullanılanları bir kurgu programı üzerinde uygulamalı olarak gösterilmektedir.</p>\r\n<p>&nbsp;</p>\r\n<p>Kurgu Semineri’nin süresi 4 aydır.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (164, 'ay-j117', 'sinema-akimlari-semineri', 'Sinema Akımları Semineri', 'Sinema akımlarının kronolojik sıraya göre tanıtılıp incelendiği ve akımın sürükleyicisi olan tarihsel atmosferi, sinema kuramcılarını, yönetmenleri ve akımın temel unsurlarını barındıran filmleri mercek altına alan bu se', '<p>Sinema akımlarının kronolojik sıraya göre tanıtılıp incelendiği ve akımın sürükleyicisi olan tarihsel atmosferi, sinema kuramcılarını, yönetmenleri ve akımın temel unsurlarını barındıran filmleri mercek altına alan bu seminer, dünya sinemasının tematik, anlatı dili ve biçim açısından gelişim evrelerinin akımlar yoluyla anlatılmasını hedefliyor. Seminer farklı sanat dallarına ait akımların sinema üzerindeki etkisiyle ortaya çıkan sinema akımlarıyla başlamakta, sinemaya özgü akımlarla sürmekte ve üçüncü dünya ülkesi sinemalarına uzanarak sona ermektedir. Sinemanın yüz yılı aşan serüvenini bu pencereden izleme imkanı sunan seminerde her bir akım, tarihsel süreç içerisindeki gelişim çizgisi ve öneminin incelenmesinin yanı sıra öne çıkan filmleri üzerine tartışılıp analiz edilerek ele alınmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerde ele aldığımız akımlardan bazıları şu şekilde sıralanabilir:</p>\r\n<p>&nbsp;</p>\r\n<div style="text-align: center;">\r\n<table border="0" style="width: 620px; height: 125px; border-collapse: collapse;" cellspacing="0" cellpadding="0" align="center">\r\n<tbody>\r\n<tr>\r\n<td>Fütürizm</td>\r\n<td>Sovyet Devrim Sineması</td>\r\n<td>İngiliz Yeni Dalga</td>\r\n<td>Cinema-Verite</td>\r\n</tr>\r\n<tr>\r\n<td>Empresyonizm</td>\r\n<td>İngiliz Belgesel Ekolü</td>\r\n<td>Fransız Yeni Dalga</td>\r\n<td>Cinema Novo</td>\r\n</tr>\r\n<tr>\r\n<td>Ekspresyonizm</td>\r\n<td>Şiirsel Gerçekçilik</td>\r\n<td>New York Okulu</td>\r\n<td>Çek Yeni Dalga</td>\r\n</tr>\r\n<tr>\r\n<td>Avantgarde</td>\r\n<td>Yeni Gerçekçilik</td>\r\n<td>Underground Cinema</td>\r\n<td>Yeni Alman Sineması</td>\r\n</tr>\r\n<tr>\r\n<td>Sürrealizm</td>\r\n<td>Free-Cinema</td>\r\n<td>Direct-Cinema</td>\r\n<td>Cinema Cedid</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p>Sinema Akımları Semineri Ankara\'da gerçekleştirilmekte olup süresi 9 aydır.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (165, 'ay-j118', 'film-cozumlemesi-semineri', 'Film Çözümlemesi Semineri', 'Sinemanın gücü ancak filmlerin taşıdığı anlam açığa çıkarıldığında anlaşılabilir. Çözümleme bilgisi, film okumalarında belli tekniklerin kullanılması alışkanlığını yerleştireceği gibi, film eleştirisine geçişte de önemli', '<p>Sinemanın gücü ancak filmlerin taşıdığı anlam açığa çıkarıldığında anlaşılabilir. Çözümleme bilgisi, film okumalarında belli tekniklerin kullanılması alışkanlığını yerleştireceği gibi, film eleştirisine geçişte de önemli bir altyapının kurulmasını sağlar.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminerde, film çözümlemesinde kullanılan gelenekçi ve modernist yaklaşımlar örneklerle aktarılmaktadır. Anlatı çözümlemesi türleri ile film çözümlemesinde odaklanılan anlatısal ve sinemasal öğeler üzerinde durulmaktadır. Her çözümleme modeli için örnek filmlerin çözümlemesi yapılmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer Ankarara\'da gerçekleştirilmektedir. Süresi 5 ay olup toplam 20 oturumdan oluşmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (166, 'ay-j119', 'film-elestirisi-semineri', 'Film Eleştirisi Semineri', 'Hakkında en çok konuşulan ama en az bilinen alanlardan biridir eleştiri. Oysa eleştiri bireysel yaratıcılığa yaslandığı kadar teknik bir altyapıya da dayanır. Seminerimiz, dileyenin salt eleştiri tekniklerini öğrenmek iç', '<p>Hakkında en çok konuşulan ama en az bilinen alanlardan biridir eleştiri. Oysa eleştiri bireysel yaratıcılığa yaslandığı kadar teknik bir altyapıya da dayanır. Seminerimiz, dileyenin salt eleştiri tekniklerini öğrenmek için, dileyenin de eleştiri alanında atölye tarzı üretim gerçekleştirmek için katılabileceği bir yapıda olup, dünden bugüne bütün eleştiri türlerine yer vermekte, uygulamalarını gerçekleştirmekte ve örnek çalışmalar sunmaktadır. Programda sosyolojik, psikanalitik, tarihsel, tür, ideolojik, feminist, göstergebilimsel ve queer eleştiri tanıtılmaktadır. Seminerin son haftasında, alınan bilgiler ışığında birlikte izlenen film üzerine eleştiri uygulamaları yapılmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Herkesin film eleştirisi ve tür filmi eleştirisi hakkında temel teorik bilgileri edinmesiyle başlayıp farklı türlerde yazacağı eleştirilerin ardından kendi eleştiri modelini geliştireceği film eleştirisi seminerimizin konu başlıkları şunlar:</p>\r\n<ul>\r\n<li>Film eleştirisi nedir?</li>\r\n<li>Film eleştirmeni kimdir?</li>\r\n<li>Yorum ve eleştiri</li>\r\n<li>Sosyolojik eleştiri</li>\r\n<li>Queer eleştiri</li>\r\n<li>Göstergebilimsel eleştiri</li>\r\n<li>Tarihsel eleştiri</li>\r\n<li>İdeolojik eleştiri</li>\r\n<li>Psikanalitik eleştiri</li>\r\n<li>Feminist eleştiri</li>\r\n<li>Türler ve eleştiri</li>\r\n<li>Bir film eleştirisi modeli</li>\r\n</ul>\r\n<p>Seminer Ankara\'da gerçekleştirilmektedir. Süresi 4 ay olup toplam 16 oturumdan oluşmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (167, 'ay-j120', 'yonetmenlerden-ulkelere-film-cozumlemeleri-semineri', 'Yönetmenlerden Ülkelere Film Çözümlemeleri Semineri', 'Film eleştirisi ve/veya film çözümlemesi seminerlerimizi bitirmiş dostlara açık olan seminerimizde auteur yönetmen filmografilerinden ve kıyıda köşede kalmış ulusal sinema örnekleri içinden seçtiğimiz filmleri, coğrafya ', '<p>Film eleştirisi ve/veya film çözümlemesi seminerlerimizi bitirmiş dostlara açık olan seminerimizde auteur yönetmen filmografilerinden ve kıyıda köşede kalmış ulusal sinema örnekleri içinden seçtiğimiz filmleri, coğrafya coğrafya gezerek ve çeşitli film çözümleme teknikleri kullanarak birlikte analiz ediyoruz. Seminerimiz katılımcılarına her hafta bir film üzerinden yeni sinemalara yelken açmanın yanı sıra, çözümleme ve eleştiri serüveninde kapsamlı tartışmalar, karşılıklı etkileşim, birlikte deneyimleme, derinleşme ve doyasıya sinema paylaşmayı vadetmektedir.</p>\r\n<p>&nbsp;</p>\r\n<p>Seminer Ankara\'da gerçekleştirilmektedir. Süresi sonsuz olup, duruma göre hareket edilmektedir.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (168, 'ay-j121', 'sinemaya-yansiyan-tarih', 'Sinemaya Yansıyan Tarih', 'Tarih bilgisini sinema, sinema bilgisini tarih üzerinden geliştirmek ve eleştirel bir yaklaşımla film analizlerine katılmak isteyenler için hazırlanan bu seminer programı, genel bir çerçeve ile tarih ve sinema alanlarını', '<p>Tarih bilgisini sinema, sinema bilgisini tarih üzerinden geliştirmek ve eleştirel bir yaklaşımla film analizlerine katılmak isteyenler için hazırlanan bu seminer programı, genel bir çerçeve ile tarih ve sinema alanlarının karşılıklı etkileşimleri üzerine odaklanmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Sinema, başlangıcından bugüne yalnız tarihin bütün alt başlıklarıyla ilgilenmekle kalmamış, kendi tarihine dönük yapıtlar da vermiştir. Bu seminer programında politika, cinsellik, sosyoloji, din, sanat ve ekonomi gibi ön adlar alarak alt uzmanlık alanları oluşturmuş tarihin sinemadaki yansımaları işlenmektedir. Bir başka açıdan bakılacak olursa, tarih gibi dev bir bilgi alanının filmler aracılığıyla analizi yapılmaktadır. Seminer, katılacak olanların içerik ve film seçimleri konusunda yönlendirmelerine olanak tanıdığı için interaktif bir yapı taşımakta, seçilen konu başlıklarına uyan ve üzerinde çözümleme yapılabilecek sekiz film seçilmektedir. Toplam 12 oturumdan oluşan programın, katılımcıların istemleri doğrultusunda biçimlenen başlıkları şu şekilde sıralanabilir:</p>\r\n<p>&nbsp;</p>\r\n<div>\r\n<table border="0" style="height: 125px;" cellspacing="0" cellpadding="0" align="center">\r\n<tbody>\r\n<tr>\r\n<td style="width: 109px;" valign="top">Politika</td>\r\n<td style="width: 109px;" valign="top">Kadın</td>\r\n<td style="width: 109px;" valign="top">İnsan Hakları</td>\r\n<td style="width: 109px;" valign="top">Göç</td>\r\n<td style="width: 109px;" valign="top">Sınıf</td>\r\n</tr>\r\n<tr>\r\n<td style="width: 109px;" valign="top">Kültür</td>\r\n<td style="width: 109px;" valign="top">Savaş</td>\r\n<td style="width: 109px;" valign="top">Nasyonalizm</td>\r\n<td style="width: 109px;" valign="top">Özgürlük</td>\r\n<td style="width: 109px;" valign="top">Çocuk</td>\r\n</tr>\r\n<tr>\r\n<td style="width: 109px;" valign="top">Azınlık</td>\r\n<td style="width: 109px;" valign="top">Cinsiyet</td>\r\n<td style="width: 109px;" valign="top">İş-İşçi</td>\r\n<td style="width: 109px;" valign="top">Ekonomi</td>\r\n<td style="width: 109px;" valign="top">Medya</td>\r\n</tr>\r\n<tr>\r\n<td style="width: 109px;" valign="top">Globalizm</td>\r\n<td style="width: 109px;" valign="top">Din</td>\r\n<td style="width: 109px;" valign="top">Kent</td>\r\n<td style="width: 109px;" valign="top">Yargı</td>\r\n<td style="width: 109px;" valign="top">Toplum</td>\r\n</tr>\r\n<tr>\r\n<td style="width: 109px;" valign="top">Eğitim</td>\r\n<td style="width: 109px;" valign="top">Şiddet</td>\r\n<td style="width: 109px;" valign="top">Etnik</td>\r\n<td style="width: 109px;" valign="top">Terör</td>\r\n<td style="width: 109px;" valign="top">&nbsp;</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p>Sinemaya Yansıyan Tarih Semineri Ankara\'da gerçekleştirilmektedir. Süresi 3 ay olup toplam 12 oturumdan oluşmaktadır.</p>\r\n<p>&nbsp;</p>\r\n<p>Eğitim seminerimiz ve programımızla ilgili detaylı bilgi için <a href="mailto:info@sekans.org">info@sekans.org</a> adresine mesaj atabilirsiniz.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table align="center">\r\n<tbody>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=116&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px;">Temel Sinema Eğitimi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=117&amp;catid=33&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Sinema Akımları</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=118:film-cozumleme&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px;">Film Çözümlemesi</button> </a></td>\r\n</tr>\r\n<tr>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=119:film-elestiri&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-top: 30px;">Film Eleştirisi</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=120:yonetmen-ulke&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Yönetmenler Ülkeler</button> </a></td>\r\n<td><a href="index.php?option=com_content&amp;view=article&amp;id=121:sinema-tarih&amp;catid=33:sekans-egitim&amp;lang=tr-TR&amp;Itemid=422" hreflang="tr"> <button type="button" style="width: 120px; height: 60px; margin-left: 30px; margin-top: 30px;">Sinemaya Yansıyan Tarih</button> </a></td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (169, 'ay-j122', 'sekans-sinema-grubu', 'Sekans Sinema Grubu', 'Sinemanın yaşamında önemli bir rol oynadığını düşünen, onu bir yaşam biçimi olarak gören bireylerin Ankara\'da kurduğu Sekans Sinema Grubu, tüketim toplumunun sinemayı bir eğlence aracı konumuna ve ticari bir ürüne indirg', '<p style="text-align: justify;">Sinemanın yaşamında önemli bir rol oynadığını düşünen, onu bir yaşam biçimi olarak gören bireylerin Ankara\'da kurduğu <strong>Sekans Sinema Grubu</strong>, tüketim toplumunun sinemayı bir eğlence aracı konumuna ve ticari bir ürüne indirgeyen anlayışına rağmen, sinemanın bir sanat, görsel bir dil ve kültürel bir veri bankası olduğu inancıyla yola çıktı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Sinemanın varsıllaşamamasındaki en büyük engelin eğitim ve bilgi boşluğu olduğuna inanmamız sebebiyle grubumuzun öncelikli çalışma alanı eğitim seminerleri oldu. Bunu film gösterimleri, paneller, söyleşiler, arşiv çalışması, kısa ve belgesel film prodüksiyonları ve son olarak film eleştirisi yarışmaları izledi.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Tüm bu etkinliklere paralel olarak sinema kültürünü yaymayı ve paylaşmayı amaçlayan dergimiz Sekans’ı 15 yılı aşkın süredir Ankara\'dan yayımlıyoruz. 2005 yılında yayımlanmaya başlayan <em><strong>Sekans Sinema Kültürü Dergisi</strong></em>’nin bayrağını 2009 yılında <em><strong>Sekans Sinema Yazıları Seçkisi</strong></em> devraldı. Grubumuz yayımladığı 20 sayının ardından 2016’da Sekans Sinema Kültürü Dergisi’nin yoluna bu defa elektronik dergi olarak devam etmesi kararını aldı.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Yapım, yayıncılık, yayımcılık, arşiv ve organizasyon alanındaki çeşitli çalışmalarla sinema kültürünün gelişip güçlenmesini sağlamak, sinemaseverlerin ve sinema üzerine üretimi amaçlayanların sosyal ve kültürel gereksinimlerini karşılamak ve aslen sinema keyfini paylaşmak grubumuzun başlıca amacı olmaya devam ediyor… Düşüncesi, birikimi ve emeğiyle aramıza katılan yeni dostlarla birlikte yol almayı sürdürüyoruz.</p>', 1, 66, 'Sekans Sinema Grubu', NULL, '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (170, 'ay-j234', 'a-brief-interview-with-miguel-llanso', 'A Brief Interview with Miguel Llanso', 'A Brief Interview with Miguel Llanso at IFFR 2015', '<p style="text-align: center;"><strong>A Brief Interview with Miguel Llanso at IFFR 2015</strong></p>\r\n<p style="text-align: right;"><a href="/docs/archive/Interview_Miguel_Llanso_IIFR2015.pdf" target="_blank">PDF</a></p>\r\n<p style="color: #000000; font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 12px; text-align: center;">&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;">We made a brief interview with <strong>Miguel Llanso</strong> about the journey of his “post-apocalyptic surrealist science fiction romance” film&nbsp;<em><strong>Crumbs</strong></em>, soon after its world premiere at the International Film Festival Rotterdam (IFFR) 2015. Here is the trailer:</p>\r\n<div align="middle">\r\n<p>&nbsp;</p>\r\n<div style="padding: 41.72% 0 0 0; position: relative;"><iframe src="https://player.vimeo.com/video/116239059?h=cc42bbd57e" width="560" height="315" style="position: absolute; top: 0; left: 0; width: 100%; height: 100%;" allowfullscreen="allowfullscreen" allow="autoplay; fullscreen; picture-in-picture" frameborder="0"></iframe></div>\r\n<p>&nbsp;</p>\r\n</div>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;">You can find the cast, crew and other info about the film at that&nbsp;<a href="https://iffr.com/en/iffr/2015/films/crumbs" style="color: #895f37;">link</a>.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><b>Altuğ Kaan Paçacı:&nbsp;</b>You made a movie in a country which produces limited films per year; you are not only using the location as a setting but also working with the local people -from inside and outside of the industry-. On the other hand, it made me feel that this film could be produced somewhere else which has similar geographical formations. How was the movie changed with the different cultural exchanges?</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong>Miguel Llanso:</strong>&nbsp;I think every film expresses a landscape, a moment of life, a circumstance and therefore the locations are not interchangeable. Can you imagine&nbsp;<strong>Herzog</strong>&nbsp;shooting&nbsp;<em><strong>Fitzcarraldo</strong></em>&nbsp;inside a Hollywood studio? The film is primarily a reflection of life experience. So,&nbsp;<em><strong>Crumbs</strong></em>&nbsp;had to be filmed in Ethiopia with actor&nbsp;<strong>Daniel Tadesse</strong>, with whom I started to collaborate some time ago. It had to be shot with producers&nbsp;<strong>Yohannes Feleke</strong>,&nbsp;<strong>Meseret Argaw</strong>&nbsp;and&nbsp;<strong>Daniel Taye</strong>&nbsp;<strong>Workou</strong>, soundman&nbsp;<strong>Quino Piñero</strong>&nbsp;and cinematographer&nbsp;<strong>Israel Seoane</strong>. And I was thinking about Atomizador making the music, from the very beginning. It doesn’t mean to experience a cultural exchange with a homogeneous unit that represents the other -"Ethiopia", but living with a group of people. And one by one these people represent a "culture". And that moment is unique. It’s not written in any screenplay, nor contained in any previous idea.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;"><img src="/images/interviews/Crumbs_resim6_660x371.jpg" alt="Crumbs resim6 660x371" width="660" height="371" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;"><strong>&nbsp;</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><b>Altuğ</b>:&nbsp;</strong>In your future imagination, being a good boy/girl is not enough for taking presents from Santa, you should firstly encounter bureaucratic obstacles. What kind of obstacles does a young director encounter, who wants to create his own language? For example, between which funds did you run around?</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong>Miguel</strong>:</strong>&nbsp;Let’s talk about protocol and habit. Last night I was watching&nbsp;<em><strong>The Gospel According to St. Matthew</strong></em>&nbsp;by&nbsp;<strong>Pasolini</strong>&nbsp;and thought about something that may answer this question. I’m an atheist, and miracles and life of Jesus don’t seem very fascinating to me. They are ok. There is something much deeper in the film which is the relationship between Jesus and Mary.&nbsp;<strong>Pasolini</strong>&nbsp;chose his own mother for this role. A mother who has to accept the freedom of his son, his destiny, his adventures, despite the danger and uncertainty. The hero is not Jesus but the victory of humans when they mutually accept each other. So, after Maria cries when Jesus dies on the cross, after the duel comes acceptance in the face of Mary: "He lived as he wanted" and then Jesus resurrects.&nbsp;<strong>Pasolini</strong>&nbsp;died in a similar way. No one wants to die. Dying sucks. The most difficult thing for a young filmmaker is finding the balance between destiny and coexistence, creativity and survival. You have to be aware of not harming anyone in your way. Obstacles? When the Spanish public funds dismissed&nbsp;<em><strong>Crumbs</strong></em>, my childhood friend and executive producer&nbsp;<strong>Sergio Uguet de Resayre</strong>&nbsp;puts his own money in this venture. Two crazies driving.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;">&nbsp;&nbsp;<img src="/images/interviews/Crumbs4-660x275.png" alt="Crumbs4-660x275" width="660" height="275" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong><b>Altuğ</b></strong>:&nbsp;</strong>With practicing on different genre codes, you also trying to make your own audio-visual language. Long since, festivals have been a shelter for unconventional filmmakers. What do you think about IFFR’s support to new and unusual directors? What kind of impression did you and your crew have during the festival?</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong>Miguel</strong>:</strong>&nbsp;IFFR is a small island, a garden within a rotten world that looks for profit and speculation in the artwork. At the festival gather all kinds of artists, recognized or lonely spirits. This is a miracle nowadays and I’m surprised that the neo-liberalist minds have not put yet the spotlight at the festival to blow it.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;">&nbsp;<img src="/images/interviews/Crumbs_resim5_660x371.jpg" alt="Crumbs resim5 660x371" width="660" height="371" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong><b>Altuğ</b></strong>:&nbsp;</strong>Nowadays one of the popular topics is, in comparison to major festivals’ -like Cannes, Berlin, Venice and Sundance- marketing power, the others have become weaker. Your film made its world premiere in IFFR. How did you draw your festival route to eliminate distribution problems?</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong>Miguel</strong>:</strong>&nbsp;IFFR still brings together key stakeholders of the film industry thanks to its market “Cinemart”. It has allowed us to find sales agents like "New Europe Film Sales" and US distributor "Indiepix". We’re working with them to distribute the film worldwide. It is a very difficult job. It’s a very competitive sector with thousands of film being produced every year and there’s certain stress to recover the huge investment of money and labor. Your film can be seen by a lot of people worldwide and even so you can continue living just above the poverty line and very worried.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong><b>Altuğ</b></strong>:&nbsp;</strong>Even though many directors have trouble with entering competitions, they are also aware of winning awards means more audience and it helps them for making the following one. In&nbsp;<em><strong>Crumbs</strong></em>, we watched popular culture images become religious symbols. Today’s award statues may become tomorrow’s religious symbols, what do you think?</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong>Miguel</strong>:</strong>&nbsp;People have plastic Oscars statues above the refrigerator. My grandmother used to have a mosaic of the Virgin of Guadalupe. Let everyone draw their own conclusions.</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt; text-align: justify;"><strong><strong><b>Altuğ</b></strong>:&nbsp;</strong>Thank you for your time. All the best Miguel!</p>\r\n<p>&nbsp;</p>\r\n<p style="color: #000000; font-family: arial, helvetica, sans-serif; font-size: 10pt;"><img src="/images/interviews/AKP_ML_resim4_495x371.jpg" alt="AKP ML resim4 495x371" width="495" height="371" style="display: block; margin-right: auto; margin-left: auto;" /></p>', 2, 67, 'Arşiv Yazıları', '/images/interviews/Crumbs_resim6_660x371.jpg', '2016-02-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (171, 'ay-j235', 'an-interview-michael-glawogger', 'An Interview: Michael Glawogger', 'PDF', '<p><a href="/docs/archive/Interview_with_Glawogger.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: right;"><strong>GÖKHAN ERKILIÇ</strong><br /><strong>SEKANS Sinema Yazıları Seçkisi 3 (December 2010, p. 90-99)</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>1) It can be told that you proceed on a route from experimental to shorts, from shorts to documentaries and from documentaries to feature films. Which of those is playing greater role on the decision mechanism of that route: living conditions, technologic resources, economical conditions, creative process?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Probably a bit of all those reasons but I was lucky enough to move along with my creative process more than anything else. I was never forced to work for television for economical reasons for example. But I considered it always important to move on. When I found a comfortable field or genre in filmmaking, I wanted to experiment in something new. I like contrast. I like a black and white image next to a picture in colors and I like to invent a story after I dealt with reality and its representation in film for month and years on end. At the moment I am writing songs for a musical about a Poodle beauty contest and next I might do a film that has no theme at all.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>2) Do you observe typical changes in documental cinema during these initiative years of the new millennium we’re in?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">To be honest, I do not observe documentary cinema that much. I am not very interested in anything in connection to reportage or the straight forward documentary. So, I only watch films of this genre if I can expect a boarder approach than just a theme. For the last few years I have been caught up very much in my own work so I cannot answer questions in terms of film history or tendencies in genres. Actually, I also do think this is more the job of a&nbsp; film critic or a film historian. I always found films and filmmakers who are close to me and my way of thinking though but those were always people who overstep genres, who see filmmaking as an art, who do essayistic work or work that is related to fine art more than journalism.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>3) Could you tell us the documentaries and the directors that framed your documental cinema style and influenced yourself?</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Dziga Vertov</strong> was always important for me because he mixed his political approach with a truly poetical style (the same is true for <strong>George Franju</strong>), works of Werner Herzog, especially <em><strong>Fata Morgana</strong></em> but then again I am always influenced by experimental filmmakers like <strong>Stan Brakhage</strong> or <strong>Peter Kubelka</strong> but mostly by painters like<strong> Hironymus Bosch</strong> or <strong>Vermeer</strong>. Painters are much more influential for me in terms of style and atristic approach than other filmmakers.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>4) Let’s start with Kino im Kopf. If you would shoot this documentary nowadays, which changes would be done by you in the triangle of pleasure-idea-style? There are people thinking this movie was reflecting the hints of your conception of cinema. What is your opinion?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>That might be true. It was interesting to find oneself in the conception of other peoples minds. And I was interested in the concept of multiplying stories. Like for example in the novel The Manuscript Found in Saragossa by Jan Potocki, who told a story where someone tells a story within that story and within that story again someone tells a story and so on and so on. From the middle part of the book all those stories are being closed again like boxes that someone opened. I like open systems, stories, images and sound that lead to something else that trigger new stories and thought and things that are unfinished. Like painting where part of the canvas stays empty and other parts a carefully crafted. Kino im Kopf was en early attempt to work with such kind of an open system. Stories that are not finished thought that lead you somewhere else and just easily tossed little episodes that are trashy, fun and artistic at the same time. It is more an exercise in storytelling than anything else though.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>5) Megacities: It is understood that the emotion belonging to cinema’s infentility period hasn’t died yet in India. Have you just focused on these four cities during the development phase of the movie? Your movie makes anyone think that for some part of the would to fantasize was a pathologic phenomenon.</strong></p>\r\n<p>I don’t know if I really understand what you are getting at but in terms of focus – no I haven’t only researched in these cities. I was also interested in Lagos, Cairo and Sao Paulo but in the end I ended up where I ended up. I t is quite long ago but I remember it as an innocent process that was mainly driven by curiosity. I did not have a theme other than big cities. So I could film anywhere and whatever I wanted. That is a kind of freedom that is scary and uplifting at the same time. I miss this approach nowadays, being often tortured by theme and approach and other stumbling blocks on the way to a good film. So I often think how it was doing Megacities.I give you an example of a movie that I am planning at the moment it is called “Untitled”. I will give you opening statement of the concept for the movie. It leads back to Megacties and opens up new paths for the future.</p>\r\n<p>&nbsp;</p>\r\n<p><em>Five Ws and one H</em></p>\r\n<p>&nbsp;</p>\r\n<p>In journalism there are six basic questions to be answered before a story can be considered “watertight.” Who was involved? What happened? Where did it take place? When did it take place? Why did it happen? And how did it happen?</p>\r\n<p>&nbsp;</p>\r\n<p>Documentary filmmaking often takes the same approach. A new film project usually starts with questions like these: What is the story? Where does it take place? Who is in it? Why do you want to make it? And how are you going to structure it?</p>\r\n<p>&nbsp;</p>\r\n<p>I want to reduce these basic questions to the concepts of “theme” and “perspective.” They can act in a friendly manner, providing the filmmaker with a framework within which to construct his film. They can, however, also twist your perspective of what is happening around you and reduce the actual events to a pre-formulated thesis. If this is the case, they demonstrate not only unfriendly behavior but even animosity.</p>\r\n<p>&nbsp;</p>\r\n<p>On trips I have taken to do research or shoot films I have repeatedly encountered instances or situations which I perceived as special but was not able to actually shoot. At the time I was always caught up in another subject that demanded my full concentration. I have always seen this as a hindrance. To a true storyteller the whole world is a potential story, and he draws from the things he encounters and tells what he considers worth relating.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>6) Nacktschnecken: A study on the effects of dialect and accent on a film genre, that was challenging in terms of thse effects’ positives and negatives. Do you see comedy as one of the present favorite areas of the potential conflict between the social classes? Is comedy protecting its character calling for us to take the reality hiding behind it serious?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Comedy is comedy is comedy. Who uses it and to what purpose is a different thing. If one uses comedy to describe the “potential conflict between the social classes” as you say, she or he can do so. But comedy is a genre and it can be used to describe the subordination of kangaroo babies under the rule of alligators on Mars. I don’t know if that might be such a good film but it could be funny. Although you are right, the reality behind a comedy is often what really does make it funny. “Slugs” was such a thing; it was invented by an actor and long term student at the time, who really lived what he was writing about. So the reality factor and the dialect factor behind it were strong. And that was what I liked about the project at the time. At the moment we are working on the third part of the Sex and drugs and rock and roll trilogy and we are experimenting on less realistic grounds. I do think a lot to use talking penguins. The casting has begun.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>7) Slumming: A poet had found place for himself on account of you. What can be a poet’s mission on the age we are living? (in the middle of economical, political and social injustice and decayedness)? Even though the material which would be processed by poet is much, isn’t a mass feding with poems is needed? Can your movie be read as a story of loneliness?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Yes it can be read like that. It can also be read as a movie that says, loneliness can be a creative and wonderful thing. Like a lot of things that happen to you can turn into the opposite of what you might think they are. This is the story of a bad deed that turns into something good for the person it was done to. The protagonist of Slumming is refined because two young men played a prank on him. Through that he is thrown back upon himself. I always ask myself what a war would have done to me, or what kind of a person I would be if I had spent five years in prison. I would think differently, maybe I would appreciate live differently. And the notion of being alien somewhere. I always like it, if I am in a country where I know nobody and I don’t speak the language that throws me back upon myself. It an hostile and peaceful state at the same time.</p>\r\n<p>&nbsp;</p>\r\n<p>And poetry is a quite lonely art. It always was. As was the world a place of economical, political and social injustice. That is definitely not new of the 21st century.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>8) Das Vaterspiel: Which were the actions that played effective role on your view of cinema and art? Is the past a thruster and substantial force? What kind of a role the city you born, the environment you growed up, the climate you lived, the environment you produce in and the cultural world surrounding you played and continue to play on your creative character?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>I come from the second largest city in Austria. During my days of gymnasium the cultural situation in my town was not bad, maybe with the exception of cinema. I became member of a club that specialized in screening movies, for example in movie theatres after the late show or in auditoriums of the local university. At that time I was a junkie for films. I would watch anything I could get a hold of and that was before VHS or DVD. So I literary spent my years of adolescents in the darkness of screening rooms or movie theatres. I would watch a minimum of 3 movies a day. So that became my substantial force. I began dreaming to do movies of my own. My doing “Kill daddy good night” had nothing much to do with that but with the social and political environment of that time. But since it is based on the novel “Das Vaterspiel” by Josef Haslinger it is still somewhat of a second hand experience. The moral and political downfall of the political elite in Austria was something that I did not experience first hand but something I could feel in the over all climate of Austrian live. When I read the novel, I thought – okay, that could have been my youth too, a little later, in another city, in another social environment. It felt close and far away at the same time. But that kind of thinking was already very close to me since I had done Slumming.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>9) Contact High: During shooting this movie, have the will to entertain the people predominated or have you wanted to do something to entertain yourself? Especially during watching the movies in which comedy items became heavy, we can’t do without thinking them to be shot for being as a psychologic balancer.</strong></p>\r\n<p>&nbsp;</p>\r\n<p>There is the conscientiously stress created by your documentaries on one scale of a balance against the relaxation feeling created by your feature films on the other scaleTerazinin bir kefesindeki belgesel filmlerinizin yarattığı vicdani gerilime karşı öteki kefede konulu filmlerinizin yarattığı bir rahatlama duygusu var.</p>\r\n<p>&nbsp;</p>\r\n<p>I never do anything to just entertain myself but of course I do have to be entertained too. Actually it is a good sign if your own work does entertain yourself. But Contact High is quite a mixture of something playful, with something philosophical with something ironic and mix the whole thing with some LSD and some songs and there it is.</p>\r\n<p>&nbsp;</p>\r\n<p>In my youth we used to listen to a song by Jefferson Airplane called White Rabbit. The lyrics of this song are like a plot description of Contact High:</p>\r\n<p>&nbsp;</p>\r\n<p>One pill makes you larger<br />And one pill makes you small<br />And the ones that mother gives you<br />Don\'t do anything at all<br />Go ask Alice<br />When she\'s ten feet tall</p>\r\n<p>&nbsp;</p>\r\n<p>And if you go chasing rabbits<br />And you know you\'re going to fall<br />Tell \'em a hookah smoking caterpillar<br />Has given you the call<br />Call Alice<br />When she was just small</p>\r\n<p>&nbsp;</p>\r\n<p>When men on the chessboard<br />Get up and tell you where to go<br />And you\'ve just had some kind of mushroom<br />And your mind is moving low<br />Go ask Alice<br />I think she\'ll know</p>\r\n<p>&nbsp;</p>\r\n<p>When logic and proportion<br />Have fallen sloppy dead<br />And the White Knight is talking backwards<br />And the Red Queen\'s "off with her head!"<br />Remember what the dormouse said:<br />"Feed your head<br />Feed your head<br />Feed your head"</p>\r\n<p>&nbsp;</p>\r\n<p><strong>10) Does your last movie Whore’s Glory aim to form a trilogy together with Megacities and Workingman’s Death in terms of technique, narration and theme? Or is their common point needed to be discussed on a narrower area?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Yes it does aim for a trilogy and it has the number 3 incorporated in its formal concept since it is a build as a triptych. http://www.glawogger.com/produktion_en.php I like the 3. Also “Slugs”, “Contact High” and “Rock and Roll” are going to be a trilogy in the end. But concerning the documentaries, I think I might do a fourth part of the trilogy with the project called “Untitled – The Film without a Name”. http://www.glawogger.com/projekte_en.php</p>\r\n<p>&nbsp;</p>\r\n<p><strong>11) Workingman’s Death is a unique example of rhythm usage in documental cinema. Was that a planned thing before you shot this movie, or appeared after shooting the images? Is it an improvisation or a design?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Rhythm is always important for me and since Megacities and Workingman’s Death are done without commentary and with only little statements the rhythm gets even more important. And also it came with the subject itself since all those jobs convey a certain kind of rhythm. Sledgehammers, Wooden baskets, knives and torches are all tools that are used in a manner that convey a rhythm. And the places these labors appear in do the same. I wrote a text once for the book accompanying the movie that tries to transport this rhythm in language. I will incorporate it in this answer.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>KANDAPELLETHEAD Port Harcourt, Nigeria</strong></p>\r\n<p>&nbsp;</p>\r\n<p>The Port Harcourt slaughter yard is a labyrinth of people and animals. It took weeks before I had visited all the departments and explored every path.</p>\r\n<p>&nbsp;</p>\r\n<p>The whole area is actually a market, which is situated between a zoo, a bridge in the middle of construction, a river, and an industrial park where multinational corporations like Coca-Cola and Shell have set up operations.</p>\r\n<p>&nbsp;</p>\r\n<p>The grounds consist of a few huts, a large covered market hall, a cold storage room, a corral for the cattle, pig pens, a pool table set up under an awning, a mosque, a few shanties, a slope leading to the river that also serves as an open toilet, and the various sites where animals are transformed into meat.</p>\r\n<p>&nbsp;</p>\r\n<p>These sites consist of a charred elevated platform for roasting the beef parts and whole goats, a large paved surface, the “Slab,” where the cattle is slaughtered, skinned, and cut into portions, and finally a kind of courtyard where the pigs are butchered, placed in bath tubs of scalding water, and scraped with sharp knives to remove their bristles. Right next to this, a long hall extends straight through the market. After roasting, this is where the goats are brought to be cleaned and further processed. And then there are the restaurants, a second mosque, the CD store, several tailors, and the photographer.</p>\r\n<p>&nbsp;</p>\r\n<p>It starts to get light at around five in the morning. Now you realize that the counters are covered with people, sleeping vendors, butchers, assistants, meat haulers. They yawn and stretch and peel back their thin blankets. The sweet smell of the previous day’s meat hangs in the air, and you can hear the roosters crowing everywhere.</p>\r\n<p>&nbsp;</p>\r\n<p>Some people pray, some wash themselves at the Slab or brush their teeth out back by the great mounds of bones, others have breakfast, a hot milk beverage or skewers of meat, and many of them hold small transistor radios to their ears. A symphony of images, sounds, and smells slowly unfolds before you, swells and becomes ever louder, ebbs at noon, and is calm again.</p>\r\n<p>&nbsp;</p>\r\n<p>First come the goats led by the young assistants of the goat butchers and goat roasters. The goats make the most noise as they are being brought – all tied together – to the slaughter yard. It is hard to tell whether they can sense what awaits them; maybe it is just uncomfortable to be pulled around all tied together like that.</p>\r\n<p>&nbsp;</p>\r\n<p>Next, other young assistants use pieces of discarded tires they have cut into sections to fetch fire from the fire pits in front of the restaurant where the women have begun to cook. As fire is brought to the slaughter yard, calls of “Mallam! Mallam!” begin mixing with the rising clamor of bleating goats. “Mallam” means “sir” or “man” and is a respectful address used to call the goat slaughterer over to where a goat is being held down and have him slit its throat for a fee of 40 nairas.</p>\r\n<p>&nbsp;</p>\r\n<p>The goat slaughtering area is dotted with masonry-lined holes, which one after another turn into fire pits. They are where the goats will be roasted later. Now the flames are leaping and thick plumes of black smoke rise and fill the sky.</p>\r\n<p>&nbsp;</p>\r\n<p>In the meantime, the assistant cattle traders and butchers are driving the cattle from the corrals to the Slab. For the workers, this is the best part. It is both a test of courage and the chance to see how fast you can run. The bulls (and they are all, without exception, bulls) do not bellow at all, but they behave like wild animals on these last fifty meters to the slaughtering grounds. A short time later, they submit almost apathetically to their fates.</p>\r\n<p>&nbsp;</p>\r\n<p>As they arrive at the Slab, the hawkers’ cries mix with the distant but audibly frantic bleating of the goats. “Kandapellethead!” or “Kandakandakanda!” or “Pelletpelletpellet!” they yell, each trying to drown out the other. “Kanda” means skin, “pellet” means innards, and “head” is the same as in English. The hawkers shout these words in any combination, announcing the three delicacies they have to offer for future consumption.</p>\r\n<p>&nbsp;</p>\r\n<p>In the meantime, the goats sizzle on their fires, and around the corner the pigs squeal. They are the ones most likely to comprehend what is in store for them. In the background, men walk past carrying charcoaled goats on their heads. They are on their way to the goat washers, who yell cheerfully as they scrub the hair off the goats with water and brushes.</p>\r\n<p>&nbsp;</p>\r\n<p>At the Slab, the first bulls are being thrown down, they hit the concrete with a heavy thud or land in the spreading puddles of blood, while the hawkers yell at the top of their lungs: “Kandapellethead!” Some are already bargaining loudly with the newly arriving customers, who usually only want to pay a fraction of what the vendors are asking.</p>\r\n<p>&nbsp;</p>\r\n<p>Wheelbarrows full of goat carcasses, bloated from roasting and bright yellow after being washed, are pushed toward the parking lot, while the first cattle heads are severed from their still kicking bodies.</p>\r\n<p>&nbsp;</p>\r\n<p>One of these heads weighs in the range of fifteen to twenty kilograms. The butchers mark the heads with the owners’ initial, then they are taken to a relay point and from there to the goat slaughtering area.</p>\r\n<p>&nbsp;</p>\r\n<p>Here, the shouting and bleating, the slaughtering and roasting are still going strong. The horns are hacked off and the cattle heads roasted, then they are washed in discarded water-filled truck tires until they are the same yellow color as the roasted goats. Then they are brought back to the Slab and cleaved in the midst of dying animals and twitching meat.</p>\r\n<p>&nbsp;</p>\r\n<p>Most of the cattle is already skinned and cut into pieces, and the haulers shoulder large sections of meat. This is one of the most grueling jobs of all. With half a bull on their shoulders, these men run to the washing troughs, where they soak and wash the meat briefly, then heave it back onto their shoulders, run clear across the market, and stow it in the trunks of taxis and transport vehicles.</p>\r\n<p>&nbsp;</p>\r\n<p>Then they hurry back to the Slab so they will be there for the good pieces and good buyers. Meanwhile, other workers are taking the tails and skins to the fires to be roasted.</p>\r\n<p>&nbsp;</p>\r\n<p>This frenetic cycle of herding, slaughtering, dying, hauling, washing, roasting, chopping, portioning, bargaining, hawking, arguing, screeching, rejoicing, and running repeats itself until noon rolls around and the vultures come.</p>\r\n<p>&nbsp;</p>\r\n<p>The vultures sit on the roofs waiting patiently for the cycle to spin to a stop. Then they hop down onto the Slab or on the great mounds of horns and bones near the goat slaughtering area to devour what is theirs.</p>\r\n<p>&nbsp;</p>\r\n<p>At around one o’clock, a couple of workers hose down the Slab.</p>\r\n<p>&nbsp;</p>\r\n<p>Then the blood flows into the river, across which a new bridge is currently being built. It looks so different than anything at the slaughter yard. The workers there are clean, the concrete is clean, and one day the president of Nigeria went there to inaugurate the clean half-finished bridge. That day, the slaughter yard at Port Harcourt was closed so that the smoke and noise would not disturb the president during the ceremony.</p>\r\n<p>&nbsp;</p>\r\n<p>The workers got the day off, and so did we. All we shot that day were five pigs in the middle of the goat slaughtering area which, amid thousands of chopped off horns, had curled up together for a little snooze.</p>\r\n<p>&nbsp;</p>\r\n<p>The book was never published in English. http://www.glawogger.com/autor_en.php</p>\r\n<p>&nbsp;</p>\r\n<p><strong>12) Have your movie Whore’s Glory ever got out of line during the course of production? Have it orbitted out of your prediction? How do the women see the world of the future?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>No, it didn’t get more out of line than any other movie I did. And how the women see the future, I really don’t know. This was a question I always asked while during Megacities and never asked during Whores’ Glory. Could be a sign I have gotten more afraid of the future during all those years.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>13) And our last question... What’s your top ten films?</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Ten feature films and a short film: A I dade da Terra, Glauber Rocha; Come and See, Elem Klimov; Mothlight, Stan Brakhage; Fata Morgana, Werner Herzog; Fat City, John Huston; Hellzapoppin’, H.C. Potter; Blue Collar, Paul Schrader; Hecate, Daniel Schmid; Senso, Luchino Visconti; In the Mood for Love, Wong Kar-wai; Tiempo de Morir, Arturo Ripstein.</p>', 45, 67, 'Arşiv Yazıları', NULL, '2017-03-31');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (172, 'ay-j258', 'alt-yazilar', 'Alt Yazılar', '', '<div style="display: table;">\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Maynila, Sa Mga Kuko Ng Liwanag.TR.srt"><img src="/images/altyazilar/Manila_280x415.jpg" alt="Manila" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Maynila, Sa Mga Kuko Ng Liwanag.TR.srt"><em><strong>Manila\'nın Işıkları</strong></em><br />(Maynila: Sa Mga Kuko Ng Liwanag /<br />Manila In the Claws of Light,<br />Lino Brocka, 1975)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Robinzoniada, anu chemi ingliseli Papa.1986.Djordjadze.TR.srt"><img src="/images/altyazilar/robinsonada_263x415.jpg" alt="robinsonada" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Robinzoniada, anu chemi ingliseli Papa.1986.Djordjadze.TR.srt"><em><strong>Robinsoniada, İngiliz Büyükbabam</strong></em><br />(Robinzoniada, anu chemi ingliseli Papa,<br />Nana Dzhordzhadze, 1986)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Sista.Kontraktet.1997.TR.srt"><img src="/images/altyazilar/Sista%20Kontraktet%20Afiş%20287x415.jpg" alt="Sista Kontraktet" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Sista.Kontraktet.1997.TR.srt"><em><strong>Son Sözleşme</strong></em><br />(Sista kontraktet, Kjell Sundvall, 1997)</a></p>\r\n</div>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/A.Single.Spark.1995.TR.srt"><img src="/images/altyazilar/A_Single_Spark_302x415.jpg" alt="A Single Spark" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/A.Single.Spark.1995.TR.srt"><em><strong>Tek Bir Kıvılcım</strong></em><br />(A Single Spark, Park Kwang-Su, 1995)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Boat.People.1982.TR.srt"><img src="/images/altyazilar/tau_ban_no_hoi_boat_people_288x415.jpg" alt="A Single Spark" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Boat.People.1982.TR.srt"><em><strong>Tekne Mültecileri</strong></em><br />(Boat People, Ann Hui, 1982)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Bian zou bian chang_Life on a string.TR.srt"><img src="/images/altyazilar/life_on_a_string_film_poster_306x415.jpg" alt="Life on a String" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Bian zou bian chang_Life on a string.TR.srt"><em><strong>Teldeki Yaşam</strong></em><br />(Bian Zou Bian Chang / Life on a String,<br />Chen Kaige, 1991)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Tokyo Ga.tr.srt"><img src="/images/altyazilar/tokyo_ga_film_poster_311x415.jpg" alt="Tokyo-Ga" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Tokyo Ga.tr.srt"><em><strong>Tokyo-Ga</strong></em><br />(Wim Wenders, 1985)</a></p>\r\n</div>\r\n<div style="float: left; padding: 15px;">\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Gishiki.The Ceremony.1971.TR.srt"><img src="/images/altyazilar/ceremony-gishiki_291x415.jpg" alt="Gishiki" /></a></p>\r\n<p style="text-align: center;"><a href="/docs/altyazilar/Gishiki.The Ceremony.1971.TR.srt"><em><strong>Tören</strong></em><br />(Gishiki / The Ceremony,<br />Nagisa Oshima, 1971)</a></p>\r\n</div>', 1, 67, 'Arşiv Yazıları', '/images/altyazilar/Manila_280x415.jpg', '2018-10-04');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (173, 'ay-j259', 'to-tarkovsky', 'To Tarkovsky', 'TO TARKOVSKY....', '<p><strong>TO TARKOVSKY.... </strong></p>\r\n<p style="text-align: right;"><strong>gökhan erkılıç</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p style="text-align: justify;">20 years have passed after your death. Every death leaves a void behind. Time, aware of being the sign of that huge void, continues to flow. While the presence of your work mitigates the pain of your absence, they also are the ones that recreate the feelings of loneliness, again and again…Yes, the real problem here is your leaving some of us so much lonelier.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">We’re here, in a location that almost all the printed papers about you are no more than mere copies, translations or reviews. Even the ones that claim to be original papers are in fact plagiarized. Since the main texts were written in your own language, the so called original European sources that they refer to are also steals. There are two main articles which almost everyone has consumed. One is dated in 1976, and the other in 1997. The one written in 1998 has not been touched yet. I wonder what would have been written so far, if these two articles didn\'t exist. Reason for the bibliography attached to the end of Turkish articles is to hide the main source that has been stolen from. By this way, authors want to show us that they were able to understand the incomprehensible. You may ask why? Because, they say you area director so hard to understand. Understanding you has almost become an important status. They believe that it is your words sometimes and your visual language other times, that is problematic. The main aptitude of man is to slander what can not be understood and not to judge himself as the one who cannot understand. There is an inverse case when it comes to you, compliments for you never end. Aside the fear of falling outside the herd of authority, they disclose their ignorance easily. In fact, not being able to understand should normally give way to the reflex of exploring and learning. However, trying to understand in the absence of a comprehension for Human, East, West, Thought, Mysticism and Art; actually, that must be the problem. At recent years we are going through a period in which East thrives to be Western and wears out itself for this aim. <strong>I </strong>am afraid it will become the responsibility of the West to remind the East of its own potential. It seems to me like you wouldn’t continue making movies, if you were still alive. I think you have set the timing of your death correctly.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">You believe that the cinema can be the language of mind, history and thought. You were drawn into the problems of alienation by political, social and economical structures of the modern society; and the crisis of belief experienced by the individual as a by product of living through that specific history. Essentially, your actions and your discourse were reactions against the disappearing of man. You were wounded deep inside by the detachment of human beings from the meaning and value of existence, as a result of their being dismissed from nature, emotions and belief. I was also fascinated by your conviction of cinema being a well equipped art, as much as music and poetry are; we were on the same page. There were already some examples of cinema as a visual structure/language in the power and taste of music and poetry. There was a huge difference between film and cinema, hubble-bubble and music, rubbish and poem.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">To deeply comprehend the areas of thought you were interested in requires an intense effort, especially in given conditions of our day. Also, I add the infiltration of your dreams, poems, memories and subconscious; questioning of time; and the reflection of your longings -that I thought as always neglected: all add up to the wall of difficulty around your work. Having said that, the ways to pass through that wall is also becoming visible. In fact, I, kind of enjoy your being found difficult. To find someone difficult is precious while so much is found easy... a proof for life!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">You are not one of the directors on whom so much has been written. However, when one looks at the quality and the depth of these articles, I see that you were one of the two directors who encourage the authors to do their job properly. That reminds me the world you have always wanted to live in.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">I am aware of my wandering from one thought to another, but recently I have happened to find an article about you. That was a quickly sketched best directors and movies list that you have had given to <strong>Leonid Kozlov</strong>. <strong>Antonioni, Bergman, Bresson, Bunuel, Dreyer, Kurosawa, Mizoguchi </strong>and <strong>Vigo</strong> were the names in your best directors list. It was also good for you to add <strong>Dovzhenko </strong>to that list in another interview. In your film list, <strong>Bergman </strong>looks unrivalled. Indeed, I have always recalled the other, while watching a movie of either one of you. It is hard to explain. You also like <strong>Bresson </strong>so much. It is thought-provoking to see three Japanese films, but no Russian film in your list. None of the films of your four best directors are present in your film list. The importance of questioning life is on top of everything, isn\'t it? I am sure, the lists you had in mind at 1972 had gone through significant changes in the following years. And here is the question: Can we call a list as the best films list, if it doesn\'t include <strong>Zerkalo?</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Zerkalo</strong> was the only film that I have engaged with you directly<strong>. </strong>The realities and the longings of childhood; the parade of memories and dreams; taking a breath on the turning points of history; the attitude of men against art, science and technology; the obsession to understand time; the moment of pay off with the government through <em>Sralin</em> (thanks to <strong>Ece, </strong>and I\'m sorry!)... an invaluable example for the common use of artsytools in cinema! What happened then? The knick-knacks responsible for arts in the Party canalized the movie to the repertoire cinemas in order to deprive Stalin of your hands. <strong>Zerkalo </strong>still was a movie noticed easily in this golden waste yard, through which the best of Soviet cinema came to life.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Years and years ago one evening, while I was reading your book with the attention I have only paid before when reading <strong>Neruda, Puşkin </strong>and <strong>Maldoror, </strong>I heard about your death<strong>. </strong>A coincidence that was not coincidental and a loneliness that was informative. You have triggered countless thoughts and everlasting discussions... The relationship between fascism and the masses with vital and humanly deficiencies... Sanctification of fascism by all ideologies when they found a space to infiltrate... The two incurable problems standing before culture and art: The monks taking decisions on behalf of others\' and the ones who only know taking and who turn back to their inns when it comes to giving... In the relationship of arts and politics, let’s say no to art of politics, but yes to politics of art...</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Man should have his own mirror, that\'s right. Even if the man is selfish, his mirror should not treat him in selfishness. It should show himself in close-up first, and then should nullify him in general plan... so that there can be room for others, for life, for nature, and in short, for the things that are more valuable.</p>\r\n<p>&nbsp;</p>\r\n<p>Me finds its highest value in Us, as it has been reflected from your <strong>Mirror...</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p style="text-align: right;"><strong>çev: seda usubütün</strong></p>\r\n<p style="text-align: right;">Sekans Sinema Kültürü Dergisi, no 7, 2007</p>', 45, 67, 'Arşiv Yazıları', NULL, '2018-11-30');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (174, 'ay-j262', 'iranian-new-wave-especially-qeysar', 'Iranian New Wave, Especially “Qeysar”', 'PDF', '<h3 style="text-align: center;"><strong>Iranian New Wave, Especially “Qeysar” </strong></h3>\r\n<p style="text-align: right;"><strong><em>&nbsp;</em></strong><a href="/docs/archive/Qeysar.pdf" target="_blank">PDF</a></p>\r\n<h4 style="text-align: center;"><strong>İlker Mutlu</strong></h4>\r\n<p style="text-align: center;"><strong>&nbsp;</strong></p>\r\n<p style="text-align: center;"><strong><em>Qeysar / Gheisar</em></strong></p>\r\n<p style="text-align: center;"><strong><em>&nbsp;</em></strong></p>\r\n<p style="text-align: center;"><strong>Director &amp; Scriptwriter:&nbsp;</strong>Masud Kimiai</p>\r\n<p style="text-align: center;"><strong>Cinematographer: </strong>Maziar Partow <br /> <strong>Soundtrack: </strong>Esfandiar Monfaredzadeh <br /> <strong>Cast: </strong>Behrouz Vossoughi, Pouri Baneai, Naser Malek Motiee, Jamshid Mashayekhi</p>\r\n<p style="text-align: center;">1969/100’/Iran</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;">Qeysar! Where are you?&nbsp; They are killing your brother!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">At first, this is a quotation which seems funny, isn’t it? However, this line passes in one of the most vital scenes of the film in which Qeysar’s brother Farman calls him in pain while he was being killed.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In my article celebrating the 50<sup>th</sup> anniversary of <strong><em>Samurai Rebellion</em></strong> (Masaki Kobayashi, 1967) in the previous issue, I also mentioned that the film I addressed was one of the most important productions of the Japanese New Wave. The years including 50s and 60s had “waved” cinemas of many countries. French, British, Czech, and Argentine New Wave movements broke out one after another. While the world was changing, it was not possible for cinemas of other countries not to be affected.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Likewise, Iran was to be affected before long. Iran’s movement started in 1969 with <strong>Dariush Mehrjui’</strong>s film called <strong><em>The Cow </em></strong>(<a href="https://tr.wikipedia.org/wiki/Gāv">Gāv</a>) and continued with <strong>Masud Kimiai’</strong>s film <strong><em>Qeysar</em></strong> which was shot in the same year. With their new cultural and intellectual contents, &nbsp;the following films has changed the status of Iranian audiences and improved the quality of the productions. Dozens of high-quality films produced caused Iranian New Wave to get this name. Important directors including <strong>Forough Farrokhzad, Bahram Beizai</strong>, and <strong>Parviz Kimiavi </strong>were also the pioneers of this movement. Their films were innovative, poetic, and philosophical. Many directors like <strong>Abbas Kiarostami, Jafar Panahi, Majid Majidi, Mohsen</strong>, and <strong>Samira Makhmalbaf</strong> who are making the locomotive movies of today’s art films owe a great deal to these pioneers.</p>\r\n<p>&nbsp;<img src="/images/archive/qeysar/dariush_mehrjui_the_cow.jpg" alt="dariush mehrjui the cow" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><strong>Dariush Mehrjui – <em>The Cow</em> (1969)</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">We can’t separate the rise of Iranian New Wave from those in other countries. The intellectual and political movements of the period were rapidly spreading all around the world. In Iran, after the coup in 1953, sociological approach gained importance in art, particularly in literature and reached the peak in 1960s. Thus, it was inevitable for this course not to affect the cinema.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In our previous issues, during the interview we did with Iranian Azerbaijani director <strong>Farid Mirkhani, </strong>we had discussed the development of Iranian Cinema. Therefore, I find it unnecessary to summarize the period before 1960 here. Although not being included in the New Wave, <strong>Ferruh Gaffari</strong>’s film <strong><em>In the South of the City</em></strong> (Jonubeshahr, 1958), which was censored and had its negatives burned, is one of the primary films that triggered the movement. By all means, this production is regarded as one of the first examples of socialist-realist cinema. Again the same director made the film <strong><em>The Night of the Hunchback</em></strong> (Shabeghuzi) which laid the foundations of art cinema in the country in 1964. Later on, talented young directors supported within the Iranian television started the Free Cinema movement in 1969. Ideas put forward and experiments done by these talented directors initiated socially sensitive films which represent the examples of political cinema. Earlier, <strong>Feridun Rehnama</strong>’s film <strong><em>Sivayeş Der Taht-e Cemşid</em></strong> (1960) which was inspired from the story of Sıvayeş in <strong>Ferdowsi’</strong>s work <strong><em>Shahnameh</em></strong> was screened in Locarno and Trieste Film Festivals, and awarded with Jean Epstein Prize in Locarno. Besides, this film had become the second film screened in The French Museum of Cinema (Musée de la Cinémathèque) after <strong>Ferruh Gaffari</strong>’s <strong><em>The Night of the Hunchback</em></strong>. In 1961, <strong>Ebrahim Golestan</strong>’s film called <strong><em>A Fire</em></strong> (Yek Atash, 1961) was awarded with Golden Mercury and Lion of Saint Mark awards in Venice Film Festival. Also, world famous woman poet <strong>Forough Farrokhzad</strong>’s film known as <strong><em>The House is Black</em></strong> (Khanehsiah ast, 1962) was selected as the best documentary, winning an award for Iranian cinema, in Oberhausen International Short Film Festival in 1963.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Qeysar</em></strong>’s director <strong>Masud Kimiai</strong> was born in Teheran in 1941. The film, which we addressed, made him famous in an instant and allowed him to be remembered as the person who changed the destiny of Iranian cinema. This film caused another genre to be born in the Iranian cinema: the tragic action drama. Though just having a few years of experience in being an assistant director and receiving no academic education on cinema or theater, <strong>Kimiai </strong>suddenly became a historical figure of Iranian cinema. He learned directing by watching films and through his early acquaintance with cinema. He talks about the times when he had waited in front of the Tehran cinemas, listening to the noise coming from the film screenings, and with the help of his friends’ narratives who stepped out of the cinema he would try to visualize the film in his mind. Another vivid memory from his childhood is the paintings of <strong>Rostam</strong> and <strong>Ashkbous</strong> behind his father’s car with which he was carrying flour to bakeries. As the car moved, he would think of the paintings as they came alive and started moving, and while habitually following the car from behind, he would try to guess the end of the war in these paintings. He had a rough childhood. He was uptight and he often got into fights that ended up in a police station.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">At last, the time came and <strong>Kimiai</strong> started directing his energy to the books. These books were especially about cinema. Inevitably, this situation led him to seek jobs in film studios, till he met with the director <strong>Samuel Khachikian.</strong> He took his first lessons about techniques in film making from <strong>Khachikian</strong> and started his film career in 1965 as his assistant. <strong>Kimiai </strong>who proved himself with his energy and efforts, and earned the trust of the producers, had written and directed his debut film <strong><em>Come Stranger</em></strong> (Baigane Biya) in 1968.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Kimiai</strong>’s second film, <strong><em>Qeysar</em></strong> is differentiated from other Iranian films not only with its innovatory structure (this structure might seem out-of-date to most of us today, but it is still intriguing) changing the course of Iranian cinema, but also with its way of handling women sexuality bravely. Moreover, he achieved this success only with his second film. Director <strong>Kimiai</strong> ‘s luck turned with the tragic story of Qeysar who tried to avenge his poor young sister who was raped, got pregnant, and eventually killed herself. On top of that, in the following years <strong>Kimiai</strong>, thanks to his film, also determined the way women take part in the cinema. However, this image was not that positive as women were being commoditized and perceived as malicious.</p>\r\n<p>&nbsp;<img src="/images/archive/qeysar/masud_kimiai_qeysar.jpg" alt="masud kimiai qeysar" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><strong>Masud Kimiai - <em>Qeysar</em> (1969)</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In addition, <strong><em>Qeysar</em></strong> represented Iran’s poor neighborhoods, craftsmen, human relations with their realist states. It took over this tradition from its pioneers improved it and passed it to its sequents. Of course, <strong><em>Qeysar</em></strong> does not owe its importance to the storyline. In <strong><em>Qeysar,</em></strong> we witness all kinds of tragedies which we already know from the Turkish cinema. However, while presenting this tragedy, the director didn’t make any concessions from reality, not even for a minute. Also, <strong><em>Qeysar</em></strong> is not overrated and it does not overshoot itself like today’s films that earn reputation with vengeance stories such as <strong>Park Chan-Wook</strong>’s film <strong><em>Oldboy</em></strong> (Oldeboi, 2003); it rather gains appreciation for being earnest.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">I had watched a poor quality version of <strong><em>Qeysar</em></strong> on a DVD without subtitles about three years ago. Indeed, there was no need for subtitles because the film was telling the story in its simplest possible way. Besides, the music that was heard just in the beginning of the film and that could easily be engraved in one’s mind was familiar to me.&nbsp; The song composed by <strong>Esfandiar Monfaredzadeh</strong> was exactly the same with the one in a film that I watched years ago, <strong><em>The Destiny</em></strong> (<strong>Alın Yazısı, Orhan Aksoy</strong>, 1972) starring Cüneyt Arkın. Only in the middle of the film it hit me that <strong><em>The Destiny</em></strong> was the adaptation of <strong><em>Qeysar</em></strong>. Today, it’s a known fact that <strong>Aksoy</strong>’s film is a direct copy of <strong><em>Qeysar</em></strong>.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/qeysar/qeysar_poster.png" alt="qeysar poster" />&nbsp;<img src="/images/archive/qeysar/naser_malek_motiee.png" alt="naser malek motiee" width="191" height="268" />&nbsp;<img src="/images/archive/qeysar/erol_tas_alin_yazisi.png" alt="erol tas alin yazisi" width="330" height="268" />&nbsp; &nbsp;&nbsp;</p>\r\n<p style="text-align: center;"><strong>Naser Malek Motiee in the poster of the film <em>Qeysar</em> and its spin-off film <em>The Destiny</em> (Alın Yazısı) featuring Erol Taş</strong></p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p style="text-align: justify;"><strong><em>Qeysar</em></strong> opens with close screenings of some tattooed men bodies accompanied by <strong>Monferadzadeh</strong>’s music. Those tattoos were the symbols representing Iranian folk art and probably their heroic epic. The tattooed men footages in this relatively long credits reveal the overall structure of the film. Yes, the film is a “revenge-themed tragic action drama” but above that it is a “man’s” film. The director who succeeds to attract the attention of the audience in the intro wastes no time in starting the story and we immediately find ourselves chasing an ambulance rapidly moving forward. <strong>Kimiai </strong>applies the steady rule “make an impressive opening and grasp the attention” from the very beginning and continues with a steady narration.</p>\r\n<p>&nbsp;<img src="/images/archive/qeysar/tattoos_qeysar.png" alt="tattoos qeysar" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><strong>The tattoos in the opening scene of <em>Qeysar</em></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Ambulance is carrying the young girl who committed suicide, and her aunt and uncle accompanies her. The doctor soon notifies that the girl is dead and jeremiads of the aunt and the uncle hint what will happen next in the film: “What are we supposed to say to her brothers? What are we supposed to say to Farman, to Qeysar?” Before long, Farman, (the character played by the beloved professional actor <strong>Naser Malek Motiee</strong> who took place in some Turkish films), who heard the news appears in the corridor with his butcher apron and bowler hat which seem funny to the audience at first, but they easily get used to it. The letter the girl left behind explains everything clearly, and Farman gets angry and busts the warehouse run by the rapist and his brothers.&nbsp; There, while Farman was about to strangle the rapist Mansoor, his two brothers Rahim and Karim stabs Farman to death from behind.</p>\r\n<p>&nbsp;<img src="/images/archive/qeysar/qeysar_where_are_you.png" alt="qeysar where are you" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p style="text-align: center;"><strong><em>“Qeysar</em></strong><strong>!<em> Where are you? They are killing your brother!”</em></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Peculiarly, the lead actor’s appearance takes place almost twenty-five minutes after the opening scene. Qeysar, wretchedly, returns to his hometown with a long train ride from the town where he works. (<strong>Behrouz Vossoughi</strong>, who played his first big role here, later became one of the legendary actors of Iran.) Qeysar’s walking with a confidence while stepping on the back of his shoes and wearing them again before each fight has become a symbol of his role, and also it suits to Cüneyt Arkın very well in the film <strong><em>The Destiny</em></strong>. Of course, we are used to the artificiality of Cüneyt’s tricks but that doesn’t exist in <strong>Vossoughi</strong>’s acts. It can be understood that <strong>Vossoughi</strong> was a rough diamond till that film, but the role Qeysar suited him well.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/qeysar/alin_yazisi_poster.png" alt="alin yazisi poster" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Qeysar comes into town to see his fiancée but when he arrives he learns what has happened to his family, he then needs to make a tough decision. His genes and upbringing lead him towards revenge, whereas his affection for his fiancée holds him back. In the end, his genes prevail and he kills his three enemies; he kills Karim in a hammam, Rahim in a slaughterhouse, and Mansoor at a train station where he is also caught and killed by the police.&nbsp; All three murder scenes are given with long plans that hold the tension: Qeysar scans the place first, planning how to reach his target then he kills him brutally and leaves the scene in cold-blood. Sequences in these murder scenes, especially in the first two, reflect the culture excellently as if they are short documentaries: Cruel bath masseurs in the hammam, a man praying on the central platform with his peshtemal on, cloudy mirrors on the wall for those who want to shave; animals brought to the slaughterhouse, slaughter rituals, and meat distributions; the human mosaic reflecting the Iranian culture of that time in the train station. Although this film is only the second one of <strong>Kimiai</strong>, with the sequences that are full of tension, he manages to arouse the audience’s curiosity for his next movies.</p>\r\n<p>&nbsp;&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/qeysar/behrouz_vossoughi.png" alt="behrouz vossoughi" width="395" height="296" />&nbsp;<img src="/images/archive/qeysar/arkin.png" alt="arkin" /></p>\r\n<p style="text-align: center;"><strong>Behrouz Vossoughi’s attitudes and sitting position <em>and</em> Arkın’s impersonation of him</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Qeysar</em></strong> also uses sexuality bravely in a degree that was unexpected from an Iranian film. For example, young actress’ breasts can be seen in the rape scene. Also, in the night club where Qeysar went to ask for Mansoor, the women singer’s dance and clothes are striking. Actually these footages are surprising especially for today’s cinema lovers who doesn’t know those times in the Iranian cinema and who are used to see those women in hijab.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/qeysar/singers_dance.png" alt="singers dance" style="display: block; margin-left: auto; margin-right: auto;" />&nbsp;</p>\r\n<p style="text-align: justify;">Despite of the presence of intense eroticism in the film, romantic relationships are quite conservative. Qeysar and his fiancée are alone together in some scenes yet there occurs no intimacy between them. The scene where Qeysar lays his eyes on his fiancée from afar while she prepares tea for him may be an exception, but that’s all. The women who work at the night club and who are partially from the upper class dress up and do not wear hijab, whereas those who live in poor neighborhoods dress the same as we see in today’s Iranian films.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Farman’s bowler hat which he never took off is an interesting feature in the film. It reminds us of the agha figure that is stuck between modernization and localness in the Turkish village films. As a consequence, it is not necessary for Farman’s past to be shown in the film; he is just a conservative small retailer living in a conservative town where modernization pain is deeply felt.&nbsp; For him, his hat is the symbol of longing for climbing the social ladder and being in limbo. In <strong><em>The Destiny</em></strong> bowler hat that <strong>Erol Taş</strong> wears seems unnatural because it only finds its meaning in <strong><em>Qeysar</em></strong>.&nbsp; The reason is that we got over that pain almost 50 years ago.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">&nbsp;There are many scenes that define the social status and support the narrative of the film. In order to explain them, we need to know the Iranian society and history very well, but I can give some examples: In the rape scene, young girl studies and the name of her book is <strong><em>Domestic Economy</em></strong>; in the coffee sequence where Qeysar learns the place of his first target we see wrestler images on the wall, (director intentionally keeps the images inside the frame); in the hammam scene a man wearing peshtemal prays in the central platform (it must be a Shia tradition.); in the opening scene there are symbolic tattoos ornamented on naked men’s bodies which we have mentioned above. There are other examples like details of wall decorations in Qeysar’s home, and images of Hazrat Ali on the wall; Qeysar’s laying his eyes on his fiancée when she is preparing embers unaware of being watched (woman, man, and embers/fire; an excellent idea for romantic love eroticism that is self-censored!); the lottery ticket Qeysar buys for the next day while trying to plan his last murder in the night club; and the shoes he wore as a sign of an upcoming fight… Last but not least, it’s symbolized that murder is a man’s job and it only occurs in places where men are present (hammam, slaughterhouse, and train station)!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Some of the Iranian actors/actresses have become known and popular in Turkey especially during 70s as a result of the co-productions. For example; <strong>Reza Beyk Imanverdi</strong> (<em>Little House</em>/Küçük Ev, Safa Onal, 1977), <strong>İraj Ghaderi</strong> (<em>Acı Hatıralar</em>, Atif Yilmaz, 1977), <strong>Cihangir Gaffari</strong> (<em>Zagor</em>, Mehmet Aslan, 1970), <strong>Manoochehr Vossoogh</strong> (<em>Perisan</em>, Mehmet Dinler, 1976), <strong>Firuz</strong> (<em>Adalet</em>, Melih Gülgen, 1977), <strong>Humayun Tebrizyan</strong> (<em>The Nameless Knight</em>/Adsız Cengaver, Halit Refig, 1970), <strong>Sait Seyit </strong>(<em>Altar</em>, 1985), and <strong>Ali Miri</strong> (<em>Can Pazarı</em>, Orhan Elmas &amp; Ertem Göreç, 1974). Also, <strong>Pouri Baneai</strong> who played Qeysar’s fiancée in <strong><em>Qeysar</em></strong> co-stars in the film <strong><em>Can Pazari</em></strong> with <strong>Kadir İnanır</strong>.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Naser Malek Motiee </strong>is one of the most beloved and renowned one of all.&nbsp; During his Turkish cinema (Yeşilçam) years, <strong>Naser</strong>, who plays Farman in <strong><em>Qeysar</em></strong>, played roles where he impersonated a man who first tries to avenge his loss brutally then gives up because of his compassion and soft-heart in the films <strong><em>Deprem</em></strong> (Serif Goren, 1976) and <strong><em>Baraj</em></strong> (Orhan Aksoy, 1977). Although not well known in Turkey, <strong><a href="https://en.wikipedia.org/wiki/Behrouz_Vossoughi">Behrouz</a> <a href="https://en.wikipedia.org/wiki/Behrouz_Vossoughi">Vossoughi</a></strong> is one of the most famous actors in Iran. Vossoughi who played in more than ninety films earned reputation in many international festivals and is honored with the Lifetime Achievement Award at the San Francisco International Film Festival in 2006. Moreover, he is one of the lead actors in the film <strong><em>Rhino Season</em></strong> (Fasle Kargadan, Bahman Ghobadi, 2012) which also became popular in Turkey.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema&nbsp; Kültürü Dergisi,&nbsp;August&nbsp; 2017, Issue&nbsp; e5, pp. 84-92</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by Esila Sucu</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">esila-sucu@hotmail.com</span></p>', 20, 67, 'Arşiv Yazıları', '/images/archive/qeysar/dariush_mehrjui_the_cow.jpg', '2018-11-30');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (175, 'ay-j264', 'waltz-with-bashir', 'Waltz with Bashir', 'PDF', '<h3 style="text-align: center;"><strong><em>WALTZ WITH BASHIR</em>: CAN A FRANK CONFESSION BE THE APOLOGY FOR HISTORIC DESTRUCTIONS?</strong></h3>\r\n<p style="text-align: right;"><strong><em>&nbsp;</em></strong><a href="/docs/archive/Waltz%20with%20Bashir.pdf" target="_blank">PDF</a></p>\r\n<h4 style="text-align: center;"><strong>A. Kadir Güneytepe</strong></h4>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Ari Folman</strong> is a documentary film-maker from Israel, who normally doesn’t work on animations. However, in <strong><em>Waltz with Bashir</em></strong>, he has successfully used the animation in order to re-fictionalize the memories, delusions, fantasies, possibilities, the past and the present. Actually, there seems to be no other way to make this film easier except than making it an animation.&nbsp; The animation is generally assigned different meanings since it is mostly related to cartoons; however, animation is also a successful way to express the historical destructions related to humanity. Furthermore, it can also be used to describe the state of humanity by making both contemporary and future predictions based on current position of humanity. Sometimes, it can also be fictionalized humorously or cunningly.&nbsp; We can give the film <strong><em>WALL-E</em> </strong>by<strong> Andrew Stanton</strong> (2008) as an example which expresses the consumerist society impressively and criticizes it radically.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Folman</strong> fictionalized <strong><em>Waltz with Bashir</em></strong> as a traditional documentary.&nbsp; He visits his old friends from army; he tries to bring together the things he saw and recalled. Eventually, with the power of freedom that he gained from animations, he visualizes the things he was told, even the nightmares. In this way, <strong>Folman</strong> tried to make both himself and the world face the reality of war, the pain it left behind, and especially the alienation of Israel society with that situation.&nbsp; The world had taken a back seat and watched silently, just like it has done in other genocides. The question of how guilty the people are is always left obscure. <strong>Folman</strong> makes a reference to this situation with his visual documentary. As well as the ones who pull the trigger, there are also others who have moral responsibility or are guilty.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong><em>Waltz with Bashir</em></strong> is a very staggering production. It depicts that Israel condoned <strong>Sabra and Shatila</strong><a href="#Footnotes"><sup>1</sup></a> massacre carried out by the Cristian Phalanges during the Lebanese War in 1982 and the social amnesia of Israel itself was perhaps behind all of these. In <strong><em>Waltz with Bashir</em></strong>, which is a kind of fictional autobiographical documentary, <strong>Folman</strong> shows that the Israeli people have consciously forgotten the massacre in a state of social amnesia; thus, he tries to make his own generation face with the doom that they themselves have created. This film, in a way, is an effort to reconstruct the lost memories, dreams, war traumas and the surrealistic reality that was engraved in subconsciously. Although the terror of the massacre was suppressed and buried deep in the Israelis’ minds in the last quarter century, according to <strong>Folman</strong>, that could not be fully achieved. Thus, the experiences can reappear at any moment as they are still close to the surface of their conscious.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Horrible events that lead to massacres are revealed in the film by using the semi-fictional re-constructive method somewhere between the oral history and psychoanalysis. A very realistic <em>rotoscope</em><a href="#Footnote-1"><sup>2</sup></a> animation method was used in the film; however, in an interview, <strong>Folman</strong> told that it was a mixture of Flash, hand-drawn animation and 3D original drawings. The live-actions on video-tape were transformed to the scenes that the reality is seen as two or three dimensional, and that is digitally bizarre and dreamlike.&nbsp; The planes and surfaces vibrate more, and the colors become more concrete, sharp, and bright. It looks like a long delusion and it is perfect in terms of reflecting the trauma of the <strong>Folman</strong>’s memories that flood&nbsp;back. However, does it mean that the tragic situation represented by animation may not be as effective for the audience as the live-action scenes and the connection that the animation makes with people may not be enough? Does the power of animation also turn into its own weakness?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">One of his friends from army (<strong>Boaz Rein</strong>) visits the middle-aged director. They drink beer together and this man mentions of a repetitive and very uncomfortable dream that he is being attacked by 26 wild dogs, which is actually the opening scene of the film.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong><em><img src="/images/archive/waltz-with-bashir/dogs.png" alt="dogs" style="display: block; margin-left: auto; margin-right: auto;" /></em></strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The rageful dogs which are successfully characterized move across and gathered in front of the man’s window. Then the man starts explaining how this dream is related to the 1982 Lebanon War. This meeting shows <strong>Folman</strong> that he doesn’t recall anything about that period. He realizes that not only he was not close to the camp places but also he doesn’t recall anything about the war itself. He then tries to recover his memories by tracing his companions in that period. For <strong>Folman</strong>, this is also going to be a travel which he confronts the past.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/waltz-with-bashir/coming_out_of_sea.png" alt="coming out of sea" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;&nbsp;</p>\r\n<p style="text-align: justify;">In his mind, there is actually no information related to those moments. Only thing he recalls is actually not a memory, but a dream or a delusion of the soldiers coming out of the sea one by one and this is actually the trace of the live-action scenes in <strong>Folman</strong>’s mind which we are going to see at the end of the film. In other words, this is perhaps the trauma that <strong>Folman</strong>’s testimony to those events have produced or left behind. In this delusion, like a slow-motion imitation of a military extraction or the arrival of amphibian creatures, skinny and frail new adolescent soldiers lie on their back in stagnant water with only the heads and fingertips outside. This still water is like a resemblance of a uterus. They come out of the water one by one. The sky is pale but oddly yellow. This color is used at the film’s most important moments, as the color of military operations and the color of weapons’ flames. As if it is the color of sovereignty and the trauma it caused. Then <strong>Folman</strong> consults his psychiatrist friend about this dream, his friend tells him that the only way out is to reach his friends who served with him, and to reveal and face the memories about what was happened in Lebanon.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">His friends tell him some unsettling and brutal things about blood and terror. Anyhow, what they say does not represent the actual truth; they tell the stories only from their own perspectives, as how they want to see things. Just like in the <strong><em>Rashomon</em></strong><a href="#Footnote-2"><sup>3</sup></a>. People want to forget the bad things and they want to recall the good things even if those are actually made up.&nbsp; One of them tells that he recalls he is sailing on the “Love Boat” and a big naked woman takes him with her.&nbsp; Despite all the evil things happening, it seems like there is a desire to return to the safe zone, because he is just lying on the woman’s womb and watching around drowsily. Another one says a Palestinian child attacked his troop with bazooka in a fruit garden; the other says he was almost killed in an ambush and survived miraculously by swimming....</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/waltz-with-bashir/memories.png" alt="memories" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">All of these slowly allow <strong>Folman</strong> to remember his memories about <strong>Sabra</strong> and <strong>Shatila.</strong>&nbsp; Was he there?&nbsp; Could he be there?&nbsp; If so, how close was he? This confusion was perhaps created to reveal the dark side of the war and to focus on the personal traumas, or perhaps for not to be accused of war crimes. And perhaps it was created in order to show that, because of television, people distance themselves from the actual events and become alienated, they are desensitized as if they have no concern and they are disoriented.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Eventually the film takes him to the crime scene, and it makes a brave turn from animation into television news.&nbsp; However, the tragedy that is shown in detail with the animation has already enough impact, even before showing the actual events; therefore, this part seems to be a little bit redundant.&nbsp; Moreover, it is interesting that the Palestinians have no name, they are represented anonymously and also, they do not talk. The fact that they are shown as brazen victims and the demonstration of Israeli soldiers as victims is one of the points that can be criticized.&nbsp; The facial reactions of Palestinians and what they are going through are not quite shown except the actual scenes at the end of the film whereas, the misery and despair of the Israeli soldiers are shown explicitly in the film. The human side of the Palestinians is also not shown. Hence, it looks like the film is causing a kind of alienation to what Palestinians go through, as well.&nbsp;&nbsp; Depicting the misery of Palestinians might have been necessary in terms of clarifying the same human drama from a different perspective. Another criticism is that a Palestinian mother cannot be told by such equality that what she has lost is more difficult and tragic than an Israeli adult should cope with. We don’t hear any statement coming from any Palestinian. In this regard, Palestinians are shown as if they are only a fraction of those times or a complementary of that event.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In addition to all these, the reasons for occupation, the destruction it has created, and the role of Israel seem to be hidden behind the confusion and fear of the young and naive 19-year-old soldiers. And this makes the film deprive of a political background and only focus on the psychological process; hence, there can be another criticism that it is misleading to show only the Israeli soldiers as experiencing the actual damages.&nbsp; The only message film gives is that the war is a terrible thing because it causes traumas; however, only its traumatic effects on the soldiers is taken as important and not its effects on masses. It can be seen as escaping from facing the actual responsibility. In a sense, it avoids questioning the current government and its ongoing actions and it remains as a superficial relief and confession. It is interesting that <strong>Ariel Sharon</strong> who is responsible for the massacre had been elected as the prime minister while the film was awarded even in Israel.&nbsp; Furthermore, the support given to the similar operations going on in Gaza is also a <a id="Footnotes"></a>remarkable controversy while the film was awarded. The film, in this sense, acts as a mass therapy.</p>\r\n<hr />\r\n<p style="text-align: justify;"><a id="Footnote-1"><sup>1</sup></a>&nbsp;<span style="font-size: 8pt;"><strong>Sabra and Shatila</strong> massacre was killing of hundreds of people including children (between 750 and 3500 people) by the pro-Israel and extreme right wing militia of Christian Phalangists by attacking the Palestinian refugee camps called <strong>Sabra and Shatila</strong> in the West Beirut. It is revealed after the massacre that <strong>Ariel Sharon</strong>, the old prime minister of Israel, had a role in this massacre. According to BBC, Israel Parliamentary Investigation Committee regarded Sharon as responsible for this massacre, and consequently <strong>Sharon</strong> resigned from his duty in Ministry of Defense.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><a id="Footnote-2"><sup>2</sup></a>&nbsp;<span style="font-size: 8pt;">It is a technique that is used frame by frame for each motion in order to produce a realistic action. For this reason, it is quite hard to apply. If there are 24 frames in a one second film, 240 pictures must be produced for a 10 seconds scene.</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><sup>3</sup>&nbsp;<span style="font-size: 8pt;"><strong><em>Rashomon</em></strong> is a 1950 Japanese dramatic film.&nbsp; Its original name is <strong><em>Rash<strong><em>ō</em></strong>mon</em></strong>. It was directed by <strong>Akira Kurosawa</strong> and was adapted by two short stories called <strong><em>Roshomon</em></strong> and<strong><em> In A Grove </em></strong>written by <strong>Ryūnosuke Akutagawa</strong> (1892-1927) who is regarded as the father of Japanese short story.&nbsp; This film also introduced the director to the West world. This psychological drama was built on the frailty of people. A samurai passing by the forest with his wife in the 12th century Japan is attacked and killed by a bandit, and his wife is raped. The bandit gets caught but his statement and the woman’s statement are totally different from each other. With the help of a psychic who comes into play to solve this problem, the samurai tells the story, but his story is totally different as well. The statement of woodsman again clashes with the others. Who tells the truth in this case where everybody’s “truth” is different from each other and the crime has four inconsistent but convincing versions? The humans are weak, so they lie even to themselves and people want to forget the bad things and believe the good even if it is a lie. This way is easier. It is the main point of the film.</span></p>\r\n<hr />\r\n<p><strong>References</strong></p>\r\n<p><a href="https://www.theguardian.com/film/2008/nov/21/waltz-with-bashir-folman" target="_blank" rel="noopener">Bradshaw, Peter. “Waltz With Bashir”, <em>The Guardian</em>, November 21, 2008</a><a href="https://www.theguardian.com/film/2008/nov/21/waltz-with-bashir-folman"><br /></a></p>\r\n<p><a href="http://www.rogerebert.com/reviews/waltz-with-bashir-2009" target="_blank" rel="noopener">Ebert, Roger. “Waltz With Bashir”, <em>rogerebert.com</em>, January 21, 2009</a><a href="http://www.rogerebert.com/reviews/waltz-with-bashir-2009"><br /></a></p>\r\n<p><a href="https://electronicintifada.net/content/film-review-waltz-bashir/3547" target="_blank" rel="noopener">Antaun, Naira. “Film Review: “Waltz With Bashir””, <em>The Elektronic Intifada</em>, February 19, 2009</a><a href="https://electronicintifada.net/content/film-review-waltz-bashir/3547"><br /></a></p>\r\n<p><a href="http://www.avclub.com/review/waltz-with-bashir-17085" target="_blank" rel="noopener">Robinson, Tasha. “Waltz With Bashir”, <em>A.V. Club</em>, December 24, 2008</a><a href="http://www.avclub.com/review/waltz-with-bashir-17085"><br /></a></p>\r\n<p><a href="http://revcom.us/a/150online/awtw_Bashir-en.html" target="_blank" rel="noopener">“Film review: Waltz with Bashir – feeling good about feeling bad”, Revolution, December 8,&nbsp;2008<br /></a></p>\r\n<p><a href="https://tr.wikipedia.org/wiki/Beşir\'le_Vals" target="_blank" rel="noopener">“Waltz With Bashir”, <em>tr.wikipedia.org</em></a><a href="https://tr.wikipedia.org/wiki/Beşir\'le_Vals"><br /></a></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema Kültürü Dergisi,&nbsp;August&nbsp; 2017, Issue&nbsp; e5, pp. 160-165</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by İzel Asal</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">izelasal033@gmail.com</span></p>', 41, 67, 'Arşiv Yazıları', '/images/archive/waltz-with-bashir/dogs.png', '2019-04-07');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (176, 'ay-j273', 'on-body-and-soul', 'On Body and Soul', 'ON BODY AND SOUL', '<p style="text-align: center;"><em><strong>ON BODY AND SOUL</strong></em></p>\r\n<p style="text-align: center;"><strong>A STATEMENT AS PURE AS A DEER</strong></p>\r\n<p style="text-align: right;">&nbsp;<a href="/docs/archive/On%20body%20and%20soul.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: center;"><strong>Seda Usubütün</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><em><strong>On Body and Soul</strong></em> (Teströl es Lelekröl, 2017) is the story of two naive people who feel emotional intimacy towards each other in the setting of a slaughterhouse. The Hungarian director <strong>Ildiko Enyedi</strong> builds the main tension of the film by putting the warmth of the intimacy amongst living creatures against the mundane harshness of the world. When the cattle are chopped in the slaughterhouse, the characters of the movie turn their faces towards the sun for the purpose of warming up their souls. When bodies are splintered, souls shelter the closest warmness and light they can find.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Before introducing the characters of the film, the thin line between introversion and autism should be mentioned. One is a personality trait, the other is a clinical diagnosis; two separate dimensions for mental health professionals. Introversion is the lack of interest into and desire of a connection with the environment. It is a shy, reserved and silent existence. It is thought of as a choice, instead of a personal disposition. On the other hand, autism is a serious pathology hindering individuals to get involved in social life. It is not a choice but an imperative. However, at different degrees of autism, some cognitive and social malfunctions may change and differentiate with the compliance mechanisms of the patient. Although the female character on <em><strong>On Body and Soul</strong></em>, Maria, has been drawn to exhibit typical features of Asperger\'s Syndrome for those familiar with the clinical spectrum of autism, for the ordinary audience, she is a cold and uncommunicative person who lives and make others live difficulties in social life, she is introvert and a little ‘’disturbed’’. Some ‘’strange’’, ‘’bizarre’’, ‘’incomprehensible’’ behaviours of her may make our judgement difficult, but the knowledge that will ensure us to perceive her as “pathological” is deducted from the film. So it\'s better to think of this character in the gray area between mild autism and severe introvert.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/maria.png" alt="maria" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>A Man, a Woman</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The female character, Maria (<strong>Alexandra Borbely</strong>) is in a state of disconnectedness that deserves the "ice queen" nickname in her new workplace working as a quality supervisor. Maria spending all day in the cold slaughterhouse in the blue light of the computer with wearing her beanie is a woman who rejects her colleagues’ coffee invitations, do causes other people to “freeze” when she sits at their table in the cafeteria, behaves uninterested and does not care much about communicating with others. She finds herself as someone whom her colleagues gossip about, laugh at and mock, although she doesn’t mind. Maria only cares about her work, she closes herself to the environment. When the people around cares for her, she has never had difficulty in pushing them away due to her undeveloped social skills. She feels extremely uncomfortable when somebody touches her. Even though this contact is made accidentally and without any harmful intention, her body is alarmed and shows avoidance response. It is a reaction of an organism that has already been enclosed inside. The outside world is full of these kinds of unexpected stimuli and threats. In her house, on the other hand, which is the most safe place for her, she has certain routines and diligence. Her life must be organized and operated perfectly. She can only cope with a small amount of objects, actions and stimuli at certain time and space. The only way for her to be purposeful and focused in life is that she does not go out of this order she has established for herself. Her little world commits just like a precise clock, always the same way she consumes her moments. It seems like a spirit does not accompany her body in this life of mechanical functioning. In rare moments when she turns her face to the sky, can solar rays find ways to enter her body to warm her? We can\'t even be sure of that.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/endre.png" alt="endre" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The male character of the movie, Endre (<strong>Geza Morcsanyi</strong>), is a finance manager who ‘’never visits the altar’’ in the slaughterhouse. He only shows himself in his office, food court and seldomly at the cafeteria. His only friend is the human resources manager, but he turns a cold shoulder as if he didn’t choose him to be his friend but couldn’t say no. Endre is good at his job and his left arm is paralyzed. We cannot know which of these two features of him is more important in his gaining distant respect from the people around him. He lives alone, has his dinners mostly at the outside and falls asleep in front of the television at nights. The spirit that accompanies the movements of his disabled body through life is delicate and fragile.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>About body and soul...</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Body is concrete, consists of flesh, bone and blood. Soul is abstract. It is incorporated to the body and encompasses other indefinable features of ours that complete the body. Our mental functions, cognitive capacity, feelings, desires and dreams -they all can be implicated in the soul. The duality of body and soul is one of the oldest and most fundamental issues of philosophy. In Cartesian thought, the proposition of <strong>Descartes</strong> ‘I think therefore I am’ (cogito ergo sum) leaves no room for a metaphysical spirit. Soul and mind, mind and thought are paired. With the post-Cartesian thought, the world of unconscious experiences, instincts, dreams, and emotions, as well as conscious thinking have been included to the existence, and soul (psyche) has been considered as a viable category of existence. (Thanks to <strong>Freud</strong> and his contemporaries) The soul and body, which always interact with each other, the mirror of one another, have transcended this dichotomy in contemporary philosophy, becoming one and whole (here, let\'s give credit to phenomenology and post-structuralists). Another explanation from psychology is <strong>Rollo May</strong>\'s analysis: <strong>Descartes</strong>\'s exclusion from the entity is not only about the soul but the power of action. The will and intentionality that make individual human are not only the power to think and design. The transformation of intentionality to an entity is possible only if abstract ideas and plans can take action and become concrete. This approach delivers credibility not only to the brain but to the whole body. ‘’Instead of saying I think therefore I am, it would be more accurate to say I act intentionally therefore I am.’’ says <strong>Rollo May</strong>.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">There are many junctions in the road of human intellectual history that scrutinized from the philosophical concepts such as intent, will, self-control and intentionality to the ‘’body’’ and ‘’soul’’ which are considered as two main categories of the existence. With the most valid approach, when we see body and soul as an inseparable whole, the question whether the cognitive system (thinking-interpreting-designing-dreaming-reminiscence) is the function of body or soul loses its meaning. Of course, they contribute these functions together. Neurobiological system, on one hand, cognitive psychological mechanisms on the other and socio-cultural interactions for sure; aren\'t they all sine qua non components of thinking, feeling, and forming relations?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>‘’Body’’ representations in the movie</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">The deer in the dream</span>: Their existences, movements, interactions, glances, touches in the forest. The two deer interacting with each other in the eye of the audience with the nuanced editing of the director. The linear narration reflected by the nonverbal communication of their bodies. First, they are in their own, separate from the herd, and from each other, over time they notice each other, watch remotely, be side by side without touching, lose sight, move together, get closer and have small contacts. They symbolize free bodies integrated with nature. Strong on their own, but not disconnected, bodies that can form relations; unlike the bodies in the slaughterhouse.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Bonding, connecting to a living, feeling attached, living connections. Are they closer to the body or the soul?</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/deers.png" alt="deers" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Animals in the slaughterhouse</span>: It is inevitable to include the captived and shattered bodies in this film. Flesh-bone-fat-blood images are clearly displayed in all processes where cattle are shattered to obtain meat. The movement of animals before slaughter, their gaze, their disengagement in a herd. The director shows us their expressions in close-up shots, and we assign feelings to them: concern, fear, indifference, shortsightedness, unresponsiveness. (drugs should be mixed in their meal, as we also know about their drug for fast mating).</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The scene of the slaughterhouse employees who follow the animal scenes in the slaughterhouse should not be overlooked. Similarities are constructed between them: being a member of a herd/community, being processed by some mechanism, and giving the right to self-determination unconsciously to the social compromises.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Physically disabled characters</span>: Both characters are prominent with bodily existence due to their physical pathologies.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Endre\'s left arm is crippled, paralyzed. It is a dysfunctional body part hanging down his shoulder, with no sense and strength. Endre’s adaptation ability is strong. With his rugged right arm, he accomplishes everything like a single-gun musketeer. We don\'t know the story of this injury. Is he born with it or not? We have no slightest idea of what Endre would be if he didn\'t have this disability. But, partially, he has some manners and attitudes that we can tie to this disability. His fragility and shyness to initiate a relationship or his lack of courage in pursuing his desires should not be independent of his physical disability.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Maria’s physical limitations are more serious. Even though the movie doesn’t show us clearly, we understand that she is diagnosed with Asperger’s Syndrome, a clinical diagnosis refers to the cases in the autism spectrum with advanced cognitive ability. The strength of Maria is her memory. She can remember all past events with specific day-month details and all of her interactions with others, even the sentence order. However, having strong memory doesn’t neutralize the other characteristics of autism. Autism is a clinical diagnosis that has a genetic origin, is mostly diagnosed at early ages and shows symptoms such as problems in social development and communication, hypersensitivity to the external stimuli, restrictive-repetitive behaviours. It is a situation characterized by the lack of empathy, emotional language and eye contact in communication, and a reserved mental state. In the movie, Maria was presented to the audience as an ideal case with almost all of these clinical features. Only the name of the diagnosis is missing.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Maria\'s physical posture is rigid as a stick, body movement is mechanical and face is impassive. As Zsoka, the cleaning worker of the slaughterhouse, expresses how important the movements of the human body are! Although our postures and movements are much more stimulating than clothing, they are being ignored while preparing for a performance in the outside world. Probably Maria\'s introverted attention has rarely met with mirrors.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">How will it be possible for these two defective bodies to connect with each other?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>‘’Soul’’ representations in the movie</strong></p>\r\n<p>&nbsp;</p>\r\n<p><span style="text-decoration: underline;">Sharing the dream</span>: Two sensitive people have the same dream, know each other by their deer form in the dream world, shelter in each other in a cold forest, and protect each other. Of course, this dream part binding the souls of characters together is a filmic invention. A metaphor. The metaphor of the belief that two people who are deprived of the ability to find and connect to each other in real life, in fact, may actually have a chance with each other.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Animals in the slaughterhouse</span>: The cattle which have no ability and power to object to their situation are at close up shot, which evokes empathy on the audition. It can be seen as the director’s attempt to give back their souls to them. Which audience can remain indifferent to this? Is there anyone who watches the scenes and doesn’t question: ‘’Do I have the right to harm them in such a way?’’ Don’t we say: ‘’Screw this mutual agreement we make on animals!’’</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In the job interview of new employee Sandor, Endre makes this advice: ‘’If you don’’t feel sorry for these butchered animals, you can’t work in the slaughterhouse.’’ Does this statement also warn us against the indifference of perceiving these animals as just a piece of meat? It is our emotions that connect with the soul and if they are oppressed, they result in depression and absorb the life energy. I transferred to the present, the compassionate and respectful point of view for the slaughtered animals, from natural relationships between humans and animals in predatory societies, <strong>Enyedi</strong> says in her interviews.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/maria_and_endre.png" alt="maria and endre" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">The interaction between Maria and Endre</span>: They are in a connection that similar to the deer: they can observe, glance at each other from a distance, feel their existence and interact even without verbal communication. Big misunderstandings, however, happen in their face to face and oral communication. They experience weak dialogues mostly because of Maria’s autistic nature but Endre’s fragile and sorehead characteristic is also a factor. Their oral communication attempts fail, despite Maria’s talking rehearsals, but how wonderful the dreams and faint sensation nurtured by dreams work for getting them closer to each other. Despite physical limitations, their souls draw each other like magnets.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Pain and joy intersecting the body and soul</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Pain and joy get coded with negative or positive emotions affecting both body and soul at the same time. While the flesh-bone-blood images in the slaughterhouse symbolize body and pain it the movie, the sun coming out occasionally symbolizes soul and joy of life. (all hail to <strong>Spinoza</strong>)</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">If we focus on what characters experience:</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Pain for Endre</span>: The moments when Maria points out his disabled arm; when he is warned about his glance to psychologist’s breast; when new employee Sandor is interested in Maria (what a quick reflex of jealousy and sense of protection); when Maria flinches herself because of his touch after a long night in the Endre’s house. Whenever expectations and reality contradict each other.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Pain for Maria</span>: No or very few feelings like other feelings of Maria. Maria shows no empathy sign for these interactions affecting Endre negatively. No feelings by her autistic nature. She is indifferent to anything but the sun… and music. Not every song, just one song. ‘’What He Wrote’’ by <strong>Laura Marling</strong> catches her feelings at the first listening.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="font-size: 9pt;">He wrote, ‘I\'m broke, please send for me.’ But I\'m broken too, and spoken for. Please, do not, tempt me</span></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The song impressed her deeply such a way that she pauses the song in this part...</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">When she screws up her courage after touching practices and insistent observation on couples making love in the park, and goes to Endre with her pyjamas and full commitment, she is rejected by Endre. This rejection must be the ‘’pain’’ in the sense we know. Whenever expectations and reality contradict each other...</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/istasyon.png" alt="istasyon" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><span style="text-decoration: underline;">Joy for Endre and Maria</span>: The moment in the train station after their mutual dreams approving that their intuitional attention towards each other and non-verbal but sensitive interaction comes out. This is a pre-joy. The true joy happens when the dreams are written and compared, and this miraculous situation is approved undeniably. The moment when their so much loving each other starts. The moment when they sense bonding through their eyes, and share mutual warm smiles. When Maria discovers the real eye contact. The irrevocable moment for each of them.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><strong>Wish dream came true</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">These two characters would never find each other, neither in the movie life nor in real life, without dreams. However, doesn’t the dream theme show us the imagination of the director, and not of the characters? These dreams can’t be created just for making a love relationship possible. <strong>Enyedi</strong> must have set up a dream setting for our real (and cruel) world that we all experience more or less defects and make mistakes while trying to achieve a connection, she dreams for us, and share her dream with us. She explains us that as living creatures, our body and soul mechanism which enables us to connect with each other rests in our deepest layers, and this mechanism is both simple and primitive (as animals), and sophisticated that needs going down into those depths (as humans). She must be telling that combining the body and the soul in relation to life requires a design and imagination that can go beyond everyday ordinary interactions with our environment. I imagine, therefore I can connect.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/on_body_and_soul/ruyalar.png" alt="ruyalar" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">In today’s cruel and chaotic world, is the call from <strong>Enyedi </strong>sufficiently convincing to go beyond copulating and fucking each other, and to return to our needs to connect with each other in our purest state to establish bonds, and to re-open ourselves to our most fundamental human value, spiritual and physical sharing? From its scenario to acting, from its images to soundtrack, from its symbolism to fiction, <em><strong>On Body and the Soul</strong> </em>does its best; however, my mind is somehow stuck in the scene of the leakage of blood after Maria’s suicide attempt. She takes a phone call in the hall while her wrist bleeds, her blood finds its way to her leg and then to the accumulation on the ground. How many people in real life can get a lifesaving phone at that exact moment, a call that should overcome all the self-protection mechanisms, retreats, misunderstandings and frustrations? Nevertheless, it is important to listen to the call and renew our faith. The best thing to do is to turn this film into a meditative opportunity to reconsider our own relationships with low risks, slight connections and internal blee.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema Kültürü Dergisi,&nbsp;August 2018, Issue e8, pp. 97-106</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by Tuğçe Yalaz</span></p>', 29, 67, 'Arşiv Yazıları', '/images/archive/on_body_and_soul/maria.png', '2019-06-20');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (177, 'ay-j274', 'nevinost-bez-zastite-innocence-unprotected', 'Nevinost Bez Zastite (Innocence Unprotected)', 'NEVINOST BEZ ZASTITE', '<p style="text-align: center;"><em><strong>NEVINOST BEZ ZASTITE</strong></em></p>\r\n<p style="text-align: center;"><em><strong>INNOCENCE UNPROTECTED</strong></em></p>\r\n<p style="text-align: center;"><strong>A MOVIE REVIVED BY DUSAN MAKAVEJEV</strong></p>\r\n<p style="text-align: right;"><strong>&nbsp;</strong><a href="/docs/archive/NEVINOST%20BEZ%20ZASTITE.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: center;"><strong>Gökhan Erkılıç</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Dusan Makavejev</strong> (1932) redesigns a film of the year 1942, arranges and enriches it with additions, and he presents a new life to it with a filmic reincarnation: The film, <strong><em>Nevinost Bez Zastite,</em></strong> born in 1968 is on the screens again. <strong>Makavejev,</strong> whom such bizarre works always suits, one day deals with the secrets of the organism, and another day passes to <em>sugar film</em> production, and indeed, when the switchboard operator does not satisfy him, he can even be found in company with <strong>Sonia Henie</strong>.</p>\r\n<p>&nbsp;……………………….</p>\r\n<p style="text-align: center;"><strong>Screenplay:</strong> Dragoljub Aleksik (1942), Dusan Makavejev &amp; Branko Vucicevic (1968)</p>\r\n<p style="text-align: center;"><strong>Cinematography:</strong> Branko Perak</p>\r\n<p style="text-align: center;"><strong>Camera Operator:</strong> Stevan Miskovic (1942)</p>\r\n<p style="text-align: center;"><strong>Editor:</strong> Ivanka Vukosovic</p>\r\n<p style="text-align: center;"><strong>Music: </strong>Vojislav Kostic</p>\r\n<p style="text-align: center;"><strong>Cast:</strong> Dragoljub Aleksik, Ana Milosavljevic, Ivan Zivkovic, Pera Milosavljevic, Bratoljub Gligorijevic, Vera Jovanovic-Segvic</p>\r\n<p>……………………….</p>\r\n<p style="text-align: justify;">Belgrade city was invaded by the German army during the Second Great War. Under those heavy conditions, the acrobat <strong>Dragoljub Aleksic</strong> (1900-1985), who was one of <strong>Makavejev</strong>’s childhood heroes, made <strong><em>Innocence Unprotected</em></strong> which is an Aleksic film about Aleksic. This first sound film of Yugoslavian cinema was left to be deeply forgotten perhaps because of either the war years or - the fabricated blindness of the authorities. After the war, Aleksic was absolved from some meaningless accusations made by judicial authorities, who became restless as the film had been made during the Nazi invasion. The film is abandoned to be forgotten for long years.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Nevinost_Bez_Zastite/GE_makavejev1.jpg" alt="GE makavejev1" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">After years, <strong>Makavejev</strong> takes the film in hand and rearranges it by adding actuality documentaries of the invasion years and the interviews made with the film crew. And he puts his mark on one of the biggest gestures of cinema history. Old and new, black-white and colorful, fictional and documentary, comedy and tragedy are blended with each other, and turn into a good harvest.</p>\r\n<p>……………………….</p>\r\n<p style="text-align: justify;">As for the topic of the film: Rich and uncultivated Petrovic comes to visit Maceha, as he does at any chance. The concern of the both is Nada; one wants to get rid of her stepdaughter and the other wants to get her. Nada gets away thanks to Aleksic’s action on the right time. Petrovic and Maceha are honored to the interest of the police. The lovers enjoy the life. As justice is served, love announces its victory.&nbsp; That’s all.</p>\r\n<p>……………………….</p>\r\n<p style="text-align: justify;">The film crew, who had been either soldiers or agit-prop members or dwellers of the concentration camps during the Yugoslav War of Independence, confides in the camera when they get the chance, with an exposition in where points and commas are replaced by exclamations and question marks.</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/archive/Nevinost_Bez_Zastite/GE_makavejev2.jpg" alt="GE makavejev2" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Ivan Zivkovic</strong> who acts as Aleksic’s brother, safeguards the negative and the audiotape of the film by burying them in Rokavica village in 1944. After the independence, in 1946, he hands it to Belgrade in mint condition.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Pera Milosavljevic</strong> (1903-1973) who plays the servant says that when they were expelled by the separatist Ustasa militants, they utilized the offer of the cameraman <strong>Stevan Miskovic</strong> who had connections with the Germans and supplied negative films in return of food from the black market. And she says that they took part in the production with the idea that it could appease their hunger and put some money in their pockets.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Ana Milosavljevic </strong>(1915-) who plays the role of the poor orphan Nada looks very upset for breaking a vase on <strong>Bratoljub Gligorijevic</strong>’s (1901-1943) head who plays the character Petrovic. Either the rape scene must have been too realistic, or the vase must have been so precious…</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;"><strong>Vera Jovanovic-Segvic</strong> (1922-1998), the stepmother Maceha in the film, complains that <strong>Aleksic</strong> went on a film screening tour and got all the money and the acclaims, while nothing is left for the others.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The camera operator <strong>Stevan Miskovic</strong> (1907-1977), on the other hand, is a Monte Narcissus <em>par excellence</em>... Even though he does not know how to craft a proper frame, we all are introduced with the zero-point of everything as it is obvious in his speech!</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The shots by <strong>Makavejev</strong> gathering the film crew on the roofs and terraces, graveyards and houses zest like footnotes: <strong>Aleksic</strong>’s continuing his shows despite his handicaps, the corn bread as a solution to hunger in the hard times, the role of the sandals in financing the&nbsp; film, their shared history&nbsp; recalled during the visit to <strong>Gligorijevic</strong>’s cemetery, the problems of production, the German officials surprised by the interest aroused after the premiere, and <strong>Aleksic</strong>’s self-defence in the case.</p>\r\n<p>……………………….</p>\r\n<p style="text-align: justify;">The actualities which played the leading role for granting documentary characteristics to the film provide quite rich data: Belgrade, ruined and aflame under the Nazi invasion… Poor people running around in the streets to protect themselves from the attacks which they don’t know when or from where can come while they try to rescue the people under the debris… 1941 Nazi attack and the Stalin line… Volga petroleum… Production of sandals… Photos of the premiere of the film… Serbian propaganda documentaries… Women in the vintage and wine production… Prince Paul… Communist wolfmen… Public concert by the military band in the squares…</p>\r\n<p>……………………….</p>\r\n<p><strong>&nbsp;</strong></p>\r\n<p><img src="/images/archive/Nevinost_Bez_Zastite/GE_makavejev3.jpg" alt="GE makavejev3" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">For the applications which make the film technically interesting, we need to prioritise the objects that are coloured by hand, such as carpets, dresses and glasses. The mis-en-scenes in which the actors shift to improvisation, economically used inter-titles, parallel editing. The scene of Aleksic’s explanations about his air show which he is understood to put special importance among all his shows draws the attention with its composite application of camera-editing-sound triad: While the camera is strolling between the rooms at his home like an airplane, the acrobat’s explanations about the occasion flows in the audiotape and the sound of the aircraft engine in the background builds the sound-bridge between the related scenes.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The scenes of the film made in 1942 (some of which were excluded) composes the spine of the film with their duration. The shots in the 1968 version weigh more or less the same in duration. The 15-minute actuality shots have been added to these.</p>\r\n<p>&nbsp;……………………….</p>\r\n<p style="text-align: justify;"><strong><em>Innocence Unprotected</em></strong> bears two more cinematic references in addition to its source film on which it is based. The first is the film <strong><em>Die Goldene Stadt</em></strong> (1942) directed by <strong>Veit Harlan</strong> and released on the same days with <strong>Aleksic</strong>’s film during the invasion years. The second one is <strong>Charlie Chaplin</strong> who finds a place for himself at the bottom of cannon-human.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Nevinost_Bez_Zastite/GE_makavejev4.jpg" alt="GE makavejev4" /></p>\r\n<p>&nbsp;</p>\r\n<p>……………………….</p>\r\n<p style="text-align: justify;">We can see this film as a portrait of the acrobat <strong>Dragoljub Aleksic</strong>, a showman who makes his name with his unexceptional strength and courageous attractions (although some of his shows are not included here). The song in the introduction of the film composed by <strong>Vojislav Kostic</strong> for <strong>Aleksic</strong> displays this situation. Poems about courage and praise written by <strong>Aleksandar Popovic</strong> also contribute the same purpose.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Let’s add that <strong><em>Innocence Unprotected </em></strong>which deserves praise even for the project itself received the FIPRESCI Prize and the Silver Bear Grand Jury Prize in the 1968 Berlin FF, and the Gold Hugo Best Film Prize in the 1968 Chicago FF.</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema Kültürü Dergisi,&nbsp;April 2018, Issue&nbsp;e7, pp. 79-84</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by Sultan Demirel</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">sultandmrl160@gmail.com</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Edited by Nurten Bayraktar</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;"><a href="mailto:nurtenbayraktar12@gmail.com">nurtenbayraktar12@gmail.com</a></span></p>', 45, 67, 'Arşiv Yazıları', '/images/archive/Nevinost_Bez_Zastite/GE_makavejev1.jpg', '2019-06-21');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (178, 'ay-j275', 'desamourussia-loveless-nelyubov', 'Desamourussia (Loveless / Nelyubov)', 'DESAMOURUSSIA', '<p style="text-align: center;"><strong>DESAMOURUSSIA</strong></p>\r\n<p style="text-align: right;">&nbsp;<a href="/docs/archive/Desamourussia%20(Loveless--Nelyubov).pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: center;"><strong>Gökhan Erkılıç</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><em><strong>Loveless (Nelyubov)</strong></em></p>\r\n<p style="text-align: center;"><strong>Director:</strong> Andrei Zvyagintsev</p>\r\n<p style="text-align: center;"><strong>Scriptwriter:</strong> Oleg Negin &amp; Andrei Zvyagintsev</p>\r\n<p style="text-align: center;"><strong>Cinematographer</strong>: Mikhail Krichman</p>\r\n<p style="text-align: center;"><strong>Music:</strong> Evgueni Galperine &amp; Sacha Galperine</p>\r\n<p style="text-align: center;"><strong>Editor</strong>: Anna Mass</p>\r\n<p style="text-align: center;"><strong>Cast:</strong> Maryana Spivak (Zhenya), Aleksey Rozin (Boris), Matvey Novikov (Alyosha), Marina Vasileva (Masha), Andris Keiss (Anton), Aleksey Fateev (İvan)</p>\r\n<p style="text-align: center;">2017 / 127’ / Russia - France - Germany - Belgium</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Here are some questions asked for a long time, answers of which have been found:&nbsp;</p>\r\n<p style="text-align: justify;">Does the essence of what is called human being belong to nature, plastic, metal, or nothingness?</p>\r\n<p style="text-align: justify;">What reduces the status of being mother and father to the mission of mediating life?&nbsp;&nbsp;</p>\r\n<p style="text-align: justify;">How long have we been a captive of suffocating, blinding and chilling lovelessness which shrinks the habitats finally kills us?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" width="30" height="30" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Specific questions about <em><strong>Nelyubov</strong></em>:</p>\r\n<p style="text-align: justify;">Is the thing called life being hung on a branch of a tree, one standing by the shore of a lake under snow and hit by time?</p>\r\n<p style="text-align: justify;">What leads a child to be a loss with his anger burning inside in his silence?</p>\r\n<p style="text-align: justify;">What do the house we try to sell at once and our partner we try to get rid of through which, we suppose, we can get rid of the past mean for our personal belongings and for our shared past?</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">We build relationships by emotional and even by shallow decisions based on the concepts ‘attractive’ and ‘unattractive’ even though we do not know and sometimes cannot explain to ourselves what they are. Then, we attempt to exist and pretend to be able to exist in the rational arena.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">While most of the life experiences consume the future, few re-establish the life. The lives bearing the burden of unforgivable mistakes become unbearable burdens on soul. Yet there is no need to discuss that the highest potential for making mistakes is when it is not the right time to make decisions.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">For a long time, it has been a favourite intellectic subject matter that it is impossible to evaluate in terms of socio-economic classes because they are invisible. However, there is a fact even clearer than a crystal: You do not and cannot see if you don’t look. The gap between social classes is not only economic and cultural; but there is even a wider one our emotional and human existence. It is ironic to call our time “age of poverty”, too narrow to call it “age of technology”, so I believe it is more appropriate, comprehensive and realistic to call it “age of human deprivation and lovelessness”.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Zhenya is a very familiar character to come across often. Suffering from a hunger for love, she is unabashed about love. She pretends to be only thinking about love and knows how to ask for limitless love, although she cannot give any love to Alyosha for not having it in herself. She is in the delusion of exchanging desire with love. Zhenya is a typical phone-addict as if it was her mate which has become an organ completing her or as if she can complete herself by it. It is one of her two organs she uses, that is, she is capable of using. She can only say “I guess” to the questions asked about her son Alyosha’s daily life, tendencies and habits. Well, does anyone called Zhenya exist? <em>I guess</em> not.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Boris is a loose cannon, giving an impression of having dual cores. He is not on the side of the “I guess” people. He is one of those who are smaller than they are, but believes he is a bigger person than he is. You can come across him at any hour, and question what sin you have committed to end up with him in the same place.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The blonde captive Masha is an artefact, as a heroine from the Slavic romanticism living among us. As if fallen from the previous century, a breeze from the nucleus Russia!</p>\r\n<p style="text-align: justify;"><br /> And the Grandmother...&nbsp; Mother Russia must have gone crazy. The steppe crochet stitched from left to right by Great Katarina echoes throughout the cities.&nbsp; As a past habit we know that <strong><em>Moscow Does Not Believe in Tears, </em></strong>but it is obvious there is no single place overtaken and covered by disbelief.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">There is also the state with its cast on the stage.&nbsp;They have a limited role of claiming that the civil search and rescue squad is faster and more efficient than the police. The reason for their existence is to declare their absence.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">There is nothing to say about the casting choice of <strong>Zvyagintsev</strong>, it is magnificent as always. However, this time all are typecast, so much that we might bump into them at any time on the coasts of Anatolia: Hail our creation, the Homo AI. (This should not be read as All-Inclusive, what I mean is “Ain’t Inclusive at all!”).</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Loveless/hareket.jpg" alt="hareket" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Radio and TV were the media for communication in the last decade, now they are used much more; however, they are no longer the means for communication but the decorative stuff as accidents of communication. Although it is a combined device, what we call mobile phone today replaces them all. A new type of human who is visible everywhere for a long time is badly intimate with this thing: We come across this type of being with the cables sprung from its head, and its absurdities include posing as if attached to a reanimator machine or sometimes falling flat on the face or gets under a car. I suppose this type of being live on fastened to the phone via cables, and it is occasionally possible to consider it as a part of the mobile phone. Isn’t it possible to interpret the invasion of this very specific species with its asocial reactions beyond human’s surrender to the infinite void of man\'s inner world but as an expression of the age of lovelessness?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">I have an objection to those who take the film as an excuse to judge the Russians. Obliged to work to repay their loans caused by the dictated unnecessary needs, their faces driven by the fear of dismissal at any time, wasting a quarter of their lifetime in the shopping malls, addiction to technology, acting the smartest by fooling others, their creativity capable of making jokes that can only be the signs of underdevelopment, surviving by eating one another up, lacking any passion, desire, interest, aim, dream or hobby, their sneaky faces veiling their destructive anger… The humans of this age have all these in common. Even though the film is set in a story of a group of Russian-speakers among the global human, it tells about the global human whose most obvious indexical sign is lovelessness.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The biggest contribution of the film might be creating an arena for thinking and discussing on lovelessness. Lovelessness is a condition preventing the individual from being qualified, original and creative, and it is a power destroying the desire for life, which swirls human into the monotype. Any domain ruled by lovelessness bears the disbelief and soon brings forth anxiety, arrogance, hatred and violence.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Loveless/asansorde.jpg" alt="asansorde" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Cinema can turn into an existential activity and a protest against lovelesness in the hands of a director kneaded with love. Nevertheless, after all, the directors of our age are not extra-terrestrial creatures either, and they do take their share of the devastating effects of this loveless age. This century is such an age in which economics and politics steal one another’s role and get integrated in global models, a place where human values are put aside and disgraceful ignorant leaders show off, rights and justice are swapped with stealing and violence, vulgarity is praised, the laborless profit is sanctified, making everything that is conceivable seem as though they can be bought by money and where the human is diminished to the cheapest object. The human whose existence is lost in such an era does not write poems or sing, or contact culture or reach out for art. The schizoid, depressive and paranoiac society loses its social ideals and aims. For this reason, what is lost in <strong><em>Nelyubov</em></strong> is not only the little Alyosha but also the future- our future.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Lovelessness is a global disease.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Where does the problem of <strong><em>Nelyubov</em></strong> lie? What originates our feeling of ‘unripeness’? It partly lies in the unbearable weight of repetitions, the scenes which could be cut to make the film tidier but instead kept despite the lack of their saying something new, the unnecessarily long scenes, the mis-en-scenes with the same meaning, the warped spine of the narrative caused by the unbalanced distribution of weight, stammering while trying to say many things, the dialogues which make the audience sometimes yawn, the unbalance resulted from the so-so quality of the scenes as exposed by&nbsp; some good ones, the narrowness evoked by the narrative which is loose for the theme, being fallen into&nbsp; prey of prosiness while telling about prosiness.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">If it has so many flaws, how come the awards teem?&nbsp; I would like to point out the fact that most of the awards are from the lower ranked festivals. None of the best film awards won is from an A-class festival. The important awards were given to the cinematographer.&nbsp; We must not forget the European production partners might have used their authority in the sector and that the director\'s name has some brand value. In addition, the fact that the film had more nominations than awards points out a problem: The judges did not find the film worthy and mature enough for the win. When there are lots of examples of this “unripeness”, there is no need to discuss on this issue further.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Is the director\'s sudden let-down unexpected? Since I expected this after the films <strong><em>Elena</em></strong> (2011) and <strong><em>Leviathan</em></strong> (2014), I was not surprised. The films <strong><em>Vozvrashcheniye</em></strong> (2003) and especially <strong><em>Izgnanie </em></strong>(2007), where the director kept the bar so high, were effective as well in this result. If we consider lovelessness as a theme, we must say that both films were more successful in portraying and conveying it.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">It is hard for me to believe that I have just watched a film whose director said he was inspired by <strong>Antonioni</strong>, <strong>Bergman</strong>, <strong>Dostoevsky</strong>, <strong>Tarkovsky</strong> as far as I can remember from his interviews. <strong>Zvyagintsev </strong>depletes his stocks with an attitude often encountered in the history of cinema.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">I wonder if <strong>Zvyagintsev</strong> were given a chance to erase one film from his filmography, would he choose any other of his films? Or would he go back before 2017?&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Another ruthlessly self-imposed question: If given a chance, where would <strong>Zvyagintsev</strong> shoot his ‘Hatred’ film?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: center;"><img src="/images/archive/Loveless/sevgisiz.png" alt="sevgisiz" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">A film on the dark side of the moon that remains in the dark side of the moon, <strong><em>Nelyubov</em></strong>.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema Kültürü Dergisi,&nbsp;April 2018, Issue&nbsp; e7, pp. 19-24</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by Gülşan Maden, Nurten Bayraktar</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;"><a href="mailto:glsn.mdn@hotmail.com">glsn.mdn@hotmail.com</a>, <a href="mailto:nurtenbayraktar12@gmail.com">nurtenbayraktar12@gmail.com</a></span></p>', 45, 67, 'Arşiv Yazıları', '/images/archive/Loveless/sevgisiz.png', '2019-06-22');
INSERT INTO ara_yazilar (id, code, slug, baslik, spot, icerik, yazar_id, kategori_id, kategori_ad, kapak_gorseli, yayin_tarihi) VALUES (179, 'ay-j280', 'the-remarkable-aspect-of-police-adjective', 'The Remarkable Aspect of Police, Adjective', 'THE REMARKABLE ASPECT OF POLICE, ADJECTIVE', '<p style="text-align: center;"><strong>THE REMARKABLE ASPECT OF <em>POLICE, ADJECTIVE</em></strong><strong><em><br /></em></strong></p>\r\n<p style="text-align: right;">&nbsp;<a href="/docs/archive/THE%20REMARKABLE%20ASPECT%20OF%20POLICE,%20ADJECTIVE.pdf" target="_blank">PDF</a></p>\r\n<p style="text-align: center;"><strong>Cem Kayalıgil</strong></p>\r\n<p>&nbsp;</p>\r\n<p><strong><em>&nbsp;</em></strong></p>\r\n<p style="text-align: center;"><strong><em>Police, Adjective</em></strong><strong> (Polițist, adjectiv)</strong></p>\r\n<p style="text-align: center;"><strong>&nbsp;</strong><strong>Director and Screenwriter: </strong>Corneliu Porumboiu</p>\r\n<p style="text-align: center;"><strong>Cinematographer: </strong>Marius Panduru</p>\r\n<p style="text-align: center;"><strong>Editor: </strong>Roxana Szel</p>\r\n<p style="text-align: center;"><strong>Cast: </strong>Dragos Bucur, Vlad Ivonov, Ion Stoica, Irina Saulescu</p>\r\n<p style="text-align: center;"><strong>2009 / 113’ / Romania</strong></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Mark these words before we start: <strong><em>Police, Adjective</em></strong> directed by <strong>Porumboiu</strong> (b. 1975), who belongs to the minimalist branch of the recent Romanian realist cinema (<em>a.k.a</em> “the Romanian new wave”), does not offer a peculiar aesthetic. Let’s <em>italicize</em>: I am saying <em>peculiar, </em>not <em>authentic, </em>so neither <em>originality </em>nor<em> novelty </em>or <em>uniqueness </em>is of my concern here. To put briefly and roughly, I would like to note that the film asserts “I belong to the recent wave of realist Romanian film!”,&nbsp; and it &nbsp;attaches too much importance to put this forth that the aesthetic coherence of the film is built around this concern. <strong><em>Police</em></strong> seems to be focused on meeting the expectations and demands towards the Romanian directors, especially after the critics’ and the audience’s appreciation, embracement and the awarding of films such as <strong><em>The Death of Mr. Lăzărescu</em></strong><em> (Moartea domnului Lăzărescu, 2005) </em>by <strong>Puiu</strong>, <strong><em>12:08 East of Bucharest</em></strong><em> (A fost sau n-a fost?, 2006) </em>by <strong>Porumboiu</strong> and <strong><em>4 Months, 3 Weeks, 2 Days</em></strong><em> (4 luni, 3 săptămâni şi 2 zile, 2007) </em>by <strong>Mungiu</strong>. The film manages to meet the expectations in the formal aspect, but fails in taking it further. It seems as if this film was shot so as to make the audience who are aware of the conventions of this cinema say “This cinema has these conventions”; bestowing its existence to the Romanian realist cinema. Ultimately it can be concluded that the film has the potential to conduce to better formal evaluations of the other more important realistic Romanian films. It features such a heuristic value in itself. And I think this is remarkable, especially for the audience who peculiarly concern themselves with the problematics of representation, conveyance, and reconstruction of reality through films.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R1_704x396.jpg" alt="R1 704x396" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">However, for the sake of my argument, let’s first see in which aspects <strong><em>Police, Adjective </em></strong>is <em>unremarkable</em>. The plot of the film is based on a moral conflict. The mission given to our main character, Officer Cristi, is to tail a high school boy who is thought to be a marijuana supplier, and catch him in the act. <strong>&nbsp;</strong>As we understand, in his first week of the investigation, Cristi did not see the boy selling marijuana or find any relevant evidence. The only thing revealed is that the boy smokes marijuana with his two friends – a boy snitching for the police, and a girl - and for Cristi, this is not a reason for undertaking an operation. Moreover, Cristi thinks that in a few years marijuana will be legalized in Romania as well (just like in the other European countries), thus “ruining” a young boy’s life is wrong. Cristi’s conscience leads him to evaluate taking action with the swiftness expected by his commander and the prosecutor as a “blind rush”. In order not to suffer from the pressure of his conscience, he extends the scope and the duration of the investigation, focuses on the snitch and the girl instead of the suspected boy. Although he avoids his commander until he finds new evidence, eventually, on the 8<sup>th</sup> day of the narrative (on the second day of the plot, in the 65<sup>th</sup> minute of the film), he gets rebuked on the phone. There is nothing to do but entering that office; he undergoes the conceptual torture from his commander in this climax lasting almost 20 minutes. He is confronted with the dictionary meaning of “conscience”, “pangs of conscience”, “laws”, “morals” and “police”. And of course, this scene reminds us that unforgettably long studio shot in the director’s hit film <strong><em>12:08</em></strong> <strong><em>East of Bucharest.</em></strong>[1] However, the absurd character of the scene here does not come into being in a process as cynical as the one we find&nbsp; in <strong><em>East of Bucharest</em></strong>. For <strong><em>Police </em></strong>purposefully lacks&nbsp; the interaction and the debate–no matter how petty it is– between the characters of&nbsp; the previous film. Instead, in <strong><em>Police</em></strong>, there is the authority of the commander and his dictionary on Cristi, which pressures the protagonist, shuts him up and forces him to be the man of the system.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R2_704x396.jpg" alt="R2 704x396" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Let’s not be surprised that the winner is this authority at the end of the day, for we know that this is <em>how things work: </em>&nbsp;No matter how Cristi comes out against it, the operation will go for sure. But far more importantly, <strong><em>Police</em></strong> is not a character-oriented moral motivation film, like <strong><em>The Lives of Others</em></strong> (Das Leben Der Anderen, 2006). The cinematographic features of <strong><em>Police</em></strong> that I am addressing below are the reasons why it does not have such a narrative structure. As the audience, we <em>do not even see</em> the moral dilemma of Cristi: There is the Cristi saying no to the operation, there is the other (transformed) Cristi who is planning a detailed operation, and between these two there is a Cristi playing futnet with his colleagues! <strong>&nbsp;</strong>This <em>off-the-track</em> futnet scene gains&nbsp; significance, when the audience realizes the element it leaves out. There we see a transforming Cristi, and, in line with the aesthetic coherence of the film, I think the reason why he is kept out of the range of the audience is as follows: <strong><em>Police</em></strong> is not a film which conveys a remarkable message about the conflict between the individual morals and the legislation with its sanctions, nor leaves such traces on the audience.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Director <strong>Porumboiu</strong> aspires to something else in his film, and in a few words we can name it as&nbsp; “witnessing the daily eventlessness”.&nbsp; The film frequently makes us question why we watch or see the things it shows. The most ordinary examples of this are the shots which take almost all of the screen time until Cristi enters the building he works at and goes to his or someone else’s room, or until he covers the distance of all the outdoor space being framed. And probably one of the two catchiest examples is the scene where we watch Cristi slurping his soup at lunch in his own kitchen (the camera is set facing&nbsp; him on the table, <em>ca.</em>&nbsp; 70-second-long single static shot) and the other is where Cristi goes to the living room after having his dinner in the same kitchen (following the 4-minute-long shot of the section of the kitchen where we watch Cristi from the side-view - even if we turn our eyes away, we do not lose the track of the film), sitting next to his wife (a small angled pan, after which the new static frame&nbsp; is described by the frame of living room’s door) teasing her about the “nonsensical” lyrics of the lightweight song she’s been playing on the computer the whole time.[2]</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R3.jpg" alt="R3" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R4_704x396.jpg" alt="R4 704x396" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Under these examples, put what you see in (1) the shots&nbsp; displaying the dialogue in the aforementioned&nbsp; 20-minute-long climax (particularly prolonged for the absurdity effect), (2) the pan-intensive&nbsp; follow shots in Cristi’s tailing scenes, and (3) the long scenes where we watch Cristi waiting and spying out for some things to happen: There you have a very good deal of the film’s aesthetic expressivity. Look, what I’m saying is quite plain: <em>This</em> is <strong>Porumboiu</strong>’s film, <strong><em>Police </em></strong>is all about that, nothing more, for there is nothing else than that.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">It is known that some films involve an invitation to aesthetically experience beyond of what is directly shown as that watched on the screen. They may require to be understood through what they don’t show but allude to. I intentionally leave open to discussion what I mean by this cool ‘out of blue’ sentence, and I claim that <strong><em>Police</em></strong> is situated&nbsp; on the opposite of what’s understood by that . So what I refer by saying “<strong><em>Police </em></strong>is all about that” is just this: The shown phenomenon and the experience of seeing it; plus, relevantly, the <em>unshown fact</em> and the experience of <em>not having seen</em> it. So let’s expand on this by going over our basic cinematography knowledge.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">A panning camera allows the frame to move on&nbsp; an arc where the tripod functions as a pivot. <strong>&nbsp;</strong>Seeing an object entering the frame from the left because of the panning to left , we can infer that this object was there, out of the frame but in the world of the film, for some time: “We didn’t see this before.. Oh, I see now- it was on the left.” The fact that the object was there before it is being shown by the panning is a cinematic phenomenon which is not shown at that moment. &nbsp;The expression “I see - it was on the left.” depends on a causal inference (<em>not </em>causal<em> perception). </em>So, the camera movements with their&nbsp; function for inference on these off-screen phenomena and the mise-en-scenes play a key role in <strong><em>Police</em></strong>’s aesthetic expressivity. In his article examining the establishment of realism in the film, <strong>Guido Kirsten</strong> uses the scene at about the 17th minute as an example for this.[3]&nbsp; In this scene, the static camera at the standard-height with a long focus lens shows us the three youngsters smoking marijuana from a distance. Between our sight and them, there is a wire fence in the mid-distance, and closer to our sight, we see the heads of some kids playing. The framing at such distance -where we have a not-so-clear view of the youngsters’ actions- gives us the feeling of spying on them, and evidently, we assume that we see them from Cristi’s viewpoint.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R5.jpg" alt="R5" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">However, as the camera pans to the left and shows us the other parts of the school area, Cristi enters the frame from the left: <em>We didn’t see him previously, so he’s been to our left, so ours comes to be not his viewpoint.</em> This time, we watch Cristi from a similar distance for a while. <strong>Guido Kirsten </strong>draws this conclusion: The film enables us, too, to experience this spying action, and his bigger claim is that, with this and similar techniques, the film as a whole&nbsp; draws us directly into the ordinary, daily and the real life of a policeman. [4] Moreover, the technique of showing/not-showing (which characterizes the form of the film) is applied not only through the pan movements: Sometimes, while Cristi is or was in fact located within the shown area, he is still invisible as something gets between the camera (the eye of the audience) and himself, hiding from the people he spies on, if not from us; then he comes out in due course, much to our surprise. Or, in my favorite scene from the technical aspect, we are shown the youngsters smoking marijuana (from a proper distance as always); it is cut&nbsp; (by a discontinuous pan to the left, the intermediary arc movement of the camera has been cut out) where we see Cristi spying on them from a certain distance. We watch Cristi: He stands out in the open, then rushes to hide in the entrance of the building behind him, cranes out, and pulls away to hide himself again; then goes back at a trot&nbsp; in the direction of the place he was standing moments ago , continuously checking out the outer parts of the frame. The panning camera follows Cristi till the spot where the three youngsters were standing but now left vacant– the panning is to the right, traversing the full arc excluded earlier. Cristi bends over and takes the cigarette butt the youngsters threw on the ground. So, we are not shown the youngsters’ finishing their smoking and leaving the area;&nbsp; happening off-screen, they are suggested indirectly through Cristi’s movements: Such an economic and effective mise-en-scene.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">My point is that <strong><em>Police</em></strong> concerns itself with the inference to the off-screen facts from the shown ones. And let me highlight that these inferences are the simple and quick ones without requiring long ponderings within a single scene. Considering the fact that there is almost nothing to narrate throughout the film, we can say that these formalistic choices bring out the audience’s state of witnessing to <em>the moment and the space in&nbsp; that moment</em>. However, we can also easily notice that the filmed moments and spaces, too, are <em>featureless. </em>So, our witnessing is important not because of the features of the objects presented to our witnessing (the frame’s temporal and spatial content, everything that the frame contains). If <strong><em>Police</em></strong> does not turn into a <em>police documentary </em>while bearing a claim for an explicit and minimalistic realism, it is because of this straightforward <em>featureless-ness</em>. Let’s add that <strong><em>Police</em></strong> does not <em>problematize the state of witnessing,</em> either; this&nbsp; is not a Hanekesque film&nbsp; – we do note that, too. But if it’s so, does our witnessing bear any worth at all, other than being aestheticized?</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">Well, I think there is: It has an attributional and (self-)referential importance. I am now going back to what I have said at the beginning. <strong>&nbsp;</strong>There is a world offered in the recent Romanian realist cinema. This is a world of ordinary (even <em>insipidly</em> ordinary) characters who rarely catch each other’s eyes or affiliate with each other, and a world where the access to these characters inner worlds is not granted to the audience. This is also a world of filmic spaces that are left <em>featureless</em>, because we cannot call them beautiful or ugly, or because, even if they are ugly in “reality”, their ugliness is nothing of cinematic concern. This is an <em>a posteriori</em> world brought into existence by the cinematic conventions of the internationally renowned Romanian directors of the 2000’s, and it is this very world that <strong><em>Police</em></strong> presents us to witness. There have been many historical and also film-historical reasons and advantages for these directors to create such a world. <strong>&nbsp;</strong>In my opinion, to have a meaningful and mind-triggering watching of <strong><em>Police</em></strong><em>, </em>it is crucial&nbsp; to be cognizant of this world and these conditions of aesthetic creation. <strong>Porumboiu</strong>’s remarkable success in his film is his ability to wrap the obligation to refer to the world he shares with his peers’ films (the world that creates his director identity, too) in the aestheticization of cinematic witnessing. In other words, his ability to justify the film’s non-peculiar, derivative aesthetics through the witnessing experience that is intrinsically object-dependent and attributional.</p>\r\n<p>&nbsp;</p>\r\n<p style="text-align: justify;">The films that enrich the experience of watching <em>other films </em>are good as well. I am not going to say that <strong><em>Police, Adjective</em></strong><em> aims</em> to achieve this, but I can claim that its minimalistic aesthetics is quite efficient for this purpose.</p>\r\n<p>&nbsp;</p>\r\n<p><img src="/images/archive/Polis_Sifat/R6_704x374.jpg" alt="R6 704x374" style="display: block; margin-left: auto; margin-right: auto;" /></p>\r\n<p>&nbsp;</p>\r\n<hr />\r\n<p>[1] For a cinematographic and semantic comparison, see. Pop, Doru. “<a href="http://www.acta.sapientia.ro/acta-film/C3/film3-2.pdf">The Grammar of the New Romanian Cinema</a>”, <em>Acta Universitatis Sapientiae, Film and Media Studies</em>, 3 (2010), p. 36-37.</p>\r\n<p>[2] The dialogue in the second half of the latter example recalls the munchies-like, pointless-to-our-lives bickerings of people whose on-screen lives we witness in TV shows like "Big Brother”. But in contrast to the practice in <strong><em>Police</em></strong>, in those VTRs with the bickerings, it is known that the active camera and the shooting angle are changed by the cuts, and montage is heavily used.</p>\r\n<p>[3] “<a href="https://cinea.be/fictions-everydayness-focalization-patterns-and-narrative-reality-effects-police-adjective-and-other-films-from-the-romanian-new-wave/">Focalization Patterns and Narrative ‘Reality Effects’ in Police, Adjective and Other Films From the Romanian New Wave</a>,” <em>photogénie</em> 2</p>\r\n<p>[4] Kirsten\'s interpretation, which I find quite reasonable, is based on the follow shots that derive directly from the film\'s narrative, on the ordinary micro-events with no dramatic effect (such as Cristi drinking soup) and on the long screen time reserved to Cristi\'s waitings during surveillance.</p>\r\n<hr />\r\n<p>&nbsp;</p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Translated by Gökçe Yıldız</span></p>\r\n<p style="text-align: right;"><span style="font-size: 9pt;">Published in&nbsp;SEKANS Sinema Kültürü Dergisi,&nbsp;August 2017, Issue&nbsp; e5, pp. 6-13</span></p>', 64, 67, 'Arşiv Yazıları', '/images/archive/Polis_Sifat/R1_704x396.jpg', '2019-06-22');
INSERT INTO yarisma_bilgi (id, baslik, aciklama) VALUES (1, 'Film Eleştirisi ve Film Çözümlemesi Yarışması', 'Sekans Sinema Grubu tarafından düzenlenen yarışma hakkında güncel bilgi için Duyurular bölümüne bakınız.') ON DUPLICATE KEY UPDATE baslik = VALUES(baslik), aciklama = VALUES(aciklama);
INSERT INTO hakkimizda (id, baslik, icerik, iletisim_email, iletisim_adres, sosyal_twitter, sosyal_instagram, sosyal_facebook) VALUES (1, 'Sekans Sinema Grubu', 'Sekans Sinema Grubu, sinema kültürünü yaymayı ve sinema üzerine eleştirel düşünceyi geliştirmeyi amaçlayan bir kolektiftir.', 'info@sekans.org', 'Ankara, Türkiye', '', '', '') ON DUPLICATE KEY UPDATE baslik = VALUES(baslik);
INSERT INTO ayarlar (anahtar, deger) VALUES ('openai_model', 'gpt-4o-mini') ON DUPLICATE KEY UPDATE deger = VALUES(deger);
